INSERT INTO `news_detail` VALUES (1, 871, 6, '科技与数字服务', 'IBM 以 1700 万美元与美国司法部达成和解协议', '', 'IBM 于上周五与美国司法部达成了一项价值 1700 万美元的和解协议。 此前该公司被指控在招聘和晋升过程中考虑“种族、肤色、国籍或性别”因素，涉嫌实施了“非法的多元化、公平与包容（DEI）做法”。美国司法部还指控 IBM 将政府合同资金用于 DEI 项目，随后又申请报销。 IBM否认有任何不当行为，并表示此次和解并不代表 ...', 'https://www.oschina.net/news/420793', 0, '', '{\"summary\": \"本文披露IBM因涉嫌非法DEI用工做法被美国司法部罚款和解，为出海美国的企业提供合规参考\", \"abstract\": \"IBM近日与美国司法部达成了金额为1700万美元的和解协议。此次和解源于美国司法部对IBM的两项指控，一是IBM在招聘和晋升过程中涉嫌存在非法多元化公平包容（DEI）做法，二是IBM违规将政府合同资金用于DEI项目并申请报销。IBM否认存在任何不当行为，本次和解不代表其承认违规。该事件为出海美国的企业敲响了用工合规的警钟，值得相关企业关注。\", \"keywords\": [\"IBM\", \"美国司法部\", \"DEI\", \"用工合规\", \"出海合规\", \"和解协议\"], \"policy_risk\": {\"market_risk\": \"出海美国的企业若DEI相关用工制度不合规，可能面临罚款、监管调查等处罚风险\", \"policy_compliance\": \"美国司法部明确查处企业在招聘晋升环节的非法DEI做法，以及违规使用政府合同资金报销DEI项目的行为\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"https://www.oschina.net/news/420793\", \"title\": \"IBM 以 1700 万美元与美国司法部达成和解协议\", \"source\": \"https://www.oschina.net/news/rss\", \"content\": \"IBM 于上周五与美国司法部达成了一项价值 1700 万美元的和解协议。 此前该公司被指控在招聘和晋升过程中考虑“种族、肤色、国籍或性别”因素，涉嫌实施了“非法的多元化、公平与包容（DEI）做法”。美国司法部还指控 IBM 将政府合同资金用于 DEI 项目，随后又申请报销。 IBM否认有任何不当行为，并表示此次和解并不代表 ...\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'IBM 以 1700 万美元与美国司法部达成和解协议\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'IBM 以 1700 万美元与美国司法部达成和解协议\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://www.oschina.net/news/420793\'}], \'link\': \'https://www.oschina.net/news/420793\', \'tags\': [{\'term\': \'综合新闻\', \'scheme\': None, \'label\': None}], \'summary\': \'IBM 于上周五与美国司法部达成了一项价值 1700 万美元的和解协议。 此前该公司被指控在招聘和晋升过程中考虑“种族、肤色、国籍或性别”因素，涉嫌实施了“非法的多元化、公平与包容（DEI）做法”。美国司法部还指控 IBM 将政府合同资金用于 DEI 项目，随后又申请报销。 IBM否认有任何不当行为，并表示此次和解并不代表 ...\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://www.oschina.net/news/rss\', \'value\': \'IBM 于上周五与美国司法部达成了一项价值 1700 万美元的和解协议。 此前该公司被指控在招聘和晋升过程中考虑“种族、肤色、国籍或性别”因素，涉嫌实施了“非法的多元化、公平与包容（DEI）做法”。美国司法部还指控 IBM 将政府合同资金用于 DEI 项目，随后又申请报销。 IBM否认有任何不当行为，并表示此次和解并不代表 ...\'}, \'published\': \'Tue, 14 Apr 2026 16:52:39 +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=8, tm_min=52, tm_sec=39, tm_wday=1, tm_yday=104, tm_isdst=0), \'id\': \'https://www.oschina.net/news/420793\', \'guidislink\': False}\", \"published_at\": \"2026-04-14 16:52:39\", \"ai_json_output\": \"\"}', NULL, '2026-04-14 16:52:39', '2026-04-16 11:23:56');
INSERT INTO `news_detail` VALUES (2, 885, 14, '合规与政策服务', '国务院办公厅关于推动外贸稳规模优结构的意见', '', '', 'http://www.gov.cn/zhengce/content/2023-04/25/content_5753130.htm', 0, '', '{\"summary\": \"帮助外贸出海企业及时了解国家级稳外贸政策方向，为企业出海布局提供政策参考\", \"abstract\": \"这是国务院办公厅发布的外贸领域指导性政策文件，主题为推动外贸稳规模优结构。文件核心目标是稳定我国外贸发展规模，优化外贸产业结构，助力外贸企业出海发展，本次未提供文件具体内容。\", \"keywords\": [\"外贸稳规模\", \"外贸优结构\", \"稳外贸\", \"出海政策\", \"国务院\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及具体政策内容\"}, \"topic_cluster\": \"合规政策\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2023-04/25/content_5753130.htm\", \"title\": \"国务院办公厅关于推动外贸稳规模优结构的意见\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院办公厅关于推动外贸稳规模优结构的意见\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于推动外贸稳规模优结构的意见\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2023-04/25/content_5753130.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2023-04/25/content_5753130.htm\', \'published\': \'Sat, 03 Dec 2022 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2022, tm_mon=12, tm_mday=3, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=5, tm_yday=337, tm_isdst=0)}\", \"published_at\": \"2022-12-03 16:00:00\", \"ai_json_output\": \"\"}', '国务院办公厅关于推动外贸\n稳规模优结构的意见\n国办发〔2023〕10号\n各省、自治区、直辖市人民政府，国务院各部委、各直属机构：\n外贸是国民经济的重要组成部分，推动外贸稳规模优结构，对稳增长稳就业、构建新发展格局、推动高质量发展具有重要支撑作用。为全面贯彻落实党的二十大精神，更大力度推动外贸稳规模优结构，确保实现进出口促稳提质目标任务，经国务院同意，现提出以下意见：\n一、强化贸易促进拓展市场\n（一）优化重点展会供采对接。\n推动国内线下展会全面恢复。办好中国国际进口博览会、中国进出口商品交易会、中国国际服务贸易交易会、中国国际消费品博览会等重点展会。支持中国进出口商品交易会优化展区设置和参展企业结构，常态化运营线上平台。各地方和贸促机构、商协会进一步加大对外贸企业参加各类境外展会的支持力度，加强组织协调和服务保障，持续培育境外自办展会、扩大办展规模。\n（二）便利跨境商务人员往来。\n加强对外沟通，提高APEC商务旅行卡办理效率，加大工作力度推动其他国家畅通我商务人员申办签证渠道、提高办理效率。继续为境外客商办理来华签证提供便利。研究优化远端检测措施。尽快推进国际客运航班特别是国内重点航空枢纽的国际客运航班稳妥有序恢复，推动中外航空公司复航增班，更好为商务人员往来提供航空运输保障。\n（三）加强拓市场服务保障。\n我驻外使领馆通过完善合作机制、加强信息交流、推介重点展会等举措，创造更多贸易机会，加大对外贸企业特别是中小微外贸企业开拓市场的支持力度。发挥贸促机构驻外代表处作用，做好信息咨询、企业对接、商事法律等方面服务。发布相关国别贸易指南，想方设法稳住对发达经济体出口，引导企业深入开拓发展中国家市场和东盟等区域市场。支持外贸大省发挥好稳外贸主力军作用。\n二、稳定和扩大重点产品进出口规模\n（四）培育汽车出口优势。\n各地方、商协会组织汽车企业与航运企业进行直客对接，引导汽车企业与航运企业签订中长期协议。鼓励中资银行及其境外机构在依法合规、风险可控前提下，创新金融产品和服务，为汽车企业在海外提供金融支持。各地方进一步支持汽车企业建立和完善国际营销服务体系，提升在海外开展品牌宣传、展示销售、售后服务方面的能力。\n（五）提升大型成套设备企业的国际合作水平。\n加大出口信用保险支持力度，更好服务大型成套设备项目。金融机构在加强风险防控基础上，统筹考虑项目具体情况，保障大型成套设备项目合理资金需求。鼓励各地方通过开展招聘服务等方式，保障企业用工需求，加强岗位技能培训，确保履约交付，推动行业长期健康发展。\n（六）扩大先进技术设备进口。\n加快修订鼓励进口技术和产品目录，进一步提高进口贴息政策精准性，引导企业扩大国内短缺的先进技术设备进口。\n三、加大财政金融支持力度\n（七）用足用好中央财政资金政策。\n开展第二批外经贸提质增效示范工作。研究设立服务贸易创新发展引导基金二期。\n（八）加大进出口信贷支持。\n商业性金融机构进一步提升中西部地区分支机构在贸易融资、结算等业务方面的服务能力。鼓励银行和保险机构扩大保单融资增信合作，加大对中小微外贸企业的融资增信支持力度。在依法合规、风险可控前提下，鼓励国有大型金融机构加大资源倾斜，积极满足中小微企业外贸融资需求。鼓励政府性融资担保机构为符合条件的小微外贸企业提供融资增信支持。\n（九）更好发挥出口信用保险作用。\n进一步扩大出口信用保险承保规模和覆盖面。加大对跨境电商等新业态新模式的支持力度，加快拓展产业链承保，进一步扩大对中小微外贸企业的承保覆盖面，优化承保和理赔条件。\n（十）优化跨境结算服务。\n鼓励金融机构创新完善外汇衍生品和跨境人民币业务，进一步扩大跨境贸易人民币结算规模，更好满足外贸企业汇率避险和跨境人民币结算需求。支持各地方加强政策宣介、优化公共服务，推动银企精准对接、企业充分享惠。\n四、加快对外贸易创新发展\n（十一）稳定和提升加工贸易。\n强化用工、用能、信贷等要素保障，引导加工贸易向中西部、东北地区梯度转移，促进加工贸易持续健康发展和产业链供应链稳定。新认定一批国家加工贸易产业园。办好中国加工贸易产品博览会，支持东中西部产业交流对接。加快推进一批“两头在外”重点保税维修试点项目落地，强化全生命周期服务保障。\n（十二）完善边境贸易支持政策。\n做大沿边省份对外贸易。有力有序推进边民互市贸易进口商品落地加工试点工作。探索建设边民互市贸易进口商品数据监测平台。修订出台边民互市贸易管理办法，优化边民互市贸易多元化发展的政策环境，增加自周边国家进口。\n（十三）推进贸易数字化。\n支持大型外贸企业运用新技术自建数字平台，培育服务中小微外贸企业的第三方综合数字化解决方案供应商。支持粤港澳大湾区全球贸易数字化领航区发展，加快贸易全链条数字化赋能，充分发挥先行示范效应，适时总结发展经验。在粤港澳大湾区、长三角地区，2023—2025年每年遴选5—10个数字化推动贸易高质量发展的典型案例，并推广应用。\n（十四）发展绿色贸易。\n指导商协会等行业组织制订外贸产品绿色低碳标准，支持相关产品进一步开拓国际市场。组织开展重点行业企业培训，增强企业绿色低碳发展意识和能力。\n（十五）推动跨境电商健康持续创新发展。\n支持外贸企业通过跨境电商等新业态新模式拓展销售渠道、培育自主品牌。鼓励各地方结合产业和禀赋优势，创新建设跨境电商综合试验区，积极发展“跨境电商+产业带”模式，带动跨境电商企业对企业出口。加快出台跨境电商知识产权保护指南，引导跨境电商企业防范知识产权风险。建设跨境电商综合试验区线上综合服务平台并发挥好其作用，指导企业用好跨境电商零售出口相关税收政策措施。持续完善跨境电商综合试验区考核评估机制，做好评估结果应用，充分发挥优秀试点示范引领作用。\n五、优化外贸发展环境\n（十六）妥善应对国外不合理贸易限制措施。\n加强对地方和外贸企业的培训指导，对受影响的重点实体帮扶纾困。发挥好预警体系和法律服务机制作用，支持各级应对贸易摩擦工作站和预警点提升公共服务能力，帮助企业积极应对不合理贸易限制措施。发挥贸促机构作用，做好风险评估和排查。\n（十七）提升贸易便利化水平。\n深入推进“单一窗口”建设，扩大“联动接卸”、“船边直提”等措施应用范围，提高货物流转效率。稳步实施多元化税收担保，助力企业减负增效。加大对外贸企业的信用培育力度，使更多符合认证标准的外贸企业成为海关“经认证的经营者”（AEO）。进一步便利出口退税办理，推动实现出口退税申报报关单、发票“免填报”，更好服务广大外贸企业。各地方做好供需对接和统筹调度，健全应急运力储备，完善应急预案，保障外贸货物高效畅通运输。提升口岸通关效率、强化疏导分流、补齐通道短板、提升口岸过货能力。\n（十八）更好发挥自由贸易协定效能。\n高质量实施已生效的自由贸易协定，编发重点行业应用指南，深入开展《区域全面经济伙伴关系协定》（RCEP）等专题培训，组织论坛等多种形式的交流活动，加强地方和企业经验分享，提高对企业的公共服务水平，不断提升自由贸易协定的综合利用率。鼓励和指导地方组织面向RCEP等自由贸易伙伴的贸易促进活动。\n六、加强组织实施\n各地方、各相关部门和单位要以习近平新时代中国特色社会主义思想为指导，全面贯彻党的二十大精神，坚决落实党中央决策部署，高度重视、切实做好推动外贸稳规模优结构工作，全力实现进出口促稳提质目标任务。鼓励各地方因地制宜出台配套支持政策，增强政策协同效应。商务部要会同各相关部门和单位密切跟踪外贸运行情况，分析形势变化，针对不同领域实际问题，不断充实、调整和完善相关政策，加强协作配合和政策指导，实施好稳外贸政策组合拳，帮助企业稳订单拓市场。\n国务院办公厅\n2023年4月11日\n（本文有删减）\n扫一扫在手机打开当前页', '2022-12-03 16:00:00', '2026-04-16 11:25:13');
INSERT INTO `news_detail` VALUES (3, 892, 14, '合规与政策服务', '国务院关于同意在海南省暂时调整实施有关行政法规规定的批复', '', '', 'http://www.gov.cn/zhengce/content/2023-03/21/content_5747668.htm', 0, '', '{\"summary\": \"本文公布国务院对海南调整行政法规的批复，为海南出海相关市场主体提供政策方向参考\", \"abstract\": \"本文为国务院作出的关于同意海南省暂时调整实施有关行政法规规定的官方批复。本次批复同意海南对相关行政法规作出暂时调整，将助力海南进一步扩大对外开放，为出海相关企业在海南发展营造更灵活的政策空间，目前暂未公布具体调整的内容细节\", \"keywords\": [\"海南省\", \"行政法规调整\", \"政策批复\", \"对外开放\", \"合规调整\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院同意海南省暂时调整实施有关行政法规，未公布具体调整事项及适用领域细节\"}, \"topic_cluster\": \"合规与政策服务\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2023-03/21/content_5747668.htm\", \"title\": \"国务院关于同意在海南省暂时调整实施有关行政法规规定的批复\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院关于同意在海南省暂时调整实施有关行政法规规定的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在海南省暂时调整实施有关行政法规规定的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2023-03/21/content_5747668.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2023-03/21/content_5747668.htm\', \'published\': \'Fri, 02 Dec 2022 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2022, tm_mon=12, tm_mday=2, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=4, tm_yday=336, tm_isdst=0)}\", \"published_at\": \"2022-12-02 16:00:00\", \"ai_json_output\": \"\"}', '国务院关于同意在海南省暂时调整实施\n有关行政法规规定的批复\n国函〔2023〕23号\n海南省人民政府，海关总署、发展改革委、司法部、财政部、税务总局：\n你们关于优化海南离岛免税政策提货方式的请示收悉。现批复如下：\n一、同意在海南省暂时调整实施《中华人民共和国海关事务担保条例》的有关规定（目录附后），自2023年4月1日起对符合规定的离岛免税品可提交担保后提前放行。\n二、海关总署、海南省人民政府要根据上述调整，及时对本部门、本省制定的规章和规范性文件作相应调整，建立相适应的管理制度。\n三、国务院将根据有关政策在海南省的实施情况，适时对本批复的内容进行调整。\n附件：国务院决定在海南省暂时调整实施的有关行政法规规定目录\n国务院\n2023年3月3日\n（此件公开发布）\n附件\n国务院决定在海南省暂时调整实施的\n有关行政法规规定目录\n有关行政法规规定\n调整实施情况\n《中华人民共和国海关事务担保条例》\n第四条第一款　有下列情形之一的，当事人可以在办结海关手续前向海关申请提供担保，要求提前放行货物：\n（一）进出口货物的商品归类、完税价格、原产地尚未确定的；\n（二）有效报关单证尚未提供的；\n（三）在纳税期限内税款尚未缴纳的；\n（四）滞报金尚未缴纳的；\n（五）其他海关手续尚未办结的。\n对符合规定的离岛免税品可提交担保后提前放行。\n扫一扫在手机打开当前页', '2022-12-02 16:00:00', '2026-04-16 11:26:03');
INSERT INTO `news_detail` VALUES (4, 901, 14, '合规与政策服务', '国务院关于同意设立中国—菲律宾经贸创新发展示范园区的批复', '', '', 'http://www.gov.cn/zhengce/content/2023-01/19/content_5737967.htm', 0, '', '{\"summary\": \"帮助出海企业及时获悉中菲经贸合作新政策，把握布局菲律宾市场的新机遇\", \"abstract\": \"国务院正式批复同意设立中国—菲律宾经贸创新发展示范园区。该示范园区将推动中菲双边经贸领域的创新发展合作。它为中国企业出海投资菲律宾市场提供了官方认可的全新合作平台\", \"keywords\": [\"中菲经贸\", \"创新发展示范园区\", \"国务院批复\", \"出海投资\", \"双边经贸\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院批复同意设立中国—菲律宾经贸创新发展示范园区，为中企对菲出海合作提供政策支持\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2023-01/19/content_5737967.htm\", \"title\": \"国务院关于同意设立中国—菲律宾经贸创新发展示范园区的批复\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院关于同意设立中国—菲律宾经贸创新发展示范园区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意设立中国—菲律宾经贸创新发展示范园区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737967.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737967.htm\', \'published\': \'Wed, 30 Nov 2022 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2022, tm_mon=11, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=2, tm_yday=334, tm_isdst=0)}\", \"published_at\": \"2022-11-30 16:00:00\", \"ai_json_output\": \"\"}', '国务院关于同意设立中国—菲律宾\n经贸创新发展示范园区的批复\n国函〔2023〕3号\n福建省人民政府、商务部：\n你们关于设立中国—菲律宾经贸创新发展示范园区的请示收悉。现批复如下：\n一、同意在福建省漳州市设立中国—菲律宾经贸创新发展示范园区（以下简称示范园区）。原则同意示范园区建设总体方案，请认真组织实施。\n二、示范园区建设要以习近平新时代中国特色社会主义思想为指导，深入贯彻党的二十大精神，立足新发展阶段，完整、准确、全面贯彻新发展理念，加快构建新发展格局，统筹发展和安全，加强战略对接，对标高标准国际经贸规则，开展体制机制创新，深化中菲经贸合作，推动产业高效协同发展。要发挥与东盟国家经贸合作互补优势，探索产业链、供应链、价值链深度融合的国际分工合作模式，打造与东盟国家经贸合作交流新高地。\n三、福建省人民政府要切实加强组织领导，健全机制、明确分工、落实责任，有效推进示范园区建设发展。要尽快制定、完善具体实施方案并抓好组织实施。示范园区建设应符合国土空间规划，涉及的重大政策和建设项目按程序报批。\n四、国务院有关部门要按照职能分工，加强指导和服务，支持示范园区建设发展。商务部要会同有关部门加强统筹协调、跟踪评估和督促检查，注重总结经验。重大问题及时向国务院报告。\n国务院\n2023年1月11日\n（此件公开发布）\n扫一扫在手机打开当前页', '2022-11-30 16:00:00', '2026-04-16 11:27:08');
INSERT INTO `news_detail` VALUES (5, 902, 14, '合规与政策服务', '国务院关于同意设立中国—印度尼西亚经贸创新发展示范园区的批复', '', '', 'http://www.gov.cn/zhengce/content/2023-01/19/content_5737964.htm', 0, '', '{\"summary\": \"本文为中国企业出海印尼提供官方政策依据，助力企业把握中印尼经贸合作新机遇\", \"abstract\": \"国务院正式发布批复，同意设立中国—印度尼西亚经贸创新发展示范园区。该示范园区是中印尼经贸创新合作的重要载体，将为中国企业出海布局印尼提供有力支撑。此举将进一步推动两国双边经贸往来的深化发展。\", \"keywords\": [\"中印尼经贸合作\", \"经贸创新发展示范园区\", \"国务院批复\", \"企业出海\", \"印尼市场\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院批复同意设立中国—印度尼西亚经贸创新发展示范园区，为中企出海印尼提供官方认可的合作平台\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2023-01/19/content_5737964.htm\", \"title\": \"国务院关于同意设立中国—印度尼西亚经贸创新发展示范园区的批复\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院关于同意设立中国—印度尼西亚经贸创新发展示范园区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意设立中国—印度尼西亚经贸创新发展示范园区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737964.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2023-01/19/content_5737964.htm\', \'published\': \'Wed, 30 Nov 2022 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2022, tm_mon=11, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=2, tm_yday=334, tm_isdst=0)}\", \"published_at\": \"2022-11-30 16:00:00\", \"ai_json_output\": \"\"}', '国务院关于同意设立中国—印度尼西亚\n经贸创新发展示范园区的批复\n国函〔2023〕2号\n福建省人民政府、商务部：\n你们关于设立中国—印度尼西亚经贸创新发展示范园区的请示收悉。现批复如下：\n一、同意在福建省福州市设立中国—印度尼西亚经贸创新发展示范园区（以下简称示范园区）。原则同意示范园区建设总体方案，请认真组织实施。\n二、示范园区建设要以习近平新时代中国特色社会主义思想为指导，深入贯彻党的二十大精神，立足新发展阶段，完整、准确、全面贯彻新发展理念，加快构建新发展格局，统筹发展和安全，加强战略对接，对标高标准国际经贸规则，开展体制机制创新，深化中印尼经贸合作，推动产业高效协同发展。要发挥与东盟国家经贸合作互补优势，探索产业链、供应链、价值链深度融合的国际分工合作模式，打造与东盟国家经贸合作交流新高地。\n三、福建省人民政府要切实加强组织领导，健全机制、明确分工、落实责任，有效推进示范园区建设发展。要尽快制定、完善具体实施方案并抓好组织实施。示范园区建设应符合国土空间规划，涉及的重大政策和建设项目按程序报批。\n四、国务院有关部门要按照职能分工，加强指导和服务，支持示范园区建设发展。商务部要会同有关部门加强统筹协调、跟踪评估和督促检查，注重总结经验。重大问题及时向国务院报告。\n国务院\n2023年1月11日\n（此件公开发布）\n扫一扫在手机打开当前页', '2022-11-30 16:00:00', '2026-04-16 11:27:55');
INSERT INTO `news_detail` VALUES (6, 910, 14, '合规与政策服务', '国务院关于同意在沈阳等6个城市开展服务业扩大开放综合试点的批复', '', '', 'http://www.gov.cn/zhengce/content/2022-12/20/content_5732723.htm', 0, '', '{\"summary\": \"本文公布国务院批复同意沈阳等6个城市开展服务业扩大开放综合试点，为出海服务业企业把握政策利好提供参考\", \"abstract\": \"国务院发布批复，同意在沈阳等6个城市开展服务业扩大开放综合试点。该试点是我国推进服务业领域对外开放的重要举措。相关企业可依托试点政策探索对外开放新机遇，助力自身出海发展。\", \"keywords\": [\"服务业扩大开放\", \"综合试点\", \"对外开放\", \"国务院批复\", \"出海政策\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院同意沈阳等6个城市开展服务业扩大开放综合试点，推进服务业领域对外开放\"}, \"topic_cluster\": \"合规与政策服务\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2022-12/20/content_5732723.htm\", \"title\": \"国务院关于同意在沈阳等6个城市开展服务业扩大开放综合试点的批复\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院关于同意在沈阳等6个城市开展服务业扩大开放综合试点的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在沈阳等6个城市开展服务业扩大开放综合试点的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-12/20/content_5732723.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-12/20/content_5732723.htm\', \'published\': \'Mon, 01 Nov 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=11, tm_mday=1, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=0, tm_yday=305, tm_isdst=0)}\", \"published_at\": \"2021-11-01 16:00:00\", \"ai_json_output\": \"\"}', '国务院关于同意在沈阳等6个城市\n开展服务业扩大开放综合试点的批复\n国函〔2022〕135号\n辽宁省、江苏省、浙江省、湖北省、广东省、四川省人民政府，商务部：\n你们关于开展服务业扩大开放综合试点的请示收悉。现批复如下：\n一、同意在沈阳市、南京市、杭州市、武汉市、广州市、成都市（以下称六城市）开展服务业扩大开放综合试点，试点期为自批复之日起3年。原则同意六城市服务业扩大开放综合试点总体方案，请认真组织实施。\n二、试点要以习近平新时代中国特色社会主义思想为指导，深入贯彻党的二十大精神，统筹推进“五位一体”总体布局，协调推进“四个全面”战略布局，按照党中央、国务院决策部署，完整、准确、全面贯彻新发展理念，稳步扩大规则、规制、管理、标准等制度型开放，紧紧围绕本地区发展定位，进一步推进服务业改革开放，加快发展现代服务业，塑造国际竞争和合作新优势，为加快构建新发展格局、推动高质量发展作出贡献。\n三、有关省级人民政府要加强对服务业扩大开放综合试点工作的组织领导，在风险可控的前提下，精心组织，大胆实践，服务国家重大战略，开展差异化探索，在加快发展现代产业体系、推进高水平对外开放等方面取得更多可复制可推广的经验，为全国服务业的开放发展、创新发展发挥示范带动作用。\n四、国务院有关部门要按照职责分工，积极支持六城市开展服务业扩大开放综合试点。商务部要会同有关部门加强指导和协调推进，组织开展成效评估，确保各项改革开放措施落实到位。\n五、需要暂时调整实施相关行政法规、国务院文件和经国务院批准的部门规章的部分规定的，按规定程序办理。国务院有关部门相应调整本部门制定的规章和规范性文件。试点中的重大问题，有关省级人民政府和商务部要及时向国务院请示报告。\n国务院\n2022年12月3日\n（此件公开发布）\n扫一扫在手机打开当前页', '2021-11-01 16:00:00', '2026-04-16 11:29:11');
INSERT INTO `news_detail` VALUES (7, 911, 11, '服务与基建', '国务院办公厅关于印发“十四五”现代物流发展规划的通知', '', '', 'http://www.gov.cn/zhengce/content/2022-12/15/content_5732092.htm', 0, '', '{\"summary\": \"帮助出海物流相关企业获取国家现代物流发展顶层政策，明确行业发展方向\", \"abstract\": \"这是国务院办公厅印发“十四五”现代物流发展规划的官方通知。该规划是我国“十四五”期间现代物流领域发展的顶层设计文件。将指引国内物流体系建设，也为出海相关跨境物流发展提供政策支撑。\", \"keywords\": [\"十四五规划\", \"现代物流\", \"物流发展\", \"跨境物流\", \"顶层政策\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院办公厅印发《“十四五”现代物流发展规划》，出台现代物流发展顶层政策规划\"}, \"topic_cluster\": \"供应链物流\", \"industry_category\": \"服务与基建\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2022-12/15/content_5732092.htm\", \"title\": \"国务院办公厅关于印发“十四五”现代物流发展规划的通知\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院办公厅关于印发“十四五”现代物流发展规划的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于印发“十四五”现代物流发展规划的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-12/15/content_5732092.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-12/15/content_5732092.htm\', \'published\': \'Mon, 01 Nov 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=11, tm_mday=1, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=0, tm_yday=305, tm_isdst=0)}\", \"published_at\": \"2021-11-01 16:00:00\", \"ai_json_output\": \"\"}', '国务院办公厅关于印发\n“十四五”现代物流发展规划的通知\n国办发〔2022〕17号\n各省、自治区、直辖市人民政府，国务院各部委、各直属机构：\n《“十四五”现代物流发展规划》已经国务院同意，现印发给你们，请认真贯彻执行。\n国务院办公厅\n2022年5月17日\n（本文有删减）\n“十四五”现代物流发展规划\n现代物流一头连着生产，一头连着消费，高度集成并融合运输、仓储、分拨、配送、信息等服务功能，是延伸产业链、提升价值链、打造供应链的重要支撑，在构建现代流通体系、促进形成强大国内市场、推动高质量发展、建设现代化经济体系中发挥着先导性、基础性、战略性作用。“十三五”以来，我国现代物流发展取得积极成效，服务质量效益明显提升，政策环境持续改善，对国民经济发展的支撑保障作用显著增强。为贯彻落实党中央、国务院关于构建现代物流体系的决策部署，根据《中华人民共和国国民经济和社会发展第十四个五年规划和2035年远景目标纲要》，经国务院同意，制定本规划。\n一、现状形势\n（一）发展基础。\n物流规模效益持续提高。\n“十三五”期间，社会物流总额保持稳定增长，2020年超过300万亿元，年均增速达5.6%。公路、铁路、内河、民航、管道运营里程以及货运量、货物周转量、快递业务量均居世界前列，规模以上物流园区达到2000个左右。社会物流成本水平稳步下降，2020年社会物流总费用与国内生产总值的比率降至14.7%，较2015年下降1.3个百分点。\n物流资源整合提质增速。\n国家物流枢纽、国家骨干冷链物流基地、示范物流园区等重大物流基础设施建设稳步推进。物流要素与服务资源整合步伐加快，市场集中度提升，中国物流企业50强2020年业务收入较2015年增长超过30%。航运企业加快重组，船队规模位居世界前列。民航货运领域混合所有制改革深入推进，资源配置进一步优化。\n物流结构调整加快推进。\n物流区域发展不平衡状况有所改善，中西部地区物流规模增速超过全国平均水平。运输结构加快调整，铁路货运量占比稳步提升，多式联运货运量年均增速超过20%。仓储结构逐步优化，高端标准仓库、智能立体仓库快速发展。快递物流、冷链物流、农村物流、即时配送等发展步伐加快，有力支撑和引领消费结构升级。\n科技赋能促进创新发展。\n移动互联网、大数据、云计算、物联网等新技术在物流领域广泛应用，网络货运、数字仓库、无接触配送等“互联网+”高效物流新模式新业态不断涌现。自动分拣系统、无人仓、无人码头、无人配送车、物流机器人、智能快件箱等技术装备加快应用，高铁快运动车组、大型货运无人机、无人驾驶卡车等起步发展，快递电子运单、铁路货运票据电子化得到普及。\n国际物流网络不断延展。\n我国国际航运、航空物流基本通达全球主要贸易合作伙伴。截至2020年底，中欧班列通达欧洲20多个国家的90多个城市，累计开行超过3万列，在深化我国与共建“一带一路”国家经贸合作、应对新冠肺炎疫情和推进复工复产中发挥了国际物流大动脉作用。企业海外仓、落地配加快布局，境外物流网络服务能力稳步提升。\n营商环境持续改善。\n推动现代物流发展的一系列规划和政策措施出台实施，特别是物流降本增效政策持续发力，“放管服”改革与减税降费等取得实效。物流市场监测、监管水平明显提升，政务服务质量和效率大幅改善。物流标准、统计、教育、培训等支撑保障体系进一步完善，物流诚信体系建设加快推进，行业治理能力稳步提升。\n（二）突出问题。\n物流降本增效仍需深化。\n全国统一大市场尚不健全，物流资源要素配置不合理、利用不充分。多式联运体系不完善，跨运输方式、跨作业环节衔接转换效率较低，载运单元标准化程度不高，全链条运行效率低、成本高。\n结构性失衡问题亟待破局。\n存量物流基础设施网络“东强西弱”、“城强乡弱”、“内强外弱”，对新发展格局下产业布局、内需消费的支撑引领能力不够。物流服务供给对需求的适配性不强，低端服务供给过剩、中高端服务供给不足。货物运输结构还需优化，大宗货物公路中长距离运输比重仍然较高。\n大而不强问题有待解决。\n物流产业规模大但规模经济效益释放不足，特别是公路货运市场同质化竞争、不正当竞争现象较为普遍，集约化程度有待提升。现代物流体系组织化、集约化、网络化、社会化程度不高，国家层面的骨干物流基础设施网络不健全，缺乏具有全球竞争力的现代物流企业，与世界物流强国相比仍存在差距。\n部分领域短板较为突出。\n大宗商品储备设施以及农村物流、冷链物流、应急物流、航空物流等专业物流和民生保障领域物流存在短板。现代物流嵌入产业链深度广度不足，供应链服务保障能力不够，对畅通国民经济循环的支撑能力有待增强。行业协同治理水平仍需提升。\n（三）面临形势。\n统筹国内国际两个大局要求强化现代物流战略支撑引领能力。\n中华民族伟大复兴战略全局与世界百年未有之大变局历史性交汇，新冠肺炎疫情、俄乌冲突影响广泛深远，全球产业链供应链加速重构，要求现代物流对内主动适应社会主要矛盾变化，更好发挥连接生产消费、畅通国内大循环的支撑作用；对外妥善应对错综复杂国际环境带来的新挑战，为推动国际经贸合作、培育国际竞争新优势提供有力保障。\n建设现代产业体系要求提高现代物流价值创造能力。\n发展壮大战略性新兴产业，促进服务业繁荣发展，要求现代物流适应现代产业体系对多元化专业化服务的需求，深度嵌入产业链供应链，促进实体经济降本增效，提升价值创造能力，推进产业基础高级化、产业链现代化。\n实施扩大内需战略要求发挥现代物流畅通经济循环作用。\n坚持扩大内需战略基点，加快培育完整内需体系，要求加快构建适应城乡居民消费升级需要的现代物流体系，提升供给体系对内需的适配性，以高质量供给引领、创造和扩大新需求。\n新一轮科技革命要求加快现代物流技术创新与业态升级。\n现代信息技术、新型智慧装备广泛应用，现代产业体系质量、效率、动力变革深入推进，既为物流创新发展注入新活力，也要求加快现代物流数字化、网络化、智慧化赋能，打造科技含量高、创新能力强的智慧物流新模式。\n二、总体要求\n（一）指导思想。\n以习近平新时代中国特色社会主义思想为指导，坚持稳中求进工作总基调，完整、准确、全面贯彻新发展理念，加快构建新发展格局，全面深化改革开放，坚持创新驱动发展，推动高质量发展，坚持以供给侧结构性改革为主线，统筹疫情防控和经济社会发展，统筹发展和安全，提升产业链供应链韧性和安全水平，推动构建现代物流体系，推进现代物流提质、增效、降本，为建设现代产业体系、形成强大国内市场、推动高水平对外开放提供有力支撑。\n（二）基本原则。\n——市场主导、政府引导。\n充分发挥市场在资源配置中的决定性作用，激发市场主体创新发展活力，提高物流要素配置效率和效益。更好发挥政府作用，加强战略规划和政策引导，推动形成规范高效、公平竞争、统一开放的物流市场，强化社会民生物流保障。\n——系统观念、统筹推进。\n统筹谋划物流设施建设、服务体系构建、技术装备升级、业态模式创新，促进现代物流与区域、产业、消费、城乡协同布局，构建支撑国内国际双循环的物流服务体系，实现物流网络高效联通。\n——创新驱动、联动融合。\n以数字化、网络化、智慧化为牵引，深化现代物流与制造、贸易、信息等融合创新发展，推动形成需求牵引供给、供给创造需求的良性互动和更高水平动态平衡。\n——绿色低碳、安全韧性。\n将绿色环保理念贯穿现代物流发展全链条，提升物流可持续发展能力。坚持总体国家安全观，提高物流安全治理水平，完善应急物流体系，提高重大疫情等公共卫生事件、突发事件应对处置能力，促进产业链供应链稳定。\n（三）主要目标。\n到2025年，基本建成供需适配、内外联通、安全高效、智慧绿色的现代物流体系。\n——物流创新发展能力和企业竞争力显著增强。\n物流数字化转型取得显著成效，智慧物流应用场景更加丰富。物流科技创新能力不断增强，产学研结合机制进一步完善，建设一批现代物流科创中心和国家工程研究中心。铁路、民航等领域体制改革取得显著成效，市场活力明显增强，形成一批具有较强国际竞争力的骨干物流企业和知名服务品牌。\n——物流服务质量效率明显提升。\n跨物流环节衔接转换、跨运输方式联运效率大幅提高，社会物流总费用与国内生产总值的比率较2020年下降2个百分点左右。多式联运、铁路（高铁）快运、内河水运、大宗商品储备设施、农村物流、冷链物流、应急物流、航空物流、国际寄递物流等重点领域补短板取得明显成效。通关便利化水平进一步提升，城乡物流服务均等化程度明显提高。\n——“通道+枢纽+网络”运行体系基本形成。\n衔接国家综合立体交通网主骨架，完成120个左右国家物流枢纽、100个左右国家骨干冷链物流基地布局建设，基本形成以国家物流枢纽为核心的骨干物流基础设施网络。物流干支仓配一体化运行更加顺畅，串接不同运输方式的多元化国际物流通道逐步完善，畅联国内国际的物流服务网络更加健全。枢纽经济发展取得成效，建设20个左右国家物流枢纽经济示范区。\n——安全绿色发展水平大幅提高。\n提高重大疫情、自然灾害等紧急情况下物流对经济社会运行的保障能力。冷链物流全流程监测能力大幅增强，生鲜产品冷链流通率显著提升。货物运输结构进一步优化，铁路货运量占比较2020年提高0.5个百分点，集装箱铁水联运量年均增长15%以上，铁路、内河集装箱运输比重和集装箱铁水联运比重大幅上升。面向重点品类的逆向物流体系初步建立，资源集约利用水平明显提升。清洁货运车辆广泛应用，绿色包装应用取得明显成效，物流领域节能减排水平显著提高。\n——现代物流发展制度环境更加完善。\n物流标准规范体系进一步健全，标准化、集装化、单元化物流装载器具和包装基础模数广泛应用。社会物流统计体系、信用体系更加健全，营商环境持续优化，行业协同治理体系不断完善、治理能力显著提升。\n展望2035年，现代物流体系更加完善，具有国际竞争力的一流物流企业成长壮大，通达全球的物流服务网络更加健全，对区域协调发展和实体经济高质量发展的支撑引领更加有力，为基本实现社会主义现代化提供坚实保障。\n三、精准聚焦现代物流发展重点方向\n（一）加快物流枢纽资源整合建设。\n深入推进国家物流枢纽建设，补齐内陆地区枢纽设施结构和功能短板，加强业务协同、政策协调、运行协作，加快推动枢纽互联成网。加强国家物流枢纽铁路专用线、联运转运设施建设，有效衔接多种运输方式，强化多式联运组织能力，实现枢纽间干线运输密切对接。依托国家物流枢纽整合区域物流设施资源，引导应急储备、分拨配送等功能设施集中集约布局，支持各类物流中心、配送设施、专业市场等与国家物流枢纽功能对接、联动发展，促进物流要素规模集聚和集成运作。\n专栏\n1\n国家物流枢纽建设工程\n优化国家物流枢纽布局，实现东中西部物流枢纽基本均衡分布。发挥国家物流枢纽联盟组织协调作用，建立物流标准衔接、行业动态监测等机制，探索优势互补、资源共享、业务协同合作模式，形成稳定完善的国家物流枢纽合作机制。积极推进国家级示范物流园区数字化、智慧化、绿色化改造。\n（二）构建国际国内物流大通道。\n依托国家综合立体交通网和主要城市群、沿海沿边口岸城市等，促进国家物流枢纽协同建设和高效联动，构建国内国际紧密衔接、物流要素高效集聚、运作服务规模化的“四横五纵、两沿十廊”物流大通道。“四横五纵”国内物流大通道建设，要畅通串接东中西部的沿黄、陆桥、长江、广昆等物流通道和联接南北方的京沪、京哈—京港澳（台）、二连浩特至北部湾、西部陆海新通道、进出藏等物流通道，提升相关城市群、陆上口岸城市物流综合服务能力和规模化运行效率。加快“两沿十廊”国际物流大通道建设，对接区域全面经济伙伴关系协定（RCEP）等，强化服务共建“一带一路”的多元化国际物流通道辐射能力。\n（三）完善现代物流服务体系。\n围绕做优服务链条、做强服务功能、做好供应链协同，完善集约高效的现代物流服务体系，支撑现代产业体系升级，推动产业迈向全球价值链中高端。加快运输、仓储、配送、流通加工、包装、装卸等领域数字化改造、智慧化升级和服务创新，补齐农村物流、冷链物流、应急物流、航空物流等专业物流短板，增强专业物流服务能力，推动现代物流向供应链上下游延伸。\n（四）延伸物流服务价值链条。\n把握物流需求多元化趋势，加强现代物流科技赋能和创新驱动，推进现代物流服务领域拓展和业态模式创新。发挥现代物流串接生产消费作用，与先进制造、现代商贸、现代农业融合共创产业链增值新空间。提高物流网络对经济要素高效流动的支持能力，引导产业集群发展和经济合理布局，推动跨区域资源整合、产业链联动和价值协同创造，发展枢纽经济、通道经济新形态，培育区域经济新增长点。\n（五）强化现代物流对社会民生的服务保障。\n围绕更好满足城乡居民生活需要，适应扩大内需、消费升级趋势，优化完善商贸、快递物流网络。完善城市特别是超大特大城市物流设施网络，健全分级配送体系，实现干线、支线物流和末端配送有机衔接、一体化运作，加强重点生活物资保障能力。补齐农村物流设施和服务短板，推动快递服务基本实现直投到建制村，支撑扩大优质消费品供给。加快建立覆盖冷链物流全链条的动态监测和追溯体系，保障食品药品消费安全。鼓励发展物流新业态新模式，创造更多就业岗位，保障就业人员权益，促进灵活就业健康发展。\n（六）提升现代物流安全应急能力。\n统筹发展和安全，强化重大物流基础设施安全和信息安全保护，提升战略物资、应急物流、国际供应链等保障水平，增强经济社会发展韧性。健全大宗商品物流体系。加快构建全球供应链物流服务网络，保持产业链供应链稳定。充分发挥社会物流作用，推动建立以企业为主体的应急物流队伍。\n四、加快培育现代物流转型升级新动能\n（一）推动物流提质增效降本。\n促进全链条降成本。\n推动解决跨运输方式、跨作业环节瓶颈问题，打破物流“中梗阻”。依托国家物流枢纽、国家骨干冷链物流基地等重大物流基础设施，提高干线运输规模化水平和支线运输网络化覆盖面，完善末端配送网点布局，扩大低成本、高效率干支仓配一体化物流服务供给。鼓励物流资源共享，整合分散的运输、仓储、配送能力，发展共建船队车队、共享仓储、共同配送、统仓统配等组织模式，提高资源利用效率。推动干支仓配一体化深度融入生产和流通，带动生产布局和流通体系调整优化，减少迂回、空驶等低效无效运输，加快库存周转，减少社会物流保管和管理费用。\n推进结构性降成本。\n加快推进铁路专用线进港区、连园区、接厂区，合理有序推进大宗商品等中长距离运输“公转铁”、“公转水”。完善集装箱公铁联运衔接设施，鼓励发展集拼集运、模块化运输、“散改集”等组织模式，发挥铁路干线运输成本低和公路网络灵活优势，培育有竞争力的“门到门”公铁联运服务模式，降低公铁联运全程物流成本。统筹沿海港口综合利用，提升大型港口基础设施服务能力，提高码头现代化专业化规模化水平，加快推进铁水联运衔接场站改造，提高港口铁路专用线集疏网络效能，优化作业流程。完善内河水运网络，统筹江海直达、江海联运发展，发挥近海航线、长江水道、珠江水道等水运效能，稳步推进货物运输“公转水”。推进铁水联运业务单证电子化，促进铁路、港口信息互联，实现铁路现车、装卸车、货物在途、到达预确报以及港口装卸、货物堆存、船舶进出港、船期舱位预定等铁水联运信息交换共享。支持港口、铁路场站加快完善集疏运油气管网，有效对接石化等产业布局，提高管道运输比例。\n专栏\n2\n铁路物流升级改造工程\n大力组织班列化货物列车开行，扩大铁路\n“点对点”直达货运服务规模，在运量较大的物流枢纽、口岸、港口间组织开行技术直达列车，形成“核心节点+通道+班列”的高效物流组织体系，增强铁路服务稳定性和时效性。有序推动城市中心城区既有铁路货场布局调整，或升级改造转型为物流配送中心。到2025年，沿海主要港口、大宗货物年运量150万吨以上的大型工矿企业、新建物流园区等的铁路专用线接入比例力争达到85%左右，长江干线主要港口全面实现铁路进港。\n（二）促进物流业与制造业深度融合。\n促进企业协同发展。\n支持物流企业与制造企业创新供应链协同运营模式，将物流服务深度嵌入制造供应链体系，提供供应链一体化物流解决方案，增强制造企业柔性制造、敏捷制造能力。引导制造企业与物流企业建立互利共赢的长期战略合作关系，共同投资专用物流设施建设和物流器具研发，提高中长期物流合同比例，制定制造业物流服务标准，提升供应链协同效率。鼓励具备条件的制造企业整合对接分散的物流服务能力和资源，实现规模化组织、专业化服务、社会化协同。\n推动设施联动发展。\n加强工业园区、产业集群与国家物流枢纽、物流园区、物流中心等设施布局衔接、联动发展。支持工业园区等新建或改造物流基础设施，吸引第三方物流企业进驻并提供专业化、社会化物流服务。发展生产服务型国家物流枢纽，完善第三方仓储、铁路专用线等物流设施，面向周边制造企业提供集成化供应链物流服务，促进物流供需规模化对接，减少物流设施重复建设和闲置。\n支持生态融合发展。\n统筹推进工业互联网和智慧物流体系同步设计、一体建设、协同运作，加大智能技术装备在制造业物流领域应用，推进关键物流环节和流程智慧化升级。打造制造业物流服务平台，促进制造业供应链上下游企业加强采购、生产、流通等环节信息实时采集、互联共享，实现物流资源共享和过程协同，提高生产制造和物流服务一体化运行水平，形成技术驱动、平台赋能的物流业制造业融合发展新生态。\n专栏\n3\n物流业制造业融合创新工程\n在重点领域梳理一批物流业制造业深度融合创新发展典型案例，培育一批物流业制造业融合创新模式、代表性企业和知名品牌。鼓励供应链核心企业发起成立物流业制造业深度融合创新发展联盟，开展流程优化、信息共享、技术共创和业务协同等创新。研究制定物流业制造业融合发展行业标准，开展制造企业物流成本核算对标。\n（三）强化物流数字化科技赋能。\n加快物流数字化转型。\n利用现代信息技术推动物流要素在线化数据化，开发多样化应用场景，实现物流资源线上线下联动。结合实施“东数西算”工程，引导企业信息系统向云端跃迁，推动“一站式”物流数据中台应用，鼓励平台企业和数字化服务商开发面向中小微企业的云平台、云服务，加强物流大数据采集、分析和应用，提升物流数据价值。培育物流数据要素市场，统筹数据交互和安全需要，完善市场交易规则，促进物流数据安全高效流通。积极参与全球物流领域数字治理，支撑全球贸易和跨境电商发展。研究电子签名和电子合同应用，促进国际物流企业间互认互验，试点铁路国际联运无纸化。\n推进物流智慧化改造。\n深度应用第五代移动通信（5G）、北斗、移动互联网、大数据、人工智能等技术，分类推动物流基础设施改造升级，加快物联网相关设施建设，发展智慧物流枢纽、智慧物流园区、智慧仓储物流基地、智慧港口、数字仓库等新型物流基础设施。鼓励智慧物流技术与模式创新，促进创新成果转化，拓展智慧物流商业化应用场景，促进自动化、无人化、智慧化物流技术装备以及自动感知、自动控制、智慧决策等智慧管理技术应用。加快高端标准仓库、智慧立体仓储设施建设，研发推广面向中小微企业的低成本、模块化、易使用、易维护智慧装备。\n促进物流网络化升级。\n依托重大物流基础设施打造物流信息组织中枢，推动物流设施设备全面联网，实现作业流程透明化、智慧设备全连接，促进物流信息交互联通。推动大型物流企业面向中小微企业提供多样化、数字化服务，稳步发展网络货运、共享物流、无人配送、智慧航运等新业态。鼓励在有条件的城市搭建智慧物流“大脑”，全面链接并促进城市物流资源共享，优化城市物流运行，建设智慧物流网络。推动物流领域基础公共信息数据有序开放，加强物流公共信息服务平台建设，推动企业数据对接，面向物流企业特别是中小微物流企业提供普惠性服务。\n专栏\n4\n数字物流创新提质工程\n加强物流公共信息服务平台建设，在确保信息安全的前提下，推动交通运输、公安交管、市场监管等政府部门和铁路、港口、航空等企事业单位向社会开放与物流相关的公共数据，推进公共数据共享。利用现代信息技术搭建数字化、网络化、协同化物流第三方服务平台，推出一批便捷高效、成本经济的云服务平台和数字化解决方案，推广一批先进数字技术装备。推动物流企业\n“上云用数赋智”，树立一批数字化转型标杆企业。\n（四）推动绿色物流发展。\n深入推进物流领域节能减排。\n加强货运车辆适用的充电桩、加氢站及内河船舶适用的岸电设施、液化天然气（LNG）加注站等配套布局建设，加快新能源、符合国六排放标准等货运车辆在现代物流特别是城市配送领域应用，促进新能源叉车在仓储领域应用。继续加大柴油货车污染治理力度，持续推进运输结构调整，提高铁路、水路运输比重。推动物流企业强化绿色节能和低碳管理，推广合同能源管理模式，积极开展节能诊断。加强绿色物流新技术和设备研发应用，推广使用循环包装，减少过度包装和二次包装，促进包装减量化、再利用。加快标准化物流周转箱推广应用，推动托盘循环共用系统建设。\n加快健全逆向物流服务体系。\n探索符合我国国情的逆向物流发展模式，鼓励相关装备设施建设和技术应用，推进标准制定、检测认证等基础工作，培育专业化逆向物流服务企业。支持国家物流枢纽率先开展逆向物流体系建设，针对产品包装、物流器具、汽车以及电商退换货等，建立线上线下融合的逆向物流服务平台和网络，创新服务模式和场景，促进产品回收和资源循环利用。\n专栏\n5\n绿色低碳物流创新工程\n依托行业协会等第三方机构，开展绿色物流企业对标贯标达标活动，推广一批节能低碳技术装备，创建一批绿色物流枢纽、绿色物流园区。在运输、仓储、配送等环节积极扩大电力、氢能、天然气、先进生物液体燃料等新能源、清洁能源应用。加快建立天然气、氢能等清洁能源供应和加注体系。\n（五）做好供应链战略设计。\n提升现代供应链运行效率。\n推进重点产业供应链体系建设，发挥供应链核心企业组织协同管理优势，搭建供应链协同服务平台，提供集贸易、物流、信息等多样化服务于一体的供应链创新解决方案，打造上下游有效串接、分工协作的联动网络。加强数字化供应链前沿技术、基础软件、先进模式等研究与推广，探索扩大区块链技术应用，提高供应链数字化效率和安全可信水平。规范发展供应链金融，鼓励银行等金融机构在依法合规、风险可控的前提下，加强与供应链核心企业或平台企业合作，丰富创新供应链金融产品供给。\n强化现代供应链安全韧性。\n坚持自主可控、安全高效，加强供应链安全风险监测、预警、防控、应对等能力建设。发挥供应链协同服务平台作用，引导行业、企业间加强供应链安全信息共享和资源协同联动，分散化解潜在风险，增强供应链弹性，确保产业链安全。积极参与供应链安全国际合作，共同防范应对供应链中断风险。\n专栏\n6\n现代供应链体系建设工程\n现代供应链创新发展工程。\n总结供应链创新与应用试点工作经验，开展全国供应链创新与应用示范创建，培育一批示范城市和示范企业，梳理一批供应链创新发展典型案例，推动供应链技术、标准和服务模式创新。\n制造业供应链提升工程。\n健全制造业供应链服务体系，促进生产制造、原材料供应、物流等企业在供应链层面强化战略合作。建立制造业供应链评价体系、重要资源和产品全球供应链风险预警系统。提升制造业供应链智慧化水平，建设以工业互联网为核心的数字化供应链服务体系，深化工业互联网标识解析体系应用。选择一批企业竞争力强、全球化程度高的行业，深入挖掘数字化应用场景，开展制造业供应链数字化创新应用示范工程。\n（六）培育发展物流经济。\n壮大物流枢纽经济。\n发挥国家物流枢纽、国家骨干冷链物流基地辐射广、成本低、效率高等优势条件，推动现代物流和相关产业深度融合创新发展，促进区域产业空间布局优化，打造具有区域集聚辐射能力的产业集群，稳妥有序开展国家物流枢纽经济示范区建设。\n发展物流通道经济。\n围绕共建“一带一路”、长江经济带发展等重大战略实施和西部陆海新通道建设，提升“四横五纵、两沿十廊”物流大通道沿线物流基础设施支撑和服务能力，密切通道经济联系，优化通道沿线产业布局与分工合作体系，提高产业组织和要素配置能力。\n五、深度挖掘现代物流重点领域潜力\n（一）加快国际物流网络化发展。\n推进国际通道网络建设。\n强化国家物流枢纽等的国际物流服务设施建设，完善通关等功能，加强国际、国内物流通道衔接，推动国际物流基础设施互联互通。推动商贸物流型境外经贸合作区建设，优化海外布局，扩大辐射范围。巩固提升中欧班列等国际铁路运输组织水平，推动跨境公路运输发展，加快构建高效畅通的多元化国际物流干线通道。积极推进海外仓建设，加快健全标准体系。鼓励大型物流企业开展境外港口、海外仓、分销网络建设合作和协同共享，完善全球物流服务网络。\n补齐国际航空物流短板。\n依托空港型国家物流枢纽，集聚整合国际航空物流货源，完善配套服务体系，打造一体化运作的航空物流服务平台，提供高品质“一站式”国际航空物流服务。加快培育规模化、专业化、网络化的国际航空物流骨干企业，优化国际航空客运航线客机腹舱运力配置，增强全货机定班国际航线和包机组织能力，逐步形成优质高效的国际航空物流服务体系，扩大国际航空物流网络覆盖范围，建设覆盖重点产业布局的国际货运通道。\n培育国际航运竞争优势。\n加密国际海运航线，打造国际航运枢纽港，提升国际航运服务能力，强化国际中转功能，拓展国际金融、国际贸易等综合服务。加快推进长三角世界级港口群一体化治理体系建设。加强港口与内陆物流枢纽等联动，发展海铁联运、江海联运，扩大港口腹地辐射范围。鼓励港航企业与货主企业、贸易企业加强战略合作，延伸境外末端服务网络。\n提高国际物流综合服务能力。\n优化完善中欧班列开行方案统筹协调和动态调整机制，加快建设中欧班列集结中心，完善海外货物集散网络，推动中欧班列双向均衡运输，提高货源集结与班列运行效率。加快国际航运、航空与中欧班列、西部陆海新通道国际海铁联运班列等协同联动，提升国际旅客列车行包运输能力，开行客车化跨境班列，构建多样化国际物流服务体系。提高重点边境铁路口岸换装和通行能力，推动边境水运口岸综合开发和国际航道物流合作，提升边境公路口岸物流能力。推进跨境物流单证规则、检验检疫、认证认可、通关报关等标准衔接和国际互认合作。\n专栏\n7\n国际物流网络畅通工程\n国际物流设施提升工程。\n培育一批具备区域和国际中转能力的海港、陆港、空港。发挥国家物流枢纽资源整合优势，加快中欧班列集结中心建设，完善物流中转配套能力，加快形成\n“干支结合、枢纽集散”的高效集疏运体系；开展航空货运枢纽规划布局研究，提升综合性机场货运设施服务能力和服务质量，稳妥有序推进专业性航空货运枢纽机场建设。\n西部陆海新通道增量提质工程。\n发挥西部陆海新通道班列运输协调委员会作用，提升通道物流服务水平。加强通道物流组织模式创新，推动通道沿线物流枢纽与北部湾港口协同联动，促进海铁联运班列提质增效。推动通道海铁联运、国际铁路联运等运输组织方式与中欧班列高效衔接。\n（二）补齐农村物流发展短板。\n完善农村物流节点网络。\n围绕巩固拓展脱贫攻坚成果与乡村振兴有效衔接，重点补齐中西部地区、经济欠发达地区和偏远山区等农村物流基础设施短板，切实改善农村流通基础条件。统筹城乡物流发展，推动完善以县级物流节点为核心、乡镇服务网点为骨架、村级末端站点为延伸的县乡村三级物流服务设施体系。推动交通运输与邮政快递融合发展，加快农村物流服务品牌宣传推广，促进交通、邮政、快递、商贸、供销、电商等农村物流资源融合和集约利用，打造一批公用型物流基础设施，建设村级寄递物流综合服务站，完善站点服务功能。推进公益性农产品市场和农产品流通骨干网络建设。\n提升农村物流服务效能。\n围绕农村产业发展和居民消费升级，推进物流与农村一二三产业深度融合，深化电商、快递进村工作，发展共同配送，打造经营规范、集约高效的农村物流服务网络，加快工业品下乡、农产品出村双向物流服务通道升级扩容、提质增效。推动物流服务与规模化种养殖、商贸渠道拓展等互促提升，推动农产品品牌打造和标准化流通，创新物流支持农村特色产业品质化、品牌化发展模式，提升农业产业化水平。\n（三）促进商贸物流提档升级。\n完善城乡商贸物流设施。\n优化以综合物流园区、专业配送中心、末端配送网点为支撑的商贸物流设施网络。完善综合物流园区干线接卸、前置仓储、流通加工等功能。结合老旧小区、老旧厂区、老旧街区和城中村改造以及新城新区建设，新建和改造升级一批集运输、仓储、加工、包装、分拨等功能于一体的公共配送中心，支持大型商超、批发市场、沿街商铺、社区商店等完善临时停靠装卸等配套物流设施，推进智能提货柜、智能快件箱、智能信包箱等设施建设。\n提升商贸物流质量效率。\n鼓励物流企业与商贸企业深化合作，优化业务流程，发展共同配送、集中配送、分时配送、夜间配送等集约化配送模式，优化完善前置仓配送、即时配送、网订店取、自助提货等末端配送模式。深化电商与快递物流融合发展，提升线上线下一体服务能力。\n（四）提升冷链物流服务水平。\n完善冷链物流设施网络。\n发挥国家物流枢纽、国家骨干冷链物流基地的资源集聚优势，引导商贸流通、农产品加工等企业向枢纽、基地集聚或强化协同衔接。加强产销冷链集配中心建设，提高产地农产品产后集散和商品化处理效率，完善销地城市冷链物流系统。改善机场、港口、铁路场站冷链物流配套条件，健全冷链集疏运网络。加快实施产地保鲜设施建设工程，推进田头小型冷藏保鲜设施等建设，加强产地预冷、仓储保鲜、移动冷库等产地冷链物流设施建设，引导商贸流通企业改善末端冷链设施装备条件，提高城乡冷链设施网络覆盖水平。\n提高冷链物流质量效率。\n大力发展铁路冷链运输和集装箱公铁水联运，对接主要农产品产区和集散地，创新冷链物流干支衔接模式。发展“生鲜电商+产地直发”等冷链物流新业态新模式。推广蓄冷箱、保温箱等单元化冷链载器具和标准化冷藏车，促进冷链物流信息互联互通，提高冷链物流规模化、标准化水平。依托国家骨干冷链物流基地、产销冷链集配中心等大型冷链物流设施，加强生鲜农产品检验检疫、农兽药残留及防腐剂、保鲜剂、添加剂合规使用等质量监管。研究推广应用冷链道路运输电子运单，加强产品溯源和全程温湿度监控，将源头至终端的冷链物流全链条纳入监管范围，提升冷链物流质量保障水平。健全进口冷链食品检验检疫制度，筑牢疫情外防输入防线。\n专栏\n8\n冷链物流基础设施网络提升工程\n国家骨干冷链物流基地建设工程。\n到\n2025年，面向农产品优势产区、重要集散地和主销区，依托存量冷链物流基础设施群布局建设100个左右国家骨干冷链物流基地，整合集聚冷链物流市场供需、存量设施以及农产品流通、生产加工等上下游产业资源，提高冷链物流规模化、集约化、组织化、网络化水平。探索建立以国家骨干冷链物流基地为核心的安全检测、全程冷链追溯系统。\n产地保鲜设施建设工程。\n到\n2025年，在农产品主产区和特色农产品优势产区支持建设一批田头小型冷藏保鲜设施，推动建设一批产地冷链集配中心，培育形成一批一体化运作、品牌化经营、专业化服务的农产品仓储保鲜冷链物流运营主体，初步形成符合我国国情的农产品仓储保鲜冷链物流运行模式，构建稳定、高效、低成本运行的农产品出村进城冷链物流网络。\n（五）推进铁路（高铁）快运稳步发展。\n完善铁路（高铁）快运网络。\n结合电商、邮政快递等货物的主要流向、流量，完善铁路（高铁）快运线路和网络。加快推进铁路场站快运服务设施布局和改造升级，强化快速接卸货、集散、分拣、存储、包装、转运和配送等物流功能，建设专业化铁路（高铁）快运物流基地。鼓励电商、邮政快递等企业参与铁路（高铁）快运设施建设和改造，就近或一体布局建设电商快递分拨中心，完善与铁路（高铁）快运高效衔接的快递物流服务网络。\n创新高铁快运服务。\n适应多样化物流需求，发展多种形式的高铁快运。在具备条件的高铁场站间发展“点对点”高铁快运班列服务。依托现有铁路物流平台，构建业务受理、跟踪查询、结算办理等“一站式”高铁快运服务平台，推动高铁快运与电商、快递物流企业信息对接。\n（六）提高专业物流质量效率。\n完善大宗商品物流体系。\n优化粮食、能源、矿产等大宗商品物流服务，提升沿海、内河水运通道大宗商品物流能力，扩大铁路货运班列、“点对点”货运列车、大宗货物直达列车开行范围，发展铁路散粮运输、棉花集装箱运输、能源和矿产重载运输。有序推进油气干线管道建设，持续完善支线管道，打通管网瓶颈和堵点，提高干支管网互联互通水平。依托具备条件的国家物流枢纽发展现代化大宗商品物流中心，增强储备、中转、通关等功能，推进大宗商品物流数字化转型，探索发展电子仓单、提单，构建衔接生产流通、串联物流贸易的大宗商品供应链服务平台。\n安全有序发展特种物流。\n提升现代物流对大型装备制造、大型工程项目建设的配套服务能力，加强大件物流跨区域通道线路设计，推动形成多种运输方式协调发展的大件物流综合网络。发展危化品罐箱多式联运，提高安全服务水平，推动危化品物流向专业化定制、高品质服务和全程供应链服务转型升级。推动危化品物流全程监测、线上监管、实时查询，提高异常预警和应急响应处置能力。完善医药物流社会化服务体系，培育壮大第三方医药物流企业。鼓励覆盖生产、流通、消费的医药供应链平台建设，健全全流程监测追溯体系，确保医药产品物流安全。\n（七）提升应急物流发展水平。\n完善应急物流设施布局。\n整合优化存量应急物资储备、转运设施，推动既有物流设施嵌入应急功能，在重大物流基础设施规划布局、设计建造阶段充分考虑平急两用需要，完善应急物流设施网络。统筹加强抗震、森林草原防灭火、防汛抗旱救灾、医疗救治等各类应急物资储备设施和应急物流设施在布局、功能、运行等方面相互匹配、有机衔接，提高紧急调运能力。\n提升应急物流组织水平。\n统筹应急物流力量建设与管理，建立专业化应急物流企业库和人员队伍，健全平急转换和经济补偿机制。充分利用市场资源，完善应急物流干线运输和区域配送体系，提升跨区域大规模物资调运组织水平，形成应对各类突发事件的应急物流保障能力。\n健全物流保通保畅机制。\n充分发挥区域统筹协调机制作用，鼓励地方建立跨区域、跨部门的应对疫情物流保通保畅工作机制，完善决策报批流程和信息发布机制，不得擅自阻断或关闭高速公路、普通公路、航道船闸等通道，不得擅自关停高速公路服务区、港口码头、铁路车站和航空机场，严禁采取全城24小时禁止货车通行的限制措施，不得层层加码实施“一刀切”管控措施；加快完善物流通道和物流枢纽、冷链基地、物流园区、边境口岸等环节的检验检疫、疫情阻断管理机制和分类分级应对操作规范，在发生重大公共卫生事件时有效阻断疫情扩散、确保物流通道畅通，保障防疫物资、生活物资以及工业原材料、农业生产资料等供应，维护正常生产生活秩序和产业链供应链安全。\n专栏\n9\n应急物流保障工程\n研究完善应急物流转运等设施和服务标准，对具备条件的铁路场站、公路港、机场和港口进行改造提升，建设平急两用的应急物资运输中转站。完善应急物流信息联通标准，强化各部门、各地区、各层级间信息共享，提高应对突发事件物流保障、组织指挥、辅助决策和社会动员能力。\n六、强化现代物流发展支撑体系\n（一）培育充满活力的物流市场主体。\n提升物流企业市场竞争力。\n鼓励物流企业通过兼并重组、联盟合作等方式进行资源优化整合，培育一批具有国际竞争力的现代物流企业，提升一体化供应链综合服务能力。引导中小微物流企业发掘细分市场需求，做精做专、创新服务，增强专业化市场竞争力，提高规范化运作水平。完善物流服务质量评价机制，支持企业塑造物流服务品牌。深化物流领域国有企业改革，盘活国有企业存量物流资产，支持国有资本参与物流大通道建设。鼓励民营物流企业做精做大做强，加快中小微企业资源整合，培育核心竞争力。\n规范物流市场运行秩序。\n统筹推进物流领域市场监管、质量监管、安全监管和金融监管，实现事前事中事后全链条全领域监管，不断提高监管效能。加大物流领域反垄断和反不正当竞争执法力度，深入推进公平竞争政策实施。有序放宽市场准入，完善市场退出机制，有效引导过剩物流能力退出，扩大优质物流服务供给。引导公路运输企业集约化、规模化经营，提升公路货物运输组织效率。\n专栏\n10\n现代物流企业竞争力培育工程\n支持具备条件的物流企业加强软硬件建设，壮大发展成为具有较强国际竞争力的现代物流领军企业，参与和主导全球物流体系建设和供应链布局。支持和鼓励中小微物流企业专业化、精益化、品质化发展，形成一批\n“专、精、特、新”现代物流企业。\n（二）强化基础标准和制度支撑。\n健全物流统计监测体系。\n研究建立物流统计分类标准，加强社会物流统计和重点物流企业统计监测，开展企业物流成本统计调查试点。研究制定反映现代物流重点领域、关键环节高质量发展的监测指标体系，科学系统反映现代物流发展质量效率，为政府宏观调控和企业经营决策提供参考依据。\n健全现代物流标准体系。\n强化物流领域国家标准和行业标准规范指导作用，鼓励高起点制定团体标准和企业标准，推动国际国内物流标准接轨，加大已发布物流标准宣传贯彻力度。推动基础通用和产业共性的物流技术标准优化升级，以标准提升促进物流科技成果转化。建立政府推动、行业协会和企业等共同参与的物流标准实施推广机制。建立物流标准实施评价体系，培育物流领域企业标准“领跑者”，发挥示范带动作用。\n加强现代物流信用体系建设。\n加强物流企业信用信息归集共享，通过“信用中国”网站和国家企业信用信息公示系统依法向社会公开。建立健全跨部门、跨区域信用信息共享机制，建立以信用为基础的企业分类监管制度，完善物流行业经营主体和从业人员守信联合激励和失信联合惩戒机制。依法依规建立物流企业诚信记录和严重失信主体名单制度，提高违法失信成本。\n加强物流安全体系建设。\n完善物流安全管理制度，加强对物流企业的监督管理和日常安全抽查，推动企业严格落实安全生产主体责任。提高物流企业承运物品、客户身份等信息登记规范化水平，加强运输物品信息共享和安全查验部门联动，实现物流活动全程跟踪，确保货物来源可追溯、责任能倒查。提高运输车辆安全性能和从业人员安全素质，规范车辆运输装载，提升运输安全水平。落实网络安全等级保护制度，提升物流相关信息系统的安全防护能力。\n专栏\n11\n物流标准化推进工程\n研究制定现代物流标准化发展规划，完善现代物流标准体系。加强多式联运、应急物流、逆向物流、绿色物流等短板领域标准研究与制订。制修订一批行业急需的物流信息资源分类与编码、物流单证、智慧物流标签标准，以及企业间物流信息采集、信息交互标准和物流公共信息服务平台应用开发、通用接口、数据传输等标准。完善包装、托盘、周转箱等标准，加强以标准托盘为基础的单元化物流系统系列标准制修订，加快运输工具、载运装备、设施体系等标准对接和系统运作，提高全社会物流运行效率。推动完善货物运输、物流园区与冷链、大件、药品和医疗器械、危化品等物流标准规范。推进危险货物在铁路、公路、水路等运输环节标准衔接。加快制定智慧物流、供应链服务、电商快递、即时配送、城乡物流配送等新兴领域标准。推进面向数字化与智慧化需求的物流装备设施标准制修订。积极参与国际物流标准制修订。\n（三）打造创新实用的科技与人才体系。\n强化物流科技创新支撑。\n依托国家企业技术中心、高等院校、科研院所等开展物流重大基础研究和示范应用，推动设立一批物流技术创新平台。建立以企业为主体的协同创新机制，鼓励企业与高等院校、科研院所联合设立产学研结合的物流科创中心，开展创新技术集中攻关、先进模式示范推广，建立成果转化工作机制。鼓励物流领域研究开发、创业孵化、技术转移、检验检测认证、科技咨询等创新服务机构发展，提升专业化服务能力。\n建设物流专业人才队伍。\n发挥物流企业用人主体作用，加强人才梯队建设，完善人才培养、使用、评价和激励机制。加强高等院校物流学科专业建设，提高专业设置的针对性，培育复合型高端物流人才。加快物流现代职业教育体系建设，支持职业院校（含技工院校）开设物流相关专业。加强校企合作，创新产教融合人才培养模式，培育一批有影响力的产教融合型企业，支持企业按规定提取和使用职工教育经费，开展大规模多层次职业技能培训，促进现代物流专业技术人员能力提升。指导推动物流领域用人单位和社会培训评价组织开展职业技能等级认定，积极开展物流领域相关职业技能竞赛。实现学历教育与培训并举衔接，进一步推动物流领域1+X证书制度和学分银行建设。对接国际专业认证体系，提高国际化物流人才培养水平，加大海外高端人才引进力度。实施新一轮专业技术人才知识更新工程和职业技能提升行动，推进物流领域工程技术人才职称评审，逐步壮大高水平工程师和高技能人才队伍。\n七、实施保障\n（一）优化营商环境。\n深化“放管服”改革，按规定放宽物流领域相关市场准入，消除各类地方保护和隐性壁垒。依托全国一体化政务服务平台，推动物流领域资质证照电子化，支持地方开展“一照多址”改革，促进物流企业网络化布局，实现企业注册、审批、变更、注销等“一网通办”，允许物流领域（不含快递）企业分支机构证照异地备案和异地审验。推动物流领域（不含快递）资质许可向资质备案和告知承诺转变。完善物流发展相关立法，推动健全物流业法律法规体系和法治监督体系。开展现代物流促进法等综合性法律立法研究和准备工作。严格依法行政依法监管，统一物流监管执法标准和处罚清单。推动跨部门、跨区域、跨层级政务信息开放共享，避免多头管理和重复监管。大力推动货车非法改装治理，研究制定非标准货运车辆治理工作方案。依托国际贸易“单一窗口”创新“通关+物流”服务，提高口岸智慧管理和服务水平。推动部门间物流安检互认、数据互通共享，减少不必要的重复安检。支持航空公司壮大货运机队规模，进一步简化货机引进程序和管理办法，优化工作流程，鼓励航空物流企业“走出去”。\n（二）创新体制机制。\n完善全国现代物流工作部际联席会议制度，强化跨部门、跨区域政策协同，着力推动降低物流成本等重点工作。深化铁路货运市场化改革，推进投融资、运输组织、科技创新等体制机制改革，吸引社会资本进入，推动铁路货运市场主体多元化和服务创新发展，促进运输市场公平有序竞争。鼓励铁路企业与港口、社会物流企业等交叉持股，拓展战略合作联盟。\n（三）强化政策支持。\n保障重大项目用地用海。\n依据国土空间规划，落实《国土空间调查、规划、用途管制用地用海分类指南（试行）》要求，完善物流设施专项规划，重点保障国家物流枢纽等重大物流基础设施和港航设施等的合理用地用海需求，确保物流用地规模、土地性质和空间位置长期稳定。创新物流用地模式，推动物流枢纽用地统一规划和科学布局，提升土地空间集约节约利用水平，支持物流仓储用地以长期租赁或先租后让、租让结合的方式供应。鼓励地方政府盘活存量土地和闲置土地资源用于物流设施建设。支持物流企业利用自有土地进行物流基础设施升级改造。支持依法合规利用铁路划拨用地、集体建设用地建设物流基础设施。\n巩固减税降费成果。\n落实深化税收征管制度改革有关部署，推进现代物流领域发票电子化。按规定落实物流企业大宗商品仓储设施用地城镇土地使用税减半征收、购置挂车车辆购置税减半征收等税收优惠政策。严格落实已出台的物流简政降费政策，严格执行收费目录清单和公示制度，严禁违规收费，坚决治理乱收费、乱罚款、乱摊派，依法治理“只收费、不服务”的行为。清理规范铁路、港口、机场等收费，对主要海运口岸、机场地面服务收费开展专项调查，增强铁路货运收费透明度。对货运车辆定位信息及相关服务商开展典型成本调查，及时调整过高收费标准。\n加大金融支持力度。\n鼓励符合条件的社会资本按市场化方式发起成立物流产业相关投资基金。发挥各类金融机构作用，按照市场化、法治化原则，加大对骨干物流企业和中小物流企业的信贷支持力度，拓宽企业兼并重组融资渠道，引导资金流向创新型物流企业。在仓储物流行业稳妥推进基础设施领域不动产投资信托基金（REITs）试点。鼓励保险公司开发农产品仓储保鲜冷链物流保险，提升鲜活农产品经营和质量安全风险保障水平。\n（四）深化国际合作。\n推动建立国际物流通道沿线国家协作机制，加强便利化运输、智慧海关、智能边境、智享联通等方面合作。持续推动中欧班列“关铁通”项目在有合作意愿国家落地实施。逐步建立适应国际铁路联运特点的陆路贸易规则体系，推动完善配套法律法规，加强与国内外银行、保险等金融机构合作，探索使用铁路运输单证开展贸易融资。\n（五）加强组织实施。\n国家发展改革委要会同国务院有关部门加强行业综合协调和宏观调控，协调解决本规划实施中存在的问题，确保规划落地见效。建立现代物流发展专家咨询委员会，加强对重大问题的调查研究和政策咨询，指导规划任务科学推进。推动行业协会深度参与行业治理，发挥社会监督职能，加强行业自律和规范发展，助力规划落地实施。\n扫一扫在手机打开当前页', '2021-11-01 16:00:00', '2026-04-16 11:29:41');
INSERT INTO `news_detail` VALUES (8, 915, 14, '合规与政策服务', '国务院关于同意在广东省暂时调整实施有关行政法规规定的批复', '', '', 'http://www.gov.cn/zhengce/content/2022-11/25/content_5728775.htm', 0, '', '{\"summary\": \"本文公示国务院对广东省行政法规调整的批复，可供布局广东的出海企业关注后续政策变动参考\", \"abstract\": \"本文为国务院关于同意在广东省暂时调整实施有关行政法规规定的批复文件。文中未附上具体批复内容与调整事项。相关政策调整方向暂不明确，出海企业可后续跟进广东相关政策落地信息。\", \"keywords\": [\"行政法规调整\", \"政策批复\", \"广东省\", \"出海政策\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及具体政策调整内容\"}, \"topic_cluster\": \"合规与政策服务\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2022-11/25/content_5728775.htm\", \"title\": \"国务院关于同意在广东省暂时调整实施有关行政法规规定的批复\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院关于同意在广东省暂时调整实施有关行政法规规定的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在广东省暂时调整实施有关行政法规规定的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/25/content_5728775.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/25/content_5728775.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}\", \"published_at\": \"2021-10-31 16:00:00\", \"ai_json_output\": \"\"}', '国务院关于同意在广东省暂时调整实施\n有关行政法规规定的批复\n国函〔2022〕129号\n广东省人民政府，海关总署、司法部、港澳办：\n你们关于对入出内地符合条件的香港、澳门机动车实行免担保政策并在广东省暂时调整实施有关行政法规规定的请示收悉。现批复如下：\n一、为支持粤港澳大湾区建设，同意自即日起在广东省暂时调整实施《中华人民共和国海关事务担保条例》、《中华人民共和国进出口关税条例》的有关规定（目录附后），对符合条件的按照香港机动车经港珠澳大桥珠海公路口岸入出内地（以下称“港车北上”）政策入出内地的香港机动车和按照澳门机动车经港珠澳大桥珠海公路口岸入出内地（以下称“澳车北上”）政策入出内地的澳门机动车实行免担保政策。\n二、广东省人民政府、海关总署等有关部门要根据上述调整，按职责分工推进落实“港车北上”、“澳车北上”政策，及时对本省、本部门制定的规章和规范性文件作相应调整，建立相适应的管理制度，在确保有效防控免担保风险的前提下，成熟一个，实施一个。\n三、国务院将根据有关政策在广东省的实施情况，适时对本批复的内容进行调整。\n附件：国务院决定在广东省暂时调整实施的有关行政法规规定目录\n国务院\n2022年11月17日\n（此件公开发布）\n附件\n国务院决定在广东省暂时调整实施的\n有关行政法规规定目录\n有关行政法规规定\n调整实施情况\n《中华人民共和国海关事务担保条例》\n第五条第一款\n当事人申请办理下列特定海关业务的，按照海关规定提供担保：\n……\n（二）货物、物品暂时进出境的；\n……\n《中华人民共和国进出口关税条例》\n第四十二条\n暂时进境或者暂时出境的下列货物，在进境或者出境时纳税义务人向海关缴纳相当于应纳税款的保证金或者提供其他担保的，可以暂不缴纳关税，并应当自进境或者出境之日起\n6\n个月内复运出境或者复运进境；需要延长复运出境或者复运进境期限的，纳税义务人应当根据海关总署的规定向海关办理延期手续：\n（一）在展览会、交易会、会议及类似活动中展示或者使用的货物；\n（二）文化、体育交流活动中使用的表演、比赛用品；\n（三）进行新闻报道或者摄制电影、电视节目使用的仪器、设备及用品；\n（四）开展科研、教学、医疗活动使用的仪器、设备及用品；\n（五）在本款第（一）项至第（四）项所列活动中使用的交通工具及特种车辆；\n（六）货样；\n（七）供安装、调试、检测设备时使用的仪器、工具；\n（八）盛装货物的容器；\n（九）其他用于非商业目的的货物。\n第一款所列暂时进境货物在规定的期限内未复运出境的，或者暂时出境货物在规定的期限内未复运进境的，海关应当依法征收关税。\n第一款所列可以暂时免征关税范围以外的其他暂时进境货物，应当按照该货物的完税价格和其在境内滞留时间与折旧时间的比例计算征收进口关税。具体办法由海关总署规定。\n暂时调整实施《中华人民共和国海关事务担保条例》第五条第一款第二项和《中华人民共和国进出口关税条例》第四十二条的有关规定，对按照\n“港车北上”、“澳车北上”政策入出内地符合条件的香港、澳门机动车实行免担保政策。广东省人民政府会同有关方面推进落实“港车北上”、“澳车北上”政策，要完善落实相关机动车源头管理和属地管控责任，签署相关协议，制定具体管理办法，加强信息化和科技手段运用，建立健全机动车入出内地的预警管控工作机制，在确保有效防控免担保风险的前提下，成熟一个，实施一个。\n扫一扫在手机打开当前页', '2021-10-31 16:00:00', '2026-04-16 11:30:17');
INSERT INTO `news_detail` VALUES (9, 916, 7, '消费与零售', '国务院关于同意在廊坊等33个城市和地区设立跨境电子商务综合试验区的批复', '', '', 'http://www.gov.cn/zhengce/content/2022-11/24/content_5728554.htm', 0, '', '{\"summary\": \"本文公布国务院新设33个跨境电商综试区的批复，帮助出海企业把握跨境电商发展政策新机遇\", \"abstract\": \"国务院正式批复同意在廊坊等33个城市和地区设立跨境电子商务综合试验区。此次新设综试区是我国跨境电商试点范围的进一步扩围。将为跨境电商出海企业提供更多政策红利与发展载体，助力行业整体发展。\", \"keywords\": [\"跨境电商\", \"跨境电子商务综合试验区\", \"国务院批复\", \"政策利好\", \"出海布局\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国务院批复同意在廊坊等33个城市和地区设立跨境电子商务综合试验区，新设试点为跨境电商出海提供政策支持\"}, \"topic_cluster\": \"合规与政策服务\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2022-11/24/content_5728554.htm\", \"title\": \"国务院关于同意在廊坊等33个城市和地区设立跨境电子商务综合试验区的批复\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院关于同意在廊坊等33个城市和地区设立跨境电子商务综合试验区的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在廊坊等33个城市和地区设立跨境电子商务综合试验区的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/24/content_5728554.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/24/content_5728554.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}\", \"published_at\": \"2021-10-31 16:00:00\", \"ai_json_output\": \"\"}', '', '2021-10-31 16:00:00', '2026-04-16 11:43:35');
INSERT INTO `news_detail` VALUES (10, 918, 14, '合规与政策服务', '国务院办公厅关于推广行政备案规范管理改革试点经验的通知', '', '', 'http://www.gov.cn/zhengce/content/2022-11/18/content_5727708.htm', 0, '', '{\"summary\": \"本文为国务院发布的行政备案改革试点经验推广通知，可供出海企业了解国内备案政策改革动态参考\", \"abstract\": \"本文是国务院办公厅发布的关于推广行政备案规范管理改革试点经验的通知。本次输入未提供通知具体正文内容，无法获取改革的具体举措与适用范围。该类行政备案改革或会影响出海企业相关国内备案办理流程\", \"keywords\": [\"行政备案\", \"改革试点\", \"备案管理\", \"合规\", \"出海备案\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提供通知具体内容，未提及明确政策合规要点\"}, \"topic_cluster\": \"合规与政策服务\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2022-11/18/content_5727708.htm\", \"title\": \"国务院办公厅关于推广行政备案规范管理改革试点经验的通知\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院办公厅关于推广行政备案规范管理改革试点经验的通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院办公厅关于推广行政备案规范管理改革试点经验的通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-11/18/content_5727708.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-11/18/content_5727708.htm\', \'published\': \'Sun, 31 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=31, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=6, tm_yday=304, tm_isdst=0)}\", \"published_at\": \"2021-10-31 16:00:00\", \"ai_json_output\": \"\"}', '国务院办公厅关于推广行政备案规范管理\n改革试点经验的通知\n国办函〔2022〕110号\n各省、自治区、直辖市人民政府，国务院各部委、各直属机构：\n经国务院批准，自2021年7月起，河北、浙江、湖北三省开展了为期一年的行政备案规范管理改革试点。试点期间，三省认真落实《国务院办公厅关于同意河北、浙江、湖北省开展行政备案规范管理改革试点的复函》（国办函〔2021〕68号）有关要求，制定行政备案管理办法，全面梳理、分类规范行政备案事项，大力推进行政备案网上可办、“一网通办”，有效提升了行政备案标准化、规范化、便利化水平，对消除市场准入隐性壁垒、激发市场主体活力等发挥了积极作用。为进一步深化行政审批制度改革，持续优化营商环境，经国务院同意，现将三省行政备案规范管理改革试点经验印发给你们，请结合自身实际学习借鉴。\n各地区各部门要高度重视行政备案规范管理工作，加强行政备案规范化、法治化建设。严格设定要求，对行政备案事项，不得规定经行政机关审查同意，企业和群众方可从事相关特定活动；能够通过政府内部信息共享、涉企电子证照库等渠道获取有关信息的，一般不得设定行政备案。要细化优化行政备案实施规范，制定并公布办事指南，对违规增加办理环节或者备案材料、超时限办理备案、无正当理由不予备案等问题，要及时整改。要建立和完善协同机制，鼓励将行政备案纳入政务服务中心集中办理、统一管理，加强相关信息共享共用，更大力度推进行政备案易办快办。要加大监督检查力度，坚决纠正以备案之名行许可之实。要充分运用备案信息提升政府监管效能和政务服务水平，不断降低制度性交易成本，努力为市场主体发展营造更好的营商环境。\n附件：1.河北省坚持问题导向 强化分类管理 大力推动行政备案规范运行\n2.浙江省坚持精细管理 强化数字赋能 全力推进行政备案规范管理\n3.湖北省坚持标准指引 强化利企便民 推动行政备案规范管理走深走实\n国务院办公厅\n2022年11月5日\n（此件公开发布）\n附件1\n河北省坚持问题导向　强化分类管理\n大力推动行政备案规范运行\n河北省针对行政备案概念不明晰、设定不严格、管理不规范、实施不透明等难题，大力推动行政备案标准统一、运行规范、智能便捷，为进一步在全国范围推进行政备案规范管理提供了有益经验。\n一、编制行政备案事项清单，实施分类管理\n（一）全面摸底梳理，清理规范事项。\n深入研究行政备案与行政许可的区别，明确行政备案的基本概念、依据标准、事项范围、办理程序等内容，在此基础上对正在实施的行政备案进行全面摸底，确保事项梳理无遗漏。组织有关部门对设定依据不充分以及此前未纳入行政备案管理的事项进行清理规范，其中，将98项设定依据不充分的事项，予以清理取消；将17项原列为其他权力类别的事项，调整规范为行政备案事项；将25项正在实施但未纳入权责清单的事项，经过严格甄别把关后纳入行政备案事项清单。\n（二）细化备案分类，编制备案清单。\n以省政府办公厅名义印发《河北省行政备案事项目录》（共计351项），将保留实施的行政备案事项全部纳入清单管理，明确清单之外不得违规实施行政备案。根据行政备案运行实际，对行政备案事项进行分类，共确定告知类备案事项282项、确认类备案事项41项、审查类备案事项28项。对行政机关仅进行形式审查的事后告知类备案，实行即来即备；对行政机关采用公告、认定或者出具备案决定、备案号等方式，对申请人某种资格进行确定的确认类备案，简化确认程序，压减备案用时。\n二、健全制度保障体系，推动行政备案规范便捷\n（一）制定管理办法，规范备案运行。\n以省政府办公厅名义印发《河北省行政备案管理办法》，内容包含行政备案概念界定、设定依据、设定标准、办理程序、监督管理等方面，为规范行政备案运行提供了制度保障。办法规定，除涉及国家秘密等特殊情形外，行政备案事项应当全部纳入省政务服务事项管理平台统一管理；对可以通过行政处罚、日常监督、信息共享等举措进行管理的事项，原则上不再要求申请人提交备案材料；行政备案原则上实行事后备案，除特殊规定外，行政备案实施机关在备案前不得限制申请人从事特定活动；在备案实施过程中，不得收取任何费用。\n（二）开发管理系统，强化技术支撑。\n开发运行行政备案事项管理系统，优化完善事项审核、数据质检、统计分析、综合管理等功能。充分应用行政备案事项要素标准化成果，将相关要素信息全部纳入省政务服务事项管理平台。同时，加强审批、备案、监管等不同管理手段的智能化衔接运用，推动实现网上可办、“一网通办”。结合电子证照、电子档案全面应用，对可以通过数据共享获得备案信息的事项免于提交备案材料，探索推行自动备案、智能备案，最大限度减少企业和群众办事跑动次数。\n三、加强工作创新，提升行政备案管理水平\n（一）探索制定行政备案地方标准。\n组建专门团队，起草《行政备案要素通用要求》地方标准制定计划，并将该标准列入2022年度河北省地方标准制修订项目计划，探索对行政备案事项名称、行使层级、实施部门、备案类型、备案条件、备案材料等18项具体要素建立地方标准，在全省范围推广应用，进一步规范行政备案运行。\n（二）专门设置行政备案权力类别。\n加强行政备案事项清单与权责清单的有效衔接、有机统一，在全省政府部门权责清单中，将行政备案增设为一类独立的权力类别，将原分散在行政确认、行政裁决、其他类等权力类别中的行政备案事项剥离，汇集后单独纳入权责清单体系，实现与权责清单事项数据同源、统一公布，进一步强化行政备案事项清单的规范性、权威性。\n附件2\n浙江省坚持精细管理　强化数字赋能\n全力推进行政备案规范管理\n浙江省将行政备案规范管理改革试点工作列入全面深化改革年度考核，组建由省政府职能转变办公室牵头、多部门共同参与的工作专班，建立“问题全面收集+每周例会讨论+跟踪督促催办”的工作机制，全力推进试点各项工作。\n一、坚持依法编制，务求全面精准\n一是厘清基本概念。\n明确行政备案是指公民、法人和其他组织依法报送其从事特定活动的相关材料，行政机关接收报送材料备查并作为监管参考依据的行为。\n二是系统梳理事项。\n组织71个省级单位建立省市县三级会审制度，对系统条线全量事项进行梳理细化：对没有合法依据的事项，原则上予以取消；对以备案之名行许可之实的，坚决清理纠正；对可通过信息共享、事中事后监管等措施进行管理的事项，原则上不再要求备案。按照上述要求共清理96项备案事项。对虽有合法依据但不符合全面深化改革要求和经济社会发展需要的事项，提出修法建议26条。\n三是编制事项清单。\n经过合法性审核、工作专班审核补正、公开征求意见、专家专题论证、与《法律、行政法规、国务院决定设定的行政许可事项清单（2022年版）》比对等程序，“三上三下”反复沟通核校，编制形成《浙江省行政备案事项清单（2022年试行）》，包含339项事项。\n二、坚持科学管理，务求规范严谨\n一是完善事项基本要素。\n组织省市主管部门细化行政备案事项颗粒度，按照办事情形拆分主项，共形成子项541项。逐个事项分析论证，梳理行政备案事项设定和实施依据。规范事项主项和子项名称，按照通俗易懂、清晰明了的原则，调整事项名称69个。\n二是规范备案指南和流程。\n按照标准化要求，组织省级主管部门逐项制定完善办事指南，统一行政备案事项主项和子项名称、适用依据、申报条件、申报材料、办理时限、申报表单、示范文本等实施要素；组织行政备案实施机关补充具体的办理时间、办理地点、咨询电话等服务性信息。同时，按照“填报→提交→接收（形式审查）→补正（形式审查）→完成备案”的流程要求，规范简化办事环节，并及时向社会公布。\n三是规范清单外事项名称。\n按照清单之外无备案事项的原则，对含有“备案”、“报备”等字样的74项非行政备案事项名称进行调整规范。\n三、坚持有序推进，务求落地见效\n一是稳妥做好改革过渡期准备。\n要求行政备案事项统一进驻全省各地政务服务中心办理，设置合理的线上线下办事过渡期，稳步迭代升级政务服务大厅、业务办理系统，及时完成业务流程配置，确保市场主体对事项前后变化无感、办理体验更优。\n二是健全清单动态管理机制。\n定期开展行政备案评估清理，根据设定依据的立改废释、机构改革和职能调整等情况，及时对行政备案事项、实施要素及办事指南等进行动态更新，确保清单的时效性、准确性。\n三是加强备案监管协同。\n组织有关部门依法依规逐项确定行政备案监管主体，明确监管要求，强化重点领域监管举措，坚决杜绝以备案代替监管、不备案就不监管等问题。\n四、坚持数字赋能，务求便捷高效\n一是推进“网上办”、“掌上办”。\n在省一体化政务服务平台上建立行政备案事项管理系统，将清单内事项纳入系统管理，推动全部行政备案事项网上可办。\n二是推进即办、智能办。\n优化改造业务办理系统，推动行政备案信息归集、共享、运用，217项事项实现即办；16项企业和群众高频办理的事项推行智能备案，做到申报零材料、填报零字段、核对零人工、回执零上门、存档零纸质，实现行政备案“智能秒办”、“无感智办”。\n三是推进智慧监管。\n将行政备案事项纳入省“互联网+监管”平台、“大综合一体化”执法监管数字应用，加强行政备案与监督检查、行政处罚、联合惩戒等数据共享、协同联动，有力提升政府监管效能。\n附件3\n湖北省坚持标准指引　强化利企便民\n推动行政备案规范管理走深走实\n湖北省政务服务管理部门牵头成立工作专班，邀请行政法学、标准化等领域专家和政务服务一线人员组成业务咨询组，先后12次组织试点地区和部门召开业务培训会、工作推进会，统一政策口径，明确业务规范，推动行政备案规范管理改革试点工作取得积极成效。\n一、深入调研摸底，编制行政备案事项清单\n一是全面梳理摸底。\n工作专班全面细致梳理相关设定依据，形成包含1256项行政备案事项的基础清单。\n二是逐项对接确认。\n在基础清单的基础上逐部门上门对接，对国家层面设定的行政备案事项逐项确认，对省、市级层面设定的行政备案事项经过合法性、必要性、合理性论证后，清理取消部分事项。\n三是集中审核把关。\n组织相关省级部门和市州召开全省行政备案事项集中审核会，对没有合法依据的112项事项全部予以取消；对可以通过日常监督、信息共享等实现管理目的的42项事项不再实施备案管理；对属于上下级或者同级行政机关之间备案的289项事项，作为政府内部管理事项，不再要求企业和群众办理。最终确定全省行政备案事项400项。\n二、加强建章立制，严格规范行政备案实施\n一是理清基本概念。\n出台行政备案管理办法，规定行政备案是指行政机关根据公民、法人或者其他组织依法报送或者申请的相关材料，经审核予以存档备查的行为，并将行政备案分为信息收集型和条件/标准审查型两种类型，分别明确不同的设定依据和管理规范。\n二是明确设定和改革要求。\n拟设定行政备案的，制定机关应当在有关起草说明中进行论证说明，并定期评估清理，根据情况变化及时修改或者废止。\n三是强化清单管理。\n明确全省县级以上地方人民政府应当实行行政备案事项清单管理制度，动态调整行政备案事项清单并向社会公布，清单之外不得违规实施行政备案。\n三、制定标准规范，推进行政备案标准化办理\n研究制定《行政备案规范管理标准化导则》、《行政备案事项编码规则》、《行政备案事项办事指南编写规范》，对行政备案规范管理的总体原则、范围界定、责任与权限、流程管理、信息管理、档案管理、监督与评价等提出明确要求；确定行政备案事项基本目录编码规则、实施清单编码规则、业务办理项编码规则和事项编码维护的原则和方法；细化对设定依据、申请材料、办理渠道、承诺办理时限等61项实施要素的具体要求。在此基础上，组织主管部门逐项明确行政备案实施要素并汇总公布，大幅提高行政备案标准化水平，着力推进同要素管理、无差别受理、同标准办理。\n四、强化利企便民，提升行政备案便利化水平\n一是大力推进“一网通办”。\n将行政备案事项纳入省一体化政务服务平台统一管理，实行一张清单告知、一张表单申报、一个标准受理、一个平台流转，目前已实现329项行政备案事项网上可办。\n二是有序推进异地可办。\n推进高频事项跨域通办，满足企业和群众异地办事需求，已实现41项行政备案事项在武汉、襄阳和“宜荆荆”三大都市圈区域通办，正在推进12项行政备案事项全省通办。\n三是深入推进移动端办理。\n将覆盖范围广的行政备案事项向政务服务移动端APP“鄂汇办”延伸，已实现367项行政备案事项“掌上办”、“指尖办”。\n四是扎实推进自助办理。\n推动自助终端入驻各级政务服务中心，设立24小时自助服务区，并向银行、工业园区、商业楼宇等场所延伸，推动“就近办、自助办、随时办”，已实现259项行政备案事项可自助办理。\n五是探索推进免证办。\n推进高频证照免提交、高频事项免证办，已实现51种高频电子证照免提交、253项行政备案事项免证办。\n扫一扫在手机打开当前页', '2021-10-31 16:00:00', '2026-04-16 11:31:52');
INSERT INTO `news_detail` VALUES (11, 926, 14, '合规与政策服务', '国务院关于同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定的批复', '', '', 'http://www.gov.cn/zhengce/content/2022-10/08/content_5716699.htm', 0, '', '{\"summary\": \"本文仅披露国务院批复四地调整行政法规的标题，无具体内容，无法为出海企业提供有效参考\", \"abstract\": \"本文仅公开了国务院相关批复的标题，未公布批复的具体内容。文中未提及任何与企业出海相关的具体信息，也没有明确调整的法规领域与适用范围，无法为出海主体提供决策参考\", \"keywords\": [\"国务院批复\", \"行政法规调整\", \"天津\", \"上海\", \"海南\", \"重庆\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"合规与政策服务\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://www.gov.cn/zhengce/content/2022-10/08/content_5716699.htm\", \"title\": \"国务院关于同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定的批复\", \"source\": \"https://www.gov.cn/jsonTag/tp/rss.xml\\n\", \"content\": \"\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国务院关于同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定的批复\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://www.gov.cn/jsonTag/tp/rss.xml\', \'value\': \'国务院关于同意在天津、上海、海南、重庆暂时调整实施有关行政法规规定的批复\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://www.gov.cn/zhengce/content/2022-10/08/content_5716699.htm\'}], \'link\': \'http://www.gov.cn/zhengce/content/2022-10/08/content_5716699.htm\', \'published\': \'Sat, 30 Oct 2021 16:00:00 GMT\', \'published_parsed\': time.struct_time(tm_year=2021, tm_mon=10, tm_mday=30, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=5, tm_yday=303, tm_isdst=0)}\", \"published_at\": \"2021-10-30 16:00:00\", \"ai_json_output\": \"\"}', '国务院关于同意在天津、上海、海南、重庆\n暂时调整实施有关行政法规规定的批复\n国函〔2022〕104号\n天津市、上海市、海南省、重庆市人民政府，商务部、司法部：\n你们关于在天津市、上海市、海南省、重庆市暂时调整实施有关行政法规规定的请示收悉。现批复如下：\n一、按照《国务院关于同意在天津、上海、海南、重庆开展服务业扩大开放综合试点的批复》（国函〔2021〕37号），同意自即日起至2024年4月8日，在相关省市暂时调整实施《旅行社条例》、《民办非企业单位登记管理暂行条例》的有关规定（目录附后）。\n二、国务院有关部门、相关省市人民政府要根据上述调整，及时对本部门、本省市制定的规章和规范性文件作相应调整，建立与服务业扩大开放综合试点相适应的管理制度。\n三、国务院将根据相关省市服务业扩大开放综合试点情况，适时对本批复的内容进行调整。\n附件：国务院决定在天津、上海、海南、重庆暂时调整实施的有关行政法规规定目录\n国务院\n2022年9月21日\n（此件公开发布）\n附件\n国务院决定在天津、上海、海南、重庆\n暂时调整实施的有关行政法规规定目录\n扫一扫在手机打开当前页', '2021-10-30 16:00:00', '2026-04-16 11:34:03');
INSERT INTO `news_detail` VALUES (12, 959, 8, '新能源与汽车', 'FF完成股权投资协议修订并将总认购金额增至1200万美元，取消反稀释条款', '', '36氪获悉，4月16日，FF宣布，公司已与Gold King Arthur Holding Limited（\"认购方\"）——AIxCrypto Holdings Inc.指定的第三方投资人——就双方于2026年2月4日签订的股份购买协议完成修订，主要内容包括：将总认购金额由1000万美元增至1200万美元，其中50万美元用于认购普通股，1150万美元用于认购C系列优先股；终止反稀释补偿条款，以固定的、与运营里程碑挂钩的认股权证取而代之；将每股认购价格修订为修订协议签署日前10个交易日的平均收盘价。', 'https://36kr.com/newsflashes/3768847820931591?f=rss', 0, '', '{\"summary\": \"本文报道FF修订股权投资协议，调整融资条款与规模，可为出海新能源车企跨境融资提供参考\", \"abstract\": \"本文是36氪发布的企业融资资讯，4月16日FF宣布与指定第三方投资人完成原有股份购买协议的修订。本次修订将总认购金额从1000万美元提升至1200万美元，明确了普通股与C系列优先股的认购份额。修订终止了原协议的反稀释补偿条款，替换为与运营里程碑挂钩的固定认股权证，同时调整了每股认购价格的计算规则。本次条款调整优化了本次股权投资的交易安排。\", \"keywords\": [\"FF\", \"股权投资\", \"股份认购\", \"反稀释条款\", \"认股权证\", \"优先股\", \"跨境融资\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"跨境投融资\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3768847820931591?f=rss\", \"title\": \"FF完成股权投资协议修订并将总认购金额增至1200万美元，取消反稀释条款\", \"source\": \"https://36kr.com/feed-newsflash\", \"content\": \"36氪获悉，4月16日，FF宣布，公司已与Gold King Arthur Holding Limited（\\\"认购方\\\"）——AIxCrypto Holdings Inc.指定的第三方投资人——就双方于2026年2月4日签订的股份购买协议完成修订，主要内容包括：将总认购金额由1000万美元增至1200万美元，其中50万美元用于认购普通股，1150万美元用于认购C系列优先股；终止反稀释补偿条款，以固定的、与运营里程碑挂钩的认股权证取而代之；将每股认购价格修订为修订协议签署日前10个交易日的平均收盘价。\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'FF完成股权投资协议修订并将总认购金额增至1200万美元，取消反稀释条款\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'FF完成股权投资协议修订并将总认购金额增至1200万美元，取消反稀释条款\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3768847820931591?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3768847820931591?f=rss\', \'published\': \'2026-04-16 09:50:15  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=1, tm_min=50, tm_sec=15, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'36氪获悉，4月16日，FF宣布，公司已与Gold King Arthur Holding Limited（\\\"认购方\\\"）——AIxCrypto Holdings Inc.指定的第三方投资人——就双方于2026年2月4日签订的股份购买协议完成修订，主要内容包括：将总认购金额由1000万美元增至1200万美元，其中50万美元用于认购普通股，1150万美元用于认购C系列优先股；终止反稀释补偿条款，以固定的、与运营里程碑挂钩的认股权证取而代之；将每股认购价格修订为修订协议签署日前10个交易日的平均收盘价。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'36氪获悉，4月16日，FF宣布，公司已与Gold King Arthur Holding Limited（\\\"认购方\\\"）——AIxCrypto Holdings Inc.指定的第三方投资人——就双方于2026年2月4日签订的股份购买协议完成修订，主要内容包括：将总认购金额由1000万美元增至1200万美元，其中50万美元用于认购普通股，1150万美元用于认购C系列优先股；终止反稀释补偿条款，以固定的、与运营里程碑挂钩的认股权证取而代之；将每股认购价格修订为修订协议签署日前10个交易日的平均收盘价。\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 09:50:15\", \"ai_json_output\": \"\"}', '账号设置\n我的关注\n我的收藏\n申请的报道\n退出登录\n登录\n搜索\n36氪Auto\n数字时氪\n未来消费\n智能涌现\n未来城市\n启动Power on\n36氪出海\n36氪研究院\n潮生TIDE\n36氪企服点评\n36氪财经\n职场bonus\n36碳\n后浪研究所\n暗涌Waves\n硬氪\n氪睿研究院\n媒体品牌\n企业号\n企服点评\n36Kr研究院\n36Kr创新咨询\n企业服务\n核心服务\n城市之窗\n政府服务\n创投发布\nLP源计划\nVClub\nVClub投资机构库\n投资机构职位推介\n投资人认证\n投资人服务\n寻求报道\n36氪Pro\n创投氪堂\n企业入驻\n创业者服务\n创投平台\nAI测评网\n首页\n快讯\n资讯\n推荐\n财经\nAI\n自助报道\n四川\n最新\n创投\n汽车\n科技\n专精特新\n直播\n视频\n专题\n活动\n搜索\n寻求报道\n我要入驻\n城市合作\n04\n月\n16\nFF完成股权投资协议修订并将总认购金额增至1200万美元，取消反稀释条款\n2026-04-16 09:50\n分享至\n打开微信“扫一扫”，打开网页后点击屏幕右上角分享按钮\n36氪获悉，4月16日，FF宣布，公司已与Gold King Arthur Holding Limited（\"认购方\"）——AIxCrypto Holdings Inc.指定的第三方投资人——就双方于2026年2月4日签订的股份购买协议完成修订，主要内容包括：将总认购金额由1000万美元增至1200万美元，其中50万美元用于认购普通股，1150万美元用于认购C系列优先股；终止反稀释补偿条款，以固定的、与运营里程碑挂钩的认股权证取而代之；将每股认购价格修订为修订协议签署日前10个交易日的平均收盘价。\n原文链接\n下一篇\n创业板指涨1%\n36氪获悉，A股三大股指高开高走，创业板指涨1%，深证成指涨0.69%，沪指涨0.3%，钛白粉概念、云游戏板块、算力租赁板块涨幅居前。\n1小时前\n24小时热榜\n查看更多榜单\nHermes Agent抄袭中国团队代码实锤，被锤后回应：你删号\n智谱让微信支付宝躺赢了\n刚刚，李飞飞最新成果发布，手机也能跑亿级粒子的 3D 世界了\n23小时前\n8点1氪丨美国将退还超1万亿元关税；多家银行密集停发信用卡；滴露回应使用宠物消毒液后5只幼猫死亡\n3小时前\n突发：Claude引入强实名制验证，必须真人手持证件自拍，否则直接封号\n3小时前\nClaude Opus 4.7 或本周上线，但 Anthropic 要查你证件了\n16小时前\n苹果疯狂狙击Vibe Coding App\n19小时前\n国产AI芯片崛起：三大门派、瓜分英伟达\n13小时前\n关于36氪\n城市合作\n寻求报道\n我要入驻\n投资者关系\n商务合作\n关于我们\n联系我们\n加入我