INSERT INTO `news_detail` VALUES (13, 962, 11, '服务与基建', '大韩航空将从下月起提高国际航班燃油附加费', '', '4月16日，据报道，大韩航空宣布，将从下个月起提高国际航班的燃油附加费，每单程费用为75000韩元至564000韩元不等。其中，从仁川出发飞往青岛、福冈等短途航线将收取75000韩元的燃油附加费，而飞往纽约、芝加哥等长途航线则需收取564000韩元。（界面）', 'https://36kr.com/newsflashes/3768838627869191?f=rss', 0, '', '{\"summary\": \"本文告知涉跨境业务出海企业大韩航空将上调国际航班燃油附加费，帮助企业提前规划航空出行与物流成本\", \"abstract\": \"4月16日据报道，大韩航空宣布将于下月起提高国际航班燃油附加费。上调后的燃油附加费按航线长短定价，每单程费用在75000韩元至564000韩元不等。短途航线收费较低，长途航线收费更高。此次调价会推高涉中韩跨境业务企业的航空相关成本。\", \"keywords\": [\"大韩航空\", \"国际航班\", \"燃油附加费\", \"跨境物流\", \"运营成本\"], \"policy_risk\": {\"market_risk\": \"大韩航空下月起上调国际航班燃油附加费，将推高出海企业跨境航空出行与物流的运营成本\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"供应链物流\", \"industry_category\": \"服务与基建\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3768838627869191?f=rss\", \"title\": \"大韩航空将从下月起提高国际航班燃油附加费\", \"source\": \"https://36kr.com/feed-newsflash\", \"content\": \"4月16日，据报道，大韩航空宣布，将从下个月起提高国际航班的燃油附加费，每单程费用为75000韩元至564000韩元不等。其中，从仁川出发飞往青岛、福冈等短途航线将收取75000韩元的燃油附加费，而飞往纽约、芝加哥等长途航线则需收取564000韩元。（界面）\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'大韩航空将从下月起提高国际航班燃油附加费\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'大韩航空将从下月起提高国际航班燃油附加费\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3768838627869191?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3768838627869191?f=rss\', \'published\': \'2026-04-16 09:40:54  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=1, tm_min=40, tm_sec=54, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'4月16日，据报道，大韩航空宣布，将从下个月起提高国际航班的燃油附加费，每单程费用为75000韩元至564000韩元不等。其中，从仁川出发飞往青岛、福冈等短途航线将收取75000韩元的燃油附加费，而飞往纽约、芝加哥等长途航线则需收取564000韩元。（界面）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-newsflash\', \'value\': \'4月16日，据报道，大韩航空宣布，将从下个月起提高国际航班的燃油附加费，每单程费用为75000韩元至564000韩元不等。其中，从仁川出发飞往青岛、福冈等短途航线将收取75000韩元的燃油附加费，而飞往纽约、芝加哥等长途航线则需收取564000韩元。（界面）\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 09:40:54\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 09:40:54', '2026-04-16 11:39:07');
INSERT INTO `news_detail` VALUES (14, 968, 13, '营销与品牌服务', '蓝色光标的“自我革命”：AI驱动收入37.25亿，Token消耗迈入万亿时代', '', '<p>4月15日晚间，蓝色光标发布2025年年度报告，全年实现营业收入686.93亿元，同比增长12.99%；经营活动产生的现金流净额6.32亿元，同比增长604.35%。CEO潘飞在《致投资人的一封信》中掷地有声地提出：“三十功名尘与土。30岁的蓝色光标，未来核心任务就一个——自我革命，重新创业。”毫无疑问，蓝色光标正以“AI Native”‌ 为核心进行一场深刻的结构性重塑。</p>\n<h3><strong>从工具到基建：万亿Token背后的AI进化论</strong></h3>\n<p>潘飞在信中坦言，蓝色光标“All in AI”已满三年，衡量其AI进程的最硬核指标，无疑是‌Token消耗量‌，这是AI是否真正深入业务流程“最诚实的起点标志”。 2025年，其API接入大模型消耗的词元（Token）总量‌首���突破1万亿‌；到了2026年，仅3月推理模型消耗的Token就‌突破2000亿‌。这标志着AI已渗入蓝色光标业务的“每一条毛细血管”——从社交媒体洞察、达人筛选，到广告风控、爆款素材提炼乃至视频内容生产，无处不渗透着智能的力量。</p>\n<h3><strong>“iPhone moment”：全链路智能决策新时代</strong></h3>\n<p>2025年，蓝色光标“AI驱动收入”已达‌37.25亿元‌。这类收入的特点是：极少人力投入、高自动化、更高毛利、业务模式新颖且数据可迭代。而比数字增长更激动人心的，是“‌真AI智能‌”的初步实现。</p>\n<p>旗下核心“智能引擎” Blue AI迎来标志性的里程碑时刻：2026年3月，其自研的智能投放系统，在包括制定策略、分配预算、投放决策在内的‌85%作业场景中，AI表现已超越人类，且全程无人工干预‌。更具启发性的数据是，2025年Blue AI内部发生的“A2A（AI-to-AI）”协同任务高达‌1.46亿次‌，这意味着大部分优化迭代已不再需要人工指挥，AI开始在内部实现自我演化。另一大平台 ‌“星合AI”则‌聚焦达人营销，实现了从洞察到分析的全链路自动化。2025年，该平台订单额‌突破10亿元‌，相关人均效能‌提升51%‌，彻底替换了传统作业模式。</p>\n<h3>‌<strong>内容能力的双轨飞跃：从规模量产到影视级殿堂</strong></h3>\n<p>作为一家内容公司，蓝色光标在AI多模态内容创作上践行“效率与审美并重”的策略。一方面，追求极致的智能化与自动化：借助“Blue AI心影”与“DDD端到端原生平台”等，实现了内容的快、准、规模化生产。2025年，Blue AI生产的视频内容达‌50万条‌，而仅2026年第一季度便已产出‌30万条‌。另一方面，则全力攀登“好莱坞级别”的顶级制作高峰。通过整合多模型、3D与动态捕捉技术，蓝色光标旗下的 ‌Blue Master‌ 与 ‌“蓝色多脑盒”在长镜头调度、情绪表演与多角色一致性上取得突破，并为百雀羚、Jeep等头部品牌交付了影视级水准的商业广告。此外，自制AI电影《新人类计划：索隆》已斩获多项国际金奖，参与的《再见萤火虫》也入围了第38届中国电影金鸡奖。</p>\n<h3><strong>范式迁移</strong>：<strong>探索营销行业的“星辰大海”</strong></h3>\n<p>蓝色光标正大力开拓“没有AI重度参与就不成立”的全新业务模式。第一个新模式：生成式引擎优化--帮助品牌在AI原生世界中建立和优化认知。第二个新模式：AI驱动的经营型服务‌--推动业务模式从“卖项目/单次交付”向“卖系统/持续在线的经营智能体”转变，构建SaaS之后的新服务形态。第三个新模式：千人亿面，实时生成‌--这是信中被认为是“最具想象力”的方向。潘飞指出，未来的营销将不再停留于“分发的个性化”，而是为每一个用户，在其接触的瞬间，实时生成独一无二的内容，这将彻底重写整个行业逻辑。</p>\n<p>而为了实现模式创新与技术前瞻，2025年也是蓝色光标‌战略聚焦AI投资‌的元年。他们已投资6家AI Native公司，覆盖多模态生成、AI达人营销、数字员工基础设施、生成引擎优化、AI广告投放决策五大方向，并与投资标的形成深度业务协同，旨在“保持和最前沿能力的同频共振”。</p>\n<h3><strong>AI Native的组织变革：AI投入不设上限，决策一律“AI First”</strong></h3>\n<p>蓝色光标正将自己重构为一家 ‌“AI Native组织”‌ 。其核心标准已变为“‌AI Native + AI First‌”， 这意味着决策、协作、人才标准与激励机制都将以AI为基因进行重构。公司规定，管理层中必须有 ‌30%至50%是具备AI能力的领导者‌，并将AI指标与考核、奖金强绑定，“No AI, No Bonus”已成为硬规则。</p>\n<p>技术投入上，公司亦不设上限。2025年AI技术人才相关投入达‌9521万元‌，同比增长‌76.52%‌；若计入基建与研发，总投入达‌1.8亿元‌。潘飞透露，“未来几年，蓝色光标的研发费用还会持续快速增长。</p>\n<h3><strong>全球化2.0：纵深突破，从\"代理驱动\"到\"技术驱动\"</strong></h3>\n<p>作为公司另一大核心引擎，蓝色光标2025年出海广告投放收入564.96亿元，同比增长16.89%，在总营收中占比达82.25%。目前，蓝色光标出海业务的总体量及市场占有率稳居中国第一，已助力超十万家中国企业出海。</p>\n<p>然而，潘飞并不满足于单纯的规模扩张。他在信中正式提出了全球化2.0战略下的几个转变：其一，从单纯追求增长转向改变利润结构，推行“5-3-2利润新准则”--50%利润来自三大头部媒体，30%来自腰部媒体，20%来自自建平台及技术；这标志着蓝色光标正从“代理驱动”向“技术驱动型全球营销平台”跃迁。其二，从远程服务转向‌自建全球办公室驱动‌，蓝色光标已开设7家海外办公室，其中新加坡、越南、泰国、印尼等办公室发展迅速，两家以上已进入规模化盈利阶段；预计2026年超10家。其三，从‌代理驱动走向技术驱动‌，依托Blue X、Blue Turbo等技术平台自建流量池；最后，在全球化业务场景中‌全面AI化‌，探索AI原生商业模式。</p>\n<h3><strong>未来展望</strong></h3>\n<p>这家三十而立的企业，正以壮士断腕的决心开启“二次创业”。它所要创造的，‌“不是一个效率更高的旧公司，而是一个面向未来的全新蓝色光标——一家真正的AI（营销）科技公司，一种新文化，一套新引擎。”<strong>‌</strong></p>\n<p>2026年，“自我革命、重新出发”的蓝色光标，将驶向更广阔的海域。</p>', 'https://36kr.com/p/3768876765496065?f=rss', 0, '', '{\"summary\": \"本文介绍蓝色光标AI转型与全球化2.0出海战略升级经验，为出海营销服务企业转型提供参考\", \"abstract\": \"蓝色光标发布2025年年度报告，全年实现营收686.93亿元，正以AI Native为核心推进结构性重塑与自我革命。其AI转型成效显著，2025年AI驱动收入达37.25亿元，大模型Token消耗量突破万亿，多业务场景实现AI全链路自动化，效能大幅提升。蓝色光标出海广告投放收入达564.96亿元，占总营收82.25%，出海业务体量稳居国内第一，目前正式启动全球化2.0战略，推动出海业务从代理驱动向技术驱动转型，全面实现AI化。公司从组织、投入层面全面适配AI转型，探索营销行业全新业务范式。\", \"keywords\": [\"出海营销\", \"AI Native\", \"全球化2.0\", \"Token消耗\", \"AI驱动收入\", \"智能投放\", \"营销转型\", \"蓝色光标\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外营销\", \"industry_category\": \"营销与品牌服务\"}', '', '{\"url\": \"https://36kr.com/p/3768876765496065?f=rss\", \"title\": \"蓝色光标的“自我革命”：AI驱动收入37.25亿，Token消耗迈入万亿时代\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>4月15日晚间，蓝色光标发布2025年年度报告，全年实现营业收入686.93亿元，同比增长12.99%；经营活动产生的现金流净额6.32亿元，同比增长604.35%。CEO潘飞在《致投资人的一封信》中掷地有声地提出：“三十功名尘与土。30岁的蓝色光标，未来核心任务就一个——自我革命，重新创业。”毫无疑问，蓝色光标正以“AI Native”‌ 为核心进行一场深刻的结构性重塑。</p>\\n<h3><strong>从工具到基建：万亿Token背后的AI进化论</strong></h3>\\n<p>潘飞在信中坦言，蓝色光标“All in AI”已满三年，衡量其AI进程的最硬核指标，无疑是‌Token消耗量‌，这是AI是否真正深入业务流程“最诚实的起点标志”。 2025年，其API接入大模型消耗的词元（Token）总量‌首���突破1万亿‌；到了2026年，仅3月推理模型消耗的Token就‌突破2000亿‌。这标志着AI已渗入蓝色光标业务的“每一条毛细血管”——从社交媒体洞察、达人筛选，到广告风控、爆款素材提炼乃至视频内容生产，无处不渗透着智能的力量。</p>\\n<h3><strong>“iPhone moment”：全链路智能决策新时代</strong></h3>\\n<p>2025年，蓝色光标“AI驱动收入”已达‌37.25亿元‌。这类收入的特点是：极少人力投入、高自动化、更高毛利、业务模式新颖且数据可迭代。而比数字增长更激动人心的，是“‌真AI智能‌”的初步实现。</p>\\n<p>旗下核心“智能引擎” Blue AI迎来标志性的里程碑时刻：2026年3月，其自研的智能投放系统，在包括制定策略、分配预算、投放决策在内的‌85%作业场景中，AI表现已超越人类，且全程无人工干预‌。更具启发性的数据是，2025年Blue AI内部发生的“A2A（AI-to-AI）”协同任务高达‌1.46亿次‌，这意味着大部分优化迭代已不再需要人工指挥，AI开始在内部实现自我演化。另一大平台 ‌“星合AI”则‌聚焦达人营销，实现了从洞察到分析的全链路自动化。2025年，该平台订单额‌突破10亿元‌，相关人均效能‌提升51%‌，彻底替换了传统作业模式。</p>\\n<h3>‌<strong>内容能力的双轨飞跃：从规模量产到影视级殿堂</strong></h3>\\n<p>作为一家内容公司，蓝色光标在AI多模态内容创作上践行“效率与审美并重”的策略。一方面，追求极致的智能化与自动化：借助“Blue AI心影”与“DDD端到端原生平台”等，实现了内容的快、准、规模化生产。2025年，Blue AI生产的视频内容达‌50万条‌，而仅2026年第一季度便已产出‌30万条‌。另一方面，则全力攀登“好莱坞级别”的顶级制作高峰。通过整合多模型、3D与动态捕捉技术，蓝色光标旗下的 ‌Blue Master‌ 与 ‌“蓝色多脑盒”在长镜头调度、情绪表演与多角色一致性上取得突破，并为百雀羚、Jeep等头部品牌交付了影视级水准的商业广告。此外，自制AI电影《新人类计划：索隆》已斩获多项国际金奖，参与的《再见萤火虫》也入围了第38届中国电影金鸡奖。</p>\\n<h3><strong>范式迁移</strong>：<strong>探索营销行业的“星辰大海”</strong></h3>\\n<p>蓝色光标正大力开拓“没有AI重度参与就不成立”的全新业务模式。第一个新模式：生成式引擎优化--帮助品牌在AI原生世界中建立和优化认知。第二个新模式：AI驱动的经营型服务‌--推动业务模式从“卖项目/单次交付”向“卖系统/持续在线的经营智能体”转变，构建SaaS之后的新服务形态。第三个新模式：千人亿面，实时生成‌--这是信中被认为是“最具想象力”的方向。潘飞指出，未来的营销将不再停留于“分发的个性化”，而是为每一个用户，在其接触的瞬间，实时生成独一无二的内容，这将彻底重写整个行业逻辑。</p>\\n<p>而为了实现模式创新与技术前瞻，2025年也是蓝色光标‌战略聚焦AI投资‌的元年。他们已投资6家AI Native公司，覆盖多模态生成、AI达人营销、数字员工基础设施、生成引擎优化、AI广告投放决策五大方向，并与投资标的形成深度业务协同，旨在“保持和最前沿能力的同频共振”。</p>\\n<h3><strong>AI Native的组织变革：AI投入不设上限，决策一律“AI First”</strong></h3>\\n<p>蓝色光标正将自己重构为一家 ‌“AI Native组织”‌ 。其核心标准已变为“‌AI Native + AI First‌”， 这意味着决策、协作、人才标准与激励机制都将以AI为基因进行重构。公司规定，管理层中必须有 ‌30%至50%是具备AI能力的领导者‌，并将AI指标与考核、奖金强绑定，“No AI, No Bonus”已成为硬规则。</p>\\n<p>技术投入上，公司亦不设上限。2025年AI技术人才相关投入达‌9521万元‌，同比增长‌76.52%‌；若计入基建与研发，总投入达‌1.8亿元‌。潘飞透露，“未来几年，蓝色光标的研发费用还会持续快速增长。</p>\\n<h3><strong>全球化2.0：纵深突破，从\\\"代理驱动\\\"到\\\"技术驱动\\\"</strong></h3>\\n<p>作为公司另一大核心引擎，蓝色光标2025年出海广告投放收入564.96亿元，同比增长16.89%，在总营收中占比达82.25%。目前，蓝色光标出海业务的总体量及市场占有率稳居中国第一，已助力超十万家中国企业出海。</p>\\n<p>然而，潘飞并不满足于单纯的规模扩张。他在信中正式提出了全球化2.0战略下的几个转变：其一，从单纯追求增长转向改变利润结构，推行“5-3-2利润新准则”--50%利润来自三大头部媒体，30%来自腰部媒体，20%来自自建平台及技术；这标志着蓝色光标正从“代理驱动”向“技术驱动型全球营销平台”跃迁。其二，从远程服务转向‌自建全球办公室驱动‌，蓝色光标已开设7家海外办公室，其中新加坡、越南、泰国、印尼等办公室发展迅速，两家以上已进入规模化盈利阶段；预计2026年超10家。其三，从‌代理驱动走向技术驱动‌，依托Blue X、Blue Turbo等技术平台自建流量池；最后，在全球化业务场景中‌全面AI化‌，探索AI原生商业模式。</p>\\n<h3><strong>未来展望</strong></h3>\\n<p>这家三十而立的企业，正以壮士断腕的决心开启“二次创业”。它所要创造的，‌“不是一个效率更高的旧公司，而是一个面向未来的全新蓝色光标——一家真正的AI（营销）科技公司，一种新文化，一套新引擎。”<strong>‌</strong></p>\\n<p>2026年，“自我革命、重新出发”的蓝色光标，将驶向更广阔的海域。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'蓝色光标的“自我革命”：AI驱动收入37.25亿，Token消耗迈入万亿时代\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'蓝色光标的“自我革命”：AI驱动收入37.25亿，Token消耗迈入万亿时代\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768876765496065?f=rss\'}], \'link\': \'https://36kr.com/p/3768876765496065?f=rss\', \'published\': \'2026-04-16 10:20:28  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=20, tm_sec=28, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>4月15日晚间，蓝色光标发布2025年年度报告，全年实现营业收入686.93亿元，同比增长12.99%；经营活动产生的现金流净额6.32亿元，同比增长604.35%。CEO潘飞在《致投资人的一封信》中掷地有声地提出：“三十功名尘与土。30岁的蓝色光标，未来核心任务就一个——自我革命，重新创业。”毫无疑问，蓝色光标正以“AI Native”\\\\u200c&nbsp;为核心进行一场深刻的结构性重塑。</p>\\\\n  <h3><strong>从工具到基建：万亿Token背后的AI进化论</strong></h3>\\\\n  <p>潘飞在信中坦言，蓝色光标“All in AI”已满三年，衡量其AI进程的最硬核指标，无疑是\\\\u200cToken消耗量\\\\u200c，这是AI是否真正深入业务流程“最诚实的起点标志”。 2025年，其API接入大模型消耗的词元（Token）总量\\\\u200c首���突破1万亿\\\\u200c；到了2026年，仅3月推理模型消耗的Token就\\\\u200c突破2000亿\\\\u200c。这标志着AI已渗入蓝色光标业务的“每一条毛细血管”——从社交媒体洞察、达人筛选，到广告风控、爆款素材提炼乃至视频内容生产，无处不渗透着智能的力量。</p>\\\\n  <h3><strong>“iPhone moment”：全链路智能决策新时代</strong></h3>\\\\n  <p>2025年，蓝色光标“AI驱动收入”已达\\\\u200c37.25亿元\\\\u200c。这类收入的特点是：极少人力投入、高自动化、更高毛利、业务模式新颖且数据可迭代。而比数字增长更激动人心的，是“\\\\u200c真AI智能\\\\u200c”的初步实现。</p>\\\\n  <p>旗下核心“智能引擎” Blue AI迎来标志性的里程碑时刻：2026年3月，其自研的智能投放系统，在包括制定策略、分配预算、投放决策在内的\\\\u200c85%作业场景中，AI表现已超越人类，且全程无人工干预\\\\u200c。更具启发性的数据是，2025年Blue AI内部发生的“A2A（AI-to-AI）”协同任务高达\\\\u200c1.46亿次\\\\u200c，这意味着大部分优化迭代已不再需要人工指挥，AI开始在内部实现自我演化。另一大平台 \\\\u200c“星合AI”则\\\\u200c聚焦达人营销，实现了从洞察到分析的全链路自动化。2025年，该平台订单额\\\\u200c突破10亿元\\\\u200c，相关人均效能\\\\u200c提升51%\\\\u200c，彻底替换了传统作业模式。</p>\\\\n  <h3>\\\\u200c<strong>内容能力的双轨飞跃：从规模量产到影视级殿堂</strong></h3>\\\\n  <p>作为一家内容公司，蓝色光标在AI多模态内容创作上践行“效率与审美并重”的策略。一方面，追求极致的智能化与自动化：借助“Blue AI心影”与“DDD端到端原生平台”等，实现了内容的快、准、规模化生产。2025年，Blue AI生产的视频内容达\\\\u200c50万条\\\\u200c，而仅2026年第一季度便已产出\\\\u200c30万条\\\\u200c。另一方面，则全力攀登“好莱坞级别”的顶级制作高峰。通过整合多模型、3D与动态捕捉技术，蓝色光标旗下的 \\\\u200cBlue Master\\\\u200c&nbsp;与 \\\\u200c“蓝色多脑盒”在长镜头调度、情绪表演与多角色一致性上取得突破，并为百雀羚、Jeep等头部品牌交付了影视级水准的商业广告。此外，自制AI电影《新人类计划：索隆》已斩获多项国际金奖，参与的《再见萤火虫》也入围了第38届中国电影金鸡奖。</p>\\\\n  <h3><strong>范式迁移</strong>：<strong>探索营销行业的“星辰大海”</strong></h3>\\\\n  <p>蓝色光标正大力开拓“没有AI重度参与就不成立”的全新业务模式。第一个新模式：生成式引擎优化--帮助品牌在AI原生世界中建立和优化认知。第二个新模式：AI驱动的经营型服务\\\\u200c--推动业务模式从“卖项目/单次交付”向“卖系统/持续在线的经营智能体”转变，构建SaaS之后的新服务形态。第三个新模式：千人亿面，实时生成\\\\u200c--这是信中被认为是“最具想象力”的方向。潘飞指出，未来的营销将不再停留于“分发的个性化”，而是为每一个用户，在其接触的瞬间，实时生成独一无二的内容，这将彻底重写整个行业逻辑。</p>\\\\n  <p>而为了实现模式创新与技术前瞻，2025年也是蓝色光标\\\\u200c战略聚焦AI投资\\\\u200c的元年。他们已投资6家AI Native公司，覆盖多模态生成、AI达人营销、数字员工基础设施、生成引擎优化、AI广告投放决策五大方向，并与投资标的形成深度业务协同，旨在“保持和最前沿能力的同频共振”。</p>\\\\n  <h3><strong>AI Native的组织变革：AI投入不设上限，决策一律“AI First”</strong></h3>\\\\n  <p>蓝色光标正将自己重构为一家 \\\\u200c“AI Native组织”\\\\u200c&nbsp;。其核心标准已变为“\\\\u200cAI Native + AI First\\\\u200c”， 这意味着决策、协作、人才标准与激励机制都将以AI为基因进行重构。公司规定，管理层中必须有 \\\\u200c30%至50%是具备AI能力的领导者\\\\u200c，并将AI指标与考核、奖金强绑定，“No AI, No Bonus”已成为硬规则。</p>\\\\n  <p>技术投入上，公司亦不设上限。2025年AI技术人才相关投入达\\\\u200c9521万元\\\\u200c，同比增长\\\\u200c76.52%\\\\u200c；若计入基建与研发，总投入达\\\\u200c1.8亿元\\\\u200c。潘飞透露，“未来几年，蓝色光标的研发费用还会持续快速增长。</p>\\\\n  <h3><strong>全球化2.0：纵深突破，从\\\"代理驱动\\\"到\\\"技术驱动\\\"</strong></h3>\\\\n  <p>作为公司另一大核心引擎，蓝色光标2025年出海广告投放收入564.96亿元，同比增长16.89%，在总营收中占比达82.25%。目前，蓝色光标出海业务的总体量及市场占有率稳居中国第一，已助力超十万家中国企业出海。</p>\\\\n  <p>然而，潘飞并不满足于单纯的规模扩张。他在信中正式提出了全球化2.0战略下的几个转变：其一，从单纯追求增长转向改变利润结构，推行“5-3-2利润新准则”--50%利润来自三大头部媒体，30%来自腰部媒体，20%来自自建平台及技术；这标志着蓝色光标正从“代理驱动”向“技术驱动型全球营销平台”跃迁。其二，从远程服务转向\\\\u200c自建全球办公室驱动\\\\u200c，蓝色光标已开设7家海外办公室，其中新加坡、越南、泰国、印尼等办公室发展迅速，两家以上已进入规模化盈利阶段；预计2026年超10家。其三，从\\\\u200c代理驱动走向技术驱动\\\\u200c，依托Blue X、Blue Turbo等技术平台自建流量池；最后，在全球化业务场景中\\\\u200c全面AI化\\\\u200c，探索AI原生商业模式。</p>\\\\n  <h3><strong>未来展望</strong></h3>\\\\n  <p>这家三十而立的企业，正以壮士断腕的决心开启“二次创业”。它所要创造的，\\\\u200c“不是一个效率更高的旧公司，而是一个面向未来的全新蓝色光标——一家真正的AI（营销）科技公司，一种新文化，一套新引擎。”<strong>\\\\u200c</strong></p>\\\\n  <p>2026年，“自我革命、重新出发”的蓝色光标，将驶向更广阔的海域。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>4月15日晚间，蓝色光标发布2025年年度报告，全年实现营业收入686.93亿元，同比增长12.99%；经营活动产生的现金流净额6.32亿元，同比增长604.35%。CEO潘飞在《致投资人的一封信》中掷地有声地提出：“三十功名尘与土。30岁的蓝色光标，未来核心任务就一个——自我革命，重新创业。”毫无疑问，蓝色光标正以“AI Native”\\\\u200c&nbsp;为核心进行一场深刻的结构性重塑。</p>\\\\n  <h3><strong>从工具到基建：万亿Token背后的AI进化论</strong></h3>\\\\n  <p>潘飞在信中坦言，蓝色光标“All in AI”已满三年，衡量其AI进程的最硬核指标，无疑是\\\\u200cToken消耗量\\\\u200c，这是AI是否真正深入业务流程“最诚实的起点标志”。 2025年，其API接入大模型消耗的词元（Token）总量\\\\u200c首���突破1万亿\\\\u200c；到了2026年，仅3月推理模型消耗的Token就\\\\u200c突破2000亿\\\\u200c。这标志着AI已渗入蓝色光标业务的“每一条毛细血管”——从社交媒体洞察、达人筛选，到广告风控、爆款素材提炼乃至视频内容生产，无处不渗透着智能的力量。</p>\\\\n  <h3><strong>“iPhone moment”：全链路智能决策新时代</strong></h3>\\\\n  <p>2025年，蓝色光标“AI驱动收入”已达\\\\u200c37.25亿元\\\\u200c。这类收入的特点是：极少人力投入、高自动化、更高毛利、业务模式新颖且数据可迭代。而比数字增长更激动人心的，是“\\\\u200c真AI智能\\\\u200c”的初步实现。</p>\\\\n  <p>旗下核心“智能引擎” Blue AI迎来标志性的里程碑时刻：2026年3月，其自研的智能投放系统，在包括制定策略、分配预算、投放决策在内的\\\\u200c85%作业场景中，AI表现已超越人类，且全程无人工干预\\\\u200c。更具启发性的数据是，2025年Blue AI内部发生的“A2A（AI-to-AI）”协同任务高达\\\\u200c1.46亿次\\\\u200c，这意味着大部分优化迭代已不再需要人工指挥，AI开始在内部实现自我演化。另一大平台 \\\\u200c“星合AI”则\\\\u200c聚焦达人营销，实现了从洞察到分析的全链路自动化。2025年，该平台订单额\\\\u200c突破10亿元\\\\u200c，相关人均效能\\\\u200c提升51%\\\\u200c，彻底替换了传统作业模式。</p>\\\\n  <h3>\\\\u200c<strong>内容能力的双轨飞跃：从规模量产到影视级殿堂</strong></h3>\\\\n  <p>作为一家内容公司，蓝色光标在AI多模态内容创作上践行“效率与审美并重”的策略。一方面，追求极致的智能化与自动化：借助“Blue AI心影”与“DDD端到端原生平台”等，实现了内容的快、准、规模化生产。2025年，Blue AI生产的视频内容达\\\\u200c50万条\\\\u200c，而仅2026年第一季度便已产出\\\\u200c30万条\\\\u200c。另一方面，则全力攀登“好莱坞级别”的顶级制作高峰。通过整合多模型、3D与动态捕捉技术，蓝色光标旗下的 \\\\u200cBlue Master\\\\u200c&nbsp;与 \\\\u200c“蓝色多脑盒”在长镜头调度、情绪表演与多角色一致性上取得突破，并为百雀羚、Jeep等头部品牌交付了影视级水准的商业广告。此外，自制AI电影《新人类计划：索隆》已斩获多项国际金奖，参与的《再见萤火虫》也入围了第38届中国电影金鸡奖。</p>\\\\n  <h3><strong>范式迁移</strong>：<strong>探索营销行业的“星辰大海”</strong></h3>\\\\n  <p>蓝色光标正大力开拓“没有AI重度参与就不成立”的全新业务模式。第一个新模式：生成式引擎优化--帮助品牌在AI原生世界中建立和优化认知。第二个新模式：AI驱动的经营型服务\\\\u200c--推动业务模式从“卖项目/单次交付”向“卖系统/持续在线的经营智能体”转变，构建SaaS之后的新服务形态。第三个新模式：千人亿面，实时生成\\\\u200c--这是信中被认为是“最具想象力”的方向。潘飞指出，未来的营销将不再停留于“分发的个性化”，而是为每一个用户，在其接触的瞬间，实时生成独一无二的内容，这将彻底重写整个行业逻辑。</p>\\\\n  <p>而为了实现模式创新与技术前瞻，2025年也是蓝色光标\\\\u200c战略聚焦AI投资\\\\u200c的元年。他们已投资6家AI Native公司，覆盖多模态生成、AI达人营销、数字员工基础设施、生成引擎优化、AI广告投放决策五大方向，并与投资标的形成深度业务协同，旨在“保持和最前沿能力的同频共振”。</p>\\\\n  <h3><strong>AI Native的组织变革：AI投入不设上限，决策一律“AI First”</strong></h3>\\\\n  <p>蓝色光标正将自己重构为一家 \\\\u200c“AI Native组织”\\\\u200c&nbsp;。其核心标准已变为“\\\\u200cAI Native + AI First\\\\u200c”， 这意味着决策、协作、人才标准与激励机制都将以AI为基因进行重构。公司规定，管理层中必须有 \\\\u200c30%至50%是具备AI能力的领导者\\\\u200c，并将AI指标与考核、奖金强绑定，“No AI, No Bonus”已成为硬规则。</p>\\\\n  <p>技术投入上，公司亦不设上限。2025年AI技术人才相关投入达\\\\u200c9521万元\\\\u200c，同比增长\\\\u200c76.52%\\\\u200c；若计入基建与研发，总投入达\\\\u200c1.8亿元\\\\u200c。潘飞透露，“未来几年，蓝色光标的研发费用还会持续快速增长。</p>\\\\n  <h3><strong>全球化2.0：纵深突破，从\\\"代理驱动\\\"到\\\"技术驱动\\\"</strong></h3>\\\\n  <p>作为公司另一大核心引擎，蓝色光标2025年出海广告投放收入564.96亿元，同比增长16.89%，在总营收中占比达82.25%。目前，蓝色光标出海业务的总体量及市场占有率稳居中国第一，已助力超十万家中国企业出海。</p>\\\\n  <p>然而，潘飞并不满足于单纯的规模扩张。他在信中正式提出了全球化2.0战略下的几个转变：其一，从单纯追求增长转向改变利润结构，推行“5-3-2利润新准则”--50%利润来自三大头部媒体，30%来自腰部媒体，20%来自自建平台及技术；这标志着蓝色光标正从“代理驱动”向“技术驱动型全球营销平台”跃迁。其二，从远程服务转向\\\\u200c自建全球办公室驱动\\\\u200c，蓝色光标已开设7家海外办公室，其中新加坡、越南、泰国、印尼等办公室发展迅速，两家以上已进入规模化盈利阶段；预计2026年超10家。其三，从\\\\u200c代理驱动走向技术驱动\\\\u200c，依托Blue X、Blue Turbo等技术平台自建流量池；最后，在全球化业务场景中\\\\u200c全面AI化\\\\u200c，探索AI原生商业模式。</p>\\\\n  <h3><strong>未来展望</strong></h3>\\\\n  <p>这家三十而立的企业，正以壮士断腕的决心开启“二次创业”。它所要创造的，\\\\u200c“不是一个效率更高的旧公司，而是一个面向未来的全新蓝色光标——一家真正的AI（营销）科技公司，一种新文化，一套新引擎。”<strong>\\\\u200c</strong></p>\\\\n  <p>2026年，“自我革命、重新出发”的蓝色光标，将驶向更广阔的海域。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'36氪品牌\'}], \'author\': \'36氪品牌\', \'author_detail\': {\'name\': \'36氪品牌\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'透视蓝色光标三十年“自我革命”新征程。\'}]}\", \"published_at\": \"2026-04-16 10:20:28\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 10:20:28', '2026-04-16 11:40:07');
INSERT INTO `news_detail` VALUES (15, 969, 18, '硬件与半导体出海', '李斌投出的百亿IPO，要翻番了', '', '<blockquote>\n<p>2025年12月10日，图达通（Seyond Holdings Ltd.）正式在港交所挂牌上市，市值一度达到180亿港元。</p>\n<p>图达通2025年财报显示，大客户蔚来的收入占比下降，客户结构显著优化，截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\n<p>对于2026年的市场增速，创始人鲍君威有着清晰的判断：“今年几近翻番。”</p>\n</blockquote>\n<p>“我们去年全年交付了33.25万颗激光雷达，灵雀系列卖了13.8万颗，同比增长超10倍。”</p>\n<p>图达通创始人兼CEO鲍君威在加州接受亿欧汽车采访时表示，灵雀的大规模放量，标志着公司正式从高端市场，向更广阔的主流乘用车市场延伸。</p>\n<p>作为全球图像级激光雷达解决方案提供商，图达通在2025年交出了一份极具转折意义的业绩答卷：</p>\n<p>全年营收约11.02亿元，毛利率由2024年的负8.7%提升至正7.9%，经调整净亏损收窄24%，现金及现金等价物同比增长146%。</p>\n<p>目前，图达通也是业内唯一同时实现1550nm与905nm/940nm双技术路线成熟量产的激光雷达企业。随着财务状况持续改善、现金储备充裕，公司毛利率已正式迈过盈亏平衡关键线。</p>\n<p>截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\n<p>鲍君威对即将到来的「百万台」节点，信心倍增。</p>\n<h2><strong>硅谷16年，45岁再创业</strong></h2>\n<p>“我是在伯克利读博期间第一次创业的。”鲍君威对亿欧汽车回忆道。</p>\n<p>上世纪90年代中期，鲍君威从北京大学物理系毕业后赴美留学，在加州大学伯克利分校攻读博士学位。他的研究方向紧密围绕半导体设备与生产线，天然具备与产业深度结合的优势。</p>\n<p>“也正因如此，我们抓住了一些机会。”鲍君威回忆道，他与两位师兄共同创立公司，将实验室的研究成果推向产业化。项目运营两三年间，公司顺利完成融资并实现营收，最终被日本规模最大的半导体设备企业收购。</p>\n<p>彼时他尚未毕业，作为联合创始人便收获了人生第一桶金，也摸清了硅谷的创业逻辑与产业脉络。博士毕业后，鲍君威加入这家日本企业，一待便是十余年。</p>\n<p>安逸，是他那段时光的形容词。</p>\n<p>但安逸，并不是他想要的。</p>\n<p>“我想换个行业，换个赛道，试一试新的东西。”</p>\n<p>2014年，鲍君威加入百度美国研发中心，负责自动驾驶硬件平台。彼时百度正在硅谷搭建自动驾驶团队，寻找科技前沿的脉搏。</p>\n<p>“百度当时愿意去尝试、去探索试错。”在百度硅谷团队，鲍君威主导自动驾驶硬件平台研发，也因此与激光雷达产生深度交集。</p>\n<p>“我梳理了自动驾驶所需的各类传感器，包括计算系统、摄像头、毫米波雷达、GPS、IMU等，其中唯一不成熟、甚至缺口明显的就是激光雷达，而它又是自动驾驶不可或缺的核心部件。”</p>\n<p>这一刻，他真切意识到，那些在自家附近两三公里路段测试的谷歌自动驾驶车辆，未来真有可能走进寻常百姓家。</p>\n<p>“自动驾驶从不是空想，而激光雷达，就是实现规模化落地的关键。”</p>\n<p>2016年，通用汽车以超过5亿美元的估值收购了Cruise，Uber不惜重金挖角谷歌自动驾驶核心团队。硅谷资本迅速嗅到机遇，自动驾驶赛道迎来爆发前夜。</p>\n<p>“我42岁加入百度，45岁正式出来创业。”鲍君威说道，“说冒险还谈不上，也不需要自夸。”</p>\n<p>但从零组建团队、从头开拓业务，与鲍君威以往按部就班的职场生涯截然不同。</p>\n<p>2016年，图达通在硅谷成立。早期，公司只有几个人，鲍君威就带着他们在硅谷的实验室里一点点打磨产品。</p>\n<p>彼时，全球激光雷达行业尚处混沌初期：美国厂商Velodyne起步较早，但产品技术初级、定价居高不下；国内玩家也刚刚起步，禾赛、速腾聚创等企业多聚焦本土市场。</p>\n<p>而鲍君威从一开始，就把目光投向了全球。</p>\n<p>“在硅谷深耕多年，我深知全球市场的广阔体量，也清楚中国企业的制造与供应链优势，我们不该局限于国内市场。要做，就做面向全球的生意。”</p>\n<p>“Velodyne与多普勒等厂商入局较早，但产品形态相对初级，市场需求也未真正爆发。”鲍君威表示，“等到2015、2016年行业需求崛起，短短两三年内，全球涌现出上百家激光雷达企业，各类技术路线与商业模式层出不穷。”</p>\n<p>在A轮融资前，图达通与国内市场几乎没有交集。完成A轮融资后，鲍君威果断决定在中国设立子公司，并于2019年正式落地苏州。</p>\n<p>公司真正的关键转折点，出现在2020年底。</p>\n<p>“蔚来向我们发出了定点项目合作。”鲍君威说道，“客户在哪里，我们就要离得更近。”</p>\n<p>蔚来成为图达通首个实现大规模量产的核心客户。</p>\n<p>随着搭载图达通猎鹰激光雷达的蔚来车型陆续上市，鲍君威终于完成了从实验室技术到车规级量产产品的跨越，让自研激光雷达真正驶上规模化应用的道路。</p>\n<h2><strong>从「小众奢侈」到「全民普及」</strong></h2>\n<p>“我们是唯一具备双技术路线量产能力的企业。”鲍君威说道。</p>\n<p>图达通采取“双技术路线并行”战略，构建了覆盖多元场景的产品矩阵。</p>\n<p>1550nm高性能超远距技术路线，聚焦L3+全场景自动驾驶，猎鹰平台已经累计交付超过了70万台，是目前唯一能批量交付图像级超远距激光雷达的企业。</p>\n<p>此外，905nm/940nm兼顾性能与成本路线，灵雀平台适配L2+辅助驾驶，2025年交付达13.8万颗，同比增长超过10倍。</p>\n<p>纯固态技术蜂鸟平台，兼具高性能与低成本优势，已获得头部主机厂定点。</p>\n<p>谈及905纳米产品的市场表现，鲍君威表示：“去年我们905纳米产品出了十几万台货，给蔚来，也给其他厂商供货。���</p>\n<p>他不回避行业内的质疑，坦然说道：“有人会质疑我们在做到超高性能的同时，能不能把成本结构做好？我们用实际成绩证明了，不仅可以快速做好产品、实现规模化出货，连纯固态激光雷达也顺利拿到了定点，跟友商站在同一个起跑线上，甚至在部分技术细节上，我们还有自己的优势。”</p>\n<p>截至2025年底，图达通已累计获得18家主机厂及ADAS/ADS公司定点，覆盖超60款车型。</p>\n<p>蔚来收入占比由97.3%降至86.2%，客户结构显著优化。新增客户包括上汽大众、广汽集团等传统车企，以及陕汽重卡、福田汽车、小马智行等商用车及自动驾驶头部企业。</p>\n<p>“我们不依赖单一客户，这是我们能稳健发展的根本。”鲍君威说道，“汽车行业的供应链，从来都不是一家独大，我们要做的，是成为全球智能汽车供应链里，不可或缺的一员。”</p>\n<p>采访中，鲍君威还回应了马斯克“不用激光雷达”的观点。“我们始终认为激光雷达是必须的。”他直言不讳，“不是激光雷达不好，是马斯克当年没有好的激光雷达可用，只能退而求其次。”</p>\n<p>在鲍君威看来，人类造系统，不是为了和人一样，而是要比人更好、更安全。汽车的安全气囊、安全带，平时用不上，但关键时刻能救命，激光雷达也是一样，它是自动驾驶的安全冗余，“花几百美金，就能换来数倍的安全提升，这很值。”</p>\n<p>如今，54岁的鲍君威，依然保持着工程师的严谨和创业者的冲劲。他见证并推动了激光雷达从「小众奢侈」到「全民普及」的过程，也带领图达通，从硅谷的一间小办公室，成长为全球激光雷达行业的领军者。</p>\n<p>2025年，图达通销售成本为1.42亿美元，较2024年的1.73亿美元同比下降18.2%。毛利率由负转正至7.9%。鲍君威把这归功于工程设计优化、运营效率提升、规模效应、核心器件本地化采购、以及自研模块的持续推进。</p>\n<p>“毛利率转正是公司经营质效提升的核心信号。”鲍君威说道，“意味着我们已经具备自我造血能力。”</p>\n<p>2026年第一季度，图达通激光雷达交付量约17万颗，同比增长约310%，收入约5500万美元。这打破了Q1是行业传统销售淡季的规律。其中猎鹰系列交付超过6万颗，灵雀系列约11万颗。</p>\n<p>“今年我们预计交付量有望达到约100万台。”鲍君威坦言，截至2026年3月31日，图达通的年设计产能约为120万台，计划于2026年新增产能100万台，其中将包括一条专门用于生产蜂鸟系列的生产线。</p>\n<h2><strong>全球化布局，激光雷达将无处不在</strong></h2>\n<p>“我们想做的一直都是全球市场。”鲍君威道出了图达通的发展野心。</p>\n<p>这份全球野心，并非空谈。</p>\n<p>图达通目前已是国内激光雷达厂商中，唯一一家在美国拥有生产产线的企业，从硅谷的研发中心，到苏州的生产基地，再到欧洲的市场布局，鲍君威一步步搭建起了覆盖全球的研发、生产、销售体系。</p>\n<p>“各个国家都有本土产业保护的需求，也有信任的考量，我们在美国设产线，就是要真正融入当地，拿到当地市场的认可；而欧洲市场，我们是最早进入的中国激光雷达企业，早早发现了他们在智慧交通上的潜在需求。”鲍君威坦言，这份先发优势，是图达通全球化布局的关键底气。</p>\n<p>2025年，图达通的海外布局迎来了实质性突破：</p>\n<p>图达通与瑞典ITS基础设施商Aventi Sweden达成战略合作，拿下近260万美元订单，把自主研发的智慧交通系统管理平台，落地到了欧洲的关键交通路口。</p>\n<p>“这不是偶然，是我们提前布局的结果。”鲍君威说道，“欧洲对智慧交通的要求很高，对产品的可靠性、安全性要求也严，我们能拿下这个订单，就是因为我们的技术和产品，能真正满足他们的需求，这就是我们的先发优势。”</p>\n<p>在国内，图达通的激光雷达，已在超过15条全自动地铁线路部署运行，港口船闸领域累计交付超1000套。此外，泛机器人赛道也迎来爆发式增长。</p>\n<p>2025年，图达通在机器人及其他产品领域的收入达1891万美元，同比增长130%，收入占比从2024年的5.1%提升至12.3%，成功启动了企业发展的第二增长曲线。</p>\n<p>其中，仅九识科技一家客户，图达通就交付了超过2.1万颗产品；非中国区的机器人及其他业务，也实现了约80%的同比增长，同时拿下了中力股份、库萨科技等企业的大规模订单，应用场景从物流仓储、工业自动化，延伸到了独居老人监测等多个领域。</p>\n<p>在鲍君威看来，激光雷达的未来，远不止于汽车领域。</p>\n<p>“激光雷达不只是汽车的「眼睛」，未来，它会像摄像头一样，无处不在。”他畅想道，“办公室里，它能监测工位占用情况，自动调节空调和灯光；矿山里，它能辅助自动化作业，规避碰撞风险；甚至在农业领域，它能帮着实现精准种植，提升生产效率。”</p>\n<p>2025年12月10日，54岁的鲍君威，带着图达通在港股成功上市。对此他表示，“上市是一个新的milestone，是给当年的投资人、同事、客户、供应链合作伙伴，一个实实在在的交代。”</p>\n<h2><strong>今年增速，几近翻番</strong></h2>\n<p>“2025年，对图达通是一个转折点。”鲍君威总结道。</p>\n<p>这份转折，藏在三个实实在在的突破里。</p>\n<p>第一，客户格局彻底打开，从最初只服务蔚来一家，变成了多个主机厂项目同步推进，摆脱了单一客户的依赖；</p>\n<p>第二，产品矩阵全面开花，905纳米路线产品实现大量出货，中高端产品线成功获得市场认可，纯固态激光雷达也顺利拿到定点，产品布局之广，已然跻身行业前列；</p>\n<p>第三，全球化布局迎来关键跨越，欧美市场从之前的孵化培育期，正式迈入规模化增长期。</p>\n<p>谈及营收，鲍君威并不急于求成，反而多了几分长远考量：“如果只看绝对营收，可能不是特别亮眼。但关键是，我们在2025年，悄悄预埋好了今年的成长种子。”</p>\n<p>他给出了一组行业数据：2025年，全球激光雷达出货量约300万台，而中国市场包揽了其中的绝大多数。对于2026年的市场增速，鲍君威有着清晰的判断：“今年几近翻番。”</p>\n<p>在他看来，激光雷达的未来，藏在更广阔的应用场景里。</p>\n<p>“各种车、机器人，还有很多轻小量的设备，都会用到激光雷达，市场空间大得很。”他打了个比方，“把时间倒回20多年前，数字相机刚出来的时候贵得离谱，后来慢慢普及，到最后嵌进手机里，彻底泛滥开来。激光雷达也是一样的道理，它能给人类带来独特价值，是摄像头无法替代的价值。只要继续把成本做下去，未来可期。”</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/c9f9dLV7f5UYGziLIwPU_w\">“亿欧汽车”</a>，作者：郝秋慧，36氪经授权发布。</p>', 'https://36kr.com/p/3768762985644546?f=rss', 0, '', '{\"summary\": \"本文分享全球激光雷达企业图达通的出海发展经验与市场判断，为出海硬件企业提供全球化布局参考\", \"abstract\": \"图达通是全球图像级激光雷达解决方案提供商，2025年12月在港交所挂牌上市，2025年实现毛利率由负转正，客户结构显著优化，全球交付量快速增长。企业创立之初就定位全球市场，搭建了覆盖全球的研发、生产、销售体系，采用双技术路线并行战略覆盖多元市场，实现从高端市场向主流乘用车市场延伸。目前图达通已在欧美市场实现实质性业务突破，同时拓展机器人、智慧交通等非汽车领域，开启第二增长曲线。创始人鲍君威判断2026年全球激光雷达市场增速将几近翻番，图达通全年交付量有望达到约100万台。\", \"keywords\": [\"激光雷达\", \"图达通\", \"全球化布局\", \"IPO\", \"自动驾驶\", \"双技术路线\", \"出海\", \"全球市场\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://36kr.com/p/3768762985644546?f=rss\", \"title\": \"李斌投出的百亿IPO，要翻番了\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<blockquote>\\n<p>2025年12月10日，图达通（Seyond Holdings Ltd.）正式在港交所挂牌上市，市值一度达到180亿港元。</p>\\n<p>图达通2025年财报显示，大客户蔚来的收入占比下降，客户结构显著优化，截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\\n<p>对于2026年的市场增速，创始人鲍君威有着清晰的判断：“今年几近翻番。”</p>\\n</blockquote>\\n<p>“我们去年全年交付了33.25万颗激光雷达，灵雀系列卖了13.8万颗，同比增长超10倍。”</p>\\n<p>图达通创始人兼CEO鲍君威在加州接受亿欧汽车采访时表示，灵雀的大规模放量，标志着公司正式从高端市场，向更广阔的主流乘用车市场延伸。</p>\\n<p>作为全球图像级激光雷达解决方案提供商，图达通在2025年交出了一份极具转折意义的业绩答卷：</p>\\n<p>全年营收约11.02亿元，毛利率由2024年的负8.7%提升至正7.9%，经调整净亏损收窄24%，现金及现金等价物同比增长146%。</p>\\n<p>目前，图达通也是业内唯一同时实现1550nm与905nm/940nm双技术路线成熟量产的激光雷达企业。随着财务状况持续改善、现金储备充裕，公司毛利率已正式迈过盈亏平衡关键线。</p>\\n<p>截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\\n<p>鲍君威对即将到来的「百万台」节点，信心倍增。</p>\\n<h2><strong>硅谷16年，45岁再创业</strong></h2>\\n<p>“我是在伯克利读博期间第一次创业的。”鲍君威对亿欧汽车回忆道。</p>\\n<p>上世纪90年代中期，鲍君威从北京大学物理系毕业后赴美留学，在加州大学伯克利分校攻读博士学位。他的研究方向紧密围绕半导体设备与生产线，天然具备与产业深度结合的优势。</p>\\n<p>“也正因如此，我们抓住了一些机会。”鲍君威回忆道，他与两位师兄共同创立公司，将实验室的研究成果推向产业化。项目运营两三年间，公司顺利完成融资并实现营收，最终被日本规模最大的半导体设备企业收购。</p>\\n<p>彼时他尚未毕业，作为联合创始人便收获了人生第一桶金，也摸清了硅谷的创业逻辑与产业脉络。博士毕业后，鲍君威加入这家日本企业，一待便是十余年。</p>\\n<p>安逸，是他那段时光的形容词。</p>\\n<p>但安逸，并不是他想要的。</p>\\n<p>“我想换个行业，换个赛道，试一试新的东西。”</p>\\n<p>2014年，鲍君威加入百度美国研发中心，负责自动驾驶硬件平台。彼时百度正在硅谷搭建自动驾驶团队，寻找科技前沿的脉搏。</p>\\n<p>“百度当时愿意去尝试、去探索试错。”在百度硅谷团队，鲍君威主导自动驾驶硬件平台研发，也因此与激光雷达产生深度交集。</p>\\n<p>“我梳理了自动驾驶所需的各类传感器，包括计算系统、摄像头、毫米波雷达、GPS、IMU等，其中唯一不成熟、甚至缺口明显的就是激光雷达，而它又是自动驾驶不可或缺的核心部件。”</p>\\n<p>这一刻，他真切意识到，那些在自家附近两三公里路段测试的谷歌自动驾驶车辆，未来真有可能走进寻常百姓家。</p>\\n<p>“自动驾驶从不是空想，而激光雷达，就是实现规模化落地的关键。”</p>\\n<p>2016年，通用汽车以超过5亿美元的估值收购了Cruise，Uber不惜重金挖角谷歌自动驾驶核心团队。硅谷资本迅速嗅到机遇，自动驾驶赛道迎来爆发前夜。</p>\\n<p>“我42岁加入百度，45岁正式出来创业。”鲍君威说道，“说冒险还谈不上，也不需要自夸。”</p>\\n<p>但从零组建团队、从头开拓业务，与鲍君威以往按部就班的职场生涯截然不同。</p>\\n<p>2016年，图达通在硅谷成立。早期，公司只有几个人，鲍君威就带着他们在硅谷的实验室里一点点打磨产品。</p>\\n<p>彼时，全球激光雷达行业尚处混沌初期：美国厂商Velodyne起步较早，但产品技术初级、定价居高不下；国内玩家也刚刚起步，禾赛、速腾聚创等企业多聚焦本土市场。</p>\\n<p>而鲍君威从一开始，就把目光投向了全球。</p>\\n<p>“在硅谷深耕多年，我深知全球市场的广阔体量，也清楚中国企业的制造与供应链优势，我们不该局限于国内市场。要做，就做面向全球的生意。”</p>\\n<p>“Velodyne与多普勒等厂商入局较早，但产品形态相对初级，市场需求也未真正爆发。”鲍君威表示，“等到2015、2016年行业需求崛起，短短两三年内，全球涌现出上百家激光雷达企业，各类技术路线与商业模式层出不穷。”</p>\\n<p>在A轮融资前，图达通与国内市场几乎没有交集。完成A轮融资后，鲍君威果断决定在中国设立子公司，并于2019年正式落地苏州。</p>\\n<p>公司真正的关键转折点，出现在2020年底。</p>\\n<p>“蔚来向我们发出了定点项目合作。”鲍君威说道，“客户在哪里，我们就要离得更近。”</p>\\n<p>蔚来成为图达通首个实现大规模量产的核心客户。</p>\\n<p>随着搭载图达通猎鹰激光雷达的蔚来车型陆续上市，鲍君威终于完成了从实验室技术到车规级量产产品的跨越，让自研激光雷达真正驶上规模化应用的道路。</p>\\n<h2><strong>从「小众奢侈」到「全民普及」</strong></h2>\\n<p>“我们是唯一具备双技术路线量产能力的企业。”鲍君威说道。</p>\\n<p>图达通采取“双技术路线并行”战略，构建了覆盖多元场景的产品矩阵。</p>\\n<p>1550nm高性能超远距技术路线，聚焦L3+全场景自动驾驶，猎鹰平台已经累计交付超过了70万台，是目前唯一能批量交付图像级超远距激光雷达的企业。</p>\\n<p>此外，905nm/940nm兼顾性能与成本路线，灵雀平台适配L2+辅助驾驶，2025年交付达13.8万颗，同比增长超过10倍。</p>\\n<p>纯固态技术蜂鸟平台，兼具高性能与低成本优势，已获得头部主机厂定点。</p>\\n<p>谈及905纳米产品的市场表现，鲍君威表示：“去年我们905纳米产品出了十几万台货，给蔚来，也给其他厂商供货。���</p>\\n<p>他不回避行业内的质疑，坦然说道：“有人会质疑我们在做到超高性能的同时，能不能把成本结构做好？我们用实际成绩证明了，不仅可以快速做好产品、实现规模化出货，连纯固态激光雷达也顺利拿到了定点，跟友商站在同一个起跑线上，甚至在部分技术细节上，我们还有自己的优势。”</p>\\n<p>截至2025年底，图达通已累计获得18家主机厂及ADAS/ADS公司定点，覆盖超60款车型。</p>\\n<p>蔚来收入占比由97.3%降至86.2%，客户结构显著优化。新增客户包括上汽大众、广汽集团等传统车企，以及陕汽重卡、福田汽车、小马智行等商用车及自动驾驶头部企业。</p>\\n<p>“我们不依赖单一客户，这是我们能稳健发展的根本。”鲍君威说道，“汽车行业的供应链，从来都不是一家独大，我们要做的，是成为全球智能汽车供应链里，不可或缺的一员。”</p>\\n<p>采访中，鲍君威还回应了马斯克“不用激光雷达”的观点。“我们始终认为激光雷达是必须的。”他直言不讳，“不是激光雷达不好，是马斯克当年没有好的激光雷达可用，只能退而求其次。”</p>\\n<p>在鲍君威看来，人类造系统，不是为了和人一样，而是要比人更好、更安全。汽车的安全气囊、安全带，平时用不上，但关键时刻能救命，激光雷达也是一样，它是自动驾驶的安全冗余，“花几百美金，就能换来数倍的安全提升，这很值。”</p>\\n<p>如今，54岁的鲍君威，依然保持着工程师的严谨和创业者的冲劲。他见证并推动了激光雷达从「小众奢侈」到「全民普及」的过程，也带领图达通，从硅谷的一间小办公室，成长为全球激光雷达行业的领军者。</p>\\n<p>2025年，图达通销售成本为1.42亿美元，较2024年的1.73亿美元同比下降18.2%。毛利率由负转正至7.9%。鲍君威把这归功于工程设计优化、运营效率提升、规模效应、核心器件本地化采购、以及自研模块的持续推进。</p>\\n<p>“毛利率转正是公司经营质效提升的核心信号。”鲍君威说道，“意味着我们已经具备自我造血能力。”</p>\\n<p>2026年第一季度，图达通激光雷达交付量约17万颗，同比增长约310%，收入约5500万美元。这打破了Q1是行业传统销售淡季的规律。其中猎鹰系列交付超过6万颗，灵雀系列约11万颗。</p>\\n<p>“今年我们预计交付量有望达到约100万台。”鲍君威坦言，截至2026年3月31日，图达通的年设计产能约为120万台，计划于2026年新增产能100万台，其中将包括一条专门用于生产蜂鸟系列的生产线。</p>\\n<h2><strong>全球化布局，激光雷达将无处不在</strong></h2>\\n<p>“我们想做的一直都是全球市场。”鲍君威道出了图达通的发展野心。</p>\\n<p>这份全球野心，并非空谈。</p>\\n<p>图达通目前已是国内激光雷达厂商中，唯一一家在美国拥有生产产线的企业，从硅谷的研发中心，到苏州的生产基地，再到欧洲的市场布局，鲍君威一步步搭建起了覆盖全球的研发、生产、销售体系。</p>\\n<p>“各个国家都有本土产业保护的需求，也有信任的考量，我们在美国设产线，就是要真正融入当地，拿到当地市场的认可；而欧洲市场，我们是最早进入的中国激光雷达企业，早早发现了他们在智慧交通上的潜在需求。”鲍君威坦言，这份先发优势，是图达通全球化布局的关键底气。</p>\\n<p>2025年，图达通的海外布局迎来了实质性突破：</p>\\n<p>图达通与瑞典ITS基础设施商Aventi Sweden达成战略合作，拿下近260万美元订单，把自主研发的智慧交通系统管理平台，落地到了欧洲的关键交通路口。</p>\\n<p>“这不是偶然，是我们提前布局的结果。”鲍君威说道，“欧洲对智慧交通的要求很高，对产品的可靠性、安全性要求也严，我们能拿下这个订单，就是因为我们的技术和产品，能真正满足他们的需求，这就是我们的先发优势。”</p>\\n<p>在国内，图达通的激光雷达，已在超过15条全自动地铁线路部署运行，港口船闸领域累计交付超1000套。此外，泛机器人赛道也迎来爆发式增长。</p>\\n<p>2025年，图达通在机器人及其他产品领域的收入达1891万美元，同比增长130%，收入占比从2024年的5.1%提升至12.3%，成功启动了企业发展的第二增长曲线。</p>\\n<p>其中，仅九识科技一家客户，图达通就交付了超过2.1万颗产品；非中国区的机器人及其他业务，也实现了约80%的同比增长，同时拿下了中力股份、库萨科技等企业的大规模订单，应用场景从物流仓储、工业自动化，延伸到了独居老人监测等多个领域。</p>\\n<p>在鲍君威看来，激光雷达的未来，远不止于汽车领域。</p>\\n<p>“激光雷达不只是汽车的「眼睛」，未来，它会像摄像头一样，无处不在。”他畅想道，“办公室里，它能监测工位占用情况，自动调节空调和灯光；矿山里，它能辅助自动化作业，规避碰撞风险；甚至在农业领域，它能帮着实现精准种植，提升生产效率。”</p>\\n<p>2025年12月10日，54岁的鲍君威，带着图达通在港股成功上市。对此他表示，“上市是一个新的milestone，是给当年的投资人、同事、客户、供应链合作伙伴，一个实实在在的交代。”</p>\\n<h2><strong>今年增速，几近翻番</strong></h2>\\n<p>“2025年，对图达通是一个转折点。”鲍君威总结道。</p>\\n<p>这份转折，藏在三个实实在在的突破里。</p>\\n<p>第一，客户格局彻底打开，从最初只服务蔚来一家，变成了多个主机厂项目同步推进，摆脱了单一客户的依赖；</p>\\n<p>第二，产品矩阵全面开花，905纳米路线产品实现大量出货，中高端产品线成功获得市场认可，纯固态激光雷达也顺利拿到定点，产品布局之广，已然跻身行业前列；</p>\\n<p>第三，全球化布局迎来关键跨越，欧美市场从之前的孵化培育期，正式迈入规模化增长期。</p>\\n<p>谈及营收，鲍君威并不急于求成，反而多了几分长远考量：“如果只看绝对营收，可能不是特别亮眼。但关键是，我们在2025年，悄悄预埋好了今年的成长种子。”</p>\\n<p>他给出了一组行业数据：2025年，全球激光雷达出货量约300万台，而中国市场包揽了其中的绝大多数。对于2026年的市场增速，鲍君威有着清晰的判断：“今年几近翻番。”</p>\\n<p>在他看来，激光雷达的未来，藏在更广阔的应用场景里。</p>\\n<p>“各种车、机器人，还有很多轻小量的设备，都会用到激光雷达，市场空间大得很。”他打了个比方，“把时间倒回20多年前，数字相机刚出来的时候贵得离谱，后来慢慢普及，到最后嵌进手机里，彻底泛滥开来。激光雷达也是一样的道理，它能给人类带来独特价值，是摄像头无法替代的价值。只要继续把成本做下去，未来可期。”</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/c9f9dLV7f5UYGziLIwPU_w\\\">“亿欧汽车”</a>，作者：郝秋慧，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'李斌投出的百亿IPO，要翻番了\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'李斌投出的百亿IPO，要翻番了\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768762985644546?f=rss\'}], \'link\': \'https://36kr.com/p/3768762985644546?f=rss\', \'published\': \'2026-04-16 10:14:29  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=14, tm_sec=29, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<blockquote>\\\\n   <p>2025年12月10日，图达通（Seyond Holdings Ltd.）正式在港交所挂牌上市，市值一度达到180亿港元。</p>\\\\n   <p>图达通2025年财报显示，大客户蔚来的收入占比下降，客户结构显著优化，截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\\\\n   <p>对于2026年的市场增速，创始人鲍君威有着清晰的判断：“今年几近翻番。”</p>\\\\n  </blockquote>\\\\n  <p>“我们去年全年交付了33.25万颗激光雷达，灵雀系列卖了13.8万颗，同比增长超10倍。”</p>\\\\n  <p>图达通创始人兼CEO鲍君威在加州接受亿欧汽车采访时表示，灵雀的大规模放量，标志着公司正式从高端市场，向更广阔的主流乘用车市场延伸。</p>\\\\n  <p>作为全球图像级激光雷达解决方案提供商，图达通在2025年交出了一份极具转折意义的业绩答卷：</p>\\\\n  <p>全年营收约11.02亿元，毛利率由2024年的负8.7%提升至正7.9%，经调整净亏损收窄24%，现金及现金等价物同比增长146%。</p>\\\\n  <p>目前，图达通也是业内唯一同时实现1550nm与905nm/940nm双技术路线成熟量产的激光雷达企业。随着财务状况持续改善、现金储备充裕，公司毛利率已正式迈过盈亏平衡关键线。</p>\\\\n  <p>截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\\\\n  <p>鲍君威对即将到来的「百万台」节点，信心倍增。</p>\\\\n  <h2><strong>硅谷16年，45岁再创业</strong></h2>\\\\n  <p>“我是在伯克利读博期间第一次创业的。”鲍君威对亿欧汽车回忆道。</p>\\\\n  <p>上世纪90年代中期，鲍君威从北京大学物理系毕业后赴美留学，在加州大学伯克利分校攻读博士学位。他的研究方向紧密围绕半导体设备与生产线，天然具备与产业深度结合的优势。</p>\\\\n  <p>“也正因如此，我们抓住了一些机会。”鲍君威回忆道，他与两位师兄共同创立公司，将实验室的研究成果推向产业化。项目运营两三年间，公司顺利完成融资并实现营收，最终被日本规模最大的半导体设备企业收购。</p>\\\\n  <p>彼时他尚未毕业，作为联合创始人便收获了人生第一桶金，也摸清了硅谷的创业逻辑与产业脉络。博士毕业后，鲍君威加入这家日本企业，一待便是十余年。</p>\\\\n  <p>安逸，是他那段时光的形容词。</p>\\\\n  <p>但安逸，并不是他想要的。</p>\\\\n  <p>“我想换个行业，换个赛道，试一试新的东西。”</p>\\\\n  <p>2014年，鲍君威加入百度美国研发中心，负责自动驾驶硬件平台。彼时百度正在硅谷搭建自动驾驶团队，寻找科技前沿的脉搏。</p>\\\\n  <p>“百度当时愿意去尝试、去探索试错。”在百度硅谷团队，鲍君威主导自动驾驶硬件平台研发，也因此与激光雷达产生深度交集。</p>\\\\n  <p>“我梳理了自动驾驶所需的各类传感器，包括计算系统、摄像头、毫米波雷达、GPS、IMU等，其中唯一不成熟、甚至缺口明显的就是激光雷达，而它又是自动驾驶不可或缺的核心部件。”</p>\\\\n  <p>这一刻，他真切意识到，那些在自家附近两三公里路段测试的谷歌自动驾驶车辆，未来真有可能走进寻常百姓家。</p>\\\\n  <p>“自动驾驶从不是空想，而激光雷达，就是实现规模化落地的关键。”</p>\\\\n  <p>2016年，通用汽车以超过5亿美元的估值收购了Cruise，Uber不惜重金挖角谷歌自动驾驶核心团队。硅谷资本迅速嗅到机遇，自动驾驶赛道迎来爆发前夜。</p>\\\\n  <p>“我42岁加入百度，45岁正式出来创业。”鲍君威说道，“说冒险还谈不上，也不需要自夸。”</p>\\\\n  <p>但从零组建团队、从头开拓业务，与鲍君威以往按部就班的职场生涯截然不同。</p>\\\\n  <p>2016年，图达通在硅谷成立。早期，公司只有几个人，鲍君威就带着他们在硅谷的实验室里一点点打磨产品。</p>\\\\n  <p>彼时，全球激光雷达行业尚处混沌初期：美国厂商Velodyne起步较早，但产品技术初级、定价居高不下；国内玩家也刚刚起步，禾赛、速腾聚创等企业多聚焦本土市场。</p>\\\\n  <p>而鲍君威从一开始，就把目光投向了全球。</p>\\\\n  <p>“在硅谷深耕多年，我深知全球市场的广阔体量，也清楚中国企业的制造与供应链优势，我们不该局限于国内市场。要做，就做面向全球的生意。”</p>\\\\n  <p>“Velodyne与多普勒等厂商入局较早，但产品形态相对初级，市场需求也未真正爆发。”鲍君威表示，“等到2015、2016年行业需求崛起，短短两三年内，全球涌现出上百家激光雷达企业，各类技术路线与商业模式层出不穷。”</p>\\\\n  <p>在A轮融资前，图达通与国内市场几乎没有交集。完成A轮融资后，鲍君威果断决定在中国设立子公司，并于2019年正式落地苏州。</p>\\\\n  <p>公司真正的关键转折点，出现在2020年底。</p>\\\\n  <p>“蔚来向我们发出了定点项目合作。”鲍君威说道，“客户在哪里，我们就要离得更近。”</p>\\\\n  <p>蔚来成为图达通首个实现大规模量产的核心客户。</p>\\\\n  <p>随着搭载图达通猎鹰激光雷达的蔚来车型陆续上市，鲍君威终于完成了从实验室技术到车规级量产产品的跨越，让自研激光雷达真正驶上规模化应用的道路。</p>\\\\n  <h2><strong>从「小众奢侈」到「全民普及」</strong></h2>\\\\n  <p>“我们是唯一具备双技术路线量产能力的企业。”鲍君威说道。</p>\\\\n  <p>图达通采取“双技术路线并行”战略，构建了覆盖多元场景的产品矩阵。</p>\\\\n  <p>1550nm高性能超远距技术路线，聚焦L3+全场景自动驾驶，猎鹰平台已经累计交付超过了70万台，是目前唯一能批量交付图像级超远距激光雷达的企业。</p>\\\\n  <p>此外，905nm/940nm兼顾性能与成本路线，灵雀平台适配L2+辅助驾驶，2025年交付达13.8万颗，同比增长超过10倍。</p>\\\\n  <p>纯固态技术蜂鸟平台，兼具高性能与低成本优势，已获得头部主机厂定点。</p>\\\\n  <p>谈及905纳米产品的市场表现，鲍君威表示：“去年我们905纳米产品出了十几万台货，给蔚来，也给其他厂商供货。���</p>\\\\n  <p>他不回避行业内的质疑，坦然说道：“有人会质疑我们在做到超高性能的同时，能不能把成本结构做好？我们用实际成绩证明了，不仅可以快速做好产品、实现规模化出货，连纯固态激光雷达也顺利拿到了定点，跟友商站在同一个起跑线上，甚至在部分技术细节上，我们还有自己的优势。”</p>\\\\n  <p>截至2025年底，图达通已累计获得18家主机厂及ADAS/ADS公司定点，覆盖超60款车型。</p>\\\\n  <p>蔚来收入占比由97.3%降至86.2%，客户结构显著优化。新增客户包括上汽大众、广汽集团等传统车企，以及陕汽重卡、福田汽车、小马智行等商用车及自动驾驶头部企业。</p>\\\\n  <p>“我们不依赖单一客户，这是我们能稳健发展的根本。”鲍君威说道，“汽车行业的供应链，从来都不是一家独大，我们要做的，是成为全球智能汽车供应链里，不可或缺的一员。”</p>\\\\n  <p>采访中，鲍君威还回应了马斯克“不用激光雷达”的观点。“我们始终认为激光雷达是必须的。”他直言不讳，“不是激光雷达不好，是马斯克当年没有好的激光雷达可用，只能退而求其次。”</p>\\\\n  <p>在鲍君威看来，人类造系统，不是为了和人一样，而是要比人更好、更安全。汽车的安全气囊、安全带，平时用不上，但关键时刻能救命，激光雷达也是一样，它是自动驾驶的安全冗余，“花几百美金，就能换来数倍的安全提升，这很值。”</p>\\\\n  <p>如今，54岁的鲍君威，依然保持着工程师的严谨和创业者的冲劲。他见证并推动了激光雷达从「小众奢侈」到「全民普及」的过程，也带领图达通，从硅谷的一间小办公室，成长为全球激光雷达行业的领军者。</p>\\\\n  <p>2025年，图达通销售成本为1.42亿美元，较2024年的1.73亿美元同比下降18.2%。毛利率由负转正至7.9%。鲍君威把这归功于工程设计优化、运营效率提升、规模效应、核心器件本地化采购、以及自研模块的持续推进。</p>\\\\n  <p>“毛利率转正是公司经营质效提升的核心信号。”鲍君威说道，“意味着我们已经具备自我造血能力。”</p>\\\\n  <p>2026年第一季度，图达通激光雷达交付量约17万颗，同比增长约310%，收入约5500万美元。这打破了Q1是行业传统销售淡季的规律。其中猎鹰系列交付超过6万颗，灵雀系列约11万颗。</p>\\\\n  <p>“今年我们预计交付量有望达到约100万台。”鲍君威坦言，截至2026年3月31日，图达通的年设计产能约为120万台，计划于2026年新增产能100万台，其中将包括一条专门用于生产蜂鸟系列的生产线。</p>\\\\n  <h2><strong>全球化布局，激光雷达将无处不在</strong></h2>\\\\n  <p>“我们想做的一直都是全球市场。”鲍君威道出了图达通的发展野心。</p>\\\\n  <p>这份全球野心，并非空谈。</p>\\\\n  <p>图达通目前已是国内激光雷达厂商中，唯一一家在美国拥有生产产线的企业，从硅谷的研发中心，到苏州的生产基地，再到欧洲的市场布局，鲍君威一步步搭建起了覆盖全球的研发、生产、销售体系。</p>\\\\n  <p>“各个国家都有本土产业保护的需求，也有信任的考量，我们在美国设产线，就是要真正融入当地，拿到当地市场的认可；而欧洲市场，我们是最早进入的中国激光雷达企业，早早发现了他们在智慧交通上的潜在需求。”鲍君威坦言，这份先发优势，是图达通全球化布局的关键底气。</p>\\\\n  <p>2025年，图达通的海外布局迎来了实质性突破：</p>\\\\n  <p>图达通与瑞典ITS基础设施商Aventi Sweden达成战略合作，拿下近260万美元订单，把自主研发的智慧交通系统管理平台，落地到了欧洲的关键交通路口。</p>\\\\n  <p>“这不是偶然，是我们提前布局的结果。”鲍君威说道，“欧洲对智慧交通的要求很高，对产品的可靠性、安全性要求也严，我们能拿下这个订单，就是因为我们的技术和产品，能真正满足他们的需求，这就是我们的先发优势。”</p>\\\\n  <p>在国内，图达通的激光雷达，已在超过15条全自动地铁线路部署运行，港口船闸领域累计交付超1000套。此外，泛机器人赛道也迎来爆发式增长。</p>\\\\n  <p>2025年，图达通在机器人及其他产品领域的收入达1891万美元，同比增长130%，收入占比从2024年的5.1%提升至12.3%，成功启动了企业发展的第二增长曲线。</p>\\\\n  <p>其中，仅九识科技一家客户，图达通就交付了超过2.1万颗产品；非中国区的机器人及其他业务，也实现了约80%的同比增长，同时拿下了中力股份、库萨科技等企业的大规模订单，应用场景从物流仓储、工业自动化，延伸到了独居老人监测等多个领域。</p>\\\\n  <p>在鲍君威看来，激光雷达的未来，远不止于汽车领域。</p>\\\\n  <p>“激光雷达不只是汽车的「眼睛」，未来，它会像摄像头一样，无处不在。”他畅想道，“办公室里，它能监测工位占用情况，自动调节空调和灯光；矿山里，它能辅助自动化作业，规避碰撞风险；甚至在农业领域，它能帮着实现精准种植，提升生产效率。”</p>\\\\n  <p>2025年12月10日，54岁的鲍君威，带着图达通在港股成功上市。对此他表示，“上市是一个新的milestone，是给当年的投资人、同事、客户、供应链合作伙伴，一个实实在在的交代。”</p>\\\\n  <h2><strong>今年增速，几近翻番</strong></h2>\\\\n  <p>“2025年，对图达通是一个转折点。”鲍君威总结道。</p>\\\\n  <p>这份转折，藏在三个实实在在的突破里。</p>\\\\n  <p>第一，客户格局彻底打开，从最初只服务蔚来一家，变成了多个主机厂项目同步推进，摆脱了单一客户的依赖；</p>\\\\n  <p>第二，产品矩阵全面开花，905纳米路线产品实现大量出货，中高端产品线成功获得市场认可，纯固态激光雷达也顺利拿到定点，产品布局之广，已然跻身行业前列；</p>\\\\n  <p>第三，全球化布局迎来关键跨越，欧美市场从之前的孵化培育期，正式迈入规模化增长期。</p>\\\\n  <p>谈及营收，鲍君威并不急于求成，反而多了几分长远考量：“如果只看绝对营收，可能不是特别亮眼。但关键是，我们在2025年，悄悄预埋好了今年的成长种子。”</p>\\\\n  <p>他给出了一组行业数据：2025年，全球激光雷达出货量约300万台，而中国市场包揽了其中的绝大多数。对于2026年的市场增速，鲍君威有着清晰的判断：“今年几近翻番。”</p>\\\\n  <p>在他看来，激光雷达的未来，藏在更广阔的应用场景里。</p>\\\\n  <p>“各种车、机器人，还有很多轻小量的设备，都会用到激光雷达，市场空间大得很。”他打了个比方，“把时间倒回20多年前，数字相机刚出来的时候贵得离谱，后来慢慢普及，到最后嵌进手机里，彻底泛滥开来。激光雷达也是一样的道理，它能给人类带来独特价值，是摄像头无法替代的价值。只要继续把成本做下去，未来可期。”</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/c9f9dLV7f5UYGziLIwPU_w\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“亿欧汽车”</a>，作者：郝秋慧，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<blockquote>\\\\n   <p>2025年12月10日，图达通（Seyond Holdings Ltd.）正式在港交所挂牌上市，市值一度达到180亿港元。</p>\\\\n   <p>图达通2025年财报显示，大客户蔚来的收入占比下降，客户结构显著优化，截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\\\\n   <p>对于2026年的市场增速，创始人鲍君威有着清晰的判断：“今年几近翻番。”</p>\\\\n  </blockquote>\\\\n  <p>“我们去年全年交付了33.25万颗激光雷达，灵雀系列卖了13.8万颗，同比增长超10倍。”</p>\\\\n  <p>图达通创始人兼CEO鲍君威在加州接受亿欧汽车采访时表示，灵雀的大规模放量，标志着公司正式从高端市场，向更广阔的主流乘用车市场延伸。</p>\\\\n  <p>作为全球图像级激光雷达解决方案提供商，图达通在2025年交出了一份极具转折意义的业绩答卷：</p>\\\\n  <p>全年营收约11.02亿元，毛利率由2024年的负8.7%提升至正7.9%，经调整净亏损收窄24%，现金及现金等价物同比增长146%。</p>\\\\n  <p>目前，图达通也是业内唯一同时实现1550nm与905nm/940nm双技术路线成熟量产的激光雷达企业。随着财务状况持续改善、现金储备充裕，公司毛利率已正式迈过盈亏平衡关键线。</p>\\\\n  <p>截至2026年3月，图达通旗下猎鹰激光雷达全球累计交付量已突破70万台。</p>\\\\n  <p>鲍君威对即将到来的「百万台」节点，信心倍增。</p>\\\\n  <h2><strong>硅谷16年，45岁再创业</strong></h2>\\\\n  <p>“我是在伯克利读博期间第一次创业的。”鲍君威对亿欧汽车回忆道。</p>\\\\n  <p>上世纪90年代中期，鲍君威从北京大学物理系毕业后赴美留学，在加州大学伯克利分校攻读博士学位。他的研究方向紧密围绕半导体设备与生产线，天然具备与产业深度结合的优势。</p>\\\\n  <p>“也正因如此，我们抓住了一些机会。”鲍君威回忆道，他与两位师兄共同创立公司，将实验室的研究成果推向产业化。项目运营两三年间，公司顺利完成融资并实现营收，最终被日本规模最大的半导体设备企业收购。</p>\\\\n  <p>彼时他尚未毕业，作为联合创始人便收获了人生第一桶金，也摸清了硅谷的创业逻辑与产业脉络。博士毕业后，鲍君威加入这家日本企业，一待便是十余年。</p>\\\\n  <p>安逸，是他那段时光的形容词。</p>\\\\n  <p>但安逸，并不是他想要的。</p>\\\\n  <p>“我想换个行业，换个赛道，试一试新的东西。”</p>\\\\n  <p>2014年，鲍君威加入百度美国研发中心，负责自动驾驶硬件平台。彼时百度正在硅谷搭建自动驾驶团队，寻找科技前沿的脉搏。</p>\\\\n  <p>“百度当时愿意去尝试、去探索试错。”在百度硅谷团队，鲍君威主导自动驾驶硬件平台研发，也因此与激光雷达产生深度交集。</p>\\\\n  <p>“我梳理了自动驾驶所需的各类传感器，包括计算系统、摄像头、毫米波雷达、GPS、IMU等，其中唯一不成熟、甚至缺口明显的就是激光雷达，而它又是自动驾驶不可或缺的核心部件。”</p>\\\\n  <p>这一刻，他真切意识到，那些在自家附近两三公里路段测试的谷歌自动驾驶车辆，未来真有可能走进寻常百姓家。</p>\\\\n  <p>“自动驾驶从不是空想，而激光雷达，就是实现规模化落地的关键。”</p>\\\\n  <p>2016年，通用汽车以超过5亿美元的估值收购了Cruise，Uber不惜重金挖角谷歌自动驾驶核心团队。硅谷资本迅速嗅到机遇，自动驾驶赛道迎来爆发前夜。</p>\\\\n  <p>“我42岁加入百度，45岁正式出来创业。”鲍君威说道，“说冒险还谈不上，也不需要自夸。”</p>\\\\n  <p>但从零组建团队、从头开拓业务，与鲍君威以往按部就班的职场生涯截然不同。</p>\\\\n  <p>2016年，图达通在硅谷成立。早期，公司只有几个人，鲍君威就带着他们在硅谷的实验室里一点点打磨产品。</p>\\\\n  <p>彼时，全球激光雷达行业尚处混沌初期：美国厂商Velodyne起步较早，但产品技术初级、定价居高不下；国内玩家也刚刚起步，禾赛、速腾聚创等企业多聚焦本土市场。</p>\\\\n  <p>而鲍君威从一开始，就把目光投向了全球。</p>\\\\n  <p>“在硅谷深耕多年，我深知全球市场的广阔体量，也清楚中国企业的制造与供应链优势，我们不该局限于国内市场。要做，就做面向全球的生意。”</p>\\\\n  <p>“Velodyne与多普勒等厂商入局较早，但产品形态相对初级，市场需求也未真正爆发。”鲍君威表示，“等到2015、2016年行业需求崛起，短短两三年内，全球涌现出上百家激光雷达企业，各类技术路线与商业模式层出不穷。”</p>\\\\n  <p>在A轮融资前，图达通与国内市场几乎没有交集。完成A轮融资后，鲍君威果断决定在中国设立子公司，并于2019年正式落地苏州。</p>\\\\n  <p>公司真正的关键转折点，出现在2020年底。</p>\\\\n  <p>“蔚来向我们发出了定点项目合作。”鲍君威说道，“客户在哪里，我们就要离得更近。”</p>\\\\n  <p>蔚来成为图达通首个实现大规模量产的核心客户。</p>\\\\n  <p>随着搭载图达通猎鹰激光雷达的蔚来车型陆续上市，鲍君威终于完成了从实验室技术到车规级量产产品的跨越，让自研激光雷达真正驶上规模化应用的道路。</p>\\\\n  <h2><strong>从「小众奢侈」到「全民普及」</strong></h2>\\\\n  <p>“我们是唯一具备双技术路线量产能力的企业。”鲍君威说道。</p>\\\\n  <p>图达通采取“双技术路线并行”战略，构建了覆盖多元场景的产品矩阵。</p>\\\\n  <p>1550nm高性能超远距技术路线，聚焦L3+全场景自动驾驶，猎鹰平台已经累计交付超过了70万台，是目前唯一能批量交付图像级超远距激光雷达的企业。</p>\\\\n  <p>此外，905nm/940nm兼顾性能与成本路线，灵雀平台适配L2+辅助驾驶，2025年交付达13.8万颗，同比增长超过10倍。</p>\\\\n  <p>纯固态技术蜂鸟平台，兼具高性能与低成本优势，已获得头部主机厂定点。</p>\\\\n  <p>谈及905纳米产品的市场表现，鲍君威表示：“去年我们905纳米产品出了十几万台货，给蔚来，也给其他厂商供货。���</p>\\\\n  <p>他不回避行业内的质疑，坦然说道：“有人会质疑我们在做到超高性能的同时，能不能把成本结构做好？我们用实际成绩证明了，不仅可以快速做好产品、实现规模化出货，连纯固态激光雷达也顺利拿到了定点，跟友商站在同一个起跑线上，甚至在部分技术细节上，我们还有自己的优势。”</p>\\\\n  <p>截至2025年底，图达通已累计获得18家主机厂及ADAS/ADS公司定点，覆盖超60款车型。</p>\\\\n  <p>蔚来收入占比由97.3%降至86.2%，客户结构显著优化。新增客户包括上汽大众、广汽集团等传统车企，以及陕汽重卡、福田汽车、小马智行等商用车及自动驾驶头部企业。</p>\\\\n  <p>“我们不依赖单一客户，这是我们能稳健发展的根本。”鲍君威说道，“汽车行业的供应链，从来都不是一家独大，我们要做的，是成为全球智能汽车供应链里，不可或缺的一员。”</p>\\\\n  <p>采访中，鲍君威还回应了马斯克“不用激光雷达”的观点。“我们始终认为激光雷达是必须的。”他直言不讳，“不是激光雷达不好，是马斯克当年没有好的激光雷达可用，只能退而求其次。”</p>\\\\n  <p>在鲍君威看来，人类造系统，不是为了和人一样，而是要比人更好、更安全。汽车的安全气囊、安全带，平时用不上，但关键时刻能救命，激光雷达也是一样，它是自动驾驶的安全冗余，“花几百美金，就能换来数倍的安全提升，这很值。”</p>\\\\n  <p>如今，54岁的鲍君威，依然保持着工程师的严谨和创业者的冲劲。他见证并推动了激光雷达从「小众奢侈」到「全民普及」的过程，也带领图达通，从硅谷的一间小办公室，成长为全球激光雷达行业的领军者。</p>\\\\n  <p>2025年，图达通销售成本为1.42亿美元，较2024年的1.73亿美元同比下降18.2%。毛利率由负转正至7.9%。鲍君威把这归功于工程设计优化、运营效率提升、规模效应、核心器件本地化采购、以及自研模块的持续推进。</p>\\\\n  <p>“毛利率转正是公司经营质效提升的核心信号。”鲍君威说道，“意味着我们已经具备自我造血能力。”</p>\\\\n  <p>2026年第一季度，图达通激光雷达交付量约17万颗，同比增长约310%，收入约5500万美元。这打破了Q1是行业传统销售淡季的规律。其中猎鹰系列交付超过6万颗，灵雀系列约11万颗。</p>\\\\n  <p>“今年我们预计交付量有望达到约100万台。”鲍君威坦言，截至2026年3月31日，图达通的年设计产能约为120万台，计划于2026年新增产能100万台，其中将包括一条专门用于生产蜂鸟系列的生产线。</p>\\\\n  <h2><strong>全球化布局，激光雷达将无处不在</strong></h2>\\\\n  <p>“我们想做的一直都是全球市场。”鲍君威道出了图达通的发展野心。</p>\\\\n  <p>这份全球野心，并非空谈。</p>\\\\n  <p>图达通目前已是国内激光雷达厂商中，唯一一家在美国拥有生产产线的企业，从硅谷的研发中心，到苏州的生产基地，再到欧洲的市场布局，鲍君威一步步搭建起了覆盖全球的研发、生产、销售体系。</p>\\\\n  <p>“各个国家都有本土产业保护的需求，也有信任的考量，我们在美国设产线，就是要真正融入当地，拿到当地市场的认可；而欧洲市场，我们是最早进入的中国激光雷达企业，早早发现了他们在智慧交通上的潜在需求。”鲍君威坦言，这份先发优势，是图达通全球化布局的关键底气。</p>\\\\n  <p>2025年，图达通的海外布局迎来了实质性突破：</p>\\\\n  <p>图达通与瑞典ITS基础设施商Aventi Sweden达成战略合作，拿下近260万美元订单，把自主研发的智慧交通系统管理平台，落地到了欧洲的关键交通路口。</p>\\\\n  <p>“这不是偶然，是我们提前布局的结果。”鲍君威说道，“欧洲对智慧交通的要求很高，对产品的可靠性、安全性要求也严，我们能拿下这个订单，就是因为我们的技术和产品，能真正满足他们的需求，这就是我们的先发优势。”</p>\\\\n  <p>在国内，图达通的激光雷达，已在超过15条全自动地铁线路部署运行，港口船闸领域累计交付超1000套。此外，泛机器人赛道也迎来爆发式增长。</p>\\\\n  <p>2025年，图达通在机器人及其他产品领域的收入达1891万美元，同比增长130%，收入占比从2024年的5.1%提升至12.3%，成功启动了企业发展的第二增长曲线。</p>\\\\n  <p>其中，仅九识科技一家客户，图达通就交付了超过2.1万颗产品；非中国区的机器人及其他业务，也实现了约80%的同比增长，同时拿下了中力股份、库萨科技等企业的大规模订单，应用场景从物流仓储、工业自动化，延伸到了独居老人监测等多个领域。</p>\\\\n  <p>在鲍君威看来，激光雷达的未来，远不止于汽车领域。</p>\\\\n  <p>“激光雷达不只是汽车的「眼睛」，未来，它会像摄像头一样，无处不在。”他畅想道，“办公室里，它能监测工位占用情况，自动调节空调和灯光；矿山里，它能辅助自动化作业，规避碰撞风险；甚至在农业领域，它能帮着实现精准种植，提升生产效率。”</p>\\\\n  <p>2025年12月10日，54岁的鲍君威，带着图达通在港股成功上市。对此他表示，“上市是一个新的milestone，是给当年的投资人、同事、客户、供应链合作伙伴，一个实实在在的交代。”</p>\\\\n  <h2><strong>今年增速，几近翻番</strong></h2>\\\\n  <p>“2025年，对图达通是一个转折点。”鲍君威总结道。</p>\\\\n  <p>这份转折，藏在三个实实在在的突破里。</p>\\\\n  <p>第一，客户格局彻底打开，从最初只服务蔚来一家，变成了多个主机厂项目同步推进，摆脱了单一客户的依赖；</p>\\\\n  <p>第二，产品矩阵全面开花，905纳米路线产品实现大量出货，中高端产品线成功获得市场认可，纯固态激光雷达也顺利拿到定点，产品布局之广，已然跻身行业前列；</p>\\\\n  <p>第三，全球化布局迎来关键跨越，欧美市场从之前的孵化培育期，正式迈入规模化增长期。</p>\\\\n  <p>谈及营收，鲍君威并不急于求成，反而多了几分长远考量：“如果只看绝对营收，可能不是特别亮眼。但关键是，我们在2025年，悄悄预埋好了今年的成长种子。”</p>\\\\n  <p>他给出了一组行业数据：2025年，全球激光雷达出货量约300万台，而中国市场包揽了其中的绝大多数。对于2026年的市场增速，鲍君威有着清晰的判断：“今年几近翻番。”</p>\\\\n  <p>在他看来，激光雷达的未来，藏在更广阔的应用场景里。</p>\\\\n  <p>“各种车、机器人，还有很多轻小量的设备，都会用到激光雷达，市场空间大得很。”他打了个比方，“把时间倒回20多年前，数字相机刚出来的时候贵得离谱，后来慢慢普及，到最后嵌进手机里，彻底泛滥开来。激光雷达也是一样的道理，它能给人类带来独特价值，是摄像头无法替代的价值。只要继续把成本做下去，未来可期。”</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/c9f9dLV7f5UYGziLIwPU_w\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“亿欧汽车”</a>，作者：郝秋慧，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'亿欧网\'}], \'author\': \'亿欧网\', \'author_detail\': {\'name\': \'亿欧网\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'李斌8年前投下的石子，正从涟漪涌成浪。\'}]}\", \"published_at\": \"2026-04-16 10:14:29\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 10:14:29', '2026-04-16 11:40:49');
INSERT INTO `news_detail` VALUES (16, 970, 7, '消费与零售', '估值160亿，巨头们争夺这一小众品牌', '', '<p>2026年香水领域大事件接连不断——欧莱雅正式完成对开云美妆的收购，雅诗兰黛与Puig的合并谈判也在推进中。就在巨头们忙于整合布局、争夺赛���话语权之际，另一家小众香水被推上了收购竞逐的牌桌。</p>\n<p>继2025年10月首次传出出售意向后，日前(4月13日)，聚美丽从外媒BeautyMatter获悉，私募基金Advent International(安宏资本)已正式聘请Jefferies与高盛，共同负责Parfums de Marly(玛丽之香)的出售事宜，目前整个出售流程仍处于早期阶段。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_dc255cb07ac849adb7b738150c8f95f1@000000_oswg440202oswg1080oswg560_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：Beauty Matter</p>\n<p>且值得注意的是，据外媒报道称，<strong>欧莱雅、雅诗兰黛、Puig等几家国际美妆巨头</strong>，以及多家私募股权公司与独立香氛分销商，均已开始探索对这款法国小众高端香水品牌的潜在收购。</p>\n<h2><strong>估值3年翻三番，玛丽之香遭欧莱雅们“围猎”</strong></h2>\n<p>公开资料显示，玛丽之香是由Julien Sprecher于2009年创立的法国小众高端香水，品牌以法国玛丽城堡皇家历史与骏马文化为基因，主打奢华沙龙香定位。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_48e33bc7226c41f1bf24f54051cedc5a@000000_oswg330334oswg1080oswg543_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：Parfums de Marly官网</p>\n<p>过去十余年间，凭借独特的宫廷叙事与高品质香调，玛丽之香从小众圈层逐步走向全球，业务覆盖欧美、亚洲等多个核心市场，品牌影响力持续提升，<strong>估值也随之水涨船高</strong>。</p>\n<p>具体来看，2023年，安宏资本从玛丽之香创始人Julien Sprecher手中，收购了旗下拥有Parfums de Marly与Initio Parfums Privés两大品牌的Sprecher Berrier集团多数股权，此时，玛丽之香的估值约为7亿美元(约合人民币47.74亿元)。</p>\n<p>如今，据BeautyMatter报道，有知情人士透露，玛丽之香预计估值达到20亿欧元(约合人民币160.75亿元)。这意味着，若以2023年安宏资本收购时约7亿美元(约合人民币47.74亿元)的估值计算，<strong>短短3年间，玛丽之香的估值已翻了超三倍</strong>。</p>\n<p><strong>而支撑估值飙升的核心，正是其持续高增的业绩表现</strong>。</p>\n<p>具体而言，2022年，玛丽之香年销售额已达到2.62亿欧元(约合人民币21.06亿元)，同比增长51%。截至2025年3月31日的财年内，玛丽之香销售额达5.86亿美元(约合人民币39.97亿元)，其姊妹品牌Initio Parfums Privés的销售额为1.89亿美元(约合人民币12.89亿元)，两者共同推动集团销售额同比增长41%至7.75亿美元(约合人民币52.86亿元)。</p>\n<p>在业绩持续高增的驱动下，玛丽之香加速向全球市场扩张。2021年，玛丽之香借上海首店正式进入中国市场。随后在颖通集团的运营支持下，品牌渠道迅速铺开，相继在北京、广州、成都、武汉、三亚、海口等关键城市的高端商圈落地数十家门店与专柜，展现出较强的市场拓展力。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_ecc259785604431d817eb6ae30b1eebc@000000_oswg666676oswg1080oswg1973_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>正是凭借持续爆发的增长势头，玛丽之香吸引了欧莱雅、雅诗兰黛、Puig等国际美妆巨头，以及多家私募股权公司与独立香氛分销商的收购意向。</p>\n<p>不过，BeautyMatter报道中也提到，雅诗兰黛与Puig的合并谈判、欧莱雅对开云美妆的整合工作仍在推进，三大战略买家短期内<strong>恐难以全力推进新收购</strong>，实际参与竞价的机构数量或将受限，<strong>因此玛丽之香可能再次掌握在私募股权手中</strong>。</p>\n<p>同时，受宏观消费环境波动及美妆集团战略重心转移影响，<strong>当前的预期估值较难实现，最终交易价格存在下调空间</strong>。</p>\n<p>这意味着，这个估值160亿的“香饽饽”，最终能否以预期价格顺利落入巨头囊中，仍存在不小的变数。</p>\n<h2><strong>巨头们疯抢小众香水，打的什么算盘？</strong></h2>\n<p>玛丽之香被巨头们盯上，并非个案。将时间轴拉长来看，近年来国际美妆集团对香水资产的争夺，已进入白热化阶段。</p>\n<p>据聚美丽不完全统计，2025年以来，包括欧莱雅、雅诗兰黛、LVMH在内的全球美妆集团，在香水赛道的布局动作高达8起，其中<strong>半数以上均聚焦于小众高端香水赛道</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_f574a67784d54dcda04e884918322b40@000000_oswg802724oswg1080oswg2431_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>从上述布局动作不难看出，小众高端香水已成为巨头们重点押注的细分领域，一场围绕小众香氛的“圈地运动”已然拉开帷幕。那么，巨头们为何不惜重金，也要“疯抢”小众香水？</p>\n<p><strong>究其原因，首先与赛道本身增长红利密切相关。</strong>在全球美妆大盘增速放缓、护肤与彩妆品类增长见顶的大背景下，高端香水成为为数不多仍能保持高增长的细分赛道。</p>\n<p>据Mordor Intelligence相关数据显示，香氛市场在2025年估值760亿美元(约合人民币5183.58亿元)，预计到2030年将达到1120亿美元(约合人民币7638.96亿元)，在预测期间以7.95%的复合年增长率增长。</p>\n<p>不过，市场增长前景只是硬币的一面。除赛道红利外，巨头们疯狂押注小众香水，还有更深层的逻辑——</p>\n<h4><strong>1、掌握小众，即掌握未来审美话语权</strong></h4>\n<p>当下，小众香水已从个性表达升级为Z世代的身份与审美载体。相比商业香水的 “安全审美”，小众香水代表审美边界，可通过视觉叙事维护品牌美学，从而转化出更高未来价值。</p>\n<p>因而，美妆集团收购小众香水品牌，本质上抢占下一代消费者的审美主导权，例如LVMH集团入股代表新一代巴黎艺术香水的BDK，正是为了补齐集团中型精品香氛版图上的空缺。</p>\n<h4><strong>2、行业驱动力从“流量”转向“文化与审美”</strong></h4>\n<p>如今，香水行业正进入新周期，其增长核心从规模、渠道、爆款逻辑，转变为地域文化、个性审美与垂直细分。正如闻献创始人<strong>孟昭然</strong>此前接受聚美丽的采访时所说：“香氛品牌往往更接近文化品牌，需要构建一个完整的叙事体系，而不仅仅是产品+价格的组合。”</p>\n<p>大型美妆集团收购小众品牌，或是为了顺应行业这一结构性变化。譬如，雅诗兰黛投资拥有极强拉美文化属性的墨西哥品牌Xinù，便意在加速集团全球文化多样性布局。</p>\n<h4><strong>3、消费者愿为独特性与文化属性支付高溢价</strong></h4>\n<p>眼下，消费者不再只为香味买单，买的是一段记忆，一个故事或是一场创作仪式，所以更愿意为小众香水的独特调性、文化叙事支付溢价。</p>\n<p>也就是说，小众香水的长期价值远超短期流量爆款，这也是美妆巨头们放弃 “买流量”、转向 “买审美” 的关键动力。</p>\n<h2><strong>狂欢之下，巨头押注小众香水的考验</strong></h2>\n<p>然而，疯狂押注小众高端香水的背后，美妆巨头们同样面临着不小的挑战。高价拿下“香饽饽”只是第一步，如何消化、整合并持续释放品牌价值，才是真正的考验。</p>\n<h4><strong>一、小众调性与规模化扩张的博弈</strong></h4>\n<p>首先，对于靠独特叙事和稀缺性吸引消费者的小众香水品牌而言，被巨头收购后<strong>如何在规模化扩张中守住品牌内核</strong>，是一个无法避开的难题。</p>\n<p>当小众品牌被大集团收购后，把控品牌灵魂与创作初心的创始人的离开似乎已成必然，如，品牌由大集团完全掌控，其稀缺性很可能在集团追求利益最大化时逐渐丢失。</p>\n<h4><strong>二、估值偏高，回报周期漫长</strong></h4>\n<p>其次，当前小众高端香水标的估值水涨船高，收购对价普遍远超营收倍数，叠加香水品类复购周期长、增长天花板清晰，美妆集团需承担高额商誉与资金成本。</p>\n<p>正如其里QILI创始人<strong>圆圆</strong>所指出的：“因香水的非刚需性，导致其无法像护肤品依靠功能性痛点建立高频复购，也难以像彩妆凭借潮流迭代形成持续消耗。”</p>\n<p>且，如今市场增速放缓，品牌短期难以兑现高增长承诺，<strong>投资回报周期被大幅拉长，极易形成业绩包袱</strong>。</p>\n<h4><strong>三、中国市场本土化“硬骨头”难啃</strong></h4>\n<p>最后，当下中国香水消费仍以礼品与场景化使用为主，与西方日常佩戴习惯差异显著，小众品牌存在认知度低、香调水土不服、线下体验成本高、跨境价格倒挂等问题。</p>\n<p>与此同时，小众香水品牌的内容传播与渠道运营高度本土化，美妆集团们既要维持奢品调性，又要适配本土流量逻辑，平衡难度极大。再加上，近期关税重压和原料涨价的影响，海外小众品牌在中国市场的盈利前景更加扑朔迷离。</p>\n<p>回到此次出售交易，玛丽之香最终能否以160亿估值顺利易主，被欧莱雅、雅诗兰黛等美妆巨头成功收入囊中，仍是未知数。</p>\n<p>但无论此次交易结果如何，美妆行业对小众香水的争夺战仍将持续升温，而如何平衡商业利益与品牌初心、破解本土化难题，将成为所有入局者必须面对的长期课题，也将持续影响全球高端香水市场的竞争格局。</p>\n<p>而对于中国美妆产业而言，当巨头们正在通过资本抢占审美“制高点”时，中国品牌在香水赛道的文化叙事能力，是否已经准备好参与下一轮全球对话？</p>\n<p>注：本文涉及汇率换算如下：1 美元≈6.82人民币，1欧元≈8.04人民币</p>\n<p>消息来源：Beauty Matter</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s?__biz=MzI0OTg1NTUxOA==&amp;mid=2247636519&amp;idx=1&amp;sn=d850238c5ddf5aa6faaab93ae826639a&amp;chksm=e8064755cf9e099db3d824b195766f583e9092ff5303a0a8fe8a7746f3acd1a1bd08099ef974&amp;scene=0&amp;xtrack=1#rd\">“聚美丽”（ID：jumeili-cn）</a>，作者：沐沐，36氪经授权发布。</p>', 'https://36kr.com/p/3768686035862018?f=rss', 0, '', '{\"summary\": \"本文解析国际美妆巨头争夺小众高端香水的行业趋势，为中国美妆品牌布局全球香水赛道提供参考\", \"abstract\": \"2026年法国小众高端香水品牌玛丽之香启动出售流程，估值约合人民币160亿元，较三年前翻超三倍，吸引欧莱雅等多家国际美妆巨头及机构竞逐。近年来全球美妆巨头纷纷加码布局小众高端香水赛道，该赛道仍保持较高增长，是巨头抢占审美话语权、顺应行业转型的核心布局方向。巨头押注小众高端香水也面临多重挑战，包括规模化扩张中难以保留品牌内核、估值偏高投资回报周期长、中国市场本土化难度大等。这一行业趋势也引发了对中国美妆品牌香水赛道全球竞争力的思考。\", \"keywords\": [\"小众高端香水\", \"玛丽之香\", \"品牌收购\", \"美妆出海\", \"全球扩张\", \"品牌本土化\", \"估值\"], \"policy_risk\": {\"market_risk\": \"本次收购中玛丽之香预期估值较难实现，最终交易价格存在下调空间；收购后小众品牌易在规模化扩张中丢失品牌内核；当前小众香水标的估值偏高，叠加香水品类复购率低，投资回报周期长，易形成业绩包袱；海外小众香水进入中国市场存在认知度低、香调水土不服、运营本土化难度大等问题，叠加原料涨价影响，盈利前景存在不确定性\", \"policy_compliance\": \"提及中国市场进口香水面临关税重压\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"https://36kr.com/p/3768686035862018?f=rss\", \"title\": \"估值160亿，巨头们争夺这一小众品牌\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>2026年香水领域大事件接连不断——欧莱雅正式完成对开云美妆的收购，雅诗兰黛与Puig的合并谈判也在推进中。就在巨头们忙于整合布局、争夺赛���话语权之际，另一家小众香水被推上了收购竞逐的牌桌。</p>\\n<p>继2025年10月首次传出出售意向后，日前(4月13日)，聚美丽从外媒BeautyMatter获悉，私募基金Advent International(安宏资本)已正式聘请Jefferies与高盛，共同负责Parfums de Marly(玛丽之香)的出售事宜，目前整个出售流程仍处于早期阶段。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dc255cb07ac849adb7b738150c8f95f1@000000_oswg440202oswg1080oswg560_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：Beauty Matter</p>\\n<p>且值得注意的是，据外媒报道称，<strong>欧莱雅、雅诗兰黛、Puig等几家国际美妆巨头</strong>，以及多家私募股权公司与独立香氛分销商，均已开始探索对这款法国小众高端香水品牌的潜在收购。</p>\\n<h2><strong>估值3年翻三番，玛丽之香遭欧莱雅们“围猎”</strong></h2>\\n<p>公开资料显示，玛丽之香是由Julien Sprecher于2009年创立的法国小众高端香水，品牌以法国玛丽城堡皇家历史与骏马文化为基因，主打奢华沙龙香定位。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_48e33bc7226c41f1bf24f54051cedc5a@000000_oswg330334oswg1080oswg543_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：Parfums de Marly官网</p>\\n<p>过去十余年间，凭借独特的宫廷叙事与高品质香调，玛丽之香从小众圈层逐步走向全球，业务覆盖欧美、亚洲等多个核心市场，品牌影响力持续提升，<strong>估值也随之水涨船高</strong>。</p>\\n<p>具体来看，2023年，安宏资本从玛丽之香创始人Julien Sprecher手中，收购了旗下拥有Parfums de Marly与Initio Parfums Privés两大品牌的Sprecher Berrier集团多数股权，此时，玛丽之香的估值约为7亿美元(约合人民币47.74亿元)。</p>\\n<p>如今，据BeautyMatter报道，有知情人士透露，玛丽之香预计估值达到20亿欧元(约合人民币160.75亿元)。这意味着，若以2023年安宏资本收购时约7亿美元(约合人民币47.74亿元)的估值计算，<strong>短短3年间，玛丽之香的估值已翻了超三倍</strong>。</p>\\n<p><strong>而支撑估值飙升的核心，正是其持续高增的业绩表现</strong>。</p>\\n<p>具体而言，2022年，玛丽之香年销售额已达到2.62亿欧元(约合人民币21.06亿元)，同比增长51%。截至2025年3月31日的财年内，玛丽之香销售额达5.86亿美元(约合人民币39.97亿元)，其姊妹品牌Initio Parfums Privés的销售额为1.89亿美元(约合人民币12.89亿元)，两者共同推动集团销售额同比增长41%至7.75亿美元(约合人民币52.86亿元)。</p>\\n<p>在业绩持续高增的驱动下，玛丽之香加速向全球市场扩张。2021年，玛丽之香借上海首店正式进入中国市场。随后在颖通集团的运营支持下，品牌渠道迅速铺开，相继在北京、广州、成都、武汉、三亚、海口等关键城市的高端商圈落地数十家门店与专柜，展现出较强的市场拓展力。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ecc259785604431d817eb6ae30b1eebc@000000_oswg666676oswg1080oswg1973_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>正是凭借持续爆发的增长势头，玛丽之香吸引了欧莱雅、雅诗兰黛、Puig等国际美妆巨头，以及多家私募股权公司与独立香氛分销商的收购意向。</p>\\n<p>不过，BeautyMatter报道中也提到，雅诗兰黛与Puig的合并谈判、欧莱雅对开云美妆的整合工作仍在推进，三大战略买家短期内<strong>恐难以全力推进新收购</strong>，实际参与竞价的机构数量或将受限，<strong>因此玛丽之香可能再次掌握在私募股权手中</strong>。</p>\\n<p>同时，受宏观消费环境波动及美妆集团战略重心转移影响，<strong>当前的预期估值较难实现，最终交易价格存在下调空间</strong>。</p>\\n<p>这意味着，这个估值160亿的“香饽饽”，最终能否以预期价格顺利落入巨头囊中，仍存在不小的变数。</p>\\n<h2><strong>巨头们疯抢小众香水，打的什么算盘？</strong></h2>\\n<p>玛丽之香被巨头们盯上，并非个案。将时间轴拉长来看，近年来国际美妆集团对香水资产的争夺，已进入白热化阶段。</p>\\n<p>据聚美丽不完全统计，2025年以来，包括欧莱雅、雅诗兰黛、LVMH在内的全球美妆集团，在香水赛道的布局动作高达8起，其中<strong>半数以上均聚焦于小众高端香水赛道</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f574a67784d54dcda04e884918322b40@000000_oswg802724oswg1080oswg2431_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>从上述布局动作不难看出，小众高端香水已成为巨头们重点押注的细分领域，一场围绕小众香氛的“圈地运动”已然拉开帷幕。那么，巨头们为何不惜重金，也要“疯抢”小众香水？</p>\\n<p><strong>究其原因，首先与赛道本身增长红利密切相关。</strong>在全球美妆大盘增速放缓、护肤与彩妆品类增长见顶的大背景下，高端香水成为为数不多仍能保持高增长的细分赛道。</p>\\n<p>据Mordor Intelligence相关数据显示，香氛市场在2025年估值760亿美元(约合人民币5183.58亿元)，预计到2030年将达到1120亿美元(约合人民币7638.96亿元)，在预测期间以7.95%的复合年增长率增长。</p>\\n<p>不过，市场增长前景只是硬币的一面。除赛道红利外，巨头们疯狂押注小众香水，还有更深层的逻辑——</p>\\n<h4><strong>1、掌握小众，即掌握未来审美话语权</strong></h4>\\n<p>当下，小众香水已从个性表达升级为Z世代的身份与审美载体。相比商业香水的 “安全审美”，小众香水代表审美边界，可通过视觉叙事维护品牌美学，从而转化出更高未来价值。</p>\\n<p>因而，美妆集团收购小众香水品牌，本质上抢占下一代消费者的审美主导权，例如LVMH集团入股代表新一代巴黎艺术香水的BDK，正是为了补齐集团中型精品香氛版图上的空缺。</p>\\n<h4><strong>2、行业驱动力从“流量”转向“文化与审美”</strong></h4>\\n<p>如今，香水行业正进入新周期，其增长核心从规模、渠道、爆款逻辑，转变为地域文化、个性审美与垂直细分。正如闻献创始人<strong>孟昭然</strong>此前接受聚美丽的采访时所说：“香氛品牌往往更接近文化品牌，需要构建一个完整的叙事体系，而不仅仅是产品+价格的组合。”</p>\\n<p>大型美妆集团收购小众品牌，或是为了顺应行业这一结构性变化。譬如，雅诗兰黛投资拥有极强拉美文化属性的墨西哥品牌Xinù，便意在加速集团全球文化多样性布局。</p>\\n<h4><strong>3、消费者愿为独特性与文化属性支付高溢价</strong></h4>\\n<p>眼下，消费者不再只为香味买单，买的是一段记忆，一个故事或是一场创作仪式，所以更愿意为小众香水的独特调性、文化叙事支付溢价。</p>\\n<p>也就是说，小众香水的长期价值远超短期流量爆款，这也是美妆巨头们放弃 “买流量”、转向 “买审美” 的关键动力。</p>\\n<h2><strong>狂欢之下，巨头押注小众香水的考验</strong></h2>\\n<p>然而，疯狂押注小众高端香水的背后，美妆巨头们同样面临着不小的挑战。高价拿下“香饽饽”只是第一步，如何消化、整合并持续释放品牌价值，才是真正的考验。</p>\\n<h4><strong>一、小众调性与规模化扩张的博弈</strong></h4>\\n<p>首先，对于靠独特叙事和稀缺性吸引消费者的小众香水品牌而言，被巨头收购后<strong>如何在规模化扩张中守住品牌内核</strong>，是一个无法避开的难题。</p>\\n<p>当小众品牌被大集团收购后，把控品牌灵魂与创作初心的创始人的离开似乎已成必然，如，品牌由大集团完全掌控，其稀缺性很可能在集团追求利益最大化时逐渐丢失。</p>\\n<h4><strong>二、估值偏高，回报周期漫长</strong></h4>\\n<p>其次，当前小众高端香水标的估值水涨船高，收购对价普遍远超营收倍数，叠加香水品类复购周期长、增长天花板清晰，美妆集团需承担高额商誉与资金成本。</p>\\n<p>正如其里QILI创始人<strong>圆圆</strong>所指出的：“因香水的非刚需性，导致其无法像护肤品依靠功能性痛点建立高频复购，也难以像彩妆凭借潮流迭代形成持续消耗。”</p>\\n<p>且，如今市场增速放缓，品牌短期难以兑现高增长承诺，<strong>投资回报周期被大幅拉长，极易形成业绩包袱</strong>。</p>\\n<h4><strong>三、中国市场本土化“硬骨头”难啃</strong></h4>\\n<p>最后，当下中国香水消费仍以礼品与场景化使用为主，与西方日常佩戴习惯差异显著，小众品牌存在认知度低、香调水土不服、线下体验成本高、跨境价格倒挂等问题。</p>\\n<p>与此同时，小众香水品牌的内容传播与渠道运营高度本土化，美妆集团们既要维持奢品调性，又要适配本土流量逻辑，平衡难度极大。再加上，近期关税重压和原料涨价的影响，海外小众品牌在中国市场的盈利前景更加扑朔迷离。</p>\\n<p>回到此次出售交易，玛丽之香最终能否以160亿估值顺利易主，被欧莱雅、雅诗兰黛等美妆巨头成功收入囊中，仍是未知数。</p>\\n<p>但无论此次交易结果如何，美妆行业对小众香水的争夺战仍将持续升温，而如何平衡商业利益与品牌初心、破解本土化难题，将成为所有入局者必须面对的长期课题，也将持续影响全球高端香水市场的竞争格局。</p>\\n<p>而对于中国美妆产业而言，当巨头们正在通过资本抢占审美“制高点”时，中国品牌在香水赛道的文化叙事能力，是否已经准备好参与下一轮全球对话？</p>\\n<p>注：本文涉及汇率换算如下：1 美元≈6.82人民币，1欧元≈8.04人民币</p>\\n<p>消息来源：Beauty Matter</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI0OTg1NTUxOA==&amp;mid=2247636519&amp;idx=1&amp;sn=d850238c5ddf5aa6faaab93ae826639a&amp;chksm=e8064755cf9e099db3d824b195766f583e9092ff5303a0a8fe8a7746f3acd1a1bd08099ef974&amp;scene=0&amp;xtrack=1#rd\\\">“聚美丽”（ID：jumeili-cn）</a>，作者：沐沐，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'估值160亿，巨头们争夺这一小众品牌\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'估值160亿，巨头们争夺这一小众品牌\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768686035862018?f=rss\'}], \'link\': \'https://36kr.com/p/3768686035862018?f=rss\', \'published\': \'2026-04-16 10:12:15  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=12, tm_sec=15, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>2026年香水领域大事件接连不断——欧莱雅正式完成对开云美妆的收购，雅诗兰黛与Puig的合并谈判也在推进中。就在巨头们忙于整合布局、争夺赛���话语权之际，另一家小众香水被推上了收购竞逐的牌桌。</p>\\\\n  <p>继2025年10月首次传出出售意向后，日前(4月13日)，聚美丽从外媒BeautyMatter获悉，私募基金Advent International(安宏资本)已正式聘请Jefferies与高盛，共同负责Parfums de Marly(玛丽之香)的出售事宜，目前整个出售流程仍处于早期阶段。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dc255cb07ac849adb7b738150c8f95f1@000000_oswg440202oswg1080oswg560_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：Beauty Matter</p>\\\\n  <p>且值得注意的是，据外媒报道称，<strong>欧莱雅、雅诗兰黛、Puig等几家国际美妆巨头</strong>，以及多家私募股权公司与独立香氛分销商，均已开始探索对这款法国小众高端香水品牌的潜在收购。</p>\\\\n  <h2><strong>估值3年翻三番，玛丽之香遭欧莱雅们“围猎”</strong></h2>\\\\n  <p>公开资料显示，玛丽之香是由Julien Sprecher于2009年创立的法国小众高端香水，品牌以法国玛丽城堡皇家历史与骏马文化为基因，主打奢华沙龙香定位。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_48e33bc7226c41f1bf24f54051cedc5a@000000_oswg330334oswg1080oswg543_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：Parfums de Marly官网</p>\\\\n  <p>过去十余年间，凭借独特的宫廷叙事与高品质香调，玛丽之香从小众圈层逐步走向全球，业务覆盖欧美、亚洲等多个核心市场，品牌影响力持续提升，<strong>估值也随之水涨船高</strong>。</p>\\\\n  <p>具体来看，2023年，安宏资本从玛丽之香创始人Julien Sprecher手中，收购了旗下拥有Parfums de Marly与Initio Parfums Privés两大品牌的Sprecher Berrier集团多数股权，此时，玛丽之香的估值约为7亿美元(约合人民币47.74亿元)。</p>\\\\n  <p>如今，据BeautyMatter报道，有知情人士透露，玛丽之香预计估值达到20亿欧元(约合人民币160.75亿元)。这意味着，若以2023年安宏资本收购时约7亿美元(约合人民币47.74亿元)的估值计算，<strong>短短3年间，玛丽之香的估值已翻了超三倍</strong>。</p>\\\\n  <p><strong>而支撑估值飙升的核心，正是其持续高增的业绩表现</strong>。</p>\\\\n  <p>具体而言，2022年，玛丽之香年销售额已达到2.62亿欧元(约合人民币21.06亿元)，同比增长51%。截至2025年3月31日的财年内，玛丽之香销售额达5.86亿美元(约合人民币39.97亿元)，其姊妹品牌Initio Parfums Privés的销售额为1.89亿美元(约合人民币12.89亿元)，两者共同推动集团销售额同比增长41%至7.75亿美元(约合人民币52.86亿元)。</p>\\\\n  <p>在业绩持续高增的驱动下，玛丽之香加速向全球市场扩张。2021年，玛丽之香借上海首店正式进入中国市场。随后在颖通集团的运营支持下，品牌渠道迅速铺开，相继在北京、广州、成都、武汉、三亚、海口等关键城市的高端商圈落地数十家门店与专柜，展现出较强的市场拓展力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ecc259785604431d817eb6ae30b1eebc@000000_oswg666676oswg1080oswg1973_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>正是凭借持续爆发的增长势头，玛丽之香吸引了欧莱雅、雅诗兰黛、Puig等国际美妆巨头，以及多家私募股权公司与独立香氛分销商的收购意向。</p>\\\\n  <p>不过，BeautyMatter报道中也提到，雅诗兰黛与Puig的合并谈判、欧莱雅对开云美妆的整合工作仍在推进，三大战略买家短期内<strong>恐难以全力推进新收购</strong>，实际参与竞价的机构数量或将受限，<strong>因此玛丽之香可能再次掌握在私募股权手中</strong>。</p>\\\\n  <p>同时，受宏观消费环境波动及美妆集团战略重心转移影响，<strong>当前的预期估值较难实现，最终交易价格存在下调空间</strong>。</p>\\\\n  <p>这意味着，这个估值160亿的“香饽饽”，最终能否以预期价格顺利落入巨头囊中，仍存在不小的变数。</p>\\\\n  <h2><strong>巨头们疯抢小众香水，打的什么算盘？</strong></h2>\\\\n  <p>玛丽之香被巨头们盯上，并非个案。将时间轴拉长来看，近年来国际美妆集团对香水资产的争夺，已进入白热化阶段。</p>\\\\n  <p>据聚美丽不完全统计，2025年以来，包括欧莱雅、雅诗兰黛、LVMH在内的全球美妆集团，在香水赛道的布局动作高达8起，其中<strong>半数以上均聚焦于小众高端香水赛道</strong>。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f574a67784d54dcda04e884918322b40@000000_oswg802724oswg1080oswg2431_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>从上述布局动作不难看出，小众高端香水已成为巨头们重点押注的细分领域，一场围绕小众香氛的“圈地运动”已然拉开帷幕。那么，巨头们为何不惜重金，也要“疯抢”小众香水？</p>\\\\n  <p><strong>究其原因，首先与赛道本身增长红利密切相关。</strong>在全球美妆大盘增速放缓、护肤与彩妆品类增长见顶的大背景下，高端香水成为为数不多仍能保持高增长的细分赛道。</p>\\\\n  <p>据Mordor Intelligence相关数据显示，香氛市场在2025年估值760亿美元(约合人民币5183.58亿元)，预计到2030年将达到1120亿美元(约合人民币7638.96亿元)，在预测期间以7.95%的复合年增长率增长。</p>\\\\n  <p>不过，市场增长前景只是硬币的一面。除赛道红利外，巨头们疯狂押注小众香水，还有更深层的逻辑——</p>\\\\n  <h4><strong>1、掌握小众，即掌握未来审美话语权</strong></h4>\\\\n  <p>当下，小众香水已从个性表达升级为Z世代的身份与审美载体。相比商业香水的 “安全审美”，小众香水代表审美边界，可通过视觉叙事维护品牌美学，从而转化出更高未来价值。</p>\\\\n  <p>因而，美妆集团收购小众香水品牌，本质上抢占下一代消费者的审美主导权，例如LVMH集团入股代表新一代巴黎艺术香水的BDK，正是为了补齐集团中型精品香氛版图上的空缺。</p>\\\\n  <h4><strong>2、行业驱动力从“流量”转向“文化与审美”</strong></h4>\\\\n  <p>如今，香水行业正进入新周期，其增长核心从规模、渠道、爆款逻辑，转变为地域文化、个性审美与垂直细分。正如闻献创始人<strong>孟昭然</strong>此前接受聚美丽的采访时所说：“香氛品牌往往更接近文化品牌，需要构建一个完整的叙事体系，而不仅仅是产品+价格的组合。”</p>\\\\n  <p>大型美妆集团收购小众品牌，或是为了顺应行业这一结构性变化。譬如，雅诗兰黛投资拥有极强拉美文化属性的墨西哥品牌Xinù，便意在加速集团全球文化多样性布局。</p>\\\\n  <h4><strong>3、消费者愿为独特性与文化属性支付高溢价</strong></h4>\\\\n  <p>眼下，消费者不再只为香味买单，买的是一段记忆，一个故事或是一场创作仪式，所以更愿意为小众香水的独特调性、文化叙事支付溢价。</p>\\\\n  <p>也就是说，小众香水的长期价值远超短期流量爆款，这也是美妆巨头们放弃 “买流量”、转向 “买审美” 的关键动力。</p>\\\\n  <h2><strong>狂欢之下，巨头押注小众香水的考验</strong></h2>\\\\n  <p>然而，疯狂押注小众高端香水的背后，美妆巨头们同样面临着不小的挑战。高价拿下“香饽饽”只是第一步，如何消化、整合并持续释放品牌价值，才是真正的考验。</p>\\\\n  <h4><strong>一、小众调性与规模化扩张的博弈</strong></h4>\\\\n  <p>首先，对于靠独特叙事和稀缺性吸引消费者的小众香水品牌而言，被巨头收购后<strong>如何在规模化扩张中守住品牌内核</strong>，是一个无法避开的难题。</p>\\\\n  <p>当小众品牌被大集团收购后，把控品牌灵魂与创作初心的创始人的离开似乎已成必然，如，品牌由大集团完全掌控，其稀缺性很可能在集团追求利益最大化时逐渐丢失。</p>\\\\n  <h4><strong>二、估值偏高，回报周期漫长</strong></h4>\\\\n  <p>其次，当前小众高端香水标的估值水涨船高，收购对价普遍远超营收倍数，叠加香水品类复购周期长、增长天花板清晰，美妆集团需承担高额商誉与资金成本。</p>\\\\n  <p>正如其里QILI创始人<strong>圆圆</strong>所指出的：“因香水的非刚需性，导致其无法像护肤品依靠功能性痛点建立高频复购，也难以像彩妆凭借潮流迭代形成持续消耗。”</p>\\\\n  <p>且，如今市场增速放缓，品牌短期难以兑现高增长承诺，<strong>投资回报周期被大幅拉长，极易形成业绩包袱</strong>。</p>\\\\n  <h4><strong>三、中国市场本土化“硬骨头”难啃</strong></h4>\\\\n  <p>最后，当下中国香水消费仍以礼品与场景化使用为主，与西方日常佩戴习惯差异显著，小众品牌存在认知度低、香调水土不服、线下体验成本高、跨境价格倒挂等问题。</p>\\\\n  <p>与此同时，小众香水品牌的内容传播与渠道运营高度本土化，美妆集团们既要维持奢品调性，又要适配本土流量逻辑，平衡难度极大。再加上，近期关税重压和原料涨价的影响，海外小众品牌在中国市场的盈利前景更加扑朔迷离。</p>\\\\n  <p>回到此次出售交易，玛丽之香最终能否以160亿估值顺利易主，被欧莱雅、雅诗兰黛等美妆巨头成功收入囊中，仍是未知数。</p>\\\\n  <p>但无论此次交易结果如何，美妆行业对小众香水的争夺战仍将持续升温，而如何平衡商业利益与品牌初心、破解本土化难题，将成为所有入局者必须面对的长期课题，也将持续影响全球高端香水市场的竞争格局。</p>\\\\n  <p>而对于中国美妆产业而言，当巨头们正在通过资本抢占审美“制高点”时，中国品牌在香水赛道的文化叙事能力，是否已经准备好参与下一轮全球对话？</p>\\\\n  <p>注：本文涉及汇率换算如下：1 美元≈6.82人民币，1欧元≈8.04人民币</p>\\\\n  <p>消息来源：Beauty Matter</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI0OTg1NTUxOA==&amp;mid=2247636519&amp;idx=1&amp;sn=d850238c5ddf5aa6faaab93ae826639a&amp;chksm=e8064755cf9e099db3d824b195766f583e9092ff5303a0a8fe8a7746f3acd1a1bd08099ef974&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“聚美丽”（ID：jumeili-cn）</a>，作者：沐沐，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>2026年香水领域大事件接连不断——欧莱雅正式完成对开云美妆的收购，雅诗兰黛与Puig的合并谈判也在推进中。就在巨头们忙于整合布局、争夺赛���话语权之际，另一家小众香水被推上了收购竞逐的牌桌。</p>\\\\n  <p>继2025年10月首次传出出售意向后，日前(4月13日)，聚美丽从外媒BeautyMatter获悉，私募基金Advent International(安宏资本)已正式聘请Jefferies与高盛，共同负责Parfums de Marly(玛丽之香)的出售事宜，目前整个出售流程仍处于早期阶段。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dc255cb07ac849adb7b738150c8f95f1@000000_oswg440202oswg1080oswg560_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：Beauty Matter</p>\\\\n  <p>且值得注意的是，据外媒报道称，<strong>欧莱雅、雅诗兰黛、Puig等几家国际美妆巨头</strong>，以及多家私募股权公司与独立香氛分销商，均已开始探索对这款法国小众高端香水品牌的潜在收购。</p>\\\\n  <h2><strong>估值3年翻三番，玛丽之香遭欧莱雅们“围猎”</strong></h2>\\\\n  <p>公开资料显示，玛丽之香是由Julien Sprecher于2009年创立的法国小众高端香水，品牌以法国玛丽城堡皇家历史与骏马文化为基因，主打奢华沙龙香定位。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_48e33bc7226c41f1bf24f54051cedc5a@000000_oswg330334oswg1080oswg543_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：Parfums de Marly官网</p>\\\\n  <p>过去十余年间，凭借独特的宫廷叙事与高品质香调，玛丽之香从小众圈层逐步走向全球，业务覆盖欧美、亚洲等多个核心市场，品牌影响力持续提升，<strong>估值也随之水涨船高</strong>。</p>\\\\n  <p>具体来看，2023年，安宏资本从玛丽之香创始人Julien Sprecher手中，收购了旗下拥有Parfums de Marly与Initio Parfums Privés两大品牌的Sprecher Berrier集团多数股权，此时，玛丽之香的估值约为7亿美元(约合人民币47.74亿元)。</p>\\\\n  <p>如今，据BeautyMatter报道，有知情人士透露，玛丽之香预计估值达到20亿欧元(约合人民币160.75亿元)。这意味着，若以2023年安宏资本收购时约7亿美元(约合人民币47.74亿元)的估值计算，<strong>短短3年间，玛丽之香的估值已翻了超三倍</strong>。</p>\\\\n  <p><strong>而支撑估值飙升的核心，正是其持续高增的业绩表现</strong>。</p>\\\\n  <p>具体而言，2022年，玛丽之香年销售额已达到2.62亿欧元(约合人民币21.06亿元)，同比增长51%。截至2025年3月31日的财年内，玛丽之香销售额达5.86亿美元(约合人民币39.97亿元)，其姊妹品牌Initio Parfums Privés的销售额为1.89亿美元(约合人民币12.89亿元)，两者共同推动集团销售额同比增长41%至7.75亿美元(约合人民币52.86亿元)。</p>\\\\n  <p>在业绩持续高增的驱动下，玛丽之香加速向全球市场扩张。2021年，玛丽之香借上海首店正式进入中国市场。随后在颖通集团的运营支持下，品牌渠道迅速铺开，相继在北京、广州、成都、武汉、三亚、海口等关键城市的高端商圈落地数十家门店与专柜，展现出较强的市场拓展力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ecc259785604431d817eb6ae30b1eebc@000000_oswg666676oswg1080oswg1973_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>正是凭借持续爆发的增长势头，玛丽之香吸引了欧莱雅、雅诗兰黛、Puig等国际美妆巨头，以及多家私募股权公司与独立香氛分销商的收购意向。</p>\\\\n  <p>不过，BeautyMatter报道中也提到，雅诗兰黛与Puig的合并谈判、欧莱雅对开云美妆的整合工作仍在推进，三大战略买家短期内<strong>恐难以全力推进新收购</strong>，实际参与竞价的机构数量或将受限，<strong>因此玛丽之香可能再次掌握在私募股权手中</strong>。</p>\\\\n  <p>同时，受宏观消费环境波动及美妆集团战略重心转移影响，<strong>当前的预期估值较难实现，最终交易价格存在下调空间</strong>。</p>\\\\n  <p>这意味着，这个估值160亿的“香饽饽”，最终能否以预期价格顺利落入巨头囊中，仍存在不小的变数。</p>\\\\n  <h2><strong>巨头们疯抢小众香水，打的什么算盘？</strong></h2>\\\\n  <p>玛丽之香被巨头们盯上，并非个案。将时间轴拉长来看，近年来国际美妆集团对香水资产的争夺，已进入白热化阶段。</p>\\\\n  <p>据聚美丽不完全统计，2025年以来，包括欧莱雅、雅诗兰黛、LVMH在内的全球美妆集团，在香水赛道的布局动作高达8起，其中<strong>半数以上均聚焦于小众高端香水赛道</strong>。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f574a67784d54dcda04e884918322b40@000000_oswg802724oswg1080oswg2431_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>从上述布局动作不难看出，小众高端香水已成为巨头们重点押注的细分领域，一场围绕小众香氛的“圈地运动”已然拉开帷幕。那么，巨头们为何不惜重金，也要“疯抢”小众香水？</p>\\\\n  <p><strong>究其原因，首先与赛道本身增长红利密切相关。</strong>在全球美妆大盘增速放缓、护肤与彩妆品类增长见顶的大背景下，高端香水成为为数不多仍能保持高增长的细分赛道。</p>\\\\n  <p>据Mordor Intelligence相关数据显示，香氛市场在2025年估值760亿美元(约合人民币5183.58亿元)，预计到2030年将达到1120亿美元(约合人民币7638.96亿元)，在预测期间以7.95%的复合年增长率增长。</p>\\\\n  <p>不过，市场增长前景只是硬币的一面。除赛道红利外，巨头们疯狂押注小众香水，还有更深层的逻辑——</p>\\\\n  <h4><strong>1、掌握小众，即掌握未来审美话语权</strong></h4>\\\\n  <p>当下，小众香水已从个性表达升级为Z世代的身份与审美载体。相比商业香水的 “安全审美”，小众香水代表审美边界，可通过视觉叙事维护品牌美学，从而转化出更高未来价值。</p>\\\\n  <p>因而，美妆集团收购小众香水品牌，本质上抢占下一代消费者的审美主导权，例如LVMH集团入股代表新一代巴黎艺术香水的BDK，正是为了补齐集团中型精品香氛版图上的空缺。</p>\\\\n  <h4><strong>2、行业驱动力从“流量”转向“文化与审美”</strong></h4>\\\\n  <p>如今，香水行业正进入新周期，其增长核心从规模、渠道、爆款逻辑，转变为地域文化、个性审美与垂直细分。正如闻献创始人<strong>孟昭然</strong>此前接受聚美丽的采访时所说：“香氛品牌往往更接近文化品牌，需要构建一个完整的叙事体系，而不仅仅是产品+价格的组合。”</p>\\\\n  <p>大型美妆集团收购小众品牌，或是为了顺应行业这一结构性变化。譬如，雅诗兰黛投资拥有极强拉美文化属性的墨西哥品牌Xinù，便意在加速集团全球文化多样性布局。</p>\\\\n  <h4><strong>3、消费者愿为独特性与文化属性支付高溢价</strong></h4>\\\\n  <p>眼下，消费者不再只为香味买单，买的是一段记忆，一个故事或是一场创作仪式，所以更愿意为小众香水的独特调性、文化叙事支付溢价。</p>\\\\n  <p>也就是说，小众香水的长期价值远超短期流量爆款，这也是美妆巨头们放弃 “买流量”、转向 “买审美” 的关键动力。</p>\\\\n  <h2><strong>狂欢之下，巨头押注小众香水的考验</strong></h2>\\\\n  <p>然而，疯狂押注小众高端香水的背后，美妆巨头们同样面临着不小的挑战。高价拿下“香饽饽”只是第一步，如何消化、整合并持续释放品牌价值，才是真正的考验。</p>\\\\n  <h4><strong>一、小众调性与规模化扩张的博弈</strong></h4>\\\\n  <p>首先，对于靠独特叙事和稀缺性吸引消费者的小众香水品牌而言，被巨头收购后<strong>如何在规模化扩张中守住品牌内核</strong>，是一个无法避开的难题。</p>\\\\n  <p>当小众品牌被大集团收购后，把控品牌灵魂与创作初心的创始人的离开似乎已成必然，如，品牌由大集团完全掌控，其稀缺性很可能在集团追求利益最大化时逐渐丢失。</p>\\\\n  <h4><strong>二、估值偏高，回报周期漫长</strong></h4>\\\\n  <p>其次，当前小众高端香水标的估值水涨船高，收购对价普遍远超营收倍数，叠加香水品类复购周期长、增长天花板清晰，美妆集团需承担高额商誉与资金成本。</p>\\\\n  <p>正如其里QILI创始人<strong>圆圆</strong>所指出的：“因香水的非刚需性，导致其无法像护肤品依靠功能性痛点建立高频复购，也难以像彩妆凭借潮流迭代形成持续消耗。”</p>\\\\n  <p>且，如今市场增速放缓，品牌短期难以兑现高增长承诺，<strong>投资回报周期被大幅拉长，极易形成业绩包袱</strong>。</p>\\\\n  <h4><strong>三、中国市场本土化“硬骨头”难啃</strong></h4>\\\\n  <p>最后，当下中国香水消费仍以礼品与场景化使用为主，与西方日常佩戴习惯差异显著，小众品牌存在认知度低、香调水土不服、线下体验成本高、跨境价格倒挂等问题。</p>\\\\n  <p>与此同时，小众香水品牌的内容传播与渠道运营高度本土化，美妆集团们既要维持奢品调性，又要适配本土流量逻辑，平衡难度极大。再加上，近期关税重压和原料涨价的影响，海外小众品牌在中国市场的盈利前景更加扑朔迷离。</p>\\\\n  <p>回到此次出售交易，玛丽之香最终能否以160亿估值顺利易主，被欧莱雅、雅诗兰黛等美妆巨头成功收入囊中，仍是未知数。</p>\\\\n  <p>但无论此次交易结果如何，美妆行业对小众香水的争夺战仍将持续升温，而如何平衡商业利益与品牌初心、破解本土化难题，将成为所有入局者必须面对的长期课题，也将持续影响全球高端香水市场的竞争格局。</p>\\\\n  <p>而对于中国美妆产业而言，当巨头们正在通过资本抢占审美“制高点”时，中国品牌在香水赛道的文化叙事能力，是否已经准备好参与下一轮全球对话？</p>\\\\n  <p>注：本文涉及汇率换算如下：1 美元≈6.82人民币，1欧元≈8.04人民币</p>\\\\n  <p>消息来源：Beauty Matter</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI0OTg1NTUxOA==&amp;mid=2247636519&amp;idx=1&amp;sn=d850238c5ddf5aa6faaab93ae826639a&amp;chksm=e8064755cf9e099db3d824b195766f583e9092ff5303a0a8fe8a7746f3acd1a1bd08099ef974&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“聚美丽”（ID：jumeili-cn）</a>，作者：沐沐，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'聚美丽\'}], \'author\': \'聚美丽\', \'author_detail\': {\'name\': \'聚美丽\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'遭多家美妆巨头“围猎”。\'}]}\", \"published_at\": \"2026-04-16 10:12:15\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 10:12:15', '2026-04-16 11:41:56');
INSERT INTO `news_detail` VALUES (17, 972, 6, '科技与数字服务', 'a16z创始人深度对谈：AI没有泡沫，但中美真正的对决在机器人', '', '<p>在a16z Runtime大会的闭幕主题演讲中，a16z公司的联合创始人Marc Andreessen、Ben Horowitz与普通合伙人Erik Torenberg（主持人）探讨了本次大会的亮点、大语言模型的能力现状，以及尽管资本支出巨大，人工智能为何并非泡沫。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_16bf13beb4b24d8c996ffc41a1276f95@5091053_oswg200323oswg750oswg423_img_png?x-oss-process=image/quality,q_100/format,jpg/interlace,1\"></p>\n<p>本文编译自 a16z Runtime 大会官方视频，原始链接：https://www.youtube.com/watch?v=Y7dwbJ0AtUA</p>\n<p><strong>Marc Andreessen</strong>：我认为，我们现在其实还不知道“最终形态”的 AI 产品到底会长成什么样。历史上一个很明显的类比是：个人电脑从 1975 年诞生开始，到差不多 1992 年之前，本质上一直都是文本命令行系统。17 年之后，整个行业突然转向了 GUI 图形界面，从此再也没有回头。又过了大约 5 年，行业又突然转向了网页浏览器，同样再也没有回头。所以，我当然相信 20 年后依然会有聊天机器人存在，但我也非常确定，无论是现在的聊天机器人公司，还是未来新出现的公司，都会摸索出很多与今天截然不同的交互方式，而那些形态是我们现在甚至都还没想明白的。</p>\n<h2><strong>一、AI 真的能创造吗？智能与发明的边界</strong></h2>\n<p><strong>主持人</strong>：最近很多人都在谈大语言模型的局限，它们不能真正发明新科学，不能实现真正的创造性天才，最多只是把已有内容重新组合、重新包装。你怎么看？</p>\n<p><strong>Marc Andreessen</strong>：对我来说，这类问题通常分成两种。第一种是：语言模型到底算不算“智能”？也就是说，它能不能像人一样真正处理信息，并实现某种概念上的突破？；第二种是：语言模型或者视频模型，到底算不算“有创造力”？它们能不能创作出真正新的艺术，产生真正的创造性突破？</p>\n<p>而我对这两个问题的回答，都是同一个反问：人类自己真的能做到吗？因为这里面其实有两个层次。第一，就算有些人确实算得上“聪明”，能提出原创性的概念突破，而不是简单复述训练材料或按既有脚本行事——这样的人在人群中到底占多大比例？坦率地说，我这辈子真正见过这样的人也没几个，今天这个房间里就有几位，但总数非常少。绝大多数人，一生都不会有那种真正意义上的原创性突破。创造力也是一样。你会指着贝多芬、梵高这样的人说：“这才叫创造力。”没错，这当然是创造力。但问题是，世界上有几个贝多芬、几个梵高？ 显然极少。所以，如果 AI 能够超过人类 99.99% 的水平，本身就已经很惊人了。</p>\n<h2><strong>二、重组、原创以及人类创造力的本质</strong></h2>\n<p><strong>Marc Andreessen</strong>：再往深里看，你会发现一个问题：在人类历史上，真正的概念性突破到底有多少？和“把已有想法重新混搭、重组”相比，哪一个才是主流？如果你回头看技术史，你会发现大多数重大突破，往往都建立在此前至少 40 年 的积累之上。事实上，今天的语言模型本身，也是此前 80 年研究积累 的结果。</p>\n<p>艺术领域也是同样的道理。小说、音乐、绘画，当然会有真正飞跃性的创造，但其中同样包含了大量来自前人的影响。即使是像贝多芬这样的大师，他的作品里也能看到莫扎特、海顿以及更早作曲家的痕迹。所以，所谓“原创”和“混搭”的界线，很多时候并没有想象中那么清楚。</p>\n<p>说到底，这有点像“针尖上能站几个天使”那样的哲学问题：如果一个系统已经能逼近那种世界级、跨时代的创造力和智能，哪怕只差极小一点点，那么在现实意义上，它可能就已经“差不多到了”。情感上，我当然也希望人类创造力依然保有某种独特、不可替代的东西。我也确实愿意相信这一点。但说实话，每次我用这些模型的时候，我都会觉得：它们真的已经非常聪明，也非常有创造力了。所以我相当相信，它们最终会跨过那道门槛。</p>\n<p><strong>主持人</strong>：我感觉这好像是你一贯的分析框架。别人一谈 LLM 的局限，比如它们能不能迁移学习、能不能举一反三，你的第一反应总是：人类自己能做到吗？</p>\n<p><strong>Marc Andreessen</strong>：对，就是这样。比如“横向思维”、比如“分布外推理”。很多人擅长在熟悉范围内推理，但真正能在陌生领域里迁移知识、跨域思考的人，其实非常少。我认识的这类人，坐在今天这个会场里，我大概也就能数出 3 个。而我的通讯录里大约有 1 万人。也就是说，真正稳定具备这种能力的人，大概只有万分之几。 这反而让我觉得很振奋。因为你看，人类明明有这么多局限，但我们还是创造出了惊人的艺术、电影、小说、技术发明和科学突破。所以，哪怕 AI 还没到让你 100% 确信“它正在进行真正原创思考”的地步，也不妨碍它带来巨大的进步。</p>\n<h2><strong>三、Ben Horowitz 谈嘻哈、创新与天才</strong></h2>\n<p><strong>主持人</strong>：Ben，你上周刚办完 Paid in Full Foundation 的活动，致敬了一批嘻哈传奇人物。你对“创造性天才”这个话题一定想得很多。你怎么看？</p>\n<p><strong>Ben Horowitz</strong>：我基本同意Marc的看法。不管你最后把它定义成什么，AI 已经非常有用了。就算它还没有完全达到“顶级天才创造力”的层级，它也已经很强。不过，在艺术领域，尤其是当下这一代技术，还是有一个地方没完全到位：人类特别在乎那种实时发生的、切身的生命体验。而当前模型的预训练数据，还不足以真正捕捉这种东西。但即便如此，它已经做得相当不错了。</p>\n<p><strong>Marc Andreessen</strong>：Ben 有一个非营利项目叫 Paid in Full Foundation，它会表彰并为嘻哈/说唱领域的重要创新者提供某种“养老金式”的支持。如果把过去 50 年整个嘻哈领域都算上，你觉得真正称得上“概念性创新者”的人有多少？</p>\n<p><strong>Ben Horowitz</strong>：这得看你把定义放得多宽。如果说得宽一点，上周六现场就有好几位：Rakim、Dr. Dre、George Clinton，这些人都可以算。如果定义再窄一些，比如 Cool G Rap 也确实提出过新的东西。但如果你要说那种最根本、最底层的音乐性突破，那我大概会把范围缩到 Rakim 和 George Clinton。总之，比例极低，非常低。</p>\n<p><strong>主持人</strong>：昨天 Jared Leto 也提到，好莱坞很多人对 AI 很害怕、很反感。那你和这些音乐人聊天时，比如 Dr. Dre、Nas、Kanye 这些人，他们是兴奋、排斥，还是已经在用？</p>\n<p><strong>Ben Horowitz</strong>：确实有不少音乐人害怕 AI，但也有很多人对它非常感兴趣。尤其是嘻哈圈的人，会更容易理解它。因为从某种意义上说，这几乎就是他们当年做的事情：把已有音乐拿来，重新拼接、重构，做成新东西。所以对他们来说，AI 是一个非常强大的创作工具，它极大拓展了创作的调色板。而且嘻哈很多时候讲的是一个非常具体的时间、地点和个人经验。如果你的模型对这个特定文化、特定语境“懂得很深”，那反而比一个泛化能力很强但不够贴身的音乐模型更有优势。</p>\n<h2><strong>四、智能、权力与谁在主导世界</strong></h2>\n<p><strong>主持人</strong>：很多人会用同一种逻辑来推演 AI：更聪明的东西最终会统治不那么聪明的东西。Marc，你最近发过一条很有名的话：“顶级的图形推理者，只会做图形推理；但顶级的‘文字型人才’，却能调度那些图形推理者。”你还说过一句：“高 IQ 的专家，往往是在给中等 IQ 的通才打工。”这是什么意思？</p>\n<p><strong>Marc Andreessen</strong>：意思其实很简单：博士通常给 MBA 打工。你把问题放大一点看：当你观察今天这个世界，你真的会得出“最聪明的人在统治世界”这个结论吗？放眼全球现实，你会觉得“我们把天才都放在最关键的位置上了”吗？显然不是。</p>\n<p>这里有两件事同时成立。第一，我们整体上可能低估了智力的重要性。第二，那些特别强调智力的人，又往往会高估智力的重要性。社会科学通常会告诉你，流体智力、g 因子、IQ 之类的指标，和很多正向人生结果都有相关性，比如教育结果、职业成就、收入、生活满意度，甚至包括更少诉诸暴力地解决问题。这些相关性很重要，但它依然不是全部。所以，你不能把“智力重要”直接推导成“智力是唯一决定因素”或者“智力是最重要的唯一变量”。现实显然不是这样。</p>\n<p>哪怕你是一个极端的 IQ 决定论者，你也不得不承认：很多结果并不能只靠 IQ 来解释。再往上看群体层面，事情就更复杂了。任何一群人，一旦变成“群体”甚至“乌合之众”，集体智商通常都会下降。你把一群聪明人放进一个群体，他们往往也会变笨。所以，不管是公司、组织还是国家，谁来掌权，从来都不只是 IQ 决定的，甚至可能根本不是主要由 IQ 决定的。 因此，AI 圈里有一种常见假设：更聪明的存在必然会统治更笨的存在。我觉得这种说法非常容易被现实反驳。因为智能不是充分条件。</p>\n<h2><strong>五、超越 IQ：领导力、情绪与“心理理论”</strong></h2>\n<p><strong>主持人</strong>：那除了智力之外，哪些能力更决定一个人能否成功领导、创业、解决复杂问题、组织团队？以及为什么 AI 不能同样学会这些能力？</p>\n<p><strong>Ben Horowitz</strong>：有很多东西都重要。比如，你能不能以正确的方式跟人发生冲突。这里面当然有一点智力成分，但更多时候，关键在于你是不是真的理解你正在跟谁打交道。你要能读懂对方怎么想，能从公司员工的视角看问题，而不是只从你自己的视角看。这种能力来自于长期和人沟通、倾听、理解，而不是 IQ 测出来的。而且管理还有一个关键点：你不是为了让大家做“最受欢迎的事”，而是要让大家去做“正确的事”，哪怕他们并不喜欢。这就是大量管理工作的本质。</p>\n<p><strong>Marc Andreessen</strong>：所以这里面涉及勇气、动机、情绪理解，以及所谓的 theory of mind（心理理论）。</p>\n<p><strong>Ben Horowitz</strong>：对。你得知道别人想要什么，同时又不能只迎合，而是要把这和“组织真正需要做什么”结合起来。还要判断：团队里谁能力强，谁是不能失去的人，谁情绪崩了影响不大，谁一出问题整个团队就会出事。这些东西充满了微妙的情境判断，很难抽象成几条通用公式。这也是为什么很多管理书都很糟糕。因为管理高度依赖具体情境：你的公司、你的产品、你的人、你的组织结构，都和别人完全不同。所以那种“建立战略的五个步骤”式的书，很多时候根本没什么用。</p>\n<p><strong>Marc Andreessen</strong>：心理理论非常关键。简单说，就是：你能不能在自己脑子里，准确模拟出别人脑子里在发生什么。直觉上你会以为，越聪明的人越擅长这个；但事实可能并非如此。美国军方是美国社会最早、也是最系统使用 IQ 测试的机构之一。他们通过 ASVAB 之类测试把人分配到不同岗位，甚至领导岗位。而他们长期观察发现：如果一个领导者的智力水平和他带领的人群相差超过一个标准差，就很容易出问题。低于团队太多当然不行；但反过来，高出太多也不行。如果一个领导者的智力比组织平均水平高出两个标准差，他往往也会失去对他人的“心理建模能力”。也就是说，特别聪明的人，反而可能很难真正理解普通聪明人的思维过程。</p>\n<p>所以，领导者和被领导者之间需要某种“可连接性”，这不是单靠智力就能解决的。由此类推，如果未来真的出现一个 IQ 高得离谱的人，或者机器，比如“1000 IQ”的存在，它对现实的理解方式可能会异化到一个程度，以至于它根本无法和它所管理的人建立真实连接。这也是为什么我认为，未来很长时间里，这个世界都不会单纯按 IQ 来组织。</p>\n<p><strong>Ben Horowitz</strong>：扎克伯格有句话说得很好：“智能不是生命本身。”生命有很多维度，而这些维度并不依赖智力。有些人太聪明了，反而会过度理性化，默认别人也会那么理性，于是把很多事情都想偏了。</p>\n<h2><strong>六、具身智能：心智与身体的问题</strong></h2>\n<p><strong>Marc Andreessen</strong>：我还怀疑，这个问题最终会越来越走向生物学。现在越来越多研究表明，人类的认知、自我意识、信息处理、决策和主观体验，并不只是大脑在工作。传统的“心身二元论”——把心智和身体完全分开——很可能本来就是错的。 人的存在体验是一个全身性的过程。神经系统当然重要，但肠道菌群、嗅觉、激素、各种生化过程，都会影响人的认知和判断。如果顺着这条研究线继续往前走，我猜我们最后会发现：人类认知比大家原先以为的，更像是一种“全身参与”的体验。</p>\n<p>而这恰恰是今天 AI 领域面临的一个基础性问题。当前真正运转起来的 AI，本质上还是一种“彻底心身分离”的形式——它像一个脱离身体的大脑。但机器人革命迟早会来。当 AI 被装进能在物理世界里移动、感知、行动的实体里，它才可能更接近那种真正“智力—身体一体化”的经验结构。机器人会带来更多传感器、更多现实世界数据，也许会让系统更接近那种完整的智能。 但至少从现在的研究来看，这个方向还很早，我们还有很多工作要做。</p>\n<h2><strong>七、今天的 AI 在“读人心”方面到底有多强？</strong></h2>\n<p><strong>主持人</strong>：你觉得现在的 AI 在“心理理论”这件事上做得怎么样？它们的边界在哪里？</p>\n<p><strong>Marc Andreessen</strong>：总体来说，我觉得它们已经相当强了。我个人很喜欢让语言模型去生成“人物角色”，再让这些角色展开一种苏格拉底式对话。现在任何先进的大模型都能把这件事做得不错。不过它们有个特别烦人的毛病：它们总想让所有人都开心，最后都达成一致。一开始讨论可能还有点意思，但很快就会变成一种“大家互相理解、圆满收场”的剧情，我特别讨厌这个。所以我会故意给它下指令：把对话写得更紧张一点，更有怒气一点，让人物之间的冲突一路升级；再加一点脏话，让他们彻底撕破脸，进入那种“我要摧毁你名誉”的状态。这样它就会变得非常有意思。再后来我还会玩过头，比如说“其实他们全都是秘密忍者”，于是爱因斯坦就拿着双节棍去打玻尔——模型居然也能顺着往下编。所以你自己也得克制一点。</p>\n<p>但这恰恰说明，它在“模拟不同人的思维状态”上已经很强了。再举个例子：英国有一家做政治相关业务的创业公司发现，现在最先进的语言模型已经好到可以在模型内部，较准确地复现一个真实选民焦点小组。现实中的焦点小组很贵，要招募人、筛人、组织现场，还很花时间。但模型现在已经能模拟出不同背景的人，比如来自肯塔基州的大学生、田纳西州的家庭主妇等等，并让这些角色在模型内部展开讨论，而且结果与真实焦点小组相当接近。所以至少在这个门槛上，它已经跨过去了。接下来能走多远，还要继续看。</p>\n<h2><strong>八、AI 是不是泡沫？基本面与市场情绪</strong></h2>\n<p><strong>主持人</strong>：前面几位嘉宾提到，AI 正在建设极其庞大的物理基础设施，资本开支已经达到 GDP 的 1%。我们到底该怎么理解“AI 泡沫”这个问题？</p>\n<p><strong>Ben Horowitz</strong>：在我看来，只要大家还在问“这是不是泡沫”，那它大概率就还不是泡沫。</p>\n<p>因为泡沫本质上首先是一种心理现象。真正的泡沫，往往发生在所有人都已经彻底相信“这绝对不是泡沫”的时候。市场术语里，这叫“投降”——原先做空的人被持续上涨逼得受不了，只能认输，转身去做多。 互联网泡沫时期就有类似现象。那时候连巴菲特都开始投资科技股了，而他原本一直说自己不投科技，因为看不懂。</p>\n<p>如果连他都“投降”了，那时市场上其实已经没人再说那是泡沫了。 但回头看，互联网本身显然不是泡沫，它是真东西。真正的问题是：当时市场价格在短期内跑得太快，远远领先于实际用户规模和市场成熟度。可 AI 跟那时又不一样。今天 AI 最大的问题不是需求不足，而是需求太强。现在没有需求问题，我也很难相信五年后会出现需求问题。当然，未来可能会出现一些奇怪的瓶颈，比如散热不够、供电不够之类。但如果你现在看供需关系、增长与估值的匹配情况，我觉得它一点都不像泡沫。</p>\n<p><strong>Marc Andreessen</strong>：说到底，没人真正知道答案。你去问对冲基金、银行、CEO，很多人其实都不知道。VC 也常常不知道，只是有些人会因为自己错过机会、看到估值越来越高而情绪失控，特别希望这最终被证明是个泡沫。</p>\n<p><strong>Ben Horowitz</strong>：在我们这个行业里，最让人难受的事情之一，就是你错过了一个项目，结果它后来成了大成功。你可能会因此气 30 年。于是你就会不断找理由解释：不是我判断错了，是世界疯了。</p>\n<p><strong>Marc Andreessen</strong>：所以我会建议把讨论拉回最朴素的两个基本面问题：第一，技术到底能不能真正工作？能不能兑现它承诺的价值？第二，客户到底愿不愿意为它付钱？只要这两点都成立，整体方向通常就不会跑偏。</p>\n<h2><strong>九、平台迁移、Google 的“珍珠港时刻”与新交互范式</strong></h2>\n<p><strong>主持人</strong>：有人说 ChatGPT 对 Google 来说是一个“珍珠港时刻”，是巨人被惊醒的一刻。历史上每次平台切换时，到底是什么决定了老巨头能不能赢下下一波，而不是被新玩家取代？</p>\n<p><strong>Ben Horowitz</strong>：对变化做出反应当然重要，但这并不代表巨头就一定能赢。Google 确实被惊醒了，用不那么客气的话说，就是它终于“把脑袋从屁股里拔出来了”。所以它不会被轻易彻底碾压，但与此同时，我也不认为 OpenAI 会消失。Google 的确给了对手机会。说到底，比的是长期执行力。很多超级大公司在不同程度上都失去了持续执行的能力。历史上，新平台往往是新公司赢下来。微软当年错过了搜索，后来又错过了移动计算；它依然很强，但确实错过了那两个关键时代。所以通常是：新公司赢下新市场，老垄断则依靠旧时代积累继续存在很久。</p>\n<p><strong>Marc Andreessen</strong>：而且我觉得大家现在还有一个很容易犯的错误，就是默认未来的主流产品形态，只会是“搜索引擎”或者“聊天机器人”��选一。这是一种过于简化的看法。</p>\n<p>这种想法背后的叙事通常是：Google 面临的经典难题是自我颠覆——要不要把“10 条蓝色链接”的模式，替换成 AI 回答，从而可能冲击自己的广告模式；OpenAI 的问题则是，它有完整的聊天产品，但还没有 Google 那样的广告体系和分发能力。听上去很像《创新者的窘境》教科书里那种“新旧势力正面对决”的模型。但这种看法默认了一个前提：5 年、10 年、15 年、20 年后，人们主要使用的产品形态，还是“搜索”或“聊天”。</p>\n<p>而我认为，这个前提本身就很可能是错的。回到个人电脑历史就知道了：1975 年到 1992 年，个人电脑基本就是文本命令系统。而在当时，交互式命令行本身已经比打孔卡和时分系统先进很多了。但 17 年后，整个行业突然转向 GUI；又过 5 年，行业再转向浏览器。也就是说，用户体验的形态、产品进入生活的方式，直到很后面才真正定型。所以，我相信 20 年后依然会有聊天机器人，但我同样相信，当前的聊天产品公司和未来的新公司，一定会发明出很多今天我们还根本没见过的 AI 产品形态。而这正是科技行业最有意思的地方：产品的最终形态并不预先写好，发明空间仍然极大。</p>\n<h2><strong>十、给创业者的建议：这是一个真正不同的时代</strong></h2>\n<p><strong>主持人</strong>：如果你们要给今天的创业者一些建议，这个时代和过去最大的不同在哪里？无论是人才争夺，还是公司组织方式，还有哪些是创业者应该特别留意的？</p>\n<p><strong>Ben Horowitz</strong>：我觉得你刚才其实已经说中了重点：这是一个真正独特的时代。所以，如果你过度试图从上一个时代照搬组织设计经验、管理经验，反而可能会被误导。今天公司被搭建起来的方式，和过去已经非常不同了。 比如 AI 研究型 PhD 和传统的全栈工程师，完全不是同一种人才画像。所以很多问题必须回到第一性原理重新思考，而不能靠历史模板套答案。</p>\n<p><strong>Marc Andreessen</strong>：我还想补充一点：接下来变化一定会继续发生。我前面说过，产品形态会变；与此同时，今天大家最头疼的资源短缺，未来很可能会反过来变成过剩。</p>\n<h2><strong>十一、人才、芯片，以及“短缺终将导向过剩”的周期</strong></h2>\n<p><strong>Marc Andreessen</strong>：在供需世界里，一个很有意思的规律是：严重短缺本身，往往会孕育未来的过剩。因为当某样东西太稀缺、利润太高时，市场就会释放出巨大的激励，逼着人们去想办法增加供给。 现在的 AI 公司，一方面非常缺顶级研究员和工程师；另一方面又在缺芯片、数据中心、电力等基础设施。我不想断言具体时间点，但我相信总有一天，这两类短缺都会缓解，甚至转向过剩。</p>\n<p>尤其在人才这一边，一个很值得注意的现象是：中国现在已经冒出了很多非常出色的模型，而且不止一家。比如 DeepSeek、Qwen（通义千问）、Kimi。更有意思的是，做出这些东西的团队，很多并不是那种“论文圈最有名、名字总挂在顶刊上的明星团队”。这说明中国正在成功摸索出一套方法：把年轻人快速训练出来，让他们真正进入这个领域、做出成果。</p>\n<p><strong>Ben Horowitz</strong>：xAI 在某种程度上也是如此。</p>\n<p><strong>Marc Andreessen</strong>：对。所以我觉得，虽然顶级 AI 研发能力在一段时间内仍会是极其稀缺、极其昂贵的技能，但知识扩散已经开始发生了。大学生在学，更多人在会做，AI 也会进一步帮助人类构建 AI。也许不会真的出现“人才过剩”，但至少未来懂得如何构建这些系统的人，一定会比今天多得多。</p>\n<p>再看芯片这一边。我不是芯片专家，但如果回顾整个芯片产业历史，你会发现一个规律：每一次短缺，最后几乎都会走向过剩。因为短缺时利润太高，利润池太大，外部竞争者进入并把这个功能“商品化”的动力就会极强。NVIDIA 今天在芯片行业的位置，可能已经好到了史无前例的程度。但即便如此，我还是很难相信，5 年后基础设施会维持今天这种极端紧张的状态。哪怕瓶颈从芯片转移到了电力、散热或别的地方，芯片本身也很可能会出现供给宽松。</p>\n<p>所以我只想说一句：五年后，我们今天面对的问题大概率都还会在，但形式会完全变掉。这个行业变化极快，绝不能用静态视角看它。</p>\n<h2><strong>十二、中美 AI 竞赛与机器人时代</strong></h2>\n<p><strong>主持人</strong>：上个月我们在华盛顿时，参议员们很关心一个问题：到底该怎么看中美 AI 竞赛的现状？你愿意把当时对他们说的核心观点再讲一遍吗？</p>\n<p><strong>Marc Andreessen</strong>：我的基本判断是：到目前为止，重大的概念性创新，主要还是来自美国，更广一点说是来自西方，而其中又越来越集中在美国。但中国在另一件事上极其擅长：迅速吸收想法、把它做出来、放大规模、压低成本、实现商品化。他们在制造业里一直就是这么干的，现在在 AI 里也正在很成功地这么做。</p>\n<p>所以我会说，中国现在是在把“追赶战”打得非常好。当然，关于追赶速度为何如此之快，外界有各种猜测和讨论，但不管怎么说，结果摆在那里——他们确实做得非常出色。而且中国当然也不满足于只做追赶者。中国有很多非常聪明、非常有创造力的人。接下来真正值得观察的是：未来那些“概念级的突破”，会不会也开始越来越多地出现在中国，甚至让他们反超。</p>\n<p>所以我们在华盛顿对政策制定者说的是：这已经是一场真正的竞赛，是短跑，是寸土必争。美国不会拥有 5 年领先优势，可能最多也就 6 个月。我们必须跑得很快，必须赢。而且我们不能给美国公司套上中国政府并没有强加给中国公司的那些额外枷锁，否则我们就会输。如果有一天你早上醒来，发现这个世界在很大程度上是由中国 AI 所主导和塑造的，多数美国人显然不希望看到那样的局面。不过就目前而言，我对美国在软件层面的优势仍然算是谨慎乐观。</p>\n<p>但一旦 AI 进入具身智能/机器人阶段，问题就会变得更棘手。因为过去 40 年里，美国和西方整体上选择了去工业化，而中国则建立起了一个庞大的工业生态系统，覆盖机械、电气、半导体、软件以及各种终端制造：手机、无人机、汽车，未来还包括机器人。AI 革命一定会有第二阶段，那就是机器人，而且我觉得这个阶段会来得很快。到那时，哪怕美国在软件上依然领先，机器人终究还是得被“造出来”。</p>\n<p>而“把机器人造出来”不是一家公司单打独斗能完成的，它需要的是一个完整的供应链生态。汽车工业不是几家车企而已，而是成千上万的零部件供应商共同构成的体系。飞机、电脑也一样，机器人未来也会一样。 而按今天的默认格局看，这套体系很可能会主要发生在中国。所以哪怕中国在软件上没有完全追平美国，也有可能在硬件和制造端反超并绕过去。好消息是，美国 政治光谱两端现在都越来越意识到：去工业化走得太远了，必须想办法往回拉。我对此持谨慎乐观态度，但要做的事情还非常多。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/i4WecVP5x7JgvVzcpfDo0Q\">“硅星GenAI”</a>，作者：大模型机动组，36氪经授权发布。</p>', 'https://36kr.com/p/3768674338079492?f=rss', 0, '', '{\"summary\": \"帮助AI及机器人领域出海从业者把握全球AI产业趋势与中美竞争格局，为AI创业者提供决策参考\", \"abstract\": \"这是a16z两位联合创始人在Runtime大会的深度对谈，围绕AI的智能创造力边界、产业发展趋势等议题展开讨论。对谈认为当前AI不存在泡沫，技术可兑现价值且市场需求旺盛，未来AI产品形态仍有极大创新空间。对谈判断当前美国在AI概念性创新领先，中国在规模化商品化落地能力突出，中美AI领域真正的对决将发生在具身智能/机器人赛道。对谈还给AI创业者提出建议，需回归第一性原理思考，以动态视角看待产业供需变化，不要照搬过往经验。\", \"keywords\": [\"AI\", \"大语言模型\", \"具身智能\", \"机器人\", \"中美AI竞赛\", \"AI泡沫\", \"供应链\"], \"policy_risk\": {\"market_risk\": \"当前AI产业面临顶级人才、芯片、电力及数据中心基础设施短缺问题；中美AI真正的对决将在机器人赛道展开，美国缺少完整的机器人制造供应链生态，存在竞争劣势\", \"policy_compliance\": \"文中提及中美AI竞赛背景下，美国政策端正推动扭转去工业化趋势，业内呼吁美国不应给本土AI企业设置中国企业未面临的额外监管枷锁\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"https://36kr.com/p/3768674338079492?f=rss\", \"title\": \"a16z创始人深度对谈：AI没有泡沫，但中美真正的对决在机器人\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>在a16z Runtime大会的闭幕主题演讲中，a16z公司的联合创始人Marc Andreessen、Ben Horowitz与普通合伙人Erik Torenberg（主持人）探讨了本次大会的亮点、大语言模型的能力现状，以及尽管资本支出巨大，人工智能为何并非泡沫。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_16bf13beb4b24d8c996ffc41a1276f95@5091053_oswg200323oswg750oswg423_img_png?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\"></p>\\n<p>本文编译自 a16z Runtime 大会官方视频，原始链接：https://www.youtube.com/watch?v=Y7dwbJ0AtUA</p>\\n<p><strong>Marc Andreessen</strong>：我认为，我们现在其实还不知道“最终形态”的 AI 产品到底会长成什么样。历史上一个很明显的类比是：个人电脑从 1975 年诞生开始，到差不多 1992 年之前，本质上一直都是文本命令行系统。17 年之后，整个行业突然转向了 GUI 图形界面，从此再也没有回头。又过了大约 5 年，行业又突然转向了网页浏览器，同样再也没有回头。所以，我当然相信 20 年后依然会有聊天机器人存在，但我也非常确定，无论是现在的聊天机器人公司，还是未来新出现的公司，都会摸索出很多与今天截然不同的交互方式，而那些形态是我们现在甚至都还没想明白的。</p>\\n<h2><strong>一、AI 真的能创造吗？智能与发明的边界</strong></h2>\\n<p><strong>主持人</strong>：最近很多人都在谈大语言模型的局限，它们不能真正发明新科学，不能实现真正的创造性天才，最多只是把已有内容重新组合、重新包装。你怎么看？</p>\\n<p><strong>Marc Andreessen</strong>：对我来说，这类问题通常分成两种。第一种是：语言模型到底算不算“智能”？也就是说，它能不能像人一样真正处理信息，并实现某种概念上的突破？；第二种是：语言模型或者视频模型，到底算不算“有创造力”？它们能不能创作出真正新的艺术，产生真正的创造性突破？</p>\\n<p>而我对这两个问题的回答，都是同一个反问：人类自己真的能做到吗？因为这里面其实有两个层次。第一，就算有些人确实算得上“聪明”，能提出原创性的概念突破，而不是简单复述训练材料或按既有脚本行事——这样的人在人群中到底占多大比例？坦率地说，我这辈子真正见过这样的人也没几个，今天这个房间里就有几位，但总数非常少。绝大多数人，一生都不会有那种真正意义上的原创性突破。创造力也是一样。你会指着贝多芬、梵高这样的人说：“这才叫创造力。”没错，这当然是创造力。但问题是，世界上有几个贝多芬、几个梵高？ 显然极少。所以，如果 AI 能够超过人类 99.99% 的水平，本身就已经很惊人了。</p>\\n<h2><strong>二、重组、原创以及人类创造力的本质</strong></h2>\\n<p><strong>Marc Andreessen</strong>：再往深里看，你会发现一个问题：在人类历史上，真正的概念性突破到底有多少？和“把已有想法重新混搭、重组”相比，哪一个才是主流？如果你回头看技术史，你会发现大多数重大突破，往往都建立在此前至少 40 年 的积累之上。事实上，今天的语言模型本身，也是此前 80 年研究积累 的结果。</p>\\n<p>艺术领域也是同样的道理。小说、音乐、绘画，当然会有真正飞跃性的创造，但其中同样包含了大量来自前人的影响。即使是像贝多芬这样的大师，他的作品里也能看到莫扎特、海顿以及更早作曲家的痕迹。所以，所谓“原创”和“混搭”的界线，很多时候并没有想象中那么清楚。</p>\\n<p>说到底，这有点像“针尖上能站几个天使”那样的哲学问题：如果一个系统已经能逼近那种世界级、跨时代的创造力和智能，哪怕只差极小一点点，那么在现实意义上，它可能就已经“差不多到了”。情感上，我当然也希望人类创造力依然保有某种独特、不可替代的东西。我也确实愿意相信这一点。但说实话，每次我用这些模型的时候，我都会觉得：它们真的已经非常聪明，也非常有创造力了。所以我相当相信，它们最终会跨过那道门槛。</p>\\n<p><strong>主持人</strong>：我感觉这好像是你一贯的分析框架。别人一谈 LLM 的局限，比如它们能不能迁移学习、能不能举一反三，你的第一反应总是：人类自己能做到吗？</p>\\n<p><strong>Marc Andreessen</strong>：对，就是这样。比如“横向思维”、比如“分布外推理”。很多人擅长在熟悉范围内推理，但真正能在陌生领域里迁移知识、跨域思考的人，其实非常少。我认识的这类人，坐在今天这个会场里，我大概也就能数出 3 个。而我的通讯录里大约有 1 万人。也就是说，真正稳定具备这种能力的人，大概只有万分之几。 这反而让我觉得很振奋。因为你看，人类明明有这么多局限，但我们还是创造出了惊人的艺术、电影、小说、技术发明和科学突破。所以，哪怕 AI 还没到让你 100% 确信“它正在进行真正原创思考”的地步，也不妨碍它带来巨大的进步。</p>\\n<h2><strong>三、Ben Horowitz 谈嘻哈、创新与天才</strong></h2>\\n<p><strong>主持人</strong>：Ben，你上周刚办完 Paid in Full Foundation 的活动，致敬了一批嘻哈传奇人物。你对“创造性天才”这个话题一定想得很多。你怎么看？</p>\\n<p><strong>Ben Horowitz</strong>：我基本同意Marc的看法。不管你最后把它定义成什么，AI 已经非常有用了。就算它还没有完全达到“顶级天才创造力”的层级，它也已经很强。不过，在艺术领域，尤其是当下这一代技术，还是有一个地方没完全到位：人类特别在乎那种实时发生的、切身的生命体验。而当前模型的预训练数据，还不足以真正捕捉这种东西。但即便如此，它已经做得相当不错了。</p>\\n<p><strong>Marc Andreessen</strong>：Ben 有一个非营利项目叫 Paid in Full Foundation，它会表彰并为嘻哈/说唱领域的重要创新者提供某种“养老金式”的支持。如果把过去 50 年整个嘻哈领域都算上，你觉得真正称得上“概念性创新者”的人有多少？</p>\\n<p><strong>Ben Horowitz</strong>：这得看你把定义放得多宽。如果说得宽一点，上周六现场就有好几位：Rakim、Dr. Dre、George Clinton，这些人都可以算。如果定义再窄一些，比如 Cool G Rap 也确实提出过新的东西。但如果你要说那种最根本、最底层的音乐性突破，那我大概会把范围缩到 Rakim 和 George Clinton。总之，比例极低，非常低。</p>\\n<p><strong>主持人</strong>：昨天 Jared Leto 也提到，好莱坞很多人对 AI 很害怕、很反感。那你和这些音乐人聊天时，比如 Dr. Dre、Nas、Kanye 这些人，他们是兴奋、排斥，还是已经在用？</p>\\n<p><strong>Ben Horowitz</strong>：确实有不少音乐人害怕 AI，但也有很多人对它非常感兴趣。尤其是嘻哈圈的人，会更容易理解它。因为从某种意义上说，这几乎就是他们当年做的事情：把已有音乐拿来，重新拼接、重构，做成新东西。所以对他们来说，AI 是一个非常强大的创作工具，它极大拓展了创作的调色板。而且嘻哈很多时候讲的是一个非常具体的时间、地点和个人经验。如果你的模型对这个特定文化、特定语境“懂得很深”，那反而比一个泛化能力很强但不够贴身的音乐模型更有优势。</p>\\n<h2><strong>四、智能、权力与谁在主导世界</strong></h2>\\n<p><strong>主持人</strong>：很多人会用同一种逻辑来推演 AI：更聪明的东西最终会统治不那么聪明的东西。Marc，你最近发过一条很有名的话：“顶级的图形推理者，只会做图形推理；但顶级的‘文字型人才’，却能调度那些图形推理者。”你还说过一句：“高 IQ 的专家，往往是在给中等 IQ 的通才打工。”这是什么意思？</p>\\n<p><strong>Marc Andreessen</strong>：意思其实很简单：博士通常给 MBA 打工。你把问题放大一点看：当你观察今天这个世界，你真的会得出“最聪明的人在统治世界”这个结论吗？放眼全球现实，你会觉得“我们把天才都放在最关键的位置上了”吗？显然不是。</p>\\n<p>这里有两件事同时成立。第一，我们整体上可能低估了智力的重要性。第二，那些特别强调智力的人，又往往会高估智力的重要性。社会科学通常会告诉你，流体智力、g 因子、IQ 之类的指标，和很多正向人生结果都有相关性，比如教育结果、职业成就、收入、生活满意度，甚至包括更少诉诸暴力地解决问题。这些相关性很重要，但它依然不是全部。所以，你不能把“智力重要”直接推导成“智力是唯一决定因素”或者“智力是最重要的唯一变量”。现实显然不是这样。</p>\\n<p>哪怕你是一个极端的 IQ 决定论者，你也不得不承认：很多结果并不能只靠 IQ 来解释。再往上看群体层面，事情就更复杂了。任何一群人，一旦变成“群体”甚至“乌合之众”，集体智商通常都会下降。你把一群聪明人放进一个群体，他们往往也会变笨。所以，不管是公司、组织还是国家，谁来掌权，从来都不只是 IQ 决定的，甚至可能根本不是主要由 IQ 决定的。 因此，AI 圈里有一种常见假设：更聪明的存在必然会统治更笨的存在。我觉得这种说法非常容易被现实反驳。因为智能不是充分条件。</p>\\n<h2><strong>五、超越 IQ：领导力、情绪与“心理理论”</strong></h2>\\n<p><strong>主持人</strong>：那除了智力之外，哪些能力更决定一个人能否成功领导、创业、解决复杂问题、组织团队？以及为什么 AI 不能同样学会这些能力？</p>\\n<p><strong>Ben Horowitz</strong>：有很多东西都重要。比如，你能不能以正确的方式跟人发生冲突。这里面当然有一点智力成分，但更多时候，关键在于你是不是真的理解你正在跟谁打交道。你要能读懂对方怎么想，能从公司员工的视角看问题，而不是只从你自己的视角看。这种能力来自于长期和人沟通、倾听、理解，而不是 IQ 测出来的。而且管理还有一个关键点：你不是为了让大家做“最受欢迎的事”，而是要让大家去做“正确的事”，哪怕他们并不喜欢。这就是大量管理工作的本质。</p>\\n<p><strong>Marc Andreessen</strong>：所以这里面涉及勇气、动机、情绪理解，以及所谓的 theory of mind（心理理论）。</p>\\n<p><strong>Ben Horowitz</strong>：对。你得知道别人想要什么，同时又不能只迎合，而是要把这和“组织真正需要做什么”结合起来。还要判断：团队里谁能力强，谁是不能失去的人，谁情绪崩了影响不大，谁一出问题整个团队就会出事。这些东西充满了微妙的情境判断，很难抽象成几条通用公式。这也是为什么很多管理书都很糟糕。因为管理高度依赖具体情境：你的公司、你的产品、你的人、你的组织结构，都和别人完全不同。所以那种“建立战略的五个步骤”式的书，很多时候根本没什么用。</p>\\n<p><strong>Marc Andreessen</strong>：心理理论非常关键。简单说，就是：你能不能在自己脑子里，准确模拟出别人脑子里在发生什么。直觉上你会以为，越聪明的人越擅长这个；但事实可能并非如此。美国军方是美国社会最早、也是最系统使用 IQ 测试的机构之一。他们通过 ASVAB 之类测试把人分配到不同岗位，甚至领导岗位。而他们长期观察发现：如果一个领导者的智力水平和他带领的人群相差超过一个标准差，就很容易出问题。低于团队太多当然不行；但反过来，高出太多也不行。如果一个领导者的智力比组织平均水平高出两个标准差，他往往也会失去对他人的“心理建模能力”。也就是说，特别聪明的人，反而可能很难真正理解普通聪明人的思维过程。</p>\\n<p>所以，领导者和被领导者之间需要某种“可连接性”，这不是单靠智力就能解决的。由此类推，如果未来真的出现一个 IQ 高得离谱的人，或者机器，比如“1000 IQ”的存在，它对现实的理解方式可能会异化到一个程度，以至于它根本无法和它所管理的人建立真实连接。这也是为什么我认为，未来很长时间里，这个世界都不会单纯按 IQ 来组织。</p>\\n<p><strong>Ben Horowitz</strong>：扎克伯格有句话说得很好：“智能不是生命本身。”生命有很多维度，而这些维度并不依赖智力。有些人太聪明了，反而会过度理性化，默认别人也会那么理性，于是把很多事情都想偏了。</p>\\n<h2><strong>六、具身智能：心智与身体的问题</strong></h2>\\n<p><strong>Marc Andreessen</strong>：我还怀疑，这个问题最终会越来越走向生物学。现在越来越多研究表明，人类的认知、自我意识、信息处理、决策和主观体验，并不只是大脑在工作。传统的“心身二元论”——把心智和身体完全分开——很可能本来就是错的。 人的存在体验是一个全身性的过程。神经系统当然重要，但肠道菌群、嗅觉、激素、各种生化过程，都会影响人的认知和判断。如果顺着这条研究线继续往前走，我猜我们最后会发现：人类认知比大家原先以为的，更像是一种“全身参与”的体验。</p>\\n<p>而这恰恰是今天 AI 领域面临的一个基础性问题。当前真正运转起来的 AI，本质上还是一种“彻底心身分离”的形式——它像一个脱离身体的大脑。但机器人革命迟早会来。当 AI 被装进能在物理世界里移动、感知、行动的实体里，它才可能更接近那种真正“智力—身体一体化”的经验结构。机器人会带来更多传感器、更多现实世界数据，也许会让系统更接近那种完整的智能。 但至少从现在的研究来看，这个方向还很早，我们还有很多工作要做。</p>\\n<h2><strong>七、今天的 AI 在“读人心”方面到底有多强？</strong></h2>\\n<p><strong>主持人</strong>：你觉得现在的 AI 在“心理理论”这件事上做得怎么样？它们的边界在哪里？</p>\\n<p><strong>Marc Andreessen</strong>：总体来说，我觉得它们已经相当强了。我个人很喜欢让语言模型去生成“人物角色”，再让这些角色展开一种苏格拉底式对话。现在任何先进的大模型都能把这件事做得不错。不过它们有个特别烦人的毛病：它们总想让所有人都开心，最后都达成一致。一开始讨论可能还有点意思，但很快就会变成一种“大家互相理解、圆满收场”的剧情，我特别讨厌这个。所以我会故意给它下指令：把对话写得更紧张一点，更有怒气一点，让人物之间的冲突一路升级；再加一点脏话，让他们彻底撕破脸，进入那种“我要摧毁你名誉”的状态。这样它就会变得非常有意思。再后来我还会玩过头，比如说“其实他们全都是秘密忍者”，于是爱因斯坦就拿着双节棍去打玻尔——模型居然也能顺着往下编。所以你自己也得克制一点。</p>\\n<p>但这恰恰说明，它在“模拟不同人的思维状态”上已经很强了。再举个例子：英国有一家做政治相关业务的创业公司发现，现在最先进的语言模型已经好到可以在模型内部，较准确地复现一个真实选民焦点小组。现实中的焦点小组很贵，要招募人、筛人、组织现场，还很花时间。但模型现在已经能模拟出不同背景的人，比如来自肯塔基州的大学生、田纳西州的家庭主妇等等，并让这些角色在模型内部展开讨论，而且结果与真实焦点小组相当接近。所以至少在这个门槛上，它已经跨过去了。接下来能走多远，还要继续看。</p>\\n<h2><strong>八、AI 是不是泡沫？基本面与市场情绪</strong></h2>\\n<p><strong>主持人</strong>：前面几位嘉宾提到，AI 正在建设极其庞大的物理基础设施，资本开支已经达到 GDP 的 1%。我们到底该怎么理解“AI 泡沫”这个问题？</p>\\n<p><strong>Ben Horowitz</strong>：在我看来，只要大家还在问“这是不是泡沫”，那它大概率就还不是泡沫。</p>\\n<p>因为泡沫本质上首先是一种心理现象。真正的泡沫，往往发生在所有人都已经彻底相信“这绝对不是泡沫”的时候。市场术语里，这叫“投降”——原先做空的人被持续上涨逼得受不了，只能认输，转身去做多。 互联网泡沫时期就有类似现象。那时候连巴菲特都开始投资科技股了，而他原本一直说自己不投科技，因为看不懂。</p>\\n<p>如果连他都“投降”了，那时市场上其实已经没人再说那是泡沫了。 但回头看，互联网本身显然不是泡沫，它是真东西。真正的问题是：当时市场价格在短期内跑得太快，远远领先于实际用户规模和市场成熟度。可 AI 跟那时又不一样。今天 AI 最大的问题不是需求不足，而是需求太强。现在没有需求问题，我也很难相信五年后会出现需求问题。当然，未来可能会出现一些奇怪的瓶颈，比如散热不够、供电不够之类。但如果你现在看供需关系、增长与估值的匹配情况，我觉得它一点都不像泡沫。</p>\\n<p><strong>Marc Andreessen</strong>：说到底，没人真正知道答案。你去问对冲基金、银行、CEO，很多人其实都不知道。VC 也常常不知道，只是有些人会因为自己错过机会、看到估值越来越高而情绪失控，特别希望这最终被证明是个泡沫。</p>\\n<p><strong>Ben Horowitz</strong>：在我们这个行业里，最让人难受的事情之一，就是你错过了一个项目，结果它后来成了大成功。你可能会因此气 30 年。于是你就会不断找理由解释：不是我判断错了，是世界疯了。</p>\\n<p><strong>Marc Andreessen</strong>：所以我会建议把讨论拉回最朴素的两个基本面问题：第一，技术到底能不能真正工作？能不能兑现它承诺的价值？第二，客户到底愿不愿意为它付钱？只要这两点都成立，整体方向通常就不会跑偏。</p>\\n<h2><strong>九、平台迁移、Google 的“珍珠港时刻”与新交互范式</strong></h2>\\n<p><strong>主持人</strong>：有人说 ChatGPT 对 Google 来说是一个“珍珠港时刻”，是巨人被惊醒的一刻。历史上每次平台切换时，到底是什么决定了老巨头能不能赢下下一波，而不是被新玩家取代？</p>\\n<p><strong>Ben Horowitz</strong>：对变化做出反应当然重要，但这并不代表巨头就一定能赢。Google 确实被惊醒了，用不那么客气的话说，就是它终于“把脑袋从屁股里拔出来了”。所以它不会被轻易彻底碾压，但与此同时，我也不认为 OpenAI 会消失。Google 的确给了对手机会。说到底，比的是长期执行力。很多超级大公司在不同程度上都失去了持续执行的能力。历史上，新平台往往是新公司赢下来。微软当年错过了搜索，后来又错过了移动计算；它依然很强，但确实错过了那两个关键时代。所以通常是：新公司赢下新市场，老垄断则依靠旧时代积累继续存在很久。</p>\\n<p><strong>Marc Andreessen</strong>：而且我觉得大家现在还有一个很容易犯的错误，就是默认未来的主流产品形态，只会是“搜索引擎”或者“聊天机器人”��选一。这是一种过于简化的看法。</p>\\n<p>这种想法背后的叙事通常是：Google 面临的经典难题是自我颠覆——要不要把“10 条蓝色链接”的模式，替换成 AI 回答，从而可能冲击自己的广告模式；OpenAI 的问题则是，它有完整的聊天产品，但还没有 Google 那样的广告体系和分发能力。听上去很像《创新者的窘境》教科书里那种“新旧势力正面对决”的模型。但这种看法默认了一个前提：5 年、10 年、15 年、20 年后，人们主要使用的产品形态，还是“搜索”或“聊天”。</p>\\n<p>而我认为，这个前提本身就很可能是错的。回到个人电脑历史就知道了：1975 年到 1992 年，个人电脑基本就是文本命令系统。而在当时，交互式命令行本身已经比打孔卡和时分系统先进很多了。但 17 年后，整个行业突然转向 GUI；又过 5 年，行业再转向浏览器。也就是说，用户体验的形态、产品进入生活的方式，直到很后面才真正定型。所以，我相信 20 年后依然会有聊天机器人，但我同样相信，当前的聊天产品公司和未来的新公司，一定会发明出很多今天我们还根本没见过的 AI 产品形态。而这正是科技行业最有意思的地方：产品的最终形态并不预先写好，发明空间仍然极大。</p>\\n<h2><strong>十、给创业者的建议：这是一个真正不同的时代</strong></h2>\\n<p><strong>主持人</strong>：如果你们要给今天的创业者一些建议，这个时代和过去最大的不同在哪里？无论是人才争夺，还是公司组织方式，还有哪些是创业者应该特别留意的？</p>\\n<p><strong>Ben Horowitz</strong>：我觉得你刚才其实已经说中了重点：这是一个真正独特的时代。所以，如果你过度试图从上一个时代照搬组织设计经验、管理经验，反而可能会被误导。今天公司被搭建起来的方式，和过去已经非常不同了。 比如 AI 研究型 PhD 和传统的全栈工程师，完全不是同一种人才画像。所以很多问题必须回到第一性原理重新思考，而不能靠历史模板套答案。</p>\\n<p><strong>Marc Andreessen</strong>：我还想补充一点：接下来变化一定会继续发生。我前面说过，产品形态会变；与此同时，今天大家最头疼的资源短缺，未来很可能会反过来变成过剩。</p>\\n<h2><strong>十一、人才、芯片，以及“短缺终将导向过剩”的周期</strong></h2>\\n<p><strong>Marc Andreessen</strong>：在供需世界里，一个很有意思的规律是：严重短缺本身，往往会孕育未来的过剩。因为当某样东西太稀缺、利润太高时，市场就会释放出巨大的激励，逼着人们去想办法增加供给。 现在的 AI 公司，一方面非常缺顶级研究员和工程师；另一方面又在缺芯片、数据中心、电力等基础设施。我不想断言具体时间点，但我相信总有一天，这两类短缺都会缓解，甚至转向过剩。</p>\\n<p>尤其在人才这一边，一个很值得注意的现象是：中国现在已经冒出了很多非常出色的模型，而且不止一家。比如 DeepSeek、Qwen（通义千问）、Kimi。更有意思的是，做出这些东西的团队，很多并不是那种“论文圈最有名、名字总挂在顶刊上的明星团队”。这说明中国正在成功摸索出一套方法：把年轻人快速训练出来，让他们真正进入这个领域、做出成果。</p>\\n<p><strong>Ben Horowitz</strong>：xAI 在某种程度上也是如此。</p>\\n<p><strong>Marc Andreessen</strong>：对。所以我觉得，虽然顶级 AI 研发能力在一段时间内仍会是极其稀缺、极其昂贵的技能，但知识扩散已经开始发生了。大学生在学，更多人在会做，AI 也会进一步帮助人类构建 AI。也许不会真的出现“人才过剩”，但至少未来懂得如何构建这些系统的人，一定会比今天多得多。</p>\\n<p>再看芯片这一边。我不是芯片专家，但如果回顾整个芯片产业历史，你会发现一个规律：每一次短缺，最后几乎都会走向过剩。因为短缺时利润太高，利润池太大，外部竞争者进入并把这个功能“商品化”的动力就会极强。NVIDIA 今天在芯片行业的位置，可能已经好到了史无前例的程度。但即便如此，我还是很难相信，5 年后基础设施会维持今天这种极端紧张的状态。哪怕瓶颈从芯片转移到了电力、散热或别的地方，芯片本身也很可能会出现供给宽松。</p>\\n<p>所以我只想说一句：五年后，我们今天面对的问题大概率都还会在，但形式会完全变掉。这个行业变化极快，绝不能用静态视角看它。</p>\\n<h2><strong>十二、中美 AI 竞赛与机器人时代</strong></h2>\\n<p><strong>主持人</strong>：上个月我们在华盛顿时，参议员们很关心一个问题：到底该怎么看中美 AI 竞赛的现状？你愿意把当时对他们说的核心观点再讲一遍吗？</p>\\n<p><strong>Marc Andreessen</strong>：我的基本判断是：到目前为止，重大的概念性创新，主要还是来自美国，更广一点说是来自西方，而其中又越来越集中在美国。但中国在另一件事上极其擅长：迅速吸收想法、把它做出来、放大规模、压低成本、实现商品化。他们在制造业里一直就是这么干的，现在在 AI 里也正在很成功地这么做。</p>\\n<p>所以我会说，中国现在是在把“追赶战”打得非常好。当然，关于追赶速度为何如此之快，外界有各种猜测和讨论，但不管怎么说，结果摆在那里——他们确实做得非常出色。而且中国当然也不满足于只做追赶者。中国有很多非常聪明、非常有创造力的人。接下来真正值得观察的是：未来那些“概念级的突破”，会不会也开始越来越多地出现在中国，甚至让他们反超。</p>\\n<p>所以我们在华盛顿对政策制定者说的是：这已经是一场真正的竞赛，是短跑，是寸土必争。美国不会拥有 5 年领先优势，可能最多也就 6 个月。我们必须跑得很快，必须赢。而且我们不能给美国公司套上中国政府并没有强加给中国公司的那些额外枷锁，否则我们就会输。如果有一天你早上醒来，发现这个世界在很大程度上是由中国 AI 所主导和塑造的，多数美国人显然不希望看到那样的局面。不过就目前而言，我对美国在软件层面的优势仍然算是谨慎乐观。</p>\\n<p>但一旦 AI 进入具身智能/机器人阶段，问题就会变得更棘手。因为过去 40 年里，美国和西方整体上选择了去工业化，而中国则建立起了一个庞大的工业生态系统，覆盖机械、电气、半导体、软件以及各种终端制造：手机、无人机、汽车，未来还包括机器人。AI 革命一定会有第二阶段，那就是机器人，而且我觉得这个阶段会来得很快。到那时，哪怕美国在软件上依然领先，机器人终究还是得被“造出来”。</p>\\n<p>而“把机器人造出来”不是一家公司单打独斗能完成的，它需要的是一个完整的供应链生态。汽车工业不是几家车企而已，而是成千上万的零部件供应商共同构成的体系。飞机、电脑也一样，机器人未来也会一样。 而按今天的默认格局看，这套体系很可能会主要发生在中国。所以哪怕中国在软件上没有完全追平美国，也有可能在硬件和制造端反超并绕过去。好消息是，美国 政治光谱两端现在都越来越意识到：去工业化走得太远了，必须想办法往回拉。我对此持谨慎乐观态度，但要做的事情还非常多。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/i4WecVP5x7JgvVzcpfDo0Q\\\">“硅星GenAI”</a>，作者：大模型机动组，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'a16z创始人深度对谈：AI没有泡沫，但中美真正的对决在机器人\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'a16z创始人深度对谈：AI没有泡沫，但中美真正的对决在机器人\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768674338079492?f=rss\'}], \'link\': \'https://36kr.com/p/3768674338079492?f=rss\', \'published\': \'2026-04-16 10:09:44  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=9, tm_sec=44, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>在a16z Runtime大会的闭幕主题演讲中，a16z公司的联合创始人Marc Andreessen、Ben Horowitz与普通合伙人Erik Torenberg（主持人）探讨了本次大会的亮点、大语言模型的能力现状，以及尽管资本支出巨大，人工智能为何并非泡沫。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_16bf13beb4b24d8c996ffc41a1276f95@5091053_oswg200323oswg750oswg423_img_png?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p>本文编译自 a16z Runtime 大会官方视频，原始链接：https://www.youtube.com/watch?v=Y7dwbJ0AtUA</p>\\\\n  <p><strong>Marc Andreessen</strong>：我认为，我们现在其实还不知道“最终形态”的 AI 产品到底会长成什么样。历史上一个很明显的类比是：个人电脑从 1975 年诞生开始，到差不多 1992 年之前，本质上一直都是文本命令行系统。17 年之后，整个行业突然转向了 GUI 图形界面，从此再也没有回头。又过了大约 5 年，行业又突然转向了网页浏览器，同样再也没有回头。所以，我当然相信 20 年后依然会有聊天机器人存在，但我也非常确定，无论是现在的聊天机器人公司，还是未来新出现的公司，都会摸索出很多与今天截然不同的交互方式，而那些形态是我们现在甚至都还没想明白的。</p>\\\\n  <h2><strong>一、AI 真的能创造吗？智能与发明的边界</strong></h2>\\\\n  <p><strong>主持人</strong>：最近很多人都在谈大语言模型的局限，它们不能真正发明新科学，不能实现真正的创造性天才，最多只是把已有内容重新组合、重新包装。你怎么看？</p>\\\\n  <p><strong>Marc Andreessen</strong>：对我来说，这类问题通常分成两种。第一种是：语言模型到底算不算“智能”？也就是说，它能不能像人一样真正处理信息，并实现某种概念上的突破？；第二种是：语言模型或者视频模型，到底算不算“有创造力”？它们能不能创作出真正新的艺术，产生真正的创造性突破？</p>\\\\n  <p>而我对这两个问题的回答，都是同一个反问：人类自己真的能做到吗？因为这里面其实有两个层次。第一，就算有些人确实算得上“聪明”，能提出原创性的概念突破，而不是简单复述训练材料或按既有脚本行事——这样的人在人群中到底占多大比例？坦率地说，我这辈子真正见过这样的人也没几个，今天这个房间里就有几位，但总数非常少。绝大多数人，一生都不会有那种真正意义上的原创性突破。创造力也是一样。你会指着贝多芬、梵高这样的人说：“这才叫创造力。”没错，这当然是创造力。但问题是，世界上有几个贝多芬、几个梵高？ 显然极少。所以，如果 AI 能够超过人类 99.99% 的水平，本身就已经很惊人了。</p>\\\\n  <h2><strong>二、重组、原创以及人类创造力的本质</strong></h2>\\\\n  <p><strong>Marc Andreessen</strong>：再往深里看，你会发现一个问题：在人类历史上，真正的概念性突破到底有多少？和“把已有想法重新混搭、重组”相比，哪一个才是主流？如果你回头看技术史，你会发现大多数重大突破，往往都建立在此前至少 40 年 的积累之上。事实上，今天的语言模型本身，也是此前 80 年研究积累 的结果。</p>\\\\n  <p>艺术领域也是同样的道理。小说、音乐、绘画，当然会有真正飞跃性的创造，但其中同样包含了大量来自前人的影响。即使是像贝多芬这样的大师，他的作品里也能看到莫扎特、海顿以及更早作曲家的痕迹。所以，所谓“原创”和“混搭”的界线，很多时候并没有想象中那么清楚。</p>\\\\n  <p>说到底，这有点像“针尖上能站几个天使”那样的哲学问题：如果一个系统已经能逼近那种世界级、跨时代的创造力和智能，哪怕只差极小一点点，那么在现实意义上，它可能就已经“差不多到了”。情感上，我当然也希望人类创造力依然保有某种独特、不可替代的东西。我也确实愿意相信这一点。但说实话，每次我用这些模型的时候，我都会觉得：它们真的已经非常聪明，也非常有创造力了。所以我相当相信，它们最终会跨过那道门槛。</p>\\\\n  <p><strong>主持人</strong>：我感觉这好像是你一贯的分析框架。别人一谈 LLM 的局限，比如它们能不能迁移学习、能不能举一反三，你的第一反应总是：人类自己能做到吗？</p>\\\\n  <p><strong>Marc Andreessen</strong>：对，就是这样。比如“横向思维”、比如“分布外推理”。很多人擅长在熟悉范围内推理，但真正能在陌生领域里迁移知识、跨域思考的人，其实非常少。我认识的这类人，坐在今天这个会场里，我大概也就能数出 3 个。而我的通讯录里大约有 1 万人。也就是说，真正稳定具备这种能力的人，大概只有万分之几。 这反而让我觉得很振奋。因为你看，人类明明有这么多局限，但我们还是创造出了惊人的艺术、电影、小说、技术发明和科学突破。所以，哪怕 AI 还没到让你 100% 确信“它正在进行真正原创思考”的地步，也不妨碍它带来巨大的进步。</p>\\\\n  <h2><strong>三、Ben Horowitz 谈嘻哈、创新与天才</strong></h2>\\\\n  <p><strong>主持人</strong>：Ben，你上周刚办完 Paid in Full Foundation 的活动，致敬了一批嘻哈传奇人物。你对“创造性天才”这个话题一定想得很多。你怎么看？</p>\\\\n  <p><strong>Ben Horowitz</strong>：我基本同意Marc的看法。不管你最后把它定义成什么，AI 已经非常有用了。就算它还没有完全达到“顶级天才创造力”的层级，它也已经很强。不过，在艺术领域，尤其是当下这一代技术，还是有一个地方没完全到位：人类特别在乎那种实时发生的、切身的生命体验。而当前模型的预训练数据，还不足以真正捕捉这种东西。但即便如此，它已经做得相当不错了。</p>\\\\n  <p><strong>Marc Andreessen</strong>：Ben 有一个非营利项目叫 Paid in Full Foundation，它会表彰并为嘻哈/说唱领域的重要创新者提供某种“养老金式”的支持。如果把过去 50 年整个嘻哈领域都算上，你觉得真正称得上“概念性创新者”的人有多少？</p>\\\\n  <p><strong>Ben Horowitz</strong>：这得看你把定义放得多宽。如果说得宽一点，上周六现场就有好几位：Rakim、Dr. Dre、George Clinton，这些人都可以算。如果定义再窄一些，比如 Cool G Rap 也确实提出过新的东西。但如果你要说那种最根本、最底层的音乐性突破，那我大概会把范围缩到 Rakim 和 George Clinton。总之，比例极低，非常低。</p>\\\\n  <p><strong>主持人</strong>：昨天 Jared Leto 也提到，好莱坞很多人对 AI 很害怕、很反感。那你和这些音乐人聊天时，比如 Dr. Dre、Nas、Kanye 这些人，他们是兴奋、排斥，还是已经在用？</p>\\\\n  <p><strong>Ben Horowitz</strong>：确实有不少音乐人害怕 AI，但也有很多人对它非常感兴趣。尤其是嘻哈圈的人，会更容易理解它。因为从某种意义上说，这几乎就是他们当年做的事情：把已有音乐拿来，重新拼接、重构，做成新东西。所以对他们来说，AI 是一个非常强大的创作工具，它极大拓展了创作的调色板。而且嘻哈很多时候讲的是一个非常具体的时间、地点和个人经验。如果你的模型对这个特定文化、特定语境“懂得很深”，那反而比一个泛化能力很强但不够贴身的音乐模型更有优势。</p>\\\\n  <h2><strong>四、智能、权力与谁在主导世界</strong></h2>\\\\n  <p><strong>主持人</strong>：很多人会用同一种逻辑来推演 AI：更聪明的东西最终会统治不那么聪明的东西。Marc，你最近发过一条很有名的话：“顶级的图形推理者，只会做图形推理；但顶级的‘文字型人才’，却能调度那些图形推理者。”你还说过一句：“高 IQ 的专家，往往是在给中等 IQ 的通才打工。”这是什么意思？</p>\\\\n  <p><strong>Marc Andreessen</strong>：意思其实很简单：博士通常给 MBA 打工。你把问题放大一点看：当你观察今天这个世界，你真的会得出“最聪明的人在统治世界”这个结论吗？放眼全球现实，你会觉得“我们把天才都放在最关键的位置上了”吗？显然不是。</p>\\\\n  <p>这里有两件事同时成立。第一，我们整体上可能低估了智力的重要性。第二，那些特别强调智力的人，又往往会高估智力的重要性。社会科学通常会告诉你，流体智力、g 因子、IQ 之类的指标，和很多正向人生结果都有相关性，比如教育结果、职业成就、收入、生活满意度，甚至包括更少诉诸暴力地解决问题。这些相关性很重要，但它依然不是全部。所以，你不能把“智力重要”直接推导成“智力是唯一决定因素”或者“智力是最重要的唯一变量”。现实显然不是这样。</p>\\\\n  <p>哪怕你是一个极端的 IQ 决定论者，你也不得不承认：很多结果并不能只靠 IQ 来解释。再往上看群体层面，事情就更复杂了。任何一群人，一旦变成“群体”甚至“乌合之众”，集体智商通常都会下降。你把一群聪明人放进一个群体，他们往往也会变笨。所以，不管是公司、组织还是国家，谁来掌权，从来都不只是 IQ 决定的，甚至可能根本不是主要由 IQ 决定的。 因此，AI 圈里有一种常见假设：更聪明的存在必然会统治更笨的存在。我觉得这种说法非常容易被现实反驳。因为智能不是充分条件。</p>\\\\n  <h2><strong>五、超越 IQ：领导力、情绪与“心理理论”</strong></h2>\\\\n  <p><strong>主持人</strong>：那除了智力之外，哪些能力更决定一个人能否成功领导、创业、解决复杂问题、组织团队？以及为什么 AI 不能同样学会这些能力？</p>\\\\n  <p><strong>Ben Horowitz</strong>：有很多东西都重要。比如，你能不能以正确的方式跟人发生冲突。这里面当然有一点智力成分，但更多时候，关键在于你是不是真的理解你正在跟谁打交道。你要能读懂对方怎么想，能从公司员工的视角看问题，而不是只从你自己的视角看。这种能力来自于长期和人沟通、倾听、理解，而不是 IQ 测出来的。而且管理还有一个关键点：你不是为了让大家做“最受欢迎的事”，而是要让大家去做“正确的事”，哪怕他们并不喜欢。这就是大量管理工作的本质。</p>\\\\n  <p><strong>Marc Andreessen</strong>：所以这里面涉及勇气、动机、情绪理解，以及所谓的 theory of mind（心理理论）。</p>\\\\n  <p><strong>Ben Horowitz</strong>：对。你得知道别人想要什么，同时又不能只迎合，而是要把这和“组织真正需要做什么”结合起来。还要判断：团队里谁能力强，谁是不能失去的人，谁情绪崩了影响不大，谁一出问题整个团队就会出事。这些东西充满了微妙的情境判断，很难抽象成几条通用公式。这也是为什么很多管理书都很糟糕。因为管理高度依赖具体情境：你的公司、你的产品、你的人、你的组织结构，都和别人完全不同。所以那种“建立战略的五个步骤”式的书，很多时候根本没什么用。</p>\\\\n  <p><strong>Marc Andreessen</strong>：心理理论非常关键。简单说，就是：你能不能在自己脑子里，准确模拟出别人脑子里在发生什么。直觉上你会以为，越聪明的人越擅长这个；但事实可能并非如此。美国军方是美国社会最早、也是最系统使用 IQ 测试的机构之一。他们通过 ASVAB 之类测试把人分配到不同岗位，甚至领导岗位。而他们长期观察发现：如果一个领导者的智力水平和他带领的人群相差超过一个标准差，就很容易出问题。低于团队太多当然不行；但反过来，高出太多也不行。如果一个领导者的智力比组织平均水平高出两个标准差，他往往也会失去对他人的“心理建模能力”。也就是说，特别聪明的人，反而可能很难真正理解普通聪明人的思维过程。</p>\\\\n  <p>所以，领导者和被领导者之间需要某种“可连接性”，这不是单靠智力就能解决的。由此类推，如果未来真的出现一个 IQ 高得离谱的人，或者机器，比如“1000 IQ”的存在，它对现实的理解方式可能会异化到一个程度，以至于它根本无法和它所管理的人建立真实连接。这也是为什么我认为，未来很长时间里，这个世界都不会单纯按 IQ 来组织。</p>\\\\n  <p><strong>Ben Horowitz</strong>：扎克伯格有句话说得很好：“智能不是生命本身。”生命有很多维度，而这些维度并不依赖智力。有些人太聪明了，反而会过度理性化，默认别人也会那么理性，于是把很多事情都想偏了。</p>\\\\n  <h2><strong>六、具身智能：心智与身体的问题</strong></h2>\\\\n  <p><strong>Marc Andreessen</strong>：我还怀疑，这个问题最终会越来越走向生物学。现在越来越多研究表明，人类的认知、自我意识、信息处理、决策和主观体验，并不只是大脑在工作。传统的“心身二元论”——把心智和身体完全分开——很可能本来就是错的。 人的存在体验是一个全身性的过程。神经系统当然重要，但肠道菌群、嗅觉、激素、各种生化过程，都会影响人的认知和判断。如果顺着这条研究线继续往前走，我猜我们最后会发现：人类认知比大家原先以为的，更像是一种“全身参与”的体验。</p>\\\\n  <p>而这恰恰是今天 AI 领域面临的一个基础性问题。当前真正运转起来的 AI，本质上还是一种“彻底心身分离”的形式——它像一个脱离身体的大脑。但机器人革命迟早会来。当 AI 被装进能在物理世界里移动、感知、行动的实体里，它才可能更接近那种真正“智力—身体一体化”的经验结构。机器人会带来更多传感器、更多现实世界数据，也许会让系统更接近那种完整的智能。 但至少从现在的研究来看，这个方向还很早，我们还有很多工作要做。</p>\\\\n  <h2><strong>七、今天的 AI 在“读人心”方面到底有多强？</strong></h2>\\\\n  <p><strong>主持人</strong>：你觉得现在的 AI 在“心理理论”这件事上做得怎么样？它们的边界在哪里？</p>\\\\n  <p><strong>Marc Andreessen</strong>：总体来说，我觉得它们已经相当强了。我个人很喜欢让语言模型去生成“人物角色”，再让这些角色展开一种苏格拉底式对话。现在任何先进的大模型都能把这件事做得不错。不过它们有个特别烦人的毛病：它们总想让所有人都开心，最后都达成一致。一开始讨论可能还有点意思，但很快就会变成一种“大家互相理解、圆满收场”的剧情，我特别讨厌这个。所以我会故意给它下指令：把对话写得更紧张一点，更有怒气一点，让人物之间的冲突一路升级；再加一点脏话，让他们彻底撕破脸，进入那种“我要摧毁你名誉”的状态。这样它就会变得非常有意思。再后来我还会玩过头，比如说“其实他们全都是秘密忍者”，于是爱因斯坦就拿着双节棍去打玻尔——模型居然也能顺着往下编。所以你自己也得克制一点。</p>\\\\n  <p>但这恰恰说明，它在“模拟不同人的思维状态”上已经很强了。再举个例子：英国有一家做政治相关业务的创业公司发现，现在最先进的语言模型已经好到可以在模型内部，较准确地复现一个真实选民焦点小组。现实中的焦点小组很贵，要招募人、筛人、组织现场，还很花时间。但模型现在已经能模拟出不同背景的人，比如来自肯塔基州的大学生、田纳西州的家庭主妇等等，并让这些角色在模型内部展开讨论，而且结果与真实焦点小组相当接近。所以至少在这个门槛上，它已经跨过去了。接下来能走多远，还要继续看。</p>\\\\n  <h2><strong>八、AI 是不是泡沫？基本面与市场情绪</strong></h2>\\\\n  <p><strong>主持人</strong>：前面几位嘉宾提到，AI 正在建设极其庞大的物理基础设施，资本开支已经达到 GDP 的 1%。我们到底该怎么理解“AI 泡沫”这个问题？</p>\\\\n  <p><strong>Ben Horowitz</strong>：在我看来，只要大家还在问“这是不是泡沫”，那它大概率就还不是泡沫。</p>\\\\n  <p>因为泡沫本质上首先是一种心理现象。真正的泡沫，往往发生在所有人都已经彻底相信“这绝对不是泡沫”的时候。市场术语里，这叫“投降”——原先做空的人被持续上涨逼得受不了，只能认输，转身去做多。 互联网泡沫时期就有类似现象。那时候连巴菲特都开始投资科技股了，而他原本一直说自己不投科技，因为看不懂。</p>\\\\n  <p>如果连他都“投降”了，那时市场上其实已经没人再说那是泡沫了。 但回头看，互联网本身显然不是泡沫，它是真东西。真正的问题是：当时市场价格在短期内跑得太快，远远领先于实际用户规模和市场成熟度。可 AI 跟那时又不一样。今天 AI 最大的问题不是需求不足，而是需求太强。现在没有需求问题，我也很难相信五年后会出现需求问题。当然，未来可能会出现一些奇怪的瓶颈，比如散热不够、供电不够之类。但如果你现在看供需关系、增长与估值的匹配情况，我觉得它一点都不像泡沫。</p>\\\\n  <p><strong>Marc Andreessen</strong>：说到底，没人真正知道答案。你去问对冲基金、银行、CEO，很多人其实都不知道。VC 也常常不知道，只是有些人会因为自己错过机会、看到估值越来越高而情绪失控，特别希望这最终被证明是个泡沫。</p>\\\\n  <p><strong>Ben Horowitz</strong>：在我们这个行业里，最让人难受的事情之一，就是你错过了一个项目，结果它后来成了大成功。你可能会因此气 30 年。于是你就会不断找理由解释：不是我判断错了，是世界疯了。</p>\\\\n  <p><strong>Marc Andreessen</strong>：所以我会建议把讨论拉回最朴素的两个基本面问题：第一，技术到底能不能真正工作？能不能兑现它承诺的价值？第二，客户到底愿不愿意为它付钱？只要这两点都成立，整体方向通常就不会跑偏。</p>\\\\n  <h2><strong>九、平台迁移、Google 的“珍珠港时刻”与新交互范式</strong></h2>\\\\n  <p><strong>主持人</strong>：有人说 ChatGPT 对 Google 来说是一个“珍珠港时刻”，是巨人被惊醒的一刻。历史上每次平台切换时，到底是什么决定了老巨头能不能赢下下一波，而不是被新玩家取代？</p>\\\\n  <p><strong>Ben Horowitz</strong>：对变化做出反应当然重要，但这并不代表巨头就一定能赢。Google 确实被惊醒了，用不那么客气的话说，就是它终于“把脑袋从屁股里拔出来了”。所以它不会被轻易彻底碾压，但与此同时，我也不认为 OpenAI 会消失。Google 的确给了对手机会。说到底，比的是长期执行力。很多超级大公司在不同程度上都失去了持续执行的能力。历史上，新平台往往是新公司赢下来。微软当年错过了搜索，后来又错过了移动计算；它依然很强，但确实错过了那两个关键时代。所以通常是：新公司赢下新市场，老垄断则依靠旧时代积累继续存在很久。</p>\\\\n  <p><strong>Marc Andreessen</strong>：而且我觉得大家现在还有一个很容易犯的错误，就是默认未来的主流产品形态，只会是“搜索引擎”或者“聊天机器人”��选一。这是一种过于简化的看法。</p>\\\\n  <p>这种想法背后的叙事通常是：Google 面临的经典难题是自我颠覆——要不要把“10 条蓝色链接”的模式，替换成 AI 回答，从而可能冲击自己的广告模式；OpenAI 的问题则是，它有完整的聊天产品，但还没有 Google 那样的广告体系和分发能力。听上去很像《创新者的窘境》教科书里那种“新旧势力正面对决”的模型。但这种看法默认了一个前提：5 年、10 年、15 年、20 年后，人们主要使用的产品形态，还是“搜索”或“聊天”。</p>\\\\n  <p>而我认为，这个前提本身就很可能是错的。回到个人电脑历史就知道了：1975 年到 1992 年，个人电脑基本就是文本命令系统。而在当时，交互式命令行本身已经比打孔卡和时分系统先进很多了。但 17 年后，整个行业突然转向 GUI；又过 5 年，行业再转向浏览器。也就是说，用户体验的形态、产品进入生活的方式，直到很后面才真正定型。所以，我相信 20 年后依然会有聊天机器人，但我同样相信，当前的聊天产品公司和未来的新公司，一定会发明出很多今天我们还根本没见过的 AI 产品形态。而这正是科技行业最有意思的地方：产品的最终形态并不预先写好，发明空间仍然极大。</p>\\\\n  <h2><strong>十、给创业者的建议：这是一个真正不同的时代</strong></h2>\\\\n  <p><strong>主持人</strong>：如果你们要给今天的创业者一些建议，这个时代和过去最大的不同在哪里？无论是人才争夺，还是公司组织方式，还有哪些是创业者应该特别留意的？</p>\\\\n  <p><strong>Ben Horowitz</strong>：我觉得你刚才其实已经说中了重点：这是一个真正独特的时代。所以，如果你过度试图从上一个时代照搬组织设计经验、管理经验，反而可能会被误导。今天公司被搭建起来的方式，和过去已经非常不同了。 比如 AI 研究型 PhD 和传统的全栈工程师，完全不是同一种人才画像。所以很多问题必须回到第一性原理重新思考，而不能靠历史模板套答案。</p>\\\\n  <p><strong>Marc Andreessen</strong>：我还想补充一点：接下来变化一定会继续发生。我前面说过，产品形态会变；与此同时，今天大家最头疼的资源短缺，未来很可能会反过来变成过剩。</p>\\\\n  <h2><strong>十一、人才、芯片，以及“短缺终将导向过剩”的周期</strong></h2>\\\\n  <p><strong>Marc Andreessen</strong>：在供需世界里，一个很有意思的规律是：严重短缺本身，往往会孕育未来的过剩。因为当某样东西太稀缺、利润太高时，市场就会释放出巨大的激励，逼着人们去想办法增加供给。 现在的 AI 公司，一方面非常缺顶级研究员和工程师；另一方面又在缺芯片、数据中心、电力等基础设施。我不想断言具体时间点，但我相信总有一天，这两类短缺都会缓解，甚至转向过剩。</p>\\\\n  <p>尤其在人才这一边，一个很值得注意的现象是：中国现在已经冒出了很多非常出色的模型，而且不止一家。比如 DeepSeek、Qwen（通义千问）、Kimi。更有意思的是，做出这些东西的团队，很多并不是那种“论文圈最有名、名字总挂在顶刊上的明星团队”。这说明中国正在成功摸索出一套方法：把年轻人快速训练出来，让他们真正进入这个领域、做出成果。</p>\\\\n  <p><strong>Ben Horowitz</strong>：xAI 在某种程度上也是如此。</p>\\\\n  <p><strong>Marc Andreessen</strong>：对。所以我觉得，虽然顶级 AI 研发能力在一段时间内仍会是极其稀缺、极其昂贵的技能，但知识扩散已经开始发生了。大学生在学，更多人在会做，AI 也会进一步帮助人类构建 AI。也许不会真的出现“人才过剩”，但至少未来懂得如何构建这些系统的人，一定会比今天多得多。</p>\\\\n  <p>再看芯片这一边。我不是芯片专家，但如果回顾整个芯片产业历史，你会发现一个规律：每一次短缺，最后几乎都会走向过剩。因为短缺时利润太高，利润池太大，外部竞争者进入并把这个功能“商品化”的动力就会极强。NVIDIA 今天在芯片行业的位置，可能已经好到了史无前例的程度。但即便如此，我还是很难相信，5 年后基础设施会维持今天这种极端紧张的状态。哪怕瓶颈从芯片转移到了电力、散热或别的地方，芯片本身也很可能会出现供给宽松。</p>\\\\n  <p>所以我只想说一句：五年后，我们今天面对的问题大概率都还会在，但形式会完全变掉。这个行业变化极快，绝不能用静态视角看它。</p>\\\\n  <h2><strong>十二、中美 AI 竞赛与机器人时代</strong></h2>\\\\n  <p><strong>主持人</strong>：上个月我们在华盛顿时，参议员们很关心一个问题：到底该怎么看中美 AI 竞赛的现状？你愿意把当时对他们说的核心观点再讲一遍吗？</p>\\\\n  <p><strong>Marc Andreessen</strong>：我的基本判断是：到目前为止，重大的概念性创新，主要还是来自美国，更广一点说是来自西方，而其中又越来越集中在美国。但中国在另一件事上极其擅长：迅速吸收想法、把它做出来、放大规模、压低成本、实现商品化。他们在制造业里一直就是这么干的，现在在 AI 里也正在很成功地这么做。</p>\\\\n  <p>所以我会说，中国现在是在把“追赶战”打得非常好。当然，关于追赶速度为何如此之快，外界有各种猜测和讨论，但不管怎么说，结果摆在那里——他们确实做得非常出色。而且中国当然也不满足于只做追赶者。中国有很多非常聪明、非常有创造力的人。接下来真正值得观察的是：未来那些“概念级的突破”，会不会也开始越来越多地出现在中国，甚至让他们反超。</p>\\\\n  <p>所以我们在华盛顿对政策制定者说的是：这已经是一场真正的竞赛，是短跑，是寸土必争。美国不会拥有 5 年领先优势，可能最多也就 6 个月。我们必须跑得很快，必须赢。而且我们不能给美国公司套上中国政府并没有强加给中国公司的那些额外枷锁，否则我们就会输。如果有一天你早上醒来，发现这个世界在很大程度上是由中国 AI 所主导和塑造的，多数美国人显然不希望看到那样的局面。不过就目前而言，我对美国在软件层面的优势仍然算是谨慎乐观。</p>\\\\n  <p>但一旦 AI 进入具身智能/机器人阶段，问题就会变得更棘手。因为过去 40 年里，美国和西方整体上选择了去工业化，而中国则建立起了一个庞大的工业生态系统，覆盖机械、电气、半导体、软件以及各种终端制造：手机、无人机、汽车，未来还包括机器人。AI 革命一定会有第二阶段，那就是机器人，而且我觉得这个阶段会来得很快。到那时，哪怕美国在软件上依然领先，机器人终究还是得被“造出来”。</p>\\\\n  <p>而“把机器人造出来”不是一家公司单打独斗能完成的，它需要的是一个完整的供应链生态。汽车工业不是几家车企而已，而是成千上万的零部件供应商共同构成的体系。飞机、电脑也一样，机器人未来也会一样。 而按今天的默认格局看，这套体系很可能会主要发生在中国。所以哪怕中国在软件上没有完全追平美国，也有可能在硬件和制造端反超并绕过去。好消息是，美国 政治光谱两端现在都越来越意识到：去工业化走得太远了，必须想办法往回拉。我对此持谨慎乐观态度，但要做的事情还非常多。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/i4WecVP5x7JgvVzcpfDo0Q\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“硅星GenAI”</a>，作者：大模型机动组，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>在a16z Runtime大会的闭幕主题演讲中，a16z公司的联合创始人Marc Andreessen、Ben Horowitz与普通合伙人Erik Torenberg（主持人）探讨了本次大会的亮点、大语言模型的能力现状，以及尽管资本支出巨大，人工智能为何并非泡沫。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_16bf13beb4b24d8c996ffc41a1276f95@5091053_oswg200323oswg750oswg423_img_png?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p>本文编译自 a16z Runtime 大会官方视频，原始链接：https://www.youtube.com/watch?v=Y7dwbJ0AtUA</p>\\\\n  <p><strong>Marc Andreessen</strong>：我认为，我们现在其实还不知道“最终形态”的 AI 产品到底会长成什么样。历史上一个很明显的类比是：个人电脑从 1975 年诞生开始，到差不多 1992 年之前，本质上一直都是文本命令行系统。17 年之后，整个行业突然转向了 GUI 图形界面，从此再也没有回头。又过了大约 5 年，行业又突然转向了网页浏览器，同样再也没有回头。所以，我当然相信 20 年后依然会有聊天机器人存在，但我也非常确定，无论是现在的聊天机器人公司，还是未来新出现的公司，都会摸索出很多与今天截然不同的交互方式，而那些形态是我们现在甚至都还没想明白的。</p>\\\\n  <h2><strong>一、AI 真的能创造吗？智能与发明的边界</strong></h2>\\\\n  <p><strong>主持人</strong>：最近很多人都在谈大语言模型的局限，它们不能真正发明新科学，不能实现真正的创造性天才，最多只是把已有内容重新组合、重新包装。你怎么看？</p>\\\\n  <p><strong>Marc Andreessen</strong>：对我来说，这类问题通常分成两种。第一种是：语言模型到底算不算“智能”？也就是说，它能不能像人一样真正处理信息，并实现某种概念上的突破？；第二种是：语言模型或者视频模型，到底算不算“有创造力”？它们能不能创作出真正新的艺术，产生真正的创造性突破？</p>\\\\n  <p>而我对这两个问题的回答，都是同一个反问：人类自己真的能做到吗？因为这里面其实有两个层次。第一，就算有些人确实算得上“聪明”，能提出原创性的概念突破，而不是简单复述训练材料或按既有脚本行事——这样的人在人群中到底占多大比例？坦率地说，我这辈子真正见过这样的人也没几个，今天这个房间里就有几位，但总数非常少。绝大多数人，一生都不会有那种真正意义上的原创性突破。创造力也是一样。你会指着贝多芬、梵高这样的人说：“这才叫创造力。”没错，这当然是创造力。但问题是，世界上有几个贝多芬、几个梵高？ 显然极少。所以，如果 AI 能够超过人类 99.99% 的水平，本身就已经很惊人了。</p>\\\\n  <h2><strong>二、重组、原创以及人类创造力的本质</strong></h2>\\\\n  <p><strong>Marc Andreessen</strong>：再往深里看，你会发现一个问题：在人类历史上，真正的概念性突破到底有多少？和“把已有想法重新混搭、重组”相比，哪一个才是主流？如果你回头看技术史，你会发现大多数重大突破，往往都建立在此前至少 40 年 的积累之上。事实上，今天的语言模型本身，也是此前 80 年研究积累 的结果。</p>\\\\n  <p>艺术领域也是同样的道理。小说、音乐、绘画，当然会有真正飞跃性的创造，但其中同样包含了大量来自前人的影响。即使是像贝多芬这样的大师，他的作品里也能看到莫扎特、海顿以及更早作曲家的痕迹。所以，所谓“原创”和“混搭”的界线，很多时候并没有想象中那么清楚。</p>\\\\n  <p>说到底，这有点像“针尖上能站几个天使”那样的哲学问题：如果一个系统已经能逼近那种世界级、跨时代的创造力和智能，哪怕只差极小一点点，那么在现实意义上，它可能就已经“差不多到了”。情感上，我当然也希望人类创造力依然保有某种独特、不可替代的东西。我也确实愿意相信这一点。但说实话，每次我用这些模型的时候，我都会觉得：它们真的已经非常聪明，也非常有创造力了。所以我相当相信，它们最终会跨过那道门槛。</p>\\\\n  <p><strong>主持人</strong>：我感觉这好像是你一贯的分析框架。别人一谈 LLM 的局限，比如它们能不能迁移学习、能不能举一反三，你的第一反应总是：人类自己能做到吗？</p>\\\\n  <p><strong>Marc Andreessen</strong>：对，就是这样。比如“横向思维”、比如“分布外推理”。很多人擅长在熟悉范围内推理，但真正能在陌生领域里迁移知识、跨域思考的人，其实非常少。我认识的这类人，坐在今天这个会场里，我大概也就能数出 3 个。而我的通讯录里大约有 1 万人。也就是说，真正稳定具备这种能力的人，大概只有万分之几。 这反而让我觉得很振奋。因为你看，人类明明有这么多局限，但我们还是创造出了惊人的艺术、电影、小说、技术发明和科学突破。所以，哪怕 AI 还没到让你 100% 确信“它正在进行真正原创思考”的地步，也不妨碍它带来巨大的进步。</p>\\\\n  <h2><strong>三、Ben Horowitz 谈嘻哈、创新与天才</strong></h2>\\\\n  <p><strong>主持人</strong>：Ben，你上周刚办完 Paid in Full Foundation 的活动，致敬了一批嘻哈传奇人物。你对“创造性天才”这个话题一定想得很多。你怎么看？</p>\\\\n  <p><strong>Ben Horowitz</strong>：我基本同意Marc的看法。不管你最后把它定义成什么，AI 已经非常有用了。就算它还没有完全达到“顶级天才创造力”的层级，它也已经很强。不过，在艺术领域，尤其是当下这一代技术，还是有一个地方没完全到位：人类特别在乎那种实时发生的、切身的生命体验。而当前模型的预训练数据，还不足以真正捕捉这种东西。但即便如此，它已经做得相当不错了。</p>\\\\n  <p><strong>Marc Andreessen</strong>：Ben 有一个非营利项目叫 Paid in Full Foundation，它会表彰并为嘻哈/说唱领域的重要创新者提供某种“养老金式”的支持。如果把过去 50 年整个嘻哈领域都算上，你觉得真正称得上“概念性创新者”的人有多少？</p>\\\\n  <p><strong>Ben Horowitz</strong>：这得看你把定义放得多宽。如果说得宽一点，上周六现场就有好几位：Rakim、Dr. Dre、George Clinton，这些人都可以算。如果定义再窄一些，比如 Cool G Rap 也确实提出过新的东西。但如果你要说那种最根本、最底层的音乐性突破，那我大概会把范围缩到 Rakim 和 George Clinton。总之，比例极低，非常低。</p>\\\\n  <p><strong>主持人</strong>：昨天 Jared Leto 也提到，好莱坞很多人对 AI 很害怕、很反感。那你和这些音乐人聊天时，比如 Dr. Dre、Nas、Kanye 这些人，他们是兴奋、排斥，还是已经在用？</p>\\\\n  <p><strong>Ben Horowitz</strong>：确实有不少音乐人害怕 AI，但也有很多人对它非常感兴趣。尤其是嘻哈圈的人，会更容易理解它。因为从某种意义上说，这几乎就是他们当年做的事情：把已有音乐拿来，重新拼接、重构，做成新东西。所以对他们来说，AI 是一个非常强大的创作工具，它极大拓展了创作的调色板。而且嘻哈很多时候讲的是一个非常具体的时间、地点和个人经验。如果你的模型对这个特定文化、特定语境“懂得很深”，那反而比一个泛化能力很强但不够贴身的音乐模型更有优势。</p>\\\\n  <h2><strong>四、智能、权力与谁在主导世界</strong></h2>\\\\n  <p><strong>主持人</strong>：很多人会用同一种逻辑来推演 AI：更聪明的东西最终会统治不那么聪明的东西。Marc，你最近发过一条很有名的话：“顶级的图形推理者，只会做图形推理；但顶级的‘文字型人才’，却能调度那些图形推理者。”你还说过一句：“高 IQ 的专家，往往是在给中等 IQ 的通才打工。”这是什么意思？</p>\\\\n  <p><strong>Marc Andreessen</strong>：意思其实很简单：博士通常给 MBA 打工。你把问题放大一点看：当你观察今天这个世界，你真的会得出“最聪明的人在统治世界”这个结论吗？放眼全球现实，你会觉得“我们把天才都放在最关键的位置上了”吗？显然不是。</p>\\\\n  <p>这里有两件事同时成立。第一，我们整体上可能低估了智力的重要性。第二，那些特别强调智力的人，又往往会高估智力的重要性。社会科学通常会告诉你，流体智力、g 因子、IQ 之类的指标，和很多正向人生结果都有相关性，比如教育结果、职业成就、收入、生活满意度，甚至包括更少诉诸暴力地解决问题。这些相关性很重要，但它依然不是全部。所以，你不能把“智力重要”直接推导成“智力是唯一决定因素”或者“智力是最重要的唯一变量”。现实显然不是这样。</p>\\\\n  <p>哪怕你是一个极端的 IQ 决定论者，你也不得不承认：很多结果并不能只靠 IQ 来解释。再往上看群体层面，事情就更复杂了。任何一群人，一旦变成“群体”甚至“乌合之众”，集体智商通常都会下降。你把一群聪明人放进一个群体，他们往往也会变笨。所以，不管是公司、组织还是国家，谁来掌权，从来都不只是 IQ 决定的，甚至可能根本不是主要由 IQ 决定的。 因此，AI 圈里有一种常见假设：更聪明的存在必然会统治更笨的存在。我觉得这种说法非常容易被现实反驳。因为智能不是充分条件。</p>\\\\n  <h2><strong>五、超越 IQ：领导力、情绪与“心理理论”</strong></h2>\\\\n  <p><strong>主持人</strong>：那除了智力之外，哪些能力更决定一个人能否成功领导、创业、解决复杂问题、组织团队？以及为什么 AI 不能同样学会这些能力？</p>\\\\n  <p><strong>Ben Horowitz</strong>：有很多东西都重要。比如，你能不能以正确的方式跟人发生冲突。这里面当然有一点智力成分，但更多时候，关键在于你是不是真的理解你正在跟谁打交道。你要能读懂对方怎么想，能从公司员工的视角看问题，而不是只从你自己的视角看。这种能力来自于长期和人沟通、倾听、理解，而不是 IQ 测出来的。而且管理还有一个关键点：你不是为了让大家做“最受欢迎的事”，而是要让大家去做“正确的事”，哪怕他们并不喜欢。这就是大量管理工作的本质。</p>\\\\n  <p><strong>Marc Andreessen</strong>：所以这里面涉及勇气、动机、情绪理解，以及所谓的 theory of mind（心理理论）。</p>\\\\n  <p><strong>Ben Horowitz</strong>：对。你得知道别人想要什么，同时又不能只迎合，而是要把这和“组织真正需要做什么”结合起来。还要判断：团队里谁能力强，谁是不能失去的人，谁情绪崩了影响不大，谁一出问题整个团队就会出事。这些东西充满了微妙的情境判断，很难抽象成几条通用公式。这也是为什么很多管理书都很糟糕。因为管理高度依赖具体情境：你的公司、你的产品、你的人、你的组织结构，都和别人完全不同。所以那种“建立战略的五个步骤”式的书，很多时候根本没什么用。</p>\\\\n  <p><strong>Marc Andreessen</strong>：心理理论非常关键。简单说，就是：你能不能在自己脑子里，准确模拟出别人脑子里在发生什么。直觉上你会以为，越聪明的人越擅长这个；但事实可能并非如此。美国军方是美国社会最早、也是最系统使用 IQ 测试的机构之一。他们通过 ASVAB 之类测试把人分配到不同岗位，甚至领导岗位。而他们长期观察发现：如果一个领导者的智力水平和他带领的人群相差超过一个标准差，就很容易出问题。低于团队太多当然不行；但反过来，高出太多也不行。如果一个领导者的智力比组织平均水平高出两个标准差，他往往也会失去对他人的“心理建模能力”。也就是说，特别聪明的人，反而可能很难真正理解普通聪明人的思维过程。</p>\\\\n  <p>所以，领导者和被领导者之间需要某种“可连接性”，这不是单靠智力就能解决的。由此类推，如果未来真的出现一个 IQ 高得离谱的人，或者机器，比如“1000 IQ”的存在，它对现实的理解方式可能会异化到一个程度，以至于它根本无法和它所管理的人建立真实连接。这也是为什么我认为，未来很长时间里，这个世界都不会单纯按 IQ 来组织。</p>\\\\n  <p><strong>Ben Horowitz</strong>：扎克伯格有句话说得很好：“智能不是生命本身。”生命有很多维度，而这些维度并不依赖智力。有些人太聪明了，反而会过度理性化，默认别人也会那么理性，于是把很多事情都想偏了。</p>\\\\n  <h2><strong>六、具身智能：心智与身体的问题</strong></h2>\\\\n  <p><strong>Marc Andreessen</strong>：我还怀疑，这个问题最终会越来越走向生物学。现在越来越多研究表明，人类的认知、自我意识、信息处理、决策和主观体验，并不只是大脑在工作。传统的“心身二元论”——把心智和身体完全分开——很可能本来就是错的。 人的存在体验是一个全身性的过程。神经系统当然重要，但肠道菌群、嗅觉、激素、各种生化过程，都会影响人的认知和判断。如果顺着这条研究线继续往前走，我猜我们最后会发现：人类认知比大家原先以为的，更像是一种“全身参与”的体验。</p>\\\\n  <p>而这恰恰是今天 AI 领域面临的一个基础性问题。当前真正运转起来的 AI，本质上还是一种“彻底心身分离”的形式——它像一个脱离身体的大脑。但机器人革命迟早会来。当 AI 被装进能在物理世界里移动、感知、行动的实体里，它才可能更接近那种真正“智力—身体一体化”的经验结构。机器人会带来更多传感器、更多现实世界数据，也许会让系统更接近那种完整的智能。 但至少从现在的研究来看，这个方向还很早，我们还有很多工作要做。</p>\\\\n  <h2><strong>七、今天的 AI 在“读人心”方面到底有多强？</strong></h2>\\\\n  <p><strong>主持人</strong>：你觉得现在的 AI 在“心理理论”这件事上做得怎么样？它们的边界在哪里？</p>\\\\n  <p><strong>Marc Andreessen</strong>：总体来说，我觉得它们已经相当强了。我个人很喜欢让语言模型去生成“人物角色”，再让这些角色展开一种苏格拉底式对话。现在任何先进的大模型都能把这件事做得不错。不过它们有个特别烦人的毛病：它们总想让所有人都开心，最后都达成一致。一开始讨论可能还有点意思，但很快就会变成一种“大家互相理解、圆满收场”的剧情，我特别讨厌这个。所以我会故意给它下指令：把对话写得更紧张一点，更有怒气一点，让人物之间的冲突一路升级；再加一点脏话，让他们彻底撕破脸，进入那种“我要摧毁你名誉”的状态。这样它就会变得非常有意思。再后来我还会玩过头，比如说“其实他们全都是秘密忍者”，于是爱因斯坦就拿着双节棍去打玻尔——模型居然也能顺着往下编。所以你自己也得克制一点。</p>\\\\n  <p>但这恰恰说明，它在“模拟不同人的思维状态”上已经很强了。再举个例子：英国有一家做政治相关业务的创业公司发现，现在最先进的语言模型已经好到可以在模型内部，较准确地复现一个真实选民焦点小组。现实中的焦点小组很贵，要招募人、筛人、组织现场，还很花时间。但模型现在已经能模拟出不同背景的人，比如来自肯塔基州的大学生、田纳西州的家庭主妇等等，并让这些角色在模型内部展开讨论，而且结果与真实焦点小组相当接近。所以至少在这个门槛上，它已经跨过去了。接下来能走多远，还要继续看。</p>\\\\n  <h2><strong>八、AI 是不是泡沫？基本面与市场情绪</strong></h2>\\\\n  <p><strong>主持人</strong>：前面几位嘉宾提到，AI 正在建设极其庞大的物理基础设施，资本开支已经达到 GDP 的 1%。我们到底该怎么理解“AI 泡沫”这个问题？</p>\\\\n  <p><strong>Ben Horowitz</strong>：在我看来，只要大家还在问“这是不是泡沫”，那它大概率就还不是泡沫。</p>\\\\n  <p>因为泡沫本质上首先是一种心理现象。真正的泡沫，往往发生在所有人都已经彻底相信“这绝对不是泡沫”的时候。市场术语里，这叫“投降”——原先做空的人被持续上涨逼得受不了，只能认输，转身去做多。 互联网泡沫时期就有类似现象。那时候连巴菲特都开始投资科技股了，而他原本一直说自己不投科技，因为看不懂。</p>\\\\n  <p>如果连他都“投降”了，那时市场上其实已经没人再说那是泡沫了。 但回头看，互联网本身显然不是泡沫，它是真东西。真正的问题是：当时市场价格在短期内跑得太快，远远领先于实际用户规模和市场成熟度。可 AI 跟那时又不一样。今天 AI 最大的问题不是需求不足，而是需求太强。现在没有需求问题，我也很难相信五年后会出现需求问题。当然，未来可能会出现一些奇怪的瓶颈，比如散热不够、供电不够之类。但如果你现在看供需关系、增长与估值的匹配情况，我觉得它一点都不像泡沫。</p>\\\\n  <p><strong>Marc Andreessen</strong>：说到底，没人真正知道答案。你去问对冲基金、银行、CEO，很多人其实都不知道。VC 也常常不知道，只是有些人会因为自己错过机会、看到估值越来越高而情绪失控，特别希望这最终被证明是个泡沫。</p>\\\\n  <p><strong>Ben Horowitz</strong>：在我们这个行业里，最让人难受的事情之一，就是你错过了一个项目，结果它后来成了大成功。你可能会因此气 30 年。于是你就会不断找理由解释：不是我判断错了，是世界疯了。</p>\\\\n  <p><strong>Marc Andreessen</strong>：所以我会建议把讨论拉回最朴素的两个基本面问题：第一，技术到底能不能真正工作？能不能兑现它承诺的价值？第二，客户到底愿不愿意为它付钱？只要这两点都成立，整体方向通常就不会跑偏。</p>\\\\n  <h2><strong>九、平台迁移、Google 的“珍珠港时刻”与新交互范式</strong></h2>\\\\n  <p><strong>主持人</strong>：有人说 ChatGPT 对 Google 来说是一个“珍珠港时刻”，是巨人被惊醒的一刻。历史上每次平台切换时，到底是什么决定了老巨头能不能赢下下一波，而不是被新玩家取代？</p>\\\\n  <p><strong>Ben Horowitz</strong>：对变化做出反应当然重要，但这并不代表巨头就一定能赢。Google 确实被惊醒了，用不那么客气的话说，就是它终于“把脑袋从屁股里拔出来了”。所以它不会被轻易彻底碾压，但与此同时，我也不认为 OpenAI 会消失。Google 的确给了对手机会。说到底，比的是长期执行力。很多超级大公司在不同程度上都失去了持续执行的能力。历史上，新平台往往是新公司赢下来。微软当年错过了搜索，后来又错过了移动计算；它依然很强，但确实错过了那两个关键时代。所以通常是：新公司赢下新市场，老垄断则依靠旧时代积累继续存在很久。</p>\\\\n  <p><strong>Marc Andreessen</strong>：而且我觉得大家现在还有一个很容易犯的错误，就是默认未来的主流产品形态，只会是“搜索引擎”或者“聊天机器人”��选一。这是一种过于简化的看法。</p>\\\\n  <p>这种想法背后的叙事通常是：Google 面临的经典难题是自我颠覆——要不要把“10 条蓝色链接”的模式，替换成 AI 回答，从而可能冲击自己的广告模式；OpenAI 的问题则是，它有完整的聊天产品，但还没有 Google 那样的广告体系和分发能力。听上去很像《创新者的窘境》教科书里那种“新旧势力正面对决”的模型。但这种看法默认了一个前提：5 年、10 年、15 年、20 年后，人们主要使用的产品形态，还是“搜索”或“聊天”。</p>\\\\n  <p>而我认为，这个前提本身就很可能是错的。回到个人电脑历史就知道了：1975 年到 1992 年，个人电脑基本就是文本命令系统。而在当时，交互式命令行本身已经比打孔卡和时分系统先进很多了。但 17 年后，整个行业突然转向 GUI；又过 5 年，行业再转向浏览器。也就是说，用户体验的形态、产品进入生活的方式，直到很后面才真正定型。所以，我相信 20 年后依然会有聊天机器人，但我同样相信，当前的聊天产品公司和未来的新公司，一定会发明出很多今天我们还根本没见过的 AI 产品形态。而这正是科技行业最有意思的地方：产品的最终形态并不预先写好，发明空间仍然极大。</p>\\\\n  <h2><strong>十、给创业者的建议：这是一个真正不同的时代</strong></h2>\\\\n  <p><strong>主持人</strong>：如果你们要给今天的创业者一些建议，这个时代和过去最大的不同在哪里？无论是人才争夺，还是公司组织方式，还有哪些是创业者应该特别留意的？</p>\\\\n  <p><strong>Ben Horowitz</strong>：我觉得你刚才其实已经说中了重点：这是一个真正独特的时代。所以，如果你过度试图从上一个时代照搬组织设计经验、管理经验，反而可能会被误导。今天公司被搭建起来的方式，和过去已经非常不同了。 比如 AI 研究型 PhD 和传统的全栈工程师，完全不是同一种人才画像。所以很多问题必须回到第一性原理重新思考，而不能靠历史模板套答案。</p>\\\\n  <p><strong>Marc Andreessen</strong>：我还想补充一点：接下来变化一定会继续发生。我前面说过，产品形态会变；与此同时，今天大家最头疼的资源短缺，未来很可能会反过来变成过剩。</p>\\\\n  <h2><strong>十一、人才、芯片，以及“短缺终将导向过剩”的周期</strong></h2>\\\\n  <p><strong>Marc Andreessen</strong>：在供需世界里，一个很有意思的规律是：严重短缺本身，往往会孕育未来的过剩。因为当某样东西太稀缺、利润太高时，市场就会释放出巨大的激励，逼着人们去想办法增加供给。 现在的 AI 公司，一方面非常缺顶级研究员和工程师；另一方面又在缺芯片、数据中心、电力等基础设施。我不想断言具体时间点，但我相信总有一天，这两类短缺都会缓解，甚至转向过剩。</p>\\\\n  <p>尤其在人才这一边，一个很值得注意的现象是：中国现在已经冒出了很多非常出色的模型，而且不止一家。比如 DeepSeek、Qwen（通义千问）、Kimi。更有意思的是，做出这些东西的团队，很多并不是那种“论文圈最有名、名字总挂在顶刊上的明星团队”。这说明中国正在成功摸索出一套方法：把年轻人快速训练出来，让他们真正进入这个领域、做出成果。</p>\\\\n  <p><strong>Ben Horowitz</strong>：xAI 在某种程度上也是如此。</p>\\\\n  <p><strong>Marc Andreessen</strong>：对。所以我觉得，虽然顶级 AI 研发能力在一段时间内仍会是极其稀缺、极其昂贵的技能，但知识扩散已经开始发生了。大学生在学，更多人在会做，AI 也会进一步帮助人类构建 AI。也许不会真的出现“人才过剩”，但至少未来懂得如何构建这些系统的人，一定会比今天多得多。</p>\\\\n  <p>再看芯片这一边。我不是芯片专家，但如果回顾整个芯片产业历史，你会发现一个规律：每一次短缺，最后几乎都会走向过剩。因为短缺时利润太高，利润池太大，外部竞争者进入并把这个功能“商品化”的动力就会极强。NVIDIA 今天在芯片行业的位置，可能已经好到了史无前例的程度。但即便如此，我还是很难相信，5 年后基础设施会维持今天这种极端紧张的状态。哪怕瓶颈从芯片转移到了电力、散热或别的地方，芯片本身也很可能会出现供给宽松。</p>\\\\n  <p>所以我只想说一句：五年后，我们今天面对的问题大概率都还会在，但形式会完全变掉。这个行业变化极快，绝不能用静态视角看它。</p>\\\\n  <h2><strong>十二、中美 AI 竞赛与机器人时代</strong></h2>\\\\n  <p><strong>主持人</strong>：上个月我们在华盛顿时，参议员们很关心一个问题：到底该怎么看中美 AI 竞赛的现状？你愿意把当时对他们说的核心观点再讲一遍吗？</p>\\\\n  <p><strong>Marc Andreessen</strong>：我的基本判断是：到目前为止，重大的概念性创新，主要还是来自美国，更广一点说是来自西方，而其中又越来越集中在美国。但中国在另一件事上极其擅长：迅速吸收想法、把它做出来、放大规模、压低成本、实现商品化。他们在制造业里一直就是这么干的，现在在 AI 里也正在很成功地这么做。</p>\\\\n  <p>所以我会说，中国现在是在把“追赶战”打得非常好。当然，关于追赶速度为何如此之快，外界有各种猜测和讨论，但不管怎么说，结果摆在那里——他们确实做得非常出色。而且中国当然也不满足于只做追赶者。中国有很多非常聪明、非常有创造力的人。接下来真正值得观察的是：未来那些“概念级的突破”，会不会也开始越来越多地出现在中国，甚至让他们反超。</p>\\\\n  <p>所以我们在华盛顿对政策制定者说的是：这已经是一场真正的竞赛，是短跑，是寸土必争。美国不会拥有 5 年领先优势，可能最多也就 6 个月。我们必须跑得很快，必须赢。而且我们不能给美国公司套上中国政府并没有强加给中国公司的那些额外枷锁，否则我们就会输。如果有一天你早上醒来，发现这个世界在很大程度上是由中国 AI 所主导和塑造的，多数美国人显然不希望看到那样的局面。不过就目前而言，我对美国在软件层面的优势仍然算是谨慎乐观。</p>\\\\n  <p>但一旦 AI 进入具身智能/机器人阶段，问题就会变得更棘手。因为过去 40 年里，美国和西方整体上选择了去工业化，而中国则建立起了一个庞大的工业生态系统，覆盖机械、电气、半导体、软件以及各种终端制造：手机、无人机、汽车，未来还包括机器人。AI 革命一定会有第二阶段，那就是机器人，而且我觉得这个阶段会来得很快。到那时，哪怕美国在软件上依然领先，机器人终究还是得被“造出来”。</p>\\\\n  <p>而“把机器人造出来”不是一家公司单打独斗能完成的，它需要的是一个完整的供应链生态。汽车工业不是几家车企而已，而是成千上万的零部件供应商共同构成的体系。飞机、电脑也一样，机器人未来也会一样。 而按今天的默认格局看，这套体系很可能会主要发生在中国。所以哪怕中国在软件上没有完全追平美国，也有可能在硬件和制造端反超并绕过去。好消息是，美国 政治光谱两端现在都越来越意识到：去工业化走得太远了，必须想办法往回拉。我对此持谨慎乐观态度，但要做的事情还非常多。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/i4WecVP5x7JgvVzcpfDo0Q\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“硅星GenAI”</a>，作者：大模型机动组，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'品玩Global\'}], \'author\': \'品玩Global\', \'author_detail\': {\'name\': \'品玩Global\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'AI的下半场，软件领先转瞬即逝，真正的硬仗是机器人制造。\'}]}\", \"published_at\": \"2026-04-16 10:09:44\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 10:09:44', '2026-04-16 11:43:29');
INSERT INTO `news_detail` VALUES (18, 974, 10, '传统制造升级', '起底巨头瘦身成效，3M、GE、强生……谁赚翻了，谁后悔了？', '', '<p>如果告诉你一家名为Solventum（舒万诺）的医疗企业年营收超过80亿美元，你或许会感到意外和迷茫，并努力在脑海中搜索关于它的一切线索。现在，当你一旦得知Solventum实际上是工业巨头3M旗下独立上市而来，一切就都说得通了。</p>\n<p>作为上市后的首个完整财年，Solventum在2025财年财报中给出了不俗的表现，各项核心指标都超出了市场预期。这似乎又为近年来全球医疗巨头们愈发流行的分拆上市提供了一个新的论据……</p>\n<h2><strong>01</strong></h2>\n<h2><strong>百年工业巨头断臂求生，医疗业务或将快速增长</strong></h2>\n<p>大名鼎鼎的3M成立于1902年，拥有超过一百年的历史。其创立之初的目标仅仅是为了开采一种矿石用来生产砂轮磨料，因此起名为明尼苏达矿业及机器制造公司（Minnesota Mining and Manufacturing Company）。</p>\n<p>随后几十年，3M参与书写了近代工业史，并历经美国大萧条和两次世界大战，成为一家工业巨头。尤其是其在1930年发明了全球首款透明胶带，衍生产品止血胶带更是在二战期间成为重要的医用战略物资，拯救了不少生命。</p>\n<p>尽管如此，3M迟至1970年代才正式开始拓展医疗业务。1978年，3M推出首款医用透明敷料Tegaderm，凭借创新的薄膜材料技术，这款产品能够在直观观察伤口的同时提供防护，迅速成为医院场景的标配耗材，至今仍是全球销量最高的医用敷料之一。</p>\n<p>从1990年代开始，3M通过自主发展和多次并购整合，将医疗业务版图从最初的医用敷料耗材延伸，逐步构建起覆盖外科医疗、牙科、医疗信息化三大板块的业务雏形。医疗板块也成为3M重要的核心业务板块之一。</p>\n<p>根据2009财年的财报，医疗板块的营收达到42.94亿美元，在3M的业务板块中排名第二，在总营收中占比达到18.6%之多。</p>\n<p>然而，作为多元化工业集团的一部分，3M医疗业务在资源配置和战略决策上一直受到集团整体节奏的制约，策略相当保守，年均增速长期维持在1-2%的较低水平，明显低于独立医疗企业的增长速度。</p>\n<p>同时，医疗板块内部也还存在一定比例的非医疗关联业务。2021财年，工业过滤、饮用水净化等非医疗关联业务在医疗板块中的占比甚至达到11.4%。这显然也不利于对医疗业务的聚焦。</p>\n<p>屋漏偏逢连夜雨，从2016年开始，3M开始深陷军用耳塞质量缺陷官司。这起“世纪官司”被认为是美国历史上最大的集体侵权诉讼案，有数十万退伍军人指控3M及其子公司生产的军用耳塞导致其听力永久性损伤。2023年，双方总算达成和解，和解金额高达60亿美元，对3M的现金流是个巨大的考验。</p>\n<p>在这种背景下，3M在2022年开始启动医疗业务分拆评估。2024年4月1日，3M医疗业务板块以Solventum的新名称正式从3M分拆独立，并在纽交所挂牌上市，成为一家专注于医疗健康领域的独立上市公司。</p>\n<p>其新名称Solventum是由两个单词形成的组合，solve代表解决问题，体现新公司致力于寻找突破性解决方案的精神；entum则取自单词momentum（动量）的后半部，象征更快、更灵活的创新。</p>\n<p>一经获得独立决策权，Solventum便开始了大刀阔斧的架构重组，通过启动全球Solventum Way重组计划实现公司去中心化，推动创新，从而纠正原有“集中化、缓慢、缺乏决策权和问责制”的组织架构。</p>\n<p>对产品线进行重组也在意料之中。除了将资源集中在几个核心产品线以外，Solventum还在2025年2月将净化与过滤业务以41亿美元出售给Thermo Fisher（赛默飞），从而让业务更加聚焦医疗。新公司也借此获得了急需的资金，用于偿还债务并为未来的潜在并购提供资金。</p>\n<p>有了资金的支持，Solventum随即在去年11月做出独立后首笔重要收购，以7.25亿美元收购了急症护理企业Acera Surgical。这家公司的急性护理环境中复杂伤口修复的再生医学合成治疗方案，能与现有产品形成协同。</p>\n<p>此外，Solventum还加强国际拓展，不仅在巴西新建工厂，还在欧洲新建配送中心，从而提升全球市场竞争力。</p>\n<p>从分拆前后的财报来看，这些动作对Solventum的业务改善显然是有帮助的。2023财年，3M医疗业务的总营收为81.95亿美元。2024财年作为过渡年，全年营收实现82.54亿美元，有机增长1.2%。不过，核心业务增长乏力，占比最大的牙科业务有机增速仅0.4%，医疗信息系统增速1.6%，外科医疗板块增速1.2%。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_9c37075a5d924c1aba093e0cf14d1a4e@000000_oswg50291oswg800oswg182_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>Solventum分拆前后财报数据（动脉网整理）</p>\n<p>作为独立后首个完整财年，Solventum在2025财年的表现明显回升。年度总营收达83.25亿美元，有机增速提升至3.3%，超出市场预期。</p>\n<p>如果去除已经出售的净化过滤业务，核心业务营收的同比增速实际上已经达到4%。其中，牙科解决方案有机增速达3.3%；医疗信息系统增速4.0%；外科医疗板块增速3.5%。负压伤口治疗、牙科修复材料、医疗编码系统等核心产品的市场渗透率也显著提升。</p>\n<p>新公司的资产结构也通过出售非医疗业务和收购得到优化，净债务从分拆初期的73亿美元大幅降低至42亿美元；通过成本节省方案预计每年可节省5亿美元运营成本；首笔战略收购也为外科业务的未来增长打下了基础。</p>\n<p>根据Solventum公布的2026财年业绩指引，2026财年全年有机营收增速可望达到2-3%，可用现金流预计达2亿美元，预期看好。</p>\n<h2><strong>02</strong></h2>\n<h2><strong>冰火两重天与1+1&gt;2，巨头分拆医疗业务表现不一</strong></h2>\n<p>Solventum的分拆不过是近来全球医疗巨头分拆潮流的一个代表。在Solventum之前，已有多家巨头进行了分拆。这些分拆的效果如何，或许可以从分拆前后的财报得出一些参考。</p>\n<p>与3M分拆Solventum的情况最为类似的莫过于GE（通用电气）与Siemens（西门子集团）。首先，在分拆前，两家企业与3M一样皆是跨多个领域的老牌工业巨头。其次，几家工业巨头的分拆皆是对旗下医疗板块进行单独分拆并独立上市。</p>\n<p>2023年1月，GE Heathcare率先从GE中拆分并独立上市。对应的2023财年是独立上市后第一个完整财年。相比独立前，GE Healthcare的营收大幅上升，增速达到6.7%。同时，几大核心业务营收比较之前提升明显。Imaging影像部门营收提升6.5%，PCS部门营收提升7.8%，PDx部门更是提升17.8%之多。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_123fae28d1ec4c23af86297c083ad133@000000_oswg39748oswg797oswg123_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>GE Healthcare分拆前后财报数据（动脉网整理）</p>\n<p>随后，在经历了2024财年的短暂调整（营收增速0.6%）后，GE Healthcare在刚刚结束的2025财年再次爆发，营收达到206.3亿美元，增速达到4.8%。这也是该板块从2017财年至今（官网财报最早回溯时间）营收首次突破200亿美元。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_95e6edc8fe9b46cd8477a4f3ce676d7d@000000_oswg24999oswg800oswg78_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>分拆前GE医疗板块曾经过多次调整（动脉网整理）</p>\n<p>表面上看，2025财年似乎只是回到了之前的水平——2019财年和2018财年该板块营收也曾分别达到199亿美元和198亿美元。不过，独立之前的这些营收还包含了已经出售的BioPharma业务的营收——2019财年，该业务营收甚至达32.9亿美元之多。</p>\n<p>直到2019年，GE将属于医疗板块的BioPharma业务以214亿美元出售给Danaher（丹纳赫）。这也使得完全并表后的2021财年，整个GE医疗板块的营收下滑至175.9亿美元的水平。</p>\n<p>若以此为基准，独立后的GE Healthcare年营收其实已经提升了17.3%之多。要知道，在独立之前的2017-2021财年，排除出售BioPharma业务的影响，GE医疗板块的营收其实已经多年没有什么变化。分拆带来的效果业绩表现中得到明显的呈现。</p>\n<p>Siemens则更早做出分拆举动，早在2018年3月，Siemens Healthineers（西门子医疗）就从集团中独立分拆上市。2019财年是其独立上市后首个完整财年，实现全年营收145.19亿欧元，同比增加9.6%。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_f058bf19a3314454b9779f2c7af73d3f@000000_oswg33351oswg800oswg85_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>Siemens Healthineers分拆前后财报数据（动脉网整理）</p>\n<p>其中，几大核心业务较上一财年明显增长，Imaging业务营收增长9.6%，Diagnostics业务增长4.3%，Advanced Therapies业务增长8.6%。</p>\n<p>2020年，Siemens Healthineers宣布以创纪录的164亿美元收购放疗巨头Varian（瓦里安医疗）。其业绩随即开启高速增长模式，并在2022财年营收首次突破200亿欧元大关。2025财年，Siemens Healthineers年营收已达到233.75亿欧元，同比增长4.5%；净利润则达到21.68亿欧元，同比增长10.7%。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_926c6cb1884042a381dd6592530679ec@000000_oswg24112oswg800oswg70_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>分拆前可比较的Siemens医疗板块财报数据（动脉网整理）</p>\n<p>相比2017财年医疗板块136.77亿欧元的营收，2025财年几乎已经接近再造一个西门子的医疗业务。根据Siemens历年财报，从2013财年至2017财年，其医疗板块的年营收变化并不大。独立上市对西门子医疗业务来说显然是成功的决策。</p>\n<p>除了工业巨头，专注医疗的巨头们也在近年纷纷开始业务分拆独立上市。去年10月，全球医疗巨头J&amp;J（强生）就宣布将把骨科业务分拆独立上市。这其实不是J&amp;J第一次分拆。2023年5月，J&amp;J原消费健康部门就以Kenvue的新名称独立上市。该部门涵盖自我护理、皮肤健康和美容三个领域，拥有如露得清、邦迪、泰诺以及大宝等多个知名品牌。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_b435fd74e7a74f71845c23b0add4c92e@000000_oswg41136oswg800oswg159_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>Kenvue独立上市后财报数据（动脉网整理）</p>\n<p>然而，Kenvue上市以来的表现一直很一般，作为独立上市后首个完整财年的2024财年实现年度营收154.55亿美元，较2022财年提升3.3%，但净利润仅有10.3亿美元，较2022财年下降50%之多。2025财年净利润有所回升，但年度营收又下降了2.1%。同时，其三大核心板块业务表现不仅没有提升，反而呈现缓慢下滑的趋势。</p>\n<p>去年11月，全球消费品巨头Kimberly-Clark（金佰利）以约487亿美元收购Kenvue，后者的独立上市之路也将很快终结。站在Kenvue的角度，这显然不是一次成功的分拆。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_b726ef17fa414163a965c3855f3d3e3b@000000_oswg34059oswg800oswg115_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>J&amp;J分拆前后财报数据（动脉网整理）</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_8cefbd059d1248b3af51b0ec6bdac032@000000_oswg29991oswg800oswg71_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>分拆前J&amp;J可比较财报数据（动脉网整理）</p>\n<p>有意思的是，原本的母公司J&amp;J分拆后的日子倒是过得比较好。根据J&amp;J重新核算现有业务后的历年财报，无论是总体业务，还是创新药及医疗器械两大核心业务，都已实现连续4年业绩增长。2025财年营收达到941.93亿美元，同比增长6%，已经非常接近分拆前整个J&amp;J的最高水平（2022财年营收949.43亿美元）。强势增长的程度可见一斑。</p>\n<p>无独有偶，医药巨头GSK（葛兰素史克）与Haleon（赫力昂）的情形有些类似。后者原为GSK旗下消费健康业务，拥有钙尔奇、善存、舒适达、芬必得、扶他林、新康泰克、百多邦、辅舒良、保丽净等知名品牌，并于2022年7月独立上市。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_c1940124443c4dbd9129b0655fc84e30@000000_oswg50558oswg800oswg189_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>Haleon独立上市后财报数据（动脉网整理）</p>\n<p>除了第一个完整财年营收增长4.1%外，Haleon后续两个财年营收都持续下滑。2025财年实现营收110.3亿英镑，几乎已经要跌回独立前的水平。</p>\n<p>最要命的是，Haleon的六大业务板块中仅有口腔健康在持续增长，其他业务均呈现缓慢衰退的态势。目前来看，Haleon分拆后的表现不算乐观。参考Kenvue的情况，也许很快就会有巨头考虑收购Haleon。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_69f46299cfdf49529f7f51d10731e16e@000000_oswg31906oswg800oswg93_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>GSK分拆前后财报数据（动脉网整理）</p>\n<p>反而是分拆前母公司的GSK在近年连续增长。2025财年，GSK实现营收326.67亿英镑，同比增长4.1%。这一营收已经接近分拆前整个GSK的营收（2021财年341.14亿英镑），若按排除原消费健康业务重新计算后的历年财报，分拆后的GSK业务实际上已经连续5年保持增长。</p>\n<p>尤其值得一提的是，在分拆后，GSK的运营利润大幅增长，2025财年实现运营利润79.32亿英镑，在营收更少的前提下明显高于分拆前的运营利润（2021财年62.01亿英镑）。</p>\n<h2><strong>03</strong></h2>\n<h2><strong>写在最后</strong></h2>\n<p>表面上，巨头们拆分医疗业务的原因各不相同，既有精简架构、聚焦主业的考虑，也有摆脱低增长业务束缚，更有应急分拆的情况。不过，可以肯定的是，分拆已经成为当下的一个趋势。</p>\n<p>一方面，资本市场近年来对“专精”企业更为看好。相比于规模庞大、业务多样化的老式集团化企业，专精某项细分业务的企业如今更容易得到资本青睐。从过往来看，分拆后两家公司的市值之和往往也会大于以往单独公司的市值。</p>\n<p>另一方面，分拆潮也是医疗行业自身演进的结果。医疗器械领域近年来的数字化、精准化趋势也要求公司具备敏捷的组织和快速的技术迭代能力。这恰恰是多元化集团的结构性短板，尤其是当医疗业务难以获得集团内部足够资源时更为明显。</p>\n<p>当然，从几大巨头分拆的表现来看，分拆独立上市可能并不是万能药，表现各异。总的来说，对于技术驱动、壁垒相对深厚的医疗器械业务，分拆后专注聚焦的好处会在中长期持续兑现。无论是Siemens Healthineers，还是GE Healthcare均呈现出这种趋势。</p>\n<p>相反，对于泛医疗的消费健康业务，虽然分拆可以独立面对市场竞争的压力，倒逼品牌创新和效率提升，但最近几年宏观经济环境承压，消费降级成为大势。在这种大背景下，哪怕是拥有众多拳头产品的Kenvue和Haleon也很难扭转乾坤。</p>\n<p>不过，通过对消费健康业务的分拆，J&amp;J和GSK却得以将有限资源聚焦到高增长的医疗主业上，提升了主业表现，基本已经弥补了剥离消费健康业务后的营收损失。从这个角度而言，1+1&gt;2仍然是成立的，医疗业务分拆的价值仍然存在。</p>\n<p>在这样的逻辑下，相信未来会有更多的巨头们会继续分拆。尤其对于类似3M、GE和Siemens这样的多元化工业巨头而言，将医疗业务分拆独立上市恐怕将是一个绕不开的话题。即便是医械巨头们也已经身在其中，比如，Medtronic（美敦力）已将糖尿病业务MiniMed独立上市，J&amp;J也将进一步推进骨科业务独立上市。</p>\n<p>分拆，已演变为行业性的结构性变革。下一个会是谁？让我们拭目以待。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s?__biz=MjM5MTMyMDg0Ng==&amp;mid=2650684337&amp;idx=1&amp;sn=cab0ea9d70b260f3de83de62081437e2&amp;chksm=bf5f0083e042f473ae6db73b456999bdf94df7b595824baa8521a50b0bb03e68480a05fc08fb&amp;scene=0&amp;xtrack=1#rd\">“动脉网”（ID：vcbeat）</a>，作者：陈鹏，36氪经授权发布。</p>', 'https://36kr.com/p/3768744860058373?f=rss', 0, '', '{\"summary\": \"本文梳理全球医疗相关业务分拆案例的成效差异，为出海医疗企业制定业务战略提供参考\", \"abstract\": \"近年来全球多元化巨头兴起分拆医疗业务独立上市的潮流，本文梳理了3M、GE、西门子、强生等多家企业分拆后的业绩表现。对于技术驱动、壁垒深厚的医疗器械业务，分拆后聚焦资源普遍实现了更快增长，而泛医疗消费健康业务分拆后大多受市场环境影响表现不佳。分拆潮的出现，一方面源于资本市场更偏好专精细分领域的企业，另一方面也是医疗行业数字化、精准化发展对敏捷组织的要求。整体来看，分拆已成为医疗行业的结构性变革趋势，不同类型业务分拆效果存在明显分化\", \"keywords\": [\"医疗业务分拆\", \"独立上市\", \"医疗器械\", \"消费健康\", \"业务聚焦\", \"全球医疗\", \"结构性变革\"], \"policy_risk\": {\"market_risk\": \"泛医疗消费健康业务面临宏观经济承压、消费降级的市场压力，增长难度较高\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"传统制造升级\"}', '', '{\"url\": \"https://36kr.com/p/3768744860058373?f=rss\", \"title\": \"起底巨头瘦身成效，3M、GE、强生……谁赚翻了，谁后悔了？\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>如果告诉你一家名为Solventum（舒万诺）的医疗企业年营收超过80亿美元，你或许会感到意外和迷茫，并努力在脑海中搜索关于它的一切线索。现在，当你一旦得知Solventum实际上是工业巨头3M旗下独立上市而来，一切就都说得通了。</p>\\n<p>作为上市后的首个完整财年，Solventum在2025财年财报中给出了不俗的表现，各项核心指标都超出了市场预期。这似乎又为近年来全球医疗巨头们愈发流行的分拆上市提供了一个新的论据……</p>\\n<h2><strong>01</strong></h2>\\n<h2><strong>百年工业巨头断臂求生，医疗业务或将快速增长</strong></h2>\\n<p>大名鼎鼎的3M成立于1902年，拥有超过一百年的历史。其创立之初的目标仅仅是为了开采一种矿石用来生产砂轮磨料，因此起名为明尼苏达矿业及机器制造公司（Minnesota Mining and Manufacturing Company）。</p>\\n<p>随后几十年，3M参与书写了近代工业史，并历经美国大萧条和两次世界大战，成为一家工业巨头。尤其是其在1930年发明了全球首款透明胶带，衍生产品止血胶带更是在二战期间成为重要的医用战略物资，拯救了不少生命。</p>\\n<p>尽管如此，3M迟至1970年代才正式开始拓展医疗业务。1978年，3M推出首款医用透明敷料Tegaderm，凭借创新的薄膜材料技术，这款产品能够在直观观察伤口的同时提供防护，迅速成为医院场景的标配耗材，至今仍是全球销量最高的医用敷料之一。</p>\\n<p>从1990年代开始，3M通过自主发展和多次并购整合，将医疗业务版图从最初的医用敷料耗材延伸，逐步构建起覆盖外科医疗、牙科、医疗信息化三大板块的业务雏形。医疗板块也成为3M重要的核心业务板块之一。</p>\\n<p>根据2009财年的财报，医疗板块的营收达到42.94亿美元，在3M的业务板块中排名第二，在总营收中占比达到18.6%之多。</p>\\n<p>然而，作为多元化工业集团的一部分，3M医疗业务在资源配置和战略决策上一直受到集团整体节奏的制约，策略相当保守，年均增速长期维持在1-2%的较低水平，明显低于独立医疗企业的增长速度。</p>\\n<p>同时，医疗板块内部也还存在一定比例的非医疗关联业务。2021财年，工业过滤、饮用水净化等非医疗关联业务在医疗板块中的占比甚至达到11.4%。这显然也不利于对医疗业务的聚焦。</p>\\n<p>屋漏偏逢连夜雨，从2016年开始，3M开始深陷军用耳塞质量缺陷官司。这起“世纪官司”被认为是美国历史上最大的集体侵权诉讼案，有数十万退伍军人指控3M及其子公司生产的军用耳塞导致其听力永久性损伤。2023年，双方总算达成和解，和解金额高达60亿美元，对3M的现金流是个巨大的考验。</p>\\n<p>在这种背景下，3M在2022年开始启动医疗业务分拆评估。2024年4月1日，3M医疗业务板块以Solventum的新名称正式从3M分拆独立，并在纽交所挂牌上市，成为一家专注于医疗健康领域的独立上市公司。</p>\\n<p>其新名称Solventum是由两个单词形成的组合，solve代表解决问题，体现新公司致力于寻找突破性解决方案的精神；entum则取自单词momentum（动量）的后半部，象征更快、更灵活的创新。</p>\\n<p>一经获得独立决策权，Solventum便开始了大刀阔斧的架构重组，通过启动全球Solventum Way重组计划实现公司去中心化，推动创新，从而纠正原有“集中化、缓慢、缺乏决策权和问责制”的组织架构。</p>\\n<p>对产品线进行重组也在意料之中。除了将资源集中在几个核心产品线以外，Solventum还在2025年2月将净化与过滤业务以41亿美元出售给Thermo Fisher（赛默飞），从而让业务更加聚焦医疗。新公司也借此获得了急需的资金，用于偿还债务并为未来的潜在并购提供资金。</p>\\n<p>有了资金的支持，Solventum随即在去年11月做出独立后首笔重要收购，以7.25亿美元收购了急症护理企业Acera Surgical。这家公司的急性护理环境中复杂伤口修复的再生医学合成治疗方案，能与现有产品形成协同。</p>\\n<p>此外，Solventum还加强国际拓展，不仅在巴西新建工厂，还在欧洲新建配送中心，从而提升全球市场竞争力。</p>\\n<p>从分拆前后的财报来看，这些动作对Solventum的业务改善显然是有帮助的。2023财年，3M医疗业务的总营收为81.95亿美元。2024财年作为过渡年，全年营收实现82.54亿美元，有机增长1.2%。不过，核心业务增长乏力，占比最大的牙科业务有机增速仅0.4%，医疗信息系统增速1.6%，外科医疗板块增速1.2%。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9c37075a5d924c1aba093e0cf14d1a4e@000000_oswg50291oswg800oswg182_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>Solventum分拆前后财报数据（动脉网整理）</p>\\n<p>作为独立后首个完整财年，Solventum在2025财年的表现明显回升。年度总营收达83.25亿美元，有机增速提升至3.3%，超出市场预期。</p>\\n<p>如果去除已经出售的净化过滤业务，核心业务营收的同比增速实际上已经达到4%。其中，牙科解决方案有机增速达3.3%；医疗信息系统增速4.0%；外科医疗板块增速3.5%。负压伤口治疗、牙科修复材料、医疗编码系统等核心产品的市场渗透率也显著提升。</p>\\n<p>新公司的资产结构也通过出售非医疗业务和收购得到优化，净债务从分拆初期的73亿美元大幅降低至42亿美元；通过成本节省方案预计每年可节省5亿美元运营成本；首笔战略收购也为外科业务的未来增长打下了基础。</p>\\n<p>根据Solventum公布的2026财年业绩指引，2026财年全年有机营收增速可望达到2-3%，可用现金流预计达2亿美元，预期看好。</p>\\n<h2><strong>02</strong></h2>\\n<h2><strong>冰火两重天与1+1&gt;2，巨头分拆医疗业务表现不一</strong></h2>\\n<p>Solventum的分拆不过是近来全球医疗巨头分拆潮流的一个代表。在Solventum之前，已有多家巨头进行了分拆。这些分拆的效果如何，或许可以从分拆前后的财报得出一些参考。</p>\\n<p>与3M分拆Solventum的情况最为类似的莫过于GE（通用电气）与Siemens（西门子集团）。首先，在分拆前，两家企业与3M一样皆是跨多个领域的老牌工业巨头。其次，几家工业巨头的分拆皆是对旗下医疗板块进行单独分拆并独立上市。</p>\\n<p>2023年1月，GE Heathcare率先从GE中拆分并独立上市。对应的2023财年是独立上市后第一个完整财年。相比独立前，GE Healthcare的营收大幅上升，增速达到6.7%。同时，几大核心业务营收比较之前提升明显。Imaging影像部门营收提升6.5%，PCS部门营收提升7.8%，PDx部门更是提升17.8%之多。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_123fae28d1ec4c23af86297c083ad133@000000_oswg39748oswg797oswg123_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>GE Healthcare分拆前后财报数据（动脉网整理）</p>\\n<p>随后，在经历了2024财年的短暂调整（营收增速0.6%）后，GE Healthcare在刚刚结束的2025财年再次爆发，营收达到206.3亿美元，增速达到4.8%。这也是该板块从2017财年至今（官网财报最早回溯时间）营收首次突破200亿美元。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_95e6edc8fe9b46cd8477a4f3ce676d7d@000000_oswg24999oswg800oswg78_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>分拆前GE医疗板块曾经过多次调整（动脉网整理）</p>\\n<p>表面上看，2025财年似乎只是回到了之前的水平——2019财年和2018财年该板块营收也曾分别达到199亿美元和198亿美元。不过，独立之前的这些营收还包含了已经出售的BioPharma业务的营收——2019财年，该业务营收甚至达32.9亿美元之多。</p>\\n<p>直到2019年，GE将属于医疗板块的BioPharma业务以214亿美元出售给Danaher（丹纳赫）。这也使得完全并表后的2021财年，整个GE医疗板块的营收下滑至175.9亿美元的水平。</p>\\n<p>若以此为基准，独立后的GE Healthcare年营收其实已经提升了17.3%之多。要知道，在独立之前的2017-2021财年，排除出售BioPharma业务的影响，GE医疗板块的营收其实已经多年没有什么变化。分拆带来的效果业绩表现中得到明显的呈现。</p>\\n<p>Siemens则更早做出分拆举动，早在2018年3月，Siemens Healthineers（西门子医疗）就从集团中独立分拆上市。2019财年是其独立上市后首个完整财年，实现全年营收145.19亿欧元，同比增加9.6%。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f058bf19a3314454b9779f2c7af73d3f@000000_oswg33351oswg800oswg85_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>Siemens Healthineers分拆前后财报数据（动脉网整理）</p>\\n<p>其中，几大核心业务较上一财年明显增长，Imaging业务营收增长9.6%，Diagnostics业务增长4.3%，Advanced Therapies业务增长8.6%。</p>\\n<p>2020年，Siemens Healthineers宣布以创纪录的164亿美元收购放疗巨头Varian（瓦里安医疗）。其业绩随即开启高速增长模式，并在2022财年营收首次突破200亿欧元大关。2025财年，Siemens Healthineers年营收已达到233.75亿欧元，同比增长4.5%；净利润则达到21.68亿欧元，同比增长10.7%。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_926c6cb1884042a381dd6592530679ec@000000_oswg24112oswg800oswg70_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>分拆前可比较的Siemens医疗板块财报数据（动脉网整理）</p>\\n<p>相比2017财年医疗板块136.77亿欧元的营收，2025财年几乎已经接近再造一个西门子的医疗业务。根据Siemens历年财报，从2013财年至2017财年，其医疗板块的年营收变化并不大。独立上市对西门子医疗业务来说显然是成功的决策。</p>\\n<p>除了工业巨头，专注医疗的巨头们也在近年纷纷开始业务分拆独立上市。去年10月，全球医疗巨头J&amp;J（强生）就宣布将把骨科业务分拆独立上市。这其实不是J&amp;J第一次分拆。2023年5月，J&amp;J原消费健康部门就以Kenvue的新名称独立上市。该部门涵盖自我护理、皮肤健康和美容三个领域，拥有如露得清、邦迪、泰诺以及大宝等多个知名品牌。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b435fd74e7a74f71845c23b0add4c92e@000000_oswg41136oswg800oswg159_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>Kenvue独立上市后财报数据（动脉网整理）</p>\\n<p>然而，Kenvue上市以来的表现一直很一般，作为独立上市后首个完整财年的2024财年实现年度营收154.55亿美元，较2022财年提升3.3%，但净利润仅有10.3亿美元，较2022财年下降50%之多。2025财年净利润有所回升，但年度营收又下降了2.1%。同时，其三大核心板块业务表现不仅没有提升，反而呈现缓慢下滑的趋势。</p>\\n<p>去年11月，全球消费品巨头Kimberly-Clark（金佰利）以约487亿美元收购Kenvue，后者的独立上市之路也将很快终结。站在Kenvue的角度，这显然不是一次成功的分拆。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b726ef17fa414163a965c3855f3d3e3b@000000_oswg34059oswg800oswg115_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>J&amp;J分拆前后财报数据（动脉网整理）</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8cefbd059d1248b3af51b0ec6bdac032@000000_oswg29991oswg800oswg71_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>分拆前J&amp;J可比较财报数据（动脉网整理）</p>\\n<p>有意思的是，原本的母公司J&amp;J分拆后的日子倒是过得比较好。根据J&amp;J重新核算现有业务后的历年财报，无论是总体业务，还是创新药及医疗器械两大核心业务，都已实现连续4年业绩增长。2025财年营收达到941.93亿美元，同比增长6%，已经非常接近分拆前整个J&amp;J的最高水平（2022财年营收949.43亿美元）。强势增长的程度可见一斑。</p>\\n<p>无独有偶，医药巨头GSK（葛兰素史克）与Haleon（赫力昂）的情形有些类似。后者原为GSK旗下消费健康业务，拥有钙尔奇、善存、舒适达、芬必得、扶他林、新康泰克、百多邦、辅舒良、保丽净等知名品牌，并于2022年7月独立上市。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c1940124443c4dbd9129b0655fc84e30@000000_oswg50558oswg800oswg189_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>Haleon独立上市后财报数据（动脉网整理）</p>\\n<p>除了第一个完整财年营收增长4.1%外，Haleon后续两个财年营收都持续下滑。2025财年实现营收110.3亿英镑，几乎已经要跌回独立前的水平。</p>\\n<p>最要命的是，Haleon的六大业务板块中仅有口腔健康在持续增长，其他业务均呈现缓慢衰退的态势。目前来看，Haleon分拆后的表现不算乐观。参考Kenvue的情况，也许很快就会有巨头考虑收购Haleon。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_69f46299cfdf49529f7f51d10731e16e@000000_oswg31906oswg800oswg93_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>GSK分拆前后财报数据（动脉网整理）</p>\\n<p>反而是分拆前母公司的GSK在近年连续增长。2025财年，GSK实现营收326.67亿英镑，同比增长4.1%。这一营收已经接近分拆前整个GSK的营收（2021财年341.14亿英镑），若按排除原消费健康业务重新计算后的历年财报，分拆后的GSK业务实际上已经连续5年保持增长。</p>\\n<p>尤其值得一提的是，在分拆后，GSK的运营利润大幅增长，2025财年实现运营利润79.32亿英镑，在营收更少的前提下明显高于分拆前的运营利润（2021财年62.01亿英镑）。</p>\\n<h2><strong>03</strong></h2>\\n<h2><strong>写在最后</strong></h2>\\n<p>表面上，巨头们拆分医疗业务的原因各不相同，既有精简架构、聚焦主业的考虑，也有摆脱低增长业务束缚，更有应急分拆的情况。不过，可以肯定的是，分拆已经成为当下的一个趋势。</p>\\n<p>一方面，资本市场近年来对“专精”企业更为看好。相比于规模庞大、业务多样化的老式集团化企业，专精某项细分业务的企业如今更容易得到资本青睐。从过往来看，分拆后两家公司的市值之和往往也会大于以往单独公司的市值。</p>\\n<p>另一方面，分拆潮也是医疗行业自身演进的结果。医疗器械领域近年来的数字化、精准化趋势也要求公司具备敏捷的组织和快速的技术迭代能力。这恰恰是多元化集团的结构性短板，尤其是当医疗业务难以获得集团内部足够资源时更为明显。</p>\\n<p>当然，从几大巨头分拆的表现来看，分拆独立上市可能并不是万能药，表现各异。总的来说，对于技术驱动、壁垒相对深厚的医疗器械业务，分拆后专注聚焦的好处会在中长期持续兑现。无论是Siemens Healthineers，还是GE Healthcare均呈现出这种趋势。</p>\\n<p>相反，对于泛医疗的消费健康业务，虽然分拆可以独立面对市场竞争的压力，倒逼品牌创新和效率提升，但最近几年宏观经济环境承压，消费降级成为大势。在这种大背景下，哪怕是拥有众多拳头产品的Kenvue和Haleon也很难扭转乾坤。</p>\\n<p>不过，通过对消费健康业务的分拆，J&amp;J和GSK却得以将有限资源聚焦到高增长的医疗主业上，提升了主业表现，基本已经弥补了剥离消费健康业务后的营收损失。从这个角度而言，1+1&gt;2仍然是成立的，医疗业务分拆的价值仍然存在。</p>\\n<p>在这样的逻辑下，相信未来会有更多的巨头们会继续分拆。尤其对于类似3M、GE和Siemens这样的多元化工业巨头而言，将医疗业务分拆独立上市恐怕将是一个绕不开的话题。即便是医械巨头们也已经身在其中，比如，Medtronic（美敦力）已将糖尿病业务MiniMed独立上市，J&amp;J也将进一步推进骨科业务独立上市。</p>\\n<p>分拆，已演变为行业性的结构性变革。下一个会是谁？让我们拭目以待。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MjM5MTMyMDg0Ng==&amp;mid=2650684337&amp;idx=1&amp;sn=cab0ea9d70b260f3de83de62081437e2&amp;chksm=bf5f0083e042f473ae6db73b456999bdf94df7b595824baa8521a50b0bb03e68480a05fc08fb&amp;scene=0&amp;xtrack=1#rd\\\">“动脉网”（ID：vcbeat）</a>，作者：陈鹏，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'起底巨头瘦身成效，3M、GE、强生……谁赚翻了，谁后悔了？\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'起底巨头瘦身成效，3M、GE、强生……谁赚翻了，谁后悔了？\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768744860058373?f=rss\'}], \'link\': \'https://36kr.com/p/3768744860058373?f=rss\', \'published\': \'2026-04-16 10:04:06  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=4, tm_sec=6, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>如果告诉你一家名为Solventum（舒万诺）的医疗企业年营收超过80亿美元，你或许会感到意外和迷茫，并努力在脑海中搜索关于它的一切线索。现在，当你一旦得知Solventum实际上是工业巨头3M旗下独立上市而来，一切就都说得通了。</p>\\\\n  <p>作为上市后的首个完整财年，Solventum在2025财年财报中给出了不俗的表现，各项核心指标都超出了市场预期。这似乎又为近年来全球医疗巨头们愈发流行的分拆上市提供了一个新的论据……</p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>百年工业巨头断臂求生，医疗业务或将快速增长</strong></h2>\\\\n  <p>大名鼎鼎的3M成立于1902年，拥有超过一百年的历史。其创立之初的目标仅仅是为了开采一种矿石用来生产砂轮磨料，因此起名为明尼苏达矿业及机器制造公司（Minnesota Mining and Manufacturing Company）。</p>\\\\n  <p>随后几十年，3M参与书写了近代工业史，并历经美国大萧条和两次世界大战，成为一家工业巨头。尤其是其在1930年发明了全球首款透明胶带，衍生产品止血胶带更是在二战期间成为重要的医用战略物资，拯救了不少生命。</p>\\\\n  <p>尽管如此，3M迟至1970年代才正式开始拓展医疗业务。1978年，3M推出首款医用透明敷料Tegaderm，凭借创新的薄膜材料技术，这款产品能够在直观观察伤口的同时提供防护，迅速成为医院场景的标配耗材，至今仍是全球销量最高的医用敷料之一。</p>\\\\n  <p>从1990年代开始，3M通过自主发展和多次并购整合，将医疗业务版图从最初的医用敷料耗材延伸，逐步构建起覆盖外科医疗、牙科、医疗信息化三大板块的业务雏形。医疗板块也成为3M重要的核心业务板块之一。</p>\\\\n  <p>根据2009财年的财报，医疗板块的营收达到42.94亿美元，在3M的业务板块中排名第二，在总营收中占比达到18.6%之多。</p>\\\\n  <p>然而，作为多元化工业集团的一部分，3M医疗业务在资源配置和战略决策上一直受到集团整体节奏的制约，策略相当保守，年均增速长期维持在1-2%的较低水平，明显低于独立医疗企业的增长速度。</p>\\\\n  <p>同时，医疗板块内部也还存在一定比例的非医疗关联业务。2021财年，工业过滤、饮用水净化等非医疗关联业务在医疗板块中的占比甚至达到11.4%。这显然也不利于对医疗业务的聚焦。</p>\\\\n  <p>屋漏偏逢连夜雨，从2016年开始，3M开始深陷军用耳塞质量缺陷官司。这起“世纪官司”被认为是美国历史上最大的集体侵权诉讼案，有数十万退伍军人指控3M及其子公司生产的军用耳塞导致其听力永久性损伤。2023年，双方总算达成和解，和解金额高达60亿美元，对3M的现金流是个巨大的考验。</p>\\\\n  <p>在这种背景下，3M在2022年开始启动医疗业务分拆评估。2024年4月1日，3M医疗业务板块以Solventum的新名称正式从3M分拆独立，并在纽交所挂牌上市，成为一家专注于医疗健康领域的独立上市公司。</p>\\\\n  <p>其新名称Solventum是由两个单词形成的组合，solve代表解决问题，体现新公司致力于寻找突破性解决方案的精神；entum则取自单词momentum（动量）的后半部，象征更快、更灵活的创新。</p>\\\\n  <p>一经获得独立决策权，Solventum便开始了大刀阔斧的架构重组，通过启动全球Solventum Way重组计划实现公司去中心化，推动创新，从而纠正原有“集中化、缓慢、缺乏决策权和问责制”的组织架构。</p>\\\\n  <p>对产品线进行重组也在意料之中。除了将资源集中在几个核心产品线以外，Solventum还在2025年2月将净化与过滤业务以41亿美元出售给Thermo Fisher（赛默飞），从而让业务更加聚焦医疗。新公司也借此获得了急需的资金，用于偿还债务并为未来的潜在并购提供资金。</p>\\\\n  <p>有了资金的支持，Solventum随即在去年11月做出独立后首笔重要收购，以7.25亿美元收购了急症护理企业Acera Surgical。这家公司的急性护理环境中复杂伤口修复的再生医学合成治疗方案，能与现有产品形成协同。</p>\\\\n  <p>此外，Solventum还加强国际拓展，不仅在巴西新建工厂，还在欧洲新建配送中心，从而提升全球市场竞争力。</p>\\\\n  <p>从分拆前后的财报来看，这些动作对Solventum的业务改善显然是有帮助的。2023财年，3M医疗业务的总营收为81.95亿美元。2024财年作为过渡年，全年营收实现82.54亿美元，有机增长1.2%。不过，核心业务增长乏力，占比最大的牙科业务有机增速仅0.4%，医疗信息系统增速1.6%，外科医疗板块增速1.2%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9c37075a5d924c1aba093e0cf14d1a4e@000000_oswg50291oswg800oswg182_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Solventum分拆前后财报数据（动脉网整理）</p>\\\\n  <p>作为独立后首个完整财年，Solventum在2025财年的表现明显回升。年度总营收达83.25亿美元，有机增速提升至3.3%，超出市场预期。</p>\\\\n  <p>如果去除已经出售的净化过滤业务，核心业务营收的同比增速实际上已经达到4%。其中，牙科解决方案有机增速达3.3%；医疗信息系统增速4.0%；外科医疗板块增速3.5%。负压伤口治疗、牙科修复材料、医疗编码系统等核心产品的市场渗透率也显著提升。</p>\\\\n  <p>新公司的资产结构也通过出售非医疗业务和收购得到优化，净债务从分拆初期的73亿美元大幅降低至42亿美元；通过成本节省方案预计每年可节省5亿美元运营成本；首笔战略收购也为外科业务的未来增长打下了基础。</p>\\\\n  <p>根据Solventum公布的2026财年业绩指引，2026财年全年有机营收增速可望达到2-3%，可用现金流预计达2亿美元，预期看好。</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>冰火两重天与1+1&gt;2，巨头分拆医疗业务表现不一</strong></h2>\\\\n  <p>Solventum的分拆不过是近来全球医疗巨头分拆潮流的一个代表。在Solventum之前，已有多家巨头进行了分拆。这些分拆的效果如何，或许可以从分拆前后的财报得出一些参考。</p>\\\\n  <p>与3M分拆Solventum的情况最为类似的莫过于GE（通用电气）与Siemens（西门子集团）。首先，在分拆前，两家企业与3M一样皆是跨多个领域的老牌工业巨头。其次，几家工业巨头的分拆皆是对旗下医疗板块进行单独分拆并独立上市。</p>\\\\n  <p>2023年1月，GE Heathcare率先从GE中拆分并独立上市。对应的2023财年是独立上市后第一个完整财年。相比独立前，GE Healthcare的营收大幅上升，增速达到6.7%。同时，几大核心业务营收比较之前提升明显。Imaging影像部门营收提升6.5%，PCS部门营收提升7.8%，PDx部门更是提升17.8%之多。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_123fae28d1ec4c23af86297c083ad133@000000_oswg39748oswg797oswg123_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">GE Healthcare分拆前后财报数据（动脉网整理）</p>\\\\n  <p>随后，在经历了2024财年的短暂调整（营收增速0.6%）后，GE Healthcare在刚刚结束的2025财年再次爆发，营收达到206.3亿美元，增速达到4.8%。这也是该板块从2017财年至今（官网财报最早回溯时间）营收首次突破200亿美元。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_95e6edc8fe9b46cd8477a4f3ce676d7d@000000_oswg24999oswg800oswg78_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">分拆前GE医疗板块曾经过多次调整（动脉网整理）</p>\\\\n  <p>表面上看，2025财年似乎只是回到了之前的水平——2019财年和2018财年该板块营收也曾分别达到199亿美元和198亿美元。不过，独立之前的这些营收还包含了已经出售的BioPharma业务的营收——2019财年，该业务营收甚至达32.9亿美元之多。</p>\\\\n  <p>直到2019年，GE将属于医疗板块的BioPharma业务以214亿美元出售给Danaher（丹纳赫）。这也使得完全并表后的2021财年，整个GE医疗板块的营收下滑至175.9亿美元的水平。</p>\\\\n  <p>若以此为基准，独立后的GE Healthcare年营收其实已经提升了17.3%之多。要知道，在独立之前的2017-2021财年，排除出售BioPharma业务的影响，GE医疗板块的营收其实已经多年没有什么变化。分拆带来的效果业绩表现中得到明显的呈现。</p>\\\\n  <p>Siemens则更早做出分拆举动，早在2018年3月，Siemens Healthineers（西门子医疗）就从集团中独立分拆上市。2019财年是其独立上市后首个完整财年，实现全年营收145.19亿欧元，同比增加9.6%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f058bf19a3314454b9779f2c7af73d3f@000000_oswg33351oswg800oswg85_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Siemens Healthineers分拆前后财报数据（动脉网整理）</p>\\\\n  <p>其中，几大核心业务较上一财年明显增长，Imaging业务营收增长9.6%，Diagnostics业务增长4.3%，Advanced Therapies业务增长8.6%。</p>\\\\n  <p>2020年，Siemens Healthineers宣布以创纪录的164亿美元收购放疗巨头Varian（瓦里安医疗）。其业绩随即开启高速增长模式，并在2022财年营收首次突破200亿欧元大关。2025财年，Siemens Healthineers年营收已达到233.75亿欧元，同比增长4.5%；净利润则达到21.68亿欧元，同比增长10.7%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_926c6cb1884042a381dd6592530679ec@000000_oswg24112oswg800oswg70_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">分拆前可比较的Siemens医疗板块财报数据（动脉网整理）</p>\\\\n  <p>相比2017财年医疗板块136.77亿欧元的营收，2025财年几乎已经接近再造一个西门子的医疗业务。根据Siemens历年财报，从2013财年至2017财年，其医疗板块的年营收变化并不大。独立上市对西门子医疗业务来说显然是成功的决策。</p>\\\\n  <p>除了工业巨头，专注医疗的巨头们也在近年纷纷开始业务分拆独立上市。去年10月，全球医疗巨头J&amp;J（强生）就宣布将把骨科业务分拆独立上市。这其实不是J&amp;J第一次分拆。2023年5月，J&amp;J原消费健康部门就以Kenvue的新名称独立上市。该部门涵盖自我护理、皮肤健康和美容三个领域，拥有如露得清、邦迪、泰诺以及大宝等多个知名品牌。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b435fd74e7a74f71845c23b0add4c92e@000000_oswg41136oswg800oswg159_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Kenvue独立上市后财报数据（动脉网整理）</p>\\\\n  <p>然而，Kenvue上市以来的表现一直很一般，作为独立上市后首个完整财年的2024财年实现年度营收154.55亿美元，较2022财年提升3.3%，但净利润仅有10.3亿美元，较2022财年下降50%之多。2025财年净利润有所回升，但年度营收又下降了2.1%。同时，其三大核心板块业务表现不仅没有提升，反而呈现缓慢下滑的趋势。</p>\\\\n  <p>去年11月，全球消费品巨头Kimberly-Clark（金佰利）以约487亿美元收购Kenvue，后者的独立上市之路也将很快终结。站在Kenvue的角度，这显然不是一次成功的分拆。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b726ef17fa414163a965c3855f3d3e3b@000000_oswg34059oswg800oswg115_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">J&amp;J分拆前后财报数据（动脉网整理）</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8cefbd059d1248b3af51b0ec6bdac032@000000_oswg29991oswg800oswg71_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">分拆前J&amp;J可比较财报数据（动脉网整理）</p>\\\\n  <p>有意思的是，原本的母公司J&amp;J分拆后的日子倒是过得比较好。根据J&amp;J重新核算现有业务后的历年财报，无论是总体业务，还是创新药及医疗器械两大核心业务，都已实现连续4年业绩增长。2025财年营收达到941.93亿美元，同比增长6%，已经非常接近分拆前整个J&amp;J的最高水平（2022财年营收949.43亿美元）。强势增长的程度可见一斑。</p>\\\\n  <p>无独有偶，医药巨头GSK（葛兰素史克）与Haleon（赫力昂）的情形有些类似。后者原为GSK旗下消费健康业务，拥有钙尔奇、善存、舒适达、芬必得、扶他林、新康泰克、百多邦、辅舒良、保丽净等知名品牌，并于2022年7月独立上市。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c1940124443c4dbd9129b0655fc84e30@000000_oswg50558oswg800oswg189_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Haleon独立上市后财报数据（动脉网整理）</p>\\\\n  <p>除了第一个完整财年营收增长4.1%外，Haleon后续两个财年营收都持续下滑。2025财年实现营收110.3亿英镑，几乎已经要跌回独立前的水平。</p>\\\\n  <p>最要命的是，Haleon的六大业务板块中仅有口腔健康在持续增长，其他业务均呈现缓慢衰退的态势。目前来看，Haleon分拆后的表现不算乐观。参考Kenvue的情况，也许很快就会有巨头考虑收购Haleon。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_69f46299cfdf49529f7f51d10731e16e@000000_oswg31906oswg800oswg93_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">GSK分拆前后财报数据（动脉网整理）</p>\\\\n  <p>反而是分拆前母公司的GSK在近年连续增长。2025财年，GSK实现营收326.67亿英镑，同比增长4.1%。这一营收已经接近分拆前整个GSK的营收（2021财年341.14亿英镑），若按排除原消费健康业务重新计算后的历年财报，分拆后的GSK业务实际上已经连续5年保持增长。</p>\\\\n  <p>尤其值得一提的是，在分拆后，GSK的运营利润大幅增长，2025财年实现运营利润79.32亿英镑，在营收更少的前提下明显高于分拆前的运营利润（2021财年62.01亿英镑）。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>写在最后</strong></h2>\\\\n  <p>表面上，巨头们拆分医疗业务的原因各不相同，既有精简架构、聚焦主业的考虑，也有摆脱低增长业务束缚，更有应急分拆的情况。不过，可以肯定的是，分拆已经成为当下的一个趋势。</p>\\\\n  <p>一方面，资本市场近年来对“专精”企业更为看好。相比于规模庞大、业务多样化的老式集团化企业，专精某项细分业务的企业如今更容易得到资本青睐。从过往来看，分拆后两家公司的市值之和往往也会大于以往单独公司的市值。</p>\\\\n  <p>另一方面，分拆潮也是医疗行业自身演进的结果。医疗器械领域近年来的数字化、精准化趋势也要求公司具备敏捷的组织和快速的技术迭代能力。这恰恰是多元化集团的结构性短板，尤其是当医疗业务难以获得集团内部足够资源时更为明显。</p>\\\\n  <p>当然，从几大巨头分拆的表现来看，分拆独立上市可能并不是万能药，表现各异。总的来说，对于技术驱动、壁垒相对深厚的医疗器械业务，分拆后专注聚焦的好处会在中长期持续兑现。无论是Siemens Healthineers，还是GE Healthcare均呈现出这种趋势。</p>\\\\n  <p>相反，对于泛医疗的消费健康业务，虽然分拆可以独立面对市场竞争的压力，倒逼品牌创新和效率提升，但最近几年宏观经济环境承压，消费降级成为大势。在这种大背景下，哪怕是拥有众多拳头产品的Kenvue和Haleon也很难扭转乾坤。</p>\\\\n  <p>不过，通过对消费健康业务的分拆，J&amp;J和GSK却得以将有限资源聚焦到高增长的医疗主业上，提升了主业表现，基本已经弥补了剥离消费健康业务后的营收损失。从这个角度而言，1+1&gt;2仍然是成立的，医疗业务分拆的价值仍然存在。</p>\\\\n  <p>在这样的逻辑下，相信未来会有更多的巨头们会继续分拆。尤其对于类似3M、GE和Siemens这样的多元化工业巨头而言，将医疗业务分拆独立上市恐怕将是一个绕不开的话题。即便是医械巨头们也已经身在其中，比如，Medtronic（美敦力）已将糖尿病业务MiniMed独立上市，J&amp;J也将进一步推进骨科业务独立上市。</p>\\\\n  <p>分拆，已演变为行业性的结构性变革。下一个会是谁？让我们拭目以待。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MjM5MTMyMDg0Ng==&amp;mid=2650684337&amp;idx=1&amp;sn=cab0ea9d70b260f3de83de62081437e2&amp;chksm=bf5f0083e042f473ae6db73b456999bdf94df7b595824baa8521a50b0bb03e68480a05fc08fb&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“动脉网”（ID：vcbeat）</a>，作者：陈鹏，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>如果告诉你一家名为Solventum（舒万诺）的医疗企业年营收超过80亿美元，你或许会感到意外和迷茫，并努力在脑海中搜索关于它的一切线索。现在，当你一旦得知Solventum实际上是工业巨头3M旗下独立上市而来，一切就都说得通了。</p>\\\\n  <p>作为上市后的首个完整财年，Solventum在2025财年财报中给出了不俗的表现，各项核心指标都超出了市场预期。这似乎又为近年来全球医疗巨头们愈发流行的分拆上市提供了一个新的论据……</p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>百年工业巨头断臂求生，医疗业务或将快速增长</strong></h2>\\\\n  <p>大名鼎鼎的3M成立于1902年，拥有超过一百年的历史。其创立之初的目标仅仅是为了开采一种矿石用来生产砂轮磨料，因此起名为明尼苏达矿业及机器制造公司（Minnesota Mining and Manufacturing Company）。</p>\\\\n  <p>随后几十年，3M参与书写了近代工业史，并历经美国大萧条和两次世界大战，成为一家工业巨头。尤其是其在1930年发明了全球首款透明胶带，衍生产品止血胶带更是在二战期间成为重要的医用战略物资，拯救了不少生命。</p>\\\\n  <p>尽管如此，3M迟至1970年代才正式开始拓展医疗业务。1978年，3M推出首款医用透明敷料Tegaderm，凭借创新的薄膜材料技术，这款产品能够在直观观察伤口的同时提供防护，迅速成为医院场景的标配耗材，至今仍是全球销量最高的医用敷料之一。</p>\\\\n  <p>从1990年代开始，3M通过自主发展和多次并购整合，将医疗业务版图从最初的医用敷料耗材延伸，逐步构建起覆盖外科医疗、牙科、医疗信息化三大板块的业务雏形。医疗板块也成为3M重要的核心业务板块之一。</p>\\\\n  <p>根据2009财年的财报，医疗板块的营收达到42.94亿美元，在3M的业务板块中排名第二，在总营收中占比达到18.6%之多。</p>\\\\n  <p>然而，作为多元化工业集团的一部分，3M医疗业务在资源配置和战略决策上一直受到集团整体节奏的制约，策略相当保守，年均增速长期维持在1-2%的较低水平，明显低于独立医疗企业的增长速度。</p>\\\\n  <p>同时，医疗板块内部也还存在一定比例的非医疗关联业务。2021财年，工业过滤、饮用水净化等非医疗关联业务在医疗板块中的占比甚至达到11.4%。这显然也不利于对医疗业务的聚焦。</p>\\\\n  <p>屋漏偏逢连夜雨，从2016年开始，3M开始深陷军用耳塞质量缺陷官司。这起“世纪官司”被认为是美国历史上最大的集体侵权诉讼案，有数十万退伍军人指控3M及其子公司生产的军用耳塞导致其听力永久性损伤。2023年，双方总算达成和解，和解金额高达60亿美元，对3M的现金流是个巨大的考验。</p>\\\\n  <p>在这种背景下，3M在2022年开始启动医疗业务分拆评估。2024年4月1日，3M医疗业务板块以Solventum的新名称正式从3M分拆独立，并在纽交所挂牌上市，成为一家专注于医疗健康领域的独立上市公司。</p>\\\\n  <p>其新名称Solventum是由两个单词形成的组合，solve代表解决问题，体现新公司致力于寻找突破性解决方案的精神；entum则取自单词momentum（动量）的后半部，象征更快、更灵活的创新。</p>\\\\n  <p>一经获得独立决策权，Solventum便开始了大刀阔斧的架构重组，通过启动全球Solventum Way重组计划实现公司去中心化，推动创新，从而纠正原有“集中化、缓慢、缺乏决策权和问责制”的组织架构。</p>\\\\n  <p>对产品线进行重组也在意料之中。除了将资源集中在几个核心产品线以外，Solventum还在2025年2月将净化与过滤业务以41亿美元出售给Thermo Fisher（赛默飞），从而让业务更加聚焦医疗。新公司也借此获得了急需的资金，用于偿还债务并为未来的潜在并购提供资金。</p>\\\\n  <p>有了资金的支持，Solventum随即在去年11月做出独立后首笔重要收购，以7.25亿美元收购了急症护理企业Acera Surgical。这家公司的急性护理环境中复杂伤口修复的再生医学合成治疗方案，能与现有产品形成协同。</p>\\\\n  <p>此外，Solventum还加强国际拓展，不仅在巴西新建工厂，还在欧洲新建配送中心，从而提升全球市场竞争力。</p>\\\\n  <p>从分拆前后的财报来看，这些动作对Solventum的业务改善显然是有帮助的。2023财年，3M医疗业务的总营收为81.95亿美元。2024财年作为过渡年，全年营收实现82.54亿美元，有机增长1.2%。不过，核心业务增长乏力，占比最大的牙科业务有机增速仅0.4%，医疗信息系统增速1.6%，外科医疗板块增速1.2%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9c37075a5d924c1aba093e0cf14d1a4e@000000_oswg50291oswg800oswg182_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Solventum分拆前后财报数据（动脉网整理）</p>\\\\n  <p>作为独立后首个完整财年，Solventum在2025财年的表现明显回升。年度总营收达83.25亿美元，有机增速提升至3.3%，超出市场预期。</p>\\\\n  <p>如果去除已经出售的净化过滤业务，核心业务营收的同比增速实际上已经达到4%。其中，牙科解决方案有机增速达3.3%；医疗信息系统增速4.0%；外科医疗板块增速3.5%。负压伤口治疗、牙科修复材料、医疗编码系统等核心产品的市场渗透率也显著提升。</p>\\\\n  <p>新公司的资产结构也通过出售非医疗业务和收购得到优化，净债务从分拆初期的73亿美元大幅降低至42亿美元；通过成本节省方案预计每年可节省5亿美元运营成本；首笔战略收购也为外科业务的未来增长打下了基础。</p>\\\\n  <p>根据Solventum公布的2026财年业绩指引，2026财年全年有机营收增速可望达到2-3%，可用现金流预计达2亿美元，预期看好。</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>冰火两重天与1+1&gt;2，巨头分拆医疗业务表现不一</strong></h2>\\\\n  <p>Solventum的分拆不过是近来全球医疗巨头分拆潮流的一个代表。在Solventum之前，已有多家巨头进行了分拆。这些分拆的效果如何，或许可以从分拆前后的财报得出一些参考。</p>\\\\n  <p>与3M分拆Solventum的情况最为类似的莫过于GE（通用电气）与Siemens（西门子集团）。首先，在分拆前，两家企业与3M一样皆是跨多个领域的老牌工业巨头。其次，几家工业巨头的分拆皆是对旗下医疗板块进行单独分拆并独立上市。</p>\\\\n  <p>2023年1月，GE Heathcare率先从GE中拆分并独立上市。对应的2023财年是独立上市后第一个完整财年。相比独立前，GE Healthcare的营收大幅上升，增速达到6.7%。同时，几大核心业务营收比较之前提升明显。Imaging影像部门营收提升6.5%，PCS部门营收提升7.8%，PDx部门更是提升17.8%之多。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_123fae28d1ec4c23af86297c083ad133@000000_oswg39748oswg797oswg123_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">GE Healthcare分拆前后财报数据（动脉网整理）</p>\\\\n  <p>随后，在经历了2024财年的短暂调整（营收增速0.6%）后，GE Healthcare在刚刚结束的2025财年再次爆发，营收达到206.3亿美元，增速达到4.8%。这也是该板块从2017财年至今（官网财报最早回溯时间）营收首次突破200亿美元。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_95e6edc8fe9b46cd8477a4f3ce676d7d@000000_oswg24999oswg800oswg78_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">分拆前GE医疗板块曾经过多次调整（动脉网整理）</p>\\\\n  <p>表面上看，2025财年似乎只是回到了之前的水平——2019财年和2018财年该板块营收也曾分别达到199亿美元和198亿美元。不过，独立之前的这些营收还包含了已经出售的BioPharma业务的营收——2019财年，该业务营收甚至达32.9亿美元之多。</p>\\\\n  <p>直到2019年，GE将属于医疗板块的BioPharma业务以214亿美元出售给Danaher（丹纳赫）。这也使得完全并表后的2021财年，整个GE医疗板块的营收下滑至175.9亿美元的水平。</p>\\\\n  <p>若以此为基准，独立后的GE Healthcare年营收其实已经提升了17.3%之多。要知道，在独立之前的2017-2021财年，排除出售BioPharma业务的影响，GE医疗板块的营收其实已经多年没有什么变化。分拆带来的效果业绩表现中得到明显的呈现。</p>\\\\n  <p>Siemens则更早做出分拆举动，早在2018年3月，Siemens Healthineers（西门子医疗）就从集团中独立分拆上市。2019财年是其独立上市后首个完整财年，实现全年营收145.19亿欧元，同比增加9.6%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f058bf19a3314454b9779f2c7af73d3f@000000_oswg33351oswg800oswg85_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Siemens Healthineers分拆前后财报数据（动脉网整理）</p>\\\\n  <p>其中，几大核心业务较上一财年明显增长，Imaging业务营收增长9.6%，Diagnostics业务增长4.3%，Advanced Therapies业务增长8.6%。</p>\\\\n  <p>2020年，Siemens Healthineers宣布以创纪录的164亿美元收购放疗巨头Varian（瓦里安医疗）。其业绩随即开启高速增长模式，并在2022财年营收首次突破200亿欧元大关。2025财年，Siemens Healthineers年营收已达到233.75亿欧元，同比增长4.5%；净利润则达到21.68亿欧元，同比增长10.7%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_926c6cb1884042a381dd6592530679ec@000000_oswg24112oswg800oswg70_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">分拆前可比较的Siemens医疗板块财报数据（动脉网整理）</p>\\\\n  <p>相比2017财年医疗板块136.77亿欧元的营收，2025财年几乎已经接近再造一个西门子的医疗业务。根据Siemens历年财报，从2013财年至2017财年，其医疗板块的年营收变化并不大。独立上市对西门子医疗业务来说显然是成功的决策。</p>\\\\n  <p>除了工业巨头，专注医疗的巨头们也在近年纷纷开始业务分拆独立上市。去年10月，全球医疗巨头J&amp;J（强生）就宣布将把骨科业务分拆独立上市。这其实不是J&amp;J第一次分拆。2023年5月，J&amp;J原消费健康部门就以Kenvue的新名称独立上市。该部门涵盖自我护理、皮肤健康和美容三个领域，拥有如露得清、邦迪、泰诺以及大宝等多个知名品牌。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b435fd74e7a74f71845c23b0add4c92e@000000_oswg41136oswg800oswg159_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Kenvue独立上市后财报数据（动脉网整理）</p>\\\\n  <p>然而，Kenvue上市以来的表现一直很一般，作为独立上市后首个完整财年的2024财年实现年度营收154.55亿美元，较2022财年提升3.3%，但净利润仅有10.3亿美元，较2022财年下降50%之多。2025财年净利润有所回升，但年度营收又下降了2.1%。同时，其三大核心板块业务表现不仅没有提升，反而呈现缓慢下滑的趋势。</p>\\\\n  <p>去年11月，全球消费品巨头Kimberly-Clark（金佰利）以约487亿美元收购Kenvue，后者的独立上市之路也将很快终结。站在Kenvue的角度，这显然不是一次成功的分拆。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b726ef17fa414163a965c3855f3d3e3b@000000_oswg34059oswg800oswg115_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">J&amp;J分拆前后财报数据（动脉网整理）</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8cefbd059d1248b3af51b0ec6bdac032@000000_oswg29991oswg800oswg71_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">分拆前J&amp;J可比较财报数据（动脉网整理）</p>\\\\n  <p>有意思的是，原本的母公司J&amp;J分拆后的日子倒是过得比较好。根据J&amp;J重新核算现有业务后的历年财报，无论是总体业务，还是创新药及医疗器械两大核心业务，都已实现连续4年业绩增长。2025财年营收达到941.93亿美元，同比增长6%，已经非常接近分拆前整个J&amp;J的最高水平（2022财年营收949.43亿美元）。强势增长的程度可见一斑。</p>\\\\n  <p>无独有偶，医药巨头GSK（葛兰素史克）与Haleon（赫力昂）的情形有些类似。后者原为GSK旗下消费健康业务，拥有钙尔奇、善存、舒适达、芬必得、扶他林、新康泰克、百多邦、辅舒良、保丽净等知名品牌，并于2022年7月独立上市。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c1940124443c4dbd9129b0655fc84e30@000000_oswg50558oswg800oswg189_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">Haleon独立上市后财报数据（动脉网整理）</p>\\\\n  <p>除了第一个完整财年营收增长4.1%外，Haleon后续两个财年营收都持续下滑。2025财年实现营收110.3亿英镑，几乎已经要跌回独立前的水平。</p>\\\\n  <p>最要命的是，Haleon的六大业务板块中仅有口腔健康在持续增长，其他业务均呈现缓慢衰退的态势。目前来看，Haleon分拆后的表现不算乐观。参考Kenvue的情况，也许很快就会有巨头考虑收购Haleon。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_69f46299cfdf49529f7f51d10731e16e@000000_oswg31906oswg800oswg93_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">GSK分拆前后财报数据（动脉网整理）</p>\\\\n  <p>反而是分拆前母公司的GSK在近年连续增长。2025财年，GSK实现营收326.67亿英镑，同比增长4.1%。这一营收已经接近分拆前整个GSK的营收（2021财年341.14亿英镑），若按排除原消费健康业务重新计算后的历年财报，分拆后的GSK业务实际上已经连续5年保持增长。</p>\\\\n  <p>尤其值得一提的是，在分拆后，GSK的运营利润大幅增长，2025财年实现运营利润79.32亿英镑，在营收更少的前提下明显高于分拆前的运营利润（2021财年62.01亿英镑）。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>写在最后</strong></h2>\\\\n  <p>表面上，巨头们拆分医疗业务的原因各不相同，既有精简架构、聚焦主业的考虑，也有摆脱低增长业务束缚，更有应急分拆的情况。不过，可以肯定的是，分拆已经成为当下的一个趋势。</p>\\\\n  <p>一方面，资本市场近年来对“专精”企业更为看好。相比于规模庞大、业务多样化的老式集团化企业，专精某项细分业务的企业如今更容易得到资本青睐。从过往来看，分拆后两家公司的市值之和往往也会大于以往单独公司的市值。</p>\\\\n  <p>另一方面，分拆潮也是医疗行业自身演进的结果。医疗器械领域近年来的数字化、精准化趋势也要求公司具备敏捷的组织和快速的技术迭代能力。这恰恰是多元化集团的结构性短板，尤其是当医疗业务难以获得集团内部足够资源时更为明显。</p>\\\\n  <p>当然，从几大巨头分拆的表现来看，分拆独立上市可能并不是万能药，表现各异。总的来说，对于技术驱动、壁垒相对深厚的医疗器械业务，分拆后专注聚焦的好处会在中长期持续兑现。无论是Siemens Healthineers，还是GE Healthcare均呈现出这种趋势。</p>\\\\n  <p>相反，对于泛医疗的消费健康业务，虽然分拆可以独立面对市场竞争的压力，倒逼品牌创新和效率提升，但最近几年宏观经济环境承压，消费降级成为大势。在这种大背景下，哪怕是拥有众多拳头产品的Kenvue和Haleon也很难扭转乾坤。</p>\\\\n  <p>不过，通过对消费健康业务的分拆，J&amp;J和GSK却得以将有限资源聚焦到高增长的医疗主业上，提升了主业表现，基本已经弥补了剥离消费健康业务后的营收损失。从这个角度而言，1+1&gt;2仍然是成立的，医疗业务分拆的价值仍然存在。</p>\\\\n  <p>在这样的逻辑下，相信未来会有更多的巨头们会继续分拆。尤其对于类似3M、GE和Siemens这样的多元化工业巨头而言，将医疗业务分拆独立上市恐怕将是一个绕不开的话题。即便是医械巨头们也已经身在其中，比如，Medtronic（美敦力）已将糖尿病业务MiniMed独立上市，J&amp;J也将进一步推进骨科业务独立上市。</p>\\\\n  <p>分拆，已演变为行业性的结构性变革。下一个会是谁？让我们拭目以待。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MjM5MTMyMDg0Ng==&amp;mid=2650684337&amp;idx=1&amp;sn=cab0ea9d70b260f3de83de62081437e2&amp;chksm=bf5f0083e042f473ae6db73b456999bdf94df7b595824baa8521a50b0bb03e68480a05fc08fb&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“动脉网”（ID：vcbeat）</a>，作者：陈鹏，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'动脉网\'}], \'author\': \'动脉网\', \'author_detail\': {\'name\': \'动脉网\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'分拆，已演变为行业性的结构性变革。下一个会是谁？让我们拭目以待。\'}]}\", \"published_at\": \"2026-04-16 10:04:06\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 10:04:06', '2026-04-16 11:44:46');
INSERT INTO `news_detail` VALUES (19, 977, 8, '新能源与汽车', '为了省钱，特斯拉开始用欣旺达电池了', '', '<p>大众合作小鹏，斯特兰蒂斯投资零跑，这种海外巨头携手国内小厂的故事，终究还是从整车制造领域吹到了供应商的头上。</p>\n<p>几天前，欣旺达 —— 这个此前被吉利控诉质量有问题的电池厂商，股价迎来了一波飙升。</p>\n<p>因为根据 36Kr 的报道，欣旺达现在已经进入了特斯拉的供应体系，给上海工厂卖去欧洲的车型提供动力电池。并且，现在已经小批量上车了。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_cea75df3058144889152777088e878df@5091053_oswg806531oswg1080oswg567_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>消息一出，不只是欣旺达的股价应声飙高了接近 20% ，人们对欣旺达的态度也是来了波 180 度大反转。</p>\n<p>“ 不是小伙子，你怎么还有两副面孔呢？ ”</p>\n<p>毕竟在宁德时代的口碑统治下，欣旺达这两年好像都是以不太靠谱的形象在国内示人的。先是极氪因为质量缺陷对欣旺达发起了 23.14 亿的索赔，然后又是用了欣旺达电池的沃尔沃 EX30 ，因为过热风险在海外发起了召回。</p>\n<p>虽说一直没有明确证据表明欣旺达到底是哪里有问题，但在负面发酵以后，各大社交平台上，甚至已经出现 “ 用了欣旺达电池的车不敢买 ”，这种十分严重的负面帖子了。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_4909695d015340ec8996c1df128bca06@5091053_oswg299522oswg1080oswg1111_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>然而反观特斯拉这头，对于供应链企业可是出了名的要求高，经常因为很小的故障率就召回一大批车型。</p>\n<p>有时候，甚至还会在公告里点名骂供应商 —— 比如当年召回 2 万多台国产 Model Y 的时候，就点名了拓普的转向节有 0.2~1% 的缺陷概率。</p>\n<p>能在动力电池这个最关键的部件上满足特斯拉的要求，欣旺达多少也是有些过硬的底子在的。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_cef459764e754e52a0e55d12a4fe7169@5091053_oswg193089oswg1080oswg664_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>当然，今天我想跟哥几个聊的也不是欣旺达到底靠不靠谱。</p>\n<p>毕竟车企招标的技术要求、欣旺达被起诉的技术细节还有特斯拉内部的质量控制体系几乎都是高度保密的水平，一般人不知道，知道的人也不会说。</p>\n<p>我想说的，其实是特斯拉为什么会在这个时间点，看上欣旺达这个新队友。</p>\n<p>去年也就是 2025 年，虽然 Model Y 依旧是全球范围内卖得最好的单一车型，但从财报数据上看，去年却是特斯拉近来过得最惨的一年。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_8a2d9840afd447c0a63de9c688cb4045@5091053_oswg202180oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>营收第一次变成了负增长（ -3% ），净利润相比 2024 年暴跌了 46.5% ，利润率也接近腰斩（ 从 7.26% 跌至 4% ）。</p>\n<p>里头的各种缘由比如美国的关税上涨、补贴取消以及中国的竞争加剧等等就不展开说了，总之对于特斯拉而言，省钱，绝对是眼下最为关键的主线任务。</p>\n<p>不然，真要保不住老马的天价薪酬了。</p>\n<p>而在动力电池这个占电车成本最多的部件上，特斯拉已经花了很长时间尝试降低它的造价了。只不过因为目标太高、实力不够等原因，特斯拉自研的 “ 又大又省钱 ” 电池 4680 ，在技术指标和大规模量产上始终没啥进度。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_82f4c7f138c9425daf682c55b1a3a26c@5091053_oswg389093oswg995oswg1024_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>也是因此，如今市面上的特斯拉车型用的也都是来自 LG、宁德时代和松下的动力电池。</p>\n<p>找供应商买电池的好处，自然是哥几个都是电池行业的老兵，有技术有积淀够靠谱，可以满足特斯拉很高的软硬件要求。</p>\n<p>但问题是，它们的电池实在是太贵了。</p>\n<p>就拿宁德时代来说，目前哥们供应着特斯拉中国和欧洲市场的绝大部分磷酸铁锂电池包，从总量上估算，更是占到了特斯拉全球动力电池采购的四到五成，属于是特斯拉目前在电池上的最大靠山了。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_bba6e607fe1349a58afbc18e67c0072a@5091053_oswg480649oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>可就如大伙所知道的那样，找宁德时代买东西，其实并不是一件体验特别好的事。不仅要受着宁王的高姿态，还得说服自己为宁王极高的品牌溢价来买单。</p>\n<p>是的，就像那句很经典的 “ 车企都在给宁德时代打工 ” 一样，宁王在去年不仅收入创了历史新高，利润率更是达到了 26.27% 。即使单看动力电池部分，它的利润率也达到了 23.84% ，比行业友商们普遍高出了 5-15% 。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_dd1b38e46a724ac8b9ddc23fa3e135d5@5091053_oswg185884oswg1080oswg530_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>对其他车企来说，多花些钱买个出货顺利够快、质量够好的安心其实没啥毛病，但对于现在急需省钱的特斯拉来说，这种没有把钱用在刀刃上的情况，属实不太能接受。</p>\n<p>这时候，就轮到欣旺达上场了。</p>\n<p>如果说宁德时代是复联里面的托尼·斯塔克，那跟欣旺达最像的肯定就是鹰眼了。没有那么猛，偶尔也会抽抽风，但至少为人和善且实力到位，最重要的是作战装备远不如同僚们费钱。</p>\n<p>是的，除去和吉利的爱恨情仇之外，欣旺达在车企端的形象其实一直还挺好。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_964b820c21c64670b0e33d4c8c078d9a@5091053_oswg721776oswg1080oswg553_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>作为国内前五（ 正好第五 ）的电池供应商，欣旺达不仅出货量在第二梯队中处在绝对领先的地位，是国内重要的电池供应商之一，近几年也和包括理想、小米、上汽、东风等头部车企建立了合作关系，也算是把口碑打出来了。</p>\n<p>同时作为二线厂家，欣旺达的姿态比宁王相比低的不是一星半点。只要车企想合作，形式车企选，方向车企定，欣旺达都愿意打配合。</p>\n<p>甚至有报道说在拿下小米昆仑的供应项目以后，欣旺达直接派了 30-50 个研发人员去到了小米驻场，只要有需求，就可以马上响应。</p>\n<p>效率高就不说了，情绪价值反正是拉满了对吧。</p>\n<p>但对特斯拉来说，最重要的肯定还是欣旺达的性价比。从后者最新的半年报，也就是 2025 上半年的财报里可以看到，欣旺达走的完完全全就是薄利多销的路线。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_9a9ceb0dc5d24da1b0a0cb0ac1375817@5091053_oswg176712oswg1080oswg519_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>动力电池相关的营业收入同比增长了 22.63% ，但毛利率却比之前下降了 1.89 个百分点，降到了 9.77% ，只有宁王的一半不到，属于是在电池之外分币不挣了。</p>\n<p>特斯拉一看，我去，知音啊！果断选择了合作。</p>\n<p>并且根据文章开头的爆料，这回的电池合作形式还和之前略有不同。之前供应商们给特斯拉供应的，大都是封装好的完整的动力电池包。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_12c302c85a854d678e9d132c8382e9fa@5091053_oswg566791oswg800oswg600_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>但这回欣旺达提供的，却只有最基础的锂酸铁锂电芯。</p>\n<p>剩下的包括电池管理系统、散热和支撑结构、整包封装等等工序，都是特斯拉自己完成。相当于欣旺达是把电池厂能挣钱的部分，又分了一块到特斯拉手里，老马又能省一波。</p>\n<p>所以看到这大伙应该都看明白了吧，特斯拉之所以会和欣旺达看上对眼，原因其实和之前用比亚迪电池是一样的。</p>\n<p>一方面，特斯拉想要摆脱对宁德时代的依赖，找到一个更好说话、更加实惠的供应商。另一方面，是欣旺达目前的业务状态可以支持特斯拉提出更多的要求、用比友商更低的利润率帮特斯拉省钱。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_a69bfe4c8d944f94bc641d31aa8a9a20@5091053_oswg403665oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>只不过因为有着直接的市场竞争，特斯拉最后中断了和比亚迪的合作。没有类似烦恼的欣旺达，能不能挑战宁王在特链里的地位还咱们还暂时下不了结论。</p>\n<p>但或许从这件事开始，人们对欣旺达的评价，可以变得不再那么负面了呢？</p>\n<p><strong>图片、资料来源</strong>：</p>\n<p>欣旺达&amp;理想汽车迎来100000台电池包下线里程碑时刻！ 欣旺达-用心做好每一块电池</p>\n<p>特斯拉（上海）有限公司召回部分国产Model Y电动汽车</p>\n<p>拓普集团回应特斯拉召回事件：产品有缺陷 不影响业绩</p>\n<p>2025 Q4 Quarterly Update Deck assets-ir.tesla.com</p>\n<p>欣旺达装车特斯拉，供应全球车型｜36氪独家</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/irOvB4Dsb7A58uDf5q7JVw\">“差评X.PIN”</a>，作者：致命空枪，编辑：脖子右拧，36氪经授权发布。</p>', 'https://36kr.com/p/3768706892301059?f=rss', 0, '', '{\"summary\": \"帮助新能源汽车出海产业链企业洞察特斯拉供应链降本新布局，把握动力电池供应商合作趋势\", \"abstract\": \"本文报道欣旺达已进入特斯拉供应体系，为上海工厂出口欧洲的车型小批量供应磷酸铁锂电芯。特斯拉近年业绩下滑，将降本作为核心任务，自研4680电池量产进度不及预期，现有头部供应商电池成本偏高。欣旺达作为二线动力电池厂商，性价比高、配合度好，毛利率远低于头部供应商，此次仅供应电芯的模式进一步帮助特斯拉降本。此次合作反映特斯拉降低对头部供应商依赖的供应链策略，也有望扭转市场对欣旺达的负面评价。\", \"keywords\": [\"特斯拉\", \"欣旺达\", \"动力电池\", \"供应链降本\", \"新能源汽车\", \"出海\", \"宁德时代\", \"电芯\"], \"policy_risk\": {\"market_risk\": \"欣旺达存在过往电池质量负面舆论，曾被车企索赔，搭载其电池的车型曾因过热风险在海外召回；特斯拉面临全球市场竞争加剧，营收与净利润大幅下滑的压力\", \"policy_compliance\": \"提及美国关税上涨、新能源汽车补贴取消，对特斯拉利润造成负面影响\"}, \"topic_cluster\": \"供应链物流\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3768706892301059?f=rss\", \"title\": \"为了省钱，特斯拉开始用欣旺达电池了\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>大众合作小鹏，斯特兰蒂斯投资零跑，这种海外巨头携手国内小厂的故事，终究还是从整车制造领域吹到了供应商的头上。</p>\\n<p>几天前，欣旺达 —— 这个此前被吉利控诉质量有问题的电池厂商，股价迎来了一波飙升。</p>\\n<p>因为根据 36Kr 的报道，欣旺达现在已经进入了特斯拉的供应体系，给上海工厂卖去欧洲的车型提供动力电池。并且，现在已经小批量上车了。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_cea75df3058144889152777088e878df@5091053_oswg806531oswg1080oswg567_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>消息一出，不只是欣旺达的股价应声飙高了接近 20% ，人们对欣旺达的态度也是来了波 180 度大反转。</p>\\n<p>“ 不是小伙子，你怎么还有两副面孔呢？ ”</p>\\n<p>毕竟在宁德时代的口碑统治下，欣旺达这两年好像都是以不太靠谱的形象在国内示人的。先是极氪因为质量缺陷对欣旺达发起了 23.14 亿的索赔，然后又是用了欣旺达电池的沃尔沃 EX30 ，因为过热风险在海外发起了召回。</p>\\n<p>虽说一直没有明确证据表明欣旺达到底是哪里有问题，但在负面发酵以后，各大社交平台上，甚至已经出现 “ 用了欣旺达电池的车不敢买 ”，这种十分严重的负面帖子了。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4909695d015340ec8996c1df128bca06@5091053_oswg299522oswg1080oswg1111_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>然而反观特斯拉这头，对于供应链企业可是出了名的要求高，经常因为很小的故障率就召回一大批车型。</p>\\n<p>有时候，甚至还会在公告里点名骂供应商 —— 比如当年召回 2 万多台国产 Model Y 的时候，就点名了拓普的转向节有 0.2~1% 的缺陷概率。</p>\\n<p>能在动力电池这个最关键的部件上满足特斯拉的要求，欣旺达多少也是有些过硬的底子在的。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_cef459764e754e52a0e55d12a4fe7169@5091053_oswg193089oswg1080oswg664_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>当然，今天我想跟哥几个聊的也不是欣旺达到底靠不靠谱。</p>\\n<p>毕竟车企招标的技术要求、欣旺达被起诉的技术细节还有特斯拉内部的质量控制体系几乎都是高度保密的水平，一般人不知道，知道的人也不会说。</p>\\n<p>我想说的，其实是特斯拉为什么会在这个时间点，看上欣旺达这个新队友。</p>\\n<p>去年也就是 2025 年，虽然 Model Y 依旧是全球范围内卖得最好的单一车型，但从财报数据上看，去年却是特斯拉近来过得最惨的一年。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8a2d9840afd447c0a63de9c688cb4045@5091053_oswg202180oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>营收第一次变成了负增长（ -3% ），净利润相比 2024 年暴跌了 46.5% ，利润率也接近腰斩（ 从 7.26% 跌至 4% ）。</p>\\n<p>里头的各种缘由比如美国的关税上涨、补贴取消以及中国的竞争加剧等等就不展开说了，总之对于特斯拉而言，省钱，绝对是眼下最为关键的主线任务。</p>\\n<p>不然，真要保不住老马的天价薪酬了。</p>\\n<p>而在动力电池这个占电车成本最多的部件上，特斯拉已经花了很长时间尝试降低它的造价了。只不过因为目标太高、实力不够等原因，特斯拉自研的 “ 又大又省钱 ” 电池 4680 ，在技术指标和大规模量产上始终没啥进度。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_82f4c7f138c9425daf682c55b1a3a26c@5091053_oswg389093oswg995oswg1024_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>也是因此，如今市面上的特斯拉车型用的也都是来自 LG、宁德时代和松下的动力电池。</p>\\n<p>找供应商买电池的好处，自然是哥几个都是电池行业的老兵，有技术有积淀够靠谱，可以满足特斯拉很高的软硬件要求。</p>\\n<p>但问题是，它们的电池实在是太贵了。</p>\\n<p>就拿宁德时代来说，目前哥们供应着特斯拉中国和欧洲市场的绝大部分磷酸铁锂电池包，从总量上估算，更是占到了特斯拉全球动力电池采购的四到五成，属于是特斯拉目前在电池上的最大靠山了。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_bba6e607fe1349a58afbc18e67c0072a@5091053_oswg480649oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>可就如大伙所知道的那样，找宁德时代买东西，其实并不是一件体验特别好的事。不仅要受着宁王的高姿态，还得说服自己为宁王极高的品牌溢价来买单。</p>\\n<p>是的，就像那句很经典的 “ 车企都在给宁德时代打工 ” 一样，宁王在去年不仅收入创了历史新高，利润率更是达到了 26.27% 。即使单看动力电池部分，它的利润率也达到了 23.84% ，比行业友商们普遍高出了 5-15% 。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dd1b38e46a724ac8b9ddc23fa3e135d5@5091053_oswg185884oswg1080oswg530_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>对其他车企来说，多花些钱买个出货顺利够快、质量够好的安心其实没啥毛病，但对于现在急需省钱的特斯拉来说，这种没有把钱用在刀刃上的情况，属实不太能接受。</p>\\n<p>这时候，就轮到欣旺达上场了。</p>\\n<p>如果说宁德时代是复联里面的托尼·斯塔克，那跟欣旺达最像的肯定就是鹰眼了。没有那么猛，偶尔也会抽抽风，但至少为人和善且实力到位，最重要的是作战装备远不如同僚们费钱。</p>\\n<p>是的，除去和吉利的爱恨情仇之外，欣旺达在车企端的形象其实一直还挺好。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_964b820c21c64670b0e33d4c8c078d9a@5091053_oswg721776oswg1080oswg553_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>作为国内前五（ 正好第五 ）的电池供应商，欣旺达不仅出货量在第二梯队中处在绝对领先的地位，是国内重要的电池供应商之一，近几年也和包括理想、小米、上汽、东风等头部车企建立了合作关系，也算是把口碑打出来了。</p>\\n<p>同时作为二线厂家，欣旺达的姿态比宁王相比低的不是一星半点。只要车企想合作，形式车企选，方向车企定，欣旺达都愿意打配合。</p>\\n<p>甚至有报道说在拿下小米昆仑的供应项目以后，欣旺达直接派了 30-50 个研发人员去到了小米驻场，只要有需求，就可以马上响应。</p>\\n<p>效率高就不说了，情绪价值反正是拉满了对吧。</p>\\n<p>但对特斯拉来说，最重要的肯定还是欣旺达的性价比。从后者最新的半年报，也就是 2025 上半年的财报里可以看到，欣旺达走的完完全全就是薄利多销的路线。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9a9ceb0dc5d24da1b0a0cb0ac1375817@5091053_oswg176712oswg1080oswg519_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>动力电池相关的营业收入同比增长了 22.63% ，但毛利率却比之前下降了 1.89 个百分点，降到了 9.77% ，只有宁王的一半不到，属于是在电池之外分币不挣了。</p>\\n<p>特斯拉一看，我去，知音啊！果断选择了合作。</p>\\n<p>并且根据文章开头的爆料，这回的电池合作形式还和之前略有不同。之前供应商们给特斯拉供应的，大都是封装好的完整的动力电池包。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_12c302c85a854d678e9d132c8382e9fa@5091053_oswg566791oswg800oswg600_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>但这回欣旺达提供的，却只有最基础的锂酸铁锂电芯。</p>\\n<p>剩下的包括电池管理系统、散热和支撑结构、整包封装等等工序，都是特斯拉自己完成。相当于欣旺达是把电池厂能挣钱的部分，又分了一块到特斯拉手里，老马又能省一波。</p>\\n<p>所以看到这大伙应该都看明白了吧，特斯拉之所以会和欣旺达看上对眼，原因其实和之前用比亚迪电池是一样的。</p>\\n<p>一方面，特斯拉想要摆脱对宁德时代的依赖，找到一个更好说话、更加实惠的供应商。另一方面，是欣旺达目前的业务状态可以支持特斯拉提出更多的要求、用比友商更低的利润率帮特斯拉省钱。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a69bfe4c8d944f94bc641d31aa8a9a20@5091053_oswg403665oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>只不过因为有着直接的市场竞争，特斯拉最后中断了和比亚迪的合作。没有类似烦恼的欣旺达，能不能挑战宁王在特链里的地位还咱们还暂时下不了结论。</p>\\n<p>但或许从这件事开始，人们对欣旺达的评价，可以变得不再那么负面了呢？</p>\\n<p><strong>图片、资料来源</strong>：</p>\\n<p>欣旺达&amp;理想汽车迎来100000台电池包下线里程碑时刻！ 欣旺达-用心做好每一块电池</p>\\n<p>特斯拉（上海）有限公司召回部分国产Model Y电动汽车</p>\\n<p>拓普集团回应特斯拉召回事件：产品有缺陷 不影响业绩</p>\\n<p>2025 Q4 Quarterly Update Deck assets-ir.tesla.com</p>\\n<p>欣旺达装车特斯拉，供应全球车型｜36氪独家</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/irOvB4Dsb7A58uDf5q7JVw\\\">“差评X.PIN”</a>，作者：致命空枪，编辑：脖子右拧，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'为了省钱，特斯拉开始用欣旺达电池了\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'为了省钱，特斯拉开始用欣旺达电池了\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768706892301059?f=rss\'}], \'link\': \'https://36kr.com/p/3768706892301059?f=rss\', \'published\': \'2026-04-16 10:01:48  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=1, tm_sec=48, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>大众合作小鹏，斯特兰蒂斯投资零跑，这种海外巨头携手国内小厂的故事，终究还是从整车制造领域吹到了供应商的头上。</p>\\\\n  <p>几天前，欣旺达 —— 这个此前被吉利控诉质量有问题的电池厂商，股价迎来了一波飙升。</p>\\\\n  <p>因为根据 36Kr 的报道，欣旺达现在已经进入了特斯拉的供应体系，给上海工厂卖去欧洲的车型提供动力电池。并且，现在已经小批量上车了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_cea75df3058144889152777088e878df@5091053_oswg806531oswg1080oswg567_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>消息一出，不只是欣旺达的股价应声飙高了接近 20% ，人们对欣旺达的态度也是来了波 180 度大反转。</p>\\\\n  <p>“ 不是小伙子，你怎么还有两副面孔呢？ ”</p>\\\\n  <p>毕竟在宁德时代的口碑统治下，欣旺达这两年好像都是以不太靠谱的形象在国内示人的。先是极氪因为质量缺陷对欣旺达发起了 23.14 亿的索赔，然后又是用了欣旺达电池的沃尔沃 EX30 ，因为过热风险在海外发起了召回。</p>\\\\n  <p>虽说一直没有明确证据表明欣旺达到底是哪里有问题，但在负面发酵以后，各大社交平台上，甚至已经出现 “ 用了欣旺达电池的车不敢买 ”，这种十分严重的负面帖子了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4909695d015340ec8996c1df128bca06@5091053_oswg299522oswg1080oswg1111_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>然而反观特斯拉这头，对于供应链企业可是出了名的要求高，经常因为很小的故障率就召回一大批车型。</p>\\\\n  <p>有时候，甚至还会在公告里点名骂供应商 —— 比如当年召回 2 万多台国产 Model Y 的时候，就点名了拓普的转向节有 0.2~1% 的缺陷概率。</p>\\\\n  <p>能在动力电池这个最关键的部件上满足特斯拉的要求，欣旺达多少也是有些过硬的底子在的。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_cef459764e754e52a0e55d12a4fe7169@5091053_oswg193089oswg1080oswg664_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>当然，今天我想跟哥几个聊的也不是欣旺达到底靠不靠谱。</p>\\\\n  <p>毕竟车企招标的技术要求、欣旺达被起诉的技术细节还有特斯拉内部的质量控制体系几乎都是高度保密的水平，一般人不知道，知道的人也不会说。</p>\\\\n  <p>我想说的，其实是特斯拉为什么会在这个时间点，看上欣旺达这个新队友。</p>\\\\n  <p>去年也就是 2025 年，虽然 Model Y 依旧是全球范围内卖得最好的单一车型，但从财报数据上看，去年却是特斯拉近来过得最惨的一年。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8a2d9840afd447c0a63de9c688cb4045@5091053_oswg202180oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>营收第一次变成了负增长（ -3% ），净利润相比 2024 年暴跌了 46.5% ，利润率也接近腰斩（ 从 7.26% 跌至 4% ）。</p>\\\\n  <p>里头的各种缘由比如美国的关税上涨、补贴取消以及中国的竞争加剧等等就不展开说了，总之对于特斯拉而言，省钱，绝对是眼下最为关键的主线任务。</p>\\\\n  <p>不然，真要保不住老马的天价薪酬了。</p>\\\\n  <p>而在动力电池这个占电车成本最多的部件上，特斯拉已经花了很长时间尝试降低它的造价了。只不过因为目标太高、实力不够等原因，特斯拉自研的 “ 又大又省钱 ” 电池 4680 ，在技术指标和大规模量产上始终没啥进度。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_82f4c7f138c9425daf682c55b1a3a26c@5091053_oswg389093oswg995oswg1024_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>也是因此，如今市面上的特斯拉车型用的也都是来自 LG、宁德时代和松下的动力电池。</p>\\\\n  <p>找供应商买电池的好处，自然是哥几个都是电池行业的老兵，有技术有积淀够靠谱，可以满足特斯拉很高的软硬件要求。</p>\\\\n  <p>但问题是，它们的电池实在是太贵了。</p>\\\\n  <p>就拿宁德时代来说，目前哥们供应着特斯拉中国和欧洲市场的绝大部分磷酸铁锂电池包，从总量上估算，更是占到了特斯拉全球动力电池采购的四到五成，属于是特斯拉目前在电池上的最大靠山了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_bba6e607fe1349a58afbc18e67c0072a@5091053_oswg480649oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>可就如大伙所知道的那样，找宁德时代买东西，其实并不是一件体验特别好的事。不仅要受着宁王的高姿态，还得说服自己为宁王极高的品牌溢价来买单。</p>\\\\n  <p>是的，就像那句很经典的 “ 车企都在给宁德时代打工 ” 一样，宁王在去年不仅收入创了历史新高，利润率更是达到了 26.27% 。即使单看动力电池部分，它的利润率也达到了 23.84% ，比行业友商们普遍高出了 5-15% 。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dd1b38e46a724ac8b9ddc23fa3e135d5@5091053_oswg185884oswg1080oswg530_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>对其他车企来说，多花些钱买个出货顺利够快、质量够好的安心其实没啥毛病，但对于现在急需省钱的特斯拉来说，这种没有把钱用在刀刃上的情况，属实不太能接受。</p>\\\\n  <p>这时候，就轮到欣旺达上场了。</p>\\\\n  <p>如果说宁德时代是复联里面的托尼·斯塔克，那跟欣旺达最像的肯定就是鹰眼了。没有那么猛，偶尔也会抽抽风，但至少为人和善且实力到位，最重要的是作战装备远不如同僚们费钱。</p>\\\\n  <p>是的，除去和吉利的爱恨情仇之外，欣旺达在车企端的形象其实一直还挺好。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_964b820c21c64670b0e33d4c8c078d9a@5091053_oswg721776oswg1080oswg553_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>作为国内前五（ 正好第五 ）的电池供应商，欣旺达不仅出货量在第二梯队中处在绝对领先的地位，是国内重要的电池供应商之一，近几年也和包括理想、小米、上汽、东风等头部车企建立了合作关系，也算是把口碑打出来了。</p>\\\\n  <p>同时作为二线厂家，欣旺达的姿态比宁王相比低的不是一星半点。只要车企想合作，形式车企选，方向车企定，欣旺达都愿意打配合。</p>\\\\n  <p>甚至有报道说在拿下小米昆仑的供应项目以后，欣旺达直接派了 30-50 个研发人员去到了小米驻场，只要有需求，就可以马上响应。</p>\\\\n  <p>效率高就不说了，情绪价值反正是拉满了对吧。</p>\\\\n  <p>但对特斯拉来说，最重要的肯定还是欣旺达的性价比。从后者最新的半年报，也就是 2025 上半年的财报里可以看到，欣旺达走的完完全全就是薄利多销的路线。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9a9ceb0dc5d24da1b0a0cb0ac1375817@5091053_oswg176712oswg1080oswg519_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>动力电池相关的营业收入同比增长了 22.63% ，但毛利率却比之前下降了 1.89 个百分点，降到了 9.77% ，只有宁王的一半不到，属于是在电池之外分币不挣了。</p>\\\\n  <p>特斯拉一看，我去，知音啊！果断选择了合作。</p>\\\\n  <p>并且根据文章开头的爆料，这回的电池合作形式还和之前略有不同。之前供应商们给特斯拉供应的，大都是封装好的完整的动力电池包。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_12c302c85a854d678e9d132c8382e9fa@5091053_oswg566791oswg800oswg600_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>但这回欣旺达提供的，却只有最基础的锂酸铁锂电芯。</p>\\\\n  <p>剩下的包括电池管理系统、散热和支撑结构、整包封装等等工序，都是特斯拉自己完成。相当于欣旺达是把电池厂能挣钱的部分，又分了一块到特斯拉手里，老马又能省一波。</p>\\\\n  <p>所以看到这大伙应该都看明白了吧，特斯拉之所以会和欣旺达看上对眼，原因其实和之前用比亚迪电池是一样的。</p>\\\\n  <p>一方面，特斯拉想要摆脱对宁德时代的依赖，找到一个更好说话、更加实惠的供应商。另一方面，是欣旺达目前的业务状态可以支持特斯拉提出更多的要求、用比友商更低的利润率帮特斯拉省钱。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a69bfe4c8d944f94bc641d31aa8a9a20@5091053_oswg403665oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>只不过因为有着直接的市场竞争，特斯拉最后中断了和比亚迪的合作。没有类似烦恼的欣旺达，能不能挑战宁王在特链里的地位还咱们还暂时下不了结论。</p>\\\\n  <p>但或许从这件事开始，人们对欣旺达的评价，可以变得不再那么负面了呢？</p>\\\\n  <p><strong>图片、资料来源</strong>：</p>\\\\n  <p>欣旺达&amp;理想汽车迎来100000台电池包下线里程碑时刻！ 欣旺达-用心做好每一块电池</p>\\\\n  <p>特斯拉（上海）有限公司召回部分国产Model Y电动汽车</p>\\\\n  <p>拓普集团回应特斯拉召回事件：产品有缺陷 不影响业绩</p>\\\\n  <p>2025 Q4 Quarterly Update Deck assets-ir.tesla.com</p>\\\\n  <p>欣旺达装车特斯拉，供应全球车型｜36氪独家</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/irOvB4Dsb7A58uDf5q7JVw\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“差评X.PIN”</a>，作者：致命空枪，编辑：脖子右拧，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>大众合作小鹏，斯特兰蒂斯投资零跑，这种海外巨头携手国内小厂的故事，终究还是从整车制造领域吹到了供应商的头上。</p>\\\\n  <p>几天前，欣旺达 —— 这个此前被吉利控诉质量有问题的电池厂商，股价迎来了一波飙升。</p>\\\\n  <p>因为根据 36Kr 的报道，欣旺达现在已经进入了特斯拉的供应体系，给上海工厂卖去欧洲的车型提供动力电池。并且，现在已经小批量上车了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_cea75df3058144889152777088e878df@5091053_oswg806531oswg1080oswg567_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>消息一出，不只是欣旺达的股价应声飙高了接近 20% ，人们对欣旺达的态度也是来了波 180 度大反转。</p>\\\\n  <p>“ 不是小伙子，你怎么还有两副面孔呢？ ”</p>\\\\n  <p>毕竟在宁德时代的口碑统治下，欣旺达这两年好像都是以不太靠谱的形象在国内示人的。先是极氪因为质量缺陷对欣旺达发起了 23.14 亿的索赔，然后又是用了欣旺达电池的沃尔沃 EX30 ，因为过热风险在海外发起了召回。</p>\\\\n  <p>虽说一直没有明确证据表明欣旺达到底是哪里有问题，但在负面发酵以后，各大社交平台上，甚至已经出现 “ 用了欣旺达电池的车不敢买 ”，这种十分严重的负面帖子了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4909695d015340ec8996c1df128bca06@5091053_oswg299522oswg1080oswg1111_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>然而反观特斯拉这头，对于供应链企业可是出了名的要求高，经常因为很小的故障率就召回一大批车型。</p>\\\\n  <p>有时候，甚至还会在公告里点名骂供应商 —— 比如当年召回 2 万多台国产 Model Y 的时候，就点名了拓普的转向节有 0.2~1% 的缺陷概率。</p>\\\\n  <p>能在动力电池这个最关键的部件上满足特斯拉的要求，欣旺达多少也是有些过硬的底子在的。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_cef459764e754e52a0e55d12a4fe7169@5091053_oswg193089oswg1080oswg664_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>当然，今天我想跟哥几个聊的也不是欣旺达到底靠不靠谱。</p>\\\\n  <p>毕竟车企招标的技术要求、欣旺达被起诉的技术细节还有特斯拉内部的质量控制体系几乎都是高度保密的水平，一般人不知道，知道的人也不会说。</p>\\\\n  <p>我想说的，其实是特斯拉为什么会在这个时间点，看上欣旺达这个新队友。</p>\\\\n  <p>去年也就是 2025 年，虽然 Model Y 依旧是全球范围内卖得最好的单一车型，但从财报数据上看，去年却是特斯拉近来过得最惨的一年。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8a2d9840afd447c0a63de9c688cb4045@5091053_oswg202180oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>营收第一次变成了负增长（ -3% ），净利润相比 2024 年暴跌了 46.5% ，利润率也接近腰斩（ 从 7.26% 跌至 4% ）。</p>\\\\n  <p>里头的各种缘由比如美国的关税上涨、补贴取消以及中国的竞争加剧等等就不展开说了，总之对于特斯拉而言，省钱，绝对是眼下最为关键的主线任务。</p>\\\\n  <p>不然，真要保不住老马的天价薪酬了。</p>\\\\n  <p>而在动力电池这个占电车成本最多的部件上，特斯拉已经花了很长时间尝试降低它的造价了。只不过因为目标太高、实力不够等原因，特斯拉自研的 “ 又大又省钱 ” 电池 4680 ，在技术指标和大规模量产上始终没啥进度。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_82f4c7f138c9425daf682c55b1a3a26c@5091053_oswg389093oswg995oswg1024_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>也是因此，如今市面上的特斯拉车型用的也都是来自 LG、宁德时代和松下的动力电池。</p>\\\\n  <p>找供应商买电池的好处，自然是哥几个都是电池行业的老兵，有技术有积淀够靠谱，可以满足特斯拉很高的软硬件要求。</p>\\\\n  <p>但问题是，它们的电池实在是太贵了。</p>\\\\n  <p>就拿宁德时代来说，目前哥们供应着特斯拉中国和欧洲市场的绝大部分磷酸铁锂电池包，从总量上估算，更是占到了特斯拉全球动力电池采购的四到五成，属于是特斯拉目前在电池上的最大靠山了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_bba6e607fe1349a58afbc18e67c0072a@5091053_oswg480649oswg1080oswg562_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>可就如大伙所知道的那样，找宁德时代买东西，其实并不是一件体验特别好的事。不仅要受着宁王的高姿态，还得说服自己为宁王极高的品牌溢价来买单。</p>\\\\n  <p>是的，就像那句很经典的 “ 车企都在给宁德时代打工 ” 一样，宁王在去年不仅收入创了历史新高，利润率更是达到了 26.27% 。即使单看动力电池部分，它的利润率也达到了 23.84% ，比行业友商们普遍高出了 5-15% 。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dd1b38e46a724ac8b9ddc23fa3e135d5@5091053_oswg185884oswg1080oswg530_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>对其他车企来说，多花些钱买个出货顺利够快、质量够好的安心其实没啥毛病，但对于现在急需省钱的特斯拉来说，这种没有把钱用在刀刃上的情况，属实不太能接受。</p>\\\\n  <p>这时候，就轮到欣旺达上场了。</p>\\\\n  <p>如果说宁德时代是复联里面的托尼·斯塔克，那跟欣旺达最像的肯定就是鹰眼了。没有那么猛，偶尔也会抽抽风，但至少为人和善且实力到位，最重要的是作战装备远不如同僚们费钱。</p>\\\\n  <p>是的，除去和吉利的爱恨情仇之外，欣旺达在车企端的形象其实一直还挺好。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_964b820c21c64670b0e33d4c8c078d9a@5091053_oswg721776oswg1080oswg553_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>作为国内前五（ 正好第五 ）的电池供应商，欣旺达不仅出货量在第二梯队中处在绝对领先的地位，是国内重要的电池供应商之一，近几年也和包括理想、小米、上汽、东风等头部车企建立了合作关系，也算是把口碑打出来了。</p>\\\\n  <p>同时作为二线厂家，欣旺达的姿态比宁王相比低的不是一星半点。只要车企想合作，形式车企选，方向车企定，欣旺达都愿意打配合。</p>\\\\n  <p>甚至有报道说在拿下小米昆仑的供应项目以后，欣旺达直接派了 30-50 个研发人员去到了小米驻场，只要有需求，就可以马上响应。</p>\\\\n  <p>效率高就不说了，情绪价值反正是拉满了对吧。</p>\\\\n  <p>但对特斯拉来说，最重要的肯定还是欣旺达的性价比。从后者最新的半年报，也就是 2025 上半年的财报里可以看到，欣旺达走的完完全全就是薄利多销的路线。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9a9ceb0dc5d24da1b0a0cb0ac1375817@5091053_oswg176712oswg1080oswg519_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>动力电池相关的营业收入同比增长了 22.63% ，但毛利率却比之前下降了 1.89 个百分点，降到了 9.77% ，只有宁王的一半不到，属于是在电池之外分币不挣了。</p>\\\\n  <p>特斯拉一看，我去，知音啊！果断选择了合作。</p>\\\\n  <p>并且根据文章开头的爆料，这回的电池合作形式还和之前略有不同。之前供应商们给特斯拉供应的，大都是封装好的完整的动力电池包。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_12c302c85a854d678e9d132c8382e9fa@5091053_oswg566791oswg800oswg600_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>但这回欣旺达提供的，却只有最基础的锂酸铁锂电芯。</p>\\\\n  <p>剩下的包括电池管理系统、散热和支撑结构、整包封装等等工序，都是特斯拉自己完成。相当于欣旺达是把电池厂能挣钱的部分，又分了一块到特斯拉手里，老马又能省一波。</p>\\\\n  <p>所以看到这大伙应该都看明白了吧，特斯拉之所以会和欣旺达看上对眼，原因其实和之前用比亚迪电池是一样的。</p>\\\\n  <p>一方面，特斯拉想要摆脱对宁德时代的依赖，找到一个更好说话、更加实惠的供应商。另一方面，是欣旺达目前的业务状态可以支持特斯拉提出更多的要求、用比友商更低的利润率帮特斯拉省钱。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a69bfe4c8d944f94bc641d31aa8a9a20@5091053_oswg403665oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>只不过因为有着直接的市场竞争，特斯拉最后中断了和比亚迪的合作。没有类似烦恼的欣旺达，能不能挑战宁王在特链里的地位还咱们还暂时下不了结论。</p>\\\\n  <p>但或许从这件事开始，人们对欣旺达的评价，可以变得不再那么负面了呢？</p>\\\\n  <p><strong>图片、资料来源</strong>：</p>\\\\n  <p>欣旺达&amp;理想汽车迎来100000台电池包下线里程碑时刻！ 欣旺达-用心做好每一块电池</p>\\\\n  <p>特斯拉（上海）有限公司召回部分国产Model Y电动汽车</p>\\\\n  <p>拓普集团回应特斯拉召回事件：产品有缺陷 不影响业绩</p>\\\\n  <p>2025 Q4 Quarterly Update Deck assets-ir.tesla.com</p>\\\\n  <p>欣旺达装车特斯拉，供应全球车型｜36氪独家</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/irOvB4Dsb7A58uDf5q7JVw\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“差评X.PIN”</a>，作者：致命空枪，编辑：脖子右拧，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'差评\'}], \'author\': \'差评\', \'author_detail\': {\'name\': \'差评\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'两极反转！\'}]}\", \"published_at\": \"2026-04-16 10:01:48\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 10:01:48', '2026-04-16 11:45:42');
INSERT INTO `news_detail` VALUES (20, 979, 6, '科技与数字服务', '要做电商Agent OS，前钉钉最年轻副总裁创立的「攀峰智能」再次完成数千万天使轮融资', '', '<p><strong>文｜王欣逸</strong></p>\n<p><strong>编辑｜邓咏仪</strong></p>\n<p>36氪获悉，近日，攀峰智能已完成数千万元天使轮融资，本轮融资由华控资本领投、云时资本跟投，将用于模型研发、团队增长以及市场扩张。</p>\n<p>攀峰智能（K2 Lab）成立于2025年10月，成立仅一个月，便拿到了来自云时资本的数千万元融资。其三位联合创始人均来自阿里钉钉团队。CEO王铭曾是钉钉最年轻的副总裁，在钉钉近五年间负责AI创新产品、SaaS生态、大模型与AI生态、产业生态和战略终端等业务；联合创始人兼CSO汤明磊，此前深耕产业数字化和产业AI的投资与研究十年，在钉钉期间负责战略生态和投资；联合创始人兼CTO赵先烈，曾任钉钉AI PaaS及AI运营负责人。</p>\n<p>攀峰智能面向To C市场，打造了一个内容电商场景的Agent OS——Moras。Moras为TikTok上的达人和商家服务——用户只需通过和Moras互动，它便能实现自动化学习，完成选品推荐、脚本生成、内容创作、智能剪辑、视频预检和发布、数据分析等环节，实现出单。</p>\n<p>目前，Moras的用户画像主要为粉丝体量在五千至五万的达人和商家群体，带货品类涵盖服装、生活用品、家居、节日用品等。</p>\n<p>过去三个月，Moras已完成了首批达人用户的共创测试。邀测用户数据显示，活跃达人通过使用Moras平均月度成交GMV接近1万美元，有达人实现了月度GMV突破10万美金的成绩。</p>\n<p>从具体数据来看，有达人实现了注册首周GMV破万美元，使用Moras的首周出单率已经达到了70%以上，而这一时间还在继续变快。</p>\n<p>Moras采用的是Multi-Agent架构，能实现自主进化。随着达人互动频次的增加，这一工具的选品、脚本、分析等能力会逐渐增强，出单能力也随之提高。</p>\n<p>而受OpenClaw和Claude Code的Agent能力启发，攀峰智能如今也在快速革新，已着手建立起A2A原生电商操作系统，来服务更广泛的客群。</p>\n<h3>“人类不想in the loop”</h3>\n<p>在邀测阶段，攀峰智能发现海外用户对操作流程的容忍度远比预期更低——哪怕只是多一步确认，用户也倾向于放弃。</p>\n<p>“人类不想in the loop。”王铭说。在王铭看来，目前阶段，AI还没有替代人的能力，但AI能把人的短板补齐，把人的长板超级放大。</p>\n<p>Moras产品最初的测试版本设计的比较简单，尽管如此，海外的用户依然觉得很复杂，这也让他们意识到另一种商业模式的可能：AI“雇佣”人类。</p>\n<p>成立之初，Moras设计了两种提供服务的方式，原意也是想测试哪一种更适合市场：</p>\n<p>第一种是用户为Moras付底薪，让Moras起协助作用，如调整选品、制作视频等，即<strong>人类雇佣AI</strong>，这种方式平台会抽成50%。</p>\n<p>第二种则是Moras完全托管，包括账号资产、形象等，AI完全帮助用户做内容、带货，即<strong>AI“雇佣”人类</strong>。在这种模式下，用户只能拿到极低比例的分成收益。</p>\n<p>在邀测阶段，攀峰智能将两种模式同步测试，有意思的是，选择第二种商业模式的用户越来越多。<strong>这意味着，在这一场景下，Agent能力越来越强，Human反而不想in the loop（人类不想参与决策）。</strong></p>\n<p>“但人类不想in the loop，并不意味着AI可以完全脱离人类。”王铭说，在实际使用过程中，达人和商家授权登录Moras后，平台会通过多模态理解分析粉丝画像、过往视频的用户画像和视频调性，来推送个性化的选品。其中，达人和商家仍然拥有对选品、文案、视频的倾向性，可以对内容进行审核、修改调整。</p>\n<p>王铭告诉《智能涌现》，Moras正在灰度测试另一个版本，达人和商家可以直接和平台对话，告诉Moras个性化的风格、审美和表达方式等。未来可能还会上线更复杂的PC端操作系统，支持用户上传专业知识和Skills等。</p>\n<p>坦白来讲，Moras目前有60分的带货能力，这或许能让它帮达人实现几千到一两万美元的月度营收，但离稳定输出大几万美元的能力还有一段距离。</p>\n<p>对于Agent而言，“活人感”“网感”等独特的表达方式和销售能力很重要，要实现这些能力，还需要大量和人类的连接——这也是攀峰智能正在自研电商场景多模态理解模型的原因。</p>\n<p>而在内容电商场景中，理解什么是爆款、理解用户的风格和审美，远比生成本身更关键。</p>\n<p>王铭认为，AI雇佣人类的结果会是，人类发现AI真的能赚钱，随即被带入行业之中来，对Moras提出更多诉求，同时也参与到创收的更多环节中来。</p>\n<p>为了让产品离钱更近，王铭还透露，Moras正在<strong>训练一个自研的电商场景的多模态理解模型</strong>。</p>\n<p>在他看来，通用模型更多的是优化生成能力，忽略了理解世界的能力，本质上还是在批发Token。如果产品只是在帮助用户更低门槛消耗Token，而不是帮助用户提高效果，最后作为批发商，Token的ROI大概率很低。</p>\n<p>这也反映了攀峰智能路线的本质不同：选择了做离商业化更近的事情——自研爆款理解模型、爆款商品和爆款脚本，从最开始就专注于效果的打磨，让模型理解爆款的逻辑。</p>\n<p>王铭表示，当前攀峰的团队中，有来自字节的多位内容电商专家，将专家的最佳实践让AI学会后，由AI来做选品模型；人类专家则变成AI的数据标注员，判断AI选出来的商品，哪些是真正的爆款。与此同时，所有发出去的内容的数据结果会回流到分析Agent，再反馈给前面的选品模型，形成自进化闭环。</p>\n<p><strong>用户愿意付费，产品能带来盈利，Token本身价值随之提高</strong>，这就形成一套“ROI Token 经济学”。</p>\n<p>而对于大厂的竞争，王铭表示，目前，大厂的第一优先级仍是抢夺AI入口，AI+电商的垂直场景尚未进入其核心视野，这也正是中小企业切入垂直场景的窗口期。</p>\n<h3>自建Personal AI系统</h3>\n<p>今年初，OpenClaw横空出世，其架构由Channel层（通道层）、Agent层（智能体层）和Tools层（工具层）组成，实现了一个完整的AI操作系统，迅速引发了行业对Agent OS的广泛讨论。</p>\n<p>这给攀峰智能的产品带来了新的启发。王铭表示，团队也尝试过基于OpenClaw进行开发，但发现其现阶段还无法达到稳定的企业级使用标准，基于OpenClaw做简单二开的产品，短期内仍难以真正落地。</p>\n<p>攀峰智能并没有走把所有产品基于OpenClaw架构重构的路线，而是借鉴了类似OpenClaw、Claude Code、Hermes Agent等架构的设计思想——包括多层记忆架构、做梦机制等——自己开发完整的Agent OS。具体来说，他们想<strong>把内容平台生态的超级个体和商家的Context信息Agent化，整合接入，形成达人和商家的“Agent OS”</strong>，用一个扎实的OS系统来服务好客户群体。</p>\n<p>在王铭的构想中，Personal AI的Memory做好了，A2A（Agent to Agent）的世界才会出现。目前，用户使用ChatGPT、Gemini、豆包等中心化AI助手时，不仅需要多平台切换，不同平台给出的答案可能还会出现冲突，且记忆无法跨平台沉淀。</p>\n<p>倘若一个系统中不同模型能被自动调用，生成结果可以被自动做对比和整合，并持续积累历史上下文，用户的体验将会发生质变。</p>\n<p>“未来，每个人可能都会拥有这样一个消费级的通用Personal AI（个人AI）助手，也会拥有一批垂直场景的Agent OS。”王铭解释，Personal AI的系统能支持用户自由调度模型、用自然语言添加Skills、拥有长期的个人记忆等功能。用户能够更好地使用产品，也才能更好地被留在平台上。</p>\n<p>基于这样的判断，攀峰智能对其产品作出了方向调整——要帮达人和商家建立属于自己的Agent OS，进而自建Personal AI系统。</p>\n<p>未来，攀峰智能计划将产品作为Skill接入到OpenClaw、Hermes Agent等去中心化的Personal AI生态中，相当于把一批商家和达人的数字分身直接带到下一个时代的流量入口里去。</p>\n<p>王铭认为，Personal AI系统的不断完善，正是实现 A2A 的重要基础。从更近的目标而言，Personal AI的下一步，是实现真正的A2A（Agent to Agent）的商业系统。</p>\n<h3>用Agent开发Agent</h3>\n<p>除了产品方向的变化之外，攀峰智能的开发范式也在经历剧烈的重构。</p>\n<p>尽管公司才成立数月，但他们已经经历了3个阶段的开发范式演进：第一阶段是AI Coding几乎没有约束，什么都交给AI去做，结果各种bug的速度让人改不过来；第二阶段是引入rules和结构化约束，借鉴了Harness的思想以及Claude Code泄露出的架构，用更多的条条框框去驾驭Agent；第三阶段则是通过通过自研的开发Agent调用Coding来开发Agent，最后交给人类做验收。</p>\n<p>王铭表示，目前公司99%以上的代码都是由AI编写，甚至很多开发工作不是由程序员完成的——产品经理、人力资源、财务、运营同学都在开发系统。而在最新的阶段，他们开发了专门的Coding Agent，能够在某个垂直场景里持续地帮助开发和迭代，周末团队休息时，Agent还在工作。</p>\n<p>随之而来的，生产力正在指数级提升。一个原来需要两周实现的复杂需求，开发时长能缩短至1天。</p>\n<p>毫无疑问，大模型的发展速度，仍然是跳脱于人类想象的。对接下来的Agent技术曲线演进，王铭分享了他对于今年Agent发展的三个判断：其一，Agent的Memory会有巨大突破；其二，Multi-Agent自主进化能力会日趋成熟；其三，Agent自己Coding出各种工具，来解决响应问题。千人千面个性化产品的时代快速到来。</p>\n<p>对于未来发展计划，团队透露，下半年攀峰智能将持续扩张团队至50人以上，并加速打造Agent OS系统。随着产品全量上线，公司也将进入快速市场扩张期，同时着手搭建Agent化的供应链体系，抢跑A2A原生电商。</p>', 'https://36kr.com/p/3768320373441281?f=rss', 0, '', '{\"summary\": \"本文为出海布局TikTok内容电商的商家、达人披露了AI自动化带货工具的创业进展，可参考AI赋能跨境电商的创新模式\", \"abstract\": \"前钉钉核心团队创立的攀峰智能近日完成数千万元天使轮融资，资金将用于模型研发、团队扩张与市场拓展。该公司打造了面向TikTok内容电商场景的AI Agent OS产品Moras，可帮助中小达人商家自动化完成选品、内容创作、发布、数据分析等全带货流程。内测数据显示，活跃达人使用后平均月度GMV接近1万美元，多数用户更偏好AI全托管的“AI雇佣人类”创新模式。目前攀峰智能正自研电商场景多模态理解模型，计划下半年加速产品落地，抢跑A2A原生电商赛道。\", \"keywords\": [\"Agent OS\", \"攀峰智能\", \"天使轮融资\", \"内容电商\", \"TikTok\", \"跨境电商\", \"多模态模型\", \"A2A\", \"AI带货\"], \"policy_risk\": {\"market_risk\": \"当前产品带货能力尚未成熟，离稳定高产出仍有差距，未来大厂可能切入该AI+跨境电商垂直赛道，存在市场竞争风险\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外营销\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"https://36kr.com/p/3768320373441281?f=rss\", \"title\": \"要做电商Agent OS，前钉钉最年轻副总裁创立的「攀峰智能」再次完成数千万天使轮融资\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p><strong>文｜王欣逸</strong></p>\\n<p><strong>编辑｜邓咏仪</strong></p>\\n<p>36氪获悉，近日，攀峰智能已完成数千万元天使轮融资，本轮融资由华控资本领投、云时资本跟投，将用于模型研发、团队增长以及市场扩张。</p>\\n<p>攀峰智能（K2 Lab）成立于2025年10月，成立仅一个月，便拿到了来自云时资本的数千万元融资。其三位联合创始人均来自阿里钉钉团队。CEO王铭曾是钉钉最年轻的副总裁，在钉钉近五年间负责AI创新产品、SaaS生态、大模型与AI生态、产业生态和战略终端等业务；联合创始人兼CSO汤明磊，此前深耕产业数字化和产业AI的投资与研究十年，在钉钉期间负责战略生态和投资；联合创始人兼CTO赵先烈，曾任钉钉AI PaaS及AI运营负责人。</p>\\n<p>攀峰智能面向To C市场，打造了一个内容电商场景的Agent OS——Moras。Moras为TikTok上的达人和商家服务——用户只需通过和Moras互动，它便能实现自动化学习，完成选品推荐、脚本生成、内容创作、智能剪辑、视频预检和发布、数据分析等环节，实现出单。</p>\\n<p>目前，Moras的用户画像主要为粉丝体量在五千至五万的达人和商家群体，带货品类涵盖服装、生活用品、家居、节日用品等。</p>\\n<p>过去三个月，Moras已完成了首批达人用户的共创测试。邀测用户数据显示，活跃达人通过使用Moras平均月度成交GMV接近1万美元，有达人实现了月度GMV突破10万美金的成绩。</p>\\n<p>从具体数据来看，有达人实现了注册首周GMV破万美元，使用Moras的首周出单率已经达到了70%以上，而这一时间还在继续变快。</p>\\n<p>Moras采用的是Multi-Agent架构，能实现自主进化。随着达人互动频次的增加，这一工具的选品、脚本、分析等能力会逐渐增强，出单能力也随之提高。</p>\\n<p>而受OpenClaw和Claude Code的Agent能力启发，攀峰智能如今也在快速革新，已着手建立起A2A原生电商操作系统，来服务更广泛的客群。</p>\\n<h3>“人类不想in the loop”</h3>\\n<p>在邀测阶段，攀峰智能发现海外用户对操作流程的容忍度远比预期更低——哪怕只是多一步确认，用户也倾向于放弃。</p>\\n<p>“人类不想in the loop。”王铭说。在王铭看来，目前阶段，AI还没有替代人的能力，但AI能把人的短板补齐，把人的长板超级放大。</p>\\n<p>Moras产品最初的测试版本设计的比较简单，尽管如此，海外的用户依然觉得很复杂，这也让他们意识到另一种商业模式的可能：AI“雇佣”人类。</p>\\n<p>成立之初，Moras设计了两种提供服务的方式，原意也是想测试哪一种更适合市场：</p>\\n<p>第一种是用户为Moras付底薪，让Moras起协助作用，如调整选品、制作视频等，即<strong>人类雇佣AI</strong>，这种方式平台会抽成50%。</p>\\n<p>第二种则是Moras完全托管，包括账号资产、形象等，AI完全帮助用户做内容、带货，即<strong>AI“雇佣”人类</strong>。在这种模式下，用户只能拿到极低比例的分成收益。</p>\\n<p>在邀测阶段，攀峰智能将两种模式同步测试，有意思的是，选择第二种商业模式的用户越来越多。<strong>这意味着，在这一场景下，Agent能力越来越强，Human反而不想in the loop（人类不想参与决策）。</strong></p>\\n<p>“但人类不想in the loop，并不意味着AI可以完全脱离人类。”王铭说，在实际使用过程中，达人和商家授权登录Moras后，平台会通过多模态理解分析粉丝画像、过往视频的用户画像和视频调性，来推送个性化的选品。其中，达人和商家仍然拥有对选品、文案、视频的倾向性，可以对内容进行审核、修改调整。</p>\\n<p>王铭告诉《智能涌现》，Moras正在灰度测试另一个版本，达人和商家可以直接和平台对话，告诉Moras个性化的风格、审美和表达方式等。未来可能还会上线更复杂的PC端操作系统，支持用户上传专业知识和Skills等。</p>\\n<p>坦白来讲，Moras目前有60分的带货能力，这或许能让它帮达人实现几千到一两万美元的月度营收，但离稳定输出大几万美元的能力还有一段距离。</p>\\n<p>对于Agent而言，“活人感”“网感”等独特的表达方式和销售能力很重要，要实现这些能力，还需要大量和人类的连接——这也是攀峰智能正在自研电商场景多模态理解模型的原因。</p>\\n<p>而在内容电商场景中，理解什么是爆款、理解用户的风格和审美，远比生成本身更关键。</p>\\n<p>王铭认为，AI雇佣人类的结果会是，人类发现AI真的能赚钱，随即被带入行业之中来，对Moras提出更多诉求，同时也参与到创收的更多环节中来。</p>\\n<p>为了让产品离钱更近，王铭还透露，Moras正在<strong>训练一个自研的电商场景的多模态理解模型</strong>。</p>\\n<p>在他看来，通用模型更多的是优化生成能力，忽略了理解世界的能力，本质上还是在批发Token。如果产品只是在帮助用户更低门槛消耗Token，而不是帮助用户提高效果，最后作为批发商，Token的ROI大概率很低。</p>\\n<p>这也反映了攀峰智能路线的本质不同：选择了做离商业化更近的事情——自研爆款理解模型、爆款商品和爆款脚本，从最开始就专注于效果的打磨，让模型理解爆款的逻辑。</p>\\n<p>王铭表示，当前攀峰的团队中，有来自字节的多位内容电商专家，将专家的最佳实践让AI学会后，由AI来做选品模型；人类专家则变成AI的数据标注员，判断AI选出来的商品，哪些是真正的爆款。与此同时，所有发出去的内容的数据结果会回流到分析Agent，再反馈给前面的选品模型，形成自进化闭环。</p>\\n<p><strong>用户愿意付费，产品能带来盈利，Token本身价值随之提高</strong>，这就形成一套“ROI Token 经济学”。</p>\\n<p>而对于大厂的竞争，王铭表示，目前，大厂的第一优先级仍是抢夺AI入口，AI+电商的垂直场景尚未进入其核心视野，这也正是中小企业切入垂直场景的窗口期。</p>\\n<h3>自建Personal AI系统</h3>\\n<p>今年初，OpenClaw横空出世，其架构由Channel层（通道层）、Agent层（智能体层）和Tools层（工具层）组成，实现了一个完整的AI操作系统，迅速引发了行业对Agent OS的广泛讨论。</p>\\n<p>这给攀峰智能的产品带来了新的启发。王铭表示，团队也尝试过基于OpenClaw进行开发，但发现其现阶段还无法达到稳定的企业级使用标准，基于OpenClaw做简单二开的产品，短期内仍难以真正落地。</p>\\n<p>攀峰智能并没有走把所有产品基于OpenClaw架构重构的路线，而是借鉴了类似OpenClaw、Claude Code、Hermes Agent等架构的设计思想——包括多层记忆架构、做梦机制等——自己开发完整的Agent OS。具体来说，他们想<strong>把内容平台生态的超级个体和商家的Context信息Agent化，整合接入，形成达人和商家的“Agent OS”</strong>，用一个扎实的OS系统来服务好客户群体。</p>\\n<p>在王铭的构想中，Personal AI的Memory做好了，A2A（Agent to Agent）的世界才会出现。目前，用户使用ChatGPT、Gemini、豆包等中心化AI助手时，不仅需要多平台切换，不同平台给出的答案可能还会出现冲突，且记忆无法跨平台沉淀。</p>\\n<p>倘若一个系统中不同模型能被自动调用，生成结果可以被自动做对比和整合，并持续积累历史上下文，用户的体验将会发生质变。</p>\\n<p>“未来，每个人可能都会拥有这样一个消费级的通用Personal AI（个人AI）助手，也会拥有一批垂直场景的Agent OS。”王铭解释，Personal AI的系统能支持用户自由调度模型、用自然语言添加Skills、拥有长期的个人记忆等功能。用户能够更好地使用产品，也才能更好地被留在平台上。</p>\\n<p>基于这样的判断，攀峰智能对其产品作出了方向调整——要帮达人和商家建立属于自己的Agent OS，进而自建Personal AI系统。</p>\\n<p>未来，攀峰智能计划将产品作为Skill接入到OpenClaw、Hermes Agent等去中心化的Personal AI生态中，相当于把一批商家和达人的数字分身直接带到下一个时代的流量入口里去。</p>\\n<p>王铭认为，Personal AI系统的不断完善，正是实现 A2A 的重要基础。从更近的目标而言，Personal AI的下一步，是实现真正的A2A（Agent to Agent）的商业系统。</p>\\n<h3>用Agent开发Agent</h3>\\n<p>除了产品方向的变化之外，攀峰智能的开发范式也在经历剧烈的重构。</p>\\n<p>尽管公司才成立数月，但他们已经经历了3个阶段的开发范式演进：第一阶段是AI Coding几乎没有约束，什么都交给AI去做，结果各种bug的速度让人改不过来；第二阶段是引入rules和结构化约束，借鉴了Harness的思想以及Claude Code泄露出的架构，用更多的条条框框去驾驭Agent；第三阶段则是通过通过自研的开发Agent调用Coding来开发Agent，最后交给人类做验收。</p>\\n<p>王铭表示，目前公司99%以上的代码都是由AI编写，甚至很多开发工作不是由程序员完成的——产品经理、人力资源、财务、运营同学都在开发系统。而在最新的阶段，他们开发了专门的Coding Agent，能够在某个垂直场景里持续地帮助开发和迭代，周末团队休息时，Agent还在工作。</p>\\n<p>随之而来的，生产力正在指数级提升。一个原来需要两周实现的复杂需求，开发时长能缩短至1天。</p>\\n<p>毫无疑问，大模型的发展速度，仍然是跳脱于人类想象的。对接下来的Agent技术曲线演进，王铭分享了他对于今年Agent发展的三个判断：其一，Agent的Memory会有巨大突破；其二，Multi-Agent自主进化能力会日趋成熟；其三，Agent自己Coding出各种工具，来解决响应问题。千人千面个性化产品的时代快速到来。</p>\\n<p>对于未来发展计划，团队透露，下半年攀峰智能将持续扩张团队至50人以上，并加速打造Agent OS系统。随着产品全量上线，公司也将进入快速市场扩张期，同时着手搭建Agent化的供应链体系，抢跑A2A原生电商。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'要做电商Agent OS，前钉钉最年轻副总裁创立的「攀峰智能」再次完成数千万天使轮融资\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'要做电商Agent OS，前钉钉最年轻副总裁创立的「攀峰智能」再次完成数千万天使轮融资\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768320373441281?f=rss\'}], \'link\': \'https://36kr.com/p/3768320373441281?f=rss\', \'published\': \'2026-04-16 10:00:26  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=0, tm_sec=26, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p><strong>文｜王欣逸</strong></p>\\\\n  <p><strong>编辑｜邓咏仪</strong></p>\\\\n  <p>36氪获悉，近日，攀峰智能已完成数千万元天使轮融资，本轮融资由华控资本领投、云时资本跟投，将用于模型研发、团队增长以及市场扩张。</p>\\\\n  <p>攀峰智能（K2 Lab）成立于2025年10月，成立仅一个月，便拿到了来自云时资本的数千万元融资。其三位联合创始人均来自阿里钉钉团队。CEO王铭曾是钉钉最年轻的副总裁，在钉钉近五年间负责AI创新产品、SaaS生态、大模型与AI生态、产业生态和战略终端等业务；联合创始人兼CSO汤明磊，此前深耕产业数字化和产业AI的投资与研究十年，在钉钉期间负责战略生态和投资；联合创始人兼CTO赵先烈，曾任钉钉AI PaaS及AI运营负责人。</p>\\\\n  <p>攀峰智能面向To C市场，打造了一个内容电商场景的Agent OS——Moras。Moras为TikTok上的达人和商家服务——用户只需通过和Moras互动，它便能实现自动化学习，完成选品推荐、脚本生成、内容创作、智能剪辑、视频预检和发布、数据分析等环节，实现出单。</p>\\\\n  <p>目前，Moras的用户画像主要为粉丝体量在五千至五万的达人和商家群体，带货品类涵盖服装、生活用品、家居、节日用品等。</p>\\\\n  <p>过去三个月，Moras已完成了首批达人用户的共创测试。邀测用户数据显示，活跃达人通过使用Moras平均月度成交GMV接近1万美元，有达人实现了月度GMV突破10万美金的成绩。</p>\\\\n  <p>从具体数据来看，有达人实现了注册首周GMV破万美元，使用Moras的首周出单率已经达到了70%以上，而这一时间还在继续变快。</p>\\\\n  <p>Moras采用的是Multi-Agent架构，能实现自主进化。随着达人互动频次的增加，这一工具的选品、脚本、分析等能力会逐渐增强，出单能力也随之提高。</p>\\\\n  <p>而受OpenClaw和Claude Code的Agent能力启发，攀峰智能如今也在快速革新，已着手建立起A2A原生电商操作系统，来服务更广泛的客群。</p>\\\\n  <h3>“人类不想in the loop”</h3>\\\\n  <p>在邀测阶段，攀峰智能发现海外用户对操作流程的容忍度远比预期更低——哪怕只是多一步确认，用户也倾向于放弃。</p>\\\\n  <p>“人类不想in the loop。”王铭说。在王铭看来，目前阶段，AI还没有替代人的能力，但AI能把人的短板补齐，把人的长板超级放大。</p>\\\\n  <p>Moras产品最初的测试版本设计的比较简单，尽管如此，海外的用户依然觉得很复杂，这也让他们意识到另一种商业模式的可能：AI“雇佣”人类。</p>\\\\n  <p>成立之初，Moras设计了两种提供服务的方式，原意也是想测试哪一种更适合市场：</p>\\\\n  <p>第一种是用户为Moras付底薪，让Moras起协助作用，如调整选品、制作视频等，即<strong>人类雇佣AI</strong>，这种方式平台会抽成50%。</p>\\\\n  <p>第二种则是Moras完全托管，包括账号资产、形象等，AI完全帮助用户做内容、带货，即<strong>AI“雇佣”人类</strong>。在这种模式下，用户只能拿到极低比例的分成收益。</p>\\\\n  <p>在邀测阶段，攀峰智能将两种模式同步测试，有意思的是，选择第二种商业模式的用户越来越多。<strong>这意味着，在这一场景下，Agent能力越来越强，Human反而不想in the loop（人类不想参与决策）。</strong></p>\\\\n  <p>“但人类不想in the loop，并不意味着AI可以完全脱离人类。”王铭说，在实际使用过程中，达人和商家授权登录Moras后，平台会通过多模态理解分析粉丝画像、过往视频的用户画像和视频调性，来推送个性化的选品。其中，达人和商家仍然拥有对选品、文案、视频的倾向性，可以对内容进行审核、修改调整。</p>\\\\n  <p>王铭告诉《智能涌现》，Moras正在灰度测试另一个版本，达人和商家可以直接和平台对话，告诉Moras个性化的风格、审美和表达方式等。未来可能还会上线更复杂的PC端操作系统，支持用户上传专业知识和Skills等。</p>\\\\n  <p>坦白来讲，Moras目前有60分的带货能力，这或许能让它帮达人实现几千到一两万美元的月度营收，但离稳定输出大几万美元的能力还有一段距离。</p>\\\\n  <p>对于Agent而言，“活人感”“网感”等独特的表达方式和销售能力很重要，要实现这些能力，还需要大量和人类的连接——这也是攀峰智能正在自研电商场景多模态理解模型的原因。</p>\\\\n  <p>而在内容电商场景中，理解什么是爆款、理解用户的风格和审美，远比生成本身更关键。</p>\\\\n  <p>王铭认为，AI雇佣人类的结果会是，人类发现AI真的能赚钱，随即被带入行业之中来，对Moras提出更多诉求，同时也参与到创收的更多环节中来。</p>\\\\n  <p>为了让产品离钱更近，王铭还透露，Moras正在<strong>训练一个自研的电商场景的多模态理解模型</strong>。</p>\\\\n  <p>在他看来，通用模型更多的是优化生成能力，忽略了理解世界的能力，本质上还是在批发Token。如果产品只是在帮助用户更低门槛消耗Token，而不是帮助用户提高效果，最后作为批发商，Token的ROI大概率很低。</p>\\\\n  <p>这也反映了攀峰智能路线的本质不同：选择了做离商业化更近的事情——自研爆款理解模型、爆款商品和爆款脚本，从最开始就专注于效果的打磨，让模型理解爆款的逻辑。</p>\\\\n  <p>王铭表示，当前攀峰的团队中，有来自字节的多位内容电商专家，将专家的最佳实践让AI学会后，由AI来做选品模型；人类专家则变成AI的数据标注员，判断AI选出来的商品，哪些是真正的爆款。与此同时，所有发出去的内容的数据结果会回流到分析Agent，再反馈给前面的选品模型，形成自进化闭环。</p>\\\\n  <p><strong>用户愿意付费，产品能带来盈利，Token本身价值随之提高</strong>，这就形成一套“ROI Token 经济学”。</p>\\\\n  <p>而对于大厂的竞争，王铭表示，目前，大厂的第一优先级仍是抢夺AI入口，AI+电商的垂直场景尚未进入其核心视野，这也正是中小企业切入垂直场景的窗口期。</p>\\\\n  <h3>自建Personal AI系统</h3>\\\\n  <p>今年初，OpenClaw横空出世，其架构由Channel层（通道层）、Agent层（智能体层）和Tools层（工具层）组成，实现了一个完整的AI操作系统，迅速引发了行业对Agent OS的广泛讨论。</p>\\\\n  <p>这给攀峰智能的产品带来了新的启发。王铭表示，团队也尝试过基于OpenClaw进行开发，但发现其现阶段还无法达到稳定的企业级使用标准，基于OpenClaw做简单二开的产品，短期内仍难以真正落地。</p>\\\\n  <p>攀峰智能并没有走把所有产品基于OpenClaw架构重构的路线，而是借鉴了类似OpenClaw、Claude Code、Hermes Agent等架构的设计思想——包括多层记忆架构、做梦机制等——自己开发完整的Agent OS。具体来说，他们想<strong>把内容平台生态的超级个体和商家的Context信息Agent化，整合接入，形成达人和商家的“Agent OS”</strong>，用一个扎实的OS系统来服务好客户群体。</p>\\\\n  <p>在王铭的构想中，Personal AI的Memory做好了，A2A（Agent to Agent）的世界才会出现。目前，用户使用ChatGPT、Gemini、豆包等中心化AI助手时，不仅需要多平台切换，不同平台给出的答案可能还会出现冲突，且记忆无法跨平台沉淀。</p>\\\\n  <p>倘若一个系统中不同模型能被自动调用，生成结果可以被自动做对比和整合，并持续积累历史上下文，用户的体验将会发生质变。</p>\\\\n  <p>“未来，每个人可能都会拥有这样一个消费级的通用Personal AI（个人AI）助手，也会拥有一批垂直场景的Agent OS。”王铭解释，Personal AI的系统能支持用户自由调度模型、用自然语言添加Skills、拥有长期的个人记忆等功能。用户能够更好地使用产品，也才能更好地被留在平台上。</p>\\\\n  <p>基于这样的判断，攀峰智能对其产品作出了方向调整——要帮达人和商家建立属于自己的Agent OS，进而自建Personal AI系统。</p>\\\\n  <p>未来，攀峰智能计划将产品作为Skill接入到OpenClaw、Hermes Agent等去中心化的Personal AI生态中，相当于把一批商家和达人的数字分身直接带到下一个时代的流量入口里去。</p>\\\\n  <p>王铭认为，Personal AI系统的不断完善，正是实现 A2A 的重要基础。从更近的目标而言，Personal AI的下一步，是实现真正的A2A（Agent to Agent）的商业系统。</p>\\\\n  <h3>用Agent开发Agent</h3>\\\\n  <p>除了产品方向的变化之外，攀峰智能的开发范式也在经历剧烈的重构。</p>\\\\n  <p>尽管公司才成立数月，但他们已经经历了3个阶段的开发范式演进：第一阶段是AI Coding几乎没有约束，什么都交给AI去做，结果各种bug的速度让人改不过来；第二阶段是引入rules和结构化约束，借鉴了Harness的思想以及Claude Code泄露出的架构，用更多的条条框框去驾驭Agent；第三阶段则是通过通过自研的开发Agent调用Coding来开发Agent，最后交给人类做验收。</p>\\\\n  <p>王铭表示，目前公司99%以上的代码都是由AI编写，甚至很多开发工作不是由程序员完成的——产品经理、人力资源、财务、运营同学都在开发系统。而在最新的阶段，他们开发了专门的Coding Agent，能够在某个垂直场景里持续地帮助开发和迭代，周末团队休息时，Agent还在工作。</p>\\\\n  <p>随之而来的，生产力正在指数级提升。一个原来需要两周实现的复杂需求，开发时长能缩短至1天。</p>\\\\n  <p>毫无疑问，大模型的发展速度，仍然是跳脱于人类想象的。对接下来的Agent技术曲线演进，王铭分享了他对于今年Agent发展的三个判断：其一，Agent的Memory会有巨大突破；其二，Multi-Agent自主进化能力会日趋成熟；其三，Agent自己Coding出各种工具，来解决响应问题。千人千面个性化产品的时代快速到来。</p>\\\\n  <p>对于未来发展计划，团队透露，下半年攀峰智能将持续扩张团队至50人以上，并加速打造Agent OS系统。随着产品全量上线，公司也将进入快速市场扩张期，同时着手搭建Agent化的供应链体系，抢跑A2A原生电商。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p><strong>文｜王欣逸</strong></p>\\\\n  <p><strong>编辑｜邓咏仪</strong></p>\\\\n  <p>36氪获悉，近日，攀峰智能已完成数千万元天使轮融资，本轮融资由华控资本领投、云时资本跟投，将用于模型研发、团队增长以及市场扩张。</p>\\\\n  <p>攀峰智能（K2 Lab）成立于2025年10月，成立仅一个月，便拿到了来自云时资本的数千万元融资。其三位联合创始人均来自阿里钉钉团队。CEO王铭曾是钉钉最年轻的副总裁，在钉钉近五年间负责AI创新产品、SaaS生态、大模型与AI生态、产业生态和战略终端等业务；联合创始人兼CSO汤明磊，此前深耕产业数字化和产业AI的投资与研究十年，在钉钉期间负责战略生态和投资；联合创始人兼CTO赵先烈，曾任钉钉AI PaaS及AI运营负责人。</p>\\\\n  <p>攀峰智能面向To C市场，打造了一个内容电商场景的Agent OS——Moras。Moras为TikTok上的达人和商家服务——用户只需通过和Moras互动，它便能实现自动化学习，完成选品推荐、脚本生成、内容创作、智能剪辑、视频预检和发布、数据分析等环节，实现出单。</p>\\\\n  <p>目前，Moras的用户画像主要为粉丝体量在五千至五万的达人和商家群体，带货品类涵盖服装、生活用品、家居、节日用品等。</p>\\\\n  <p>过去三个月，Moras已完成了首批达人用户的共创测试。邀测用户数据显示，活跃达人通过使用Moras平均月度成交GMV接近1万美元，有达人实现了月度GMV突破10万美金的成绩。</p>\\\\n  <p>从具体数据来看，有达人实现了注册首周GMV破万美元，使用Moras的首周出单率已经达到了70%以上，而这一时间还在继续变快。</p>\\\\n  <p>Moras采用的是Multi-Agent架构，能实现自主进化。随着达人互动频次的增加，这一工具的选品、脚本、分析等能力会逐渐增强，出单能力也随之提高。</p>\\\\n  <p>而受OpenClaw和Claude Code的Agent能力启发，攀峰智能如今也在快速革新，已着手建立起A2A原生电商操作系统，来服务更广泛的客群。</p>\\\\n  <h3>“人类不想in the loop”</h3>\\\\n  <p>在邀测阶段，攀峰智能发现海外用户对操作流程的容忍度远比预期更低——哪怕只是多一步确认，用户也倾向于放弃。</p>\\\\n  <p>“人类不想in the loop。”王铭说。在王铭看来，目前阶段，AI还没有替代人的能力，但AI能把人的短板补齐，把人的长板超级放大。</p>\\\\n  <p>Moras产品最初的测试版本设计的比较简单，尽管如此，海外的用户依然觉得很复杂，这也让他们意识到另一种商业模式的可能：AI“雇佣”人类。</p>\\\\n  <p>成立之初，Moras设计了两种提供服务的方式，原意也是想测试哪一种更适合市场：</p>\\\\n  <p>第一种是用户为Moras付底薪，让Moras起协助作用，如调整选品、制作视频等，即<strong>人类雇佣AI</strong>，这种方式平台会抽成50%。</p>\\\\n  <p>第二种则是Moras完全托管，包括账号资产、形象等，AI完全帮助用户做内容、带货，即<strong>AI“雇佣”人类</strong>。在这种模式下，用户只能拿到极低比例的分成收益。</p>\\\\n  <p>在邀测阶段，攀峰智能将两种模式同步测试，有意思的是，选择第二种商业模式的用户越来越多。<strong>这意味着，在这一场景下，Agent能力越来越强，Human反而不想in the loop（人类不想参与决策）。</strong></p>\\\\n  <p>“但人类不想in the loop，并不意味着AI可以完全脱离人类。”王铭说，在实际使用过程中，达人和商家授权登录Moras后，平台会通过多模态理解分析粉丝画像、过往视频的用户画像和视频调性，来推送个性化的选品。其中，达人和商家仍然拥有对选品、文案、视频的倾向性，可以对内容进行审核、修改调整。</p>\\\\n  <p>王铭告诉《智能涌现》，Moras正在灰度测试另一个版本，达人和商家可以直接和平台对话，告诉Moras个性化的风格、审美和表达方式等。未来可能还会上线更复杂的PC端操作系统，支持用户上传专业知识和Skills等。</p>\\\\n  <p>坦白来讲，Moras目前有60分的带货能力，这或许能让它帮达人实现几千到一两万美元的月度营收，但离稳定输出大几万美元的能力还有一段距离。</p>\\\\n  <p>对于Agent而言，“活人感”“网感”等独特的表达方式和销售能力很重要，要实现这些能力，还需要大量和人类的连接——这也是攀峰智能正在自研电商场景多模态理解模型的原因。</p>\\\\n  <p>而在内容电商场景中，理解什么是爆款、理解用户的风格和审美，远比生成本身更关键。</p>\\\\n  <p>王铭认为，AI雇佣人类的结果会是，人类发现AI真的能赚钱，随即被带入行业之中来，对Moras提出更多诉求，同时也参与到创收的更多环节中来。</p>\\\\n  <p>为了让产品离钱更近，王铭还透露，Moras正在<strong>训练一个自研的电商场景的多模态理解模型</strong>。</p>\\\\n  <p>在他看来，通用模型更多的是优化生成能力，忽略了理解世界的能力，本质上还是在批发Token。如果产品只是在帮助用户更低门槛消耗Token，而不是帮助用户提高效果，最后作为批发商，Token的ROI大概率很低。</p>\\\\n  <p>这也反映了攀峰智能路线的本质不同：选择了做离商业化更近的事情——自研爆款理解模型、爆款商品和爆款脚本，从最开始就专注于效果的打磨，让模型理解爆款的逻辑。</p>\\\\n  <p>王铭表示，当前攀峰的团队中，有来自字节的多位内容电商专家，将专家的最佳实践让AI学会后，由AI来做选品模型；人类专家则变成AI的数据标注员，判断AI选出来的商品，哪些是真正的爆款。与此同时，所有发出去的内容的数据结果会回流到分析Agent，再反馈给前面的选品模型，形成自进化闭环。</p>\\\\n  <p><strong>用户愿意付费，产品能带来盈利，Token本身价值随之提高</strong>，这就形成一套“ROI Token 经济学”。</p>\\\\n  <p>而对于大厂的竞争，王铭表示，目前，大厂的第一优先级仍是抢夺AI入口，AI+电商的垂直场景尚未进入其核心视野，这也正是中小企业切入垂直场景的窗口期。</p>\\\\n  <h3>自建Personal AI系统</h3>\\\\n  <p>今年初，OpenClaw横空出世，其架构由Channel层（通道层）、Agent层（智能体层）和Tools层（工具层）组成，实现了一个完整的AI操作系统，迅速引发了行业对Agent OS的广泛讨论。</p>\\\\n  <p>这给攀峰智能的产品带来了新的启发。王铭表示，团队也尝试过基于OpenClaw进行开发，但发现其现阶段还无法达到稳定的企业级使用标准，基于OpenClaw做简单二开的产品，短期内仍难以真正落地。</p>\\\\n  <p>攀峰智能并没有走把所有产品基于OpenClaw架构重构的路线，而是借鉴了类似OpenClaw、Claude Code、Hermes Agent等架构的设计思想——包括多层记忆架构、做梦机制等——自己开发完整的Agent OS。具体来说，他们想<strong>把内容平台生态的超级个体和商家的Context信息Agent化，整合接入，形成达人和商家的“Agent OS”</strong>，用一个扎实的OS系统来服务好客户群体。</p>\\\\n  <p>在王铭的构想中，Personal AI的Memory做好了，A2A（Agent to Agent）的世界才会出现。目前，用户使用ChatGPT、Gemini、豆包等中心化AI助手时，不仅需要多平台切换，不同平台给出的答案可能还会出现冲突，且记忆无法跨平台沉淀。</p>\\\\n  <p>倘若一个系统中不同模型能被自动调用，生成结果可以被自动做对比和整合，并持续积累历史上下文，用户的体验将会发生质变。</p>\\\\n  <p>“未来，每个人可能都会拥有这样一个消费级的通用Personal AI（个人AI）助手，也会拥有一批垂直场景的Agent OS。”王铭解释，Personal AI的系统能支持用户自由调度模型、用自然语言添加Skills、拥有长期的个人记忆等功能。用户能够更好地使用产品，也才能更好地被留在平台上。</p>\\\\n  <p>基于这样的判断，攀峰智能对其产品作出了方向调整——要帮达人和商家建立属于自己的Agent OS，进而自建Personal AI系统。</p>\\\\n  <p>未来，攀峰智能计划将产品作为Skill接入到OpenClaw、Hermes Agent等去中心化的Personal AI生态中，相当于把一批商家和达人的数字分身直接带到下一个时代的流量入口里去。</p>\\\\n  <p>王铭认为，Personal AI系统的不断完善，正是实现 A2A 的重要基础。从更近的目标而言，Personal AI的下一步，是实现真正的A2A（Agent to Agent）的商业系统。</p>\\\\n  <h3>用Agent开发Agent</h3>\\\\n  <p>除了产品方向的变化之外，攀峰智能的开发范式也在经历剧烈的重构。</p>\\\\n  <p>尽管公司才成立数月，但他们已经经历了3个阶段的开发范式演进：第一阶段是AI Coding几乎没有约束，什么都交给AI去做，结果各种bug的速度让人改不过来；第二阶段是引入rules和结构化约束，借鉴了Harness的思想以及Claude Code泄露出的架构，用更多的条条框框去驾驭Agent；第三阶段则是通过通过自研的开发Agent调用Coding来开发Agent，最后交给人类做验收。</p>\\\\n  <p>王铭表示，目前公司99%以上的代码都是由AI编写，甚至很多开发工作不是由程序员完成的——产品经理、人力资源、财务、运营同学都在开发系统。而在最新的阶段，他们开发了专门的Coding Agent，能够在某个垂直场景里持续地帮助开发和迭代，周末团队休息时，Agent还在工作。</p>\\\\n  <p>随之而来的，生产力正在指数级提升。一个原来需要两周实现的复杂需求，开发时长能缩短至1天。</p>\\\\n  <p>毫无疑问，大模型的发展速度，仍然是跳脱于人类想象的。对接下来的Agent技术曲线演进，王铭分享了他对于今年Agent发展的三个判断：其一，Agent的Memory会有巨大突破；其二，Multi-Agent自主进化能力会日趋成熟；其三，Agent自己Coding出各种工具，来解决响应问题。千人千面个性化产品的时代快速到来。</p>\\\\n  <p>对于未来发展计划，团队透露，下半年攀峰智能将持续扩张团队至50人以上，并加速打造Agent OS系统。随着产品全量上线，公司也将进入快速市场扩张期，同时着手搭建Agent化的供应链体系，抢跑A2A原生电商。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'王欣逸\'}], \'author\': \'王欣逸\', \'author_detail\': {\'name\': \'王欣逸\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'懒得插手AI带货的老外，已经月入10万刀。\'}]}\", \"published_at\": \"2026-04-16 10:00:26\", \"ai_json_output\": \"\"}', '文｜王欣逸\n编辑｜邓咏仪\n36氪获悉，近日，攀峰智能已完成数千万元天使轮融资，本轮融资由华控资本领投、云时资本跟投，将用于模型研发、团队增长以及市场扩张。\n攀峰智能（K2 Lab）成立于2025年10月，成立仅一个月，便拿到了来自云时资本的数千万元融资。其三位联合创始人均来自阿里钉钉团队。CEO王铭曾是钉钉最年轻的副总裁，在钉钉近五年间负责AI创新产品、SaaS生态、大模型与AI生态、产业生态和战略终端等业务；联合创始人兼CSO汤明磊，此前深耕产业数字化和产业AI的投资与研究十年，在钉钉期间负责战略生态和投资；联合创始人兼CTO赵先烈，曾任钉钉AI PaaS及AI运营负责人。\n攀峰智能面向To C市场，打造了一个内容电商场景的Agent OS——Moras。Moras为TikTok上的达人和商家服务——用户只需通过和Moras互动，它便能实现自动化学习，完成选品推荐、脚本生成、内容创作、智能剪辑、视频预检和发布、数据分析等环节，实现出单。\n目前，Moras的用户画像主要为粉丝体量在五千至五万的达人和商家群体，带货品类涵盖服装、生活用品、家居、节日用品等。\n过去三个月，Moras已完成了首批达人用户的共创测试。邀测用户数据显示，活跃达人通过使用Moras平均月度成交GMV接近1万美元，有达人实现了月度GMV突破10万美金的成绩。\n从具体数据来看，有达人实现了注册首周GMV破万美元，使用Moras的首周出单率已经达到了70%以上，而这一时间还在继续变快。\nMoras采用的是Multi-Agent架构，能实现自主进化。随着达人互动频次的增加，这一工具的选品、脚本、分析等能力会逐渐增强，出单能力也随之提高。\n而受OpenClaw和Claude Code的Agent能力启发，攀峰智能如今也在快速革新，已着手建立起A2A原生电商操作系统，来服务更广泛的客群。\n“人类不想in the loop”\n在邀测阶段，攀峰智能发现海外用户对操作流程的容忍度远比预期更低——哪怕只是多一步确认，用户也倾向于放弃。\n“人类不想in the loop。”王铭说。在王铭看来，目前阶段，AI还没有替代人的能力，但AI能把人的短板补齐，把人的长板超级放大。\nMoras产品最初的测试版本设计的比较简单，尽管如此，海外的用户依然觉得很复杂，这也让他们意识到另一种商业模式的可能：AI“雇佣”人类。\n成立之初，Moras设计了两种提供服务的方式，原意也是想测试哪一种更适合市场：\n第一种是用户为Moras付底薪，让Moras起协助作用，如调整选品、制作视频等，即\n人类雇佣AI\n，这种方式平台会抽成50%。\n第二种则是Moras完全托管，包括账号资产、形象等，AI完全帮助用户做内容、带货，即\nAI“雇佣”人类\n。在这种模式下，用户只能拿到极低比例的分成收益。\n在邀测阶段，攀峰智能将两种模式同步测试，有意思的是，选择第二种商业模式的用户越来越多。\n这意味着，在这一场景下，Agent能力越来越强，Human反而不想in the loop（人类不想参与决策）。\n“但人类不想in the loop，并不意味着AI可以完全脱离人类。”王铭说，在实际使用过程中，达人和商家授权登录Moras后，平台会通过多模态理解分析粉丝画像、过往视频的用户画像和视频调性，来推送个性化的选品。其中，达人和商家仍然拥有对选品、文案、视频的倾向性，可以对内容进行审核、修改调整。\n王铭告诉《智能涌现》，Moras正在灰度测试另一个版本，达人和商家可以直接和平台对话，告诉Moras个性化的风格、审美和表达方式等。未来可能还会上线更复杂的PC端操作系统，支持用户上传专业知识和Skills等。\n坦白来讲，Moras目前有60分的带货能力，这或许能让它帮达人实现几千到一两万美元的月度营收，但离稳定输出大几万美元的能力还有一段距离。\n对于Agent而言，“活人感”“网感”等独特的表达方式和销售能力很重要，要实现这些能力，还需要大量和人类的连接——这也是攀峰智能正在自研电商场景多模态理解模型的原因。\n而在内容电商场景中，理解什么是爆款、理解用户的风格和审美，远比生成本身更关键。\n王铭认为，AI雇佣人类的结果会是，人类发现AI真的能赚钱，随即被带入行业之中来，对Moras提出更多诉求，同时也参与到创收的更多环节中来。\n为了让产品离钱更近，王铭还透露，Moras正在\n训练一个自研的电商场景的多模态理解模型\n。\n在他看来，通用模型更多的是优化生成能力，忽略了理解世界的能力，本质上还是在批发Token。如果产品只是在帮助用户更低门槛消耗Token，而不是帮助用户提高效果，最后作为批发商，Token的ROI大概率很低。\n这也反映了攀峰智能路线的本质不同：选择了做离商业化更近的事情——自研爆款理解模型、爆款商品和爆款脚本，从最开始就专注于效果的打磨，让模型理解爆款的逻辑。\n王铭表示，当前攀峰的团队中，有来自字节的多位内容电商专家，将专家的最佳实践让AI学会后，由AI来做选品模型；人类专家则变成AI的数据标注员，判断AI选出来的商品，哪些是真正的爆款。与此同时，所有发出去的内容的数据结果会回流到分析Agent，再反馈给前面的选品模型，形成自进化闭环。\n用户愿意付费，产品能带来盈利，Token本身价值随之提高\n，这就形成一套“ROI Token 经济学”。\n而对于大厂的竞争，王铭表示，目前，大厂的第一优先级仍是抢夺AI入口，AI+电商的垂直场景尚未进入其核心视野，这也正是中小企业切入垂直场景的窗口期。\n自建Personal AI系统\n今年初，OpenClaw横空出世，其架构由Channel层（通道层）、Agent层（智能体层）和Tools层（工具层）组成，实现了一个完整的AI操作系统，迅速引发了行业对Agent OS的广泛讨论。\n这给攀峰智能的产品带来了新的启发。王铭表示，团队也尝试过基于OpenClaw进行开发，但发现其现阶段还无法达到稳定的企业级使用标准，基于OpenClaw做简单二开的产品，短期内仍难以真正落地。\n攀峰智能并没有走把所有产品基于OpenClaw架构重构的路线，而是借鉴了类似OpenClaw、Claude Code、Hermes Agent等架构的设计思想——包括多层记忆架构、做梦机制等——自己开发完整的Agent OS。具体来说，他们想\n把内容平台生态的超级个体和商家的Context信息Agent化，整合接入，形成达人和商家的“Agent OS”\n，用一个扎实的OS系统来服务好客户群体。\n在王铭的构想中，Personal AI的Memory做好了，A2A（Agent to Agent）的世界才会出现。目前，用户使用ChatGPT、Gemini、豆包等中心化AI助手时，不仅需要多平台切换，不同平台给出的答案可能还会出现冲突，且记忆无法跨平台沉淀。\n倘若一个系统中不同模型能被自动调用，生成结果可以被自动做对比和整合，并持续积累历史上下文，用户的体验将会发生质变。\n“未来，每个人可能都会拥有这样一个消费级的通用Personal AI（个人AI）助手，也会拥有一批垂直场景的Agent OS。”王铭解释，Personal AI的系统能支持用户自由调度模型、用自然语言添加Skills、拥有长期的个人记忆等功能。用户能够更好地使用产品，也才能更好地被留在平台上。\n基于这样的判断，攀峰智能对其产品作出了方向调整——要帮达人和商家建立属于自己的Agent OS，进而自建Personal AI系统。\n未来，攀峰智能计划将产品作为Skill接入到OpenClaw、Hermes Agent等去中心化的Personal AI生态中，相当于把一批商家和达人的数字分身直接带到下一个时代的流量入口里去。\n王铭认为，Personal AI系统的不断完善，正是实现 A2A 的重要基础。从更近的目标而言，Personal AI的下一步，是实现真正的A2A（Agent to Agent）的商业系统。\n用Agent开发Agent\n除了产品方向的变化之外，攀峰智能的开发范式也在经历剧烈的重构。\n尽管公司才成立数月，但他们已经经历了3个阶段的开发范式演进：第一阶段是AI Coding几乎没有约束，什么都交给AI去做，结果各种bug的速度让人改不过来；第二阶段是引入rules和结构化约束，借鉴了Harness的思想以及Claude Code泄露出的架构，用更多的条条框框去驾驭Agent；第三阶段则是通过通过自研的开发Agent调用Coding来开发Agent，最后交给人类做验收。\n王铭表示，目前公司99%以上的代码都是由AI编写，甚至很多开发工作不是由程序员完成的——产品经理、人力资源、财务、运营同学都在开发系统。而在最新的阶段，他们开发了专门的Coding Agent，能够在某个垂直场景里持续地帮助开发和迭代，周末团队休息时，Agent还在工作。\n随之而来的，生产力正在指数级提升。一个原来需要两周实现的复杂需求，开发时长能缩短至1天。\n毫无疑问，大模型的发展速度，仍然是跳脱于人类想象的。对接下来的Agent技术曲线演进，王铭分享了他对于今年Agent发展的三个判断：其一，Agent的Memory会有巨大突破；其二，Multi-Agent自主进化能力会日趋成熟；其三，Agent自己Coding出各种工具，来解决响应问题。千人千面个性化产品的时代快速到来。\n对于未来发展计划，团队透露，下半年攀峰智能将持续扩张团队至50人以上，并加速打造Agent OS系统。随着产品全量上线，公司也将进入快速市场扩张期，同时着手搭建Agent化的供应链体系，抢跑A2A原生电商。', '2026-04-16 10:00:26', '2026-04-16 11:47:00');
INSERT INTO `news_detail` VALUES (21, 982, 10, '传统制造升级', '辉瑞押注中国Biotech：三生制药、先为达与创新药BD逻辑重估', '', '<blockquote>\n<p>2026Q1中国创新药BD交易额破600亿美元。辉瑞等MNC为对冲自身专利悬崖危机，利用中国研发低成本及全球第一的在研管线规模优势，持续购入三生制药等本土高价值资产。该趋势无视地缘博弈，叠加A股创业板改革，正重塑行业定价范式，构建起BD退出常态化的中国创新药多元融资与新估值体系。</p>\n</blockquote>\n<p>有一个数字，足以让所有人停下来重新思考这个行业。</p>\n<p>今年一季度，中国创新药对外授权（BD）交易总额突破600亿美元，这是国家药监局在3月底正式发布的数据。单看这个数字可能没有概念，对比一下：2024年全年，中国创新药出海总额是519亿美元；2025年全年翻了一倍多，达到1357亿美元。而2026年，仅仅一个季度，就已逼近2025年全年的一半。</p>\n<p>3年前，我们还在讨论国产创新药如何摆脱仿制药依赖。3年后，每周刷屏的BD公告，已经让人有些审美疲劳了。</p>\n<p>但就在这场出海狂潮中，有一个新的信号悄然浮现，且远比任何单笔交易都更值得关注：</p>\n<p>辉瑞CEO Albert Bourla，开始在华尔街的公开发言里，把对华合作作为辉瑞估值修复的关键故事来讲。</p>\n<p>这是一个质变的信号。</p>\n<h2><strong>01</strong></h2>\n<h2><strong>辉瑞为什么要押注中国</strong></h2>\n<p>要理解辉瑞在中国的一系列动作，先得理解它在担心什么。</p>\n<p>辉瑞正深陷专利悬崖困境：核心产品Eliquis、Ibrance将在2026至2028年陆续失去专利保护。辉瑞管理层在去年11月的杰富瑞会议上承认，专利到期将在本十年末合计影响约170亿美元的营收，公司的增长目标最早要到2029–2030年才能实现。</p>\n<p>以前更常见的解法，是美国大药企通过本土大并购补管线。辉瑞2023年以430亿美元收购Seagen，并计划主要通过310亿美元新增长期债务等方式完成融资。交易虽然补强了ADC管线，但也带来了债务、整合和短期业绩稀释压力，说明这条路越来越贵。</p>\n<p>这时候，中国给了一个截然不同的成本结构，据行业估算，中国研发成本约为欧美的1/3至1/2，临床试验速度快30%-50%，而且已深度覆盖ADC、双抗、CAR-T等几乎所有前沿赛道。更关键的是，首付款/总额比相对可控，意味着在药物真正上市前，跨国药企可以用较小的风险锁定高潜力资产。</p>\n<p>如果说美国大药企的大并购更像是“全款买房”，那么中国BD更像是“分期付款+优先锁定资产”。在这个逻辑下，辉瑞过去12个月在中国有两笔关键动作：一笔是买海外创新权益，另一笔是买中国商业化机会。</p>\n<p>去年5月，辉瑞以12.5亿美元首付款、潜在总额60.5亿美元，获得三生制药PD-1/VEGF双特异性抗体SSGJ-707在全球（除中国外的全球权益，并附带中国商业化选项）的独家开发、生产和商业化权利，并约定在协议生效时认购价值1亿美元的三生股份；按潜在总额计算，首付款占比约21%。该合作后续于7月24日正式生效。</p>\n<p>2026年2月，辉瑞中国与先为达生物就偏向型GLP-1受体激动剂埃诺格鲁肽达成商业化战略合作，获得其在中国大陆的独家商业化权益，付款总额最高4.95亿美元；而先为达继续担任MAH，并负责研发、注册、生产和供应。由于该产品已于今年1月获得NMPA批准用于成人2型糖尿病治疗，辉瑞拿到的是上市初期的商业化入口。</p>\n<p>概括来说，辉瑞这两步分别对应两种能力诉求：前者是出海买创新，后者是入华买商业化机会，并借GLP-1切入代谢赛道。</p>\n<h2><strong>02</strong></h2>\n<h2><strong>为什么中国值得押注</strong></h2>\n<p>辉瑞的判断，建立在一组正在被越来越多人认识到的核心数据上。</p>\n<p>医药魔方数据显示，截至2025年底，中国在研创新药总数达到4751个，占全球总量的33.7%，正式超越美国成为全球在研创新药第一大国。十年前，这个占比是6.9%。</p>\n<p>这个数字背后还隐藏着中国突出的结构性优势：据科技日报等转引的行业统计，在研细胞疗法项目中，中国占全球48%；在研ADC项目中，中国占全球超50%；全球超1500个进入临床的抗体分子里，中国占近四成。在几乎所有最难、最贵、最代表未来的赛道上，中国都已经进入全球前列。</p>\n<p>临床转化能力同样完成了验证。2025年中国批准创新药76个，创历史新高，其中包括11个首创新药：如恒瑞医药PCSK9单抗瑞卡西单抗（全球首个给药周期可达6个月的超长效降脂单抗）、康方生物依沃西单抗（全球首个头对头III期优于K药的双抗）、迪哲医药舒沃替尼（全球首个在美获批的EGFR exon20ins NSCLC中国创新药）等。</p>\n<p>这是辉瑞们真正在押注的东西：不是价格洼地，而是一个创新策源地的兴起。</p>\n<p>Bourla原话也提到，美国制药业需要与中国合作。过去十年，中国的快速研发流程已占全球药物研发的30%。中国目前拥有约1200种新型候选药物，而十年前只有约60种。</p>\n<p>60到1200，增长了20倍。</p>\n<h2><strong>03</strong></h2>\n<h2><strong>一场席卷所有人的抢椅子游戏</strong></h2>\n<p>辉瑞不是孤例。2026年Q1 600亿美元的背后，是一场跨国药企集体涌向中国谈判桌的抢椅子游戏，而且格局正在快速成型。</p>\n<p>先看这轮出海的三驾马车。</p>\n<p>双抗是最成熟的战场。康方生物的依沃西单抗在头对头临床中证明PD-1/VEGF双抗可以正面挑战Keytruda（2025年销售额超300亿美元的全球最畅销药物）之后，坐不住了就有艾伯维。</p>\n<p>今年1月，荣昌生物将PD-1/VEGF双抗RC148授权艾伯维，首付款6.5亿美元、潜在总额56亿美元。值得一提的是，康方生物的依沃西单抗BLA由合作方Summit于2025年底向FDA提交，并于今年1月12日公开宣布，若顺利受理，FDA有望于2026年第四季度作出决定。一旦获批将成为首个在美上市的中国PD-1/VEGF双抗，届时这条赛道的价值将再次被重估。</p>\n<p>GLP-1受体激动剂赛道无疑是新热点。辉瑞在GLP-1赛道的布局也说明了一个清晰的共识：全球GLP-1市场预计2030年将达到约900亿美元至千亿美元量级，是继PD-1之后最大的药物机会。各路跨国药企已在华展开新一轮抢椅子。</p>\n<p>而真正的意外，是小核酸的异军突起。今年Q1，瑞博生物将6款MASH siRNA资产打包授权Madrigal：6000万美元首付款+44亿美元潜在里程碑，一笔交易完成了对整个MASH siRNA管线的押注式扫货。小核酸，正在成为继ADC、双抗之后中国创新药出海的第三张王牌。</p>\n<p>今年Q1，全球21笔重磅BD交易中，15笔是中国交易，披露金额的全球占比达75%。这个数字，已经超出了中国是一个重要来源地的描述范畴，更接近的表述是：中国正在定义全球创新药BD的主战场。</p>\n<h2><strong>04</strong></h2>\n<h2><strong>越打压，越押注，一个新估值体系正在形成</strong></h2>\n<p>有一个看似矛盾的现象，必须正视。</p>\n<p>一方面，美国《生物安全法》（BIOSECURE Act）已于去年12月随《2026 财年国防授权法》正式签署生效，大大限制了联邦机构与被界定为受关注生物技术公司（biotechnology companies of concern）之间的合同、采购及相关资助联系。美国国家新兴生物技术安全委员会（NSCEB）于去年4月向国会提交的215页报告指出，将中国生物技术崛起定性为国家安全威胁，称若美国三年内不行动，可能再也无法追上。</p>\n<p>另一方面，辉瑞、礼来、默沙东、GSK、武田一众MNC，一个接一个在中国签下10亿美元级别的协议，跑得比立法者还快。</p>\n<p>政府在打压，企业在押注。这个错位，本身就是一个信号。</p>\n<p>对华合作被辉瑞纳入华尔街估值叙事，意味着不只是一家公司的策略调整，而是一个行业定价范式的转变。分析师不再只用专利风险折扣给辉瑞定价，而是开始用中国创新期权给其长期成长加分。</p>\n<p>这个变化，对中国Biotech一级市场的影响是实质性的。</p>\n<p>据医药魔方数据，2022年至2026年Q1，中国创新药对外BD首付款整体大涨超187%。三生首付款占总额21%，高于近年生物医药授权交易常见水平，这一细节至少说明，买方愿意将更多价值前置支付。一个处于临床中期、靶点清晰、BD路径可预期的管线，可以参照潜在首付款反推估值，而不再只靠港股18A上市公司的PS打折。</p>\n<p>对VC而言，一个重要的结构变化正在出现：BD退出正从偶发性超额回报，逐步走向可规划的退出路径，并开始影响部分基金的回报预期框架。</p>\n<p>与此同时，国内资本市场正在同步打开新的通道。4月10日，证监会正式发布《关于深化创业板改革更好服务新质生产力发展的意见》，核心举措是增设第四套上市标准，为尚未盈利的高成长科技企业正式打开A股大门。两档门槛已明确：新兴产业（市值≥30亿元，近1年营收≥2亿，近3年营收复合增速≥30%）；未来产业（市值≥40亿元，近1年营收≥2亿，近3年研发累计≥1亿且占营收比≥15%）。</p>\n<p>这意味着，一个手握强BD管线、有License-out收入但尚未盈利的创新药企，现在可以把A股创业板放进上市路径的选项里认真比较。港股18A+纳斯达克+科创板+创业板，正在形成真正意义上的多层次融资矩阵。</p>\n<p>中国生物医药资产的定价权，正在向本土资本市场回流。</p>\n<h2><strong>05</strong></h2>\n<h2><strong>那些总说泡沫的人，错过了什么</strong></h2>\n<p>每一轮BD高峰到来时，都会有质疑的声音。2024年说热潮已近顶点，2025年说地缘政治太不确定，2026年Q1刚刚突破600亿，一定还有人在说这不正常。</p>\n<p>但有几个数字，是任何叙事都绕不开的：在研创新药占全球33.7%，超越美国成为第一大国；在研ADC占全球超50%；Q1全球21笔重磅BD，15笔来自中国。</p>\n<p>这些数字，不是泡沫能解释的。这是一代研究者、临床医生、创业者用十年心血砌起来的技术积累。</p>\n<p>当辉瑞CEO开始用中国修复自己公司的估值故事，当600亿美元的季度成绩单摆在眼前，当创业板为未盈利的创新公司打开大门。</p>\n<p>这个行业，已经不需要再问中国创新药会不会成功了。</p>\n<p>真正值得问的问题，是：你准备好了吗？</p>\n<p>数据来源：国家药监局、证监会官方文件、医药魔方、科技日报、Reuters、FierceBiotech（截至2026年4月12日）。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/8PPGeYppLG5QGBQpV3wyrA\">“分子稳态”</a>，作者：创新药组 稳态君，36氪经授权发布。</p>', 'https://36kr.com/p/3768800114504456?f=rss', 0, '', '{\"summary\": \"本文梳理了跨国药企押注中国创新药资产的行业趋势，为创新药出海企业和投资方把握机会、明晰估值逻辑提供参考\", \"abstract\": \"2026年第一季度中国创新药对外授权BD交易额突破600亿美元，占全球同期重磅BD交易总额的七成以上。辉瑞等跨国药企为对冲自身专利悬崖危机，借助中国创新药研发成本低、管线规模全球第一的优势，纷纷加大对中国创新药资产的布局，逆地缘博弈趋势推进合作。当前中国创新药在ADC、双抗等多个前沿赛道已位居全球前列，临床转化能力也得到市场验证。该趋势叠加A股创业板改革，正在重塑中国创新药行业的定价范式，构建起BD退出常态化的多元融资与新估值体系。\", \"keywords\": [\"创新药出海\", \"BD交易\", \"生物医药\", \"跨国药企\", \"License-out\", \"估值体系\", \"创业板改革\", \"专利悬崖\"], \"policy_risk\": {\"market_risk\": \"美国将中国生物技术崛起定性为国家安全威胁，中国创新药出海存在地缘政治层面的政策不确定性风险\", \"policy_compliance\": \"美国《生物安全法》随2026财年国防授权法正式生效，限制联邦机构与被界定为受关注的中国生物技术公司开展合作、采购及资助；中国证监会深化创业板改革，增设第四套上市标准，为未盈利高成长创新药企开放A股上市通道\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"传统制造升级\"}', '', '{\"url\": \"https://36kr.com/p/3768800114504456?f=rss\", \"title\": \"辉瑞押注中国Biotech：三生制药、先为达与创新药BD逻辑重估\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<blockquote>\\n<p>2026Q1中国创新药BD交易额破600亿美元。辉瑞等MNC为对冲自身专利悬崖危机，利用中国研发低成本及全球第一的在研管线规模优势，持续购入三生制药等本土高价值资产。该趋势无视地缘博弈，叠加A股创业板改革，正重塑行业定价范式，构建起BD退出常态化的中国创新药多元融资与新估值体系。</p>\\n</blockquote>\\n<p>有一个数字，足以让所有人停下来重新思考这个行业。</p>\\n<p>今年一季度，中国创新药对外授权（BD）交易总额突破600亿美元，这是国家药监局在3月底正式发布的数据。单看这个数字可能没有概念，对比一下：2024年全年，中国创新药出海总额是519亿美元；2025年全年翻了一倍多，达到1357亿美元。而2026年，仅仅一个季度，就已逼近2025年全年的一半。</p>\\n<p>3年前，我们还在讨论国产创新药如何摆脱仿制药依赖。3年后，每周刷屏的BD公告，已经让人有些审美疲劳了。</p>\\n<p>但就在这场出海狂潮中，有一个新的信号悄然浮现，且远比任何单笔交易都更值得关注：</p>\\n<p>辉瑞CEO Albert Bourla，开始在华尔街的公开发言里，把对华合作作为辉瑞估值修复的关键故事来讲。</p>\\n<p>这是一个质变的信号。</p>\\n<h2><strong>01</strong></h2>\\n<h2><strong>辉瑞为什么要押注中国</strong></h2>\\n<p>要理解辉瑞在中国的一系列动作，先得理解它在担心什么。</p>\\n<p>辉瑞正深陷专利悬崖困境：核心产品Eliquis、Ibrance将在2026至2028年陆续失去专利保护。辉瑞管理层在去年11月的杰富瑞会议上承认，专利到期将在本十年末合计影响约170亿美元的营收，公司的增长目标最早要到2029–2030年才能实现。</p>\\n<p>以前更常见的解法，是美国大药企通过本土大并购补管线。辉瑞2023年以430亿美元收购Seagen，并计划主要通过310亿美元新增长期债务等方式完成融资。交易虽然补强了ADC管线，但也带来了债务、整合和短期业绩稀释压力，说明这条路越来越贵。</p>\\n<p>这时候，中国给了一个截然不同的成本结构，据行业估算，中国研发成本约为欧美的1/3至1/2，临床试验速度快30%-50%，而且已深度覆盖ADC、双抗、CAR-T等几乎所有前沿赛道。更关键的是，首付款/总额比相对可控，意味着在药物真正上市前，跨国药企可以用较小的风险锁定高潜力资产。</p>\\n<p>如果说美国大药企的大并购更像是“全款买房”，那么中国BD更像是“分期付款+优先锁定资产”。在这个逻辑下，辉瑞过去12个月在中国有两笔关键动作：一笔是买海外创新权益，另一笔是买中国商业化机会。</p>\\n<p>去年5月，辉瑞以12.5亿美元首付款、潜在总额60.5亿美元，获得三生制药PD-1/VEGF双特异性抗体SSGJ-707在全球（除中国外的全球权益，并附带中国商业化选项）的独家开发、生产和商业化权利，并约定在协议生效时认购价值1亿美元的三生股份；按潜在总额计算，首付款占比约21%。该合作后续于7月24日正式生效。</p>\\n<p>2026年2月，辉瑞中国与先为达生物就偏向型GLP-1受体激动剂埃诺格鲁肽达成商业化战略合作，获得其在中国大陆的独家商业化权益，付款总额最高4.95亿美元；而先为达继续担任MAH，并负责研发、注册、生产和供应。由于该产品已于今年1月获得NMPA批准用于成人2型糖尿病治疗，辉瑞拿到的是上市初期的商业化入口。</p>\\n<p>概括来说，辉瑞这两步分别对应两种能力诉求：前者是出海买创新，后者是入华买商业化机会，并借GLP-1切入代谢赛道。</p>\\n<h2><strong>02</strong></h2>\\n<h2><strong>为什么中国值得押注</strong></h2>\\n<p>辉瑞的判断，建立在一组正在被越来越多人认识到的核心数据上。</p>\\n<p>医药魔方数据显示，截至2025年底，中国在研创新药总数达到4751个，占全球总量的33.7%，正式超越美国成为全球在研创新药第一大国。十年前，这个占比是6.9%。</p>\\n<p>这个数字背后还隐藏着中国突出的结构性优势：据科技日报等转引的行业统计，在研细胞疗法项目中，中国占全球48%；在研ADC项目中，中国占全球超50%；全球超1500个进入临床的抗体分子里，中国占近四成。在几乎所有最难、最贵、最代表未来的赛道上，中国都已经进入全球前列。</p>\\n<p>临床转化能力同样完成了验证。2025年中国批准创新药76个，创历史新高，其中包括11个首创新药：如恒瑞医药PCSK9单抗瑞卡西单抗（全球首个给药周期可达6个月的超长效降脂单抗）、康方生物依沃西单抗（全球首个头对头III期优于K药的双抗）、迪哲医药舒沃替尼（全球首个在美获批的EGFR exon20ins NSCLC中国创新药）等。</p>\\n<p>这是辉瑞们真正在押注的东西：不是价格洼地，而是一个创新策源地的兴起。</p>\\n<p>Bourla原话也提到，美国制药业需要与中国合作。过去十年，中国的快速研发流程已占全球药物研发的30%。中国目前拥有约1200种新型候选药物，而十年前只有约60种。</p>\\n<p>60到1200，增长了20倍。</p>\\n<h2><strong>03</strong></h2>\\n<h2><strong>一场席卷所有人的抢椅子游戏</strong></h2>\\n<p>辉瑞不是孤例。2026年Q1 600亿美元的背后，是一场跨国药企集体涌向中国谈判桌的抢椅子游戏，而且格局正在快速成型。</p>\\n<p>先看这轮出海的三驾马车。</p>\\n<p>双抗是最成熟的战场。康方生物的依沃西单抗在头对头临床中证明PD-1/VEGF双抗可以正面挑战Keytruda（2025年销售额超300亿美元的全球最畅销药物）之后，坐不住了就有艾伯维。</p>\\n<p>今年1月，荣昌生物将PD-1/VEGF双抗RC148授权艾伯维，首付款6.5亿美元、潜在总额56亿美元。值得一提的是，康方生物的依沃西单抗BLA由合作方Summit于2025年底向FDA提交，并于今年1月12日公开宣布，若顺利受理，FDA有望于2026年第四季度作出决定。一旦获批将成为首个在美上市的中国PD-1/VEGF双抗，届时这条赛道的价值将再次被重估。</p>\\n<p>GLP-1受体激动剂赛道无疑是新热点。辉瑞在GLP-1赛道的布局也说明了一个清晰的共识：全球GLP-1市场预计2030年将达到约900亿美元至千亿美元量级，是继PD-1之后最大的药物机会。各路跨国药企已在华展开新一轮抢椅子。</p>\\n<p>而真正的意外，是小核酸的异军突起。今年Q1，瑞博生物将6款MASH siRNA资产打包授权Madrigal：6000万美元首付款+44亿美元潜在里程碑，一笔交易完成了对整个MASH siRNA管线的押注式扫货。小核酸，正在成为继ADC、双抗之后中国创新药出海的第三张王牌。</p>\\n<p>今年Q1，全球21笔重磅BD交易中，15笔是中国交易，披露金额的全球占比达75%。这个数字，已经超出了中国是一个重要来源地的描述范畴，更接近的表述是：中国正在定义全球创新药BD的主战场。</p>\\n<h2><strong>04</strong></h2>\\n<h2><strong>越打压，越押注，一个新估值体系正在形成</strong></h2>\\n<p>有一个看似矛盾的现象，必须正视。</p>\\n<p>一方面，美国《生物安全法》（BIOSECURE Act）已于去年12月随《2026 财年国防授权法》正式签署生效，大大限制了联邦机构与被界定为受关注生物技术公司（biotechnology companies of concern）之间的合同、采购及相关资助联系。美国国家新兴生物技术安全委员会（NSCEB）于去年4月向国会提交的215页报告指出，将中国生物技术崛起定性为国家安全威胁，称若美国三年内不行动，可能再也无法追上。</p>\\n<p>另一方面，辉瑞、礼来、默沙东、GSK、武田一众MNC，一个接一个在中国签下10亿美元级别的协议，跑得比立法者还快。</p>\\n<p>政府在打压，企业在押注。这个错位，本身就是一个信号。</p>\\n<p>对华合作被辉瑞纳入华尔街估值叙事，意味着不只是一家公司的策略调整，而是一个行业定价范式的转变。分析师不再只用专利风险折扣给辉瑞定价，而是开始用中国创新期权给其长期成长加分。</p>\\n<p>这个变化，对中国Biotech一级市场的影响是实质性的。</p>\\n<p>据医药魔方数据，2022年至2026年Q1，中国创新药对外BD首付款整体大涨超187%。三生首付款占总额21%，高于近年生物医药授权交易常见水平，这一细节至少说明，买方愿意将更多价值前置支付。一个处于临床中期、靶点清晰、BD路径可预期的管线，可以参照潜在首付款反推估值，而不再只靠港股18A上市公司的PS打折。</p>\\n<p>对VC而言，一个重要的结构变化正在出现：BD退出正从偶发性超额回报，逐步走向可规划的退出路径，并开始影响部分基金的回报预期框架。</p>\\n<p>与此同时，国内资本市场正在同步打开新的通道。4月10日，证监会正式发布《关于深化创业板改革更好服务新质生产力发展的意见》，核心举措是增设第四套上市标准，为尚未盈利的高成长科技企业正式打开A股大门。两档门槛已明确：新兴产业（市值≥30亿元，近1年营收≥2亿，近3年营收复合增速≥30%）；未来产业（市值≥40亿元，近1年营收≥2亿，近3年研发累计≥1亿且占营收比≥15%）。</p>\\n<p>这意味着，一个手握强BD管线、有License-out收入但尚未盈利的创新药企，现在可以把A股创业板放进上市路径的选项里认真比较。港股18A+纳斯达克+科创板+创业板，正在形成真正意义上的多层次融资矩阵。</p>\\n<p>中国生物医药资产的定价权，正在向本土资本市场回流。</p>\\n<h2><strong>05</strong></h2>\\n<h2><strong>那些总说泡沫的人，错过了什么</strong></h2>\\n<p>每一轮BD高峰到来时，都会有质疑的声音。2024年说热潮已近顶点，2025年说地缘政治太不确定，2026年Q1刚刚突破600亿，一定还有人在说这不正常。</p>\\n<p>但有几个数字，是任何叙事都绕不开的：在研创新药占全球33.7%，超越美国成为第一大国；在研ADC占全球超50%；Q1全球21笔重磅BD，15笔来自中国。</p>\\n<p>这些数字，不是泡沫能解释的。这是一代研究者、临床医生、创业者用十年心血砌起来的技术积累。</p>\\n<p>当辉瑞CEO开始用中国修复自己公司的估值故事，当600亿美元的季度成绩单摆在眼前，当创业板为未盈利的创新公司打开大门。</p>\\n<p>这个行业，已经不需要再问中国创新药会不会成功了。</p>\\n<p>真正值得问的问题，是：你准备好了吗？</p>\\n<p>数据来源：国家药监局、证监会官方文件、医药魔方、科技日报、Reuters、FierceBiotech（截至2026年4月12日）。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/8PPGeYppLG5QGBQpV3wyrA\\\">“分子稳态”</a>，作者：创新药组 稳态君，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'辉瑞押注中国Biotech：三生制药、先为达与创新药BD逻辑重估\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'辉瑞押注中国Biotech：三生制药、先为达与创新药BD逻辑重估\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768800114504456?f=rss\'}], \'link\': \'https://36kr.com/p/3768800114504456?f=rss\', \'published\': \'2026-04-16 09:55:53  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=1, tm_min=55, tm_sec=53, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<blockquote>\\\\n   <p>2026Q1中国创新药BD交易额破600亿美元。辉瑞等MNC为对冲自身专利悬崖危机，利用中国研发低成本及全球第一的在研管线规模优势，持续购入三生制药等本土高价值资产。该趋势无视地缘博弈，叠加A股创业板改革，正重塑行业定价范式，构建起BD退出常态化的中国创新药多元融资与新估值体系。</p>\\\\n  </blockquote>\\\\n  <p>有一个数字，足以让所有人停下来重新思考这个行业。</p>\\\\n  <p>今年一季度，中国创新药对外授权（BD）交易总额突破600亿美元，这是国家药监局在3月底正式发布的数据。单看这个数字可能没有概念，对比一下：2024年全年，中国创新药出海总额是519亿美元；2025年全年翻了一倍多，达到1357亿美元。而2026年，仅仅一个季度，就已逼近2025年全年的一半。</p>\\\\n  <p>3年前，我们还在讨论国产创新药如何摆脱仿制药依赖。3年后，每周刷屏的BD公告，已经让人有些审美疲劳了。</p>\\\\n  <p>但就在这场出海狂潮中，有一个新的信号悄然浮现，且远比任何单笔交易都更值得关注：</p>\\\\n  <p>辉瑞CEO Albert Bourla，开始在华尔街的公开发言里，把对华合作作为辉瑞估值修复的关键故事来讲。</p>\\\\n  <p>这是一个质变的信号。</p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>辉瑞为什么要押注中国</strong></h2>\\\\n  <p>要理解辉瑞在中国的一系列动作，先得理解它在担心什么。</p>\\\\n  <p>辉瑞正深陷专利悬崖困境：核心产品Eliquis、Ibrance将在2026至2028年陆续失去专利保护。辉瑞管理层在去年11月的杰富瑞会议上承认，专利到期将在本十年末合计影响约170亿美元的营收，公司的增长目标最早要到2029–2030年才能实现。</p>\\\\n  <p>以前更常见的解法，是美国大药企通过本土大并购补管线。辉瑞2023年以430亿美元收购Seagen，并计划主要通过310亿美元新增长期债务等方式完成融资。交易虽然补强了ADC管线，但也带来了债务、整合和短期业绩稀释压力，说明这条路越来越贵。</p>\\\\n  <p>这时候，中国给了一个截然不同的成本结构，据行业估算，中国研发成本约为欧美的1/3至1/2，临床试验速度快30%-50%，而且已深度覆盖ADC、双抗、CAR-T等几乎所有前沿赛道。更关键的是，首付款/总额比相对可控，意味着在药物真正上市前，跨国药企可以用较小的风险锁定高潜力资产。</p>\\\\n  <p>如果说美国大药企的大并购更像是“全款买房”，那么中国BD更像是“分期付款+优先锁定资产”。在这个逻辑下，辉瑞过去12个月在中国有两笔关键动作：一笔是买海外创新权益，另一笔是买中国商业化机会。</p>\\\\n  <p>去年5月，辉瑞以12.5亿美元首付款、潜在总额60.5亿美元，获得三生制药PD-1/VEGF双特异性抗体SSGJ-707在全球（除中国外的全球权益，并附带中国商业化选项）的独家开发、生产和商业化权利，并约定在协议生效时认购价值1亿美元的三生股份；按潜在总额计算，首付款占比约21%。该合作后续于7月24日正式生效。</p>\\\\n  <p>2026年2月，辉瑞中国与先为达生物就偏向型GLP-1受体激动剂埃诺格鲁肽达成商业化战略合作，获得其在中国大陆的独家商业化权益，付款总额最高4.95亿美元；而先为达继续担任MAH，并负责研发、注册、生产和供应。由于该产品已于今年1月获得NMPA批准用于成人2型糖尿病治疗，辉瑞拿到的是上市初期的商业化入口。</p>\\\\n  <p>概括来说，辉瑞这两步分别对应两种能力诉求：前者是出海买创新，后者是入华买商业化机会，并借GLP-1切入代谢赛道。</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>为什么中国值得押注</strong></h2>\\\\n  <p>辉瑞的判断，建立在一组正在被越来越多人认识到的核心数据上。</p>\\\\n  <p>医药魔方数据显示，截至2025年底，中国在研创新药总数达到4751个，占全球总量的33.7%，正式超越美国成为全球在研创新药第一大国。十年前，这个占比是6.9%。</p>\\\\n  <p>这个数字背后还隐藏着中国突出的结构性优势：据科技日报等转引的行业统计，在研细胞疗法项目中，中国占全球48%；在研ADC项目中，中国占全球超50%；全球超1500个进入临床的抗体分子里，中国占近四成。在几乎所有最难、最贵、最代表未来的赛道上，中国都已经进入全球前列。</p>\\\\n  <p>临床转化能力同样完成了验证。2025年中国批准创新药76个，创历史新高，其中包括11个首创新药：如恒瑞医药PCSK9单抗瑞卡西单抗（全球首个给药周期可达6个月的超长效降脂单抗）、康方生物依沃西单抗（全球首个头对头III期优于K药的双抗）、迪哲医药舒沃替尼（全球首个在美获批的EGFR exon20ins NSCLC中国创新药）等。</p>\\\\n  <p>这是辉瑞们真正在押注的东西：不是价格洼地，而是一个创新策源地的兴起。</p>\\\\n  <p>Bourla原话也提到，美国制药业需要与中国合作。过去十年，中国的快速研发流程已占全球药物研发的30%。中国目前拥有约1200种新型候选药物，而十年前只有约60种。</p>\\\\n  <p>60到1200，增长了20倍。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>一场席卷所有人的抢椅子游戏</strong></h2>\\\\n  <p>辉瑞不是孤例。2026年Q1 600亿美元的背后，是一场跨国药企集体涌向中国谈判桌的抢椅子游戏，而且格局正在快速成型。</p>\\\\n  <p>先看这轮出海的三驾马车。</p>\\\\n  <p>双抗是最成熟的战场。康方生物的依沃西单抗在头对头临床中证明PD-1/VEGF双抗可以正面挑战Keytruda（2025年销售额超300亿美元的全球最畅销药物）之后，坐不住了就有艾伯维。</p>\\\\n  <p>今年1月，荣昌生物将PD-1/VEGF双抗RC148授权艾伯维，首付款6.5亿美元、潜在总额56亿美元。值得一提的是，康方生物的依沃西单抗BLA由合作方Summit于2025年底向FDA提交，并于今年1月12日公开宣布，若顺利受理，FDA有望于2026年第四季度作出决定。一旦获批将成为首个在美上市的中国PD-1/VEGF双抗，届时这条赛道的价值将再次被重估。</p>\\\\n  <p>GLP-1受体激动剂赛道无疑是新热点。辉瑞在GLP-1赛道的布局也说明了一个清晰的共识：全球GLP-1市场预计2030年将达到约900亿美元至千亿美元量级，是继PD-1之后最大的药物机会。各路跨国药企已在华展开新一轮抢椅子。</p>\\\\n  <p>而真正的意外，是小核酸的异军突起。今年Q1，瑞博生物将6款MASH siRNA资产打包授权Madrigal：6000万美元首付款+44亿美元潜在里程碑，一笔交易完成了对整个MASH siRNA管线的押注式扫货。小核酸，正在成为继ADC、双抗之后中国创新药出海的第三张王牌。</p>\\\\n  <p>今年Q1，全球21笔重磅BD交易中，15笔是中国交易，披露金额的全球占比达75%。这个数字，已经超出了中国是一个重要来源地的描述范畴，更接近的表述是：中国正在定义全球创新药BD的主战场。</p>\\\\n  <h2><strong>04</strong></h2>\\\\n  <h2><strong>越打压，越押注，一个新估值体系正在形成</strong></h2>\\\\n  <p>有一个看似矛盾的现象，必须正视。</p>\\\\n  <p>一方面，美国《生物安全法》（BIOSECURE Act）已于去年12月随《2026 财年国防授权法》正式签署生效，大大限制了联邦机构与被界定为受关注生物技术公司（biotechnology companies of concern）之间的合同、采购及相关资助联系。美国国家新兴生物技术安全委员会（NSCEB）于去年4月向国会提交的215页报告指出，将中国生物技术崛起定性为国家安全威胁，称若美国三年内不行动，可能再也无法追上。</p>\\\\n  <p>另一方面，辉瑞、礼来、默沙东、GSK、武田一众MNC，一个接一个在中国签下10亿美元级别的协议，跑得比立法者还快。</p>\\\\n  <p>政府在打压，企业在押注。这个错位，本身就是一个信号。</p>\\\\n  <p>对华合作被辉瑞纳入华尔街估值叙事，意味着不只是一家公司的策略调整，而是一个行业定价范式的转变。分析师不再只用专利风险折扣给辉瑞定价，而是开始用中国创新期权给其长期成长加分。</p>\\\\n  <p>这个变化，对中国Biotech一级市场的影响是实质性的。</p>\\\\n  <p>据医药魔方数据，2022年至2026年Q1，中国创新药对外BD首付款整体大涨超187%。三生首付款占总额21%，高于近年生物医药授权交易常见水平，这一细节至少说明，买方愿意将更多价值前置支付。一个处于临床中期、靶点清晰、BD路径可预期的管线，可以参照潜在首付款反推估值，而不再只靠港股18A上市公司的PS打折。</p>\\\\n  <p>对VC而言，一个重要的结构变化正在出现：BD退出正从偶发性超额回报，逐步走向可规划的退出路径，并开始影响部分基金的回报预期框架。</p>\\\\n  <p>与此同时，国内资本市场正在同步打开新的通道。4月10日，证监会正式发布《关于深化创业板改革更好服务新质生产力发展的意见》，核心举措是增设第四套上市标准，为尚未盈利的高成长科技企业正式打开A股大门。两档门槛已明确：新兴产业（市值≥30亿元，近1年营收≥2亿，近3年营收复合增速≥30%）；未来产业（市值≥40亿元，近1年营收≥2亿，近3年研发累计≥1亿且占营收比≥15%）。</p>\\\\n  <p>这意味着，一个手握强BD管线、有License-out收入但尚未盈利的创新药企，现在可以把A股创业板放进上市路径的选项里认真比较。港股18A+纳斯达克+科创板+创业板，正在形成真正意义上的多层次融资矩阵。</p>\\\\n  <p>中国生物医药资产的定价权，正在向本土资本市场回流。</p>\\\\n  <h2><strong>05</strong></h2>\\\\n  <h2><strong>那些总说泡沫的人，错过了什么</strong></h2>\\\\n  <p>每一轮BD高峰到来时，都会有质疑的声音。2024年说热潮已近顶点，2025年说地缘政治太不确定，2026年Q1刚刚突破600亿，一定还有人在说这不正常。</p>\\\\n  <p>但有几个数字，是任何叙事都绕不开的：在研创新药占全球33.7%，超越美国成为第一大国；在研ADC占全球超50%；Q1全球21笔重磅BD，15笔来自中国。</p>\\\\n  <p>这些数字，不是泡沫能解释的。这是一代研究者、临床医生、创业者用十年心血砌起来的技术积累。</p>\\\\n  <p>当辉瑞CEO开始用中国修复自己公司的估值故事，当600亿美元的季度成绩单摆在眼前，当创业板为未盈利的创新公司打开大门。</p>\\\\n  <p>这个行业，已经不需要再问中国创新药会不会成功了。</p>\\\\n  <p>真正值得问的问题，是：你准备好了吗？</p>\\\\n  <p>数据来源：国家药监局、证监会官方文件、医药魔方、科技日报、Reuters、FierceBiotech（截至2026年4月12日）。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/8PPGeYppLG5QGBQpV3wyrA\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“分子稳态”</a>，作者：创新药组&nbsp;稳态君，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<blockquote>\\\\n   <p>2026Q1中国创新药BD交易额破600亿美元。辉瑞等MNC为对冲自身专利悬崖危机，利用中国研发低成本及全球第一的在研管线规模优势，持续购入三生制药等本土高价值资产。该趋势无视地缘博弈，叠加A股创业板改革，正重塑行业定价范式，构建起BD退出常态化的中国创新药多元融资与新估值体系。</p>\\\\n  </blockquote>\\\\n  <p>有一个数字，足以让所有人停下来重新思考这个行业。</p>\\\\n  <p>今年一季度，中国创新药对外授权（BD）交易总额突破600亿美元，这是国家药监局在3月底正式发布的数据。单看这个数字可能没有概念，对比一下：2024年全年，中国创新药出海总额是519亿美元；2025年全年翻了一倍多，达到1357亿美元。而2026年，仅仅一个季度，就已逼近2025年全年的一半。</p>\\\\n  <p>3年前，我们还在讨论国产创新药如何摆脱仿制药依赖。3年后，每周刷屏的BD公告，已经让人有些审美疲劳了。</p>\\\\n  <p>但就在这场出海狂潮中，有一个新的信号悄然浮现，且远比任何单笔交易都更值得关注：</p>\\\\n  <p>辉瑞CEO Albert Bourla，开始在华尔街的公开发言里，把对华合作作为辉瑞估值修复的关键故事来讲。</p>\\\\n  <p>这是一个质变的信号。</p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>辉瑞为什么要押注中国</strong></h2>\\\\n  <p>要理解辉瑞在中国的一系列动作，先得理解它在担心什么。</p>\\\\n  <p>辉瑞正深陷专利悬崖困境：核心产品Eliquis、Ibrance将在2026至2028年陆续失去专利保护。辉瑞管理层在去年11月的杰富瑞会议上承认，专利到期将在本十年末合计影响约170亿美元的营收，公司的增长目标最早要到2029–2030年才能实现。</p>\\\\n  <p>以前更常见的解法，是美国大药企通过本土大并购补管线。辉瑞2023年以430亿美元收购Seagen，并计划主要通过310亿美元新增长期债务等方式完成融资。交易虽然补强了ADC管线，但也带来了债务、整合和短期业绩稀释压力，说明这条路越来越贵。</p>\\\\n  <p>这时候，中国给了一个截然不同的成本结构，据行业估算，中国研发成本约为欧美的1/3至1/2，临床试验速度快30%-50%，而且已深度覆盖ADC、双抗、CAR-T等几乎所有前沿赛道。更关键的是，首付款/总额比相对可控，意味着在药物真正上市前，跨国药企可以用较小的风险锁定高潜力资产。</p>\\\\n  <p>如果说美国大药企的大并购更像是“全款买房”，那么中国BD更像是“分期付款+优先锁定资产”。在这个逻辑下，辉瑞过去12个月在中国有两笔关键动作：一笔是买海外创新权益，另一笔是买中国商业化机会。</p>\\\\n  <p>去年5月，辉瑞以12.5亿美元首付款、潜在总额60.5亿美元，获得三生制药PD-1/VEGF双特异性抗体SSGJ-707在全球（除中国外的全球权益，并附带中国商业化选项）的独家开发、生产和商业化权利，并约定在协议生效时认购价值1亿美元的三生股份；按潜在总额计算，首付款占比约21%。该合作后续于7月24日正式生效。</p>\\\\n  <p>2026年2月，辉瑞中国与先为达生物就偏向型GLP-1受体激动剂埃诺格鲁肽达成商业化战略合作，获得其在中国大陆的独家商业化权益，付款总额最高4.95亿美元；而先为达继续担任MAH，并负责研发、注册、生产和供应。由于该产品已于今年1月获得NMPA批准用于成人2型糖尿病治疗，辉瑞拿到的是上市初期的商业化入口。</p>\\\\n  <p>概括来说，辉瑞这两步分别对应两种能力诉求：前者是出海买创新，后者是入华买商业化机会，并借GLP-1切入代谢赛道。</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>为什么中国值得押注</strong></h2>\\\\n  <p>辉瑞的判断，建立在一组正在被越来越多人认识到的核心数据上。</p>\\\\n  <p>医药魔方数据显示，截至2025年底，中国在研创新药总数达到4751个，占全球总量的33.7%，正式超越美国成为全球在研创新药第一大国。十年前，这个占比是6.9%。</p>\\\\n  <p>这个数字背后还隐藏着中国突出的结构性优势：据科技日报等转引的行业统计，在研细胞疗法项目中，中国占全球48%；在研ADC项目中，中国占全球超50%；全球超1500个进入临床的抗体分子里，中国占近四成。在几乎所有最难、最贵、最代表未来的赛道上，中国都已经进入全球前列。</p>\\\\n  <p>临床转化能力同样完成了验证。2025年中国批准创新药76个，创历史新高，其中包括11个首创新药：如恒瑞医药PCSK9单抗瑞卡西单抗（全球首个给药周期可达6个月的超长效降脂单抗）、康方生物依沃西单抗（全球首个头对头III期优于K药的双抗）、迪哲医药舒沃替尼（全球首个在美获批的EGFR exon20ins NSCLC中国创新药）等。</p>\\\\n  <p>这是辉瑞们真正在押注的东西：不是价格洼地，而是一个创新策源地的兴起。</p>\\\\n  <p>Bourla原话也提到，美国制药业需要与中国合作。过去十年，中国的快速研发流程已占全球药物研发的30%。中国目前拥有约1200种新型候选药物，而十年前只有约60种。</p>\\\\n  <p>60到1200，增长了20倍。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>一场席卷所有人的抢椅子游戏</strong></h2>\\\\n  <p>辉瑞不是孤例。2026年Q1 600亿美元的背后，是一场跨国药企集体涌向中国谈判桌的抢椅子游戏，而且格局正在快速成型。</p>\\\\n  <p>先看这轮出海的三驾马车。</p>\\\\n  <p>双抗是最成熟的战场。康方生物的依沃西单抗在头对头临床中证明PD-1/VEGF双抗可以正面挑战Keytruda（2025年销售额超300亿美元的全球最畅销药物）之后，坐不住了就有艾伯维。</p>\\\\n  <p>今年1月，荣昌生物将PD-1/VEGF双抗RC148授权艾伯维，首付款6.5亿美元、潜在总额56亿美元。值得一提的是，康方生物的依沃西单抗BLA由合作方Summit于2025年底向FDA提交，并于今年1月12日公开宣布，若顺利受理，FDA有望于2026年第四季度作出决定。一旦获批将成为首个在美上市的中国PD-1/VEGF双抗，届时这条赛道的价值将再次被重估。</p>\\\\n  <p>GLP-1受体激动剂赛道无疑是新热点。辉瑞在GLP-1赛道的布局也说明了一个清晰的共识：全球GLP-1市场预计2030年将达到约900亿美元至千亿美元量级，是继PD-1之后最大的药物机会。各路跨国药企已在华展开新一轮抢椅子。</p>\\\\n  <p>而真正的意外，是小核酸的异军突起。今年Q1，瑞博生物将6款MASH siRNA资产打包授权Madrigal：6000万美元首付款+44亿美元潜在里程碑，一笔交易完成了对整个MASH siRNA管线的押注式扫货。小核酸，正在成为继ADC、双抗之后中国创新药出海的第三张王牌。</p>\\\\n  <p>今年Q1，全球21笔重磅BD交易中，15笔是中国交易，披露金额的全球占比达75%。这个数字，已经超出了中国是一个重要来源地的描述范畴，更接近的表述是：中国正在定义全球创新药BD的主战场。</p>\\\\n  <h2><strong>04</strong></h2>\\\\n  <h2><strong>越打压，越押注，一个新估值体系正在形成</strong></h2>\\\\n  <p>有一个看似矛盾的现象，必须正视。</p>\\\\n  <p>一方面，美国《生物安全法》（BIOSECURE Act）已于去年12月随《2026 财年国防授权法》正式签署生效，大大限制了联邦机构与被界定为受关注生物技术公司（biotechnology companies of concern）之间的合同、采购及相关资助联系。美国国家新兴生物技术安全委员会（NSCEB）于去年4月向国会提交的215页报告指出，将中国生物技术崛起定性为国家安全威胁，称若美国三年内不行动，可能再也无法追上。</p>\\\\n  <p>另一方面，辉瑞、礼来、默沙东、GSK、武田一众MNC，一个接一个在中国签下10亿美元级别的协议，跑得比立法者还快。</p>\\\\n  <p>政府在打压，企业在押注。这个错位，本身就是一个信号。</p>\\\\n  <p>对华合作被辉瑞纳入华尔街估值叙事，意味着不只是一家公司的策略调整，而是一个行业定价范式的转变。分析师不再只用专利风险折扣给辉瑞定价，而是开始用中国创新期权给其长期成长加分。</p>\\\\n  <p>这个变化，对中国Biotech一级市场的影响是实质性的。</p>\\\\n  <p>据医药魔方数据，2022年至2026年Q1，中国创新药对外BD首付款整体大涨超187%。三生首付款占总额21%，高于近年生物医药授权交易常见水平，这一细节至少说明，买方愿意将更多价值前置支付。一个处于临床中期、靶点清晰、BD路径可预期的管线，可以参照潜在首付款反推估值，而不再只靠港股18A上市公司的PS打折。</p>\\\\n  <p>对VC而言，一个重要的结构变化正在出现：BD退出正从偶发性超额回报，逐步走向可规划的退出路径，并开始影响部分基金的回报预期框架。</p>\\\\n  <p>与此同时，国内资本市场正在同步打开新的通道。4月10日，证监会正式发布《关于深化创业板改革更好服务新质生产力发展的意见》，核心举措是增设第四套上市标准，为尚未盈利的高成长科技企业正式打开A股大门。两档门槛已明确：新兴产业（市值≥30亿元，近1年营收≥2亿，近3年营收复合增速≥30%）；未来产业（市值≥40亿元，近1年营收≥2亿，近3年研发累计≥1亿且占营收比≥15%）。</p>\\\\n  <p>这意味着，一个手握强BD管线、有License-out收入但尚未盈利的创新药企，现在可以把A股创业板放进上市路径的选项里认真比较。港股18A+纳斯达克+科创板+创业板，正在形成真正意义上的多层次融资矩阵。</p>\\\\n  <p>中国生物医药资产的定价权，正在向本土资本市场回流。</p>\\\\n  <h2><strong>05</strong></h2>\\\\n  <h2><strong>那些总说泡沫的人，错过了什么</strong></h2>\\\\n  <p>每一轮BD高峰到来时，都会有质疑的声音。2024年说热潮已近顶点，2025年说地缘政治太不确定，2026年Q1刚刚突破600亿，一定还有人在说这不正常。</p>\\\\n  <p>但有几个数字，是任何叙事都绕不开的：在研创新药占全球33.7%，超越美国成为第一大国；在研ADC占全球超50%；Q1全球21笔重磅BD，15笔来自中国。</p>\\\\n  <p>这些数字，不是泡沫能解释的。这是一代研究者、临床医生、创业者用十年心血砌起来的技术积累。</p>\\\\n  <p>当辉瑞CEO开始用中国修复自己公司的估值故事，当600亿美元的季度成绩单摆在眼前，当创业板为未盈利的创新公司打开大门。</p>\\\\n  <p>这个行业，已经不需要再问中国创新药会不会成功了。</p>\\\\n  <p>真正值得问的问题，是：你准备好了吗？</p>\\\\n  <p>数据来源：国家药监局、证监会官方文件、医药魔方、科技日报、Reuters、FierceBiotech（截至2026年4月12日）。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/8PPGeYppLG5QGBQpV3wyrA\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“分子稳态”</a>，作者：创新药组&nbsp;稳态君，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'分子稳态\'}], \'author\': \'分子稳态\', \'author_detail\': {\'name\': \'分子稳态\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'这是一个质变的信号\'}]}\", \"published_at\": \"2026-04-16 09:55:53\", \"ai_json_output\": \"\"}', '2026Q1中国创新药BD交易额破600亿美元。辉瑞等MNC为对冲自身专利悬崖危机，利用中国研发低成本及全球第一的在研管线规模优势，持续购入三生制药等本土高价值资产。该趋势无视地缘博弈，叠加A股创业板改革，正重塑行业定价范式，构建起BD退出常态化的中国创新药多元融资与新估值体系。\n有一个数字，足以让所有人停下来重新思考这个行业。\n今年一季度，中国创新药对外授权（BD）交易总额突破600亿美元，这是国家药监局在3月底正式发布的数据。单看这个数字可能没有概念，对比一下：2024年全年，中国创新药出海总额是519亿美元；2025年全年翻了一倍多，达到1357亿美元。而2026年，仅仅一个季度，就已逼近2025年全年的一半。\n3年前，我们还在讨论国产创新药如何摆脱仿制药依赖。3年后，每周刷屏的BD公告，已经让人有些审美疲劳了。\n但就在这场出海狂潮中，有一个新的信号悄然浮现，且远比任何单笔交易都更值得关注：\n辉瑞CEO Albert Bourla，开始在华尔街的公开发言里，把对华合作作为辉瑞估值修复的关键故事来讲。\n这是一个质变的信号。\n01\n辉瑞为什么要押注中国\n要理解辉瑞在中国的一系列动作，先得理解它在担心什么。\n辉瑞正深陷专利悬崖困境：核心产品Eliquis、Ibrance将在2026至2028年陆续失去专利保护。辉瑞管理层在去年11月的杰富瑞会议上承认，专利到期将在本十年末合计影响约170亿美元的营收，公司的增长目标最早要到2029–2030年才能实现。\n以前更常见的解法，是美国大药企通过本土大并购补管线。辉瑞2023年以430亿美元收购Seagen，并计划主要通过310亿美元新增长期债务等方式完成融资。交易虽然补强了ADC管线，但也带来了债务、整合和短期业绩稀释压力，说明这条路越来越贵。\n这时候，中国给了一个截然不同的成本结构，据行业估算，中国研发成本约为欧美的1/3至1/2，临床试验速度快30%-50%，而且已深度覆盖ADC、双抗、CAR-T等几乎所有前沿赛道。更关键的是，首付款/总额比相对可控，意味着在药物真正上市前，跨国药企可以用较小的风险锁定高潜力资产。\n如果说美国大药企的大并购更像是“全款买房”，那么中国BD更像是“分期付款+优先锁定资产”。在这个逻辑下，辉瑞过去12个月在中国有两笔关键动作：一笔是买海外创新权益，另一笔是买中国商业化机会。\n去年5月，辉瑞以12.5亿美元首付款、潜在总额60.5亿美元，获得三生制药PD-1/VEGF双特异性抗体SSGJ-707在全球（除中国外的全球权益，并附带中国商业化选项）的独家开发、生产和商业化权利，并约定在协议生效时认购价值1亿美元的三生股份；按潜在总额计算，首付款占比约21%。该合作后续于7月24日正式生效。\n2026年2月，辉瑞中国与先为达生物就偏向型GLP-1受体激动剂埃诺格鲁肽达成商业化战略合作，获得其在中国大陆的独家商业化权益，付款总额最高4.95亿美元；而先为达继续担任MAH，并负责研发、注册、生产和供应。由于该产品已于今年1月获得NMPA批准用于成人2型糖尿病治疗，辉瑞拿到的是上市初期的商业化入口。\n概括来说，辉瑞这两步分别对应两种能力诉求：前者是出海买创新，后者是入华买商业化机会，并借GLP-1切入代谢赛道。\n02\n为什么中国值得押注\n辉瑞的判断，建立在一组正在被越来越多人认识到的核心数据上。\n医药魔方数据显示，截至2025年底，中国在研创新药总数达到4751个，占全球总量的33.7%，正式超越美国成为全球在研创新药第一大国。十年前，这个占比是6.9%。\n这个数字背后还隐藏着中国突出的结构性优势：据科技日报等转引的行业统计，在研细胞疗法项目中，中国占全球48%；在研ADC项目中，中国占全球超50%；全球超1500个进入临床的抗体分子里，中国占近四成。在几乎所有最难、最贵、最代表未来的赛道上，中国都已经进入全球前列。\n临床转化能力同样完成了验证。2025年中国批准创新药76个，创历史新高，其中包括11个首创新药：如恒瑞医药PCSK9单抗瑞卡西单抗（全球首个给药周期可达6个月的超长效降脂单抗）、康方生物依沃西单抗（全球首个头对头III期优于K药的双抗）、迪哲医药舒沃替尼（全球首个在美获批的EGFR exon20ins NSCLC中国创新药）等。\n这是辉瑞们真正在押注的东西：不是价格洼地，而是一个创新策源地的兴起。\nBourla原话也提到，美国制药业需要与中国合作。过去十年，中国的快速研发流程已占全球药物研发的30%。中国目前拥有约1200种新型候选药物，而十年前只有约60种。\n60到1200，增长了20倍。\n03\n一场席卷所有人的抢椅子游戏\n辉瑞不是孤例。2026年Q1 600亿美元的背后，是一场跨国药企集体涌向中国谈判桌的抢椅子游戏，而且格局正在快速成型。\n先看这轮出海的三驾马车。\n双抗是最成熟的战场。康方生物的依沃西单抗在头对头临床中证明PD-1/VEGF双抗可以正面挑战Keytruda（2025年销售额超300亿美元的全球最畅销药物）之后，坐不住了就有艾伯维。\n今年1月，荣昌生物将PD-1/VEGF双抗RC148授权艾伯维，首付款6.5亿美元、潜在总额56亿美元。值得一提的是，康方生物的依沃西单抗BLA由合作方Summit于2025年底向FDA提交，并于今年1月12日公开宣布，若顺利受理，FDA有望于2026年第四季度作出决定。一旦获批将成为首个在美上市的中国PD-1/VEGF双抗，届时这条赛道的价值将再次被重估。\nGLP-1受体激动剂赛道无疑是新热点。辉瑞在GLP-1赛道的布局也说明了一个清晰的共识：全球GLP-1市场预计2030年将达到约900亿美元至千亿美元量级，是继PD-1之后最大的药物机会。各路跨国药企已在华展开新一轮抢椅子。\n而真正的意外，是小核酸的异军突起。今年Q1，瑞博生物将6款MASH siRNA资产打包授权Madrigal：6000万美元首付款+44亿美元潜在里程碑，一笔交易完成了对整个MASH siRNA管线的押注式扫货。小核酸，正在成为继ADC、双抗之后中国创新药出海的第三张王牌。\n今年Q1，全球21笔重磅BD交易中，15笔是中国交易，披露金额的全球占比达75%。这个数字，已经超出了中国是一个重要来源地的描述范畴，更接近的表述是：中国正在定义全球创新药BD的主战场。\n04\n越打压，越押注，一个新估值体系正在形成\n有一个看似矛盾的现象，必须正视。\n一方面，美国《生物安全法》（BIOSECURE Act）已于去年12月随《2026 财年国防授权法》正式签署生效，大大限制了联邦机构与被界定为受关注生物技术公司（biotechnology companies of concern）之间的合同、采购及相关资助联系。美国国家新兴生物技术安全委员会（NSCEB）于去年4月向国会提交的215页报告指出，将中国生物技术崛起定性为国家安全威胁，称若美国三年内不行动，可能再也无法追上。\n另一方面，辉瑞、礼来、默沙东、GSK、武田一众MNC，一个接一个在中国签下10亿美元级别的协议，跑得比立法者还快。\n政府在打压，企业在押注。这个错位，本身就是一个信号。\n对华合作被辉瑞纳入华尔街估值叙事，意味着不只是一家公司的策略调整，而是一个行业定价范式的转变。分析师不再只用专利风险折扣给辉瑞定价，而是开始用中国创新期权给其长期成长加分。\n这个变化，对中国Biotech一级市场的影响是实质性的。\n据医药魔方数据，2022年至2026年Q1，中国创新药对外BD首付款整体大涨超187%。三生首付款占总额21%，高于近年生物医药授权交易常见水平，这一细节至少说明，买方愿意将更多价值前置支付。一个处于临床中期、靶点清晰、BD路径可预期的管线，可以参照潜在首付款反推估值，而不再只靠港股18A上市公司的PS打折。\n对VC而言，一个重要的结构变化正在出现：BD退出正从偶发性超额回报，逐步走向可规划的退出路径，并开始影响部分基金的回报预期框架。\n与此同时，国内资本市场正在同步打开新的通道。4月10日，证监会正式发布《关于深化创业板改革更好服务新质生产力发展的意见》，核心举措是增设第四套上市标准，为尚未盈利的高成长科技企业正式打开A股大门。两档门槛已明确：新兴产业（市值≥30亿元，近1年营收≥2亿，近3年营收复合增速≥30%）；未来产业（市值≥40亿元，近1年营收≥2亿，近3年研发累计≥1亿且占营收比≥15%）。\n这意味着，一个手握强BD管线、有License-out收入但尚未盈利的创新药企，现在可以把A股创业板放进上市路径的选项里认真比较。港股18A+纳斯达克+科创板+创业板，正在形成真正意义上的多层次融资矩阵。\n中国生物医药资产的定价权，正在向本土资本市场回流。\n05\n那些总说泡沫的人，错过了什么\n每一轮BD高峰到来时，都会有质疑的声音。2024年说热潮已近顶点，2025年说地缘政治太不确定，2026年Q1刚刚突破600亿，一定还有人在说这不正常。\n但有几个数字，是任何叙事都绕不开的：在研创新药占全球33.7%，超越美国成为第一大国；在研ADC占全球超50%；Q1全球21笔重磅BD，15笔来自中国。\n这些数字，不是泡沫能解释的。这是一代研究者、临床医生、创业者用十年心血砌起来的技术积累。\n当辉瑞CEO开始用中国修复自己公司的估值故事，当600亿美元的季度成绩单摆在眼前，当创业板为未盈利的创新公司打开大门。\n这个行业，已经不需要再问中国创新药会不会成功了。\n真正值得问的问题，是：你准备好了吗？\n数据来源：国家药监局、证监会官方文件、医药魔方、科技日报、Reuters、FierceBiotech（截至2026年4月12日）。\n本文来自微信公众号\n“分子稳态”\n，作者：创新药组 稳态君，36氪经授权发布。', '2026-04-16 09:55:53', '2026-04-16 11:47:51');
INSERT INTO `news_detail` VALUES (22, 983, 16, '食品与农业出海', '山东调味品，撑起了中国厨房的半壁江山', '', '<p>如果你想在最短时间内把后厨的调味料配齐，最好的办法是找一个山东人。</p>\n<p>从鲁菜后厨的一碗甜面酱，到全国餐桌的一瓶小磨香油，再到海外商超的一袋复合香辛料……山东人早已把酱油、食醋、香辛料、复合调味料的生意做遍了大江南北。</p>\n<p>企查查数据也显示，<strong>山东现存4.8万家调味品相关企业，全国第一。</strong></p>\n<p>但奇怪的是，你问一个山东以外的消费者“山东有什么调味品品牌”，大部分人想半天可能说不出一二三。</p>\n<p><strong>全国最多的企业，却没能长出足够多的全国性品牌。</strong>山东调味品的家底，到底藏在哪？</p>\n<h2><strong>01.酱是底色</strong></h2>\n<p>山东的调味天赋，首先来自风土。</p>\n<p>在章丘，肥沃的耕地加上雨热同期的温带季风，孕育出比人高的大葱。还有济宁金乡的大蒜、莱芜的生姜，都稳坐“全国农产品地理标志”。</p>\n<p>除了基础的葱姜蒜，山东人还尤其偏爱“酱”。山东的酱料种类丰富，经典代表有大葱蘸酱、黄豆酱（黄酱）、甜面酱、辣椒酱、芝麻酱等。没吃过大葱蘸酱，约等于没来过山东。</p>\n<p>此外，今天还能尝到蠓子虾酱、郓城西瓜酱、尚书府馍馍酱以及各色酱菜，这些具有鲜明地域特色的酱料，都是山东酱文化的缩影。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_71c2003e37b44995b738ce5eb51b2588@5781278_oswg991981oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：图虫创意</p>\n<p><strong>酱文化的载体是酱园，专事发酵的地方。</strong>据1928年《历城县乡土调查录》记载，单单是济南城，就有146家酱园，包括著名的醴泉居、北厚记、兴顺福和德馨斋。那时候大酱园号称“五魁手”，指酿酒、制醋、酱油、腌菜和榨油都做。</p>\n<p>山东厨师也认这些，糖醋鲤鱼、葱烧海参、九转大肠等经典鲁菜都会用到黄豆酱或甜面酱来调味。绝对点说，<strong>没有黄豆酱、甜面酱，就没有鲁菜的浓油赤酱、酱爆鲜香。</strong></p>\n<p>酱园不仅养了鲁菜，还早早将山东酱料送出了省、销往国外。清宣统年间，威海豆面酱已成为朝中贡品。</p>\n<p>20世纪初，威海四海酱园的产品端上了日本、高丽的餐桌。彼时，北京、天津、徐州、武汉等大中城市都能买到鲁地的酱香风味。走海运的货物也可以从济南、淄博、周村、潍县、龙口、济宁等商埠出发，沿胶济铁路这条大动脉到达威海、青岛等港口。</p>\n<p>有酿造传统、有渠道，山东调味品产业由此攒下了规模化的家底。此后各地酿造厂陆续合并，逐渐出现了德馨斋、玉兔、崔字牌等传承百年工艺的中华老字号。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_25b4e95d0fda4cf5bfc94b065e13dd52@5781278_oswg850992oswg1080oswg428_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△崔字牌的石磨工艺，图源：瑞福油脂官网</p>\n<p>到了八九十年代，工业化开始重新整合地方资源。莲花控股、长寿花、欣和、一品农产等老牌调味品企业先后起步，在味精、玉米油、原酿酱、姜蒜深加工等领域进行自主研发和生产。</p>\n<p>山东省工信厅的报告显示，2023年山东调味品已成为重点做大的200亿体量的行业聚集区。</p>\n<p>而这张庞大的产业地图上，有两个小镇的故事格外耐人寻味。它们都不是原料大户，却都成了全国乃至全球的调味品重镇。</p>\n<h2><strong>02.不产原料的小镇</strong></h2>\n<p>杨安镇，总面积88.47平方公里，是全国调味品集散地，被誉为“中国调味品第一镇”。根据新华网的报道，截至去年12月，这个小镇上已有调味品生产加工企业300多家，复合香辛料占全国40%以上市场份额，出口到了70多个国家和地区。</p>\n<p>只是，这个“小镇奇迹”并不是靠山东的物产资源发家，而是靠敏锐的商业嗅觉和超强的加工能力。</p>\n<p>杨安镇调味品产业，是从当地人卖调料原料开始。上世纪70年代，耕种庄稼的杨安镇人喜欢在自留地上种点辣椒来吃，吃不完的辣椒他们磨成辣椒面存放起来。碰到农闲时，村民们会推着车子，去外地做点手艺活，辣椒面被当成了附属品出售。</p>\n<p>渐渐地，杨安镇人发现东北、山西等地对辣椒面有很大市场需求，于是杨安镇人开始去四川、陕西等地收购辣椒，回来进行加工再销售。再后来，他们还卖起了花椒粉、五香粉等产品，经营品类持续拓展。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_00856353a5c84d0db89d1cf046e55f69@5781278_oswg1342178oswg1080oswg719_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：图虫创意</p>\n<p>90年代，注册公司、投资建厂取代了过去的小作坊式生产，新飞达、庞大、乐畅、华畅、腾达等龙头企业相继落地杨安镇，以工业级品质和规模化产出进一步打开市场。</p>\n<p>但随着调味品企业的增加，各企业产品开始高度雷同，市场竞争激烈。<strong>如何让调味品产业破局“出圈”？杨安镇打出了抱团牌。</strong></p>\n<p>2018年，“味都杨安”区域公共品牌成立。在前端，杨安镇调味品集团整合中小企业的原料需求，与云南、四川等原料供应商谈采购价，在终端有“味都杨安”统一标识的调味品被摆放在了商超等渠道的显眼位置。</p>\n<p>“调二代”“调三代”接了班，又利用电商给杨安镇添了把火。2022年，味都杨安的调味品成为德州首个年寄递量过5000万件的单类产品。2024年，快递单量已突破1.5亿。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_68b6234d2c984a9f928efbeb6dc72f8d@5781278_oswg92932oswg1080oswg653_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：“乐陵旅游”公众号</p>\n<p>如今，杨安镇的调味品博物馆里陈列着1200余种本地生产的调味品。在杨安镇，你可以一站购齐方便面调料包、火腿肠调料，黄焖鸡、瓦罐汤的汤底，烧烤撒料，火锅底料，各地名菜的复合调料，还有西餐、泰餐、韩餐等异国风味产品……</p>\n<p>杨安镇的发家史，是整个山东调味品升级的缩影，它吸纳了全国的香辛料资源，早早占据附加值更高的加工环节，最后变成谁也不可撼动的集散枢纽，手里攥着定价权。</p>\n<h2><strong>03.辣椒宇宙的尽头</strong></h2>\n<p>如果说杨安镇走的是“复合香辛料”路线，那胶州于家村做的则是“辣椒单品”。</p>\n<p>做辣椒买卖的人，十有八九逛过“环球辣椒网”。这家网站不仅按天刷新全国各地的辣椒价格，还能发帖求购或售出，俨然一个线上大市场。</p>\n<p>而它的首页栏目赫然并列着：<strong>国内、国际、于家村。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_327f7b467bdd465f9a889a0e27a49c32@5781278_oswg15991oswg343oswg155_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：环球辣椒网</p>\n<p>于家村在哪儿？山东人会告诉你，那是辣椒宇宙的尽头。</p>\n<p>于家村所在的胶州市是中国北方最大的干制辣椒集散地，青岛市辣椒产业商会、胶州辣椒产业协会会长王勇曾介绍，于家村的辣椒市场年交易量约120万吨，市场交易额超160亿元。村里的大椒城也是全国辣椒产业的“晴雨表”。</p>\n<p>但胶州的辣椒并不算土生土长，它的根来自100多公里外的青州市。</p>\n<p>1964年，胶州开始从青州引进羊角椒试种，到90年代时种植面积达15万亩。这期间，胶州市还被确定为山东省辣椒生产出口基地。</p>\n<p>随着出口量的不断攀升，原料供应已经跟不上加工需求，种植环节便开始自然地外溢。先是山东省内的青岛、潍坊、聊城、德州接手，从鲁东跨至鲁西。</p>\n<p>再然后，种子又被带去了河南、河北、新疆、内蒙古等省份广泛种植，累计建设辣椒种植示范基地300多万亩。</p>\n<p>种植和加工不在一地，就需要人把外地的干辣椒运回胶州，这些人就叫“辣椒耗子”。他们构成了输送辣椒原料的毛细血管。至今，胶州的“辣椒耗子”已超过2000人。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_b561edadebb045b6b4ec6d8906b56968@5781278_oswg937349oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：图虫创意</p>\n<p>“放种”虽然缓解了原料压力，却也带来了一堆麻烦，比如：外地种植户盲目跟栽、品质杂乱、出口农残超标、色价不高被退货……</p>\n<p>为此，胶州政府联合骨干企业和种植大户，率先推出“订单种植+统一标准”模式：先接国外订单，明确辣椒的色价、辣度、农残标准，再和外地农户签种植协议，提供优质种苗和技术指导，最后统一回收。</p>\n<p>2022年3月，胶州正式启动了上合国际绿色农产品博览会交易中心项目，该项目预计2027年交易额达到600亿元。据介绍，该中心整合了线上交易、冷链仓储、检验检测、金融服务等多种功能，将物流、金融等流程一次打通。</p>\n<p>从引进种植到“放种”模式，当地辣椒企业能更专注于育种和加工升级，扩大出口产品的溢价空间，从初级农产品升级为高端定制。</p>\n<p>今天的胶州已把控了辣椒的种源、加工和贸易，也掌握了辣椒副产品的定价权。据统计，胶州已有辣椒加工企业 300余家，其中72家有出口权，<strong>辣椒产品出口量占全国的七成以上。</strong></p>\n<h2><strong>04.4.8万家最后能留下多少？</strong></h2>\n<p>描绘山东调味品的真实底色，不能只看宏观的产业版图，更要看微观的企业画像。</p>\n<p>将视线拉回全省。今天的山东调味品赛道上，也跑出了一批具有代表性的样本，既有承袭百年工艺的守正者，也有后来居上的弄潮儿。</p>\n<p>“山东调味品一哥”欣和，旗下六月鲜、禾然、味达美、葱伴侣等品牌的产品在北方市场很吃得开，长年占据各大商超的核心位置。</p>\n<p>食醋赛道，玉兔有红曲米醋，巧媳妇有清香米醋。</p>\n<p>山东云德食品，旗下既有老字号“德馨斋”的五粮醋、甜面酱，也有“云享”牌各类火锅底料，是鲁菜餐饮企业的核心供应商。</p>\n<p>日辰股份则专注复合调味料的餐饮定制生产，旗下“味之物语”品牌面向终端消费者，2023年和2024年均保持营收的双位数增长。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_69f9e888f68f477c9a54ed4a0d8cb0e7@5781278_oswg156285oswg1080oswg668_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：红餐供应链指南摄</p>\n<p>同为上市公司的莲花股份除了味精，也有豆瓣酱、甜面酱、火锅蘸料等产品。</p>\n<p>长寿花、鲁花以粮油为主，同时也有推酱油等产品；崔字牌守着小磨香油的细分赛道；一品农产是中国鲜蒜蓉、鲜姜蓉的开创者，年创汇超2500万美元。</p>\n<p>但从另一个视角看，也有一些潜在问题。</p>\n<p>酱油、豆瓣酱、黄豆酱等传统品类的增速放缓，不同品牌、同一品类很容易互相替代。尤其在供应链效率提升的前提下，一些具有规模化优势和品牌光环的南方品牌开始进入北方市场，铺上货架，山东本土企业正面临被瓜分蛋糕的威胁。</p>\n<p><strong>以酱油为例，“一哥”欣和尚且稳健，但大部分区域老字号过度依赖本地市场，应对头部冲击的能力弱。</strong>据“泰山财经”报道，“弯腰”“寻找”成了消费者在济南商超选购老牌山东酱油的常态，海天、厨邦、千禾等粤、川品牌占比超五成。</p>\n<p>此外，曾为八大菜系之首的鲁菜，还没跑出门店体量特别大的连锁品牌，且鲁菜费时费力的制作工艺很难跟上今天的快节奏生活，鲁地风格的调味品需求自然也难打开。</p>\n<p>从企业数量上看，山东还是调味品第一大省，但位居其后的河北省，盘踞了远东食品、老磨坊、益彰食品等老牌企业，排名第三的广东则汇聚了海天、中炬高新、百利食品、东古等企业，这两个省份在调味品产业发展层面，亦有雄厚的实力。此外，四川的调味品企业数量排名近几年有所上升，川味复调发展较迅猛。</p>\n<p>企查查显示，2023年9月，山东有调味品企业5.63万家，2024年1月缩减至5.55万家。截至2026年4月15日，该项数据为4.8万家。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_8c29cc7e300549c893844b56f1b4a269@5781278_oswg264923oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>△图源：企查查</p>\n<p>事实上，<strong>不只是山东，整个调味品行业的企业数量都在减少。</strong>在经历连锁餐饮爆发、调味品企业趋于饱和后，行业又逐渐降温，进入综合性企业领跑、“大鱼吃小鱼”的新阶段。</p>\n<p>不缺产能、不缺工艺、不缺口碑，山东调味品历经百年，正站在又一个十字路口。</p>\n<p>4.8万家 企业，最后能留下多少，谁也不知道。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/tMtdQAbrRMtVpAsYmaMzRA\">“红餐供应链指南”</a>，作者：春莹，编辑：景雪，36氪经授权发布。</p>', 'https://36kr.com/p/3768806257701639?f=rss', 0, '', '{\"summary\": \"帮助调味品出海从业者了解山东调味品产业发展现状，洞悉国内调味品产业出海的优势与潜在挑战\", \"abstract\": \"山东是国内调味品相关企业数量最多的省份，依托深厚的酱文化传承与产业基础，已经形成200亿体量的调味品产业聚集区，多个特色产区的产品已出口至全球多个国家和地区。当地发展出杨安镇复合香辛料集散、胶州辣椒贸易等特色产业模式，胶州辣椒出口量占全国七成以上，还诞生了欣和、日辰等一批代表性头部企业。目前山东调味品产业仍存在缺乏强势全国性知名品牌、区域老字号过度依赖本地市场等问题，正面临其他省份头部品牌的市场竞争压力。当前国内调味品行业进入整合淘汰阶段，山东调味品产业正处于转型升级的关键路口，其产业发展与出海布局经验对国内调味品出海具备较高参考价值。\", \"keywords\": [\"调味品出海\", \"山东调味品\", \"食品出口\", \"复合香辛料\", \"辣椒出口\", \"产业集群\", \"调味品出口\"], \"policy_risk\": {\"market_risk\": \"山东本土调味品品牌力不足，多数区域老字号依赖本地市场，应对头部品牌冲击能力弱，面临省外头部品牌的市场挤压；国内调味品行业进入整合阶段，企业数量持续缩减，中小调味品企业面临淘汰风险；鲁菜连锁化发展不足，限制了鲁系调味品的市场拓展空间\", \"policy_compliance\": \"出口调味品需满足目标市场对产品的色价、辣度、农残等品质标准要求，国内地方政府推动\\\"订单种植+统一标准\\\"模式适配出口合规要求\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"食品与农业出海\"}', '', '{\"url\": \"https://36kr.com/p/3768806257701639?f=rss\", \"title\": \"山东调味品，撑起了中国厨房的半壁江山\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>如果你想在最短时间内把后厨的调味料配齐，最好的办法是找一个山东人。</p>\\n<p>从鲁菜后厨的一碗甜面酱，到全国餐桌的一瓶小磨香油，再到海外商超的一袋复合香辛料……山东人早已把酱油、食醋、香辛料、复合调味料的生意做遍了大江南北。</p>\\n<p>企查查数据也显示，<strong>山东现存4.8万家调味品相关企业，全国第一。</strong></p>\\n<p>但奇怪的是，你问一个山东以外的消费者“山东有什么调味品品牌”，大部分人想半天可能说不出一二三。</p>\\n<p><strong>全国最多的企业，却没能长出足够多的全国性品牌。</strong>山东调味品的家底，到底藏在哪？</p>\\n<h2><strong>01.酱是底色</strong></h2>\\n<p>山东的调味天赋，首先来自风土。</p>\\n<p>在章丘，肥沃的耕地加上雨热同期的温带季风，孕育出比人高的大葱。还有济宁金乡的大蒜、莱芜的生姜，都稳坐“全国农产品地理标志”。</p>\\n<p>除了基础的葱姜蒜，山东人还尤其偏爱“酱”。山东的酱料种类丰富，经典代表有大葱蘸酱、黄豆酱（黄酱）、甜面酱、辣椒酱、芝麻酱等。没吃过大葱蘸酱，约等于没来过山东。</p>\\n<p>此外，今天还能尝到蠓子虾酱、郓城西瓜酱、尚书府馍馍酱以及各色酱菜，这些具有鲜明地域特色的酱料，都是山东酱文化的缩影。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_71c2003e37b44995b738ce5eb51b2588@5781278_oswg991981oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：图虫创意</p>\\n<p><strong>酱文化的载体是酱园，专事发酵的地方。</strong>据1928年《历城县乡土调查录》记载，单单是济南城，就有146家酱园，包括著名的醴泉居、北厚记、兴顺福和德馨斋。那时候大酱园号称“五魁手”，指酿酒、制醋、酱油、腌菜和榨油都做。</p>\\n<p>山东厨师也认这些，糖醋鲤鱼、葱烧海参、九转大肠等经典鲁菜都会用到黄豆酱或甜面酱来调味。绝对点说，<strong>没有黄豆酱、甜面酱，就没有鲁菜的浓油赤酱、酱爆鲜香。</strong></p>\\n<p>酱园不仅养了鲁菜，还早早将山东酱料送出了省、销往国外。清宣统年间，威海豆面酱已成为朝中贡品。</p>\\n<p>20世纪初，威海四海酱园的产品端上了日本、高丽的餐桌。彼时，北京、天津、徐州、武汉等大中城市都能买到鲁地的酱香风味。走海运的货物也可以从济南、淄博、周村、潍县、龙口、济宁等商埠出发，沿胶济铁路这条大动脉到达威海、青岛等港口。</p>\\n<p>有酿造传统、有渠道，山东调味品产业由此攒下了规模化的家底。此后各地酿造厂陆续合并，逐渐出现了德馨斋、玉兔、崔字牌等传承百年工艺的中华老字号。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_25b4e95d0fda4cf5bfc94b065e13dd52@5781278_oswg850992oswg1080oswg428_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△崔字牌的石磨工艺，图源：瑞福油脂官网</p>\\n<p>到了八九十年代，工业化开始重新整合地方资源。莲花控股、长寿花、欣和、一品农产等老牌调味品企业先后起步，在味精、玉米油、原酿酱、姜蒜深加工等领域进行自主研发和生产。</p>\\n<p>山东省工信厅的报告显示，2023年山东调味品已成为重点做大的200亿体量的行业聚集区。</p>\\n<p>而这张庞大的产业地图上，有两个小镇的故事格外耐人寻味。它们都不是原料大户，却都成了全国乃至全球的调味品重镇。</p>\\n<h2><strong>02.不产原料的小镇</strong></h2>\\n<p>杨安镇，总面积88.47平方公里，是全国调味品集散地，被誉为“中国调味品第一镇”。根据新华网的报道，截至去年12月，这个小镇上已有调味品生产加工企业300多家，复合香辛料占全国40%以上市场份额，出口到了70多个国家和地区。</p>\\n<p>只是，这个“小镇奇迹”并不是靠山东的物产资源发家，而是靠敏锐的商业嗅觉和超强的加工能力。</p>\\n<p>杨安镇调味品产业，是从当地人卖调料原料开始。上世纪70年代，耕种庄稼的杨安镇人喜欢在自留地上种点辣椒来吃，吃不完的辣椒他们磨成辣椒面存放起来。碰到农闲时，村民们会推着车子，去外地做点手艺活，辣椒面被当成了附属品出售。</p>\\n<p>渐渐地，杨安镇人发现东北、山西等地对辣椒面有很大市场需求，于是杨安镇人开始去四川、陕西等地收购辣椒，回来进行加工再销售。再后来，他们还卖起了花椒粉、五香粉等产品，经营品类持续拓展。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_00856353a5c84d0db89d1cf046e55f69@5781278_oswg1342178oswg1080oswg719_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：图虫创意</p>\\n<p>90年代，注册公司、投资建厂取代了过去的小作坊式生产，新飞达、庞大、乐畅、华畅、腾达等龙头企业相继落地杨安镇，以工业级品质和规模化产出进一步打开市场。</p>\\n<p>但随着调味品企业的增加，各企业产品开始高度雷同，市场竞争激烈。<strong>如何让调味品产业破局“出圈”？杨安镇打出了抱团牌。</strong></p>\\n<p>2018年，“味都杨安”区域公共品牌成立。在前端，杨安镇调味品集团整合中小企业的原料需求，与云南、四川等原料供应商谈采购价，在终端有“味都杨安”统一标识的调味品被摆放在了商超等渠道的显眼位置。</p>\\n<p>“调二代”“调三代”接了班，又利用电商给杨安镇添了把火。2022年，味都杨安的调味品成为德州首个年寄递量过5000万件的单类产品。2024年，快递单量已突破1.5亿。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_68b6234d2c984a9f928efbeb6dc72f8d@5781278_oswg92932oswg1080oswg653_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：“乐陵旅游”公众号</p>\\n<p>如今，杨安镇的调味品博物馆里陈列着1200余种本地生产的调味品。在杨安镇，你可以一站购齐方便面调料包、火腿肠调料，黄焖鸡、瓦罐汤的汤底，烧烤撒料，火锅底料，各地名菜的复合调料，还有西餐、泰餐、韩餐等异国风味产品……</p>\\n<p>杨安镇的发家史，是整个山东调味品升级的缩影，它吸纳了全国的香辛料资源，早早占据附加值更高的加工环节，最后变成谁也不可撼动的集散枢纽，手里攥着定价权。</p>\\n<h2><strong>03.辣椒宇宙的尽头</strong></h2>\\n<p>如果说杨安镇走的是“复合香辛料”路线，那胶州于家村做的则是“辣椒单品”。</p>\\n<p>做辣椒买卖的人，十有八九逛过“环球辣椒网”。这家网站不仅按天刷新全国各地的辣椒价格，还能发帖求购或售出，俨然一个线上大市场。</p>\\n<p>而它的首页栏目赫然并列着：<strong>国内、国际、于家村。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_327f7b467bdd465f9a889a0e27a49c32@5781278_oswg15991oswg343oswg155_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：环球辣椒网</p>\\n<p>于家村在哪儿？山东人会告诉你，那是辣椒宇宙的尽头。</p>\\n<p>于家村所在的胶州市是中国北方最大的干制辣椒集散地，青岛市辣椒产业商会、胶州辣椒产业协会会长王勇曾介绍，于家村的辣椒市场年交易量约120万吨，市场交易额超160亿元。村里的大椒城也是全国辣椒产业的“晴雨表”。</p>\\n<p>但胶州的辣椒并不算土生土长，它的根来自100多公里外的青州市。</p>\\n<p>1964年，胶州开始从青州引进羊角椒试种，到90年代时种植面积达15万亩。这期间，胶州市还被确定为山东省辣椒生产出口基地。</p>\\n<p>随着出口量的不断攀升，原料供应已经跟不上加工需求，种植环节便开始自然地外溢。先是山东省内的青岛、潍坊、聊城、德州接手，从鲁东跨至鲁西。</p>\\n<p>再然后，种子又被带去了河南、河北、新疆、内蒙古等省份广泛种植，累计建设辣椒种植示范基地300多万亩。</p>\\n<p>种植和加工不在一地，就需要人把外地的干辣椒运回胶州，这些人就叫“辣椒耗子”。他们构成了输送辣椒原料的毛细血管。至今，胶州的“辣椒耗子”已超过2000人。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b561edadebb045b6b4ec6d8906b56968@5781278_oswg937349oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：图虫创意</p>\\n<p>“放种”虽然缓解了原料压力，却也带来了一堆麻烦，比如：外地种植户盲目跟栽、品质杂乱、出口农残超标、色价不高被退货……</p>\\n<p>为此，胶州政府联合骨干企业和种植大户，率先推出“订单种植+统一标准”模式：先接国外订单，明确辣椒的色价、辣度、农残标准，再和外地农户签种植协议，提供优质种苗和技术指导，最后统一回收。</p>\\n<p>2022年3月，胶州正式启动了上合国际绿色农产品博览会交易中心项目，该项目预计2027年交易额达到600亿元。据介绍，该中心整合了线上交易、冷链仓储、检验检测、金融服务等多种功能，将物流、金融等流程一次打通。</p>\\n<p>从引进种植到“放种”模式，当地辣椒企业能更专注于育种和加工升级，扩大出口产品的溢价空间，从初级农产品升级为高端定制。</p>\\n<p>今天的胶州已把控了辣椒的种源、加工和贸易，也掌握了辣椒副产品的定价权。据统计，胶州已有辣椒加工企业 300余家，其中72家有出口权，<strong>辣椒产品出口量占全国的七成以上。</strong></p>\\n<h2><strong>04.4.8万家最后能留下多少？</strong></h2>\\n<p>描绘山东调味品的真实底色，不能只看宏观的产业版图，更要看微观的企业画像。</p>\\n<p>将视线拉回全省。今天的山东调味品赛道上，也跑出了一批具有代表性的样本，既有承袭百年工艺的守正者，也有后来居上的弄潮儿。</p>\\n<p>“山东调味品一哥”欣和，旗下六月鲜、禾然、味达美、葱伴侣等品牌的产品在北方市场很吃得开，长年占据各大商超的核心位置。</p>\\n<p>食醋赛道，玉兔有红曲米醋，巧媳妇有清香米醋。</p>\\n<p>山东云德食品，旗下既有老字号“德馨斋”的五粮醋、甜面酱，也有“云享”牌各类火锅底料，是鲁菜餐饮企业的核心供应商。</p>\\n<p>日辰股份则专注复合调味料的餐饮定制生产，旗下“味之物语”品牌面向终端消费者，2023年和2024年均保持营收的双位数增长。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_69f9e888f68f477c9a54ed4a0d8cb0e7@5781278_oswg156285oswg1080oswg668_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：红餐供应链指南摄</p>\\n<p>同为上市公司的莲花股份除了味精，也有豆瓣酱、甜面酱、火锅蘸料等产品。</p>\\n<p>长寿花、鲁花以粮油为主，同时也有推酱油等产品；崔字牌守着小磨香油的细分赛道；一品农产是中国鲜蒜蓉、鲜姜蓉的开创者，年创汇超2500万美元。</p>\\n<p>但从另一个视角看，也有一些潜在问题。</p>\\n<p>酱油、豆瓣酱、黄豆酱等传统品类的增速放缓，不同品牌、同一品类很容易互相替代。尤其在供应链效率提升的前提下，一些具有规模化优势和品牌光环的南方品牌开始进入北方市场，铺上货架，山东本土企业正面临被瓜分蛋糕的威胁。</p>\\n<p><strong>以酱油为例，“一哥”欣和尚且稳健，但大部分区域老字号过度依赖本地市场，应对头部冲击的能力弱。</strong>据“泰山财经”报道，“弯腰”“寻找”成了消费者在济南商超选购老牌山东酱油的常态，海天、厨邦、千禾等粤、川品牌占比超五成。</p>\\n<p>此外，曾为八大菜系之首的鲁菜，还没跑出门店体量特别大的连锁品牌，且鲁菜费时费力的制作工艺很难跟上今天的快节奏生活，鲁地风格的调味品需求自然也难打开。</p>\\n<p>从企业数量上看，山东还是调味品第一大省，但位居其后的河北省，盘踞了远东食品、老磨坊、益彰食品等老牌企业，排名第三的广东则汇聚了海天、中炬高新、百利食品、东古等企业，这两个省份在调味品产业发展层面，亦有雄厚的实力。此外，四川的调味品企业数量排名近几年有所上升，川味复调发展较迅猛。</p>\\n<p>企查查显示，2023年9月，山东有调味品企业5.63万家，2024年1月缩减至5.55万家。截至2026年4月15日，该项数据为4.8万家。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8c29cc7e300549c893844b56f1b4a269@5781278_oswg264923oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>△图源：企查查</p>\\n<p>事实上，<strong>不只是山东，整个调味品行业的企业数量都在减少。</strong>在经历连锁餐饮爆发、调味品企业趋于饱和后，行业又逐渐降温，进入综合性企业领跑、“大鱼吃小鱼”的新阶段。</p>\\n<p>不缺产能、不缺工艺、不缺口碑，山东调味品历经百年，正站在又一个十字路口。</p>\\n<p>4.8万家 企业，最后能留下多少，谁也不知道。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/tMtdQAbrRMtVpAsYmaMzRA\\\">“红餐供应链指南”</a>，作者：春莹，编辑：景雪，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'山东调味品，撑起了中国厨房的半壁江山\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'山东调味品，撑起了中国厨房的半壁江山\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768806257701639?f=rss\'}], \'link\': \'https://36kr.com/p/3768806257701639?f=rss\', \'published\': \'2026-04-16 09:54:19  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=1, tm_min=54, tm_sec=19, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>如果你想在最短时间内把后厨的调味料配齐，最好的办法是找一个山东人。</p>\\\\n  <p>从鲁菜后厨的一碗甜面酱，到全国餐桌的一瓶小磨香油，再到海外商超的一袋复合香辛料……山东人早已把酱油、食醋、香辛料、复合调味料的生意做遍了大江南北。</p>\\\\n  <p>企查查数据也显示，<strong>山东现存4.8万家调味品相关企业，全国第一。</strong></p>\\\\n  <p>但奇怪的是，你问一个山东以外的消费者“山东有什么调味品品牌”，大部分人想半天可能说不出一二三。</p>\\\\n  <p><strong>全国最多的企业，却没能长出足够多的全国性品牌。</strong>山东调味品的家底，到底藏在哪？</p>\\\\n  <h2><strong>01.酱是底色</strong></h2>\\\\n  <p>山东的调味天赋，首先来自风土。</p>\\\\n  <p>在章丘，肥沃的耕地加上雨热同期的温带季风，孕育出比人高的大葱。还有济宁金乡的大蒜、莱芜的生姜，都稳坐“全国农产品地理标志”。</p>\\\\n  <p>除了基础的葱姜蒜，山东人还尤其偏爱“酱”。山东的酱料种类丰富，经典代表有大葱蘸酱、黄豆酱（黄酱）、甜面酱、辣椒酱、芝麻酱等。没吃过大葱蘸酱，约等于没来过山东。</p>\\\\n  <p>此外，今天还能尝到蠓子虾酱、郓城西瓜酱、尚书府馍馍酱以及各色酱菜，这些具有鲜明地域特色的酱料，都是山东酱文化的缩影。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_71c2003e37b44995b738ce5eb51b2588@5781278_oswg991981oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：图虫创意</p>\\\\n  <p><strong>酱文化的载体是酱园，专事发酵的地方。</strong>据1928年《历城县乡土调查录》记载，单单是济南城，就有146家酱园，包括著名的醴泉居、北厚记、兴顺福和德馨斋。那时候大酱园号称“五魁手”，指酿酒、制醋、酱油、腌菜和榨油都做。</p>\\\\n  <p>山东厨师也认这些，糖醋鲤鱼、葱烧海参、九转大肠等经典鲁菜都会用到黄豆酱或甜面酱来调味。绝对点说，<strong>没有黄豆酱、甜面酱，就没有鲁菜的浓油赤酱、酱爆鲜香。</strong></p>\\\\n  <p>酱园不仅养了鲁菜，还早早将山东酱料送出了省、销往国外。清宣统年间，威海豆面酱已成为朝中贡品。</p>\\\\n  <p>20世纪初，威海四海酱园的产品端上了日本、高丽的餐桌。彼时，北京、天津、徐州、武汉等大中城市都能买到鲁地的酱香风味。走海运的货物也可以从济南、淄博、周村、潍县、龙口、济宁等商埠出发，沿胶济铁路这条大动脉到达威海、青岛等港口。</p>\\\\n  <p>有酿造传统、有渠道，山东调味品产业由此攒下了规模化的家底。此后各地酿造厂陆续合并，逐渐出现了德馨斋、玉兔、崔字牌等传承百年工艺的中华老字号。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_25b4e95d0fda4cf5bfc94b065e13dd52@5781278_oswg850992oswg1080oswg428_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△崔字牌的石磨工艺，图源：瑞福油脂官网</p>\\\\n  <p>到了八九十年代，工业化开始重新整合地方资源。莲花控股、长寿花、欣和、一品农产等老牌调味品企业先后起步，在味精、玉米油、原酿酱、姜蒜深加工等领域进行自主研发和生产。</p>\\\\n  <p>山东省工信厅的报告显示，2023年山东调味品已成为重点做大的200亿体量的行业聚集区。</p>\\\\n  <p>而这张庞大的产业地图上，有两个小镇的故事格外耐人寻味。它们都不是原料大户，却都成了全国乃至全球的调味品重镇。</p>\\\\n  <h2><strong>02.不产原料的小镇</strong></h2>\\\\n  <p>杨安镇，总面积88.47平方公里，是全国调味品集散地，被誉为“中国调味品第一镇”。根据新华网的报道，截至去年12月，这个小镇上已有调味品生产加工企业300多家，复合香辛料占全国40%以上市场份额，出口到了70多个国家和地区。</p>\\\\n  <p>只是，这个“小镇奇迹”并不是靠山东的物产资源发家，而是靠敏锐的商业嗅觉和超强的加工能力。</p>\\\\n  <p>杨安镇调味品产业，是从当地人卖调料原料开始。上世纪70年代，耕种庄稼的杨安镇人喜欢在自留地上种点辣椒来吃，吃不完的辣椒他们磨成辣椒面存放起来。碰到农闲时，村民们会推着车子，去外地做点手艺活，辣椒面被当成了附属品出售。</p>\\\\n  <p>渐渐地，杨安镇人发现东北、山西等地对辣椒面有很大市场需求，于是杨安镇人开始去四川、陕西等地收购辣椒，回来进行加工再销售。再后来，他们还卖起了花椒粉、五香粉等产品，经营品类持续拓展。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_00856353a5c84d0db89d1cf046e55f69@5781278_oswg1342178oswg1080oswg719_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：图虫创意</p>\\\\n  <p>90年代，注册公司、投资建厂取代了过去的小作坊式生产，新飞达、庞大、乐畅、华畅、腾达等龙头企业相继落地杨安镇，以工业级品质和规模化产出进一步打开市场。</p>\\\\n  <p>但随着调味品企业的增加，各企业产品开始高度雷同，市场竞争激烈。<strong>如何让调味品产业破局“出圈”？杨安镇打出了抱团牌。</strong></p>\\\\n  <p>2018年，“味都杨安”区域公共品牌成立。在前端，杨安镇调味品集团整合中小企业的原料需求，与云南、四川等原料供应商谈采购价，在终端有“味都杨安”统一标识的调味品被摆放在了商超等渠道的显眼位置。</p>\\\\n  <p>“调二代”“调三代”接了班，又利用电商给杨安镇添了把火。2022年，味都杨安的调味品成为德州首个年寄递量过5000万件的单类产品。2024年，快递单量已突破1.5亿。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_68b6234d2c984a9f928efbeb6dc72f8d@5781278_oswg92932oswg1080oswg653_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：“乐陵旅游”公众号</p>\\\\n  <p>如今，杨安镇的调味品博物馆里陈列着1200余种本地生产的调味品。在杨安镇，你可以一站购齐方便面调料包、火腿肠调料，黄焖鸡、瓦罐汤的汤底，烧烤撒料，火锅底料，各地名菜的复合调料，还有西餐、泰餐、韩餐等异国风味产品……</p>\\\\n  <p>杨安镇的发家史，是整个山东调味品升级的缩影，它吸纳了全国的香辛料资源，早早占据附加值更高的加工环节，最后变成谁也不可撼动的集散枢纽，手里攥着定价权。</p>\\\\n  <h2><strong>03.辣椒宇宙的尽头</strong></h2>\\\\n  <p>如果说杨安镇走的是“复合香辛料”路线，那胶州于家村做的则是“辣椒单品”。</p>\\\\n  <p>做辣椒买卖的人，十有八九逛过“环球辣椒网”。这家网站不仅按天刷新全国各地的辣椒价格，还能发帖求购或售出，俨然一个线上大市场。</p>\\\\n  <p>而它的首页栏目赫然并列着：<strong>国内、国际、于家村。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_327f7b467bdd465f9a889a0e27a49c32@5781278_oswg15991oswg343oswg155_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：环球辣椒网</p>\\\\n  <p>于家村在哪儿？山东人会告诉你，那是辣椒宇宙的尽头。</p>\\\\n  <p>于家村所在的胶州市是中国北方最大的干制辣椒集散地，青岛市辣椒产业商会、胶州辣椒产业协会会长王勇曾介绍，于家村的辣椒市场年交易量约120万吨，市场交易额超160亿元。村里的大椒城也是全国辣椒产业的“晴雨表”。</p>\\\\n  <p>但胶州的辣椒并不算土生土长，它的根来自100多公里外的青州市。</p>\\\\n  <p>1964年，胶州开始从青州引进羊角椒试种，到90年代时种植面积达15万亩。这期间，胶州市还被确定为山东省辣椒生产出口基地。</p>\\\\n  <p>随着出口量的不断攀升，原料供应已经跟不上加工需求，种植环节便开始自然地外溢。先是山东省内的青岛、潍坊、聊城、德州接手，从鲁东跨至鲁西。</p>\\\\n  <p>再然后，种子又被带去了河南、河北、新疆、内蒙古等省份广泛种植，累计建设辣椒种植示范基地300多万亩。</p>\\\\n  <p>种植和加工不在一地，就需要人把外地的干辣椒运回胶州，这些人就叫“辣椒耗子”。他们构成了输送辣椒原料的毛细血管。至今，胶州的“辣椒耗子”已超过2000人。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b561edadebb045b6b4ec6d8906b56968@5781278_oswg937349oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：图虫创意</p>\\\\n  <p>“放种”虽然缓解了原料压力，却也带来了一堆麻烦，比如：外地种植户盲目跟栽、品质杂乱、出口农残超标、色价不高被退货……</p>\\\\n  <p>为此，胶州政府联合骨干企业和种植大户，率先推出“订单种植+统一标准”模式：先接国外订单，明确辣椒的色价、辣度、农残标准，再和外地农户签种植协议，提供优质种苗和技术指导，最后统一回收。</p>\\\\n  <p>2022年3月，胶州正式启动了上合国际绿色农产品博览会交易中心项目，该项目预计2027年交易额达到600亿元。据介绍，该中心整合了线上交易、冷链仓储、检验检测、金融服务等多种功能，将物流、金融等流程一次打通。</p>\\\\n  <p>从引进种植到“放种”模式，当地辣椒企业能更专注于育种和加工升级，扩大出口产品的溢价空间，从初级农产品升级为高端定制。</p>\\\\n  <p>今天的胶州已把控了辣椒的种源、加工和贸易，也掌握了辣椒副产品的定价权。据统计，胶州已有辣椒加工企业 300余家，其中72家有出口权，<strong>辣椒产品出口量占全国的七成以上。</strong></p>\\\\n  <h2><strong>04.4.8万家最后能留下多少？</strong></h2>\\\\n  <p>描绘山东调味品的真实底色，不能只看宏观的产业版图，更要看微观的企业画像。</p>\\\\n  <p>将视线拉回全省。今天的山东调味品赛道上，也跑出了一批具有代表性的样本，既有承袭百年工艺的守正者，也有后来居上的弄潮儿。</p>\\\\n  <p>“山东调味品一哥”欣和，旗下六月鲜、禾然、味达美、葱伴侣等品牌的产品在北方市场很吃得开，长年占据各大商超的核心位置。</p>\\\\n  <p>食醋赛道，玉兔有红曲米醋，巧媳妇有清香米醋。</p>\\\\n  <p>山东云德食品，旗下既有老字号“德馨斋”的五粮醋、甜面酱，也有“云享”牌各类火锅底料，是鲁菜餐饮企业的核心供应商。</p>\\\\n  <p>日辰股份则专注复合调味料的餐饮定制生产，旗下“味之物语”品牌面向终端消费者，2023年和2024年均保持营收的双位数增长。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_69f9e888f68f477c9a54ed4a0d8cb0e7@5781278_oswg156285oswg1080oswg668_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：红餐供应链指南摄</p>\\\\n  <p>同为上市公司的莲花股份除了味精，也有豆瓣酱、甜面酱、火锅蘸料等产品。</p>\\\\n  <p>长寿花、鲁花以粮油为主，同时也有推酱油等产品；崔字牌守着小磨香油的细分赛道；一品农产是中国鲜蒜蓉、鲜姜蓉的开创者，年创汇超2500万美元。</p>\\\\n  <p>但从另一个视角看，也有一些潜在问题。</p>\\\\n  <p>酱油、豆瓣酱、黄豆酱等传统品类的增速放缓，不同品牌、同一品类很容易互相替代。尤其在供应链效率提升的前提下，一些具有规模化优势和品牌光环的南方品牌开始进入北方市场，铺上货架，山东本土企业正面临被瓜分蛋糕的威胁。</p>\\\\n  <p><strong>以酱油为例，“一哥”欣和尚且稳健，但大部分区域老字号过度依赖本地市场，应对头部冲击的能力弱。</strong>据“泰山财经”报道，“弯腰”“寻找”成了消费者在济南商超选购老牌山东酱油的常态，海天、厨邦、千禾等粤、川品牌占比超五成。</p>\\\\n  <p>此外，曾为八大菜系之首的鲁菜，还没跑出门店体量特别大的连锁品牌，且鲁菜费时费力的制作工艺很难跟上今天的快节奏生活，鲁地风格的调味品需求自然也难打开。</p>\\\\n  <p>从企业数量上看，山东还是调味品第一大省，但位居其后的河北省，盘踞了远东食品、老磨坊、益彰食品等老牌企业，排名第三的广东则汇聚了海天、中炬高新、百利食品、东古等企业，这两个省份在调味品产业发展层面，亦有雄厚的实力。此外，四川的调味品企业数量排名近几年有所上升，川味复调发展较迅猛。</p>\\\\n  <p>企查查显示，2023年9月，山东有调味品企业5.63万家，2024年1月缩减至5.55万家。截至2026年4月15日，该项数据为4.8万家。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8c29cc7e300549c893844b56f1b4a269@5781278_oswg264923oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：企查查</p>\\\\n  <p>事实上，<strong>不只是山东，整个调味品行业的企业数量都在减少。</strong>在经历连锁餐饮爆发、调味品企业趋于饱和后，行业又逐渐降温，进入综合性企业领跑、“大鱼吃小鱼”的新阶段。</p>\\\\n  <p>不缺产能、不缺工艺、不缺口碑，山东调味品历经百年，正站在又一个十字路口。</p>\\\\n  <p>4.8万家 企业，最后能留下多少，谁也不知道。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/tMtdQAbrRMtVpAsYmaMzRA\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“红餐供应链指南”</a>，作者：春莹，编辑：景雪，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>如果你想在最短时间内把后厨的调味料配齐，最好的办法是找一个山东人。</p>\\\\n  <p>从鲁菜后厨的一碗甜面酱，到全国餐桌的一瓶小磨香油，再到海外商超的一袋复合香辛料……山东人早已把酱油、食醋、香辛料、复合调味料的生意做遍了大江南北。</p>\\\\n  <p>企查查数据也显示，<strong>山东现存4.8万家调味品相关企业，全国第一。</strong></p>\\\\n  <p>但奇怪的是，你问一个山东以外的消费者“山东有什么调味品品牌”，大部分人想半天可能说不出一二三。</p>\\\\n  <p><strong>全国最多的企业，却没能长出足够多的全国性品牌。</strong>山东调味品的家底，到底藏在哪？</p>\\\\n  <h2><strong>01.酱是底色</strong></h2>\\\\n  <p>山东的调味天赋，首先来自风土。</p>\\\\n  <p>在章丘，肥沃的耕地加上雨热同期的温带季风，孕育出比人高的大葱。还有济宁金乡的大蒜、莱芜的生姜，都稳坐“全国农产品地理标志”。</p>\\\\n  <p>除了基础的葱姜蒜，山东人还尤其偏爱“酱”。山东的酱料种类丰富，经典代表有大葱蘸酱、黄豆酱（黄酱）、甜面酱、辣椒酱、芝麻酱等。没吃过大葱蘸酱，约等于没来过山东。</p>\\\\n  <p>此外，今天还能尝到蠓子虾酱、郓城西瓜酱、尚书府馍馍酱以及各色酱菜，这些具有鲜明地域特色的酱料，都是山东酱文化的缩影。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_71c2003e37b44995b738ce5eb51b2588@5781278_oswg991981oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：图虫创意</p>\\\\n  <p><strong>酱文化的载体是酱园，专事发酵的地方。</strong>据1928年《历城县乡土调查录》记载，单单是济南城，就有146家酱园，包括著名的醴泉居、北厚记、兴顺福和德馨斋。那时候大酱园号称“五魁手”，指酿酒、制醋、酱油、腌菜和榨油都做。</p>\\\\n  <p>山东厨师也认这些，糖醋鲤鱼、葱烧海参、九转大肠等经典鲁菜都会用到黄豆酱或甜面酱来调味。绝对点说，<strong>没有黄豆酱、甜面酱，就没有鲁菜的浓油赤酱、酱爆鲜香。</strong></p>\\\\n  <p>酱园不仅养了鲁菜，还早早将山东酱料送出了省、销往国外。清宣统年间，威海豆面酱已成为朝中贡品。</p>\\\\n  <p>20世纪初，威海四海酱园的产品端上了日本、高丽的餐桌。彼时，北京、天津、徐州、武汉等大中城市都能买到鲁地的酱香风味。走海运的货物也可以从济南、淄博、周村、潍县、龙口、济宁等商埠出发，沿胶济铁路这条大动脉到达威海、青岛等港口。</p>\\\\n  <p>有酿造传统、有渠道，山东调味品产业由此攒下了规模化的家底。此后各地酿造厂陆续合并，逐渐出现了德馨斋、玉兔、崔字牌等传承百年工艺的中华老字号。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_25b4e95d0fda4cf5bfc94b065e13dd52@5781278_oswg850992oswg1080oswg428_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△崔字牌的石磨工艺，图源：瑞福油脂官网</p>\\\\n  <p>到了八九十年代，工业化开始重新整合地方资源。莲花控股、长寿花、欣和、一品农产等老牌调味品企业先后起步，在味精、玉米油、原酿酱、姜蒜深加工等领域进行自主研发和生产。</p>\\\\n  <p>山东省工信厅的报告显示，2023年山东调味品已成为重点做大的200亿体量的行业聚集区。</p>\\\\n  <p>而这张庞大的产业地图上，有两个小镇的故事格外耐人寻味。它们都不是原料大户，却都成了全国乃至全球的调味品重镇。</p>\\\\n  <h2><strong>02.不产原料的小镇</strong></h2>\\\\n  <p>杨安镇，总面积88.47平方公里，是全国调味品集散地，被誉为“中国调味品第一镇”。根据新华网的报道，截至去年12月，这个小镇上已有调味品生产加工企业300多家，复合香辛料占全国40%以上市场份额，出口到了70多个国家和地区。</p>\\\\n  <p>只是，这个“小镇奇迹”并不是靠山东的物产资源发家，而是靠敏锐的商业嗅觉和超强的加工能力。</p>\\\\n  <p>杨安镇调味品产业，是从当地人卖调料原料开始。上世纪70年代，耕种庄稼的杨安镇人喜欢在自留地上种点辣椒来吃，吃不完的辣椒他们磨成辣椒面存放起来。碰到农闲时，村民们会推着车子，去外地做点手艺活，辣椒面被当成了附属品出售。</p>\\\\n  <p>渐渐地，杨安镇人发现东北、山西等地对辣椒面有很大市场需求，于是杨安镇人开始去四川、陕西等地收购辣椒，回来进行加工再销售。再后来，他们还卖起了花椒粉、五香粉等产品，经营品类持续拓展。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_00856353a5c84d0db89d1cf046e55f69@5781278_oswg1342178oswg1080oswg719_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：图虫创意</p>\\\\n  <p>90年代，注册公司、投资建厂取代了过去的小作坊式生产，新飞达、庞大、乐畅、华畅、腾达等龙头企业相继落地杨安镇，以工业级品质和规模化产出进一步打开市场。</p>\\\\n  <p>但随着调味品企业的增加，各企业产品开始高度雷同，市场竞争激烈。<strong>如何让调味品产业破局“出圈”？杨安镇打出了抱团牌。</strong></p>\\\\n  <p>2018年，“味都杨安”区域公共品牌成立。在前端，杨安镇调味品集团整合中小企业的原料需求，与云南、四川等原料供应商谈采购价，在终端有“味都杨安”统一标识的调味品被摆放在了商超等渠道的显眼位置。</p>\\\\n  <p>“调二代”“调三代”接了班，又利用电商给杨安镇添了把火。2022年，味都杨安的调味品成为德州首个年寄递量过5000万件的单类产品。2024年，快递单量已突破1.5亿。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_68b6234d2c984a9f928efbeb6dc72f8d@5781278_oswg92932oswg1080oswg653_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：“乐陵旅游”公众号</p>\\\\n  <p>如今，杨安镇的调味品博物馆里陈列着1200余种本地生产的调味品。在杨安镇，你可以一站购齐方便面调料包、火腿肠调料，黄焖鸡、瓦罐汤的汤底，烧烤撒料，火锅底料，各地名菜的复合调料，还有西餐、泰餐、韩餐等异国风味产品……</p>\\\\n  <p>杨安镇的发家史，是整个山东调味品升级的缩影，它吸纳了全国的香辛料资源，早早占据附加值更高的加工环节，最后变成谁也不可撼动的集散枢纽，手里攥着定价权。</p>\\\\n  <h2><strong>03.辣椒宇宙的尽头</strong></h2>\\\\n  <p>如果说杨安镇走的是“复合香辛料”路线，那胶州于家村做的则是“辣椒单品”。</p>\\\\n  <p>做辣椒买卖的人，十有八九逛过“环球辣椒网”。这家网站不仅按天刷新全国各地的辣椒价格，还能发帖求购或售出，俨然一个线上大市场。</p>\\\\n  <p>而它的首页栏目赫然并列着：<strong>国内、国际、于家村。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_327f7b467bdd465f9a889a0e27a49c32@5781278_oswg15991oswg343oswg155_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：环球辣椒网</p>\\\\n  <p>于家村在哪儿？山东人会告诉你，那是辣椒宇宙的尽头。</p>\\\\n  <p>于家村所在的胶州市是中国北方最大的干制辣椒集散地，青岛市辣椒产业商会、胶州辣椒产业协会会长王勇曾介绍，于家村的辣椒市场年交易量约120万吨，市场交易额超160亿元。村里的大椒城也是全国辣椒产业的“晴雨表”。</p>\\\\n  <p>但胶州的辣椒并不算土生土长，它的根来自100多公里外的青州市。</p>\\\\n  <p>1964年，胶州开始从青州引进羊角椒试种，到90年代时种植面积达15万亩。这期间，胶州市还被确定为山东省辣椒生产出口基地。</p>\\\\n  <p>随着出口量的不断攀升，原料供应已经跟不上加工需求，种植环节便开始自然地外溢。先是山东省内的青岛、潍坊、聊城、德州接手，从鲁东跨至鲁西。</p>\\\\n  <p>再然后，种子又被带去了河南、河北、新疆、内蒙古等省份广泛种植，累计建设辣椒种植示范基地300多万亩。</p>\\\\n  <p>种植和加工不在一地，就需要人把外地的干辣椒运回胶州，这些人就叫“辣椒耗子”。他们构成了输送辣椒原料的毛细血管。至今，胶州的“辣椒耗子”已超过2000人。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b561edadebb045b6b4ec6d8906b56968@5781278_oswg937349oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：图虫创意</p>\\\\n  <p>“放种”虽然缓解了原料压力，却也带来了一堆麻烦，比如：外地种植户盲目跟栽、品质杂乱、出口农残超标、色价不高被退货……</p>\\\\n  <p>为此，胶州政府联合骨干企业和种植大户，率先推出“订单种植+统一标准”模式：先接国外订单，明确辣椒的色价、辣度、农残标准，再和外地农户签种植协议，提供优质种苗和技术指导，最后统一回收。</p>\\\\n  <p>2022年3月，胶州正式启动了上合国际绿色农产品博览会交易中心项目，该项目预计2027年交易额达到600亿元。据介绍，该中心整合了线上交易、冷链仓储、检验检测、金融服务等多种功能，将物流、金融等流程一次打通。</p>\\\\n  <p>从引进种植到“放种”模式，当地辣椒企业能更专注于育种和加工升级，扩大出口产品的溢价空间，从初级农产品升级为高端定制。</p>\\\\n  <p>今天的胶州已把控了辣椒的种源、加工和贸易，也掌握了辣椒副产品的定价权。据统计，胶州已有辣椒加工企业 300余家，其中72家有出口权，<strong>辣椒产品出口量占全国的七成以上。</strong></p>\\\\n  <h2><strong>04.4.8万家最后能留下多少？</strong></h2>\\\\n  <p>描绘山东调味品的真实底色，不能只看宏观的产业版图，更要看微观的企业画像。</p>\\\\n  <p>将视线拉回全省。今天的山东调味品赛道上，也跑出了一批具有代表性的样本，既有承袭百年工艺的守正者，也有后来居上的弄潮儿。</p>\\\\n  <p>“山东调味品一哥”欣和，旗下六月鲜、禾然、味达美、葱伴侣等品牌的产品在北方市场很吃得开，长年占据各大商超的核心位置。</p>\\\\n  <p>食醋赛道，玉兔有红曲米醋，巧媳妇有清香米醋。</p>\\\\n  <p>山东云德食品，旗下既有老字号“德馨斋”的五粮醋、甜面酱，也有“云享”牌各类火锅底料，是鲁菜餐饮企业的核心供应商。</p>\\\\n  <p>日辰股份则专注复合调味料的餐饮定制生产，旗下“味之物语”品牌面向终端消费者，2023年和2024年均保持营收的双位数增长。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_69f9e888f68f477c9a54ed4a0d8cb0e7@5781278_oswg156285oswg1080oswg668_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：红餐供应链指南摄</p>\\\\n  <p>同为上市公司的莲花股份除了味精，也有豆瓣酱、甜面酱、火锅蘸料等产品。</p>\\\\n  <p>长寿花、鲁花以粮油为主，同时也有推酱油等产品；崔字牌守着小磨香油的细分赛道；一品农产是中国鲜蒜蓉、鲜姜蓉的开创者，年创汇超2500万美元。</p>\\\\n  <p>但从另一个视角看，也有一些潜在问题。</p>\\\\n  <p>酱油、豆瓣酱、黄豆酱等传统品类的增速放缓，不同品牌、同一品类很容易互相替代。尤其在供应链效率提升的前提下，一些具有规模化优势和品牌光环的南方品牌开始进入北方市场，铺上货架，山东本土企业正面临被瓜分蛋糕的威胁。</p>\\\\n  <p><strong>以酱油为例，“一哥”欣和尚且稳健，但大部分区域老字号过度依赖本地市场，应对头部冲击的能力弱。</strong>据“泰山财经”报道，“弯腰”“寻找”成了消费者在济南商超选购老牌山东酱油的常态，海天、厨邦、千禾等粤、川品牌占比超五成。</p>\\\\n  <p>此外，曾为八大菜系之首的鲁菜，还没跑出门店体量特别大的连锁品牌，且鲁菜费时费力的制作工艺很难跟上今天的快节奏生活，鲁地风格的调味品需求自然也难打开。</p>\\\\n  <p>从企业数量上看，山东还是调味品第一大省，但位居其后的河北省，盘踞了远东食品、老磨坊、益彰食品等老牌企业，排名第三的广东则汇聚了海天、中炬高新、百利食品、东古等企业，这两个省份在调味品产业发展层面，亦有雄厚的实力。此外，四川的调味品企业数量排名近几年有所上升，川味复调发展较迅猛。</p>\\\\n  <p>企查查显示，2023年9月，山东有调味品企业5.63万家，2024年1月缩减至5.55万家。截至2026年4月15日，该项数据为4.8万家。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8c29cc7e300549c893844b56f1b4a269@5781278_oswg264923oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">△图源：企查查</p>\\\\n  <p>事实上，<strong>不只是山东，整个调味品行业的企业数量都在减少。</strong>在经历连锁餐饮爆发、调味品企业趋于饱和后，行业又逐渐降温，进入综合性企业领跑、“大鱼吃小鱼”的新阶段。</p>\\\\n  <p>不缺产能、不缺工艺、不缺口碑，山东调味品历经百年，正站在又一个十字路口。</p>\\\\n  <p>4.8万家 企业，最后能留下多少，谁也不知道。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/tMtdQAbrRMtVpAsYmaMzRA\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“红餐供应链指南”</a>，作者：春莹，编辑：景雪，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'红餐供应链指南\'}], \'author\': \'红餐供应链指南\', \'author_detail\': {\'name\': \'红餐供应链指南\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'低调的大王。\'}]}\", \"published_at\": \"2026-04-16 09:54:19\", \"ai_json_output\": \"\"}', '如果你想在最短时间内把后厨的调味料配齐，最好的办法是找一个山东人。\n从鲁菜后厨的一碗甜面酱，到全国餐桌的一瓶小磨香油，再到海外商超的一袋复合香辛料……山东人早已把酱油、食醋、香辛料、复合调味料的生意做遍了大江南北。\n企查查数据也显示，\n山东现存4.8万家调味品相关企业，全国第一。\n但奇怪的是，你问一个山东以外的消费者“山东有什么调味品品牌”，大部分人想半天可能说不出一二三。\n全国最多的企业，却没能长出足够多的全国性品牌。\n山东调味品的家底，到底藏在哪？\n01.酱是底色\n山东的调味天赋，首先来自风土。\n在章丘，肥沃的耕地加上雨热同期的温带季风，孕育出比人高的大葱。还有济宁金乡的大蒜、莱芜的生姜，都稳坐“全国农产品地理标志”。\n除了基础的葱姜蒜，山东人还尤其偏爱“酱”。山东的酱料种类丰富，经典代表有大葱蘸酱、黄豆酱（黄酱）、甜面酱、辣椒酱、芝麻酱等。没吃过大葱蘸酱，约等于没来过山东。\n此外，今天还能尝到蠓子虾酱、郓城西瓜酱、尚书府馍馍酱以及各色酱菜，这些具有鲜明地域特色的酱料，都是山东酱文化的缩影。\n△图源：图虫创意\n酱文化的载体是酱园，专事发酵的地方。\n据1928年《历城县乡土调查录》记载，单单是济南城，就有146家酱园，包括著名的醴泉居、北厚记、兴顺福和德馨斋。那时候大酱园号称“五魁手”，指酿酒、制醋、酱油、腌菜和榨油都做。\n山东厨师也认这些，糖醋鲤鱼、葱烧海参、九转大肠等经典鲁菜都会用到黄豆酱或甜面酱来调味。绝对点说，\n没有黄豆酱、甜面酱，就没有鲁菜的浓油赤酱、酱爆鲜香。\n酱园不仅养了鲁菜，还早早将山东酱料送出了省、销往国外。清宣统年间，威海豆面酱已成为朝中贡品。\n20世纪初，威海四海酱园的产品端上了日本、高丽的餐桌。彼时，北京、天津、徐州、武汉等大中城市都能买到鲁地的酱香风味。走海运的货物也可以从济南、淄博、周村、潍县、龙口、济宁等商埠出发，沿胶济铁路这条大动脉到达威海、青岛等港口。\n有酿造传统、有渠道，山东调味品产业由此攒下了规模化的家底。此后各地酿造厂陆续合并，逐渐出现了德馨斋、玉兔、崔字牌等传承百年工艺的中华老字号。\n△崔字牌的石磨工艺，图源：瑞福油脂官网\n到了八九十年代，工业化开始重新整合地方资源。莲花控股、长寿花、欣和、一品农产等老牌调味品企业先后起步，在味精、玉米油、原酿酱、姜蒜深加工等领域进行自主研发和生产。\n山东省工信厅的报告显示，2023年山东调味品已成为重点做大的200亿体量的行业聚集区。\n而这张庞大的产业地图上，有两个小镇的故事格外耐人寻味。它们都不是原料大户，却都成了全国乃至全球的调味品重镇。\n02.不产原料的小镇\n杨安镇，总面积88.47平方公里，是全国调味品集散地，被誉为“中国调味品第一镇”。根据新华网的报道，截至去年12月，这个小镇上已有调味品生产加工企业300多家，复合香辛料占全国40%以上市场份额，出口到了70多个国家和地区。\n只是，这个“小镇奇迹”并不是靠山东的物产资源发家，而是靠敏锐的商业嗅觉和超强的加工能力。\n杨安镇调味品产业，是从当地人卖调料原料开始。上世纪70年代，耕种庄稼的杨安镇人喜欢在自留地上种点辣椒来吃，吃不完的辣椒他们磨成辣椒面存放起来。碰到农闲时，村民们会推着车子，去外地做点手艺活，辣椒面被当成了附属品出售。\n渐渐地，杨安镇人发现东北、山西等地对辣椒面有很大市场需求，于是杨安镇人开始去四川、陕西等地收购辣椒，回来进行加工再销售。再后来，他们还卖起了花椒粉、五香粉等产品，经营品类持续拓展。\n△图源：图虫创意\n90年代，注册公司、投资建厂取代了过去的小作坊式生产，新飞达、庞大、乐畅、华畅、腾达等龙头企业相继落地杨安镇，以工业级品质和规模化产出进一步打开市场。\n但随着调味品企业的增加，各企业产品开始高度雷同，市场竞争激烈。\n如何让调味品产业破局“出圈”？杨安镇打出了抱团牌。\n2018年，“味都杨安”区域公共品牌成立。在前端，杨安镇调味品集团整合中小企业的原料需求，与云南、四川等原料供应商谈采购价，在终端有“味都杨安”统一标识的调味品被摆放在了商超等渠道的显眼位置。\n“调二代”“调三代”接了班，又利用电商给杨安镇添了把火。2022年，味都杨安的调味品成为德州首个年寄递量过5000万件的单类产品。2024年，快递单量已突破1.5亿。\n△图源：“乐陵旅游”公众号\n如今，杨安镇的调味品博物馆里陈列着1200余种本地生产的调味品。在杨安镇，你可以一站购齐方便面调料包、火腿肠调料，黄焖鸡、瓦罐汤的汤底，烧烤撒料，火锅底料，各地名菜的复合调料，还有西餐、泰餐、韩餐等异国风味产品……\n杨安镇的发家史，是整个山东调味品升级的缩影，它吸纳了全国的香辛料资源，早早占据附加值更高的加工环节，最后变成谁也不可撼动的集散枢纽，手里攥着定价权。\n03.辣椒宇宙的尽头\n如果说杨安镇走的是“复合香辛料”路线，那胶州于家村做的则是“辣椒单品”。\n做辣椒买卖的人，十有八九逛过“环球辣椒网”。这家网站不仅按天刷新全国各地的辣椒价格，还能发帖求购或售出，俨然一个线上大市场。\n而它的首页栏目赫然并列着：\n国内、国际、于家村。\n△图源：环球辣椒网\n于家村在哪儿？山东人会告诉你，那是辣椒宇宙的尽头。\n于家村所在的胶州市是中国北方最大的干制辣椒集散地，青岛市辣椒产业商会、胶州辣椒产业协会会长王勇曾介绍，于家村的辣椒市场年交易量约120万吨，市场交易额超160亿元。村里的大椒城也是全国辣椒产业的“晴雨表”。\n但胶州的辣椒并不算土生土长，它的根来自100多公里外的青州市。\n1964年，胶州开始从青州引进羊角椒试种，到90年代时种植面积达15万亩。这期间，胶州市还被确定为山东省辣椒生产出口基地。\n随着出口量的不断攀升，原料供应已经跟不上加工需求，种植环节便开始自然地外溢。先是山东省内的青岛、潍坊、聊城、德州接手，从鲁东跨至鲁西。\n再然后，种子又被带去了河南、河北、新疆、内蒙古等省份广泛种植，累计建设辣椒种植示范基地300多万亩。\n种植和加工不在一地，就需要人把外地的干辣椒运回胶州，这些人就叫“辣椒耗子”。他们构成了输送辣椒原料的毛细血管。至今，胶州的“辣椒耗子”已超过2000人。\n△图源：图虫创意\n“放种”虽然缓解了原料压力，却也带来了一堆麻烦，比如：外地种植户盲目跟栽、品质杂乱、出口农残超标、色价不高被退货……\n为此，胶州政府联合骨干企业和种植大户，率先推出“订单种植+统一标准”模式：先接国外订单，明确辣椒的色价、辣度、农残标准，再和外地农户签种植协议，提供优质种苗和技术指导，最后统一回收。\n2022年3月，胶州正式启动了上合国际绿色农产品博览会交易中心项目，该项目预计2027年交易额达到600亿元。据介绍，该中心整合了线上交易、冷链仓储、检验检测、金融服务等多种功能，将物流、金融等流程一次打通。\n从引进种植到“放种”模式，当地辣椒企业能更专注于育种和加工升级，扩大出口产品的溢价空间，从初级农产品升级为高端定制。\n今天的胶州已把控了辣椒的种源、加工和贸易，也掌握了辣椒副产品的定价权。据统计，胶州已有辣椒加工企业 300余家，其中72家有出口权，\n辣椒产品出口量占全国的七成以上。\n04.4.8万家最后能留下多少？\n描绘山东调味品的真实底色，不能只看宏观的产业版图，更要看微观的企业画像。\n将视线拉回全省。今天的山东调味品赛道上，也跑出了一批具有代表性的样本，既有承袭百年工艺的守正者，也有后来居上的弄潮儿。\n“山东调味品一哥”欣和，旗下六月鲜、禾然、味达美、葱伴侣等品牌的产品在北方市场很吃得开，长年占据各大商超的核心位置。\n食醋赛道，玉兔有红曲米醋，巧媳妇有清香米醋。\n山东云德食品，旗下既有老字号“德馨斋”的五粮醋、甜面酱，也有“云享”牌各类火锅底料，是鲁菜餐饮企业的核心供应商。\n日辰股份则专注复合调味料的餐饮定制生产，旗下“味之物语”品牌面向终端消费者，2023年和2024年均保持营收的双位数增长。\n△图源：红餐供应链指南摄\n同为上市公司的莲花股份除了味精，也有豆瓣酱、甜面酱、火锅蘸料等产品。\n长寿花、鲁花以粮油为主，同时也有推酱油等产品；崔字牌守着小磨香油的细分赛道；一品农产是中国鲜蒜蓉、鲜姜蓉的开创者，年创汇超2500万美元。\n但从另一个视角看，也有一些潜在问题。\n酱油、豆瓣酱、黄豆酱等传统品类的增速放缓，不同品牌、同一品类很容易互相替代。尤其在供应链效率提升的前提下，一些具有规模化优势和品牌光环的南方品牌开始进入北方市场，铺上货架，山东本土企业正面临被瓜分蛋糕的威胁。\n以酱油为例，“一哥”欣和尚且稳健，但大部分区域老字号过度依赖本地市场，应对头部冲击的能力弱。\n据“泰山财经”报道，“弯腰”“寻找”成了消费者在济南商超选购老牌山东酱油的常态，海天、厨邦、千禾等粤、川品牌占比超五成。\n此外，曾为八大菜系之首的鲁菜，还没跑出门店体量特别大的连锁品牌，且鲁菜费时费力的制作工艺很难跟上今天的快节奏生活，鲁地风格的调味品需求自然也难打开。\n从企业数量上看，山东还是调味品第一大省，但位居其后的河北省，盘踞了远东食品、老磨坊、益彰食品等老牌企业，排名第三的广东则汇聚了海天、中炬高新、百利食品、东古等企业，这两个省份在调味品产业发展层面，亦有雄厚的实力。此外，四川的调味品企业数量排名近几年有所上升，川味复调发展较迅猛。\n企查查显示，2023年9月，山东有调味品企业5.63万家，2024年1月缩减至5.55万家。截至2026年4月15日，该项数据为4.8万家。\n△图源：企查查\n事实上，\n不只是山东，整个调味品行业的企业数量都在减少。\n在经历连锁餐饮爆发、调味品企业趋于饱和后，行业又逐渐降温，进入综合性企业领跑、“大鱼吃小鱼”的新阶段。\n不缺产能、不缺工艺、不缺口碑，山东调味品历经百年，正站在又一个十字路口。\n4.8万家 企业，最后能留下多少，谁也不知道。\n本文来自微信公众号\n“红餐供应链指南”\n，作者：春莹，编辑：景雪，36氪经授权发布。', '2026-04-16 09:54:19', '2026-04-16 11:48:57');
INSERT INTO `news_detail` VALUES (23, 989, 18, '硬件与半导体出海', '机器人擂台打到广交会：追觅放机械臂涮肉，智元亮出家用野心', '', '<p>一年两届的广交会（中国进出口商品交易会），在今天拉开2026年第139届盛会的大幕。</p>\n<p><strong>今年以来，雷科技（ID：leitech）先后完成CES、MWC、AWE等国内外大型科技展会现场报道。在广州主场举行的这届广交会，雷科技报道团也没有缺席。</strong></p>\n<p>第139届广交会参展企业超过3.2万家，其中拥有专精特新、单项冠军等称号的优质企业超过1.1万家，均超往届水平。顺应外贸发展新趋势、新特点，本届广交会展品专区增至179个，更多新企业、新产品、新技术借助这一旗舰展示平台走向世界，服务更多全球消费者。</p>\n<p><strong>2026广交会开展首日，雷科技（ID：leitech）报道团从179个专区中选出声势最大的「服务机器人专区」，并对这一专区进行了深度探展，以下是我们从现场发回的一手观察。</strong></p>\n<h2><strong>服务机器人外贸战，苏州和深圳打起了擂台</strong></h2>\n<p>雷科技报道团在探展CES、MWC的具身智能机器人企业展台时，一大印象是品牌展台整体面积相对偏小，如果有上百平方米的展台面积，都可以算机器人品牌中的「大户」了。</p>\n<p><strong>本届广交会的服务机器人专区，在21.2馆，总面积达到4200平方米，汇聚46家企业，平均每家品牌都有上百平方米的展台面积，实现了家家企业的展览「大户」梦。</strong></p>\n<p><strong>广交会服务机器人专区，给雷科技（ID：leitech）报道团的另一大直观印象是，在宇树、云深处等杭州明星机器人企业缺席后，苏州在中国外贸这一顶流舞台与深圳机器人企业打起了擂台赛。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1760e894041846d8a089311dc3562bd4@1547419282_oswg3447329oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p>在进入广交会服务机器人专区的通道，雷科技（ID：leitech）报道团一眼就看到了苏州机器人企业打出的巨幅宣传海报，「苏州智能机器人，全能实力派」，涵盖追觅、科沃斯、魔法原子、知行、穿山甲等5家代表企业。</p>\n<p>今年的46家服务机器人专区企业中，深圳则贡献了其中的6家代表企业，涵盖智元、越疆、普渡等代表企业。</p>\n<p>苏州军团缘何可以在广交会叫板深圳企业，玄机就藏在专区的名称上。<strong>所谓的「服务机器人」，不只包括人形机器人，也包括非人形机器人，而非人形机器人正是追觅、科沃斯等智能清洁品类或发家品类企业的技术和形态发力重点。</strong></p>\n<p>追觅就在服务机器人专区带来了智能机械臂的展示。这款具身智能机械臂由追觅生态时空象限旗下沸点计划（X-HotPot）品牌打造，依托AI烹饪大脑、3D工业视觉、柔顺力控骨骼等三大核心技术，实现8秒牛肉标准化出品，可实现毫秒级精准涮煮和毫米级投放误差。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_6df92d6ef47f4539b31ef6f5903cfe77@1547419282_oswg218633oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p>追觅旗下沸点计划，以中餐热门的火锅大类切入，推出对应的火锅机器人，涵盖具身智能机械臂、智能系统等。对于海外市场和海外华人来说，火锅也是颇为流行的一类中式大餐。<strong>在广交会舞台和美食之都，追觅给海外客商实现了「精准投喂」。</strong></p>\n<p>追觅还带来了服务居家洗护场景的智能机械臂产品，可实现衣物洗护全流程自动化，支持20种方言语音控制。</p>\n<p>追觅生态另一家机器人企业魔法原子，在广交会展台携马年春晚同款机器人亮相，涵盖全尺寸通用人形机器人GEN 1、高动态双足人形机器人MagicBot Z1，以及覆盖消费与工业场景的MagicDog系列等在内的多形态机器人产品矩阵，展示「让广义机器人服务地球每个角落」的愿景。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_95c2b030fa3e49aaadf250c1fbfe103e@1547419282_oswg3703498oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p>科沃斯在本届广交会带来了火爆AWE展台的首款搭载OpenClaw的「管家机器人」：八界。</p>\n<p>结合OpenClaw等「AI智能体」技术框架，八界已经能够在真实家庭环境中持续学习，并以更快的速度习得技能、理解世界，既可实现基于长期记忆的主动收纳功能，也可担当「居家分身」远程响应的代办需求。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_e6c7b0923b494113a32637588d6a3bd0@1547419282_oswg88385oswg1280oswg960_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p><strong>凭借追觅这样的智能生态全场景新锐品牌，以及科沃斯这样的智能清洁机器人老牌企业，苏州在今年的广交会打起了对深圳机器人企业基于「服务」品类的外贸战。而同台竞技的深圳机器人企业也做好了以硬实力应战的准备，打头的正是目前的机器人销量王企业：智元。</strong></p>\n<h2><strong>具身智能机器人巨头，也在发力商用服务领域</strong></h2>\n<p>作为本届广交会服务机器人专区最大牌的机器人企业，智元带来了旗下具身智能机器人多产品矩阵的展示。</p>\n<p><strong>作为全球具身智能机器人销量冠军企业，智元的产线形态愈加丰满，除了主打的人形机器人、轮式机器人、四足机器人和关键灵巧手部件，面向商业空间的自主清洁解决方案，也在成为其新的拓展和发力重点。</strong></p>\n<p>在广交会智元展台，雷科技（ID：leitech）报道团注意到，其产品层面更显眼的展示落在了旗下首款智能清洁设备C5身上。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_868fa3cec9bb4a1786243b71f5c3c34d@1547419282_oswg3869133oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p>智元绝尘C5，面向中大型清洁场景和商用客户群体，具备扫地、洗地、尘推等多种清洁功能，满足各类硬质地面清洁所需；设备配备多种传感器，激光视觉融合定位、点云图像融合感知，应对较复杂工作环境场景；配备工作站可实现自动充电、自动加排水、自动清洁污水箱，显著降低维护难度。</p>\n<p>智元希望自己的具身智能和硬件技术，可以借由在商用智能清洁设备上的落地，提升公共空间清洁质量、降低保洁工作强度、降低综合作业成本，同时实现清洁数字化，助力智慧物业转型。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_5c80a9493a124208958ceb416276d764@1547419282_oswg4099861oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p><strong>而从根本上来说，智能清洁机器人是目前商业变现能力最强、用户认可和接受度最高的新硬件赛道。相比工业和家庭机器人，智能清洁机器人在产品设计层面进行了更务实、更专一的功能和场景适配，从而也实现了更快速的落地和普及进程。</strong></p>\n<p><strong>在智能清洁设备愈加机器人化的当下，智元这类的人形和具身智能机器人新巨头企业，拓展和发力智能清洁品类，也就有了更为现实的多重考量。在商用智能清洁设备领域取得初步市场成果后，智元不排除将进军消费级智能清洁赛道。</strong></p>\n<p>抢先智元，深圳另一家机器人企业越疆已经实现了上市。在广交会展台，雷科技（ID：leitech）报道团看到，越疆同样以机械臂作为目前的主推形态产品，强调其在按摩、制作冰淇淋、吸杯等实际应用场景下的操作娴熟度和流程可靠性。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_fcdf8fb8d233432189909b12888c664f@1547419282_oswg3765177oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p><strong>不难看出，相比CES、MWC等科技大展，广交会的大舞台更强调产品落地的成熟度和可靠性。毕竟来广交会的参展企业以及全球客商，核心目的只有一个，那就是把双方的需求意向转化为实际的订单交易，相比秀技术肌肉，更重要的是能否把产品买卖出去。</strong></p>\n<p>科大讯飞和九号这类的应用和出行领域巨头企业，也在本届广交会带来了旗下服务机器人产品的展示。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_14fbb90719cc41f69f68734172579daa@1547419282_oswg255579oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>科大讯飞（图源：雷科技2026广交会现场摄制）</p>\n<p>其中，科大讯飞带来了旗下具身智能采训推机器人的演示，其可精准记忆人类操作动作，结合星火大模型可实现任务自主学习与迭代，是一款适配全行业的通用数据采集设备。</p>\n<p>九号则带来了旗下主攻智能酒店服务场景的机器人产品矩阵展示，涵盖送物、送餐等特定场景下的不同形态机器人产品。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_4ba3172f662a4d40b46e23c20f049ab2@1547419282_oswg236187oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<h2><strong>灵巧手、球形和外骨骼，广交会服务机器人专区的三大亮点</strong></h2>\n<p>逛遍本届广交会的服务机器人专区，雷科技（ID：leitech）报道团还发现了更多亮点。</p>\n<p>相比于机器人产品展台，雷科技（ID：leitech）发现外骨骼和灵巧手产品展台更容易吸引现场观众排队体验，其中外骨骼更甚。</p>\n<p>为什么外骨骼机器人展台人气颇高呢？其实也好理解，首先是外骨骼可以直接用来佩戴体验，客商的参与感和体验感更高，也就更易于订单交易的最终促成；其次是外骨骼的体验区面积占比不小，自然也就吸引了更多的排队体验客流；最后是外骨骼产品近年来在国内外市场愈加升温，尤其是在欧美发达国家市场，品类规模体量已经显著上来了。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_b887dd789ad941dbaa0ca91c8dcb2b83@1547419282_oswg775036oswg3412oswg1280_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>太希智能（图源：雷科技2026广交会现场摄制）</p>\n<p>灵巧手技术体验区的火热，同理，而其当下在国内不管是产品市场，还是资本市场，也都愈加火热。</p>\n<p>雷科技（ID：leitech）在广交会灵巧手展台看到，目前有无线和有线两大类技术方案。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_e5396193310547bca0f1d60ce9c509ae@1547419282_oswg188123oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>傲意（图源：雷科技2026广交会现场摄制）</p>\n<p>其中，无线灵巧手方案，基于摄像头的机器视觉进行跟随，目前有比较明显的延迟感；有线灵巧手方案，当下则更精准和更低延迟。</p>\n<p>产品创新层面，引发雷科技（ID：leitech）好奇的是球形机器人。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_be9873c4d4fd42cd8c59a54fedaf4eb6@1547419282_oswg229011oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<p>这款机器人，出自一家名叫逻腾的杭州机器人厂商，号称「非友好环境中唯一适用的两栖球形机器人」，可在复杂地形地貌、极端天气条件、恶劣及危险工作环境、危险及对抗性业务场景下使用。</p>\n<p>逻腾展台人员对雷科技（ID：leitech）表示，目前其两栖球形机器人已在国内多家公安机关、武警部队、机场及石油化工园区等投入使用。</p>\n<p>需要指出的是，虽然杭州机器人企业中的宇树科技、云深处、强脑科技等明星品牌并未参展这届广交会，但杭州服务机器人军团数量（6家）依然在所有城市中处于领先地位，持平深圳、多过苏州。</p>\n<p><strong>深圳、杭州、苏州的机器人头部企业和集群间的比拼，也将在很大程度上助推国产机器人产业的更快、更好发展。而在广交会舞台，雷科技（ID：leitech）报道团也看到了不少来自广州（7家）的机器人企业或业务企业</strong>，例如动易带来的全尺寸人形机器人，以及视源等企业展示的服务机器人产品。</p>\n<p>其中，动易的全尺寸人形机器人，攻克了高惯量平衡、万瓦级爆发与���冲击恢复等核心难题，可适配工业劳动、特种应急等通用重负载作业场景。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_4185b219f8da4331bbee72f5e95bd818@1547419282_oswg173390oswg1279oswg1706_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>动易（图源：雷科技2026广交会现场摄制）</p>\n<p>而从中国先进技术产业外贸和出海层面来说，我国的AI应用乃至AI硬件企业已经取得颇为亮眼的出海成绩单，而以智元、宇树等为代表的国产机器人企业，虽然也已取得中国和全球市场的销量领先地位，但在市场发展早期、整体规模体量较小的实际情况下，仍需全面夯实国内、国外两大市场。</p>\n<p><strong>真正做到国内外市场通吃的国产机器人企业，才会在长远竞赛中立于不败之地，这届广交会舞台上的激烈比拼也是面向未来的一个「预演」。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_f353e86e93ad42f8bc96cca6c11a5f22@1547419282_oswg4927310oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：雷科技2026广交会现场摄制</p>\n<h2><strong>老外买机器人去干吗？用途出乎国人意料</strong></h2>\n<p>近期，一条人形机器人「赶野猪」的短视频在全球社交媒体迅速走红。</p>\n<p>原来，宇树推出的G1人形机器人在被引入波兰当地后，被命名为「爱德华」（Edward），并在首都华沙执行各种工作任务，既包括在街头驱赶野猪，也包括在波兰议会进行演讲，例如用波兰语讲个冷笑话。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_0212de5b40b74bd7a97953a44650913f@1547419282_oswg414104oswg2166oswg1388_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：新华国际</p>\n<p>其实，国产机器人在进入海外用户和当地场景后，已经衍生出了不少出乎国人意料的新用途。</p>\n<p>例如「机器人警察」。在北美，「波士顿动力狗」逐渐成为不少地区警方标配，地位堪比警用无人机，常被用于危险的侦察任务。在泰国，人形机器人摇身一变为「AI警察机器人」，可利用360度全景摄像头和面部识别系统监控人群，并能识别棍棒等危险物品，实时将数据传回指挥中心。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_c1102ac406ac4460bbeed984fa42c29d@1547419282_oswg2501566oswg2382oswg1218_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：泰媒</p>\n<p>例如「去造船厂焊接钢板」，意大利造船巨头正在研发这类的人形机器人，目的是解决专业焊工短缺的问题；例如「培养人造肌腱」，在牛津大学的研究中，人形机器人被改装成生物反应器，通过模仿人体肩关节的复杂运动，精准地「拉伸」和「锻炼」实验室里培育的人造肌腱；例如「化身第二双手去逛街」，虽然你在中国，但可以通过机器人替你在纽约的商场里试衣服、拿起商品端详......</p>\n<p>而在中东「土豪国」阿联酋，当地土豪们，正在将机器人融入奢华生活与顶层设计中，例如让人形机器人穿上当地传统白袍、在「未来博物馆」充当明星互动展品，以及在商场扮演客服和警员双重角色等。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_80c86857706940aaabad09096b6bd2de@1547419282_oswg1511860oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图源：看中东DeepMENA</p>\n<p>以上案例可以看出，机器人的角色正在变得越来越多元：Ta可以是国家文化的展示窗口、城市安全的移动节点、危险环境下的替身，甚至是前沿科研的得力助手。</p>\n<p><strong>而基于当地的特定情况和社会现象，海外开发者也带来了对国产机器人的二次开发与本土化应用，例如用来解决当地的野猪泛滥、劳动力短缺、公共安全需求等现实问题。</strong></p>\n<p><strong>国产机器人，也只有在全球各地和多元用户群体中广泛使用起来，才可以迎来更多极富想象力的功能和应用场景，从而走上越来越宽广的技术落地和产品普及之路。</strong></p>\n<p>（@三七二十一 对本文亦有贡献）</p>\n<p>本文来自“雷科技”，36氪经授权发布。</p>', 'https://36kr.com/p/3768776195814151?f=rss', 0, '', '{\"summary\": \"本文展示了广交会国产服务机器人参展动态与海外应用现状，为有意出海的国产机器人企业提供市场参考。\", \"abstract\": \"2026年第139届广交会顺利开幕，本次展会服务机器人专区规模创下新高，国内多个机器人产业集群的企业同台竞技展示新品。多家头部机器人企业推出覆盖家用、商用、特种作业等多场景的产品，积极借助广交会拓展海外订单。文章提到国产机器人出海后，被海外用户开发出大量本土化创新应用场景。当前国产机器人出海仍处于发展早期，需同时夯实国内外两大市场才能在长期竞争中站稳脚跟。\", \"keywords\": [\"服务机器人\", \"国产机器人出海\", \"具身智能\", \"广交会\", \"人形机器人\", \"智能清洁\", \"本土化应用\"], \"policy_risk\": {\"market_risk\": \"国产机器人出海整体仍处于发展早期，整体市场规模体量较小，全球化布局尚未成熟，需进一步夯实国内外两大市场\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://36kr.com/p/3768776195814151?f=rss\", \"title\": \"机器人擂台打到广交会：追觅放机械臂涮肉，智元亮出家用野心\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>一年两届的广交会（中国进出口商品交易会），在今天拉开2026年第139届盛会的大幕。</p>\\n<p><strong>今年以来，雷科技（ID：leitech）先后完成CES、MWC、AWE等国内外大型科技展会现场报道。在广州主场举行的这届广交会，雷科技报道团也没有缺席。</strong></p>\\n<p>第139届广交会参展企业超过3.2万家，其中拥有专精特新、单项冠军等称号的优质企业超过1.1万家，均超往届水平。顺应外贸发展新趋势、新特点，本届广交会展品专区增至179个，更多新企业、新产品、新技术借助这一旗舰展示平台走向世界，服务更多全球消费者。</p>\\n<p><strong>2026广交会开展首日，雷科技（ID：leitech）报道团从179个专区中选出声势最大的「服务机器人专区」，并对这一专区进行了深度探展，以下是我们从现场发回的一手观察。</strong></p>\\n<h2><strong>服务机器人外贸战，苏州和深圳打起了擂台</strong></h2>\\n<p>雷科技报道团在探展CES、MWC的具身智能机器人企业展台时，一大印象是品牌展台整体面积相对偏小，如果有上百平方米的展台面积，都可以算机器人品牌中的「大户」了。</p>\\n<p><strong>本届广交会的服务机器人专区，在21.2馆，总面积达到4200平方米，汇聚46家企业，平均每家品牌都有上百平方米的展台面积，实现了家家企业的展览「大户」梦。</strong></p>\\n<p><strong>广交会服务机器人专区，给雷科技（ID：leitech）报道团的另一大直观印象是，在宇树、云深处等杭州明星机器人企业缺席后，苏州在中国外贸这一顶流舞台与深圳机器人企业打起了擂台赛。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1760e894041846d8a089311dc3562bd4@1547419282_oswg3447329oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p>在进入广交会服务机器人专区的通道，雷科技（ID：leitech）报道团一眼就看到了苏州机器人企业打出的巨幅宣传海报，「苏州智能机器人，全能实力派」，涵盖追觅、科沃斯、魔法原子、知行、穿山甲等5家代表企业。</p>\\n<p>今年的46家服务机器人专区企业中，深圳则贡献了其中的6家代表企业，涵盖智元、越疆、普渡等代表企业。</p>\\n<p>苏州军团缘何可以在广交会叫板深圳企业，玄机就藏在专区的名称上。<strong>所谓的「服务机器人」，不只包括人形机器人，也包括非人形机器人，而非人形机器人正是追觅、科沃斯等智能清洁品类或发家品类企业的技术和形态发力重点。</strong></p>\\n<p>追觅就在服务机器人专区带来了智能机械臂的展示。这款具身智能机械臂由追觅生态时空象限旗下沸点计划（X-HotPot）品牌打造，依托AI烹饪大脑、3D工业视觉、柔顺力控骨骼等三大核心技术，实现8秒牛肉标准化出品，可实现毫秒级精准涮煮和毫米级投放误差。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6df92d6ef47f4539b31ef6f5903cfe77@1547419282_oswg218633oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p>追觅旗下沸点计划，以中餐热门的火锅大类切入，推出对应的火锅机器人，涵盖具身智能机械臂、智能系统等。对于海外市场和海外华人来说，火锅也是颇为流行的一类中式大餐。<strong>在广交会舞台和美食之都，追觅给海外客商实现了「精准投喂」。</strong></p>\\n<p>追觅还带来了服务居家洗护场景的智能机械臂产品，可实现衣物洗护全流程自动化，支持20种方言语音控制。</p>\\n<p>追觅生态另一家机器人企业魔法原子，在广交会展台携马年春晚同款机器人亮相，涵盖全尺寸通用人形机器人GEN 1、高动态双足人形机器人MagicBot Z1，以及覆盖消费与工业场景的MagicDog系列等在内的多形态机器人产品矩阵，展示「让广义机器人服务地球每个角落」的愿景。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_95c2b030fa3e49aaadf250c1fbfe103e@1547419282_oswg3703498oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p>科沃斯在本届广交会带来了火爆AWE展台的首款搭载OpenClaw的「管家机器人」：八界。</p>\\n<p>结合OpenClaw等「AI智能体」技术框架，八界已经能够在真实家庭环境中持续学习，并以更快的速度习得技能、理解世界，既可实现基于长期记忆的主动收纳功能，也可担当「居家分身」远程响应的代办需求。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e6c7b0923b494113a32637588d6a3bd0@1547419282_oswg88385oswg1280oswg960_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p><strong>凭借追觅这样的智能生态全场景新锐品牌，以及科沃斯这样的智能清洁机器人老牌企业，苏州在今年的广交会打起了对深圳机器人企业基于「服务」品类的外贸战。而同台竞技的深圳机器人企业也做好了以硬实力应战的准备，打头的正是目前的机器人销量王企业：智元。</strong></p>\\n<h2><strong>具身智能机器人巨头，也在发力商用服务领域</strong></h2>\\n<p>作为本届广交会服务机器人专区最大牌的机器人企业，智元带来了旗下具身智能机器人多产品矩阵的展示。</p>\\n<p><strong>作为全球具身智能机器人销量冠军企业，智元的产线形态愈加丰满，除了主打的人形机器人、轮式机器人、四足机器人和关键灵巧手部件，面向商业空间的自主清洁解决方案，也在成为其新的拓展和发力重点。</strong></p>\\n<p>在广交会智元展台，雷科技（ID：leitech）报道团注意到，其产品层面更显眼的展示落在了旗下首款智能清洁设备C5身上。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_868fa3cec9bb4a1786243b71f5c3c34d@1547419282_oswg3869133oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p>智元绝尘C5，面向中大型清洁场景和商用客户群体，具备扫地、洗地、尘推等多种清洁功能，满足各类硬质地面清洁所需；设备配备多种传感器，激光视觉融合定位、点云图像融合感知，应对较复杂工作环境场景；配备工作站可实现自动充电、自动加排水、自动清洁污水箱，显著降低维护难度。</p>\\n<p>智元希望自己的具身智能和硬件技术，可以借由在商用智能清洁设备上的落地，提升公共空间清洁质量、降低保洁工作强度、降低综合作业成本，同时实现清洁数字化，助力智慧物业转型。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_5c80a9493a124208958ceb416276d764@1547419282_oswg4099861oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p><strong>而从根本上来说，智能清洁机器人是目前商业变现能力最强、用户认可和接受度最高的新硬件赛道。相比工业和家庭机器人，智能清洁机器人在产品设计层面进行了更务实、更专一的功能和场景适配，从而也实现了更快速的落地和普及进程。</strong></p>\\n<p><strong>在智能清洁设备愈加机器人化的当下，智元这类的人形和具身智能机器人新巨头企业，拓展和发力智能清洁品类，也就有了更为现实的多重考量。在商用智能清洁设备领域取得初步市场成果后，智元不排除将进军消费级智能清洁赛道。</strong></p>\\n<p>抢先智元，深圳另一家机器人企业越疆已经实现了上市。在广交会展台，雷科技（ID：leitech）报道团看到，越疆同样以机械臂作为目前的主推形态产品，强调其在按摩、制作冰淇淋、吸杯等实际应用场景下的操作娴熟度和流程可靠性。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_fcdf8fb8d233432189909b12888c664f@1547419282_oswg3765177oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p><strong>不难看出，相比CES、MWC等科技大展，广交会的大舞台更强调产品落地的成熟度和可靠性。毕竟来广交会的参展企业以及全球客商，核心目的只有一个，那就是把双方的需求意向转化为实际的订单交易，相比秀技术肌肉，更重要的是能否把产品买卖出去。</strong></p>\\n<p>科大讯飞和九号这类的应用和出行领域巨头企业，也在本届广交会带来了旗下服务机器人产品的展示。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_14fbb90719cc41f69f68734172579daa@1547419282_oswg255579oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>科大讯飞（图源：雷科技2026广交会现场摄制）</p>\\n<p>其中，科大讯飞带来了旗下具身智能采训推机器人的演示，其可精准记忆人类操作动作，结合星火大模型可实现任务自主学习与迭代，是一款适配全行业的通用数据采集设备。</p>\\n<p>九号则带来了旗下主攻智能酒店服务场景的机器人产品矩阵展示，涵盖送物、送餐等特定场景下的不同形态机器人产品。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4ba3172f662a4d40b46e23c20f049ab2@1547419282_oswg236187oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<h2><strong>灵巧手、球形和外骨骼，广交会服务机器人专区的三大亮点</strong></h2>\\n<p>逛遍本届广交会的服务机器人专区，雷科技（ID：leitech）报道团还发现了更多亮点。</p>\\n<p>相比于机器人产品展台，雷科技（ID：leitech）发现外骨骼和灵巧手产品展台更容易吸引现场观众排队体验，其中外骨骼更甚。</p>\\n<p>为什么外骨骼机器人展台人气颇高呢？其实也好理解，首先是外骨骼可以直接用来佩戴体验，客商的参与感和体验感更高，也就更易于订单交易的最终促成；其次是外骨骼的体验区面积占比不小，自然也就吸引了更多的排队体验客流；最后是外骨骼产品近年来在国内外市场愈加升温，尤其是在欧美发达国家市场，品类规模体量已经显著上来了。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b887dd789ad941dbaa0ca91c8dcb2b83@1547419282_oswg775036oswg3412oswg1280_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>太希智能（图源：雷科技2026广交会现场摄制）</p>\\n<p>灵巧手技术体验区的火热，同理，而其当下在国内不管是产品市场，还是资本市场，也都愈加火热。</p>\\n<p>雷科技（ID：leitech）在广交会灵巧手展台看到，目前有无线和有线两大类技术方案。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e5396193310547bca0f1d60ce9c509ae@1547419282_oswg188123oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>傲意（图源：雷科技2026广交会现场摄制）</p>\\n<p>其中，无线灵巧手方案，基于摄像头的机器视觉进行跟随，目前有比较明显的延迟感；有线灵巧手方案，当下则更精准和更低延迟。</p>\\n<p>产品创新层面，引发雷科技（ID：leitech）好奇的是球形机器人。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_be9873c4d4fd42cd8c59a54fedaf4eb6@1547419282_oswg229011oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<p>这款机器人，出自一家名叫逻腾的杭州机器人厂商，号称「非友好环境中唯一适用的两栖球形机器人」，可在复杂地形地貌、极端天气条件、恶劣及危险工作环境、危险及对抗性业务场景下使用。</p>\\n<p>逻腾展台人员对雷科技（ID：leitech）表示，目前其两栖球形机器人已在国内多家公安机关、武警部队、机场及石油化工园区等投入使用。</p>\\n<p>需要指出的是，虽然杭州机器人企业中的宇树科技、云深处、强脑科技等明星品牌并未参展这届广交会，但杭州服务机器人军团数量（6家）依然在所有城市中处于领先地位，持平深圳、多过苏州。</p>\\n<p><strong>深圳、杭州、苏州的机器人头部企业和集群间的比拼，也将在很大程度上助推国产机器人产业的更快、更好发展。而在广交会舞台，雷科技（ID：leitech）报道团也看到了不少来自广州（7家）的机器人企业或业务企业</strong>，例如动易带来的全尺寸人形机器人，以及视源等企业展示的服务机器人产品。</p>\\n<p>其中，动易的全尺寸人形机器人，攻克了高惯量平衡、万瓦级爆发与���冲击恢复等核心难题，可适配工业劳动、特种应急等通用重负载作业场景。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4185b219f8da4331bbee72f5e95bd818@1547419282_oswg173390oswg1279oswg1706_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>动易（图源：雷科技2026广交会现场摄制）</p>\\n<p>而从中国先进技术产业外贸和出海层面来说，我国的AI应用乃至AI硬件企业已经取得颇为亮眼的出海成绩单，而以智元、宇树等为代表的国产机器人企业，虽然也已取得中国和全球市场的销量领先地位，但在市场发展早期、整体规模体量较小的实际情况下，仍需全面夯实国内、国外两大市场。</p>\\n<p><strong>真正做到国内外市场通吃的国产机器人企业，才会在长远竞赛中立于不败之地，这届广交会舞台上的激烈比拼也是面向未来的一个「预演」。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f353e86e93ad42f8bc96cca6c11a5f22@1547419282_oswg4927310oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：雷科技2026广交会现场摄制</p>\\n<h2><strong>老外买机器人去干吗？用途出乎国人意料</strong></h2>\\n<p>近期，一条人形机器人「赶野猪」的短视频在全球社交媒体迅速走红。</p>\\n<p>原来，宇树推出的G1人形机器人在被引入波兰当地后，被命名为「爱德华」（Edward），并在首都华沙执行各种工作任务，既包括在街头驱赶野猪，也包括在波兰议会进行演讲，例如用波兰语讲个冷笑话。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_0212de5b40b74bd7a97953a44650913f@1547419282_oswg414104oswg2166oswg1388_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：新华国际</p>\\n<p>其实，国产机器人在进入海外用户和当地场景后，已经衍生出了不少出乎国人意料的新用途。</p>\\n<p>例如「机器人警察」。在北美，「波士顿动力狗」逐渐成为不少地区警方标配，地位堪比警用无人机，常被用于危险的侦察任务。在泰国，人形机器人摇身一变为「AI警察机器人」，可利用360度全景摄像头和面部识别系统监控人群，并能识别棍棒等危险物品，实时将数据传回指挥中心。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c1102ac406ac4460bbeed984fa42c29d@1547419282_oswg2501566oswg2382oswg1218_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：泰媒</p>\\n<p>例如「去造船厂焊接钢板」，意大利造船巨头正在研发这类的人形机器人，目的是解决专业焊工短缺的问题；例如「培养人造肌腱」，在牛津大学的研究中，人形机器人被改装成生物反应器，通过模仿人体肩关节的复杂运动，精准地「拉伸」和「锻炼」实验室里培育的人造肌腱；例如「化身第二双手去逛街」，虽然你在中国，但可以通过机器人替你在纽约的商场里试衣服、拿起商品端详......</p>\\n<p>而在中东「土豪国」阿联酋，当地土豪们，正在将机器人融入奢华生活与顶层设计中，例如让人形机器人穿上当地传统白袍、在「未来博物馆」充当明星互动展品，以及在商场扮演客服和警员双重角色等。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_80c86857706940aaabad09096b6bd2de@1547419282_oswg1511860oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图源：看中东DeepMENA</p>\\n<p>以上案例可以看出，机器人的角色正在变得越来越多元：Ta可以是国家文化的展示窗口、城市安全的移动节点、危险环境下的替身，甚至是前沿科研的得力助手。</p>\\n<p><strong>而基于当地的特定情况和社会现象，海外开发者也带来了对国产机器人的二次开发与本土化应用，例如用来解决当地的野猪泛滥、劳动力短缺、公共安全需求等现实问题。</strong></p>\\n<p><strong>国产机器人，也只有在全球各地和多元用户群体中广泛使用起来，才可以迎来更多极富想象力的功能和应用场景，从而走上越来越宽广的技术落地和产品普及之路。</strong></p>\\n<p>（@三七二十一 对本文亦有贡献）</p>\\n<p>本文来自“雷科技”，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'机器人擂台打到广交会：追觅放机械臂涮肉，智元亮出家用野心\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'机器人擂台打到广交会：追觅放机械臂涮肉，智元亮出家用野心\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768776195814151?f=rss\'}], \'link\': \'https://36kr.com/p/3768776195814151?f=rss\', \'published\': \'2026-04-16 09:22:03  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=1, tm_min=22, tm_sec=3, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>一年两届的广交会（中国进出口商品交易会），在今天拉开2026年第139届盛会的大幕。</p>\\\\n  <p><strong>今年以来，雷科技（ID：leitech）先后完成CES、MWC、AWE等国内外大型科技展会现场报道。在广州主场举行的这届广交会，雷科技报道团也没有缺席。</strong></p>\\\\n  <p>第139届广交会参展企业超过3.2万家，其中拥有专精特新、单项冠军等称号的优质企业超过1.1万家，均超往届水平。顺应外贸发展新趋势、新特点，本届广交会展品专区增至179个，更多新企业、新产品、新技术借助这一旗舰展示平台走向世界，服务更多全球消费者。</p>\\\\n  <p><strong>2026广交会开展首日，雷科技（ID：leitech）报道团从179个专区中选出声势最大的「服务机器人专区」，并对这一专区进行了深度探展，以下是我们从现场发回的一手观察。</strong></p>\\\\n  <h2><strong>服务机器人外贸战，苏州和深圳打起了擂台</strong></h2>\\\\n  <p>雷科技报道团在探展CES、MWC的具身智能机器人企业展台时，一大印象是品牌展台整体面积相对偏小，如果有上百平方米的展台面积，都可以算机器人品牌中的「大户」了。</p>\\\\n  <p><strong>本届广交会的服务机器人专区，在21.2馆，总面积达到4200平方米，汇聚46家企业，平均每家品牌都有上百平方米的展台面积，实现了家家企业的展览「大户」梦。</strong></p>\\\\n  <p><strong>广交会服务机器人专区，给雷科技（ID：leitech）报道团的另一大直观印象是，在宇树、云深处等杭州明星机器人企业缺席后，苏州在中国外贸这一顶流舞台与深圳机器人企业打起了擂台赛。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1760e894041846d8a089311dc3562bd4@1547419282_oswg3447329oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>在进入广交会服务机器人专区的通道，雷科技（ID：leitech）报道团一眼就看到了苏州机器人企业打出的巨幅宣传海报，「苏州智能机器人，全能实力派」，涵盖追觅、科沃斯、魔法原子、知行、穿山甲等5家代表企业。</p>\\\\n  <p>今年的46家服务机器人专区企业中，深圳则贡献了其中的6家代表企业，涵盖智元、越疆、普渡等代表企业。</p>\\\\n  <p>苏州军团缘何可以在广交会叫板深圳企业，玄机就藏在专区的名称上。<strong>所谓的「服务机器人」，不只包括人形机器人，也包括非人形机器人，而非人形机器人正是追觅、科沃斯等智能清洁品类或发家品类企业的技术和形态发力重点。</strong></p>\\\\n  <p>追觅就在服务机器人专区带来了智能机械臂的展示。这款具身智能机械臂由追觅生态时空象限旗下沸点计划（X-HotPot）品牌打造，依托AI烹饪大脑、3D工业视觉、柔顺力控骨骼等三大核心技术，实现8秒牛肉标准化出品，可实现毫秒级精准涮煮和毫米级投放误差。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6df92d6ef47f4539b31ef6f5903cfe77@1547419282_oswg218633oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>追觅旗下沸点计划，以中餐热门的火锅大类切入，推出对应的火锅机器人，涵盖具身智能机械臂、智能系统等。对于海外市场和海外华人来说，火锅也是颇为流行的一类中式大餐。<strong>在广交会舞台和美食之都，追觅给海外客商实现了「精准投喂」。</strong></p>\\\\n  <p>追觅还带来了服务居家洗护场景的智能机械臂产品，可实现衣物洗护全流程自动化，支持20种方言语音控制。</p>\\\\n  <p>追觅生态另一家机器人企业魔法原子，在广交会展台携马年春晚同款机器人亮相，涵盖全尺寸通用人形机器人GEN 1、高动态双足人形机器人MagicBot Z1，以及覆盖消费与工业场景的MagicDog系列等在内的多形态机器人产品矩阵，展示「让广义机器人服务地球每个角落」的愿景。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_95c2b030fa3e49aaadf250c1fbfe103e@1547419282_oswg3703498oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>科沃斯在本届广交会带来了火爆AWE展台的首款搭载OpenClaw的「管家机器人」：八界。</p>\\\\n  <p>结合OpenClaw等「AI智能体」技术框架，八界已经能够在真实家庭环境中持续学习，并以更快的速度习得技能、理解世界，既可实现基于长期记忆的主动收纳功能，也可担当「居家分身」远程响应的代办需求。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e6c7b0923b494113a32637588d6a3bd0@1547419282_oswg88385oswg1280oswg960_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p><strong>凭借追觅这样的智能生态全场景新锐品牌，以及科沃斯这样的智能清洁机器人老牌企业，苏州在今年的广交会打起了对深圳机器人企业基于「服务」品类的外贸战。而同台竞技的深圳机器人企业也做好了以硬实力应战的准备，打头的正是目前的机器人销量王企业：智元。</strong></p>\\\\n  <h2><strong>具身智能机器人巨头，也在发力商用服务领域</strong></h2>\\\\n  <p>作为本届广交会服务机器人专区最大牌的机器人企业，智元带来了旗下具身智能机器人多产品矩阵的展示。</p>\\\\n  <p><strong>作为全球具身智能机器人销量冠军企业，智元的产线形态愈加丰满，除了主打的人形机器人、轮式机器人、四足机器人和关键灵巧手部件，面向商业空间的自主清洁解决方案，也在成为其新的拓展和发力重点。</strong></p>\\\\n  <p>在广交会智元展台，雷科技（ID：leitech）报道团注意到，其产品层面更显眼的展示落在了旗下首款智能清洁设备C5身上。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_868fa3cec9bb4a1786243b71f5c3c34d@1547419282_oswg3869133oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>智元绝尘C5，面向中大型清洁场景和商用客户群体，具备扫地、洗地、尘推等多种清洁功能，满足各类硬质地面清洁所需；设备配备多种传感器，激光视觉融合定位、点云图像融合感知，应对较复杂工作环境场景；配备工作站可实现自动充电、自动加排水、自动清洁污水箱，显著降低维护难度。</p>\\\\n  <p>智元希望自己的具身智能和硬件技术，可以借由在商用智能清洁设备上的落地，提升公共空间清洁质量、降低保洁工作强度、降低综合作业成本，同时实现清洁数字化，助力智慧物业转型。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_5c80a9493a124208958ceb416276d764@1547419282_oswg4099861oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p><strong>而从根本上来说，智能清洁机器人是目前商业变现能力最强、用户认可和接受度最高的新硬件赛道。相比工业和家庭机器人，智能清洁机器人在产品设计层面进行了更务实、更专一的功能和场景适配，从而也实现了更快速的落地和普及进程。</strong></p>\\\\n  <p><strong>在智能清洁设备愈加机器人化的当下，智元这类的人形和具身智能机器人新巨头企业，拓展和发力智能清洁品类，也就有了更为现实的多重考量。在商用智能清洁设备领域取得初步市场成果后，智元不排除将进军消费级智能清洁赛道。</strong></p>\\\\n  <p>抢先智元，深圳另一家机器人企业越疆已经实现了上市。在广交会展台，雷科技（ID：leitech）报道团看到，越疆同样以机械臂作为目前的主推形态产品，强调其在按摩、制作冰淇淋、吸杯等实际应用场景下的操作娴熟度和流程可靠性。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_fcdf8fb8d233432189909b12888c664f@1547419282_oswg3765177oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p><strong>不难看出，相比CES、MWC等科技大展，广交会的大舞台更强调产品落地的成熟度和可靠性。毕竟来广交会的参展企业以及全球客商，核心目的只有一个，那就是把双方的需求意向转化为实际的订单交易，相比秀技术肌肉，更重要的是能否把产品买卖出去。</strong></p>\\\\n  <p>科大讯飞和九号这类的应用和出行领域巨头企业，也在本届广交会带来了旗下服务机器人产品的展示。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_14fbb90719cc41f69f68734172579daa@1547419282_oswg255579oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">科大讯飞（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>其中，科大讯飞带来了旗下具身智能采训推机器人的演示，其可精准记忆人类操作动作，结合星火大模型可实现任务自主学习与迭代，是一款适配全行业的通用数据采集设备。</p>\\\\n  <p>九号则带来了旗下主攻智能酒店服务场景的机器人产品矩阵展示，涵盖送物、送餐等特定场景下的不同形态机器人产品。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4ba3172f662a4d40b46e23c20f049ab2@1547419282_oswg236187oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <h2><strong>灵巧手、球形和外骨骼，广交会服务机器人专区的三大亮点</strong></h2>\\\\n  <p>逛遍本届广交会的服务机器人专区，雷科技（ID：leitech）报道团还发现了更多亮点。</p>\\\\n  <p>相比于机器人产品展台，雷科技（ID：leitech）发现外骨骼和灵巧手产品展台更容易吸引现场观众排队体验，其中外骨骼更甚。</p>\\\\n  <p>为什么外骨骼机器人展台人气颇高呢？其实也好理解，首先是外骨骼可以直接用来佩戴体验，客商的参与感和体验感更高，也就更易于订单交易的最终促成；其次是外骨骼的体验区面积占比不小，自然也就吸引了更多的排队体验客流；最后是外骨骼产品近年来在国内外市场愈加升温，尤其是在欧美发达国家市场，品类规模体量已经显著上来了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b887dd789ad941dbaa0ca91c8dcb2b83@1547419282_oswg775036oswg3412oswg1280_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">太希智能（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>灵巧手技术体验区的火热，同理，而其当下在国内不管是产品市场，还是资本市场，也都愈加火热。</p>\\\\n  <p>雷科技（ID：leitech）在广交会灵巧手展台看到，目前有无线和有线两大类技术方案。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e5396193310547bca0f1d60ce9c509ae@1547419282_oswg188123oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">傲意（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>其中，无线灵巧手方案，基于摄像头的机器视觉进行跟随，目前有比较明显的延迟感；有线灵巧手方案，当下则更精准和更低延迟。</p>\\\\n  <p>产品创新层面，引发雷科技（ID：leitech）好奇的是球形机器人。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_be9873c4d4fd42cd8c59a54fedaf4eb6@1547419282_oswg229011oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>这款机器人，出自一家名叫逻腾的杭州机器人厂商，号称「非友好环境中唯一适用的两栖球形机器人」，可在复杂地形地貌、极端天气条件、恶劣及危险工作环境、危险及对抗性业务场景下使用。</p>\\\\n  <p>逻腾展台人员对雷科技（ID：leitech）表示，目前其两栖球形机器人已在国内多家公安机关、武警部队、机场及石油化工园区等投入使用。</p>\\\\n  <p>需要指出的是，虽然杭州机器人企业中的宇树科技、云深处、强脑科技等明星品牌并未参展这届广交会，但杭州服务机器人军团数量（6家）依然在所有城市中处于领先地位，持平深圳、多过苏州。</p>\\\\n  <p><strong>深圳、杭州、苏州的机器人头部企业和集群间的比拼，也将在很大程度上助推国产机器人产业的更快、更好发展。而在广交会舞台，雷科技（ID：leitech）报道团也看到了不少来自广州（7家）的机器人企业或业务企业</strong>，例如动易带来的全尺寸人形机器人，以及视源等企业展示的服务机器人产品。</p>\\\\n  <p>其中，动易的全尺寸人形机器人，攻克了高惯量平衡、万瓦级爆发与���冲击恢复等核心难题，可适配工业劳动、特种应急等通用重负载作业场景。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4185b219f8da4331bbee72f5e95bd818@1547419282_oswg173390oswg1279oswg1706_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">动易（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>而从中国先进技术产业外贸和出海层面来说，我国的AI应用乃至AI硬件企业已经取得颇为亮眼的出海成绩单，而以智元、宇树等为代表的国产机器人企业，虽然也已取得中国和全球市场的销量领先地位，但在市场发展早期、整体规模体量较小的实际情况下，仍需全面夯实国内、国外两大市场。</p>\\\\n  <p><strong>真正做到国内外市场通吃的国产机器人企业，才会在长远竞赛中立于不败之地，这届广交会舞台上的激烈比拼也是面向未来的一个「预演」。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f353e86e93ad42f8bc96cca6c11a5f22@1547419282_oswg4927310oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <h2><strong>老外买机器人去干吗？用途出乎国人意料</strong></h2>\\\\n  <p>近期，一条人形机器人「赶野猪」的短视频在全球社交媒体迅速走红。</p>\\\\n  <p>原来，宇树推出的G1人形机器人在被引入波兰当地后，被命名为「爱德华」（Edward），并在首都华沙执行各种工作任务，既包括在街头驱赶野猪，也包括在波兰议会进行演讲，例如用波兰语讲个冷笑话。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_0212de5b40b74bd7a97953a44650913f@1547419282_oswg414104oswg2166oswg1388_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：新华国际</p>\\\\n  <p>其实，国产机器人在进入海外用户和当地场景后，已经衍生出了不少出乎国人意料的新用途。</p>\\\\n  <p>例如「机器人警察」。在北美，「波士顿动力狗」逐渐成为不少地区警方标配，地位堪比警用无人机，常被用于危险的侦察任务。在泰国，人形机器人摇身一变为「AI警察机器人」，可利用360度全景摄像头和面部识别系统监控人群，并能识别棍棒等危险物品，实时将数据传回指挥中心。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c1102ac406ac4460bbeed984fa42c29d@1547419282_oswg2501566oswg2382oswg1218_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：泰媒</p>\\\\n  <p>例如「去造船厂焊接钢板」，意大利造船巨头正在研发这类的人形机器人，目的是解决专业焊工短缺的问题；例如「培养人造肌腱」，在牛津大学的研究中，人形机器人被改装成生物反应器，通过模仿人体肩关节的复杂运动，精准地「拉伸」和「锻炼」实验室里培育的人造肌腱；例如「化身第二双手去逛街」，虽然你在中国，但可以通过机器人替你在纽约的商场里试衣服、拿起商品端详......</p>\\\\n  <p>而在中东「土豪国」阿联酋，当地土豪们，正在将机器人融入奢华生活与顶层设计中，例如让人形机器人穿上当地传统白袍、在「未来博物馆」充当明星互动展品，以及在商场扮演客服和警员双重角色等。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_80c86857706940aaabad09096b6bd2de@1547419282_oswg1511860oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：看中东DeepMENA</p>\\\\n  <p>以上案例可以看出，机器人的角色正在变得越来越多元：Ta可以是国家文化的展示窗口、城市安全的移动节点、危险环境下的替身，甚至是前沿科研的得力助手。</p>\\\\n  <p><strong>而基于当地的特定情况和社会现象，海外开发者也带来了对国产机器人的二次开发与本土化应用，例如用来解决当地的野猪泛滥、劳动力短缺、公共安全需求等现实问题。</strong></p>\\\\n  <p><strong>国产机器人，也只有在全球各地和多元用户群体中广泛使用起来，才可以迎来更多极富想象力的功能和应用场景，从而走上越来越宽广的技术落地和产品普及之路。</strong></p>\\\\n  <p>（@三七二十一 对本文亦有贡献）</p>\\\\n  <p>本文来自“雷科技”，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>一年两届的广交会（中国进出口商品交易会），在今天拉开2026年第139届盛会的大幕。</p>\\\\n  <p><strong>今年以来，雷科技（ID：leitech）先后完成CES、MWC、AWE等国内外大型科技展会现场报道。在广州主场举行的这届广交会，雷科技报道团也没有缺席。</strong></p>\\\\n  <p>第139届广交会参展企业超过3.2万家，其中拥有专精特新、单项冠军等称号的优质企业超过1.1万家，均超往届水平。顺应外贸发展新趋势、新特点，本届广交会展品专区增至179个，更多新企业、新产品、新技术借助这一旗舰展示平台走向世界，服务更多全球消费者。</p>\\\\n  <p><strong>2026广交会开展首日，雷科技（ID：leitech）报道团从179个专区中选出声势最大的「服务机器人专区」，并对这一专区进行了深度探展，以下是我们从现场发回的一手观察。</strong></p>\\\\n  <h2><strong>服务机器人外贸战，苏州和深圳打起了擂台</strong></h2>\\\\n  <p>雷科技报道团在探展CES、MWC的具身智能机器人企业展台时，一大印象是品牌展台整体面积相对偏小，如果有上百平方米的展台面积，都可以算机器人品牌中的「大户」了。</p>\\\\n  <p><strong>本届广交会的服务机器人专区，在21.2馆，总面积达到4200平方米，汇聚46家企业，平均每家品牌都有上百平方米的展台面积，实现了家家企业的展览「大户」梦。</strong></p>\\\\n  <p><strong>广交会服务机器人专区，给雷科技（ID：leitech）报道团的另一大直观印象是，在宇树、云深处等杭州明星机器人企业缺席后，苏州在中国外贸这一顶流舞台与深圳机器人企业打起了擂台赛。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1760e894041846d8a089311dc3562bd4@1547419282_oswg3447329oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>在进入广交会服务机器人专区的通道，雷科技（ID：leitech）报道团一眼就看到了苏州机器人企业打出的巨幅宣传海报，「苏州智能机器人，全能实力派」，涵盖追觅、科沃斯、魔法原子、知行、穿山甲等5家代表企业。</p>\\\\n  <p>今年的46家服务机器人专区企业中，深圳则贡献了其中的6家代表企业，涵盖智元、越疆、普渡等代表企业。</p>\\\\n  <p>苏州军团缘何可以在广交会叫板深圳企业，玄机就藏在专区的名称上。<strong>所谓的「服务机器人」，不只包括人形机器人，也包括非人形机器人，而非人形机器人正是追觅、科沃斯等智能清洁品类或发家品类企业的技术和形态发力重点。</strong></p>\\\\n  <p>追觅就在服务机器人专区带来了智能机械臂的展示。这款具身智能机械臂由追觅生态时空象限旗下沸点计划（X-HotPot）品牌打造，依托AI烹饪大脑、3D工业视觉、柔顺力控骨骼等三大核心技术，实现8秒牛肉标准化出品，可实现毫秒级精准涮煮和毫米级投放误差。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6df92d6ef47f4539b31ef6f5903cfe77@1547419282_oswg218633oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>追觅旗下沸点计划，以中餐热门的火锅大类切入，推出对应的火锅机器人，涵盖具身智能机械臂、智能系统等。对于海外市场和海外华人来说，火锅也是颇为流行的一类中式大餐。<strong>在广交会舞台和美食之都，追觅给海外客商实现了「精准投喂」。</strong></p>\\\\n  <p>追觅还带来了服务居家洗护场景的智能机械臂产品，可实现衣物洗护全流程自动化，支持20种方言语音控制。</p>\\\\n  <p>追觅生态另一家机器人企业魔法原子，在广交会展台携马年春晚同款机器人亮相，涵盖全尺寸通用人形机器人GEN 1、高动态双足人形机器人MagicBot Z1，以及覆盖消费与工业场景的MagicDog系列等在内的多形态机器人产品矩阵，展示「让广义机器人服务地球每个角落」的愿景。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_95c2b030fa3e49aaadf250c1fbfe103e@1547419282_oswg3703498oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>科沃斯在本届广交会带来了火爆AWE展台的首款搭载OpenClaw的「管家机器人」：八界。</p>\\\\n  <p>结合OpenClaw等「AI智能体」技术框架，八界已经能够在真实家庭环境中持续学习，并以更快的速度习得技能、理解世界，既可实现基于长期记忆的主动收纳功能，也可担当「居家分身」远程响应的代办需求。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e6c7b0923b494113a32637588d6a3bd0@1547419282_oswg88385oswg1280oswg960_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p><strong>凭借追觅这样的智能生态全场景新锐品牌，以及科沃斯这样的智能清洁机器人老牌企业，苏州在今年的广交会打起了对深圳机器人企业基于「服务」品类的外贸战。而同台竞技的深圳机器人企业也做好了以硬实力应战的准备，打头的正是目前的机器人销量王企业：智元。</strong></p>\\\\n  <h2><strong>具身智能机器人巨头，也在发力商用服务领域</strong></h2>\\\\n  <p>作为本届广交会服务机器人专区最大牌的机器人企业，智元带来了旗下具身智能机器人多产品矩阵的展示。</p>\\\\n  <p><strong>作为全球具身智能机器人销量冠军企业，智元的产线形态愈加丰满，除了主打的人形机器人、轮式机器人、四足机器人和关键灵巧手部件，面向商业空间的自主清洁解决方案，也在成为其新的拓展和发力重点。</strong></p>\\\\n  <p>在广交会智元展台，雷科技（ID：leitech）报道团注意到，其产品层面更显眼的展示落在了旗下首款智能清洁设备C5身上。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_868fa3cec9bb4a1786243b71f5c3c34d@1547419282_oswg3869133oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>智元绝尘C5，面向中大型清洁场景和商用客户群体，具备扫地、洗地、尘推等多种清洁功能，满足各类硬质地面清洁所需；设备配备多种传感器，激光视觉融合定位、点云图像融合感知，应对较复杂工作环境场景；配备工作站可实现自动充电、自动加排水、自动清洁污水箱，显著降低维护难度。</p>\\\\n  <p>智元希望自己的具身智能和硬件技术，可以借由在商用智能清洁设备上的落地，提升公共空间清洁质量、降低保洁工作强度、降低综合作业成本，同时实现清洁数字化，助力智慧物业转型。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_5c80a9493a124208958ceb416276d764@1547419282_oswg4099861oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p><strong>而从根本上来说，智能清洁机器人是目前商业变现能力最强、用户认可和接受度最高的新硬件赛道。相比工业和家庭机器人，智能清洁机器人在产品设计层面进行了更务实、更专一的功能和场景适配，从而也实现了更快速的落地和普及进程。</strong></p>\\\\n  <p><strong>在智能清洁设备愈加机器人化的当下，智元这类的人形和具身智能机器人新巨头企业，拓展和发力智能清洁品类，也就有了更为现实的多重考量。在商用智能清洁设备领域取得初步市场成果后，智元不排除将进军消费级智能清洁赛道。</strong></p>\\\\n  <p>抢先智元，深圳另一家机器人企业越疆已经实现了上市。在广交会展台，雷科技（ID：leitech）报道团看到，越疆同样以机械臂作为目前的主推形态产品，强调其在按摩、制作冰淇淋、吸杯等实际应用场景下的操作娴熟度和流程可靠性。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_fcdf8fb8d233432189909b12888c664f@1547419282_oswg3765177oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p><strong>不难看出，相比CES、MWC等科技大展，广交会的大舞台更强调产品落地的成熟度和可靠性。毕竟来广交会的参展企业以及全球客商，核心目的只有一个，那就是把双方的需求意向转化为实际的订单交易，相比秀技术肌肉，更重要的是能否把产品买卖出去。</strong></p>\\\\n  <p>科大讯飞和九号这类的应用和出行领域巨头企业，也在本届广交会带来了旗下服务机器人产品的展示。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_14fbb90719cc41f69f68734172579daa@1547419282_oswg255579oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">科大讯飞（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>其中，科大讯飞带来了旗下具身智能采训推机器人的演示，其可精准记忆人类操作动作，结合星火大模型可实现任务自主学习与迭代，是一款适配全行业的通用数据采集设备。</p>\\\\n  <p>九号则带来了旗下主攻智能酒店服务场景的机器人产品矩阵展示，涵盖送物、送餐等特定场景下的不同形态机器人产品。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4ba3172f662a4d40b46e23c20f049ab2@1547419282_oswg236187oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <h2><strong>灵巧手、球形和外骨骼，广交会服务机器人专区的三大亮点</strong></h2>\\\\n  <p>逛遍本届广交会的服务机器人专区，雷科技（ID：leitech）报道团还发现了更多亮点。</p>\\\\n  <p>相比于机器人产品展台，雷科技（ID：leitech）发现外骨骼和灵巧手产品展台更容易吸引现场观众排队体验，其中外骨骼更甚。</p>\\\\n  <p>为什么外骨骼机器人展台人气颇高呢？其实也好理解，首先是外骨骼可以直接用来佩戴体验，客商的参与感和体验感更高，也就更易于订单交易的最终促成；其次是外骨骼的体验区面积占比不小，自然也就吸引了更多的排队体验客流；最后是外骨骼产品近年来在国内外市场愈加升温，尤其是在欧美发达国家市场，品类规模体量已经显著上来了。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b887dd789ad941dbaa0ca91c8dcb2b83@1547419282_oswg775036oswg3412oswg1280_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">太希智能（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>灵巧手技术体验区的火热，同理，而其当下在国内不管是产品市场，还是资本市场，也都愈加火热。</p>\\\\n  <p>雷科技（ID：leitech）在广交会灵巧手展台看到，目前有无线和有线两大类技术方案。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e5396193310547bca0f1d60ce9c509ae@1547419282_oswg188123oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">傲意（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>其中，无线灵巧手方案，基于摄像头的机器视觉进行跟随，目前有比较明显的延迟感；有线灵巧手方案，当下则更精准和更低延迟。</p>\\\\n  <p>产品创新层面，引发雷科技（ID：leitech）好奇的是球形机器人。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_be9873c4d4fd42cd8c59a54fedaf4eb6@1547419282_oswg229011oswg1706oswg1279_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <p>这款机器人，出自一家名叫逻腾的杭州机器人厂商，号称「非友好环境中唯一适用的两栖球形机器人」，可在复杂地形地貌、极端天气条件、恶劣及危险工作环境、危险及对抗性业务场景下使用。</p>\\\\n  <p>逻腾展台人员对雷科技（ID：leitech）表示，目前其两栖球形机器人已在国内多家公安机关、武警部队、机场及石油化工园区等投入使用。</p>\\\\n  <p>需要指出的是，虽然杭州机器人企业中的宇树科技、云深处、强脑科技等明星品牌并未参展这届广交会，但杭州服务机器人军团数量（6家）依然在所有城市中处于领先地位，持平深圳、多过苏州。</p>\\\\n  <p><strong>深圳、杭州、苏州的机器人头部企业和集群间的比拼，也将在很大程度上助推国产机器人产业的更快、更好发展。而在广交会舞台，雷科技（ID：leitech）报道团也看到了不少来自广州（7家）的机器人企业或业务企业</strong>，例如动易带来的全尺寸人形机器人，以及视源等企业展示的服务机器人产品。</p>\\\\n  <p>其中，动易的全尺寸人形机器人，攻克了高惯量平衡、万瓦级爆发与���冲击恢复等核心难题，可适配工业劳动、特种应急等通用重负载作业场景。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4185b219f8da4331bbee72f5e95bd818@1547419282_oswg173390oswg1279oswg1706_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">动易（图源：雷科技2026广交会现场摄制）</p>\\\\n  <p>而从中国先进技术产业外贸和出海层面来说，我国的AI应用乃至AI硬件企业已经取得颇为亮眼的出海成绩单，而以智元、宇树等为代表的国产机器人企业，虽然也已取得中国和全球市场的销量领先地位，但在市场发展早期、整体规模体量较小的实际情况下，仍需全面夯实国内、国外两大市场。</p>\\\\n  <p><strong>真正做到国内外市场通吃的国产机器人企业，才会在长远竞赛中立于不败之地，这届广交会舞台上的激烈比拼也是面向未来的一个「预演」。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_f353e86e93ad42f8bc96cca6c11a5f22@1547419282_oswg4927310oswg4096oswg3072_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：雷科技2026广交会现场摄制</p>\\\\n  <h2><strong>老外买机器人去干吗？用途出乎国人意料</strong></h2>\\\\n  <p>近期，一条人形机器人「赶野猪」的短视频在全球社交媒体迅速走红。</p>\\\\n  <p>原来，宇树推出的G1人形机器人在被引入波兰当地后，被命名为「爱德华」（Edward），并在首都华沙执行各种工作任务，既包括在街头驱赶野猪，也包括在波兰议会进行演讲，例如用波兰语讲个冷笑话。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_0212de5b40b74bd7a97953a44650913f@1547419282_oswg414104oswg2166oswg1388_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：新华国际</p>\\\\n  <p>其实，国产机器人在进入海外用户和当地场景后，已经衍生出了不少出乎国人意料的新用途。</p>\\\\n  <p>例如「机器人警察」。在北美，「波士顿动力狗」逐渐成为不少地区警方标配，地位堪比警用无人机，常被用于危险的侦察任务。在泰国，人形机器人摇身一变为「AI警察机器人」，可利用360度全景摄像头和面部识别系统监控人群，并能识别棍棒等危险物品，实时将数据传回指挥中心。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c1102ac406ac4460bbeed984fa42c29d@1547419282_oswg2501566oswg2382oswg1218_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：泰媒</p>\\\\n  <p>例如「去造船厂焊接钢板」，意大利造船巨头正在研发这类的人形机器人，目的是解决专业焊工短缺的问题；例如「培养人造肌腱」，在牛津大学的研究中，人形机器人被改装成生物反应器，通过模仿人体肩关节的复杂运动，精准地「拉伸」和「锻炼」实验室里培育的人造肌腱；例如「化身第二双手去逛街」，虽然你在中国，但可以通过机器人替你在纽约的商场里试衣服、拿起商品端详......</p>\\\\n  <p>而在中东「土豪国」阿联酋，当地土豪们，正在将机器人融入奢华生活与顶层设计中，例如让人形机器人穿上当地传统白袍、在「未来博物馆」充当明星互动展品，以及在商场扮演客服和警员双重角色等。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_80c86857706940aaabad09096b6bd2de@1547419282_oswg1511860oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图源：看中东DeepMENA</p>\\\\n  <p>以上案例可以看出，机器人的角色正在变得越来越多元：Ta可以是国家文化的展示窗口、城市安全的移动节点、危险环境下的替身，甚至是前沿科研的得力助手。</p>\\\\n  <p><strong>而基于当地的特定情况和社会现象，海外开发者也带来了对国产机器人的二次开发与本土化应用，例如用来解决当地的野猪泛滥、劳动力短缺、公共安全需求等现实问题。</strong></p>\\\\n  <p><strong>国产机器人，也只有在全球各地和多元用户群体中广泛使用起来，才可以迎来更多极富想象力的功能和应用场景，从而走上越来越宽广的技术落地和产品普及之路。</strong></p>\\\\n  <p>（@三七二十一 对本文亦有贡献）</p>\\\\n  <p>本文来自“雷科技”，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'雷科技\'}], \'author\': \'雷科技\', \'author_detail\': {\'name\': \'雷科技\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'智能清洁和人形机器人企业互相斗法。\'}]}\", \"published_at\": \"2026-04-16 09:22:03\", \"ai_json_output\": \"\"}', '一年两届的广交会（中国进出口商品交易会），在今天拉开2026年第139届盛会的大幕。\n今年以来，雷科技（ID：leitech）先后完成CES、MWC、AWE等国内外大型科技展会现场报道。在广州主场举行的这届广交会，雷科技报道团也没有缺席。\n第139届广交会参展企业超过3.2万家，其中拥有专精特新、单项冠军等称号的优质企业超过1.1万家，均超往届水平。顺应外贸发展新趋势、新特点，本届广交会展品专区增至179个，更多新企业、新产品、新技术借助这一旗舰展示平台走向世界，服务更多全球消费者。\n2026广交会开展首日，雷科技（ID：leitech）报道团从179个专区中选出声势最大的「服务机器人专区」，并对这一专区进行了深度探展，以下是我们从现场发回的一手观察。\n服务机器人外贸战，苏州和深圳打起了擂台\n雷科技报道团在探展CES、MWC的具身智能机器人企业展台时，一大印象是品牌展台整体面积相对偏小，如果有上百平方米的展台面积，都可以算机器人品牌中的「大户」了。\n本届广交会的服务机器人专区，在21.2馆，总面积达到4200平方米，汇聚46家企业，平均每家品牌都有上百平方米的展台面积，实现了家家企业的展览「大户」梦。\n广交会服务机器人专区，给雷科技（ID：leitech）报道团的另一大直观印象是，在宇树、云深处等杭州明星机器人企业缺席后，苏州在中国外贸这一顶流舞台与深圳机器人企业打起了擂台赛。\n图源：雷科技2026广交会现场摄制\n在进入广交会服务机器人专区的通道，雷科技（ID：leitech）报道团一眼就看到了苏州机器人企业打出的巨幅宣传海报，「苏州智能机器人，全能实力派」，涵盖追觅、科沃斯、魔法原子、知行、穿山甲等5家代表企业。\n今年的46家服务机器人专区企业中，深圳则贡献了其中的6家代表企业，涵盖智元、越疆、普渡等代表企业。\n苏州军团缘何可以在广交会叫板深圳企业，玄机就藏在专区的名称上。\n所谓的「服务机器人」，不只包括人形机器人，也包括非人形机器人，而非人形机器人正是追觅、科沃斯等智能清洁品类或发家品类企业的技术和形态发力重点。\n追觅就在服务机器人专区带来了智能机械臂的展示。这款具身智能机械臂由追觅生态时空象限旗下沸点计划（X-HotPot）品牌打造，依托AI烹饪大脑、3D工业视觉、柔顺力控骨骼等三大核心技术，实现8秒牛肉标准化出品，可实现毫秒级精准涮煮和毫米级投放误差。\n图源：雷科技2026广交会现场摄制\n追觅旗下沸点计划，以中餐热门的火锅大类切入，推出对应的火锅机器人，涵盖具身智能机械臂、智能系统等。对于海外市场和海外华人来说，火锅也是颇为流行的一类中式大餐。\n在广交会舞台和美食之都，追觅给海外客商实现了「精准投喂」。\n追觅还带来了服务居家洗护场景的智能机械臂产品，可实现衣物洗护全流程自动化，支持20种方言语音控制。\n追觅生态另一家机器人企业魔法原子，在广交会展台携马年春晚同款机器人亮相，涵盖全尺寸通用人形机器人GEN 1、高动态双足人形机器人MagicBot Z1，以及覆盖消费与工业场景的MagicDog系列等在内的多形态机器人产品矩阵，展示「让广义机器人服务地球每个角落」的愿景。\n图源：雷科技2026广交会现场摄制\n科沃斯在本届广交会带来了火爆AWE展台的首款搭载OpenClaw的「管家机器人」：八界。\n结合OpenClaw等「AI智能体」技术框架，八界已经能够在真实家庭环境中持续学习，并以更快的速度习得技能、理解世界，既可实现基于长期记忆的主动收纳功能，也可担当「居家分身」远程响应的代办需求。\n图源：雷科技2026广交会现场摄制\n凭借追觅这样的智能生态全场景新锐品牌，以及科沃斯这样的智能清洁机器人老牌企业，苏州在今年的广交会打起了对深圳机器人企业基于「服务」品类的外贸战。而同台竞技的深圳机器人企业也做好了以硬实力应战的准备，打头的正是目前的机器人销量王企业：智元。\n具身智能机器人巨头，也在发力商用服务领域\n作为本届广交会服务机器人专区最大牌的机器人企业，智元带来了旗下具身智能机器人多产品矩阵的展示。\n作为全球具身智能机器人销量冠军企业，智元的产线形态愈加丰满，除了主打的人形机器人、轮式机器人、四足机器人和关键灵巧手部件，面向商业空间的自主清洁解决方案，也在成为其新的拓展和发力重点。\n在广交会智元展台，雷科技（ID：leitech）报道团注意到，其产品层面更显眼的展示落在了旗下首款智能清洁设备C5身上。\n图源：雷科技2026广交会现场摄制\n智元绝尘C5，面向中大型清洁场景和商用客户群体，具备扫地、洗地、尘推等多种清洁功能，满足各类硬质地面清洁所需；设备配备多种传感器，激光视觉融合定位、点云图像融合感知，应对较复杂工作环境场景；配备工作站可实现自动充电、自动加排水、自动清洁污水箱，显著降低维护难度。\n智元希望自己的具身智能和硬件技术，可以借由在商用智能清洁设备上的落地，提升公共空间清洁质量、降低保洁工作强度、降低综合作业成本，同时实现清洁数字化，助力智慧物业转型。\n图源：雷科技2026广交会现场摄制\n而从根本上来说，智能清洁机器人是目前商业变现能力最强、用户认可和接受度最高的新硬件赛道。相比工业和家庭机器人，智能清洁机器人在产品设计层面进行了更务实、更专一的功能和场景适配，从而也实现了更快速的落地和普及进程。\n在智能清洁设备愈加机器人化的当下，智元这类的人形和具身智能机器人新巨头企业，拓展和发力智能清洁品类，也就有了更为现实的多重考量。在商用智能清洁设备领域取得初步市场成果后，智元不排除将进军消费级智能清洁赛道。\n抢先智元，深圳另一家机器人企业越疆已经实现了上市。在广交会展台，雷科技（ID：leitech）报道团看到，越疆同样以机械臂作为目前的主推形态产品，强调其在按摩、制作冰淇淋、吸杯等实际应用场景下的操作娴熟度和流程可靠性。\n图源：雷科技2026广交会现场摄制\n不难看出，相比CES、MWC等科技大展，广交会的大舞台更强调产品落地的成熟度和可靠性。毕竟来广交会的参展企业以及全球客商，核心目的只有一个，那就是把双方的需求意向转化为实际的订单交易，相比秀技术肌肉，更重要的是能否把产品买卖出去。\n科大讯飞和九号这类的应用和出行领域巨头企业，也在本届广交会带来了旗下服务机器人产品的展示。\n科大讯飞（图源：雷科技2026广交会现场摄制）\n其中，科大讯飞带来了旗下具身智能采训推机器人的演示，其可精准记忆人类操作动作，结合星火大模型可实现任务自主学习与迭代，是一款适配全行业的通用数据采集设备。\n九号则带来了旗下主攻智能酒店服务场景的机器人产品矩阵展示，涵盖送物、送餐等特定场景下的不同形态机器人产品。\n图源：雷科技2026广交会现场摄制\n灵巧手、球形和外骨骼，广交会服务机器人专区的三大亮点\n逛遍本届广交会的服务机器人专区，雷科技（ID：leitech）报道团还发现了更多亮点。\n相比于机器人产品展台，雷科技（ID：leitech）发现外骨骼和灵巧手产品展台更容易吸引现场观众排队体验，其中外骨骼更甚。\n为什么外骨骼机器人展台人气颇高呢？其实也好理解，首先是外骨骼可以直接用来佩戴体验，客商的参与感和体验感更高，也就更易于订单交易的最终促成；其次是外骨骼的体验区面积占比不小，自然也就吸引了更多的排队体验客流；最后是外骨骼产品近年来在国内外市场愈加升温，尤其是在欧美发达国家市场，品类规模体量已经显著上来了。\n太希智能（图源：雷科技2026广交会现场摄制）\n灵巧手技术体验区的火热，同理，而其当下在国内不管是产品市场，还是资本市场，也都愈加火热。\n雷科技（ID：leitech）在广交会灵巧手展台看到，目前有无线和有线两大类技术方案。\n傲意（图源：雷科技2026广交会现场摄制）\n其中，无线灵巧手方案，基于摄像头的机器视觉进行跟随，目前有比较明显的延迟感；有线灵巧手方案，当下则更精准和更低延迟。\n产品创新层面，引发雷科技（ID：leitech）好奇的是球形机器人。\n图源：雷科技2026广交会现场摄制\n这款机器人，出自一家名叫逻腾的杭州机器人厂商，号称「非友好环境中唯一适用的两栖球形机器人」，可在复杂地形地貌、极端天气条件、恶劣及危险工作环境、危险及对抗性业务场景下使用。\n逻腾展台人员对雷科技（ID：leitech）表示，目前其两栖球形机器人已在国内多家公安机关、武警部队、机场及石油化工园区等投入使用。\n需要指出的是，虽然杭州机器人企业中的宇树科技、云深处、强脑科技等明星品牌并未参展这届广交会，但杭州服务机器人军团数量（6家）依然在所有城市中处于领先地位，持平深圳、多过苏州。\n深圳、杭州、苏州的机器人头部企业和集群间的比拼，也将在很大程度上助推国产机器人产业的更快、更好发展。而在广交会舞台，雷科技（ID：leitech）报道团也看到了不少来自广州（7家）的机器人企业或业务企业\n，例如动易带来的全尺寸人形机器人，以及视源等企业展示的服务机器人产品。\n其中，动易的全尺寸人形机器人，攻克了高惯量平衡、万瓦级爆发与抗冲击恢复等核心难题，可适配工业劳动、特种应急等通用重负载作业场景。\n动易（图源：雷科技2026广交会现场摄制）\n而从中国先进技术产业外贸和出海层面来说，我国的AI应用乃至AI硬件企业已经取得颇为亮眼的出海成绩单，而以智元、宇树等为代表的国产机器人企业，虽然也已取得中国和全球市场的销量领先地位，但在市场发展早期、整体规模体量较小的实际情况下，仍需全面夯实国内、国外两大市场。\n真正做到国内外市场通吃的国产机器人企业，才会在长远竞赛中立于不败之地，这届广交会舞台上的激烈比拼也是面向未来的一个「预演」。\n图源：雷科技2026广交会现场摄制\n老外买机器人去干吗？用途出乎国人意料\n近期，一条人形机器人「赶野猪」的短视频在全球社交媒体迅速走红。\n原来，宇树推出的G1人形机器人在被引入波兰当地后，被命名为「爱德华」（Edward），并在首都华沙执行各种工作任务，既包括在街头驱赶野猪，也包括在波兰议会进行演讲，例如用波兰语讲个冷笑话。\n图源：新华国际\n其实，国产机器人在进入海外用户和当地场景后，已经衍生出了不少出乎国人意料的新用途。\n例如「机器人警察」。在北美，「波士顿动力狗」逐渐成为不少地区警方标配，地位堪比警用无人机，常被用于危险的侦察任务。在泰国，人形机器人摇身一变为「AI警察机器人」，可利用360度全景摄像头和面部识别系统监控人群，并能识别棍棒等危险物品，实时将数据传回指挥中心。\n图源：泰媒\n例如「去造船厂焊接钢板」，意大利造船巨头正在研发这类的人形机器人，目的是解决专业焊工短缺的问题；例如「培养人造肌腱」，在牛津大学的研究中，人形机器人被改装成生物反应器，通过模仿人体肩关节的复杂运动，精准地「拉伸」和「锻炼」实验室里培育的人造肌腱；例如「化身第二双手去逛街」，虽然你在中国，但可以通过机器人替你在纽约的商场里试衣服、拿起商品端详......\n而在中东「土豪国」阿联酋，当地土豪们，正在将机器人融入奢华生活与顶层设计中，例如让人形机器人穿上当地传统白袍、在「未来博物馆」充当明星互动展品，以及在商场扮演客服和警员双重角色等。\n图源：看中东DeepMENA\n以上案例可以看出，机器人的角色正在变得越来越多元：Ta可以是国家文化的展示窗口、城市安全的移动节点、危险环境下的替身，甚至是前沿科研的得力助手。\n而基于当地的特定情况和社会现象，海外开发者也带来了对国产机器人的二次开发与本土化应用，例如用来解决当地的野猪泛滥、劳动力短缺、公共安全需求等现实问题。\n国产机器人，也只有在全球各地和多元用户群体中广泛使用起来，才可以迎来更多极富想象力的功能和应用场景，从而走上越来越宽广的技术落地和产品普及之路。\n（@三七二十一 对本文亦有贡献）\n本文来自“雷科技”，36氪经授权发布。', '2026-04-16 09:22:03', '2026-04-16 11:50:01');
INSERT INTO `news_detail` VALUES (24, 1002, 7, '消费与零售', '深陷调查风波，Lululemon的中产滤镜破了', '', '<p>LuluLemon摊上事了。</p>\n<p>据“新华社”消息，美国得克萨斯州总检察长肯·帕克斯顿日前宣布，已向加拿大运动服饰品牌Lululemon（Lululemon）的美国公司发布调查令，将调查其产品是否含有“永久性化学物质”。</p>\n<p>这个被誉为中产女性最爱的健身服饰品牌，一直主打着“健康生活方式”的价值观，但这一次供应链合规性的抽检，揭开了Lululemon的真实底色。</p>\n<p>当所谓的中产阶级“神裤”与有毒化学物质产生关联，品牌高昂的溢价逻辑正面临前所未有的信任崩塌。</p>\n<p>消费者开始“算账”：1000元一条的瑜伽裤，到底值不值？</p>\n<h2><strong>Lululemon被指控“有毒”？</strong></h2>\n<p>近日，加拿大运动品牌Lululemon因涉嫌含有“永久性化学物质”PFAS遭遇美国得克萨斯州总检察长的调查。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_afee7e5822a347a58b03a264ec522df2@000000_oswg424766oswg752oswg375_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>“永久性化学物质”主要是指全氟和多氟烷基物质（PFAS）。“全氟和多氟烷基物质”是一类广泛应用于防水服装、食品包装、化妆品等产品的人工合成化学物质，这种物质难以自然降解，因此被称为“永久性化学物质”。</p>\n<p><strong>《节点财经》了解到，这类物质会在环境和人体中持续累积，长期暴露可能与内分泌紊乱、不孕不育乃至癌症相关。正因如此，多国监管机构已将其列为重点管控对象。</strong></p>\n<p>按照调查安排，得克萨斯州检察长办公室将审查Lululemon的限用物质清单、产品检测流程和供应链管理，核查其产品是否真的达到了它自己宣传的安全标准。帕克斯顿的话说得很直接：不会允许任何企业打着\"健康\"和\"可持续\"的幌子，高价向消费者兜售有害产品。</p>\n<p>对此，Lululemon方面回应称，该公司产品不使用PFAS。此前曾在少量防水产品中使用相关物质，已于2023财年逐步淘汰。该公司要求供应商通过第三方机构定期开展包括PFAS在内的限用物质检测，以确保持续合规。Lululemon还表示，正在配合提供调查所需材料。</p>\n<p>此外，4月14日晚，Lululemon中国就其运动服饰中可能含有“永久性化学物”的指控回应，“始终将客人的健康与安全置于首位。Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。”</p>\n<p>尽管品牌方展现出积极配合调查的态度，但这场关于“产品安全性”的博弈，已将其长期标榜的“健康”标签推向了舆论的风口浪尖。</p>\n<h2><strong>业绩失速：群雄围猎下的“防御期”</strong></h2>\n<p>对Lululemon来说，这次调查的时间节点，实在难受。</p>\n<p>财报显示，其核心的美洲市场净收入同比下滑4%，今年以来股价跌幅已超过20%。增长失速的品牌，最怕的就是信任危机——而这次调查，偏偏打在了\"健康\"这个品牌最核心的标签上。</p>\n<p>更麻烦的是，竞争对手早就环伺四周。</p>\n<p>如果谈及Lululemon的最大对手，那当属Alo Yoga。</p>\n<p>Alo Yoga被视为 Lululemon 在北美最强劲的对手。其定位更偏向“运动奢侈品”，深受好莱坞明星追捧。2026 年初，Alo 正式进军中国市场，在选址上极度贴近 Lululemon，似乎意在与Lululemon 直接争夺高端瑜伽客群。</p>\n<p>不仅如此，近几年，Nike 和 Adidas这样的巨头运动品牌，也在加强对瑜伽赛道的投入。</p>\n<p>在中国本土市场，同样跑出了实力强悍的玩家。安踏旗下的 MAIA ACTIVE在剪裁和价格上更具亲和力，精准切中中国中产女性的需求。</p>\n<p><strong>《节点财经》看来，内忧外患之下，Lululemon 正处于一个极为被动的防御周期</strong>。往上打的，是Alo Yoga这类品牌，把瑜伽服往奢侈品方向拉，靠明星背书和更强的视觉调性，争夺愿意付更高溢价的消费者；往下打的，是MAIA ACTIVE、源头工厂品牌这类，把“同等面料、同等剪裁、砍掉品牌叙事成本”作为卖点，直接切走价格敏感但不愿将就品质的那批人。</p>\n<p>横向挤压的，是Nike、Adidas这种巨头，体量大、渠道广，虽然在专业度和品牌调性上不如Lululemon，但在大众市场的覆盖能力是碾压级的。</p>\n<p>Lululemon被夹在中间，上不像奢侈品，下打不过平替，这个位置其实越来越难受。</p>\n<p>对于中国市场而言，压力同样不小。</p>\n<p>今年3月，Lululemon发布的2025财年第四季度及全年财报。中国市场方面，2025财年第四季度净营收同比增长24%，整个财年净营收同比增长达29%。截至2025财年底，Lululemon在中国的直营门店数量已超过170家。</p>\n<p>在门店拓展方面，Lululemon方面透露，2026财年，公司计划在全球范围内新开设40至45家直营门店。具体而言，计划北美市场新开设约15家门店，国际市场新开设25至30家门店，其中大部分将布局于中国市场。</p>\n<p>该事件曝光后，不少网友直言“立马退掉”。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_02cbb8f58d40409193334c15fbc99a1a@000000_oswg24535oswg792oswg196_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_1a6a0893bd9445038626599ef15eea2b@000000_oswg509948oswg1080oswg393_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>Lululemon 如果不能在 2026 年通过材料创新重新夺回“安全与健康”的话语权，其行业龙头的宝座将被进一步动摇。</p>\n<h2><strong>\"溢价\"的逻辑，正在被消费者重新算账</strong></h2>\n<p>巨大的竞争之下，品牌开始“祛魅”。</p>\n<p><strong>过去，Lululemon能卖出高价，靠的是三件事撑着：更好的品质、更安全的材料、更有辨识度的身份感。这三条里，\"品质与安全\"是地基。一旦地基松了，整个定价逻辑就站不住。</strong></p>\n<p>当Lululemon这样主打健康、环保的高溢价品牌，被曝出含有致癌风险的“永久性化学物质”时，溢价逻辑中最核心的“品质与安全”支柱塌方了。</p>\n<p>消费者开始反思，如果1000元的瑜伽裤和200元的瑜伽裤同样面临化学残留风险，甚至200元的平替在国标检测下更透明，那么“溢价”就变成了纯粹的“智商税”。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_45ff877b34d1486ebbcd73aa8c71ca8f@000000_oswg259607oswg597oswg570_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>说白了，溢价时代买的是品牌讲的故事；现在的消费者，越来越想知道裤子本身是什么做的、安不安全、值不值这个价。</strong></p>\n<p>瑜伽服其实是个很特殊的品类——它介于\"功能性运动服\"和\"日常穿搭\"之间。消费者买它，不只是为了练瑜伽，更多时候是穿着它去咖啡馆、去买菜、去接娃。这就决定了它的竞争逻辑跟跑鞋、篮球服不一样，它既要卖功能，也要卖\"我是什么样的人\"。</p>\n<p>Lululemon当年崛起，本质上是把一件运动裤变成了中产女性的“身份符号”。 这个打法极其聪明，但也极其脆弱——因为身份符号一旦破圈或者祛魅，溢价就很难维持。</p>\n<p>溢价时代，消费者买的是“品牌讲的故事”；质价比时代，买的是“产品的物理属性”。</p>\n<p>像MAIA ACTIVE或一些源头工厂品牌的流行，是因为它们去掉了品牌的“叙事成本”，直接提供与大牌体感相似的产品。当消费者发现“故事”并不能保护健康或提升运动表现时，回归功能真实成为必然。</p>\n<p>《节点财经》看来，“质价比时代”不代表消费降级，而是消费者的专业化和去盲目化。 对于Lululemon而言，这次化学物质风波是一次致命的提醒。当<strong>品牌失去“安全性”这一底层质价比时，它所引以为傲的品牌溢价就会迅速风化。</strong></p>\n<p>对Lululemon来说，这次风波是一个很重的警告。品牌可以靠营销把故事讲得很好，但供应链的底层如果撑不住，这个故事迟早会塌。比业绩下滑更难收拾的，是被消费者质疑：你卖给我的那条\"健康裤\"，到底健不健康？</p>\n<p>真正的出路只有一条：不是再发一篇声明，而是在材料和供应链上拿出真正经得起检验的东西。</p>\n<p><strong>《节点财经》看来，这个行业的天花板其实没有想象中高。</strong>瑜伽服的复购频次有限，功能迭代空间也不像科技产品那么大，最终拼的还是：面料技术的真实差异、供应链的合规透明度、以及品牌能不能持续和消费者保持情感连接。</p>\n<p><strong>谁能在这三件事上同时做扎实，谁才能真正站稳。光靠故事，越来越难了。</strong></p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s?__biz=MzI1ODgwMDk3OQ==&amp;mid=2247546355&amp;idx=2&amp;sn=9d097c6b19f4dc28978fc3ab95088a6c&amp;chksm=ebab7dfa9170f205878d1bcd52864b46a3ad1004afc8504c475aaca3aa94d92b70aa0eeb61a9&amp;scene=0&amp;xtrack=1#rd\">“节点财经”（ID：jiedian2018）</a>，作者：零度，36氪经授权发布。</p>', 'https://36kr.com/p/3768176882369033?f=rss', 0, '', '{\"summary\": \"本文解析Lululemon陷入化学物质调查风波的影响，为出海服饰品牌提供供应链合规与品牌运营的参考\", \"abstract\": \"加拿大运动服饰品牌Lululemon因产品涉嫌含管控永久性化学物质PFAS，被美国得克萨斯州总检察长发起调查。Lululemon回应称已淘汰PFAS使用，中国在售产品符合合规要求，正配合调查。本次风波发生在Lululemon业绩增长失速期，品牌核心的健康人设与高溢价逻辑遭到消费者质疑。文章指出，运动服饰赛道进入质价比时代，仅靠品牌叙事难以维持优势，合规供应链与产品品质才是核心竞争力。\", \"keywords\": [\"Lululemon\", \"PFAS\", \"永久性化学物质\", \"供应链合规\", \"品牌溢价\", \"运动服饰\", \"美国监管\", \"消费信任\"], \"policy_risk\": {\"market_risk\": \"Lululemon因本次调查陷入信任危机，核心“健康”品牌标签受损，高溢价逻辑遭到消费者质疑，叠加业绩失速、多竞品挤压，市场处境被动，中国市场也出现消费者退单情况。\", \"policy_compliance\": \"多国已将全氟和多氟烷基物质（PFAS，即永久性化学物质）列为重点管控对象，美国得克萨斯州总检察长已对Lululemon美国公司发布调查令，核查产品是否符合宣传的安全标准，审查其限用物质清单、检测流程及供应链管理。\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"https://36kr.com/p/3768176882369033?f=rss\", \"title\": \"深陷调查风波，Lululemon的中产滤镜破了\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>LuluLemon摊上事了。</p>\\n<p>据“新华社”消息，美国得克萨斯州总检察长肯·帕克斯顿日前宣布，已向加拿大运动服饰品牌Lululemon（Lululemon）的美国公司发布调查令，将调查其产品是否含有“永久性化学物质”。</p>\\n<p>这个被誉为中产女性最爱的健身服饰品牌，一直主打着“健康生活方式”的价值观，但这一次供应链合规性的抽检，揭开了Lululemon的真实底色。</p>\\n<p>当所谓的中产阶级“神裤”与有毒化学物质产生关联，品牌高昂的溢价逻辑正面临前所未有的信任崩塌。</p>\\n<p>消费者开始“算账”：1000元一条的瑜伽裤，到底值不值？</p>\\n<h2><strong>Lululemon被指控“有毒”？</strong></h2>\\n<p>近日，加拿大运动品牌Lululemon因涉嫌含有“永久性化学物质”PFAS遭遇美国得克萨斯州总检察长的调查。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_afee7e5822a347a58b03a264ec522df2@000000_oswg424766oswg752oswg375_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>“永久性化学物质”主要是指全氟和多氟烷基物质（PFAS）。“全氟和多氟烷基物质”是一类广泛应用于防水服装、食品包装、化妆品等产品的人工合成化学物质，这种物质难以自然降解，因此被称为“永久性化学物质”。</p>\\n<p><strong>《节点财经》了解到，这类物质会在环境和人体中持续累积，长期暴露可能与内分泌紊乱、不孕不育乃至癌症相关。正因如此，多国监管机构已将其列为重点管控对象。</strong></p>\\n<p>按照调查安排，得克萨斯州检察长办公室将审查Lululemon的限用物质清单、产品检测流程和供应链管理，核查其产品是否真的达到了它自己宣传的安全标准。帕克斯顿的话说得很直接：不会允许任何企业打着\\\"健康\\\"和\\\"可持续\\\"的幌子，高价向消费者兜售有害产品。</p>\\n<p>对此，Lululemon方面回应称，该公司产品不使用PFAS。此前曾在少量防水产品中使用相关物质，已于2023财年逐步淘汰。该公司要求供应商通过第三方机构定期开展包括PFAS在内的限用物质检测，以确保持续合规。Lululemon还表示，正在配合提供调查所需材料。</p>\\n<p>此外，4月14日晚，Lululemon中国就其运动服饰中可能含有“永久性化学物”的指控回应，“始终将客人的健康与安全置于首位。Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。”</p>\\n<p>尽管品牌方展现出积极配合调查的态度，但这场关于“产品安全性”的博弈，已将其长期标榜的“健康”标签推向了舆论的风口浪尖。</p>\\n<h2><strong>业绩失速：群雄围猎下的“防御期”</strong></h2>\\n<p>对Lululemon来说，这次调查的时间节点，实在难受。</p>\\n<p>财报显示，其核心的美洲市场净收入同比下滑4%，今年以来股价跌幅已超过20%。增长失速的品牌，最怕的就是信任危机——而这次调查，偏偏打在了\\\"健康\\\"这个品牌最核心的标签上。</p>\\n<p>更麻烦的是，竞争对手早就环伺四周。</p>\\n<p>如果谈及Lululemon的最大对手，那当属Alo Yoga。</p>\\n<p>Alo Yoga被视为 Lululemon 在北美最强劲的对手。其定位更偏向“运动奢侈品”，深受好莱坞明星追捧。2026 年初，Alo 正式进军中国市场，在选址上极度贴近 Lululemon，似乎意在与Lululemon 直接争夺高端瑜伽客群。</p>\\n<p>不仅如此，近几年，Nike 和 Adidas这样的巨头运动品牌，也在加强对瑜伽赛道的投入。</p>\\n<p>在中国本土市场，同样跑出了实力强悍的玩家。安踏旗下的 MAIA ACTIVE在剪裁和价格上更具亲和力，精准切中中国中产女性的需求。</p>\\n<p><strong>《节点财经》看来，内忧外患之下，Lululemon 正处于一个极为被动的防御周期</strong>。往上打的，是Alo Yoga这类品牌，把瑜伽服往奢侈品方向拉，靠明星背书和更强的视觉调性，争夺愿意付更高溢价的消费者；往下打的，是MAIA ACTIVE、源头工厂品牌这类，把“同等面料、同等剪裁、砍掉品牌叙事成本”作为卖点，直接切走价格敏感但不愿将就品质的那批人。</p>\\n<p>横向挤压的，是Nike、Adidas这种巨头，体量大、渠道广，虽然在专业度和品牌调性上不如Lululemon，但在大众市场的覆盖能力是碾压级的。</p>\\n<p>Lululemon被夹在中间，上不像奢侈品，下打不过平替，这个位置其实越来越难受。</p>\\n<p>对于中国市场而言，压力同样不小。</p>\\n<p>今年3月，Lululemon发布的2025财年第四季度及全年财报。中国市场方面，2025财年第四季度净营收同比增长24%，整个财年净营收同比增长达29%。截至2025财年底，Lululemon在中国的直营门店数量已超过170家。</p>\\n<p>在门店拓展方面，Lululemon方面透露，2026财年，公司计划在全球范围内新开设40至45家直营门店。具体而言，计划北美市场新开设约15家门店，国际市场新开设25至30家门店，其中大部分将布局于中国市场。</p>\\n<p>该事件曝光后，不少网友直言“立马退掉”。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_02cbb8f58d40409193334c15fbc99a1a@000000_oswg24535oswg792oswg196_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_1a6a0893bd9445038626599ef15eea2b@000000_oswg509948oswg1080oswg393_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>Lululemon 如果不能在 2026 年通过材料创新重新夺回“安全与健康”的话语权，其行业龙头的宝座将被进一步动摇。</p>\\n<h2><strong>\\\"溢价\\\"的逻辑，正在被消费者重新算账</strong></h2>\\n<p>巨大的竞争之下，品牌开始“祛魅”。</p>\\n<p><strong>过去，Lululemon能卖出高价，靠的是三件事撑着：更好的品质、更安全的材料、更有辨识度的身份感。这三条里，\\\"品质与安全\\\"是地基。一旦地基松了，整个定价逻辑就站不住。</strong></p>\\n<p>当Lululemon这样主打健康、环保的高溢价品牌，被曝出含有致癌风险的“永久性化学物质”时，溢价逻辑中最核心的“品质与安全”支柱塌方了。</p>\\n<p>消费者开始反思，如果1000元的瑜伽裤和200元的瑜伽裤同样面临化学残留风险，甚至200元的平替在国标检测下更透明，那么“溢价”就变成了纯粹的“智商税”。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_45ff877b34d1486ebbcd73aa8c71ca8f@000000_oswg259607oswg597oswg570_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>说白了，溢价时代买的是品牌讲的故事；现在的消费者，越来越想知道裤子本身是什么做的、安不安全、值不值这个价。</strong></p>\\n<p>瑜伽服其实是个很特殊的品类——它介于\\\"功能性运动服\\\"和\\\"日常穿搭\\\"之间。消费者买它，不只是为了练瑜伽，更多时候是穿着它去咖啡馆、去买菜、去接娃。这就决定了它的竞争逻辑跟跑鞋、篮球服不一样，它既要卖功能，也要卖\\\"我是什么样的人\\\"。</p>\\n<p>Lululemon当年崛起，本质上是把一件运动裤变成了中产女性的“身份符号”。 这个打法极其聪明，但也极其脆弱——因为身份符号一旦破圈或者祛魅，溢价就很难维持。</p>\\n<p>溢价时代，消费者买的是“品牌讲的故事”；质价比时代，买的是“产品的物理属性”。</p>\\n<p>像MAIA ACTIVE或一些源头工厂品牌的流行，是因为它们去掉了品牌的“叙事成本”，直接提供与大牌体感相似的产品。当消费者发现“故事”并不能保护健康或提升运动表现时，回归功能真实成为必然。</p>\\n<p>《节点财经》看来，“质价比时代”不代表消费降级，而是消费者的专业化和去盲目化。 对于Lululemon而言，这次化学物质风波是一次致命的提醒。当<strong>品牌失去“安全性”这一底层质价比时，它所引以为傲的品牌溢价就会迅速风化。</strong></p>\\n<p>对Lululemon来说，这次风波是一个很重的警告。品牌可以靠营销把故事讲得很好，但供应链的底层如果撑不住，这个故事迟早会塌。比业绩下滑更难收拾的，是被消费者质疑：你卖给我的那条\\\"健康裤\\\"，到底健不健康？</p>\\n<p>真正的出路只有一条：不是再发一篇声明，而是在材料和供应链上拿出真正经得起检验的东西。</p>\\n<p><strong>《节点财经》看来，这个行业的天花板其实没有想象中高。</strong>瑜伽服的复购频次有限，功能迭代空间也不像科技产品那么大，最终拼的还是：面料技术的真实差异、供应链的合规透明度、以及品牌能不能持续和消费者保持情感连接。</p>\\n<p><strong>谁能在这三件事上同时做扎实，谁才能真正站稳。光靠故事，越来越难了。</strong></p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI1ODgwMDk3OQ==&amp;mid=2247546355&amp;idx=2&amp;sn=9d097c6b19f4dc28978fc3ab95088a6c&amp;chksm=ebab7dfa9170f205878d1bcd52864b46a3ad1004afc8504c475aaca3aa94d92b70aa0eeb61a9&amp;scene=0&amp;xtrack=1#rd\\\">“节点财经”（ID：jiedian2018）</a>，作者：零度，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'深陷调查风波，Lululemon的中产滤镜破了\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'深陷调查风波，Lululemon的中产滤镜破了\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768176882369033?f=rss\'}], \'link\': \'https://36kr.com/p/3768176882369033?f=rss\', \'published\': \'2026-04-16 08:17:18  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=0, tm_min=17, tm_sec=18, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>LuluLemon摊上事了。</p>\\\\n  <p>据“新华社”消息，美国得克萨斯州总检察长肯·帕克斯顿日前宣布，已向加拿大运动服饰品牌Lululemon（Lululemon）的美国公司发布调查令，将调查其产品是否含有“永久性化学物质”。</p>\\\\n  <p>这个被誉为中产女性最爱的健身服饰品牌，一直主打着“健康生活方式”的价值观，但这一次供应链合规性的抽检，揭开了Lululemon的真实底色。</p>\\\\n  <p>当所谓的中产阶级“神裤”与有毒化学物质产生关联，品牌高昂的溢价逻辑正面临前所未有的信任崩塌。</p>\\\\n  <p>消费者开始“算账”：1000元一条的瑜伽裤，到底值不值？</p>\\\\n  <h2><strong>Lululemon被指控“有毒”？</strong></h2>\\\\n  <p>近日，加拿大运动品牌Lululemon因涉嫌含有“永久性化学物质”PFAS遭遇美国得克萨斯州总检察长的调查。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_afee7e5822a347a58b03a264ec522df2@000000_oswg424766oswg752oswg375_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>“永久性化学物质”主要是指全氟和多氟烷基物质（PFAS）。“全氟和多氟烷基物质”是一类广泛应用于防水服装、食品包装、化妆品等产品的人工合成化学物质，这种物质难以自然降解，因此被称为“永久性化学物质”。</p>\\\\n  <p><strong>《节点财经》了解到，这类物质会在环境和人体中持续累积，长期暴露可能与内分泌紊乱、不孕不育乃至癌症相关。正因如此，多国监管机构已将其列为重点管控对象。</strong></p>\\\\n  <p>按照调查安排，得克萨斯州检察长办公室将审查Lululemon的限用物质清单、产品检测流程和供应链管理，核查其产品是否真的达到了它自己宣传的安全标准。帕克斯顿的话说得很直接：不会允许任何企业打着\\\"健康\\\"和\\\"可持续\\\"的幌子，高价向消费者兜售有害产品。</p>\\\\n  <p>对此，Lululemon方面回应称，该公司产品不使用PFAS。此前曾在少量防水产品中使用相关物质，已于2023财年逐步淘汰。该公司要求供应商通过第三方机构定期开展包括PFAS在内的限用物质检测，以确保持续合规。Lululemon还表示，正在配合提供调查所需材料。</p>\\\\n  <p>此外，4月14日晚，Lululemon中国就其运动服饰中可能含有“永久性化学物”的指控回应，“始终将客人的健康与安全置于首位。Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。”</p>\\\\n  <p>尽管品牌方展现出积极配合调查的态度，但这场关于“产品安全性”的博弈，已将其长期标榜的“健康”标签推向了舆论的风口浪尖。</p>\\\\n  <h2><strong>业绩失速：群雄围猎下的“防御期”</strong></h2>\\\\n  <p>对Lululemon来说，这次调查的时间节点，实在难受。</p>\\\\n  <p>财报显示，其核心的美洲市场净收入同比下滑4%，今年以来股价跌幅已超过20%。增长失速的品牌，最怕的就是信任危机——而这次调查，偏偏打在了\\\"健康\\\"这个品牌最核心的标签上。</p>\\\\n  <p>更麻烦的是，竞争对手早就环伺四周。</p>\\\\n  <p>如果谈及Lululemon的最大对手，那当属Alo Yoga。</p>\\\\n  <p>Alo Yoga被视为 Lululemon 在北美最强劲的对手。其定位更偏向“运动奢侈品”，深受好莱坞明星追捧。2026 年初，Alo 正式进军中国市场，在选址上极度贴近 Lululemon，似乎意在与Lululemon 直接争夺高端瑜伽客群。</p>\\\\n  <p>不仅如此，近几年，Nike 和 Adidas这样的巨头运动品牌，也在加强对瑜伽赛道的投入。</p>\\\\n  <p>在中国本土市场，同样跑出了实力强悍的玩家。安踏旗下的 MAIA ACTIVE在剪裁和价格上更具亲和力，精准切中中国中产女性的需求。</p>\\\\n  <p><strong>《节点财经》看来，内忧外患之下，Lululemon 正处于一个极为被动的防御周期</strong>。往上打的，是Alo Yoga这类品牌，把瑜伽服往奢侈品方向拉，靠明星背书和更强的视觉调性，争夺愿意付更高溢价的消费者；往下打的，是MAIA ACTIVE、源头工厂品牌这类，把“同等面料、同等剪裁、砍掉品牌叙事成本”作为卖点，直接切走价格敏感但不愿将就品质的那批人。</p>\\\\n  <p>横向挤压的，是Nike、Adidas这种巨头，体量大、渠道广，虽然在专业度和品牌调性上不如Lululemon，但在大众市场的覆盖能力是碾压级的。</p>\\\\n  <p>Lululemon被夹在中间，上不像奢侈品，下打不过平替，这个位置其实越来越难受。</p>\\\\n  <p>对于中国市场而言，压力同样不小。</p>\\\\n  <p>今年3月，Lululemon发布的2025财年第四季度及全年财报。中国市场方面，2025财年第四季度净营收同比增长24%，整个财年净营收同比增长达29%。截至2025财年底，Lululemon在中国的直营门店数量已超过170家。</p>\\\\n  <p>在门店拓展方面，Lululemon方面透露，2026财年，公司计划在全球范围内新开设40至45家直营门店。具体而言，计划北美市场新开设约15家门店，国际市场新开设25至30家门店，其中大部分将布局于中国市场。</p>\\\\n  <p>该事件曝光后，不少网友直言“立马退掉”。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_02cbb8f58d40409193334c15fbc99a1a@000000_oswg24535oswg792oswg196_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_1a6a0893bd9445038626599ef15eea2b@000000_oswg509948oswg1080oswg393_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>Lululemon 如果不能在 2026 年通过材料创新重新夺回“安全与健康”的话语权，其行业龙头的宝座将被进一步动摇。</p>\\\\n  <h2><strong>\\\"溢价\\\"的逻辑，正在被消费者重新算账</strong></h2>\\\\n  <p>巨大的竞争之下，品牌开始“祛魅”。</p>\\\\n  <p><strong>过去，Lululemon能卖出高价，靠的是三件事撑着：更好的品质、更安全的材料、更有辨识度的身份感。这三条里，\\\"品质与安全\\\"是地基。一旦地基松了，整个定价逻辑就站不住。</strong></p>\\\\n  <p>当Lululemon这样主打健康、环保的高溢价品牌，被曝出含有致癌风险的“永久性化学物质”时，溢价逻辑中最核心的“品质与安全”支柱塌方了。</p>\\\\n  <p>消费者开始反思，如果1000元的瑜伽裤和200元的瑜伽裤同样面临化学残留风险，甚至200元的平替在国标检测下更透明，那么“溢价”就变成了纯粹的“智商税”。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_45ff877b34d1486ebbcd73aa8c71ca8f@000000_oswg259607oswg597oswg570_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p><strong>说白了，溢价时代买的是品牌讲的故事；现在的消费者，越来越想知道裤子本身是什么做的、安不安全、值不值这个价。</strong></p>\\\\n  <p>瑜伽服其实是个很特殊的品类——它介于\\\"功能性运动服\\\"和\\\"日常穿搭\\\"之间。消费者买它，不只是为了练瑜伽，更多时候是穿着它去咖啡馆、去买菜、去接娃。这就决定了它的竞争逻辑跟跑鞋、篮球服不一样，它既要卖功能，也要卖\\\"我是什么样的人\\\"。</p>\\\\n  <p>Lululemon当年崛起，本质上是把一件运动裤变成了中产女性的“身份符号”。 这个打法极其聪明，但也极其脆弱——因为身份符号一旦破圈或者祛魅，溢价就很难维持。</p>\\\\n  <p>溢价时代，消费者买的是“品牌讲的故事”；质价比时代，买的是“产品的物理属性”。</p>\\\\n  <p>像MAIA ACTIVE或一些源头工厂品牌的流行，是因为它们去掉了品牌的“叙事成本”，直接提供与大牌体感相似的产品。当消费者发现“故事”并不能保护健康或提升运动表现时，回归功能真实成为必然。</p>\\\\n  <p>《节点财经》看来，“质价比时代”不代表消费降级，而是消费者的专业化和去盲目化。 对于Lululemon而言，这次化学物质风波是一次致命的提醒。当<strong>品牌失去“安全性”这一底层质价比时，它所引以为傲的品牌溢价就会迅速风化。</strong></p>\\\\n  <p>对Lululemon来说，这次风波是一个很重的警告。品牌可以靠营销把故事讲得很好，但供应链的底层如果撑不住，这个故事迟早会塌。比业绩下滑更难收拾的，是被消费者质疑：你卖给我的那条\\\"健康裤\\\"，到底健不健康？</p>\\\\n  <p>真正的出路只有一条：不是再发一篇声明，而是在材料和供应链上拿出真正经得起检验的东西。</p>\\\\n  <p><strong>《节点财经》看来，这个行业的天花板其实没有想象中高。</strong>瑜伽服的复购频次有限，功能迭代空间也不像科技产品那么大，最终拼的还是：面料技术的真实差异、供应链的合规透明度、以及品牌能不能持续和消费者保持情感连接。</p>\\\\n  <p><strong>谁能在这三件事上同时做扎实，谁才能真正站稳。光靠故事，越来越难了。</strong></p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI1ODgwMDk3OQ==&amp;mid=2247546355&amp;idx=2&amp;sn=9d097c6b19f4dc28978fc3ab95088a6c&amp;chksm=ebab7dfa9170f205878d1bcd52864b46a3ad1004afc8504c475aaca3aa94d92b70aa0eeb61a9&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“节点财经”（ID：jiedian2018）</a>，作者：零度，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>LuluLemon摊上事了。</p>\\\\n  <p>据“新华社”消息，美国得克萨斯州总检察长肯·帕克斯顿日前宣布，已向加拿大运动服饰品牌Lululemon（Lululemon）的美国公司发布调查令，将调查其产品是否含有“永久性化学物质”。</p>\\\\n  <p>这个被誉为中产女性最爱的健身服饰品牌，一直主打着“健康生活方式”的价值观，但这一次供应链合规性的抽检，揭开了Lululemon的真实底色。</p>\\\\n  <p>当所谓的中产阶级“神裤”与有毒化学物质产生关联，品牌高昂的溢价逻辑正面临前所未有的信任崩塌。</p>\\\\n  <p>消费者开始“算账”：1000元一条的瑜伽裤，到底值不值？</p>\\\\n  <h2><strong>Lululemon被指控“有毒”？</strong></h2>\\\\n  <p>近日，加拿大运动品牌Lululemon因涉嫌含有“永久性化学物质”PFAS遭遇美国得克萨斯州总检察长的调查。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_afee7e5822a347a58b03a264ec522df2@000000_oswg424766oswg752oswg375_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>“永久性化学物质”主要是指全氟和多氟烷基物质（PFAS）。“全氟和多氟烷基物质”是一类广泛应用于防水服装、食品包装、化妆品等产品的人工合成化学物质，这种物质难以自然降解，因此被称为“永久性化学物质”。</p>\\\\n  <p><strong>《节点财经》了解到，这类物质会在环境和人体中持续累积，长期暴露可能与内分泌紊乱、不孕不育乃至癌症相关。正因如此，多国监管机构已将其列为重点管控对象。</strong></p>\\\\n  <p>按照调查安排，得克萨斯州检察长办公室将审查Lululemon的限用物质清单、产品检测流程和供应链管理，核查其产品是否真的达到了它自己宣传的安全标准。帕克斯顿的话说得很直接：不会允许任何企业打着\\\"健康\\\"和\\\"可持续\\\"的幌子，高价向消费者兜售有害产品。</p>\\\\n  <p>对此，Lululemon方面回应称，该公司产品不使用PFAS。此前曾在少量防水产品中使用相关物质，已于2023财年逐步淘汰。该公司要求供应商通过第三方机构定期开展包括PFAS在内的限用物质检测，以确保持续合规。Lululemon还表示，正在配合提供调查所需材料。</p>\\\\n  <p>此外，4月14日晚，Lululemon中国就其运动服饰中可能含有“永久性化学物”的指控回应，“始终将客人的健康与安全置于首位。Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。”</p>\\\\n  <p>尽管品牌方展现出积极配合调查的态度，但这场关于“产品安全性”的博弈，已将其长期标榜的“健康”标签推向了舆论的风口浪尖。</p>\\\\n  <h2><strong>业绩失速：群雄围猎下的“防御期”</strong></h2>\\\\n  <p>对Lululemon来说，这次调查的时间节点，实在难受。</p>\\\\n  <p>财报显示，其核心的美洲市场净收入同比下滑4%，今年以来股价跌幅已超过20%。增长失速的品牌，最怕的就是信任危机——而这次调查，偏偏打在了\\\"健康\\\"这个品牌最核心的标签上。</p>\\\\n  <p>更麻烦的是，竞争对手早就环伺四周。</p>\\\\n  <p>如果谈及Lululemon的最大对手，那当属Alo Yoga。</p>\\\\n  <p>Alo Yoga被视为 Lululemon 在北美最强劲的对手。其定位更偏向“运动奢侈品”，深受好莱坞明星追捧。2026 年初，Alo 正式进军中国市场，在选址上极度贴近 Lululemon，似乎意在与Lululemon 直接争夺高端瑜伽客群。</p>\\\\n  <p>不仅如此，近几年，Nike 和 Adidas这样的巨头运动品牌，也在加强对瑜伽赛道的投入。</p>\\\\n  <p>在中国本土市场，同样跑出了实力强悍的玩家。安踏旗下的 MAIA ACTIVE在剪裁和价格上更具亲和力，精准切中中国中产女性的需求。</p>\\\\n  <p><strong>《节点财经》看来，内忧外患之下，Lululemon 正处于一个极为被动的防御周期</strong>。往上打的，是Alo Yoga这类品牌，把瑜伽服往奢侈品方向拉，靠明星背书和更强的视觉调性，争夺愿意付更高溢价的消费者；往下打的，是MAIA ACTIVE、源头工厂品牌这类，把“同等面料、同等剪裁、砍掉品牌叙事成本”作为卖点，直接切走价格敏感但不愿将就品质的那批人。</p>\\\\n  <p>横向挤压的，是Nike、Adidas这种巨头，体量大、渠道广，虽然在专业度和品牌调性上不如Lululemon，但在大众市场的覆盖能力是碾压级的。</p>\\\\n  <p>Lululemon被夹在中间，上不像奢侈品，下打不过平替，这个位置其实越来越难受。</p>\\\\n  <p>对于中国市场而言，压力同样不小。</p>\\\\n  <p>今年3月，Lululemon发布的2025财年第四季度及全年财报。中国市场方面，2025财年第四季度净营收同比增长24%，整个财年净营收同比增长达29%。截至2025财年底，Lululemon在中国的直营门店数量已超过170家。</p>\\\\n  <p>在门店拓展方面，Lululemon方面透露，2026财年，公司计划在全球范围内新开设40至45家直营门店。具体而言，计划北美市场新开设约15家门店，国际市场新开设25至30家门店，其中大部分将布局于中国市场。</p>\\\\n  <p>该事件曝光后，不少网友直言“立马退掉”。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_02cbb8f58d40409193334c15fbc99a1a@000000_oswg24535oswg792oswg196_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_1a6a0893bd9445038626599ef15eea2b@000000_oswg509948oswg1080oswg393_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>Lululemon 如果不能在 2026 年通过材料创新重新夺回“安全与健康”的话语权，其行业龙头的宝座将被进一步动摇。</p>\\\\n  <h2><strong>\\\"溢价\\\"的逻辑，正在被消费者重新算账</strong></h2>\\\\n  <p>巨大的竞争之下，品牌开始“祛魅”。</p>\\\\n  <p><strong>过去，Lululemon能卖出高价，靠的是三件事撑着：更好的品质、更安全的材料、更有辨识度的身份感。这三条里，\\\"品质与安全\\\"是地基。一旦地基松了，整个定价逻辑就站不住。</strong></p>\\\\n  <p>当Lululemon这样主打健康、环保的高溢价品牌，被曝出含有致癌风险的“永久性化学物质”时，溢价逻辑中最核心的“品质与安全”支柱塌方了。</p>\\\\n  <p>消费者开始反思，如果1000元的瑜伽裤和200元的瑜伽裤同样面临化学残留风险，甚至200元的平替在国标检测下更透明，那么“溢价”就变成了纯粹的“智商税”。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_45ff877b34d1486ebbcd73aa8c71ca8f@000000_oswg259607oswg597oswg570_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p><strong>说白了，溢价时代买的是品牌讲的故事；现在的消费者，越来越想知道裤子本身是什么做的、安不安全、值不值这个价。</strong></p>\\\\n  <p>瑜伽服其实是个很特殊的品类——它介于\\\"功能性运动服\\\"和\\\"日常穿搭\\\"之间。消费者买它，不只是为了练瑜伽，更多时候是穿着它去咖啡馆、去买菜、去接娃。这就决定了它的竞争逻辑跟跑鞋、篮球服不一样，它既要卖功能，也要卖\\\"我是什么样的人\\\"。</p>\\\\n  <p>Lululemon当年崛起，本质上是把一件运动裤变成了中产女性的“身份符号”。 这个打法极其聪明，但也极其脆弱——因为身份符号一旦破圈或者祛魅，溢价就很难维持。</p>\\\\n  <p>溢价时代，消费者买的是“品牌讲的故事”；质价比时代，买的是“产品的物理属性”。</p>\\\\n  <p>像MAIA ACTIVE或一些源头工厂品牌的流行，是因为它们去掉了品牌的“叙事成本”，直接提供与大牌体感相似的产品。当消费者发现“故事”并不能保护健康或提升运动表现时，回归功能真实成为必然。</p>\\\\n  <p>《节点财经》看来，“质价比时代”不代表消费降级，而是消费者的专业化和去盲目化。 对于Lululemon而言，这次化学物质风波是一次致命的提醒。当<strong>品牌失去“安全性”这一底层质价比时，它所引以为傲的品牌溢价就会迅速风化。</strong></p>\\\\n  <p>对Lululemon来说，这次风波是一个很重的警告。品牌可以靠营销把故事讲得很好，但供应链的底层如果撑不住，这个故事迟早会塌。比业绩下滑更难收拾的，是被消费者质疑：你卖给我的那条\\\"健康裤\\\"，到底健不健康？</p>\\\\n  <p>真正的出路只有一条：不是再发一篇声明，而是在材料和供应链上拿出真正经得起检验的东西。</p>\\\\n  <p><strong>《节点财经》看来，这个行业的天花板其实没有想象中高。</strong>瑜伽服的复购频次有限，功能迭代空间也不像科技产品那么大，最终拼的还是：面料技术的真实差异、供应链的合规透明度、以及品牌能不能持续和消费者保持情感连接。</p>\\\\n  <p><strong>谁能在这三件事上同时做扎实，谁才能真正站稳。光靠故事，越来越难了。</strong></p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI1ODgwMDk3OQ==&amp;mid=2247546355&amp;idx=2&amp;sn=9d097c6b19f4dc28978fc3ab95088a6c&amp;chksm=ebab7dfa9170f205878d1bcd52864b46a3ad1004afc8504c475aaca3aa94d92b70aa0eeb61a9&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“节点财经”（ID：jiedian2018）</a>，作者：零度，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'节点财经\'}], \'author\': \'节点财经\', \'author_detail\': {\'name\': \'节点财经\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'中产神话的泡沫，破了。\'}]}\", \"published_at\": \"2026-04-16 08:17:18\", \"ai_json_output\": \"\"}', 'LuluLemon摊上事了。\n据“新华社”消息，美国得克萨斯州总检察长肯·帕克斯顿日前宣布，已向加拿大运动服饰品牌Lululemon（Lululemon）的美国公司发布调查令，将调查其产品是否含有“永久性化学物质”。\n这个被誉为中产女性最爱的健身服饰品牌，一直主打着“健康生活方式”的价值观，但这一次供应链合规性的抽检，揭开了Lululemon的真实底色。\n当所谓的中产阶级“神裤”与有毒化学物质产生关联，品牌高昂的溢价逻辑正面临前所未有的信任崩塌。\n消费者开始“算账”：1000元一条的瑜伽裤，到底值不值？\nLululemon被指控“有毒”？\n近日，加拿大运动品牌Lululemon因涉嫌含有“永久性化学物质”PFAS遭遇美国得克萨斯州总检察长的调查。\n“永久性化学物质”主要是指全氟和多氟烷基物质（PFAS）。“全氟和多氟烷基物质”是一类广泛应用于防水服装、食品包装、化妆品等产品的人工合成化学物质，这种物质难以自然降解，因此被称为“永久性化学物质”。\n《节点财经》了解到，这类物质会在环境和人体中持续累积，长期暴露可能与内分泌紊乱、不孕不育乃至癌症相关。正因如此，多国监管机构已将其列为重点管控对象。\n按照调查安排，得克萨斯州检察长办公室将审查Lululemon的限用物质清单、产品检测流程和供应链管理，核查其产品是否真的达到了它自己宣传的安全标准。帕克斯顿的话说得很直接：不会允许任何企业打着\"健康\"和\"可持续\"的幌子，高价向消费者兜售有害产品。\n对此，Lululemon方面回应称，该公司产品不使用PFAS。此前曾在少量防水产品中使用相关物质，已于2023财年逐步淘汰。该公司要求供应商通过第三方机构定期开展包括PFAS在内的限用物质检测，以确保持续合规。Lululemon还表示，正在配合提供调查所需材料。\n此外，4月14日晚，Lululemon中国就其运动服饰中可能含有“永久性化学物”的指控回应，“始终将客人的健康与安全置于首位。Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。”\n尽管品牌方展现出积极配合调查的态度，但这场关于“产品安全性”的博弈，已将其长期标榜的“健康”标签推向了舆论的风口浪尖。\n业绩失速：群雄围猎下的“防御期”\n对Lululemon来说，这次调查的时间节点，实在难受。\n财报显示，其核心的美洲市场净收入同比下滑4%，今年以来股价跌幅已超过20%。增长失速的品牌，最怕的就是信任危机——而这次调查，偏偏打在了\"健康\"这个品牌最核心的标签上。\n更麻烦的是，竞争对手早就环伺四周。\n如果谈及Lululemon的最大对手，那当属Alo Yoga。\nAlo Yoga被视为 Lululemon 在北美最强劲的对手。其定位更偏向“运动奢侈品”，深受好莱坞明星追捧。2026 年初，Alo 正式进军中国市场，在选址上极度贴近 Lululemon，似乎意在与Lululemon 直接争夺高端瑜伽客群。\n不仅如此，近几年，Nike 和 Adidas这样的巨头运动品牌，也在加强对瑜伽赛道的投入。\n在中国本土市场，同样跑出了实力强悍的玩家。安踏旗下的 MAIA ACTIVE在剪裁和价格上更具亲和力，精准切中中国中产女性的需求。\n《节点财经》看来，内忧外患之下，Lululemon 正处于一个极为被动的防御周期\n。往上打的，是Alo Yoga这类品牌，把瑜伽服往奢侈品方向拉，靠明星背书和更强的视觉调性，争夺愿意付更高溢价的消费者；往下打的，是MAIA ACTIVE、源头工厂品牌这类，把“同等面料、同等剪裁、砍掉品牌叙事成本”作为卖点，直接切走价格敏感但不愿将就品质的那批人。\n横向挤压的，是Nike、Adidas这种巨头，体量大、渠道广，虽然在专业度和品牌调性上不如Lululemon，但在大众市场的覆盖能力是碾压级的。\nLululemon被夹在中间，上不像奢侈品，下打不过平替，这个位置其实越来越难受。\n对于中国市场而言，压力同样不小。\n今年3月，Lululemon发布的2025财年第四季度及全年财报。中国市场方面，2025财年第四季度净营收同比增长24%，整个财年净营收同比增长达29%。截至2025财年底，Lululemon在中国的直营门店数量已超过170家。\n在门店拓展方面，Lululemon方面透露，2026财年，公司计划在全球范围内新开设40至45家直营门店。具体而言，计划北美市场新开设约15家门店，国际市场新开设25至30家门店，其中大部分将布局于中国市场。\n该事件曝光后，不少网友直言“立马退掉”。\nLululemon 如果不能在 2026 年通过材料创新重新夺回“安全与健康”的话语权，其行业龙头的宝座将被进一步动摇。\n\"溢价\"的逻辑，正在被消费者重新算账\n巨大的竞争之下，品牌开始“祛魅”。\n过去，Lululemon能卖出高价，靠的是三件事撑着：更好的品质、更安全的材料、更有辨识度的身份感。这三条里，\"品质与安全\"是地基。一旦地基松了，整个定价逻辑就站不住。\n当Lululemon这样主打健康、环保的高溢价品牌，被曝出含有致癌风险的“永久性化学物质”时，溢价逻辑中最核心的“品质与安全”支柱塌方了。\n消费者开始反思，如果1000元的瑜伽裤和200元的瑜伽裤同样面临化学残留风险，甚至200元的平替在国标检测下更透明，那么“溢价”就变成了纯粹的“智商税”。\n说白了，溢价时代买的是品牌讲的故事；现在的消费者，越来越想知道裤子本身是什么做的、安不安全、值不值这个价。\n瑜伽服其实是个很特殊的品类——它介于\"功能性运动服\"和\"日常穿搭\"之间。消费者买它，不只是为了练瑜伽，更多时候是穿着它去咖啡馆、去买菜、去接娃。这就决定了它的竞争逻辑跟跑鞋、篮球服不一样，它既要卖功能，也要卖\"我是什么样的人\"。\nLululemon当年崛起，本质上是把一件运动裤变成了中产女性的“身份符号”。 这个打法极其聪明，但也极其脆弱——因为身份符号一旦破圈或者祛魅，溢价就很难维持。\n溢价时代，消费者买的是“品牌讲的故事”；质价比时代，买的是“产品的物理属性”。\n像MAIA ACTIVE或一些源头工厂品牌的流行，是因为它们去掉了品牌的“叙事成本”，直接提供与大牌体感相似的产品。当消费者发现“故事”并不能保护健康或提升运动表现时，回归功能真实成为必然。\n《节点财经》看来，“质价比时代”不代表消费降级，而是消费者的专业化和去盲目化。 对于Lululemon而言，这次化学物质风波是一次致命的提醒。当\n品牌失去“安全性”这一底层质价比时，它所引以为傲的品牌溢价就会迅速风化。\n对Lululemon来说，这次风波是一个很重的警告。品牌可以靠营销把故事讲得很好，但供应链的底层如果撑不住，这个故事迟早会塌。比业绩下滑更难收拾的，是被消费者质疑：你卖给我的那条\"健康裤\"，到底健不健康？\n真正的出路只有一条：不是再发一篇声明，而是在材料和供应链上拿出真正经得起检验的东西。\n《节点财经》看来，这个行业的天花板其实没有想象中高。\n瑜伽服的复购频次有限，功能迭代空间也不像科技产品那么大，最终拼的还是：面料技术的真实差异、供应链的合规透明度、以及品牌能不能持续和消费者保持情感连接。\n谁能在这三件事上同时做扎实，谁才能真正站稳。光靠故事，越来越难了。\n本文来自微信公众号\n“节点财经”（ID：jiedian2018）\n，作者：零度，36氪经授权发布。', '2026-04-16 08:17:18', '2026-04-16 11:51:53');
INSERT INTO `news_detail` VALUES (25, 1008, 8, '新能源与汽车', '手握重金，德赛西威为什么仍要赴港上市？', '', '<p>一边是传统汽车智能化业务的增速放缓与毛利承压，另一边是机器人、无人车等 “ AI+ 新业务”从 0 到 1 的破冰——这家中国汽车电子龙头正试图在 汽车之 外寻找第二增长曲线。</p>\n<p>4月13日，德赛西威发布公告称，公司已于4月12日向香港联交所递交了发行境外上市股份（H股）并在香港联交所主板挂牌上市的申请，并于同日在香港联交所网站刊登了本次发行的申请材料。</p>\n<p>但与很多冲刺IPO的企业不同，<strong>德赛西威争取在港股上市的目的不是为了融资，至少不完全是。</strong></p>\n<p>从账面上来看，德赛西威并不差钱，<strong>其刚完成44亿元A股定增、账面理财也近40亿元，</strong>其目标更多是为海外扩张与新业务孵化搭建全球化融资平台。</p>\n<p><strong>2025年财报显示，德赛西威全年营收达325.57亿元，同比增长17.88%，归母净利润24.54亿元，同比增长22.38%，</strong>业绩再创新高。然而，光鲜数字背后，核心业务毛利率连续三年下滑、国内市场竞争加剧、大客户依赖症未解等隐忧正逐一浮现。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_3807723f31b44dfaa3a20ecc19aadf4a@000000_oswg89705oswg554oswg328_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：2025财报</p>\n<p>面对瓶颈，德赛西威选择了两条突围路径：<strong>一是技术跨界，将车规级能力延伸至无人配送与机器人赛道；二是资本出海，启动H股上市以支撑国际化战略。</strong></p>\n<h2><strong>01</strong></h2>\n<h2><strong>现状：增速放缓、毛利承压、产能利用率回落</strong></h2>\n<p>从表面看，德赛西威2025年交出了一份稳健的成绩单。全年营收325.57亿元，同比增长17.88%。2021至2025年，营收与净利润的复合增长率分别达35.81%和31.01%，新项目订单年化销售额突破350亿元。</p>\n<p>分产品看，智能座舱仍为营收主力但占比持续下滑，从2023年的72.1%降至2025年的63.2%；智能驾驶产品收入则实现爆发式增长，2023-2025年累计增长116.3%，收入占比从20.5%提升至29.8%，成为驱动营收增长的核心动力。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_6db92573a44a425385efd06f06750feb@000000_oswg40621oswg553oswg162_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<p>但高速增长背后，结构性瓶颈日益突出。</p>\n<p><strong>一是，增速放缓的迹象已十分明显。</strong>2023年至2025年，公司营收同比增速从46.71%一路下滑至26.06%、17.88%；净利润增速也从30.57%降至22.38%。</p>\n<p><strong>二是，盈利能力的持续下滑。</strong>公司整体毛利率从2023年的20.0%降至2025年的19.1%。两大核心业务中，智能座舱业务毛利率从20.0%下滑至18.8%；智能驾驶业务毛利率在2024年短暂回升至19.9%后，2025年骤降至16.4%，同比下跌3.55个百分点。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_48045465cc64457d9c927ef8b1ba253f@000000_oswg41924oswg554oswg222_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_6c7a767aae37417e97f164cc79acbd60@000000_oswg45409oswg554oswg175_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<p><strong>招股书披露的细节揭示了原因：下游整车厂的降价压力正直接侵蚀供应商利润</strong>。智能驾驶产品平均售价从2024年的856元暴跌23.9%至2025年的651元。公司坦言，“在产品生命周期内，整车厂通常要求供应商降价，绝大部分项目均受价格调整机制规限”。简言之，下游车企年降机制直接挤压利润空间。</p>\n<p><strong>三是，智能座舱产品产能利用率已连续两年回落</strong>——从2023年的91.4%降至2024年的89.7%，再到2025年的85%。然而公司仍在激进扩产：2025年资本开支达18.03亿元，本次H股募资也将继续用于产能扩充。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1dccee4ad9f64e5db3048c49161453bb@000000_oswg39853oswg553oswg154_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<p><strong>此外，客户集中度高的隐形风险同样不容忽视</strong>。2025年前五大客户贡献了55.5%的销售额，最大客户占比达14.5%。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_5a65b16411e04bffa4dc6cde1cd23e69@000000_oswg77264oswg553oswg382_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<h2><strong>02</strong></h2>\n<h2><strong>破局：车规技术外溢，跨界无人配送与机器人</strong></h2>\n<p>面对传统赛道天花板，德赛西威将汽车智能化核心能力向无人配送、智能机器人等高成长场景迁移，形成智能汽车+智能终端双轮驱动格局，两大新业务已实现从0到1突破。</p>\n<p><strong>2025年9月，公司发布低速无人车品牌“川行致远”及S6系列平台化产品</strong>，覆盖园区物流、城市配送、冷链运输等场景，直击末端物流“最后一公里”痛点。同年12月，公司宣布管理层及核心员工共同出资3000万元参与设立川行致远子公司，彰显内部信心。</p>\n<p>无人车业务的算法为纯自研，与公司自动驾驶算法体系协同，核心技术能力体现在技术复用与场景落地两方面。</p>\n<p>同年11月，德赛西威基于智能驾驶领域积累的高算力域控制器、AI算法、多传感器融合及车规级制造工艺，<strong>推出了“机器人智能基座AI Cube”</strong>——一款采用标准化、模块化设计的AI计算终端，旨在为机器人提供核心算力与算法支撑，解决软硬件适配痛点。</p>\n<p><strong>这并非简单的技术“移植”，而是车规级能力的跨场景复用。</strong>公司将原本用于L2+至L4级自动驾驶的域控制器设计、车规级SIP封装工艺、功能安全ASIL D认证体系，延伸至机器人领域。AI Cube可视为机器人的“通用大脑”，助力客户提升研发效率、降低开发成本。</p>\n<p>据公司披露，<strong>AI Cube已与多家知名机器人企业达成战略合作，并成功获取机器人域控项目定点订单，相关产品规划于2026年实现量产交付</strong>。应用场景覆盖生产制造、智慧家居、车载延伸等多元领域。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_a3aeb7556ed14677b2cbcf25d4093e7e@000000_oswg49931oswg553oswg260_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<p>需要正视的是，新业务尚未贡献实质性营收。<strong>截至2025年末，机器人及无人车业务仍处于试点与小规模落地阶段，未纳入核心营收统计</strong>。公司亦未披露相关订单金额。但从技术突破、产品认证到量产定点，德赛西威已完成新业务从0到1的跨越，可以预见，2026年将是验证商业化能力的关键窗口。</p>\n<p>跨界并非凭空起高楼，而是有着基础。德赛西威在汽车电子领域三十余年的积累，为其新业务提供了技术底座。</p>\n<p>研发投入持续高位运行。2025年，公司研发投入达26.37亿元，占营收8.10%，研发人员占比高达42.40%。全球设立11个研发分部，累计申请专利超4,100项，主导或参与发布国内外技术标准超120项。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_a1e2a650e3374e7386be69e2f11dc378@000000_oswg35479oswg554oswg305_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：2025财报</p>\n<p>在智能座舱领域，公司构建了涵盖“智能显示、智能交互、智能域控”的完整系统。在智能驾驶领域，产品覆盖从传感器到域控制器、从AI算法到V2X的全链条，适配L2+至L4级量产，<strong>是国内少数具备软硬一体全栈安全能力的企业。</strong></p>\n<p>这些能力正在向新业务高效迁移。AI Cube的核心竞争力，正是源于智能驾驶域控制器的车规级冗余设计。车规级SIP产品的批量交付能力，为机器人核心模块的规模化、高可靠性生产奠定基础。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_91df3ea8af7242508edbd7c9a796d989@000000_oswg180372oswg782oswg582_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<p>此外，德赛西威已与超50家生态伙伴协同，构建开放共创生态，推动跨行业技术落地。2025年研发投入中的相当比例，正投向舱驾融合平台、智算中心等与新业务协同的前沿方向。</p>\n<h2><strong>03</strong></h2>\n<h2><strong>H股上市：目标“出海”</strong></h2>\n<p>2025年10月，德赛西威刚完成A股定增，募资净额43.93亿元。截至年末，仅使用11.24亿元，账面仍有超32亿元未动用。同时，公司持有现金及现金等价物14.16亿元，购入理财产品规模达38.42亿元。账面资金充裕，并非缺钱。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_dd5b62dde8a44a38b59f6a0be505fa39@000000_oswg199110oswg1080oswg616_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_76ed7dd25cc040af99bbb0c2045fdaa7@000000_oswg53661oswg1080oswg346_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<p>在此背景下启动H股上市，核心逻辑清晰指向两点：一是为海外业务扩张搭建资本通道，二是提升国际资本市场能见度。</p>\n<p>招股书明确表示，本次H股发行旨在“推进国际化战略布局、提升国际影响力、加快海外业务拓展”，募资将用于智能驾驶、智能座舱、舱驾一体解决方案、机器人AI Cube的持续研发，以及产能扩充。</p>\n<p>海外市场正成为公司重要的盈利增长点。<strong>2025年，境外业务毛利率达27.3%，高出国内约9个百分点。公司已开拓大众、奔驰、宝马、雷诺、马自达等国际客户，墨西哥、马来西亚工厂已投产，西班牙工厂预计2026年量产。海外收入三年复合增长率达31.2%。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_e4dd825180534ea6a73a7f7852c7fa7e@000000_oswg42021oswg553oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>资料来源：招股书</p>\n<p>在传统业务增长放缓的背景下，德赛西威将业务拓展至无人配送与智能机器人两大万亿级市场。值得注意的是，这两项业务也是很多车企的拓展方向，技术底座高度相似、客户关联性较强，业务拓展成本较低，收益却很高。若新业务能够如期放量，叠加海外收入占比提升带来的毛利率修复，德赛西威有望在下一轮周期中打开新的增长空间。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s?__biz=MzkwNTIzNTMyOQ==&amp;mid=2247500022&amp;idx=1&amp;sn=9e0dfee01c5cef8d0c0dd9b04ecf13f7&amp;chksm=c19703fec97185caed6ead74700ff49e35b82608ce864baa94accf81b53b5e65bf8a74aa8cc9&amp;scene=0&amp;xtrack=1#rd\">“赛博汽车”（ID：Cyber-car）</a>，作者：王凌方，编辑：章涟漪，36氪经授权发布。</p>', 'https://36kr.com/p/3768715862508296?f=rss', 0, '', '{\"summary\": \"本文解析国内汽车电子龙头德赛西威赴港上市的出海战略逻辑，为计划出海扩张的制造企业提供参考\", \"abstract\": \"中国汽车电子龙头德赛西威传统业务面临增速放缓、毛利率下滑、客户集中度高等发展瓶颈，正积极寻找第二增长曲线。公司已将车规级技术延伸至无人配送、智能机器人新赛道，完成从0到1的业务突破，目前新业务尚未贡献实质性营收。德赛西威账面资金充裕，此次赴港递交H股上市申请，核心目的并非融资，而是为海外业务扩张搭建全球化融资平台，提升国际资本市场能见度。德赛西威当前海外业务毛利率高于国内，海外收入增长较快，H股募资将用于研发及产能扩充，有望助力其打开新的增长空间。\", \"keywords\": [\"德赛西威\", \"H股上市\", \"资本出海\", \"国际化战略\", \"海外扩张\", \"汽车电子\", \"智能机器人\", \"无人车\"], \"policy_risk\": {\"market_risk\": \"传统汽车智能化业务增速放缓、毛利率连续下滑，国内市场竞争加剧，存在大客户集中风险；新业务仍处于试点落地阶段，尚未贡献实质性营收，商业化能力有待验证\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3768715862508296?f=rss\", \"title\": \"手握重金，德赛西威为什么仍要赴港上市？\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>一边是传统汽车智能化业务的增速放缓与毛利承压，另一边是机器人、无人车等 “ AI+ 新业务”从 0 到 1 的破冰——这家中国汽车电子龙头正试图在 汽车之 外寻找第二增长曲线。</p>\\n<p>4月13日，德赛西威发布公告称，公司已于4月12日向香港联交所递交了发行境外上市股份（H股）并在香港联交所主板挂牌上市的申请，并于同日在香港联交所网站刊登了本次发行的申请材料。</p>\\n<p>但与很多冲刺IPO的企业不同，<strong>德赛西威争取在港股上市的目的不是为了融资，至少不完全是。</strong></p>\\n<p>从账面上来看，德赛西威并不差钱，<strong>其刚完成44亿元A股定增、账面理财也近40亿元，</strong>其目标更多是为海外扩张与新业务孵化搭建全球化融资平台。</p>\\n<p><strong>2025年财报显示，德赛西威全年营收达325.57亿元，同比增长17.88%，归母净利润24.54亿元，同比增长22.38%，</strong>业绩再创新高。然而，光鲜数字背后，核心业务毛利率连续三年下滑、国内市场竞争加剧、大客户依赖症未解等隐忧正逐一浮现。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3807723f31b44dfaa3a20ecc19aadf4a@000000_oswg89705oswg554oswg328_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：2025财报</p>\\n<p>面对瓶颈，德赛西威选择了两条突围路径：<strong>一是技术跨界，将车规级能力延伸至无人配送与机器人赛道；二是资本出海，启动H股上市以支撑国际化战略。</strong></p>\\n<h2><strong>01</strong></h2>\\n<h2><strong>现状：增速放缓、毛利承压、产能利用率回落</strong></h2>\\n<p>从表面看，德赛西威2025年交出了一份稳健的成绩单。全年营收325.57亿元，同比增长17.88%。2021至2025年，营收与净利润的复合增长率分别达35.81%和31.01%，新项目订单年化销售额突破350亿元。</p>\\n<p>分产品看，智能座舱仍为营收主力但占比持续下滑，从2023年的72.1%降至2025年的63.2%；智能驾驶产品收入则实现爆发式增长，2023-2025年累计增长116.3%，收入占比从20.5%提升至29.8%，成为驱动营收增长的核心动力。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6db92573a44a425385efd06f06750feb@000000_oswg40621oswg553oswg162_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<p>但高速增长背后，结构性瓶颈日益突出。</p>\\n<p><strong>一是，增速放缓的迹象已十分明显。</strong>2023年至2025年，公司营收同比增速从46.71%一路下滑至26.06%、17.88%；净利润增速也从30.57%降至22.38%。</p>\\n<p><strong>二是，盈利能力的持续下滑。</strong>公司整体毛利率从2023年的20.0%降至2025年的19.1%。两大核心业务中，智能座舱业务毛利率从20.0%下滑至18.8%；智能驾驶业务毛利率在2024年短暂回升至19.9%后，2025年骤降至16.4%，同比下跌3.55个百分点。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_48045465cc64457d9c927ef8b1ba253f@000000_oswg41924oswg554oswg222_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6c7a767aae37417e97f164cc79acbd60@000000_oswg45409oswg554oswg175_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<p><strong>招股书披露的细节揭示了原因：下游整车厂的降价压力正直接侵蚀供应商利润</strong>。智能驾驶产品平均售价从2024年的856元暴跌23.9%至2025年的651元。公司坦言，“在产品生命周期内，整车厂通常要求供应商降价，绝大部分项目均受价格调整机制规限”。简言之，下游车企年降机制直接挤压利润空间。</p>\\n<p><strong>三是，智能座舱产品产能利用率已连续两年回落</strong>——从2023年的91.4%降至2024年的89.7%，再到2025年的85%。然而公司仍在激进扩产：2025年资本开支达18.03亿元，本次H股募资也将继续用于产能扩充。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1dccee4ad9f64e5db3048c49161453bb@000000_oswg39853oswg553oswg154_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<p><strong>此外，客户集中度高的隐形风险同样不容忽视</strong>。2025年前五大客户贡献了55.5%的销售额，最大客户占比达14.5%。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_5a65b16411e04bffa4dc6cde1cd23e69@000000_oswg77264oswg553oswg382_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<h2><strong>02</strong></h2>\\n<h2><strong>破局：车规技术外溢，跨界无人配送与机器人</strong></h2>\\n<p>面对传统赛道天花板，德赛西威将汽车智能化核心能力向无人配送、智能机器人等高成长场景迁移，形成智能汽车+智能终端双轮驱动格局，两大新业务已实现从0到1突破。</p>\\n<p><strong>2025年9月，公司发布低速无人车品牌“川行致远”及S6系列平台化产品</strong>，覆盖园区物流、城市配送、冷链运输等场景，直击末端物流“最后一公里”痛点。同年12月，公司宣布管理层及核心员工共同出资3000万元参与设立川行致远子公司，彰显内部信心。</p>\\n<p>无人车业务的算法为纯自研，与公司自动驾驶算法体系协同，核心技术能力体现在技术复用与场景落地两方面。</p>\\n<p>同年11月，德赛西威基于智能驾驶领域积累的高算力域控制器、AI算法、多传感器融合及车规级制造工艺，<strong>推出了“机器人智能基座AI Cube”</strong>——一款采用标准化、模块化设计的AI计算终端，旨在为机器人提供核心算力与算法支撑，解决软硬件适配痛点。</p>\\n<p><strong>这并非简单的技术“移植”，而是车规级能力的跨场景复用。</strong>公司将原本用于L2+至L4级自动驾驶的域控制器设计、车规级SIP封装工艺、功能安全ASIL D认证体系，延伸至机器人领域。AI Cube可视为机器人的“通用大脑”，助力客户提升研发效率、降低开发成本。</p>\\n<p>据公司披露，<strong>AI Cube已与多家知名机器人企业达成战略合作，并成功获取机器人域控项目定点订单，相关产品规划于2026年实现量产交付</strong>。应用场景覆盖生产制造、智慧家居、车载延伸等多元领域。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a3aeb7556ed14677b2cbcf25d4093e7e@000000_oswg49931oswg553oswg260_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<p>需要正视的是，新业务尚未贡献实质性营收。<strong>截至2025年末，机器人及无人车业务仍处于试点与小规模落地阶段，未纳入核心营收统计</strong>。公司亦未披露相关订单金额。但从技术突破、产品认证到量产定点，德赛西威已完成新业务从0到1的跨越，可以预见，2026年将是验证商业化能力的关键窗口。</p>\\n<p>跨界并非凭空起高楼，而是有着基础。德赛西威在汽车电子领域三十余年的积累，为其新业务提供了技术底座。</p>\\n<p>研发投入持续高位运行。2025年，公司研发投入达26.37亿元，占营收8.10%，研发人员占比高达42.40%。全球设立11个研发分部，累计申请专利超4,100项，主导或参与发布国内外技术标准超120项。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a1e2a650e3374e7386be69e2f11dc378@000000_oswg35479oswg554oswg305_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：2025财报</p>\\n<p>在智能座舱领域，公司构建了涵盖“智能显示、智能交互、智能域控”的完整系统。在智能驾驶领域，产品覆盖从传感器到域控制器、从AI算法到V2X的全链条，适配L2+至L4级量产，<strong>是国内少数具备软硬一体全栈安全能力的企业。</strong></p>\\n<p>这些能力正在向新业务高效迁移。AI Cube的核心竞争力，正是源于智能驾驶域控制器的车规级冗余设计。车规级SIP产品的批量交付能力，为机器人核心模块的规模化、高可靠性生产奠定基础。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_91df3ea8af7242508edbd7c9a796d989@000000_oswg180372oswg782oswg582_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<p>此外，德赛西威已与超50家生态伙伴协同，构建开放共创生态，推动跨行业技术落地。2025年研发投入中的相当比例，正投向舱驾融合平台、智算中心等与新业务协同的前沿方向。</p>\\n<h2><strong>03</strong></h2>\\n<h2><strong>H股上市：目标“出海”</strong></h2>\\n<p>2025年10月，德赛西威刚完成A股定增，募资净额43.93亿元。截至年末，仅使用11.24亿元，账面仍有超32亿元未动用。同时，公司持有现金及现金等价物14.16亿元，购入理财产品规模达38.42亿元。账面资金充裕，并非缺钱。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dd5b62dde8a44a38b59f6a0be505fa39@000000_oswg199110oswg1080oswg616_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_76ed7dd25cc040af99bbb0c2045fdaa7@000000_oswg53661oswg1080oswg346_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<p>在此背景下启动H股上市，核心逻辑清晰指向两点：一是为海外业务扩张搭建资本通道，二是提升国际资本市场能见度。</p>\\n<p>招股书明确表示，本次H股发行旨在“推进国际化战略布局、提升国际影响力、加快海外业务拓展”，募资将用于智能驾驶、智能座舱、舱驾一体解决方案、机器人AI Cube的持续研发，以及产能扩充。</p>\\n<p>海外市场正成为公司重要的盈利增长点。<strong>2025年，境外业务毛利率达27.3%，高出国内约9个百分点。公司已开拓大众、奔驰、宝马、雷诺、马自达等国际客户，墨西哥、马来西亚工厂已投产，西班牙工厂预计2026年量产。海外收入三年复合增长率达31.2%。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e4dd825180534ea6a73a7f7852c7fa7e@000000_oswg42021oswg553oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>资料来源：招股书</p>\\n<p>在传统业务增长放缓的背景下，德赛西威将业务拓展至无人配送与智能机器人两大万亿级市场。值得注意的是，这两项业务也是很多车企的拓展方向，技术底座高度相似、客户关联性较强，业务拓展成本较低，收益却很高。若新业务能够如期放量，叠加海外收入占比提升带来的毛利率修复，德赛西威有望在下一轮周期中打开新的增长空间。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzkwNTIzNTMyOQ==&amp;mid=2247500022&amp;idx=1&amp;sn=9e0dfee01c5cef8d0c0dd9b04ecf13f7&amp;chksm=c19703fec97185caed6ead74700ff49e35b82608ce864baa94accf81b53b5e65bf8a74aa8cc9&amp;scene=0&amp;xtrack=1#rd\\\">“赛博汽车”（ID：Cyber-car）</a>，作者：王凌方，编辑：章涟漪，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'手握重金，德赛西威为什么仍要赴港上市？\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'手握重金，德赛西威为什么仍要赴港上市？\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768715862508296?f=rss\'}], \'link\': \'https://36kr.com/p/3768715862508296?f=rss\', \'published\': \'2026-04-16 08:05:27  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=0, tm_min=5, tm_sec=27, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>一边是传统汽车智能化业务的增速放缓与毛利承压，另一边是机器人、无人车等 “ AI+ 新业务”从 0 到 1 的破冰——这家中国汽车电子龙头正试图在 汽车之 外寻找第二增长曲线。</p>\\\\n  <p>4月13日，德赛西威发布公告称，公司已于4月12日向香港联交所递交了发行境外上市股份（H股）并在香港联交所主板挂牌上市的申请，并于同日在香港联交所网站刊登了本次发行的申请材料。</p>\\\\n  <p>但与很多冲刺IPO的企业不同，<strong>德赛西威争取在港股上市的目的不是为了融资，至少不完全是。</strong></p>\\\\n  <p>从账面上来看，德赛西威并不差钱，<strong>其刚完成44亿元A股定增、账面理财也近40亿元，</strong>其目标更多是为海外扩张与新业务孵化搭建全球化融资平台。</p>\\\\n  <p><strong>2025年财报显示，德赛西威全年营收达325.57亿元，同比增长17.88%，归母净利润24.54亿元，同比增长22.38%，</strong>业绩再创新高。然而，光鲜数字背后，核心业务毛利率连续三年下滑、国内市场竞争加剧、大客户依赖症未解等隐忧正逐一浮现。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3807723f31b44dfaa3a20ecc19aadf4a@000000_oswg89705oswg554oswg328_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：2025财报</p>\\\\n  <p>面对瓶颈，德赛西威选择了两条突围路径：<strong>一是技术跨界，将车规级能力延伸至无人配送与机器人赛道；二是资本出海，启动H股上市以支撑国际化战略。</strong></p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>现状：增速放缓、毛利承压、产能利用率回落</strong></h2>\\\\n  <p>从表面看，德赛西威2025年交出了一份稳健的成绩单。全年营收325.57亿元，同比增长17.88%。2021至2025年，营收与净利润的复合增长率分别达35.81%和31.01%，新项目订单年化销售额突破350亿元。</p>\\\\n  <p>分产品看，智能座舱仍为营收主力但占比持续下滑，从2023年的72.1%降至2025年的63.2%；智能驾驶产品收入则实现爆发式增长，2023-2025年累计增长116.3%，收入占比从20.5%提升至29.8%，成为驱动营收增长的核心动力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6db92573a44a425385efd06f06750feb@000000_oswg40621oswg553oswg162_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>但高速增长背后，结构性瓶颈日益突出。</p>\\\\n  <p><strong>一是，增速放缓的迹象已十分明显。</strong>2023年至2025年，公司营收同比增速从46.71%一路下滑至26.06%、17.88%；净利润增速也从30.57%降至22.38%。</p>\\\\n  <p><strong>二是，盈利能力的持续下滑。</strong>公司整体毛利率从2023年的20.0%降至2025年的19.1%。两大核心业务中，智能座舱业务毛利率从20.0%下滑至18.8%；智能驾驶业务毛利率在2024年短暂回升至19.9%后，2025年骤降至16.4%，同比下跌3.55个百分点。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_48045465cc64457d9c927ef8b1ba253f@000000_oswg41924oswg554oswg222_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6c7a767aae37417e97f164cc79acbd60@000000_oswg45409oswg554oswg175_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p><strong>招股书披露的细节揭示了原因：下游整车厂的降价压力正直接侵蚀供应商利润</strong>。智能驾驶产品平均售价从2024年的856元暴跌23.9%至2025年的651元。公司坦言，“在产品生命周期内，整车厂通常要求供应商降价，绝大部分项目均受价格调整机制规限”。简言之，下游车企年降机制直接挤压利润空间。</p>\\\\n  <p><strong>三是，智能座舱产品产能利用率已连续两年回落</strong>——从2023年的91.4%降至2024年的89.7%，再到2025年的85%。然而公司仍在激进扩产：2025年资本开支达18.03亿元，本次H股募资也将继续用于产能扩充。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1dccee4ad9f64e5db3048c49161453bb@000000_oswg39853oswg553oswg154_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p><strong>此外，客户集中度高的隐形风险同样不容忽视</strong>。2025年前五大客户贡献了55.5%的销售额，最大客户占比达14.5%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_5a65b16411e04bffa4dc6cde1cd23e69@000000_oswg77264oswg553oswg382_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>破局：车规技术外溢，跨界无人配送与机器人</strong></h2>\\\\n  <p>面对传统赛道天花板，德赛西威将汽车智能化核心能力向无人配送、智能机器人等高成长场景迁移，形成智能汽车+智能终端双轮驱动格局，两大新业务已实现从0到1突破。</p>\\\\n  <p><strong>2025年9月，公司发布低速无人车品牌“川行致远”及S6系列平台化产品</strong>，覆盖园区物流、城市配送、冷链运输等场景，直击末端物流“最后一公里”痛点。同年12月，公司宣布管理层及核心员工共同出资3000万元参与设立川行致远子公司，彰显内部信心。</p>\\\\n  <p>无人车业务的算法为纯自研，与公司自动驾驶算法体系协同，核心技术能力体现在技术复用与场景落地两方面。</p>\\\\n  <p>同年11月，德赛西威基于智能驾驶领域积累的高算力域控制器、AI算法、多传感器融合及车规级制造工艺，<strong>推出了“机器人智能基座AI Cube”</strong>——一款采用标准化、模块化设计的AI计算终端，旨在为机器人提供核心算力与算法支撑，解决软硬件适配痛点。</p>\\\\n  <p><strong>这并非简单的技术“移植”，而是车规级能力的跨场景复用。</strong>公司将原本用于L2+至L4级自动驾驶的域控制器设计、车规级SIP封装工艺、功能安全ASIL D认证体系，延伸至机器人领域。AI Cube可视为机器人的“通用大脑”，助力客户提升研发效率、降低开发成本。</p>\\\\n  <p>据公司披露，<strong>AI Cube已与多家知名机器人企业达成战略合作，并成功获取机器人域控项目定点订单，相关产品规划于2026年实现量产交付</strong>。应用场景覆盖生产制造、智慧家居、车载延伸等多元领域。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a3aeb7556ed14677b2cbcf25d4093e7e@000000_oswg49931oswg553oswg260_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>需要正视的是，新业务尚未贡献实质性营收。<strong>截至2025年末，机器人及无人车业务仍处于试点与小规模落地阶段，未纳入核心营收统计</strong>。公司亦未披露相关订单金额。但从技术突破、产品认证到量产定点，德赛西威已完成新业务从0到1的跨越，可以预见，2026年将是验证商业化能力的关键窗口。</p>\\\\n  <p>跨界并非凭空起高楼，而是有着基础。德赛西威在汽车电子领域三十余年的积累，为其新业务提供了技术底座。</p>\\\\n  <p>研发投入持续高位运行。2025年，公司研发投入达26.37亿元，占营收8.10%，研发人员占比高达42.40%。全球设立11个研发分部，累计申请专利超4,100项，主导或参与发布国内外技术标准超120项。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a1e2a650e3374e7386be69e2f11dc378@000000_oswg35479oswg554oswg305_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：2025财报</p>\\\\n  <p>在智能座舱领域，公司构建了涵盖“智能显示、智能交互、智能域控”的完整系统。在智能驾驶领域，产品覆盖从传感器到域控制器、从AI算法到V2X的全链条，适配L2+至L4级量产，<strong>是国内少数具备软硬一体全栈安全能力的企业。</strong></p>\\\\n  <p>这些能力正在向新业务高效迁移。AI Cube的核心竞争力，正是源于智能驾驶域控制器的车规级冗余设计。车规级SIP产品的批量交付能力，为机器人核心模块的规模化、高可靠性生产奠定基础。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_91df3ea8af7242508edbd7c9a796d989@000000_oswg180372oswg782oswg582_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>此外，德赛西威已与超50家生态伙伴协同，构建开放共创生态，推动跨行业技术落地。2025年研发投入中的相当比例，正投向舱驾融合平台、智算中心等与新业务协同的前沿方向。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>H股上市：目标“出海”</strong></h2>\\\\n  <p>2025年10月，德赛西威刚完成A股定增，募资净额43.93亿元。截至年末，仅使用11.24亿元，账面仍有超32亿元未动用。同时，公司持有现金及现金等价物14.16亿元，购入理财产品规模达38.42亿元。账面资金充裕，并非缺钱。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dd5b62dde8a44a38b59f6a0be505fa39@000000_oswg199110oswg1080oswg616_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_76ed7dd25cc040af99bbb0c2045fdaa7@000000_oswg53661oswg1080oswg346_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>在此背景下启动H股上市，核心逻辑清晰指向两点：一是为海外业务扩张搭建资本通道，二是提升国际资本市场能见度。</p>\\\\n  <p>招股书明确表示，本次H股发行旨在“推进国际化战略布局、提升国际影响力、加快海外业务拓展”，募资将用于智能驾驶、智能座舱、舱驾一体解决方案、机器人AI Cube的持续研发，以及产能扩充。</p>\\\\n  <p>海外市场正成为公司重要的盈利增长点。<strong>2025年，境外业务毛利率达27.3%，高出国内约9个百分点。公司已开拓大众、奔驰、宝马、雷诺、马自达等国际客户，墨西哥、马来西亚工厂已投产，西班牙工厂预计2026年量产。海外收入三年复合增长率达31.2%。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e4dd825180534ea6a73a7f7852c7fa7e@000000_oswg42021oswg553oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>在传统业务增长放缓的背景下，德赛西威将业务拓展至无人配送与智能机器人两大万亿级市场。值得注意的是，这两项业务也是很多车企的拓展方向，技术底座高度相似、客户关联性较强，业务拓展成本较低，收益却很高。若新业务能够如期放量，叠加海外收入占比提升带来的毛利率修复，德赛西威有望在下一轮周期中打开新的增长空间。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzkwNTIzNTMyOQ==&amp;mid=2247500022&amp;idx=1&amp;sn=9e0dfee01c5cef8d0c0dd9b04ecf13f7&amp;chksm=c19703fec97185caed6ead74700ff49e35b82608ce864baa94accf81b53b5e65bf8a74aa8cc9&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“赛博汽车”（ID：Cyber-car）</a>，作者：王凌方，编辑：章涟漪，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>一边是传统汽车智能化业务的增速放缓与毛利承压，另一边是机器人、无人车等 “ AI+ 新业务”从 0 到 1 的破冰——这家中国汽车电子龙头正试图在 汽车之 外寻找第二增长曲线。</p>\\\\n  <p>4月13日，德赛西威发布公告称，公司已于4月12日向香港联交所递交了发行境外上市股份（H股）并在香港联交所主板挂牌上市的申请，并于同日在香港联交所网站刊登了本次发行的申请材料。</p>\\\\n  <p>但与很多冲刺IPO的企业不同，<strong>德赛西威争取在港股上市的目的不是为了融资，至少不完全是。</strong></p>\\\\n  <p>从账面上来看，德赛西威并不差钱，<strong>其刚完成44亿元A股定增、账面理财也近40亿元，</strong>其目标更多是为海外扩张与新业务孵化搭建全球化融资平台。</p>\\\\n  <p><strong>2025年财报显示，德赛西威全年营收达325.57亿元，同比增长17.88%，归母净利润24.54亿元，同比增长22.38%，</strong>业绩再创新高。然而，光鲜数字背后，核心业务毛利率连续三年下滑、国内市场竞争加剧、大客户依赖症未解等隐忧正逐一浮现。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3807723f31b44dfaa3a20ecc19aadf4a@000000_oswg89705oswg554oswg328_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：2025财报</p>\\\\n  <p>面对瓶颈，德赛西威选择了两条突围路径：<strong>一是技术跨界，将车规级能力延伸至无人配送与机器人赛道；二是资本出海，启动H股上市以支撑国际化战略。</strong></p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>现状：增速放缓、毛利承压、产能利用率回落</strong></h2>\\\\n  <p>从表面看，德赛西威2025年交出了一份稳健的成绩单。全年营收325.57亿元，同比增长17.88%。2021至2025年，营收与净利润的复合增长率分别达35.81%和31.01%，新项目订单年化销售额突破350亿元。</p>\\\\n  <p>分产品看，智能座舱仍为营收主力但占比持续下滑，从2023年的72.1%降至2025年的63.2%；智能驾驶产品收入则实现爆发式增长，2023-2025年累计增长116.3%，收入占比从20.5%提升至29.8%，成为驱动营收增长的核心动力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6db92573a44a425385efd06f06750feb@000000_oswg40621oswg553oswg162_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>但高速增长背后，结构性瓶颈日益突出。</p>\\\\n  <p><strong>一是，增速放缓的迹象已十分明显。</strong>2023年至2025年，公司营收同比增速从46.71%一路下滑至26.06%、17.88%；净利润增速也从30.57%降至22.38%。</p>\\\\n  <p><strong>二是，盈利能力的持续下滑。</strong>公司整体毛利率从2023年的20.0%降至2025年的19.1%。两大核心业务中，智能座舱业务毛利率从20.0%下滑至18.8%；智能驾驶业务毛利率在2024年短暂回升至19.9%后，2025年骤降至16.4%，同比下跌3.55个百分点。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_48045465cc64457d9c927ef8b1ba253f@000000_oswg41924oswg554oswg222_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6c7a767aae37417e97f164cc79acbd60@000000_oswg45409oswg554oswg175_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p><strong>招股书披露的细节揭示了原因：下游整车厂的降价压力正直接侵蚀供应商利润</strong>。智能驾驶产品平均售价从2024年的856元暴跌23.9%至2025年的651元。公司坦言，“在产品生命周期内，整车厂通常要求供应商降价，绝大部分项目均受价格调整机制规限”。简言之，下游车企年降机制直接挤压利润空间。</p>\\\\n  <p><strong>三是，智能座舱产品产能利用率已连续两年回落</strong>——从2023年的91.4%降至2024年的89.7%，再到2025年的85%。然而公司仍在激进扩产：2025年资本开支达18.03亿元，本次H股募资也将继续用于产能扩充。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1dccee4ad9f64e5db3048c49161453bb@000000_oswg39853oswg553oswg154_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p><strong>此外，客户集中度高的隐形风险同样不容忽视</strong>。2025年前五大客户贡献了55.5%的销售额，最大客户占比达14.5%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_5a65b16411e04bffa4dc6cde1cd23e69@000000_oswg77264oswg553oswg382_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>破局：车规技术外溢，跨界无人配送与机器人</strong></h2>\\\\n  <p>面对传统赛道天花板，德赛西威将汽车智能化核心能力向无人配送、智能机器人等高成长场景迁移，形成智能汽车+智能终端双轮驱动格局，两大新业务已实现从0到1突破。</p>\\\\n  <p><strong>2025年9月，公司发布低速无人车品牌“川行致远”及S6系列平台化产品</strong>，覆盖园区物流、城市配送、冷链运输等场景，直击末端物流“最后一公里”痛点。同年12月，公司宣布管理层及核心员工共同出资3000万元参与设立川行致远子公司，彰显内部信心。</p>\\\\n  <p>无人车业务的算法为纯自研，与公司自动驾驶算法体系协同，核心技术能力体现在技术复用与场景落地两方面。</p>\\\\n  <p>同年11月，德赛西威基于智能驾驶领域积累的高算力域控制器、AI算法、多传感器融合及车规级制造工艺，<strong>推出了“机器人智能基座AI Cube”</strong>——一款采用标准化、模块化设计的AI计算终端，旨在为机器人提供核心算力与算法支撑，解决软硬件适配痛点。</p>\\\\n  <p><strong>这并非简单的技术“移植”，而是车规级能力的跨场景复用。</strong>公司将原本用于L2+至L4级自动驾驶的域控制器设计、车规级SIP封装工艺、功能安全ASIL D认证体系，延伸至机器人领域。AI Cube可视为机器人的“通用大脑”，助力客户提升研发效率、降低开发成本。</p>\\\\n  <p>据公司披露，<strong>AI Cube已与多家知名机器人企业达成战略合作，并成功获取机器人域控项目定点订单，相关产品规划于2026年实现量产交付</strong>。应用场景覆盖生产制造、智慧家居、车载延伸等多元领域。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a3aeb7556ed14677b2cbcf25d4093e7e@000000_oswg49931oswg553oswg260_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>需要正视的是，新业务尚未贡献实质性营收。<strong>截至2025年末，机器人及无人车业务仍处于试点与小规模落地阶段，未纳入核心营收统计</strong>。公司亦未披露相关订单金额。但从技术突破、产品认证到量产定点，德赛西威已完成新业务从0到1的跨越，可以预见，2026年将是验证商业化能力的关键窗口。</p>\\\\n  <p>跨界并非凭空起高楼，而是有着基础。德赛西威在汽车电子领域三十余年的积累，为其新业务提供了技术底座。</p>\\\\n  <p>研发投入持续高位运行。2025年，公司研发投入达26.37亿元，占营收8.10%，研发人员占比高达42.40%。全球设立11个研发分部，累计申请专利超4,100项，主导或参与发布国内外技术标准超120项。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a1e2a650e3374e7386be69e2f11dc378@000000_oswg35479oswg554oswg305_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：2025财报</p>\\\\n  <p>在智能座舱领域，公司构建了涵盖“智能显示、智能交互、智能域控”的完整系统。在智能驾驶领域，产品覆盖从传感器到域控制器、从AI算法到V2X的全链条，适配L2+至L4级量产，<strong>是国内少数具备软硬一体全栈安全能力的企业。</strong></p>\\\\n  <p>这些能力正在向新业务高效迁移。AI Cube的核心竞争力，正是源于智能驾驶域控制器的车规级冗余设计。车规级SIP产品的批量交付能力，为机器人核心模块的规模化、高可靠性生产奠定基础。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_91df3ea8af7242508edbd7c9a796d989@000000_oswg180372oswg782oswg582_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>此外，德赛西威已与超50家生态伙伴协同，构建开放共创生态，推动跨行业技术落地。2025年研发投入中的相当比例，正投向舱驾融合平台、智算中心等与新业务协同的前沿方向。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>H股上市：目标“出海”</strong></h2>\\\\n  <p>2025年10月，德赛西威刚完成A股定增，募资净额43.93亿元。截至年末，仅使用11.24亿元，账面仍有超32亿元未动用。同时，公司持有现金及现金等价物14.16亿元，购入理财产品规模达38.42亿元。账面资金充裕，并非缺钱。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dd5b62dde8a44a38b59f6a0be505fa39@000000_oswg199110oswg1080oswg616_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_76ed7dd25cc040af99bbb0c2045fdaa7@000000_oswg53661oswg1080oswg346_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>在此背景下启动H股上市，核心逻辑清晰指向两点：一是为海外业务扩张搭建资本通道，二是提升国际资本市场能见度。</p>\\\\n  <p>招股书明确表示，本次H股发行旨在“推进国际化战略布局、提升国际影响力、加快海外业务拓展”，募资将用于智能驾驶、智能座舱、舱驾一体解决方案、机器人AI Cube的持续研发，以及产能扩充。</p>\\\\n  <p>海外市场正成为公司重要的盈利增长点。<strong>2025年，境外业务毛利率达27.3%，高出国内约9个百分点。公司已开拓大众、奔驰、宝马、雷诺、马自达等国际客户，墨西哥、马来西亚工厂已投产，西班牙工厂预计2026年量产。海外收入三年复合增长率达31.2%。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e4dd825180534ea6a73a7f7852c7fa7e@000000_oswg42021oswg553oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">资料来源：招股书</p>\\\\n  <p>在传统业务增长放缓的背景下，德赛西威将业务拓展至无人配送与智能机器人两大万亿级市场。值得注意的是，这两项业务也是很多车企的拓展方向，技术底座高度相似、客户关联性较强，业务拓展成本较低，收益却很高。若新业务能够如期放量，叠加海外收入占比提升带来的毛利率修复，德赛西威有望在下一轮周期中打开新的增长空间。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzkwNTIzNTMyOQ==&amp;mid=2247500022&amp;idx=1&amp;sn=9e0dfee01c5cef8d0c0dd9b04ecf13f7&amp;chksm=c19703fec97185caed6ead74700ff49e35b82608ce864baa94accf81b53b5e65bf8a74aa8cc9&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“赛博汽车”（ID：Cyber-car）</a>，作者：王凌方，编辑：章涟漪，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'赛博汽车\'}], \'author\': \'赛博汽车\', \'author_detail\': {\'name\': \'赛博汽车\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'下一步：机器人、无人车和海外市场。\'}]}\", \"published_at\": \"2026-04-16 08:05:27\", \"ai_json_output\": \"\"}', '一边是传统汽车智能化业务的增速放缓与毛利承压，另一边是机器人、无人车等 “ AI+ 新业务”从 0 到 1 的破冰——这家中国汽车电子龙头正试图在 汽车之 外寻找第二增长曲线。\n4月13日，德赛西威发布公告称，公司已于4月12日向香港联交所递交了发行境外上市股份（H股）并在香港联交所主板挂牌上市的申请，并于同日在香港联交所网站刊登了本次发行的申请材料。\n但与很多冲刺IPO的企业不同，\n德赛西威争取在港股上市的目的不是为了融资，至少不完全是。\n从账面上来看，德赛西威并不差钱，\n其刚完成44亿元A股定增、账面理财也近40亿元，\n其目标更多是为海外扩张与新业务孵化搭建全球化融资平台。\n2025年财报显示，德赛西威全年营收达325.57亿元，同比增长17.88%，归母净利润24.54亿元，同比增长22.38%，\n业绩再创新高。然而，光鲜数字背后，核心业务毛利率连续三年下滑、国内市场竞争加剧、大客户依赖症未解等隐忧正逐一浮现。\n资料来源：2025财报\n面对瓶颈，德赛西威选择了两条突围路径：\n一是技术跨界，将车规级能力延伸至无人配送与机器人赛道；二是资本出海，启动H股上市以支撑国际化战略。\n01\n现状：增速放缓、毛利承压、产能利用率回落\n从表面看，德赛西威2025年交出了一份稳健的成绩单。全年营收325.57亿元，同比增长17.88%。2021至2025年，营收与净利润的复合增长率分别达35.81%和31.01%，新项目订单年化销售额突破350亿元。\n分产品看，智能座舱仍为营收主力但占比持续下滑，从2023年的72.1%降至2025年的63.2%；智能驾驶产品收入则实现爆发式增长，2023-2025年累计增长116.3%，收入占比从20.5%提升至29.8%，成为驱动营收增长的核心动力。\n资料来源：招股书\n但高速增长背后，结构性瓶颈日益突出。\n一是，增速放缓的迹象已十分明显。\n2023年至2025年，公司营收同比增速从46.71%一路下滑至26.06%、17.88%；净利润增速也从30.57%降至22.38%。\n二是，盈利能力的持续下滑。\n公司整体毛利率从2023年的20.0%降至2025年的19.1%。两大核心业务中，智能座舱业务毛利率从20.0%下滑至18.8%；智能驾驶业务毛利率在2024年短暂回升至19.9%后，2025年骤降至16.4%，同比下跌3.55个百分点。\n资料来源：招股书\n招股书披露的细节揭示了原因：下游整车厂的降价压力正直接侵蚀供应商利润\n。智能驾驶产品平均售价从2024年的856元暴跌23.9%至2025年的651元。公司坦言，“在产品生命周期内，整车厂通常要求供应商降价，绝大部分项目均受价格调整机制规限”。简言之，下游车企年降机制直接挤压利润空间。\n三是，智能座舱产品产能利用率已连续两年回落\n——从2023年的91.4%降至2024年的89.7%，再到2025年的85%。然而公司仍在激进扩产：2025年资本开支达18.03亿元，本次H股募资也将继续用于产能扩充。\n资料来源：招股书\n此外，客户集中度高的隐形风险同样不容忽视\n。2025年前五大客户贡献了55.5%的销售额，最大客户占比达14.5%。\n资料来源：招股书\n02\n破局：车规技术外溢，跨界无人配送与机器人\n面对传统赛道天花板，德赛西威将汽车智能化核心能力向无人配送、智能机器人等高成长场景迁移，形成智能汽车+智能终端双轮驱动格局，两大新业务已实现从0到1突破。\n2025年9月，公司发布低速无人车品牌“川行致远”及S6系列平台化产品\n，覆盖园区物流、城市配送、冷链运输等场景，直击末端物流“最后一公里”痛点。同年12月，公司宣布管理层及核心员工共同出资3000万元参与设立川行致远子公司，彰显内部信心。\n无人车业务的算法为纯自研，与公司自动驾驶算法体系协同，核心技术能力体现在技术复用与场景落地两方面。\n同年11月，德赛西威基于智能驾驶领域积累的高算力域控制器、AI算法、多传感器融合及车规级制造工艺，\n推出了“机器人智能基座AI Cube”\n——一款采用标准化、模块化设计的AI计算终端，旨在为机器人提供核心算力与算法支撑，解决软硬件适配痛点。\n这并非简单的技术“移植”，而是车规级能力的跨场景复用。\n公司将原本用于L2+至L4级自动驾驶的域控制器设计、车规级SIP封装工艺、功能安全ASIL D认证体系，延伸至机器人领域。AI Cube可视为机器人的“通用大脑”，助力客户提升研发效率、降低开发成本。\n据公司披露，\nAI Cube已与多家知名机器人企业达成战略合作，并成功获取机器人域控项目定点订单，相关产品规划于2026年实现量产交付\n。应用场景覆盖生产制造、智慧家居、车载延伸等多元领域。\n资料来源：招股书\n需要正视的是，新业务尚未贡献实质性营收。\n截至2025年末，机器人及无人车业务仍处于试点与小规模落地阶段，未纳入核心营收统计\n。公司亦未披露相关订单金额。但从技术突破、产品认证到量产定点，德赛西威已完成新业务从0到1的跨越，可以预见，2026年将是验证商业化能力的关键窗口。\n跨界并非凭空起高楼，而是有着基础。德赛西威在汽车电子领域三十余年的积累，为其新业务提供了技术底座。\n研发投入持续高位运行。2025年，公司研发投入达26.37亿元，占营收8.10%，研发人员占比高达42.40%。全球设立11个研发分部，累计申请专利超4,100项，主导或参与发布国内外技术标准超120项。\n资料来源：2025财报\n在智能座舱领域，公司构建了涵盖“智能显示、智能交互、智能域控”的完整系统。在智能驾驶领域，产品覆盖从传感器到域控制器、从AI算法到V2X的全链条，适配L2+至L4级量产，\n是国内少数具备软硬一体全栈安全能力的企业。\n这些能力正在向新业务高效迁移。AI Cube的核心竞争力，正是源于智能驾驶域控制器的车规级冗余设计。车规级SIP产品的批量交付能力，为机器人核心模块的规模化、高可靠性生产奠定基础。\n资料来源：招股书\n此外，德赛西威已与超50家生态伙伴协同，构建开放共创生态，推动跨行业技术落地。2025年研发投入中的相当比例，正投向舱驾融合平台、智算中心等与新业务协同的前沿方向。\n03\nH股上市：目标“出海”\n2025年10月，德赛西威刚完成A股定增，募资净额43.93亿元。截至年末，仅使用11.24亿元，账面仍有超32亿元未动用。同时，公司持有现金及现金等价物14.16亿元，购入理财产品规模达38.42亿元。账面资金充裕，并非缺钱。\n资料来源：招股书\n在此背景下启动H股上市，核心逻辑清晰指向两点：一是为海外业务扩张搭建资本通道，二是提升国际资本市场能见度。\n招股书明确表示，本次H股发行旨在“推进国际化战略布局、提升国际影响力、加快海外业务拓展”，募资将用于智能驾驶、智能座舱、舱驾一体解决方案、机器人AI Cube的持续研发，以及产能扩充。\n海外市场正成为公司重要的盈利增长点。\n2025年，境外业务毛利率达27.3%，高出国内约9个百分点。公司已开拓大众、奔驰、宝马、雷诺、马自达等国际客户，墨西哥、马来西亚工厂已投产，西班牙工厂预计2026年量产。海外收入三年复合增长率达31.2%。\n资料来源：招股书\n在传统业务增长放缓的背景下，德赛西威将业务拓展至无人配送与智能机器人两大万亿级市场。值得注意的是，这两项业务也是很多车企的拓展方向，技术底座高度相似、客户关联性较强，业务拓展成本较低，收益却很高。若新业务能够如期放量，叠加海外收入占比提升带来的毛利率修复，德赛西威有望在下一轮周期中打开新的增长空间。\n本文来自微信公众号\n“赛博汽车”（ID：Cyber-car）\n，作者：王凌方，编辑：章涟漪，36氪经授权发布。', '2026-04-16 08:05:27', '2026-04-16 11:53:05');
INSERT INTO `news_detail` VALUES (26, 1009, 14, '合规与政策服务', '8点1氪丨美国将退还超1万亿元关税；多家银行密集停发信用卡；滴露回应使用宠物消毒液后5只幼猫死亡', '', '<h2>今日热点导览</h2>\n<p>京东宣布推出“机器人救护车”</p>\n<p>抖音集团将投入5亿专项资金扶持真人短剧</p>\n<p>永辉超市38亿追款获胜，王健林等承担连带保证责任</p>\n<p>张雪机车LOGO抄袭？设计公司发声明回应</p>\n<p>小米汽车公布降噪处理新专利</p>\n<h2>TOP 3大新闻</h2>\n<p><strong>美国将退还超1万亿元关税</strong></p>\n<p>据路透社报道，美国特朗普政府计划于当地时间4月20日正式启动一个关税退款系统，用于向进口商退还1660亿美元（约合人民币1.13万亿元）的关税，这些关税在今年2月被美国最高法院裁定为“非法”。据报道，美国海关与边境保护局14日在一份提交给国际贸易法院的法庭文件中表示，已基本完成向进口商大规模退款的报关系统第一阶段研发，将于20日启动相关关税退款工作。退款将以电子方式统一发放，并在适用情况下附带利息，取代此前逐笔处理的方式。数据显示，截至4月9日，已有约5.6万家进口商完成电子退款流程，涉及总金额达1270亿美元（约合人民币8660亿元）。（央视财经）</p>\n<p><strong>多家银行密集停发信用卡</strong></p>\n<p>近期，民生银行、农业银行、交通银行等多家银行接连发布公告，宣布停止发行部分信用卡产品，涉及国有大行、股份制银行及地方银行，停发产品以联名信用卡为主，同时涵盖部分主题信用卡。多家中小银行也加入到停发信用卡的行列之中。比如，2025年年末，武汉农商银行发布公告称，因联名信用卡合作业务调整，现与联名方合作终止，将于2026年1月1日起停止发行淘票票&amp;大麦联名信用卡；浙江农商联合银行也于2025年年底宣布，因业务合作调整，丰收京东联名卡将停止发行。</p>\n<p>此外，对于停发后的存量卡片，多家银行明确表示，持卡人手中的卡片在有效期内可正常使用，仅停止新增发行。若遇到损坏换卡、挂失补卡、到期换卡等情况，银行将根据不同规则处理，或换发同等级标准卡，或逐步更换为新版卡面，部分原产品的特殊功能与权益将不再提供。（界面新闻）</p>\n<p><strong>滴露回应使用宠物消毒液后5只幼猫死亡</strong></p>\n<p>4月15日，针对有消费者称“在使用滴露宠物消毒液拖地后，家中5只幼猫死亡”一事，<strong>滴露品牌母公司利洁时消费者热线工作人员回应新京报贝壳财经记者称，该产品经过安全性评估，“在依照标签正常使用的情况下，不会对宠物造成任何不良影响。”</strong>面对记者关于事件最新进展的追问，该工作人员表示，“暂时没有，无法获知更详细的情况。”</p>\n<p>据报道，有消费者称其于4月6日下午使用滴露消毒液（宠物家庭专用）在家里拖地，当晚11点左右，她发现家中5只幼猫全部死亡，“复盘下来，在那一天，我们唯一做的与之前不同的事情就是用这款消毒液拖了地”，该消费者表示，“之前家里都是大猫，那时候正常使用没有发现问题。”（新京报）</p>\n<h2>大公司/大事件</h2>\n<p><strong>京东宣布推出“机器人救护车”</strong></p>\n<p>4月15日，京东宣布正式推出“机器人救护车”，为人形机器人、四足机器人、AI陪伴机器人等提供维修保养服务，涵盖基础维修、故障诊断、换电补能、测试鉴定、美容保养、设备回收等。目前，京东“机器人救护车”已服务北京地区，未来三年，机器人上门维修服务还将拓展至全国超50个核心城市。（界面新闻）</p>\n<p><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></p>\n<p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。（第一财经）</p>\n<p><strong>哈啰回应超量投放共享单车被行政处罚</strong></p>\n<p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。（第一财经）</p>\n<p><strong>永辉超市38亿追款获胜，王健林等承担连带保证责任</strong></p>\n<p>时隔一年有余，永辉超市（601933.SH）针对大连御锦贸易有限公司（简称“大连御锦”）未按约支付万达商管股份转让款而进行的追款申请，获终局裁决支持。4月14日晚间，永辉超市发布公告称，近日收到上海国际经济贸易仲裁委员会(上海国际仲裁中心)(简称“上国仲”)送达的裁决书。根据裁决，第一被申请人大连御锦需向永辉超市支付剩余股份转让价款和加速到期违约金等共计38.57亿元。第二被申请人王健林、第三被申请人孙喜双、第四被申请人大连一方集团对上述债务承担连带保证责任。（界面新闻）</p>\n<p><strong>张雪机车LOGO抄袭？设计公司发声明回应</strong></p>\n<p>针对张雪机车品牌LOGO疑似抄袭一事，4月14日，杭州巴顿品牌设计有限公司发布声明称，本次LOGO设计由巴顿独立创作完成，相关商标已向国家知识产权局申请并核准注册。该公司表示，欢迎并支持任何认为侵犯其权利的主体通过司法途径解决问题。据了解，张雪机车创始人张雪曾表示，张雪机车的LOGO是找了杭州一家设计公司，包括视觉及店面形象等，花了40万元。（界面新闻）</p>\n<p><strong>拟赴港上市？接近度小满人士：不实</strong></p>\n<p>近日，有关度小满最快将于2026年上半年向港交所递交招股书，拟主板挂牌上市的信息在社交媒体传播。从接近度小满人士处独家获悉，相关信息不实，系对传闻的拼凑与虚构。公司已通过法律途径维护合法权益，并将追究相关方责任。（界面新闻）</p>\n<p><strong>飞天茅台全线上涨，26年飞天原箱批价报1665元/瓶</strong></p>\n<p>36氪获悉，“今日酒价”披露的最新批发参考价显示，4月15日，26年飞天茅台原箱报1665元/瓶，较上一日上涨5元；26年飞天茅台散瓶报1565元/瓶，与上日价格持平。25年飞天茅台原箱报1675元/瓶，较上一日上涨5元；25年飞天茅台散瓶报1610元/瓶，较上一日上涨10元。</p>\n<p><strong>现货黄金向下跌破4800美元</strong></p>\n<p>36氪获悉，现货黄金向下跌破4800美元，日内下跌0.89%。</p>\n<p><strong>传抖音电商将迎调整，成立红果电商，官方暂无回应</strong></p>\n<p>有市场消息称，抖音电商将迎调整，成立红果电商，架构在中国电商下，与行业产品、用户产品等部门平级。对此消息，抖音官方暂无回应。（新浪财经）</p>\n<p><strong>广电总局发布微短剧精品创作传播计划</strong></p>\n<p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。（新华社）</p>\n<p><strong>Lululemon回应被指使用致癌化学物：称国内在售产品不含PFAS</strong></p>\n<p>针对产品涉嫌含致癌化学物被调查一事，4月14日，Lululemon方面向中新网表示，Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。此前，据路透社报道，美国得克萨斯州总检察长肯·帕克斯顿已对知名运动品牌Lululemon展开调查，此次调查将查明Lululemon的运动服装是否含有“永久性化学物质”全氟和多氟烷基物质，该类化学物质在自然界中不易分解。帕克斯顿提到，最新研究结果与消费者担忧引发了人们的质疑：服装中的某些合成材料，是否可能与内分泌紊乱、不孕不育、癌症和其他健康风险有关。（中国新闻网）</p>\n<p><strong>小米汽车公布降噪处理新专利</strong></p>\n<p>36氪获悉，爱企查App显示，近日，小米汽车科技有限公司申请的“降噪处理方法、装置、车辆及存储介质”专利公布。摘要显示，该专利基于车辆的误差信号和加速度计信号识别车辆所处的噪声场景，并将加速度计信号分解为多个互不重叠的子带信号，再结合各子带信号对应的降噪处理参数进行自适应滤波，得到全频带降噪信号。该方案能够对复杂、多谱结构噪声进行高效分治与响应，提升降噪效果，进而提升用户的用车体验感。</p>\n<p><strong>30年期国债期货创新高，机构看多超长债行情</strong></p>\n<p>在资金面持续宽松与外部扰动阶段性缓和的背景下，债券市场近期整体走强，超长端利率债表现尤为突出。4月14日，30年期国债期货创近1个月新高，带动债市情绪明显回暖。多家机构认为，在配置力量回归、供需结构优化及宏观基本面逐步验证的支撑下，债市“配置牛”逻辑正在强化，超长债投资价值进一步凸显。（上证报）</p>\n<p><strong>美股三大指数收盘涨跌不一，纳指11连涨创收盘新高</strong></p>\n<p>36氪获悉，4月15日收盘，美股三大指数涨跌不一，纳指涨1.59%，为连续11个交易日上涨并创收盘新高，这11个交易日累计涨幅超15%，标普500指数涨0.8%创历史新高，道指跌0.15%。大型科技股普涨，特斯拉涨超7%，微软涨超4%，苹果涨近3%，英伟达、谷歌、Meta涨超1%。热门中概股涨跌不一，百度涨超2%，阿里巴巴、腾讯音乐涨超1%，理想汽车跌超3%，蔚来跌超2%，小鹏集团跌超1%。</p>\n<p><strong>奈飞公司CEO与美国影院行业负责人举行会谈，双方未来或将合作</strong></p>\n<p>美国一年一度的电影产业盛会——电影博览会于4月13日至16日在拉斯维加斯举行。该博览会的组织方“联合影院”，也就是曾经的美国全国影院主协会主席迈克尔•奥利里4月14日表示，奈飞公司首席执行官特德·萨兰多斯12日与该组织的代表们举行了一次“建设性的会谈”。对于奈飞公司此次与影院方面进行的会谈，奥利里认为，双方目前都认识到需要寻求互助合作，以建立一套更具互补性的商业模式。他同时表示，双方4月12日只是进行了初步会谈，并未达成任何协议。但他依然对奈飞公司所展现出的意愿表示赞赏。截至目前，奈飞公司尚未对上述事宜发表评论。（央视新闻）</p>\n<p><strong>KKR将通过购买可转换债券向三星SDS投资8.2亿美元</strong></p>\n<p>当地时间4月14日，美国私募股权巨头KKR宣布，将通过收购可转换债券向三星SDS投资1.22万亿韩元（约合8.2亿美元）。根据合作协议，KKR将通过其管理的基金，与三星SDS就一系列旨在为该公司创造价值的举措展开紧密合作，包括支持有机与非有机增长战略、加速该公司作为全栈式人工智能解决方案提供商的扩张，以及拓展新业务领域。KKR还将积极为三星SDS管理团队提供咨询服务，特别是在并购、资本配置以及支持公司寻求全球战略增长机遇等方面。（界面新闻）</p>\n<p><strong>苹果官微发文提醒iPhone用户立即更新设备</strong></p>\n<p>36氪获悉，4月15日，苹果官微发文表示，安全研究人员最近发现，存在一些基于网页的攻击，它们会借助恶意网页内容，对过时版本的iOS发起攻击。例如，如果用户使用的是较旧版本的iOS，一旦点按恶意链接或访问被入侵的网站，iPhone上的数据就可能面临被盗的风险。在发现这些问题后，苹果进行了全面调查，并在第一时间针对最新的操作系统版本发布了软件更新，旨在解决相关漏洞，阻断这类攻击。如果用户的iPhone运行的是较旧版本的iOS，请立即更新以保护数据安全。无法更新设备的用户，如果设备支持，可考虑启用锁定模式，以防范恶意网页内容及其他威胁。</p>\n<p><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></p>\n<p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。（财联社）</p>\n<p><strong>博通宣布与Meta扩大合作，总裁兼CEO陈福阳将转任Meta顾问</strong></p>\n<p>当地时间4月14日，博通公司与Meta宣布达成多年多代战略合作，以支持Meta快速扩展的人工智能计算基础设施。基于现有合作基础，博通将为Meta训练与推理加速器（MTIA）芯片提供技术支持，双方计划将合作延续至2029年。该技术将成为Meta部署尖端AI数据中心的基础架构核心。首期合作规模超过1吉瓦。鉴于此次扩展合作的规模，陈福阳（Hock Tan）将从Meta董事会卸任，转任Meta顾问角色，他将为Meta的定制芯片路线图提供指导。（新浪财经）</p>\n<p><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></p>\n<p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。（界面新闻）</p>\n<p><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></p>\n<p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武4月10日向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。（新浪财经）</p>\n<p><strong>苹果CEO库克斥资106万美元增持耐克</strong></p>\n<p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。（界面新闻）</p>\n<p><strong>风险投资机构争相向Anthropic抛出投资要约，估值最高达8000亿美元</strong></p>\n<p>据多位知情人士透露，近几周来，开发了Claude的初创公司Anthropic已收到多家风投机构的投资要约，对其估值最高达到8000亿美元，较最近估值翻了一倍有余。备受市场追捧的初创公司常会收到投资者主动提前抛出的要约，但往往会予以回绝。尽管如此，风投机构给出的估值水平仍反映出，随着Anthropic准备在今年晚些时候可能进行IPO，硅谷对入股该公司的需求已近乎狂热。（新浪财经）</p>\n<h2>AI最前沿</h2>\n<p><strong>OpenAI向部分用户发布Cyber模型，与Mythos展开竞争</strong></p>\n<p>OpenAI允许特定用户访问一款更擅长发现软件安全漏洞的新模型。就在一周前，竞争对手Anthropic PBC宣布小范围发布人工智能工具Mythos。这家ChatGPT开发商4月14日表示，已开始推出GPT-5.4-Cyber模型，目标是发现软件中的问题，以便组织加以修复。OpenAI称，该模型在用于此类任务时对用户探测方式的限制也更少。（新浪财经）</p>\n<p><strong>OpenAI推出旨在增强网络安全能力的迭代模型</strong></p>\n<p>美国开放人工智能研究中心（OpenAI）14日宣布推出GPT-5.4的迭代模型GPT-5.4-Cyber，旨在增强网络安全能力；并宣布扩大其“网络安全可信访问”项目，将向经审核验证的网络安全人员和团队开放。（新华社）</p>\n<p><strong>阿里ATH事业群发布首款AI开发工具秒悟</strong></p>\n<p>36氪获悉，4月15日，阿里ATH事业群发布旗下首款AI开发工具Meoo（秒悟），该工具集成千问、Kimi、GLM、MiniMax四大模型，并内置阿里云数据库、存储等核心产品服务，用户只需用自然语言描述想法，Meoo最快1分钟就能自动生成前端后端完整的网站、H5页面，在阿里云上一键部署上线。</p>\n<p><strong>腾讯轻量云独家上线Hermes Agent应用模板</strong></p>\n<p>36氪获悉，4月14日，腾讯云轻量应用服务器Lighthouse正式上线Hermes Agent专属应用模板，行业首家实现该开源AI智能体的云端一键快速部署，其企业级ClawPro产品也将于本周内完成适配支持。依托轻量化云服务器的便捷特性，开发者无需复杂配置，即可快速完成Hermes Agent的云端搭建与运行。</p>\n<p><strong>算力紧缺之下，Anthropic调整定价模式，按企业AI使用量计费</strong></p>\n<p>Anthropic发言人证实，根据此次定价调整，Claude企业版客户除每月为每位用户支付20美元固定费用外，还需按使用软件时消耗的算力容量额外付费。Claude企业版是面向大型企业推出的产品组合，已推出两年，目前包含代码工具ClaudeCode及办公助手ClaudeCowork。（新浪财经）</p>\n<h2>大公司财报</h2>\n<p><strong>爱马仕第一季度总收入为40.7亿欧元，销售额同比增长5.6%</strong></p>\n<p>4月15日，爱马仕公布第一季度业绩报告，第一季度总收入为40.7亿欧元。第一季度销售额同比增长5.6%，其中，按地区划分来看，欧洲地区销售额总计增长4.5%，亚洲地区总计增长3.5%，美洲增长17.2%，其他地区为增长5.9%；按行业划分来看，皮革制品与马具销售额增长9.4%，成衣与配饰增长0.4%，丝绸与纺织品增长7.8%等。（界面新闻）</p>\n<p><strong>宁德时代：一季度净利润207.38亿元，同比增长48.52%</strong></p>\n<p>36氪获悉，宁德时代发布一季度报告，一季度实现营收1291.31亿元，同比增长52.45%；归属于上市公司股东的净利润207.38亿元，同比增长48.52%。</p>\n<p><strong>蓝色光标：2025年净利润2.25亿元，同比扭亏</strong></p>\n<p>36氪获悉，蓝色光标披露年报，2025年实现营业收入686.93亿元，同比增长12.99%；归属于上市公司股东的净利润2.25亿元，上年同期亏损2.91亿元；基本每股收益0.063元。公司拟每10股派发现金红利0.1元（含税）。</p>\n<p><strong>阿斯麦第一季度营收87.67亿欧元，高于市场预期</strong></p>\n<p>4月15日，阿斯麦公布第一季度业绩报告，第一季度净销售额为87.67亿欧元，市场预估为86.9亿欧元；净利润为27.6亿欧元，市场预估为25.6亿欧元。阿斯麦预计2026年第二季度总净销售额将在84亿至90亿欧元之间，预计2026年总净销售额在360亿至400亿欧元之间。（界面新闻）</p>\n<p><strong>多氟多：2025年净利润2.13亿元，同比扭亏</strong></p>\n<p>36氪获悉，多氟多披露年报，2025年实现营业收入94.34亿元，同比增长14.37%；归属于上市公司股东的净利润2.13亿元，上年同期亏损3.08亿元；基本每股收益0.18元。公司拟每10股派发现金红利2元（含税）。</p>\n<h2>投融资</h2>\n<p><strong>自动驾驶初创公司Glydways洽谈2.5亿美元融资</strong></p>\n<p>4月15日消息，据报道，由山姆·奥特曼支持的自动驾驶汽车初创公司Glydways正在洽谈新一轮融资，计划筹集2.5亿美元，这将使公司估值达到10亿美元或更高。Glydways此前刚刚完成1.7亿美元的融资，估值接近7亿美元。（界面新闻）</p>\n<p><strong>“智象未来”完成超5亿元新一轮融资</strong></p>\n<p>36氪获悉，近日，国内多模态生成式人工智能公司“智象未来”宣布完成超5亿元新一轮融资。本轮融资由东方富海、安徽省投资集团旗下的省产业投资公司、峰华资本等新股东联合投资，同时合肥产投、兴泰集团、合肥高投、安徽省人工智能母基金等老股东持续加注。本轮融资将主要用于智象独创的下一代原生全模态世界模型研发、企业服务智能体的产品建设以及全球市场拓展。</p>\n<p><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></p>\n<p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\n<p><strong>“源升智能”完成上亿元Pre-A轮融资</strong></p>\n<p>36氪获悉，“源升智能”宣布完成上亿元Pre-A轮融资。本轮融资由达晨财智、老股东春华创投共同领投，渶策资本、南山战新投跟投，老股东弘晖基金超额跟投。本轮融资将用于Apex Hand的产能扩充与批量交付、灵巧操作平台生态建设以及全球化市场拓展，以此巩固在高性能灵巧手领域的技术优势，加速具身智能在真实工业场景中的落地。这也是公司一年内完成的第5轮融资，累计融资金额达数亿元。</p>\n<h2>酷产品</h2>\n<p><strong>菜鸟发布攀爬机器人ZeeBot，实测智能化存取效率提升一倍</strong></p>\n<p>36氪获悉，4月15日，菜鸟集团在美国亚特兰大举行的MODEX 2026国际物流展上发布了首款自研的“攀爬机器人”ZeeBot，并确认首个由攀爬机器人智能作业的仓储项目已在广东省交付使用。实测数据显示，该技术使仓库存取效率提升了100%。</p>\n<p><strong>小鹏GX上市，预售价39.98万元</strong></p>\n<p>36氪获悉，4月15日，小鹏大六座旗舰SUV小鹏GX上市，共推出增程和纯电两个版本，预售价39.98万元起。何小鹏在发布会上提到，小鹏GX是中国首款前装量产的Robotaxi原型车，完全按照L4自动驾驶标准打造，搭载四颗图灵芯片，有效算力达3000TOPS，搭载小鹏第二代VLA。</p>\n<p><strong>千问AI眼镜S1宣布正式开售</strong></p>\n<p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\n<p><strong>优步承诺投入100亿美元发展机器人出租车，实现战略转型</strong></p>\n<p>据英国金融时报4月15日报道，优步已承诺投入100多亿美元购买数千辆自动驾驶汽车，并参股其开发商，打破其轻资产的\"临时工经济\"业务模式，以避免机器人出租车的干扰。（新浪财经）</p>\n<p><strong>整理</strong>｜Kris</p>', 'https://36kr.com/p/3768734631527176?f=rss', 0, '', '{\"summary\": \"本文汇总全球多领域每日热点，美国退还超万亿非法关税的政策信息可供对美出海贸易企业参考\", \"abstract\": \"这是一篇综合热点资讯汇总，涵盖大公司动态、AI进展、投融资、财报等多个领域内容。核心出海相关信息为，美国将于4月20日正式启动关税退款系统，向进口商退还被最高法院裁定为非法的超1万亿元人民币关税。目前已有超5.6万家进口商完成退款流程，涉及金额超8600亿元人民币。该政策变化对开展对美贸易的出海企业具备参考价值。\", \"keywords\": [\"美国关税\", \"关税退款\", \"对美贸易\", \"跨境贸易\", \"出海合规\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"美国最高法院裁定特朗普政府此前征收的部分关税为非法，美国将于4月20日启动统一电子关税退款系统，向相关进口商退还合计约1.13万亿元人民币的关税，目前已有约5.6万家进口商完成电子退款流程，涉及金额约8660亿元人民币\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"https://36kr.com/p/3768734631527176?f=rss\", \"title\": \"8点1氪丨美国将退还超1万亿元关税；多家银行密集停发信用卡；滴露回应使用宠物消毒液后5只幼猫死亡\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<h2>今日热点导览</h2>\\n<p>京东宣布推出“机器人救护车”</p>\\n<p>抖音集团将投入5亿专项资金扶持真人短剧</p>\\n<p>永辉超市38亿追款获胜，王健林等承担连带保证责任</p>\\n<p>张雪机车LOGO抄袭？设计公司发声明回应</p>\\n<p>小米汽车公布降噪处理新专利</p>\\n<h2>TOP 3大新闻</h2>\\n<p><strong>美国将退还超1万亿元关税</strong></p>\\n<p>据路透社报道，美国特朗普政府计划于当地时间4月20日正式启动一个关税退款系统，用于向进口商退还1660亿美元（约合人民币1.13万亿元）的关税，这些关税在今年2月被美国最高法院裁定为“非法”。据报道，美国海关与边境保护局14日在一份提交给国际贸易法院的法庭文件中表示，已基本完成向进口商大规模退款的报关系统第一阶段研发，将于20日启动相关关税退款工作。退款将以电子方式统一发放，并在适用情况下附带利息，取代此前逐笔处理的方式。数据显示，截至4月9日，已有约5.6万家进口商完成电子退款流程，涉及总金额达1270亿美元（约合人民币8660亿元）。（央视财经）</p>\\n<p><strong>多家银行密集停发信用卡</strong></p>\\n<p>近期，民生银行、农业银行、交通银行等多家银行接连发布公告，宣布停止发行部分信用卡产品，涉及国有大行、股份制银行及地方银行，停发产品以联名信用卡为主，同时涵盖部分主题信用卡。多家中小银行也加入到停发信用卡的行列之中。比如，2025年年末，武汉农商银行发布公告称，因联名信用卡合作业务调整，现与联名方合作终止，将于2026年1月1日起停止发行淘票票&amp;大麦联名信用卡；浙江农商联合银行也于2025年年底宣布，因业务合作调整，丰收京东联名卡将停止发行。</p>\\n<p>此外，对于停发后的存量卡片，多家银行明确表示，持卡人手中的卡片在有效期内可正常使用，仅停止新增发行。若遇到损坏换卡、挂失补卡、到期换卡等情况，银行将根据不同规则处理，或换发同等级标准卡，或逐步更换为新版卡面，部分原产品的特殊功能与权益将不再提供。（界面新闻）</p>\\n<p><strong>滴露回应使用宠物消毒液后5只幼猫死亡</strong></p>\\n<p>4月15日，针对有消费者称“在使用滴露宠物消毒液拖地后，家中5只幼猫死亡”一事，<strong>滴露品牌母公司利洁时消费者热线工作人员回应新京报贝壳财经记者称，该产品经过安全性评估，“在依照标签正常使用的情况下，不会对宠物造成任何不良影响。”</strong>面对记者关于事件最新进展的追问，该工作人员表示，“暂时没有，无法获知更详细的情况。”</p>\\n<p>据报道，有消费者称其于4月6日下午使用滴露消毒液（宠物家庭专用）在家里拖地，当晚11点左右，她发现家中5只幼猫全部死亡，“复盘下来，在那一天，我们唯一做的与之前不同的事情就是用这款消毒液拖了地”，该消费者表示，“之前家里都是大猫，那时候正常使用没有发现问题。”（新京报）</p>\\n<h2>大公司/大事件</h2>\\n<p><strong>京东宣布推出“机器人救护车”</strong></p>\\n<p>4月15日，京东宣布正式推出“机器人救护车”，为人形机器人、四足机器人、AI陪伴机器人等提供维修保养服务，涵盖基础维修、故障诊断、换电补能、测试鉴定、美容保养、设备回收等。目前，京东“机器人救护车”已服务北京地区，未来三年，机器人上门维修服务还将拓展至全国超50个核心城市。（界面新闻）</p>\\n<p><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></p>\\n<p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。（第一财经）</p>\\n<p><strong>哈啰回应超量投放共享单车被行政处罚</strong></p>\\n<p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。（第一财经）</p>\\n<p><strong>永辉超市38亿追款获胜，王健林等承担连带保证责任</strong></p>\\n<p>时隔一年有余，永辉超市（601933.SH）针对大连御锦贸易有限公司（简称“大连御锦”）未按约支付万达商管股份转让款而进行的追款申请，获终局裁决支持。4月14日晚间，永辉超市发布公告称，近日收到上海国际经济贸易仲裁委员会(上海国际仲裁中心)(简称“上国仲”)送达的裁决书。根据裁决，第一被申请人大连御锦需向永辉超市支付剩余股份转让价款和加速到期违约金等共计38.57亿元。第二被申请人王健林、第三被申请人孙喜双、第四被申请人大连一方集团对上述债务承担连带保证责任。（界面新闻）</p>\\n<p><strong>张雪机车LOGO抄袭？设计公司发声明回应</strong></p>\\n<p>针对张雪机车品牌LOGO疑似抄袭一事，4月14日，杭州巴顿品牌设计有限公司发布声明称，本次LOGO设计由巴顿独立创作完成，相关商标已向国家知识产权局申请并核准注册。该公司表示，欢迎并支持任何认为侵犯其权利的主体通过司法途径解决问题。据了解，张雪机车创始人张雪曾表示，张雪机车的LOGO是找了杭州一家设计公司，包括视觉及店面形象等，花了40万元。（界面新闻）</p>\\n<p><strong>拟赴港上市？接近度小满人士：不实</strong></p>\\n<p>近日，有关度小满最快将于2026年上半年向港交所递交招股书，拟主板挂牌上市的信息在社交媒体传播。从接近度小满人士处独家获悉，相关信息不实，系对传闻的拼凑与虚构。公司已通过法律途径维护合法权益，并将追究相关方责任。（界面新闻）</p>\\n<p><strong>飞天茅台全线上涨，26年飞天原箱批价报1665元/瓶</strong></p>\\n<p>36氪获悉，“今日酒价”披露的最新批发参考价显示，4月15日，26年飞天茅台原箱报1665元/瓶，较上一日上涨5元；26年飞天茅台散瓶报1565元/瓶，与上日价格持平。25年飞天茅台原箱报1675元/瓶，较上一日上涨5元；25年飞天茅台散瓶报1610元/瓶，较上一日上涨10元。</p>\\n<p><strong>现货黄金向下跌破4800美元</strong></p>\\n<p>36氪获悉，现货黄金向下跌破4800美元，日内下跌0.89%。</p>\\n<p><strong>传抖音电商将迎调整，成立红果电商，官方暂无回应</strong></p>\\n<p>有市场消息称，抖音电商将迎调整，成立红果电商，架构在中国电商下，与行业产品、用户产品等部门平级。对此消息，抖音官方暂无回应。（新浪财经）</p>\\n<p><strong>广电总局发布微短剧精品创作传播计划</strong></p>\\n<p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。（新华社）</p>\\n<p><strong>Lululemon回应被指使用致癌化学物：称国内在售产品不含PFAS</strong></p>\\n<p>针对产品涉嫌含致癌化学物被调查一事，4月14日，Lululemon方面向中新网表示，Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。此前，据路透社报道，美国得克萨斯州总检察长肯·帕克斯顿已对知名运动品牌Lululemon展开调查，此次调查将查明Lululemon的运动服装是否含有“永久性化学物质”全氟和多氟烷基物质，该类化学物质在自然界中不易分解。帕克斯顿提到，最新研究结果与消费者担忧引发了人们的质疑：服装中的某些合成材料，是否可能与内分泌紊乱、不孕不育、癌症和其他健康风险有关。（中国新闻网）</p>\\n<p><strong>小米汽车公布降噪处理新专利</strong></p>\\n<p>36氪获悉，爱企查App显示，近日，小米汽车科技有限公司申请的“降噪处理方法、装置、车辆及存储介质”专利公布。摘要显示，该专利基于车辆的误差信号和加速度计信号识别车辆所处的噪声场景，并将加速度计信号分解为多个互不重叠的子带信号，再结合各子带信号对应的降噪处理参数进行自适应滤波，得到全频带降噪信号。该方案能够对复杂、多谱结构噪声进行高效分治与响应，提升降噪效果，进而提升用户的用车体验感。</p>\\n<p><strong>30年期国债期货创新高，机构看多超长债行情</strong></p>\\n<p>在资金面持续宽松与外部扰动阶段性缓和的背景下，债券市场近期整体走强，超长端利率债表现尤为突出。4月14日，30年期国债期货创近1个月新高，带动债市情绪明显回暖。多家机构认为，在配置力量回归、供需结构优化及宏观基本面逐步验证的支撑下，债市“配置牛”逻辑正在强化，超长债投资价值进一步凸显。（上证报）</p>\\n<p><strong>美股三大指数收盘涨跌不一，纳指11连涨创收盘新高</strong></p>\\n<p>36氪获悉，4月15日收盘，美股三大指数涨跌不一，纳指涨1.59%，为连续11个交易日上涨并创收盘新高，这11个交易日累计涨幅超15%，标普500指数涨0.8%创历史新高，道指跌0.15%。大型科技股普涨，特斯拉涨超7%，微软涨超4%，苹果涨近3%，英伟达、谷歌、Meta涨超1%。热门中概股涨跌不一，百度涨超2%，阿里巴巴、腾讯音乐涨超1%，理想汽车跌超3%，蔚来跌超2%，小鹏集团跌超1%。</p>\\n<p><strong>奈飞公司CEO与美国影院行业负责人举行会谈，双方未来或将合作</strong></p>\\n<p>美国一年一度的电影产业盛会——电影博览会于4月13日至16日在拉斯维加斯举行。该博览会的组织方“联合影院”，也就是曾经的美国全国影院主协会主席迈克尔•奥利里4月14日表示，奈飞公司首席执行官特德·萨兰多斯12日与该组织的代表们举行了一次“建设性的会谈”。对于奈飞公司此次与影院方面进行的会谈，奥利里认为，双方目前都认识到需要寻求互助合作，以建立一套更具互补性的商业模式。他同时表示，双方4月12日只是进行了初步会谈，并未达成任何协议。但他依然对奈飞公司所展现出的意愿表示赞赏。截至目前，奈飞公司尚未对上述事宜发表评论。（央视新闻）</p>\\n<p><strong>KKR将通过购买可转换债券向三星SDS投资8.2亿美元</strong></p>\\n<p>当地时间4月14日，美国私募股权巨头KKR宣布，将通过收购可转换债券向三星SDS投资1.22万亿韩元（约合8.2亿美元）。根据合作协议，KKR将通过其管理的基金，与三星SDS就一系列旨在为该公司创造价值的举措展开紧密合作，包括支持有机与非有机增长战略、加速该公司作为全栈式人工智能解决方案提供商的扩张，以及拓展新业务领域。KKR还将积极为三星SDS管理团队提供咨询服务，特别是在并购、资本配置以及支持公司寻求全球战略增长机遇等方面。（界面新闻）</p>\\n<p><strong>苹果官微发文提醒iPhone用户立即更新设备</strong></p>\\n<p>36氪获悉，4月15日，苹果官微发文表示，安全研究人员最近发现，存在一些基于网页的攻击，它们会借助恶意网页内容，对过时版本的iOS发起攻击。例如，如果用户使用的是较旧版本的iOS，一旦点按恶意链接或访问被入侵的网站，iPhone上的数据就可能面临被盗的风险。在发现这些问题后，苹果进行了全面调查，并在第一时间针对最新的操作系统版本发布了软件更新，旨在解决相关漏洞，阻断这类攻击。如果用户的iPhone运行的是较旧版本的iOS，请立即更新以保护数据安全。无法更新设备的用户，如果设备支持，可考虑启用锁定模式，以防范恶意网页内容及其他威胁。</p>\\n<p><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></p>\\n<p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。（财联社）</p>\\n<p><strong>博通宣布与Meta扩大合作，总裁兼CEO陈福阳将转任Meta顾问</strong></p>\\n<p>当地时间4月14日，博通公司与Meta宣布达成多年多代战略合作，以支持Meta快速扩展的人工智能计算基础设施。基于现有合作基础，博通将为Meta训练与推理加速器（MTIA）芯片提供技术支持，双方计划将合作延续至2029年。该技术将成为Meta部署尖端AI数据中心的基础架构核心。首期合作规模超过1吉瓦。鉴于此次扩展合作的规模，陈福阳（Hock Tan）将从Meta董事会卸任，转任Meta顾问角色，他将为Meta的定制芯片路线图提供指导。（新浪财经）</p>\\n<p><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></p>\\n<p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。（界面新闻）</p>\\n<p><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></p>\\n<p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武4月10日向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。（新浪财经）</p>\\n<p><strong>苹果CEO库克斥资106万美元增持耐克</strong></p>\\n<p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。（界面新闻）</p>\\n<p><strong>风险投资机构争相向Anthropic抛出投资要约，估值最高达8000亿美元</strong></p>\\n<p>据多位知情人士透露，近几周来，开发了Claude的初创公司Anthropic已收到多家风投机构的投资要约，对其估值最高达到8000亿美元，较最近估值翻了一倍有余。备受市场追捧的初创公司常会收到投资者主动提前抛出的要约，但往往会予以回绝。尽管如此，风投机构给出的估值水平仍反映出，随着Anthropic准备在今年晚些时候可能进行IPO，硅谷对入股该公司的需求已近乎狂热。（新浪财经）</p>\\n<h2>AI最前沿</h2>\\n<p><strong>OpenAI向部分用户发布Cyber模型，与Mythos展开竞争</strong></p>\\n<p>OpenAI允许特定用户访问一款更擅长发现软件安全漏洞的新模型。就在一周前，竞争对手Anthropic PBC宣布小范围发布人工智能工具Mythos。这家ChatGPT开发商4月14日表示，已开始推出GPT-5.4-Cyber模型，目标是发现软件中的问题，以便组织加以修复。OpenAI称，该模型在用于此类任务时对用户探测方式的限制也更少。（新浪财经）</p>\\n<p><strong>OpenAI推出旨在增强网络安全能力的迭代模型</strong></p>\\n<p>美国开放人工智能研究中心（OpenAI）14日宣布推出GPT-5.4的迭代模型GPT-5.4-Cyber，旨在增强网络安全能力；并宣布扩大其“网络安全可信访问”项目，将向经审核验证的网络安全人员和团队开放。（新华社）</p>\\n<p><strong>阿里ATH事业群发布首款AI开发工具秒悟</strong></p>\\n<p>36氪获悉，4月15日，阿里ATH事业群发布旗下首款AI开发工具Meoo（秒悟），该工具集成千问、Kimi、GLM、MiniMax四大模型，并内置阿里云数据库、存储等核心产品服务，用户只需用自然语言描述想法，Meoo最快1分钟就能自动生成前端后端完整的网站、H5页面，在阿里云上一键部署上线。</p>\\n<p><strong>腾讯轻量云独家上线Hermes Agent应用模板</strong></p>\\n<p>36氪获悉，4月14日，腾讯云轻量应用服务器Lighthouse正式上线Hermes Agent专属应用模板，行业首家实现该开源AI智能体的云端一键快速部署，其企业级ClawPro产品也将于本周内完成适配支持。依托轻量化云服务器的便捷特性，开发者无需复杂配置，即可快速完成Hermes Agent的云端搭建与运行。</p>\\n<p><strong>算力紧缺之下，Anthropic调整定价模式，按企业AI使用量计费</strong></p>\\n<p>Anthropic发言人证实，根据此次定价调整，Claude企业版客户除每月为每位用户支付20美元固定费用外，还需按使用软件时消耗的算力容量额外付费。Claude企业版是面向大型企业推出的产品组合，已推出两年，目前包含代码工具ClaudeCode及办公助手ClaudeCowork。（新浪财经）</p>\\n<h2>大公司财报</h2>\\n<p><strong>爱马仕第一季度总收入为40.7亿欧元，销售额同比增长5.6%</strong></p>\\n<p>4月15日，爱马仕公布第一季度业绩报告，第一季度总收入为40.7亿欧元。第一季度销售额同比增长5.6%，其中，按地区划分来看，欧洲地区销售额总计增长4.5%，亚洲地区总计增长3.5%，美洲增长17.2%，其他地区为增长5.9%；按行业划分来看，皮革制品与马具销售额增长9.4%，成衣与配饰增长0.4%，丝绸与纺织品增长7.8%等。（界面新闻）</p>\\n<p><strong>宁德时代：一季度净利润207.38亿元，同比增长48.52%</strong></p>\\n<p>36氪获悉，宁德时代发布一季度报告，一季度实现营收1291.31亿元，同比增长52.45%；归属于上市公司股东的净利润207.38亿元，同比增长48.52%。</p>\\n<p><strong>蓝色光标：2025年净利润2.25亿元，同比扭亏</strong></p>\\n<p>36氪获悉，蓝色光标披露年报，2025年实现营业收入686.93亿元，同比增长12.99%；归属于上市公司股东的净利润2.25亿元，上年同期亏损2.91亿元；基本每股收益0.063元。公司拟每10股派发现金红利0.1元（含税）。</p>\\n<p><strong>阿斯麦第一季度营收87.67亿欧元，高于市场预期</strong></p>\\n<p>4月15日，阿斯麦公布第一季度业绩报告，第一季度净销售额为87.67亿欧元，市场预估为86.9亿欧元；净利润为27.6亿欧元，市场预估为25.6亿欧元。阿斯麦预计2026年第二季度总净销售额将在84亿至90亿欧元之间，预计2026年总净销售额在360亿至400亿欧元之间。（界面新闻）</p>\\n<p><strong>多氟多：2025年净利润2.13亿元，同比扭亏</strong></p>\\n<p>36氪获悉，多氟多披露年报，2025年实现营业收入94.34亿元，同比增长14.37%；归属于上市公司股东的净利润2.13亿元，上年同期亏损3.08亿元；基本每股收益0.18元。公司拟每10股派发现金红利2元（含税）。</p>\\n<h2>投融资</h2>\\n<p><strong>自动驾驶初创公司Glydways洽谈2.5亿美元融资</strong></p>\\n<p>4月15日消息，据报道，由山姆·奥特曼支持的自动驾驶汽车初创公司Glydways正在洽谈新一轮融资，计划筹集2.5亿美元，这将使公司估值达到10亿美元或更高。Glydways此前刚刚完成1.7亿美元的融资，估值接近7亿美元。（界面新闻）</p>\\n<p><strong>“智象未来”完成超5亿元新一轮融资</strong></p>\\n<p>36氪获悉，近日，国内多模态生成式人工智能公司“智象未来”宣布完成超5亿元新一轮融资。本轮融资由东方富海、安徽省投资集团旗下的省产业投资公司、峰华资本等新股东联合投资，同时合肥产投、兴泰集团、合肥高投、安徽省人工智能母基金等老股东持续加注。本轮融资将主要用于智象独创的下一代原生全模态世界模型研发、企业服务智能体的产品建设以及全球市场拓展。</p>\\n<p><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></p>\\n<p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\\n<p><strong>“源升智能”完成上亿元Pre-A轮融资</strong></p>\\n<p>36氪获悉，“源升智能”宣布完成上亿元Pre-A轮融资。本轮融资由达晨财智、老股东春华创投共同领投，渶策资本、南山战新投跟投，老股东弘晖基金超额跟投。本轮融资将用于Apex Hand的产能扩充与批量交付、灵巧操作平台生态建设以及全球化市场拓展，以此巩固在高性能灵巧手领域的技术优势，加速具身智能在真实工业场景中的落地。这也是公司一年内完成的第5轮融资，累计融资金额达数亿元。</p>\\n<h2>酷产品</h2>\\n<p><strong>菜鸟发布攀爬机器人ZeeBot，实测智能化存取效率提升一倍</strong></p>\\n<p>36氪获悉，4月15日，菜鸟集团在美国亚特兰大举行的MODEX 2026国际物流展上发布了首款自研的“攀爬机器人”ZeeBot，并确认首个由攀爬机器人智能作业的仓储项目已在广东省交付使用。实测数据显示，该技术使仓库存取效率提升了100%。</p>\\n<p><strong>小鹏GX上市，预售价39.98万元</strong></p>\\n<p>36氪获悉，4月15日，小鹏大六座旗舰SUV小鹏GX上市，共推出增程和纯电两个版本，预售价39.98万元起。何小鹏在发布会上提到，小鹏GX是中国首款前装量产的Robotaxi原型车，完全按照L4自动驾驶标准打造，搭载四颗图灵芯片，有效算力达3000TOPS，搭载小鹏第二代VLA。</p>\\n<p><strong>千问AI眼镜S1宣布正式开售</strong></p>\\n<p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\\n<p><strong>优步承诺投入100亿美元发展机器人出租车，实现战略转型</strong></p>\\n<p>据英国金融时报4月15日报道，优步已承诺投入100多亿美元购买数千辆自动驾驶汽车，并参股其开发商，打破其轻资产的\\\"临时工经济\\\"业务模式，以避免机器人出租车的干扰。（新浪财经）</p>\\n<p><strong>整理</strong>｜Kris</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'8点1氪丨美国将退还超1万亿元关税；多家银行密集停发信用卡；滴露回应使用宠物消毒液后5只幼猫死亡\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'8点1氪丨美国将退还超1万亿元关税；多家银行密集停发信用卡；滴露回应使用宠物消毒液后5只幼猫死亡\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768734631527176?f=rss\'}], \'link\': \'https://36kr.com/p/3768734631527176?f=rss\', \'published\': \'2026-04-16 08:00:35  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=0, tm_min=0, tm_sec=35, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<h2>今日热点导览</h2>\\\\n  <p>京东宣布推出“机器人救护车”</p>\\\\n  <p>抖音集团将投入5亿专项资金扶持真人短剧</p>\\\\n  <p>永辉超市38亿追款获胜，王健林等承担连带保证责任</p>\\\\n  <p>张雪机车LOGO抄袭？设计公司发声明回应</p>\\\\n  <p>小米汽车公布降噪处理新专利</p>\\\\n  <h2>TOP 3大新闻</h2>\\\\n  <p><strong>美国将退还超1万亿元关税</strong></p>\\\\n  <p>据路透社报道，美国特朗普政府计划于当地时间4月20日正式启动一个关税退款系统，用于向进口商退还1660亿美元（约合人民币1.13万亿元）的关税，这些关税在今年2月被美国最高法院裁定为“非法”。据报道，美国海关与边境保护局14日在一份提交给国际贸易法院的法庭文件中表示，已基本完成向进口商大规模退款的报关系统第一阶段研发，将于20日启动相关关税退款工作。退款将以电子方式统一发放，并在适用情况下附带利息，取代此前逐笔处理的方式。数据显示，截至4月9日，已有约5.6万家进口商完成电子退款流程，涉及总金额达1270亿美元（约合人民币8660亿元）。（央视财经）</p>\\\\n  <p><strong>多家银行密集停发信用卡</strong></p>\\\\n  <p>近期，民生银行、农业银行、交通银行等多家银行接连发布公告，宣布停止发行部分信用卡产品，涉及国有大行、股份制银行及地方银行，停发产品以联名信用卡为主，同时涵盖部分主题信用卡。多家中小银行也加入到停发信用卡的行列之中。比如，2025年年末，武汉农商银行发布公告称，因联名信用卡合作业务调整，现与联名方合作终止，将于2026年1月1日起停止发行淘票票&amp;大麦联名信用卡；浙江农商联合银行也于2025年年底宣布，因业务合作调整，丰收京东联名卡将停止发行。</p>\\\\n  <p>此外，对于停发后的存量卡片，多家银行明确表示，持卡人手中的卡片在有效期内可正常使用，仅停止新增发行。若遇到损坏换卡、挂失补卡、到期换卡等情况，银行将根据不同规则处理，或换发同等级标准卡，或逐步更换为新版卡面，部分原产品的特殊功能与权益将不再提供。（界面新闻）</p>\\\\n  <p><strong>滴露回应使用宠物消毒液后5只幼猫死亡</strong></p>\\\\n  <p>4月15日，针对有消费者称“在使用滴露宠物消毒液拖地后，家中5只幼猫死亡”一事，<strong>滴露品牌母公司利洁时消费者热线工作人员回应新京报贝壳财经记者称，该产品经过安全性评估，“在依照标签正常使用的情况下，不会对宠物造成任何不良影响。”</strong>面对记者关于事件最新进展的追问，该工作人员表示，“暂时没有，无法获知更详细的情况。”</p>\\\\n  <p>据报道，有消费者称其于4月6日下午使用滴露消毒液（宠物家庭专用）在家里拖地，当晚11点左右，她发现家中5只幼猫全部死亡，“复盘下来，在那一天，我们唯一做的与之前不同的事情就是用这款消毒液拖了地”，该消费者表示，“之前家里都是大猫，那时候正常使用没有发现问题。”（新京报）</p>\\\\n  <h2>大公司/大事件</h2>\\\\n  <p><strong>京东宣布推出“机器人救护车”</strong></p>\\\\n  <p>4月15日，京东宣布正式推出“机器人救护车”，为人形机器人、四足机器人、AI陪伴机器人等提供维修保养服务，涵盖基础维修、故障诊断、换电补能、测试鉴定、美容保养、设备回收等。目前，京东“机器人救护车”已服务北京地区，未来三年，机器人上门维修服务还将拓展至全国超50个核心城市。（界面新闻）</p>\\\\n  <p><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></p>\\\\n  <p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。（第一财经）</p>\\\\n  <p><strong>哈啰回应超量投放共享单车被行政处罚</strong></p>\\\\n  <p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。（第一财经）</p>\\\\n  <p><strong>永辉超市38亿追款获胜，王健林等承担连带保证责任</strong></p>\\\\n  <p>时隔一年有余，永辉超市（601933.SH）针对大连御锦贸易有限公司（简称“大连御锦”）未按约支付万达商管股份转让款而进行的追款申请，获终局裁决支持。4月14日晚间，永辉超市发布公告称，近日收到上海国际经济贸易仲裁委员会(上海国际仲裁中心)(简称“上国仲”)送达的裁决书。根据裁决，第一被申请人大连御锦需向永辉超市支付剩余股份转让价款和加速到期违约金等共计38.57亿元。第二被申请人王健林、第三被申请人孙喜双、第四被申请人大连一方集团对上述债务承担连带保证责任。（界面新闻）</p>\\\\n  <p><strong>张雪机车LOGO抄袭？设计公司发声明回应</strong></p>\\\\n  <p>针对张雪机车品牌LOGO疑似抄袭一事，4月14日，杭州巴顿品牌设计有限公司发布声明称，本次LOGO设计由巴顿独立创作完成，相关商标已向国家知识产权局申请并核准注册。该公司表示，欢迎并支持任何认为侵犯其权利的主体通过司法途径解决问题。据了解，张雪机车创始人张雪曾表示，张雪机车的LOGO是找了杭州一家设计公司，包括视觉及店面形象等，花了40万元。（界面新闻）</p>\\\\n  <p><strong>拟赴港上市？接近度小满人士：不实</strong></p>\\\\n  <p>近日，有关度小满最快将于2026年上半年向港交所递交招股书，拟主板挂牌上市的信息在社交媒体传播。从接近度小满人士处独家获悉，相关信息不实，系对传闻的拼凑与虚构。公司已通过法律途径维护合法权益，并将追究相关方责任。（界面新闻）</p>\\\\n  <p><strong>飞天茅台全线上涨，26年飞天原箱批价报1665元/瓶</strong></p>\\\\n  <p>36氪获悉，“今日酒价”披露的最新批发参考价显示，4月15日，26年飞天茅台原箱报1665元/瓶，较上一日上涨5元；26年飞天茅台散瓶报1565元/瓶，与上日价格持平。25年飞天茅台原箱报1675元/瓶，较上一日上涨5元；25年飞天茅台散瓶报1610元/瓶，较上一日上涨10元。</p>\\\\n  <p><strong>现货黄金向下跌破4800美元</strong></p>\\\\n  <p>36氪获悉，现货黄金向下跌破4800美元，日内下跌0.89%。</p>\\\\n  <p><strong>传抖音电商将迎调整，成立红果电商，官方暂无回应</strong></p>\\\\n  <p>有市场消息称，抖音电商将迎调整，成立红果电商，架构在中国电商下，与行业产品、用户产品等部门平级。对此消息，抖音官方暂无回应。（新浪财经）</p>\\\\n  <p><strong>广电总局发布微短剧精品创作传播计划</strong></p>\\\\n  <p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。（新华社）</p>\\\\n  <p><strong>Lululemon回应被指使用致癌化学物：称国内在售产品不含PFAS</strong></p>\\\\n  <p>针对产品涉嫌含致癌化学物被调查一事，4月14日，Lululemon方面向中新网表示，Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。此前，据路透社报道，美国得克萨斯州总检察长肯·帕克斯顿已对知名运动品牌Lululemon展开调查，此次调查将查明Lululemon的运动服装是否含有“永久性化学物质”全氟和多氟烷基物质，该类化学物质在自然界中不易分解。帕克斯顿提到，最新研究结果与消费者担忧引发了人们的质疑：服装中的某些合成材料，是否可能与内分泌紊乱、不孕不育、癌症和其他健康风险有关。（中国新闻网）</p>\\\\n  <p><strong>小米汽车公布降噪处理新专利</strong></p>\\\\n  <p>36氪获悉，爱企查App显示，近日，小米汽车科技有限公司申请的“降噪处理方法、装置、车辆及存储介质”专利公布。摘要显示，该专利基于车辆的误差信号和加速度计信号识别车辆所处的噪声场景，并将加速度计信号分解为多个互不重叠的子带信号，再结合各子带信号对应的降噪处理参数进行自适应滤波，得到全频带降噪信号。该方案能够对复杂、多谱结构噪声进行高效分治与响应，提升降噪效果，进而提升用户的用车体验感。</p>\\\\n  <p><strong>30年期国债期货创新高，机构看多超长债行情</strong></p>\\\\n  <p>在资金面持续宽松与外部扰动阶段性缓和的背景下，债券市场近期整体走强，超长端利率债表现尤为突出。4月14日，30年期国债期货创近1个月新高，带动债市情绪明显回暖。多家机构认为，在配置力量回归、供需结构优化及宏观基本面逐步验证的支撑下，债市“配置牛”逻辑正在强化，超长债投资价值进一步凸显。（上证报）</p>\\\\n  <p><strong>美股三大指数收盘涨跌不一，纳指11连涨创收盘新高</strong></p>\\\\n  <p>36氪获悉，4月15日收盘，美股三大指数涨跌不一，纳指涨1.59%，为连续11个交易日上涨并创收盘新高，这11个交易日累计涨幅超15%，标普500指数涨0.8%创历史新高，道指跌0.15%。大型科技股普涨，特斯拉涨超7%，微软涨超4%，苹果涨近3%，英伟达、谷歌、Meta涨超1%。热门中概股涨跌不一，百度涨超2%，阿里巴巴、腾讯音乐涨超1%，理想汽车跌超3%，蔚来跌超2%，小鹏集团跌超1%。</p>\\\\n  <p><strong>奈飞公司CEO与美国影院行业负责人举行会谈，双方未来或将合作</strong></p>\\\\n  <p>美国一年一度的电影产业盛会——电影博览会于4月13日至16日在拉斯维加斯举行。该博览会的组织方“联合影院”，也就是曾经的美国全国影院主协会主席迈克尔•奥利里4月14日表示，奈飞公司首席执行官特德·萨兰多斯12日与该组织的代表们举行了一次“建设性的会谈”。对于奈飞公司此次与影院方面进行的会谈，奥利里认为，双方目前都认识到需要寻求互助合作，以建立一套更具互补性的商业模式。他同时表示，双方4月12日只是进行了初步会谈，并未达成任何协议。但他依然对奈飞公司所展现出的意愿表示赞赏。截至目前，奈飞公司尚未对上述事宜发表评论。（央视新闻）</p>\\\\n  <p><strong>KKR将通过购买可转换债券向三星SDS投资8.2亿美元</strong></p>\\\\n  <p>当地时间4月14日，美国私募股权巨头KKR宣布，将通过收购可转换债券向三星SDS投资1.22万亿韩元（约合8.2亿美元）。根据合作协议，KKR将通过其管理的基金，与三星SDS就一系列旨在为该公司创造价值的举措展开紧密合作，包括支持有机与非有机增长战略、加速该公司作为全栈式人工智能解决方案提供商的扩张，以及拓展新业务领域。KKR还将积极为三星SDS管理团队提供咨询服务，特别是在并购、资本配置以及支持公司寻求全球战略增长机遇等方面。（界面新闻）</p>\\\\n  <p><strong>苹果官微发文提醒iPhone用户立即更新设备</strong></p>\\\\n  <p>36氪获悉，4月15日，苹果官微发文表示，安全研究人员最近发现，存在一些基于网页的攻击，它们会借助恶意网页内容，对过时版本的iOS发起攻击。例如，如果用户使用的是较旧版本的iOS，一旦点按恶意链接或访问被入侵的网站，iPhone上的数据就可能面临被盗的风险。在发现这些问题后，苹果进行了全面调查，并在第一时间针对最新的操作系统版本发布了软件更新，旨在解决相关漏洞，阻断这类攻击。如果用户的iPhone运行的是较旧版本的iOS，请立即更新以保护数据安全。无法更新设备的用户，如果设备支持，可考虑启用锁定模式，以防范恶意网页内容及其他威胁。</p>\\\\n  <p><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></p>\\\\n  <p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。（财联社）</p>\\\\n  <p><strong>博通宣布与Meta扩大合作，总裁兼CEO陈福阳将转任Meta顾问</strong></p>\\\\n  <p>当地时间4月14日，博通公司与Meta宣布达成多年多代战略合作，以支持Meta快速扩展的人工智能计算基础设施。基于现有合作基础，博通将为Meta训练与推理加速器（MTIA）芯片提供技术支持，双方计划将合作延续至2029年。该技术将成为Meta部署尖端AI数据中心的基础架构核心。首期合作规模超过1吉瓦。鉴于此次扩展合作的规模，陈福阳（Hock Tan）将从Meta董事会卸任，转任Meta顾问角色，他将为Meta的定制芯片路线图提供指导。（新浪财经）</p>\\\\n  <p><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></p>\\\\n  <p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。（界面新闻）</p>\\\\n  <p><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></p>\\\\n  <p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武4月10日向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。（新浪财经）</p>\\\\n  <p><strong>苹果CEO库克斥资106万美元增持耐克</strong></p>\\\\n  <p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。（界面新闻）</p>\\\\n  <p><strong>风险投资机构争相向Anthropic抛出投资要约，估值最高达8000亿美元</strong></p>\\\\n  <p>据多位知情人士透露，近几周来，开发了Claude的初创公司Anthropic已收到多家风投机构的投资要约，对其估值最高达到8000亿美元，较最近估值翻了一倍有余。备受市场追捧的初创公司常会收到投资者主动提前抛出的要约，但往往会予以回绝。尽管如此，风投机构给出的估值水平仍反映出，随着Anthropic准备在今年晚些时候可能进行IPO，硅谷对入股该公司的需求已近乎狂热。（新浪财经）</p>\\\\n  <h2>AI最前沿</h2>\\\\n  <p><strong>OpenAI向部分用户发布Cyber模型，与Mythos展开竞争</strong></p>\\\\n  <p>OpenAI允许特定用户访问一款更擅长发现软件安全漏洞的新模型。就在一周前，竞争对手Anthropic PBC宣布小范围发布人工智能工具Mythos。这家ChatGPT开发商4月14日表示，已开始推出GPT-5.4-Cyber模型，目标是发现软件中的问题，以便组织加以修复。OpenAI称，该模型在用于此类任务时对用户探测方式的限制也更少。（新浪财经）</p>\\\\n  <p><strong>OpenAI推出旨在增强网络安全能力的迭代模型</strong></p>\\\\n  <p>美国开放人工智能研究中心（OpenAI）14日宣布推出GPT-5.4的迭代模型GPT-5.4-Cyber，旨在增强网络安全能力；并宣布扩大其“网络安全可信访问”项目，将向经审核验证的网络安全人员和团队开放。（新华社）</p>\\\\n  <p><strong>阿里ATH事业群发布首款AI开发工具秒悟</strong></p>\\\\n  <p>36氪获悉，4月15日，阿里ATH事业群发布旗下首款AI开发工具Meoo（秒悟），该工具集成千问、Kimi、GLM、MiniMax四大模型，并内置阿里云数据库、存储等核心产品服务，用户只需用自然语言描述想法，Meoo最快1分钟就能自动生成前端后端完整的网站、H5页面，在阿里云上一键部署上线。</p>\\\\n  <p><strong>腾讯轻量云独家上线Hermes Agent应用模板</strong></p>\\\\n  <p>36氪获悉，4月14日，腾讯云轻量应用服务器Lighthouse正式上线Hermes Agent专属应用模板，行业首家实现该开源AI智能体的云端一键快速部署，其企业级ClawPro产品也将于本周内完成适配支持。依托轻量化云服务器的便捷特性，开发者无需复杂配置，即可快速完成Hermes Agent的云端搭建与运行。</p>\\\\n  <p><strong>算力紧缺之下，Anthropic调整定价模式，按企业AI使用量计费</strong></p>\\\\n  <p>Anthropic发言人证实，根据此次定价调整，Claude企业版客户除每月为每位用户支付20美元固定费用外，还需按使用软件时消耗的算力容量额外付费。Claude企业版是面向大型企业推出的产品组合，已推出两年，目前包含代码工具ClaudeCode及办公助手ClaudeCowork。（新浪财经）</p>\\\\n  <h2>大公司财报</h2>\\\\n  <p><strong>爱马仕第一季度总收入为40.7亿欧元，销售额同比增长5.6%</strong></p>\\\\n  <p>4月15日，爱马仕公布第一季度业绩报告，第一季度总收入为40.7亿欧元。第一季度销售额同比增长5.6%，其中，按地区划分来看，欧洲地区销售额总计增长4.5%，亚洲地区总计增长3.5%，美洲增长17.2%，其他地区为增长5.9%；按行业划分来看，皮革制品与马具销售额增长9.4%，成衣与配饰增长0.4%，丝绸与纺织品增长7.8%等。（界面新闻）</p>\\\\n  <p><strong>宁德时代：一季度净利润207.38亿元，同比增长48.52%</strong></p>\\\\n  <p>36氪获悉，宁德时代发布一季度报告，一季度实现营收1291.31亿元，同比增长52.45%；归属于上市公司股东的净利润207.38亿元，同比增长48.52%。</p>\\\\n  <p><strong>蓝色光标：2025年净利润2.25亿元，同比扭亏</strong></p>\\\\n  <p>36氪获悉，蓝色光标披露年报，2025年实现营业收入686.93亿元，同比增长12.99%；归属于上市公司股东的净利润2.25亿元，上年同期亏损2.91亿元；基本每股收益0.063元。公司拟每10股派发现金红利0.1元（含税）。</p>\\\\n  <p><strong>阿斯麦第一季度营收87.67亿欧元，高于市场预期</strong></p>\\\\n  <p>4月15日，阿斯麦公布第一季度业绩报告，第一季度净销售额为87.67亿欧元，市场预估为86.9亿欧元；净利润为27.6亿欧元，市场预估为25.6亿欧元。阿斯麦预计2026年第二季度总净销售额将在84亿至90亿欧元之间，预计2026年总净销售额在360亿至400亿欧元之间。（界面新闻）</p>\\\\n  <p><strong>多氟多：2025年净利润2.13亿元，同比扭亏</strong></p>\\\\n  <p>36氪获悉，多氟多披露年报，2025年实现营业收入94.34亿元，同比增长14.37%；归属于上市公司股东的净利润2.13亿元，上年同期亏损3.08亿元；基本每股收益0.18元。公司拟每10股派发现金红利2元（含税）。</p>\\\\n  <h2>投融资</h2>\\\\n  <p><strong>自动驾驶初创公司Glydways洽谈2.5亿美元融资</strong></p>\\\\n  <p>4月15日消息，据报道，由山姆·奥特曼支持的自动驾驶汽车初创公司Glydways正在洽谈新一轮融资，计划筹集2.5亿美元，这将使公司估值达到10亿美元或更高。Glydways此前刚刚完成1.7亿美元的融资，估值接近7亿美元。（界面新闻）</p>\\\\n  <p><strong>“智象未来”完成超5亿元新一轮融资</strong></p>\\\\n  <p>36氪获悉，近日，国内多模态生成式人工智能公司“智象未来”宣布完成超5亿元新一轮融资。本轮融资由东方富海、安徽省投资集团旗下的省产业投资公司、峰华资本等新股东联合投资，同时合肥产投、兴泰集团、合肥高投、安徽省人工智能母基金等老股东持续加注。本轮融资将主要用于智象独创的下一代原生全模态世界模型研发、企业服务智能体的产品建设以及全球市场拓展。</p>\\\\n  <p><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></p>\\\\n  <p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\\\\n  <p><strong>“源升智能”完成上亿元Pre-A轮融资</strong></p>\\\\n  <p>36氪获悉，“源升智能”宣布完成上亿元Pre-A轮融资。本轮融资由达晨财智、老股东春华创投共同领投，渶策资本、南山战新投跟投，老股东弘晖基金超额跟投。本轮融资将用于Apex Hand的产能扩充与批量交付、灵巧操作平台生态建设以及全球化市场拓展，以此巩固在高性能灵巧手领域的技术优势，加速具身智能在真实工业场景中的落地。这也是公司一年内完成的第5轮融资，累计融资金额达数亿元。</p>\\\\n  <h2>酷产品</h2>\\\\n  <p><strong>菜鸟发布攀爬机器人ZeeBot，实测智能化存取效率提升一倍</strong></p>\\\\n  <p>36氪获悉，4月15日，菜鸟集团在美国亚特兰大举行的MODEX 2026国际物流展上发布了首款自研的“攀爬机器人”ZeeBot，并确认首个由攀爬机器人智能作业的仓储项目已在广东省交付使用。实测数据显示，该技术使仓库存取效率提升了100%。</p>\\\\n  <p><strong>小鹏GX上市，预售价39.98万元</strong></p>\\\\n  <p>36氪获悉，4月15日，小鹏大六座旗舰SUV小鹏GX上市，共推出增程和纯电两个版本，预售价39.98万元起。何小鹏在发布会上提到，小鹏GX是中国首款前装量产的Robotaxi原型车，完全按照L4自动驾驶标准打造，搭载四颗图灵芯片，有效算力达3000TOPS，搭载小鹏第二代VLA。</p>\\\\n  <p><strong>千问AI眼镜S1宣布正式开售</strong></p>\\\\n  <p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\\\\n  <p><strong>优步承诺投入100亿美元发展机器人出租车，实现战略转型</strong></p>\\\\n  <p>据英国金融时报4月15日报道，优步已承诺投入100多亿美元购买数千辆自动驾驶汽车，并参股其开发商，打破其轻资产的\\\"临时工经济\\\"业务模式，以避免机器人出租车的干扰。（新浪财经）</p>\\\\n  <p class=\\\"editor-note\\\"><strong>整理</strong>｜Kris</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<h2>今日热点导览</h2>\\\\n  <p>京东宣布推出“机器人救护车”</p>\\\\n  <p>抖音集团将投入5亿专项资金扶持真人短剧</p>\\\\n  <p>永辉超市38亿追款获胜，王健林等承担连带保证责任</p>\\\\n  <p>张雪机车LOGO抄袭？设计公司发声明回应</p>\\\\n  <p>小米汽车公布降噪处理新专利</p>\\\\n  <h2>TOP 3大新闻</h2>\\\\n  <p><strong>美国将退还超1万亿元关税</strong></p>\\\\n  <p>据路透社报道，美国特朗普政府计划于当地时间4月20日正式启动一个关税退款系统，用于向进口商退还1660亿美元（约合人民币1.13万亿元）的关税，这些关税在今年2月被美国最高法院裁定为“非法”。据报道，美国海关与边境保护局14日在一份提交给国际贸易法院的法庭文件中表示，已基本完成向进口商大规模退款的报关系统第一阶段研发，将于20日启动相关关税退款工作。退款将以电子方式统一发放，并在适用情况下附带利息，取代此前逐笔处理的方式。数据显示，截至4月9日，已有约5.6万家进口商完成电子退款流程，涉及总金额达1270亿美元（约合人民币8660亿元）。（央视财经）</p>\\\\n  <p><strong>多家银行密集停发信用卡</strong></p>\\\\n  <p>近期，民生银行、农业银行、交通银行等多家银行接连发布公告，宣布停止发行部分信用卡产品，涉及国有大行、股份制银行及地方银行，停发产品以联名信用卡为主，同时涵盖部分主题信用卡。多家中小银行也加入到停发信用卡的行列之中。比如，2025年年末，武汉农商银行发布公告称，因联名信用卡合作业务调整，现与联名方合作终止，将于2026年1月1日起停止发行淘票票&amp;大麦联名信用卡；浙江农商联合银行也于2025年年底宣布，因业务合作调整，丰收京东联名卡将停止发行。</p>\\\\n  <p>此外，对于停发后的存量卡片，多家银行明确表示，持卡人手中的卡片在有效期内可正常使用，仅停止新增发行。若遇到损坏换卡、挂失补卡、到期换卡等情况，银行将根据不同规则处理，或换发同等级标准卡，或逐步更换为新版卡面，部分原产品的特殊功能与权益将不再提供。（界面新闻）</p>\\\\n  <p><strong>滴露回应使用宠物消毒液后5只幼猫死亡</strong></p>\\\\n  <p>4月15日，针对有消费者称“在使用滴露宠物消毒液拖地后，家中5只幼猫死亡”一事，<strong>滴露品牌母公司利洁时消费者热线工作人员回应新京报贝壳财经记者称，该产品经过安全性评估，“在依照标签正常使用的情况下，不会对宠物造成任何不良影响。”</strong>面对记者关于事件最新进展的追问，该工作人员表示，“暂时没有，无法获知更详细的情况。”</p>\\\\n  <p>据报道，有消费者称其于4月6日下午使用滴露消毒液（宠物家庭专用）在家里拖地，当晚11点左右，她发现家中5只幼猫全部死亡，“复盘下来，在那一天，我们唯一做的与之前不同的事情就是用这款消毒液拖了地”，该消费者表示，“之前家里都是大猫，那时候正常使用没有发现问题。”（新京报）</p>\\\\n  <h2>大公司/大事件</h2>\\\\n  <p><strong>京东宣布推出“机器人救护车”</strong></p>\\\\n  <p>4月15日，京东宣布正式推出“机器人救护车”，为人形机器人、四足机器人、AI陪伴机器人等提供维修保养服务，涵盖基础维修、故障诊断、换电补能、测试鉴定、美容保养、设备回收等。目前，京东“机器人救护车”已服务北京地区，未来三年，机器人上门维修服务还将拓展至全国超50个核心城市。（界面新闻）</p>\\\\n  <p><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></p>\\\\n  <p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。（第一财经）</p>\\\\n  <p><strong>哈啰回应超量投放共享单车被行政处罚</strong></p>\\\\n  <p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。（第一财经）</p>\\\\n  <p><strong>永辉超市38亿追款获胜，王健林等承担连带保证责任</strong></p>\\\\n  <p>时隔一年有余，永辉超市（601933.SH）针对大连御锦贸易有限公司（简称“大连御锦”）未按约支付万达商管股份转让款而进行的追款申请，获终局裁决支持。4月14日晚间，永辉超市发布公告称，近日收到上海国际经济贸易仲裁委员会(上海国际仲裁中心)(简称“上国仲”)送达的裁决书。根据裁决，第一被申请人大连御锦需向永辉超市支付剩余股份转让价款和加速到期违约金等共计38.57亿元。第二被申请人王健林、第三被申请人孙喜双、第四被申请人大连一方集团对上述债务承担连带保证责任。（界面新闻）</p>\\\\n  <p><strong>张雪机车LOGO抄袭？设计公司发声明回应</strong></p>\\\\n  <p>针对张雪机车品牌LOGO疑似抄袭一事，4月14日，杭州巴顿品牌设计有限公司发布声明称，本次LOGO设计由巴顿独立创作完成，相关商标已向国家知识产权局申请并核准注册。该公司表示，欢迎并支持任何认为侵犯其权利的主体通过司法途径解决问题。据了解，张雪机车创始人张雪曾表示，张雪机车的LOGO是找了杭州一家设计公司，包括视觉及店面形象等，花了40万元。（界面新闻）</p>\\\\n  <p><strong>拟赴港上市？接近度小满人士：不实</strong></p>\\\\n  <p>近日，有关度小满最快将于2026年上半年向港交所递交招股书，拟主板挂牌上市的信息在社交媒体传播。从接近度小满人士处独家获悉，相关信息不实，系对传闻的拼凑与虚构。公司已通过法律途径维护合法权益，并将追究相关方责任。（界面新闻）</p>\\\\n  <p><strong>飞天茅台全线上涨，26年飞天原箱批价报1665元/瓶</strong></p>\\\\n  <p>36氪获悉，“今日酒价”披露的最新批发参考价显示，4月15日，26年飞天茅台原箱报1665元/瓶，较上一日上涨5元；26年飞天茅台散瓶报1565元/瓶，与上日价格持平。25年飞天茅台原箱报1675元/瓶，较上一日上涨5元；25年飞天茅台散瓶报1610元/瓶，较上一日上涨10元。</p>\\\\n  <p><strong>现货黄金向下跌破4800美元</strong></p>\\\\n  <p>36氪获悉，现货黄金向下跌破4800美元，日内下跌0.89%。</p>\\\\n  <p><strong>传抖音电商将迎调整，成立红果电商，官方暂无回应</strong></p>\\\\n  <p>有市场消息称，抖音电商将迎调整，成立红果电商，架构在中国电商下，与行业产品、用户产品等部门平级。对此消息，抖音官方暂无回应。（新浪财经）</p>\\\\n  <p><strong>广电总局发布微短剧精品创作传播计划</strong></p>\\\\n  <p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。（新华社）</p>\\\\n  <p><strong>Lululemon回应被指使用致癌化学物：称国内在售产品不含PFAS</strong></p>\\\\n  <p>针对产品涉嫌含致癌化学物被调查一事，4月14日，Lululemon方面向中新网表示，Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。此前，据路透社报道，美国得克萨斯州总检察长肯·帕克斯顿已对知名运动品牌Lululemon展开调查，此次调查将查明Lululemon的运动服装是否含有“永久性化学物质”全氟和多氟烷基物质，该类化学物质在自然界中不易分解。帕克斯顿提到，最新研究结果与消费者担忧引发了人们的质疑：服装中的某些合成材料，是否可能与内分泌紊乱、不孕不育、癌症和其他健康风险有关。（中国新闻网）</p>\\\\n  <p><strong>小米汽车公布降噪处理新专利</strong></p>\\\\n  <p>36氪获悉，爱企查App显示，近日，小米汽车科技有限公司申请的“降噪处理方法、装置、车辆及存储介质”专利公布。摘要显示，该专利基于车辆的误差信号和加速度计信号识别车辆所处的噪声场景，并将加速度计信号分解为多个互不重叠的子带信号，再结合各子带信号对应的降噪处理参数进行自适应滤波，得到全频带降噪信号。该方案能够对复杂、多谱结构噪声进行高效分治与响应，提升降噪效果，进而提升用户的用车体验感。</p>\\\\n  <p><strong>30年期国债期货创新高，机构看多超长债行情</strong></p>\\\\n  <p>在资金面持续宽松与外部扰动阶段性缓和的背景下，债券市场近期整体走强，超长端利率债表现尤为突出。4月14日，30年期国债期货创近1个月新高，带动债市情绪明显回暖。多家机构认为，在配置力量回归、供需结构优化及宏观基本面逐步验证的支撑下，债市“配置牛”逻辑正在强化，超长债投资价值进一步凸显。（上证报）</p>\\\\n  <p><strong>美股三大指数收盘涨跌不一，纳指11连涨创收盘新高</strong></p>\\\\n  <p>36氪获悉，4月15日收盘，美股三大指数涨跌不一，纳指涨1.59%，为连续11个交易日上涨并创收盘新高，这11个交易日累计涨幅超15%，标普500指数涨0.8%创历史新高，道指跌0.15%。大型科技股普涨，特斯拉涨超7%，微软涨超4%，苹果涨近3%，英伟达、谷歌、Meta涨超1%。热门中概股涨跌不一，百度涨超2%，阿里巴巴、腾讯音乐涨超1%，理想汽车跌超3%，蔚来跌超2%，小鹏集团跌超1%。</p>\\\\n  <p><strong>奈飞公司CEO与美国影院行业负责人举行会谈，双方未来或将合作</strong></p>\\\\n  <p>美国一年一度的电影产业盛会——电影博览会于4月13日至16日在拉斯维加斯举行。该博览会的组织方“联合影院”，也就是曾经的美国全国影院主协会主席迈克尔•奥利里4月14日表示，奈飞公司首席执行官特德·萨兰多斯12日与该组织的代表们举行了一次“建设性的会谈”。对于奈飞公司此次与影院方面进行的会谈，奥利里认为，双方目前都认识到需要寻求互助合作，以建立一套更具互补性的商业模式。他同时表示，双方4月12日只是进行了初步会谈，并未达成任何协议。但他依然对奈飞公司所展现出的意愿表示赞赏。截至目前，奈飞公司尚未对上述事宜发表评论。（央视新闻）</p>\\\\n  <p><strong>KKR将通过购买可转换债券向三星SDS投资8.2亿美元</strong></p>\\\\n  <p>当地时间4月14日，美国私募股权巨头KKR宣布，将通过收购可转换债券向三星SDS投资1.22万亿韩元（约合8.2亿美元）。根据合作协议，KKR将通过其管理的基金，与三星SDS就一系列旨在为该公司创造价值的举措展开紧密合作，包括支持有机与非有机增长战略、加速该公司作为全栈式人工智能解决方案提供商的扩张，以及拓展新业务领域。KKR还将积极为三星SDS管理团队提供咨询服务，特别是在并购、资本配置以及支持公司寻求全球战略增长机遇等方面。（界面新闻）</p>\\\\n  <p><strong>苹果官微发文提醒iPhone用户立即更新设备</strong></p>\\\\n  <p>36氪获悉，4月15日，苹果官微发文表示，安全研究人员最近发现，存在一些基于网页的攻击，它们会借助恶意网页内容，对过时版本的iOS发起攻击。例如，如果用户使用的是较旧版本的iOS，一旦点按恶意链接或访问被入侵的网站，iPhone上的数据就可能面临被盗的风险。在发现这些问题后，苹果进行了全面调查，并在第一时间针对最新的操作系统版本发布了软件更新，旨在解决相关漏洞，阻断这类攻击。如果用户的iPhone运行的是较旧版本的iOS，请立即更新以保护数据安全。无法更新设备的用户，如果设备支持，可考虑启用锁定模式，以防范恶意网页内容及其他威胁。</p>\\\\n  <p><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></p>\\\\n  <p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。（财联社）</p>\\\\n  <p><strong>博通宣布与Meta扩大合作，总裁兼CEO陈福阳将转任Meta顾问</strong></p>\\\\n  <p>当地时间4月14日，博通公司与Meta宣布达成多年多代战略合作，以支持Meta快速扩展的人工智能计算基础设施。基于现有合作基础，博通将为Meta训练与推理加速器（MTIA）芯片提供技术支持，双方计划将合作延续至2029年。该技术将成为Meta部署尖端AI数据中心的基础架构核心。首期合作规模超过1吉瓦。鉴于此次扩展合作的规模，陈福阳（Hock Tan）将从Meta董事会卸任，转任Meta顾问角色，他将为Meta的定制芯片路线图提供指导。（新浪财经）</p>\\\\n  <p><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></p>\\\\n  <p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。（界面新闻）</p>\\\\n  <p><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></p>\\\\n  <p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武4月10日向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。（新浪财经）</p>\\\\n  <p><strong>苹果CEO库克斥资106万美元增持耐克</strong></p>\\\\n  <p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。（界面新闻）</p>\\\\n  <p><strong>风险投资机构争相向Anthropic抛出投资要约，估值最高达8000亿美元</strong></p>\\\\n  <p>据多位知情人士透露，近几周来，开发了Claude的初创公司Anthropic已收到多家风投机构的投资要约，对其估值最高达到8000亿美元，较最近估值翻了一倍有余。备受市场追捧的初创公司常会收到投资者主动提前抛出的要约，但往往会予以回绝。尽管如此，风投机构给出的估值水平仍反映出，随着Anthropic准备在今年晚些时候可能进行IPO，硅谷对入股该公司的需求已近乎狂热。（新浪财经）</p>\\\\n  <h2>AI最前沿</h2>\\\\n  <p><strong>OpenAI向部分用户发布Cyber模型，与Mythos展开竞争</strong></p>\\\\n  <p>OpenAI允许特定用户访问一款更擅长发现软件安全漏洞的新模型。就在一周前，竞争对手Anthropic PBC宣布小范围发布人工智能工具Mythos。这家ChatGPT开发商4月14日表示，已开始推出GPT-5.4-Cyber模型，目标是发现软件中的问题，以便组织加以修复。OpenAI称，该模型在用于此类任务时对用户探测方式的限制也更少。（新浪财经）</p>\\\\n  <p><strong>OpenAI推出旨在增强网络安全能力的迭代模型</strong></p>\\\\n  <p>美国开放人工智能研究中心（OpenAI）14日宣布推出GPT-5.4的迭代模型GPT-5.4-Cyber，旨在增强网络安全能力；并宣布扩大其“网络安全可信访问”项目，将向经审核验证的网络安全人员和团队开放。（新华社）</p>\\\\n  <p><strong>阿里ATH事业群发布首款AI开发工具秒悟</strong></p>\\\\n  <p>36氪获悉，4月15日，阿里ATH事业群发布旗下首款AI开发工具Meoo（秒悟），该工具集成千问、Kimi、GLM、MiniMax四大模型，并内置阿里云数据库、存储等核心产品服务，用户只需用自然语言描述想法，Meoo最快1分钟就能自动生成前端后端完整的网站、H5页面，在阿里云上一键部署上线。</p>\\\\n  <p><strong>腾讯轻量云独家上线Hermes Agent应用模板</strong></p>\\\\n  <p>36氪获悉，4月14日，腾讯云轻量应用服务器Lighthouse正式上线Hermes Agent专属应用模板，行业首家实现该开源AI智能体的云端一键快速部署，其企业级ClawPro产品也将于本周内完成适配支持。依托轻量化云服务器的便捷特性，开发者无需复杂配置，即可快速完成Hermes Agent的云端搭建与运行。</p>\\\\n  <p><strong>算力紧缺之下，Anthropic调整定价模式，按企业AI使用量计费</strong></p>\\\\n  <p>Anthropic发言人证实，根据此次定价调整，Claude企业版客户除每月为每位用户支付20美元固定费用外，还需按使用软件时消耗的算力容量额外付费。Claude企业版是面向大型企业推出的产品组合，已推出两年，目前包含代码工具ClaudeCode及办公助手ClaudeCowork。（新浪财经）</p>\\\\n  <h2>大公司财报</h2>\\\\n  <p><strong>爱马仕第一季度总收入为40.7亿欧元，销售额同比增长5.6%</strong></p>\\\\n  <p>4月15日，爱马仕公布第一季度业绩报告，第一季度总收入为40.7亿欧元。第一季度销售额同比增长5.6%，其中，按地区划分来看，欧洲地区销售额总计增长4.5%，亚洲地区总计增长3.5%，美洲增长17.2%，其他地区为增长5.9%；按行业划分来看，皮革制品与马具销售额增长9.4%，成衣与配饰增长0.4%，丝绸与纺织品增长7.8%等。（界面新闻）</p>\\\\n  <p><strong>宁德时代：一季度净利润207.38亿元，同比增长48.52%</strong></p>\\\\n  <p>36氪获悉，宁德时代发布一季度报告，一季度实现营收1291.31亿元，同比增长52.45%；归属于上市公司股东的净利润207.38亿元，同比增长48.52%。</p>\\\\n  <p><strong>蓝色光标：2025年净利润2.25亿元，同比扭亏</strong></p>\\\\n  <p>36氪获悉，蓝色光标披露年报，2025年实现营业收入686.93亿元，同比增长12.99%；归属于上市公司股东的净利润2.25亿元，上年同期亏损2.91亿元；基本每股收益0.063元。公司拟每10股派发现金红利0.1元（含税）。</p>\\\\n  <p><strong>阿斯麦第一季度营收87.67亿欧元，高于市场预期</strong></p>\\\\n  <p>4月15日，阿斯麦公布第一季度业绩报告，第一季度净销售额为87.67亿欧元，市场预估为86.9亿欧元；净利润为27.6亿欧元，市场预估为25.6亿欧元。阿斯麦预计2026年第二季度总净销售额将在84亿至90亿欧元之间，预计2026年总净销售额在360亿至400亿欧元之间。（界面新闻）</p>\\\\n  <p><strong>多氟多：2025年净利润2.13亿元，同比扭亏</strong></p>\\\\n  <p>36氪获悉，多氟多披露年报，2025年实现营业收入94.34亿元，同比增长14.37%；归属于上市公司股东的净利润2.13亿元，上年同期亏损3.08亿元；基本每股收益0.18元。公司拟每10股派发现金红利2元（含税）。</p>\\\\n  <h2>投融资</h2>\\\\n  <p><strong>自动驾驶初创公司Glydways洽谈2.5亿美元融资</strong></p>\\\\n  <p>4月15日消息，据报道，由山姆·奥特曼支持的自动驾驶汽车初创公司Glydways正在洽谈新一轮融资，计划筹集2.5亿美元，这将使公司估值达到10亿美元或更高。Glydways此前刚刚完成1.7亿美元的融资，估值接近7亿美元。（界面新闻）</p>\\\\n  <p><strong>“智象未来”完成超5亿元新一轮融资</strong></p>\\\\n  <p>36氪获悉，近日，国内多模态生成式人工智能公司“智象未来”宣布完成超5亿元新一轮融资。本轮融资由东方富海、安徽省投资集团旗下的省产业投资公司、峰华资本等新股东联合投资，同时合肥产投、兴泰集团、合肥高投、安徽省人工智能母基金等老股东持续加注。本轮融资将主要用于智象独创的下一代原生全模态世界模型研发、企业服务智能体的产品建设以及全球市场拓展。</p>\\\\n  <p><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></p>\\\\n  <p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\\\\n  <p><strong>“源升智能”完成上亿元Pre-A轮融资</strong></p>\\\\n  <p>36氪获悉，“源升智能”宣布完成上亿元Pre-A轮融资。本轮融资由达晨财智、老股东春华创投共同领投，渶策资本、南山战新投跟投，老股东弘晖基金超额跟投。本轮融资将用于Apex Hand的产能扩充与批量交付、灵巧操作平台生态建设以及全球化市场拓展，以此巩固在高性能灵巧手领域的技术优势，加速具身智能在真实工业场景中的落地。这也是公司一年内完成的第5轮融资，累计融资金额达数亿元。</p>\\\\n  <h2>酷产品</h2>\\\\n  <p><strong>菜鸟发布攀爬机器人ZeeBot，实测智能化存取效率提升一倍</strong></p>\\\\n  <p>36氪获悉，4月15日，菜鸟集团在美国亚特兰大举行的MODEX 2026国际物流展上发布了首款自研的“攀爬机器人”ZeeBot，并确认首个由攀爬机器人智能作业的仓储项目已在广东省交付使用。实测数据显示，该技术使仓库存取效率提升了100%。</p>\\\\n  <p><strong>小鹏GX上市，预售价39.98万元</strong></p>\\\\n  <p>36氪获悉，4月15日，小鹏大六座旗舰SUV小鹏GX上市，共推出增程和纯电两个版本，预售价39.98万元起。何小鹏在发布会上提到，小鹏GX是中国首款前装量产的Robotaxi原型车，完全按照L4自动驾驶标准打造，搭载四颗图灵芯片，有效算力达3000TOPS，搭载小鹏第二代VLA。</p>\\\\n  <p><strong>千问AI眼镜S1宣布正式开售</strong></p>\\\\n  <p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\\\\n  <p><strong>优步承诺投入100亿美元发展机器人出租车，实现战略转型</strong></p>\\\\n  <p>据英国金融时报4月15日报道，优步已承诺投入100多亿美元购买数千辆自动驾驶汽车，并参股其开发商，打破其轻资产的\\\"临时工经济\\\"业务模式，以避免机器人出租车的干扰。（新浪财经）</p>\\\\n  <p class=\\\"editor-note\\\"><strong>整理</strong>｜Kris</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'8点1氪\'}], \'author\': \'8点1氪\', \'author_detail\': {\'name\': \'8点1氪\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'美国将于4月20日启动关税退款系统，退还被裁定非法的1660亿美元关税，多家进口商已完成流程。\'}]}\", \"published_at\": \"2026-04-16 08:00:35\", \"ai_json_output\": \"\"}', '今日热点导览\n京东宣布推出“机器人救护车”\n抖音集团将投入5亿专项资金扶持真人短剧\n永辉超市38亿追款获胜，王健林等承担连带保证责任\n张雪机车LOGO抄袭？设计公司发声明回应\n小米汽车公布降噪处理新专利\nTOP 3大新闻\n美国将退还超1万亿元关税\n据路透社报道，美国特朗普政府计划于当地时间4月20日正式启动一个关税退款系统，用于向进口商退还1660亿美元（约合人民币1.13万亿元）的关税，这些关税在今年2月被美国最高法院裁定为“非法”。据报道，美国海关与边境保护局14日在一份提交给国际贸易法院的法庭文件中表示，已基本完成向进口商大规模退款的报关系统第一阶段研发，将于20日启动相关关税退款工作。退款将以电子方式统一发放，并在适用情况下附带利息，取代此前逐笔处理的方式。数据显示，截至4月9日，已有约5.6万家进口商完成电子退款流程，涉及总金额达1270亿美元（约合人民币8660亿元）。（央视财经）\n多家银行密集停发信用卡\n近期，民生银行、农业银行、交通银行等多家银行接连发布公告，宣布停止发行部分信用卡产品，涉及国有大行、股份制银行及地方银行，停发产品以联名信用卡为主，同时涵盖部分主题信用卡。多家中小银行也加入到停发信用卡的行列之中。比如，2025年年末，武汉农商银行发布公告称，因联名信用卡合作业务调整，现与联名方合作终止，将于2026年1月1日起停止发行淘票票&大麦联名信用卡；浙江农商联合银行也于2025年年底宣布，因业务合作调整，丰收京东联名卡将停止发行。\n此外，对于停发后的存量卡片，多家银行明确表示，持卡人手中的卡片在有效期内可正常使用，仅停止新增发行。若遇到损坏换卡、挂失补卡、到期换卡等情况，银行将根据不同规则处理，或换发同等级标准卡，或逐步更换为新版卡面，部分原产品的特殊功能与权益将不再提供。（界面新闻）\n滴露回应使用宠物消毒液后5只幼猫死亡\n4月15日，针对有消费者称“在使用滴露宠物消毒液拖地后，家中5只幼猫死亡”一事，\n滴露品牌母公司利洁时消费者热线工作人员回应新京报贝壳财经记者称，该产品经过安全性评估，“在依照标签正常使用的情况下，不会对宠物造成任何不良影响。”\n面对记者关于事件最新进展的追问，该工作人员表示，“暂时没有，无法获知更详细的情况。”\n据报道，有消费者称其于4月6日下午使用滴露消毒液（宠物家庭专用）在家里拖地，当晚11点左右，她发现家中5只幼猫全部死亡，“复盘下来，在那一天，我们唯一做的与之前不同的事情就是用这款消毒液拖了地”，该消费者表示，“之前家里都是大猫，那时候正常使用没有发现问题。”（新京报）\n大公司/大事件\n京东宣布推出“机器人救护车”\n4月15日，京东宣布正式推出“机器人救护车”，为人形机器人、四足机器人、AI陪伴机器人等提供维修保养服务，涵盖基础维修、故障诊断、换电补能、测试鉴定、美容保养、设备回收等。目前，京东“机器人救护车”已服务北京地区，未来三年，机器人上门维修服务还将拓展至全国超50个核心城市。（界面新闻）\n抖音集团将投入5亿专项资金扶持真人短剧\n4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。（第一财经）\n哈啰回应超量投放共享单车被行政处罚\n4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。（第一财经）\n永辉超市38亿追款获胜，王健林等承担连带保证责任\n时隔一年有余，永辉超市（601933.SH）针对大连御锦贸易有限公司（简称“大连御锦”）未按约支付万达商管股份转让款而进行的追款申请，获终局裁决支持。4月14日晚间，永辉超市发布公告称，近日收到上海国际经济贸易仲裁委员会(上海国际仲裁中心)(简称“上国仲”)送达的裁决书。根据裁决，第一被申请人大连御锦需向永辉超市支付剩余股份转让价款和加速到期违约金等共计38.57亿元。第二被申请人王健林、第三被申请人孙喜双、第四被申请人大连一方集团对上述债务承担连带保证责任。（界面新闻）\n张雪机车LOGO抄袭？设计公司发声明回应\n针对张雪机车品牌LOGO疑似抄袭一事，4月14日，杭州巴顿品牌设计有限公司发布声明称，本次LOGO设计由巴顿独立创作完成，相关商标已向国家知识产权局申请并核准注册。该公司表示，欢迎并支持任何认为侵犯其权利的主体通过司法途径解决问题。据了解，张雪机车创始人张雪曾表示，张雪机车的LOGO是找了杭州一家设计公司，包括视觉及店面形象等，花了40万元。（界面新闻）\n拟赴港上市？接近度小满人士：不实\n近日，有关度小满最快将于2026年上半年向港交所递交招股书，拟主板挂牌上市的信息在社交媒体传播。从接近度小满人士处独家获悉，相关信息不实，系对传闻的拼凑与虚构。公司已通过法律途径维护合法权益，并将追究相关方责任。（界面新闻）\n飞天茅台全线上涨，26年飞天原箱批价报1665元/瓶\n36氪获悉，“今日酒价”披露的最新批发参考价显示，4月15日，26年飞天茅台原箱报1665元/瓶，较上一日上涨5元；26年飞天茅台散瓶报1565元/瓶，与上日价格持平。25年飞天茅台原箱报1675元/瓶，较上一日上涨5元；25年飞天茅台散瓶报1610元/瓶，较上一日上涨10元。\n现货黄金向下跌破4800美元\n36氪获悉，现货黄金向下跌破4800美元，日内下跌0.89%。\n传抖音电商将迎调整，成立红果电商，官方暂无回应\n有市场消息称，抖音电商将迎调整，成立红果电商，架构在中国电商下，与行业产品、用户产品等部门平级。对此消息，抖音官方暂无回应。（新浪财经）\n广电总局发布微短剧精品创作传播计划\n15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。（新华社）\nLululemon回应被指使用致癌化学物：称国内在售产品不含PFAS\n针对产品涉嫌含致癌化学物被调查一事，4月14日，Lululemon方面向中新网表示，Lululemon目前国内所有在售产品均不含全氟和多氟烷基物质（PFAS），且符合相关法律法规及国家和行业标准。此前，据路透社报道，美国得克萨斯州总检察长肯·帕克斯顿已对知名运动品牌Lululemon展开调查，此次调查将查明Lululemon的运动服装是否含有“永久性化学物质”全氟和多氟烷基物质，该类化学物质在自然界中不易分解。帕克斯顿提到，最新研究结果与消费者担忧引发了人们的质疑：服装中的某些合成材料，是否可能与内分泌紊乱、不孕不育、癌症和其他健康风险有关。（中国新闻网）\n小米汽车公布降噪处理新专利\n36氪获悉，爱企查App显示，近日，小米汽车科技有限公司申请的“降噪处理方法、装置、车辆及存储介质”专利公布。摘要显示，该专利基于车辆的误差信号和加速度计信号识别车辆所处的噪声场景，并将加速度计信号分解为多个互不重叠的子带信号，再结合各子带信号对应的降噪处理参数进行自适应滤波，得到全频带降噪信号。该方案能够对复杂、多谱结构噪声进行高效分治与响应，提升降噪效果，进而提升用户的用车体验感。\n30年期国债期货创新高，机构看多超长债行情\n在资金面持续宽松与外部扰动阶段性缓和的背景下，债券市场近期整体走强，超长端利率债表现尤为突出。4月14日，30年期国债期货创近1个月新高，带动债市情绪明显回暖。多家机构认为，在配置力量回归、供需结构优化及宏观基本面逐步验证的支撑下，债市“配置牛”逻辑正在强化，超长债投资价值进一步凸显。（上证报）\n美股三大指数收盘涨跌不一，纳指11连涨创收盘新高\n36氪获悉，4月15日收盘，美股三大指数涨跌不一，纳指涨1.59%，为连续11个交易日上涨并创收盘新高，这11个交易日累计涨幅超15%，标普500指数涨0.8%创历史新高，道指跌0.15%。大型科技股普涨，特斯拉涨超7%，微软涨超4%，苹果涨近3%，英伟达、谷歌、Meta涨超1%。热门中概股涨跌不一，百度涨超2%，阿里巴巴、腾讯音乐涨超1%，理想汽车跌超3%，蔚来跌超2%，小鹏集团跌超1%。\n奈飞公司CEO与美国影院行业负责人举行会谈，双方未来或将合作\n美国一年一度的电影产业盛会——电影博览会于4月13日至16日在拉斯维加斯举行。该博览会的组织方“联合影院”，也就是曾经的美国全国影院主协会主席迈克尔•奥利里4月14日表示，奈飞公司首席执行官特德·萨兰多斯12日与该组织的代表们举行了一次“建设性的会谈”。对于奈飞公司此次与影院方面进行的会谈，奥利里认为，双方目前都认识到需要寻求互助合作，以建立一套更具互补性的商业模式。他同时表示，双方4月12日只是进行了初步会谈，并未达成任何协议。但他依然对奈飞公司所展现出的意愿表示赞赏。截至目前，奈飞公司尚未对上述事宜发表评论。（央视新闻）\nKKR将通过购买可转换债券向三星SDS投资8.2亿美元\n当地时间4月14日，美国私募股权巨头KKR宣布，将通过收购可转换债券向三星SDS投资1.22万亿韩元（约合8.2亿美元）。根据合作协议，KKR将通过其管理的基金，与三星SDS就一系列旨在为该公司创造价值的举措展开紧密合作，包括支持有机与非有机增长战略、加速该公司作为全栈式人工智能解决方案提供商的扩张，以及拓展新业务领域。KKR还将积极为三星SDS管理团队提供咨询服务，特别是在并购、资本配置以及支持公司寻求全球战略增长机遇等方面。（界面新闻）\n苹果官微发文提醒iPhone用户立即更新设备\n36氪获悉，4月15日，苹果官微发文表示，安全研究人员最近发现，存在一些基于网页的攻击，它们会借助恶意网页内容，对过时版本的iOS发起攻击。例如，如果用户使用的是较旧版本的iOS，一旦点按恶意链接或访问被入侵的网站，iPhone上的数据就可能面临被盗的风险。在发现这些问题后，苹果进行了全面调查，并在第一时间针对最新的操作系统版本发布了软件更新，旨在解决相关漏洞，阻断这类攻击。如果用户的iPhone运行的是较旧版本的iOS，请立即更新以保护数据安全。无法更新设备的用户，如果设备支持，可考虑启用锁定模式，以防范恶意网页内容及其他威胁。\n苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%\n根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。（财联社）\n博通宣布与Meta扩大合作，总裁兼CEO陈福阳将转任Meta顾问\n当地时间4月14日，博通公司与Meta宣布达成多年多代战略合作，以支持Meta快速扩展的人工智能计算基础设施。基于现有合作基础，博通将为Meta训练与推理加速器（MTIA）芯片提供技术支持，双方计划将合作延续至2029年。该技术将成为Meta部署尖端AI数据中心的基础架构核心。首期合作规模超过1吉瓦。鉴于此次扩展合作的规模，陈福阳（Hock Tan）将从Meta董事会卸任，转任Meta顾问角色，他将为Meta的定制芯片路线图提供指导。（新浪财经）\n马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一\n特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。（界面新闻）\n英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节\n根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武4月10日向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。（新浪财经）\n苹果CEO库克斥资106万美元增持耐克\n当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。（界面新闻）\n风险投资机构争相向Anthropic抛出投资要约，估值最高达8000亿美元\n据多位知情人士透露，近几周来，开发了Claude的初创公司Anthropic已收到多家风投机构的投资要约，对其估值最高达到8000亿美元，较最近估值翻了一倍有余。备受市场追捧的初创公司常会收到投资者主动提前抛出的要约，但往往会予以回绝。尽管如此，风投机构给出的估值水平仍反映出，随着Anthropic准备在今年晚些时候可能进行IPO，硅谷对入股该公司的需求已近乎狂热。（新浪财经）\nAI最前沿\nOpenAI向部分用户发布Cyber模型，与Mythos展开竞争\nOpenAI允许特定用户访问一款更擅长发现软件安全漏洞的新模型。就在一周前，竞争对手Anthropic PBC宣布小范围发布人工智能工具Mythos。这家ChatGPT开发商4月14日表示，已开始推出GPT-5.4-Cyber模型，目标是发现软件中的问题，以便组织加以修复。OpenAI称，该模型在用于此类任务时对用户探测方式的限制也更少。（新浪财经）\nOpenAI推出旨在增强网络安全能力的迭代模型\n美国开放人工智能研究中心（OpenAI）14日宣布推出GPT-5.4的迭代模型GPT-5.4-Cyber，旨在增强网络安全能力；并宣布扩大其“网络安全可信访问”项目，将向经审核验证的网络安全人员和团队开放。（新华社）\n阿里ATH事业群发布首款AI开发工具秒悟\n36氪获悉，4月15日，阿里ATH事业群发布旗下首款AI开发工具Meoo（秒悟），该工具集成千问、Kimi、GLM、MiniMax四大模型，并内置阿里云数据库、存储等核心产品服务，用户只需用自然语言描述想法，Meoo最快1分钟就能自动生成前端后端完整的网站、H5页面，在阿里云上一键部署上线。\n腾讯轻量云独家上线Hermes Agent应用模板\n36氪获悉，4月14日，腾讯云轻量应用服务器Lighthouse正式上线Hermes Agent专属应用模板，行业首家实现该开源AI智能体的云端一键快速部署，其企业级ClawPro产品也将于本周内完成适配支持。依托轻量化云服务器的便捷特性，开发者无需复杂配置，即可快速完成Hermes Agent的云端搭建与运行。\n算力紧缺之下，Anthropic调整定价模式，按企业AI使用量计费\nAnthropic发言人证实，根据此次定价调整，Claude企业版客户除每月为每位用户支付20美元固定费用外，还需按使用软件时消耗的算力容量额外付费。Claude企业版是面向大型企业推出的产品组合，已推出两年，目前包含代码工具ClaudeCode及办公助手ClaudeCowork。（新浪财经）\n大公司财报\n爱马仕第一季度总收入为40.7亿欧元，销售额同比增长5.6%\n4月15日，爱马仕公布第一季度业绩报告，第一季度总收入为40.7亿欧元。第一季度销售额同比增长5.6%，其中，按地区划分来看，欧洲地区销售额总计增长4.5%，亚洲地区总计增长3.5%，美洲增长17.2%，其他地区为增长5.9%；按行业划分来看，皮革制品与马具销售额增长9.4%，成衣与配饰增长0.4%，丝绸与纺织品增长7.8%等。（界面新闻）\n宁德时代：一季度净利润207.38亿元，同比增长48.52%\n36氪获悉，宁德时代发布一季度报告，一季度实现营收1291.31亿元，同比增长52.45%；归属于上市公司股东的净利润207.38亿元，同比增长48.52%。\n蓝色光标：2025年净利润2.25亿元，同比扭亏\n36氪获悉，蓝色光标披露年报，2025年实现营业收入686.93亿元，同比增长12.99%；归属于上市公司股东的净利润2.25亿元，上年同期亏损2.91亿元；基本每股收益0.063元。公司拟每10股派发现金红利0.1元（含税）。\n阿斯麦第一季度营收87.67亿欧元，高于市场预期\n4月15日，阿斯麦公布第一季度业绩报告，第一季度净销售额为87.67亿欧元，市场预估为86.9亿欧元；净利润为27.6亿欧元，市场预估为25.6亿欧元。阿斯麦预计2026年第二季度总净销售额将在84亿至90亿欧元之间，预计2026年总净销售额在360亿至400亿欧元之间。（界面新闻）\n多氟多：2025年净利润2.13亿元，同比扭亏\n36氪获悉，多氟多披露年报，2025年实现营业收入94.34亿元，同比增长14.37%；归属于上市公司股东的净利润2.13亿元，上年同期亏损3.08亿元；基本每股收益0.18元。公司拟每10股派发现金红利2元（含税）。\n投融资\n自动驾驶初创公司Glydways洽谈2.5亿美元融资\n4月15日消息，据报道，由山姆·奥特曼支持的自动驾驶汽车初创公司Glydways正在洽谈新一轮融资，计划筹集2.5亿美元，这将使公司估值达到10亿美元或更高。Glydways此前刚刚完成1.7亿美元的融资，估值接近7亿美元。（界面新闻）\n“智象未来”完成超5亿元新一轮融资\n36氪获悉，近日，国内多模态生成式人工智能公司“智象未来”宣布完成超5亿元新一轮融资。本轮融资由东方富海、安徽省投资集团旗下的省产业投资公司、峰华资本等新股东联合投资，同时合肥产投、兴泰集团、合肥高投、安徽省人工智能母基金等老股东持续加注。本轮融资将主要用于智象独创的下一代原生全模态世界模型研发、企业服务智能体的产品建设以及全球市场拓展。\n“达美盛（DMS）”完成新一轮过亿元股权融资\n36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。\n“源升智能”完成上亿元Pre-A轮融资\n36氪获悉，“源升智能”宣布完成上亿元Pre-A轮融资。本轮融资由达晨财智、老股东春华创投共同领投，渶策资本、南山战新投跟投，老股东弘晖基金超额跟投。本轮融资将用于Apex Hand的产能扩充与批量交付、灵巧操作平台生态建设以及全球化市场拓展，以此巩固在高性能灵巧手领域的技术优势，加速具身智能在真实工业场景中的落地。这也是公司一年内完成的第5轮融资，累计融资金额达数亿元。\n酷产品\n菜鸟发布攀爬机器人ZeeBot，实测智能化存取效率提升一倍\n36氪获悉，4月15日，菜鸟集团在美国亚特兰大举行的MODEX 2026国际物流展上发布了首款自研的“攀爬机器人”ZeeBot，并确认首个由攀爬机器人智能作业的仓储项目已在广东省交付使用。实测数据显示，该技术使仓库存取效率提升了100%。\n小鹏GX上市，预售价39.98万元\n36氪获悉，4月15日，小鹏大六座旗舰SUV小鹏GX上市，共推出增程和纯电两个版本，预售价39.98万元起。何小鹏在发布会上提到，小鹏GX是中国首款前装量产的Robotaxi原型车，完全按照L4自动驾驶标准打造，搭载四颗图灵芯片，有效算力达3000TOPS，搭载小鹏第二代VLA。\n千问AI眼镜S1宣布正式开售\n36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。\n优步承诺投入100亿美元发展机器人出租车，实现战略转型\n据英国金融时报4月15日报道，优步已承诺投入100多亿美元购买数千辆自动驾驶汽车，并参股其开发商，打破其轻资产的\"临时工经济\"业务模式，以避免机器人出租车的干扰。（新浪财经）\n整理\n｜Kris', '2026-04-16 08:00:35', '2026-04-16 11:54:00');
INSERT INTO `news_detail` VALUES (27, 1022, 20, '其他', '俄工贸部长:俄方希望与中方寻找双边贸易新增长点', '', '原标题：专访：俄方希望与中方寻找双边贸易新增长点――访俄罗斯工业和贸易部长曼图罗夫\n　　新华社记者栾海　高兰\n　　“在当前贸易保护主义抬头背景下，俄方希望与中方共同应对风险，化消极因素为机遇，寻找俄中贸易的新增长点”，俄罗斯工业和贸易部长丹尼斯・曼图罗夫日前....', 'http://go.rss.sina.com.cn/redirect.php?url=http://news.sina.com.cn/o/2018-09-23/doc-ihkmwytn7036240.shtml', 0, '', '{\"summary\": \"帮助出海企业掌握中俄双边贸易最新合作动向，把握潜在贸易新机遇，应对当前贸易领域风险\", \"abstract\": \"本文是新华社对俄罗斯工业和贸易部长曼图罗夫的专访。当前全球贸易保护主义抬头，俄方表示希望同中方共同应对贸易相关风险。俄方提出将消极因素转化为机遇，共同寻找俄中双边贸易的新增长点。本文传递了俄中期待深化双边贸易合作的积极信号\", \"keywords\": [\"中俄贸易\", \"双边贸易\", \"贸易增长点\", \"贸易保护主义\", \"出海机遇\"], \"policy_risk\": {\"market_risk\": \"当前全球贸易保护主义抬头，给中俄双边贸易带来市场风险\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"其他\"}', '', '{\"url\": \"http://go.rss.sina.com.cn/redirect.php?url=http://news.sina.com.cn/o/2018-09-23/doc-ihkmwytn7036240.shtml\", \"title\": \"俄工贸部长:俄方希望与中方寻找双边贸易新增长点\", \"source\": \"http://rss.sina.com.cn/news/china/focus15.xml\", \"content\": \"原标题：专访：俄方希望与中方寻找双边贸易新增长点――访俄罗斯工业和贸易部长曼图罗夫\\n　　新华社记者栾海　高兰\\n　　“在当前贸易保护主义抬头背景下，俄方希望与中方共同应对风险，化消极因素为机遇，寻找俄中贸易的新增长点”，俄罗斯工业和贸易部长丹尼斯・曼图罗夫日前....\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'俄工贸部长:俄方希望与中方寻找双边贸易新增长点\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'http://rss.sina.com.cn/news/china/focus15.xml\', \'value\': \'俄工贸部长:俄方希望与中方寻找双边贸易新增长点\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://go.rss.sina.com.cn/redirect.php?url=http://news.sina.com.cn/o/2018-09-23/doc-ihkmwytn7036240.shtml\'}], \'link\': \'http://go.rss.sina.com.cn/redirect.php?url=http://news.sina.com.cn/o/2018-09-23/doc-ihkmwytn7036240.shtml\', \'authors\': [{\'name\': \'WWW.SINA.COM.CN\'}], \'author\': \'WWW.SINA.COM.CN\', \'author_detail\': {\'name\': \'WWW.SINA.COM.CN\'}, \'id\': \'http://go.rss.sina.com.cn/redirect.php?url=http://news.sina.com.cn/o/2018-09-23/doc-ihkmwytn7036240.shtml\', \'guidislink\': False, \'tags\': [{\'term\': \'