INSERT INTO `news_detail` VALUES (28, 1031, 6, '科技与数字服务', '香港与联合国工发组织签署联合文告 共同推动工业合作..', '', '<a href=\"http://baijiahao.baidu.com/s?id=1862458676951507393\"><img src=\"http://t1.baidu.com/it/u=http%3A%2F%2Ft10.baidu.com%2Fit%2Fu%3D1332654918%2C294127940%26fm%3D30%26app%3D106%26f%3DJPEG%3Fw%3D312%26h%3D208%26s%3D67B038C44CCA455D0C04513A03008050&amp;fm=30\"></a><br>中新社香港4月14日电香港特区政府创新科技及工业局(简称“创科局”)与联合国工业发展组织(简称“工发组织”)14日在香港签署有关推动工业发展、创新及数字转型合作的联合文告。香港特区行政长官李家超于当日<br>', 'http://baijiahao.baidu.com/s?id=1862458676951507393', 0, '', '{\"summary\": \"本文通报香港与联合国工发组织签署工业创新合作文告，为出海企业提供潜在国际合作机遇\", \"abstract\": \"4月14日，香港特区政府创新科技及工业局与联合国工业发展组织在香港签署联合文告。双方约定共同推动工业发展、创新及数字转型领域的合作，香港特区行政长官李家超出席了本次活动。该合作有望为有意拓展国际市场的出海企业带来新的合作机会。\", \"keywords\": [\"香港\", \"联合国工发组织\", \"工业合作\", \"数字转型\", \"创新科技\", \"出海合作\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"http://baijiahao.baidu.com/s?id=1862458676951507393\", \"title\": \"香港与联合国工发组织签署联合文告 共同推动工业合作..\", \"source\": \"http://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\", \"content\": \"<a href=\\\"http://baijiahao.baidu.com/s?id=1862458676951507393\\\"><img src=\\\"http://t1.baidu.com/it/u=http%3A%2F%2Ft10.baidu.com%2Fit%2Fu%3D1332654918%2C294127940%26fm%3D30%26app%3D106%26f%3DJPEG%3Fw%3D312%26h%3D208%26s%3D67B038C44CCA455D0C04513A03008050&amp;fm=30\\\"></a><br>中新社香港4月14日电香港特区政府创新科技及工业局(简称“创科局”)与联合国工业发展组织(简称“工发组织”)14日在香港签署有关推动工业发展、创新及数字转型合作的联合文告。香港特区行政长官李家超于当日<br>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'香港与联合国工发组织签署联合文告 共同推动工业合作..\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'香港与联合国工发组织签署联合文告 共同推动工业合作..\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://baijiahao.baidu.com/s?id=1862458676951507393\'}], \'link\': \'http://baijiahao.baidu.com/s?id=1862458676951507393\', \'published\': \'2026-04-16T02:49:54.000Z\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=49, tm_sec=54, tm_wday=3, tm_yday=106, tm_isdst=0), \'source\': {}, \'authors\': [{}], \'author\': \'\', \'summary\': \'<a href=\\\"http://baijiahao.baidu.com/s?id=1862458676951507393\\\" target=\\\"_blank\\\"><img border=\\\"0\\\" src=\\\"http://t1.baidu.com/it/u=http%3A%2F%2Ft10.baidu.com%2Fit%2Fu%3D1332654918%2C294127940%26fm%3D30%26app%3D106%26f%3DJPEG%3Fw%3D312%26h%3D208%26s%3D67B038C44CCA455D0C04513A03008050&amp;fm=30\\\" /></a><br />中新社香港4月14日电香港特区政府创新科技及工业局(简称“创科局”)与联合国工业发展组织(简称“工发组织”)14日在香港签署有关推动工业发展、创新及数字转型合作的联合文告。香港特区行政长官李家超于当日<br />\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'<a href=\\\"http://baijiahao.baidu.com/s?id=1862458676951507393\\\" target=\\\"_blank\\\"><img border=\\\"0\\\" src=\\\"http://t1.baidu.com/it/u=http%3A%2F%2Ft10.baidu.com%2Fit%2Fu%3D1332654918%2C294127940%26fm%3D30%26app%3D106%26f%3DJPEG%3Fw%3D312%26h%3D208%26s%3D67B038C44CCA455D0C04513A03008050&amp;fm=30\\\" /></a><br />中新社香港4月14日电香港特区政府创新科技及工业局(简称“创科局”)与联合国工业发展组织(简称“工发组织”)14日在香港签署有关推动工业发展、创新及数字转型合作的联合文告。香港特区行政长官李家超于当日<br />\'}}\", \"published_at\": \"2026-04-16 02:49:54\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 02:49:54', '2026-04-16 11:56:30');
INSERT INTO `news_detail` VALUES (29, 1047, 19, '跨境支付与金融配套', '事关调整银行业金融机构境外贷款业务 两部门最新通知', '', '中新网4月15日电据央行网站消息，中国人民银行、国家外汇管理局日前发布《关于调整银行业金融机构境外贷款业务有关事宜的通知(银发〔2026〕72号)》。其中明确，将境内外商独资银行、境内中外合资银行、外<br>', 'http://baijiahao.baidu.com/s?id=1862524613725695168', 0, '', '{\"summary\": \"本文公布两部门调整银行业金融机构境外贷款业务的最新政策，帮助出海相关主体掌握跨境金融政策动态\", \"abstract\": \"中国人民银行与国家外汇管理局日前发布调整银行业金融机构境外贷款业务的通知。本次通知对境内外资相关银行的境外贷款业务事宜作出明确调整。该政策调整将对跨境境外贷款业务开展产生影响。相关政策消息已通过央行官方渠道对外公布\", \"keywords\": [\"境外贷款\", \"政策调整\", \"跨境金融\", \"银行业金融机构\", \"中国人民银行\", \"国家外汇管理局\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"中国人民银行、国家外汇管理局发布《关于调整银行业金融机构境外贷款业务有关事宜的通知》，对银行业金融机构境外贷款业务进行调整，明确涉及境内外商独资银行、境内中外合资银行相关业务\"}, \"topic_cluster\": \"跨境金融配套\", \"industry_category\": \"跨境支付与金融配套\"}', '', '{\"url\": \"http://baijiahao.baidu.com/s?id=1862524613725695168\", \"title\": \"事关调整银行业金融机构境外贷款业务 两部门最新通知\", \"source\": \"http://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\", \"content\": \"中新网4月15日电据央行网站消息，中国人民银行、国家外汇管理局日前发布《关于调整银行业金融机构境外贷款业务有关事宜的通知(银发〔2026〕72号)》。其中明确，将境内外商独资银行、境内中外合资银行、外<br>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'事关调整银行业金融机构境外贷款业务 两部门最新通知\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'事关调整银行业金融机构境外贷款业务 两部门最新通知\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://baijiahao.baidu.com/s?id=1862524613725695168\'}], \'link\': \'http://baijiahao.baidu.com/s?id=1862524613725695168\', \'published\': \'2026-04-16T02:49:54.000Z\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=49, tm_sec=54, tm_wday=3, tm_yday=106, tm_isdst=0), \'source\': {}, \'authors\': [{}], \'author\': \'\', \'summary\': \'中新网4月15日电据央行网站消息，中国人民银行、国家外汇管理局日前发布《关于调整银行业金融机构境外贷款业务有关事宜的通知(银发〔2026〕72号)》。其中明确，将境内外商独资银行、境内中外合资银行、外<br />\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'中新网4月15日电据央行网站消息，中国人民银行、国家外汇管理局日前发布《关于调整银行业金融机构境外贷款业务有关事宜的通知(银发〔2026〕72号)》。其中明确，将境内外商独资银行、境内中外合资银行、外<br />\'}}\", \"published_at\": \"2026-04-16 02:49:54\", \"ai_json_output\": \"\"}', '百度首页\n登录\n搜索\n复制\n事关调整银行业金融机构境外贷款业务 两部门最新通知\n中国新闻网\n2026-04-15 16:28\n北京中新网信息科技有限公司官方账号\n关注\n中新网4月15日电 据央行网站消息，中国人民银行、国家外汇管理局日前发布《关于调整银行业金融机构境外贷款业务有关事宜的通知(银发〔2026〕72号)》。其中明确，将境内外商独资银行、境内中外合资银行、外国银行境内分行的境外贷款杠杆率由0.5上调至1.5，香港特别行政区、澳门特别行政区和台湾地区的金融机构在内地(大陆)设立的银行机构比照适用。将进出口银行的境外贷款杠杆率由3上调至3.5。如计算的境外贷款余额上限小于100亿元，核定该银行境外贷款余额上限为100亿元。\n通知全文如下：\n中国人民银行 国家外汇管理局关于调整银行业金融机构境外贷款业务有关事宜的通知(银发〔2026〕72号)\n中国人民银行上海总部，各省、自治区、直辖市及计划单列市分行；国家外汇管理局各省、自治区、直辖市及计划单列市分局；国家开发银行，各政策性银行、国有商业银行，中国邮政储蓄银行，各股份制商业银行：\n为更好发挥金融服务实体经济、促进贸易投资便利化作用，现就银行业金融机构境外贷款业务有关事宜通知如下：\n一、将境内外商独资银行、境内中外合资银行、外国银行境内分行的境外贷款杠杆率由0.5上调至1.5，香港特别行政区、澳门特别行政区和台湾地区的金融机构在内地(大陆)设立的银行机构比照适用。将进出口银行的境外贷款杠杆率由3上调至3.5。如计算的境外贷款余额上限小于100亿元，核定该银行境外贷款余额上限为100亿元。\n二、境内银行通过向境外银行融出资金等方式间接向境外企业发放一年期以上本外币贷款的，可由境外银行依据其所在国家或地区相关法律法规办理。\n本通知自发布之日起实施。《中国人民银行 国家外汇管理局关于银行业金融机构境外贷款业务有关事宜的通知》(银发〔2022〕27号)第七条中“境内银行通过向境外银行融出资金等方式间接向境外企业发放一年期以上本外币贷款的，原则上应要求境外银行等直接债权人参照本条规定办理”的规定不再适用。银行业金融机构境外贷款业务的其他事宜仍按照银发〔2022〕27号文执行。\n中国人民银行\n国家外汇管理局\n2026年4月11日\n举报/反馈\n0\n0\n收藏\n分享\n微信好友\n新浪微博\n复制链接\n扫码分享至微信\n设为首页\n© Baidu\n使用百度前必读\n京ICP证030173号\n京公网安备11000002000001号', '2026-04-16 02:49:54', '2026-04-16 11:58:18');
INSERT INTO `news_detail` VALUES (30, 1048, 14, '合规与政策服务', '香港律政司首次推出支援出海法律专业服务名册', '', '新华社香港4月14日电　香港特区政府律政司14日首次发布《支援“出海”香港法律专业服务提供者名册》，涵盖逾70个香港法律服务单位，协助内地企业按出海服务具体需求与香港法律专业服务精准对接，促进内地企业<br>', 'http://baijiahao.baidu.com/s?id=1862454429686789109', 0, '', '{\"summary\": \"本文介绍香港律政司推出的出海法律服务名册，可帮助内地出海企业精准对接香港法律资源，满足出海法律需求\", \"abstract\": \"香港特区政府律政司于4月14日首次发布《支援“出海”香港法律专业服务提供者名册》。该名册涵盖超过70个香港法律服务单位。推出名册旨在协助内地出海企业根据自身具体需求，精准对接香港法律专业服务，为内地企业出海提供法律支持\", \"keywords\": [\"企业出海\", \"香港律政司\", \"法律服务名册\", \"香港法律服务\", \"内地企业\", \"出海对接\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"香港律政司首次推出《支援“出海”香港法律专业服务提供者名册》，涵盖逾70个香港法律服务单位，协助内地出海企业对接香港法律专业服务\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"http://baijiahao.baidu.com/s?id=1862454429686789109\", \"title\": \"香港律政司首次推出支援出海法律专业服务名册\", \"source\": \"http://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\", \"content\": \"新华社香港4月14日电　香港特区政府律政司14日首次发布《支援“出海”香港法律专业服务提供者名册》，涵盖逾70个香港法律服务单位，协助内地企业按出海服务具体需求与香港法律专业服务精准对接，促进内地企业<br>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'香港律政司首次推出支援出海法律专业服务名册\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'香港律政司首次推出支援出海法律专业服务名册\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://baijiahao.baidu.com/s?id=1862454429686789109\'}], \'link\': \'http://baijiahao.baidu.com/s?id=1862454429686789109\', \'published\': \'2026-04-16T02:49:54.000Z\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=49, tm_sec=54, tm_wday=3, tm_yday=106, tm_isdst=0), \'source\': {}, \'authors\': [{}], \'author\': \'\', \'summary\': \'新华社香港4月14日电\\\\u3000香港特区政府律政司14日首次发布《支援“出海”香港法律专业服务提供者名册》，涵盖逾70个香港法律服务单位，协助内地企业按出海服务具体需求与香港法律专业服务精准对接，促进内地企业<br />\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'新华社香港4月14日电\\\\u3000香港特区政府律政司14日首次发布《支援“出海”香港法律专业服务提供者名册》，涵盖逾70个香港法律服务单位，协助内地企业按出海服务具体需求与香港法律专业服务精准对接，促进内地企业<br />\'}}\", \"published_at\": \"2026-04-16 02:49:54\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 02:49:54', '2026-04-16 11:58:48');
INSERT INTO `news_detail` VALUES (31, 1049, 18, '硬件与半导体出海', '氪星晚报｜Snap宣布将裁员约1000人；字节启动新一轮期权回购；苹果CEO库克斥资106万美元增持耐克', '', '<h2><strong>大公司：</strong></h2>\n<p><a href=\"https://36kr.com/newsflashes/3767932351709953\"><strong>Snap宣布将裁员约1000人</strong></a></p>\n<p>4月15日，社交媒体公司Snap宣布一系列调整，这些调整将影响Snap约1000名团队成员，包括16%的全职员工，此外，公司还将关闭300多个空缺职位。通过调整，公司预计到2026年下半年，年度成本将减少超过5亿美元。Snap表示，对即将离职的美国团队成员，公司将提供四个月的遣散费、医疗保险和股权激励，以及职业转型支持。在美国以外地区，公司将遵循当地流程，并努力提供符合当地规范的同等支持。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767334817088009\"><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></a></p>\n<p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武上周五向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI 和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767370241163780\"><strong>特斯拉高管称上海工厂将为擎天柱机器人量产提供“金钥匙”</strong></a></p>\n<p>特斯拉中国区总经理王昊表示，特斯拉最大的生产基地——上海超级工厂未来有潜力生产人形机器人。该工厂的高效生产和创新能力被视为推动CEO埃隆·马斯克快速实现该技术商业化的关键因素。王昊在周二的一次发布会上表示，CEO马斯克曾指出，大规模生产是制造人形机器人的一个关键挑战。他认为上海制造部门是“解决这一挑战的金钥匙”，但没有具体说明运营将如何支持公司的机器人业务。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767922444927496\"><strong>字节启动新一轮期权回购</strong></a></p>\n<p>字节发布内部邮件，启动最新一轮期权回购。其中：在职员工：229.5美元/股（约人民币1588元）离职员工：201.96美元/股（约人民币1397元）。字节上一轮回购期权时间是2025年10月，此次在职员工的回购价对比上一轮提升约14.5%。在2025年10月的回购中，在职员工回购价200.41美元，离职员工180.37美元。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767891011682823\"><strong>广电总局发布微短剧精品创作传播计划</strong></a></p>\n<p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767882377216772\"><strong>哈啰回应超量投放共享单车被行政处罚</strong></a></p>\n<p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767791865398021\"><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></a></p>\n<p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767786531488516\"><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></a></p>\n<p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。</p>\n<h2><strong>新产品：</strong></h2>\n<p><a href=\"https://36kr.com/newsflashes/3767467065803529\"><strong>千问AI眼镜S1宣布正式开售</strong></a></p>\n<p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\n<h2><strong>投融资：</strong></h2>\n<p><a href=\"https://36kr.com/newsflashes/3767950609203972\"><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></a></p>\n<p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\n<p><a href=\"https://36kr.com/newsflashes/3767826218140166\"><strong>苹果CEO库克斥资106万美元增持耐克</strong></a></p>\n<p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。</p>\n<h2><strong>今日观点：</strong></h2>\n<p><a href=\"https://36kr.com/newsflashes/3767782898795266\"><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></a></p>\n<p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。</p>\n<h2><strong>其他值得关注的新闻：</strong></h2>\n<p><a href=\"https://36kr.com/newsflashes/3767830158820100\"><strong>李成钢会见美国福特汽车公司全球执行副总裁兼首席政务官柯立</strong></a></p>\n<p>4月13日，商务部国际贸易谈判代表兼副部长李成钢在京会见美国福特汽车公司全球执行副总裁兼首席政务官柯立。双方就中美经贸关系、福特公司在华发展等进行了交流。</p>', 'https://36kr.com/p/3767970803221251?f=rss', 0, '', '{\"summary\": \"本文汇总全球科技互联网领域头部企业最新动态，可为出海企业把握全球行业趋势提供参考\", \"abstract\": \"本文是氪星晚报的行业新闻汇总，涵盖大公司动态、新产品、投融资等多个板块。文中提到苹果正在提升印度iPhone产能，预计印度全球iPhone组装份额将在2027年达到30-35%，特斯拉上海超级工厂被认为将助力擎天柱人形机器人量产。同时还涵盖Snap裁员、字节跳动新一轮期权回购、国内出台微短剧扶持政策等多个行业热点事件，帮助读者快速掌握全球科技行业最新变动\", \"keywords\": [\"印度市场\", \"产能布局\", \"AI芯片\", \"人形机器人\", \"期权回购\", \"微短剧\", \"芯片制造\"], \"policy_risk\": {\"market_risk\": \"全球科技企业面临经营成本压力，社交媒体公司Snap宣布裁员约1000人削减年度运营成本\", \"policy_compliance\": \"国家广播电视总局发布微短剧精品创作传播计划，推动微短剧行业向精品化、数智化、产业化、国际化发展\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://36kr.com/p/3767970803221251?f=rss\", \"title\": \"氪星晚报｜Snap宣布将裁员约1000人；字节启动新一轮期权回购；苹果CEO库克斥资106万美元增持耐克\", \"source\": \"https://36kr.com/feed\", \"content\": \"<h2><strong>大公司：</strong></h2>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767932351709953\\\"><strong>Snap宣布将裁员约1000人</strong></a></p>\\n<p>4月15日，社交媒体公司Snap宣布一系列调整，这些调整将影响Snap约1000名团队成员，包括16%的全职员工，此外，公司还将关闭300多个空缺职位。通过调整，公司预计到2026年下半年，年度成本将减少超过5亿美元。Snap表示，对即将离职的美国团队成员，公司将提供四个月的遣散费、医疗保险和股权激励，以及职业转型支持。在美国以外地区，公司将遵循当地流程，并努力提供符合当地规范的同等支持。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767334817088009\\\"><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></a></p>\\n<p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武上周五向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI 和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767370241163780\\\"><strong>特斯拉高管称上海工厂将为擎天柱机器人量产提供“金钥匙”</strong></a></p>\\n<p>特斯拉中国区总经理王昊表示，特斯拉最大的生产基地——上海超级工厂未来有潜力生产人形机器人。该工厂的高效生产和创新能力被视为推动CEO埃隆·马斯克快速实现该技术商业化的关键因素。王昊在周二的一次发布会上表示，CEO马斯克曾指出，大规模生产是制造人形机器人的一个关键挑战。他认为上海制造部门是“解决这一挑战的金钥匙”，但没有具体说明运营将如何支持公司的机器人业务。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767922444927496\\\"><strong>字节启动新一轮期权回购</strong></a></p>\\n<p>字节发布内部邮件，启动最新一轮期权回购。其中：在职员工：229.5美元/股（约人民币1588元）离职员工：201.96美元/股（约人民币1397元）。字节上一轮回购期权时间是2025年10月，此次在职员工的回购价对比上一轮提升约14.5%。在2025年10月的回购中，在职员工回购价200.41美元，离职员工180.37美元。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767891011682823\\\"><strong>广电总局发布微短剧精品创作传播计划</strong></a></p>\\n<p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767882377216772\\\"><strong>哈啰回应超量投放共享单车被行政处罚</strong></a></p>\\n<p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767791865398021\\\"><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></a></p>\\n<p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767786531488516\\\"><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></a></p>\\n<p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。</p>\\n<h2><strong>新产品：</strong></h2>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767467065803529\\\"><strong>千问AI眼镜S1宣布正式开售</strong></a></p>\\n<p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\\n<h2><strong>投融资：</strong></h2>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767950609203972\\\"><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></a></p>\\n<p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767826218140166\\\"><strong>苹果CEO库克斥资106万美元增持耐克</strong></a></p>\\n<p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。</p>\\n<h2><strong>今日观点：</strong></h2>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767782898795266\\\"><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></a></p>\\n<p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。</p>\\n<h2><strong>其他值得关注的新闻：</strong></h2>\\n<p><a href=\\\"https://36kr.com/newsflashes/3767830158820100\\\"><strong>李成钢会见美国福特汽车公司全球执行副总裁兼首席政务官柯立</strong></a></p>\\n<p>4月13日，商务部国际贸易谈判代表兼副部长李成钢在京会见美国福特汽车公司全球执行副总裁兼首席政务官柯立。双方就中美经贸关系、福特公司在华发展等进行了交流。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'氪星晚报｜Snap宣布将裁员约1000人；字节启动新一轮期权回购；苹果CEO库克斥资106万美元增持耐克\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'氪星晚报｜Snap宣布将裁员约1000人；字节启动新一轮期权回购；苹果CEO库克斥资106万美元增持耐克\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3767970803221251?f=rss\'}], \'link\': \'https://36kr.com/p/3767970803221251?f=rss\', \'published\': \'2026-04-15 21:53:11  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=15, tm_hour=13, tm_min=53, tm_sec=11, tm_wday=2, tm_yday=105, tm_isdst=0), \'summary\': \'<h2><strong>大公司：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767932351709953\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>Snap宣布将裁员约1000人</strong></a></p>\\\\n  <p>4月15日，社交媒体公司Snap宣布一系列调整，这些调整将影响Snap约1000名团队成员，包括16%的全职员工，此外，公司还将关闭300多个空缺职位。通过调整，公司预计到2026年下半年，年度成本将减少超过5亿美元。Snap表示，对即将离职的美国团队成员，公司将提供四个月的遣散费、医疗保险和股权激励，以及职业转型支持。在美国以外地区，公司将遵循当地流程，并努力提供符合当地规范的同等支持。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767334817088009\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></a></p>\\\\n  <p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武上周五向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI 和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767370241163780\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>特斯拉高管称上海工厂将为擎天柱机器人量产提供“金钥匙”</strong></a></p>\\\\n  <p>特斯拉中国区总经理王昊表示，特斯拉最大的生产基地——上海超级工厂未来有潜力生产人形机器人。该工厂的高效生产和创新能力被视为推动CEO埃隆·马斯克快速实现该技术商业化的关键因素。王昊在周二的一次发布会上表示，CEO马斯克曾指出，大规模生产是制造人形机器人的一个关键挑战。他认为上海制造部门是“解决这一挑战的金钥匙”，但没有具体说明运营将如何支持公司的机器人业务。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767922444927496\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>字节启动新一轮期权回购</strong></a></p>\\\\n  <p>字节发布内部邮件，启动最新一轮期权回购。其中：在职员工：229.5美元/股（约人民币1588元）离职员工：201.96美元/股（约人民币1397元）。字节上一轮回购期权时间是2025年10月，此次在职员工的回购价对比上一轮提升约14.5%。在2025年10月的回购中，在职员工回购价200.41美元，离职员工180.37美元。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767891011682823\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>广电总局发布微短剧精品创作传播计划</strong></a></p>\\\\n  <p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767882377216772\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>哈啰回应超量投放共享单车被行政处罚</strong></a></p>\\\\n  <p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767791865398021\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></a></p>\\\\n  <p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767786531488516\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></a></p>\\\\n  <p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。</p>\\\\n  <h2><strong>新产品：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767467065803529\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>千问AI眼镜S1宣布正式开售</strong></a></p>\\\\n  <p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\\\\n  <h2><strong>投融资：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767950609203972\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></a></p>\\\\n  <p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767826218140166\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>苹果CEO库克斥资106万美元增持耐克</strong></a></p>\\\\n  <p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。</p>\\\\n  <h2><strong>今日观点：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767782898795266\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></a></p>\\\\n  <p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。</p>\\\\n  <h2><strong>其他值得关注的新闻：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767830158820100\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>李成钢会见美国福特汽车公司全球执行副总裁兼首席政务官柯立</strong></a></p>\\\\n  <p>4月13日，商务部国际贸易谈判代表兼副部长李成钢在京会见美国福特汽车公司全球执行副总裁兼首席政务官柯立。双方就中美经贸关系、福特公司在华发展等进行了交流。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<h2><strong>大公司：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767932351709953\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>Snap宣布将裁员约1000人</strong></a></p>\\\\n  <p>4月15日，社交媒体公司Snap宣布一系列调整，这些调整将影响Snap约1000名团队成员，包括16%的全职员工，此外，公司还将关闭300多个空缺职位。通过调整，公司预计到2026年下半年，年度成本将减少超过5亿美元。Snap表示，对即将离职的美国团队成员，公司将提供四个月的遣散费、医疗保险和股权激励，以及职业转型支持。在美国以外地区，公司将遵循当地流程，并努力提供符合当地规范的同等支持。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767334817088009\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>英特尔据悉将在未来几周向员工披露参与马斯克Terafab项目的细节</strong></a></p>\\\\n  <p>根据英特尔(CEO陈立武上周发出的一份备忘录，该公司计划在“未来几周”向员工披露其参与埃隆·马斯克雄心勃勃的“Terafab”芯片制造项目的“范围和性质”。陈立武上周五向英特尔员工发送了这份备忘录，此前两天，这家半导体巨头宣布与马斯克的公司——SpaceX、xAI 和特斯拉——共同参与Terafab项目，这对于正在经历最新转型尝试的英特尔来说，可能是一个福音。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767370241163780\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>特斯拉高管称上海工厂将为擎天柱机器人量产提供“金钥匙”</strong></a></p>\\\\n  <p>特斯拉中国区总经理王昊表示，特斯拉最大的生产基地——上海超级工厂未来有潜力生产人形机器人。该工厂的高效生产和创新能力被视为推动CEO埃隆·马斯克快速实现该技术商业化的关键因素。王昊在周二的一次发布会上表示，CEO马斯克曾指出，大规模生产是制造人形机器人的一个关键挑战。他认为上海制造部门是“解决这一挑战的金钥匙”，但没有具体说明运营将如何支持公司的机器人业务。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767922444927496\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>字节启动新一轮期权回购</strong></a></p>\\\\n  <p>字节发布内部邮件，启动最新一轮期权回购。其中：在职员工：229.5美元/股（约人民币1588元）离职员工：201.96美元/股（约人民币1397元）。字节上一轮回购期权时间是2025年10月，此次在职员工的回购价对比上一轮提升约14.5%。在2025年10月的回购中，在职员工回购价200.41美元，离职员工180.37美元。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767891011682823\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>广电总局发布微短剧精品创作传播计划</strong></a></p>\\\\n  <p>15日在成都开幕的第13届中国网络视听大会上，国家广播电视总局发布微短剧精品创作传播计划，并启动“长征：我们的故事”主题微短剧创作展播活动。广电总局相关负责人表示，我国微短剧已由粗放式增长进入到繁荣发展的关键阶段，正处于迈向精品化、数智化、产业化、国际化的战略机遇期。广电总局牵头构建“总局引领、省局支持、平台激励”的创作引导体系，启动微短剧精品创作传播计划，推动微短剧高质量发展。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767882377216772\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>哈啰回应超量投放共享单车被行政处罚</strong></a></p>\\\\n  <p>4月15日，针对哈啰违规超量投放共享单车被立案调查和约谈处罚一事，哈啰公司方面回应称，哈啰骑行北京分公司在新车置换与跨区域调度中，运力调度及响应效率上存在管理短板，未能将工作做实做细。对此，哈啰表示已启动全面整改：连夜增派运维力量，恢复重点区域的停放秩序，同时启动内部管理机制的调整优化。哈啰称，接受北京市主管部门的约谈与指导，并以此次整改为契机，深耕精细化运营，向主管部门及社会公众汇报进度。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767791865398021\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>苹果提高印度iPhone产量，塔塔集团组装份额应能达到10-15%</strong></a></p>\\\\n  <p>根据Counterpoint的数据，印度在全球组装业务中的份额从2022年的5.8%上升至2025年的22.2%。到2026年，这一份额将达到25-30%，到2027年将达到30-35%。鸿海仍是印度最大的组装商，其次是塔塔集团，该集团于2023年收购了纬创资通的工厂，并于2024年收购了和硕在当地工厂60%的股份。未来两年，塔塔集团的iPhone组装份额应能达到10-15%。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767786531488516\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>抖音集团将投入5亿专项资金扶持真人短剧</strong></a></p>\\\\n  <p>4月15日，2026年第十三届中国网络视听大会上，抖音集团宣布将投入5亿元专项资金扶持真人短剧内容创新与现实题材深耕。红果短剧总编辑乐力表示，真人短剧是行业高质量发展的“进行时”与“未来时”。只有各方积极引导扶持真人创作，才能让短剧行业行稳致远。</p>\\\\n  <h2><strong>新产品：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767467065803529\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>千问AI眼镜S1宣布正式开售</strong></a></p>\\\\n  <p>36氪获悉，4月15日，千问AI眼镜S1宣布正式开售，最低到手价为3499元。该产品支持屏幕显示、1200万像素摄像头、热插拔换电池，并为全天候AI服务在整机层面进行了系统性重。</p>\\\\n  <h2><strong>投融资：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767950609203972\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>“达美盛（DMS）”完成新一轮过亿元股权融资</strong></a></p>\\\\n  <p>36氪获悉，近日，工业智能化解决方案提供商“达美盛（DMS）”宣布完成了新一轮过亿元股权融资。本轮融资由天津智汇基金领投，中集资本、北洋海棠基金、中控技术等多家机构跟投。融资资金将主要用于工业智能体平台等核心技术研发、市场拓展以及生态建设。</p>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767826218140166\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>苹果CEO库克斥资106万美元增持耐克</strong></a></p>\\\\n  <p>当地时间4月14日，耐克提交至美国证券交易委员会（SEC）的文件显示，苹果首席执行官蒂姆·库克于4月10日以42.43美元每股价格买入25,000股耐克股票，斥资约106万美元。</p>\\\\n  <h2><strong>今日观点：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767782898795266\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>马斯克：特斯拉AI5芯片成功流片，将成为产量最高AI芯片之一</strong></a></p>\\\\n  <p>特斯拉首席执行官埃隆·马斯克4月15日宣布，特斯拉AI芯片设计团队已成功完成AI5芯片的流片。他同时透露，性能更强大的AI6、Dojo3以及其他多款芯片也正在研发中。马斯克表示，感谢合作伙伴台积电和三星在芯片量产过程中的支持，“AI5芯片未来将成为全球产量最大的AI芯片之一”。</p>\\\\n  <h2><strong>其他值得关注的新闻：</strong></h2>\\\\n  <p><a href=\\\"https://36kr.com/newsflashes/3767830158820100\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>李成钢会见美国福特汽车公司全球执行副总裁兼首席政务官柯立</strong></a></p>\\\\n  <p>4月13日，商务部国际贸易谈判代表兼副部长李成钢在京会见美国福特汽车公司全球执行副总裁兼首席政务官柯立。双方就中美经贸关系、福特公司在华发展等进行了交流。</p>\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-15 21:53:11\", \"ai_json_output\": \"\"}', NULL, '2026-04-15 21:53:11', '2026-04-16 11:59:48');
INSERT INTO `news_detail` VALUES (32, 1052, 7, '消费与零售', '8点1氪丨许家印一审当庭认罪悔罪；交管部门回应新能源车牌绿色变白色；生成内容涉黄，哩布哩布AI回应', '', '<h2>今日热点导览</h2>\n<p>可能含有“永久性化学物”，Lululemon在美被调查</p>\n<p>近一周“一口价”黄金产品最高下跌17%</p>\n<p>中国将健全药品价格形成机制</p>\n<p>离境退税2.0版措施预计4月底前推出</p>\n<p>苹果加码iPhone Fold</p>\n<h2>TOP3大新闻</h2>\n<p><strong>恒大集团、恒大地产及许家印案一审开庭</strong></p>\n<p>2026年4月13日至14日，广东省深圳市中级人民法院对深圳市人民检察院提起公诉的被告单位恒大集团有限公司非法吸收公众存款、集资诈骗、违法发放贷款、欺诈发行证券、违规披露重要信息、单位行贿，被告单位恒大地产集团有限公司欺诈发行证券，被告人许家印非法吸收公众存款、集资诈骗、违法发放贷款、违法运用资金、欺诈发行证券、违规披露重要信息、职务侵占、单位行贿一案进行了公开开庭审理。庭审中，法庭主持控辩双方围绕指控的事实进行了法庭调查及法庭辩论，被告单位、许家印进行了最后陈述。许家印当庭表示认罪悔罪。法庭将择期宣判。部分人大代表、政协委员，被告人亲属，集资参与人代表等旁听了庭审。（央视新闻）</p>\n<p><strong>交管部门回应新能源车牌绿色变白色</strong></p>\n<p>近日，有网友通过社交平台发布视频，称其在路上看到有车辆悬挂白底黑字的机动车号牌，感到十分好奇。通过社交平台搜索发现，国内多地均出现白底黑字的新能源汽车号牌，相关帖文的发布者表达了对于这种车牌风格的喜爱，认为其更具高级感。</p>\n<p>4月13日，据媒体从交管部门了解到，人为将新能源机动车号牌褪色属于污损车辆号牌，是违法行为，市民如遇此类车牌可向交管部门举报反映。《中华人民共和国道路交通安全法》第十一条明确规定，机动车号牌应按规定悬挂并保持清晰、完整，不得故意遮挡、污损。第九十五条指出，故意遮挡、污损或不按规定安装号牌的，将依据第九十条处以警告或二十元以上二百元以下罚款。（第一财经）</p>\n<p><strong>哩布哩布AI就内容安全问题致歉</strong></p>\n<p>4月14日，哩布哩布AI发布关于加强内容安全管理的说明：近期媒体对AI生成内容安全问题的讨论，我们已关注并高度重视。第一时间启动内部专项排查，对平台生成能力及审核机制进行了全面自查。经排查发现，在个别复杂提示词组合及规避表达的边界场景下，平台存在生成不符合规范内容的情况。对此，我们深表歉意。本次问题也为我们敲响了警钟，使我们清醒认识到在内容安全边界识别与机制完善方面仍存在不足，未达到应有标准。相关问题已第一时间完成技术修复，并对风险路径进行全面封堵。同时，我们已同步加强攻防演练与审核机制升级，持续提升识别能力与处置效率，从源头降低风险发生。我们也已启动内部责任复盘机制，进一步完善相关管理与审核流程。(界面新闻)</p>\n<h2>大公司/大事件</h2>\n<p><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></p>\n<p>4月14日，就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。（澎湃新闻）</p>\n<p><strong>大批“五一”航班突然取消背后：高油价下的停飞潮正在全球蔓延</strong></p>\n<p>最近一段时间，不少网友在社交平台上，贴出了自己提前预订的“五一”假期机票被取消的截图，被取消的航班主要以飞东南亚和大洋洲居多。记者从多家航空公司获悉，从4月��始主动取消的航班确实有所增加，其中东南亚和大洋洲是重头，这与油价的大幅上涨不无关系。相比国内，部分国际机场加油价格更高，叠加需求和竞争的影响，部分航线的取消就首当其冲。而这样的情况，正在全球航线市场蔓延，也逐渐改变着航空业的竞争格局和旅客的出行选择。（第一财经）</p>\n<p><strong>可能含有“永久性化学物”，Lululemon在美被调查</strong></p>\n<p>据路透社报道，美国得克萨斯州总检察长Ken Paxton当地时间4月13日在社交平台X上发文称，已对运动休闲品牌露露乐蒙(Lululemon)展开调查，原因是其运动服饰中可能含有“永久性化学物”。Paxton表示，此次调查将核查露露乐蒙的运动服装是否含有全氟及多氟烷基物质(PFAS)。对此，露露乐蒙一名发言人表示，已知悉此次调查，并将予以配合。露露乐蒙的发言人回应称：“公司产品中并未使用全氟及多氟烷基物质。”该发言人补充称，此前该物质仅少量用于耐用防水类产品，公司已于2023财年完成对其的逐步淘汰。（中新经纬）</p>\n<p><strong>突破20万小时人类视频，智在无界发布下一代具身世界模型H0.7</strong></p>\n<p>BeingBeyond（智在无界）发布新一代具身世界模型Being-H0.7，成为业内首个可端侧部署的商用世界模型。该模型基于国内现有最大规模20万小时人类视频，采用隐空间推理方式替代视频生成，首次在75TOPS的低成本端侧计算平台Orin NX上实时部署。Being-H0.7在6项世界权威评测榜单中综合排名第一（其中4项登顶）。公司称，H0.7实现了跨本体迁移和物理世界理解能力，目前已与多家国内具身本体企业建立合作关系。</p>\n<p><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></p>\n<p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表14日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。（新浪科技）</p>\n<p><strong>近一周“一口价”黄金产品最高下跌17%</strong></p>\n<p>近一周，多个品牌的“一口价”黄金产品价格出现了不同程度的下跌。4月14日，有交易软件发布数据显示，近一周，“一口价”金价波动集中在3000元以下的黄金配饰产品，3000元以上的黄金配饰暂未出现明显变化。老凤祥的莲花吊坠（1g）近一周市场成交价由峰值1683元下跌至1398元，下跌了285元，跌幅17%；中国黄金四叶草吊坠（0.3g）市场成交价由579元下跌至504元，下跌了75元，跌幅13%；中国黄金小金马手链市场成交价由876元下跌至798元，下跌了78元，跌幅9%。</p>\n<p>除了一口价黄金配饰外，年轻人喜欢“攒金”的小金豆价格也有一定程度下滑，老凤祥金豆（1g）市场成交价从1314元下跌至1195元，下跌了119元，跌幅9%；中国黄金小金猪（0.1g）市场成交价由213元下跌至169元，跌幅21%。（证券时报）</p>\n<p><strong>执法部门：违规超量投放共享自行车，哈啰拒不改正将被处罚</strong></p>\n<p>4月13日，执法人员复核整改情况，发现东城区盛德紫阙、簋街等地仍存在大量未备案车辆，经认定，哈啰公司未按交通行政管理部门要求投放车辆，且拒不改正，违反了《北京市非机动车管理条例》及《北京市互联网租赁自行车监管管理办法（试行）》有关规定。针对哈啰公司未按照交通行政管理部门要求投放车辆、拒不改正的行为，依据《北京市非机动车管理条例》第二十条第一项、第三十一条及《北京市交通运输行政处罚裁量基准》，总队将依法对哈啰公司作出行政处罚，并调减其运营规模。目前，该案正在按法定程序办理。（界面新闻）</p>\n<p><strong>中国将健全药品价格形成机制</strong></p>\n<p>国务院办公厅4月14日发布《关于健全药品价格形成机制的若干意见》，提出14条举措，包括优化创新药等新上市药品首发价格机制、发挥医保支付标准对药品价格形成的引导作用、引导药店合理制定药品零售价格、强化短缺药保供稳价等。意见要求加强药品价格治理，提出实行药品价格风险预警、健全药品价格风险处置制度、防范非理性竞价中标影响供应、严惩药品和原辅料生产经营领域以缺逼涨等违法违规行为、加强医药领域全链条穿透式审计监督、建立药品医保价值评估制度等针对性措施，引导药品价格运行在合理区间。（新华社）</p>\n<p><strong>2026总票房突破125亿</strong></p>\n<p>据网络平台数据，截至4月14日12时08分，2026年度电影总票房（含预售）突破125亿元。(界面新闻)</p>\n<p><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></p>\n<p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。（界面新闻）</p>\n<p><strong>离境退税2.0版措施预计4月底前推出</strong></p>\n<p>4月14日在第六届消博会期间获悉，离境退税2.0版措施目前正在报批过程中，预计4月底前推出。（中证金牛座）</p>\n<p><strong>一季度业绩陆续出炉，多家行业龙头公司亮相</strong></p>\n<p>据统计，4月14日，共计29家上市公司发布2026年一季度业绩相关公告，多家行业龙头公司在列。从净利润规模来看，16家净利润在1亿元以上，盐湖股份、神火股份、金山办公、卫星化学等四家公司均超过20亿元；沪电股份超过10亿元。从净利润变动来看，金山办公同比增幅居首，高达437.35%；神火股份、亚翔集成增幅超过200%；盐湖股份、金徽股份、中船防务、北方稀土等紧随其后，一季度业绩均实现同比翻倍增长。（证券时报）</p>\n<p><strong>国家统计局：4月上旬生猪（外三元）价格环比下降4.2%</strong></p>\n<p>36氪获悉，据国家统计局，据对全国流通领域9大类50种重要生产资料市场价格的监测显示，2026年4月上旬与3月下旬相比，30种产品价格上涨，18种下降，2种持平。其中，生猪（外三元）价格为9.1元/千克，环比下降4.2%。</p>\n<p><strong>Omdia：存储成本上涨推升设备价格，2026年中国大陆智能手机市场小幅下滑1%</strong></p>\n<p>36氪获悉，Omdia的最新研究显示，2026年第一季度，因为成本上涨导致部分品牌产品涨价，大盘持续呈下滑趋势，中国大陆智能手机市场同比下降1%，出货6980万台。华为以1390万台的出货量得到第一，占据20%市场份额。苹果排名第二，出货量1310万台，市场份额为19%。OPPO在realme回归后首个季度出货1100万台，排名市场前三。vivo出货1050万台，排名第四。小米出货870万台排名第五。</p>\n<p><strong>美股三大指数集体收涨，纳指连续十个交易日上涨</strong></p>\n<p>36氪获悉，4月14日收盘，美股三大指数集体个涨，道指涨0.66%，纳指涨1.96%，实现连续十个交易日上涨，标普500指数涨1.18%，大型科技股普涨，Meta涨超4%，英伟达、特斯拉、谷歌、亚马逊涨超3%，微软涨超2%。热门中概股集体走强，爱奇艺涨超11%.京东涨近8%.百度涨超5%.阿里巴巴、哔哩哔哩、小鹏集团涨超2%。拼多多、蔚来涨超1%。</p>\n<p><strong>特斯拉机器人出租车推进引发现金流担忧，不断增加的支出给财务带来压力</strong></p>\n<p>特斯拉公司因其向机器人出租车和自动驾驶汽车的进军开始对其现金流造成压力而备受关注，尽管其在全自动驾驶计划中正接近一个重大目标。一些分析师认为，特斯拉今年的资本支出可能超过200亿美元，部分估计甚至高达250亿至300亿美元，具体取决于公司的增长目标。这样的投资水平很可能会导致自由现金流下降。（新浪财经）</p>\n<p><strong>亚马逊或接近达成收购GlobalStar的交易，以期与Starlink展开竞争</strong></p>\n<p>知情人士透露，亚马逊接近达成收购GlobalStar的交易，以期与Starlink展开竞争。（财联社）</p>\n<p><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></p>\n<p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。（财联社）</p>\n<p><strong>苹果加码iPhone Fold</strong></p>\n<p>4月14日，尽管折叠屏手机市场近年成长力道趋缓，但消息称苹果已为首款折叠屏手机iPhone Fold加码20%面板库存。（新浪财经）</p>\n<p><strong>甲骨文被指在近期裁员中针对持有股票期权的员工</strong></p>\n<p>根据报道，科技巨头甲骨文近期的大规模裁员引发了争议，有前员工指责公司在裁员过程中，可能通过算法刻意针对那些持有未行权股票期权的资深员工和高绩效人才。报道指出，在甲骨文于3月31日裁员约3万人后，一位在该公司工作了三十余年的前安全警报经理在领英上发帖称，裁员似乎遵循着一种“算法”，专门针对高级个人贡献者、中层管理人员，“尤其是那些持有未行权股票期权的人”。这一指控迅速引发了外界对甲骨文裁员公平性的质疑。（新浪财经）</p>\n<p><strong>伊媒：伊美或重返伊斯兰堡继续谈判</strong></p>\n<p>据伊朗新闻电视台15日报道，伊朗和美国代表团可能本周晚些时候在巴基斯坦首都伊斯兰堡重启谈判。伊美双方上轮谈判未能达成协议，在多个问题上存在分歧。（新华社）</p>\n<p><strong>美能源部长：霍尔木兹海峡通航前，美国能源将持续涨价</strong></p>\n<p>美国能源部长克里斯·赖特4月13日承认，在霍尔木兹海峡恢复“有意义”的船只通行前，美国能源价格可能持续上涨。克里斯·赖特称，霍尔木兹海峡的航运将在未来数周内恢复。（央视新闻）</p>\n<p><strong>英伟达否认“洽购大型PC制造商”传闻</strong></p>\n<p>当地时间4月13日，有消息称，英伟达公司正寻求收购一家大型公司，此举将“重塑个人电脑行业格局”。消息称，英伟达就这笔交易的谈判已持续了一年多。英伟达对此回应称，消息不实，英伟达没有在磋商收购任何个人电脑制造商。（界面新闻）</p>\n<p><strong>快看漫画将研发多款AI应用，涉及AI角色互动等</strong></p>\n<p>36氪获悉，4月14日，快看漫画内部正在推进不止一款App，而是一组围绕AI能力展开的多款App组成的产品矩阵。该AI应用矩阵可能覆盖多个用户需求与使用场景，涉及AI角色互动、开放世界、破次元陪伴等维度。</p>\n<p><strong>谷歌宣布提供1000万美元资助，支持4万名制造业从业者掌握AI技能</strong></p>\n<p>当地时间4月13日，谷歌宣布提供1000万美元的资助，以支持美国制造业研究所帮助美国劳动力迎接工业创新新时代的到来，这笔资金将助力4万名现有及未来的制造业从业人员掌握AI技能，并将学徒培训机会扩展至全美15个地区。（界面新闻）</p>\n<p><strong>SpaceX星链业务2025年营收或增长50%，达到114亿美元</strong></p>\n<p>据报道，马斯克旗下SpaceX公司的最新财务数据显示，星链业务2025年营收增长50%，达到114亿美元，而SpaceX的另外两项业务——火箭发射和人工智能，未能产生足够增长，让投资者为马斯克所寻求的惊人估值买单。（界面新闻）</p>\n<h2>上市进行时</h2>\n<p><strong>Nuclea Energy</strong></p>\n<p>致力于为离网市场及数据中心开发核微反应堆的Nuclea Energy于4月13日向美国证券交易委员会提交申请，拟通过首次公开募股（IPO）筹资最高5000万美元。Nuclea Energy的核心产品为“Morpheus微反应堆”，这是一种可运输、工厂预制、密封堆芯的核反应堆，专为加拿大偏远北极地区和原住民社区、采矿及资源开采、数据中心及关键基础设施、国防与国家安全等场景设计。目前公司仍处于开发阶段，尚未产生任何收入。（新浪财经）</p>\n<p><strong>越疆</strong></p>\n<p>36氪获悉，证监会网站披露，深圳市越疆科技股份有限公司（简称“越疆”）IPO辅导状态于近日变更为“辅导验收”。此前，越疆曾于2025年12月30日在深圳证监局办理辅导备案登记，拟首次公开发行股票并在深交所上市，辅导券商为国泰海通证券。</p>\n<h2>AI最前沿</h2>\n<p><strong>Seedance 2.0全面开放API服务</strong></p>\n<p>36氪获悉，火山引擎正式上线Seedance 2.0系列API服务。据介绍，Seedance 2.0支持文字、图片、音频、视频四种模态输入。火山引擎为Seedance 2.0建立了肖像与版权安全标准，覆盖视频生成涉及的各种模态和创作前后的全部流程。</p>\n<p><strong>MiniMax Agent桌面端更新：新增Pocket功能，支持接入飞书、微信等</strong></p>\n<p>36氪获悉，MiniMax发布MiniMax Agent桌面端两项更新：Pocket功能上线（Beta版），支持接入飞书、微信、企业微信、Slack等主流IM通讯软件；Computer Use功能上线，Agent可以像人一样看屏幕、操作鼠标和键盘，直接操作用户电脑上的软件。</p>\n<p><strong>美团发布AI产品“小团健康管家”</strong></p>\n<p>36氪获悉，4月14日，在乌镇健康大会上，美团正式发布聚焦家庭健康管理的AI产品“小团健康管家”和全新付费会员服务“健康卡”。前者提供基础的问病问药、健康咨询服务，还支持家庭健康档案管理和体检报告智能解读。用户在对话中可跳转线上购药、在线问诊或预约线下就医。“健康卡”则提供超千款药品购药返现服务，其中原研药超过300款。</p>\n<p><strong>诺和诺德宣布与OpenAI建立战略合作伙伴关系</strong></p>\n<p>诺和诺德4月14日宣布与OpenAI建立战略合作伙伴关系，此次合作将运用先进的人工智能能力，对复杂数据集进行分析，筛选具有潜力的候选药物，并缩短从基础研究到惠及患者所需的周期。（界面新闻）</p>\n<p><strong>对标OpenClaw，微软拟为Copilot开发新功能</strong></p>\n<p>据报道，微软正为其AI助手Copilot开发一系列新功能，旨在使其更接近OpenClaw。微软表示，公司目前正“在企业应用场景下，探索OpenClaw等技术的潜力”。这些新特性包括在Microsoft 365应用程序内部引入一支“始终在线”的智能代理团队。（界面新闻）</p>\n<h2>大公司财报</h2>\n<p><strong>LVMH集团第一季度收入下滑6%</strong></p>\n<p>LVMH集团2026年第一季度营收191.21亿欧元（约合人民币1537亿元），同比下滑6%，有机收入增长1%。该集团提到，在中国、亚洲及美国看到有机收入稳健增长，而中东市场受到该地持续冲突的严重影响，拖累集团一季度有机收入下滑1%。分部门看，营收占比近50%的时装与皮具同比下滑9%，有机收入减少2%；余下部门按规模大小依次是精品零售、珠宝腕表、香水和化妆品、葡萄酒和烈酒，同比分别下滑3%、2%、6%和2%，有机收入增长4%、7%、0%和5%。（界面新闻）</p>\n<p><strong>申通快递：2025年净利润13.69亿元，同比增长31.63%</strong></p>\n<p>36氪获悉，申通快递发布业绩快报，2025年实现营业总收入555.86亿元，同比增长17.84%；归属于上市公司股东的净利润13.69亿元，同比增长31.63%；基本每股收益0.92元。</p>\n<p><strong>BP发布首季交易更新：石油交易表现卓越，净债务预计上升</strong></p>\n<p>4月14日，BP发布2026年第一季度交易更新报告。报告显示，BP预计第一季度的石油交易结果将表现“卓越”。财务方面，由于营运资本预计出现40亿至70亿美元的显著增加，公司预计截至一季度末的净债务将从2025年底的220亿美元上升至250亿至270亿美元区间。（界面新闻）</p>\n<p><strong>燕京啤酒：2025年净利润16.79亿元，同比增长59.06%</strong></p>\n<p>36氪获悉，燕京啤酒披露年报，2025年实现营业收入153.33亿元，同比增长4.54%；归属于上市公司股东的净利润16.79亿元，同比增长59.06%；基本每股收益0.596元。公司拟每10股派发现金红利2元（含税）。</p>\n<p><strong>鄂尔多斯：2025年净利润23.63亿元，同比增长27.93%</strong></p>\n<p>36氪获悉，鄂尔多斯披露年报，2025年实现营业收入257.41亿元，同比下降9.37%；归属于上市公司股东的净利润23.63亿元，同比增长27.93%；基本每股收益0.84元。公司拟每10股派发现金红利7元（含税）。</p>\n<h2>投融资</h2>\n<p><strong>CREAO AI完成千万美金融资</strong></p>\n<p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\n<p><strong>“蓝点触控”完成超亿元C+轮融资</strong></p>\n<p>36氪获悉，“蓝点触控”近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。这是近一年内蓝点触控完成的第三轮过亿元融资。</p>\n<p><strong>“庞伯特”完成近2亿元A轮系列融资</strong></p>\n<p>36氪获悉，“庞伯特”已完成A轮系列融资、三轮累计金额近2亿元，神骐资本、明势创投、蓝驰创投、锦秋基金、华创资本等头部机构参投，高鹄资本担任独家财务顾问。本次融资将用于公司产品技术迭代，同时加速推进全球化品牌与市场布局。</p>\n<h2>酷产品</h2>\n<p><strong>高德首款具身机器人将亮相</strong></p>\n<p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。（上证报）</p>\n<p><strong>雷诺韩国计划到2029年每年推出新车型</strong></p>\n<p>据报道，雷诺韩国计划到2029年每年推出新车型，并从2028年起在釜山生产下一代电动车。（财联社）</p>\n<p><strong>有道词典笔A7S正式发布</strong></p>\n<p>36氪获悉，14日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\n<p><strong>亚马逊卫星联网项目Leo发布航空天线</strong></p>\n<p>亚马逊当地时间4月13日发布了专为商业航空设计的Leo航空天线，该天线利用低地球轨道卫星网络，可提供高达1 Gbps的下载和400 Mbps的上传速度，足以支撑全机乘客同时进行4K视频、游戏或协作办公。目前，亚马逊已与达美航空和捷蓝航空达成合作协议。（界面新闻）</p>\n<h2>氪大事</h2>\n<p><strong>氪大事短视频栏目，鲜活解读商业世界大事。</strong> 为了保住同伙，AI有多癫？ </p>\n<p> </p>\n<p><strong>年轻人“丰容方式”小调查</strong></p>\n<p>丰容，一个动物园学术语。原本指动物园通过丰富环境，让圈养动物摆脱单调压抑，减少刻板行为。如今这个词，却被越来越多人用在了自己身上。这些“人类的自我丰容”措施包括但不限于：认真做一顿早餐；走一条从没走过的路；独自打卡一家美食；主动和卖菜摊主聊聊菜价……</p>\n<p>这种看得见摸得着的小事，或许是一场年轻人的精神自救。你是否也曾通过一些微小的改变，打破重复枯燥的生活常态？让你重新感到安全、充实、新鲜，拿回了生活掌控感？<strong>扫描下方二维码</strong>，分享你的“丰容Tips”。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_8a429eea17a2456dbc9668dff4e5196b@5667365_oswg20430oswg512oswg512_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>年轻人“丰容方式”小调查</p>\n<p><strong>整理</strong>｜Kris </p>', 'https://36kr.com/p/3767326268392199?f=rss', 0, '', '{\"summary\": \"本文汇总了当日海内外多领域商业热点，包含出海相关的品牌合规调查与市场动态，帮助出海从业者快速掌握最新行业资讯\", \"abstract\": \"本文是36氪“8点1氪”的每日商业热点汇总，覆盖国内外科技、消费、能源、金融等多个领域最新动态。文中涉及出海相关事件包括运动品牌Lululemon因疑似含永久性化学物PFAS在美国被调查，TCL电子回应拟出售印度电视制造业务传闻称不持有该资产。文中提到我国离境退税2.0版措施预计4月底推出，同时公布了多家上市公司业绩、AI新品发布、企业融资等多领域动态。这份汇总可帮助出海相关主体快速获取海内外最新市场与政策资讯。\", \"keywords\": [\"离境退税\", \"品牌出海\", \"海外合规\", \"PFAS\", \"印度市场\", \"消费出海\", \"市场动态\"], \"policy_risk\": {\"market_risk\": \"全球高油价引发全球停飞潮，大量五一往返东南亚、大洋洲航班取消；霍尔木兹海峡通航未恢复将推高能源价格；出海品牌面临海外合规审查风险\", \"policy_compliance\": \"美国得克萨斯州对运动品牌Lululemon启动PFAS（永久性化学物）合规调查；中国离境退税2.0版措施预计4月底前推出\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"https://36kr.com/p/3767326268392199?f=rss\", \"title\": \"8点1氪丨许家印一审当庭认罪悔罪；交管部门回应新能源车牌绿色变白色；生成内容涉黄，哩布哩布AI回应\", \"source\": \"https://36kr.com/feed\", \"content\": \"<h2>今日热点导览</h2>\\n<p>可能含有“永久性化学物”，Lululemon在美被调查</p>\\n<p>近一周“一口价”黄金产品最高下跌17%</p>\\n<p>中国将健全药品价格形成机制</p>\\n<p>离境退税2.0版措施预计4月底前推出</p>\\n<p>苹果加码iPhone Fold</p>\\n<h2>TOP3大新闻</h2>\\n<p><strong>恒大集团、恒大地产及许家印案一审开庭</strong></p>\\n<p>2026年4月13日至14日，广东省深圳市中级人民法院对深圳市人民检察院提起公诉的被告单位恒大集团有限公司非法吸收公众存款、集资诈骗、违法发放贷款、欺诈发行证券、违规披露重要信息、单位行贿，被告单位恒大地产集团有限公司欺诈发行证券，被告人许家印非法吸收公众存款、集资诈骗、违法发放贷款、违法运用资金、欺诈发行证券、违规披露重要信息、职务侵占、单位行贿一案进行了公开开庭审理。庭审中，法庭主持控辩双方围绕指控的事实进行了法庭调查及法庭辩论，被告单位、许家印进行了最后陈述。许家印当庭表示认罪悔罪。法庭将择期宣判。部分人大代表、政协委员，被告人亲属，集资参与人代表等旁听了庭审。（央视新闻）</p>\\n<p><strong>交管部门回应新能源车牌绿色变白色</strong></p>\\n<p>近日，有网友通过社交平台发布视频，称其在路上看到有车辆悬挂白底黑字的机动车号牌，感到十分好奇。通过社交平台搜索发现，国内多地均出现白底黑字的新能源汽车号牌，相关帖文的发布者表达了对于这种车牌风格的喜爱，认为其更具高级感。</p>\\n<p>4月13日，据媒体从交管部门了解到，人为将新能源机动车号牌褪色属于污损车辆号牌，是违法行为，市民如遇此类车牌可向交管部门举报反映。《中华人民共和国道路交通安全法》第十一条明确规定，机动车号牌应按规定悬挂并保持清晰、完整，不得故意遮挡、污损。第九十五条指出，故意遮挡、污损或不按规定安装号牌的，将依据第九十条处以警告或二十元以上二百元以下罚款。（第一财经）</p>\\n<p><strong>哩布哩布AI就内容安全问题致歉</strong></p>\\n<p>4月14日，哩布哩布AI发布关于加强内容安全管理的说明：近期媒体对AI生成内容安全问题的讨论，我们已关注并高度重视。第一时间启动内部专项排查，对平台生成能力及审核机制进行了全面自查。经排查发现，在个别复杂提示词组合及规避表达的边界场景下，平台存在生成不符合规范内容的情况。对此，我们深表歉意。本次问题也为我们敲响了警钟，使我们清醒认识到在内容安全边界识别与机制完善方面仍存在不足，未达到应有标准。相关问题已第一时间完成技术修复，并对风险路径进行全面封堵。同时，我们已同步加强攻防演练与审核机制升级，持续提升识别能力与处置效率，从源头降低风险发生。我们也已启动内部责任复盘机制，进一步完善相关管理与审核流程。(界面新闻)</p>\\n<h2>大公司/大事件</h2>\\n<p><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></p>\\n<p>4月14日，就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。（澎湃新闻）</p>\\n<p><strong>大批“五一”航班突然取消背后：高油价下的停飞潮正在全球蔓延</strong></p>\\n<p>最近一段时间，不少网友在社交平台上，贴出了自己提前预订的“五一”假期机票被取消的截图，被取消的航班主要以飞东南亚和大洋洲居多。记者从多家航空公司获悉，从4月��始主动取消的航班确实有所增加，其中东南亚和大洋洲是重头，这与油价的大幅上涨不无关系。相比国内，部分国际机场加油价格更高，叠加需求和竞争的影响，部分航线的取消就首当其冲。而这样的情况，正在全球航线市场蔓延，也逐渐改变着航空业的竞争格局和旅客的出行选择。（第一财经）</p>\\n<p><strong>可能含有“永久性化学物”，Lululemon在美被调查</strong></p>\\n<p>据路透社报道，美国得克萨斯州总检察长Ken Paxton当地时间4月13日在社交平台X上发文称，已对运动休闲品牌露露乐蒙(Lululemon)展开调查，原因是其运动服饰中可能含有“永久性化学物”。Paxton表示，此次调查将核查露露乐蒙的运动服装是否含有全氟及多氟烷基物质(PFAS)。对此，露露乐蒙一名发言人表示，已知悉此次调查，并将予以配合。露露乐蒙的发言人回应称：“公司产品中并未使用全氟及多氟烷基物质。”该发言人补充称，此前该物质仅少量用于耐用防水类产品，公司已于2023财年完成对其的逐步淘汰。（中新经纬）</p>\\n<p><strong>突破20万小时人类视频，智在无界发布下一代具身世界模型H0.7</strong></p>\\n<p>BeingBeyond（智在无界）发布新一代具身世界模型Being-H0.7，成为业内首个可端侧部署的商用世界模型。该模型基于国内现有最大规模20万小时人类视频，采用隐空间推理方式替代视频生成，首次在75TOPS的低成本端侧计算平台Orin NX上实时部署。Being-H0.7在6项世界权威评测榜单中综合排名第一（其中4项登顶）。公司称，H0.7实现了跨本体迁移和物理世界理解能力，目前已与多家国内具身本体企业建立合作关系。</p>\\n<p><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></p>\\n<p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表14日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。（新浪科技）</p>\\n<p><strong>近一周“一口价”黄金产品最高下跌17%</strong></p>\\n<p>近一周，多个品牌的“一口价”黄金产品价格出现了不同程度的下跌。4月14日，有交易软件发布数据显示，近一周，“一口价”金价波动集中在3000元以下的黄金配饰产品，3000元以上的黄金配饰暂未出现明显变化。老凤祥的莲花吊坠（1g）近一周市场成交价由峰值1683元下跌至1398元，下跌了285元，跌幅17%；中国黄金四叶草吊坠（0.3g）市场成交价由579元下跌至504元，下跌了75元，跌幅13%；中国黄金小金马手链市场成交价由876元下跌至798元，下跌了78元，跌幅9%。</p>\\n<p>除了一口价黄金配饰外，年轻人喜欢“攒金”的小金豆价格也有一定程度下滑，老凤祥金豆（1g）市场成交价从1314元下跌至1195元，下跌了119元，跌幅9%；中国黄金小金猪（0.1g）市场成交价由213元下跌至169元，跌幅21%。（证券时报）</p>\\n<p><strong>执法部门：违规超量投放共享自行车，哈啰拒不改正将被处罚</strong></p>\\n<p>4月13日，执法人员复核整改情况，发现东城区盛德紫阙、簋街等地仍存在大量未备案车辆，经认定，哈啰公司未按交通行政管理部门要求投放车辆，且拒不改正，违反了《北京市非机动车管理条例》及《北京市互联网租赁自行车监管管理办法（试行）》有关规定。针对哈啰公司未按照交通行政管理部门要求投放车辆、拒不改正的行为，依据《北京市非机动车管理条例》第二十条第一项、第三十一条及《北京市交通运输行政处罚裁量基准》，总队将依法对哈啰公司作出行政处罚，并调减其运营规模。目前，该案正在按法定程序办理。（界面新闻）</p>\\n<p><strong>中国将健全药品价格形成机制</strong></p>\\n<p>国务院办公厅4月14日发布《关于健全药品价格形成机制的若干意见》，提出14条举措，包括优化创新药等新上市药品首发价格机制、发挥医保支付标准对药品价格形成的引导作用、引导药店合理制定药品零售价格、强化短缺药保供稳价等。意见要求加强药品价格治理，提出实行药品价格风险预警、健全药品价格风险处置制度、防范非理性竞价中标影响供应、严惩药品和原辅料生产经营领域以缺逼涨等违法违规行为、加强医药领域全链条穿透式审计监督、建立药品医保价值评估制度等针对性措施，引导药品价格运行在合理区间。（新华社）</p>\\n<p><strong>2026总票房突破125亿</strong></p>\\n<p>据网络平台数据，截至4月14日12时08分，2026年度电影总票房（含预售）突破125亿元。(界面新闻)</p>\\n<p><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></p>\\n<p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。（界面新闻）</p>\\n<p><strong>离境退税2.0版措施预计4月底前推出</strong></p>\\n<p>4月14日在第六届消博会期间获悉，离境退税2.0版措施目前正在报批过程中，预计4月底前推出。（中证金牛座）</p>\\n<p><strong>一季度业绩陆续出炉，多家行业龙头公司亮相</strong></p>\\n<p>据统计，4月14日，共计29家上市公司发布2026年一季度业绩相关公告，多家行业龙头公司在列。从净利润规模来看，16家净利润在1亿元以上，盐湖股份、神火股份、金山办公、卫星化学等四家公司均超过20亿元；沪电股份超过10亿元。从净利润变动来看，金山办公同比增幅居首，高达437.35%；神火股份、亚翔集成增幅超过200%；盐湖股份、金徽股份、中船防务、北方稀土等紧随其后，一季度业绩均实现同比翻倍增长。（证券时报）</p>\\n<p><strong>国家统计局：4月上旬生猪（外三元）价格环比下降4.2%</strong></p>\\n<p>36氪获悉，据国家统计局，据对全国流通领域9大类50种重要生产资料市场价格的监测显示，2026年4月上旬与3月下旬相比，30种产品价格上涨，18种下降，2种持平。其中，生猪（外三元）价格为9.1元/千克，环比下降4.2%。</p>\\n<p><strong>Omdia：存储成本上涨推升设备价格，2026年中国大陆智能手机市场小幅下滑1%</strong></p>\\n<p>36氪获悉，Omdia的最新研究显示，2026年第一季度，因为成本上涨导致部分品牌产品涨价，大盘持续呈下滑趋势，中国大陆智能手机市场同比下降1%，出货6980万台。华为以1390万台的出货量得到第一，占据20%市场份额。苹果排名第二，出货量1310万台，市场份额为19%。OPPO在realme回归后首个季度出货1100万台，排名市场前三。vivo出货1050万台，排名第四。小米出货870万台排名第五。</p>\\n<p><strong>美股三大指数集体收涨，纳指连续十个交易日上涨</strong></p>\\n<p>36氪获悉，4月14日收盘，美股三大指数集体个涨，道指涨0.66%，纳指涨1.96%，实现连续十个交易日上涨，标普500指数涨1.18%，大型科技股普涨，Meta涨超4%，英伟达、特斯拉、谷歌、亚马逊涨超3%，微软涨超2%。热门中概股集体走强，爱奇艺涨超11%.京东涨近8%.百度涨超5%.阿里巴巴、哔哩哔哩、小鹏集团涨超2%。拼多多、蔚来涨超1%。</p>\\n<p><strong>特斯拉机器人出租车推进引发现金流担忧，不断增加的支出给财务带来压力</strong></p>\\n<p>特斯拉公司因其向机器人出租车和自动驾驶汽车的进军开始对其现金流造成压力而备受关注，尽管其在全自动驾驶计划中正接近一个重大目标。一些分析师认为，特斯拉今年的资本支出可能超过200亿美元，部分估计甚至高达250亿至300亿美元，具体取决于公司的增长目标。这样的投资水平很可能会导致自由现金流下降。（新浪财经）</p>\\n<p><strong>亚马逊或接近达成收购GlobalStar的交易，以期与Starlink展开竞争</strong></p>\\n<p>知情人士透露，亚马逊接近达成收购GlobalStar的交易，以期与Starlink展开竞争。（财联社）</p>\\n<p><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></p>\\n<p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。（财联社）</p>\\n<p><strong>苹果加码iPhone Fold</strong></p>\\n<p>4月14日，尽管折叠屏手机市场近年成长力道趋缓，但消息称苹果已为首款折叠屏手机iPhone Fold加码20%面板库存。（新浪财经）</p>\\n<p><strong>甲骨文被指在近期裁员中针对持有股票期权的员工</strong></p>\\n<p>根据报道，科技巨头甲骨文近期的大规模裁员引发了争议，有前员工指责公司在裁员过程中，可能通过算法刻意针对那些持有未行权股票期权的资深员工和高绩效人才。报道指出，在甲骨文于3月31日裁员约3万人后，一位在该公司工作了三十余年的前安全警报经理在领英上发帖称，裁员似乎遵循着一种“算法”，专门针对高级个人贡献者、中层管理人员，“尤其是那些持有未行权股票期权的人”。这一指控迅速引发了外界对甲骨文裁员公平性的质疑。（新浪财经）</p>\\n<p><strong>伊媒：伊美或重返伊斯兰堡继续谈判</strong></p>\\n<p>据伊朗新闻电视台15日报道，伊朗和美国代表团可能本周晚些时候在巴基斯坦首都伊斯兰堡重启谈判。伊美双方上轮谈判未能达成协议，在多个问题上存在分歧。（新华社）</p>\\n<p><strong>美能源部长：霍尔木兹海峡通航前，美国能源将持续涨价</strong></p>\\n<p>美国能源部长克里斯·赖特4月13日承认，在霍尔木兹海峡恢复“有意义”的船只通行前，美国能源价格可能持续上涨。克里斯·赖特称，霍尔木兹海峡的航运将在未来数周内恢复。（央视新闻）</p>\\n<p><strong>英伟达否认“洽购大型PC制造商”传闻</strong></p>\\n<p>当地时间4月13日，有消息称，英伟达公司正寻求收购一家大型公司，此举将“重塑个人电脑行业格局”。消息称，英伟达就这笔交易的谈判已持续了一年多。英伟达对此回应称，消息不实，英伟达没有在磋商收购任何个人电脑制造商。（界面新闻）</p>\\n<p><strong>快看漫画将研发多款AI应用，涉及AI角色互动等</strong></p>\\n<p>36氪获悉，4月14日，快看漫画内部正在推进不止一款App，而是一组围绕AI能力展开的多款App组成的产品矩阵。该AI应用矩阵可能覆盖多个用户需求与使用场景，涉及AI角色互动、开放世界、破次元陪伴等维度。</p>\\n<p><strong>谷歌宣布提供1000万美元资助，支持4万名制造业从业者掌握AI技能</strong></p>\\n<p>当地时间4月13日，谷歌宣布提供1000万美元的资助，以支持美国制造业研究所帮助美国劳动力迎接工业创新新时代的到来，这笔资金将助力4万名现有及未来的制造业从业人员掌握AI技能，并将学徒培训机会扩展至全美15个地区。（界面新闻）</p>\\n<p><strong>SpaceX星链业务2025年营收或增长50%，达到114亿美元</strong></p>\\n<p>据报道，马斯克旗下SpaceX公司的最新财务数据显示，星链业务2025年营收增长50%，达到114亿美元，而SpaceX的另外两项业务——火箭发射和人工智能，未能产生足够增长，让投资者为马斯克所寻求的惊人估值买单。（界面新闻）</p>\\n<h2>上市进行时</h2>\\n<p><strong>Nuclea Energy</strong></p>\\n<p>致力于为离网市场及数据中心开发核微反应堆的Nuclea Energy于4月13日向美国证券交易委员会提交申请，拟通过首次公开募股（IPO）筹资最高5000万美元。Nuclea Energy的核心产品为“Morpheus微反应堆”，这是一种可运输、工厂预制、密封堆芯的核反应堆，专为加拿大偏远北极地区和原住民社区、采矿及资源开采、数据中心及关键基础设施、国防与国家安全等场景设计。目前公司仍处于开发阶段，尚未产生任何收入。（新浪财经）</p>\\n<p><strong>越疆</strong></p>\\n<p>36氪获悉，证监会网站披露，深圳市越疆科技股份有限公司（简称“越疆”）IPO辅导状态于近日变更为“辅导验收”。此前，越疆曾于2025年12月30日在深圳证监局办理辅导备案登记，拟首次公开发行股票并在深交所上市，辅导券商为国泰海通证券。</p>\\n<h2>AI最前沿</h2>\\n<p><strong>Seedance 2.0全面开放API服务</strong></p>\\n<p>36氪获悉，火山引擎正式上线Seedance 2.0系列API服务。据介绍，Seedance 2.0支持文字、图片、音频、视频四种模态输入。火山引擎为Seedance 2.0建立了肖像与版权安全标准，覆盖视频生成涉及的各种模态和创作前后的全部流程。</p>\\n<p><strong>MiniMax Agent桌面端更新：新增Pocket功能，支持接入飞书、微信等</strong></p>\\n<p>36氪获悉，MiniMax发布MiniMax Agent桌面端两项更新：Pocket功能上线（Beta版），支持接入飞书、微信、企业微信、Slack等主流IM通讯软件；Computer Use功能上线，Agent可以像人一样看屏幕、操作鼠标和键盘，直接操作用户电脑上的软件。</p>\\n<p><strong>美团发布AI产品“小团健康管家”</strong></p>\\n<p>36氪获悉，4月14日，在乌镇健康大会上，美团正式发布聚焦家庭健康管理的AI产品“小团健康管家”和全新付费会员服务“健康卡”。前者提供基础的问病问药、健康咨询服务，还支持家庭健康档案管理和体检报告智能解读。用户在对话中可跳转线上购药、在线问诊或预约线下就医。“健康卡”则提供超千款药品购药返现服务，其中原研药超过300款。</p>\\n<p><strong>诺和诺德宣布与OpenAI建立战略合作伙伴关系</strong></p>\\n<p>诺和诺德4月14日宣布与OpenAI建立战略合作伙伴关系，此次合作将运用先进的人工智能能力，对复杂数据集进行分析，筛选具有潜力的候选药物，并缩短从基础研究到惠及患者所需的周期。（界面新闻）</p>\\n<p><strong>对标OpenClaw，微软拟为Copilot开发新功能</strong></p>\\n<p>据报道，微软正为其AI助手Copilot开发一系列新功能，旨在使其更接近OpenClaw。微软表示，公司目前正“在企业应用场景下，探索OpenClaw等技术的潜力”。这些新特性包括在Microsoft 365应用程序内部引入一支“始终在线”的智能代理团队。（界面新闻）</p>\\n<h2>大公司财报</h2>\\n<p><strong>LVMH集团第一季度收入下滑6%</strong></p>\\n<p>LVMH集团2026年第一季度营收191.21亿欧元（约合人民币1537亿元），同比下滑6%，有机收入增长1%。该集团提到，在中国、亚洲及美国看到有机收入稳健增长，而中东市场受到该地持续冲突的严重影响，拖累集团一季度有机收入下滑1%。分部门看，营收占比近50%的时装与皮具同比下滑9%，有机收入减少2%；余下部门按规模大小依次是精品零售、珠宝腕表、香水和化妆品、葡萄酒和烈酒，同比分别下滑3%、2%、6%和2%，有机收入增长4%、7%、0%和5%。（界面新闻）</p>\\n<p><strong>申通快递：2025年净利润13.69亿元，同比增长31.63%</strong></p>\\n<p>36氪获悉，申通快递发布业绩快报，2025年实现营业总收入555.86亿元，同比增长17.84%；归属于上市公司股东的净利润13.69亿元，同比增长31.63%；基本每股收益0.92元。</p>\\n<p><strong>BP发布首季交易更新：石油交易表现卓越，净债务预计上升</strong></p>\\n<p>4月14日，BP发布2026年第一季度交易更新报告。报告显示，BP预计第一季度的石油交易结果将表现“卓越”。财务方面，由于营运资本预计出现40亿至70亿美元的显著增加，公司预计截至一季度末的净债务将从2025年底的220亿美元上升至250亿至270亿美元区间。（界面新闻）</p>\\n<p><strong>燕京啤酒：2025年净利润16.79亿元，同比增长59.06%</strong></p>\\n<p>36氪获悉，燕京啤酒披露年报，2025年实现营业收入153.33亿元，同比增长4.54%；归属于上市公司股东的净利润16.79亿元，同比增长59.06%；基本每股收益0.596元。公司拟每10股派发现金红利2元（含税）。</p>\\n<p><strong>鄂尔多斯：2025年净利润23.63亿元，同比增长27.93%</strong></p>\\n<p>36氪获悉，鄂尔多斯披露年报，2025年实现营业收入257.41亿元，同比下降9.37%；归属于上市公司股东的净利润23.63亿元，同比增长27.93%；基本每股收益0.84元。公司拟每10股派发现金红利7元（含税）。</p>\\n<h2>投融资</h2>\\n<p><strong>CREAO AI完成千万美金融资</strong></p>\\n<p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\\n<p><strong>“蓝点触控”完成超亿元C+轮融资</strong></p>\\n<p>36氪获悉，“蓝点触控”近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。这是近一年内蓝点触控完成的第三轮过亿元融资。</p>\\n<p><strong>“庞伯特”完成近2亿元A轮系列融资</strong></p>\\n<p>36氪获悉，“庞伯特”已完成A轮系列融资、三轮累计金额近2亿元，神骐资本、明势创投、蓝驰创投、锦秋基金、华创资本等头部机构参投，高鹄资本担任独家财务顾问。本次融资将用于公司产品技术迭代，同时加速推进全球化品牌与市场布局。</p>\\n<h2>酷产品</h2>\\n<p><strong>高德首款具身机器人将亮相</strong></p>\\n<p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。（上证报）</p>\\n<p><strong>雷诺韩国计划到2029年每年推出新车型</strong></p>\\n<p>据报道，雷诺韩国计划到2029年每年推出新车型，并从2028年起在釜山生产下一代电动车。（财联社）</p>\\n<p><strong>有道词典笔A7S正式发布</strong></p>\\n<p>36氪获悉，14日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\\n<p><strong>亚马逊卫星联网项目Leo发布航空天线</strong></p>\\n<p>亚马逊当地时间4月13日发布了专为商业航空设计的Leo航空天线，该天线利用低地球轨道卫星网络，可提供高达1 Gbps的下载和400 Mbps的上传速度，足以支撑全机乘客同时进行4K视频、游戏或协作办公。目前，亚马逊已与达美航空和捷蓝航空达成合作协议。（界面新闻）</p>\\n<h2>氪大事</h2>\\n<p><strong>氪大事短视频栏目，鲜活解读商业世界大事。</strong> 为了保住同伙，AI有多癫？ </p>\\n<p> </p>\\n<p><strong>年轻人“丰容方式”小调查</strong></p>\\n<p>丰容，一个动物园学术语。原本指动物园通过丰富环境，让圈养动物摆脱单调压抑，减少刻板行为。如今这个词，却被越来越多人用在了自己身上。这些“人类的自我丰容”措施包括但不限于：认真做一顿早餐；走一条从没走过的路；独自打卡一家美食；主动和卖菜摊主聊聊菜价……</p>\\n<p>这种看得见摸得着的小事，或许是一场年轻人的精神自救。你是否也曾通过一些微小的改变，打破重复枯燥的生活常态？让你重新感到安全、充实、新鲜，拿回了生活掌控感？<strong>扫描下方二维码</strong>，分享你的“丰容Tips”。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_8a429eea17a2456dbc9668dff4e5196b@5667365_oswg20430oswg512oswg512_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>年轻人“丰容方式”小调查</p>\\n<p><strong>整理</strong>｜Kris </p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'8点1氪丨许家印一审当庭认罪悔罪；交管部门回应新能源车牌绿色变白色；生成内容涉黄，哩布哩布AI回应\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'8点1氪丨许家印一审当庭认罪悔罪；交管部门回应新能源车牌绿色变白色；生成内容涉黄，哩布哩布AI回应\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3767326268392199?f=rss\'}], \'link\': \'https://36kr.com/p/3767326268392199?f=rss\', \'published\': \'2026-04-15 08:05:51  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=15, tm_hour=0, tm_min=5, tm_sec=51, tm_wday=2, tm_yday=105, tm_isdst=0), \'summary\': \'<h2>今日热点导览</h2>\\\\n  <p>可能含有“永久性化学物”，Lululemon在美被调查</p>\\\\n  <p>近一周“一口价”黄金产品最高下跌17%</p>\\\\n  <p>中国将健全药品价格形成机制</p>\\\\n  <p>离境退税2.0版措施预计4月底前推出</p>\\\\n  <p>苹果加码iPhone Fold</p>\\\\n  <h2>TOP3大新闻</h2>\\\\n  <p><strong>恒大集团、恒大地产及许家印案一审开庭</strong></p>\\\\n  <p>2026年4月13日至14日，广东省深圳市中级人民法院对深圳市人民检察院提起公诉的被告单位恒大集团有限公司非法吸收公众存款、集资诈骗、违法发放贷款、欺诈发行证券、违规披露重要信息、单位行贿，被告单位恒大地产集团有限公司欺诈发行证券，被告人许家印非法吸收公众存款、集资诈骗、违法发放贷款、违法运用资金、欺诈发行证券、违规披露重要信息、职务侵占、单位行贿一案进行了公开开庭审理。庭审中，法庭主持控辩双方围绕指控的事实进行了法庭调查及法庭辩论，被告单位、许家印进行了最后陈述。许家印当庭表示认罪悔罪。法庭将择期宣判。部分人大代表、政协委员，被告人亲属，集资参与人代表等旁听了庭审。（央视新闻）</p>\\\\n  <p><strong>交管部门回应新能源车牌绿色变白色</strong></p>\\\\n  <p>近日，有网友通过社交平台发布视频，称其在路上看到有车辆悬挂白底黑字的机动车号牌，感到十分好奇。通过社交平台搜索发现，国内多地均出现白底黑字的新能源汽车号牌，相关帖文的发布者表达了对于这种车牌风格的喜爱，认为其更具高级感。</p>\\\\n  <p>4月13日，据媒体从交管部门了解到，人为将新能源机动车号牌褪色属于污损车辆号牌，是违法行为，市民如遇此类车牌可向交管部门举报反映。《中华人民共和国道路交通安全法》第十一条明确规定，机动车号牌应按规定悬挂并保持清晰、完整，不得故意遮挡、污损。第九十五条指出，故意遮挡、污损或不按规定安装号牌的，将依据第九十条处以警告或二十元以上二百元以下罚款。（第一财经）</p>\\\\n  <p><strong>哩布哩布AI就内容安全问题致歉</strong></p>\\\\n  <p>4月14日，哩布哩布AI发布关于加强内容安全管理的说明：近期媒体对AI生成内容安全问题的讨论，我们已关注并高度重视。第一时间启动内部专项排查，对平台生成能力及审核机制进行了全面自查。经排查发现，在个别复杂提示词组合及规避表达的边界场景下，平台存在生成不符合规范内容的情况。对此，我们深表歉意。本次问题也为我们敲响了警钟，使我们清醒认识到在内容安全边界识别与机制完善方面仍存在不足，未达到应有标准。相关问题已第一时间完成技术修复，并对风险路径进行全面封堵。同时，我们已同步加强攻防演练与审核机制升级，持续提升识别能力与处置效率，从源头降低风险发生。我们也已启动内部责任复盘机制，进一步完善相关管理与审核流程。(界面新闻)</p>\\\\n  <h2>大公司/大事件</h2>\\\\n  <p><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></p>\\\\n  <p>4月14日，就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。（澎湃新闻）</p>\\\\n  <p><strong>大批“五一”航班突然取消背后：高油价下的停飞潮正在全球蔓延</strong></p>\\\\n  <p>最近一段时间，不少网友在社交平台上，贴出了自己提前预订的“五一”假期机票被取消的截图，被取消的航班主要以飞东南亚和大洋洲居多。记者从多家航空公司获悉，从4月��始主动取消的航班确实有所增加，其中东南亚和大洋洲是重头，这与油价的大幅上涨不无关系。相比国内，部分国际机场加油价格更高，叠加需求和竞争的影响，部分航线的取消就首当其冲。而这样的情况，正在全球航线市场蔓延，也逐渐改变着航空业的竞争格局和旅客的出行选择。（第一财经）</p>\\\\n  <p><strong>可能含有“永久性化学物”，Lululemon在美被调查</strong></p>\\\\n  <p>据路透社报道，美国得克萨斯州总检察长Ken Paxton当地时间4月13日在社交平台X上发文称，已对运动休闲品牌露露乐蒙(Lululemon)展开调查，原因是其运动服饰中可能含有“永久性化学物”。Paxton表示，此次调查将核查露露乐蒙的运动服装是否含有全氟及多氟烷基物质(PFAS)。对此，露露乐蒙一名发言人表示，已知悉此次调查，并将予以配合。露露乐蒙的发言人回应称：“公司产品中并未使用全氟及多氟烷基物质。”该发言人补充称，此前该物质仅少量用于耐用防水类产品，公司已于2023财年完成对其的逐步淘汰。（中新经纬）</p>\\\\n  <p><strong>突破20万小时人类视频，智在无界发布下一代具身世界模型H0.7</strong></p>\\\\n  <p>BeingBeyond（智在无界）发布新一代具身世界模型Being-H0.7，成为业内首个可端侧部署的商用世界模型。该模型基于国内现有最大规模20万小时人类视频，采用隐空间推理方式替代视频生成，首次在75TOPS的低成本端侧计算平台Orin NX上实时部署。Being-H0.7在6项世界权威评测榜单中综合排名第一（其中4项登顶）。公司称，H0.7实现了跨本体迁移和物理世界理解能力，目前已与多家国内具身本体企业建立合作关系。</p>\\\\n  <p><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></p>\\\\n  <p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表14日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。（新浪科技）</p>\\\\n  <p><strong>近一周“一口价”黄金产品最高下跌17%</strong></p>\\\\n  <p>近一周，多个品牌的“一口价”黄金产品价格出现了不同程度的下跌。4月14日，有交易软件发布数据显示，近一周，“一口价”金价波动集中在3000元以下的黄金配饰产品，3000元以上的黄金配饰暂未出现明显变化。老凤祥的莲花吊坠（1g）近一周市场成交价由峰值1683元下跌至1398元，下跌了285元，跌幅17%；中国黄金四叶草吊坠（0.3g）市场成交价由579元下跌至504元，下跌了75元，跌幅13%；中国黄金小金马手链市场成交价由876元下跌至798元，下跌了78元，跌幅9%。</p>\\\\n  <p>除了一口价黄金配饰外，年轻人喜欢“攒金”的小金豆价格也有一定程度下滑，老凤祥金豆（1g）市场成交价从1314元下跌至1195元，下跌了119元，跌幅9%；中国黄金小金猪（0.1g）市场成交价由213元下跌至169元，跌幅21%。（证券时报）</p>\\\\n  <p><strong>执法部门：违规超量投放共享自行车，哈啰拒不改正将被处罚</strong></p>\\\\n  <p>4月13日，执法人员复核整改情况，发现东城区盛德紫阙、簋街等地仍存在大量未备案车辆，经认定，哈啰公司未按交通行政管理部门要求投放车辆，且拒不改正，违反了《北京市非机动车管理条例》及《北京市互联网租赁自行车监管管理办法（试行）》有关规定。针对哈啰公司未按照交通行政管理部门要求投放车辆、拒不改正的行为，依据《北京市非机动车管理条例》第二十条第一项、第三十一条及《北京市交通运输行政处罚裁量基准》，总队将依法对哈啰公司作出行政处罚，并调减其运营规模。目前，该案正在按法定程序办理。（界面新闻）</p>\\\\n  <p><strong>中国将健全药品价格形成机制</strong></p>\\\\n  <p>国务院办公厅4月14日发布《关于健全药品价格形成机制的若干意见》，提出14条举措，包括优化创新药等新上市药品首发价格机制、发挥医保支付标准对药品价格形成的引导作用、引导药店合理制定药品零售价格、强化短缺药保供稳价等。意见要求加强药品价格治理，提出实行药品价格风险预警、健全药品价格风险处置制度、防范非理性竞价中标影响供应、严惩药品和原辅料生产经营领域以缺逼涨等违法违规行为、加强医药领域全链条穿透式审计监督、建立药品医保价值评估制度等针对性措施，引导药品价格运行在合理区间。（新华社）</p>\\\\n  <p><strong>2026总票房突破125亿</strong></p>\\\\n  <p>据网络平台数据，截至4月14日12时08分，2026年度电影总票房（含预售）突破125亿元。(界面新闻)</p>\\\\n  <p><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></p>\\\\n  <p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。（界面新闻）</p>\\\\n  <p><strong>离境退税2.0版措施预计4月底前推出</strong></p>\\\\n  <p>4月14日在第六届消博会期间获悉，离境退税2.0版措施目前正在报批过程中，预计4月底前推出。（中证金牛座）</p>\\\\n  <p><strong>一季度业绩陆续出炉，多家行业龙头公司亮相</strong></p>\\\\n  <p>据统计，4月14日，共计29家上市公司发布2026年一季度业绩相关公告，多家行业龙头公司在列。从净利润规模来看，16家净利润在1亿元以上，盐湖股份、神火股份、金山办公、卫星化学等四家公司均超过20亿元；沪电股份超过10亿元。从净利润变动来看，金山办公同比增幅居首，高达437.35%；神火股份、亚翔集成增幅超过200%；盐湖股份、金徽股份、中船防务、北方稀土等紧随其后，一季度业绩均实现同比翻倍增长。（证券时报）</p>\\\\n  <p><strong>国家统计局：4月上旬生猪（外三元）价格环比下降4.2%</strong></p>\\\\n  <p>36氪获悉，据国家统计局，据对全国流通领域9大类50种重要生产资料市场价格的监测显示，2026年4月上旬与3月下旬相比，30种产品价格上涨，18种下降，2种持平。其中，生猪（外三元）价格为9.1元/千克，环比下降4.2%。</p>\\\\n  <p><strong>Omdia：存储成本上涨推升设备价格，2026年中国大陆智能手机市场小幅下滑1%</strong></p>\\\\n  <p>36氪获悉，Omdia的最新研究显示，2026年第一季度，因为成本上涨导致部分品牌产品涨价，大盘持续呈下滑趋势，中国大陆智能手机市场同比下降1%，出货6980万台。华为以1390万台的出货量得到第一，占据20%市场份额。苹果排名第二，出货量1310万台，市场份额为19%。OPPO在realme回归后首个季度出货1100万台，排名市场前三。vivo出货1050万台，排名第四。小米出货870万台排名第五。</p>\\\\n  <p><strong>美股三大指数集体收涨，纳指连续十个交易日上涨</strong></p>\\\\n  <p>36氪获悉，4月14日收盘，美股三大指数集体个涨，道指涨0.66%，纳指涨1.96%，实现连续十个交易日上涨，标普500指数涨1.18%，大型科技股普涨，Meta涨超4%，英伟达、特斯拉、谷歌、亚马逊涨超3%，微软涨超2%。热门中概股集体走强，爱奇艺涨超11%.京东涨近8%.百度涨超5%.阿里巴巴、哔哩哔哩、小鹏集团涨超2%。拼多多、蔚来涨超1%。</p>\\\\n  <p><strong>特斯拉机器人出租车推进引发现金流担忧，不断增加的支出给财务带来压力</strong></p>\\\\n  <p>特斯拉公司因其向机器人出租车和自动驾驶汽车的进军开始对其现金流造成压力而备受关注，尽管其在全自动驾驶计划中正接近一个重大目标。一些分析师认为，特斯拉今年的资本支出可能超过200亿美元，部分估计甚至高达250亿至300亿美元，具体取决于公司的增长目标。这样的投资水平很可能会导致自由现金流下降。（新浪财经）</p>\\\\n  <p><strong>亚马逊或接近达成收购GlobalStar的交易，以期与Starlink展开竞争</strong></p>\\\\n  <p>知情人士透露，亚马逊接近达成收购GlobalStar的交易，以期与Starlink展开竞争。（财联社）</p>\\\\n  <p><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></p>\\\\n  <p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。（财联社）</p>\\\\n  <p><strong>苹果加码iPhone Fold</strong></p>\\\\n  <p>4月14日，尽管折叠屏手机市场近年成长力道趋缓，但消息称苹果已为首款折叠屏手机iPhone Fold加码20%面板库存。（新浪财经）</p>\\\\n  <p><strong>甲骨文被指在近期裁员中针对持有股票期权的员工</strong></p>\\\\n  <p>根据报道，科技巨头甲骨文近期的大规模裁员引发了争议，有前员工指责公司在裁员过程中，可能通过算法刻意针对那些持有未行权股票期权的资深员工和高绩效人才。报道指出，在甲骨文于3月31日裁员约3万人后，一位在该公司工作了三十余年的前安全警报经理在领英上发帖称，裁员似乎遵循着一种“算法”，专门针对高级个人贡献者、中层管理人员，“尤其是那些持有未行权股票期权的人”。这一指控迅速引发了外界对甲骨文裁员公平性的质疑。（新浪财经）</p>\\\\n  <p><strong>伊媒：伊美或重返伊斯兰堡继续谈判</strong></p>\\\\n  <p>据伊朗新闻电视台15日报道，伊朗和美国代表团可能本周晚些时候在巴基斯坦首都伊斯兰堡重启谈判。伊美双方上轮谈判未能达成协议，在多个问题上存在分歧。（新华社）</p>\\\\n  <p><strong>美能源部长：霍尔木兹海峡通航前，美国能源将持续涨价</strong></p>\\\\n  <p>美国能源部长克里斯·赖特4月13日承认，在霍尔木兹海峡恢复“有意义”的船只通行前，美国能源价格可能持续上涨。克里斯·赖特称，霍尔木兹海峡的航运将在未来数周内恢复。（央视新闻）</p>\\\\n  <p><strong>英伟达否认“洽购大型PC制造商”传闻</strong></p>\\\\n  <p>当地时间4月13日，有消息称，英伟达公司正寻求收购一家大型公司，此举将“重塑个人电脑行业格局”。消息称，英伟达就这笔交易的谈判已持续了一年多。英伟达对此回应称，消息不实，英伟达没有在磋商收购任何个人电脑制造商。（界面新闻）</p>\\\\n  <p><strong>快看漫画将研发多款AI应用，涉及AI角色互动等</strong></p>\\\\n  <p>36氪获悉，4月14日，快看漫画内部正在推进不止一款App，而是一组围绕AI能力展开的多款App组成的产品矩阵。该AI应用矩阵可能覆盖多个用户需求与使用场景，涉及AI角色互动、开放世界、破次元陪伴等维度。</p>\\\\n  <p><strong>谷歌宣布提供1000万美元资助，支持4万名制造业从业者掌握AI技能</strong></p>\\\\n  <p>当地时间4月13日，谷歌宣布提供1000万美元的资助，以支持美国制造业研究所帮助美国劳动力迎接工业创新新时代的到来，这笔资金将助力4万名现有及未来的制造业从业人员掌握AI技能，并将学徒培训机会扩展至全美15个地区。（界面新闻）</p>\\\\n  <p><strong>SpaceX星链业务2025年营收或增长50%，达到114亿美元</strong></p>\\\\n  <p>据报道，马斯克旗下SpaceX公司的最新财务数据显示，星链业务2025年营收增长50%，达到114亿美元，而SpaceX的另外两项业务——火箭发射和人工智能，未能产生足够增长，让投资者为马斯克所寻求的惊人估值买单。（界面新闻）</p>\\\\n  <h2>上市进行时</h2>\\\\n  <p><strong>Nuclea Energy</strong></p>\\\\n  <p>致力于为离网市场及数据中心开发核微反应堆的Nuclea Energy于4月13日向美国证券交易委员会提交申请，拟通过首次公开募股（IPO）筹资最高5000万美元。Nuclea Energy的核心产品为“Morpheus微反应堆”，这是一种可运输、工厂预制、密封堆芯的核反应堆，专为加拿大偏远北极地区和原住民社区、采矿及资源开采、数据中心及关键基础设施、国防与国家安全等场景设计。目前公司仍处于开发阶段，尚未产生任何收入。（新浪财经）</p>\\\\n  <p><strong>越疆</strong></p>\\\\n  <p>36氪获悉，证监会网站披露，深圳市越疆科技股份有限公司（简称“越疆”）IPO辅导状态于近日变更为“辅导验收”。此前，越疆曾于2025年12月30日在深圳证监局办理辅导备案登记，拟首次公开发行股票并在深交所上市，辅导券商为国泰海通证券。</p>\\\\n  <h2>AI最前沿</h2>\\\\n  <p><strong>Seedance 2.0全面开放API服务</strong></p>\\\\n  <p>36氪获悉，火山引擎正式上线Seedance 2.0系列API服务。据介绍，Seedance 2.0支持文字、图片、音频、视频四种模态输入。火山引擎为Seedance 2.0建立了肖像与版权安全标准，覆盖视频生成涉及的各种模态和创作前后的全部流程。</p>\\\\n  <p><strong>MiniMax Agent桌面端更新：新增Pocket功能，支持接入飞书、微信等</strong></p>\\\\n  <p>36氪获悉，MiniMax发布MiniMax Agent桌面端两项更新：Pocket功能上线（Beta版），支持接入飞书、微信、企业微信、Slack等主流IM通讯软件；Computer Use功能上线，Agent可以像人一样看屏幕、操作鼠标和键盘，直接操作用户电脑上的软件。</p>\\\\n  <p><strong>美团发布AI产品“小团健康管家”</strong></p>\\\\n  <p>36氪获悉，4月14日，在乌镇健康大会上，美团正式发布聚焦家庭健康管理的AI产品“小团健康管家”和全新付费会员服务“健康卡”。前者提供基础的问病问药、健康咨询服务，还支持家庭健康档案管理和体检报告智能解读。用户在对话中可跳转线上购药、在线问诊或预约线下就医。“健康卡”则提供超千款药品购药返现服务，其中原研药超过300款。</p>\\\\n  <p><strong>诺和诺德宣布与OpenAI建立战略合作伙伴关系</strong></p>\\\\n  <p>诺和诺德4月14日宣布与OpenAI建立战略合作伙伴关系，此次合作将运用先进的人工智能能力，对复杂数据集进行分析，筛选具有潜力的候选药物，并缩短从基础研究到惠及患者所需的周期。（界面新闻）</p>\\\\n  <p><strong>对标OpenClaw，微软拟为Copilot开发新功能</strong></p>\\\\n  <p>据报道，微软正为其AI助手Copilot开发一系列新功能，旨在使其更接近OpenClaw。微软表示，公司目前正“在企业应用场景下，探索OpenClaw等技术的潜力”。这些新特性包括在Microsoft 365应用程序内部引入一支“始终在线”的智能代理团队。（界面新闻）</p>\\\\n  <h2>大公司财报</h2>\\\\n  <p><strong>LVMH集团第一季度收入下滑6%</strong></p>\\\\n  <p>LVMH集团2026年第一季度营收191.21亿欧元（约合人民币1537亿元），同比下滑6%，有机收入增长1%。该集团提到，在中国、亚洲及美国看到有机收入稳健增长，而中东市场受到该地持续冲突的严重影响，拖累集团一季度有机收入下滑1%。分部门看，营收占比近50%的时装与皮具同比下滑9%，有机收入减少2%；余下部门按规模大小依次是精品零售、珠宝腕表、香水和化妆品、葡萄酒和烈酒，同比分别下滑3%、2%、6%和2%，有机收入增长4%、7%、0%和5%。（界面新闻）</p>\\\\n  <p><strong>申通快递：2025年净利润13.69亿元，同比增长31.63%</strong></p>\\\\n  <p>36氪获悉，申通快递发布业绩快报，2025年实现营业总收入555.86亿元，同比增长17.84%；归属于上市公司股东的净利润13.69亿元，同比增长31.63%；基本每股收益0.92元。</p>\\\\n  <p><strong>BP发布首季交易更新：石油交易表现卓越，净债务预计上升</strong></p>\\\\n  <p>4月14日，BP发布2026年第一季度交易更新报告。报告显示，BP预计第一季度的石油交易结果将表现“卓越”。财务方面，由于营运资本预计出现40亿至70亿美元的显著增加，公司预计截至一季度末的净债务将从2025年底的220亿美元上升至250亿至270亿美元区间。（界面新闻）</p>\\\\n  <p><strong>燕京啤酒：2025年净利润16.79亿元，同比增长59.06%</strong></p>\\\\n  <p>36氪获悉，燕京啤酒披露年报，2025年实现营业收入153.33亿元，同比增长4.54%；归属于上市公司股东的净利润16.79亿元，同比增长59.06%；基本每股收益0.596元。公司拟每10股派发现金红利2元（含税）。</p>\\\\n  <p><strong>鄂尔多斯：2025年净利润23.63亿元，同比增长27.93%</strong></p>\\\\n  <p>36氪获悉，鄂尔多斯披露年报，2025年实现营业收入257.41亿元，同比下降9.37%；归属于上市公司股东的净利润23.63亿元，同比增长27.93%；基本每股收益0.84元。公司拟每10股派发现金红利7元（含税）。</p>\\\\n  <h2>投融资</h2>\\\\n  <p><strong>CREAO AI完成千万美金融资</strong></p>\\\\n  <p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\\\\n  <p><strong>“蓝点触控”完成超亿元C+轮融资</strong></p>\\\\n  <p>36氪获悉，“蓝点触控”近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。这是近一年内蓝点触控完成的第三轮过亿元融资。</p>\\\\n  <p><strong>“庞伯特”完成近2亿元A轮系列融资</strong></p>\\\\n  <p>36氪获悉，“庞伯特”已完成A轮系列融资、三轮累计金额近2亿元，神骐资本、明势创投、蓝驰创投、锦秋基金、华创资本等头部机构参投，高鹄资本担任独家财务顾问。本次融资将用于公司产品技术迭代，同时加速推进全球化品牌与市场布局。</p>\\\\n  <h2>酷产品</h2>\\\\n  <p><strong>高德首款具身机器人将亮相</strong></p>\\\\n  <p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。（上证报）</p>\\\\n  <p><strong>雷诺韩国计划到2029年每年推出新车型</strong></p>\\\\n  <p>据报道，雷诺韩国计划到2029年每年推出新车型，并从2028年起在釜山生产下一代电动车。（财联社）</p>\\\\n  <p><strong>有道词典笔A7S正式发布</strong></p>\\\\n  <p>36氪获悉，14日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\\\\n  <p><strong>亚马逊卫星联网项目Leo发布航空天线</strong></p>\\\\n  <p>亚马逊当地时间4月13日发布了专为商业航空设计的Leo航空天线，该天线利用低地球轨道卫星网络，可提供高达1 Gbps的下载和400 Mbps的上传速度，足以支撑全机乘客同时进行4K视频、游戏或协作办公。目前，亚马逊已与达美航空和捷蓝航空达成合作协议。（界面新闻）</p>\\\\n  <h2>氪大事</h2>\\\\n  <p><strong>氪大事短视频栏目，鲜活解读商业世界大事。</strong> 为了保住同伙，AI有多癫？&nbsp;</p>\\\\n  <p>&nbsp;</p>\\\\n  <p><strong>年轻人“丰容方式”小调查</strong></p>\\\\n  <p>丰容，一个动物园学术语。原本指动物园通过丰富环境，让圈养动物摆脱单调压抑，减少刻板行为。如今这个词，却被越来越多人用在了自己身上。这些“人类的自我丰容”措施包括但不限于：认真做一顿早餐；走一条从没走过的路；独自打卡一家美食；主动和卖菜摊主聊聊菜价……</p>\\\\n  <p>这种看得见摸得着的小事，或许是一场年轻人的精神自救。你是否也曾通过一些微小的改变，打破重复枯燥的生活常态？让你重新感到安全、充实、新鲜，拿回了生活掌控感？<strong>扫描下方二维码</strong>，分享你的“丰容Tips”。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_8a429eea17a2456dbc9668dff4e5196b@5667365_oswg20430oswg512oswg512_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">年轻人“丰容方式”小调查</p>\\\\n  <p><strong>整理</strong>｜Kris&nbsp;</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<h2>今日热点导览</h2>\\\\n  <p>可能含有“永久性化学物”，Lululemon在美被调查</p>\\\\n  <p>近一周“一口价”黄金产品最高下跌17%</p>\\\\n  <p>中国将健全药品价格形成机制</p>\\\\n  <p>离境退税2.0版措施预计4月底前推出</p>\\\\n  <p>苹果加码iPhone Fold</p>\\\\n  <h2>TOP3大新闻</h2>\\\\n  <p><strong>恒大集团、恒大地产及许家印案一审开庭</strong></p>\\\\n  <p>2026年4月13日至14日，广东省深圳市中级人民法院对深圳市人民检察院提起公诉的被告单位恒大集团有限公司非法吸收公众存款、集资诈骗、违法发放贷款、欺诈发行证券、违规披露重要信息、单位行贿，被告单位恒大地产集团有限公司欺诈发行证券，被告人许家印非法吸收公众存款、集资诈骗、违法发放贷款、违法运用资金、欺诈发行证券、违规披露重要信息、职务侵占、单位行贿一案进行了公开开庭审理。庭审中，法庭主持控辩双方围绕指控的事实进行了法庭调查及法庭辩论，被告单位、许家印进行了最后陈述。许家印当庭表示认罪悔罪。法庭将择期宣判。部分人大代表、政协委员，被告人亲属，集资参与人代表等旁听了庭审。（央视新闻）</p>\\\\n  <p><strong>交管部门回应新能源车牌绿色变白色</strong></p>\\\\n  <p>近日，有网友通过社交平台发布视频，称其在路上看到有车辆悬挂白底黑字的机动车号牌，感到十分好奇。通过社交平台搜索发现，国内多地均出现白底黑字的新能源汽车号牌，相关帖文的发布者表达了对于这种车牌风格的喜爱，认为其更具高级感。</p>\\\\n  <p>4月13日，据媒体从交管部门了解到，人为将新能源机动车号牌褪色属于污损车辆号牌，是违法行为，市民如遇此类车牌可向交管部门举报反映。《中华人民共和国道路交通安全法》第十一条明确规定，机动车号牌应按规定悬挂并保持清晰、完整，不得故意遮挡、污损。第九十五条指出，故意遮挡、污损或不按规定安装号牌的，将依据第九十条处以警告或二十元以上二百元以下罚款。（第一财经）</p>\\\\n  <p><strong>哩布哩布AI就内容安全问题致歉</strong></p>\\\\n  <p>4月14日，哩布哩布AI发布关于加强内容安全管理的说明：近期媒体对AI生成内容安全问题的讨论，我们已关注并高度重视。第一时间启动内部专项排查，对平台生成能力及审核机制进行了全面自查。经排查发现，在个别复杂提示词组合及规避表达的边界场景下，平台存在生成不符合规范内容的情况。对此，我们深表歉意。本次问题也为我们敲响了警钟，使我们清醒认识到在内容安全边界识别与机制完善方面仍存在不足，未达到应有标准。相关问题已第一时间完成技术修复，并对风险路径进行全面封堵。同时，我们已同步加强攻防演练与审核机制升级，持续提升识别能力与处置效率，从源头降低风险发生。我们也已启动内部责任复盘机制，进一步完善相关管理与审核流程。(界面新闻)</p>\\\\n  <h2>大公司/大事件</h2>\\\\n  <p><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></p>\\\\n  <p>4月14日，就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。（澎湃新闻）</p>\\\\n  <p><strong>大批“五一”航班突然取消背后：高油价下的停飞潮正在全球蔓延</strong></p>\\\\n  <p>最近一段时间，不少网友在社交平台上，贴出了自己提前预订的“五一”假期机票被取消的截图，被取消的航班主要以飞东南亚和大洋洲居多。记者从多家航空公司获悉，从4月��始主动取消的航班确实有所增加，其中东南亚和大洋洲是重头，这与油价的大幅上涨不无关系。相比国内，部分国际机场加油价格更高，叠加需求和竞争的影响，部分航线的取消就首当其冲。而这样的情况，正在全球航线市场蔓延，也逐渐改变着航空业的竞争格局和旅客的出行选择。（第一财经）</p>\\\\n  <p><strong>可能含有“永久性化学物”，Lululemon在美被调查</strong></p>\\\\n  <p>据路透社报道，美国得克萨斯州总检察长Ken Paxton当地时间4月13日在社交平台X上发文称，已对运动休闲品牌露露乐蒙(Lululemon)展开调查，原因是其运动服饰中可能含有“永久性化学物”。Paxton表示，此次调查将核查露露乐蒙的运动服装是否含有全氟及多氟烷基物质(PFAS)。对此，露露乐蒙一名发言人表示，已知悉此次调查，并将予以配合。露露乐蒙的发言人回应称：“公司产品中并未使用全氟及多氟烷基物质。”该发言人补充称，此前该物质仅少量用于耐用防水类产品，公司已于2023财年完成对其的逐步淘汰。（中新经纬）</p>\\\\n  <p><strong>突破20万小时人类视频，智在无界发布下一代具身世界模型H0.7</strong></p>\\\\n  <p>BeingBeyond（智在无界）发布新一代具身世界模型Being-H0.7，成为业内首个可端侧部署的商用世界模型。该模型基于国内现有最大规模20万小时人类视频，采用隐空间推理方式替代视频生成，首次在75TOPS的低成本端侧计算平台Orin NX上实时部署。Being-H0.7在6项世界权威评测榜单中综合排名第一（其中4项登顶）。公司称，H0.7实现了跨本体迁移和物理世界理解能力，目前已与多家国内具身本体企业建立合作关系。</p>\\\\n  <p><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></p>\\\\n  <p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表14日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。（新浪科技）</p>\\\\n  <p><strong>近一周“一口价”黄金产品最高下跌17%</strong></p>\\\\n  <p>近一周，多个品牌的“一口价”黄金产品价格出现了不同程度的下跌。4月14日，有交易软件发布数据显示，近一周，“一口价”金价波动集中在3000元以下的黄金配饰产品，3000元以上的黄金配饰暂未出现明显变化。老凤祥的莲花吊坠（1g）近一周市场成交价由峰值1683元下跌至1398元，下跌了285元，跌幅17%；中国黄金四叶草吊坠（0.3g）市场成交价由579元下跌至504元，下跌了75元，跌幅13%；中国黄金小金马手链市场成交价由876元下跌至798元，下跌了78元，跌幅9%。</p>\\\\n  <p>除了一口价黄金配饰外，年轻人喜欢“攒金”的小金豆价格也有一定程度下滑，老凤祥金豆（1g）市场成交价从1314元下跌至1195元，下跌了119元，跌幅9%；中国黄金小金猪（0.1g）市场成交价由213元下跌至169元，跌幅21%。（证券时报）</p>\\\\n  <p><strong>执法部门：违规超量投放共享自行车，哈啰拒不改正将被处罚</strong></p>\\\\n  <p>4月13日，执法人员复核整改情况，发现东城区盛德紫阙、簋街等地仍存在大量未备案车辆，经认定，哈啰公司未按交通行政管理部门要求投放车辆，且拒不改正，违反了《北京市非机动车管理条例》及《北京市互联网租赁自行车监管管理办法（试行）》有关规定。针对哈啰公司未按照交通行政管理部门要求投放车辆、拒不改正的行为，依据《北京市非机动车管理条例》第二十条第一项、第三十一条及《北京市交通运输行政处罚裁量基准》，总队将依法对哈啰公司作出行政处罚，并调减其运营规模。目前，该案正在按法定程序办理。（界面新闻）</p>\\\\n  <p><strong>中国将健全药品价格形成机制</strong></p>\\\\n  <p>国务院办公厅4月14日发布《关于健全药品价格形成机制的若干意见》，提出14条举措，包括优化创新药等新上市药品首发价格机制、发挥医保支付标准对药品价格形成的引导作用、引导药店合理制定药品零售价格、强化短缺药保供稳价等。意见要求加强药品价格治理，提出实行药品价格风险预警、健全药品价格风险处置制度、防范非理性竞价中标影响供应、严惩药品和原辅料生产经营领域以缺逼涨等违法违规行为、加强医药领域全链条穿透式审计监督、建立药品医保价值评估制度等针对性措施，引导药品价格运行在合理区间。（新华社）</p>\\\\n  <p><strong>2026总票房突破125亿</strong></p>\\\\n  <p>据网络平台数据，截至4月14日12时08分，2026年度电影总票房（含预售）突破125亿元。(界面新闻)</p>\\\\n  <p><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></p>\\\\n  <p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。（界面新闻）</p>\\\\n  <p><strong>离境退税2.0版措施预计4月底前推出</strong></p>\\\\n  <p>4月14日在第六届消博会期间获悉，离境退税2.0版措施目前正在报批过程中，预计4月底前推出。（中证金牛座）</p>\\\\n  <p><strong>一季度业绩陆续出炉，多家行业龙头公司亮相</strong></p>\\\\n  <p>据统计，4月14日，共计29家上市公司发布2026年一季度业绩相关公告，多家行业龙头公司在列。从净利润规模来看，16家净利润在1亿元以上，盐湖股份、神火股份、金山办公、卫星化学等四家公司均超过20亿元；沪电股份超过10亿元。从净利润变动来看，金山办公同比增幅居首，高达437.35%；神火股份、亚翔集成增幅超过200%；盐湖股份、金徽股份、中船防务、北方稀土等紧随其后，一季度业绩均实现同比翻倍增长。（证券时报）</p>\\\\n  <p><strong>国家统计局：4月上旬生猪（外三元）价格环比下降4.2%</strong></p>\\\\n  <p>36氪获悉，据国家统计局，据对全国流通领域9大类50种重要生产资料市场价格的监测显示，2026年4月上旬与3月下旬相比，30种产品价格上涨，18种下降，2种持平。其中，生猪（外三元）价格为9.1元/千克，环比下降4.2%。</p>\\\\n  <p><strong>Omdia：存储成本上涨推升设备价格，2026年中国大陆智能手机市场小幅下滑1%</strong></p>\\\\n  <p>36氪获悉，Omdia的最新研究显示，2026年第一季度，因为成本上涨导致部分品牌产品涨价，大盘持续呈下滑趋势，中国大陆智能手机市场同比下降1%，出货6980万台。华为以1390万台的出货量得到第一，占据20%市场份额。苹果排名第二，出货量1310万台，市场份额为19%。OPPO在realme回归后首个季度出货1100万台，排名市场前三。vivo出货1050万台，排名第四。小米出货870万台排名第五。</p>\\\\n  <p><strong>美股三大指数集体收涨，纳指连续十个交易日上涨</strong></p>\\\\n  <p>36氪获悉，4月14日收盘，美股三大指数集体个涨，道指涨0.66%，纳指涨1.96%，实现连续十个交易日上涨，标普500指数涨1.18%，大型科技股普涨，Meta涨超4%，英伟达、特斯拉、谷歌、亚马逊涨超3%，微软涨超2%。热门中概股集体走强，爱奇艺涨超11%.京东涨近8%.百度涨超5%.阿里巴巴、哔哩哔哩、小鹏集团涨超2%。拼多多、蔚来涨超1%。</p>\\\\n  <p><strong>特斯拉机器人出租车推进引发现金流担忧，不断增加的支出给财务带来压力</strong></p>\\\\n  <p>特斯拉公司因其向机器人出租车和自动驾驶汽车的进军开始对其现金流造成压力而备受关注，尽管其在全自动驾驶计划中正接近一个重大目标。一些分析师认为，特斯拉今年的资本支出可能超过200亿美元，部分估计甚至高达250亿至300亿美元，具体取决于公司的增长目标。这样的投资水平很可能会导致自由现金流下降。（新浪财经）</p>\\\\n  <p><strong>亚马逊或接近达成收购GlobalStar的交易，以期与Starlink展开竞争</strong></p>\\\\n  <p>知情人士透露，亚马逊接近达成收购GlobalStar的交易，以期与Starlink展开竞争。（财联社）</p>\\\\n  <p><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></p>\\\\n  <p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。（财联社）</p>\\\\n  <p><strong>苹果加码iPhone Fold</strong></p>\\\\n  <p>4月14日，尽管折叠屏手机市场近年成长力道趋缓，但消息称苹果已为首款折叠屏手机iPhone Fold加码20%面板库存。（新浪财经）</p>\\\\n  <p><strong>甲骨文被指在近期裁员中针对持有股票期权的员工</strong></p>\\\\n  <p>根据报道，科技巨头甲骨文近期的大规模裁员引发了争议，有前员工指责公司在裁员过程中，可能通过算法刻意针对那些持有未行权股票期权的资深员工和高绩效人才。报道指出，在甲骨文于3月31日裁员约3万人后，一位在该公司工作了三十余年的前安全警报经理在领英上发帖称，裁员似乎遵循着一种“算法”，专门针对高级个人贡献者、中层管理人员，“尤其是那些持有未行权股票期权的人”。这一指控迅速引发了外界对甲骨文裁员公平性的质疑。（新浪财经）</p>\\\\n  <p><strong>伊媒：伊美或重返伊斯兰堡继续谈判</strong></p>\\\\n  <p>据伊朗新闻电视台15日报道，伊朗和美国代表团可能本周晚些时候在巴基斯坦首都伊斯兰堡重启谈判。伊美双方上轮谈判未能达成协议，在多个问题上存在分歧。（新华社）</p>\\\\n  <p><strong>美能源部长：霍尔木兹海峡通航前，美国能源将持续涨价</strong></p>\\\\n  <p>美国能源部长克里斯·赖特4月13日承认，在霍尔木兹海峡恢复“有意义”的船只通行前，美国能源价格可能持续上涨。克里斯·赖特称，霍尔木兹海峡的航运将在未来数周内恢复。（央视新闻）</p>\\\\n  <p><strong>英伟达否认“洽购大型PC制造商”传闻</strong></p>\\\\n  <p>当地时间4月13日，有消息称，英伟达公司正寻求收购一家大型公司，此举将“重塑个人电脑行业格局”。消息称，英伟达就这笔交易的谈判已持续了一年多。英伟达对此回应称，消息不实，英伟达没有在磋商收购任何个人电脑制造商。（界面新闻）</p>\\\\n  <p><strong>快看漫画将研发多款AI应用，涉及AI角色互动等</strong></p>\\\\n  <p>36氪获悉，4月14日，快看漫画内部正在推进不止一款App，而是一组围绕AI能力展开的多款App组成的产品矩阵。该AI应用矩阵可能覆盖多个用户需求与使用场景，涉及AI角色互动、开放世界、破次元陪伴等维度。</p>\\\\n  <p><strong>谷歌宣布提供1000万美元资助，支持4万名制造业从业者掌握AI技能</strong></p>\\\\n  <p>当地时间4月13日，谷歌宣布提供1000万美元的资助，以支持美国制造业研究所帮助美国劳动力迎接工业创新新时代的到来，这笔资金将助力4万名现有及未来的制造业从业人员掌握AI技能，并将学徒培训机会扩展至全美15个地区。（界面新闻）</p>\\\\n  <p><strong>SpaceX星链业务2025年营收或增长50%，达到114亿美元</strong></p>\\\\n  <p>据报道，马斯克旗下SpaceX公司的最新财务数据显示，星链业务2025年营收增长50%，达到114亿美元，而SpaceX的另外两项业务——火箭发射和人工智能，未能产生足够增长，让投资者为马斯克所寻求的惊人估值买单。（界面新闻）</p>\\\\n  <h2>上市进行时</h2>\\\\n  <p><strong>Nuclea Energy</strong></p>\\\\n  <p>致力于为离网市场及数据中心开发核微反应堆的Nuclea Energy于4月13日向美国证券交易委员会提交申请，拟通过首次公开募股（IPO）筹资最高5000万美元。Nuclea Energy的核心产品为“Morpheus微反应堆”，这是一种可运输、工厂预制、密封堆芯的核反应堆，专为加拿大偏远北极地区和原住民社区、采矿及资源开采、数据中心及关键基础设施、国防与国家安全等场景设计。目前公司仍处于开发阶段，尚未产生任何收入。（新浪财经）</p>\\\\n  <p><strong>越疆</strong></p>\\\\n  <p>36氪获悉，证监会网站披露，深圳市越疆科技股份有限公司（简称“越疆”）IPO辅导状态于近日变更为“辅导验收”。此前，越疆曾于2025年12月30日在深圳证监局办理辅导备案登记，拟首次公开发行股票并在深交所上市，辅导券商为国泰海通证券。</p>\\\\n  <h2>AI最前沿</h2>\\\\n  <p><strong>Seedance 2.0全面开放API服务</strong></p>\\\\n  <p>36氪获悉，火山引擎正式上线Seedance 2.0系列API服务。据介绍，Seedance 2.0支持文字、图片、音频、视频四种模态输入。火山引擎为Seedance 2.0建立了肖像与版权安全标准，覆盖视频生成涉及的各种模态和创作前后的全部流程。</p>\\\\n  <p><strong>MiniMax Agent桌面端更新：新增Pocket功能，支持接入飞书、微信等</strong></p>\\\\n  <p>36氪获悉，MiniMax发布MiniMax Agent桌面端两项更新：Pocket功能上线（Beta版），支持接入飞书、微信、企业微信、Slack等主流IM通讯软件；Computer Use功能上线，Agent可以像人一样看屏幕、操作鼠标和键盘，直接操作用户电脑上的软件。</p>\\\\n  <p><strong>美团发布AI产品“小团健康管家”</strong></p>\\\\n  <p>36氪获悉，4月14日，在乌镇健康大会上，美团正式发布聚焦家庭健康管理的AI产品“小团健康管家”和全新付费会员服务“健康卡”。前者提供基础的问病问药、健康咨询服务，还支持家庭健康档案管理和体检报告智能解读。用户在对话中可跳转线上购药、在线问诊或预约线下就医。“健康卡”则提供超千款药品购药返现服务，其中原研药超过300款。</p>\\\\n  <p><strong>诺和诺德宣布与OpenAI建立战略合作伙伴关系</strong></p>\\\\n  <p>诺和诺德4月14日宣布与OpenAI建立战略合作伙伴关系，此次合作将运用先进的人工智能能力，对复杂数据集进行分析，筛选具有潜力的候选药物，并缩短从基础研究到惠及患者所需的周期。（界面新闻）</p>\\\\n  <p><strong>对标OpenClaw，微软拟为Copilot开发新功能</strong></p>\\\\n  <p>据报道，微软正为其AI助手Copilot开发一系列新功能，旨在使其更接近OpenClaw。微软表示，公司目前正“在企业应用场景下，探索OpenClaw等技术的潜力”。这些新特性包括在Microsoft 365应用程序内部引入一支“始终在线”的智能代理团队。（界面新闻）</p>\\\\n  <h2>大公司财报</h2>\\\\n  <p><strong>LVMH集团第一季度收入下滑6%</strong></p>\\\\n  <p>LVMH集团2026年第一季度营收191.21亿欧元（约合人民币1537亿元），同比下滑6%，有机收入增长1%。该集团提到，在中国、亚洲及美国看到有机收入稳健增长，而中东市场受到该地持续冲突的严重影响，拖累集团一季度有机收入下滑1%。分部门看，营收占比近50%的时装与皮具同比下滑9%，有机收入减少2%；余下部门按规模大小依次是精品零售、珠宝腕表、香水和化妆品、葡萄酒和烈酒，同比分别下滑3%、2%、6%和2%，有机收入增长4%、7%、0%和5%。（界面新闻）</p>\\\\n  <p><strong>申通快递：2025年净利润13.69亿元，同比增长31.63%</strong></p>\\\\n  <p>36氪获悉，申通快递发布业绩快报，2025年实现营业总收入555.86亿元，同比增长17.84%；归属于上市公司股东的净利润13.69亿元，同比增长31.63%；基本每股收益0.92元。</p>\\\\n  <p><strong>BP发布首季交易更新：石油交易表现卓越，净债务预计上升</strong></p>\\\\n  <p>4月14日，BP发布2026年第一季度交易更新报告。报告显示，BP预计第一季度的石油交易结果将表现“卓越”。财务方面，由于营运资本预计出现40亿至70亿美元的显著增加，公司预计截至一季度末的净债务将从2025年底的220亿美元上升至250亿至270亿美元区间。（界面新闻）</p>\\\\n  <p><strong>燕京啤酒：2025年净利润16.79亿元，同比增长59.06%</strong></p>\\\\n  <p>36氪获悉，燕京啤酒披露年报，2025年实现营业收入153.33亿元，同比增长4.54%；归属于上市公司股东的净利润16.79亿元，同比增长59.06%；基本每股收益0.596元。公司拟每10股派发现金红利2元（含税）。</p>\\\\n  <p><strong>鄂尔多斯：2025年净利润23.63亿元，同比增长27.93%</strong></p>\\\\n  <p>36氪获悉，鄂尔多斯披露年报，2025年实现营业收入257.41亿元，同比下降9.37%；归属于上市公司股东的净利润23.63亿元，同比增长27.93%；基本每股收益0.84元。公司拟每10股派发现金红利7元（含税）。</p>\\\\n  <h2>投融资</h2>\\\\n  <p><strong>CREAO AI完成千万美金融资</strong></p>\\\\n  <p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\\\\n  <p><strong>“蓝点触控”完成超亿元C+轮融资</strong></p>\\\\n  <p>36氪获悉，“蓝点触控”近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。这是近一年内蓝点触控完成的第三轮过亿元融资。</p>\\\\n  <p><strong>“庞伯特”完成近2亿元A轮系列融资</strong></p>\\\\n  <p>36氪获悉，“庞伯特”已完成A轮系列融资、三轮累计金额近2亿元，神骐资本、明势创投、蓝驰创投、锦秋基金、华创资本等头部机构参投，高鹄资本担任独家财务顾问。本次融资将用于公司产品技术迭代，同时加速推进全球化品牌与市场布局。</p>\\\\n  <h2>酷产品</h2>\\\\n  <p><strong>高德首款具身机器人将亮相</strong></p>\\\\n  <p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。（上证报）</p>\\\\n  <p><strong>雷诺韩国计划到2029年每年推出新车型</strong></p>\\\\n  <p>据报道，雷诺韩国计划到2029年每年推出新车型，并从2028年起在釜山生产下一代电动车。（财联社）</p>\\\\n  <p><strong>有道词典笔A7S正式发布</strong></p>\\\\n  <p>36氪获悉，14日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\\\\n  <p><strong>亚马逊卫星联网项目Leo发布航空天线</strong></p>\\\\n  <p>亚马逊当地时间4月13日发布了专为商业航空设计的Leo航空天线，该天线利用低地球轨道卫星网络，可提供高达1 Gbps的下载和400 Mbps的上传速度，足以支撑全机乘客同时进行4K视频、游戏或协作办公。目前，亚马逊已与达美航空和捷蓝航空达成合作协议。（界面新闻）</p>\\\\n  <h2>氪大事</h2>\\\\n  <p><strong>氪大事短视频栏目，鲜活解读商业世界大事。</strong> 为了保住同伙，AI有多癫？&nbsp;</p>\\\\n  <p>&nbsp;</p>\\\\n  <p><strong>年轻人“丰容方式”小调查</strong></p>\\\\n  <p>丰容，一个动物园学术语。原本指动物园通过丰富环境，让圈养动物摆脱单调压抑，减少刻板行为。如今这个词，却被越来越多人用在了自己身上。这些“人类的自我丰容”措施包括但不限于：认真做一顿早餐；走一条从没走过的路；独自打卡一家美食；主动和卖菜摊主聊聊菜价……</p>\\\\n  <p>这种看得见摸得着的小事，或许是一场年轻人的精神自救。你是否也曾通过一些微小的改变，打破重复枯燥的生活常态？让你重新感到安全、充实、新鲜，拿回了生活掌控感？<strong>扫描下方二维码</strong>，分享你的“丰容Tips”。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_8a429eea17a2456dbc9668dff4e5196b@5667365_oswg20430oswg512oswg512_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">年轻人“丰容方式”小调查</p>\\\\n  <p><strong>整理</strong>｜Kris&nbsp;</p>\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-15 08:05:51\", \"ai_json_output\": \"\"}', NULL, '2026-04-15 08:05:51', '2026-04-16 12:00:40');
INSERT INTO `news_detail` VALUES (33, 1053, 9, '内容与社交', '《明末》团队解散背后，国产单机究竟还缺什么？', '', '<p>文丨果脯</p>\n<p>编辑丨刘士武</p>\n<p>过去几天里，《明末：渊虚之羽》（后称：明末）制作组解散、制作人夏思源离职创业的消息，让不少人感到唏嘘。</p>\n<p>这款由灵泽科技开发的国产类魂动作游戏，曾被寄予厚望，后续也取得了不错的成绩。</p>\n<p>据统计，2025年上线后，游戏在Steam预估销量约120万套，主机平台PS5约30至40万套，加上其他渠道总计约200万套，销售额超过5亿元。这样的成绩，放在国内单机史上，已与《戴森球计划》《鬼谷八荒》等大火产品同处一个量级。</p>\n<p>更重要的是，它把国产单机游戏的单价继续推到了3A级价位——Steam国区248元，海外49.99美元，又一次证明了国产单机也能站稳3A赛道。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_7778be437ee04255a0333917b40cc0fd@6202862_oswg578637oswg1080oswg568_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《明末：渊虚之羽》的Steam界面</p>\n<p>灵泽的故事也确实励志。这家从VR游戏起家、曾靠外包维持运转的团队，凭一腔热血熬出了《明末》，一度穷到只剩理想支撑。</p>\n<p>然而热闹背后藏着尴尬。上线后的舆论风波、优化问题、定价策略失误，以及最致命的剧情方向与主流玩家预期的严重偏差，让这款产品<strong>从“村里第二个大学生”一夜变成了“村里的第一个大学退学生”。</strong></p>\n<p>发行商505 Games虽仍以“Strong”形容游戏表现，但多方分账之后，项目首年仅能勉强打平研发成本，无法形成持续的利润闭环。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_2dae518a862c438c9080a5f70ed47d1d@242988687_oswg1875806oswg1969oswg1110_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1\"></p>\n<p>夏思源讲解《明末》关卡设计（36氪拍摄于2025年7月的灵泽科技）</p>\n<p>去年游戏上线前，36氪游戏曾与灵泽科技几位核心创始成员进行过深入交流，彼时我们能感受到这个团队对于《明末》的信心与期待。</p>\n<p>毕竟，这家成立于2016年的公司，初期大部分营收来源于外包——2021年正式上市的VR游戏《A.D.2047》并不足以证明灵泽制作大型游戏甚至3A级单机的能力。但对于几位创始成员来说，3A国单是梦想，也是《明末》能够坚持至今取得亮眼销量成绩的原因。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_ba0e6f1aea2146bfafd77669f2c944b7@6202862_oswg73701oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《明末：渊虚之羽》</p>\n<p><strong>然而，一系列的事件后，《明末》最终还是迎来了这样一个Bad Eding——</strong></p>\n<p>灵泽股方要求团队全部转外包，团队拒绝，团队直接被解散，制作人夏思源带着不足5万元注册资本的工作室从零开始。前几天我们与夏思源简单沟通得知，他已经在专注于新的工作。</p>\n<p>或许过去的就让它过去吧。</p>\n<p>但唏嘘背后，一款销量约200万套、过了“成本关”的游戏，一棋下错，满盘皆输，最终落得物是人非的境地。这究竟是为什么？或者说，国产单机走到今天，我们究竟还缺什么？</p>\n<p>要回答这个问题，有必要先正视一个事实：<strong>时至今日，国产游戏或许早已不需要向世界证明什么。</strong></p>\n<p>“人越炫耀什么，就越缺什么”这句俗语，大多数人都听过。它可能不完全对，但多少有几分道理。很长一段时间，当我们反复强调“中国游戏”如何如何，可能都依旧下意识把自己放在低位，试图向世界证明什么。但现在，这个命题或许已经悄然翻转。</p>\n<p>论产品能力与文化传播力，国内诸多二次元游戏哪怕在二次元文化的发源地日本，都已建立起无可比拟的统治力。从《原神》开启的“文化输出”讨论，到《鸣潮》在海外掀起的热潮，再到《恋与深空》拿下TGA、App Store、Google Play等多个维度的奖项，中国游戏产品早已站上全球头部赛道。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_9c5d99392992439096a34c5ec603da05@6202862_oswg63910oswg552oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《恋与深空》在东京电玩展</p>\n<p>腾讯的《三角洲行动》则是在欧美最擅长的射击赛道，进一步拉高了此类产品的天花板。比起过去一味的模仿、追赶，这款产品基本是从\"搜打撤\"的玩法循环中，真真正正摸索出了一个属于自己的解法。</p>\n<p>有部分人质疑它的优秀成绩仅限于国内，但不可否认，它比《逃离塔科夫》或《ARC Raider》都更先找到了理想化的商业化与玩法平衡的解法，甚至在这条路上走得更远。</p>\n<p>而聚焦到更具体的产品，《黑神话：悟空》不论是技术力还是项目管理水平，基本得以比肩世界第一梯队的团队。2024年正式发售后，首月销量破2000万份，全球媒体评分均在90分以上，TGA年度游戏提名。2000万份的销量证明了\"中国人也有做好3A\"的能力。</p>\n<p>它不仅是一款成功的游戏，更是一个文化符号——它告诉世界：<strong>中国人，也能做出世界顶级的单机大作。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_d48005e0018b4a7e83356c768423fbb3@6202862_oswg69840oswg1080oswg698_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《很神话：悟空》</p>\n<p>此外，国内游戏市场每年依旧会爆出一些足够惊艳的小产品。像去年上线的《苏丹的游戏》《逃离鸭科夫》《明末：渊虚之羽》，以及即将推出的《影之刃零》等等，都在不同路线上推动着国产单机的前行。基于这份成绩，国外甚至已经出现了有关\"中国游戏\"的专属词条。在Reddit上，r/ChineseGames小组的成员已经超过10万，他们讨论的不再只是\"made in China\"，而是那些真正由中国团队主导、有中国味儿的原创作品。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_231cd3848c5e42b882cdc548a73d6165@6202862_oswg123151oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《影之刃零》</p>\n<p>说白了，时至今日我们或许已经不用再向世界去证明什么。所谓\"想要国产游戏崛起\"的期望，更多是中国游戏人基于热爱、经历和遗憾，而对当下与未来生出的一股子心气。</p>\n<p><strong>那么，这股心气为什么最终又会聚焦于\"国产单机\"这一标签？</strong></p>\n<p>明显能看到，即使在长线运营的多端互通产品上已成绩斐然，行业与玩家最寄望的，依然是更多的《黑神话：悟空》。玩家的这份希冀，甚至比下一个《王者荣耀》或《原神》来得更猛烈。</p>\n<p>究其原因，一方面，单机游戏的商品属性更弱，内容属性更强。与粗暴的DAU、留存等数据化指标相比，这类产品具有更加强烈的设计导向和内容驱动。并且在这个一切都变成\"长线服务\"的时代，单机游戏难得保留着一股子完整性。它要求你坐下来，投入几十小时，与角色建立情感连接，最终在通关的那一刻，获得一种算法永远无法给予的\"完成感\"。</p>\n<p>另一方面，时至今日，玩家都需要足够多的高质量产品去证明：比起纯粹的娱乐性，电子游戏作为走在科技前沿的产物，实际还能承载住更多意义与价值。并且如果游戏还需要被“正名”，国产单机游戏也是最有力的武器。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_a9cbf2670d3b4507a2a995e5ea2ddd8f@6202862_oswg52547oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《古剑奇谭3》</p>\n<p>只是，回看这批国产游戏开发者的成长路径，会有一个更深的体感：他们大多从小玩着千禧年前后的优秀国产作品长大，经历过国产游戏的辉煌，也见识了它的衰落，更经历过在不同公司打工赚钱的日子。游戏科学为了做出\"黑神话\"，必须先造出\"斗战神\"；灵游坊想要养家糊口，也得先放下\"雨血\"先做\"影之刃\"。一如冯骥所说：\"我们想做自己的游戏，想了很多年。\"</p>\n<p>于他们而言，做一款属于自己的单机游戏，无异于机车迷找到了哈雷。这不是高低之分，只是前两者中，很多人可能只是飞机上的一颗螺丝钉，受各类数据牵制，并不符合他们这代人最初对游戏的印象。</p>\n<p>而从市场层面看，根据《2025年中国游戏产业报告》显示，包含了单机与网游的“客户端游戏”，其营收占比行业全年总营收的22.26%；而主机游戏则仅占比2.38%。当然，无论是客户端还是主机游戏，整体增长仍然强劲，从侧面证明了国单的崛起和玩家的期待。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_202ecfd70aca4f199d28514ad018f175@6202862_oswg53158oswg1080oswg637_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《2025年中国游戏产业报告》</p>\n<p><strong>除了市场规模的增长以外，钱也是重要推手。</strong></p>\n<p>过去几年，随着游戏市场逐渐成熟，手游借助工业化模式已经变得相对稳定，越来越多的资本积累开始流向可能性更多的单机领域。腾讯投资了游戏科学、灵游坊等一大批单机团队；网易已着手开发《归唐》；米哈游的品质已逐步开始向单机的设计质感靠拢；鹰角也在逐步尝试各类不同方向的单机产品。<strong>与其说是资本不再现实了，不如说是单机游戏的回报率让他们足以愿意为此投入。</strong></p>\n<p>同时，基于多年积累，中国玩家数量显著增多。2015年，Steam的中国用户数还只有几百万，而现在一度超过5000万，占了软件整体用户数量的半壁江山。中国已经有了一个巨大且愿意为正版付费的玩家群体。</p>\n<p>而最后不可忽视的，还有国家政策各个维度的支持。从前几年版号回暖开始，国家层面对游戏行业的关注度明显在持续上升。2023年，中国音像与数字出版协会联合央视推出纪录片《中国游戏纪事》；2025年，教育部通过游戏艺术设计专业，将游戏学科正式纳入国家高等教育体系；国务院新闻办公室举办发布会，提及要发展游戏出海业务，布局从IP打造到游戏制作、发行、海外运营的整个产业链——这是国务院第一次在发布会上提及游戏。针对游戏开发者，北京、上海、深圳、广州各地也已开启了相应的政府扶持政策。</p>\n<p>但《黑神话：悟空》的出现，会不会只是昙花一现？</p>\n<p>显然不是。但大家想要的，确实不只是一两款偶然成功的产品，而是一个\"国产单机\"不再需要被特意强调的时代。</p>\n<p>去年11月，知乎上曾冒出个提问：\"2026年会是国产单机游戏更加百花齐放的一年吗？\"问题并不具体，整体数据寥寥，没什么人关注。底下的回答只有一条，来自《太吾绘卷》制作人茄子：</p>\n<p><strong>\"这是必然的，大势所趋。\"</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_0d1bf28d523c498cb52e5b196f989a74@6202862_oswg13622oswg418oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>茄子的知乎回答</p>\n<p>这句话，或许是对未来几年国产单机游戏市场最好的预测与总结，就像《黑神话：悟空》的出现并非偶然，而是数十年积累沉淀而爆发的必然结果。况且，<strong>当一个行业的从业者开始用\"必然\"而非\"希望\"来描述未来时，风向其实就已经变了。</strong></p>\n<p>于投资人而言，比起早几年偶然爆品时期，现在无疑是更好的入局时间。不论是玩家数量、官方关注度还是技术支持，都已能构建出一套足够完整、可持续的商业生态。一个明显的证据是：比起单独的某款新品，各大公司明显开始更加关注自身持有的IP，以及未来长线发展的可能。</p>\n<p>中手游收购《仙剑奇侠传》全球IP版权，意图构建\"仙剑宇宙\"；网元圣唐围绕《古剑奇谭》打造影视、游戏、衍生品联动；就连一向被视为\"手游大厂\"的腾讯，也开始在年度发布会上给单机产品留出专门的版块。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_d92aa46c15264f41ba8011a8e73cdd1a@6202862_oswg70384oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《湮灭之潮》</p>\n<p>长此以往，做单机游戏就不再是一件需要\"卖房卖车，只为追梦\"的事情，而是一件有利可图、有意义可寻的事情。</p>\n<p>而往深了看，这同样意味着游戏作为娱乐媒介的价值正在被重新定义。在碎片化的信息时代，当短视频以15秒为单位切割着人们的注意力，当算法用无尽的推荐消解着深度思考的可能，单机游戏这种强沉浸感、高互动性的娱乐模式，反而成为了一种稀缺的\"完整体验\"。而对于国产游戏而言，这种\"完整体验\"的载体，恰好是我们自己那些尚未被表述、被传达出来的文化。</p>\n<p>2022年，《原神》推出\"神女劈观\"章节，一段以京剧为基底、融合现代音乐创作的剧情短片，在海外引发热潮。外国玩家为了理解\"云堇\"的唱词，主动去查阅中国戏曲的历史；YouTube上出现了大量解析\"京剧唱腔\"\"戏词韵脚\"的教学视频。《古剑奇谭三》则以\"传承\"为主题，将视角从个人爱恨情仇，拉升到种族存续、文明传承的高度，让无数人第一次从游戏身上感受到了游戏作为文化载体的表达使命。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_3b13dda1b32646d9bcc775fcc86dc8cd@6202862_oswg503039oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>《古剑奇谭3》最后的寄语</p>\n<p>这些无法通过纯粹言语传递的情绪与精神，往往能借助视听互动的模式，让人更感同身受地理解。</p>\n<p>这就是为什么，国产游戏剩下的路，是它自己的路。这条路没有现成的模板可以参考，因为我们要讲述的故事、要触达的玩家、要承载的文化，都是独一份的。欧美的魔幻史诗、日本的武士物语，都已找到了最适合自己的表达方式。而中国的武侠、仙侠、神话、历史，以及当代都市里那些细碎的日常，正在等待属于自己的游戏语言。</p>\n<p><strong>回到开头的那个问题：国产单机究竟还缺什么？</strong></p>\n<p>或许缺的从来不是做出好产品的能力，而是一套能让好产品持续活下去的生态。《明末》的故事已经说明，一款销量约200万套的游戏，在海外成熟市场或许会被给予持续投入的机会，但在这里，团队在第一次\"不够成功\"之后就失去了一切。这是整个行业都需要回答的问题：当越来越多的团队选择走这条路，我们能不能给他们足够的支撑系统？</p>\n<p>《明末》的制作人夏思源，在离开灵泽后成立了自己的工作室，注册资本只有5万元。他需要的不是情怀式的惋惜，而是一个能够让他再次安稳做产品的环境。</p>\n<p>这条路肯定还有曲折，会有人失败，会有团队解散。但这一次，站在牌桌上的并不是少数情怀人，而是一整代经历过断层的玩家和从业者。他们见过辉煌，也见过衰落；他们被现实打磨过，但心底那团火始终没灭。</p>\n<p><strong>毕竟，胜败乃兵家常事，大侠还请重新来过。</strong></p>', 'https://36kr.com/p/3766718158324489?f=rss', 0, '', '{\"summary\": \"本文复盘国产单机项目发展案例，分析国产游戏产业现状，为国产游戏出海布局提供行业参考\", \"abstract\": \"本文以取得超5亿元销售额、近200万套销量的国产3A单机《明末：渊虚之羽》制作团队解散事件切入，探讨国产单机游戏发展的问题与未来。当前国产游戏已经具备制作世界级3A大作的能力，多款产品已经在全球市场取得亮眼成绩，同时也获得了政策扶持、资本投入以及庞大付费用户群体的支撑。文章指出，国产单机目前不缺制作优质产品的能力，缺的是能让好产品持续发展存活的成熟产业生态。整体来看，国产单机产业大势向好，未来将迎来百花齐放的发展阶段\", \"keywords\": [\"国产单机游戏\", \"游戏出海\", \"3A游戏\", \"文化出海\", \"产业生态\", \"游戏IP\"], \"policy_risk\": {\"market_risk\": \"国产单机产业尚未形成成熟的可持续发展生态，优质项目出现争议后团队难以获得持续发展空间，中小游戏开发者生存支撑不足\", \"policy_compliance\": \"国家出台多项政策支持游戏产业发展，包括版号回暖、将游戏学科纳入国家高等教育体系，国务院首次明确提出发展游戏出海，多地出台针对游戏开发者的扶持政策\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"内容与社交\"}', '', '{\"url\": \"https://36kr.com/p/3766718158324489?f=rss\", \"title\": \"《明末》团队解散背后，国产单机究竟还缺什么？\", \"source\": \"https://36kr.com/feed\", \"content\": \"<p>文丨果脯</p>\\n<p>编辑丨刘士武</p>\\n<p>过去几天里，《明末：渊虚之羽》（后称：明末）制作组解散、制作人夏思源离职创业的消息，让不少人感到唏嘘。</p>\\n<p>这款由灵泽科技开发的国产类魂动作游戏，曾被寄予厚望，后续也取得了不错的成绩。</p>\\n<p>据统计，2025年上线后，游戏在Steam预估销量约120万套，主机平台PS5约30至40万套，加上其他渠道总计约200万套，销售额超过5亿元。这样的成绩，放在国内单机史上，已与《戴森球计划》《鬼谷八荒》等大火产品同处一个量级。</p>\\n<p>更重要的是，它把国产单机游戏的单价继续推到了3A级价位——Steam国区248元，海外49.99美元，又一次证明了国产单机也能站稳3A赛道。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_7778be437ee04255a0333917b40cc0fd@6202862_oswg578637oswg1080oswg568_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《明末：渊虚之羽》的Steam界面</p>\\n<p>灵泽的故事也确实励志。这家从VR游戏起家、曾靠外包维持运转的团队，凭一腔热血熬出了《明末》，一度穷到只剩理想支撑。</p>\\n<p>然而热闹背后藏着尴尬。上线后的舆论风波、优化问题、定价策略失误，以及最致命的剧情方向与主流玩家预期的严重偏差，让这款产品<strong>从“村里第二个大学生”一夜变成了“村里的第一个大学退学生”。</strong></p>\\n<p>发行商505 Games虽仍以“Strong”形容游戏表现，但多方分账之后，项目首年仅能勉强打平研发成本，无法形成持续的利润闭环。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_2dae518a862c438c9080a5f70ed47d1d@242988687_oswg1875806oswg1969oswg1110_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1\\\"></p>\\n<p>夏思源讲解《明末》关卡设计（36氪拍摄于2025年7月的灵泽科技）</p>\\n<p>去年游戏上线前，36氪游戏曾与灵泽科技几位核心创始成员进行过深入交流，彼时我们能感受到这个团队对于《明末》的信心与期待。</p>\\n<p>毕竟，这家成立于2016年的公司，初期大部分营收来源于外包——2021年正式上市的VR游戏《A.D.2047》并不足以证明灵泽制作大型游戏甚至3A级单机的能力。但对于几位创始成员来说，3A国单是梦想，也是《明末》能够坚持至今取得亮眼销量成绩的原因。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_ba0e6f1aea2146bfafd77669f2c944b7@6202862_oswg73701oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《明末：渊虚之羽》</p>\\n<p><strong>然而，一系列的事件后，《明末》最终还是迎来了这样一个Bad Eding——</strong></p>\\n<p>灵泽股方要求团队全部转外包，团队拒绝，团队直接被解散，制作人夏思源带着不足5万元注册资本的工作室从零开始。前几天我们与夏思源简单沟通得知，他已经在专注于新的工作。</p>\\n<p>或许过去的就让它过去吧。</p>\\n<p>但唏嘘背后，一款销量约200万套、过了“成本关”的游戏，一棋下错，满盘皆输，最终落得物是人非的境地。这究竟是为什么？或者说，国产单机走到今天，我们究竟还缺什么？</p>\\n<p>要回答这个问题，有必要先正视一个事实：<strong>时至今日，国产游戏或许早已不需要向世界证明什么。</strong></p>\\n<p>“人越炫耀什么，就越缺什么”这句俗语，大多数人都听过。它可能不完全对，但多少有几分道理。很长一段时间，当我们反复强调“中国游戏”如何如何，可能都依旧下意识把自己放在低位，试图向世界证明什么。但现在，这个命题或许已经悄然翻转。</p>\\n<p>论产品能力与文化传播力，国内诸多二次元游戏哪怕在二次元文化的发源地日本，都已建立起无可比拟的统治力。从《原神》开启的“文化输出”讨论，到《鸣潮》在海外掀起的热潮，再到《恋与深空》拿下TGA、App Store、Google Play等多个维度的奖项，中国游戏产品早已站上全球头部赛道。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_9c5d99392992439096a34c5ec603da05@6202862_oswg63910oswg552oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《恋与深空》在东京电玩展</p>\\n<p>腾讯的《三角洲行动》则是在欧美最擅长的射击赛道，进一步拉高了此类产品的天花板。比起过去一味的模仿、追赶，这款产品基本是从\\\"搜打撤\\\"的玩法循环中，真真正正摸索出了一个属于自己的解法。</p>\\n<p>有部分人质疑它的优秀成绩仅限于国内，但不可否认，它比《逃离塔科夫》或《ARC Raider》都更先找到了理想化的商业化与玩法平衡的解法，甚至在这条路上走得更远。</p>\\n<p>而聚焦到更具体的产品，《黑神话：悟空》不论是技术力还是项目管理水平，基本得以比肩世界第一梯队的团队。2024年正式发售后，首月销量破2000万份，全球媒体评分均在90分以上，TGA年度游戏提名。2000万份的销量证明了\\\"中国人也有做好3A\\\"的能力。</p>\\n<p>它不仅是一款成功的游戏，更是一个文化符号——它告诉世界：<strong>中国人，也能做出世界顶级的单机大作。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_d48005e0018b4a7e83356c768423fbb3@6202862_oswg69840oswg1080oswg698_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《很神话：悟空》</p>\\n<p>此外，国内游戏市场每年依旧会爆出一些足够惊艳的小产品。像去年上线的《苏丹的游戏》《逃离鸭科夫》《明末：渊虚之羽》，以及即将推出的《影之刃零》等等，都在不同路线上推动着国产单机的前行。基于这份成绩，国外甚至已经出现了有关\\\"中国游戏\\\"的专属词条。在Reddit上，r/ChineseGames小组的成员已经超过10万，他们讨论的不再只是\\\"made in China\\\"，而是那些真正由中国团队主导、有中国味儿的原创作品。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_231cd3848c5e42b882cdc548a73d6165@6202862_oswg123151oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《影之刃零》</p>\\n<p>说白了，时至今日我们或许已经不用再向世界去证明什么。所谓\\\"想要国产游戏崛起\\\"的期望，更多是中国游戏人基于热爱、经历和遗憾，而对当下与未来生出的一股子心气。</p>\\n<p><strong>那么，这股心气为什么最终又会聚焦于\\\"国产单机\\\"这一标签？</strong></p>\\n<p>明显能看到，即使在长线运营的多端互通产品上已成绩斐然，行业与玩家最寄望的，依然是更多的《黑神话：悟空》。玩家的这份希冀，甚至比下一个《王者荣耀》或《原神》来得更猛烈。</p>\\n<p>究其原因，一方面，单机游戏的商品属性更弱，内容属性更强。与粗暴的DAU、留存等数据化指标相比，这类产品具有更加强烈的设计导向和内容驱动。并且在这个一切都变成\\\"长线服务\\\"的时代，单机游戏难得保留着一股子完整性。它要求你坐下来，投入几十小时，与角色建立情感连接，最终在通关的那一刻，获得一种算法永远无法给予的\\\"完成感\\\"。</p>\\n<p>另一方面，时至今日，玩家都需要足够多的高质量产品去证明：比起纯粹的娱乐性，电子游戏作为走在科技前沿的产物，实际还能承载住更多意义与价值。并且如果游戏还需要被“正名”，国产单机游戏也是最有力的武器。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_a9cbf2670d3b4507a2a995e5ea2ddd8f@6202862_oswg52547oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《古剑奇谭3》</p>\\n<p>只是，回看这批国产游戏开发者的成长路径，会有一个更深的体感：他们大多从小玩着千禧年前后的优秀国产作品长大，经历过国产游戏的辉煌，也见识了它的衰落，更经历过在不同公司打工赚钱的日子。游戏科学为了做出\\\"黑神话\\\"，必须先造出\\\"斗战神\\\"；灵游坊想要养家糊口，也得先放下\\\"雨血\\\"先做\\\"影之刃\\\"。一如冯骥所说：\\\"我们想做自己的游戏，想了很多年。\\\"</p>\\n<p>于他们而言，做一款属于自己的单机游戏，无异于机车迷找到了哈雷。这不是高低之分，只是前两者中，很多人可能只是飞机上的一颗螺丝钉，受各类数据牵制，并不符合他们这代人最初对游戏的印象。</p>\\n<p>而从市场层面看，根据《2025年中国游戏产业报告》显示，包含了单机与网游的“客户端游戏”，其营收占比行业全年总营收的22.26%；而主机游戏则仅占比2.38%。当然，无论是客户端还是主机游戏，整体增长仍然强劲，从侧面证明了国单的崛起和玩家的期待。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_202ecfd70aca4f199d28514ad018f175@6202862_oswg53158oswg1080oswg637_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《2025年中国游戏产业报告》</p>\\n<p><strong>除了市场规模的增长以外，钱也是重要推手。</strong></p>\\n<p>过去几年，随着游戏市场逐渐成熟，手游借助工业化模式已经变得相对稳定，越来越多的资本积累开始流向可能性更多的单机领域。腾讯投资了游戏科学、灵游坊等一大批单机团队；网易已着手开发《归唐》；米哈游的品质已逐步开始向单机的设计质感靠拢；鹰角也在逐步尝试各类不同方向的单机产品。<strong>与其说是资本不再现实了，不如说是单机游戏的回报率让他们足以愿意为此投入。</strong></p>\\n<p>同时，基于多年积累，中国玩家数量显著增多。2015年，Steam的中国用户数还只有几百万，而现在一度超过5000万，占了软件整体用户数量的半壁江山。中国已经有了一个巨大且愿意为正版付费的玩家群体。</p>\\n<p>而最后不可忽视的，还有国家政策各个维度的支持。从前几年版号回暖开始，国家层面对游戏行业的关注度明显在持续上升。2023年，中国音像与数字出版协会联合央视推出纪录片《中国游戏纪事》；2025年，教育部通过游戏艺术设计专业，将游戏学科正式纳入国家高等教育体系；国务院新闻办公室举办发布会，提及要发展游戏出海业务，布局从IP打造到游戏制作、发行、海外运营的整个产业链——这是国务院第一次在发布会上提及游戏。针对游戏开发者，北京、上海、深圳、广州各地也已开启了相应的政府扶持政策。</p>\\n<p>但《黑神话：悟空》的出现，会不会只是昙花一现？</p>\\n<p>显然不是。但大家想要的，确实不只是一两款偶然成功的产品，而是一个\\\"国产单机\\\"不再需要被特意强调的时代。</p>\\n<p>去年11月，知乎上曾冒出个提问：\\\"2026年会是国产单机游戏更加百花齐放的一年吗？\\\"问题并不具体，整体数据寥寥，没什么人关注。底下的回答只有一条，来自《太吾绘卷》制作人茄子：</p>\\n<p><strong>\\\"这是必然的，大势所趋。\\\"</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_0d1bf28d523c498cb52e5b196f989a74@6202862_oswg13622oswg418oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>茄子的知乎回答</p>\\n<p>这句话，或许是对未来几年国产单机游戏市场最好的预测与总结，就像《黑神话：悟空》的出现并非偶然，而是数十年积累沉淀而爆发的必然结果。况且，<strong>当一个行业的从业者开始用\\\"必然\\\"而非\\\"希望\\\"来描述未来时，风向其实就已经变了。</strong></p>\\n<p>于投资人而言，比起早几年偶然爆品时期，现在无疑是更好的入局时间。不论是玩家数量、官方关注度还是技术支持，都已能构建出一套足够完整、可持续的商业生态。一个明显的证据是：比起单独的某款新品，各大公司明显开始更加关注自身持有的IP，以及未来长线发展的可能。</p>\\n<p>中手游收购《仙剑奇侠传》全球IP版权，意图构建\\\"仙剑宇宙\\\"；网元圣唐围绕《古剑奇谭》打造影视、游戏、衍生品联动；就连一向被视为\\\"手游大厂\\\"的腾讯，也开始在年度发布会上给单机产品留出专门的版块。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_d92aa46c15264f41ba8011a8e73cdd1a@6202862_oswg70384oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《湮灭之潮》</p>\\n<p>长此以往，做单机游戏就不再是一件需要\\\"卖房卖车，只为追梦\\\"的事情，而是一件有利可图、有意义可寻的事情。</p>\\n<p>而往深了看，这同样意味着游戏作为娱乐媒介的价值正在被重新定义。在碎片化的信息时代，当短视频以15秒为单位切割着人们的注意力，当算法用无尽的推荐消解着深度思考的可能，单机游戏这种强沉浸感、高互动性的娱乐模式，反而成为了一种稀缺的\\\"完整体验\\\"。而对于国产游戏而言，这种\\\"完整体验\\\"的载体，恰好是我们自己那些尚未被表述、被传达出来的文化。</p>\\n<p>2022年，《原神》推出\\\"神女劈观\\\"章节，一段以京剧为基底、融合现代音乐创作的剧情短片，在海外引发热潮。外国玩家为了理解\\\"云堇\\\"的唱词，主动去查阅中国戏曲的历史；YouTube上出现了大量解析\\\"京剧唱腔\\\"\\\"戏词韵脚\\\"的教学视频。《古剑奇谭三》则以\\\"传承\\\"为主题，将视角从个人爱恨情仇，拉升到种族存续、文明传承的高度，让无数人第一次从游戏身上感受到了游戏作为文化载体的表达使命。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_3b13dda1b32646d9bcc775fcc86dc8cd@6202862_oswg503039oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>《古剑奇谭3》最后的寄语</p>\\n<p>这些无法通过纯粹言语传递的情绪与精神，往往能借助视听互动的模式，让人更感同身受地理解。</p>\\n<p>这就是为什么，国产游戏剩下的路，是它自己的路。这条路没有现成的模板可以参考，因为我们要讲述的故事、要触达的玩家、要承载的文化，都是独一份的。欧美的魔幻史诗、日本的武士物语，都已找到了最适合自己的表达方式。而中国的武侠、仙侠、神话、历史，以及当代都市里那些细碎的日常，正在等待属于自己的游戏语言。</p>\\n<p><strong>回到开头的那个问题：国产单机究竟还缺什么？</strong></p>\\n<p>或许缺的从来不是做出好产品的能力，而是一套能让好产品持续活下去的生态。《明末》的故事已经说明，一款销量约200万套的游戏，在海外成熟市场或许会被给予持续投入的机会，但在这里，团队在第一次\\\"不够成功\\\"之后就失去了一切。这是整个行业都需要回答的问题：当越来越多的团队选择走这条路，我们能不能给他们足够的支撑系统？</p>\\n<p>《明末》的制作人夏思源，在离开灵泽后成立了自己的工作室，注册资本只有5万元。他需要的不是情怀式的惋惜，而是一个能够让他再次安稳做产品的环境。</p>\\n<p>这条路肯定还有曲折，会有人失败，会有团队解散。但这一次，站在牌桌上的并不是少数情怀人，而是一整代经历过断层的玩家和从业者。他们见过辉煌，也见过衰落；他们被现实打磨过，但心底那团火始终没灭。</p>\\n<p><strong>毕竟，胜败乃兵家常事，大侠还请重新来过。</strong></p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'《明末》团队解散背后，国产单机究竟还缺什么？\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'《明末》团队解散背后，国产单机究竟还缺什么？\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766718158324489?f=rss\'}], \'link\': \'https://36kr.com/p/3766718158324489?f=rss\', \'published\': \'2026-04-15 08:00:00  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=15, tm_hour=0, tm_min=0, tm_sec=0, tm_wday=2, tm_yday=105, tm_isdst=0), \'summary\': \'<p>文丨果脯</p>\\\\n  <p>编辑丨刘士武</p>\\\\n  <p>过去几天里，《明末：渊虚之羽》（后称：明末）制作组解散、制作人夏思源离职创业的消息，让不少人感到唏嘘。</p>\\\\n  <p>这款由灵泽科技开发的国产类魂动作游戏，曾被寄予厚望，后续也取得了不错的成绩。</p>\\\\n  <p>据统计，2025年上线后，游戏在Steam预估销量约120万套，主机平台PS5约30至40万套，加上其他渠道总计约200万套，销售额超过5亿元。这样的成绩，放在国内单机史上，已与《戴森球计划》《鬼谷八荒》等大火产品同处一个量级。</p>\\\\n  <p>更重要的是，它把国产单机游戏的单价继续推到了3A级价位——Steam国区248元，海外49.99美元，又一次证明了国产单机也能站稳3A赛道。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_7778be437ee04255a0333917b40cc0fd@6202862_oswg578637oswg1080oswg568_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《明末：渊虚之羽》的Steam界面</p>\\\\n  <p>灵泽的故事也确实励志。这家从VR游戏起家、曾靠外包维持运转的团队，凭一腔热血熬出了《明末》，一度穷到只剩理想支撑。</p>\\\\n  <p>然而热闹背后藏着尴尬。上线后的舆论风波、优化问题、定价策略失误，以及最致命的剧情方向与主流玩家预期的严重偏差，让这款产品<strong>从“村里第二个大学生”一夜变成了“村里的第一个大学退学生”。</strong></p>\\\\n  <p>发行商505 Games虽仍以“Strong”形容游戏表现，但多方分账之后，项目首年仅能勉强打平研发成本，无法形成持续的利润闭环。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_2dae518a862c438c9080a5f70ed47d1d@242988687_oswg1875806oswg1969oswg1110_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">夏思源讲解《明末》关卡设计（36氪拍摄于2025年7月的灵泽科技）</p>\\\\n  <p>去年游戏上线前，36氪游戏曾与灵泽科技几位核心创始成员进行过深入交流，彼时我们能感受到这个团队对于《明末》的信心与期待。</p>\\\\n  <p>毕竟，这家成立于2016年的公司，初期大部分营收来源于外包——2021年正式上市的VR游戏《A.D.2047》并不足以证明灵泽制作大型游戏甚至3A级单机的能力。但对于几位创始成员来说，3A国单是梦想，也是《明末》能够坚持至今取得亮眼销量成绩的原因。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_ba0e6f1aea2146bfafd77669f2c944b7@6202862_oswg73701oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《明末：渊虚之羽》</p>\\\\n  <p><strong>然而，一系列的事件后，《明末》最终还是迎来了这样一个Bad&nbsp;Eding——</strong></p>\\\\n  <p>灵泽股方要求团队全部转外包，团队拒绝，团队直接被解散，制作人夏思源带着不足5万元注册资本的工作室从零开始。前几天我们与夏思源简单沟通得知，他已经在专注于新的工作。</p>\\\\n  <p>或许过去的就让它过去吧。</p>\\\\n  <p>但唏嘘背后，一款销量约200万套、过了“成本关”的游戏，一棋下错，满盘皆输，最终落得物是人非的境地。这究竟是为什么？或者说，国产单机走到今天，我们究竟还缺什么？</p>\\\\n  <p>要回答这个问题，有必要先正视一个事实：<strong>时至今日，国产游戏或许早已不需要向世界证明什么。</strong></p>\\\\n  <p>“人越炫耀什么，就越缺什么”这句俗语，大多数人都听过。它可能不完全对，但多少有几分道理。很长一段时间，当我们反复强调“中国游戏”如何如何，可能都依旧下意识把自己放在低位，试图向世界证明什么。但现在，这个命题或许已经悄然翻转。</p>\\\\n  <p>论产品能力与文化传播力，国内诸多二次元游戏哪怕在二次元文化的发源地日本，都已建立起无可比拟的统治力。从《原神》开启的“文化输出”讨论，到《鸣潮》在海外掀起的热潮，再到《恋与深空》拿下TGA、App Store、Google Play等多个维度的奖项，中国游戏产品早已站上全球头部赛道。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_9c5d99392992439096a34c5ec603da05@6202862_oswg63910oswg552oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《恋与深空》在东京电玩展</p>\\\\n  <p>腾讯的《三角洲行动》则是在欧美最擅长的射击赛道，进一步拉高了此类产品的天花板。比起过去一味的模仿、追赶，这款产品基本是从\\\"搜打撤\\\"的玩法循环中，真真正正摸索出了一个属于自己的解法。</p>\\\\n  <p>有部分人质疑它的优秀成绩仅限于国内，但不可否认，它比《逃离塔科夫》或《ARC Raider》都更先找到了理想化的商业化与玩法平衡的解法，甚至在这条路上走得更远。</p>\\\\n  <p>而聚焦到更具体的产品，《黑神话：悟空》不论是技术力还是项目管理水平，基本得以比肩世界第一梯队的团队。2024年正式发售后，首月销量破2000万份，全球媒体评分均在90分以上，TGA年度游戏提名。2000万份的销量证明了\\\"中国人也有做好3A\\\"的能力。</p>\\\\n  <p>它不仅是一款成功的游戏，更是一个文化符号——它告诉世界：<strong>中国人，也能做出世界顶级的单机大作。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_d48005e0018b4a7e83356c768423fbb3@6202862_oswg69840oswg1080oswg698_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《很神话：悟空》</p>\\\\n  <p>此外，国内游戏市场每年依旧会爆出一些足够惊艳的小产品。像去年上线的《苏丹的游戏》《逃离鸭科夫》《明末：渊虚之羽》，以及即将推出的《影之刃零》等等，都在不同路线上推动着国产单机的前行。基于这份成绩，国外甚至已经出现了有关\\\"中国游戏\\\"的专属词条。在Reddit上，r/ChineseGames小组的成员已经超过10万，他们讨论的不再只是\\\"made in China\\\"，而是那些真正由中国团队主导、有中国味儿的原创作品。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_231cd3848c5e42b882cdc548a73d6165@6202862_oswg123151oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《影之刃零》</p>\\\\n  <p>说白了，时至今日我们或许已经不用再向世界去证明什么。所谓\\\"想要国产游戏崛起\\\"的期望，更多是中国游戏人基于热爱、经历和遗憾，而对当下与未来生出的一股子心气。</p>\\\\n  <p><strong>那么，这股心气为什么最终又会聚焦于\\\"国产单机\\\"这一标签？</strong></p>\\\\n  <p>明显能看到，即使在长线运营的多端互通产品上已成绩斐然，行业与玩家最寄望的，依然是更多的《黑神话：悟空》。玩家的这份希冀，甚至比下一个《王者荣耀》或《原神》来得更猛烈。</p>\\\\n  <p>究其原因，一方面，单机游戏的商品属性更弱，内容属性更强。与粗暴的DAU、留存等数据化指标相比，这类产品具有更加强烈的设计导向和内容驱动。并且在这个一切都变成\\\"长线服务\\\"的时代，单机游戏难得保留着一股子完整性。它要求你坐下来，投入几十小时，与角色建立情感连接，最终在通关的那一刻，获得一种算法永远无法给予的\\\"完成感\\\"。</p>\\\\n  <p>另一方面，时至今日，玩家都需要足够多的高质量产品去证明：比起纯粹的娱乐性，电子游戏作为走在科技前沿的产物，实际还能承载住更多意义与价值。并且如果游戏还需要被“正名”，国产单机游戏也是最有力的武器。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_a9cbf2670d3b4507a2a995e5ea2ddd8f@6202862_oswg52547oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《古剑奇谭3》</p>\\\\n  <p>只是，回看这批国产游戏开发者的成长路径，会有一个更深的体感：他们大多从小玩着千禧年前后的优秀国产作品长大，经历过国产游戏的辉煌，也见识了它的衰落，更经历过在不同公司打工赚钱的日子。游戏科学为了做出\\\"黑神话\\\"，必须先造出\\\"斗战神\\\"；灵游坊想要养家糊口，也得先放下\\\"雨血\\\"先做\\\"影之刃\\\"。一如冯骥所说：\\\"我们想做自己的游戏，想了很多年。\\\"</p>\\\\n  <p>于他们而言，做一款属于自己的单机游戏，无异于机车迷找到了哈雷。这不是高低之分，只是前两者中，很多人可能只是飞机上的一颗螺丝钉，受各类数据牵制，并不符合他们这代人最初对游戏的印象。</p>\\\\n  <p>而从市场层面看，根据《2025年中国游戏产业报告》显示，包含了单机与网游的“客户端游戏”，其营收占比行业全年总营收的22.26%；而主机游戏则仅占比2.38%。当然，无论是客户端还是主机游戏，整体增长仍然强劲，从侧面证明了国单的崛起和玩家的期待。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_202ecfd70aca4f199d28514ad018f175@6202862_oswg53158oswg1080oswg637_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《2025年中国游戏产业报告》</p>\\\\n  <p><strong>除了市场规模的增长以外，钱也是重要推手。</strong></p>\\\\n  <p>过去几年，随着游戏市场逐渐成熟，手游借助工业化模式已经变得相对稳定，越来越多的资本积累开始流向可能性更多的单机领域。腾讯投资了游戏科学、灵游坊等一大批单机团队；网易已着手开发《归唐》；米哈游的品质已逐步开始向单机的设计质感靠拢；鹰角也在逐步尝试各类不同方向的单机产品。<strong>与其说是资本不再现实了，不如说是单机游戏的回报率让他们足以愿意为此投入。</strong></p>\\\\n  <p>同时，基于多年积累，中国玩家数量显著增多。2015年，Steam的中国用户数还只有几百万，而现在一度超过5000万，占了软件整体用户数量的半壁江山。中国已经有了一个巨大且愿意为正版付费的玩家群体。</p>\\\\n  <p>而最后不可忽视的，还有国家政策各个维度的支持。从前几年版号回暖开始，国家层面对游戏行业的关注度明显在持续上升。2023年，中国音像与数字出版协会联合央视推出纪录片《中国游戏纪事》；2025年，教育部通过游戏艺术设计专业，将游戏学科正式纳入国家高等教育体系；国务院新闻办公室举办发布会，提及要发展游戏出海业务，布局从IP打造到游戏制作、发行、海外运营的整个产业链——这是国务院第一次在发布会上提及游戏。针对游戏开发者，北京、上海、深圳、广州各地也已开启了相应的政府扶持政策。</p>\\\\n  <p>但《黑神话：悟空》的出现，会不会只是昙花一现？</p>\\\\n  <p>显然不是。但大家想要的，确实不只是一两款偶然成功的产品，而是一个\\\"国产单机\\\"不再需要被特意强调的时代。</p>\\\\n  <p>去年11月，知乎上曾冒出个提问：\\\"2026年会是国产单机游戏更加百花齐放的一年吗？\\\"问题并不具体，整体数据寥寥，没什么人关注。底下的回答只有一条，来自《太吾绘卷》制作人茄子：</p>\\\\n  <p><strong>\\\"这是必然的，大势所趋。\\\"</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_0d1bf28d523c498cb52e5b196f989a74@6202862_oswg13622oswg418oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">茄子的知乎回答</p>\\\\n  <p>这句话，或许是对未来几年国产单机游戏市场最好的预测与总结，就像《黑神话：悟空》的出现并非偶然，而是数十年积累沉淀而爆发的必然结果。况且，<strong>当一个行业的从业者开始用\\\"必然\\\"而非\\\"希望\\\"来描述未来时，风向其实就已经变了。</strong></p>\\\\n  <p>于投资人而言，比起早几年偶然爆品时期，现在无疑是更好的入局时间。不论是玩家数量、官方关注度还是技术支持，都已能构建出一套足够完整、可持续的商业生态。一个明显的证据是：比起单独的某款新品，各大公司明显开始更加关注自身持有的IP，以及未来长线发展的可能。</p>\\\\n  <p>中手游收购《仙剑奇侠传》全球IP版权，意图构建\\\"仙剑宇宙\\\"；网元圣唐围绕《古剑奇谭》打造影视、游戏、衍生品联动；就连一向被视为\\\"手游大厂\\\"的腾讯，也开始在年度发布会上给单机产品留出专门的版块。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_d92aa46c15264f41ba8011a8e73cdd1a@6202862_oswg70384oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《湮灭之潮》</p>\\\\n  <p>长此以往，做单机游戏就不再是一件需要\\\"卖房卖车，只为追梦\\\"的事情，而是一件有利可图、有意义可寻的事情。</p>\\\\n  <p>而往深了看，这同样意味着游戏作为娱乐媒介的价值正在被重新定义。在碎片化的信息时代，当短视频以15秒为单位切割着人们的注意力，当算法用无尽的推荐消解着深度思考的可能，单机游戏这种强沉浸感、高互动性的娱乐模式，反而成为了一种稀缺的\\\"完整体验\\\"。而对于国产游戏而言，这种\\\"完整体验\\\"的载体，恰好是我们自己那些尚未被表述、被传达出来的文化。</p>\\\\n  <p>2022年，《原神》推出\\\"神女劈观\\\"章节，一段以京剧为基底、融合现代音乐创作的剧情短片，在海外引发热潮。外国玩家为了理解\\\"云堇\\\"的唱词，主动去查阅中国戏曲的历史；YouTube上出现了大量解析\\\"京剧唱腔\\\"\\\"戏词韵脚\\\"的教学视频。《古剑奇谭三》则以\\\"传承\\\"为主题，将视角从个人爱恨情仇，拉升到种族存续、文明传承的高度，让无数人第一次从游戏身上感受到了游戏作为文化载体的表达使命。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_3b13dda1b32646d9bcc775fcc86dc8cd@6202862_oswg503039oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《古剑奇谭3》最后的寄语</p>\\\\n  <p>这些无法通过纯粹言语传递的情绪与精神，往往能借助视听互动的模式，让人更感同身受地理解。</p>\\\\n  <p>这就是为什么，国产游戏剩下的路，是它自己的路。这条路没有现成的模板可以参考，因为我们要讲述的故事、要触达的玩家、要承载的文化，都是独一份的。欧美的魔幻史诗、日本的武士物语，都已找到了最适合自己的表达方式。而中国的武侠、仙侠、神话、历史，以及当代都市里那些细碎的日常，正在等待属于自己的游戏语言。</p>\\\\n  <p><strong>回到开头的那个问题：国产单机究竟还缺什么？</strong></p>\\\\n  <p>或许缺的从来不是做出好产品的能力，而是一套能让好产品持续活下去的生态。《明末》的故事已经说明，一款销量约200万套的游戏，在海外成熟市场或许会被给予持续投入的机会，但在这里，团队在第一次\\\"不够成功\\\"之后就失去了一切。这是整个行业都需要回答的问题：当越来越多的团队选择走这条路，我们能不能给他们足够的支撑系统？</p>\\\\n  <p>《明末》的制作人夏思源，在离开灵泽后成立了自己的工作室，注册资本只有5万元。他需要的不是情怀式的惋惜，而是一个能够让他再次安稳做产品的环境。</p>\\\\n  <p>这条路肯定还有曲折，会有人失败，会有团队解散。但这一次，站在牌桌上的并不是少数情怀人，而是一整代经历过断层的玩家和从业者。他们见过辉煌，也见过衰落；他们被现实打磨过，但心底那团火始终没灭。</p>\\\\n  <p><strong>毕竟，胜败乃兵家常事，大侠还请重新来过。</strong></p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p>文丨果脯</p>\\\\n  <p>编辑丨刘士武</p>\\\\n  <p>过去几天里，《明末：渊虚之羽》（后称：明末）制作组解散、制作人夏思源离职创业的消息，让不少人感到唏嘘。</p>\\\\n  <p>这款由灵泽科技开发的国产类魂动作游戏，曾被寄予厚望，后续也取得了不错的成绩。</p>\\\\n  <p>据统计，2025年上线后，游戏在Steam预估销量约120万套，主机平台PS5约30至40万套，加上其他渠道总计约200万套，销售额超过5亿元。这样的成绩，放在国内单机史上，已与《戴森球计划》《鬼谷八荒》等大火产品同处一个量级。</p>\\\\n  <p>更重要的是，它把国产单机游戏的单价继续推到了3A级价位——Steam国区248元，海外49.99美元，又一次证明了国产单机也能站稳3A赛道。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_7778be437ee04255a0333917b40cc0fd@6202862_oswg578637oswg1080oswg568_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《明末：渊虚之羽》的Steam界面</p>\\\\n  <p>灵泽的故事也确实励志。这家从VR游戏起家、曾靠外包维持运转的团队，凭一腔热血熬出了《明末》，一度穷到只剩理想支撑。</p>\\\\n  <p>然而热闹背后藏着尴尬。上线后的舆论风波、优化问题、定价策略失误，以及最致命的剧情方向与主流玩家预期的严重偏差，让这款产品<strong>从“村里第二个大学生”一夜变成了“村里的第一个大学退学生”。</strong></p>\\\\n  <p>发行商505 Games虽仍以“Strong”形容游戏表现，但多方分账之后，项目首年仅能勉强打平研发成本，无法形成持续的利润闭环。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_2dae518a862c438c9080a5f70ed47d1d@242988687_oswg1875806oswg1969oswg1110_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">夏思源讲解《明末》关卡设计（36氪拍摄于2025年7月的灵泽科技）</p>\\\\n  <p>去年游戏上线前，36氪游戏曾与灵泽科技几位核心创始成员进行过深入交流，彼时我们能感受到这个团队对于《明末》的信心与期待。</p>\\\\n  <p>毕竟，这家成立于2016年的公司，初期大部分营收来源于外包——2021年正式上市的VR游戏《A.D.2047》并不足以证明灵泽制作大型游戏甚至3A级单机的能力。但对于几位创始成员来说，3A国单是梦想，也是《明末》能够坚持至今取得亮眼销量成绩的原因。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_ba0e6f1aea2146bfafd77669f2c944b7@6202862_oswg73701oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《明末：渊虚之羽》</p>\\\\n  <p><strong>然而，一系列的事件后，《明末》最终还是迎来了这样一个Bad&nbsp;Eding——</strong></p>\\\\n  <p>灵泽股方要求团队全部转外包，团队拒绝，团队直接被解散，制作人夏思源带着不足5万元注册资本的工作室从零开始。前几天我们与夏思源简单沟通得知，他已经在专注于新的工作。</p>\\\\n  <p>或许过去的就让它过去吧。</p>\\\\n  <p>但唏嘘背后，一款销量约200万套、过了“成本关”的游戏，一棋下错，满盘皆输，最终落得物是人非的境地。这究竟是为什么？或者说，国产单机走到今天，我们究竟还缺什么？</p>\\\\n  <p>要回答这个问题，有必要先正视一个事实：<strong>时至今日，国产游戏或许早已不需要向世界证明什么。</strong></p>\\\\n  <p>“人越炫耀什么，就越缺什么”这句俗语，大多数人都听过。它可能不完全对，但多少有几分道理。很长一段时间，当我们反复强调“中国游戏”如何如何，可能都依旧下意识把自己放在低位，试图向世界证明什么。但现在，这个命题或许已经悄然翻转。</p>\\\\n  <p>论产品能力与文化传播力，国内诸多二次元游戏哪怕在二次元文化的发源地日本，都已建立起无可比拟的统治力。从《原神》开启的“文化输出”讨论，到《鸣潮》在海外掀起的热潮，再到《恋与深空》拿下TGA、App Store、Google Play等多个维度的奖项，中国游戏产品早已站上全球头部赛道。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_9c5d99392992439096a34c5ec603da05@6202862_oswg63910oswg552oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《恋与深空》在东京电玩展</p>\\\\n  <p>腾讯的《三角洲行动》则是在欧美最擅长的射击赛道，进一步拉高了此类产品的天花板。比起过去一味的模仿、追赶，这款产品基本是从\\\"搜打撤\\\"的玩法循环中，真真正正摸索出了一个属于自己的解法。</p>\\\\n  <p>有部分人质疑它的优秀成绩仅限于国内，但不可否认，它比《逃离塔科夫》或《ARC Raider》都更先找到了理想化的商业化与玩法平衡的解法，甚至在这条路上走得更远。</p>\\\\n  <p>而聚焦到更具体的产品，《黑神话：悟空》不论是技术力还是项目管理水平，基本得以比肩世界第一梯队的团队。2024年正式发售后，首月销量破2000万份，全球媒体评分均在90分以上，TGA年度游戏提名。2000万份的销量证明了\\\"中国人也有做好3A\\\"的能力。</p>\\\\n  <p>它不仅是一款成功的游戏，更是一个文化符号——它告诉世界：<strong>中国人，也能做出世界顶级的单机大作。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_d48005e0018b4a7e83356c768423fbb3@6202862_oswg69840oswg1080oswg698_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《很神话：悟空》</p>\\\\n  <p>此外，国内游戏市场每年依旧会爆出一些足够惊艳的小产品。像去年上线的《苏丹的游戏》《逃离鸭科夫》《明末：渊虚之羽》，以及即将推出的《影之刃零》等等，都在不同路线上推动着国产单机的前行。基于这份成绩，国外甚至已经出现了有关\\\"中国游戏\\\"的专属词条。在Reddit上，r/ChineseGames小组的成员已经超过10万，他们讨论的不再只是\\\"made in China\\\"，而是那些真正由中国团队主导、有中国味儿的原创作品。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_231cd3848c5e42b882cdc548a73d6165@6202862_oswg123151oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《影之刃零》</p>\\\\n  <p>说白了，时至今日我们或许已经不用再向世界去证明什么。所谓\\\"想要国产游戏崛起\\\"的期望，更多是中国游戏人基于热爱、经历和遗憾，而对当下与未来生出的一股子心气。</p>\\\\n  <p><strong>那么，这股心气为什么最终又会聚焦于\\\"国产单机\\\"这一标签？</strong></p>\\\\n  <p>明显能看到，即使在长线运营的多端互通产品上已成绩斐然，行业与玩家最寄望的，依然是更多的《黑神话：悟空》。玩家的这份希冀，甚至比下一个《王者荣耀》或《原神》来得更猛烈。</p>\\\\n  <p>究其原因，一方面，单机游戏的商品属性更弱，内容属性更强。与粗暴的DAU、留存等数据化指标相比，这类产品具有更加强烈的设计导向和内容驱动。并且在这个一切都变成\\\"长线服务\\\"的时代，单机游戏难得保留着一股子完整性。它要求你坐下来，投入几十小时，与角色建立情感连接，最终在通关的那一刻，获得一种算法永远无法给予的\\\"完成感\\\"。</p>\\\\n  <p>另一方面，时至今日，玩家都需要足够多的高质量产品去证明：比起纯粹的娱乐性，电子游戏作为走在科技前沿的产物，实际还能承载住更多意义与价值。并且如果游戏还需要被“正名”，国产单机游戏也是最有力的武器。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_a9cbf2670d3b4507a2a995e5ea2ddd8f@6202862_oswg52547oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《古剑奇谭3》</p>\\\\n  <p>只是，回看这批国产游戏开发者的成长路径，会有一个更深的体感：他们大多从小玩着千禧年前后的优秀国产作品长大，经历过国产游戏的辉煌，也见识了它的衰落，更经历过在不同公司打工赚钱的日子。游戏科学为了做出\\\"黑神话\\\"，必须先造出\\\"斗战神\\\"；灵游坊想要养家糊口，也得先放下\\\"雨血\\\"先做\\\"影之刃\\\"。一如冯骥所说：\\\"我们想做自己的游戏，想了很多年。\\\"</p>\\\\n  <p>于他们而言，做一款属于自己的单机游戏，无异于机车迷找到了哈雷。这不是高低之分，只是前两者中，很多人可能只是飞机上的一颗螺丝钉，受各类数据牵制，并不符合他们这代人最初对游戏的印象。</p>\\\\n  <p>而从市场层面看，根据《2025年中国游戏产业报告》显示，包含了单机与网游的“客户端游戏”，其营收占比行业全年总营收的22.26%；而主机游戏则仅占比2.38%。当然，无论是客户端还是主机游戏，整体增长仍然强劲，从侧面证明了国单的崛起和玩家的期待。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_202ecfd70aca4f199d28514ad018f175@6202862_oswg53158oswg1080oswg637_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《2025年中国游戏产业报告》</p>\\\\n  <p><strong>除了市场规模的增长以外，钱也是重要推手。</strong></p>\\\\n  <p>过去几年，随着游戏市场逐渐成熟，手游借助工业化模式已经变得相对稳定，越来越多的资本积累开始流向可能性更多的单机领域。腾讯投资了游戏科学、灵游坊等一大批单机团队；网易已着手开发《归唐》；米哈游的品质已逐步开始向单机的设计质感靠拢；鹰角也在逐步尝试各类不同方向的单机产品。<strong>与其说是资本不再现实了，不如说是单机游戏的回报率让他们足以愿意为此投入。</strong></p>\\\\n  <p>同时，基于多年积累，中国玩家数量显著增多。2015年，Steam的中国用户数还只有几百万，而现在一度超过5000万，占了软件整体用户数量的半壁江山。中国已经有了一个巨大且愿意为正版付费的玩家群体。</p>\\\\n  <p>而最后不可忽视的，还有国家政策各个维度的支持。从前几年版号回暖开始，国家层面对游戏行业的关注度明显在持续上升。2023年，中国音像与数字出版协会联合央视推出纪录片《中国游戏纪事》；2025年，教育部通过游戏艺术设计专业，将游戏学科正式纳入国家高等教育体系；国务院新闻办公室举办发布会，提及要发展游戏出海业务，布局从IP打造到游戏制作、发行、海外运营的整个产业链——这是国务院第一次在发布会上提及游戏。针对游戏开发者，北京、上海、深圳、广州各地也已开启了相应的政府扶持政策。</p>\\\\n  <p>但《黑神话：悟空》的出现，会不会只是昙花一现？</p>\\\\n  <p>显然不是。但大家想要的，确实不只是一两款偶然成功的产品，而是一个\\\"国产单机\\\"不再需要被特意强调的时代。</p>\\\\n  <p>去年11月，知乎上曾冒出个提问：\\\"2026年会是国产单机游戏更加百花齐放的一年吗？\\\"问题并不具体，整体数据寥寥，没什么人关注。底下的回答只有一条，来自《太吾绘卷》制作人茄子：</p>\\\\n  <p><strong>\\\"这是必然的，大势所趋。\\\"</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_0d1bf28d523c498cb52e5b196f989a74@6202862_oswg13622oswg418oswg211_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">茄子的知乎回答</p>\\\\n  <p>这句话，或许是对未来几年国产单机游戏市场最好的预测与总结，就像《黑神话：悟空》的出现并非偶然，而是数十年积累沉淀而爆发的必然结果。况且，<strong>当一个行业的从业者开始用\\\"必然\\\"而非\\\"希望\\\"来描述未来时，风向其实就已经变了。</strong></p>\\\\n  <p>于投资人而言，比起早几年偶然爆品时期，现在无疑是更好的入局时间。不论是玩家数量、官方关注度还是技术支持，都已能构建出一套足够完整、可持续的商业生态。一个明显的证据是：比起单独的某款新品，各大公司明显开始更加关注自身持有的IP，以及未来长线发展的可能。</p>\\\\n  <p>中手游收购《仙剑奇侠传》全球IP版权，意图构建\\\"仙剑宇宙\\\"；网元圣唐围绕《古剑奇谭》打造影视、游戏、衍生品联动；就连一向被视为\\\"手游大厂\\\"的腾讯，也开始在年度发布会上给单机产品留出专门的版块。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_d92aa46c15264f41ba8011a8e73cdd1a@6202862_oswg70384oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《湮灭之潮》</p>\\\\n  <p>长此以往，做单机游戏就不再是一件需要\\\"卖房卖车，只为追梦\\\"的事情，而是一件有利可图、有意义可寻的事情。</p>\\\\n  <p>而往深了看，这同样意味着游戏作为娱乐媒介的价值正在被重新定义。在碎片化的信息时代，当短视频以15秒为单位切割着人们的注意力，当算法用无尽的推荐消解着深度思考的可能，单机游戏这种强沉浸感、高互动性的娱乐模式，反而成为了一种稀缺的\\\"完整体验\\\"。而对于国产游戏而言，这种\\\"完整体验\\\"的载体，恰好是我们自己那些尚未被表述、被传达出来的文化。</p>\\\\n  <p>2022年，《原神》推出\\\"神女劈观\\\"章节，一段以京剧为基底、融合现代音乐创作的剧情短片，在海外引发热潮。外国玩家为了理解\\\"云堇\\\"的唱词，主动去查阅中国戏曲的历史；YouTube上出现了大量解析\\\"京剧唱腔\\\"\\\"戏词韵脚\\\"的教学视频。《古剑奇谭三》则以\\\"传承\\\"为主题，将视角从个人爱恨情仇，拉升到种族存续、文明传承的高度，让无数人第一次从游戏身上感受到了游戏作为文化载体的表达使命。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_3b13dda1b32646d9bcc775fcc86dc8cd@6202862_oswg503039oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">《古剑奇谭3》最后的寄语</p>\\\\n  <p>这些无法通过纯粹言语传递的情绪与精神，往往能借助视听互动的模式，让人更感同身受地理解。</p>\\\\n  <p>这就是为什么，国产游戏剩下的路，是它自己的路。这条路没有现成的模板可以参考，因为我们要讲述的故事、要触达的玩家、要承载的文化，都是独一份的。欧美的魔幻史诗、日本的武士物语，都已找到了最适合自己的表达方式。而中国的武侠、仙侠、神话、历史，以及当代都市里那些细碎的日常，正在等待属于自己的游戏语言。</p>\\\\n  <p><strong>回到开头的那个问题：国产单机究竟还缺什么？</strong></p>\\\\n  <p>或许缺的从来不是做出好产品的能力，而是一套能让好产品持续活下去的生态。《明末》的故事已经说明，一款销量约200万套的游戏，在海外成熟市场或许会被给予持续投入的机会，但在这里，团队在第一次\\\"不够成功\\\"之后就失去了一切。这是整个行业都需要回答的问题：当越来越多的团队选择走这条路，我们能不能给他们足够的支撑系统？</p>\\\\n  <p>《明末》的制作人夏思源，在离开灵泽后成立了自己的工作室，注册资本只有5万元。他需要的不是情怀式的惋惜，而是一个能够让他再次安稳做产品的环境。</p>\\\\n  <p>这条路肯定还有曲折，会有人失败，会有团队解散。但这一次，站在牌桌上的并不是少数情怀人，而是一整代经历过断层的玩家和从业者。他们见过辉煌，也见过衰落；他们被现实打磨过，但心底那团火始终没灭。</p>\\\\n  <p><strong>毕竟，胜败乃兵家常事，大侠还请重新来过。</strong></p>\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-15 08:00:00\", \"ai_json_output\": \"\"}', NULL, '2026-04-15 08:00:00', '2026-04-16 12:01:36');
INSERT INTO `news_detail` VALUES (34, 1054, 9, '内容与社交', '网易互娱架构调整，市场负责人王怡调任海外', '', '<p>文 | 贝果树</p>\n<p>编辑 | 果脯</p>\n<p>4月14日，网易互娱回应了“网易互娱市场中心负责人网怡离职”的传闻。网易互娱表示上述信息不实，“裁撤营销中台”也属子虚乌有，王怡因个人原因提出调任，已获公司批准。</p>\n<p>网易互娱发布的内部邮件显示，市场负责人王怡工作地点将调整至海外。原市场中心更名为用户增长中心，原渠道发行中心更名为发行中心。相关组织架构和人员调整工作将在4月内完成。</p>\n<p>王怡曾任宝洁品牌经理，于2010年加入网易，负责网易旗下游戏的市场营销工作，在网易任职长达16年，是网易游戏营销体系的核心人物。王怡长期活跃于行业活动，2016-2023年间，王怡多次以“网易副总裁”的身份出席中国游戏产业年会，发表演讲。</p>\n<p>此前，网易内部也经历了多次人事变动。今年1月8日，原梦幻事业部负责人林云枫离职。2025年12月，任职23年的网易执行副总裁、互动娱乐事业群负责人丁迎峰宣布退休，转任公司顾问。</p>\n<p>同时，新一代负责人也在晋升。2025年3月，雷火事业群负责人胡志鹏晋升为集团执行副总裁，程龙晋升为集团高级副总裁。雷火事业群开发的《永劫无间》《逆水寒》成绩表现优异，在研的二次元开放世界游戏《无限大》也获得了极高的关注，预约量超过1200万。</p>\n<p>在增长放缓的压力下，网易正在通过内部的多次调整，进行一场新老交替的转型。</p>', 'https://36kr.com/p/3766722584822537?f=rss', 0, '', '{\"summary\": \"本文披露网易互娱架构人事调整动态，核心营销负责人调任海外，帮助从业者把握头部游戏厂商出海布局动向\", \"abstract\": \"4月14日网易互娱澄清人事离职、裁撤营销中台的不实传闻，确认市场中心负责人王怡因个人原因调任海外，相关组织架构调整将于4月内完成。王怡是网易游戏营销体系核心人物，在网易任职16年，拥有丰富的品牌营销经验。近期网易互娱多次推进人事变动，完成管理层新老交替，推动企业转型。此次核心营销负责人调任海外，体现出网易对游戏出海业务的战略重视。\", \"keywords\": [\"网易互娱\", \"架构调整\", \"人事调任\", \"游戏出海\", \"海外布局\", \"组织转型\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"内容与社交\"}', '', '{\"url\": \"https://36kr.com/p/3766722584822537?f=rss\", \"title\": \"网易互娱架构调整，市场负责人王怡调任海外\", \"source\": \"https://36kr.com/feed\", \"content\": \"<p>文 | 贝果树</p>\\n<p>编辑 | 果脯</p>\\n<p>4月14日，网易互娱回应了“网易互娱市场中心负责人网怡离职”的传闻。网易互娱表示上述信息不实，“裁撤营销中台”也属子虚乌有，王怡因个人原因提出调任，已获公司批准。</p>\\n<p>网易互娱发布的内部邮件显示，市场负责人王怡工作地点将调整至海外。原市场中心更名为用户增长中心，原渠道发行中心更名为发行中心。相关组织架构和人员调整工作将在4月内完成。</p>\\n<p>王怡曾任宝洁品牌经理，于2010年加入网易，负责网易旗下游戏的市场营销工作，在网易任职长达16年，是网易游戏营销体系的核心人物。王怡长期活跃于行业活动，2016-2023年间，王怡多次以“网易副总裁”的身份出席中国游戏产业年会，发表演讲。</p>\\n<p>此前，网易内部也经历了多次人事变动。今年1月8日，原梦幻事业部负责人林云枫离职。2025年12月，任职23年的网易执行副总裁、互动娱乐事业群负责人丁迎峰宣布退休，转任公司顾问。</p>\\n<p>同时，新一代负责人也在晋升。2025年3月，雷火事业群负责人胡志鹏晋升为集团执行副总裁，程龙晋升为集团高级副总裁。雷火事业群开发的《永劫无间》《逆水寒》成绩表现优异，在研的二次元开放世界游戏《无限大》也获得了极高的关注，预约量超过1200万。</p>\\n<p>在增长放缓的压力下，网易正在通过内部的多次调整，进行一场新老交替的转型。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'网易互娱架构调整，市场负责人王怡调任海外\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'网易互娱架构调整，市场负责人王怡调任海外\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766722584822537?f=rss\'}], \'link\': \'https://36kr.com/p/3766722584822537?f=rss\', \'published\': \'2026-04-14 22:40:13  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=14, tm_min=40, tm_sec=13, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p class=\\\"image-wrapper\\\">文 | 贝果树</p>\\\\n  <p class=\\\"image-wrapper\\\">编辑 | 果脯</p>\\\\n  <p class=\\\"image-wrapper\\\"><span style=\\\"letter-spacing: 0px;\\\">4月14日，网易互娱回应了“网易互娱市场中心负责人网怡离职”的传闻。网易互娱表示上述信息不实，“裁撤营销中台”也属子虚乌有，王怡因个人原因提出调任，已获公司批准。</span></p>\\\\n  <p>网易互娱发布的内部邮件显示，市场负责人王怡工作地点将调整至海外。原市场中心更名为用户增长中心，原渠道发行中心更名为发行中心。相关组织架构和人员调整工作将在4月内完成。</p>\\\\n  <p>王怡曾任宝洁品牌经理，于2010年加入网易，负责网易旗下游戏的市场营销工作，在网易任职长达16年，是网易游戏营销体系的核心人物。王怡长期活跃于行业活动，2016-2023年间，王怡多次以“网易副总裁”的身份出席中国游戏产业年会，发表演讲。</p>\\\\n  <p>此前，网易内部也经历了多次人事变动。今年1月8日，原梦幻事业部负责人林云枫离职。2025年12月，任职23年的网易执行副总裁、互动娱乐事业群负责人丁迎峰宣布退休，转任公司顾问。</p>\\\\n  <p><span style=\\\"letter-spacing: 0px;\\\">同时，新一代负责人也在晋升。</span><span style=\\\"letter-spacing: 0px;\\\">2025年3月，雷火事业群负责人胡志鹏晋升为集团执行副总裁，程龙晋升为集团高级副总裁。雷火事业群开发的《永劫无间》《逆水寒》成绩表现优异，在研的二次元开放世界游戏《无限大》也获得了极高的关注，预约量超过1200万。</span></p>\\\\n  <p><span style=\\\"letter-spacing: 0px;\\\">在增长放缓的压力下，网易正在通过内部的多次调整，进行一场新老交替的转型。</span></p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p class=\\\"image-wrapper\\\">文 | 贝果树</p>\\\\n  <p class=\\\"image-wrapper\\\">编辑 | 果脯</p>\\\\n  <p class=\\\"image-wrapper\\\"><span style=\\\"letter-spacing: 0px;\\\">4月14日，网易互娱回应了“网易互娱市场中心负责人网怡离职”的传闻。网易互娱表示上述信息不实，“裁撤营销中台”也属子虚乌有，王怡因个人原因提出调任，已获公司批准。</span></p>\\\\n  <p>网易互娱发布的内部邮件显示，市场负责人王怡工作地点将调整至海外。原市场中心更名为用户增长中心，原渠道发行中心更名为发行中心。相关组织架构和人员调整工作将在4月内完成。</p>\\\\n  <p>王怡曾任宝洁品牌经理，于2010年加入网易，负责网易旗下游戏的市场营销工作，在网易任职长达16年，是网易游戏营销体系的核心人物。王怡长期活跃于行业活动，2016-2023年间，王怡多次以“网易副总裁”的身份出席中国游戏产业年会，发表演讲。</p>\\\\n  <p>此前，网易内部也经历了多次人事变动。今年1月8日，原梦幻事业部负责人林云枫离职。2025年12月，任职23年的网易执行副总裁、互动娱乐事业群负责人丁迎峰宣布退休，转任公司顾问。</p>\\\\n  <p><span style=\\\"letter-spacing: 0px;\\\">同时，新一代负责人也在晋升。</span><span style=\\\"letter-spacing: 0px;\\\">2025年3月，雷火事业群负责人胡志鹏晋升为集团执行副总裁，程龙晋升为集团高级副总裁。雷火事业群开发的《永劫无间》《逆水寒》成绩表现优异，在研的二次元开放世界游戏《无限大》也获得了极高的关注，预约量超过1200万。</span></p>\\\\n  <p><span style=\\\"letter-spacing: 0px;\\\">在增长放缓的压力下，网易正在通过内部的多次调整，进行一场新老交替的转型。</span></p>\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-14 22:40:13\", \"ai_json_output\": \"\"}', NULL, '2026-04-14 22:40:13', '2026-04-16 12:02:27');
INSERT INTO `news_detail` VALUES (35, 1055, 7, '消费与零售', '氪星晚报｜高德首款具身机器人将亮相；日产发布转型计划：削减20%车型，冲刺中美百万销量；随着战略转向，OpenAI的8520亿美元估值遭投资者质疑', '', '<h2><strong>大公司：</strong></h2>\n<p><a href=\"https://www.36kr.com/newsflashes/3766433899037191\"><strong>全球最大零食店“零食王国”将于4月17日开业</strong></a></p>\n<p>36氪获悉，由鸣鸣很忙集团创建的全球规模最大的沉浸式零食体验空间“零食王国”，将于4月17日在湖南长沙芙蓉广场正式开业。该项目拥有超1.2万㎡的零售与体验空间，汇聚了全球约70个国家和地区的风味、超过6500个国内外品牌及3.5万款商品。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3766346595074565\"><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></a></p>\n<p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表今日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3766337496072960\"><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></a></p>\n<p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3766176130646790\"><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></a></p>\n<p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3765996603310850\"><strong>日产发布转型计划：削减20%车型，冲刺中美百万销量</strong></a></p>\n<p>4月14日，日产汽车发布转型战略，拟将全球车型数量从56款削减至45款（降幅约20%），并计划将其80%的销量集中在三大核心车型家族中。日产力争到2030财年，在美国和中国两大市场分别实现年销量超100万辆的目标。为此，公司将推出更具竞争力的新品。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3765998058980103\"><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></a></p>\n<p>就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。</p>\n<h2><strong>新产品：</strong></h2>\n<p><a href=\"https://www.36kr.com/newsflashes/3766365669802501\"><strong>高德首款具身机器人将亮相</strong></a></p>\n<p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3766352952590848\"><strong>有道词典笔A7S正式发布</strong></a></p>\n<p>36氪获悉，今日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3766231859102470\"><strong>联想助力理想汽车打造的PPAP文档审核智能体正式发布</strong></a></p>\n<p>36氪获悉，近日，联想助力理想汽车打造的行业首个PPAP文档审核智能体正式发布。基于联想ThinkStation PGX AI工作站，该智能体实现了PPAP文档审核效率质的飞跃。ThinkStation PGX基于NVIDIA GB10 Grace Blackwell超级芯片打造，具备1 PetaFLOP（每秒1千万亿次浮点计算）算力与128GB统一内存，能在本地实时运行理想自研的27B大模型，同时支撑多个智能体并行推理。</p>\n<h2><strong>投融资：</strong></h2>\n<p><a href=\"https://www.36kr.com/newsflashes/3766363299545858\"><strong>CREAO AI完成千万美金融资</strong></a></p>\n<p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\n<h2><strong>今日观点：</strong></h2>\n<p><a href=\"https://www.36kr.com/newsflashes/3766108299936521\"><strong>报告：欧洲消费者在速卖通的年花费增速达25%</strong></a></p>\n<p>36氪获悉，尼尔森发布《2026出海品牌平台迁移白皮书》指出，品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%；品牌侧，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。30%的欧洲消费者视速卖通为“最有可能挑战亚马逊”的平台，认知度居首。</p>\n<h2><strong>其他值得关注的新闻：</strong></h2>\n<p><a href=\"https://www.36kr.com/newsflashes/3766448282223108\"><strong>国办：优化创新药等新上市药品首发价格机制</strong></a></p>\n<p>36氪获悉，国务院办公厅印发《关于健全药品价格形成机制的若干意见》，意见提出，优化创新药等新上市药品首发价格机制。实行新上市药品企业自评制度，引导医药企业做好自评，综合临床价值、市场供求、竞争格局、社会承受能力等因素自主合理定价，接受社会监督和同行评议。对新上市药品价格制定，区分高水平创新药、改良新药、通用名药（即仿制药）等情形，分别予以政策支持和引导。对创新程度高、临床价值大的高水平创新药，支持在上市初期制定与高投入、高风险相符的价格，在一定时期内保持价格相对稳定。对改良新药等，鼓励引导制定与患者获益相匹配的价格。对通用名药等其他新上市药品，引导医药企业参照同通用名、同作用机制、同功能主治药品价格合理定价。根据真实世界研究结果和临床使用实效，医药企业可在药品首发价格基础上适当调整价格水平。</p>\n<p><a href=\"https://www.36kr.com/newsflashes/3766381508379138\"><strong>我国最大规模科学智能计算集群投入使用</strong></a></p>\n<p>今天（14日）我国最大规模科学智能计算集群在位于郑州的国家超算互联网核心节点投入使用。这标志着我国在人工智能驱动科学研究算力基础设施领域实现关键突破，将助力我国抢占人工智能产业应用制高点。</p>', 'https://36kr.com/p/3766487517594377?f=rss', 0, '', '{\"summary\": \"本文披露了欧洲跨境电商出海平台的最新格局变化，可为出海品牌制定渠道策略提供参考，同时汇总多个领域最新商业动态\", \"abstract\": \"本文是36氪的综合商业晚报，汇总了大公司动态、新产品发布、投融资及行业观点等多领域资讯。尼尔森报告指出，当前出海品牌重心正从亚马逊向速卖通等中国平台迁移，欧洲消费者在速卖通的年花费增速达25%。本文还报道了日产汽车发布转型计划冲刺中美百万销量、OpenAI高估值遭投资者质疑、多款AI新品发布等行业动态。国务院办公厅印发相关意见，优化创新药等新上市药品的首发价格机制，对不同类型药品实施差异化定价引导。\", \"keywords\": [\"出海品牌\", \"跨境电商\", \"速卖通\", \"亚马逊\", \"欧洲市场\", \"品牌出海\", \"AI\"], \"policy_risk\": {\"market_risk\": \"OpenAI 8520亿美元估值因战略转向遭投资者质疑，其面临来自Anthropic与谷歌的激烈竞争；跨境电商领域亚马逊GMV下滑，出海品牌渠道格局发生变化\", \"policy_compliance\": \"国务院办公厅印发《关于健全药品价格形成机制的若干意见》，优化创新药等新上市药品首发价格机制，区分高水平创新药、改良新药、仿制药实施差异化定价引导\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"https://36kr.com/p/3766487517594377?f=rss\", \"title\": \"氪星晚报｜高德首款具身机器人将亮相；日产发布转型计划：削减20%车型，冲刺中美百万销量；随着战略转向，OpenAI的8520亿美元估值遭投资者质疑\", \"source\": \"https://36kr.com/feed\", \"content\": \"<h2><strong>大公司：</strong></h2>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766433899037191\\\"><strong>全球最大零食店“零食王国”将于4月17日开业</strong></a></p>\\n<p>36氪获悉，由鸣鸣很忙集团创建的全球规模最大的沉浸式零食体验空间“零食王国”，将于4月17日在湖南长沙芙蓉广场正式开业。该项目拥有超1.2万㎡的零售与体验空间，汇聚了全球约70个国家和地区的风味、超过6500个国内外品牌及3.5万款商品。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766346595074565\\\"><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></a></p>\\n<p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表今日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766337496072960\\\"><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></a></p>\\n<p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766176130646790\\\"><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></a></p>\\n<p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3765996603310850\\\"><strong>日产发布转型计划：削减20%车型，冲刺中美百万销量</strong></a></p>\\n<p>4月14日，日产汽车发布转型战略，拟将全球车型数量从56款削减至45款（降幅约20%），并计划将其80%的销量集中在三大核心车型家族中。日产力争到2030财年，在美国和中国两大市场分别实现年销量超100万辆的目标。为此，公司将推出更具竞争力的新品。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3765998058980103\\\"><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></a></p>\\n<p>就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。</p>\\n<h2><strong>新产品：</strong></h2>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766365669802501\\\"><strong>高德首款具身机器人将亮相</strong></a></p>\\n<p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766352952590848\\\"><strong>有道词典笔A7S正式发布</strong></a></p>\\n<p>36氪获悉，今日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766231859102470\\\"><strong>联想助力理想汽车打造的PPAP文档审核智能体正式发布</strong></a></p>\\n<p>36氪获悉，近日，联想助力理想汽车打造的行业首个PPAP文档审核智能体正式发布。基于联想ThinkStation PGX AI工作站，该智能体实现了PPAP文档审核效率质的飞跃。ThinkStation PGX基于NVIDIA GB10 Grace Blackwell超级芯片打造，具备1 PetaFLOP（每秒1千万亿次浮点计算）算力与128GB统一内存，能在本地实时运行理想自研的27B大模型，同时支撑多个智能体并行推理。</p>\\n<h2><strong>投融资：</strong></h2>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766363299545858\\\"><strong>CREAO AI完成千万美金融资</strong></a></p>\\n<p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\\n<h2><strong>今日观点：</strong></h2>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766108299936521\\\"><strong>报告：欧洲消费者在速卖通的年花费增速达25%</strong></a></p>\\n<p>36氪获悉，尼尔森发布《2026出海品牌平台迁移白皮书》指出，品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%；品牌侧，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。30%的欧洲消费者视速卖通为“最有可能挑战亚马逊”的平台，认知度居首。</p>\\n<h2><strong>其他值得关注的新闻：</strong></h2>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766448282223108\\\"><strong>国办：优化创新药等新上市药品首发价格机制</strong></a></p>\\n<p>36氪获悉，国务院办公厅印发《关于健全药品价格形成机制的若干意见》，意见提出，优化创新药等新上市药品首发价格机制。实行新上市药品企业自评制度，引导医药企业做好自评，综合临床价值、市场供求、竞争格局、社会承受能力等因素自主合理定价，接受社会监督和同行评议。对新上市药品价格制定，区分高水平创新药、改良新药、通用名药（即仿制药）等情形，分别予以政策支持和引导。对创新程度高、临床价值大的高水平创新药，支持在上市初期制定与高投入、高风险相符的价格，在一定时期内保持价格相对稳定。对改良新药等，鼓励引导制定与患者获益相匹配的价格。对通用名药等其他新上市药品，引导医药企业参照同通用名、同作用机制、同功能主治药品价格合理定价。根据真实世界研究结果和临床使用实效，医药企业可在药品首发价格基础上适当调整价格水平。</p>\\n<p><a href=\\\"https://www.36kr.com/newsflashes/3766381508379138\\\"><strong>我国最大规模科学智能计算集群投入使用</strong></a></p>\\n<p>今天（14日）我国最大规模科学智能计算集群在位于郑州的国家超算互联网核心节点投入使用。这标志着我国在人工智能驱动科学研究算力基础设施领域实现关键突破，将助力我国抢占人工智能产业应用制高点。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'氪星晚报｜高德首款具身机器人将亮相；日产发布转型计划：削减20%车型，冲刺中美百万销量；随着战略转向，OpenAI的8520亿美元估值遭投资者质疑\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'氪星晚报｜高德首款具身机器人将亮相；日产发布转型计划：削减20%车型，冲刺中美百万销量；随着战略转向，OpenAI的8520亿美元估值遭投资者质疑\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766487517594377?f=rss\'}], \'link\': \'https://36kr.com/p/3766487517594377?f=rss\', \'published\': \'2026-04-14 18:01:53  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=10, tm_min=1, tm_sec=53, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<h2><strong>大公司：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766433899037191\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>全球最大零食店“零食王国”将于4月17日开业</strong></a></p>\\\\n  <p>36氪获悉，由鸣鸣很忙集团创建的全球规模最大的沉浸式零食体验空间“零食王国”，将于4月17日在湖南长沙芙蓉广场正式开业。该项目拥有超1.2万㎡的零售与体验空间，汇聚了全球约70个国家和地区的风味、超过6500个国内外品牌及3.5万款商品。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766346595074565\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></a></p>\\\\n  <p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表今日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766337496072960\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></a></p>\\\\n  <p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766176130646790\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></a></p>\\\\n  <p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3765996603310850\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>日产发布转型计划：削减20%车型，冲刺中美百万销量</strong></a></p>\\\\n  <p>4月14日，日产汽车发布转型战略，拟将全球车型数量从56款削减至45款（降幅约20%），并计划将其80%的销量集中在三大核心车型家族中。日产力争到2030财年，在美国和中国两大市场分别实现年销量超100万辆的目标。为此，公司将推出更具竞争力的新品。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3765998058980103\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></a></p>\\\\n  <p>就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。</p>\\\\n  <h2><strong>新产品：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766365669802501\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>高德首款具身机器人将亮相</strong></a></p>\\\\n  <p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766352952590848\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>有道词典笔A7S正式发布</strong></a></p>\\\\n  <p>36氪获悉，今日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766231859102470\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>联想助力理想汽车打造的PPAP文档审核智能体正式发布</strong></a></p>\\\\n  <p>36氪获悉，近日，联想助力理想汽车打造的行业首个PPAP文档审核智能体正式发布。基于联想ThinkStation PGX AI工作站，该智能体实现了PPAP文档审核效率质的飞跃。ThinkStation PGX基于NVIDIA GB10 Grace Blackwell超级芯片打造，具备1 PetaFLOP（每秒1千万亿次浮点计算）算力与128GB统一内存，能在本地实时运行理想自研的27B大模型，同时支撑多个智能体并行推理。</p>\\\\n  <h2><strong>投融资：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766363299545858\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>CREAO AI完成千万美金融资</strong></a></p>\\\\n  <p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\\\\n  <h2><strong>今日观点：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766108299936521\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>报告：欧洲消费者在速卖通的年花费增速达25%</strong></a></p>\\\\n  <p>36氪获悉，尼尔森发布《2026出海品牌平台迁移白皮书》指出，品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%；品牌侧，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。30%的欧洲消费者视速卖通为“最有可能挑战亚马逊”的平台，认知度居首。</p>\\\\n  <h2><strong>其他值得关注的新闻：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766448282223108\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>国办：优化创新药等新上市药品首发价格机制</strong></a></p>\\\\n  <p>36氪获悉，国务院办公厅印发《关于健全药品价格形成机制的若干意见》，意见提出，优化创新药等新上市药品首发价格机制。实行新上市药品企业自评制度，引导医药企业做好自评，综合临床价值、市场供求、竞争格局、社会承受能力等因素自主合理定价，接受社会监督和同行评议。对新上市药品价格制定，区分高水平创新药、改良新药、通用名药（即仿制药）等情形，分别予以政策支持和引导。对创新程度高、临床价值大的高水平创新药，支持在上市初期制定与高投入、高风险相符的价格，在一定时期内保持价格相对稳定。对改良新药等，鼓励引导制定与患者获益相匹配的价格。对通用名药等其他新上市药品，引导医药企业参照同通用名、同作用机制、同功能主治药品价格合理定价。根据真实世界研究结果和临床使用实效，医药企业可在药品首发价格基础上适当调整价格水平。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766381508379138\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>我国最大规模科学智能计算集群投入使用</strong></a></p>\\\\n  <p>今天（14日）我国最大规模科学智能计算集群在位于郑州的国家超算互联网核心节点投入使用。这标志着我国在人工智能驱动科学研究算力基础设施领域实现关键突破，将助力我国抢占人工智能产业应用制高点。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<h2><strong>大公司：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766433899037191\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>全球最大零食店“零食王国”将于4月17日开业</strong></a></p>\\\\n  <p>36氪获悉，由鸣鸣很忙集团创建的全球规模最大的沉浸式零食体验空间“零食王国”，将于4月17日在湖南长沙芙蓉广场正式开业。该项目拥有超1.2万㎡的零售与体验空间，汇聚了全球约70个国家和地区的风味、超过6500个国内外品牌及3.5万款商品。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766346595074565\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>TCL电子将出售印度电视制造业务？公司回应：不持有该资产</strong></a></p>\\\\n  <p>针对TCL电子拟出售印度电视制造部门股份传闻，TCL电子代表今日回应称，“公司并不拥有此前报道中提到的资产”。据此前报道，TCL电子控股有限公司正考虑向印度买家出售其在当地电视制造部门的部分股份，以帮助务增长。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766337496072960\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>苹果新款平价电脑MacBook Neo首批产品已售罄，正向供应商鸿海和广达紧急追加大量订单</strong></a></p>\\\\n  <p>苹果推出的新款平价电脑MacBook Neo在消费市场取得了早期成功，目前其首批产品据称已经售罄，导致苹果正在向供应商鸿海和广达紧急追加大量订单。MacBook Neo自3月11日起全球发售。有消息称，这款售价为599美元（国内起售价为4599元人民币）的笔记本的交货周期已经延长至5月。苹果还上调了MacBook Neo的销量预期，从700万台增长至1000万台。与此同时，MacBook Neo使用的A18 Pro芯片库存成为了限制该款笔记本电脑产能的一个关键制约因素。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766176130646790\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>随着战略转向，OpenAI的8520亿美元估值遭投资者质疑</strong></a></p>\\\\n  <p>据报道，随着OpenAI将战略重心转向企业市场，并着手应对来自Anthropic的竞争，其高达8520亿美元的估值正受到其自身投资者的审视。部分OpenAI投资者透露，尽管该公司正筹备最早于今年进行首次公开募股（IPO），但上述战略调整恐使其在面对Anthropic以及势头回升的谷歌时，处于较为脆弱的境地。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3765996603310850\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>日产发布转型计划：削减20%车型，冲刺中美百万销量</strong></a></p>\\\\n  <p>4月14日，日产汽车发布转型战略，拟将全球车型数量从56款削减至45款（降幅约20%），并计划将其80%的销量集中在三大核心车型家族中。日产力争到2030财年，在美国和中国两大市场分别实现年销量超100万辆的目标。为此，公司将推出更具竞争力的新品。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3765998058980103\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>比亚迪回应坪山园区一立体车库火情：为试验及报废车辆专用停放区，火势已扑灭，无人员伤亡</strong></a></p>\\\\n  <p>就网传工厂起火事件，比亚迪回应称，“今日凌晨，我司坪山园区一立体车库发生火情，该车库为试验及报废车辆专用停放区。目前，火势已扑灭，无人员伤亡。”此前，坪山区消防救援局发文称：2026年4月14日2时48分，坪山区马峦街道一立体车库发生火情，市区两级应急、消防等部门第一时间赶赴现场处置。火势已扑灭，没有人员伤亡。</p>\\\\n  <h2><strong>新产品：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766365669802501\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>高德首款具身机器人将亮相</strong></a></p>\\\\n  <p>从高德获悉，高德首款具身机器人产品将在2026亦庄机器人半马赛事上首次公开亮相。该产品来自高德具身业务部，是一款四足机器人，为阿里巴巴集团推出的首款具身机器人产品。这款机器人将在比赛现场的开放环境下，通过自主感知、决策与交互，完成一系列任务挑战。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766352952590848\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>有道词典笔A7S正式发布</strong></a></p>\\\\n  <p>36氪获悉，今日，网易有道正式发布有道词典笔A7S，首发到手价349元。有道词典笔A7S集成了豆包、千问、DeepSeek、子曰等模型集群，用户可根据推理或语言场景自由切换。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766231859102470\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>联想助力理想汽车打造的PPAP文档审核智能体正式发布</strong></a></p>\\\\n  <p>36氪获悉，近日，联想助力理想汽车打造的行业首个PPAP文档审核智能体正式发布。基于联想ThinkStation PGX AI工作站，该智能体实现了PPAP文档审核效率质的飞跃。ThinkStation PGX基于NVIDIA GB10 Grace Blackwell超级芯片打造，具备1 PetaFLOP（每秒1千万亿次浮点计算）算力与128GB统一内存，能在本地实时运行理想自研的27B大模型，同时支撑多个智能体并行推理。</p>\\\\n  <h2><strong>投融资：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766363299545858\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>CREAO AI完成千万美金融资</strong></a></p>\\\\n  <p>36氪获悉，据Prosperity7消息，CREAO AI完成千万级美金融资，领投方为阿美风险投资（Aramco Ventures）旗下的多元化风投基金Prosperity7 Ventures和经纬创投，并获得过往投资人，包括云启资本、砺思资本、高瓴创投、红杉中国、华业天成资本持续加注。在过去不到一年的时间内，CREAO AI已累积完成超3000万美元融资。</p>\\\\n  <h2><strong>今日观点：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766108299936521\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>报告：欧洲消费者在速卖通的年花费增速达25%</strong></a></p>\\\\n  <p>36氪获悉，尼尔森发布《2026出海品牌平台迁移白皮书》指出，品牌出海重心正从亚马逊向以速卖通为首的中国平台迁移。数据显示，欧洲消费者在速卖通的年花费增速达25%；品牌侧，亚马逊GMV下滑4%，速卖通以4%增速领涨“出海四小龙”。30%的欧洲消费者视速卖通为“最有可能挑战亚马逊”的平台，认知度居首。</p>\\\\n  <h2><strong>其他值得关注的新闻：</strong></h2>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766448282223108\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>国办：优化创新药等新上市药品首发价格机制</strong></a></p>\\\\n  <p>36氪获悉，国务院办公厅印发《关于健全药品价格形成机制的若干意见》，意见提出，优化创新药等新上市药品首发价格机制。实行新上市药品企业自评制度，引导医药企业做好自评，综合临床价值、市场供求、竞争格局、社会承受能力等因素自主合理定价，接受社会监督和同行评议。对新上市药品价格制定，区分高水平创新药、改良新药、通用名药（即仿制药）等情形，分别予以政策支持和引导。对创新程度高、临床价值大的高水平创新药，支持在上市初期制定与高投入、高风险相符的价格，在一定时期内保持价格相对稳定。对改良新药等，鼓励引导制定与患者获益相匹配的价格。对通用名药等其他新上市药品，引导医药企业参照同通用名、同作用机制、同功能主治药品价格合理定价。根据真实世界研究结果和临床使用实效，医药企业可在药品首发价格基础上适当调整价格水平。</p>\\\\n  <p><a href=\\\"https://www.36kr.com/newsflashes/3766381508379138\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>我国最大规模科学智能计算集群投入使用</strong></a></p>\\\\n  <p>今天（14日）我国最大规模科学智能计算集群在位于郑州的国家超算互联网核心节点投入使用。这标志着我国在人工智能驱动科学研究算力基础设施领域实现关键突破，将助力我国抢占人工智能产业应用制高点。</p>\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-14 18:01:53\", \"ai_json_output\": \"\"}', NULL, '2026-04-14 18:01:53', '2026-04-16 12:03:30');
INSERT INTO `news_detail` VALUES (36, 1056, 18, '硬件与半导体出海', '宁德时代、智元、银河通用联合投资，六维力传感器头部企业「蓝点触控」完成超亿元C+轮融资 | 36氪首发', '', '<p>文 | 张冰冰</p>\n<p>编辑 | 阿至</p>\n<p>36氪获悉，蓝点触控（北京）科技有限公司（以下简称「蓝点触控」）<strong>近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。</strong>这是近一年内「蓝点触控」完成的第三轮过亿元融资。</p>\n<p>「蓝点触控」是36氪长期关注的企业，聚焦机器人力传感器，已搭建涵盖高性能弹性体设计、嵌入式硬件电路、高精度结构解耦算法及六维同步校准在内的四大平台型技术，形成人形机器人专用力传感器、通用力传感器、力控综合解决方案及复合型机器人工作站等多元化产品体系。</p>\n<p>凭借0.1%FS的高精度、10kHz以上高频响应、500%抗过载等性能指标，「蓝点触控」打破海外厂商技术垄断，<strong>已获得智元、小米、小鹏、银河通用、众擎、优必选、星海图、北京人形机器人创新中心等头部人形机器人企业的批量订单。</strong></p>\n<p>根据睿工业《2025年中国人形机器人六维力传感器市场调研报告》，2024年蓝点触控在中国人形机器人六维力传感器市场占有率约为62%，并预计2025年将提升至70%。高工机器人《GGII：2025中国人形机器人六维力传感器市场分析报告》显示，「蓝点触控」2025年前三季度市场份额达72.6%。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_c987a78bc6d647b0ad9373f406e22709@16805102_oswg78064oswg1080oswg661_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>「蓝点触控」产品系列</p>\n<p>2026年以来，持续火热的具身智能赛道融资中，频繁出现宁德时代的身影。除了重资投入整机企业，<strong>宁德时代的布局也在向产业链上下游延伸，其中，力传感器作为关键力控、末端力控的刚需零部件，成为其中的重要一环。</strong></p>\n<p>据了解，资金支持之外，双方将从三方面进一步合作：第一，宁德时代在机器人领域已经投资了多家企业，能够提供客户资源支持；第二，宁德时代在零部件制造方面的管理经验和业务逻辑值得借鉴；第三，作为终端用户，宁德时代自身存在大量工业应用场景，有助于推动产品落地。</p>\n<p><strong>除了产业投资方，本轮投资方还包括「蓝点触控」的客户：智元机器人、银河通用。</strong>从客户到股东，合作的核心是行业共识的形成——大模型在人形机器人上的应用高度依赖于力控能力，力传感器因而成为核心零部件。同时，作为力传感器的规模化使用者，两家头部人形机器人企业在长期产品搭载中，对「蓝点触控」的技术指标与交付能力完成了严苛验证，本次投资体现了客户对「蓝点触控」的进一步认可。</p>\n<p>为什么力控对机器人如此关键？刘吴月从两个维度进行了说明：第一，机械臂的绝对定位精度受限。由于谐波减速器、连杆等环节存在变形或间隙，加上各臂体一致性不如工业机械臂，导致理论位置与实际到达位置之间存在偏差。第二，视觉系统同样受限于柔性环节，在复杂光照环境下识别和定位误差较大。因此在实际操作中，视觉和手臂只能进行粗定位，最终的精细操作需依赖力觉感知与控制来完成。</p>\n<p>另一方面，机器人大模型的训练高度依赖可靠的数据。由于真机数据的缺口较大，不少大模型训练采用仿真数据和真机数据结合的方式，但与位置、动作轨迹等数据相比，力觉数据更难通过仿真来实现。“力觉数据涉及接触物体的刚性及机械臂的柔性环节，存在很多非线性和不一致的问题，更难建模，这是后续数据训练时用真机补充的核心要点，必须通过大量操作来实现。” 刘吴月总结。</p>\n<p>放到实际应用场景中，情况将更加复杂，因此<strong>「蓝点触控」下一步的技术重点是配合客户做场景化的批量落地。</strong>“场景化落地就是真正把力控批量应用起来，这过程中会暴露出很多客户端对机器人的新需求，这也是对传感器和力控整体的新需求。”刘吴月介绍，机器人的硬件关节虽然指标相同，但在不同的机器人硬件产品上，解决方式各有特点和方式。「蓝点触控」基于客户群体和应用规模的优势，能更好地跟踪客户需求，满足其更高性能要求。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_1964e7e9f9024bbc83bffc0ca5583b23@16805102_oswg24321oswg900oswg490_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>「蓝点触控」力传感器产品在机械臂应用</p>\n<p>市场方面，人形机器人增长速度超过市场预期。咨询公司IDC发布的《全球人形机器人市场分析》显示，2025年全球人形机器人出货量约为1.8万台，同比增长约508%，其中中国厂商领跑市场。摩根士丹利将我国2026年人形机器人的销量预测从1.4万台上调至2.8万台，并预计我国2030年的人形机器人销量将达到26.2万台。</p>\n<p>伴随具身智能和机器人产业的快速崛起，「蓝点触控」已连续三年实现销售收入翻倍，并实现盈利。市场需求的快速扩张，给核心零部件供应链带来巨大机遇。<strong>刘吴月预计，2026年「蓝点触控」关节力传感器出货量将达约40万套，六维力传感器出货量约为3万至4万套。</strong></p>\n<p>目前，「蓝点触控」已在广东建成超万平自有生产基地，实现机器人力觉传感器生产的自动化，一期全自动产线实际利用率已接近90%。下一步，通过产线复制，「蓝点触控」将具备关节力传感器年产100万套、末端六维力传感器年产20万套的能力，交付周期有望进一步压缩至2周。</p>\n<p>谈及未来发展，刘吴月表示，「蓝点触控」将加大下一代高精度、高集成度力控传感器研发，更好地适配人形整机量产刚需；产业生态上加强和人形机器人、汽车产业链相关伙伴的合作；在销售端做好国内战略目标规划，同时开展海外市场。</p>\n<h3><strong>36氪未来产业</strong></h3>\n<p>「36氪未来产业」持续关注城市发展、产业转型和创新创业项目落地。寻求报道可邮箱联系wangfengzhi@36kr.com或扫码联系。</p>\n<p>此外，36氪正式推出《36氪企业投资指南内参》，依托在经济圈产业群、区域重点推进规划与招商领域的深厚积累，36氪通过提供深入详细、更为及时、独家专有的全面信息服务，为政府部门提供高效、精准的产业项目内参；助力项目方匹配产业资金、链接关键人脉、快速融入新的产业生态。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260414/v2_538a8fd2f7e34eeebe56c993e473e439@16805102_oswg464390oswg1036oswg388_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>    </p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/WBCsVnYX2jkSMr5UzAuYRg\">“36氪未来产业”</a>，作者：张冰冰，阿至，36氪经授权发布。</p>', 'https://36kr.com/p/3766434507440903?f=rss', 0, '', '{\"summary\": \"本文为人形机器人核心零部件出海企业提供赛道动态参考，帮助把握全球人形机器人产业增长机遇\", \"abstract\": \"六维力传感器头部企业蓝点触控近日完成超亿元C+轮融资，由宁德时代旗下资本、智元机器人、银河通用等机构联合投资，这是其一年内完成的第三轮过亿元融资。蓝点触控聚焦机器人力传感器，打破海外厂商技术垄断，目前在中国人形机器人六维力传感器市场占有率超六成，已获得多家头部人形机器人企业批量订单，连续三年营收翻倍并实现盈利。伴随全球人形机器人市场高速增长，蓝点触控已建成自动化生产基地扩大产能，下一步计划加大下一代传感器研发，正式开展海外市场布局。\", \"keywords\": [\"六维力传感器\", \"蓝点触控\", \"人形机器人\", \"C+轮融资\", \"核心零部件\", \"海外市场拓展\", \"力控传感器\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://36kr.com/p/3766434507440903?f=rss\", \"title\": \"宁德时代、智元、银河通用联合投资，六维力传感器头部企业「蓝点触控」完成超亿元C+轮融资 | 36氪首发\", \"source\": \"https://36kr.com/feed\", \"content\": \"<p>文 | 张冰冰</p>\\n<p>编辑 | 阿至</p>\\n<p>36氪获悉，蓝点触控（北京）科技有限公司（以下简称「蓝点触控」）<strong>近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。</strong>这是近一年内「蓝点触控」完成的第三轮过亿元融资。</p>\\n<p>「蓝点触控」是36氪长期关注的企业，聚焦机器人力传感器，已搭建涵盖高性能弹性体设计、嵌入式硬件电路、高精度结构解耦算法及六维同步校准在内的四大平台型技术，形成人形机器人专用力传感器、通用力传感器、力控综合解决方案及复合型机器人工作站等多元化产品体系。</p>\\n<p>凭借0.1%FS的高精度、10kHz以上高频响应、500%抗过载等性能指标，「蓝点触控」打破海外厂商技术垄断，<strong>已获得智元、小米、小鹏、银河通用、众擎、优必选、星海图、北京人形机器人创新中心等头部人形机器人企业的批量订单。</strong></p>\\n<p>根据睿工业《2025年中国人形机器人六维力传感器市场调研报告》，2024年蓝点触控在中国人形机器人六维力传感器市场占有率约为62%，并预计2025年将提升至70%。高工机器人《GGII：2025中国人形机器人六维力传感器市场分析报告》显示，「蓝点触控」2025年前三季度市场份额达72.6%。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_c987a78bc6d647b0ad9373f406e22709@16805102_oswg78064oswg1080oswg661_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>「蓝点触控」产品系列</p>\\n<p>2026年以来，持续火热的具身智能赛道融资中，频繁出现宁德时代的身影。除了重资投入整机企业，<strong>宁德时代的布局也在向产业链上下游延伸，其中，力传感器作为关键力控、末端力控的刚需零部件，成为其中的重要一环。</strong></p>\\n<p>据了解，资金支持之外，双方将从三方面进一步合作：第一，宁德时代在机器人领域已经投资了多家企业，能够提供客户资源支持；第二，宁德时代在零部件制造方面的管理经验和业务逻辑值得借鉴；第三，作为终端用户，宁德时代自身存在大量工业应用场景，有助于推动产品落地。</p>\\n<p><strong>除了产业投资方，本轮投资方还包括「蓝点触控」的客户：智元机器人、银河通用。</strong>从客户到股东，合作的核心是行业共识的形成——大模型在人形机器人上的应用高度依赖于力控能力，力传感器因而成为核心零部件。同时，作为力传感器的规模化使用者，两家头部人形机器人企业在长期产品搭载中，对「蓝点触控」的技术指标与交付能力完成了严苛验证，本次投资体现了客户对「蓝点触控」的进一步认可。</p>\\n<p>为什么力控对机器人如此关键？刘吴月从两个维度进行了说明：第一，机械臂的绝对定位精度受限。由于谐波减速器、连杆等环节存在变形或间隙，加上各臂体一致性不如工业机械臂，导致理论位置与实际到达位置之间存在偏差。第二，视觉系统同样受限于柔性环节，在复杂光照环境下识别和定位误差较大。因此在实际操作中，视觉和手臂只能进行粗定位，最终的精细操作需依赖力觉感知与控制来完成。</p>\\n<p>另一方面，机器人大模型的训练高度依赖可靠的数据。由于真机数据的缺口较大，不少大模型训练采用仿真数据和真机数据结合的方式，但与位置、动作轨迹等数据相比，力觉数据更难通过仿真来实现。“力觉数据涉及接触物体的刚性及机械臂的柔性环节，存在很多非线性和不一致的问题，更难建模，这是后续数据训练时用真机补充的核心要点，必须通过大量操作来实现。” 刘吴月总结。</p>\\n<p>放到实际应用场景中，情况将更加复杂，因此<strong>「蓝点触控」下一步的技术重点是配合客户做场景化的批量落地。</strong>“场景化落地就是真正把力控批量应用起来，这过程中会暴露出很多客户端对机器人的新需求，这也是对传感器和力控整体的新需求。”刘吴月介绍，机器人的硬件关节虽然指标相同，但在不同的机器人硬件产品上，解决方式各有特点和方式。「蓝点触控」基于客户群体和应用规模的优势，能更好地跟踪客户需求，满足其更高性能要求。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_1964e7e9f9024bbc83bffc0ca5583b23@16805102_oswg24321oswg900oswg490_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>「蓝点触控」力传感器产品在机械臂应用</p>\\n<p>市场方面，人形机器人增长速度超过市场预期。咨询公司IDC发布的《全球人形机器人市场分析》显示，2025年全球人形机器人出货量约为1.8万台，同比增长约508%，其中中国厂商领跑市场。摩根士丹利将我国2026年人形机器人的销量预测从1.4万台上调至2.8万台，并预计我国2030年的人形机器人销量将达到26.2万台。</p>\\n<p>伴随具身智能和机器人产业的快速崛起，「蓝点触控」已连续三年实现销售收入翻倍，并实现盈利。市场需求的快速扩张，给核心零部件供应链带来巨大机遇。<strong>刘吴月预计，2026年「蓝点触控」关节力传感器出货量将达约40万套，六维力传感器出货量约为3万至4万套。</strong></p>\\n<p>目前，「蓝点触控」已在广东建成超万平自有生产基地，实现机器人力觉传感器生产的自动化，一期全自动产线实际利用率已接近90%。下一步，通过产线复制，「蓝点触控」将具备关节力传感器年产100万套、末端六维力传感器年产20万套的能力，交付周期有望进一步压缩至2周。</p>\\n<p>谈及未来发展，刘吴月表示，「蓝点触控」将加大下一代高精度、高集成度力控传感器研发，更好地适配人形整机量产刚需；产业生态上加强和人形机器人、汽车产业链相关伙伴的合作；在销售端做好国内战略目标规划，同时开展海外市场。</p>\\n<h3><strong>36氪未来产业</strong></h3>\\n<p>「36氪未来产业」持续关注城市发展、产业转型和创新创业项目落地。寻求报道可邮箱联系wangfengzhi@36kr.com或扫码联系。</p>\\n<p>此外，36氪正式推出《36氪企业投资指南内参》，依托在经济圈产业群、区域重点推进规划与招商领域的深厚积累，36氪通过提供深入详细、更为及时、独家专有的全面信息服务，为政府部门提供高效、精准的产业项目内参；助力项目方匹配产业资金、链接关键人脉、快速融入新的产业生态。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_538a8fd2f7e34eeebe56c993e473e439@16805102_oswg464390oswg1036oswg388_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>    </p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/WBCsVnYX2jkSMr5UzAuYRg\\\">“36氪未来产业”</a>，作者：张冰冰，阿至，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'宁德时代、智元、银河通用联合投资，六维力传感器头部企业「蓝点触控」完成超亿元C+轮融资 | 36氪首发\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'宁德时代、智元、银河通用联合投资，六维力传感器头部企业「蓝点触控」完成超亿元C+轮融资 | 36氪首发\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3766434507440903?f=rss\'}], \'link\': \'https://36kr.com/p/3766434507440903?f=rss\', \'published\': \'2026-04-14 17:09:33  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=14, tm_hour=9, tm_min=9, tm_sec=33, tm_wday=1, tm_yday=104, tm_isdst=0), \'summary\': \'<p>文&nbsp;|&nbsp;张冰冰</p>\\\\n  <p>编辑&nbsp;|&nbsp;阿至</p>\\\\n  <p>36氪获悉，蓝点触控（北京）科技有限公司（以下简称「蓝点触控」）<strong>近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。</strong>这是近一年内「蓝点触控」完成的第三轮过亿元融资。</p>\\\\n  <p>「蓝点触控」是36氪长期关注的企业，聚焦机器人力传感器，已搭建涵盖高性能弹性体设计、嵌入式硬件电路、高精度结构解耦算法及六维同步校准在内的四大平台型技术，形成人形机器人专用力传感器、通用力传感器、力控综合解决方案及复合型机器人工作站等多元化产品体系。</p>\\\\n  <p>凭借0.1%FS的高精度、10kHz以上高频响应、500%抗过载等性能指标，「蓝点触控」打破海外厂商技术垄断，<strong>已获得智元、小米、小鹏、银河通用、众擎、优必选、星海图、北京人形机器人创新中心等头部人形机器人企业的批量订单。</strong></p>\\\\n  <p>根据睿工业《2025年中国人形机器人六维力传感器市场调研报告》，2024年蓝点触控在中国人形机器人六维力传感器市场占有率约为62%，并预计2025年将提升至70%。高工机器人《GGII：2025中国人形机器人六维力传感器市场分析报告》显示，「蓝点触控」2025年前三季度市场份额达72.6%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_c987a78bc6d647b0ad9373f406e22709@16805102_oswg78064oswg1080oswg661_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">「蓝点触控」产品系列</p>\\\\n  <p>2026年以来，持续火热的具身智能赛道融资中，频繁出现宁德时代的身影。除了重资投入整机企业，<strong>宁德时代的布局也在向产业链上下游延伸，其中，力传感器作为关键力控、末端力控的刚需零部件，成为其中的重要一环。</strong></p>\\\\n  <p>据了解，资金支持之外，双方将从三方面进一步合作：第一，宁德时代在机器人领域已经投资了多家企业，能够提供客户资源支持；第二，宁德时代在零部件制造方面的管理经验和业务逻辑值得借鉴；第三，作为终端用户，宁德时代自身存在大量工业应用场景，有助于推动产品落地。</p>\\\\n  <p><strong>除了产业投资方，本轮投资方还包括「蓝点触控」的客户：智元机器人、银河通用。</strong>从客户到股东，合作的核心是行业共识的形成——大模型在人形机器人上的应用高度依赖于力控能力，力传感器因而成为核心零部件。同时，作为力传感器的规模化使用者，两家头部人形机器人企业在长期产品搭载中，对「蓝点触控」的技术指标与交付能力完成了严苛验证，本次投资体现了客户对「蓝点触控」的进一步认可。</p>\\\\n  <p>为什么力控对机器人如此关键？刘吴月从两个维度进行了说明：第一，机械臂的绝对定位精度受限。由于谐波减速器、连杆等环节存在变形或间隙，加上各臂体一致性不如工业机械臂，导致理论位置与实际到达位置之间存在偏差。第二，视觉系统同样受限于柔性环节，在复杂光照环境下识别和定位误差较大。因此在实际操作中，视觉和手臂只能进行粗定位，最终的精细操作需依赖力觉感知与控制来完成。</p>\\\\n  <p>另一方面，机器人大模型的训练高度依赖可靠的数据。由于真机数据的缺口较大，不少大模型训练采用仿真数据和真机数据结合的方式，但与位置、动作轨迹等数据相比，力觉数据更难通过仿真来实现。“力觉数据涉及接触物体的刚性及机械臂的柔性环节，存在很多非线性和不一致的问题，更难建模，这是后续数据训练时用真机补充的核心要点，必须通过大量操作来实现。” 刘吴月总结。</p>\\\\n  <p>放到实际应用场景中，情况将更加复杂，因此<strong>「蓝点触控」下一步的技术重点是配合客户做场景化的批量落地。</strong>“场景化落地就是真正把力控批量应用起来，这过程中会暴露出很多客户端对机器人的新需求，这也是对传感器和力控整体的新需求。”刘吴月介绍，机器人的硬件关节虽然指标相同，但在不同的机器人硬件产品上，解决方式各有特点和方式。「蓝点触控」基于客户群体和应用规模的优势，能更好地跟踪客户需求，满足其更高性能要求。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_1964e7e9f9024bbc83bffc0ca5583b23@16805102_oswg24321oswg900oswg490_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">「蓝点触控」力传感器产品在机械臂应用</p>\\\\n  <p>市场方面，人形机器人增长速度超过市场预期。咨询公司IDC发布的《全球人形机器人市场分析》显示，2025年全球人形机器人出货量约为1.8万台，同比增长约508%，其中中国厂商领跑市场。摩根士丹利将我国2026年人形机器人的销量预测从1.4万台上调至2.8万台，并预计我国2030年的人形机器人销量将达到26.2万台。</p>\\\\n  <p>伴随具身智能和机器人产业的快速崛起，「蓝点触控」已连续三年实现销售收入翻倍，并实现盈利。市场需求的快速扩张，给核心零部件供应链带来巨大机遇。<strong>刘吴月预计，2026年「蓝点触控」关节力传感器出货量将达约40万套，六维力传感器出货量约为3万至4万套。</strong></p>\\\\n  <p>目前，「蓝点触控」已在广东建成超万平自有生产基地，实现机器人力觉传感器生产的自动化，一期全自动产线实际利用率已接近90%。下一步，通过产线复制，「蓝点触控」将具备关节力传感器年产100万套、末端六维力传感器年产20万套的能力，交付周期有望进一步压缩至2周。</p>\\\\n  <p>谈及未来发展，刘吴月表示，「蓝点触控」将加大下一代高精度、高集成度力控传感器研发，更好地适配人形整机量产刚需；产业生态上加强和人形机器人、汽车产业链相关伙伴的合作；在销售端做好国内战略目标规划，同时开展海外市场。</p>\\\\n  <h3><strong>36氪未来产业</strong></h3>\\\\n  <p>「36氪未来产业」持续关注城市发展、产业转型和创新创业项目落地。寻求报道可邮箱联系wangfengzhi@36kr.com或扫码联系。</p>\\\\n  <p>此外，36氪正式推出《36氪企业投资指南内参》，依托在经济圈产业群、区域重点推进规划与招商领域的深厚积累，36氪通过提供深入详细、更为及时、独家专有的全面信息服务，为政府部门提供高效、精准的产业项目内参；助力项目方匹配产业资金、链接关键人脉、快速融入新的产业生态。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_538a8fd2f7e34eeebe56c993e473e439@16805102_oswg464390oswg1036oswg388_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">&nbsp; &nbsp;&nbsp;</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/WBCsVnYX2jkSMr5UzAuYRg\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“36氪未来产业”</a>，作者：张冰冰，阿至，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p>文&nbsp;|&nbsp;张冰冰</p>\\\\n  <p>编辑&nbsp;|&nbsp;阿至</p>\\\\n  <p>36氪获悉，蓝点触控（北京）科技有限公司（以下简称「蓝点触控」）<strong>近日宣布完成超亿元C+轮融资，由宁德时代旗下溥泉资本、智元机器人、银河通用、奥普特、银河源汇等机构联合投资。</strong>这是近一年内「蓝点触控」完成的第三轮过亿元融资。</p>\\\\n  <p>「蓝点触控」是36氪长期关注的企业，聚焦机器人力传感器，已搭建涵盖高性能弹性体设计、嵌入式硬件电路、高精度结构解耦算法及六维同步校准在内的四大平台型技术，形成人形机器人专用力传感器、通用力传感器、力控综合解决方案及复合型机器人工作站等多元化产品体系。</p>\\\\n  <p>凭借0.1%FS的高精度、10kHz以上高频响应、500%抗过载等性能指标，「蓝点触控」打破海外厂商技术垄断，<strong>已获得智元、小米、小鹏、银河通用、众擎、优必选、星海图、北京人形机器人创新中心等头部人形机器人企业的批量订单。</strong></p>\\\\n  <p>根据睿工业《2025年中国人形机器人六维力传感器市场调研报告》，2024年蓝点触控在中国人形机器人六维力传感器市场占有率约为62%，并预计2025年将提升至70%。高工机器人《GGII：2025中国人形机器人六维力传感器市场分析报告》显示，「蓝点触控」2025年前三季度市场份额达72.6%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_c987a78bc6d647b0ad9373f406e22709@16805102_oswg78064oswg1080oswg661_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">「蓝点触控」产品系列</p>\\\\n  <p>2026年以来，持续火热的具身智能赛道融资中，频繁出现宁德时代的身影。除了重资投入整机企业，<strong>宁德时代的布局也在向产业链上下游延伸，其中，力传感器作为关键力控、末端力控的刚需零部件，成为其中的重要一环。</strong></p>\\\\n  <p>据了解，资金支持之外，双方将从三方面进一步合作：第一，宁德时代在机器人领域已经投资了多家企业，能够提供客户资源支持；第二，宁德时代在零部件制造方面的管理经验和业务逻辑值得借鉴；第三，作为终端用户，宁德时代自身存在大量工业应用场景，有助于推动产品落地。</p>\\\\n  <p><strong>除了产业投资方，本轮投资方还包括「蓝点触控」的客户：智元机器人、银河通用。</strong>从客户到股东，合作的核心是行业共识的形成——大模型在人形机器人上的应用高度依赖于力控能力，力传感器因而成为核心零部件。同时，作为力传感器的规模化使用者，两家头部人形机器人企业在长期产品搭载中，对「蓝点触控」的技术指标与交付能力完成了严苛验证，本次投资体现了客户对「蓝点触控」的进一步认可。</p>\\\\n  <p>为什么力控对机器人如此关键？刘吴月从两个维度进行了说明：第一，机械臂的绝对定位精度受限。由于谐波减速器、连杆等环节存在变形或间隙，加上各臂体一致性不如工业机械臂，导致理论位置与实际到达位置之间存在偏差。第二，视觉系统同样受限于柔性环节，在复杂光照环境下识别和定位误差较大。因此在实际操作中，视觉和手臂只能进行粗定位，最终的精细操作需依赖力觉感知与控制来完成。</p>\\\\n  <p>另一方面，机器人大模型的训练高度依赖可靠的数据。由于真机数据的缺口较大，不少大模型训练采用仿真数据和真机数据结合的方式，但与位置、动作轨迹等数据相比，力觉数据更难通过仿真来实现。“力觉数据涉及接触物体的刚性及机械臂的柔性环节，存在很多非线性和不一致的问题，更难建模，这是后续数据训练时用真机补充的核心要点，必须通过大量操作来实现。” 刘吴月总结。</p>\\\\n  <p>放到实际应用场景中，情况将更加复杂，因此<strong>「蓝点触控」下一步的技术重点是配合客户做场景化的批量落地。</strong>“场景化落地就是真正把力控批量应用起来，这过程中会暴露出很多客户端对机器人的新需求，这也是对传感器和力控整体的新需求。”刘吴月介绍，机器人的硬件关节虽然指标相同，但在不同的机器人硬件产品上，解决方式各有特点和方式。「蓝点触控」基于客户群体和应用规模的优势，能更好地跟踪客户需求，满足其更高性能要求。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_1964e7e9f9024bbc83bffc0ca5583b23@16805102_oswg24321oswg900oswg490_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">「蓝点触控」力传感器产品在机械臂应用</p>\\\\n  <p>市场方面，人形机器人增长速度超过市场预期。咨询公司IDC发布的《全球人形机器人市场分析》显示，2025年全球人形机器人出货量约为1.8万台，同比增长约508%，其中中国厂商领跑市场。摩根士丹利将我国2026年人形机器人的销量预测从1.4万台上调至2.8万台，并预计我国2030年的人形机器人销量将达到26.2万台。</p>\\\\n  <p>伴随具身智能和机器人产业的快速崛起，「蓝点触控」已连续三年实现销售收入翻倍，并实现盈利。市场需求的快速扩张，给核心零部件供应链带来巨大机遇。<strong>刘吴月预计，2026年「蓝点触控」关节力传感器出货量将达约40万套，六维力传感器出货量约为3万至4万套。</strong></p>\\\\n  <p>目前，「蓝点触控」已在广东建成超万平自有生产基地，实现机器人力觉传感器生产的自动化，一期全自动产线实际利用率已接近90%。下一步，通过产线复制，「蓝点触控」将具备关节力传感器年产100万套、末端六维力传感器年产20万套的能力，交付周期有望进一步压缩至2周。</p>\\\\n  <p>谈及未来发展，刘吴月表示，「蓝点触控」将加大下一代高精度、高集成度力控传感器研发，更好地适配人形整机量产刚需；产业生态上加强和人形机器人、汽车产业链相关伙伴的合作；在销售端做好国内战略目标规划，同时开展海外市场。</p>\\\\n  <h3><strong>36氪未来产业</strong></h3>\\\\n  <p>「36氪未来产业」持续关注城市发展、产业转型和创新创业项目落地。寻求报道可邮箱联系wangfengzhi@36kr.com或扫码联系。</p>\\\\n  <p>此外，36氪正式推出《36氪企业投资指南内参》，依托在经济圈产业群、区域重点推进规划与招商领域的深厚积累，36氪通过提供深入详细、更为及时、独家专有的全面信息服务，为政府部门提供高效、精准的产业项目内参；助力项目方匹配产业资金、链接关键人脉、快速融入新的产业生态。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260414/v2_538a8fd2f7e34eeebe56c993e473e439@16805102_oswg464390oswg1036oswg388_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">&nbsp; &nbsp;&nbsp;</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/WBCsVnYX2jkSMr5UzAuYRg\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“36氪未来产业”</a>，作者：张冰冰，阿至，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-14 17:09:33\", \"ai_json_output\": \"\"}', NULL, '2026-04-14 17:09:33', '2026-04-16 12:04:15');
INSERT INTO `news_detail` VALUES (37, 1072, 7, '消费与零售', 'Motorola sues social platforms and creators over posts, raising speech concerns in India', '', 'Motorola has sought a permanent injunction restraining the defendants from publishing or sharing what it describes as false or defamatory content about its products, including reviews, videos, comments, and boycott campaigns.', 'https://techcrunch.com/2026/04/15/motorola-sues-social-platforms-and-creators-over-posts-raising-speech-concerns-in-india/', 0, '', '{\"summary\": \"帮助出海印度的消费电子企业了解当地网络内容维权的潜在舆论与法律风险\", \"abstract\": \"摩托罗拉近日在印度提起诉讼，将社交平台与内容创作者列为被告。摩托罗拉向法院申请永久禁令，要求禁止被告发布或分享针对其产品的虚假诽谤内容，涉案内容涵盖测评、视频、评论及抵制活动。该案引发了印度国内关于言论自由的担忧，也为出海印度的消费企业敲响了风险警钟。\", \"keywords\": [\"摩托罗拉\", \"印度出海\", \"诉讼\", \"虚假诽谤内容\", \"永久禁令\", \"言论合规\"], \"policy_risk\": {\"market_risk\": \"出海企业在印度针对网络负面内容发起维权诉讼，易引发言论自由相关舆论争议，可能损害品牌公众形象\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"https://techcrunch.com/2026/04/15/motorola-sues-social-platforms-and-creators-over-posts-raising-speech-concerns-in-india/\", \"title\": \"Motorola sues social platforms and creators over posts, raising speech concerns in India\", \"source\": \"https://techcrunch.com/feed/\", \"content\": \"Motorola has sought a permanent injunction restraining the defendants from publishing or sharing what it describes as false or defamatory content about its products, including reviews, videos, comments, and boycott campaigns.\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'Motorola sues social platforms and creators over posts, raising speech concerns in India\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Motorola sues social platforms and creators over posts, raising speech concerns in India\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://techcrunch.com/2026/04/15/motorola-sues-social-platforms-and-creators-over-posts-raising-speech-concerns-in-india/\'}], \'link\': \'https://techcrunch.com/2026/04/15/motorola-sues-social-platforms-and-creators-over-posts-raising-speech-concerns-in-india/\', \'authors\': [{\'name\': \'Jagmeet Singh\'}], \'author\': \'Jagmeet Singh\', \'author_detail\': {\'name\': \'Jagmeet Singh\'}, \'published\': \'Wed, 15 Apr 2026 16:00:17 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=15, tm_hour=16, tm_min=0, tm_sec=17, tm_wday=2, tm_yday=105, tm_isdst=0), \'tags\': [{\'term\': \'Hardware\', \'scheme\': None, \'label\': None}, {\'term\': \'Government & Policy\', \'scheme\': None, \'label\': None}, {\'term\': \'Exclusive\', \'scheme\': None, \'label\': None}, {\'term\': \'Motorola\', \'scheme\': None, \'label\': None}], \'id\': \'https://techcrunch.com/?p=3112597\', \'guidislink\': False, \'summary\': \'Motorola has sought a permanent injunction restraining the defendants from publishing or sharing what it describes as false or defamatory content about its products, including reviews, videos, comments, and boycott campaigns.\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Motorola has sought a permanent injunction restraining the defendants from publishing or sharing what it describes as false or defamatory content about its products, including reviews, videos, comments, and boycott campaigns.\'}}\", \"published_at\": \"2026-04-15 16:00:17\", \"ai_json_output\": \"\"}', 'Motorola has filed a lawsuit in India against social media platforms and content creators over posts it alleges are defamatory, raising concerns it could dampen critical coverage of the company, experts say.\nThe lawsuit, filed in a Bengaluru court and obtained by TechCrunch, names platforms such as X, YouTube, and Instagram along with dozens of content creators, and seeks takedown of the content as well as broader restraint on what it describes as false or defamatory material related to the company’s devices.\nIn its over 60-page filing, Motorola has sought a permanent injunction restraining the defendants from publishing or sharing what it describes as false or defamatory content about its products, including reviews, videos, comments, and boycott campaigns.\nThe complaint cites hundreds of posts across platforms, including videos alleging device issues and phones catching fire. But it is also targeting unfavorable product reviews and user commentary that the company alleges are false or defamatory.\nTwo content creators named in the suit, who spoke on condition of anonymity, said they learned about the case only after receiving an email from X’s support team on Tuesday notifying them that their account had been referenced in the proceedings.\nIn the email, X said it had received the lawsuit and was informing the user in the interest of transparency, suggesting they could seek legal counsel, contest the case, or remove the content.\nOne of the creators said the post cited in the suit related to an incident they had verified, adding that the company had replaced the device. “Brand is just mentally harassing us, and they want to set an example,” the creator told TechCrunch.\nTechcrunch event\nMeet your next investor or portfolio startup at Disrupt\nYour next round. Your next hire. Your next breakout opportunity. Find it at TechCrunch Disrupt 2026, where 10,000+ founders, investors, and tech leaders gather for three days of 250+ tactical sessions, powerful introductions, and market-defining innovation. Register now to save up to $410.\nMeet your next investor or portfolio startup at Disrupt\nYour next round. Your next hire. Your next breakout opportunity. Find it at TechCrunch Disrupt 2026, where 10,000+ founders, investors, and tech leaders gather for three days of 250+ tactical sessions, powerful introductions, and market-defining innovation. Register now to save up to $410.\nSan Francisco, CA\n|\nOctober 13-15, 2026\nREGISTER NOW\n“It will impact,” they said. “I will stop covering good parts too.”\nIndia is the second-biggest market for Motorola after the U.S., accounting for about 21% of its global smartphone shipments in 2025, according to data from International Data Corporation (IDC). More than 90% of its devices shipped in India were in the sub-$250 segment, the IDC data showed — a price band where consumers often rely on online reviews and word of mouth.\nFree-speech advocates contend that Motorola’s complaint is overreaching.\n“When a single complaint pulls together hundreds of URLs and asks for a blanket injunction against all of them, it collapses categories that the law has traditionally kept separate,” said Apar Gupta, a lawyer and founding director at the New Delhi-based digital rights group Internet Freedom Foundation. He warned of a broader “chilling effect,” saying many creators may choose to take down content rather than face the cost and stress of legal proceedings.\n“The category at greatest risk is precisely the one consumers most depend on: independent product criticism that holds manufacturers accountable for genuine safety and quality issues,” he told TechCrunch.\nMadhav Sheth, CEO of local smartphone brand Ai+ and former Realme India head, defended stricter action against what he described as misinformation,\nsaying\non social media that “freedom of speech is not a license for defamation.” He warned of legal action against “fake news or unverified ‘exposés.’” His remarks drew criticism online from users who said they could discourage legitimate product reviews.\nOthers in the industry took a different view. Sunil Raina, managing director of Lava International,\nsaid\non X: “When faced with criticism, you have two choices: intimidate or improve. One silences the feedback. The other silences the need for it.”\nThe case may signal a broader shift in how brands respond to online criticism in India. The creator cited above said they expect more such legal action in the future, as evolving rules around online content increase liability for creators and platforms — a trend reflected in\nrecently proposed changes to India’s IT rules\naimed at tightening oversight of online content.\nMotorola did not respond to a request for comment. Google, Meta, and X also did not respond.\nTopics\nExclusive\n,\nGovernment & Policy\n,\nHardware\n,\nIndia\n,\nMotorola\nJagmeet Singh\nReporter\nJagmeet covers startups, tech policy-related updates, and all other major tech-centric developments from India for TechCrunch. He previously worked as a principal correspondent at NDTV.\nYou can contact or verify outreach from Jagmeet by emailing\nmail@journalistjagmeet.com\n.\nView Bio\nApril 30\nSan Francisco, CA\nStrictlyVC kicks off the year in SF. Get in the room for unfiltered fireside chats with industry leaders, insider VC insights, and high-value connections that actually move the needle.\nTickets are limited.\nREGISTER NOW\nMost Popular\nAn Amazon warehouse worker died on the job at Oregon facility\nAmanda Silberling\nOpenAI has bought AI personal finance startup Hiro\nJulie Bort\nStanford report highlights growing disconnect between AI insiders and everyone else\nSarah Perez\nSam Altman responds to ‘incendiary’ New Yorker article after attack on his home\nAnthony Ha\nAnthropic temporarily banned OpenClaw’s creator from accessing Claude\nJulie Bort\nFrance to ditch Windows for Linux to reduce reliance on US tech\nZack Whittaker\nYouTube Premium and YouTube Music are getting more expensive\nAisha Malik', '2026-04-15 16:00:17', '2026-04-16 12:06:06');
INSERT INTO `news_detail` VALUES (38, 1073, 19, '跨境支付与金融配套', 'Airwallex is about to take on Stripe and the rest of the payments industry — in the physical world', '', 'Airwallex, valued at $8 billion, is launching a point-of-sale product that lets businesses accept in-person payments in multiple countries via a single platform.', 'https://techcrunch.com/2026/04/15/airwallex-is-about-to-take-on-stripe-and-the-rest-of-the-payments-industry-in-the-physical-world/', 0, '', '{\"summary\": \"本文为有线下跨境收款需求的出海企业介绍了Airwallex新推出的全球多国家线下POS支付产品，提供新的跨境支付选择\", \"abstract\": \"估值80亿美元的支付企业Airwallex即将推出线下销售点POS支付产品。该产品支持企业通过单一平台在多个国家接受线下当面支付。推出该产品后Airwallex将在线下支付领域与Stripe等行业对手竞争。这一产品为出海企业拓展了线下跨境收款的可选方案。\", \"keywords\": [\"Airwallex\", \"Stripe\", \"跨境支付\", \"线下支付\", \"POS产品\", \"全球收款\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"跨境支付服务\", \"industry_category\": \"跨境支付与金融配套\"}', '', '{\"url\": \"https://techcrunch.com/2026/04/15/airwallex-is-about-to-take-on-stripe-and-the-rest-of-the-payments-industry-in-the-physical-world/\", \"title\": \"Airwallex is about to take on Stripe and the rest of the payments industry — in the physical world\", \"source\": \"https://techcrunch.com/feed/\", \"content\": \"Airwallex, valued at $8 billion, is launching a point-of-sale product that lets businesses accept in-person payments in multiple countries via a single platform.\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'Airwallex is about to take on Stripe and the rest of the payments industry — in the physical world\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Airwallex is about to take on Stripe and the rest of the payments industry — in the physical world\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://techcrunch.com/2026/04/15/airwallex-is-about-to-take-on-stripe-and-the-rest-of-the-payments-industry-in-the-physical-world/\'}], \'link\': \'https://techcrunch.com/2026/04/15/airwallex-is-about-to-take-on-stripe-and-the-rest-of-the-payments-industry-in-the-physical-world/\', \'authors\': [{\'name\': \'Connie Loizos\'}], \'author\': \'Connie Loizos\', \'author_detail\': {\'name\': \'Connie Loizos\'}, \'published\': \'Wed, 15 Apr 2026 16:00:00 +0000\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=15, tm_hour=16, tm_min=0, tm_sec=0, tm_wday=2, tm_yday=105, tm_isdst=0), \'tags\': [{\'term\': \'Fintech\', \'scheme\': None, \'label\': None}, {\'term\': \'Startups\', \'scheme\': None, \'label\': None}, {\'term\': \'Airwallex\', \'scheme\': None, \'label\': None}, {\'term\': \'Jack Zhang\', \'scheme\': None, \'label\': None}, {\'term\': \'payments Tech\', \'scheme\': None, \'label\': None}, {\'term\': \'Square\', \'scheme\': None, \'label\': None}, {\'term\': \'stripe\', \'scheme\': None, \'label\': None}], \'id\': \'https://techcrunch.com/?p=3112527\', \'guidislink\': False, \'summary\': \'Airwallex, valued at $8 billion, is launching a point-of-sale product that lets businesses accept in-person payments in multiple countries via a single platform.\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://techcrunch.com/feed/\', \'value\': \'Airwallex, valued at $8 billion, is launching a point-of-sale product that lets businesses accept in-person payments in multiple countries via a single platform.\'}}\", \"published_at\": \"2026-04-15 16:00:00\", \"ai_json_output\": \"\"}', 'Airwallex\n, the Australian fintech that has spent a decade quietly building global payments infrastructure, is moving into in-person payments. The move deepens its rivalry with Stripe across the payments stack, and enables the startup to directly aim at Square and Adyen on one of the last major battlegrounds in financial technology.\nAirwallex is launching a point-of-sale product that it says does something its rivals’ offerings don’t: Allow businesses to accept in-person payments in multiple countries via a single platform, without onboarding local vendors in every market.\n“When a business expands into a new market, they typically have to onboard a new local acquirer, navigate fragmented compliance, and manage yet another set of vendor relationships,” CEO and co-founder Jack Zhang told TechCrunch.\nIn 2019, Stripe offered to acquire Airwallex for $1.2 billion, when Airwallex had just $2 million in revenue. But Zhang decided to keep building. “I even said yes to the deal,” he said, recalling the months-long negotiation. “But what really got me to change my mind is when I actually flew back to Melbourne and went deep on what motivated me to build Airwallex.”\nZhang founded Airwallex in 2015 out of frustration with the friction and expense of moving money internationally, but took a different approach than most fintech: He spent years assembling its own underlying payment rails.\nToday, Airwallex, valued at\n$8 billion\nby its investors, claims it generates annualized revenue of about $1.3 billion, and that the number is growing by roughly 85% every year. The startup says it now serves more than 46,000 U.S. businesses and processes $100 billion in annual volume.\nThe startup currently boasts close to 90 regulatory licenses across roughly 50 markets, direct connections to local payment networks in over 120 countries, and the ability to settle transactions in more than 90 currencies. It is the very infrastructure, Zhang says, that Stripe and Square lack in meaningful ways — particularly the local banking licenses that allow funds to be held, converted, and deployed within a given market rather than immediately repatriated.\nTechcrunch event\nMeet your next investor or portfolio startup at Disrupt\nYour next round. Your next hire. Your next breakout opportunity. Find it at TechCrunch Disrupt 2026, where 10,000+ founders, investors, and tech leaders gather for three days of 250+ tactical sessions, powerful introductions, and market-defining innovation. Register now to save up to $410.\nMeet your next investor or portfolio startup at Disrupt\nYour next round. Your next hire. Your next breakout opportunity. Find it at TechCrunch Disrupt 2026, where 10,000+ founders, investors, and tech leaders gather for three days of 250+ tactical sessions, powerful introductions, and market-defining innovation. Register now to save up to $410.\nSan Francisco, CA\n|\nOctober 13-15, 2026\nREGISTER NOW\n“Stripe and Square can process payments in Japan,” he said, “but when you actually process the payment, you need to immediately pay out to the merchant’s bank account. You can’t hold the funds.”\nAirwallex’s license in Japan — which took seven years to obtain — enables it to do exactly that.\nThe company’s new POS product extends that infrastructure to the physical countertop. Its platform now connects in-store and online payments, and offers unified reporting and direct integrations into back-office systems. For businesses operating across borders, stores in different countries can operate on the same payment systems and reconcile in the same place, without the usual tangle of local vendor relationships.\nAdyen, the listed Dutch payments company, makes a similar global infrastructure argument, and is perhaps Airwallex’s most direct competitor in this space. At the legacy end of the market, Fiserv as well as the newly combined Global Payments and Worldpay, command enormous market share among traditional brick-and-mortar retailers, though their architectures are considerably older.\nWhether businesses with established Stripe or Square relationships will find the global infrastructure argument compelling enough to switch is the open question. Airwallex is betting that multinationals tired of managing a different payments vendor in every country will favor its product.\n“There’s just not been a real competition to Stripe in the last 15 years, which is quite amazing considering how big the market is,” Zhang said.\nTopics\nAirwallex\n,\nFintech\n,\nJack Zhang\n,\npayments Tech\n,\nSquare\n,\nStartups\n,\nstripe\nConnie Loizos\nEditor in Chief & General Manager\nLoizos has been reporting on Silicon Valley since the late ’90s, when she joined the original Red Herring magazine. Previously the Silicon Valley Editor of TechCrunch, she was named Editor in Chief and General Manager of TechCrunch in September 2023. She’s also the founder of StrictlyVC, a daily e-newsletter and lecture series acquired by Yahoo in August 2023 and now operated as a sub brand of TechCrunch.\nYou can contact or verify outreach from Connie by emailing\nconnie@strictlyvc.com\nor\nconnie@techcrunch.com\n, or via encrypted message at ConnieLoizos.53 on Signal.\nView Bio\nApril 30\nSan Francisco, CA\nStrictlyVC kicks off the year in SF. Get in the room for unfiltered fireside chats with industry leaders, insider VC insights, and high-value connections that actually move the needle.\nTickets are limited.\nREGISTER NOW\nMost Popular\nAn Amazon warehouse worker died on the job at Oregon facility\nAmanda Silberling\nOpenAI has bought AI personal finance startup Hiro\nJulie Bort\nStanford report highlights growing disconnect between AI insiders and everyone else\nSarah Perez\nSam Altman responds to ‘incendiary’ New Yorker article after attack on his home\nAnthony Ha\nAnthropic temporarily banned OpenClaw’s creator from accessing Claude\nJulie Bort\nFrance to ditch Windows for Linux to reduce reliance on US tech\nZack Whittaker\nYouTube Premium and YouTube Music are getting more expensive\nAisha Malik', '2026-04-15 16:00:00', '2026-04-16 12:06:51');
INSERT INTO `news_detail` VALUES (39, 1117, 7, '消费与零售', '香港国际创科展及春季电子产品展开幕', '', '新华社香港4月14日电（记者舒娜）香港国际创科展及春季电子产品展14日在香港会议展览中心开幕。两展汇聚环球顶尖创科方案、人工智能技术及电子产品，吸引来自27个国家及地区的超过2800家展商参与。香港特<br>', 'http://baijiahao.baidu.com/s?id=1862451809142592588', 0, '', '{\"summary\": \"帮助出海创科、电子领域企业了解香港国际展会信息，对接全球行业资源\", \"abstract\": \"香港国际创科展及春季电子产品展于4月14日在香港会议展览中心开幕。本届展会汇聚环球顶尖创科方案、人工智能技术及各类电子产品。展会吸引来自27个国家及地区的超过2800家展商参与，为全球相关企业搭建了交流对接平台\", \"keywords\": [\"香港国际创科展\", \"春季电子产品展\", \"创科方案\", \"人工智能\", \"电子产品\", \"全球展商\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"http://baijiahao.baidu.com/s?id=1862451809142592588\", \"title\": \"香港国际创科展及春季电子产品展开幕\", \"source\": \"http://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\", \"content\": \"新华社香港4月14日电（记者舒娜）香港国际创科展及春季电子产品展14日在香港会议展览中心开幕。两展汇聚环球顶尖创科方案、人工智能技术及电子产品，吸引来自27个国家及地区的超过2800家展商参与。香港特<br>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'香港国际创科展及春季电子产品展开幕\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'香港国际创科展及春季电子产品展开幕\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://baijiahao.baidu.com/s?id=1862451809142592588\'}], \'link\': \'http://baijiahao.baidu.com/s?id=1862451809142592588\', \'published\': \'2026-04-16T02:55:05.000Z\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=55, tm_sec=5, tm_wday=3, tm_yday=106, tm_isdst=0), \'source\': {}, \'authors\': [{}], \'author\': \'\', \'summary\': \'新华社香港4月14日电（记者舒娜）香港国际创科展及春季电子产品展14日在香港会议展览中心开幕。两展汇聚环球顶尖创科方案、人工智能技术及电子产品，吸引来自27个国家及地区的超过2800家展商参与。香港特<br />\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'新华社香港4月14日电（记者舒娜）香港国际创科展及春季电子产品展14日在香港会议展览中心开幕。两展汇聚环球顶尖创科方案、人工智能技术及电子产品，吸引来自27个国家及地区的超过2800家展商参与。香港特<br />\'}}\", \"published_at\": \"2026-04-16 02:55:05\", \"ai_json_output\": \"\"}', '百度首页\n登录\n搜索\n复制\n香港国际创科展及春季电子产品展开幕\n新华社\n2026-04-14 21:14\n北京\n新华社官方账号\n关注\n新华社香港4月14日电（记者舒娜）香港国际创科展及春季电子产品展14日在香港会议展览中心开幕。两展汇聚环球顶尖创科方案、人工智能技术及电子产品，吸引来自27个国家及地区的超过2800家展商参与。\n香港特区政府创新科技及工业局局长孙东在开幕典礼上表示，香港国际创科展不仅是展示香港创科优势的年度展会，更是连接初创与投资者、科研与产业、本地企业与海内外市场的国际平台。\n香港贸发局总裁张淑芬表示，创科展已发展为具代表性的旗舰级平台，汇聚世界级创新者、研发中心及创科先锋，吸引越来越多展商展示前沿创新成果，促成策略性合作。\n联合国工业发展组织总干事格尔德·穆勒说，“全球南方”蕴藏着庞大的人口红利与市场潜力，需加大在人工智能方面投资力度，创造互利共赢局面。他期待与香港携手将前沿科技转化为高效生产力，让更多创新成果惠及全球产业和社会。\n今年创科展以“创新·智动·起飞”为主题，展会聚焦人工智能+、机器人技术、低空经济、房地产科技及零售科技五大领域。香港特区政府数字政策办公室设立“智慧香港展馆”，展出超过20个政府部门和公营机构的创新科技解决方案。低空经济成为今年新亮点，展会首次与“发展低空经济工作组”合办“低空经济发展会议”，并设立“低空经济专区”。\n春季电子产品展设有“品牌荟萃廊”、“初创专区”等约30个展区，来自15个国家及地区的展商带来约60款首次发布的电子产品，涵盖智能家居、健康科技及宠物智能等领域。\n作为“国际创科营商周”的核心活动，两大展会不仅展示了全球创科前沿成果，更透过跨区域、跨领域的协同效应，为业界带来广阔的交流与合作契机。为期四天的展览将举行超过100场活动。（完）\n举报/反馈\n0\n0\n收藏\n分享\n微信好友\n新浪微博\n复制链接\n扫码分享至微信\n设为首页\n© Baidu\n使用百度前必读\n京ICP证030173号\n京公网安备11000002000001号', '2026-04-16 02:55:05', '2026-04-16 12:12:50');
INSERT INTO `news_detail` VALUES (40, 1118, 11, '服务与基建', '香港启动“出海全球通”服务', '', '本报香港4月14日电(记者陈然)香港贸易发展局14日启动“出海全球通”服务，旨在善用全球51个办事处资源，促进内地企业更有效对接香港专业服务供应商，共同发掘全球商机。香港特区政府商务及经济发展局局长丘<br>', 'http://baijiahao.baidu.com/s?id=1862496611149998838', 0, '', '{\"summary\": \"本文介绍香港贸发局推出\\\"出海全球通\\\"服务，可帮助内地出海企业对接香港专业服务，挖掘全球商机，为出海企业提供新的资源对接渠道\", \"abstract\": \"香港贸易发展局于4月14日在香港正式启动\\\"出海全球通\\\"服务。该服务将依托贸发局全球51个办事处的资源网络，帮助内地企业对接香港的专业服务供应商。该服务旨在助力内地出海企业发掘全球商机，拓展海外业务。\", \"keywords\": [\"出海全球通\", \"香港贸易发展局\", \"企业出海\", \"全球商机\", \"专业服务对接\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"出海服务资源对接\", \"industry_category\": \"服务与基建\"}', '', '{\"url\": \"http://baijiahao.baidu.com/s?id=1862496611149998838\", \"title\": \"香港启动“出海全球通”服务\", \"source\": \"http://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\", \"content\": \"本报香港4月14日电(记者陈然)香港贸易发展局14日启动“出海全球通”服务，旨在善用全球51个办事处资源，促进内地企业更有效对接香港专业服务供应商，共同发掘全球商机。香港特区政府商务及经济发展局局长丘<br>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'香港启动“出海全球通”服务\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'香港启动“出海全球通”服务\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://baijiahao.baidu.com/s?id=1862496611149998838\'}], \'link\': \'http://baijiahao.baidu.com/s?id=1862496611149998838\', \'published\': \'2026-04-16T02:55:05.000Z\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=2, tm_min=55, tm_sec=5, tm_wday=3, tm_yday=106, tm_isdst=0), \'source\': {}, \'authors\': [{}], \'author\': \'\', \'summary\': \'本报香港4月14日电(记者陈然)香港贸易发展局14日启动“出海全球通”服务，旨在善用全球51个办事处资源，促进内地企业更有效对接香港专业服务供应商，共同发掘全球商机。香港特区政府商务及经济发展局局长丘<br />\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'本报香港4月14日电(记者陈然)香港贸易发展局14日启动“出海全球通”服务，旨在善用全球51个办事处资源，促进内地企业更有效对接香港专业服务供应商，共同发掘全球商机。香港特区政府商务及经济发展局局长丘<br />\'}}\", \"published_at\": \"2026-04-16 02:55:05\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 02:55:05', '2026-04-16 12:13:32');
INSERT INTO `news_detail` VALUES (41, 1328, 6, '科技与数字服务', '孙东：香港将努力打造国际创新科技中心', '', '4月13日，2026年世界互联网大会亚太峰会在香港举行。香港特别行政区政府创新科技及工业局局长孙东在致辞中强调，数字化转型浪潮下，技术创新和国际合作是推动可持续发展的必由之路。孙东表示，香港将建成国际<br>', 'http://baijiahao.baidu.com/s?id=1862494507319799704', 0, '', '{\"summary\": \"帮助科创出海企业了解香港打造国际创科中心的规划，把握港澳科创出海合作机遇\", \"abstract\": \"4月13日，2026年世界互联网大会亚太峰会在香港举办。香港特别行政区政府创新科技及工业局局长孙东在致辞中提出，数字化转型浪潮下，技术创新和国际合作是推动可持续发展的必由之路。孙东表示香港将努力打造国际创新科技中心，本次原文内容在此处截断。\", \"keywords\": [\"香港\", \"国际创新科技中心\", \"世界互联网大会\", \"数字化转型\", \"技术创新\", \"国际合作\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"香港明确提出将打造国际创新科技中心，推动科创领域国际合作，未提及具体合规要求变化\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"http://baijiahao.baidu.com/s?id=1862494507319799704\", \"title\": \"孙东：香港将努力打造国际创新科技中心\", \"source\": \"http://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\", \"content\": \"4月13日，2026年世界互联网大会亚太峰会在香港举行。香港特别行政区政府创新科技及工业局局长孙东在致辞中强调，数字化转型浪潮下，技术创新和国际合作是推动可持续发展的必由之路。孙东表示，香港将建成国际<br>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'孙东：香港将努力打造国际创新科技中心\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'孙东：香港将努力打造国际创新科技中心\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://baijiahao.baidu.com/s?id=1862494507319799704\'}], \'link\': \'http://baijiahao.baidu.com/s?id=1862494507319799704\', \'published\': \'2026-04-16T03:23:37.000Z\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=3, tm_min=23, tm_sec=37, tm_wday=3, tm_yday=106, tm_isdst=0), \'source\': {}, \'authors\': [{}], \'author\': \'\', \'summary\': \'4月13日，2026年世界互联网大会亚太峰会在香港举行。香港特别行政区政府创新科技及工业局局长孙东在致辞中强调，数字化转型浪潮下，技术创新和国际合作是推动可持续发展的必由之路。孙东表示，香港将建成国际<br />\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'4月13日，2026年世界互联网大会亚太峰会在香港举行。香港特别行政区政府创新科技及工业局局长孙东在致辞中强调，数字化转型浪潮下，技术创新和国际合作是推动可持续发展的必由之路。孙东表示，香港将建成国际<br />\'}}\", \"published_at\": \"2026-04-16 03:23:37\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 03:23:37', '2026-04-16 13:13:01');
INSERT INTO `news_detail` VALUES (42, 1425, 20, '其他', '国家统计局：我国进出口有条件保持较好增长', '', '国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，从过去多年的实践看，不管外部环境如何变化，即便是在疫情期间市场担心我国外贸能否持续下去，但我国进出口一直很强劲。这得益于企业下功夫苦练内功，提高产品技术含量和综合竞争能力等。综合来看，我国进出口还是有条件保持比较好的增长。（证券时报）', 'https://36kr.com/newsflashes/3768960742638084?f=rss', 0, '', '{\"summary\": \"本文公布官方对我国进出口形势的判断，帮助出海外贸企业把握市场走势，合理规划业务布局\", \"abstract\": \"国家统计局副局长4月16日在国新办新闻发布会上，就我国进出口发展形势作出判断。多年实践显示，无论外部环境如何变化，我国进出口始终保持强劲态势。这一成果得益于企业苦练内功，提升了产品技术含量与综合竞争力。官方综合判断认为，我国进出口仍有条件保持较好增长。\", \"keywords\": [\"进出口\", \"外贸增长\", \"外部环境\", \"企业竞争力\", \"国家统计局\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"其他\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3768960742638084?f=rss\", \"title\": \"国家统计局：我国进出口有条件保持较好增长\", \"source\": \"https://36kr.com/feed\", \"content\": \"国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，从过去多年的实践看，不管外部环境如何变化，即便是在疫情期间市场担心我国外贸能否持续下去，但我国进出口一直很强劲。这得益于企业下功夫苦练内功，提高产品技术含量和综合竞争能力等。综合来看，我国进出口还是有条件保持比较好的增长。（证券时报）\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'国家统计局：我国进出口有条件保持较好增长\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'国家统计局：我国进出口有条件保持较好增长\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3768960742638084?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3768960742638084?f=rss\', \'published\': \'2026-04-16 11:45:07  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=3, tm_min=45, tm_sec=7, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，从过去多年的实践看，不管外部环境如何变化，即便是在疫情期间市场担心我国外贸能否持续下去，但我国进出口一直很强劲。这得益于企业下功夫苦练内功，提高产品技术含量和综合竞争能力等。综合来看，我国进出口还是有条件保持比较好的增长。（证券时报）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，从过去多年的实践看，不管外部环境如何变化，即便是在疫情期间市场担心我国外贸能否持续下去，但我国进出口一直很强劲。这得益于企业下功夫苦练内功，提高产品技术含量和综合竞争能力等。综合来看，我国进出口还是有条件保持比较好的增长。（证券时报）\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 11:45:07\", \"ai_json_output\": \"\"}', '账号设置\n我的关注\n我的收藏\n申请的报道\n退出登录\n登录\n搜索\n36氪Auto\n数字时氪\n未来消费\n智能涌现\n未来城市\n启动Power on\n36氪出海\n36氪研究院\n潮生TIDE\n36氪企服点评\n36氪财经\n职场bonus\n36碳\n后浪研究所\n暗涌Waves\n硬氪\n氪睿研究院\n媒体品牌\n企业号\n企服点评\n36Kr研究院\n36Kr创新咨询\n企业服务\n核心服务\n城市之窗\n政府服务\n创投发布\nLP源计划\nVClub\nVClub投资机构库\n投资机构职位推介\n投资人认证\n投资人服务\n寻求报道\n36氪Pro\n创投氪堂\n企业入驻\n创业者服务\n创投平台\nAI测评网\n首页\n快讯\n资讯\n推荐\n财经\nAI\n自助报道\n四川\n最新\n创投\n汽车\n科技\n专精特新\n直播\n视频\n专题\n活动\n搜索\n寻求报道\n我要入驻\n城市合作\n04\n月\n16\n国家统计局：我国进出口有条件保持较好增长\n2026-04-16 11:45\n分享至\n打开微信“扫一扫”，打开网页后点击屏幕右上角分享按钮\n国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，从过去多年的实践看，不管外部环境如何变化，即便是在疫情期间市场担心我国外贸能否持续下去，但我国进出口一直很强劲。这得益于企业下功夫苦练内功，提高产品技术含量和综合竞争能力等。综合来看，我国进出口还是有条件保持比较好的增长。（证券时报）\n原文链接\n下一篇\n京东发布机器人产业服务全景图\n36氪获悉，4月15日，京东发布“机器人产业服务全景图”。全景图聚焦三大核心：携手超 200家品牌，目标2026年销售破百亿；依托超级供应链，建全球最大具身数据采集中心、京东机器人售后维修服务3年覆盖50余城；基于JoyAI大模型加速开放JoyInside附身智能交互能力，为机器人注入“智慧大脑”。\n1小时前\n24小时热榜\n查看更多榜单\nHermes Agent抄袭中国团队代码实锤，被锤后回应：你删号\n8点1氪丨美国将退还超1万亿元关税；多家银行密集停发信用卡；滴露回应使用宠物消毒液后5只幼猫死亡\n突发：Claude引入强实名制验证，必须真人手持证件自拍，否则直接封号\n5小时前\nClaude Opus 4.7 或本周上线，但 Anthropic 要查你证件了\n18小时前\n苹果疯狂狙击Vibe Coding App\n21小时前\n国产AI芯片崛起：三大门派、瓜分英伟达\n15小时前\n北京车展终极前瞻：新势力“9系”豪车正面硬刚，Robotaxi成智驾新战场\n2小时前\n你等的DeepSeek，早已变了\n19小时前\n关于36氪\n城市合作\n寻求报道\n我要入驻\n投资者关系\n商务合作\n关于我们\n联系我们\n加入我们\n36氪欧洲站\n36氪欧洲站\n36氪欧洲站\nAi产品日报\n网络谣言信息举报入口\n热门推荐\n热门资讯\n热门产品\n文章标签\n快讯标签\n合作伙伴\n36氪APP下载\niOS & Android\n本站由\n阿里云\n提供计算与安全服务 违法和不良信息、未成年人保护举报电话：010-89650707 举报邮箱：jubao@36kr.com\n网上有害信息举报\n© 2011~\n2026\n北京多氪信息科技有限公司 |\n京ICP备12031756号-6\n|\n京ICP证150143号\n|\n京公网安备11010502057322号\n意见反馈\n36氪APP\n让一部分人先看到未来\n36氪\n鲸准\n氪空间\n推送和解读前沿、有料的科技创投资讯\n一级市场金融信息和系统服务提供商\n聚焦全球优秀创业者，项目融资率接近97%，领跑行业', '2026-04-16 11:45:07', '2026-04-16 13:31:15');
INSERT INTO `news_detail` VALUES (43, 1440, 8, '新能源与汽车', '2026北京车展前瞻：自动驾驶从秀场突围，商业化迎决定性拐点', '', '<blockquote>\n<p><strong>北京车展在即，自动驾驶5大预测出炉，L3普及、商业化落地成核心看点。</strong></p>\n</blockquote>\n<p>2026 年 4 月 24 日，以 “领时代 智未来” 为主题的北京国际车展将拉开帷幕。作为全球智能化量产的分水岭，本届车展不再是概念车的 “秀场”，而是自动驾驶技术与商业化落地的<strong>终极决战场</strong>。基于<strong>政策窗口期、技术成熟度与产业竞争格局</strong>，我们做出<strong>自动驾驶五大大胆预测</strong>，看清未来一年行业的核心走向。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_ab8f762ede584905933fdfb3f6064f44@35930_oswg110639oswg1080oswg1539_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<h2><strong>预测一</strong></h2>\n<h2><strong>L3级自动驾驶规模化落地</strong></h2>\n<p>2026年，业内已形成共识：这是<strong>L3级自动驾驶从“试点试水”走向“全民普及”的真正元年</strong>，而北京车展将成为这一行业里程碑的集中兑现场。</p>\n<p>此前国内L3级自动驾驶政策的全面落地，为本次车展的技术爆发奠定了基础——<strong>全国23城开放高速/快速路L3合法路段</strong>，明确事故责任主体（车企主责，仅10秒不接管车主担责），强制搭载智驾“黑匣子”与专项险，这些政策红利将在车展上转化为实实在在的量产成果。</p>\n<p>从技术落地来看，头部企业的智驾方案将全面下放，彻底打破“高阶智驾=高端车型”的固有认知。华为ADS 5.0、小鹏XNGP 4.0、地平线征程6P三大主流方案，将不再局限于50万级以上豪华车型，而是<strong>全面渗透至20-30万级主流市场，成为该价位段车型的标配</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_02f762e8ec664daf9df9c6306107f769@35930_oswg453707oswg1080oswg486_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>更值得关注的是，<strong>15万级经济型车型将推出L3级智驾选装包，选装成本控制在1-2万元</strong>，让普通消费者也能享受到高阶智驾的便捷。这种价格下探并非技术妥协，而是源于传感器与芯片成本的规模化摊薄，以及算法效率的持续优化。</p>\n<p>场景覆盖方面，<strong>高速L3将实现全面普及</strong>，城市快速路与拥堵路段的L3试点将进一步扩容，核心突破点在于“10秒合法接管”机制的落地——驾驶员可短暂脱离视线，无需时刻紧盯路面，真正实现“高速通勤解放双手”。</p>\n<p>从车企动作来看，问界M9、岚图泰山Ultra等已获得L3准入资质的车型，将在车展现场进行实车演示，直观展示复杂路况下的智驾表现；宝马、奔驰等豪华品牌也将紧跟中国标准，发布基于MB.OS、Momenta方案的L3量产系统，标志着全球车企开始主动适配中国智驾生态。</p>\n<p>更关键的是，L3级智驾的规模化落地将倒逼产业链协同升级，从智驾芯片、激光雷达到算法软件，整个供应链将进入“量产优化”的良性循环，为后续L4级技术的落地积累数据与经验。</p>\n<h2><strong>预测二</strong></h2>\n<h2><strong>国产智驾芯片登顶，成本下探至千元级</strong></h2>\n<p>芯片是自动驾驶的“心脏”，也是此前中国智驾产业的“卡脖子”环节。而2026北京车展，将正式见证<strong>国产智驾芯片的全面突围</strong>，彻底打破海外企业在高端智驾芯片领域的垄断格局，实现<strong>“算力领先+成本普惠”的双重突破</strong>。</p>\n<p>技术层面，国产智驾芯片将迎来“算力爆发”。地平线征程6P（560TOPS）、黑芝麻智能华山A2000（7nm工艺）、芯驰X9系列等国产旗舰芯片将集中亮相，其中<strong>黑芝麻智能华山A2000的单芯片算力将突破1000TOPS</strong>，支持Transformer大模型实时推理。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_578f3da1c3c14d0aa6b225c6b8c0aa30@35930_oswg477217oswg1080oswg685_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>这种算力突破并非“盲目堆料”，而是基于国内复杂路况的场景优化，能够更好地适配加塞、鬼探头、无标线道路等中国特色路况，算法响应速度提升30%以上。</p>\n<p>成本革命将成为本次车展的核心亮点之一。随着国产芯片的规模化量产与技术成熟，激光雷达与智驾芯片的成本将同步下探——<strong>激光雷达单价将从当前的3000-5000元降至千元级</strong>，智驾芯片单车成本将压缩30%，彻底解决此前高阶智驾“硬件成本过高”的痛点。</p>\n<p>产业绑定方面，国产芯片企业与车企、Tier1供应商的合作将进一步深化，“软硬件解耦”成为行业共识。地平线与采埃孚、黑芝麻与国汽智控、比亚迪与芯驰的合作成果将在车展上集中展示，车企可根据自身需求灵活选择芯片与算法方案。</p>\n<h2><strong>预测三</strong></h2>\n<h2><strong>AI大模型全栈上车，端侧融合提效</strong></h2>\n<p>如果说芯片是自动驾驶的“心脏”，那么AI大模型就是自动驾驶的“大脑”。2026北京车展，将实现<strong>AI大模型从“座舱娱乐”向“智驾核心”的全栈渗透</strong>，技术从“实验室原型”走向“量产车落地”，彻底改变自动驾驶的决策逻辑。</p>\n<p>技术落地层面，华为、小鹏、轻舟智航等头部企业将集中发布端到端大模型方案，核心突破点在于<strong>“无图化城区NOA”的规模化落地</strong>。不同于传统依赖高精地图的智驾方案，端到端大模型能够通过视觉感知与环境理解，无需高精地图即可适配复杂城区路况，感知准确率提升40%。</p>\n<p>其中，小鹏XNGP 5.0采用纯视觉路线，依托VLM视觉语言模型+轻传感器，双Orin-X芯片(508TOPS)的硬件配置，成本更低且驾驶风格激进；华为ADS 5.0则主打多传感器融合+无图NOA，<strong>4颗896线激光雷达、13颗摄像头的豪华配置</strong>，让无保护左转成功率达99.5%。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_198d5f9db1594c8883f6883aaf5a38cf@35930_oswg470679oswg978oswg534_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>场景贯通方面，高速、城区、泊车全场景打通将成为常态，VLM（世界模型）+强化学习技术将广泛应用。搭载该技术的车辆，能够自主学习中国路况特点，应对加塞、鬼探头等复杂场景，甚至能够根据驾驶员的驾驶习惯调整行驶风格。</p>\n<p>座舱与智驾的深度融合将成为另一大亮点。车载大模型将实现多轮自然语言交互、语音控全车，能够理解驾驶员的复杂指令，甚至能够预判驾驶员的需求，实现“车控家、家控车”的智能联动。</p>\n<h2><strong>预测四</strong></h2>\n<h2><strong>自动驾驶巴士商业化提速，方案出海常态化</strong></h2>\n<p>自动驾驶巴士作为商业化落地的关键场景，凭借“固定路线、低速行驶、场景封闭”的优势，成为<strong>自动驾驶技术规模化落地的“先行军”</strong>。</p>\n<p>其中，蘑菇车联MOGOBUS已成为该赛道的最大亮点——依托近期在消博会斩获大奖、登陆新加坡等重磅成果，蘑菇车联将进一步巩固中国自动驾驶巴士的全球领先地位。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1ce238813d8243b08ab39a5cd963492f@35930_oswg110976oswg960oswg640_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>就在北京车展前夕，蘑菇车联MOGOBUS凭借扎实的技术能力和全球化落地成果，在第六届中国国际消费品博览会上，从数百家企业的激烈竞争中脱颖而出，荣获“全球好礼”科技创新奖，成为唯一获此殊荣的中国自动驾驶巴士产品。</p>\n<p>更关键的是，新一代MOGOBUS已正式登陆新加坡，成为中国自动驾驶公交巴士首次进入发达国家公交骨干网络的标杆项目，标志着蘑菇车联自动驾驶解决方案已获得全球最严苛市场的认可。</p>\n<p>国内落地方面，MOGOBUS已在中国20余个城市落地运营，为超过20万人次提供智能出行服务，累计行驶里程突破500万公里，曾服务于多项高规格国际活动和大型赛事。近期，蘑菇车联打造的全国首条跨境医疗自动驾驶微循环线路——“琴澳医线”正式开通。</p>\n<h2><strong>预测五</strong></h2>\n<h2><strong>商业模式重构，订阅制+保险生态成主流</strong></h2>\n<p>经历了多年的“烧钱换规模”，2026年自动驾驶行业将正式从“技术驱动”转向“商业驱动”，而北京车展将明确行业可持续盈利的核心路径，单车盈利拐点将正式显现。</p>\n<p>订阅制将成为智驾服务的主流商业模式。车企与科技公司将推出多元化的智驾订阅服务，按“月/季/年”付费，解锁高速NOA、城区NOA等核心功能，满足不同用户的需求。例如，特斯拉FSD中国版推出月租680元、一次性购买3.2万元的灵活订阅方案。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_442048276afc4a5da68746167874f1b6@35930_oswg445759oswg712oswg403_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>智驾专属保险的全面落地，将进一步降低用户的使用门槛与车企的运营风险。不同于传统车险，智驾专属保险将覆盖系统故障、事故责任等核心风险，保费与驾驶行为、系统数据挂钩，彻底解决用户“不敢用、怕担责”的顾虑。</p>\n<p>单车盈利拐点将在头部企业率先显现。通过出行服务、数据服务、软件订阅等多元收入，头部企业将实现“硬件成本覆盖+盈利”的目标，行业将彻底告别“烧钱换规模”的野蛮生长阶段，进入“盈利增规模”的良性发展周期。</p>\n<h2><strong>北京车展</strong></h2>\n<h2><strong>见证中国自动驾驶从“跟随”到“领跑”的质变</strong></h2>\n<p>2026年北京车展，注定是中国自动驾驶产业发展史上的“里程碑式展会”——它不再是技术的“展示台”，而是商业化落地的“试金石”，是中国智驾<strong>从“技术领先”走向“产业领跑”</strong>的质变节点。</p>\n<p>对于普通消费者而言，这意味着“花15万就能享50万级智驾体验”，日常通勤将彻底解放双手；对于产业而言，这意味着中国标准、中国方案、中国生态将成为全球标杆。</p>\n<p>4月24日，北京车展大幕将启。这场智能化量产的终极决战，将见证自动驾驶真正走进千家万户，见证中国自动驾驶产业完成从“跟随者”到“领跑者”的华丽转身。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/lq5DmG43CvSL8EuRDyPf2w\">“山自”</a>，作者：Rayking629，36氪经授权发布。</p>', 'https://36kr.com/p/3768944509186569?f=rss', 0, '', '{\"summary\": \"本文发布2026北京车展自动驾驶行业五大发展预测，帮助自动驾驶出海企业把握产业趋势与商业化方向\", \"abstract\": \"2026年4月举办的北京车展被视为自动驾驶技术商业化落地的关键节点，本文针对行业发展做出五大核心预测。预测指出L3级自动驾驶将在2026年规模化落地，价格下探至15万级经济型车市场，实现高速路段全面普及。国产智驾芯片将打破海外垄断，实现算力提升与成本下探，AI大模型也将全栈上车渗透至智驾核心环节。自动驾驶巴士商业化进程提速，中国自动驾驶方案已实现出海常态化，进入发达国家市场，行业商业模式重构后将迎来盈利拐点。\", \"keywords\": [\"自动驾驶\", \"L3级自动驾驶\", \"商业化落地\", \"智驾芯片\", \"方案出海\", \"AI大模型\", \"北京车展\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"国内L3级自动驾驶政策已全面落地，全国23城开放高速/快速路L3合法路段，明确事故责任划分，强制搭载智驾“黑匣子”与专项险\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3768944509186569?f=rss\", \"title\": \"2026北京车展前瞻：自动驾驶从秀场突围，商业化迎决定性拐点\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<blockquote>\\n<p><strong>北京车展在即，自动驾驶5大预测出炉，L3普及、商业化落地成核心看点。</strong></p>\\n</blockquote>\\n<p>2026 年 4 月 24 日，以 “领时代 智未来” 为主题的北京国际车展将拉开帷幕。作为全球智能化量产的分水岭，本届车展不再是概念车的 “秀场”，而是自动驾驶技术与商业化落地的<strong>终极决战场</strong>。基于<strong>政策窗口期、技术成熟度与产业竞争格局</strong>，我们做出<strong>自动驾驶五大大胆预测</strong>，看清未来一年行业的核心走向。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ab8f762ede584905933fdfb3f6064f44@35930_oswg110639oswg1080oswg1539_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<h2><strong>预测一</strong></h2>\\n<h2><strong>L3级自动驾驶规模化落地</strong></h2>\\n<p>2026年，业内已形成共识：这是<strong>L3级自动驾驶从“试点试水”走向“全民普及”的真正元年</strong>，而北京车展将成为这一行业里程碑的集中兑现场。</p>\\n<p>此前国内L3级自动驾驶政策的全面落地，为本次车展的技术爆发奠定了基础——<strong>全国23城开放高速/快速路L3合法路段</strong>，明确事故责任主体（车企主责，仅10秒不接管车主担责），强制搭载智驾“黑匣子”与专项险，这些政策红利将在车展上转化为实实在在的量产成果。</p>\\n<p>从技术落地来看，头部企业的智驾方案将全面下放，彻底打破“高阶智驾=高端车型”的固有认知。华为ADS 5.0、小鹏XNGP 4.0、地平线征程6P三大主流方案，将不再局限于50万级以上豪华车型，而是<strong>全面渗透至20-30万级主流市场，成为该价位段车型的标配</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_02f762e8ec664daf9df9c6306107f769@35930_oswg453707oswg1080oswg486_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>更值得关注的是，<strong>15万级经济型车型将推出L3级智驾选装包，选装成本控制在1-2万元</strong>，让普通消费者也能享受到高阶智驾的便捷。这种价格下探并非技术妥协，而是源于传感器与芯片成本的规模化摊薄，以及算法效率的持续优化。</p>\\n<p>场景覆盖方面，<strong>高速L3将实现全面普及</strong>，城市快速路与拥堵路段的L3试点将进一步扩容，核心突破点在于“10秒合法接管”机制的落地——驾驶员可短暂脱离视线，无需时刻紧盯路面，真正实现“高速通勤解放双手”。</p>\\n<p>从车企动作来看，问界M9、岚图泰山Ultra等已获得L3准入资质的车型，将在车展现场进行实车演示，直观展示复杂路况下的智驾表现；宝马、奔驰等豪华品牌也将紧跟中国标准，发布基于MB.OS、Momenta方案的L3量产系统，标志着全球车企开始主动适配中国智驾生态。</p>\\n<p>更关键的是，L3级智驾的规模化落地将倒逼产业链协同升级，从智驾芯片、激光雷达到算法软件，整个供应链将进入“量产优化”的良性循环，为后续L4级技术的落地积累数据与经验。</p>\\n<h2><strong>预测二</strong></h2>\\n<h2><strong>国产智驾芯片登顶，成本下探至千元级</strong></h2>\\n<p>芯片是自动驾驶的“心脏”，也是此前中国智驾产业的“卡脖子”环节。而2026北京车展，将正式见证<strong>国产智驾芯片的全面突围</strong>，彻底打破海外企业在高端智驾芯片领域的垄断格局，实现<strong>“算力领先+成本普惠”的双重突破</strong>。</p>\\n<p>技术层面，国产智驾芯片将迎来“算力爆发”。地平线征程6P（560TOPS）、黑芝麻智能华山A2000（7nm工艺）、芯驰X9系列等国产旗舰芯片将集中亮相，其中<strong>黑芝麻智能华山A2000的单芯片算力将突破1000TOPS</strong>，支持Transformer大模型实时推理。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_578f3da1c3c14d0aa6b225c6b8c0aa30@35930_oswg477217oswg1080oswg685_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>这种算力突破并非“盲目堆料”，而是基于国内复杂路况的场景优化，能够更好地适配加塞、鬼探头、无标线道路等中国特色路况，算法响应速度提升30%以上。</p>\\n<p>成本革命将成为本次车展的核心亮点之一。随着国产芯片的规模化量产与技术成熟，激光雷达与智驾芯片的成本将同步下探——<strong>激光雷达单价将从当前的3000-5000元降至千元级</strong>，智驾芯片单车成本将压缩30%，彻底解决此前高阶智驾“硬件成本过高”的痛点。</p>\\n<p>产业绑定方面，国产芯片企业与车企、Tier1供应商的合作将进一步深化，“软硬件解耦”成为行业共识。地平线与采埃孚、黑芝麻与国汽智控、比亚迪与芯驰的合作成果将在车展上集中展示，车企可根据自身需求灵活选择芯片与算法方案。</p>\\n<h2><strong>预测三</strong></h2>\\n<h2><strong>AI大模型全栈上车，端侧融合提效</strong></h2>\\n<p>如果说芯片是自动驾驶的“心脏”，那么AI大模型就是自动驾驶的“大脑”。2026北京车展，将实现<strong>AI大模型从“座舱娱乐”向“智驾核心”的全栈渗透</strong>，技术从“实验室原型”走向“量产车落地”，彻底改变自动驾驶的决策逻辑。</p>\\n<p>技术落地层面，华为、小鹏、轻舟智航等头部企业将集中发布端到端大模型方案，核心突破点在于<strong>“无图化城区NOA”的规模化落地</strong>。不同于传统依赖高精地图的智驾方案，端到端大模型能够通过视觉感知与环境理解，无需高精地图即可适配复杂城区路况，感知准确率提升40%。</p>\\n<p>其中，小鹏XNGP 5.0采用纯视觉路线，依托VLM视觉语言模型+轻传感器，双Orin-X芯片(508TOPS)的硬件配置，成本更低且驾驶风格激进；华为ADS 5.0则主打多传感器融合+无图NOA，<strong>4颗896线激光雷达、13颗摄像头的豪华配置</strong>，让无保护左转成功率达99.5%。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_198d5f9db1594c8883f6883aaf5a38cf@35930_oswg470679oswg978oswg534_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>场景贯通方面，高速、城区、泊车全场景打通将成为常态，VLM（世界模型）+强化学习技术将广泛应用。搭载该技术的车辆，能够自主学习中国路况特点，应对加塞、鬼探头等复杂场景，甚至能够根据驾驶员的驾驶习惯调整行驶风格。</p>\\n<p>座舱与智驾的深度融合将成为另一大亮点。车载大模型将实现多轮自然语言交互、语音控全车，能够理解驾驶员的复杂指令，甚至能够预判驾驶员的需求，实现“车控家、家控车”的智能联动。</p>\\n<h2><strong>预测四</strong></h2>\\n<h2><strong>自动驾驶巴士商业化提速，方案出海常态化</strong></h2>\\n<p>自动驾驶巴士作为商业化落地的关键场景，凭借“固定路线、低速行驶、场景封闭”的优势，成为<strong>自动驾驶技术规模化落地的“先行军”</strong>。</p>\\n<p>其中，蘑菇车联MOGOBUS已成为该赛道的最大亮点——依托近期在消博会斩获大奖、登陆新加坡等重磅成果，蘑菇车联将进一步巩固中国自动驾驶巴士的全球领先地位。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1ce238813d8243b08ab39a5cd963492f@35930_oswg110976oswg960oswg640_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>就在北京车展前夕，蘑菇车联MOGOBUS凭借扎实的技术能力和全球化落地成果，在第六届中国国际消费品博览会上，从数百家企业的激烈竞争中脱颖而出，荣获“全球好礼”科技创新奖，成为唯一获此殊荣的中国自动驾驶巴士产品。</p>\\n<p>更关键的是，新一代MOGOBUS已正式登陆新加坡，成为中国自动驾驶公交巴士首次进入发达国家公交骨干网络的标杆项目，标志着蘑菇车联自动驾驶解决方案已获得全球最严苛市场的认可。</p>\\n<p>国内落地方面，MOGOBUS已在中国20余个城市落地运营，为超过20万人次提供智能出行服务，累计行驶里程突破500万公里，曾服务于多项高规格国际活动和大型赛事。近期，蘑菇车联打造的全国首条跨境医疗自动驾驶微循环线路——“琴澳医线”正式开通。</p>\\n<h2><strong>预测五</strong></h2>\\n<h2><strong>商业模式重构，订阅制+保险生态成主流</strong></h2>\\n<p>经历了多年的“烧钱换规模”，2026年自动驾驶行业将正式从“技术驱动”转向“商业驱动”，而北京车展将明确行业可持续盈利的核心路径，单车盈利拐点将正式显现。</p>\\n<p>订阅制将成为智驾服务的主流商业模式。车企与科技公司将推出多元化的智驾订阅服务，按“月/季/年”付费，解锁高速NOA、城区NOA等核心功能，满足不同用户的需求。例如，特斯拉FSD中国版推出月租680元、一次性购买3.2万元的灵活订阅方案。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_442048276afc4a5da68746167874f1b6@35930_oswg445759oswg712oswg403_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>智驾专属保险的全面落地，将进一步降低用户的使用门槛与车企的运营风险。不同于传统车险，智驾专属保险将覆盖系统故障、事故责任等核心风险，保费与驾驶行为、系统数据挂钩，彻底解决用户“不敢用、怕担责”的顾虑。</p>\\n<p>单车盈利拐点将在头部企业率先显现。通过出行服务、数据服务、软件订阅等多元收入，头部企业将实现“硬件成本覆盖+盈利”的目标，行业将彻底告别“烧钱换规模”的野蛮生长阶段，进入“盈利增规模”的良性发展周期。</p>\\n<h2><strong>北京车展</strong></h2>\\n<h2><strong>见证中国自动驾驶从“跟随”到“领跑”的质变</strong></h2>\\n<p>2026年北京车展，注定是中国自动驾驶产业发展史上的“里程碑式展会”——它不再是技术的“展示台”，而是商业化落地的“试金石”，是中国智驾<strong>从“技术领先”走向“产业领跑”</strong>的质变节点。</p>\\n<p>对于普通消费者而言，这意味着“花15万就能享50万级智驾体验”，日常通勤将彻底解放双手；对于产业而言，这意味着中国标准、中国方案、中国生态将成为全球标杆。</p>\\n<p>4月24日，北京车展大幕将启。这场智能化量产的终极决战，将见证自动驾驶真正走进千家万户，见证中国自动驾驶产业完成从“跟随者”到“领跑者”的华丽转身。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/lq5DmG43CvSL8EuRDyPf2w\\\">“山自”</a>，作者：Rayking629，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'2026北京车展前瞻：自动驾驶从秀场突围，商业化迎决定性拐点\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'2026北京车展前瞻：自动驾驶从秀场突围，商业化迎决定性拐点\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768944509186569?f=rss\'}], \'link\': \'https://36kr.com/p/3768944509186569?f=rss\', \'published\': \'2026-04-16 11:47:18  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=3, tm_min=47, tm_sec=18, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<blockquote>\\\\n   <p><strong>北京车展在即，自动驾驶5大预测出炉，L3普及、商业化落地成核心看点。</strong></p>\\\\n  </blockquote>\\\\n  <p>2026 年 4 月 24 日，以 “领时代 智未来” 为主题的北京国际车展将拉开帷幕。作为全球智能化量产的分水岭，本届车展不再是概念车的 “秀场”，而是自动驾驶技术与商业化落地的<strong>终极决战场</strong>。基于<strong>政策窗口期、技术成熟度与产业竞争格局</strong>，我们做出<strong>自动驾驶五大大胆预测</strong>，看清未来一年行业的核心走向。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ab8f762ede584905933fdfb3f6064f44@35930_oswg110639oswg1080oswg1539_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <h2><strong>预测一</strong></h2>\\\\n  <h2><strong>L3级自动驾驶规模化落地</strong></h2>\\\\n  <p>2026年，业内已形成共识：这是<strong>L3级自动驾驶从“试点试水”走向“全民普及”的真正元年</strong>，而北京车展将成为这一行业里程碑的集中兑现场。</p>\\\\n  <p>此前国内L3级自动驾驶政策的全面落地，为本次车展的技术爆发奠定了基础——<strong>全国23城开放高速/快速路L3合法路段</strong>，明确事故责任主体（车企主责，仅10秒不接管车主担责），强制搭载智驾“黑匣子”与专项险，这些政策红利将在车展上转化为实实在在的量产成果。</p>\\\\n  <p>从技术落地来看，头部企业的智驾方案将全面下放，彻底打破“高阶智驾=高端车型”的固有认知。华为ADS 5.0、小鹏XNGP 4.0、地平线征程6P三大主流方案，将不再局限于50万级以上豪华车型，而是<strong>全面渗透至20-30万级主流市场，成为该价位段车型的标配</strong>。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_02f762e8ec664daf9df9c6306107f769@35930_oswg453707oswg1080oswg486_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>更值得关注的是，<strong>15万级经济型车型将推出L3级智驾选装包，选装成本控制在1-2万元</strong>，让普通消费者也能享受到高阶智驾的便捷。这种价格下探并非技术妥协，而是源于传感器与芯片成本的规模化摊薄，以及算法效率的持续优化。</p>\\\\n  <p>场景覆盖方面，<strong>高速L3将实现全面普及</strong>，城市快速路与拥堵路段的L3试点将进一步扩容，核心突破点在于“10秒合法接管”机制的落地——驾驶员可短暂脱离视线，无需时刻紧盯路面，真正实现“高速通勤解放双手”。</p>\\\\n  <p>从车企动作来看，问界M9、岚图泰山Ultra等已获得L3准入资质的车型，将在车展现场进行实车演示，直观展示复杂路况下的智驾表现；宝马、奔驰等豪华品牌也将紧跟中国标准，发布基于MB.OS、Momenta方案的L3量产系统，标志着全球车企开始主动适配中国智驾生态。</p>\\\\n  <p>更关键的是，L3级智驾的规模化落地将倒逼产业链协同升级，从智驾芯片、激光雷达到算法软件，整个供应链将进入“量产优化”的良性循环，为后续L4级技术的落地积累数据与经验。</p>\\\\n  <h2><strong>预测二</strong></h2>\\\\n  <h2><strong>国产智驾芯片登顶，成本下探至千元级</strong></h2>\\\\n  <p>芯片是自动驾驶的“心脏”，也是此前中国智驾产业的“卡脖子”环节。而2026北京车展，将正式见证<strong>国产智驾芯片的全面突围</strong>，彻底打破海外企业在高端智驾芯片领域的垄断格局，实现<strong>“算力领先+成本普惠”的双重突破</strong>。</p>\\\\n  <p>技术层面，国产智驾芯片将迎来“算力爆发”。地平线征程6P（560TOPS）、黑芝麻智能华山A2000（7nm工艺）、芯驰X9系列等国产旗舰芯片将集中亮相，其中<strong>黑芝麻智能华山A2000的单芯片算力将突破1000TOPS</strong>，支持Transformer大模型实时推理。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_578f3da1c3c14d0aa6b225c6b8c0aa30@35930_oswg477217oswg1080oswg685_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>这种算力突破并非“盲目堆料”，而是基于国内复杂路况的场景优化，能够更好地适配加塞、鬼探头、无标线道路等中国特色路况，算法响应速度提升30%以上。</p>\\\\n  <p>成本革命将成为本次车展的核心亮点之一。随着国产芯片的规模化量产与技术成熟，激光雷达与智驾芯片的成本将同步下探——<strong>激光雷达单价将从当前的3000-5000元降至千元级</strong>，智驾芯片单车成本将压缩30%，彻底解决此前高阶智驾“硬件成本过高”的痛点。</p>\\\\n  <p>产业绑定方面，国产芯片企业与车企、Tier1供应商的合作将进一步深化，“软硬件解耦”成为行业共识。地平线与采埃孚、黑芝麻与国汽智控、比亚迪与芯驰的合作成果将在车展上集中展示，车企可根据自身需求灵活选择芯片与算法方案。</p>\\\\n  <h2><strong>预测三</strong></h2>\\\\n  <h2><strong>AI大模型全栈上车，端侧融合提效</strong></h2>\\\\n  <p>如果说芯片是自动驾驶的“心脏”，那么AI大模型就是自动驾驶的“大脑”。2026北京车展，将实现<strong>AI大模型从“座舱娱乐”向“智驾核心”的全栈渗透</strong>，技术从“实验室原型”走向“量产车落地”，彻底改变自动驾驶的决策逻辑。</p>\\\\n  <p>技术落地层面，华为、小鹏、轻舟智航等头部企业将集中发布端到端大模型方案，核心突破点在于<strong>“无图化城区NOA”的规模化落地</strong>。不同于传统依赖高精地图的智驾方案，端到端大模型能够通过视觉感知与环境理解，无需高精地图即可适配复杂城区路况，感知准确率提升40%。</p>\\\\n  <p>其中，小鹏XNGP 5.0采用纯视觉路线，依托VLM视觉语言模型+轻传感器，双Orin-X芯片(508TOPS)的硬件配置，成本更低且驾驶风格激进；华为ADS 5.0则主打多传感器融合+无图NOA，<strong>4颗896线激光雷达、13颗摄像头的豪华配置</strong>，让无保护左转成功率达99.5%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_198d5f9db1594c8883f6883aaf5a38cf@35930_oswg470679oswg978oswg534_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>场景贯通方面，高速、城区、泊车全场景打通将成为常态，VLM（世界模型）+强化学习技术将广泛应用。搭载该技术的车辆，能够自主学习中国路况特点，应对加塞、鬼探头等复杂场景，甚至能够根据驾驶员的驾驶习惯调整行驶风格。</p>\\\\n  <p>座舱与智驾的深度融合将成为另一大亮点。车载大模型将实现多轮自然语言交互、语音控全车，能够理解驾驶员的复杂指令，甚至能够预判驾驶员的需求，实现“车控家、家控车”的智能联动。</p>\\\\n  <h2><strong>预测四</strong></h2>\\\\n  <h2><strong>自动驾驶巴士商业化提速，方案出海常态化</strong></h2>\\\\n  <p>自动驾驶巴士作为商业化落地的关键场景，凭借“固定路线、低速行驶、场景封闭”的优势，成为<strong>自动驾驶技术规模化落地的“先行军”</strong>。</p>\\\\n  <p>其中，蘑菇车联MOGOBUS已成为该赛道的最大亮点——依托近期在消博会斩获大奖、登陆新加坡等重磅成果，蘑菇车联将进一步巩固中国自动驾驶巴士的全球领先地位。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1ce238813d8243b08ab39a5cd963492f@35930_oswg110976oswg960oswg640_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>就在北京车展前夕，蘑菇车联MOGOBUS凭借扎实的技术能力和全球化落地成果，在第六届中国国际消费品博览会上，从数百家企业的激烈竞争中脱颖而出，荣获“全球好礼”科技创新奖，成为唯一获此殊荣的中国自动驾驶巴士产品。</p>\\\\n  <p>更关键的是，新一代MOGOBUS已正式登陆新加坡，成为中国自动驾驶公交巴士首次进入发达国家公交骨干网络的标杆项目，标志着蘑菇车联自动驾驶解决方案已获得全球最严苛市场的认可。</p>\\\\n  <p>国内落地方面，MOGOBUS已在中国20余个城市落地运营，为超过20万人次提供智能出行服务，累计行驶里程突破500万公里，曾服务于多项高规格国际活动和大型赛事。近期，蘑菇车联打造的全国首条跨境医疗自动驾驶微循环线路——“琴澳医线”正式开通。</p>\\\\n  <h2><strong>预测五</strong></h2>\\\\n  <h2><strong>商业模式重构，订阅制+保险生态成主流</strong></h2>\\\\n  <p>经历了多年的“烧钱换规模”，2026年自动驾驶行业将正式从“技术驱动”转向“商业驱动”，而北京车展将明确行业可持续盈利的核心路径，单车盈利拐点将正式显现。</p>\\\\n  <p>订阅制将成为智驾服务的主流商业模式。车企与科技公司将推出多元化的智驾订阅服务，按“月/季/年”付费，解锁高速NOA、城区NOA等核心功能，满足不同用户的需求。例如，特斯拉FSD中国版推出月租680元、一次性购买3.2万元的灵活订阅方案。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_442048276afc4a5da68746167874f1b6@35930_oswg445759oswg712oswg403_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>智驾专属保险的全面落地，将进一步降低用户的使用门槛与车企的运营风险。不同于传统车险，智驾专属保险将覆盖系统故障、事故责任等核心风险，保费与驾驶行为、系统数据挂钩，彻底解决用户“不敢用、怕担责”的顾虑。</p>\\\\n  <p>单车盈利拐点将在头部企业率先显现。通过出行服务、数据服务、软件订阅等多元收入，头部企业将实现“硬件成本覆盖+盈利”的目标，行业将彻底告别“烧钱换规模”的野蛮生长阶段，进入“盈利增规模”的良性发展周期。</p>\\\\n  <h2><strong>北京车展</strong></h2>\\\\n  <h2><strong>见证中国自动驾驶从“跟随”到“领跑”的质变</strong></h2>\\\\n  <p>2026年北京车展，注定是中国自动驾驶产业发展史上的“里程碑式展会”——它不再是技术的“展示台”，而是商业化落地的“试金石”，是中国智驾<strong>从“技术领先”走向“产业领跑”</strong>的质变节点。</p>\\\\n  <p>对于普通消费者而言，这意味着“花15万就能享50万级智驾体验”，日常通勤将彻底解放双手；对于产业而言，这意味着中国标准、中国方案、中国生态将成为全球标杆。</p>\\\\n  <p>4月24日，北京车展大幕将启。这场智能化量产的终极决战，将见证自动驾驶真正走进千家万户，见证中国自动驾驶产业完成从“跟随者”到“领跑者”的华丽转身。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/lq5DmG43CvSL8EuRDyPf2w\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“山自”</a>，作者：Rayking629，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<blockquote>\\\\n   <p><strong>北京车展在即，自动驾驶5大预测出炉，L3普及、商业化落地成核心看点。</strong></p>\\\\n  </blockquote>\\\\n  <p>2026 年 4 月 24 日，以 “领时代 智未来” 为主题的北京国际车展将拉开帷幕。作为全球智能化量产的分水岭，本届车展不再是概念车的 “秀场”，而是自动驾驶技术与商业化落地的<strong>终极决战场</strong>。基于<strong>政策窗口期、技术成熟度与产业竞争格局</strong>，我们做出<strong>自动驾驶五大大胆预测</strong>，看清未来一年行业的核心走向。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ab8f762ede584905933fdfb3f6064f44@35930_oswg110639oswg1080oswg1539_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <h2><strong>预测一</strong></h2>\\\\n  <h2><strong>L3级自动驾驶规模化落地</strong></h2>\\\\n  <p>2026年，业内已形成共识：这是<strong>L3级自动驾驶从“试点试水”走向“全民普及”的真正元年</strong>，而北京车展将成为这一行业里程碑的集中兑现场。</p>\\\\n  <p>此前国内L3级自动驾驶政策的全面落地，为本次车展的技术爆发奠定了基础——<strong>全国23城开放高速/快速路L3合法路段</strong>，明确事故责任主体（车企主责，仅10秒不接管车主担责），强制搭载智驾“黑匣子”与专项险，这些政策红利将在车展上转化为实实在在的量产成果。</p>\\\\n  <p>从技术落地来看，头部企业的智驾方案将全面下放，彻底打破“高阶智驾=高端车型”的固有认知。华为ADS 5.0、小鹏XNGP 4.0、地平线征程6P三大主流方案，将不再局限于50万级以上豪华车型，而是<strong>全面渗透至20-30万级主流市场，成为该价位段车型的标配</strong>。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_02f762e8ec664daf9df9c6306107f769@35930_oswg453707oswg1080oswg486_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>更值得关注的是，<strong>15万级经济型车型将推出L3级智驾选装包，选装成本控制在1-2万元</strong>，让普通消费者也能享受到高阶智驾的便捷。这种价格下探并非技术妥协，而是源于传感器与芯片成本的规模化摊薄，以及算法效率的持续优化。</p>\\\\n  <p>场景覆盖方面，<strong>高速L3将实现全面普及</strong>，城市快速路与拥堵路段的L3试点将进一步扩容，核心突破点在于“10秒合法接管”机制的落地——驾驶员可短暂脱离视线，无需时刻紧盯路面，真正实现“高速通勤解放双手”。</p>\\\\n  <p>从车企动作来看，问界M9、岚图泰山Ultra等已获得L3准入资质的车型，将在车展现场进行实车演示，直观展示复杂路况下的智驾表现；宝马、奔驰等豪华品牌也将紧跟中国标准，发布基于MB.OS、Momenta方案的L3量产系统，标志着全球车企开始主动适配中国智驾生态。</p>\\\\n  <p>更关键的是，L3级智驾的规模化落地将倒逼产业链协同升级，从智驾芯片、激光雷达到算法软件，整个供应链将进入“量产优化”的良性循环，为后续L4级技术的落地积累数据与经验。</p>\\\\n  <h2><strong>预测二</strong></h2>\\\\n  <h2><strong>国产智驾芯片登顶，成本下探至千元级</strong></h2>\\\\n  <p>芯片是自动驾驶的“心脏”，也是此前中国智驾产业的“卡脖子”环节。而2026北京车展，将正式见证<strong>国产智驾芯片的全面突围</strong>，彻底打破海外企业在高端智驾芯片领域的垄断格局，实现<strong>“算力领先+成本普惠”的双重突破</strong>。</p>\\\\n  <p>技术层面，国产智驾芯片将迎来“算力爆发”。地平线征程6P（560TOPS）、黑芝麻智能华山A2000（7nm工艺）、芯驰X9系列等国产旗舰芯片将集中亮相，其中<strong>黑芝麻智能华山A2000的单芯片算力将突破1000TOPS</strong>，支持Transformer大模型实时推理。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_578f3da1c3c14d0aa6b225c6b8c0aa30@35930_oswg477217oswg1080oswg685_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>这种算力突破并非“盲目堆料”，而是基于国内复杂路况的场景优化，能够更好地适配加塞、鬼探头、无标线道路等中国特色路况，算法响应速度提升30%以上。</p>\\\\n  <p>成本革命将成为本次车展的核心亮点之一。随着国产芯片的规模化量产与技术成熟，激光雷达与智驾芯片的成本将同步下探——<strong>激光雷达单价将从当前的3000-5000元降至千元级</strong>，智驾芯片单车成本将压缩30%，彻底解决此前高阶智驾“硬件成本过高”的痛点。</p>\\\\n  <p>产业绑定方面，国产芯片企业与车企、Tier1供应商的合作将进一步深化，“软硬件解耦”成为行业共识。地平线与采埃孚、黑芝麻与国汽智控、比亚迪与芯驰的合作成果将在车展上集中展示，车企可根据自身需求灵活选择芯片与算法方案。</p>\\\\n  <h2><strong>预测三</strong></h2>\\\\n  <h2><strong>AI大模型全栈上车，端侧融合提效</strong></h2>\\\\n  <p>如果说芯片是自动驾驶的“心脏”，那么AI大模型就是自动驾驶的“大脑”。2026北京车展，将实现<strong>AI大模型从“座舱娱乐”向“智驾核心”的全栈渗透</strong>，技术从“实验室原型”走向“量产车落地”，彻底改变自动驾驶的决策逻辑。</p>\\\\n  <p>技术落地层面，华为、小鹏、轻舟智航等头部企业将集中发布端到端大模型方案，核心突破点在于<strong>“无图化城区NOA”的规模化落地</strong>。不同于传统依赖高精地图的智驾方案，端到端大模型能够通过视觉感知与环境理解，无需高精地图即可适配复杂城区路况，感知准确率提升40%。</p>\\\\n  <p>其中，小鹏XNGP 5.0采用纯视觉路线，依托VLM视觉语言模型+轻传感器，双Orin-X芯片(508TOPS)的硬件配置，成本更低且驾驶风格激进；华为ADS 5.0则主打多传感器融合+无图NOA，<strong>4颗896线激光雷达、13颗摄像头的豪华配置</strong>，让无保护左转成功率达99.5%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_198d5f9db1594c8883f6883aaf5a38cf@35930_oswg470679oswg978oswg534_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>场景贯通方面，高速、城区、泊车全场景打通将成为常态，VLM（世界模型）+强化学习技术将广泛应用。搭载该技术的车辆，能够自主学习中国路况特点，应对加塞、鬼探头等复杂场景，甚至能够根据驾驶员的驾驶习惯调整行驶风格。</p>\\\\n  <p>座舱与智驾的深度融合将成为另一大亮点。车载大模型将实现多轮自然语言交互、语音控全车，能够理解驾驶员的复杂指令，甚至能够预判驾驶员的需求，实现“车控家、家控车”的智能联动。</p>\\\\n  <h2><strong>预测四</strong></h2>\\\\n  <h2><strong>自动驾驶巴士商业化提速，方案出海常态化</strong></h2>\\\\n  <p>自动驾驶巴士作为商业化落地的关键场景，凭借“固定路线、低速行驶、场景封闭”的优势，成为<strong>自动驾驶技术规模化落地的“先行军”</strong>。</p>\\\\n  <p>其中，蘑菇车联MOGOBUS已成为该赛道的最大亮点——依托近期在消博会斩获大奖、登陆新加坡等重磅成果，蘑菇车联将进一步巩固中国自动驾驶巴士的全球领先地位。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1ce238813d8243b08ab39a5cd963492f@35930_oswg110976oswg960oswg640_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>就在北京车展前夕，蘑菇车联MOGOBUS凭借扎实的技术能力和全球化落地成果，在第六届中国国际消费品博览会上，从数百家企业的激烈竞争中脱颖而出，荣获“全球好礼”科技创新奖，成为唯一获此殊荣的中国自动驾驶巴士产品。</p>\\\\n  <p>更关键的是，新一代MOGOBUS已正式登陆新加坡，成为中国自动驾驶公交巴士首次进入发达国家公交骨干网络的标杆项目，标志着蘑菇车联自动驾驶解决方案已获得全球最严苛市场的认可。</p>\\\\n  <p>国内落地方面，MOGOBUS已在中国20余个城市落地运营，为超过20万人次提供智能出行服务，累计行驶里程突破500万公里，曾服务于多项高规格国际活动和大型赛事。近期，蘑菇车联打造的全国首条跨境医疗自动驾驶微循环线路——“琴澳医线”正式开通。</p>\\\\n  <h2><strong>预测五</strong></h2>\\\\n  <h2><strong>商业模式重构，订阅制+保险生态成主流</strong></h2>\\\\n  <p>经历了多年的“烧钱换规模”，2026年自动驾驶行业将正式从“技术驱动”转向“商业驱动”，而北京车展将明确行业可持续盈利的核心路径，单车盈利拐点将正式显现。</p>\\\\n  <p>订阅制将成为智驾服务的主流商业模式。车企与科技公司将推出多元化的智驾订阅服务，按“月/季/年”付费，解锁高速NOA、城区NOA等核心功能，满足不同用户的需求。例如，特斯拉FSD中国版推出月租680元、一次性购买3.2万元的灵活订阅方案。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_442048276afc4a5da68746167874f1b6@35930_oswg445759oswg712oswg403_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>智驾专属保险的全面落地，将进一步降低用户的使用门槛与车企的运营风险。不同于传统车险，智驾专属保险将覆盖系统故障、事故责任等核心风险，保费与驾驶行为、系统数据挂钩，彻底解决用户“不敢用、怕担责”的顾虑。</p>\\\\n  <p>单车盈利拐点将在头部企业率先显现。通过出行服务、数据服务、软件订阅等多元收入，头部企业将实现“硬件成本覆盖+盈利”的目标，行业将彻底告别“烧钱换规模”的野蛮生长阶段，进入“盈利增规模”的良性发展周期。</p>\\\\n  <h2><strong>北京车展</strong></h2>\\\\n  <h2><strong>见证中国自动驾驶从“跟随”到“领跑”的质变</strong></h2>\\\\n  <p>2026年北京车展，注定是中国自动驾驶产业发展史上的“里程碑式展会”——它不再是技术的“展示台”，而是商业化落地的“试金石”，是中国智驾<strong>从“技术领先”走向“产业领跑”</strong>的质变节点。</p>\\\\n  <p>对于普通消费者而言，这意味着“花15万就能享50万级智驾体验”，日常通勤将彻底解放双手；对于产业而言，这意味着中国标准、中国方案、中国生态将成为全球标杆。</p>\\\\n  <p>4月24日，北京车展大幕将启。这场智能化量产的终极决战，将见证自动驾驶真正走进千家万户，见证中国自动驾驶产业完成从“跟随者”到“领跑者”的华丽转身。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/lq5DmG43CvSL8EuRDyPf2w\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“山自”</a>，作者：Rayking629，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'山自\'}], \'author\': \'山自\', \'author_detail\': {\'name\': \'山自\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'下周北京车展启幕，2026年正式迈入自动驾驶商业化元年。AI 大模型上车、L3 规模化落地、国产芯片突围、自动驾驶巴士出海、订阅制与保险生态成型，技术迭代与商业落地双向提速，智能化量产将迎来终极拐点。\'}]}\", \"published_at\": \"2026-04-16 11:47:18\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 11:47:18', '2026-04-16 13:33:00');
INSERT INTO `news_detail` VALUES (44, 1445, 18, '硬件与半导体出海', '“AI SSD第一股”上市，市值冲上1000亿', '', '<p><strong>大普微企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong></p>\n<p>今日，A股市场“企业级SSD第一股”大普微将正式在深交所创业板挂牌上市。大普微首次公开发行股份数量为4362.1636万股，发行价格为人民币46.08元/股。<strong>上市首日高开403.03%，总市值1012亿元。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_9fcbcd04d1124444b7122579708f130c@5634127_oswg19672oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\"></p>\n<p><strong>大普微此次IPO预计融资18.78亿元</strong>，募集资金将主要用于下一代主控芯片及企业级SSD的研发与产业化、建设量产测试基地，并补充流动资金。此举旨在持续提升公司的技术实力与市场竞争力。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1e6018944ad3458e8ccce94c3c393626@5634127_oswg26375oswg640oswg209_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>大普微<strong>主要从事数据中心企业级SSD产品的研发和销售</strong>，是业内领先、国内极少数具备企业级SSD<strong>“主控芯片+固件算法+模组”</strong>全栈自研能力并实现批量出货的半导体存储产品提供商。</p>\n<p>目前，大普微已实现PCIe3.0至5.0全代际覆盖，构建起SCM SSD、TLC SSD、QLC SSD全谱系矩阵，匹配AI训练、推理等高端场景需求。据招股书披露，大普微已积累<strong>Google、字节跳动、腾讯、百度、三大运营商</strong>等国内外头部客户，2025年更相继通过<strong>NVIDIA、xAI两家全球AI前沿企业的测试导入</strong>，海外拓展进程进一步加速。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_568ec909d25b49deb0a0a9a3830c23b9@5634127_oswg32461oswg640oswg274_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>从财务指标上看，2022年至2024年，大普微分别实现营业收入5.57亿元、5.19亿元、9.62亿元<strong>。2025年，预计实现营业收入22.89亿元（审阅数），同比增长137.94%。</strong></p>\n<p>报告期内，<strong>公司企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong>根据IDC数据，最近三年国内企业级SSD市场中公司占有率稳居市场前列，国际厂商仍占据主导地位。</p>\n<p>对于2026年1-3月业绩，大普微表示，2026年1-3月，<strong>公司预计可实现营业收入约8.50亿元至12.00亿元，同比增幅约为186.18%至304.01%</strong>；公司预计可实现扣除非经常性损益前后归属于母公司所有者的净利润同比增长1<strong>44.44%-164.64%和142.78%-162.58%。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_76b21b80de7f470ca1979e13cb2d882e@5634127_oswg21310oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\"></p>\n<p>2026年1-3月，公司预计营业收入和扣除非经常性损益前后归属于母公司所有者的净利润均大幅增长，<strong>主要原因系受益于AI领域的服务器集群建设进度加速，企业级SSD市场需求快速增长，并显著推升企业级SSD市场价格。</strong>基于销售订单及行业周期上行预期，公司预计2026年1-3月主要产品企业级SSD将呈现量价齐升趋势，收入和利润水平均同比大幅增长。</p>\n<h2><strong>主要产品</strong></h2>\n<p>公司主要产品为数据中心企业级SSD。企业级SSD主要应用于AI、云计算、大数据等数据中心应用场景，消费级SSD广泛应用于电脑、手机、移动硬盘等消费电子场景。与消费级SSD相比，企业级SSD在产品性能、可靠性、耐用性等方面表现更为突出。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_6a582b30ac784e058815ba3945d3f21d@5634127_oswg20130oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\"></p>\n<p>报告期内，大普微企业级SSD产品主要使用自研主控芯片，同时基于国际化需要部分产品也使用Marvell品牌企业级主控芯片；NANDFlash主要使用公司A、铠侠、SK海力士等品牌；DRAM主要使用南亚科技、SK海力士、公司B等品牌。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_07ef383e1c3540c88b902ac04cf8b4eb@5634127_oswg36672oswg640oswg354_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>大普微企业级SSD主要产品包括：PCIe3.0的Haishen3；PCIe4.0的Roealsen5、Jiaorong5；PCIe5.0的Roealsen6，同时，大普微还开发了应用于数据中心网络互联场景的智能网联产品及RAID卡，包括RAID卡、DN200系列万兆以太网智能网卡、DN200C系列Combo（二合一）卡。</p>\n<h2><strong>前五大客户</strong></h2>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_17985f974d5e4b399484a21f05ad7602@5634127_oswg35868oswg640oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>报告期内，大普微对前五大客户销售占比分别为77.90%、53.97%、57.22%和68.40%，不存在向单个客户销售比例超过当期主营业务收入总额50%的情况。</p>\n<h2><strong>存货情况</strong></h2>\n<p>存货方面，报告期各期末，大普微存货账面价值分别为31,801.82万元、23,371.22万元、106,214.03万元和98,381.06万元，主要由原材料和在产品构成。公司根据下游市场需求及主要原材料价格变动趋势管控存货规模。报告期各期末，公司存货跌价准备余额分别为9,489.54万元、14,129.23万元、15,398.65万元和22,738.25万元，公司已根据存货的可变现净值低于成本的金额谨慎计提存货跌价准备。</p>\n<h2><strong>研发情况</strong></h2>\n<p><strong>2022年至2024年，大普微累计研发投入金额为7.3亿元，占累计营业收入36.15%。</strong>截至2025年底，公司仍处于未盈利状态。同时，据大普微披露，公司预计最早于2026年跨越盈亏平衡点，实现整体扭亏为盈。</p>\n<p>截至2025年6月30日，公司已取得国内外发明专利162项，可计算存储（ComputationalStorageDrives）、智能多流（IntelligenceMulti-Stream）、智能故障预测（IntelligentFailurePrediction）等多项企业级SSD技术处于业内领先水平。</p>\n<h2><strong>未来发展战略</strong></h2>\n<p>作为创业板第三套上市标准激活后的首单未盈利企业上市项目，大普微的成功上市的意义，不止是一家企业的资本市场首秀，更是资本市场服务科技型实体企业、服务国家创新战略的实例。</p>\n<p>对于未来的发展战略，大普微表示，公司以推动中国“可计算存储”与“智能存储”产业发展为己任，秉承“为AI时代定义先进存储”的使命愿景，致力于成为具备平台化、国际化、创新化的存储产品及方案提供商。</p>\n<p>大普微将继续围绕着企业级SSD领域的核心技术进行持续研究和创新，不断巩固和提升行业地位及市场知名度，融合企业级SSD主控芯片设计、固件算法开发、模组设计及验证测试四方面的技术研发，<strong>持续输出新一代企业级SSD（含TLCSSD、大容量QLCSSD、SCMSSD、可计算存储SSD等），</strong>丰富数据中心存储产品矩阵。同时，公司还将进一步开发应用于数据中心网络互联场景的网卡、RAID卡等产品，打通下游产业生态链，实现公司产品结构的丰富和延伸。</p>\n<p>本文来自微信公众号“半导体产业纵横”，36氪经授权发布。</p>', 'https://36kr.com/p/3768925640503810?f=rss', 0, '', '{\"summary\": \"本文介绍国内AI存储厂商大普微上市情况，助力出海从业者了解半导体存储企业的海外拓展动态与行业增长趋势\", \"abstract\": \"国内具备全栈自研能力的企业级SSD厂商大普微近日登陆深交所创业板，上市首日总市值突破千亿，IPO融资将用于技术研发与产能扩张。公司产品适配AI训练、推理等高端场景，已积累多个国内外头部客户，近期通过NVIDIA、xAI测试导入，海外拓展进程进一步加速。受益于AI服务器集群建设加速，企业级SSD需求增长，公司业绩高速增长，2026年一季度预计收入利润将大幅提升。大普微计划持续技术创新，目标成为具备国际化能力的存储产品服务商。\", \"keywords\": [\"企业级SSD\", \"半导体存储\", \"AI存储\", \"海外拓展\", \"全栈自研\", \"大普微\", \"IPO\"], \"policy_risk\": {\"market_risk\": \"国内企业级SSD市场中国际厂商仍占据主导地位，公司截至2025年底仍处于未盈利状态\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://36kr.com/p/3768925640503810?f=rss\", \"title\": \"“AI SSD第一股”上市，市值冲上1000亿\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p><strong>大普微企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong></p>\\n<p>今日，A股市场“企业级SSD第一股”大普微将正式在深交所创业板挂牌上市。大普微首次公开发行股份数量为4362.1636万股，发行价格为人民币46.08元/股。<strong>上市首日高开403.03%，总市值1012亿元。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9fcbcd04d1124444b7122579708f130c@5634127_oswg19672oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\"></p>\\n<p><strong>大普微此次IPO预计融资18.78亿元</strong>，募集资金将主要用于下一代主控芯片及企业级SSD的研发与产业化、建设量产测试基地，并补充流动资金。此举旨在持续提升公司的技术实力与市场竞争力。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1e6018944ad3458e8ccce94c3c393626@5634127_oswg26375oswg640oswg209_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>大普微<strong>主要从事数据中心企业级SSD产品的研发和销售</strong>，是业内领先、国内极少数具备企业级SSD<strong>“主控芯片+固件算法+模组”</strong>全栈自研能力并实现批量出货的半导体存储产品提供商。</p>\\n<p>目前，大普微已实现PCIe3.0至5.0全代际覆盖，构建起SCM SSD、TLC SSD、QLC SSD全谱系矩阵，匹配AI训练、推理等高端场景需求。据招股书披露，大普微已积累<strong>Google、字节跳动、腾讯、百度、三大运营商</strong>等国内外头部客户，2025年更相继通过<strong>NVIDIA、xAI两家全球AI前沿企业的测试导入</strong>，海外拓展进程进一步加速。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_568ec909d25b49deb0a0a9a3830c23b9@5634127_oswg32461oswg640oswg274_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>从财务指标上看，2022年至2024年，大普微分别实现营业收入5.57亿元、5.19亿元、9.62亿元<strong>。2025年，预计实现营业收入22.89亿元（审阅数），同比增长137.94%。</strong></p>\\n<p>报告期内，<strong>公司企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong>根据IDC数据，最近三年国内企业级SSD市场中公司占有率稳居市场前列，国际厂商仍占据主导地位。</p>\\n<p>对于2026年1-3月业绩，大普微表示，2026年1-3月，<strong>公司预计可实现营业收入约8.50亿元至12.00亿元，同比增幅约为186.18%至304.01%</strong>；公司预计可实现扣除非经常性损益前后归属于母公司所有者的净利润同比增长1<strong>44.44%-164.64%和142.78%-162.58%。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_76b21b80de7f470ca1979e13cb2d882e@5634127_oswg21310oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\"></p>\\n<p>2026年1-3月，公司预计营业收入和扣除非经常性损益前后归属于母公司所有者的净利润均大幅增长，<strong>主要原因系受益于AI领域的服务器集群建设进度加速，企业级SSD市场需求快速增长，并显著推升企业级SSD市场价格。</strong>基于销售订单及行业周期上行预期，公司预计2026年1-3月主要产品企业级SSD将呈现量价齐升趋势，收入和利润水平均同比大幅增长。</p>\\n<h2><strong>主要产品</strong></h2>\\n<p>公司主要产品为数据中心企业级SSD。企业级SSD主要应用于AI、云计算、大数据等数据中心应用场景，消费级SSD广泛应用于电脑、手机、移动硬盘等消费电子场景。与消费级SSD相比，企业级SSD在产品性能、可靠性、耐用性等方面表现更为突出。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6a582b30ac784e058815ba3945d3f21d@5634127_oswg20130oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\"></p>\\n<p>报告期内，大普微企业级SSD产品主要使用自研主控芯片，同时基于国际化需要部分产品也使用Marvell品牌企业级主控芯片；NANDFlash主要使用公司A、铠侠、SK海力士等品牌；DRAM主要使用南亚科技、SK海力士、公司B等品牌。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_07ef383e1c3540c88b902ac04cf8b4eb@5634127_oswg36672oswg640oswg354_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>大普微企业级SSD主要产品包括：PCIe3.0的Haishen3；PCIe4.0的Roealsen5、Jiaorong5；PCIe5.0的Roealsen6，同时，大普微还开发了应用于数据中心网络互联场景的智能网联产品及RAID卡，包括RAID卡、DN200系列万兆以太网智能网卡、DN200C系列Combo（二合一）卡。</p>\\n<h2><strong>前五大客户</strong></h2>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_17985f974d5e4b399484a21f05ad7602@5634127_oswg35868oswg640oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>报告期内，大普微对前五大客户销售占比分别为77.90%、53.97%、57.22%和68.40%，不存在向单个客户销售比例超过当期主营业务收入总额50%的情况。</p>\\n<h2><strong>存货情况</strong></h2>\\n<p>存货方面，报告期各期末，大普微存货账面价值分别为31,801.82万元、23,371.22万元、106,214.03万元和98,381.06万元，主要由原材料和在产品构成。公司根据下游市场需求及主要原材料价格变动趋势管控存货规模。报告期各期末，公司存货跌价准备余额分别为9,489.54万元、14,129.23万元、15,398.65万元和22,738.25万元，公司已根据存货的可变现净值低于成本的金额谨慎计提存货跌价准备。</p>\\n<h2><strong>研发情况</strong></h2>\\n<p><strong>2022年至2024年，大普微累计研发投入金额为7.3亿元，占累计营业收入36.15%。</strong>截至2025年底，公司仍处于未盈利状态。同时，据大普微披露，公司预计最早于2026年跨越盈亏平衡点，实现整体扭亏为盈。</p>\\n<p>截至2025年6月30日，公司已取得国内外发明专利162项，可计算存储（ComputationalStorageDrives）、智能多流（IntelligenceMulti-Stream）、智能故障预测（IntelligentFailurePrediction）等多项企业级SSD技术处于业内领先水平。</p>\\n<h2><strong>未来发展战略</strong></h2>\\n<p>作为创业板第三套上市标准激活后的首单未盈利企业上市项目，大普微的成功上市的意义，不止是一家企业的资本市场首秀，更是资本市场服务科技型实体企业、服务国家创新战略的实例。</p>\\n<p>对于未来的发展战略，大普微表示，公司以推动中国“可计算存储”与“智能存储”产业发展为己任，秉承“为AI时代定义先进存储”的使命愿景，致力于成为具备平台化、国际化、创新化的存储产品及方案提供商。</p>\\n<p>大普微将继续围绕着企业级SSD领域的核心技术进行持续研究和创新，不断巩固和提升行业地位及市场知名度，融合企业级SSD主控芯片设计、固件算法开发、模组设计及验证测试四方面的技术研发，<strong>持续输出新一代企业级SSD（含TLCSSD、大容量QLCSSD、SCMSSD、可计算存储SSD等），</strong>丰富数据中心存储产品矩阵。同时，公司还将进一步开发应用于数据中心网络互联场景的网卡、RAID卡等产品，打通下游产业生态链，实现公司产品结构的丰富和延伸。</p>\\n<p>本文来自微信公众号“半导体产业纵横”，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'“AI SSD第一股”上市，市值冲上1000亿\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'“AI SSD第一股”上市，市值冲上1000亿\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768925640503810?f=rss\'}], \'link\': \'https://36kr.com/p/3768925640503810?f=rss\', \'published\': \'2026-04-16 11:42:04  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=3, tm_min=42, tm_sec=4, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p><strong>大普微企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong></p>\\\\n  <p>今日，A股市场“企业级SSD第一股”大普微将正式在深交所创业板挂牌上市。大普微首次公开发行股份数量为4362.1636万股，发行价格为人民币46.08元/股。<strong>上市首日高开403.03%，总市值1012亿元。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9fcbcd04d1124444b7122579708f130c@5634127_oswg19672oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\" /></p>\\\\n  <p><strong>大普微此次IPO预计融资18.78亿元</strong>，募集资金将主要用于下一代主控芯片及企业级SSD的研发与产业化、建设量产测试基地，并补充流动资金。此举旨在持续提升公司的技术实力与市场竞争力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1e6018944ad3458e8ccce94c3c393626@5634127_oswg26375oswg640oswg209_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>大普微<strong>主要从事数据中心企业级SSD产品的研发和销售</strong>，是业内领先、国内极少数具备企业级SSD<strong>“主控芯片+固件算法+模组”</strong>全栈自研能力并实现批量出货的半导体存储产品提供商。</p>\\\\n  <p>目前，大普微已实现PCIe3.0至5.0全代际覆盖，构建起SCM SSD、TLC SSD、QLC SSD全谱系矩阵，匹配AI训练、推理等高端场景需求。据招股书披露，大普微已积累<strong>Google、字节跳动、腾讯、百度、三大运营商</strong>等国内外头部客户，2025年更相继通过<strong>NVIDIA、xAI两家全球AI前沿企业的测试导入</strong>，海外拓展进程进一步加速。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_568ec909d25b49deb0a0a9a3830c23b9@5634127_oswg32461oswg640oswg274_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>从财务指标上看，2022年至2024年，大普微分别实现营业收入5.57亿元、5.19亿元、9.62亿元<strong>。2025年，预计实现营业收入22.89亿元（审阅数），同比增长137.94%。</strong></p>\\\\n  <p>报告期内，<strong>公司企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong>根据IDC数据，最近三年国内企业级SSD市场中公司占有率稳居市场前列，国际厂商仍占据主导地位。</p>\\\\n  <p>对于2026年1-3月业绩，大普微表示，2026年1-3月，<strong>公司预计可实现营业收入约8.50亿元至12.00亿元，同比增幅约为186.18%至304.01%</strong>；公司预计可实现扣除非经常性损益前后归属于母公司所有者的净利润同比增长1<strong>44.44%-164.64%和142.78%-162.58%。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_76b21b80de7f470ca1979e13cb2d882e@5634127_oswg21310oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\" /></p>\\\\n  <p>2026年1-3月，公司预计营业收入和扣除非经常性损益前后归属于母公司所有者的净利润均大幅增长，<strong>主要原因系受益于AI领域的服务器集群建设进度加速，企业级SSD市场需求快速增长，并显著推升企业级SSD市场价格。</strong>基于销售订单及行业周期上行预期，公司预计2026年1-3月主要产品企业级SSD将呈现量价齐升趋势，收入和利润水平均同比大幅增长。</p>\\\\n  <h2><strong>主要产品</strong></h2>\\\\n  <p>公司主要产品为数据中心企业级SSD。企业级SSD主要应用于AI、云计算、大数据等数据中心应用场景，消费级SSD广泛应用于电脑、手机、移动硬盘等消费电子场景。与消费级SSD相比，企业级SSD在产品性能、可靠性、耐用性等方面表现更为突出。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6a582b30ac784e058815ba3945d3f21d@5634127_oswg20130oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\" /></p>\\\\n  <p>报告期内，大普微企业级SSD产品主要使用自研主控芯片，同时基于国际化需要部分产品也使用Marvell品牌企业级主控芯片；NANDFlash主要使用公司A、铠侠、SK海力士等品牌；DRAM主要使用南亚科技、SK海力士、公司B等品牌。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_07ef383e1c3540c88b902ac04cf8b4eb@5634127_oswg36672oswg640oswg354_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>大普微企业级SSD主要产品包括：PCIe3.0的Haishen3；PCIe4.0的Roealsen5、Jiaorong5；PCIe5.0的Roealsen6，同时，大普微还开发了应用于数据中心网络互联场景的智能网联产品及RAID卡，包括RAID卡、DN200系列万兆以太网智能网卡、DN200C系列Combo（二合一）卡。</p>\\\\n  <h2><strong>前五大客户</strong></h2>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_17985f974d5e4b399484a21f05ad7602@5634127_oswg35868oswg640oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>报告期内，大普微对前五大客户销售占比分别为77.90%、53.97%、57.22%和68.40%，不存在向单个客户销售比例超过当期主营业务收入总额50%的情况。</p>\\\\n  <h2><strong>存货情况</strong></h2>\\\\n  <p>存货方面，报告期各期末，大普微存货账面价值分别为31,801.82万元、23,371.22万元、106,214.03万元和98,381.06万元，主要由原材料和在产品构成。公司根据下游市场需求及主要原材料价格变动趋势管控存货规模。报告期各期末，公司存货跌价准备余额分别为9,489.54万元、14,129.23万元、15,398.65万元和22,738.25万元，公司已根据存货的可变现净值低于成本的金额谨慎计提存货跌价准备。</p>\\\\n  <h2><strong>研发情况</strong></h2>\\\\n  <p><strong>2022年至2024年，大普微累计研发投入金额为7.3亿元，占累计营业收入36.15%。</strong>截至2025年底，公司仍处于未盈利状态。同时，据大普微披露，公司预计最早于2026年跨越盈亏平衡点，实现整体扭亏为盈。</p>\\\\n  <p>截至2025年6月30日，公司已取得国内外发明专利162项，可计算存储（ComputationalStorageDrives）、智能多流（IntelligenceMulti-Stream）、智能故障预测（IntelligentFailurePrediction）等多项企业级SSD技术处于业内领先水平。</p>\\\\n  <h2><strong>未来发展战略</strong></h2>\\\\n  <p>作为创业板第三套上市标准激活后的首单未盈利企业上市项目，大普微的成功上市的意义，不止是一家企业的资本市场首秀，更是资本市场服务科技型实体企业、服务国家创新战略的实例。</p>\\\\n  <p>对于未来的发展战略，大普微表示，公司以推动中国“可计算存储”与“智能存储”产业发展为己任，秉承“为AI时代定义先进存储”的使命愿景，致力于成为具备平台化、国际化、创新化的存储产品及方案提供商。</p>\\\\n  <p>大普微将继续围绕着企业级SSD领域的核心技术进行持续研究和创新，不断巩固和提升行业地位及市场知名度，融合企业级SSD主控芯片设计、固件算法开发、模组设计及验证测试四方面的技术研发，<strong>持续输出新一代企业级SSD（含TLCSSD、大容量QLCSSD、SCMSSD、可计算存储SSD等），</strong>丰富数据中心存储产品矩阵。同时，公司还将进一步开发应用于数据中心网络互联场景的网卡、RAID卡等产品，打通下游产业生态链，实现公司产品结构的丰富和延伸。</p>\\\\n  <p>本文来自微信公众号“半导体产业纵横”，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p><strong>大普微企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong></p>\\\\n  <p>今日，A股市场“企业级SSD第一股”大普微将正式在深交所创业板挂牌上市。大普微首次公开发行股份数量为4362.1636万股，发行价格为人民币46.08元/股。<strong>上市首日高开403.03%，总市值1012亿元。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9fcbcd04d1124444b7122579708f130c@5634127_oswg19672oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\" /></p>\\\\n  <p><strong>大普微此次IPO预计融资18.78亿元</strong>，募集资金将主要用于下一代主控芯片及企业级SSD的研发与产业化、建设量产测试基地，并补充流动资金。此举旨在持续提升公司的技术实力与市场竞争力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1e6018944ad3458e8ccce94c3c393626@5634127_oswg26375oswg640oswg209_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>大普微<strong>主要从事数据中心企业级SSD产品的研发和销售</strong>，是业内领先、国内极少数具备企业级SSD<strong>“主控芯片+固件算法+模组”</strong>全栈自研能力并实现批量出货的半导体存储产品提供商。</p>\\\\n  <p>目前，大普微已实现PCIe3.0至5.0全代际覆盖，构建起SCM SSD、TLC SSD、QLC SSD全谱系矩阵，匹配AI训练、推理等高端场景需求。据招股书披露，大普微已积累<strong>Google、字节跳动、腾讯、百度、三大运营商</strong>等国内外头部客户，2025年更相继通过<strong>NVIDIA、xAI两家全球AI前沿企业的测试导入</strong>，海外拓展进程进一步加速。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_568ec909d25b49deb0a0a9a3830c23b9@5634127_oswg32461oswg640oswg274_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>从财务指标上看，2022年至2024年，大普微分别实现营业收入5.57亿元、5.19亿元、9.62亿元<strong>。2025年，预计实现营业收入22.89亿元（审阅数），同比增长137.94%。</strong></p>\\\\n  <p>报告期内，<strong>公司企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。</strong>根据IDC数据，最近三年国内企业级SSD市场中公司占有率稳居市场前列，国际厂商仍占据主导地位。</p>\\\\n  <p>对于2026年1-3月业绩，大普微表示，2026年1-3月，<strong>公司预计可实现营业收入约8.50亿元至12.00亿元，同比增幅约为186.18%至304.01%</strong>；公司预计可实现扣除非经常性损益前后归属于母公司所有者的净利润同比增长1<strong>44.44%-164.64%和142.78%-162.58%。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_76b21b80de7f470ca1979e13cb2d882e@5634127_oswg21310oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\" /></p>\\\\n  <p>2026年1-3月，公司预计营业收入和扣除非经常性损益前后归属于母公司所有者的净利润均大幅增长，<strong>主要原因系受益于AI领域的服务器集群建设进度加速，企业级SSD市场需求快速增长，并显著推升企业级SSD市场价格。</strong>基于销售订单及行业周期上行预期，公司预计2026年1-3月主要产品企业级SSD将呈现量价齐升趋势，收入和利润水平均同比大幅增长。</p>\\\\n  <h2><strong>主要产品</strong></h2>\\\\n  <p>公司主要产品为数据中心企业级SSD。企业级SSD主要应用于AI、云计算、大数据等数据中心应用场景，消费级SSD广泛应用于电脑、手机、移动硬盘等消费电子场景。与消费级SSD相比，企业级SSD在产品性能、可靠性、耐用性等方面表现更为突出。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6a582b30ac784e058815ba3945d3f21d@5634127_oswg20130oswg430oswg430_img_000?x-oss-process=image/format,jpg/format,jpg/interlace,1\\\" /></p>\\\\n  <p>报告期内，大普微企业级SSD产品主要使用自研主控芯片，同时基于国际化需要部分产品也使用Marvell品牌企业级主控芯片；NANDFlash主要使用公司A、铠侠、SK海力士等品牌；DRAM主要使用南亚科技、SK海力士、公司B等品牌。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_07ef383e1c3540c88b902ac04cf8b4eb@5634127_oswg36672oswg640oswg354_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>大普微企业级SSD主要产品包括：PCIe3.0的Haishen3；PCIe4.0的Roealsen5、Jiaorong5；PCIe5.0的Roealsen6，同时，大普微还开发了应用于数据中心网络互联场景的智能网联产品及RAID卡，包括RAID卡、DN200系列万兆以太网智能网卡、DN200C系列Combo（二合一）卡。</p>\\\\n  <h2><strong>前五大客户</strong></h2>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_17985f974d5e4b399484a21f05ad7602@5634127_oswg35868oswg640oswg395_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>报告期内，大普微对前五大客户销售占比分别为77.90%、53.97%、57.22%和68.40%，不存在向单个客户销售比例超过当期主营业务收入总额50%的情况。</p>\\\\n  <h2><strong>存货情况</strong></h2>\\\\n  <p>存货方面，报告期各期末，大普微存货账面价值分别为31,801.82万元、23,371.22万元、106,214.03万元和98,381.06万元，主要由原材料和在产品构成。公司根据下游市场需求及主要原材料价格变动趋势管控存货规模。报告期各期末，公司存货跌价准备余额分别为9,489.54万元、14,129.23万元、15,398.65万元和22,738.25万元，公司已根据存货的可变现净值低于成本的金额谨慎计提存货跌价准备。</p>\\\\n  <h2><strong>研发情况</strong></h2>\\\\n  <p><strong>2022年至2024年，大普微累计研发投入金额为7.3亿元，占累计营业收入36.15%。</strong>截至2025年底，公司仍处于未盈利状态。同时，据大普微披露，公司预计最早于2026年跨越盈亏平衡点，实现整体扭亏为盈。</p>\\\\n  <p>截至2025年6月30日，公司已取得国内外发明专利162项，可计算存储（ComputationalStorageDrives）、智能多流（IntelligenceMulti-Stream）、智能故障预测（IntelligentFailurePrediction）等多项企业级SSD技术处于业内领先水平。</p>\\\\n  <h2><strong>未来发展战略</strong></h2>\\\\n  <p>作为创业板第三套上市标准激活后的首单未盈利企业上市项目，大普微的成功上市的意义，不止是一家企业的资本市场首秀，更是资本市场服务科技型实体企业、服务国家创新战略的实例。</p>\\\\n  <p>对于未来的发展战略，大普微表示，公司以推动中国“可计算存储”与“智能存储”产业发展为己任，秉承“为AI时代定义先进存储”的使命愿景，致力于成为具备平台化、国际化、创新化的存储产品及方案提供商。</p>\\\\n  <p>大普微将继续围绕着企业级SSD领域的核心技术进行持续研究和创新，不断巩固和提升行业地位及市场知名度，融合企业级SSD主控芯片设计、固件算法开发、模组设计及验证测试四方面的技术研发，<strong>持续输出新一代企业级SSD（含TLCSSD、大容量QLCSSD、SCMSSD、可计算存储SSD等），</strong>丰富数据中心存储产品矩阵。同时，公司还将进一步开发应用于数据中心网络互联场景的网卡、RAID卡等产品，打通下游产业生态链，实现公司产品结构的丰富和延伸。</p>\\\\n  <p>本文来自微信公众号“半导体产业纵横”，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'半导体产业纵横\'}], \'author\': \'半导体产业纵横\', \'author_detail\': {\'name\': \'半导体产业纵横\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'大普微企业级SSD累计出货量达4,900PB以上，其中搭载自研主控芯片的出货比例达75%以上。\'}]}\", \"published_at\": \"2026-04-16 11:42:04\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 11:42:04', '2026-04-16 13:34:06');
INSERT INTO `news_detail` VALUES (45, 1446, 8, '新能源与汽车', '高瓴坐镇，1400亿IPO敲钟了', '', '<p>港交所震撼一幕。</p>\n<p>今日（4月16日），思格新能源正式登陆港交所，成为“AI储能第一股”。此次IPO发行价为324.2港元，开盘大涨近80%，市值破1400亿港元，这在港股历史上并不多见。</p>\n<p>当中，公司在招股阶段获1102倍超额认购。身后基石投资阵容豪华，累计认购约2.8亿美元，涵盖淡马锡、高盛资产管理、高瓴、瑞银、法国巴黎银行、CPE源峰、博裕资本、景林资产、富国基金、中国太保、正大机器人有限公司、工银理财等国内外顶级机构。</p>\n<p>在高瓴创始合伙人李良看来，思格新能源掌舵人许映童是典型的「产业牛人」。2022年，这位产业界元老带队创立思格新能源，从一开始就走那条难而正确的路，专注于用AI重新定义储能。期间，高瓴从天使轮开始押注两轮，成为思格新能源最大外部投资方。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_6799aa6226684beebcf21dd605857ee0@000000_oswg76467oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>思格新能源创始人、董事长兼CEO许映童（左）与高瓴创始合伙人李良（右）</p>\n<p>如此，从成立到IPO不足4年时间，中国企业港股IPO最快纪录再次被刷新了。</p>\n<h2><strong>今天，产业大牛敲钟</strong></h2>\n<h2><strong>高瓴重仓</strong></h2>\n<p>思格新能源的诞生，离不开灵魂人物——许映童。</p>\n<p>这个名字对圈外或许有些陌生，但在光伏圈内却是赫赫有名：23年产业生涯，亲手开创华为智能光伏业务，带领团队从零做到全球第一。1974年出生，许映童毕业于南京理工大学，1999年入行，从无线通信、智能光伏干到昇腾AI计算，几乎完整见证了中国能源产业的崛起历程。</p>\n<p>后来，许映童离开大厂，酝酿开启创业之路。那是2022上半年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间；但对真正看得懂产业趋势的人来说，越是在信心低谷，越能看出长期机会的价值。</p>\n<p>高瓴最早就找到了许映童。彼时对于未来创业方向，许映童其实有多条路的选择。高瓴团队和他一直保持密切的交流。双方讨论的重点，并不是一个短期热门机会，而是：在全球能源格局重构的大背景下，什么样的方向最能够承接团队过去积累的产业能力，什么样的战场最值得长期投入。</p>\n<p>最终，双方形成高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。许映童也很认同这一判断。</p>\n<p>2022年6月，思格新能源正式成立，高瓴第一时间领投了天使轮。当时团队并不大，却自带浓厚的“铁军”基因——总裁张先淼，智能光伏前副总裁，17年光伏行业经验；核心高管均为产业背景，浸泡在光伏储能领域10年以上。</p>\n<p>然而挑战很快出现。虽然许映童身为产业老兵，但创业公司的现实是：作为新入局者，思格新能源仍须应对供应链短缺的重大挑战，早期最现实的问题往往是能不能顺利把产品做出来、交出去。</p>\n<p>尤其在锂电、功率器件等核心部件上，早期创业公司常常会面对价格高、拿货难，优质产能几乎被头部企业优先锁定的问题。对一家刚成立的创业公司而言，这不是成本问题，而是会直接影响产品迭代、交付节奏、客户信任和公司生存的关键问题。</p>\n<p>高瓴没有停留在“给钱”的层面，而是主动把多年积累的生态内的核心产业资源开放给思格：比如在电池侧，对接宁德时代，帮助思格在产能最紧缺的时期获得稳定、优质的锂电供应，缓解了BOM成本压力和交付风险；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供，为产品的一致性与可靠性打下基础。</p>\n<p>潮水总是快得令人意想不到——2022年思格新能源决定全力押注一体机时，全球储能市场对此的需求还不到30%；首创的一体机上市后，95%以上的需求都转向了光储一体。据弗若斯特沙利文报告，按产品出货量计，2024年思格新能源已成为全球排名第一的可堆叠分布式光储一体机解决方案提供商。</p>\n<p>亲历这一幕，高瓴创始合伙人李良颇为感慨：“在全球能源结构转型的实业浪潮中，思格新能源扎扎实实地从底层研发和供应链做起。创始人许映童带领的团队，展现了中国顶尖制造业老兵深厚的系统工程能力和极强的全球化落地执行力。”</p>\n<h2><strong>在最不确定的时候站在一起</strong></h2>\n<h2><strong>投资人迎来超级回报</strong></h2>\n<p>如今回头来看，这是一场难得的双向奔赴。</p>\n<p>回想四年前，俄乌战争爆发、市场剧烈波动，宏观环境带来的不确定性仍然存在。那时候高瓴的出手，并非源自短期市场情绪，而是对思格新能源团队能力和产业方向的坚定判断。</p>\n<p>当中有一段插曲：在思格新能源后续融资阶段，行业一度不被看好，市场情绪十分低迷。但高瓴并没有因为周期波动而动摇，而是继续坚定支持公司发展，不仅连投两轮，而且协助其引入了产业方和财务投资人，完成多轮关键融资。</p>\n<p>背后的逻辑很朴素：在全球能源结构转型的浪潮下，从底层研发和供应链出发的思格新能源，具备能够把复杂产品和组织真正做出来的品质。</p>\n<p>创业路上，最难的是在不确定的时刻依然有人坚定地选择相信你。许映童这样的产业老兵，选择投资人的逻辑很朴素：不看热闹，而是要懂行。</p>\n<p>“高瓴懂我们的语言，也理解我们想做成的事。这种超越资本的陪伴，让我们敢于从一开始就走那条难而正确的路。”许映童表示。</p>\n<p>如今翻开招股书，思格新能源成长惊人——公司营收在2023年还是5830万元，2024年就来到了13.3亿元，去年这个数字是90亿元，两年时间翻了150倍多；盈利层面，2024年扭亏为盈，实现净利润8385万元，2025年达到29.19亿，毛利率从2023年的31.3%提升至最新的50.1%，收入和利润双双飙升。</p>\n<p>由此，缔造中国新能源一个增长神话。</p>\n<p>一路崛起，思格新能源身后浮现一支投资人队伍：高瓴、华登国际、云晖资本、钟鼎资本、天堂硅谷、国科东方、国核投资等。招股书显示，全球发售后高瓴仍通过珠海玫恒持股14.08%，为最大外部投资方，总投资金额约人民币3亿元，账面持股市值约200亿港元。</p>\n<p>说起来，华登亦是自早期便坚定重仓思格新能源；天堂硅谷则在40亿估值时出手；钟鼎决定投资思格，是看中了公司团队对“能源互联网”底层逻辑的深刻洞察。硬科技浪潮席卷，坚守的人都收获时间的回报。</p>\n<h2><strong>千亿市值</strong></h2>\n<p>首日市值破千亿港元，思格新能源创造了历史。透过其身后，我们再次看到AI的威力——储能的天花板，被AI打开了。</p>\n<p>上个月，黄仁勋在分享中将AI生态比作一块五层蛋糕：顶层是应用，其次是模型、基础设施、芯片，而最底层正是能源。所谓AI的尽头是能源，归根结底是能源成本的竞争。</p>\n<p>行业的变化已摆在眼前。瑞银报告���出，2026年全球储能需求有望同比增长40%。在AI电力需求空前上升的推动下，储能产业正迈入新一轮繁荣周期。仅在美国，预计2025年至2027年太阳能与储能系统将贡献75%至80%的新增电力装机容量。</p>\n<p>这意味着，AI带来的电力焦虑，正将储能从过去电力系统的配角，推向新一轮基础设施建设的前排。而ResearchAndMarkets报告显示，到2030年，仅AI数据中心直接配套的储能市场，保守看已是数十亿美元规模；若把AI驱动的整条电力系统升级算进去，储能的想象空间显然远不止于此。</p>\n<p>但风口并不会平均落到每一家公司头上。AI带来的，不只是更多储能需求，也在重写这个行业的能力门槛：真正被需要的，是围绕稳定性、调度效率、系统灵活性和场景适配展开的整体能力。</p>\n<p>这正是思格新能源见长的地方。无论是家庭户用、工商业，还是地面电站，背后考验的都不只是单一设备，而是系统稳定性、部署效率、安全性与场景适配能力的整体水平。尤其在思格新能源主打的AI储能，相比传统储能解决电量问题，AI储能解决的是“这度电何时使用能释放更大价值”。</p>\n<p>如此，高瓴们对思格新能源的押注也就不难理解了。所看中的，是一支长期在产业中历练、能把复杂产品真正落地的团队，恰好站上了被时代放大的机会。风口提供了加速度，真正决定上限的，仍是团队本身。</p>\n<p>“对许映童这样的产业创业者而言，投资人的价值首先在于理解。听得懂产业语言，理解制造业创业的难处，并能在关键时刻提供长期支持，远比资金本身更重要。”高瓴创始合伙人李良向投资界强调，这种产业能力与时代窗口之间的精准契合，最为稀缺。</p>\n<p>风口轮转，周期起伏。</p>\n<p>很多时候，所谓高光，不过是时间终于看见了那些长期埋头向前的人。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s?__biz=MzI5ODk1NjY1MA==&amp;mid=2247720766&amp;idx=1&amp;sn=e4f403fcfe32b54cbcc0885ada005561&amp;chksm=edbaf20987abc0fd03c89b5a23754ba195c172ed193db7eb6416a4a8c11d17ab29768009f69e&amp;scene=0&amp;xtrack=1#rd\">“投资界”（ID：pedaily2012）</a>，作者：余梦莹 王露，36氪经授权发布。</p>', 'https://36kr.com/p/3768933931647744?f=rss', 0, '', '{\"summary\": \"本文介绍AI储能企业思格新能源不足4年登陆港交所完成千亿市值IPO的历程，为新能源出海企业洞察全球储能产业机遇提供参考\", \"abstract\": \"由前华为智能光伏业务创始人许映童2022年创立的思格新能源，专注AI储能赛道，获得高瓴等顶级机构从天使轮开始的持续投资，高瓴还开放生态资源帮助企业解决早期供应链短缺问题。思格新能源成长迅速，两年营收增长超150倍，于4月16日登陆港交所，开盘大涨后市值突破1400亿港元，成为“AI储能第一股”，刷新了中国企业港股IPO最快纪录。随着AI产业发展带动全球能源需求增长，全球储能产业迎来新一轮繁荣周期，AI打开了储能行业的增长天花板，具备核心产业能力的出海玩家将获得更大发展空间\", \"keywords\": [\"AI储能\", \"储能\", \"思格新能源\", \"港股IPO\", \"高瓴\", \"全球能源转型\", \"光储一体机\", \"新能源出海\"], \"policy_risk\": {\"market_risk\": \"新能源储能创业企业早期面临锂电、功率器件等核心部件供应链短缺，优质产能被头部企业锁定，存在拿货难、成本高的问题，会直接影响产品交付与企业生存；行业周期波动中会出现市场信心不足、融资受阻的风险\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3768933931647744?f=rss\", \"title\": \"高瓴坐镇，1400亿IPO敲钟了\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>港交所震撼一幕。</p>\\n<p>今日（4月16日），思格新能源正式登陆港交所，成为“AI储能第一股”。此次IPO发行价为324.2港元，开盘大涨近80%，市值破1400亿港元，这在港股历史上并不多见。</p>\\n<p>当中，公司在招股阶段获1102倍超额认购。身后基石投资阵容豪华，累计认购约2.8亿美元，涵盖淡马锡、高盛资产管理、高瓴、瑞银、法国巴黎银行、CPE源峰、博裕资本、景林资产、富国基金、中国太保、正大机器人有限公司、工银理财等国内外顶级机构。</p>\\n<p>在高瓴创始合伙人李良看来，思格新能源掌舵人许映童是典型的「产业牛人」。2022年，这位产业界元老带队创立思格新能源，从一开始就走那条难而正确的路，专注于用AI重新定义储能。期间，高瓴从天使轮开始押注两轮，成为思格新能源最大外部投资方。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6799aa6226684beebcf21dd605857ee0@000000_oswg76467oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>思格新能源创始人、董事长兼CEO许映童（左）与高瓴创始合伙人李良（右）</p>\\n<p>如此，从成立到IPO不足4年时间，中国企业港股IPO最快纪录再次被刷新了。</p>\\n<h2><strong>今天，产业大牛敲钟</strong></h2>\\n<h2><strong>高瓴重仓</strong></h2>\\n<p>思格新能源的诞生，离不开灵魂人物——许映童。</p>\\n<p>这个名字对圈外或许有些陌生，但在光伏圈内却是赫赫有名：23年产业生涯，亲手开创华为智能光伏业务，带领团队从零做到全球第一。1974年出生，许映童毕业于南京理工大学，1999年入行，从无线通信、智能光伏干到昇腾AI计算，几乎完整见证了中国能源产业的崛起历程。</p>\\n<p>后来，许映童离开大厂，酝酿开启创业之路。那是2022上半年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间；但对真正看得懂产业趋势的人来说，越是在信心低谷，越能看出长期机会的价值。</p>\\n<p>高瓴最早就找到了许映童。彼时对于未来创业方向，许映童其实有多条路的选择。高瓴团队和他一直保持密切的交流。双方讨论的重点，并不是一个短期热门机会，而是：在全球能源格局重构的大背景下，什么样的方向最能够承接团队过去积累的产业能力，什么样的战场最值得长期投入。</p>\\n<p>最终，双方形成高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。许映童也很认同这一判断。</p>\\n<p>2022年6月，思格新能源正式成立，高瓴第一时间领投了天使轮。当时团队并不大，却自带浓厚的“铁军”基因——总裁张先淼，智能光伏前副总裁，17年光伏行业经验；核心高管均为产业背景，浸泡在光伏储能领域10年以上。</p>\\n<p>然而挑战很快出现。虽然许映童身为产业老兵，但创业公司的现实是：作为新入局者，思格新能源仍须应对供应链短缺的重大挑战，早期最现实的问题往往是能不能顺利把产品做出来、交出去。</p>\\n<p>尤其在锂电、功率器件等核心部件上，早期创业公司常常会面对价格高、拿货难，优质产能几乎被头部企业优先锁定的问题。对一家刚成立的创业公司而言，这不是成本问题，而是会直接影响产品迭代、交付节奏、客户信任和公司生存的关键问题。</p>\\n<p>高瓴没有停留在“给钱”的层面，而是主动把多年积累的生态内的核心产业资源开放给思格：比如在电池侧，对接宁德时代，帮助思格在产能最紧缺的时期获得稳定、优质的锂电供应，缓解了BOM成本压力和交付风险；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供，为产品的一致性与可靠性打下基础。</p>\\n<p>潮水总是快得令人意想不到——2022年思格新能源决定全力押注一体机时，全球储能市场对此的需求还不到30%；首创的一体机上市后，95%以上的需求都转向了光储一体。据弗若斯特沙利文报告，按产品出货量计，2024年思格新能源已成为全球排名第一的可堆叠分布式光储一体机解决方案提供商。</p>\\n<p>亲历这一幕，高瓴创始合伙人李良颇为感慨：“在全球能源结构转型的实业浪潮中，思格新能源扎扎实实地从底层研发和供应链做起。创始人许映童带领的团队，展现了中国顶尖制造业老兵深厚的系统工程能力和极强的全球化落地执行力。”</p>\\n<h2><strong>在最不确定的时候站在一起</strong></h2>\\n<h2><strong>投资人迎来超级回报</strong></h2>\\n<p>如今回头来看，这是一场难得的双向奔赴。</p>\\n<p>回想四年前，俄乌战争爆发、市场剧烈波动，宏观环境带来的不确定性仍然存在。那时候高瓴的出手，并非源自短期市场情绪，而是对思格新能源团队能力和产业方向的坚定判断。</p>\\n<p>当中有一段插曲：在思格新能源后续融资阶段，行业一度不被看好，市场情绪十分低迷。但高瓴并没有因为周期波动而动摇，而是继续坚定支持公司发展，不仅连投两轮，而且协助其引入了产业方和财务投资人，完成多轮关键融资。</p>\\n<p>背后的逻辑很朴素：在全球能源结构转型的浪潮下，从底层研发和供应链出发的思格新能源，具备能够把复杂产品和组织真正做出来的品质。</p>\\n<p>创业路上，最难的是在不确定的时刻依然有人坚定地选择相信你。许映童这样的产业老兵，选择投资人的逻辑很朴素：不看热闹，而是要懂行。</p>\\n<p>“高瓴懂我们的语言，也理解我们想做成的事。这种超越资本的陪伴，让我们敢于从一开始就走那条难而正确的路。”许映童表示。</p>\\n<p>如今翻开招股书，思格新能源成长惊人——公司营收在2023年还是5830万元，2024年就来到了13.3亿元，去年这个数字是90亿元，两年时间翻了150倍多；盈利层面，2024年扭亏为盈，实现净利润8385万元，2025年达到29.19亿，毛利率从2023年的31.3%提升至最新的50.1%，收入和利润双双飙升。</p>\\n<p>由此，缔造中国新能源一个增长神话。</p>\\n<p>一路崛起，思格新能源身后浮现一支投资人队伍：高瓴、华登国际、云晖资本、钟鼎资本、天堂硅谷、国科东方、国核投资等。招股书显示，全球发售后高瓴仍通过珠海玫恒持股14.08%，为最大外部投资方，总投资金额约人民币3亿元，账面持股市值约200亿港元。</p>\\n<p>说起来，华登亦是自早期便坚定重仓思格新能源；天堂硅谷则在40亿估值时出手；钟鼎决定投资思格，是看中了公司团队对“能源互联网”底层逻辑的深刻洞察。硬科技浪潮席卷，坚守的人都收获时间的回报。</p>\\n<h2><strong>千亿市值</strong></h2>\\n<p>首日市值破千亿港元，思格新能源创造了历史。透过其身后，我们再次看到AI的威力——储能的天花板，被AI打开了。</p>\\n<p>上个月，黄仁勋在分享中将AI生态比作一块五层蛋糕：顶层是应用，其次是模型、基础设施、芯片，而最底层正是能源。所谓AI的尽头是能源，归根结底是能源成本的竞争。</p>\\n<p>行业的变化已摆在眼前。瑞银报告���出，2026年全球储能需求有望同比增长40%。在AI电力需求空前上升的推动下，储能产业正迈入新一轮繁荣周期。仅在美国，预计2025年至2027年太阳能与储能系统将贡献75%至80%的新增电力装机容量。</p>\\n<p>这意味着，AI带来的电力焦虑，正将储能从过去电力系统的配角，推向新一轮基础设施建设的前排。而ResearchAndMarkets报告显示，到2030年，仅AI数据中心直接配套的储能市场，保守看已是数十亿美元规模；若把AI驱动的整条电力系统升级算进去，储能的想象空间显然远不止于此。</p>\\n<p>但风口并不会平均落到每一家公司头上。AI带来的，不只是更多储能需求，也在重写这个行业的能力门槛：真正被需要的，是围绕稳定性、调度效率、系统灵活性和场景适配展开的整体能力。</p>\\n<p>这正是思格新能源见长的地方。无论是家庭户用、工商业，还是地面电站，背后考验的都不只是单一设备，而是系统稳定性、部署效率、安全性与场景适配能力的整体水平。尤其在思格新能源主打的AI储能，相比传统储能解决电量问题，AI储能解决的是“这度电何时使用能释放更大价值”。</p>\\n<p>如此，高瓴们对思格新能源的押注也就不难理解了。所看中的，是一支长期在产业中历练、能把复杂产品真正落地的团队，恰好站上了被时代放大的机会。风口提供了加速度，真正决定上限的，仍是团队本身。</p>\\n<p>“对许映童这样的产业创业者而言，投资人的价值首先在于理解。听得懂产业语言，理解制造业创业的难处，并能在关键时刻提供长期支持，远比资金本身更重要。”高瓴创始合伙人李良向投资界强调，这种产业能力与时代窗口之间的精准契合，最为稀缺。</p>\\n<p>风口轮转，周期起伏。</p>\\n<p>很多时候，所谓高光，不过是时间终于看见了那些长期埋头向前的人。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI5ODk1NjY1MA==&amp;mid=2247720766&amp;idx=1&amp;sn=e4f403fcfe32b54cbcc0885ada005561&amp;chksm=edbaf20987abc0fd03c89b5a23754ba195c172ed193db7eb6416a4a8c11d17ab29768009f69e&amp;scene=0&amp;xtrack=1#rd\\\">“投资界”（ID：pedaily2012）</a>，作者：余梦莹 王露，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'高瓴坐镇，1400亿IPO敲钟了\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'高瓴坐镇，1400亿IPO敲钟了\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768933931647744?f=rss\'}], \'link\': \'https://36kr.com/p/3768933931647744?f=rss\', \'published\': \'2026-04-16 11:39:56  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=3, tm_min=39, tm_sec=56, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>港交所震撼一幕。</p>\\\\n  <p>今日（4月16日），思格新能源正式登陆港交所，成为“AI储能第一股”。此次IPO发行价为324.2港元，开盘大涨近80%，市值破1400亿港元，这在港股历史上并不多见。</p>\\\\n  <p>当中，公司在招股阶段获1102倍超额认购。身后基石投资阵容豪华，累计认购约2.8亿美元，涵盖淡马锡、高盛资产管理、高瓴、瑞银、法国巴黎银行、CPE源峰、博裕资本、景林资产、富国基金、中国太保、正大机器人有限公司、工银理财等国内外顶级机构。</p>\\\\n  <p>在高瓴创始合伙人李良看来，思格新能源掌舵人许映童是典型的「产业牛人」。2022年，这位产业界元老带队创立思格新能源，从一开始就走那条难而正确的路，专注于用AI重新定义储能。期间，高瓴从天使轮开始押注两轮，成为思格新能源最大外部投资方。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6799aa6226684beebcf21dd605857ee0@000000_oswg76467oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">思格新能源创始人、董事长兼CEO许映童（左）与高瓴创始合伙人李良（右）</p>\\\\n  <p>如此，从成立到IPO不足4年时间，中国企业港股IPO最快纪录再次被刷新了。</p>\\\\n  <h2><strong>今天，产业大牛敲钟</strong></h2>\\\\n  <h2><strong>高瓴重仓</strong></h2>\\\\n  <p>思格新能源的诞生，离不开灵魂人物——许映童。</p>\\\\n  <p>这个名字对圈外或许有些陌生，但在光伏圈内却是赫赫有名：23年产业生涯，亲手开创华为智能光伏业务，带领团队从零做到全球第一。1974年出生，许映童毕业于南京理工大学，1999年入行，从无线通信、智能光伏干到昇腾AI计算，几乎完整见证了中国能源产业的崛起历程。</p>\\\\n  <p>后来，许映童离开大厂，酝酿开启创业之路。那是2022上半年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间；但对真正看得懂产业趋势的人来说，越是在信心低谷，越能看出长期机会的价值。</p>\\\\n  <p>高瓴最早就找到了许映童。彼时对于未来创业方向，许映童其实有多条路的选择。高瓴团队和他一直保持密切的交流。双方讨论的重点，并不是一个短期热门机会，而是：在全球能源格局重构的大背景下，什么样的方向最能够承接团队过去积累的产业能力，什么样的战场最值得长期投入。</p>\\\\n  <p>最终，双方形成高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。许映童也很认同这一判断。</p>\\\\n  <p>2022年6月，思格新能源正式成立，高瓴第一时间领投了天使轮。当时团队并不大，却自带浓厚的“铁军”基因——总裁张先淼，智能光伏前副总裁，17年光伏行业经验；核心高管均为产业背景，浸泡在光伏储能领域10年以上。</p>\\\\n  <p>然而挑战很快出现。虽然许映童身为产业老兵，但创业公司的现实是：作为新入局者，思格新能源仍须应对供应链短缺的重大挑战，早期最现实的问题往往是能不能顺利把产品做出来、交出去。</p>\\\\n  <p>尤其在锂电、功率器件等核心部件上，早期创业公司常常会面对价格高、拿货难，优质产能几乎被头部企业优先锁定的问题。对一家刚成立的创业公司而言，这不是成本问题，而是会直接影响产品迭代、交付节奏、客户信任和公司生存的关键问题。</p>\\\\n  <p>高瓴没有停留在“给钱”的层面，而是主动把多年积累的生态内的核心产业资源开放给思格：比如在电池侧，对接宁德时代，帮助思格在产能最紧缺的时期获得稳定、优质的锂电供应，缓解了BOM成本压力和交付风险；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供，为产品的一致性与可靠性打下基础。</p>\\\\n  <p>潮水总是快得令人意想不到——2022年思格新能源决定全力押注一体机时，全球储能市场对此的需求还不到30%；首创的一体机上市后，95%以上的需求都转向了光储一体。据弗若斯特沙利文报告，按产品出货量计，2024年思格新能源已成为全球排名第一的可堆叠分布式光储一体机解决方案提供商。</p>\\\\n  <p>亲历这一幕，高瓴创始合伙人李良颇为感慨：“在全球能源结构转型的实业浪潮中，思格新能源扎扎实实地从底层研发和供应链做起。创始人许映童带领的团队，展现了中国顶尖制造业老兵深厚的系统工程能力和极强的全球化落地执行力。”</p>\\\\n  <h2><strong>在最不确定的时候站在一起</strong></h2>\\\\n  <h2><strong>投资人迎来超级回报</strong></h2>\\\\n  <p>如今回头来看，这是一场难得的双向奔赴。</p>\\\\n  <p>回想四年前，俄乌战争爆发、市场剧烈波动，宏观环境带来的不确定性仍然存在。那时候高瓴的出手，并非源自短期市场情绪，而是对思格新能源团队能力和产业方向的坚定判断。</p>\\\\n  <p>当中有一段插曲：在思格新能源后续融资阶段，行业一度不被看好，市场情绪十分低迷。但高瓴并没有因为周期波动而动摇，而是继续坚定支持公司发展，不仅连投两轮，而且协助其引入了产业方和财务投资人，完成多轮关键融资。</p>\\\\n  <p>背后的逻辑很朴素：在全球能源结构转型的浪潮下，从底层研发和供应链出发的思格新能源，具备能够把复杂产品和组织真正做出来的品质。</p>\\\\n  <p>创业路上，最难的是在不确定的时刻依然有人坚定地选择相信你。许映童这样的产业老兵，选择投资人的逻辑很朴素：不看热闹，而是要懂行。</p>\\\\n  <p>“高瓴懂我们的语言，也理解我们想做成的事。这种超越资本的陪伴，让我们敢于从一开始就走那条难而正确的路。”许映童表示。</p>\\\\n  <p>如今翻开招股书，思格新能源成长惊人——公司营收在2023年还是5830万元，2024年就来到了13.3亿元，去年这个数字是90亿元，两年时间翻了150倍多；盈利层面，2024年扭亏为盈，实现净利润8385万元，2025年达到29.19亿，毛利率从2023年的31.3%提升至最新的50.1%，收入和利润双双飙升。</p>\\\\n  <p>由此，缔造中国新能源一个增长神话。</p>\\\\n  <p>一路崛起，思格新能源身后浮现一支投资人队伍：高瓴、华登国际、云晖资本、钟鼎资本、天堂硅谷、国科东方、国核投资等。招股书显示，全球发售后高瓴仍通过珠海玫恒持股14.08%，为最大外部投资方，总投资金额约人民币3亿元，账面持股市值约200亿港元。</p>\\\\n  <p>说起来，华登亦是自早期便坚定重仓思格新能源；天堂硅谷则在40亿估值时出手；钟鼎决定投资思格，是看中了公司团队对“能源互联网”底层逻辑的深刻洞察。硬科技浪潮席卷，坚守的人都收获时间的回报。</p>\\\\n  <h2><strong>千亿市值</strong></h2>\\\\n  <p>首日市值破千亿港元，思格新能源创造了历史。透过其身后，我们再次看到AI的威力——储能的天花板，被AI打开了。</p>\\\\n  <p>上个月，黄仁勋在分享中将AI生态比作一块五层蛋糕：顶层是应用，其次是模型、基础设施、芯片，而最底层正是能源。所谓AI的尽头是能源，归根结底是能源成本的竞争。</p>\\\\n  <p>行业的变化已摆在眼前。瑞银报告���出，2026年全球储能需求有望同比增长40%。在AI电力需求空前上升的推动下，储能产业正迈入新一轮繁荣周期。仅在美国，预计2025年至2027年太阳能与储能系统将贡献75%至80%的新增电力装机容量。</p>\\\\n  <p>这意味着，AI带来的电力焦虑，正将储能从过去电力系统的配角，推向新一轮基础设施建设的前排。而ResearchAndMarkets报告显示，到2030年，仅AI数据中心直接配套的储能市场，保守看已是数十亿美元规模；若把AI驱动的整条电力系统升级算进去，储能的想象空间显然远不止于此。</p>\\\\n  <p>但风口并不会平均落到每一家公司头上。AI带来的，不只是更多储能需求，也在重写这个行业的能力门槛：真正被需要的，是围绕稳定性、调度效率、系统灵活性和场景适配展开的整体能力。</p>\\\\n  <p>这正是思格新能源见长的地方。无论是家庭户用、工商业，还是地面电站，背后考验的都不只是单一设备，而是系统稳定性、部署效率、安全性与场景适配能力的整体水平。尤其在思格新能源主打的AI储能，相比传统储能解决电量问题，AI储能解决的是“这度电何时使用能释放更大价值”。</p>\\\\n  <p>如此，高瓴们对思格新能源的押注也就不难理解了。所看中的，是一支长期在产业中历练、能把复杂产品真正落地的团队，恰好站上了被时代放大的机会。风口提供了加速度，真正决定上限的，仍是团队本身。</p>\\\\n  <p>“对许映童这样的产业创业者而言，投资人的价值首先在于理解。听得懂产业语言，理解制造业创业的难处，并能在关键时刻提供长期支持，远比资金本身更重要。”高瓴创始合伙人李良向投资界强调，这种产业能力与时代窗口之间的精准契合，最为稀缺。</p>\\\\n  <p>风口轮转，周期起伏。</p>\\\\n  <p>很多时候，所谓高光，不过是时间终于看见了那些长期埋头向前的人。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI5ODk1NjY1MA==&amp;mid=2247720766&amp;idx=1&amp;sn=e4f403fcfe32b54cbcc0885ada005561&amp;chksm=edbaf20987abc0fd03c89b5a23754ba195c172ed193db7eb6416a4a8c11d17ab29768009f69e&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“投资界”（ID：pedaily2012）</a>，作者：余梦莹 王露，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>港交所震撼一幕。</p>\\\\n  <p>今日（4月16日），思格新能源正式登陆港交所，成为“AI储能第一股”。此次IPO发行价为324.2港元，开盘大涨近80%，市值破1400亿港元，这在港股历史上并不多见。</p>\\\\n  <p>当中，公司在招股阶段获1102倍超额认购。身后基石投资阵容豪华，累计认购约2.8亿美元，涵盖淡马锡、高盛资产管理、高瓴、瑞银、法国巴黎银行、CPE源峰、博裕资本、景林资产、富国基金、中国太保、正大机器人有限公司、工银理财等国内外顶级机构。</p>\\\\n  <p>在高瓴创始合伙人李良看来，思格新能源掌舵人许映童是典型的「产业牛人」。2022年，这位产业界元老带队创立思格新能源，从一开始就走那条难而正确的路，专注于用AI重新定义储能。期间，高瓴从天使轮开始押注两轮，成为思格新能源最大外部投资方。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6799aa6226684beebcf21dd605857ee0@000000_oswg76467oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">思格新能源创始人、董事长兼CEO许映童（左）与高瓴创始合伙人李良（右）</p>\\\\n  <p>如此，从成立到IPO不足4年时间，中国企业港股IPO最快纪录再次被刷新了。</p>\\\\n  <h2><strong>今天，产业大牛敲钟</strong></h2>\\\\n  <h2><strong>高瓴重仓</strong></h2>\\\\n  <p>思格新能源的诞生，离不开灵魂人物——许映童。</p>\\\\n  <p>这个名字对圈外或许有些陌生，但在光伏圈内却是赫赫有名：23年产业生涯，亲手开创华为智能光伏业务，带领团队从零做到全球第一。1974年出生，许映童毕业于南京理工大学，1999年入行，从无线通信、智能光伏干到昇腾AI计算，几乎完整见证了中国能源产业的崛起历程。</p>\\\\n  <p>后来，许映童离开大厂，酝酿开启创业之路。那是2022上半年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间；但对真正看得懂产业趋势的人来说，越是在信心低谷，越能看出长期机会的价值。</p>\\\\n  <p>高瓴最早就找到了许映童。彼时对于未来创业方向，许映童其实有多条路的选择。高瓴团队和他一直保持密切的交流。双方讨论的重点，并不是一个短期热门机会，而是：在全球能源格局重构的大背景下，什么样的方向最能够承接团队过去积累的产业能力，什么样的战场最值得长期投入。</p>\\\\n  <p>最终，双方形成高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。许映童也很认同这一判断。</p>\\\\n  <p>2022年6月，思格新能源正式成立，高瓴第一时间领投了天使轮。当时团队并不大，却自带浓厚的“铁军”基因——总裁张先淼，智能光伏前副总裁，17年光伏行业经验；核心高管均为产业背景，浸泡在光伏储能领域10年以上。</p>\\\\n  <p>然而挑战很快出现。虽然许映童身为产业老兵，但创业公司的现实是：作为新入局者，思格新能源仍须应对供应链短缺的重大挑战，早期最现实的问题往往是能不能顺利把产品做出来、交出去。</p>\\\\n  <p>尤其在锂电、功率器件等核心部件上，早期创业公司常常会面对价格高、拿货难，优质产能几乎被头部企业优先锁定的问题。对一家刚成立的创业公司而言，这不是成本问题，而是会直接影响产品迭代、交付节奏、客户信任和公司生存的关键问题。</p>\\\\n  <p>高瓴没有停留在“给钱”的层面，而是主动把多年积累的生态内的核心产业资源开放给思格：比如在电池侧，对接宁德时代，帮助思格在产能最紧缺的时期获得稳定、优质的锂电供应，缓解了BOM成本压力和交付风险；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供，为产品的一致性与可靠性打下基础。</p>\\\\n  <p>潮水总是快得令人意想不到——2022年思格新能源决定全力押注一体机时，全球储能市场对此的需求还不到30%；首创的一体机上市后，95%以上的需求都转向了光储一体。据弗若斯特沙利文报告，按产品出货量计，2024年思格新能源已成为全球排名第一的可堆叠分布式光储一体机解决方案提供商。</p>\\\\n  <p>亲历这一幕，高瓴创始合伙人李良颇为感慨：“在全球能源结构转型的实业浪潮中，思格新能源扎扎实实地从底层研发和供应链做起。创始人许映童带领的团队，展现了中国顶尖制造业老兵深厚的系统工程能力和极强的全球化落地执行力。”</p>\\\\n  <h2><strong>在最不确定的时候站在一起</strong></h2>\\\\n  <h2><strong>投资人迎来超级回报</strong></h2>\\\\n  <p>如今回头来看，这是一场难得的双向奔赴。</p>\\\\n  <p>回想四年前，俄乌战争爆发、市场剧烈波动，宏观环境带来的不确定性仍然存在。那时候高瓴的出手，并非源自短期市场情绪，而是对思格新能源团队能力和产业方向的坚定判断。</p>\\\\n  <p>当中有一段插曲：在思格新能源后续融资阶段，行业一度不被看好，市场情绪十分低迷。但高瓴并没有因为周期波动而动摇，而是继续坚定支持公司发展，不仅连投两轮，而且协助其引入了产业方和财务投资人，完成多轮关键融资。</p>\\\\n  <p>背后的逻辑很朴素：在全球能源结构转型的浪潮下，从底层研发和供应链出发的思格新能源，具备能够把复杂产品和组织真正做出来的品质。</p>\\\\n  <p>创业路上，最难的是在不确定的时刻依然有人坚定地选择相信你。许映童这样的产业老兵，选择投资人的逻辑很朴素：不看热闹，而是要懂行。</p>\\\\n  <p>“高瓴懂我们的语言，也理解我们想做成的事。这种超越资本的陪伴，让我们敢于从一开始就走那条难而正确的路。”许映童表示。</p>\\\\n  <p>如今翻开招股书，思格新能源成长惊人——公司营收在2023年还是5830万元，2024年就来到了13.3亿元，去年这个数字是90亿元，两年时间翻了150倍多；盈利层面，2024年扭亏为盈，实现净利润8385万元，2025年达到29.19亿，毛利率从2023年的31.3%提升至最新的50.1%，收入和利润双双飙升。</p>\\\\n  <p>由此，缔造中国新能源一个增长神话。</p>\\\\n  <p>一路崛起，思格新能源身后浮现一支投资人队伍：高瓴、华登国际、云晖资本、钟鼎资本、天堂硅谷、国科东方、国核投资等。招股书显示，全球发售后高瓴仍通过珠海玫恒持股14.08%，为最大外部投资方，总投资金额约人民币3亿元，账面持股市值约200亿港元。</p>\\\\n  <p>说起来，华登亦是自早期便坚定重仓思格新能源；天堂硅谷则在40亿估值时出手；钟鼎决定投资思格，是看中了公司团队对“能源互联网”底层逻辑的深刻洞察。硬科技浪潮席卷，坚守的人都收获时间的回报。</p>\\\\n  <h2><strong>千亿市值</strong></h2>\\\\n  <p>首日市值破千亿港元，思格新能源创造了历史。透过其身后，我们再次看到AI的威力——储能的天花板，被AI打开了。</p>\\\\n  <p>上个月，黄仁勋在分享中将AI生态比作一块五层蛋糕：顶层是应用，其次是模型、基础设施、芯片，而最底层正是能源。所谓AI的尽头是能源，归根结底是能源成本的竞争。</p>\\\\n  <p>行业的变化已摆在眼前。瑞银报告���出，2026年全球储能需求有望同比增长40%。在AI电力需求空前上升的推动下，储能产业正迈入新一轮繁荣周期。仅在美国，预计2025年至2027年太阳能与储能系统将贡献75%至80%的新增电力装机容量。</p>\\\\n  <p>这意味着，AI带来的电力焦虑，正将储能从过去电力系统的配角，推向新一轮基础设施建设的前排。而ResearchAndMarkets报告显示，到2030年，仅AI数据中心直接配套的储能市场，保守看已是数十亿美元规模；若把AI驱动的整条电力系统升级算进去，储能的想象空间显然远不止于此。</p>\\\\n  <p>但风口并不会平均落到每一家公司头上。AI带来的，不只是更多储能需求，也在重写这个行业的能力门槛：真正被需要的，是围绕稳定性、调度效率、系统灵活性和场景适配展开的整体能力。</p>\\\\n  <p>这正是思格新能源见长的地方。无论是家庭户用、工商业，还是地面电站，背后考验的都不只是单一设备，而是系统稳定性、部署效率、安全性与场景适配能力的整体水平。尤其在思格新能源主打的AI储能，相比传统储能解决电量问题，AI储能解决的是“这度电何时使用能释放更大价值”。</p>\\\\n  <p>如此，高瓴们对思格新能源的押注也就不难理解了。所看中的，是一支长期在产业中历练、能把复杂产品真正落地的团队，恰好站上了被时代放大的机会。风口提供了加速度，真正决定上限的，仍是团队本身。</p>\\\\n  <p>“对许映童这样的产业创业者而言，投资人的价值首先在于理解。听得懂产业语言，理解制造业创业的难处，并能在关键时刻提供长期支持，远比资金本身更重要。”高瓴创始合伙人李良向投资界强调，这种产业能力与时代窗口之间的精准契合，最为稀缺。</p>\\\\n  <p>风口轮转，周期起伏。</p>\\\\n  <p>很多时候，所谓高光，不过是时间终于看见了那些长期埋头向前的人。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI5ODk1NjY1MA==&amp;mid=2247720766&amp;idx=1&amp;sn=e4f403fcfe32b54cbcc0885ada005561&amp;chksm=edbaf20987abc0fd03c89b5a23754ba195c172ed193db7eb6416a4a8c11d17ab29768009f69e&amp;scene=0&amp;xtrack=1#rd\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“投资界”（ID：pedaily2012）</a>，作者：余梦莹 王露，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'投资界\'}], \'author\': \'投资界\', \'author_detail\': {\'name\': \'投资界\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'始于天使轮。\'}]}\", \"published_at\": \"2026-04-16 11:39:56\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 11:39:56', '2026-04-16 13:35:03');
INSERT INTO `news_detail` VALUES (46, 1448, 10, '传统制造升级', 'FDA连续两次说“不”，Gilead砸50亿说“要”，Soleno暴涨56%说“跟”：这场生死游戏，中国创新药看懂了吗？', '', '<p>一周之内，不到5天的时间，美国生物医药市场同时上演了三幕截然不同的戏码。</p>\n<p>Replimune的溶瘤病毒药物RP1第二次被FDA打回，股价崩跌超60%，公司宣告裁员；Gilead以最高50亿美元收购德国ADC公司Tubulis，干净利落；Neurocrine以29亿美元全现金拿下孤儿药公司Soleno，后者股价一周之内涨超56%。</p>\n<p>三个故事，三种结局，但背后只有一条逻辑：证据不硬，监管不放行；资产够硬，大药企抢着掏钱；壁垒够硬，孤儿药能卖出真溢价。</p>\n<h2><strong>01</strong></h2>\n<h2><strong>第二次被拒意味着什么？</strong></h2>\n<p>4月9日晚至10日，Replimune披露收到FDA第二封完全回应函（CRL），FDA拒绝批准RP1（vusolimogene oderparepvec）联合nivolumab治疗抗PD-1后进展晚期黑色素瘤的BLA。</p>\n<p>注意，这已经是第二次了。</p>\n<p>2025年7月，FDA第一次拒绝时，理由清晰：<strong>单臂试验的数据，不足以证明真实临床获益。</strong>按理说，Replimune有将近一年的时间去解决这个问题。但4月份的二审结果告诉所有人，证据链没有实质改善，FDA依然不认。</p>\n<p>Replimune管理层的公开回应措辞激烈，称FDA审评碎片化、前后不一致。但这几乎于事无补。</p>\n<p>市场的判断比公司声明更残酷：4月13日早盘，Replimune股价一度跌61%至1.86美元，盘中最低触及1.50美元，年初以来累计跌约75%，多家卖方机构下调评级至减持。公司随后宣布裁员和产能缩减，在公告语境里，这几乎等同于承认：公司已经没有足够的资金独立推进随机对照试验了。</p>\n<p>说白了，这第二封CRL不只是一次审评失败，而是FDA对RP1现有注册逻辑的正式否定：单臂试验冲加速批准，这条路变得很难走了。</p>\n<h2><strong>02</strong></h2>\n<h2><strong>单臂试验的赌局，中国药企也在押</strong></h2>\n<p>Replimune的问题，在中国并不陌生。</p>\n<p>过去几年，国内不少创新药企同样在走单臂试验＋替代终点的路径，押注FDA加速批准。合理使用政策红利本身没问题，是个捷径，但它或多或少掺杂了赌的成分：赌监管容忍度，赌审评官认可未满足需求，赌没有竞争对手在同一时间递交更扎实的随机对照数据。</p>\n<p>Replimune的案例在告诉所有人：这场赌局的赔率，正在快速变低。</p>\n<p>FDA在肿瘤领域已经多次释放信号，加速批准不是免检通道，而是一份可以被撤销的临时许可。2024年加速批准改革之后，对替代终点能否预测真实临床获益的审查越来越严，转化验证要求越来越具体。</p>\n<p>单臂试验、ORR终点、小样本……这些要素单独存在尚可接受，但叠加在一起又遭遇随机对照数据缺失，这个组合在FDA眼中已经越来越难以接受。</p>\n<p>对中国创新药企来说，这不是一个人家被拒跟我有什么关系的问题。</p>\n<p>很多企业的出海逻辑，恰恰建立在先拿中国批文，再用同样数据敲美国的门。这条路能不能走通，很大程度上取决于临床试验在设计之初，有没有按FDA真实的证据审查标准来，而不是按差不多能过的心理预期来。</p>\n<p>监管不是最后一关，是第一关。如果试验设计本身就没有为全球注册留出余量，后续所有的BD谈判、里程碑定价、海外IPO，都是在沙滩上盖楼。</p>\n<h2><strong>03</strong></h2>\n<h2><strong>Gilead为什么愿意砸50亿买Tubulis？</strong></h2>\n<p>理解了监管的严苛，再看这笔喜气洋洋的收购，逻辑就顺了。</p>\n<p>Gilead以31.5亿美元现金预付、最高18.5亿美元里程碑付款，合计最高50亿美元，收购德国ADC公司Tubulis，预计于2026年二季度完成。</p>\n<p>这家公司的核心价值有两块：一是针对NaPi2b等靶点的临床期ADC管线；二是能显著降低毒性的新一代连接子/载荷平台，收购后将作为Gilead在慕尼黑的专属ADC研发中心独立运营。</p>\n<p>大药企买这类资产，不看故事，看三件事：<strong>机制是否差异化、毒性窗口是否更优、全球临床注册路径是否清晰。</strong></p>\n<p>巧了，Tubulis三样都有。</p>\n<p>而且这是Gilead短期内第三笔重磅并购；此前Arcellx偏肿瘤，Ouro偏免疫，Tubulis则进一步补强其ADC肿瘤布局。三笔交易，预计于2026年二季度完成。</p>\n<p>密集出手的背后逻辑只有一个：当专利悬崖临近、内生研发无法及时填补，大药企最理性的选择就是去外部买证据足够硬、监管路径足够清晰的资产。<strong>买概念，已经过时了。</strong></p>\n<p><strong>Tubulis被收购的逻辑，与Replimune被拒的逻辑，是同一枚硬币的两面：监管确定性，是资产能否被高价收购的前提条件。</strong>一个过了这道门，一个没过，差距就是几十亿美元。</p>\n<h2><strong>04</strong></h2>\n<h2><strong>29亿美元买孤儿药，溢价从哪来？</strong></h2>\n<p>如果说前两个案例是关于监管能否通过，Neurocrine收购Soleno，则是在教另一课：<strong>真正被监管偏爱并筑起壁垒的孤儿药，比任何临床阶段的故事都值钱。</strong></p>\n<p>Neurocrine以每股53美元、总对价约29亿美元全现金收购Soleno，较公告前溢价约34%，较30日均价溢价约51%，Soleno股价一周之内累计涨超56%。</p>\n<p>核心标的是Vykat XR，美国首个且目前唯一获批用于治疗Prader-Willi综合征相关病理性饥饿的孤儿药。2025年全年收入约1.9亿美元，Q4单季贡献约9200万美元，年化超3.6亿美元，且仍处商业化早期。</p>\n<p>孤儿药的核心竞争力，从来不在规模，在于：无集采压力、无大规模仿制竞争、患者终身用药、定价权长期稳固。Neurocrine买的不是增长故事，而是一个<strong>可预期的、高质量的现金流</strong>。</p>\n<p>这对中国VC和大药企的战略并购有直接参考价值。</p>\n<p>过去几年，国内投资逻辑主要围绕“大赛道、大市场、高峰值销售”，孤儿病和小众适应症的商业价值是被看到的，但资产的估值框架怎么具象定义，相对不够完全成熟。但现实是，在监管门槛持续抬高、临床成本持续上升的当下，<strong>已上市、有定价权、在小赛道做到唯一或第一的资产，往往比大而全但未商业化的管线更容易在并购中获得真实溢价。</strong></p>\n<p>更深一层：<strong>孤儿药能获得监管快速通道、市场独占期保护，这本身也是监管逻辑给予的确定性。最终兑现的溢价，还是要回归到监管这个原点。</strong></p>\n<h2><strong>05</strong></h2>\n<h2><strong>这笔账，中国药企和投资人该怎么算？</strong></h2>\n<p>2026年一季度，中国创新药对外授权交易总额超过600亿美元，热度居历史高位。但热闹背后，那些真正被海外大药企付真钱接走的项目，<strong>无一例外都是监管路径清晰的</strong>；那些被低价打包甚至无人问津的，往往是临床设计早期就埋下了监管隐患。</p>\n<p>这就是2026年创新药市场真正的竞争维度。</p>\n<p>不是谁的故事讲得更宏大，不是谁的靶点更新颖，而是，<strong>你这套临床证据，FDA、EMA和NMPA都能接受吗？</strong></p>\n<p>Replimune给出了最昂贵的反面教材：一款机制上有独特性的溶瘤病毒药物，因为试验设计上的路径依赖和证据不足，最终被监管拦在门外，市值断崖，公司裁员求生。而Gilead买Tubulis、Neurocrine买Soleno，不过是在用真金白银确认同一件事：<strong>监管的确定性和监管直接筑起壁垒，才是最稀缺的溢价来源。</strong></p>\n<p>这一点，这个月的美国市场已经用真金白银说清楚了。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/cSU-TlEKjD-wRuyXk0rvuQ\">“分子稳态”</a>，作者：创新药组 稳态君，36氪经授权发布。</p>', 'https://36kr.com/p/3768801194275332?f=rss', 0, '', '{\"summary\": \"本文通过美国生物医药市场三个典型案例，揭示FDA最新监管逻辑，为中国创新药出海规划临床路径、把握资产价值提供参考\", \"abstract\": \"近日美国生物医药市场接连发生三件事：Replimune的溶瘤病毒药物第二次被FDA拒绝批准，吉利德以最高50亿美元收购ADC公司Tubulis，Neurocrine以29亿美元收购孤儿药公司Soleno，后者股价大涨超56%。文章指出，FDA2024年加速批准改革后，对创新药临床证据的审查愈发严格，单臂试验叠加随机对照数据缺失的注册路径获批难度已大幅提升，而不少中国创新药出海正采用该押注路径。文章总结，当前全球创新药市场的核心逻辑是，监管确定性是资产获得高估值、被大药企收购的核心前提，已上市、有壁垒的孤儿药资产更易获得真实溢价。该逻辑对中国创新药出海及国内医药投资并购具有重要参考意义，提示出海药企需在临床设计阶段就符合目标市场监管标准。\", \"keywords\": [\"创新药出海\", \"FDA\", \"监管合规\", \"加速批准\", \"单臂试验\", \"孤儿药\", \"生物医药\", \"药企并购\"], \"policy_risk\": {\"market_risk\": \"国内不少创新药出海采用“单臂试验+替代终点”路径押注FDA加速批准，若临床设计未满足FDA监管要求，将面临审评被拒、项目价值大幅缩水、后续融资与并购受阻的风险\", \"policy_compliance\": \"FDA2024年完成加速批准改革后，对肿瘤创新药的审评要求收紧，对替代终点能否预测真实临床获益的审查愈发严格；单臂试验叠加随机对照数据缺失的注册路径已难以获得FDA认可，要求出海创新药企业从临床设计阶段就符合FDA的证据审查标准\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"传统制造升级\"}', '', '{\"url\": \"https://36kr.com/p/3768801194275332?f=rss\", \"title\": \"FDA连续两次说“不”，Gilead砸50亿说“要”，Soleno暴涨56%说“跟”：这场生死游戏，中国创新药看懂了吗？\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>一周之内，不到5天的时间，美国生物医药市场同时上演了三幕截然不同的戏码。</p>\\n<p>Replimune的溶瘤病毒药物RP1第二次被FDA打回，股价崩跌超60%，公司宣告裁员；Gilead以最高50亿美元收购德国ADC公司Tubulis，干净利落；Neurocrine以29亿美元全现金拿下孤儿药公司Soleno，后者股价一周之内涨超56%。</p>\\n<p>三个故事，三种结局，但背后只有一条逻辑：证据不硬，监管不放行；资产够硬，大药企抢着掏钱；壁垒够硬，孤儿药能卖出真溢价。</p>\\n<h2><strong>01</strong></h2>\\n<h2><strong>第二次被拒意味着什么？</strong></h2>\\n<p>4月9日晚至10日，Replimune披露收到FDA第二封完全回应函（CRL），FDA拒绝批准RP1（vusolimogene oderparepvec）联合nivolumab治疗抗PD-1后进展晚期黑色素瘤的BLA。</p>\\n<p>注意，这已经是第二次了。</p>\\n<p>2025年7月，FDA第一次拒绝时，理由清晰：<strong>单臂试验的数据，不足以证明真实临床获益。</strong>按理说，Replimune有将近一年的时间去解决这个问题。但4月份的二审结果告诉所有人，证据链没有实质改善，FDA依然不认。</p>\\n<p>Replimune管理层的公开回应措辞激烈，称FDA审评碎片化、前后不一致。但这几乎于事无补。</p>\\n<p>市场的判断比公司声明更残酷：4月13日早盘，Replimune股价一度跌61%至1.86美元，盘中最低触及1.50美元，年初以来累计跌约75%，多家卖方机构下调评级至减持。公司随后宣布裁员和产能缩减，在公告语境里，这几乎等同于承认：公司已经没有足够的资金独立推进随机对照试验了。</p>\\n<p>说白了，这第二封CRL不只是一次审评失败，而是FDA对RP1现有注册逻辑的正式否定：单臂试验冲加速批准，这条路变得很难走了。</p>\\n<h2><strong>02</strong></h2>\\n<h2><strong>单臂试验的赌局，中国药企也在押</strong></h2>\\n<p>Replimune的问题，在中国并不陌生。</p>\\n<p>过去几年，国内不少创新药企同样在走单臂试验＋替代终点的路径，押注FDA加速批准。合理使用政策红利本身没问题，是个捷径，但它或多或少掺杂了赌的成分：赌监管容忍度，赌审评官认可未满足需求，赌没有竞争对手在同一时间递交更扎实的随机对照数据。</p>\\n<p>Replimune的案例在告诉所有人：这场赌局的赔率，正在快速变低。</p>\\n<p>FDA在肿瘤领域已经多次释放信号，加速批准不是免检通道，而是一份可以被撤销的临时许可。2024年加速批准改革之后，对替代终点能否预测真实临床获益的审查越来越严，转化验证要求越来越具体。</p>\\n<p>单臂试验、ORR终点、小样本……这些要素单独存在尚可接受，但叠加在一起又遭遇随机对照数据缺失，这个组合在FDA眼中已经越来越难以接受。</p>\\n<p>对中国创新药企来说，这不是一个人家被拒跟我有什么关系的问题。</p>\\n<p>很多企业的出海逻辑，恰恰建立在先拿中国批文，再用同样数据敲美国的门。这条路能不能走通，很大程度上取决于临床试验在设计之初，有没有按FDA真实的证据审查标准来，而不是按差不多能过的心理预期来。</p>\\n<p>监管不是最后一关，是第一关。如果试验设计本身就没有为全球注册留出余量，后续所有的BD谈判、里程碑定价、海外IPO，都是在沙滩上盖楼。</p>\\n<h2><strong>03</strong></h2>\\n<h2><strong>Gilead为什么愿意砸50亿买Tubulis？</strong></h2>\\n<p>理解了监管的严苛，再看这笔喜气洋洋的收购，逻辑就顺了。</p>\\n<p>Gilead以31.5亿美元现金预付、最高18.5亿美元里程碑付款，合计最高50亿美元，收购德国ADC公司Tubulis，预计于2026年二季度完成。</p>\\n<p>这家公司的核心价值有两块：一是针对NaPi2b等靶点的临床期ADC管线；二是能显著降低毒性的新一代连接子/载荷平台，收购后将作为Gilead在慕尼黑的专属ADC研发中心独立运营。</p>\\n<p>大药企买这类资产，不看故事，看三件事：<strong>机制是否差异化、毒性窗口是否更优、全球临床注册路径是否清晰。</strong></p>\\n<p>巧了，Tubulis三样都有。</p>\\n<p>而且这是Gilead短期内第三笔重磅并购；此前Arcellx偏肿瘤，Ouro偏免疫，Tubulis则进一步补强其ADC肿瘤布局。三笔交易，预计于2026年二季度完成。</p>\\n<p>密集出手的背后逻辑只有一个：当专利悬崖临近、内生研发无法及时填补，大药企最理性的选择就是去外部买证据足够硬、监管路径足够清晰的资产。<strong>买概念，已经过时了。</strong></p>\\n<p><strong>Tubulis被收购的逻辑，与Replimune被拒的逻辑，是同一枚硬币的两面：监管确定性，是资产能否被高价收购的前提条件。</strong>一个过了这道门，一个没过，差距就是几十亿美元。</p>\\n<h2><strong>04</strong></h2>\\n<h2><strong>29亿美元买孤儿药，溢价从哪来？</strong></h2>\\n<p>如果说前两个案例是关于监管能否通过，Neurocrine收购Soleno，则是在教另一课：<strong>真正被监管偏爱并筑起壁垒的孤儿药，比任何临床阶段的故事都值钱。</strong></p>\\n<p>Neurocrine以每股53美元、总对价约29亿美元全现金收购Soleno，较公告前溢价约34%，较30日均价溢价约51%，Soleno股价一周之内累计涨超56%。</p>\\n<p>核心标的是Vykat XR，美国首个且目前唯一获批用于治疗Prader-Willi综合征相关病理性饥饿的孤儿药。2025年全年收入约1.9亿美元，Q4单季贡献约9200万美元，年化超3.6亿美元，且仍处商业化早期。</p>\\n<p>孤儿药的核心竞争力，从来不在规模，在于：无集采压力、无大规模仿制竞争、患者终身用药、定价权长期稳固。Neurocrine买的不是增长故事，而是一个<strong>可预期的、高质量的现金流</strong>。</p>\\n<p>这对中国VC和大药企的战略并购有直接参考价值。</p>\\n<p>过去几年，国内投资逻辑主要围绕“大赛道、大市场、高峰值销售”，孤儿病和小众适应症的商业价值是被看到的，但资产的估值框架怎么具象定义，相对不够完全成熟。但现实是，在监管门槛持续抬高、临床成本持续上升的当下，<strong>已上市、有定价权、在小赛道做到唯一或第一的资产，往往比大而全但未商业化的管线更容易在并购中获得真实溢价。</strong></p>\\n<p>更深一层：<strong>孤儿药能获得监管快速通道、市场独占期保护，这本身也是监管逻辑给予的确定性。最终兑现的溢价，还是要回归到监管这个原点。</strong></p>\\n<h2><strong>05</strong></h2>\\n<h2><strong>这笔账，中国药企和投资人该怎么算？</strong></h2>\\n<p>2026年一季度，中国创新药对外授权交易总额超过600亿美元，热度居历史高位。但热闹背后，那些真正被海外大药企付真钱接走的项目，<strong>无一例外都是监管路径清晰的</strong>；那些被低价打包甚至无人问津的，往往是临床设计早期就埋下了监管隐患。</p>\\n<p>这就是2026年创新药市场真正的竞争维度。</p>\\n<p>不是谁的故事讲得更宏大，不是谁的靶点更新颖，而是，<strong>你这套临床证据，FDA、EMA和NMPA都能接受吗？</strong></p>\\n<p>Replimune给出了最昂贵的反面教材：一款机制上有独特性的溶瘤病毒药物，因为试验设计上的路径依赖和证据不足，最终被监管拦在门外，市值断崖，公司裁员求生。而Gilead买Tubulis、Neurocrine买Soleno，不过是在用真金白银确认同一件事：<strong>监管的确定性和监管直接筑起壁垒，才是最稀缺的溢价来源。</strong></p>\\n<p>这一点，这个月的美国市场已经用真金白银说清楚了。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/cSU-TlEKjD-wRuyXk0rvuQ\\\">“分子稳态”</a>，作者：创新药组 稳态君，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'FDA连续两次说“不”，Gilead砸50亿说“要”，Soleno暴涨56%说“跟”：这场生死游戏，中国创新药看懂了吗？\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'FDA连续两次说“不”，Gilead砸50亿说“要”，Soleno暴涨56%说“跟”：这场生死游戏，中国创新药看懂了吗？\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768801194275332?f=rss\'}], \'link\': \'https://36kr.com/p/3768801194275332?f=rss\', \'published\': \'2026-04-16 11:10:21  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=3, tm_min=10, tm_sec=21, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>一周之内，不到5天的时间，美国生物医药市场同时上演了三幕截然不同的戏码。</p>\\\\n  <p>Replimune的溶瘤病毒药物RP1第二次被FDA打回，股价崩跌超60%，公司宣告裁员；Gilead以最高50亿美元收购德国ADC公司Tubulis，干净利落；Neurocrine以29亿美元全现金拿下孤儿药公司Soleno，后者股价一周之内涨超56%。</p>\\\\n  <p>三个故事，三种结局，但背后只有一条逻辑：证据不硬，监管不放行；资产够硬，大药企抢着掏钱；壁垒够硬，孤儿药能卖出真溢价。</p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>第二次被拒意味着什么？</strong></h2>\\\\n  <p>4月9日晚至10日，Replimune披露收到FDA第二封完全回应函（CRL），FDA拒绝批准RP1（vusolimogene oderparepvec）联合nivolumab治疗抗PD-1后进展晚期黑色素瘤的BLA。</p>\\\\n  <p>注意，这已经是第二次了。</p>\\\\n  <p>2025年7月，FDA第一次拒绝时，理由清晰：<strong>单臂试验的数据，不足以证明真实临床获益。</strong>按理说，Replimune有将近一年的时间去解决这个问题。但4月份的二审结果告诉所有人，证据链没有实质改善，FDA依然不认。</p>\\\\n  <p>Replimune管理层的公开回应措辞激烈，称FDA审评碎片化、前后不一致。但这几乎于事无补。</p>\\\\n  <p>市场的判断比公司声明更残酷：4月13日早盘，Replimune股价一度跌61%至1.86美元，盘中最低触及1.50美元，年初以来累计跌约75%，多家卖方机构下调评级至减持。公司随后宣布裁员和产能缩减，在公告语境里，这几乎等同于承认：公司已经没有足够的资金独立推进随机对照试验了。</p>\\\\n  <p>说白了，这第二封CRL不只是一次审评失败，而是FDA对RP1现有注册逻辑的正式否定：单臂试验冲加速批准，这条路变得很难走了。</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>单臂试验的赌局，中国药企也在押</strong></h2>\\\\n  <p>Replimune的问题，在中国并不陌生。</p>\\\\n  <p>过去几年，国内不少创新药企同样在走单臂试验＋替代终点的路径，押注FDA加速批准。合理使用政策红利本身没问题，是个捷径，但它或多或少掺杂了赌的成分：赌监管容忍度，赌审评官认可未满足需求，赌没有竞争对手在同一时间递交更扎实的随机对照数据。</p>\\\\n  <p>Replimune的案例在告诉所有人：这场赌局的赔率，正在快速变低。</p>\\\\n  <p>FDA在肿瘤领域已经多次释放信号，加速批准不是免检通道，而是一份可以被撤销的临时许可。2024年加速批准改革之后，对替代终点能否预测真实临床获益的审查越来越严，转化验证要求越来越具体。</p>\\\\n  <p>单臂试验、ORR终点、小样本……这些要素单独存在尚可接受，但叠加在一起又遭遇随机对照数据缺失，这个组合在FDA眼中已经越来越难以接受。</p>\\\\n  <p>对中国创新药企来说，这不是一个人家被拒跟我有什么关系的问题。</p>\\\\n  <p>很多企业的出海逻辑，恰恰建立在先拿中国批文，再用同样数据敲美国的门。这条路能不能走通，很大程度上取决于临床试验在设计之初，有没有按FDA真实的证据审查标准来，而不是按差不多能过的心理预期来。</p>\\\\n  <p>监管不是最后一关，是第一关。如果试验设计本身就没有为全球注册留出余量，后续所有的BD谈判、里程碑定价、海外IPO，都是在沙滩上盖楼。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>Gilead为什么愿意砸50亿买Tubulis？</strong></h2>\\\\n  <p>理解了监管的严苛，再看这笔喜气洋洋的收购，逻辑就顺了。</p>\\\\n  <p>Gilead以31.5亿美元现金预付、最高18.5亿美元里程碑付款，合计最高50亿美元，收购德国ADC公司Tubulis，预计于2026年二季度完成。</p>\\\\n  <p>这家公司的核心价值有两块：一是针对NaPi2b等靶点的临床期ADC管线；二是能显著降低毒性的新一代连接子/载荷平台，收购后将作为Gilead在慕尼黑的专属ADC研发中心独立运营。</p>\\\\n  <p>大药企买这类资产，不看故事，看三件事：<strong>机制是否差异化、毒性窗口是否更优、全球临床注册路径是否清晰。</strong></p>\\\\n  <p>巧了，Tubulis三样都有。</p>\\\\n  <p>而且这是Gilead短期内第三笔重磅并购；此前Arcellx偏肿瘤，Ouro偏免疫，Tubulis则进一步补强其ADC肿瘤布局。三笔交易，预计于2026年二季度完成。</p>\\\\n  <p>密集出手的背后逻辑只有一个：当专利悬崖临近、内生研发无法及时填补，大药企最理性的选择就是去外部买证据足够硬、监管路径足够清晰的资产。<strong>买概念，已经过时了。</strong></p>\\\\n  <p><strong>Tubulis被收购的逻辑，与Replimune被拒的逻辑，是同一枚硬币的两面：监管确定性，是资产能否被高价收购的前提条件。</strong>一个过了这道门，一个没过，差距就是几十亿美元。</p>\\\\n  <h2><strong>04</strong></h2>\\\\n  <h2><strong>29亿美元买孤儿药，溢价从哪来？</strong></h2>\\\\n  <p>如果说前两个案例是关于监管能否通过，Neurocrine收购Soleno，则是在教另一课：<strong>真正被监管偏爱并筑起壁垒的孤儿药，比任何临床阶段的故事都值钱。</strong></p>\\\\n  <p>Neurocrine以每股53美元、总对价约29亿美元全现金收购Soleno，较公告前溢价约34%，较30日均价溢价约51%，Soleno股价一周之内累计涨超56%。</p>\\\\n  <p>核心标的是Vykat XR，美国首个且目前唯一获批用于治疗Prader-Willi综合征相关病理性饥饿的孤儿药。2025年全年收入约1.9亿美元，Q4单季贡献约9200万美元，年化超3.6亿美元，且仍处商业化早期。</p>\\\\n  <p>孤儿药的核心竞争力，从来不在规模，在于：无集采压力、无大规模仿制竞争、患者终身用药、定价权长期稳固。Neurocrine买的不是增长故事，而是一个<strong>可预期的、高质量的现金流</strong>。</p>\\\\n  <p>这对中国VC和大药企的战略并购有直接参考价值。</p>\\\\n  <p>过去几年，国内投资逻辑主要围绕“大赛道、大市场、高峰值销售”，孤儿病和小众适应症的商业价值是被看到的，但资产的估值框架怎么具象定义，相对不够完全成熟。但现实是，在监管门槛持续抬高、临床成本持续上升的当下，<strong>已上市、有定价权、在小赛道做到唯一或第一的资产，往往比大而全但未商业化的管线更容易在并购中获得真实溢价。</strong></p>\\\\n  <p>更深一层：<strong>孤儿药能获得监管快速通道、市场独占期保护，这本身也是监管逻辑给予的确定性。最终兑现的溢价，还是要回归到监管这个原点。</strong></p>\\\\n  <h2><strong>05</strong></h2>\\\\n  <h2><strong>这笔账，中国药企和投资人该怎么算？</strong></h2>\\\\n  <p>2026年一季度，中国创新药对外授权交易总额超过600亿美元，热度居历史高位。但热闹背后，那些真正被海外大药企付真钱接走的项目，<strong>无一例外都是监管路径清晰的</strong>；那些被低价打包甚至无人问津的，往往是临床设计早期就埋下了监管隐患。</p>\\\\n  <p>这就是2026年创新药市场真正的竞争维度。</p>\\\\n  <p>不是谁的故事讲得更宏大，不是谁的靶点更新颖，而是，<strong>你这套临床证据，FDA、EMA和NMPA都能接受吗？</strong></p>\\\\n  <p>Replimune给出了最昂贵的反面教材：一款机制上有独特性的溶瘤病毒药物，因为试验设计上的路径依赖和证据不足，最终被监管拦在门外，市值断崖，公司裁员求生。而Gilead买Tubulis、Neurocrine买Soleno，不过是在用真金白银确认同一件事：<strong>监管的确定性和监管直接筑起壁垒，才是最稀缺的溢价来源。</strong></p>\\\\n  <p>这一点，这个月的美国市场已经用真金白银说清楚了。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/cSU-TlEKjD-wRuyXk0rvuQ\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“分子稳态”</a>，作者：创新药组&nbsp;稳态君，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>一周之内，不到5天的时间，美国生物医药市场同时上演了三幕截然不同的戏码。</p>\\\\n  <p>Replimune的溶瘤病毒药物RP1第二次被FDA打回，股价崩跌超60%，公司宣告裁员；Gilead以最高50亿美元收购德国ADC公司Tubulis，干净利落；Neurocrine以29亿美元全现金拿下孤儿药公司Soleno，后者股价一周之内涨超56%。</p>\\\\n  <p>三个故事，三种结局，但背后只有一条逻辑：证据不硬，监管不放行；资产够硬，大药企抢着掏钱；壁垒够硬，孤儿药能卖出真溢价。</p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>第二次被拒意味着什么？</strong></h2>\\\\n  <p>4月9日晚至10日，Replimune披露收到FDA第二封完全回应函（CRL），FDA拒绝批准RP1（vusolimogene oderparepvec）联合nivolumab治疗抗PD-1后进展晚期黑色素瘤的BLA。</p>\\\\n  <p>注意，这已经是第二次了。</p>\\\\n  <p>2025年7月，FDA第一次拒绝时，理由清晰：<strong>单臂试验的数据，不足以证明真实临床获益。</strong>按理说，Replimune有将近一年的时间去解决这个问题。但4月份的二审结果告诉所有人，证据链没有实质改善，FDA依然不认。</p>\\\\n  <p>Replimune管理层的公开回应措辞激烈，称FDA审评碎片化、前后不一致。但这几乎于事无补。</p>\\\\n  <p>市场的判断比公司声明更残酷：4月13日早盘，Replimune股价一度跌61%至1.86美元，盘中最低触及1.50美元，年初以来累计跌约75%，多家卖方机构下调评级至减持。公司随后宣布裁员和产能缩减，在公告语境里，这几乎等同于承认：公司已经没有足够的资金独立推进随机对照试验了。</p>\\\\n  <p>说白了，这第二封CRL不只是一次审评失败，而是FDA对RP1现有注册逻辑的正式否定：单臂试验冲加速批准，这条路变得很难走了。</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>单臂试验的赌局，中国药企也在押</strong></h2>\\\\n  <p>Replimune的问题，在中国并不陌生。</p>\\\\n  <p>过去几年，国内不少创新药企同样在走单臂试验＋替代终点的路径，押注FDA加速批准。合理使用政策红利本身没问题，是个捷径，但它或多或少掺杂了赌的成分：赌监管容忍度，赌审评官认可未满足需求，赌没有竞争对手在同一时间递交更扎实的随机对照数据。</p>\\\\n  <p>Replimune的案例在告诉所有人：这场赌局的赔率，正在快速变低。</p>\\\\n  <p>FDA在肿瘤领域已经多次释放信号，加速批准不是免检通道，而是一份可以被撤销的临时许可。2024年加速批准改革之后，对替代终点能否预测真实临床获益的审查越来越严，转化验证要求越来越具体。</p>\\\\n  <p>单臂试验、ORR终点、小样本……这些要素单独存在尚可接受，但叠加在一起又遭遇随机对照数据缺失，这个组合在FDA眼中已经越来越难以接受。</p>\\\\n  <p>对中国创新药企来说，这不是一个人家被拒跟我有什么关系的问题。</p>\\\\n  <p>很多企业的出海逻辑，恰恰建立在先拿中国批文，再用同样数据敲美国的门。这条路能不能走通，很大程度上取决于临床试验在设计之初，有没有按FDA真实的证据审查标准来，而不是按差不多能过的心理预期来。</p>\\\\n  <p>监管不是最后一关，是第一关。如果试验设计本身就没有为全球注册留出余量，后续所有的BD谈判、里程碑定价、海外IPO，都是在沙滩上盖楼。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>Gilead为什么愿意砸50亿买Tubulis？</strong></h2>\\\\n  <p>理解了监管的严苛，再看这笔喜气洋洋的收购，逻辑就顺了。</p>\\\\n  <p>Gilead以31.5亿美元现金预付、最高18.5亿美元里程碑付款，合计最高50亿美元，收购德国ADC公司Tubulis，预计于2026年二季度完成。</p>\\\\n  <p>这家公司的核心价值有两块：一是针对NaPi2b等靶点的临床期ADC管线；二是能显著降低毒性的新一代连接子/载荷平台，收购后将作为Gilead在慕尼黑的专属ADC研发中心独立运营。</p>\\\\n  <p>大药企买这类资产，不看故事，看三件事：<strong>机制是否差异化、毒性窗口是否更优、全球临床注册路径是否清晰。</strong></p>\\\\n  <p>巧了，Tubulis三样都有。</p>\\\\n  <p>而且这是Gilead短期内第三笔重磅并购；此前Arcellx偏肿瘤，Ouro偏免疫，Tubulis则进一步补强其ADC肿瘤布局。三笔交易，预计于2026年二季度完成。</p>\\\\n  <p>密集出手的背后逻辑只有一个：当专利悬崖临近、内生研发无法及时填补，大药企最理性的选择就是去外部买证据足够硬、监管路径足够清晰的资产。<strong>买概念，已经过时了。</strong></p>\\\\n  <p><strong>Tubulis被收购的逻辑，与Replimune被拒的逻辑，是同一枚硬币的两面：监管确定性，是资产能否被高价收购的前提条件。</strong>一个过了这道门，一个没过，差距就是几十亿美元。</p>\\\\n  <h2><strong>04</strong></h2>\\\\n  <h2><strong>29亿美元买孤儿药，溢价从哪来？</strong></h2>\\\\n  <p>如果说前两个案例是关于监管能否通过，Neurocrine收购Soleno，则是在教另一课：<strong>真正被监管偏爱并筑起壁垒的孤儿药，比任何临床阶段的故事都值钱。</strong></p>\\\\n  <p>Neurocrine以每股53美元、总对价约29亿美元全现金收购Soleno，较公告前溢价约34%，较30日均价溢价约51%，Soleno股价一周之内累计涨超56%。</p>\\\\n  <p>核心标的是Vykat XR，美国首个且目前唯一获批用于治疗Prader-Willi综合征相关病理性饥饿的孤儿药。2025年全年收入约1.9亿美元，Q4单季贡献约9200万美元，年化超3.6亿美元，且仍处商业化早期。</p>\\\\n  <p>孤儿药的核心竞争力，从来不在规模，在于：无集采压力、无大规模仿制竞争、患者终身用药、定价权长期稳固。Neurocrine买的不是增长故事，而是一个<strong>可预期的、高质量的现金流</strong>。</p>\\\\n  <p>这对中国VC和大药企的战略并购有直接参考价值。</p>\\\\n  <p>过去几年，国内投资逻辑主要围绕“大赛道、大市场、高峰值销售”，孤儿病和小众适应症的商业价值是被看到的，但资产的估值框架怎么具象定义，相对不够完全成熟。但现实是，在监管门槛持续抬高、临床成本持续上升的当下，<strong>已上市、有定价权、在小赛道做到唯一或第一的资产，往往比大而全但未商业化的管线更容易在并购中获得真实溢价。</strong></p>\\\\n  <p>更深一层：<strong>孤儿药能获得监管快速通道、市场独占期保护，这本身也是监管逻辑给予的确定性。最终兑现的溢价，还是要回归到监管这个原点。</strong></p>\\\\n  <h2><strong>05</strong></h2>\\\\n  <h2><strong>这笔账，中国药企和投资人该怎么算？</strong></h2>\\\\n  <p>2026年一季度，中国创新药对外授权交易总额超过600亿美元，热度居历史高位。但热闹背后，那些真正被海外大药企付真钱接走的项目，<strong>无一例外都是监管路径清晰的</strong>；那些被低价打包甚至无人问津的，往往是临床设计早期就埋下了监管隐患。</p>\\\\n  <p>这就是2026年创新药市场真正的竞争维度。</p>\\\\n  <p>不是谁的故事讲得更宏大，不是谁的靶点更新颖，而是，<strong>你这套临床证据，FDA、EMA和NMPA都能接受吗？</strong></p>\\\\n  <p>Replimune给出了最昂贵的反面教材：一款机制上有独特性的溶瘤病毒药物，因为试验设计上的路径依赖和证据不足，最终被监管拦在门外，市值断崖，公司裁员求生。而Gilead买Tubulis、Neurocrine买Soleno，不过是在用真金白银确认同一件事：<strong>监管的确定性和监管直接筑起壁垒，才是最稀缺的溢价来源。</strong></p>\\\\n  <p>这一点，这个月的美国市场已经用真金白银说清楚了。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/cSU-TlEKjD-wRuyXk0rvuQ\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“分子稳态”</a>，作者：创新药组&nbsp;稳态君，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'分子稳态\'}], \'author\': \'分子稳态\', \'author_detail\': {\'name\': \'分子稳态\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'监管，从来不是创新药商业化的最后一步，而是决定你能否走到终点的第一关。\'}]}\", \"published_at\": \"2026-04-16 11:10:21\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 11:10:21', '2026-04-16 13:36:29');
INSERT INTO `news_detail` VALUES (47, 1472, 6, '科技与数字服务', '美团，闷声投了半个科技圈', '', '<p>这几天的资本市场，几乎被一堆IPO消息刷屏。宇树科技科创板上市申请获受理，估值直指420亿；智谱AI港股挂牌，市值一度冲破3200亿；摩尔线程、沐曦股份上市首日市值均突破千亿大关。</p>\n<p>如果仔细翻过这些公司的招股书和股权结构，会发现一个有意思的现象：<strong>它们背后都站着同一个名字，美团。</strong></p>\n<h2><strong>01</strong></h2>\n<h2><strong>老谋深算的布局</strong></h2>\n<p>前日美团发布了2025年全年业绩，数字不怎么好看。</p>\n<p>笔者做过专门分析（<a href=\"https://mp.weixin.qq.com/s?__biz=MjM5MTAwNzI3NQ==&amp;mid=2247562234&amp;idx=1&amp;sn=e486560440522ffe11a647a7726b9535&amp;scene=21#wechat_redirect\"><strong>年亏234亿！美团怎么了？</strong></a>），今天不在赘述。</p>\n<p>王兴在业绩会上说得很直白：“补贴驱动的竞争，是典型的非理性竞争。”</p>\n<p>可就在核心业务被对手疯狂冲击的这一年，美团悄悄完成了另一件事，<strong>它在硬科技领域的投资版图，已经庞大到足以让大多数VC机构都自愧不如。</strong></p>\n<p>据极客公园不完全统计，美团至少投资了超过50家硬科技企业，其中超四分之一已是独角兽级别，接近10家已经或正在推进上市。</p>\n<p>投资横跨<strong>具身智能、AI大模型、芯片半导体、智能硬件、自动驾驶</strong>五大核心赛道，累计陪伴了28家独角兽、7家上市公司成长。</p>\n<p>这张图已经不只是投资，更像是<strong>一张覆盖了从底层算力到上层应用的完整AI产业链图谱。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_d31b8a64b1644b7ab889b5708fe9a5ae@6307721_oswg577860oswg912oswg1017_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图片来源：公开查询</p>\n<h2><strong>02</strong></h2>\n<h2><strong>美团的科技牌</strong></h2>\n<p>聊美团的硬科技投资，先得从王兴说起。</p>\n<p>美团CEO王兴，现在被圈内人戏称为“中国具身智能第一投资人”。这个称呼不是白来的，在宇树科技B2轮融资时，估值才10亿元，美团就已经是领投方了，随后又继续加码B3轮、C1轮。</p>\n<p>等到腾讯、阿里、字节这些互联网巨头在2025年年中密集入场的时候，宇树的估值已经飙到了120亿。也就是说，当别人花高价买“防御性门票”的时候，美团已经在这个牌桌上坐了一年半。</p>\n<p>这种“早到”的节奏贯穿了美团整个投资版图。在具身智能赛道，美团至少投资了16家企业，其中10家估值已超10亿美元。</p>\n<p><strong>在芯片算力层</strong>，美团投了摩尔线程、沐曦股份、紫光展锐、爱芯智元、荣芯半导体等一大批企业，覆盖了国内GPU头部和“国家队”级别的半导体公司。</p>\n<p><strong>在AI大模型领域</strong>，美团既是智谱AI的早期股东，又在A1轮重仓月之暗面，顺带覆盖了AIGC3D、视频Agent等一堆细分方向。</p>\n<p><strong>美团对硬科技的投资，核心逻辑其实很简单：芯片算力是底层基建，AI是应用，自动驾驶是连接，具身智能是执行。这四个赛道层层递进，形成了一个从数字世界到物理世界的完整闭环。</strong>这套投资逻辑或许也值得当下很多VC/PE机构借鉴。</p>\n<p>说得再直白一点，美团的业务场景太“接地气”了，外卖配送、仓储分拣、线下零售，每一个环节都对效率和自动化有着极其迫切的需求。与其等技术成熟了再去买，不如在技术还只有实验室雏形的时候，就直接坐在研发桌上。</p>\n<h2><strong>03</strong></h2>\n<h2><strong>到底投了多少？</strong></h2>\n<p>笔者根据公开查询，基于可查询到的数据（可能不全），把美团核心投资布局整理了一个表格：</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_659a586f3b4b4a148ad296ea478a6553@6307721_oswg246988oswg1080oswg835_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>数据来源：公开查询</p>\n<p>这个清单远没完。普渡科技、高仙机器人、未来机器人、法奥机器人，还有快手、Shein、水滴公司、众安在线、贝壳……</p>\n<p>美团这些年投的企业，横跨了硬科技和本地生活的几乎每一个角落。</p>\n<h2><strong>04</strong></h2>\n<h2><strong>遍地开花，却喜忧参半</strong></h2>\n<p>有件事说起来挺讽刺的。</p>\n<p>美团投的那些硬科技公司，这两年一个接一个地敲钟上市，<strong>账面回报相当可观。</strong></p>\n<p>可美团自己的核心业务却在2025年遭遇了史上最惨烈的“外卖大战”，一年亏掉234亿。</p>\n<p>一边是投资版图的科技公司批量IPO，一边是主业被对手按在地上摩擦。腾讯也在今年1月的年度员工大会上宣布，已经完全退出了对美团的战略投资。</p>\n<p>这其实是理解美团现在处境最好的切面，它在做一件极其矛盾的事情：<strong>一边在战壕里跟对手拼刺刀、烧钱保份额，一边又把自己变成了全中国最活跃的硬科技产业投资人。</strong></p>\n<p>王兴在2025年的财报电话会上给了一个说法：“我们对AI的策略是进攻而不是防守。”</p>\n<p>翻译一下就是：外卖大战再惨，也只是短期的事。</p>\n<p>美团真正要打的仗，是在未来的物理世界AI底座上。美团2025年的研发投入达到260亿元，同比增长23.5%，重点砸向了AI大模型和具身智能。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_fa00baecb2194375ba024d2df27767a3@6307721_oswg1057185oswg1080oswg511_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>260亿元，这个数字，已经超过了绝大多数A股上市公司的全年营收。</p>\n<h2><strong>05</strong></h2>\n<h2><strong>收购叮咚，补上生鲜的最后一块拼图</strong></h2>\n<p>2026年2月5日，美团甩出一张50亿的支票，以7.17亿美元全资收购了叮咚买菜的中国业务。</p>\n<p>这笔交易带来了什么？1000余个前置仓、超700万月活用户，以及叮咚深耕了近9年的产地直采供应链。</p>\n<p>最关键的是，叮咚已经连续12个季度实现盈利，在生鲜这个公认的“烧钱无底洞”里跑通了商业模型。</p>\n<p>说实话，美团在生鲜这件事上没少走弯路。2018年搞过小象生鲜线下大店，运营成本太高，一年后就关了。后来转向前置仓做美团买菜，2023年升级成小象超市。这次直接买下叮咚，等于用钱把时间和经验差一次性补齐了。</p>\n<p>但更值得琢磨的是这笔收购背后的信号，当竞争对手还在拼命砸补贴抢用户的时候，美团已经开始系统性整合供应链和基础设施了。即时零售这个赛道，正在从“谁能烧钱”切换到“谁能提效”的新阶段。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_ff011e43440c402f820bd281c6ac2d80@6307721_oswg852784oswg1080oswg624_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<h2><strong>06</strong></h2>\n<h2><strong>接下来会怎样？</strong></h2>\n<p>展望2026年，笔者认为，几个关键节点值得关注。</p>\n<p>第一，<strong>外卖大战的退潮速度。如果行业能真正回归理性竞争</strong>，美团的核心本地商业有望在2026年下半年重回盈利通道。</p>\n<p>第二，<strong>被投企业的变现节奏</strong>。智谱AI已经上市，宇树科技即将IPO，摩尔线程、沐曦股份也都完成了上市，这些标的的退出能给美团带来多少账面收益，值得关注。</p>\n<p>但更重要的是，这些技术能不能反哺美团自己的业务。目前美团AI商家经营助手已经服务了超340万商户，AI助手“小团”在春节期间服务了过亿用户。如果能把这些技术能力转化成实实在在的效率和成本优势，那才是真金白银。</p>\n<p>第三，<strong>出海能否成为第二增长曲线</strong>。Keeta在中东的扩张还在继续，虽然短期亏损难免，但王兴的表态很明确——新业务分部的整体亏损不会超过2025年。</p>\n<p>对于现在的美团来说，2025年的亏损更像是在为未来“交学费”。这张学费账单虽然贵，一年592亿的利润蒸发，但换来的是一个横跨五大硬科技赛道、覆盖50多家独角兽的投资版图。</p>\n<p>王兴是不是在押注一个别人还看不清的未来？</p>\n<p>这个问题，可能再过两三年才会有答案。</p>\n<p>但有一点已经可以确定：<strong>当我们以为美团只是一个送外卖的平台时，它已经在悄悄变成一家科技投资机构了。</strong></p>\n<p>‍本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/dciv64YEp5gD4oyhzSciaw\">“投行圈子”</a>，作者：投行大师姐，36氪经授权发布。</p>', 'https://36kr.com/p/3768963813061123?f=rss', 0, '', '{\"summary\": \"本文梳理美团的硬科技投资布局，披露其中东出海扩张计划，可为科技出海企业的布局与投资合作提供参考\", \"abstract\": \"本文梳理了美团的投资布局，指出美团在核心本地业务2025年亏损的背景下，已经建成覆盖具身智能、AI大模型、芯片半导体、智能硬件、自动驾驶五大硬科技赛道的庞大投资版图，已有近10家被投企业上市或推进上市。美团投资硬科技的核心逻辑，是为自身外卖配送、仓储分拣、线下零售等业务场景提前布局自动化技术，满足效率升级需求。文章还提到，美团2026年初全资收购叮咚买菜中国业务补齐生鲜供应链短板，同时其出海业务Keeta正在中东扩张，被寄予成为第二增长曲线的期望。\", \"keywords\": [\"美团\", \"硬科技投资\", \"AI大模型\", \"具身智能\", \"芯片半导体\", \"中东出海\", \"第二增长曲线\", \"Keeta\"], \"policy_risk\": {\"market_risk\": \"美团核心外卖行业竞争激烈，2025年亏损234亿元；出海业务短期存在亏损压力，被投硬科技技术能否反哺主业仍待验证\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"https://36kr.com/p/3768963813061123?f=rss\", \"title\": \"美团，闷声投了半个科技圈\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>这几天的资本市场，几乎被一堆IPO消息刷屏。宇树科技科创板上市申请获受理，估值直指420亿；智谱AI港股挂牌，市值一度冲破3200亿；摩尔线程、沐曦股份上市首日市值均突破千亿大关。</p>\\n<p>如果仔细翻过这些公司的招股书和股权结构，会发现一个有意思的现象：<strong>它们背后都站着同一个名字，美团。</strong></p>\\n<h2><strong>01</strong></h2>\\n<h2><strong>老谋深算的布局</strong></h2>\\n<p>前日美团发布了2025年全年业绩，数字不怎么好看。</p>\\n<p>笔者做过专门分析（<a href=\\\"https://mp.weixin.qq.com/s?__biz=MjM5MTAwNzI3NQ==&amp;mid=2247562234&amp;idx=1&amp;sn=e486560440522ffe11a647a7726b9535&amp;scene=21#wechat_redirect\\\"><strong>年亏234亿！美团怎么了？</strong></a>），今天不在赘述。</p>\\n<p>王兴在业绩会上说得很直白：“补贴驱动的竞争，是典型的非理性竞争。”</p>\\n<p>可就在核心业务被对手疯狂冲击的这一年，美团悄悄完成了另一件事，<strong>它在硬科技领域的投资版图，已经庞大到足以让大多数VC机构都自愧不如。</strong></p>\\n<p>据极客公园不完全统计，美团至少投资了超过50家硬科技企业，其中超四分之一已是独角兽级别，接近10家已经或正在推进上市。</p>\\n<p>投资横跨<strong>具身智能、AI大模型、芯片半导体、智能硬件、自动驾驶</strong>五大核心赛道，累计陪伴了28家独角兽、7家上市公司成长。</p>\\n<p>这张图已经不只是投资，更像是<strong>一张覆盖了从底层算力到上层应用的完整AI产业链图谱。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_d31b8a64b1644b7ab889b5708fe9a5ae@6307721_oswg577860oswg912oswg1017_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图片来源：公开查询</p>\\n<h2><strong>02</strong></h2>\\n<h2><strong>美团的科技牌</strong></h2>\\n<p>聊美团的硬科技投资，先得从王兴说起。</p>\\n<p>美团CEO王兴，现在被圈内人戏称为“中国具身智能第一投资人”。这个称呼不是白来的，在宇树科技B2轮融资时，估值才10亿元，美团就已经是领投方了，随后又继续加码B3轮、C1轮。</p>\\n<p>等到腾讯、阿里、字节这些互联网巨头在2025年年中密集入场的时候，宇树的估值已经飙到了120亿。也就是说，当别人花高价买“防御性门票”的时候，美团已经在这个牌桌上坐了一年半。</p>\\n<p>这种“早到”的节奏贯穿了美团整个投资版图。在具身智能赛道，美团至少投资了16家企业，其中10家估值已超10亿美元。</p>\\n<p><strong>在芯片算力层</strong>，美团投了摩尔线程、沐曦股份、紫光展锐、爱芯智元、荣芯半导体等一大批企业，覆盖了国内GPU头部和“国家队”级别的半导体公司。</p>\\n<p><strong>在AI大模型领域</strong>，美团既是智谱AI的早期股东，又在A1轮重仓月之暗面，顺带覆盖了AIGC3D、视频Agent等一堆细分方向。</p>\\n<p><strong>美团对硬科技的投资，核心逻辑其实很简单：芯片算力是底层基建，AI是应用，自动驾驶是连接，具身智能是执行。这四个赛道层层递进，形成了一个从数字世界到物理世界的完整闭环。</strong>这套投资逻辑或许也值得当下很多VC/PE机构借鉴。</p>\\n<p>说得再直白一点，美团的业务场景太“接地气”了，外卖配送、仓储分拣、线下零售，每一个环节都对效率和自动化有着极其迫切的需求。与其等技术成熟了再去买，不如在技术还只有实验室雏形的时候，就直接坐在研发桌上。</p>\\n<h2><strong>03</strong></h2>\\n<h2><strong>到底投了多少？</strong></h2>\\n<p>笔者根据公开查询，基于可查询到的数据（可能不全），把美团核心投资布局整理了一个表格：</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_659a586f3b4b4a148ad296ea478a6553@6307721_oswg246988oswg1080oswg835_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>数据来源：公开查询</p>\\n<p>这个清单远没完。普渡科技、高仙机器人、未来机器人、法奥机器人，还有快手、Shein、水滴公司、众安在线、贝壳……</p>\\n<p>美团这些年投的企业，横跨了硬科技和本地生活的几乎每一个角落。</p>\\n<h2><strong>04</strong></h2>\\n<h2><strong>遍地开花，却喜忧参半</strong></h2>\\n<p>有件事说起来挺讽刺的。</p>\\n<p>美团投的那些硬科技公司，这两年一个接一个地敲钟上市，<strong>账面回报相当可观。</strong></p>\\n<p>可美团自己的核心业务却在2025年遭遇了史上最惨烈的“外卖大战”，一年亏掉234亿。</p>\\n<p>一边是投资版图的科技公司批量IPO，一边是主业被对手按在地上摩擦。腾讯也在今年1月的年度员工大会上宣布，已经完全退出了对美团的战略投资。</p>\\n<p>这其实是理解美团现在处境最好的切面，它在做一件极其矛盾的事情：<strong>一边在战壕里跟对手拼刺刀、烧钱保份额，一边又把自己变成了全中国最活跃的硬科技产业投资人。</strong></p>\\n<p>王兴在2025年的财报电话会上给了一个说法：“我们对AI的策略是进攻而不是防守。”</p>\\n<p>翻译一下就是：外卖大战再惨，也只是短期的事。</p>\\n<p>美团真正要打的仗，是在未来的物理世界AI底座上。美团2025年的研发投入达到260亿元，同比增长23.5%，重点砸向了AI大模型和具身智能。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_fa00baecb2194375ba024d2df27767a3@6307721_oswg1057185oswg1080oswg511_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>260亿元，这个数字，已经超过了绝大多数A股上市公司的全年营收。</p>\\n<h2><strong>05</strong></h2>\\n<h2><strong>收购叮咚，补上生鲜的最后一块拼图</strong></h2>\\n<p>2026年2月5日，美团甩出一张50亿的支票，以7.17亿美元全资收购了叮咚买菜的中国业务。</p>\\n<p>这笔交易带来了什么？1000余个前置仓、超700万月活用户，以及叮咚深耕了近9年的产地直采供应链。</p>\\n<p>最关键的是，叮咚已经连续12个季度实现盈利，在生鲜这个公认的“烧钱无底洞”里跑通了商业模型。</p>\\n<p>说实话，美团在生鲜这件事上没少走弯路。2018年搞过小象生鲜线下大店，运营成本太高，一年后就关了。后来转向前置仓做美团买菜，2023年升级成小象超市。这次直接买下叮咚，等于用钱把时间和经验差一次性补齐了。</p>\\n<p>但更值得琢磨的是这笔收购背后的信号，当竞争对手还在拼命砸补贴抢用户的时候，美团已经开始系统性整合供应链和基础设施了。即时零售这个赛道，正在从“谁能烧钱”切换到“谁能提效”的新阶段。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ff011e43440c402f820bd281c6ac2d80@6307721_oswg852784oswg1080oswg624_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<h2><strong>06</strong></h2>\\n<h2><strong>接下来会怎样？</strong></h2>\\n<p>展望2026年，笔者认为，几个关键节点值得关注。</p>\\n<p>第一，<strong>外卖大战的退潮速度。如果行业能真正回归理性竞争</strong>，美团的核心本地商业有望在2026年下半年重回盈利通道。</p>\\n<p>第二，<strong>被投企业的变现节奏</strong>。智谱AI已经上市，宇树科技即将IPO，摩尔线程、沐曦股份也都完成了上市，这些标的的退出能给美团带来多少账面收益，值得关注。</p>\\n<p>但更重要的是，这些技术能不能反哺美团自己的业务。目前美团AI商家经营助手已经服务了超340万商户，AI助手“小团”在春节期间服务了过亿用户。如果能把这些技术能力转化成实实在在的效率和成本优势，那才是真金白银。</p>\\n<p>第三，<strong>出海能否成为第二增长曲线</strong>。Keeta在中东的扩张还在继续，虽然短期亏损难免，但王兴的表态很明确——新业务分部的整体亏损不会超过2025年。</p>\\n<p>对于现在的美团来说，2025年的亏损更像是在为未来“交学费”。这张学费账单虽然贵，一年592亿的利润蒸发，但换来的是一个横跨五大硬科技赛道、覆盖50多家独角兽的投资版图。</p>\\n<p>王兴是不是在押注一个别人还看不清的未来？</p>\\n<p>这个问题，可能再过两三年才会有答案。</p>\\n<p>但有一点已经可以确定：<strong>当我们以为美团只是一个送外卖的平台时，它已经在悄悄变成一家科技投资机构了。</strong></p>\\n<p>‍本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/dciv64YEp5gD4oyhzSciaw\\\">“投行圈子”</a>，作者：投行大师姐，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'美团，闷声投了半个科技圈\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'美团，闷声投了半个科技圈\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768963813061123?f=rss\'}], \'link\': \'https://36kr.com/p/3768963813061123?f=rss\', \'published\': \'2026-04-16 12:44:42  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=4, tm_min=44, tm_sec=42, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>这几天的资本市场，几乎被一堆IPO消息刷屏。宇树科技科创板上市申请获受理，估值直指420亿；智谱AI港股挂牌，市值一度冲破3200亿；摩尔线程、沐曦股份上市首日市值均突破千亿大关。</p>\\\\n  <p>如果仔细翻过这些公司的招股书和股权结构，会发现一个有意思的现象：<strong>它们背后都站着同一个名字，美团。</strong></p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>老谋深算的布局</strong></h2>\\\\n  <p>前日美团发布了2025年全年业绩，数字不怎么好看。</p>\\\\n  <p>笔者做过专门分析（<a href=\\\"https://mp.weixin.qq.com/s?__biz=MjM5MTAwNzI3NQ==&amp;mid=2247562234&amp;idx=1&amp;sn=e486560440522ffe11a647a7726b9535&amp;scene=21#wechat_redirect\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>年亏234亿！美团怎么了？</strong></a>），今天不在赘述。</p>\\\\n  <p>王兴在业绩会上说得很直白：“补贴驱动的竞争，是典型的非理性竞争。”</p>\\\\n  <p>可就在核心业务被对手疯狂冲击的这一年，美团悄悄完成了另一件事，<strong>它在硬科技领域的投资版图，已经庞大到足以让大多数VC机构都自愧不如。</strong></p>\\\\n  <p>据极客公园不完全统计，美团至少投资了超过50家硬科技企业，其中超四分之一已是独角兽级别，接近10家已经或正在推进上市。</p>\\\\n  <p>投资横跨<strong>具身智能、AI大模型、芯片半导体、智能硬件、自动驾驶</strong>五大核心赛道，累计陪伴了28家独角兽、7家上市公司成长。</p>\\\\n  <p>这张图已经不只是投资，更像是<strong>一张覆盖了从底层算力到上层应用的完整AI产业链图谱。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_d31b8a64b1644b7ab889b5708fe9a5ae@6307721_oswg577860oswg912oswg1017_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图片来源：公开查询</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>美团的科技牌</strong></h2>\\\\n  <p>聊美团的硬科技投资，先得从王兴说起。</p>\\\\n  <p>美团CEO王兴，现在被圈内人戏称为“中国具身智能第一投资人”。这个称呼不是白来的，在宇树科技B2轮融资时，估值才10亿元，美团就已经是领投方了，随后又继续加码B3轮、C1轮。</p>\\\\n  <p>等到腾讯、阿里、字节这些互联网巨头在2025年年中密集入场的时候，宇树的估值已经飙到了120亿。也就是说，当别人花高价买“防御性门票”的时候，美团已经在这个牌桌上坐了一年半。</p>\\\\n  <p>这种“早到”的节奏贯穿了美团整个投资版图。在具身智能赛道，美团至少投资了16家企业，其中10家估值已超10亿美元。</p>\\\\n  <p><strong>在芯片算力层</strong>，美团投了摩尔线程、沐曦股份、紫光展锐、爱芯智元、荣芯半导体等一大批企业，覆盖了国内GPU头部和“国家队”级别的半导体公司。</p>\\\\n  <p><strong>在AI大模型领域</strong>，美团既是智谱AI的早期股东，又在A1轮重仓月之暗面，顺带覆盖了AIGC3D、视频Agent等一堆细分方向。</p>\\\\n  <p><strong>美团对硬科技的投资，核心逻辑其实很简单：芯片算力是底层基建，AI是应用，自动驾驶是连接，具身智能是执行。这四个赛道层层递进，形成了一个从数字世界到物理世界的完整闭环。</strong>这套投资逻辑或许也值得当下很多VC/PE机构借鉴。</p>\\\\n  <p>说得再直白一点，美团的业务场景太“接地气”了，外卖配送、仓储分拣、线下零售，每一个环节都对效率和自动化有着极其迫切的需求。与其等技术成熟了再去买，不如在技术还只有实验室雏形的时候，就直接坐在研发桌上。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>到底投了多少？</strong></h2>\\\\n  <p>笔者根据公开查询，基于可查询到的数据（可能不全），把美团核心投资布局整理了一个表格：</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_659a586f3b4b4a148ad296ea478a6553@6307721_oswg246988oswg1080oswg835_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">数据来源：公开查询</p>\\\\n  <p>这个清单远没完。普渡科技、高仙机器人、未来机器人、法奥机器人，还有快手、Shein、水滴公司、众安在线、贝壳……</p>\\\\n  <p>美团这些年投的企业，横跨了硬科技和本地生活的几乎每一个角落。</p>\\\\n  <h2><strong>04</strong></h2>\\\\n  <h2><strong>遍地开花，却喜忧参半</strong></h2>\\\\n  <p>有件事说起来挺讽刺的。</p>\\\\n  <p>美团投的那些硬科技公司，这两年一个接一个地敲钟上市，<strong>账面回报相当可观。</strong></p>\\\\n  <p>可美团自己的核心业务却在2025年遭遇了史上最惨烈的“外卖大战”，一年亏掉234亿。</p>\\\\n  <p>一边是投资版图的科技公司批量IPO，一边是主业被对手按在地上摩擦。腾讯也在今年1月的年度员工大会上宣布，已经完全退出了对美团的战略投资。</p>\\\\n  <p>这其实是理解美团现在处境最好的切面，它在做一件极其矛盾的事情：<strong>一边在战壕里跟对手拼刺刀、烧钱保份额，一边又把自己变成了全中国最活跃的硬科技产业投资人。</strong></p>\\\\n  <p>王兴在2025年的财报电话会上给了一个说法：“我们对AI的策略是进攻而不是防守。”</p>\\\\n  <p>翻译一下就是：外卖大战再惨，也只是短期的事。</p>\\\\n  <p>美团真正要打的仗，是在未来的物理世界AI底座上。美团2025年的研发投入达到260亿元，同比增长23.5%，重点砸向了AI大模型和具身智能。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_fa00baecb2194375ba024d2df27767a3@6307721_oswg1057185oswg1080oswg511_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>260亿元，这个数字，已经超过了绝大多数A股上市公司的全年营收。</p>\\\\n  <h2><strong>05</strong></h2>\\\\n  <h2><strong>收购叮咚，补上生鲜的最后一块拼图</strong></h2>\\\\n  <p>2026年2月5日，美团甩出一张50亿的支票，以7.17亿美元全资收购了叮咚买菜的中国业务。</p>\\\\n  <p>这笔交易带来了什么？1000余个前置仓、超700万月活用户，以及叮咚深耕了近9年的产地直采供应链。</p>\\\\n  <p>最关键的是，叮咚已经连续12个季度实现盈利，在生鲜这个公认的“烧钱无底洞”里跑通了商业模型。</p>\\\\n  <p>说实话，美团在生鲜这件事上没少走弯路。2018年搞过小象生鲜线下大店，运营成本太高，一年后就关了。后来转向前置仓做美团买菜，2023年升级成小象超市。这次直接买下叮咚，等于用钱把时间和经验差一次性补齐了。</p>\\\\n  <p>但更值得琢磨的是这笔收购背后的信号，当竞争对手还在拼命砸补贴抢用户的时候，美团已经开始系统性整合供应链和基础设施了。即时零售这个赛道，正在从“谁能烧钱”切换到“谁能提效”的新阶段。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ff011e43440c402f820bd281c6ac2d80@6307721_oswg852784oswg1080oswg624_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <h2><strong>06</strong></h2>\\\\n  <h2><strong>接下来会怎样？</strong></h2>\\\\n  <p>展望2026年，笔者认为，几个关键节点值得关注。</p>\\\\n  <p>第一，<strong>外卖大战的退潮速度。如果行业能真正回归理性竞争</strong>，美团的核心本地商业有望在2026年下半年重回盈利通道。</p>\\\\n  <p>第二，<strong>被投企业的变现节奏</strong>。智谱AI已经上市，宇树科技即将IPO，摩尔线程、沐曦股份也都完成了上市，这些标的的退出能给美团带来多少账面收益，值得关注。</p>\\\\n  <p>但更重要的是，这些技术能不能反哺美团自己的业务。目前美团AI商家经营助手已经服务了超340万商户，AI助手“小团”在春节期间服务了过亿用户。如果能把这些技术能力转化成实实在在的效率和成本优势，那才是真金白银。</p>\\\\n  <p>第三，<strong>出海能否成为第二增长曲线</strong>。Keeta在中东的扩张还在继续，虽然短期亏损难免，但王兴的表态很明确——新业务分部的整体亏损不会超过2025年。</p>\\\\n  <p>对于现在的美团来说，2025年的亏损更像是在为未来“交学费”。这张学费账单虽然贵，一年592亿的利润蒸发，但换来的是一个横跨五大硬科技赛道、覆盖50多家独角兽的投资版图。</p>\\\\n  <p>王兴是不是在押注一个别人还看不清的未来？</p>\\\\n  <p>这个问题，可能再过两三年才会有答案。</p>\\\\n  <p>但有一点已经可以确定：<strong>当我们以为美团只是一个送外卖的平台时，它已经在悄悄变成一家科技投资机构了。</strong></p>\\\\n  <p>\\\\u200d本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/dciv64YEp5gD4oyhzSciaw\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“投行圈子”</a>，作者：投行大师姐，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>这几天的资本市场，几乎被一堆IPO消息刷屏。宇树科技科创板上市申请获受理，估值直指420亿；智谱AI港股挂牌，市值一度冲破3200亿；摩尔线程、沐曦股份上市首日市值均突破千亿大关。</p>\\\\n  <p>如果仔细翻过这些公司的招股书和股权结构，会发现一个有意思的现象：<strong>它们背后都站着同一个名字，美团。</strong></p>\\\\n  <h2><strong>01</strong></h2>\\\\n  <h2><strong>老谋深算的布局</strong></h2>\\\\n  <p>前日美团发布了2025年全年业绩，数字不怎么好看。</p>\\\\n  <p>笔者做过专门分析（<a href=\\\"https://mp.weixin.qq.com/s?__biz=MjM5MTAwNzI3NQ==&amp;mid=2247562234&amp;idx=1&amp;sn=e486560440522ffe11a647a7726b9535&amp;scene=21#wechat_redirect\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\"><strong>年亏234亿！美团怎么了？</strong></a>），今天不在赘述。</p>\\\\n  <p>王兴在业绩会上说得很直白：“补贴驱动的竞争，是典型的非理性竞争。”</p>\\\\n  <p>可就在核心业务被对手疯狂冲击的这一年，美团悄悄完成了另一件事，<strong>它在硬科技领域的投资版图，已经庞大到足以让大多数VC机构都自愧不如。</strong></p>\\\\n  <p>据极客公园不完全统计，美团至少投资了超过50家硬科技企业，其中超四分之一已是独角兽级别，接近10家已经或正在推进上市。</p>\\\\n  <p>投资横跨<strong>具身智能、AI大模型、芯片半导体、智能硬件、自动驾驶</strong>五大核心赛道，累计陪伴了28家独角兽、7家上市公司成长。</p>\\\\n  <p>这张图已经不只是投资，更像是<strong>一张覆盖了从底层算力到上层应用的完整AI产业链图谱。</strong></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_d31b8a64b1644b7ab889b5708fe9a5ae@6307721_oswg577860oswg912oswg1017_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图片来源：公开查询</p>\\\\n  <h2><strong>02</strong></h2>\\\\n  <h2><strong>美团的科技牌</strong></h2>\\\\n  <p>聊美团的硬科技投资，先得从王兴说起。</p>\\\\n  <p>美团CEO王兴，现在被圈内人戏称为“中国具身智能第一投资人”。这个称呼不是白来的，在宇树科技B2轮融资时，估值才10亿元，美团就已经是领投方了，随后又继续加码B3轮、C1轮。</p>\\\\n  <p>等到腾讯、阿里、字节这些互联网巨头在2025年年中密集入场的时候，宇树的估值已经飙到了120亿。也就是说，当别人花高价买“防御性门票”的时候，美团已经在这个牌桌上坐了一年半。</p>\\\\n  <p>这种“早到”的节奏贯穿了美团整个投资版图。在具身智能赛道，美团至少投资了16家企业，其中10家估值已超10亿美元。</p>\\\\n  <p><strong>在芯片算力层</strong>，美团投了摩尔线程、沐曦股份、紫光展锐、爱芯智元、荣芯半导体等一大批企业，覆盖了国内GPU头部和“国家队”级别的半导体公司。</p>\\\\n  <p><strong>在AI大模型领域</strong>，美团既是智谱AI的早期股东，又在A1轮重仓月之暗面，顺带覆盖了AIGC3D、视频Agent等一堆细分方向。</p>\\\\n  <p><strong>美团对硬科技的投资，核心逻辑其实很简单：芯片算力是底层基建，AI是应用，自动驾驶是连接，具身智能是执行。这四个赛道层层递进，形成了一个从数字世界到物理世界的完整闭环。</strong>这套投资逻辑或许也值得当下很多VC/PE机构借鉴。</p>\\\\n  <p>说得再直白一点，美团的业务场景太“接地气”了，外卖配送、仓储分拣、线下零售，每一个环节都对效率和自动化有着极其迫切的需求。与其等技术成熟了再去买，不如在技术还只有实验室雏形的时候，就直接坐在研发桌上。</p>\\\\n  <h2><strong>03</strong></h2>\\\\n  <h2><strong>到底投了多少？</strong></h2>\\\\n  <p>笔者根据公开查询，基于可查询到的数据（可能不全），把美团核心投资布局整理了一个表格：</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_659a586f3b4b4a148ad296ea478a6553@6307721_oswg246988oswg1080oswg835_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">数据来源：公开查询</p>\\\\n  <p>这个清单远没完。普渡科技、高仙机器人、未来机器人、法奥机器人，还有快手、Shein、水滴公司、众安在线、贝壳……</p>\\\\n  <p>美团这些年投的企业，横跨了硬科技和本地生活的几乎每一个角落。</p>\\\\n  <h2><strong>04</strong></h2>\\\\n  <h2><strong>遍地开花，却喜忧参半</strong></h2>\\\\n  <p>有件事说起来挺讽刺的。</p>\\\\n  <p>美团投的那些硬科技公司，这两年一个接一个地敲钟上市，<strong>账面回报相当可观。</strong></p>\\\\n  <p>可美团自己的核心业务却在2025年遭遇了史上最惨烈的“外卖大战”，一年亏掉234亿。</p>\\\\n  <p>一边是投资版图的科技公司批量IPO，一边是主业被对手按在地上摩擦。腾讯也在今年1月的年度员工大会上宣布，已经完全退出了对美团的战略投资。</p>\\\\n  <p>这其实是理解美团现在处境最好的切面，它在做一件极其矛盾的事情：<strong>一边在战壕里跟对手拼刺刀、烧钱保份额，一边又把自己变成了全中国最活跃的硬科技产业投资人。</strong></p>\\\\n  <p>王兴在2025年的财报电话会上给了一个说法：“我们对AI的策略是进攻而不是防守。”</p>\\\\n  <p>翻译一下就是：外卖大战再惨，也只是短期的事。</p>\\\\n  <p>美团真正要打的仗，是在未来的物理世界AI底座上。美团2025年的研发投入达到260亿元，同比增长23.5%，重点砸向了AI大模型和具身智能。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_fa00baecb2194375ba024d2df27767a3@6307721_oswg1057185oswg1080oswg511_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p>260亿元，这个数字，已经超过了绝大多数A股上市公司的全年营收。</p>\\\\n  <h2><strong>05</strong></h2>\\\\n  <h2><strong>收购叮咚，补上生鲜的最后一块拼图</strong></h2>\\\\n  <p>2026年2月5日，美团甩出一张50亿的支票，以7.17亿美元全资收购了叮咚买菜的中国业务。</p>\\\\n  <p>这笔交易带来了什么？1000余个前置仓、超700万月活用户，以及叮咚深耕了近9年的产地直采供应链。</p>\\\\n  <p>最关键的是，叮咚已经连续12个季度实现盈利，在生鲜这个公认的“烧钱无底洞”里跑通了商业模型。</p>\\\\n  <p>说实话，美团在生鲜这件事上没少走弯路。2018年搞过小象生鲜线下大店，运营成本太高，一年后就关了。后来转向前置仓做美团买菜，2023年升级成小象超市。这次直接买下叮咚，等于用钱把时间和经验差一次性补齐了。</p>\\\\n  <p>但更值得琢磨的是这笔收购背后的信号，当竞争对手还在拼命砸补贴抢用户的时候，美团已经开始系统性整合供应链和基础设施了。即时零售这个赛道，正在从“谁能烧钱”切换到“谁能提效”的新阶段。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ff011e43440c402f820bd281c6ac2d80@6307721_oswg852784oswg1080oswg624_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <h2><strong>06</strong></h2>\\\\n  <h2><strong>接下来会怎样？</strong></h2>\\\\n  <p>展望2026年，笔者认为，几个关键节点值得关注。</p>\\\\n  <p>第一，<strong>外卖大战的退潮速度。如果行业能真正回归理性竞争</strong>，美团的核心本地商业有望在2026年下半年重回盈利通道。</p>\\\\n  <p>第二，<strong>被投企业的变现节奏</strong>。智谱AI已经上市，宇树科技即将IPO，摩尔线程、沐曦股份也都完成了上市，这些标的的退出能给美团带来多少账面收益，值得关注。</p>\\\\n  <p>但更重要的是，这些技术能不能反哺美团自己的业务。目前美团AI商家经营助手已经服务了超340万商户，AI助手“小团”在春节期间服务了过亿用户。如果能把这些技术能力转化成实实在在的效率和成本优势，那才是真金白银。</p>\\\\n  <p>第三，<strong>出海能否成为第二增长曲线</strong>。Keeta在中东的扩张还在继续，虽然短期亏损难免，但王兴的表态很明确——新业务分部的整体亏损不会超过2025年。</p>\\\\n  <p>对于现在的美团来说，2025年的亏损更像是在为未来“交学费”。这张学费账单虽然贵，一年592亿的利润蒸发，但换来的是一个横跨五大硬科技赛道、覆盖50多家独角兽的投资版图。</p>\\\\n  <p>王兴是不是在押注一个别人还看不清的未来？</p>\\\\n  <p>这个问题，可能再过两三年才会有答案。</p>\\\\n  <p>但有一点已经可以确定：<strong>当我们以为美团只是一个送外卖的平台时，它已经在悄悄变成一家科技投资机构了。</strong></p>\\\\n  <p>\\\\u200d本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/dciv64YEp5gD4oyhzSciaw\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“投行圈子”</a>，作者：投行大师姐，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'投行圈子\'}], \'author\': \'投行圈子\', \'author_detail\': {\'name\': \'投行圈子\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'遍地开花，却喜忧参半。\'}]}\", \"published_at\": \"2026-04-16 12:44:42\", \"ai_json_output\": \"\"}', '这几天的资本市场，几乎被一堆IPO消息刷屏。宇树科技科创板上市申请获受理，估值直指420亿；智谱AI港股挂牌，市值一度冲破3200亿；摩尔线程、沐曦股份上市首日市值均突破千亿大关。\n如果仔细翻过这些公司的招股书和股权结构，会发现一个有意思的现象：\n它们背后都站着同一个名字，美团。\n01\n老谋深算的布局\n前日美团发布了2025年全年业绩，数字不怎么好看。\n笔者做过专门分析（\n年亏234亿！美团怎么了？\n），今天不在赘述。\n王兴在业绩会上说得很直白：“补贴驱动的竞争，是典型的非理性竞争。”\n可就在核心业务被对手疯狂冲击的这一年，美团悄悄完成了另一件事，\n它在硬科技领域的投资版图，已经庞大到足以让大多数VC机构都自愧不如。\n据极客公园不完全统计，美团至少投资了超过50家硬科技企业，其中超四分之一已是独角兽级别，接近10家已经或正在推进上市。\n投资横跨\n具身智能、AI大模型、芯片半导体、智能硬件、自动驾驶\n五大核心赛道，累计陪伴了28家独角兽、7家上市公司成长。\n这张图已经不只是投资，更像是\n一张覆盖了从底层算力到上层应用的完整AI产业链图谱。\n图片来源：公开查询\n02\n美团的科技牌\n聊美团的硬科技投资，先得从王兴说起。\n美团CEO王兴，现在被圈内人戏称为“中国具身智能第一投资人”。这个称呼不是白来的，在宇树科技B2轮融资时，估值才10亿元，美团就已经是领投方了，随后又继续加码B3轮、C1轮。\n等到腾讯、阿里、字节这些互联网巨头在2025年年中密集入场的时候，宇树的估值已经飙到了120亿。也就是说，当别人花高价买“防御性门票”的时候，美团已经在这个牌桌上坐了一年半。\n这种“早到”的节奏贯穿了美团整个投资版图。在具身智能赛道，美团至少投资了16家企业，其中10家估值已超10亿美元。\n在芯片算力层\n，美团投了摩尔线程、沐曦股份、紫光展锐、爱芯智元、荣芯半导体等一大批企业，覆盖了国内GPU头部和“国家队”级别的半导体公司。\n在AI大模型领域\n，美团既是智谱AI的早期股东，又在A1轮重仓月之暗面，顺带覆盖了AIGC3D、视频Agent等一堆细分方向。\n美团对硬科技的投资，核心逻辑其实很简单：芯片算力是底层基建，AI是应用，自动驾驶是连接，具身智能是执行。这四个赛道层层递进，形成了一个从数字世界到物理世界的完整闭环。\n这套投资逻辑或许也值得当下很多VC/PE机构借鉴。\n说得再直白一点，美团的业务场景太“接地气”了，外卖配送、仓储分拣、线下零售，每一个环节都对效率和自动化有着极其迫切的需求。与其等技术成熟了再去买，不如在技术还只有实验室雏形的时候，就直接坐在研发桌上。\n03\n到底投了多少？\n笔者根据公开查询，基于可查询到的数据（可能不全），把美团核心投资布局整理了一个表格：\n数据来源：公开查询\n这个清单远没完。普渡科技、高仙机器人、未来机器人、法奥机器人，还有快手、Shein、水滴公司、众安在线、贝壳……\n美团这些年投的企业，横跨了硬科技和本地生活的几乎每一个角落。\n04\n遍地开花，却喜忧参半\n有件事说起来挺讽刺的。\n美团投的那些硬科技公司，这两年一个接一个地敲钟上市，\n账面回报相当可观。\n可美团自己的核心业务却在2025年遭遇了史上最惨烈的“外卖大战”，一年亏掉234亿。\n一边是投资版图的科技公司批量IPO，一边是主业被对手按在地上摩擦。腾讯也在今年1月的年度员工大会上宣布，已经完全退出了对美团的战略投资。\n这其实是理解美团现在处境最好的切面，它在做一件极其矛盾的事情：\n一边在战壕里跟对手拼刺刀、烧钱保份额，一边又把自己变成了全中国最活跃的硬科技产业投资人。\n王兴在2025年的财报电话会上给了一个说法：“我们对AI的策略是进攻而不是防守。”\n翻译一下就是：外卖大战再惨，也只是短期的事。\n美团真正要打的仗，是在未来的物理世界AI底座上。美团2025年的研发投入达到260亿元，同比增长23.5%，重点砸向了AI大模型和具身智能。\n260亿元，这个数字，已经超过了绝大多数A股上市公司的全年营收。\n05\n收购叮咚，补上生鲜的最后一块拼图\n2026年2月5日，美团甩出一张50亿的支票，以7.17亿美元全资收购了叮咚买菜的中国业务。\n这笔交易带来了什么？1000余个前置仓、超700万月活用户，以及叮咚深耕了近9年的产地直采供应链。\n最关键的是，叮咚已经连续12个季度实现盈利，在生鲜这个公认的“烧钱无底洞”里跑通了商业模型。\n说实话，美团在生鲜这件事上没少走弯路。2018年搞过小象生鲜线下大店，运营成本太高，一年后就关了。后来转向前置仓做美团买菜，2023年升级成小象超市。这次直接买下叮咚，等于用钱把时间和经验差一次性补齐了。\n但更值得琢磨的是这笔收购背后的信号，当竞争对手还在拼命砸补贴抢用户的时候，美团已经开始系统性整合供应链和基础设施了。即时零售这个赛道，正在从“谁能烧钱”切换到“谁能提效”的新阶段。\n06\n接下来会怎样？\n展望2026年，笔者认为，几个关键节点值得关注。\n第一，\n外卖大战的退潮速度。如果行业能真正回归理性竞争\n，美团的核心本地商业有望在2026年下半年重回盈利通道。\n第二，\n被投企业的变现节奏\n。智谱AI已经上市，宇树科技即将IPO，摩尔线程、沐曦股份也都完成了上市，这些标的的退出能给美团带来多少账面收益，值得关注。\n但更重要的是，这些技术能不能反哺美团自己的业务。目前美团AI商家经营助手已经服务了超340万商户，AI助手“小团”在春节期间服务了过亿用户。如果能把这些技术能力转化成实实在在的效率和成本优势，那才是真金白银。\n第三，\n出海能否成为第二增长曲线\n。Keeta在中东的扩张还在继续，虽然短期亏损难免，但王兴的表态很明确——新业务分部的整体亏损不会超过2025年。\n对于现在的美团来说，2025年的亏损更像是在为未来“交学费”。这张学费账单虽然贵，一年592亿的利润蒸发，但换来的是一个横跨五大硬科技赛道、覆盖50多家独角兽的投资版图。\n王兴是不是在押注一个别人还看不清的未来？\n这个问题，可能再过两三年才会有答案。\n但有一点已经可以确定：\n当我们以为美团只是一个送外卖的平台时，它已经在悄悄变成一家科技投资机构了。\n‍本文来自微信公众号\n“投行圈子”\n，作者：投行大师姐，36氪经授权发布。', '2026-04-16 12:44:42', '2026-04-16 13:42:12');
INSERT INTO `news_detail` VALUES (48, 1473, 8, '新能源与汽车', '刚刚，诞生一笔210亿回报', '', '<p>4月16日，“全球可堆叠分布式光储第一股”思格新能源正式登陆港交所，每股发行价324.2港元，开盘涨幅近80%，市值突破1433.89亿港元（约1248亿元人民币），同时，成立不足四年的思格新能源也创下了中国储能企业最快IPO的纪录。</p>\n<p>这个速度是什么概念？“户储第一股”派能科技从成立到上市用了11年，逆变器龙头阳光电源走了14年。思格新能源的时间表，压缩了至少三分之二。</p>\n<p>其实，思格新能源上市第一天的表现并不让人意外，早在前几天的招股阶段，它拿下超额认购近800倍的成绩。其背后的资方同样豪华，淡马锡、高盛资管、瑞银资管、高瓴、欧力士、景林、博裕、太平洋保险等在内的19家世界顶级投行悉数集结。</p>\n<p>其中，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\n<p>如果时间拉得更长，思格新能源还是最快实现1亿美元营收的中国储能企业。而这种种成绩背后是印刻在思格新能源身上的两个明显标签：华为与全球化。</p>\n<h2><strong>华为23年，从无线到光伏再到AI</strong></h2>\n<p>故事要从许映童的华为生涯说起。</p>\n<p>1999年，许映童加入华为。此后的23年里，他经历了华为最波澜壮阔的发展阶段。在无线产品线，他做过 PDT 经理，管过无线软件平台，担任过华为无线杭州研究所所长。</p>\n<p>2010年底，许映童从通信领域转岗至新能源领域，后来华为决定进军智能光伏业务，许映童被委以重任，出任智能光伏业务总裁。</p>\n<p>这是一次从零开始的创业。当时华为在逆变器领域毫无积累，面对的是在行业深耕多年的对手。许映童带领团队埋头研发，终于在2015年，登顶全球逆变器出货量榜首，并且连续七年保持这个位置。</p>\n<p>2020年，许映童又接到了新任务，负责华为昇腾人工智能计算业务。这是华为在AI芯片领域的关键布局，需要既懂硬件又懂软件、既有产品经验又有战略视野的一号位。不过，许映童在昇腾待得时间并不长，仅两年后，他的身份就变为了思格新能源创始人。</p>\n<p>2022年5月，思格新能源在上海注册成立，主营分布式储能系统（DESS），意味着这位华为老兵正式踏上了创业之路。</p>\n<p>当时的许映童之于储能市场是怎样的存在呢？用一个相对贴切的类比，可能就是大模型领域的闫俊杰。</p>\n<p>一个细节是，刚离开华为时，储能方向只是许映童众多创业选项中的一个。在这期间，他与高瓴进行了长期、深入的交流，最终双方形成了高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。</p>\n<p>许映童与高瓴在创业早期的关系，也从某种程度上决定了高瓴成为其最大、最早外部股东的结果。</p>\n<p>跟许映童一起离开华为的，还有华为智能光伏前副总裁张先淼，他拥有17年以上的光伏及储能系统行业经验，加入思格新能源后，他出任执行董事兼总裁，全面负责公司产品研发、规划及供应链管理。</p>\n<p>不止如此。思格新能源的创始团队中，还有多位华为旧部：监事会主席刘秦维、全球品牌总监杨顺霞，软件、渠道等各条线的骨干也陆续到位，这几乎是一个完整的作战班底整体迁移。也难怪有人戏称许映童是“最会挖华为墙脚”的人。</p>\n<p>资本市场对大厂人才向来偏爱，更不用说是这样成熟的华为班底了。</p>\n<p>根据招股书可以看到，2022年6月，也就是刚注册成立1个月，思格新能源拿到了500万元的种子轮，该轮投资方为上海煜菘和捷沣科技，投后估值为1亿元。同年7月，高瓴创投就出现在A1轮融资名单上。到年底，思格新能源完成了A1到A3轮，共5.4亿元融资，估值也从1亿元飙升至了27亿元。</p>\n<p>要知道，这时候的思格新能源还没有任何产品上市，2022年全年营收为零，净亏损7620 万元。</p>\n<p>在宏观环境上，2022年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间。据透露，在早期高瓴积极帮助思格引入了云辉、钟鼎等产业方和财务投资人，完成多轮关键融资。</p>\n<h2><strong>两年营收增长154倍</strong></h2>\n<p>开篇提到思格新能源区别于其他竞争对手最明显的标签就是华为班底和全球化，可以看到，在早期，资本向思格新能源投出橄榄枝，还是基于VC传统的投人逻辑。</p>\n<p>不过，在产品问世之后，整个的估值逻辑就变得更理性和商业了，这之中全球化的重要性就显示出来了。</p>\n<p>2023年6月，思格新能源在德国慕尼黑EES Europe展会上推出了首款产品SigenStor，这是全球首款五合一光储充一体机，即把光伏逆变器、储能变流器、储能电池、直流充电模块、能量管理系统（EMS）五大模块集成在了一起，让用户根据实际情况灵活配置和扩展。</p>\n<p>除了这个明显的卖点外，思格新能源还为这款产品配备了AI辅助节能和安装维护。其对外宣称，户储产品配套的mySigen App是能源行业内首个集成GPT-4能力的App。</p>\n<p>依托于这款产品，思格新能源正式开启了商业化之路。</p>\n<p>不过2023年时，它的收入只有5830万人民币，亏损也进一步扩大为3.73亿元。也是在这一年，思格新能源先后完成了B轮系列融资，包括1.4亿元B轮融资，投资方为余杭国投集团、国核投资等，以及天堂硅谷独家投资的3000万元B1轮融资。而B1轮融资也成为了其IPO前的最后一轮融资，当时思格新能源的估值为41.7亿元。</p>\n<p>到2025年，思格新能源的营收规模大跃进般地突破了90亿元，实现了两年增长154倍的神话。除了营收之外，思格的毛利率也在一路上涨，并在2025年飙升至了50.1%。需要指出的是，SigenStor连续三年贡献总收入90%以上，分销渠道占比超过97%，</p>\n<p>拆解来看，2023年、2024年及截至2025年9月30日止，思格新能源来自海外市场的收入分别占总营收的87.8%、95.2%及99.3%。</p>\n<p>在地区分布上，亚太和欧洲是思格新能源2025年海外收入的主要来源，其次为非洲、中东、中亚、拉丁美洲及北美洲。前五大单一市场依次为：澳大利亚（42.6%）、德国（10.2%）、瑞典（6.9%）、爱尔兰（5.1%）、比利时（3.5%）。</p>\n<p>据招股书，截至2025年底，思格业务覆盖全球85个国家和地区，与172家分销商建立了深度合作。拥有1.7万家以上的注册安装商，占二级分销商90%以上。</p>\n<p>一个微妙的变化是，2025年初，思格新能源第一次递交招股书时，其业务覆盖范围为60多个国家和地区，合作分销商99个，拥有5600多家注册安装商。对比来看，短短一年时间，思格新能源全球拓展分销商数量新增了73家，注册安装商增加逾1.1万家。</p>\n<p>此外，按产品出货量计，思格新能源2024年已位居“可堆叠分布式光储一体机”全球第一，市场份额为28.6%。在更广阔的户储市场，它也一跃成为全球户储系统出货量第五名，仅次于Tesla、华为、比亚迪储能、阳光电源等一众巨头。</p>\n<h2><strong>高瓴获得超200亿回报</strong></h2>\n<p>正是基于这样财务数据带来的底气，思格新能源在2025年曾两次递表港交所，不过均未冲击成功，好在，如今顺利登陆港股。</p>\n<p>由于IPO前，思格新能源仅进行了六轮融资，所以其股权结构相对清晰，创始团队对公司拥有绝对的话语权。上市前，许映童拥有49.28%的投票权，而张先淼持股超过11%。此外，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\n<p>4月初思格新能源启动招股时，高瓴又以基石投资者身份再度入场，通过HHLR Advisors认购1400万美元，通过Hillhouse Investment Management认购700万美元，合计2100万美元。</p>\n<p>其实，把视角拉远，会发现思格新能源只是高瓴新能源版图中的最新一块拼图。</p>\n<p>过去五年，高瓴一直在持续重仓新能源，根据投中嘉川CVSource显示，最近五年高瓴在新能源领域出手36次。</p>\n<p>2022年6月高瓴官宣了首只总规模逾40亿元人民币的碳中和产业投资基金，明确表示将重点投向新能源、新材料等绿色技术领域。</p>\n<p>在产业链布局上，不管是上游的电池材料、中游的电池制造还是下游的整车企业以及充电基础设施和储能系统，高瓴几乎覆盖了新能源产业的每一个关键环节。</p>\n<p>在这种强大生态圈的助力下，高瓴对思格新能源的帮助并没有停留在给钱层面，而是主动把多年积累的产业资源开放给思格，在电池侧，对接宁德时代，帮助思格在产能最紧缺时期获得稳定供应；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供。</p>\n<p>如今伴随着储能市场需求的崛起，高瓴的投资也步入了收获期。</p>\n<p>抛开基石轮，如果以每股324.20港元的发行价计算，思格新能源将募资超44亿港元，IPO市值将超800亿港元，高瓴的持股市值将达到119.1亿港元。而按照开盘市值1433亿港元来计算，高瓴这笔IPO的账面回报则超过了200亿元。</p>\n<p>思格新能源创始人许映童表示，“创业路上，最难的不是拿到第一笔钱，而是在最不确定的时刻，依然有人坚定地选择相信你。我们起步于市场极富挑战的时期，是高瓴坚定看好，在产业资源紧张的关头，高瓴开放了他们长期积累的生态能力，帮助我们跨越了早期创业公司的生存门槛。”</p>\n<p>短短几年间，新能源经历了大起大落，但没人否认，被大浪淘沙后的项目正在成为市场新宠，并开启了新一轮的资本盛宴。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/HX5YrQbkGb65IkYMz9PWUw\">“投中网”</a>，作者：张雪，36氪经授权发布。</p>', 'https://36kr.com/p/3768962317943554?f=rss', 0, '', '{\"summary\": \"本文分享出海储能创业企业思格新能源快速IPO的成功案例，为新能源出海创业及投资提供参考\", \"abstract\": \"由华为前核心高管创办的思格新能源，成立不足四年便登陆港交所，创下中国储能企业最快IPO纪录。思格主打全球化分布式光储产品，目前营收99.3%来自海外市场，业务覆盖全球85个国家和地区，可堆叠分布式光储一体机出货量位居全球第一。高瓴作为思格最早最大的外部投资方，不仅提供资金支持，还开放自身产业资源帮助思格解决早期供应链难题，本次IPO获得超200亿人民币账面回报。该案例展现了全球储能需求下，新能源出海创业赛道的巨大潜力。\", \"keywords\": [\"新能源出海\", \"储能\", \"光储一体机\", \"全球化\", \"IPO\", \"海外营收\", \"分布式储能\", \"高瓴\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3768962317943554?f=rss\", \"title\": \"刚刚，诞生一笔210亿回报\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>4月16日，“全球可堆叠分布式光储第一股”思格新能源正式登陆港交所，每股发行价324.2港元，开盘涨幅近80%，市值突破1433.89亿港元（约1248亿元人民币），同时，成立不足四年的思格新能源也创下了中国储能企业最快IPO的纪录。</p>\\n<p>这个速度是什么概念？“户储第一股”派能科技从成立到上市用了11年，逆变器龙头阳光电源走了14年。思格新能源的时间表，压缩了至少三分之二。</p>\\n<p>其实，思格新能源上市第一天的表现并不让人意外，早在前几天的招股阶段，它拿下超额认购近800倍的成绩。其背后的资方同样豪华，淡马锡、高盛资管、瑞银资管、高瓴、欧力士、景林、博裕、太平洋保险等在内的19家世界顶级投行悉数集结。</p>\\n<p>其中，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\\n<p>如果时间拉得更长，思格新能源还是最快实现1亿美元营收的中国储能企业。而这种种成绩背后是印刻在思格新能源身上的两个明显标签：华为与全球化。</p>\\n<h2><strong>华为23年，从无线到光伏再到AI</strong></h2>\\n<p>故事要从许映童的华为生涯说起。</p>\\n<p>1999年，许映童加入华为。此后的23年里，他经历了华为最波澜壮阔的发展阶段。在无线产品线，他做过 PDT 经理，管过无线软件平台，担任过华为无线杭州研究所所长。</p>\\n<p>2010年底，许映童从通信领域转岗至新能源领域，后来华为决定进军智能光伏业务，许映童被委以重任，出任智能光伏业务总裁。</p>\\n<p>这是一次从零开始的创业。当时华为在逆变器领域毫无积累，面对的是在行业深耕多年的对手。许映童带领团队埋头研发，终于在2015年，登顶全球逆变器出货量榜首，并且连续七年保持这个位置。</p>\\n<p>2020年，许映童又接到了新任务，负责华为昇腾人工智能计算业务。这是华为在AI芯片领域的关键布局，需要既懂硬件又懂软件、既有产品经验又有战略视野的一号位。不过，许映童在昇腾待得时间并不长，仅两年后，他的身份就变为了思格新能源创始人。</p>\\n<p>2022年5月，思格新能源在上海注册成立，主营分布式储能系统（DESS），意味着这位华为老兵正式踏上了创业之路。</p>\\n<p>当时的许映童之于储能市场是怎样的存在呢？用一个相对贴切的类比，可能就是大模型领域的闫俊杰。</p>\\n<p>一个细节是，刚离开华为时，储能方向只是许映童众多创业选项中的一个。在这期间，他与高瓴进行了长期、深入的交流，最终双方形成了高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。</p>\\n<p>许映童与高瓴在创业早期的关系，也从某种程度上决定了高瓴成为其最大、最早外部股东的结果。</p>\\n<p>跟许映童一起离开华为的，还有华为智能光伏前副总裁张先淼，他拥有17年以上的光伏及储能系统行业经验，加入思格新能源后，他出任执行董事兼总裁，全面负责公司产品研发、规划及供应链管理。</p>\\n<p>不止如此。思格新能源的创始团队中，还有多位华为旧部：监事会主席刘秦维、全球品牌总监杨顺霞，软件、渠道等各条线的骨干也陆续到位，这几乎是一个完整的作战班底整体迁移。也难怪有人戏称许映童是“最会挖华为墙脚”的人。</p>\\n<p>资本市场对大厂人才向来偏爱，更不用说是这样成熟的华为班底了。</p>\\n<p>根据招股书可以看到，2022年6月，也就是刚注册成立1个月，思格新能源拿到了500万元的种子轮，该轮投资方为上海煜菘和捷沣科技，投后估值为1亿元。同年7月，高瓴创投就出现在A1轮融资名单上。到年底，思格新能源完成了A1到A3轮，共5.4亿元融资，估值也从1亿元飙升至了27亿元。</p>\\n<p>要知道，这时候的思格新能源还没有任何产品上市，2022年全年营收为零，净亏损7620 万元。</p>\\n<p>在宏观环境上，2022年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间。据透露，在早期高瓴积极帮助思格引入了云辉、钟鼎等产业方和财务投资人，完成多轮关键融资。</p>\\n<h2><strong>两年营收增长154倍</strong></h2>\\n<p>开篇提到思格新能源区别于其他竞争对手最明显的标签就是华为班底和全球化，可以看到，在早期，资本向思格新能源投出橄榄枝，还是基于VC传统的投人逻辑。</p>\\n<p>不过，在产品问世之后，整个的估值逻辑就变得更理性和商业了，这之中全球化的重要性就显示出来了。</p>\\n<p>2023年6月，思格新能源在德国慕尼黑EES Europe展会上推出了首款产品SigenStor，这是全球首款五合一光储充一体机，即把光伏逆变器、储能变流器、储能电池、直流充电模块、能量管理系统（EMS）五大模块集成在了一起，让用户根据实际情况灵活配置和扩展。</p>\\n<p>除了这个明显的卖点外，思格新能源还为这款产品配备了AI辅助节能和安装维护。其对外宣称，户储产品配套的mySigen App是能源行业内首个集成GPT-4能力的App。</p>\\n<p>依托于这款产品，思格新能源正式开启了商业化之路。</p>\\n<p>不过2023年时，它的收入只有5830万人民币，亏损也进一步扩大为3.73亿元。也是在这一年，思格新能源先后完成了B轮系列融资，包括1.4亿元B轮融资，投资方为余杭国投集团、国核投资等，以及天堂硅谷独家投资的3000万元B1轮融资。而B1轮融资也成为了其IPO前的最后一轮融资，当时思格新能源的估值为41.7亿元。</p>\\n<p>到2025年，思格新能源的营收规模大跃进般地突破了90亿元，实现了两年增长154倍的神话。除了营收之外，思格的毛利率也在一路上涨，并在2025年飙升至了50.1%。需要指出的是，SigenStor连续三年贡献总收入90%以上，分销渠道占比超过97%，</p>\\n<p>拆解来看，2023年、2024年及截至2025年9月30日止，思格新能源来自海外市场的收入分别占总营收的87.8%、95.2%及99.3%。</p>\\n<p>在地区分布上，亚太和欧洲是思格新能源2025年海外收入的主要来源，其次为非洲、中东、中亚、拉丁美洲及北美洲。前五大单一市场依次为：澳大利亚（42.6%）、德国（10.2%）、瑞典（6.9%）、爱尔兰（5.1%）、比利时（3.5%）。</p>\\n<p>据招股书，截至2025年底，思格业务覆盖全球85个国家和地区，与172家分销商建立了深度合作。拥有1.7万家以上的注册安装商，占二级分销商90%以上。</p>\\n<p>一个微妙的变化是，2025年初，思格新能源第一次递交招股书时，其业务覆盖范围为60多个国家和地区，合作分销商99个，拥有5600多家注册安装商。对比来看，短短一年时间，思格新能源全球拓展分销商数量新增了73家，注册安装商增加逾1.1万家。</p>\\n<p>此外，按产品出货量计，思格新能源2024年已位居“可堆叠分布式光储一体机”全球第一，市场份额为28.6%。在更广阔的户储市场，它也一跃成为全球户储系统出货量第五名，仅次于Tesla、华为、比亚迪储能、阳光电源等一众巨头。</p>\\n<h2><strong>高瓴获得超200亿回报</strong></h2>\\n<p>正是基于这样财务数据带来的底气，思格新能源在2025年曾两次递表港交所，不过均未冲击成功，好在，如今顺利登陆港股。</p>\\n<p>由于IPO前，思格新能源仅进行了六轮融资，所以其股权结构相对清晰，创始团队对公司拥有绝对的话语权。上市前，许映童拥有49.28%的投票权，而张先淼持股超过11%。此外，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\\n<p>4月初思格新能源启动招股时，高瓴又以基石投资者身份再度入场，通过HHLR Advisors认购1400万美元，通过Hillhouse Investment Management认购700万美元，合计2100万美元。</p>\\n<p>其实，把视角拉远，会发现思格新能源只是高瓴新能源版图中的最新一块拼图。</p>\\n<p>过去五年，高瓴一直在持续重仓新能源，根据投中嘉川CVSource显示，最近五年高瓴在新能源领域出手36次。</p>\\n<p>2022年6月高瓴官宣了首只总规模逾40亿元人民币的碳中和产业投资基金，明确表示将重点投向新能源、新材料等绿色技术领域。</p>\\n<p>在产业链布局上，不管是上游的电池材料、中游的电池制造还是下游的整车企业以及充电基础设施和储能系统，高瓴几乎覆盖了新能源产业的每一个关键环节。</p>\\n<p>在这种强大生态圈的助力下，高瓴对思格新能源的帮助并没有停留在给钱层面，而是主动把多年积累的产业资源开放给思格，在电池侧，对接宁德时代，帮助思格在产能最紧缺时期获得稳定供应；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供。</p>\\n<p>如今伴随着储能市场需求的崛起，高瓴的投资也步入了收获期。</p>\\n<p>抛开基石轮，如果以每股324.20港元的发行价计算，思格新能源将募资超44亿港元，IPO市值将超800亿港元，高瓴的持股市值将达到119.1亿港元。而按照开盘市值1433亿港元来计算，高瓴这笔IPO的账面回报则超过了200亿元。</p>\\n<p>思格新能源创始人许映童表示，“创业路上，最难的不是拿到第一笔钱，而是在最不确定的时刻，依然有人坚定地选择相信你。我们起步于市场极富挑战的时期，是高瓴坚定看好，在产业资源紧张的关头，高瓴开放了他们长期积累的生态能力，帮助我们跨越了早期创业公司的生存门槛。”</p>\\n<p>短短几年间，新能源经历了大起大落，但没人否认，被大浪淘沙后的项目正在成为市场新宠，并开启了新一轮的资本盛宴。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/HX5YrQbkGb65IkYMz9PWUw\\\">“投中网”</a>，作者：张雪，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'刚刚，诞生一笔210亿回报\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'刚刚，诞生一笔210亿回报\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768962317943554?f=rss\'}], \'link\': \'https://36kr.com/p/3768962317943554?f=rss\', \'published\': \'2026-04-16 12:45:39  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=4, tm_min=45, tm_sec=39, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>4月16日，“全球可堆叠分布式光储第一股”思格新能源正式登陆港交所，每股发行价324.2港元，开盘涨幅近80%，市值突破1433.89亿港元（约1248亿元人民币），同时，成立不足四年的思格新能源也创下了中国储能企业最快IPO的纪录。</p>\\\\n  <p>这个速度是什么概念？“户储第一股”派能科技从成立到上市用了11年，逆变器龙头阳光电源走了14年。思格新能源的时间表，压缩了至少三分之二。</p>\\\\n  <p>其实，思格新能源上市第一天的表现并不让人意外，早在前几天的招股阶段，它拿下超额认购近800倍的成绩。其背后的资方同样豪华，淡马锡、高盛资管、瑞银资管、高瓴、欧力士、景林、博裕、太平洋保险等在内的19家世界顶级投行悉数集结。</p>\\\\n  <p>其中，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\\\\n  <p>如果时间拉得更长，思格新能源还是最快实现1亿美元营收的中国储能企业。而这种种成绩背后是印刻在思格新能源身上的两个明显标签：华为与全球化。</p>\\\\n  <h2><strong>华为23年，从无线到光伏再到AI</strong></h2>\\\\n  <p>故事要从许映童的华为生涯说起。</p>\\\\n  <p>1999年，许映童加入华为。此后的23年里，他经历了华为最波澜壮阔的发展阶段。在无线产品线，他做过&nbsp;PDT&nbsp;经理，管过无线软件平台，担任过华为无线杭州研究所所长。</p>\\\\n  <p>2010年底，许映童从通信领域转岗至新能源领域，后来华为决定进军智能光伏业务，许映童被委以重任，出任智能光伏业务总裁。</p>\\\\n  <p>这是一次从零开始的创业。当时华为在逆变器领域毫无积累，面对的是在行业深耕多年的对手。许映童带领团队埋头研发，终于在2015年，登顶全球逆变器出货量榜首，并且连续七年保持这个位置。</p>\\\\n  <p>2020年，许映童又接到了新任务，负责华为昇腾人工智能计算业务。这是华为在AI芯片领域的关键布局，需要既懂硬件又懂软件、既有产品经验又有战略视野的一号位。不过，许映童在昇腾待得时间并不长，仅两年后，他的身份就变为了思格新能源创始人。</p>\\\\n  <p>2022年5月，思格新能源在上海注册成立，主营分布式储能系统（DESS），意味着这位华为老兵正式踏上了创业之路。</p>\\\\n  <p>当时的许映童之于储能市场是怎样的存在呢？用一个相对贴切的类比，可能就是大模型领域的闫俊杰。</p>\\\\n  <p>一个细节是，刚离开华为时，储能方向只是许映童众多创业选项中的一个。在这期间，他与高瓴进行了长期、深入的交流，最终双方形成了高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。</p>\\\\n  <p>许映童与高瓴在创业早期的关系，也从某种程度上决定了高瓴成为其最大、最早外部股东的结果。</p>\\\\n  <p>跟许映童一起离开华为的，还有华为智能光伏前副总裁张先淼，他拥有17年以上的光伏及储能系统行业经验，加入思格新能源后，他出任执行董事兼总裁，全面负责公司产品研发、规划及供应链管理。</p>\\\\n  <p>不止如此。思格新能源的创始团队中，还有多位华为旧部：监事会主席刘秦维、全球品牌总监杨顺霞，软件、渠道等各条线的骨干也陆续到位，这几乎是一个完整的作战班底整体迁移。也难怪有人戏称许映童是“最会挖华为墙脚”的人。</p>\\\\n  <p>资本市场对大厂人才向来偏爱，更不用说是这样成熟的华为班底了。</p>\\\\n  <p>根据招股书可以看到，2022年6月，也就是刚注册成立1个月，思格新能源拿到了500万元的种子轮，该轮投资方为上海煜菘和捷沣科技，投后估值为1亿元。同年7月，高瓴创投就出现在A1轮融资名单上。到年底，思格新能源完成了A1到A3轮，共5.4亿元融资，估值也从1亿元飙升至了27亿元。</p>\\\\n  <p>要知道，这时候的思格新能源还没有任何产品上市，2022年全年营收为零，净亏损7620&nbsp;万元。</p>\\\\n  <p>在宏观环境上，2022年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间。据透露，在早期高瓴积极帮助思格引入了云辉、钟鼎等产业方和财务投资人，完成多轮关键融资。</p>\\\\n  <h2><strong>两年营收增长154倍</strong></h2>\\\\n  <p>开篇提到思格新能源区别于其他竞争对手最明显的标签就是华为班底和全球化，可以看到，在早期，资本向思格新能源投出橄榄枝，还是基于VC传统的投人逻辑。</p>\\\\n  <p>不过，在产品问世之后，整个的估值逻辑就变得更理性和商业了，这之中全球化的重要性就显示出来了。</p>\\\\n  <p>2023年6月，思格新能源在德国慕尼黑EES Europe展会上推出了首款产品SigenStor，这是全球首款五合一光储充一体机，即把光伏逆变器、储能变流器、储能电池、直流充电模块、能量管理系统（EMS）五大模块集成在了一起，让用户根据实际情况灵活配置和扩展。</p>\\\\n  <p>除了这个明显的卖点外，思格新能源还为这款产品配备了AI辅助节能和安装维护。其对外宣称，户储产品配套的mySigen App是能源行业内首个集成GPT-4能力的App。</p>\\\\n  <p>依托于这款产品，思格新能源正式开启了商业化之路。</p>\\\\n  <p>不过2023年时，它的收入只有5830万人民币，亏损也进一步扩大为3.73亿元。也是在这一年，思格新能源先后完成了B轮系列融资，包括1.4亿元B轮融资，投资方为余杭国投集团、国核投资等，以及天堂硅谷独家投资的3000万元B1轮融资。而B1轮融资也成为了其IPO前的最后一轮融资，当时思格新能源的估值为41.7亿元。</p>\\\\n  <p>到2025年，思格新能源的营收规模大跃进般地突破了90亿元，实现了两年增长154倍的神话。除了营收之外，思格的毛利率也在一路上涨，并在2025年飙升至了50.1%。需要指出的是，SigenStor连续三年贡献总收入90%以上，分销渠道占比超过97%，</p>\\\\n  <p>拆解来看，2023年、2024年及截至2025年9月30日止，思格新能源来自海外市场的收入分别占总营收的87.8%、95.2%及99.3%。</p>\\\\n  <p>在地区分布上，亚太和欧洲是思格新能源2025年海外收入的主要来源，其次为非洲、中东、中亚、拉丁美洲及北美洲。前五大单一市场依次为：澳大利亚（42.6%）、德国（10.2%）、瑞典（6.9%）、爱尔兰（5.1%）、比利时（3.5%）。</p>\\\\n  <p>据招股书，截至2025年底，思格业务覆盖全球85个国家和地区，与172家分销商建立了深度合作。拥有1.7万家以上的注册安装商，占二级分销商90%以上。</p>\\\\n  <p>一个微妙的变化是，2025年初，思格新能源第一次递交招股书时，其业务覆盖范围为60多个国家和地区，合作分销商99个，拥有5600多家注册安装商。对比来看，短短一年时间，思格新能源全球拓展分销商数量新增了73家，注册安装商增加逾1.1万家。</p>\\\\n  <p>此外，按产品出货量计，思格新能源2024年已位居“可堆叠分布式光储一体机”全球第一，市场份额为28.6%。在更广阔的户储市场，它也一跃成为全球户储系统出货量第五名，仅次于Tesla、华为、比亚迪储能、阳光电源等一众巨头。</p>\\\\n  <h2><strong>高瓴获得超200亿回报</strong></h2>\\\\n  <p>正是基于这样财务数据带来的底气，思格新能源在2025年曾两次递表港交所，不过均未冲击成功，好在，如今顺利登陆港股。</p>\\\\n  <p>由于IPO前，思格新能源仅进行了六轮融资，所以其股权结构相对清晰，创始团队对公司拥有绝对的话语权。上市前，许映童拥有49.28%的投票权，而张先淼持股超过11%。此外，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\\\\n  <p>4月初思格新能源启动招股时，高瓴又以基石投资者身份再度入场，通过HHLR Advisors认购1400万美元，通过Hillhouse Investment Management认购700万美元，合计2100万美元。</p>\\\\n  <p>其实，把视角拉远，会发现思格新能源只是高瓴新能源版图中的最新一块拼图。</p>\\\\n  <p>过去五年，高瓴一直在持续重仓新能源，根据投中嘉川CVSource显示，最近五年高瓴在新能源领域出手36次。</p>\\\\n  <p>2022年6月高瓴官宣了首只总规模逾40亿元人民币的碳中和产业投资基金，明确表示将重点投向新能源、新材料等绿色技术领域。</p>\\\\n  <p>在产业链布局上，不管是上游的电池材料、中游的电池制造还是下游的整车企业以及充电基础设施和储能系统，高瓴几乎覆盖了新能源产业的每一个关键环节。</p>\\\\n  <p>在这种强大生态圈的助力下，高瓴对思格新能源的帮助并没有停留在给钱层面，而是主动把多年积累的产业资源开放给思格，在电池侧，对接宁德时代，帮助思格在产能最紧缺时期获得稳定供应；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供。</p>\\\\n  <p>如今伴随着储能市场需求的崛起，高瓴的投资也步入了收获期。</p>\\\\n  <p>抛开基石轮，如果以每股324.20港元的发行价计算，思格新能源将募资超44亿港元，IPO市值将超800亿港元，高瓴的持股市值将达到119.1亿港元。而按照开盘市值1433亿港元来计算，高瓴这笔IPO的账面回报则超过了200亿元。</p>\\\\n  <p>思格新能源创始人许映童表示，“创业路上，最难的不是拿到第一笔钱，而是在最不确定的时刻，依然有人坚定地选择相信你。我们起步于市场极富挑战的时期，是高瓴坚定看好，在产业资源紧张的关头，高瓴开放了他们长期积累的生态能力，帮助我们跨越了早期创业公司的生存门槛。”</p>\\\\n  <p>短短几年间，新能源经历了大起大落，但没人否认，被大浪淘沙后的项目正在成为市场新宠，并开启了新一轮的资本盛宴。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/HX5YrQbkGb65IkYMz9PWUw\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“投中网”</a>，作者：张雪，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>4月16日，“全球可堆叠分布式光储第一股”思格新能源正式登陆港交所，每股发行价324.2港元，开盘涨幅近80%，市值突破1433.89亿港元（约1248亿元人民币），同时，成立不足四年的思格新能源也创下了中国储能企业最快IPO的纪录。</p>\\\\n  <p>这个速度是什么概念？“户储第一股”派能科技从成立到上市用了11年，逆变器龙头阳光电源走了14年。思格新能源的时间表，压缩了至少三分之二。</p>\\\\n  <p>其实，思格新能源上市第一天的表现并不让人意外，早在前几天的招股阶段，它拿下超额认购近800倍的成绩。其背后的资方同样豪华，淡马锡、高盛资管、瑞银资管、高瓴、欧力士、景林、博裕、太平洋保险等在内的19家世界顶级投行悉数集结。</p>\\\\n  <p>其中，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\\\\n  <p>如果时间拉得更长，思格新能源还是最快实现1亿美元营收的中国储能企业。而这种种成绩背后是印刻在思格新能源身上的两个明显标签：华为与全球化。</p>\\\\n  <h2><strong>华为23年，从无线到光伏再到AI</strong></h2>\\\\n  <p>故事要从许映童的华为生涯说起。</p>\\\\n  <p>1999年，许映童加入华为。此后的23年里，他经历了华为最波澜壮阔的发展阶段。在无线产品线，他做过&nbsp;PDT&nbsp;经理，管过无线软件平台，担任过华为无线杭州研究所所长。</p>\\\\n  <p>2010年底，许映童从通信领域转岗至新能源领域，后来华为决定进军智能光伏业务，许映童被委以重任，出任智能光伏业务总裁。</p>\\\\n  <p>这是一次从零开始的创业。当时华为在逆变器领域毫无积累，面对的是在行业深耕多年的对手。许映童带领团队埋头研发，终于在2015年，登顶全球逆变器出货量榜首，并且连续七年保持这个位置。</p>\\\\n  <p>2020年，许映童又接到了新任务，负责华为昇腾人工智能计算业务。这是华为在AI芯片领域的关键布局，需要既懂硬件又懂软件、既有产品经验又有战略视野的一号位。不过，许映童在昇腾待得时间并不长，仅两年后，他的身份就变为了思格新能源创始人。</p>\\\\n  <p>2022年5月，思格新能源在上海注册成立，主营分布式储能系统（DESS），意味着这位华为老兵正式踏上了创业之路。</p>\\\\n  <p>当时的许映童之于储能市场是怎样的存在呢？用一个相对贴切的类比，可能就是大模型领域的闫俊杰。</p>\\\\n  <p>一个细节是，刚离开华为时，储能方向只是许映童众多创业选项中的一个。在这期间，他与高瓴进行了长期、深入的交流，最终双方形成了高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。</p>\\\\n  <p>许映童与高瓴在创业早期的关系，也从某种程度上决定了高瓴成为其最大、最早外部股东的结果。</p>\\\\n  <p>跟许映童一起离开华为的，还有华为智能光伏前副总裁张先淼，他拥有17年以上的光伏及储能系统行业经验，加入思格新能源后，他出任执行董事兼总裁，全面负责公司产品研发、规划及供应链管理。</p>\\\\n  <p>不止如此。思格新能源的创始团队中，还有多位华为旧部：监事会主席刘秦维、全球品牌总监杨顺霞，软件、渠道等各条线的骨干也陆续到位，这几乎是一个完整的作战班底整体迁移。也难怪有人戏称许映童是“最会挖华为墙脚”的人。</p>\\\\n  <p>资本市场对大厂人才向来偏爱，更不用说是这样成熟的华为班底了。</p>\\\\n  <p>根据招股书可以看到，2022年6月，也就是刚注册成立1个月，思格新能源拿到了500万元的种子轮，该轮投资方为上海煜菘和捷沣科技，投后估值为1亿元。同年7月，高瓴创投就出现在A1轮融资名单上。到年底，思格新能源完成了A1到A3轮，共5.4亿元融资，估值也从1亿元飙升至了27亿元。</p>\\\\n  <p>要知道，这时候的思格新能源还没有任何产品上市，2022年全年营收为零，净亏损7620&nbsp;万元。</p>\\\\n  <p>在宏观环境上，2022年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间。据透露，在早期高瓴积极帮助思格引入了云辉、钟鼎等产业方和财务投资人，完成多轮关键融资。</p>\\\\n  <h2><strong>两年营收增长154倍</strong></h2>\\\\n  <p>开篇提到思格新能源区别于其他竞争对手最明显的标签就是华为班底和全球化，可以看到，在早期，资本向思格新能源投出橄榄枝，还是基于VC传统的投人逻辑。</p>\\\\n  <p>不过，在产品问世之后，整个的估值逻辑就变得更理性和商业了，这之中全球化的重要性就显示出来了。</p>\\\\n  <p>2023年6月，思格新能源在德国慕尼黑EES Europe展会上推出了首款产品SigenStor，这是全球首款五合一光储充一体机，即把光伏逆变器、储能变流器、储能电池、直流充电模块、能量管理系统（EMS）五大模块集成在了一起，让用户根据实际情况灵活配置和扩展。</p>\\\\n  <p>除了这个明显的卖点外，思格新能源还为这款产品配备了AI辅助节能和安装维护。其对外宣称，户储产品配套的mySigen App是能源行业内首个集成GPT-4能力的App。</p>\\\\n  <p>依托于这款产品，思格新能源正式开启了商业化之路。</p>\\\\n  <p>不过2023年时，它的收入只有5830万人民币，亏损也进一步扩大为3.73亿元。也是在这一年，思格新能源先后完成了B轮系列融资，包括1.4亿元B轮融资，投资方为余杭国投集团、国核投资等，以及天堂硅谷独家投资的3000万元B1轮融资。而B1轮融资也成为了其IPO前的最后一轮融资，当时思格新能源的估值为41.7亿元。</p>\\\\n  <p>到2025年，思格新能源的营收规模大跃进般地突破了90亿元，实现了两年增长154倍的神话。除了营收之外，思格的毛利率也在一路上涨，并在2025年飙升至了50.1%。需要指出的是，SigenStor连续三年贡献总收入90%以上，分销渠道占比超过97%，</p>\\\\n  <p>拆解来看，2023年、2024年及截至2025年9月30日止，思格新能源来自海外市场的收入分别占总营收的87.8%、95.2%及99.3%。</p>\\\\n  <p>在地区分布上，亚太和欧洲是思格新能源2025年海外收入的主要来源，其次为非洲、中东、中亚、拉丁美洲及北美洲。前五大单一市场依次为：澳大利亚（42.6%）、德国（10.2%）、瑞典（6.9%）、爱尔兰（5.1%）、比利时（3.5%）。</p>\\\\n  <p>据招股书，截至2025年底，思格业务覆盖全球85个国家和地区，与172家分销商建立了深度合作。拥有1.7万家以上的注册安装商，占二级分销商90%以上。</p>\\\\n  <p>一个微妙的变化是，2025年初，思格新能源第一次递交招股书时，其业务覆盖范围为60多个国家和地区，合作分销商99个，拥有5600多家注册安装商。对比来看，短短一年时间，思格新能源全球拓展分销商数量新增了73家，注册安装商增加逾1.1万家。</p>\\\\n  <p>此外，按产品出货量计，思格新能源2024年已位居“可堆叠分布式光储一体机”全球第一，市场份额为28.6%。在更广阔的户储市场，它也一跃成为全球户储系统出货量第五名，仅次于Tesla、华为、比亚迪储能、阳光电源等一众巨头。</p>\\\\n  <h2><strong>高瓴获得超200亿回报</strong></h2>\\\\n  <p>正是基于这样财务数据带来的底气，思格新能源在2025年曾两次递表港交所，不过均未冲击成功，好在，如今顺利登陆港股。</p>\\\\n  <p>由于IPO前，思格新能源仅进行了六轮融资，所以其股权结构相对清晰，创始团队对公司拥有绝对的话语权。上市前，许映童拥有49.28%的投票权，而张先淼持股超过11%。此外，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。</p>\\\\n  <p>4月初思格新能源启动招股时，高瓴又以基石投资者身份再度入场，通过HHLR Advisors认购1400万美元，通过Hillhouse Investment Management认购700万美元，合计2100万美元。</p>\\\\n  <p>其实，把视角拉远，会发现思格新能源只是高瓴新能源版图中的最新一块拼图。</p>\\\\n  <p>过去五年，高瓴一直在持续重仓新能源，根据投中嘉川CVSource显示，最近五年高瓴在新能源领域出手36次。</p>\\\\n  <p>2022年6月高瓴官宣了首只总规模逾40亿元人民币的碳中和产业投资基金，明确表示将重点投向新能源、新材料等绿色技术领域。</p>\\\\n  <p>在产业链布局上，不管是上游的电池材料、中游的电池制造还是下游的整车企业以及充电基础设施和储能系统，高瓴几乎覆盖了新能源产业的每一个关键环节。</p>\\\\n  <p>在这种强大生态圈的助力下，高瓴对思格新能源的帮助并没有停留在给钱层面，而是主动把多年积累的产业资源开放给思格，在电池侧，对接宁德时代，帮助思格在产能最紧缺时期获得稳定供应；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供。</p>\\\\n  <p>如今伴随着储能市场需求的崛起，高瓴的投资也步入了收获期。</p>\\\\n  <p>抛开基石轮，如果以每股324.20港元的发行价计算，思格新能源将募资超44亿港元，IPO市值将超800亿港元，高瓴的持股市值将达到119.1亿港元。而按照开盘市值1433亿港元来计算，高瓴这笔IPO的账面回报则超过了200亿元。</p>\\\\n  <p>思格新能源创始人许映童表示，“创业路上，最难的不是拿到第一笔钱，而是在最不确定的时刻，依然有人坚定地选择相信你。我们起步于市场极富挑战的时期，是高瓴坚定看好，在产业资源紧张的关头，高瓴开放了他们长期积累的生态能力，帮助我们跨越了早期创业公司的生存门槛。”</p>\\\\n  <p>短短几年间，新能源经历了大起大落，但没人否认，被大浪淘沙后的项目正在成为市场新宠，并开启了新一轮的资本盛宴。</p>\\\\n  <p class=\\\"editor-note\\\">本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/HX5YrQbkGb65IkYMz9PWUw\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“投中网”</a>，作者：张雪，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'36氪的朋友们\'}], \'author\': \'36氪的朋友们\', \'author_detail\': {\'name\': \'36氪的朋友们\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'新能源产业在大浪淘沙后，开启了新一轮的资本盛宴。\'}]}\", \"published_at\": \"2026-04-16 12:45:39\", \"ai_json_output\": \"\"}', '4月16日，“全球可堆叠分布式光储第一股”思格新能源正式登陆港交所，每股发行价324.2港元，开盘涨幅近80%，市值突破1433.89亿港元（约1248亿元人民币），同时，成立不足四年的思格新能源也创下了中国储能企业最快IPO的纪录。\n这个速度是什么概念？“户储第一股”派能科技从成立到上市用了11年，逆变器龙头阳光电源走了14年。思格新能源的时间表，压缩了至少三分之二。\n其实，思格新能源上市第一天的表现并不让人意外，早在前几天的招股阶段，它拿下超额认购近800倍的成绩。其背后的资方同样豪华，淡马锡、高盛资管、瑞银资管、高瓴、欧力士、景林、博裕、太平洋保险等在内的19家世界顶级投行悉数集结。\n其中，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。\n如果时间拉得更长，思格新能源还是最快实现1亿美元营收的中国储能企业。而这种种成绩背后是印刻在思格新能源身上的两个明显标签：华为与全球化。\n华为23年，从无线到光伏再到AI\n故事要从许映童的华为生涯说起。\n1999年，许映童加入华为。此后的23年里，他经历了华为最波澜壮阔的发展阶段。在无线产品线，他做过 PDT 经理，管过无线软件平台，担任过华为无线杭州研究所所长。\n2010年底，许映童从通信领域转岗至新能源领域，后来华为决定进军智能光伏业务，许映童被委以重任，出任智能光伏业务总裁。\n这是一次从零开始的创业。当时华为在逆变器领域毫无积累，面对的是在行业深耕多年的对手。许映童带领团队埋头研发，终于在2015年，登顶全球逆变器出货量榜首，并且连续七年保持这个位置。\n2020年，许映童又接到了新任务，负责华为昇腾人工智能计算业务。这是华为在AI芯片领域的关键布局，需要既懂硬件又懂软件、既有产品经验又有战略视野的一号位。不过，许映童在昇腾待得时间并不长，仅两年后，他的身份就变为了思格新能源创始人。\n2022年5月，思格新能源在上海注册成立，主营分布式储能系统（DESS），意味着这位华为老兵正式踏上了创业之路。\n当时的许映童之于储能市场是怎样的存在呢？用一个相对贴切的类比，可能就是大模型领域的闫俊杰。\n一个细节是，刚离开华为时，储能方向只是许映童众多创业选项中的一个。在这期间，他与高瓴进行了长期、深入的交流，最终双方形成了高度一致的判断：基于对全球能源格局重构的长期判断，结合许映童及创始团队过去的经验，储能的全球化能够最大程度发挥许映童及核心团队在产品、研发、供应链和全球市场上的复合能力。\n许映童与高瓴在创业早期的关系，也从某种程度上决定了高瓴成为其最大、最早外部股东的结果。\n跟许映童一起离开华为的，还有华为智能光伏前副总裁张先淼，他拥有17年以上的光伏及储能系统行业经验，加入思格新能源后，他出任执行董事兼总裁，全面负责公司产品研发、规划及供应链管理。\n不止如此。思格新能源的创始团队中，还有多位华为旧部：监事会主席刘秦维、全球品牌总监杨顺霞，软件、渠道等各条线的骨干也陆续到位，这几乎是一个完整的作战班底整体迁移。也难怪有人戏称许映童是“最会挖华为墙脚”的人。\n资本市场对大厂人才向来偏爱，更不用说是这样成熟的华为班底了。\n根据招股书可以看到，2022年6月，也就是刚注册成立1个月，思格新能源拿到了500万元的种子轮，该轮投资方为上海煜菘和捷沣科技，投后估值为1亿元。同年7月，高瓴创投就出现在A1轮融资名单上。到年底，思格新能源完成了A1到A3轮，共5.4亿元融资，估值也从1亿元飙升至了27亿元。\n要知道，这时候的思格新能源还没有任何产品上市，2022年全年营收为零，净亏损7620 万元。\n在宏观环境上，2022年，疫情反复，市场剧烈波动，俄乌战争爆发，外部环境极不友好。对许多创业项目来说，那是最不容易启动的一段时间。据透露，在早期高瓴积极帮助思格引入了云辉、钟鼎等产业方和财务投资人，完成多轮关键融资。\n两年营收增长154倍\n开篇提到思格新能源区别于其他竞争对手最明显的标签就是华为班底和全球化，可以看到，在早期，资本向思格新能源投出橄榄枝，还是基于VC传统的投人逻辑。\n不过，在产品问世之后，整个的估值逻辑就变得更理性和商业了，这之中全球化的重要性就显示出来了。\n2023年6月，思格新能源在德国慕尼黑EES Europe展会上推出了首款产品SigenStor，这是全球首款五合一光储充一体机，即把光伏逆变器、储能变流器、储能电池、直流充电模块、能量管理系统（EMS）五大模块集成在了一起，让用户根据实际情况灵活配置和扩展。\n除了这个明显的卖点外，思格新能源还为这款产品配备了AI辅助节能和安装维护。其对外宣称，户储产品配套的mySigen App是能源行业内首个集成GPT-4能力的App。\n依托于这款产品，思格新能源正式开启了商业化之路。\n不过2023年时，它的收入只有5830万人民币，亏损也进一步扩大为3.73亿元。也是在这一年，思格新能源先后完成了B轮系列融资，包括1.4亿元B轮融资，投资方为余杭国投集团、国核投资等，以及天堂硅谷独家投资的3000万元B1轮融资。而B1轮融资也成为了其IPO前的最后一轮融资，当时思格新能源的估值为41.7亿元。\n到2025年，思格新能源的营收规模大跃进般地突破了90亿元，实现了两年增长154倍的神话。除了营收之外，思格的毛利率也在一路上涨，并在2025年飙升至了50.1%。需要指出的是，SigenStor连续三年贡献总收入90%以上，分销渠道占比超过97%，\n拆解来看，2023年、2024年及截至2025年9月30日止，思格新能源来自海外市场的收入分别占总营收的87.8%、95.2%及99.3%。\n在地区分布上，亚太和欧洲是思格新能源2025年海外收入的主要来源，其次为非洲、中东、中亚、拉丁美洲及北美洲。前五大单一市场依次为：澳大利亚（42.6%）、德国（10.2%）、瑞典（6.9%）、爱尔兰（5.1%）、比利时（3.5%）。\n据招股书，截至2025年底，思格业务覆盖全球85个国家和地区，与172家分销商建立了深度合作。拥有1.7万家以上的注册安装商，占二级分销商90%以上。\n一个微妙的变化是，2025年初，思格新能源第一次递交招股书时，其业务覆盖范围为60多个国家和地区，合作分销商99个，拥有5600多家注册安装商。对比来看，短短一年时间，思格新能源全球拓展分销商数量新增了73家，注册安装商增加逾1.1万家。\n此外，按产品出货量计，思格新能源2024年已位居“可堆叠分布式光储一体机”全球第一，市场份额为28.6%。在更广阔的户储市场，它也一跃成为全球户储系统出货量第五名，仅次于Tesla、华为、比亚迪储能、阳光电源等一众巨头。\n高瓴获得超200亿回报\n正是基于这样财务数据带来的底气，思格新能源在2025年曾两次递表港交所，不过均未冲击成功，好在，如今顺利登陆港股。\n由于IPO前，思格新能源仅进行了六轮融资，所以其股权结构相对清晰，创始团队对公司拥有绝对的话语权。上市前，许映童拥有49.28%的投票权，而张先淼持股超过11%。此外，高瓴创投持股14.89%，为外部第一大股东；华登国际持股8.18%，云晖资本持股2.88%，钟鼎资本持股2.88%。\n4月初思格新能源启动招股时，高瓴又以基石投资者身份再度入场，通过HHLR Advisors认购1400万美元，通过Hillhouse Investment Management认购700万美元，合计2100万美元。\n其实，把视角拉远，会发现思格新能源只是高瓴新能源版图中的最新一块拼图。\n过去五年，高瓴一直在持续重仓新能源，根据投中嘉川CVSource显示，最近五年高瓴在新能源领域出手36次。\n2022年6月高瓴官宣了首只总规模逾40亿元人民币的碳中和产业投资基金，明确表示将重点投向新能源、新材料等绿色技术领域。\n在产业链布局上，不管是上游的电池材料、中游的电池制造还是下游的整车企业以及充电基础设施和储能系统，高瓴几乎覆盖了新能源产业的每一个关键环节。\n在这种强大生态圈的助力下，高瓴对思格新能源的帮助并没有停留在给钱层面，而是主动把多年积累的产业资源开放给思格，在电池侧，对接宁德时代，帮助思格在产能最紧缺时期获得稳定供应；在功率器件侧，对接英飞凌等全球头部供应商，确保IGBT等关键元器件不断供。\n如今伴随着储能市场需求的崛起，高瓴的投资也步入了收获期。\n抛开基石轮，如果以每股324.20港元的发行价计算，思格新能源将募资超44亿港元，IPO市值将超800亿港元，高瓴的持股市值将达到119.1亿港元。而按照开盘市值1433亿港元来计算，高瓴这笔IPO的账面回报则超过了200亿元。\n思格新能源创始人许映童表示，“创业路上，最难的不是拿到第一笔钱，而是在最不确定的时刻，依然有人坚定地选择相信你。我们起步于市场极富挑战的时期，是高瓴坚定看好，在产业资源紧张的关头，高瓴开放了他们长期积累的生态能力，帮助我们跨越了早期创业公司的生存门槛。”\n短短几年间，新能源经历了大起大落，但没人否认，被大浪淘沙后的项目正在成为市场新宠，并开启了新一轮的资本盛宴。\n本文来自微信公众号\n“投中网”\n，作者：张雪，36氪经授权发布。', '2026-04-16 12:45:39', '2026-04-16 13:43:07');
INSERT INTO `news_detail` VALUES (49, 1665, 14, '合规与政策服务', '韩国拟最早7月起禁止企业集团分拆上市', '', '韩国金融监管机构周四表示，最早将于7月起采取必要措施，禁止韩国企业集团进行“分拆上市”。韩国金融服务委员会（FSC）指出，分拆上市，也称重复上市，是指将核心业务部门剥离出来单独上市，长期以来被认为是造成所谓“韩国折价”的主要原因之一。该监管机构指出，这种上市方式长期以来损害了股东价值，并表示将“原则上”禁止这种做法。（新浪财经）', 'https://36kr.com/newsflashes/3769044856619785?f=rss', 0, '', '{\"summary\": \"帮助出海企业及时掌握韩国资本市场最新监管政策变化，提前做好相关投资布局调整\", \"abstract\": \"韩国金融服务委员会宣布，最早将于7月起原则上禁止韩国企业集团进行分拆上市。分拆上市又称重复上市，指将企业核心业务剥离后单独上市。韩国监管机构认为，该上市方式长期损害股东价值，是造成\\\"韩国折价\\\"的主要原因之一。这一监管调整将改变韩国本土企业资本运作逻辑，对布局韩国市场的出海企业有参考意义\", \"keywords\": [\"韩国\", \"分拆上市\", \"重复上市\", \"金融监管\", \"韩国折价\", \"股东价值\", \"资本市场\"], \"policy_risk\": {\"market_risk\": \"该政策调整将改变韩国企业集团资本运作路径，对布局韩国资本市场的出海企业带来原有规划调整的不确定性\", \"policy_compliance\": \"韩国金融监管机构拟最早7月起原则上禁止韩国企业集团分拆（重复）上市，该监管要求旨在解决分拆上市损害股东价值的问题\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"合规与政策服务\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3769044856619785?f=rss\", \"title\": \"韩国拟最早7月起禁止企业集团分拆上市\", \"source\": \"https://36kr.com/feed\", \"content\": \"韩国金融监管机构周四表示，最早将于7月起采取必要措施，禁止韩国企业集团进行“分拆上市”。韩国金融服务委员会（FSC）指出，分拆上市，也称重复上市，是指将核心业务部门剥离出来单独上市，长期以来被认为是造成所谓“韩国折价”的主要原因之一。该监管机构指出，这种上市方式长期以来损害了股东价值，并表示将“原则上”禁止这种做法。（新浪财经）\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'韩国拟最早7月起禁止企业集团分拆上市\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'韩国拟最早7月起禁止企业集团分拆上市\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3769044856619785?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3769044856619785?f=rss\', \'published\': \'2026-04-16 13:10:41  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=5, tm_min=10, tm_sec=41, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'韩国金融监管机构周四表示，最早将于7月起采取必要措施，禁止韩国企业集团进行“分拆上市”。韩国金融服务委员会（FSC）指出，分拆上市，也称重复上市，是指将核心业务部门剥离出来单独上市，长期以来被认为是造成所谓“韩国折价”的主要原因之一。该监管机构指出，这种上市方式长期以来损害了股东价值，并表示将“原则上”禁止这种做法。（新浪财经）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'韩国金融监管机构周四表示，最早将于7月起采取必要措施，禁止韩国企业集团进行“分拆上市”。韩国金融服务委员会（FSC）指出，分拆上市，也称重复上市，是指将核心业务部门剥离出来单独上市，长期以来被认为是造成所谓“韩国折价”的主要原因之一。该监管机构指出，这种上市方式长期以来损害了股东价值，并表示将“原则上”禁止这种做法。（新浪财经）\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 13:10:41\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 13:10:41', '2026-04-16 14:13:41');
INSERT INTO `news_detail` VALUES (50, 1683, 10, '传统制造升级', '金铉集团战略入股香港医药分销商朗辉医药', '', '36氪获悉，4月15日，金铉集团宣布已签署一项具有约束力的合作意向书，计划通过股权交换方式收购香港领先的医药分销商 LangHui。此次战略收购标志着金铉集团正式切入大健康分销赛道。', 'https://36kr.com/newsflashes/3769065443246595?f=rss', 0, '', '{\"summary\": \"本文为出海相关企业提供国内企业布局海外大健康分销赛道的最新行业动态\", \"abstract\": \"4月15日，金铉集团宣布签署了具有约束力的合作意向书。金铉集团计划通过股权交换方式收购香港领先医药分销商朗辉医药。此次战略入股标志着金铉集团正式切入大健康分销赛道\", \"keywords\": [\"金铉集团\", \"朗辉医药\", \"战略入股\", \"股权交换\", \"医药分销\", \"大健康\", \"香港\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"传统制造升级\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3769065443246595?f=rss\", \"title\": \"金铉集团战略入股香港医药分销商朗辉医药\", \"source\": \"https://36kr.com/feed\", \"content\": \"36氪获悉，4月15日，金铉集团宣布已签署一项具有约束力的合作意向书，计划通过股权交换方式收购香港领先的医药分销商 LangHui。此次战略收购标志着金铉集团正式切入大健康分销赛道。\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'金铉集团战略入股香港医药分销商朗辉医药\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'金铉集团战略入股香港医药分销商朗辉医药\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3769065443246595?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3769065443246595?f=rss\', \'published\': \'2026-04-16 13:37:34  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=5, tm_min=37, tm_sec=34, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'36氪获悉，4月15日，金铉集团宣布已签署一项具有约束力的合作意向书，计划通过股权交换方式收购香港领先的医药分销商 LangHui。此次战略收购标志着金铉集团正式切入大健康分销赛道。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，4月15日，金铉集团宣布已签署一项具有约束力的合作意向书，计划通过股权交换方式收购香港领先的医药分销商 LangHui。此次战略收购标志着金铉集团正式切入大健康分销赛道。\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 13:37:34\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 13:37:34', '2026-04-16 14:14:48');
INSERT INTO `news_detail` VALUES (51, 1720, 13, '营销与品牌服务', '流水的偶像铁打的韩流，如何为我所用？', '', '<p>“BLACKPINK in your area”早已经不是一句歌词，而是一种现象。</p>\n<p>当阿迪达斯靠着Jennie出圈一次又一次，Nike也终于没把持住，于2026年年初正式开启与Lisa的长期合作。</p>\n<p>在耐克的官方新闻稿中，2025年是Lisa完成从 K-POP 歌手到全球巨星蜕变的一年，标志性的事件是，参与了HBO影集《白莲花度假村》演出、Blackpink合体演唱会DEADLINE WORLD TOUR场场爆满、推出首张个人专辑《Alter Ego》引发热烈回响。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_4cb38e3d094440ac85c2fa215513aaa2@5576336_oswg680357oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/Lisa开启与Nike的长期合作，图源/Nike官网</p>\n<p>内娱为番位或版权扯头花时，韩娱正在开始收割全球。不管你是否乐于接受，韩娱事实上已经在影响亚太年轻人的审美偏好、消费选择与生活想象。</p>\n<p>当韩流成为年轻人审美和消费语境的一部分，摆在品牌面前的问题，不是追不追，而是追什么、怎么追。</p>\n<h2>韩流风靡全球不在文化优势，而在产业优势</h2>\n<p>近几年，韩国文艺作品持续闪耀世界舞台：</p>\n<p>2020年，《寄生虫》成为获评奥斯卡最佳影片的第一部非英语电影；2021年，《鱿鱼游戏》成为Netflix平台播放量第一的内容；2024年，韩国作家韩江获得诺贝尔文学奖，流行多年的“韩女文学”得到权威印证。2026年，《K-POP：猎魔女团》击败《疯狂动物城2》，斩获奥斯卡最佳动画长片奖。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_ff53649d8d3e49ca9394f93881520534@5576336_oswg63916oswg1080oswg453_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_9bb5746c11444db79e70f53d9b2811ac@5576336_oswg86379oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/《K-POP：猎魔女团》经典吃泡面情节</p>\n<p>韩流的全面开花，无法脱离韩国践行20多年的“文化立国”战略背景。<strong>如果我们继续以“小韩”“文化挪用”“魅粉”的视角看韩流，其实会忽略韩国文化产业的先进性和自造血功能。</strong></p>\n<p>亚洲金融危机后，韩国开始将文化作为救国良药：从1999年出台《文化产业振兴基本法》，意识到内容的经济价值；到2001 年成立韩国文化产业振兴院（KOCCA），为企业提供文化出口相关的对口服务；再到2013年强调“创造经济”，鼓励游戏、动漫、K-pop 和时尚行业的跨界融合、推动文化产品的数字化……</p>\n<p>借由<strong>“举国体制+市场竞争+出口导向”</strong>的模式，韩国文化产品迅速崛起，国际影响力也持续提升。2000年，韩国的文化产业出口只有5亿美元；2004年，文化产业成为仅次于汽车制造的第二大出口创汇产业；到2024年，出口总额来到了140.8 亿美元。</p>\n<p>文化产品具有明显的溢出效应，韩国更是将这种效应发挥到了极致。韩国官方曾有过一个著名的测算：每出口100美元的文化内容，能带动相关消费品出口增加412美元。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_ef112bf3fe4f4c8a9d35359174d6276e@5576336_oswg64701oswg800oswg555_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/韩国文化产业振兴院（KOCCA）带团参加法国“Series Mania 2026”产业交流活动，图源/KOCCA官网</p>\n<p>“文化可以分为艺术和产业两个方面。韩国尤其关注产业价值，从国家层面积极支持，这是与其他国家的明显区别。”韩国文化产业振兴院北京代表处原首席代表尹镐此前接受采访时表示。</p>\n<p>韩国文化产业高度重视与实体消费的联动。以韩剧为例，美食、美景、美妆、服饰等呈现往往是制作方、政府与企业三方协同的结果。作为天然的曝光资源，韩剧的产品植入既受到政府支持——韩国文化体育观光部牵头的官方机构，为韩剧的企业、旅游联动提供资金补贴、渠道对接，又有标准化的制作流程——镜头选择、拍摄时机、运镜方式都有明确执行规范，确保贴合剧情表达、商业联动、视觉呈现。</p>\n<p>这其中，官方角色非常关键。韩国文化体育观光部、韩国文化产业振兴院、韩国电影振兴委员会、韩国文学翻译院等官方机构，均设有国际事业部或海外组织，不仅提供政策、资金、渠道支持，也通过频繁的国际交流、前沿的市场研究，在意识层面引领着产业发展。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_8dadec2e92be4409a223552cc4a6095b@5576336_oswg693240oswg1011oswg675_img_png?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_f4f42e7e189b416a91160b9589ad8fd1@5576336_oswg842434oswg1010oswg672_img_png?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_f5db877272a346ac937048f7e881c48b@5576336_oswg606953oswg1007oswg669_img_png?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/KOCCA支持韩国本土设计师品牌而举办的时装周活动，图源/KOCCA官网</p>\n<p>KOCCA们给钱、给政策的同时，始终与创作表达保持“一臂之距”，剧本怎么写、艺人怎么包装，由HYBE、SM、YG等市场化公司发挥，尽管背后也蕴藏着财阀势力、权力腐败，但高度的创作自由、充分的市场竞争、出口及消费溢出导向，迫使产业链条中的创作者及公司对目标市场有深入研究，并追求创新。</p>\n<p>这造成了韩国文艺与中国文艺的本质不同。<strong>前者是外向型的，追求国际视野下的产业先进性、产品观赏性及消费溢出效应，后者是内向型的，注重文化的正统性，导向的正当性。</strong></p>\n<p>在地缘政治局势演变下，韩国文化产品的出口重心也在偏离，从早期依赖中国、日本等亚洲市场，逐步拓展至北美、东南亚、中东等地区。</p>\n<h2>站上潮流尖端的K-POP，“无接触”渗透年轻人</h2>\n<p>立足中国市场看韩流，K-POP成为当前最受品牌瞩目的一个产品分支。</p>\n<p>2016年以来，国内事实上对韩国文娱产品实施了限制性管理，中韩之间的影视引进、艺人演出、合拍项目等几乎停滞。这种“停滞”，也倒逼韩国娱乐行业加速布局欧美、东南亚等市场，间接推高了 K-POP 的国际地位。</p>\n<p>韩国官方发布的《2025年全球韩流趋势分析报告》显示，在有关韩国文化内容的海外媒体报道中，K-POP所占比重最高，在亚洲为31.8%，欧洲和北美分别为24.5%和32.3%，中南美为38.1%，BLACKPINK以14.2%的占比位居话题度首位，BTS和NewJeans分别占比7.3%、3%。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_ca2e85b507564c5aa23343e0cb14bc35@5576336_oswg32102oswg500oswg366_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/《2025年全球韩流趋势分析报告》，图源/韩联社</p>\n<p>韩娱艺人不入境、不上台，热度照样穿透了中国年轻群体。凭借全球化、社交化的互联网传播体系，K-POP可以绕过官方直接抵达年轻人。BTS、BLACKPINK、NewJeans等在Billboard、Spotify、YouTube、TikTok全球登顶，格莱美、科切拉、时装周、世界巡回演唱会等曝光，中国粉丝其实并未缺席。在微博、B站、抖音、小红书，K-POP相关话题、舞台直拍、混剪、造型等长期处于流量高位。</p>\n<p>而K-POP成功“闯美”，又反向强化了其在中国市场的影响力。</p>\n<p>根据韩国关税厅发布的数据，2025年韩国K-POP唱片出口额史上首次突破3亿美元。其中，对华出口同比增长16.6%，达到6971.5万美元，时隔三年超越美国，重回第二大出口市场。这一增长也部分弥补了日本市场的萎缩——日本出口额为8062.5万美元，同比下滑10.2%。</p>\n<p>对品牌而言，K-POP在Z世代中的渗透力是难以抗拒的，因此Jennie、Lisa、张元英等艺人的形象频繁出现在年轻人经常出没的商场、街区，成为潮流符号。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_a9dd952ea1b64e79a126256d44b81084@5576336_oswg123341oswg1080oswg1440_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/Stanley1913 x JENNIE 联名快闪成为粉丝打卡点</p>\n<p>品牌出海营销机构AWH studio创始人、时尚博主MIKI TANG，亲眼见证了K-POP凭借全球社交影响力在时尚圈登顶的过程。十年前她还是时尚编辑时，时装周更像是设计师和时尚媒体的盛会，社交媒体兴起后，明星成为前排常客，先是中国明星受到瞩目，后来BLACKPINK成员与品牌CEO同框，标志着韩流在时尚圈的地位达到了顶峰。</p>\n<p>对于品牌来说，借K-POP触达和影响年轻群体，需进一步看懂K-POP的吸引力法则。男团女团像流水线的产品一样不停更新换代，K-POP却生生不息，究竟有什么魔力？</p>\n<p>结合自身经验以及行业观察，<strong>MIKI TANG 总结，K-POP能始终吸引年轻人，在于其独特的养成系造星机制和创新能力。</strong></p>\n<p>“工业产品是由供需关系决定的，韩团也不例外。这个时代需要什么样的偶像，娱乐公司就会培育什么样的偶像，他们有专门的市场研究部门，承担这部分工作。”</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_be40baef4b0f4a64a4d570f2b93b2e3f@5576336_oswg246823oswg1080oswg1698_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/歌手兼喜剧演员Charlene Kaye总结K-pop规律,TED：How to become a K-pop superstar — in 7 minutes</p>\n<p>如果你还以为流行音乐关注耳朵就够了，那就大错特错了。至少对于依赖社媒发酵的K-POP来说，视觉呈现是最难忽视的一部分。除了造型，妆容、打光、镜头也是精心设计的结果，韩娱非常懂得如何让衣服上镜、显身材，如何发挥艺人的身体优势，形成记忆点。</p>\n<p>MIKI TANG 介绍，K-POP从90年代以H.O.T为代表的第一代偶像，到千禧年的东方神起、Super Junior、BIGBANG等第二代，娱乐公司不断调整偶像形象以迎合市场喜好。少女时代作为韩流“女帝”，代表了男性视角下的清纯少女风，到BLACKPINK加入了Girl Crush风格，强调女性力量，NewJeans又是一种全新的清新的、初恋般的形象。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_84260878b3764ee0b2c8e29bbc81fabb@5576336_oswg256938oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_b64542ebf8e849738bfafbbdb1e6bd31@5576336_oswg249475oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/NewJeans风格受到新一代喜爱，但因为公司内部纠纷事业陷入停摆，图源/@NewJeans_ADOR</p>\n<p>这些团都因为别具一格、贴合青少年审美取向的风格受到瞩目，MIKI TANG 表示：“K-POP潮流是一个循环，创新是成功的关键。”</p>\n<p><strong>除了迎合市场、遵循算法科学做的风格创新，韩娱在练习生培养、专辑制作、打歌舞台、团体综艺、媒体曝光、社媒运营方面的基础设施趋于成熟，为偶像的养成提供了得天独厚的条件。</strong></p>\n<p>几乎每个团都会经历相同的生命周期——练习生时期的默默努力，出道后的舞台打磨、风格定型，随着曝光增多人气逐步攀升，再走向更大的舞台、实现更大的商业回报，登顶之后成立个人工作室，逐步明晰发展路线。</p>\n<p>在体系化的偶像培养过程中，韩国娱乐公司也同样擅长精细化的用户运营，发挥心理投射作用吸粉、固粉，以养成系、陪伴感逐步深化与受众的情感联系。</p>\n<p>对青少年而言，K-POP内容和文化像一个精心设计的捕捞网：</p>\n<p>一方面，高强度训练与舞台绽放的成长性叙事，自带激励属性，偶像在舞台上的专注、热情与掌控力，极易引发青少年共鸣。舞台直���动辄破千万、亿级播放，背后正是粉丝反复观看、情绪沉浸的结果。研究显示，青少年大脑多巴胺反应更敏感，音乐节奏与强烈视觉冲击能带来数倍于成人的愉悦感，形成天然吸引力。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_fbb09756cd044f6886ae6ec8114abed2@5576336_oswg528511oswg762oswg1272_img_png?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_41b89533bb6646dd8dcfd21947bd48af@5576336_oswg309228oswg762oswg1271_img_png?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_9c26f0a5e27b4e6aae249bb86902de2d@5576336_oswg470977oswg759oswg1218_img_png?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/BIGBANG最新演出社媒讨论</p>\n<p>另一方面，通过专辑、打歌舞台、团综等长线曝光，粉丝得以全程陪伴偶像成长，也在情感层面，共享每一次成功与突破。</p>\n<p>在此基础上，多人团体模式通过不同长相、性格、定位能击中不同偏好的受众，在扩大粉丝基本盘的同时，可推动粉丝圈层内的多元观念交流与碰撞，形成共同体意识，极大调动粉丝的参与感和忠诚度。</p>\n<p>在相似的养成周期和反复的产品打磨过程中，娱乐公司在K-POP内容生产、艺人宣发以及粉丝互动机制，已经趋于科学化。</p>\n<p>某种程度上，读懂了K-POP的养成逻辑，就读懂了产品年轻化的核心要义——对内专注产品的成长性和专业度，对外保持长线内容曝光和情感连接，在品牌和用户的持续互动中，让消费者成为产品的共建者。</p>\n<h2>养成系下的年轻化，如何实现审美与情感的协同</h2>\n<p>具体到商业化层面，K-POP的年轻感、时尚感可以在哪些层面为品牌创造价值？</p>\n<p>“如果仅在中国市场销售，K-POP偶像带货能力不如中国明星，其粉丝基础不及中国顶流，这是事实。”MIKI TANG 对胖鲸表示，K-POP不是单纯的带货逻辑。</p>\n<p>背后涉及到中国粉丝对内娱明星与韩娱明星的追星体验的差异，虽然同属粉丝群体，生态却不完全一致。MIKI TANG指出，内娱中粉容易背负一种为偶像做数据、完成品牌销售KPI的压力，而韩娱粉丝的心态则倾向于“买同款优先”。</p>\n<p>对于品牌而言最大的助力是其全球影响力，“无论通过K-POP舞台，还是通过参与剧集制作，借助K-POP偶像在国际平台的曝光，可以在全球粉丝中建立认知。”</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_7ddd829638644999a967aaf5fb70f035@5576336_oswg123055oswg1080oswg732_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_896b9d6864904bfeb0e25fcb19b2aef7@5576336_oswg124315oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/BLACKPINK 新单曲《GO》与平台的联动</p>\n<p>除了有效破圈，更有价值的部分体现K-POP产业对品牌的时尚赋能，具体可关注两个方面：</p>\n<h3><strong>1.人设概念加持，打破品牌印象</strong></h3>\n<p>“我和很多造型师合作过，K-POP的造型师最大的优势就是帮助艺人维持人设，打造IP形象。”MIKI TANG 说，品牌通过与偶像的合作可以快速实现年轻化，因为他们常常突破固定搭配，打破人们对单品的原有认知，阿迪达斯也好，耐克也好，都是专业运动装备，但这些单品穿在Jennie或Lisa身上就会变成时髦战袍。</p>\n<p>她注意到，在首尔，光是造型工作室就有几百家，均有自己擅长的风格和场景。娱乐公司会根据艺人不同发展阶段的创意概念，精准匹配造型团队，所以最终呈现出来每个团都有非常强烈的风格。</p>\n<p>通过极高的审美管理，K-POP 输出内容可将原本普通的产品或小众的品牌穿出“高级感”，赋予产品额外的时尚价值。很多粉丝抱怨中国籍的韩娱艺人在国内的曝光缺乏“星味”，也暴露出了中韩在审美管理上的差距。</p>\n<h3><strong>2.场景化表达，放大同款效应</strong></h3>\n<p>K-POP造型资源包括舞台造型、机场私服、练习室穿搭等，为品牌提供了自然且高频的曝光机会，品牌合作应融入养成系的情感叙事，而不应将商业目的凌驾于产品表达之上。在遵守K-POP工业化视觉、专业造型建议的同时，品牌需做好“扒同款”账号联动、品牌认领、粉丝圈层激动等一系列协同动作，放大明星同款效应。</p>\n<p>MIKI TANG 指出，K-POP产业链条上的每个环节都是高度专业化的。一件产品要转化为“时髦战袍”，背后是整个视觉造型团队在努力——将艺人风格与品牌特色结合，从而扩展单品的适用场景以及品牌的市场影响力。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_ed99010302f444bdaa896acc0814b06f@5576336_oswg608595oswg1080oswg558_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/明星同款账号是商业化的重要一环，图源/小红书截图</p>\n<p>胖鲸注意到，与国内的明星营销相比，韩流营销需密切关注长期性，诸如阿迪达斯、耐克已深谙此道，国内品牌需要摆脱短期收割的惯性。</p>\n<p>代言合作是最简单的交易，但光是艺人签约无法形成差异化。“与艺人造型团队保持长期合作是打入韩国以及其他海外市场的重要途径。”MIKI TANG 说，K-POP人设和概念在妆造中始终是第一位的，品牌可以通过与造型团队合作保持固定露出。</p>\n<p>有时候，品牌需要调动多方资源，才能得到合作机会。例如，一些设计师品牌要得到偶像的垂青，往往需要先获得主流时尚媒体的认可，因为他们更愿意通过时尚杂志的露出体现时尚品位。在日常非商务场合，艺人也会尊重造型团队的意见。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_74e3d55f4e5f4008b73c6816c4c86f7a@5576336_oswg389825oswg460oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_445b4687179e4998a951eb69fe4a3096@5576336_oswg407184oswg456oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_9c38f4356f9a43a6b4933693c9b1ced1@5576336_oswg405022oswg460oswg702_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/韩流产业链平民化，变美三件套依然是热门vlog主题</p>\n<p>韩团千千万，究竟如何挑合作对象？MIKI TANG 建议遵循产业规律，优先与资源强大的娱乐公司合作：“K-POP成果可预测性较强，大型公司推出的团体通常能获得最好的市场反馈，新团尽管存在不确定性，但依托强大的资源背景也支持值得下注。”</p>\n<p>MIKI TANG 指出，成熟品牌可能不适合直接与新人团体合作，可通过年轻化单品或针对年轻市场的产品线进行尝试，长期合作的品牌能在粉丝心中建立真实可信的形象关联，而且通过与娱乐公司的密切联系，可以提前了解新团的推出计划、预期投资和回报。</p>\n<p>K-POP的出圈内容，如舞台表演、油管节目、团综和其他综艺，都有明码标价的植入机会。然而，与内娱的不同在于，韩国艺人的社媒账号会极力保证人设的一致性，通常不进行商业化运营，会避免出现突兀的内容。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_e55d1053945c4362a9d8f8acba9fac0d@5576336_oswg62841oswg690oswg966_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/权志龙个人品牌与OXFORD合作款818 BLOOM线下快闪落地上海，图源/@BFC外滩金融中心</p>\n<p>“韩娱虽然商业化程度高，但仍能保持产品的主体性，不受过多商业因素干扰。”MIKI TANG 总结，成功的韩国艺人往往风格鲜明，合作品牌与其人设高度契合，诸如权志龙、Jennie，已经能够通过个人风格的影响力，与品牌进行销售分成的合作。</p>\n<h2>结语：</h2>\n<p>阿迪达斯与耐克竞逐BLACKPINK成员，揭示着韩流已经在影响年轻人的生活想象。如何将这一时尚符号为我所用？我们总结了几个值得关注的角度：</p>\n<p><strong>生态嵌入：</strong>通过与造型团队、娱乐公司建立长期合作，将产品深度嵌入高度专业化的审美管理与工业化生产体系中，不拘泥于短期转化，而是在养成系叙事中，成为偶像和粉丝心目中有记忆点、有贡献度的成长伙伴。</p>\n<p><strong>借溢出效应布局全球：</strong>品牌可以将韩流作为出海跳板，在全球粉丝心中建立起年轻、时髦且想象力的品牌认知。</p>\n<p><strong>回归产品主体性：</strong>学习韩娱在商业化与艺术表达之间的平衡术，消费者不仅需要看到一个产品，更要看到产品背后所代表的审美品位与生活方式，无论是Girl Crush的力量感，还是 NewJeans 的氧气感，品牌必须替用户提前营造产品的氛围感，让产品变得个性鲜明。</p>\n<p><strong>极致的年轻化：</strong>在不脱离品牌价值观的前提下，用灵活的手段，征用年轻人的创造力与表达欲，并根据市场反馈及时调整产品改良方向，做养成系产品和品牌。</p>\n<p>自疫情后，MIKI TANG 见证了中国品牌对韩流表现出越来越多的兴趣，但在她看来，大多数品牌都有入场的野心，却少有落地的章法。</p>\n<p>不论是借韩流认识韩国市场，还是布局东南亚、北美，亦或是反哺国内市场，大家都还在一脚深、一脚浅地摸着石头过河。MIKI TANG 也是这样走过来的，她说：“没有白走的路，做了再说。”</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260415/v2_bd947293ab7c4bcfb7498d61cbe1d680@5576336_oswg80710oswg1080oswg646_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>图说/YG娱乐在10年前便开始布局中国和美国市场</p>\n<p>这也是韩国文化产业的生存哲学。如今的多点开花，看似是疫情后的狂飙突进，其实是产业优势的集中爆发。</p>\n<p>实际上，KOCCA们和YG们都在产品出海这条路上探索了很久，投入产出不总是正的，但认定了方向就一往无前，最终才在贫瘠的土壤中开出花，在茫茫大海中找到自己的航道。</p>\n<p>韩流自身也是一种养成系——开弓没有回头箭，扎根现实，通过极致的心理洞察，极致的专业分工，极致的亲和力，最终实现了极致的渗透力。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/EjxF9nFajcyZBmPORNVL2A\">“胖鲸头条”</a>，作者：张婷，编辑：范怿，36氪经授权发布。</p>', 'https://36kr.com/p/3768198771225088?f=rss', 0, '', '{\"summary\": \"拆解韩流尤其是K-POP的产业成功逻辑，为出海品牌借韩流开展年轻化营销、布局全球市场提供可落地的实践参考\", \"abstract\": \"韩流近年在全球文娱市场影响力持续提升，依托韩国坚持二十多年的\\\"文化立国\\\"战略和\\\"举国体制+市场竞争+出口导向\\\"的产业模式，韩国文化出口规模快速增长，文化溢出效应还能显著带动实体消费品出口。K-POP作为韩流当前最具影响力的分支，凭借体系化养成系造星机制、持续风格创新与精细化用户运营，已经成为渗透全球年轻群体的核心文化符号。K-POP对品牌的核心价值不在于短期带货，而在于其全球影响力能帮助品牌建立国际认知，同时依托专业化审美运营为品牌实现年轻化赋能。本文总结了品牌借韩流开展营销的落地方法，为出海品牌借韩流作为跳板布局全球市场提供了可参考的思路。\", \"keywords\": [\"韩流\", \"K-POP\", \"品牌出海\", \"海外营销\", \"年轻化营销\", \"文化出海\", \"溢出效应\"], \"policy_risk\": {\"market_risk\": \"多数布局韩流营销的品牌缺乏成熟落地章法，存在短期收割的惯性；合作新K-POP团体存在不确定性，团体也可能因所属公司内部纠纷影响品牌合作效果\", \"policy_compliance\": \"2016年以来，国内对韩国文娱产品实施限制性管理，中韩之间的影视引进、艺人演出、合拍项目几乎停滞\"}, \"topic_cluster\": \"海外营销\", \"industry_category\": \"营销与品牌服务\"}', '', '{\"url\": \"https://36kr.com/p/3768198771225088?f=rss\", \"title\": \"流水的偶像铁打的韩流，如何为我所用？\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>“BLACKPINK in your area”早已经不是一句歌词，而是一种现象。</p>\\n<p>当阿迪达斯靠着Jennie出圈一次又一次，Nike也终于没把持住，于2026年年初正式开启与Lisa的长期合作。</p>\\n<p>在耐克的官方新闻稿中，2025年是Lisa完成从 K-POP 歌手到全球巨星蜕变的一年，标志性的事件是，参与了HBO影集《白莲花度假村》演出、Blackpink合体演唱会DEADLINE WORLD TOUR场场爆满、推出首张个人专辑《Alter Ego》引发热烈回响。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_4cb38e3d094440ac85c2fa215513aaa2@5576336_oswg680357oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/Lisa开启与Nike的长期合作，图源/Nike官网</p>\\n<p>内娱为番位或版权扯头花时，韩娱正在开始收割全球。不管你是否乐于接受，韩娱事实上已经在影响亚太年轻人的审美偏好、消费选择与生活想象。</p>\\n<p>当韩流成为年轻人审美和消费语境的一部分，摆在品牌面前的问题，不是追不追，而是追什么、怎么追。</p>\\n<h2>韩流风靡全球不在文化优势，而在产业优势</h2>\\n<p>近几年，韩国文艺作品持续闪耀世界舞台：</p>\\n<p>2020年，《寄生虫》成为获评奥斯卡最佳影片的第一部非英语电影；2021年，《鱿鱼游戏》成为Netflix平台播放量第一的内容；2024年，韩国作家韩江获得诺贝尔文学奖，流行多年的“韩女文学”得到权威印证。2026年，《K-POP：猎魔女团》击败《疯狂动物城2》，斩获奥斯卡最佳动画长片奖。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ff53649d8d3e49ca9394f93881520534@5576336_oswg63916oswg1080oswg453_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9bb5746c11444db79e70f53d9b2811ac@5576336_oswg86379oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/《K-POP：猎魔女团》经典吃泡面情节</p>\\n<p>韩流的全面开花，无法脱离韩国践行20多年的“文化立国”战略背景。<strong>如果我们继续以“小韩”“文化挪用”“魅粉”的视角看韩流，其实会忽略韩国文化产业的先进性和自造血功能。</strong></p>\\n<p>亚洲金融危机后，韩国开始将文化作为救国良药：从1999年出台《文化产业振兴基本法》，意识到内容的经济价值；到2001 年成立韩国文化产业振兴院（KOCCA），为企业提供文化出口相关的对口服务；再到2013年强调“创造经济”，鼓励游戏、动漫、K-pop 和时尚行业的跨界融合、推动文化产品的数字化……</p>\\n<p>借由<strong>“举国体制+市场竞争+出口导向”</strong>的模式，韩国文化产品迅速崛起，国际影响力也持续提升。2000年，韩国的文化产业出口只有5亿美元；2004年，文化产业成为仅次于汽车制造的第二大出口创汇产业；到2024年，出口总额来到了140.8 亿美元。</p>\\n<p>文化产品具有明显的溢出效应，韩国更是将这种效应发挥到了极致。韩国官方曾有过一个著名的测算：每出口100美元的文化内容，能带动相关消费品出口增加412美元。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ef112bf3fe4f4c8a9d35359174d6276e@5576336_oswg64701oswg800oswg555_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/韩国文化产业振兴院（KOCCA）带团参加法国“Series Mania 2026”产业交流活动，图源/KOCCA官网</p>\\n<p>“文化可以分为艺术和产业两个方面。韩国尤其关注产业价值，从国家层面积极支持，这是与其他国家的明显区别。”韩国文化产业振兴院北京代表处原首席代表尹镐此前接受采访时表示。</p>\\n<p>韩国文化产业高度重视与实体消费的联动。以韩剧为例，美食、美景、美妆、服饰等呈现往往是制作方、政府与企业三方协同的结果。作为天然的曝光资源，韩剧的产品植入既受到政府支持——韩国文化体育观光部牵头的官方机构，为韩剧的企业、旅游联动提供资金补贴、渠道对接，又有标准化的制作流程——镜头选择、拍摄时机、运镜方式都有明确执行规范，确保贴合剧情表达、商业联动、视觉呈现。</p>\\n<p>这其中，官方角色非常关键。韩国文化体育观光部、韩国文化产业振兴院、韩国电影振兴委员会、韩国文学翻译院等官方机构，均设有国际事业部或海外组织，不仅提供政策、资金、渠道支持，也通过频繁的国际交流、前沿的市场研究，在意识层面引领着产业发展。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_8dadec2e92be4409a223552cc4a6095b@5576336_oswg693240oswg1011oswg675_img_png?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_f4f42e7e189b416a91160b9589ad8fd1@5576336_oswg842434oswg1010oswg672_img_png?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_f5db877272a346ac937048f7e881c48b@5576336_oswg606953oswg1007oswg669_img_png?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/KOCCA支持韩国本土设计师品牌而举办的时装周活动，图源/KOCCA官网</p>\\n<p>KOCCA们给钱、给政策的同时，始终与创作表达保持“一臂之距”，剧本怎么写、艺人怎么包装，由HYBE、SM、YG等市场化公司发挥，尽管背后也蕴藏着财阀势力、权力腐败，但高度的创作自由、充分的市场竞争、出口及消费溢出导向，迫使产业链条中的创作者及公司对目标市场有深入研究，并追求创新。</p>\\n<p>这造成了韩国文艺与中国文艺的本质不同。<strong>前者是外向型的，追求国际视野下的产业先进性、产品观赏性及消费溢出效应，后者是内向型的，注重文化的正统性，导向的正当性。</strong></p>\\n<p>在地缘政治局势演变下，韩国文化产品的出口重心也在偏离，从早期依赖中国、日本等亚洲市场，逐步拓展至北美、东南亚、中东等地区。</p>\\n<h2>站上潮流尖端的K-POP，“无接触”渗透年轻人</h2>\\n<p>立足中国市场看韩流，K-POP成为当前最受品牌瞩目的一个产品分支。</p>\\n<p>2016年以来，国内事实上对韩国文娱产品实施了限制性管理，中韩之间的影视引进、艺人演出、合拍项目等几乎停滞。这种“停滞”，也倒逼韩国娱乐行业加速布局欧美、东南亚等市场，间接推高了 K-POP 的国际地位。</p>\\n<p>韩国官方发布的《2025年全球韩流趋势分析报告》显示，在有关韩国文化内容的海外媒体报道中，K-POP所占比重最高，在亚洲为31.8%，欧洲和北美分别为24.5%和32.3%，中南美为38.1%，BLACKPINK以14.2%的占比位居话题度首位，BTS和NewJeans分别占比7.3%、3%。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ca2e85b507564c5aa23343e0cb14bc35@5576336_oswg32102oswg500oswg366_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/《2025年全球韩流趋势分析报告》，图源/韩联社</p>\\n<p>韩娱艺人不入境、不上台，热度照样穿透了中国年轻群体。凭借全球化、社交化的互联网传播体系，K-POP可以绕过官方直接抵达年轻人。BTS、BLACKPINK、NewJeans等在Billboard、Spotify、YouTube、TikTok全球登顶，格莱美、科切拉、时装周、世界巡回演唱会等曝光，中国粉丝其实并未缺席。在微博、B站、抖音、小红书，K-POP相关话题、舞台直拍、混剪、造型等长期处于流量高位。</p>\\n<p>而K-POP成功“闯美”，又反向强化了其在中国市场的影响力。</p>\\n<p>根据韩国关税厅发布的数据，2025年韩国K-POP唱片出口额史上首次突破3亿美元。其中，对华出口同比增长16.6%，达到6971.5万美元，时隔三年超越美国，重回第二大出口市场。这一增长也部分弥补了日本市场的萎缩——日本出口额为8062.5万美元，同比下滑10.2%。</p>\\n<p>对品牌而言，K-POP在Z世代中的渗透力是难以抗拒的，因此Jennie、Lisa、张元英等艺人的形象频繁出现在年轻人经常出没的商场、街区，成为潮流符号。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_a9dd952ea1b64e79a126256d44b81084@5576336_oswg123341oswg1080oswg1440_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/Stanley1913 x JENNIE 联名快闪成为粉丝打卡点</p>\\n<p>品牌出海营销机构AWH studio创始人、时尚博主MIKI TANG，亲眼见证了K-POP凭借全球社交影响力在时尚圈登顶的过程。十年前她还是时尚编辑时，时装周更像是设计师和时尚媒体的盛会，社交媒体兴起后，明星成为前排常客，先是中国明星受到瞩目，后来BLACKPINK成员与品牌CEO同框，标志着韩流在时尚圈的地位达到了顶峰。</p>\\n<p>对于品牌来说，借K-POP触达和影响年轻群体，需进一步看懂K-POP的吸引力法则。男团女团像流水线的产品一样不停更新换代，K-POP却生生不息，究竟有什么魔力？</p>\\n<p>结合自身经验以及行业观察，<strong>MIKI TANG 总结，K-POP能始终吸引年轻人，在于其独特的养成系造星机制和创新能力。</strong></p>\\n<p>“工业产品是由供需关系决定的，韩团也不例外。这个时代需要什么样的偶像，娱乐公司就会培育什么样的偶像，他们有专门的市场研究部门，承担这部分工作。”</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_be40baef4b0f4a64a4d570f2b93b2e3f@5576336_oswg246823oswg1080oswg1698_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/歌手兼喜剧演员Charlene Kaye总结K-pop规律,TED：How to become a K-pop superstar — in 7 minutes</p>\\n<p>如果你还以为流行音乐关注耳朵就够了，那就大错特错了。至少对于依赖社媒发酵的K-POP来说，视觉呈现是最难忽视的一部分。除了造型，妆容、打光、镜头也是精心设计的结果，韩娱非常懂得如何让衣服上镜、显身材，如何发挥艺人的身体优势，形成记忆点。</p>\\n<p>MIKI TANG 介绍，K-POP从90年代以H.O.T为代表的第一代偶像，到千禧年的东方神起、Super Junior、BIGBANG等第二代，娱乐公司不断调整偶像形象以迎合市场喜好。少女时代作为韩流“女帝”，代表了男性视角下的清纯少女风，到BLACKPINK加入了Girl Crush风格，强调女性力量，NewJeans又是一种全新的清新的、初恋般的形象。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_84260878b3764ee0b2c8e29bbc81fabb@5576336_oswg256938oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_b64542ebf8e849738bfafbbdb1e6bd31@5576336_oswg249475oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/NewJeans风格受到新一代喜爱，但因为公司内部纠纷事业陷入停摆，图源/@NewJeans_ADOR</p>\\n<p>这些团都因为别具一格、贴合青少年审美取向的风格受到瞩目，MIKI TANG 表示：“K-POP潮流是一个循环，创新是成功的关键。”</p>\\n<p><strong>除了迎合市场、遵循算法科学做的风格创新，韩娱在练习生培养、专辑制作、打歌舞台、团体综艺、媒体曝光、社媒运营方面的基础设施趋于成熟，为偶像的养成提供了得天独厚的条件。</strong></p>\\n<p>几乎每个团都会经历相同的生命周期——练习生时期的默默努力，出道后的舞台打磨、风格定型，随着曝光增多人气逐步攀升，再走向更大的舞台、实现更大的商业回报，登顶之后成立个人工作室，逐步明晰发展路线。</p>\\n<p>在体系化的偶像培养过程中，韩国娱乐公司也同样擅长精细化的用户运营，发挥心理投射作用吸粉、固粉，以养成系、陪伴感逐步深化与受众的情感联系。</p>\\n<p>对青少年而言，K-POP内容和文化像一个精心设计的捕捞网：</p>\\n<p>一方面，高强度训练与舞台绽放的成长性叙事，自带激励属性，偶像在舞台上的专注、热情与掌控力，极易引发青少年共鸣。舞台直���动辄破千万、亿级播放，背后正是粉丝反复观看、情绪沉浸的结果。研究显示，青少年大脑多巴胺反应更敏感，音乐节奏与强烈视觉冲击能带来数倍于成人的愉悦感，形成天然吸引力。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_fbb09756cd044f6886ae6ec8114abed2@5576336_oswg528511oswg762oswg1272_img_png?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_41b89533bb6646dd8dcfd21947bd48af@5576336_oswg309228oswg762oswg1271_img_png?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9c26f0a5e27b4e6aae249bb86902de2d@5576336_oswg470977oswg759oswg1218_img_png?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/BIGBANG最新演出社媒讨论</p>\\n<p>另一方面，通过专辑、打歌舞台、团综等长线曝光，粉丝得以全程陪伴偶像成长，也在情感层面，共享每一次成功与突破。</p>\\n<p>在此基础上，多人团体模式通过不同长相、性格、定位能击中不同偏好的受众，在扩大粉丝基本盘的同时，可推动粉丝圈层内的多元观念交流与碰撞，形成共同体意识，极大调动粉丝的参与感和忠诚度。</p>\\n<p>在相似的养成周期和反复的产品打磨过程中，娱乐公司在K-POP内容生产、艺人宣发以及粉丝互动机制，已经趋于科学化。</p>\\n<p>某种程度上，读懂了K-POP的养成逻辑，就读懂了产品年轻化的核心要义——对内专注产品的成长性和专业度，对外保持长线内容曝光和情感连接，在品牌和用户的持续互动中，让消费者成为产品的共建者。</p>\\n<h2>养成系下的年轻化，如何实现审美与情感的协同</h2>\\n<p>具体到商业化层面，K-POP的年轻感、时尚感可以在哪些层面为品牌创造价值？</p>\\n<p>“如果仅在中国市场销售，K-POP偶像带货能力不如中国明星，其粉丝基础不及中国顶流，这是事实。”MIKI TANG 对胖鲸表示，K-POP不是单纯的带货逻辑。</p>\\n<p>背后涉及到中国粉丝对内娱明星与韩娱明星的追星体验的差异，虽然同属粉丝群体，生态却不完全一致。MIKI TANG指出，内娱中粉容易背负一种为偶像做数据、完成品牌销售KPI的压力，而韩娱粉丝的心态则倾向于“买同款优先”。</p>\\n<p>对于品牌而言最大的助力是其全球影响力，“无论通过K-POP舞台，还是通过参与剧集制作，借助K-POP偶像在国际平台的曝光，可以在全球粉丝中建立认知。”</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_7ddd829638644999a967aaf5fb70f035@5576336_oswg123055oswg1080oswg732_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_896b9d6864904bfeb0e25fcb19b2aef7@5576336_oswg124315oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/BLACKPINK 新单曲《GO》与平台的联动</p>\\n<p>除了有效破圈，更有价值的部分体现K-POP产业对品牌的时尚赋能，具体可关注两个方面：</p>\\n<h3><strong>1.人设概念加持，打破品牌印象</strong></h3>\\n<p>“我和很多造型师合作过，K-POP的造型师最大的优势就是帮助艺人维持人设，打造IP形象。”MIKI TANG 说，品牌通过与偶像的合作可以快速实现年轻化，因为他们常常突破固定搭配，打破人们对单品的原有认知，阿迪达斯也好，耐克也好，都是专业运动装备，但这些单品穿在Jennie或Lisa身上就会变成时髦战袍。</p>\\n<p>她注意到，在首尔，光是造型工作室就有几百家，均有自己擅长的风格和场景。娱乐公司会根据艺人不同发展阶段的创意概念，精准匹配造型团队，所以最终呈现出来每个团都有非常强烈的风格。</p>\\n<p>通过极高的审美管理，K-POP 输出内容可将原本普通的产品或小众的品牌穿出“高级感”，赋予产品额外的时尚价值。很多粉丝抱怨中国籍的韩娱艺人在国内的曝光缺乏“星味”，也暴露出了中韩在审美管理上的差距。</p>\\n<h3><strong>2.场景化表达，放大同款效应</strong></h3>\\n<p>K-POP造型资源包括舞台造型、机场私服、练习室穿搭等，为品牌提供了自然且高频的曝光机会，品牌合作应融入养成系的情感叙事，而不应将商业目的凌驾于产品表达之上。在遵守K-POP工业化视觉、专业造型建议的同时，品牌需做好“扒同款”账号联动、品牌认领、粉丝圈层激动等一系列协同动作，放大明星同款效应。</p>\\n<p>MIKI TANG 指出，K-POP产业链条上的每个环节都是高度专业化的。一件产品要转化为“时髦战袍”，背后是整个视觉造型团队在努力——将艺人风格与品牌特色结合，从而扩展单品的适用场景以及品牌的市场影响力。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ed99010302f444bdaa896acc0814b06f@5576336_oswg608595oswg1080oswg558_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/明星同款账号是商业化的重要一环，图源/小红书截图</p>\\n<p>胖鲸注意到，与国内的明星营销相比，韩流营销需密切关注长期性，诸如阿迪达斯、耐克已深谙此道，国内品牌需要摆脱短期收割的惯性。</p>\\n<p>代言合作是最简单的交易，但光是艺人签约无法形成差异化。“与艺人造型团队保持长期合作是打入韩国以及其他海外市场的重要途径。”MIKI TANG 说，K-POP人设和概念在妆造中始终是第一位的，品牌可以通过与造型团队合作保持固定露出。</p>\\n<p>有时候，品牌需要调动多方资源，才能得到合作机会。例如，一些设计师品牌要得到偶像的垂青，往往需要先获得主流时尚媒体的认可，因为他们更愿意通过时尚杂志的露出体现时尚品位。在日常非商务场合，艺人也会尊重造型团队的意见。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_74e3d55f4e5f4008b73c6816c4c86f7a@5576336_oswg389825oswg460oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_445b4687179e4998a951eb69fe4a3096@5576336_oswg407184oswg456oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9c38f4356f9a43a6b4933693c9b1ced1@5576336_oswg405022oswg460oswg702_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/韩流产业链平民化，变美三件套依然是热门vlog主题</p>\\n<p>韩团千千万，究竟如何挑合作对象？MIKI TANG 建议遵循产业规律，优先与资源强大的娱乐公司合作：“K-POP成果可预测性较强，大型公司推出的团体通常能获得最好的市场反馈，新团尽管存在不确定性，但依托强大的资源背景也支持值得下注。”</p>\\n<p>MIKI TANG 指出，成熟品牌可能不适合直接与新人团体合作，可通过年轻化单品或针对年轻市场的产品线进行尝试，长期合作的品牌能在粉丝心中建立真实可信的形象关联，而且通过与娱乐公司的密切联系，可以提前了解新团的推出计划、预期投资和回报。</p>\\n<p>K-POP的出圈内容，如舞台表演、油管节目、团综和其他综艺，都有明码标价的植入机会。然而，与内娱的不同在于，韩国艺人的社媒账号会极力保证人设的一致性，通常不进行商业化运营，会避免出现突兀的内容。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_e55d1053945c4362a9d8f8acba9fac0d@5576336_oswg62841oswg690oswg966_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/权志龙个人品牌与OXFORD合作款818 BLOOM线下快闪落地上海，图源/@BFC外滩金融中心</p>\\n<p>“韩娱虽然商业化程度高，但仍能保持产品的主体性，不受过多商业因素干扰。”MIKI TANG 总结，成功的韩国艺人往往风格鲜明，合作品牌与其人设高度契合，诸如权志龙、Jennie，已经能够通过个人风格的影响力，与品牌进行销售分成的合作。</p>\\n<h2>结语：</h2>\\n<p>阿迪达斯与耐克竞逐BLACKPINK成员，揭示着韩流已经在影响年轻人的生活想象。如何将这一时尚符号为我所用？我们总结了几个值得关注的角度：</p>\\n<p><strong>生态嵌入：</strong>通过与造型团队、娱乐公司建立长期合作，将产品深度嵌入高度专业化的审美管理与工业化生产体系中，不拘泥于短期转化，而是在养成系叙事中，成为偶像和粉丝心目中有记忆点、有贡献度的成长伙伴。</p>\\n<p><strong>借溢出效应布局全球：</strong>品牌可以将韩流作为出海跳板，在全球粉丝心中建立起年轻、时髦且想象力的品牌认知。</p>\\n<p><strong>回归产品主体性：</strong>学习韩娱在商业化与艺术表达之间的平衡术，消费者不仅需要看到一个产品，更要看到产品背后所代表的审美品位与生活方式，无论是Girl Crush的力量感，还是 NewJeans 的氧气感，品牌必须替用户提前营造产品的氛围感，让产品变得个性鲜明。</p>\\n<p><strong>极致的年轻化：</strong>在不脱离品牌价值观的前提下，用灵活的手段，征用年轻人的创造力与表达欲，并根据市场反馈及时调整产品改良方向，做养成系产品和品牌。</p>\\n<p>自疫情后，MIKI TANG 见证了中国品牌对韩流表现出越来越多的兴趣，但在她看来，大多数品牌都有入场的野心，却少有落地的章法。</p>\\n<p>不论是借韩流认识韩国市场，还是布局东南亚、北美，亦或是反哺国内市场，大家都还在一脚深、一脚浅地摸着石头过河。MIKI TANG 也是这样走过来的，她说：“没有白走的路，做了再说。”</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_bd947293ab7c4bcfb7498d61cbe1d680@5576336_oswg80710oswg1080oswg646_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>图说/YG娱乐在10年前便开始布局中国和美国市场</p>\\n<p>这也是韩国文化产业的生存哲学。如今的多点开花，看似是疫情后的狂飙突进，其实是产业优势的集中爆发。</p>\\n<p>实际上，KOCCA们和YG们都在产品出海这条路上探索了很久，投入产出不总是正的，但认定了方向就一往无前，最终才在贫瘠的土壤中开出花，在茫茫大海中找到自己的航道。</p>\\n<p>韩流自身也是一种养成系——开弓没有回头箭，扎根现实，通过极致的心理洞察，极致的专业分工，极致的亲和力，最终实现了极致的渗透力。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/EjxF9nFajcyZBmPORNVL2A\\\">“胖鲸头条”</a>，作者：张婷，编辑：范怿，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'流水的偶像铁打的韩流，如何为我所用？\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'流水的偶像铁打的韩流，如何为我所用？\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768198771225088?f=rss\'}], \'link\': \'https://36kr.com/p/3768198771225088?f=rss\', \'published\': \'2026-04-16 12:59:27  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=4, tm_min=59, tm_sec=27, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>“BLACKPINK in your area”早已经不是一句歌词，而是一种现象。</p>\\\\n  <p>当阿迪达斯靠着Jennie出圈一次又一次，Nike也终于没把持住，于2026年年初正式开启与Lisa的长期合作。</p>\\\\n  <p>在耐克的官方新闻稿中，2025年是Lisa完成从 K-POP 歌手到全球巨星蜕变的一年，标志性的事件是，参与了HBO影集《白莲花度假村》演出、Blackpink合体演唱会DEADLINE WORLD TOUR场场爆满、推出首张个人专辑《Alter Ego》引发热烈回响。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_4cb38e3d094440ac85c2fa215513aaa2@5576336_oswg680357oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/Lisa开启与Nike的长期合作，图源/Nike官网</p>\\\\n  <p>内娱为番位或版权扯头花时，韩娱正在开始收割全球。不管你是否乐于接受，韩娱事实上已经在影响亚太年轻人的审美偏好、消费选择与生活想象。</p>\\\\n  <p>当韩流成为年轻人审美和消费语境的一部分，摆在品牌面前的问题，不是追不追，而是追什么、怎么追。</p>\\\\n  <h2>韩流风靡全球不在文化优势，而在产业优势</h2>\\\\n  <p>近几年，韩国文艺作品持续闪耀世界舞台：</p>\\\\n  <p>2020年，《寄生虫》成为获评奥斯卡最佳影片的第一部非英语电影；2021年，《鱿鱼游戏》成为Netflix平台播放量第一的内容；2024年，韩国作家韩江获得诺贝尔文学奖，流行多年的“韩女文学”得到权威印证。2026年，《K-POP：猎魔女团》击败《疯狂动物城2》，斩获奥斯卡最佳动画长片奖。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ff53649d8d3e49ca9394f93881520534@5576336_oswg63916oswg1080oswg453_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9bb5746c11444db79e70f53d9b2811ac@5576336_oswg86379oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/《K-POP：猎魔女团》经典吃泡面情节</p>\\\\n  <p>韩流的全面开花，无法脱离韩国践行20多年的“文化立国”战略背景。<strong>如果我们继续以“小韩”“文化挪用”“魅粉”的视角看韩流，其实会忽略韩国文化产业的先进性和自造血功能。</strong></p>\\\\n  <p>亚洲金融危机后，韩国开始将文化作为救国良药：从1999年出台《文化产业振兴基本法》，意识到内容的经济价值；到2001 年成立韩国文化产业振兴院（KOCCA），为企业提供文化出口相关的对口服务；再到2013年强调“创造经济”，鼓励游戏、动漫、K-pop 和时尚行业的跨界融合、推动文化产品的数字化……</p>\\\\n  <p>借由<strong>“举国体制+市场竞争+出口导向”</strong>的模式，韩国文化产品迅速崛起，国际影响力也持续提升。2000年，韩国的文化产业出口只有5亿美元；2004年，文化产业成为仅次于汽车制造的第二大出口创汇产业；到2024年，出口总额来到了140.8 亿美元。</p>\\\\n  <p>文化产品具有明显的溢出效应，韩国更是将这种效应发挥到了极致。韩国官方曾有过一个著名的测算：每出口100美元的文化内容，能带动相关消费品出口增加412美元。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ef112bf3fe4f4c8a9d35359174d6276e@5576336_oswg64701oswg800oswg555_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/韩国文化产业振兴院（KOCCA）带团参加法国“Series Mania 2026”产业交流活动，图源/KOCCA官网</p>\\\\n  <p>“文化可以分为艺术和产业两个方面。韩国尤其关注产业价值，从国家层面积极支持，这是与其他国家的明显区别。”韩国文化产业振兴院北京代表处原首席代表尹镐此前接受采访时表示。</p>\\\\n  <p>韩国文化产业高度重视与实体消费的联动。以韩剧为例，美食、美景、美妆、服饰等呈现往往是制作方、政府与企业三方协同的结果。作为天然的曝光资源，韩剧的产品植入既受到政府支持——韩国文化体育观光部牵头的官方机构，为韩剧的企业、旅游联动提供资金补贴、渠道对接，又有标准化的制作流程——镜头选择、拍摄时机、运镜方式都有明确执行规范，确保贴合剧情表达、商业联动、视觉呈现。</p>\\\\n  <p>这其中，官方角色非常关键。韩国文化体育观光部、韩国文化产业振兴院、韩国电影振兴委员会、韩国文学翻译院等官方机构，均设有国际事业部或海外组织，不仅提供政策、资金、渠道支持，也通过频繁的国际交流、前沿的市场研究，在意识层面引领着产业发展。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_8dadec2e92be4409a223552cc4a6095b@5576336_oswg693240oswg1011oswg675_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_f4f42e7e189b416a91160b9589ad8fd1@5576336_oswg842434oswg1010oswg672_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_f5db877272a346ac937048f7e881c48b@5576336_oswg606953oswg1007oswg669_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/KOCCA支持韩国本土设计师品牌而举办的时装周活动，图源/KOCCA官网</p>\\\\n  <p>KOCCA们给钱、给政策的同时，始终与创作表达保持“一臂之距”，剧本怎么写、艺人怎么包装，由HYBE、SM、YG等市场化公司发挥，尽管背后也蕴藏着财阀势力、权力腐败，但高度的创作自由、充分的市场竞争、出口及消费溢出导向，迫使产业链条中的创作者及公司对目标市场有深入研究，并追求创新。</p>\\\\n  <p>这造成了韩国文艺与中国文艺的本质不同。<strong>前者是外向型的，追求国际视野下的产业先进性、产品观赏性及消费溢出效应，后者是内向型的，注重文化的正统性，导向的正当性。</strong></p>\\\\n  <p>在地缘政治局势演变下，韩国文化产品的出口重心也在偏离，从早期依赖中国、日本等亚洲市场，逐步拓展至北美、东南亚、中东等地区。</p>\\\\n  <h2>站上潮流尖端的K-POP，“无接触”渗透年轻人</h2>\\\\n  <p>立足中国市场看韩流，K-POP成为当前最受品牌瞩目的一个产品分支。</p>\\\\n  <p>2016年以来，国内事实上对韩国文娱产品实施了限制性管理，中韩之间的影视引进、艺人演出、合拍项目等几乎停滞。这种“停滞”，也倒逼韩国娱乐行业加速布局欧美、东南亚等市场，间接推高了 K-POP 的国际地位。</p>\\\\n  <p>韩国官方发布的《2025年全球韩流趋势分析报告》显示，在有关韩国文化内容的海外媒体报道中，K-POP所占比重最高，在亚洲为31.8%，欧洲和北美分别为24.5%和32.3%，中南美为38.1%，BLACKPINK以14.2%的占比位居话题度首位，BTS和NewJeans分别占比7.3%、3%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ca2e85b507564c5aa23343e0cb14bc35@5576336_oswg32102oswg500oswg366_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/《2025年全球韩流趋势分析报告》，图源/韩联社</p>\\\\n  <p>韩娱艺人不入境、不上台，热度照样穿透了中国年轻群体。凭借全球化、社交化的互联网传播体系，K-POP可以绕过官方直接抵达年轻人。BTS、BLACKPINK、NewJeans等在Billboard、Spotify、YouTube、TikTok全球登顶，格莱美、科切拉、时装周、世界巡回演唱会等曝光，中国粉丝其实并未缺席。在微博、B站、抖音、小红书，K-POP相关话题、舞台直拍、混剪、造型等长期处于流量高位。</p>\\\\n  <p>而K-POP成功“闯美”，又反向强化了其在中国市场的影响力。</p>\\\\n  <p>根据韩国关税厅发布的数据，2025年韩国K-POP唱片出口额史上首次突破3亿美元。其中，对华出口同比增长16.6%，达到6971.5万美元，时隔三年超越美国，重回第二大出口市场。这一增长也部分弥补了日本市场的萎缩——日本出口额为8062.5万美元，同比下滑10.2%。</p>\\\\n  <p>对品牌而言，K-POP在Z世代中的渗透力是难以抗拒的，因此Jennie、Lisa、张元英等艺人的形象频繁出现在年轻人经常出没的商场、街区，成为潮流符号。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_a9dd952ea1b64e79a126256d44b81084@5576336_oswg123341oswg1080oswg1440_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/Stanley1913 x JENNIE 联名快闪成为粉丝打卡点</p>\\\\n  <p>品牌出海营销机构AWH studio创始人、时尚博主MIKI TANG，亲眼见证了K-POP凭借全球社交影响力在时尚圈登顶的过程。十年前她还是时尚编辑时，时装周更像是设计师和时尚媒体的盛会，社交媒体兴起后，明星成为前排常客，先是中国明星受到瞩目，后来BLACKPINK成员与品牌CEO同框，标志着韩流在时尚圈的地位达到了顶峰。</p>\\\\n  <p>对于品牌来说，借K-POP触达和影响年轻群体，需进一步看懂K-POP的吸引力法则。男团女团像流水线的产品一样不停更新换代，K-POP却生生不息，究竟有什么魔力？</p>\\\\n  <p>结合自身经验以及行业观察，<strong>MIKI TANG 总结，K-POP能始终吸引年轻人，在于其独特的养成系造星机制和创新能力。</strong></p>\\\\n  <p>“工业产品是由供需关系决定的，韩团也不例外。这个时代需要什么样的偶像，娱乐公司就会培育什么样的偶像，他们有专门的市场研究部门，承担这部分工作。”</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_be40baef4b0f4a64a4d570f2b93b2e3f@5576336_oswg246823oswg1080oswg1698_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/歌手兼喜剧演员Charlene Kaye总结K-pop规律,TED：How to become a K-pop superstar — in 7 minutes</p>\\\\n  <p>如果你还以为流行音乐关注耳朵就够了，那就大错特错了。至少对于依赖社媒发酵的K-POP来说，视觉呈现是最难忽视的一部分。除了造型，妆容、打光、镜头也是精心设计的结果，韩娱非常懂得如何让衣服上镜、显身材，如何发挥艺人的身体优势，形成记忆点。</p>\\\\n  <p>MIKI TANG 介绍，K-POP从90年代以H.O.T为代表的第一代偶像，到千禧年的东方神起、Super Junior、BIGBANG等第二代，娱乐公司不断调整偶像形象以迎合市场喜好。少女时代作为韩流“女帝”，代表了男性视角下的清纯少女风，到BLACKPINK加入了Girl Crush风格，强调女性力量，NewJeans又是一种全新的清新的、初恋般的形象。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_84260878b3764ee0b2c8e29bbc81fabb@5576336_oswg256938oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_b64542ebf8e849738bfafbbdb1e6bd31@5576336_oswg249475oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/NewJeans风格受到新一代喜爱，但因为公司内部纠纷事业陷入停摆，图源/@NewJeans_ADOR</p>\\\\n  <p>这些团都因为别具一格、贴合青少年审美取向的风格受到瞩目，MIKI TANG 表示：“K-POP潮流是一个循环，创新是成功的关键。”</p>\\\\n  <p><strong>除了迎合市场、遵循算法科学做的风格创新，韩娱在练习生培养、专辑制作、打歌舞台、团体综艺、媒体曝光、社媒运营方面的基础设施趋于成熟，为偶像的养成提供了得天独厚的条件。</strong></p>\\\\n  <p>几乎每个团都会经历相同的生命周期——练习生时期的默默努力，出道后的舞台打磨、风格定型，随着曝光增多人气逐步攀升，再走向更大的舞台、实现更大的商业回报，登顶之后成立个人工作室，逐步明晰发展路线。</p>\\\\n  <p>在体系化的偶像培养过程中，韩国娱乐公司也同样擅长精细化的用户运营，发挥心理投射作用吸粉、固粉，以养成系、陪伴感逐步深化与受众的情感联系。</p>\\\\n  <p>对青少年而言，K-POP内容和文化像一个精心设计的捕捞网：</p>\\\\n  <p>一方面，高强度训练与舞台绽放的成长性叙事，自带激励属性，偶像在舞台上的专注、热情与掌控力，极易引发青少年共鸣。舞台直���动辄破千万、亿级播放，背后正是粉丝反复观看、情绪沉浸的结果。研究显示，青少年大脑多巴胺反应更敏感，音乐节奏与强烈视觉冲击能带来数倍于成人的愉悦感，形成天然吸引力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_fbb09756cd044f6886ae6ec8114abed2@5576336_oswg528511oswg762oswg1272_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_41b89533bb6646dd8dcfd21947bd48af@5576336_oswg309228oswg762oswg1271_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9c26f0a5e27b4e6aae249bb86902de2d@5576336_oswg470977oswg759oswg1218_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/BIGBANG最新演出社媒讨论</p>\\\\n  <p>另一方面，通过专辑、打歌舞台、团综等长线曝光，粉丝得以全程陪伴偶像成长，也在情感层面，共享每一次成功与突破。</p>\\\\n  <p>在此基础上，多人团体模式通过不同长相、性格、定位能击中不同偏好的受众，在扩大粉丝基本盘的同时，可推动粉丝圈层内的多元观念交流与碰撞，形成共同体意识，极大调动粉丝的参与感和忠诚度。</p>\\\\n  <p>在相似的养成周期和反复的产品打磨过程中，娱乐公司在K-POP内容生产、艺人宣发以及粉丝互动机制，已经趋于科学化。</p>\\\\n  <p>某种程度上，读懂了K-POP的养成逻辑，就读懂了产品年轻化的核心要义——对内专注产品的成长性和专业度，对外保持长线内容曝光和情感连接，在品牌和用户的持续互动中，让消费者成为产品的共建者。</p>\\\\n  <h2>养成系下的年轻化，如何实现审美与情感的协同</h2>\\\\n  <p>具体到商业化层面，K-POP的年轻感、时尚感可以在哪些层面为品牌创造价值？</p>\\\\n  <p>“如果仅在中国市场销售，K-POP偶像带货能力不如中国明星，其粉丝基础不及中国顶流，这是事实。”MIKI TANG 对胖鲸表示，K-POP不是单纯的带货逻辑。</p>\\\\n  <p>背后涉及到中国粉丝对内娱明星与韩娱明星的追星体验的差异，虽然同属粉丝群体，生态却不完全一致。MIKI TANG指出，内娱中粉容易背负一种为偶像做数据、完成品牌销售KPI的压力，而韩娱粉丝的心态则倾向于“买同款优先”。</p>\\\\n  <p>对于品牌而言最大的助力是其全球影响力，“无论通过K-POP舞台，还是通过参与剧集制作，借助K-POP偶像在国际平台的曝光，可以在全球粉丝中建立认知。”</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_7ddd829638644999a967aaf5fb70f035@5576336_oswg123055oswg1080oswg732_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_896b9d6864904bfeb0e25fcb19b2aef7@5576336_oswg124315oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/BLACKPINK 新单曲《GO》与平台的联动</p>\\\\n  <p>除了有效破圈，更有价值的部分体现K-POP产业对品牌的时尚赋能，具体可关注两个方面：</p>\\\\n  <h3><strong>1.人设概念加持，打破品牌印象</strong></h3>\\\\n  <p>“我和很多造型师合作过，K-POP的造型师最大的优势就是帮助艺人维持人设，打造IP形象。”MIKI TANG 说，品牌通过与偶像的合作可以快速实现年轻化，因为他们常常突破固定搭配，打破人们对单品的原有认知，阿迪达斯也好，耐克也好，都是专业运动装备，但这些单品穿在Jennie或Lisa身上就会变成时髦战袍。</p>\\\\n  <p>她注意到，在首尔，光是造型工作室就有几百家，均有自己擅长的风格和场景。娱乐公司会根据艺人不同发展阶段的创意概念，精准匹配造型团队，所以最终呈现出来每个团都有非常强烈的风格。</p>\\\\n  <p>通过极高的审美管理，K-POP 输出内容可将原本普通的产品或小众的品牌穿出“高级感”，赋予产品额外的时尚价值。很多粉丝抱怨中国籍的韩娱艺人在国内的曝光缺乏“星味”，也暴露出了中韩在审美管理上的差距。</p>\\\\n  <h3><strong>2.场景化表达，放大同款效应</strong></h3>\\\\n  <p>K-POP造型资源包括舞台造型、机场私服、练习室穿搭等，为品牌提供了自然且高频的曝光机会，品牌合作应融入养成系的情感叙事，而不应将商业目的凌驾于产品表达之上。在遵守K-POP工业化视觉、专业造型建议的同时，品牌需做好“扒同款”账号联动、品牌认领、粉丝圈层激动等一系列协同动作，放大明星同款效应。</p>\\\\n  <p>MIKI TANG 指出，K-POP产业链条上的每个环节都是高度专业化的。一件产品要转化为“时髦战袍”，背后是整个视觉造型团队在努力——将艺人风格与品牌特色结合，从而扩展单品的适用场景以及品牌的市场影响力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ed99010302f444bdaa896acc0814b06f@5576336_oswg608595oswg1080oswg558_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/明星同款账号是商业化的重要一环，图源/小红书截图</p>\\\\n  <p>胖鲸注意到，与国内的明星营销相比，韩流营销需密切关注长期性，诸如阿迪达斯、耐克已深谙此道，国内品牌需要摆脱短期收割的惯性。</p>\\\\n  <p>代言合作是最简单的交易，但光是艺人签约无法形成差异化。“与艺人造型团队保持长期合作是打入韩国以及其他海外市场的重要途径。”MIKI TANG 说，K-POP人设和概念在妆造中始终是第一位的，品牌可以通过与造型团队合作保持固定露出。</p>\\\\n  <p>有时候，品牌需要调动多方资源，才能得到合作机会。例如，一些设计师品牌要得到偶像的垂青，往往需要先获得主流时尚媒体的认可，因为他们更愿意通过时尚杂志的露出体现时尚品位。在日常非商务场合，艺人也会尊重造型团队的意见。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_74e3d55f4e5f4008b73c6816c4c86f7a@5576336_oswg389825oswg460oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_445b4687179e4998a951eb69fe4a3096@5576336_oswg407184oswg456oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9c38f4356f9a43a6b4933693c9b1ced1@5576336_oswg405022oswg460oswg702_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/韩流产业链平民化，变美三件套依然是热门vlog主题</p>\\\\n  <p>韩团千千万，究竟如何挑合作对象？MIKI TANG 建议遵循产业规律，优先与资源强大的娱乐公司合作：“K-POP成果可预测性较强，大型公司推出的团体通常能获得最好的市场反馈，新团尽管存在不确定性，但依托强大的资源背景也支持值得下注。”</p>\\\\n  <p>MIKI TANG 指出，成熟品牌可能不适合直接与新人团体合作，可通过年轻化单品或针对年轻市场的产品线进行尝试，长期合作的品牌能在粉丝心中建立真实可信的形象关联，而且通过与娱乐公司的密切联系，可以提前了解新团的推出计划、预期投资和回报。</p>\\\\n  <p>K-POP的出圈内容，如舞台表演、油管节目、团综和其他综艺，都有明码标价的植入机会。然而，与内娱的不同在于，韩国艺人的社媒账号会极力保证人设的一致性，通常不进行商业化运营，会避免出现突兀的内容。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_e55d1053945c4362a9d8f8acba9fac0d@5576336_oswg62841oswg690oswg966_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/权志龙个人品牌与OXFORD合作款818 BLOOM线下快闪落地上海，图源/@BFC外滩金融中心</p>\\\\n  <p>“韩娱虽然商业化程度高，但仍能保持产品的主体性，不受过多商业因素干扰。”MIKI TANG 总结，成功的韩国艺人往往风格鲜明，合作品牌与其人设高度契合，诸如权志龙、Jennie，已经能够通过个人风格的影响力，与品牌进行销售分成的合作。</p>\\\\n  <h2>结语：</h2>\\\\n  <p>阿迪达斯与耐克竞逐BLACKPINK成员，揭示着韩流已经在影响年轻人的生活想象。如何将这一时尚符号为我所用？我们总结了几个值得关注的角度：</p>\\\\n  <p><strong>生态嵌入：</strong>通过与造型团队、娱乐公司建立长期合作，将产品深度嵌入高度专业化的审美管理与工业化生产体系中，不拘泥于短期转化，而是在养成系叙事中，成为偶像和粉丝心目中有记忆点、有贡献度的成长伙伴。</p>\\\\n  <p><strong>借溢出效应布局全球：</strong>品牌可以将韩流作为出海跳板，在全球粉丝心中建立起年轻、时髦且想象力的品牌认知。</p>\\\\n  <p><strong>回归产品主体性：</strong>学习韩娱在商业化与艺术表达之间的平衡术，消费者不仅需要看到一个产品，更要看到产品背后所代表的审美品位与生活方式，无论是Girl Crush的力量感，还是 NewJeans 的氧气感，品牌必须替用户提前营造产品的氛围感，让产品变得个性鲜明。</p>\\\\n  <p><strong>极致的年轻化：</strong>在不脱离品牌价值观的前提下，用灵活的手段，征用年轻人的创造力与表达欲，并根据市场反馈及时调整产品改良方向，做养成系产品和品牌。</p>\\\\n  <p>自疫情后，MIKI TANG 见证了中国品牌对韩流表现出越来越多的兴趣，但在她看来，大多数品牌都有入场的野心，却少有落地的章法。</p>\\\\n  <p>不论是借韩流认识韩国市场，还是布局东南亚、北美，亦或是反哺国内市场，大家都还在一脚深、一脚浅地摸着石头过河。MIKI TANG 也是这样走过来的，她说：“没有白走的路，做了再说。”</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_bd947293ab7c4bcfb7498d61cbe1d680@5576336_oswg80710oswg1080oswg646_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/YG娱乐在10年前便开始布局中国和美国市场</p>\\\\n  <p>这也是韩国文化产业的生存哲学。如今的多点开花，看似是疫情后的狂飙突进，其实是产业优势的集中爆发。</p>\\\\n  <p>实际上，KOCCA们和YG们都在产品出海这条路上探索了很久，投入产出不总是正的，但认定了方向就一往无前，最终才在贫瘠的土壤中开出花，在茫茫大海中找到自己的航道。</p>\\\\n  <p>韩流自身也是一种养成系——开弓没有回头箭，扎根现实，通过极致的心理洞察，极致的专业分工，极致的亲和力，最终实现了极致的渗透力。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/EjxF9nFajcyZBmPORNVL2A\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“胖鲸头条”</a>，作者：张婷，编辑：范怿，36氪经授权发布。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'<p>“BLACKPINK in your area”早已经不是一句歌词，而是一种现象。</p>\\\\n  <p>当阿迪达斯靠着Jennie出圈一次又一次，Nike也终于没把持住，于2026年年初正式开启与Lisa的长期合作。</p>\\\\n  <p>在耐克的官方新闻稿中，2025年是Lisa完成从 K-POP 歌手到全球巨星蜕变的一年，标志性的事件是，参与了HBO影集《白莲花度假村》演出、Blackpink合体演唱会DEADLINE WORLD TOUR场场爆满、推出首张个人专辑《Alter Ego》引发热烈回响。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_4cb38e3d094440ac85c2fa215513aaa2@5576336_oswg680357oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/Lisa开启与Nike的长期合作，图源/Nike官网</p>\\\\n  <p>内娱为番位或版权扯头花时，韩娱正在开始收割全球。不管你是否乐于接受，韩娱事实上已经在影响亚太年轻人的审美偏好、消费选择与生活想象。</p>\\\\n  <p>当韩流成为年轻人审美和消费语境的一部分，摆在品牌面前的问题，不是追不追，而是追什么、怎么追。</p>\\\\n  <h2>韩流风靡全球不在文化优势，而在产业优势</h2>\\\\n  <p>近几年，韩国文艺作品持续闪耀世界舞台：</p>\\\\n  <p>2020年，《寄生虫》成为获评奥斯卡最佳影片的第一部非英语电影；2021年，《鱿鱼游戏》成为Netflix平台播放量第一的内容；2024年，韩国作家韩江获得诺贝尔文学奖，流行多年的“韩女文学”得到权威印证。2026年，《K-POP：猎魔女团》击败《疯狂动物城2》，斩获奥斯卡最佳动画长片奖。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ff53649d8d3e49ca9394f93881520534@5576336_oswg63916oswg1080oswg453_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9bb5746c11444db79e70f53d9b2811ac@5576336_oswg86379oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/《K-POP：猎魔女团》经典吃泡面情节</p>\\\\n  <p>韩流的全面开花，无法脱离韩国践行20多年的“文化立国”战略背景。<strong>如果我们继续以“小韩”“文化挪用”“魅粉”的视角看韩流，其实会忽略韩国文化产业的先进性和自造血功能。</strong></p>\\\\n  <p>亚洲金融危机后，韩国开始将文化作为救国良药：从1999年出台《文化产业振兴基本法》，意识到内容的经济价值；到2001 年成立韩国文化产业振兴院（KOCCA），为企业提供文化出口相关的对口服务；再到2013年强调“创造经济”，鼓励游戏、动漫、K-pop 和时尚行业的跨界融合、推动文化产品的数字化……</p>\\\\n  <p>借由<strong>“举国体制+市场竞争+出口导向”</strong>的模式，韩国文化产品迅速崛起，国际影响力也持续提升。2000年，韩国的文化产业出口只有5亿美元；2004年，文化产业成为仅次于汽车制造的第二大出口创汇产业；到2024年，出口总额来到了140.8 亿美元。</p>\\\\n  <p>文化产品具有明显的溢出效应，韩国更是将这种效应发挥到了极致。韩国官方曾有过一个著名的测算：每出口100美元的文化内容，能带动相关消费品出口增加412美元。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ef112bf3fe4f4c8a9d35359174d6276e@5576336_oswg64701oswg800oswg555_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/韩国文化产业振兴院（KOCCA）带团参加法国“Series Mania 2026”产业交流活动，图源/KOCCA官网</p>\\\\n  <p>“文化可以分为艺术和产业两个方面。韩国尤其关注产业价值，从国家层面积极支持，这是与其他国家的明显区别。”韩国文化产业振兴院北京代表处原首席代表尹镐此前接受采访时表示。</p>\\\\n  <p>韩国文化产业高度重视与实体消费的联动。以韩剧为例，美食、美景、美妆、服饰等呈现往往是制作方、政府与企业三方协同的结果。作为天然的曝光资源，韩剧的产品植入既受到政府支持——韩国文化体育观光部牵头的官方机构，为韩剧的企业、旅游联动提供资金补贴、渠道对接，又有标准化的制作流程——镜头选择、拍摄时机、运镜方式都有明确执行规范，确保贴合剧情表达、商业联动、视觉呈现。</p>\\\\n  <p>这其中，官方角色非常关键。韩国文化体育观光部、韩国文化产业振兴院、韩国电影振兴委员会、韩国文学翻译院等官方机构，均设有国际事业部或海外组织，不仅提供政策、资金、渠道支持，也通过频繁的国际交流、前沿的市场研究，在意识层面引领着产业发展。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_8dadec2e92be4409a223552cc4a6095b@5576336_oswg693240oswg1011oswg675_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_f4f42e7e189b416a91160b9589ad8fd1@5576336_oswg842434oswg1010oswg672_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_f5db877272a346ac937048f7e881c48b@5576336_oswg606953oswg1007oswg669_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/KOCCA支持韩国本土设计师品牌而举办的时装周活动，图源/KOCCA官网</p>\\\\n  <p>KOCCA们给钱、给政策的同时，始终与创作表达保持“一臂之距”，剧本怎么写、艺人怎么包装，由HYBE、SM、YG等市场化公司发挥，尽管背后也蕴藏着财阀势力、权力腐败，但高度的创作自由、充分的市场竞争、出口及消费溢出导向，迫使产业链条中的创作者及公司对目标市场有深入研究，并追求创新。</p>\\\\n  <p>这造成了韩国文艺与中国文艺的本质不同。<strong>前者是外向型的，追求国际视野下的产业先进性、产品观赏性及消费溢出效应，后者是内向型的，注重文化的正统性，导向的正当性。</strong></p>\\\\n  <p>在地缘政治局势演变下，韩国文化产品的出口重心也在偏离，从早期依赖中国、日本等亚洲市场，逐步拓展至北美、东南亚、中东等地区。</p>\\\\n  <h2>站上潮流尖端的K-POP，“无接触”渗透年轻人</h2>\\\\n  <p>立足中国市场看韩流，K-POP成为当前最受品牌瞩目的一个产品分支。</p>\\\\n  <p>2016年以来，国内事实上对韩国文娱产品实施了限制性管理，中韩之间的影视引进、艺人演出、合拍项目等几乎停滞。这种“停滞”，也倒逼韩国娱乐行业加速布局欧美、东南亚等市场，间接推高了 K-POP 的国际地位。</p>\\\\n  <p>韩国官方发布的《2025年全球韩流趋势分析报告》显示，在有关韩国文化内容的海外媒体报道中，K-POP所占比重最高，在亚洲为31.8%，欧洲和北美分别为24.5%和32.3%，中南美为38.1%，BLACKPINK以14.2%的占比位居话题度首位，BTS和NewJeans分别占比7.3%、3%。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ca2e85b507564c5aa23343e0cb14bc35@5576336_oswg32102oswg500oswg366_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/《2025年全球韩流趋势分析报告》，图源/韩联社</p>\\\\n  <p>韩娱艺人不入境、不上台，热度照样穿透了中国年轻群体。凭借全球化、社交化的互联网传播体系，K-POP可以绕过官方直接抵达年轻人。BTS、BLACKPINK、NewJeans等在Billboard、Spotify、YouTube、TikTok全球登顶，格莱美、科切拉、时装周、世界巡回演唱会等曝光，中国粉丝其实并未缺席。在微博、B站、抖音、小红书，K-POP相关话题、舞台直拍、混剪、造型等长期处于流量高位。</p>\\\\n  <p>而K-POP成功“闯美”，又反向强化了其在中国市场的影响力。</p>\\\\n  <p>根据韩国关税厅发布的数据，2025年韩国K-POP唱片出口额史上首次突破3亿美元。其中，对华出口同比增长16.6%，达到6971.5万美元，时隔三年超越美国，重回第二大出口市场。这一增长也部分弥补了日本市场的萎缩——日本出口额为8062.5万美元，同比下滑10.2%。</p>\\\\n  <p>对品牌而言，K-POP在Z世代中的渗透力是难以抗拒的，因此Jennie、Lisa、张元英等艺人的形象频繁出现在年轻人经常出没的商场、街区，成为潮流符号。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_a9dd952ea1b64e79a126256d44b81084@5576336_oswg123341oswg1080oswg1440_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/Stanley1913 x JENNIE 联名快闪成为粉丝打卡点</p>\\\\n  <p>品牌出海营销机构AWH studio创始人、时尚博主MIKI TANG，亲眼见证了K-POP凭借全球社交影响力在时尚圈登顶的过程。十年前她还是时尚编辑时，时装周更像是设计师和时尚媒体的盛会，社交媒体兴起后，明星成为前排常客，先是中国明星受到瞩目，后来BLACKPINK成员与品牌CEO同框，标志着韩流在时尚圈的地位达到了顶峰。</p>\\\\n  <p>对于品牌来说，借K-POP触达和影响年轻群体，需进一步看懂K-POP的吸引力法则。男团女团像流水线的产品一样不停更新换代，K-POP却生生不息，究竟有什么魔力？</p>\\\\n  <p>结合自身经验以及行业观察，<strong>MIKI TANG 总结，K-POP能始终吸引年轻人，在于其独特的养成系造星机制和创新能力。</strong></p>\\\\n  <p>“工业产品是由供需关系决定的，韩团也不例外。这个时代需要什么样的偶像，娱乐公司就会培育什么样的偶像，他们有专门的市场研究部门，承担这部分工作。”</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_be40baef4b0f4a64a4d570f2b93b2e3f@5576336_oswg246823oswg1080oswg1698_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/歌手兼喜剧演员Charlene Kaye总结K-pop规律,TED：How to become a K-pop superstar — in 7 minutes</p>\\\\n  <p>如果你还以为流行音乐关注耳朵就够了，那就大错特错了。至少对于依赖社媒发酵的K-POP来说，视觉呈现是最难忽视的一部分。除了造型，妆容、打光、镜头也是精心设计的结果，韩娱非常懂得如何让衣服上镜、显身材，如何发挥艺人的身体优势，形成记忆点。</p>\\\\n  <p>MIKI TANG 介绍，K-POP从90年代以H.O.T为代表的第一代偶像，到千禧年的东方神起、Super Junior、BIGBANG等第二代，娱乐公司不断调整偶像形象以迎合市场喜好。少女时代作为韩流“女帝”，代表了男性视角下的清纯少女风，到BLACKPINK加入了Girl Crush风格，强调女性力量，NewJeans又是一种全新的清新的、初恋般的形象。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_84260878b3764ee0b2c8e29bbc81fabb@5576336_oswg256938oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_b64542ebf8e849738bfafbbdb1e6bd31@5576336_oswg249475oswg1080oswg1621_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/NewJeans风格受到新一代喜爱，但因为公司内部纠纷事业陷入停摆，图源/@NewJeans_ADOR</p>\\\\n  <p>这些团都因为别具一格、贴合青少年审美取向的风格受到瞩目，MIKI TANG 表示：“K-POP潮流是一个循环，创新是成功的关键。”</p>\\\\n  <p><strong>除了迎合市场、遵循算法科学做的风格创新，韩娱在练习生培养、专辑制作、打歌舞台、团体综艺、媒体曝光、社媒运营方面的基础设施趋于成熟，为偶像的养成提供了得天独厚的条件。</strong></p>\\\\n  <p>几乎每个团都会经历相同的生命周期——练习生时期的默默努力，出道后的舞台打磨、风格定型，随着曝光增多人气逐步攀升，再走向更大的舞台、实现更大的商业回报，登顶之后成立个人工作室，逐步明晰发展路线。</p>\\\\n  <p>在体系化的偶像培养过程中，韩国娱乐公司也同样擅长精细化的用户运营，发挥心理投射作用吸粉、固粉，以养成系、陪伴感逐步深化与受众的情感联系。</p>\\\\n  <p>对青少年而言，K-POP内容和文化像一个精心设计的捕捞网：</p>\\\\n  <p>一方面，高强度训练与舞台绽放的成长性叙事，自带激励属性，偶像在舞台上的专注、热情与掌控力，极易引发青少年共鸣。舞台直���动辄破千万、亿级播放，背后正是粉丝反复观看、情绪沉浸的结果。研究显示，青少年大脑多巴胺反应更敏感，音乐节奏与强烈视觉冲击能带来数倍于成人的愉悦感，形成天然吸引力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_fbb09756cd044f6886ae6ec8114abed2@5576336_oswg528511oswg762oswg1272_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_41b89533bb6646dd8dcfd21947bd48af@5576336_oswg309228oswg762oswg1271_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9c26f0a5e27b4e6aae249bb86902de2d@5576336_oswg470977oswg759oswg1218_img_png?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/BIGBANG最新演出社媒讨论</p>\\\\n  <p>另一方面，通过专辑、打歌舞台、团综等长线曝光，粉丝得以全程陪伴偶像成长，也在情感层面，共享每一次成功与突破。</p>\\\\n  <p>在此基础上，多人团体模式通过不同长相、性格、定位能击中不同偏好的受众，在扩大粉丝基本盘的同时，可推动粉丝圈层内的多元观念交流与碰撞，形成共同体意识，极大调动粉丝的参与感和忠诚度。</p>\\\\n  <p>在相似的养成周期和反复的产品打磨过程中，娱乐公司在K-POP内容生产、艺人宣发以及粉丝互动机制，已经趋于科学化。</p>\\\\n  <p>某种程度上，读懂了K-POP的养成逻辑，就读懂了产品年轻化的核心要义——对内专注产品的成长性和专业度，对外保持长线内容曝光和情感连接，在品牌和用户的持续互动中，让消费者成为产品的共建者。</p>\\\\n  <h2>养成系下的年轻化，如何实现审美与情感的协同</h2>\\\\n  <p>具体到商业化层面，K-POP的年轻感、时尚感可以在哪些层面为品牌创造价值？</p>\\\\n  <p>“如果仅在中国市场销售，K-POP偶像带货能力不如中国明星，其粉丝基础不及中国顶流，这是事实。”MIKI TANG 对胖鲸表示，K-POP不是单纯的带货逻辑。</p>\\\\n  <p>背后涉及到中国粉丝对内娱明星与韩娱明星的追星体验的差异，虽然同属粉丝群体，生态却不完全一致。MIKI TANG指出，内娱中粉容易背负一种为偶像做数据、完成品牌销售KPI的压力，而韩娱粉丝的心态则倾向于“买同款优先”。</p>\\\\n  <p>对于品牌而言最大的助力是其全球影响力，“无论通过K-POP舞台，还是通过参与剧集制作，借助K-POP偶像在国际平台的曝光，可以在全球粉丝中建立认知。”</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_7ddd829638644999a967aaf5fb70f035@5576336_oswg123055oswg1080oswg732_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_896b9d6864904bfeb0e25fcb19b2aef7@5576336_oswg124315oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/BLACKPINK 新单曲《GO》与平台的联动</p>\\\\n  <p>除了有效破圈，更有价值的部分体现K-POP产业对品牌的时尚赋能，具体可关注两个方面：</p>\\\\n  <h3><strong>1.人设概念加持，打破品牌印象</strong></h3>\\\\n  <p>“我和很多造型师合作过，K-POP的造型师最大的优势就是帮助艺人维持人设，打造IP形象。”MIKI TANG 说，品牌通过与偶像的合作可以快速实现年轻化，因为他们常常突破固定搭配，打破人们对单品的原有认知，阿迪达斯也好，耐克也好，都是专业运动装备，但这些单品穿在Jennie或Lisa身上就会变成时髦战袍。</p>\\\\n  <p>她注意到，在首尔，光是造型工作室就有几百家，均有自己擅长的风格和场景。娱乐公司会根据艺人不同发展阶段的创意概念，精准匹配造型团队，所以最终呈现出来每个团都有非常强烈的风格。</p>\\\\n  <p>通过极高的审美管理，K-POP 输出内容可将原本普通的产品或小众的品牌穿出“高级感”，赋予产品额外的时尚价值。很多粉丝抱怨中国籍的韩娱艺人在国内的曝光缺乏“星味”，也暴露出了中韩在审美管理上的差距。</p>\\\\n  <h3><strong>2.场景化表达，放大同款效应</strong></h3>\\\\n  <p>K-POP造型资源包括舞台造型、机场私服、练习室穿搭等，为品牌提供了自然且高频的曝光机会，品牌合作应融入养成系的情感叙事，而不应将商业目的凌驾于产品表达之上。在遵守K-POP工业化视觉、专业造型建议的同时，品牌需做好“扒同款”账号联动、品牌认领、粉丝圈层激动等一系列协同动作，放大明星同款效应。</p>\\\\n  <p>MIKI TANG 指出，K-POP产业链条上的每个环节都是高度专业化的。一件产品要转化为“时髦战袍”，背后是整个视觉造型团队在努力——将艺人风格与品牌特色结合，从而扩展单品的适用场景以及品牌的市场影响力。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_ed99010302f444bdaa896acc0814b06f@5576336_oswg608595oswg1080oswg558_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/明星同款账号是商业化的重要一环，图源/小红书截图</p>\\\\n  <p>胖鲸注意到，与国内的明星营销相比，韩流营销需密切关注长期性，诸如阿迪达斯、耐克已深谙此道，国内品牌需要摆脱短期收割的惯性。</p>\\\\n  <p>代言合作是最简单的交易，但光是艺人签约无法形成差异化。“与艺人造型团队保持长期合作是打入韩国以及其他海外市场的重要途径。”MIKI TANG 说，K-POP人设和概念在妆造中始终是第一位的，品牌可以通过与造型团队合作保持固定露出。</p>\\\\n  <p>有时候，品牌需要调动多方资源，才能得到合作机会。例如，一些设计师品牌要得到偶像的垂青，往往需要先获得主流时尚媒体的认可，因为他们更愿意通过时尚杂志的露出体现时尚品位。在日常非商务场合，艺人也会尊重造型团队的意见。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_74e3d55f4e5f4008b73c6816c4c86f7a@5576336_oswg389825oswg460oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_445b4687179e4998a951eb69fe4a3096@5576336_oswg407184oswg456oswg770_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_9c38f4356f9a43a6b4933693c9b1ced1@5576336_oswg405022oswg460oswg702_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/韩流产业链平民化，变美三件套依然是热门vlog主题</p>\\\\n  <p>韩团千千万，究竟如何挑合作对象？MIKI TANG 建议遵循产业规律，优先与资源强大的娱乐公司合作：“K-POP成果可预测性较强，大型公司推出的团体通常能获得最好的市场反馈，新团尽管存在不确定性，但依托强大的资源背景也支持值得下注。”</p>\\\\n  <p>MIKI TANG 指出，成熟品牌可能不适合直接与新人团体合作，可通过年轻化单品或针对年轻市场的产品线进行尝试，长期合作的品牌能在粉丝心中建立真实可信的形象关联，而且通过与娱乐公司的密切联系，可以提前了解新团的推出计划、预期投资和回报。</p>\\\\n  <p>K-POP的出圈内容，如舞台表演、油管节目、团综和其他综艺，都有明码标价的植入机会。然而，与内娱的不同在于，韩国艺人的社媒账号会极力保证人设的一致性，通常不进行商业化运营，会避免出现突兀的内容。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_e55d1053945c4362a9d8f8acba9fac0d@5576336_oswg62841oswg690oswg966_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/权志龙个人品牌与OXFORD合作款818 BLOOM线下快闪落地上海，图源/@BFC外滩金融中心</p>\\\\n  <p>“韩娱虽然商业化程度高，但仍能保持产品的主体性，不受过多商业因素干扰。”MIKI TANG 总结，成功的韩国艺人往往风格鲜明，合作品牌与其人设高度契合，诸如权志龙、Jennie，已经能够通过个人风格的影响力，与品牌进行销售分成的合作。</p>\\\\n  <h2>结语：</h2>\\\\n  <p>阿迪达斯与耐克竞逐BLACKPINK成员，揭示着韩流已经在影响年轻人的生活想象。如何将这一时尚符号为我所用？我们总结了几个值得关注的角度：</p>\\\\n  <p><strong>生态嵌入：</strong>通过与造型团队、娱乐公司建立长期合作，将产品深度嵌入高度专业化的审美管理与工业化生产体系中，不拘泥于短期转化，而是在养成系叙事中，成为偶像和粉丝心目中有记忆点、有贡献度的成长伙伴。</p>\\\\n  <p><strong>借溢出效应布局全球：</strong>品牌可以将韩流作为出海跳板，在全球粉丝心中建立起年轻、时髦且想象力的品牌认知。</p>\\\\n  <p><strong>回归产品主体性：</strong>学习韩娱在商业化与艺术表达之间的平衡术，消费者不仅需要看到一个产品，更要看到产品背后所代表的审美品位与生活方式，无论是Girl Crush的力量感，还是 NewJeans 的氧气感，品牌必须替用户提前营造产品的氛围感，让产品变得个性鲜明。</p>\\\\n  <p><strong>极致的年轻化：</strong>在不脱离品牌价值观的前提下，用灵活的手段，征用年轻人的创造力与表达欲，并根据市场反馈及时调整产品改良方向，做养成系产品和品牌。</p>\\\\n  <p>自疫情后，MIKI TANG 见证了中国品牌对韩流表现出越来越多的兴趣，但在她看来，大多数品牌都有入场的野心，却少有落地的章法。</p>\\\\n  <p>不论是借韩流认识韩国市场，还是布局东南亚、北美，亦或是反哺国内市场，大家都还在一脚深、一脚浅地摸着石头过河。MIKI TANG 也是这样走过来的，她说：“没有白走的路，做了再说。”</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260415/v2_bd947293ab7c4bcfb7498d61cbe1d680@5576336_oswg80710oswg1080oswg646_img_000?x-oss-process=image/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">图说/YG娱乐在10年前便开始布局中国和美国市场</p>\\\\n  <p>这也是韩国文化产业的生存哲学。如今的多点开花，看似是疫情后的狂飙突进，其实是产业优势的集中爆发。</p>\\\\n  <p>实际上，KOCCA们和YG们都在产品出海这条路上探索了很久，投入产出不总是正的，但认定了方向就一往无前，最终才在贫瘠的土壤中开出花，在茫茫大海中找到自己的航道。</p>\\\\n  <p>韩流自身也是一种养成系——开弓没有回头箭，扎根现实，通过极致的心理洞察，极致的专业分工，极致的亲和力，最终实现了极致的渗透力。</p>\\\\n  <p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/EjxF9nFajcyZBmPORNVL2A\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">“胖鲸头条”</a>，作者：张婷，编辑：范怿，36氪经授权发布。</p>\'}, \'source\': {\'title\': \'36氪\'}, \'authors\': [{\'name\': \'胖鲸头条\'}], \'author\': \'胖鲸头条\', \'author_detail\': {\'name\': \'胖鲸头条\'}, \'content\': [{\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed-article\', \'value\': \'不靠文化优势，韩流凭什么统治亚太青年审美？\'}]}\", \"published_at\": \"2026-04-16 12:59:27\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 12:59:27', '2026-04-16 14:17:40');
INSERT INTO `news_detail` VALUES (52, 2010, 6, '科技与数字服务', '新加坡的AI征途：孕育下一个“硅谷”', '', '<p>“Punggol”，是一个位于新加坡东北部的新区，它有一个可爱的中文名：“榜鹅”，读起来，确实像某种动物的叫声。</p>\n<p>Punggol其实是马来语，翻译过来，是指用木棍敲打果树，把果子打下来。</p>\n<p>而现实中的榜鹅镇，相当长一段时间，都被大片大片森林覆盖。当新加坡乌节路的写字楼一栋栋拔地而起时，榜鹅还是一片蛮荒之地，即使现在，新加坡本地人告诉我，“有人在丛林中看到过狮子”。</p>\n<p>不过，如今的榜鹅，有的不仅是密林与野兽的传说，设在此地的榜鹅数码园区(Punggol Digital District, PDD) 是新加坡新晋的科技创新聚集地。</p>\n<p>就在4月初，中国自动驾驶科技公司文远知行与Grab宣布，在新加坡榜鹅地区启动自动驾驶出行服务公开运营，这也是新加坡首个在住宅区部署的自动驾驶公共出行服务。</p>\n<p>去年底，我曾在榜鹅实地看到过文远知行的Robotaxi GXR Ai.r，紫红色渐变外观的七座车，在榜鹅灰白色的组屋群中十分显眼，试点期间，当地居民可以通过申请试乘Ai.r，车上空间很大，即使拿着行李箱也没问题。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_8666e99bcaa34b39887e1a27a5a16964@6162492_oswg204522oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\"></p>\n<p>文远知行的Robotaxi GXR Ai.r；作者拍摄</p>\n<p>榜鹅区域的发展阶段，恰好满足新兴技术落地的要求，因为是新区，这里的居民更年轻，对科技的接受程度也更高。</p>\n<p>就拿文远知行的自动驾驶来说，初期试点时，榜鹅的人流与路况不会像市中心那样过于复杂，但榜鹅也具备完整的生活配套，组屋社区、地铁站、写字楼，Robotaxi GXR得以在这样的真实环境下，验证技术可行性。</p>\n<p>“新加坡政府要把榜鹅发展成一个AI driven（驱动）、AI focus（聚焦）的区域，自动驾驶就很符合这里的AI narrative（叙事）。”陪同我的文远知行工作人员谈到。</p>\n<p>你可以把这里想象成新加坡的硅谷，同样是在蛮荒中开辟一块创新之地，榜鹅的动作迅速，自2018年起，新加坡政府就联合工业巨头裕廊集团，着手筹建榜鹅数码园区，第一阶段工程在2024年落地， 预计整个项目将在2026年完成。</p>\n<p>在招商层面，园区除了招揽新加坡企业入驻外，也希望引进更多跨国企业，首批四家跨国企业中就有中国企业的身影。</p>\n<p>相关资料显示，这四家企业分别为提供智慧生活方案的台达集团新加坡子公司Delta Electronics Int’l (Singapore)、机器人技术公司Boston Dynamics、网络安全公司Group-IB以及来自中国的区块链公司万向（Wanxiang）。</p>\n<p>在硅谷的产业构成中，诸如斯坦福等高校的存在必不可少。毗邻榜鹅园区的，则是新加坡第五所公立大学——新加坡理工大学 (Singapore Institute of Technology) 的校园，为了让产、学合作更紧密，在园区设计上，也通过廊道互通的方式，将榜鹅园区与新加坡理工大学二者“无缝”连接起来。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_baaf3fb1cb4a43d98b04c712fbbcd4b9@6162492_oswg243769oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\"></p>\n<p>新加坡理工大学 (Singapore Institute of Technology) 的校园；作者拍摄</p>\n<p>新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)，向我们介绍了新加坡政府对榜鹅的规划，在他的演示文档中，榜鹅的定位是“Singapore’s First Smart Town（新加坡首个智慧小镇）”。</p>\n<p>所谓“智慧小镇”，是指园区背后依托的核心系统采用开放智能平台（Open Digital Platform）技术，通过传感器、数字平台，园区得以实现数据可视化、设备实时监控、AI节能等，同时园区倡导可持续理念，设置了屋顶太阳能板发电、雨水净化灌溉、 厨余垃圾转化为肥料等多种绿色设施，都体现了新加坡发展绿色城市的理念。</p>\n<p>新加坡对于发展人工智能的决心可见一斑。2026年2月12日，新加坡总理兼财政部长黄循财在发表财政预算案声明中时谈到，新加坡将启动新的人工智能发展愿景（AI Missions），率先推动四个关键经济领域的人工智能转型，即互联互通、先进制造业、金融和医疗保健。</p>\n<p>为落实相关计划，新加坡政府还将成立由黄循财领导的全国人工智能理事会（National AI Council）。黄循财强调，在变革的世界中，新加坡能否成功，取决于如何运用新科技，而人工智能是其中最关键的一环。</p>\n<p>不过，对于人口只有600万人，面积还不到北京朝阳区两倍的新加坡来说，发展人工智能，最重要的优势，是对人才的吸引力。</p>\n<p>包括Meta、OpenAI、Google等全球顶尖科技公司，均在新加坡设有规模不小的分部，中国有不少赫赫有名的AI公司选择迁居新加坡发展业务，比如今年刚刚被谷歌收购的中国AI初创公司Manus。</p>\n<p>Manus在新加坡的办公地址，位于市中心Funan商场旁的一家WeWork里，这里经常能遇到讲着中文的华人面孔。工作环境和国内没什么不同，负一层能吃到不到5新币（不到30元）的吉野家和麻辣烫，4楼就有纯K。</p>\n<p>对于迁居而来的中国员工来说，除了常年高温潮湿的气候，在生活习惯上几乎可以无缝切换。</p>\n<p>从新加坡政府的视角，对于创新企业来说，找到一个人才宜居、且能够方便抵达的地方，相当重要。</p>\n<p>“你要在全世界找一个中国人、美国人、欧洲人，都愿意来的地方，这种选择真的不多，新加坡就是其中之一。”沈丰吉对我们说。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_3fe6a14712ac43b5b47e16e6cf852a2f@6162492_oswg249458oswg1702oswg1276_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\"></p>\n<p>新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)；作者拍摄</p>\n<p>而对于这样的高新企业，新加坡政府也会协助他们落地发展。</p>\n<p>“（我们）像一个班级的老师，要照顾班上每一个同学的需求。”沈丰吉笑着比喻道。</p>', 'https://36kr.com/p/3768997634130434?f=rss', 0, '', '{\"summary\": \"帮助中国AI科技企业了解新加坡AI产业布局与招商环境，为出海新加坡投资布局提供参考\", \"abstract\": \"本文介绍新加坡正打造聚焦人工智能的榜鹅数码园区，定位为新加坡首个智慧小镇，目前已有包括中国AI企业文远知行、中国企业万向在内的多家国内外科技企业落地布局。新加坡政府推出新的人工智能发展愿景，成立由总理领导的全国人工智能理事会，重点推动四大经济领域的AI转型，出台政策积极招揽跨国AI企业入驻。新加坡凭借开放包容的环境、对全球人才的吸引力以及政府的配套扶持，正逐步发展成为新兴的全球AI创新聚集地，为包括中国在内的AI企业出海提供了优质落脚点。\", \"keywords\": [\"新加坡\", \"人工智能\", \"AI出海\", \"榜鹅数码园区\", \"自动驾驶\", \"跨国企业\", \"产业招商\", \"中国企业\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"新加坡政府推出人工智能发展愿景（AI Missions），成立由总理领导的全国人工智能理事会，重点推动互联互通、先进制造业、金融、医疗保健四大领域AI转型；规划打造榜鹅AI聚焦智慧小镇，面向全球招揽跨国企业入驻，并为创新企业提供落地配套扶持\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"https://36kr.com/p/3768997634130434?f=rss\", \"title\": \"新加坡的AI征途：孕育下一个“硅谷”\", \"source\": \"https://36kr.com/feed\", \"content\": \"<p>“Punggol”，是一个位于新加坡东北部的新区，它有一个可爱的中文名：“榜鹅”，读起来，确实像某种动物的叫声。</p>\\n<p>Punggol其实是马来语，翻译过来，是指用木棍敲打果树，把果子打下来。</p>\\n<p>而现实中的榜鹅镇，相当长一段时间，都被大片大片森林覆盖。当新加坡乌节路的写字楼一栋栋拔地而起时，榜鹅还是一片蛮荒之地，即使现在，新加坡本地人告诉我，“有人在丛林中看到过狮子”。</p>\\n<p>不过，如今的榜鹅，有的不仅是密林与野兽的传说，设在此地的榜鹅数码园区(Punggol Digital District, PDD) 是新加坡新晋的科技创新聚集地。</p>\\n<p>就在4月初，中国自动驾驶科技公司文远知行与Grab宣布，在新加坡榜鹅地区启动自动驾驶出行服务公开运营，这也是新加坡首个在住宅区部署的自动驾驶公共出行服务。</p>\\n<p>去年底，我曾在榜鹅实地看到过文远知行的Robotaxi GXR Ai.r，紫红色渐变外观的七座车，在榜鹅灰白色的组屋群中十分显眼，试点期间，当地居民可以通过申请试乘Ai.r，车上空间很大，即使拿着行李箱也没问题。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8666e99bcaa34b39887e1a27a5a16964@6162492_oswg204522oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\"></p>\\n<p>文远知行的Robotaxi GXR Ai.r；作者拍摄</p>\\n<p>榜鹅区域的发展阶段，恰好满足新兴技术落地的要求，因为是新区，这里的居民更年轻，对科技的接受程度也更高。</p>\\n<p>就拿文远知行的自动驾驶来说，初期试点时，榜鹅的人流与路况不会像市中心那样过于复杂，但榜鹅也具备完整的生活配套，组屋社区、地铁站、写字楼，Robotaxi GXR得以在这样的真实环境下，验证技术可行性。</p>\\n<p>“新加坡政府要把榜鹅发展成一个AI driven（驱动）、AI focus（聚焦）的区域，自动驾驶就很符合这里的AI narrative（叙事）。”陪同我的文远知行工作人员谈到。</p>\\n<p>你可以把这里想象成新加坡的硅谷，同样是在蛮荒中开辟一块创新之地，榜鹅的动作迅速，自2018年起，新加坡政府就联合工业巨头裕廊集团，着手筹建榜鹅数码园区，第一阶段工程在2024年落地， 预计整个项目将在2026年完成。</p>\\n<p>在招商层面，园区除了招揽新加坡企业入驻外，也希望引进更多跨国企业，首批四家跨国企业中就有中国企业的身影。</p>\\n<p>相关资料显示，这四家企业分别为提供智慧生活方案的台达集团新加坡子公司Delta Electronics Int’l (Singapore)、机器人技术公司Boston Dynamics、网络安全公司Group-IB以及来自中国的区块链公司万向（Wanxiang）。</p>\\n<p>在硅谷的产业构成中，诸如斯坦福等高校的存在必不可少。毗邻榜鹅园区的，则是新加坡第五所公立大学——新加坡理工大学 (Singapore Institute of Technology) 的校园，为了让产、学合作更紧密，在园区设计上，也通过廊道互通的方式，将榜鹅园区与新加坡理工大学二者“无缝”连接起来。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_baaf3fb1cb4a43d98b04c712fbbcd4b9@6162492_oswg243769oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\"></p>\\n<p>新加坡理工大学 (Singapore Institute of Technology) 的校园；作者拍摄</p>\\n<p>新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)，向我们介绍了新加坡政府对榜鹅的规划，在他的演示文档中，榜鹅的定位是“Singapore’s First Smart Town（新加坡首个智慧小镇）”。</p>\\n<p>所谓“智慧小镇”，是指园区背后依托的核心系统采用开放智能平台（Open Digital Platform）技术，通过传感器、数字平台，园区得以实现数据可视化、设备实时监控、AI节能等，同时园区倡导可持续理念，设置了屋顶太阳能板发电、雨水净化灌溉、 厨余垃圾转化为肥料等多种绿色设施，都体现了新加坡发展绿色城市的理念。</p>\\n<p>新加坡对于发展人工智能的决心可见一斑。2026年2月12日，新加坡总理兼财政部长黄循财在发表财政预算案声明中时谈到，新加坡将启动新的人工智能发展愿景（AI Missions），率先推动四个关键经济领域的人工智能转型，即互联互通、先进制造业、金融和医疗保健。</p>\\n<p>为落实相关计划，新加坡政府还将成立由黄循财领导的全国人工智能理事会（National AI Council）。黄循财强调，在变革的世界中，新加坡能否成功，取决于如何运用新科技，而人工智能是其中最关键的一环。</p>\\n<p>不过，对于人口只有600万人，面积还不到北京朝阳区两倍的新加坡来说，发展人工智能，最重要的优势，是对人才的吸引力。</p>\\n<p>包括Meta、OpenAI、Google等全球顶尖科技公司，均在新加坡设有规模不小的分部，中国有不少赫赫有名的AI公司选择迁居新加坡发展业务，比如今年刚刚被谷歌收购的中国AI初创公司Manus。</p>\\n<p>Manus在新加坡的办公地址，位于市中心Funan商场旁的一家WeWork里，这里经常能遇到讲着中文的华人面孔。工作环境和国内没什么不同，负一层能吃到不到5新币（不到30元）的吉野家和麻辣烫，4楼就有纯K。</p>\\n<p>对于迁居而来的中国员工来说，除了常年高温潮湿的气候，在生活习惯上几乎可以无缝切换。</p>\\n<p>从新加坡政府的视角，对于创新企业来说，找到一个人才宜居、且能够方便抵达的地方，相当重要。</p>\\n<p>“你要在全世界找一个中国人、美国人、欧洲人，都愿意来的地方，这种选择真的不多，新加坡就是其中之一。”沈丰吉对我们说。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3fe6a14712ac43b5b47e16e6cf852a2f@6162492_oswg249458oswg1702oswg1276_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\"></p>\\n<p>新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)；作者拍摄</p>\\n<p>而对于这样的高新企业，新加坡政府也会协助他们落地发展。</p>\\n<p>“（我们）像一个班级的老师，要照顾班上每一个同学的需求。”沈丰吉笑着比喻道。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'新加坡的AI征途：孕育下一个“硅谷”\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'新加坡的AI征途：孕育下一个“硅谷”\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/p/3768997634130434?f=rss\'}], \'link\': \'https://36kr.com/p/3768997634130434?f=rss\', \'published\': \'2026-04-16 14:59:53  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=6, tm_min=59, tm_sec=53, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'<p>“Punggol”，是一个位于新加坡东北部的新区，它有一个可爱的中文名：“榜鹅”，读起来，确实像某种动物的叫声。</p>\\\\n  <p>Punggol其实是马来语，翻译过来，是指用木棍敲打果树，把果子打下来。</p>\\\\n  <p>而现实中的榜鹅镇，相当长一段时间，都被大片大片森林覆盖。当新加坡乌节路的写字楼一栋栋拔地而起时，榜鹅还是一片蛮荒之地，即使现在，新加坡本地人告诉我，“有人在丛林中看到过狮子”。</p>\\\\n  <p>不过，如今的榜鹅，有的不仅是密林与野兽的传说，设在此地的榜鹅数码园区(Punggol Digital District, PDD) 是新加坡新晋的科技创新聚集地。</p>\\\\n  <p>就在4月初，中国自动驾驶科技公司文远知行与Grab宣布，在新加坡榜鹅地区启动自动驾驶出行服务公开运营，这也是新加坡首个在住宅区部署的自动驾驶公共出行服务。</p>\\\\n  <p>去年底，我曾在榜鹅实地看到过文远知行的Robotaxi GXR Ai.r，紫红色渐变外观的七座车，在榜鹅灰白色的组屋群中十分显眼，试点期间，当地居民可以通过申请试乘Ai.r，车上空间很大，即使拿着行李箱也没问题。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8666e99bcaa34b39887e1a27a5a16964@6162492_oswg204522oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">文远知行的Robotaxi GXR Ai.r；作者拍摄</p>\\\\n  <p>榜鹅区域的发展阶段，恰好满足新兴技术落地的要求，因为是新区，这里的居民更年轻，对科技的接受程度也更高。</p>\\\\n  <p>就拿文远知行的自动驾驶来说，初期试点时，榜鹅的人流与路况不会像市中心那样过于复杂，但榜鹅也具备完整的生活配套，组屋社区、地铁站、写字楼，Robotaxi GXR得以在这样的真实环境下，验证技术可行性。</p>\\\\n  <p>“新加坡政府要把榜鹅发展成一个AI driven（驱动）、AI focus（聚焦）的区域，自动驾驶就很符合这里的AI narrative（叙事）。”陪同我的文远知行工作人员谈到。</p>\\\\n  <p>你可以把这里想象成新加坡的硅谷，同样是在蛮荒中开辟一块创新之地，榜鹅的动作迅速，自2018年起，新加坡政府就联合工业巨头裕廊集团，着手筹建榜鹅数码园区，第一阶段工程在2024年落地， 预计整个项目将在2026年完成。</p>\\\\n  <p>在招商层面，园区除了招揽新加坡企业入驻外，也希望引进更多跨国企业，首批四家跨国企业中就有中国企业的身影。</p>\\\\n  <p>相关资料显示，这四家企业分别为提供智慧生活方案的台达集团新加坡子公司Delta Electronics Int’l (Singapore)、机器人技术公司Boston Dynamics、网络安全公司Group-IB以及来自中国的区块链公司万向（Wanxiang）。</p>\\\\n  <p>在硅谷的产业构成中，诸如斯坦福等高校的存在必不可少。毗邻榜鹅园区的，则是新加坡第五所公立大学——新加坡理工大学 (Singapore Institute of Technology) 的校园，为了让产、学合作更紧密，在园区设计上，也通过廊道互通的方式，将榜鹅园区与新加坡理工大学二者“无缝”连接起来。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_baaf3fb1cb4a43d98b04c712fbbcd4b9@6162492_oswg243769oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">新加坡理工大学 (Singapore Institute of Technology) 的校园；作者拍摄</p>\\\\n  <p>新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)，向我们介绍了新加坡政府对榜鹅的规划，在他的演示文档中，榜鹅的定位是“Singapore’s First Smart Town（新加坡首个智慧小镇）”。</p>\\\\n  <p>所谓“智慧小镇”，是指园区背后依托的核心系统采用开放智能平台（Open Digital Platform）技术，通过传感器、数字平台，园区得以实现数据可视化、设备实时监控、AI节能等，同时园区倡导可持续理念，设置了屋顶太阳能板发电、雨水净化灌溉、 厨余垃圾转化为肥料等多种绿色设施，都体现了新加坡发展绿色城市的理念。</p>\\\\n  <p>新加坡对于发展人工智能的决心可见一斑。2026年2月12日，新加坡总理兼财政部长黄循财在发表财政预算案声明中时谈到，新加坡将启动新的人工智能发展愿景（AI Missions），率先推动四个关键经济领域的人工智能转型，即互联互通、先进制造业、金融和医疗保健。</p>\\\\n  <p>为落实相关计划，新加坡政府还将成立由黄循财领导的全国人工智能理事会（National AI Council）。黄循财强调，在变革的世界中，新加坡能否成功，取决于如何运用新科技，而人工智能是其中最关键的一环。</p>\\\\n  <p>不过，对于人口只有600万人，面积还不到北京朝阳区两倍的新加坡来说，发展人工智能，最重要的优势，是对人才的吸引力。</p>\\\\n  <p>包括Meta、OpenAI、Google等全球顶尖科技公司，均在新加坡设有规模不小的分部，中国有不少赫赫有名的AI公司选择迁居新加坡发展业务，比如今年刚刚被谷歌收购的中国AI初创公司Manus。</p>\\\\n  <p>Manus在新加坡的办公地址，位于市中心Funan商场旁的一家WeWork里，这里经常能遇到讲着中文的华人面孔。工作环境和国内没什么不同，负一层能吃到不到5新币（不到30元）的吉野家和麻辣烫，4楼就有纯K。</p>\\\\n  <p>对于迁居而来的中国员工来说，除了常年高温潮湿的气候，在生活习惯上几乎可以无缝切换。</p>\\\\n  <p>从新加坡政府的视角，对于创新企业来说，找到一个人才宜居、且能够方便抵达的地方，相当重要。</p>\\\\n  <p>“你要在全世界找一个中国人、美国人、欧洲人，都愿意来的地方，这种选择真的不多，新加坡就是其中之一。”沈丰吉对我们说。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3fe6a14712ac43b5b47e16e6cf852a2f@6162492_oswg249458oswg1702oswg1276_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)；作者拍摄</p>\\\\n  <p>而对于这样的高新企业，新加坡政府也会协助他们落地发展。</p>\\\\n  <p>“（我们）像一个班级的老师，要照顾班上每一个同学的需求。”沈丰吉笑着比喻道。</p>\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'<p>“Punggol”，是一个位于新加坡东北部的新区，它有一个可爱的中文名：“榜鹅”，读起来，确实像某种动物的叫声。</p>\\\\n  <p>Punggol其实是马来语，翻译过来，是指用木棍敲打果树，把果子打下来。</p>\\\\n  <p>而现实中的榜鹅镇，相当长一段时间，都被大片大片森林覆盖。当新加坡乌节路的写字楼一栋栋拔地而起时，榜鹅还是一片蛮荒之地，即使现在，新加坡本地人告诉我，“有人在丛林中看到过狮子”。</p>\\\\n  <p>不过，如今的榜鹅，有的不仅是密林与野兽的传说，设在此地的榜鹅数码园区(Punggol Digital District, PDD) 是新加坡新晋的科技创新聚集地。</p>\\\\n  <p>就在4月初，中国自动驾驶科技公司文远知行与Grab宣布，在新加坡榜鹅地区启动自动驾驶出行服务公开运营，这也是新加坡首个在住宅区部署的自动驾驶公共出行服务。</p>\\\\n  <p>去年底，我曾在榜鹅实地看到过文远知行的Robotaxi GXR Ai.r，紫红色渐变外观的七座车，在榜鹅灰白色的组屋群中十分显眼，试点期间，当地居民可以通过申请试乘Ai.r，车上空间很大，即使拿着行李箱也没问题。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8666e99bcaa34b39887e1a27a5a16964@6162492_oswg204522oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">文远知行的Robotaxi GXR Ai.r；作者拍摄</p>\\\\n  <p>榜鹅区域的发展阶段，恰好满足新兴技术落地的要求，因为是新区，这里的居民更年轻，对科技的接受程度也更高。</p>\\\\n  <p>就拿文远知行的自动驾驶来说，初期试点时，榜鹅的人流与路况不会像市中心那样过于复杂，但榜鹅也具备完整的生活配套，组屋社区、地铁站、写字楼，Robotaxi GXR得以在这样的真实环境下，验证技术可行性。</p>\\\\n  <p>“新加坡政府要把榜鹅发展成一个AI driven（驱动）、AI focus（聚焦）的区域，自动驾驶就很符合这里的AI narrative（叙事）。”陪同我的文远知行工作人员谈到。</p>\\\\n  <p>你可以把这里想象成新加坡的硅谷，同样是在蛮荒中开辟一块创新之地，榜鹅的动作迅速，自2018年起，新加坡政府就联合工业巨头裕廊集团，着手筹建榜鹅数码园区，第一阶段工程在2024年落地， 预计整个项目将在2026年完成。</p>\\\\n  <p>在招商层面，园区除了招揽新加坡企业入驻外，也希望引进更多跨国企业，首批四家跨国企业中就有中国企业的身影。</p>\\\\n  <p>相关资料显示，这四家企业分别为提供智慧生活方案的台达集团新加坡子公司Delta Electronics Int’l (Singapore)、机器人技术公司Boston Dynamics、网络安全公司Group-IB以及来自中国的区块链公司万向（Wanxiang）。</p>\\\\n  <p>在硅谷的产业构成中，诸如斯坦福等高校的存在必不可少。毗邻榜鹅园区的，则是新加坡第五所公立大学——新加坡理工大学 (Singapore Institute of Technology) 的校园，为了让产、学合作更紧密，在园区设计上，也通过廊道互通的方式，将榜鹅园区与新加坡理工大学二者“无缝”连接起来。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_baaf3fb1cb4a43d98b04c712fbbcd4b9@6162492_oswg243769oswg1269oswg951_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">新加坡理工大学 (Singapore Institute of Technology) 的校园；作者拍摄</p>\\\\n  <p>新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)，向我们介绍了新加坡政府对榜鹅的规划，在他的演示文档中，榜鹅的定位是“Singapore’s First Smart Town（新加坡首个智慧小镇）”。</p>\\\\n  <p>所谓“智慧小镇”，是指园区背后依托的核心系统采用开放智能平台（Open Digital Platform）技术，通过传感器、数字平台，园区得以实现数据可视化、设备实时监控、AI节能等，同时园区倡导可持续理念，设置了屋顶太阳能板发电、雨水净化灌溉、 厨余垃圾转化为肥料等多种绿色设施，都体现了新加坡发展绿色城市的理念。</p>\\\\n  <p>新加坡对于发展人工智能的决心可见一斑。2026年2月12日，新加坡总理兼财政部长黄循财在发表财政预算案声明中时谈到，新加坡将启动新的人工智能发展愿景（AI Missions），率先推动四个关键经济领域的人工智能转型，即互联互通、先进制造业、金融和医疗保健。</p>\\\\n  <p>为落实相关计划，新加坡政府还将成立由黄循财领导的全国人工智能理事会（National AI Council）。黄循财强调，在变革的世界中，新加坡能否成功，取决于如何运用新科技，而人工智能是其中最关键的一环。</p>\\\\n  <p>不过，对于人口只有600万人，面积还不到北京朝阳区两倍的新加坡来说，发展人工智能，最重要的优势，是对人才的吸引力。</p>\\\\n  <p>包括Meta、OpenAI、Google等全球顶尖科技公司，均在新加坡设有规模不小的分部，中国有不少赫赫有名的AI公司选择迁居新加坡发展业务，比如今年刚刚被谷歌收购的中国AI初创公司Manus。</p>\\\\n  <p>Manus在新加坡的办公地址，位于市中心Funan商场旁的一家WeWork里，这里经常能遇到讲着中文的华人面孔。工作环境和国内没什么不同，负一层能吃到不到5新币（不到30元）的吉野家和麻辣烫，4楼就有纯K。</p>\\\\n  <p>对于迁居而来的中国员工来说，除了常年高温潮湿的气候，在生活习惯上几乎可以无缝切换。</p>\\\\n  <p>从新加坡政府的视角，对于创新企业来说，找到一个人才宜居、且能够方便抵达的地方，相当重要。</p>\\\\n  <p>“你要在全世界找一个中国人、美国人、欧洲人，都愿意来的地方，这种选择真的不多，新加坡就是其中之一。”沈丰吉对我们说。</p>\\\\n  <p class=\\\"image-wrapper\\\"><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3fe6a14712ac43b5b47e16e6cf852a2f@6162492_oswg249458oswg1702oswg1276_img_jpeg?x-oss-process=image/quality,q_100/format,jpg/interlace,1\\\" /></p>\\\\n  <p class=\\\"img-desc\\\">新加坡数码发展及新闻部 (MDDI) 数码政府副常任秘书沈丰吉 (Sim Feng-Ji)；作者拍摄</p>\\\\n  <p>而对于这样的高新企业，新加坡政府也会协助他们落地发展。</p>\\\\n  <p>“（我们）像一个班级的老师，要照顾班上每一个同学的需求。”沈丰吉笑着比喻道。</p>\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 14:59:53\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 14:59:53', '2026-04-16 18:14:39');
INSERT INTO `news_detail` VALUES (53, 2049, 11, '服务与基建', '亚马逊全球智能枢纽仓（GWD）深圳首仓面向卖家正式开放', '', '36氪获悉，亚马逊今日宣布，全球首个亚马逊全球智能枢纽仓（Global Warehousing and Distribution, GWD）在深圳正式向卖家全面开放。目前，深圳GWD仓支持向亚马逊美国站运营中心（Fulfillment Center）发货。', 'https://36kr.com/newsflashes/3769310482514438?f=rss', 0, '', '{\"summary\": \"本文告知亚马逊全球首个智能枢纽仓深圳首仓开放，帮助中国出海卖家优化对美跨境物流\", \"abstract\": \"亚马逊宣布全球首个全球智能枢纽仓（GWD）深圳首仓正式面向卖家全面开放。目前该深圳GWD仓仅支持向亚马逊美国站运营中心发货。该设施开放将帮助中国出海亚马逊卖家优化跨境发货链路，提升对美出海物流效率。\", \"keywords\": [\"亚马逊\", \"GWD\", \"全球智能枢纽仓\", \"跨境物流\", \"出海卖家\", \"美国站\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"供应链物流\", \"industry_category\": \"服务与基建\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3769310482514438?f=rss\", \"title\": \"亚马逊全球智能枢纽仓（GWD）深圳首仓面向卖家正式开放\", \"source\": \"https://36kr.com/feed\", \"content\": \"36氪获悉，亚马逊今日宣布，全球首个亚马逊全球智能枢纽仓（Global Warehousing and Distribution, GWD）在深圳正式向卖家全面开放。目前，深圳GWD仓支持向亚马逊美国站运营中心（Fulfillment Center）发货。\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'亚马逊全球智能枢纽仓（GWD）深圳首仓面向卖家正式开放\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'亚马逊全球智能枢纽仓（GWD）深圳首仓面向卖家正式开放\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3769310482514438?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3769310482514438?f=rss\', \'published\': \'2026-04-16 17:40:54  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=9, tm_min=40, tm_sec=54, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'36氪获悉，亚马逊今日宣布，全球首个亚马逊全球智能枢纽仓（Global Warehousing and Distribution, GWD）在深圳正式向卖家全面开放。目前，深圳GWD仓支持向亚马逊美国站运营中心（Fulfillment Center）发货。\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'36氪获悉，亚马逊今日宣布，全球首个亚马逊全球智能枢纽仓（Global Warehousing and Distribution, GWD）在深圳正式向卖家全面开放。目前，深圳GWD仓支持向亚马逊美国站运营中心（Fulfillment Center）发货。\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 17:40:54\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 17:40:54', '2026-04-16 18:19:17');
INSERT INTO `news_detail` VALUES (54, 2059, 19, '跨境支付与金融配套', '英国金融行为监管局：推出更清晰、更简化的卖空规则', '', '英国金融行为监管局（FCA）表示，推出更清晰、更简化的卖空规则。已最终确定更简化的英国卖空制度，这将减少企业的报告负担，同时保持监管监督。FCA将公布显示每家公司净卖空头寸总体规模的汇总数据，而不是披露具体的卖空方身份。新规明确了FCA将以更适当、更务实的方式监管卖空活动。（财联社）', 'https://36kr.com/newsflashes/3769288956936969?f=rss', 0, '', '{\"summary\": \"帮助出海英国的金融相关企业了解英国FCA最新卖空监管新规，清晰掌握合规要求\", \"abstract\": \"英国金融行为监管局（FCA）正式推出更清晰、更简化的卖空新规。新规确定了简化后的英国卖空制度，在保留监管监督的同时减少了相关企业的报告负担。新规调整了披露规则，FCA将仅公布每家公司净卖空头寸的总体汇总规模，不会披露具体卖空方身份。新规明确FCA将以更适当务实的方式监管卖空活动。\", \"keywords\": [\"英国FCA\", \"卖空规则\", \"监管合规\", \"金融出海\", \"信息披露\", \"卖空制度\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"英国FCA推出更清晰简化的卖空新规，简化卖空制度减少企业报告负担，仅公布净卖空头寸汇总数据，不披露具体卖空方身份，将以更适当务实的方式监管卖空活动\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"跨境支付与金融配套\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3769288956936969?f=rss\", \"title\": \"英国金融行为监管局：推出更清晰、更简化的卖空规则\", \"source\": \"https://36kr.com/feed\", \"content\": \"英国金融行为监管局（FCA）表示，推出更清晰、更简化的卖空规则。已最终确定更简化的英国卖空制度，这将减少企业的报告负担，同时保持监管监督。FCA将公布显示每家公司净卖空头寸总体规模的汇总数据，而不是披露具体的卖空方身份。新规明确了FCA将以更适当、更务实的方式监管卖空活动。（财联社）\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'英国金融行为监管局：推出更清晰、更简化的卖空规则\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'英国金融行为监管局：推出更清晰、更简化的卖空规则\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'https://36kr.com/newsflashes/3769288956936969?f=rss\'}], \'link\': \'https://36kr.com/newsflashes/3769288956936969?f=rss\', \'published\': \'2026-04-16 17:19:00  +0800\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=9, tm_min=19, tm_sec=0, tm_wday=3, tm_yday=106, tm_isdst=0), \'summary\': \'英国金融行为监管局（FCA）表示，推出更清晰、更简化的卖空规则。已最终确定更简化的英国卖空制度，这将减少企业的报告负担，同时保持监管监督。FCA将公布显示每家公司净卖空头寸总体规模的汇总数据，而不是披露具体的卖空方身份。新规明确了FCA将以更适当、更务实的方式监管卖空活动。（财联社）\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://36kr.com/feed\', \'value\': \'英国金融行为监管局（FCA）表示，推出更清晰、更简化的卖空规则。已最终确定更简化的英国卖空制度，这将减少企业的报告负担，同时保持监管监督。FCA将公布显示每家公司净卖空头寸总体规模的汇总数据，而不是披露具体的卖空方身份。新规明确了FCA将以更适当、更务实的方式监管卖空活动。（财联社）\'}, \'source\': {\'title\': \'36氪\'}}\", \"published_at\": \"2026-04-16 17:19:00\", \"ai_json_output\": \"\"}', NULL, '2026-04-16 17:19:00', '2026-04-16 18:19:40');
INSERT INTO `news_detail` VALUES (55, 2092, 11, '服务与基建', '港媒：香港巩固全球商贸枢纽地位', '', '参考消息网4月13日报道香港《亚洲周刊》4月13日一期刊登题为《香港跃升全球商贸经济体前列》的文章，内容如下：根据世界贸易组织最新发表的《全球贸易展望与统计》报告，香港2025年跃升为全球第五大商品贸<br>', 'http://baijiahao.baidu.com/s?id=1862339075511482839', 0, '', '{\"summary\": \"本文披露WTO对香港贸易地位的最新预测，帮助出海企业把握香港商贸枢纽优势，规划出海布局\", \"abstract\": \"本文引用港媒的相关报道，援引世界贸易组织最新发布的全球贸易报告内容，提到香港将在2025年跃升为全球第五大商品贸易经济体，指出香港正不断巩固自身全球商贸枢纽的地位，可供出海企业规划全球布局参考。\", \"keywords\": [\"香港\", \"全球商贸枢纽\", \"世界贸易组织\", \"商品贸易\", \"全球贸易\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"服务与基建\"}', '', '{\"url\": \"http://baijiahao.baidu.com/s?id=1862339075511482839\", \"title\": \"港媒：香港巩固全球商贸枢纽地位\", \"source\": \"http://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\", \"content\": \"参考消息网4月13日报道香港《亚洲周刊》4月13日一期刊登题为《香港跃升全球商贸经济体前列》的文章，内容如下：根据世界贸易组织最新发表的《全球贸易展望与统计》报告，香港2025年跃升为全球第五大商品贸<br>\", \"is_policy\": 0, \"origin_msg\": \"{\'title\': \'港媒：香港巩固全球商贸枢纽地位\', \'title_detail\': {\'type\': \'text/plain\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'港媒：香港巩固全球商贸枢纽地位\'}, \'links\': [{\'rel\': \'alternate\', \'type\': \'text/html\', \'href\': \'http://baijiahao.baidu.com/s?id=1862339075511482839\'}], \'link\': \'http://baijiahao.baidu.com/s?id=1862339075511482839\', \'published\': \'2026-04-16T10:19:46.000Z\', \'published_parsed\': time.struct_time(tm_year=2026, tm_mon=4, tm_mday=16, tm_hour=10, tm_min=19, tm_sec=46, tm_wday=3, tm_yday=106, tm_isdst=0), \'source\': {}, \'authors\': [{}], \'author\': \'\', \'summary\': \'参考消息网4月13日报道香港《亚洲周刊》4月13日一期刊登题为《香港跃升全球商贸经济体前列》的文章，内容如下：根据世界贸易组织最新发表的《全球贸易展望与统计》报告，香港2025年跃升为全球第五大商品贸<br />\', \'summary_detail\': {\'type\': \'text/html\', \'language\': None, \'base\': \'https://news.baidu.com/n?cmd=1&class=gangaotai&tn=rss\', \'value\': \'参考消息网4月13日报道香港《亚洲周刊》4月13日一期刊登题为《香港跃升全球商贸经济体前列》的文章，内容如下：根据世界贸易组织最新发表的《全球贸易展望与统计》报告，香港2025年跃升为全球第五大商品贸<br />\'}}\", \"published_at\": \"2026-04-16 10:19:46\", \"ai_json_output\": \"\"}', '百度首页\n登录\n搜索\n复制\n港媒：香港巩固全球商贸枢纽地位\n参考消息\n2026-04-13 15:11\n《参考消息》官方账号\n关注\n参考消息网4月13日报道\n香港《亚洲周刊》4月13日一期刊登题为《香港跃升全球商贸经济体前列》的文章，内容如下：\n根据世界贸易组织最新发表的《全球贸易展望与统计》报告，香港2025年跃升为全球第五大商品贸易经济体，较2024年跃升两位，反映香港经济复苏强劲。在全球局势动荡之下仍然保持活力，已然冲破疫情的困顿。上述排名主要计算香港的商品贸易总额，反映香港作为国际贸易枢纽地位稳固，预料在国际冲突频仍的2026年仍能成为中国“内联外通”的商品贸易中心。\n根据统计，去年香港的商品贸易总额高达15860亿美元，占全球总额3%，香港商贸出口升至7540亿美元，全球排名第五；进口则以8320亿美元排全球第六，两者均按年升三位。\n中国内地为全球商品贸易冠军，占全球总额12.2%；其次为美国，市占率为10.77%，之后是德国及荷兰。香港特区政府商务及经济发展局局长丘应桦更进一步表示，若将欧盟视作单一贸易经济体，香港可说是位列全球第四。\n不论是全球第四还是第五，均反映香港作为区域乃至全球商贸枢纽的地位稳固，在全球经济不明朗加剧、局势紧张下发挥中外重要贸易节点的功能。\n商品贸易发展上，按区域分布而言，香港与东盟国家的贸易增长最快。财政司副司长黄伟纶说，去年香港出口在东盟市场表现突出，对马来西亚出口增幅高达72%，对越南增长55%，对泰国亦增长接近40%。\n此外，香港作为两岸贸易枢纽的地位亦明显增强，香港在2025年12月对台湾出口同比增加72.7%，对台湾进口则增加30.8%，估计是由于人工智能发展对高技术产品的需求，令香港成为两岸贸易的桥梁，亦是台湾电子零件的中转和高价值产品贸易中心。\n香港传统上是区域以及全球的物流中心，但物流发展呈现“空运崛起、航运衰落”的趋势。香港巩固了其国际航空枢纽的地位，民航、空运物流方面均保持世界领先。虽然2025年的国际排名尚未公布，但根据此前国际机场理事会的排名，香港机场已连续14年被评为全球最繁忙货运机场。在中东机场面对美以伊战争的威胁下，香港的物流地位更显重要。\n对比航运，空运的货物量虽然有所不及，但空运货物附加值较高，占香港货物总出口的38%以及总进口的52.8%。香港政府也非常重视香港空运中心的地位，将引入人工智能、智能交通管理系统及绿色节能装置，优化货运流程。香港机场更不只限于本地，还在东莞设立物流园，实现“无缝”海空联运，内地货物可直接在东莞完成安检、打板及清关，再透过海路运至香港国际机场。要把握“低空经济”的先机，结合无人机与电动垂直起降飞行器，开展跨境货运、智能物流配送及大湾区接驳服务。\n香港正处于经济转型的关键时刻，上述数据反映香港经济活力充足。旅游业亦为香港经济注入活力，带动零售及餐饮业蓬勃发展。在资本市场方面，香港IPO重夺全球第一位，今年同样势头良好，目前有超过400家公司正申请上市。\n由此可见，香港经济在金融、物流方面均有突破，令香港经济持续繁荣，在全球供应链重组过程中积极发挥“内联外通”关键功能，但政府亦要注意“数据热、体感冷”的问题，着重在经济发展过程中考虑财富分配，令社会整体获益。\n举报/反馈\n0\n0\n收藏\n分享\n微信好友\n新浪微博\n复制链接\n扫码分享至微信\n设为首页\n© Baidu\n使用百度前必读\n京ICP证030173号\n京公网安备11000002000001号', '2026-04-16 10:19:46', '2026-04-16 18:20:50');
INSERT INTO `news_detail` VALUES (56, 2184, 7, '消费与零售', 'Apple accelerates eco progress with highest-ever recycled materials', '', '<p>Article URL: <a href=\"https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/\">https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/</a></p>\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47791855\">https://news.ycombinator.com/item?id=47791855</a></p>\n<p>Points: 63</p>\n<p># Comments: 55</p>', 'https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/', 0, '', '{\"summary\": \"帮助出海消费电子企业掌握海外头部品牌环保动向，把握行业可持续发展趋势\", \"abstract\": \"这是苹果2026年4月发布的环保进展新闻，宣布其产品中回收材料使用占比达到历史最高水平，正加速推进生态环保目标。该新闻在海外科技社区引发讨论，获得了较高关注度。这一动向反映了全球消费电子行业的可持续发展趋势，可为出海相关企业提供方向参考。\", \"keywords\": [\"苹果\", \"回收材料\", \"环保\", \"消费电子\", \"ESG\", \"可持续发展\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/\", \"title\": \"Apple accelerates eco progress with highest-ever recycled materials\", \"source\": \"https://hnrss.org/frontpage\", \"content\": \"<p>Article URL: <a href=\\\"https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/\\\">https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/</a></p>\\n<p>Comments URL: <a href=\\\"https://news.ycombinator.com/item?id=47791855\\\">https://news.ycombinator.com/item?id=47791855</a></p>\\n<p>Points: 63</p>\\n<p># Comments: 55</p>\", \"is_policy\": 0, \"origin_msg\": \"{\\\"title\\\": \\\"Apple accelerates eco progress with highest-ever recycled materials\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://hnrss.org/frontpage\\\", \\\"value\\\": \\\"Apple accelerates eco progress with highest-ever recycled materials\\\"}, \\\"summary\\\": \\\"<p>Article URL: <a href=\\\\\\\"https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/\\\\\\\">https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/</a></p>\\\\n<p>Comments URL: <a href=\\\\\\\"https://news.ycombinator.com/item?id=47791855\\\\\\\">https://news.ycombinator.com/item?id=47791855</a></p>\\\\n<p>Points: 63</p>\\\\n<p># Comments: 55</p>\\\", \\\"summary_detail\\\": {\\\"type\\\": \\\"text/html\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://hnrss.org/frontpage\\\", \\\"value\\\": \\\"<p>Article URL: <a href=\\\\\\\"https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/\\\\\\\">https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/</a></p>\\\\n<p>Comments URL: <a href=\\\\\\\"https://news.ycombinator.com/item?id=47791855\\\\\\\">https://news.ycombinator.com/item?id=47791855</a></p>\\\\n<p>Points: 63</p>\\\\n<p># Comments: 55</p>\\\"}, \\\"published\\\": \\\"Thu, 16 Apr 2026 12:11:17 +0000\\\", \\\"published_parsed\\\": [2026, 4, 16, 12, 11, 17, 3, 106, 0], \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/\\\"}], \\\"link\\\": \\\"https://www.apple.com/newsroom/2026/04/apple-accelerates-progress-with-highest-ever-recycled-material-in-its-products/\\\", \\\"authors\\\": [{\\\"name\\\": \\\"salkahfi\\\"}], \\\"author\\\": \\\"salkahfi\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"salkahfi\\\"}, \\\"comments\\\": \\\"https://news.ycombinator.com/item?id=47791855\\\", \\\"id\\\": \\\"https://news.ycombinator.com/item?id=47791855\\\", \\\"guidislink\\\": false}\", \"published_at\": \"2026-04-16 12:11:17\", \"ai_json_output\": \"\"}', 'UPDATE\nApril 16, 2026\nApple accelerates environmental progress with highest‑ever recycled material in its products\nNew milestones include removing plastic from packaging, using 100 percent recycled cobalt in Apple-designed batteries, and replenishing more than half of Apple’s corporate water use\nWith this year’s launch of MacBook Neo, featuring 60 percent recycled content overall, and other key environmental milestones announced today, Apple is making steady gains toward its ambitious goal to be carbon neutral across its entire footprint by 2030.\nApple today announced that a record 30 percent of material across all of its products shipped in 2025 came from recycled content.\n1\nThe achievement, along with other key progress milestones Apple shared today, is the result of innovation by teams across Apple and deep collaboration with its global supply chain. As part of this work, Apple now uses 100 percent recycled cobalt in all the batteries it designs and 100 percent recycled rare earth elements in all magnets.\n2\nThe company also accomplished its goal to remove plastic from packaging, with Apple products now shipping in fiber-based packaging that can be easily recycled at home.\n3\n“At Apple, we believe deeply in leaving the world better than we found it, and that commitment runs across everything we do,” said Tim Cook, Apple’s CEO. “These milestones in our work to protect the planet show that ambitious goals can also be powerful engines of innovation. And as always, we’ll keep pushing to build on this progress even more.”\nIn its annual\nEnvironmental Progress Report\nreleased today, Apple marked progress toward Apple 2030, the company’s ambitious goal to be carbon neutral across its entire footprint by the end of this decade. Apple’s greenhouse gas emissions in 2025 remain down over 60 percent compared to 2015 levels, holding constant from 2024 even in a year of significant business growth. The report highlights additional progress in renewable energy, materials innovation and recycling, water stewardship, and zero waste.\nTo celebrate Earth Day, Apple is sharing its environmental milestones for 2025, as highlighted in the company’s annual Environmental Progress Report.\nTo celebrate Earth Day, Apple is sharing its environmental milestones for 2025, as highlighted in the company’s annual Environmental Progress Report.\nTo celebrate Earth Day, Apple is sharing its environmental milestones for 2025, as highlighted in the company’s annual Environmental Progress Report.\nTo celebrate Earth Day, Apple is sharing its environmental milestones for 2025, as highlighted in the company’s annual Environmental Progress Report.\n“Across every part of our business, we’re showing how innovation and collaboration can turn big ideas and bold ambitions into measurable progress,” said Sabih Khan, Apple’s chief operating officer. “From expanding recycled material to removing plastic from our packaging, we’re setting new benchmarks that inspire us to reach further and work even harder for the good of people and planet.”\nAs Apple celebrates Earth Day with its teams, partners, and customers around the world — including with a special offer for users who bring in their Apple devices for recycling at participating Apple Store locations\n4\n— here’s a look at the progress the company is making across its environmental initiatives.\nSetting New Benchmarks for Recycled Content\nOn top of hitting 30 percent recycled content across all of its products shipped in 2025, Apple also reached several targets for recycled content in select components last year. Today, all batteries designed by Apple are made with 100 percent recycled cobalt, and all magnets are made with 100 percent recycled rare earth elements. Additionally, all Apple-designed printed circuit boards are made with 100 percent recycled gold plating and tin soldering. Whether materials are recycled or primary, Apple is committed to sourcing all materials responsibly, and drives high standards for human rights and the environment across its supply chain.\nApple met several goals for transitioning to recycled material in select components, including 100 percent recycled gold plating in all Apple-designed printed circuit boards.\nInnovating to Remove Plastic\nApple completed the transition to 100 percent fiber-based packaging last year, fulfilling its pledge to remove plastic from packaging by 2025. Over the past 10 years, Apple engineers and designers have developed alternatives to common packaging components, replacing plastic screen protectors and trays with versions made with recycled or responsibly sourced paper. They also innovated to make packaging more recyclable, designing the largest boxes, like for the new Studio Display XDR, to collapse into smaller pieces that fit into a home recycling bin. Apple avoided more than 15,000 metric tons of plastic in the past five years alone — the equivalent of about 500 million plastic water bottles.\n5\nApple completed the transition to 100 percent fiber-based packaging, fulfilling its pledge to remove plastic from packaging by 2025.\nInvesting in Next-Generation Recycling Technology\nAs the company expands the use of recycled material in its products, Apple is also developing new technology to help maximize the material recovered from devices at the end of their life. Apple launched Cora, a new world-class electronics-recycling line located at the Advanced Recovery Center in California. Designed and built in the U.S., Cora uses precision shredding and advanced sensor technology to achieve material recovery rates that are significantly higher than industry baselines. Apple also developed\nA.R.I.S.\n, a new detection system powered by machine learning, to help recyclers efficiently classify and sort electronic scrap. Leveraging the A.R.I.S. software, which runs on Mac mini, Apple is piloting new, industry-deployable recycling tools with partner recyclers.\nCora, Apple’s next-generation electronics recycling system in California, promises higher material recovery rates from recycled Apple products.\nExpanding Renewable Energy Across Apple’s Footprint\nApple’s direct suppliers procured more than 20 gigawatts of renewable energy last year as part of the Supplier Clean Energy Program, generating more than 38 million megawatt-hours of electricity. That’s enough clean electricity to power more than 3.4 million U.S. households for a year.\n6\nApple procured an additional 1.8 gigawatts of renewable energy to power its offices, retail stores, and data centers with 100 percent renewable electricity. And the company is advancing toward its Apple 2030 goal by enabling new renewable energy projects around the world to help match the energy customers use to charge and power their Apple products with 100 percent clean electricity.\nIn 2025, Apple and its direct suppliers procured more than 20 gigawatts of renewable energy — generating enough clean electricity to power more than 3.4 million U.S. households for a year.\nConserving and Replenishing Fresh Water Around the World\nLast year, Apple and its suppliers saved 17 billion gallons of fresh water — enough to fill more than 25,000 Olympic-size swimming pools. The company is also driving water conservation efforts across its corporate operations, and by 2030, is working to replenish all of the fresh water withdrawn to support Apple’s facilities worldwide through innovative, long-term partnerships designed to save, restore, and secure water at the watershed level. In 2025, Apple’s contracted projects replenished more than half the water it withdrew to support its global offices, data centers, and retail stores. Additionally, all eight Apple-owned data centers have now been certified to the Alliance for Water Stewardship standard.\nApple replenished 800 million gallons of water in 2025 — more than half the amount the company withdrew for its global facilities. Apple’s partnership with The Nature Conservancy helped the company replenish 100 percent of its water use in California. Photo by Andrea Craig, TNC.\nLaunching the Lowest-Carbon MacBook\nEarlier this year, Apple launched MacBook Neo, which was built from the ground up to be the company’s lowest-carbon MacBook. Featuring 60 percent recycled content overall, MacBook Neo has the most recycled content of any Apple device yet, including 100 percent recycled cobalt in the battery and 100 percent recycled rare earth elements in all magnets.\n7\nIts beautiful, durable enclosure is manufactured with a material-efficient forming process that uses half the raw material compared to traditional machining methods. And to conserve water in its production, Apple and its suppliers developed an enhanced, new anodization process that achieved a 70 percent water-reuse rate — transforming a traditionally water-intensive process into a closed-loop system that continuously recycles and recirculates water, preserving fresh water for only the most critical uses. Apple is working to expand this anodization process to additional production lines in the coming years.\nBuilt from the ground up, MacBook Neo is Apple’s lowest-carbon laptop computer with the most recycled content of any Apple device.\nDriving Waste to Zero\nThrough recycling, composting, and waste reduction efforts across all of its global facilities, Apple reached a waste diversion rate of 75 percent last year. And earlier this year, Apple Fifth Avenue became the company’s first-ever retail store to achieve TRUE Zero Waste Certification, which recognizes facilities that divert more than 90 percent of their waste from landfills. Apple Fifth Avenue joins five data centers and four corporate campuses that have already earned the certification at the platinum level. Across the supply chain, Apple and its suppliers redirected more than 600,000 metric tons of waste from landfills in 2025, with 400 supplier facilities actively participating in the company’s Zero Waste Program. All Apple products continue to ship from final assembly sites that maintain zero-waste-to-landfill operations.\n8\nEarlier this year, Apple Fifth Avenue became the company’s first-ever retail store to achieve TRUE Zero Waste Certification, which recognizes facilities that divert more than 90 percent of their waste from landfills.\nCelebrating Earth Day by Recycling with Apple\nAs part of Apple’s Earth Day celebration, customers who recycle an eligible Apple product at their local participating Apple Store from now until May 16 can receive 10 percent off Apple AirPods or accessories. Products brought to Apple for free recycling undergo thorough screenings, and eligible devices are sent to Apple’s advanced recycling systems, including Daisy and Cora, for further processing.\nWhen customers recycle the products they no longer use with Apple, their devices go through thorough screenings. Products and parts that cannot be reused or repaired may go to Apple’s advanced recycling systems, including Daisy and Cora.\nShare article\nMedia\nText of this article\nApril 16, 2026\nUPDATE\nApple accelerates environmental progress with highest‑ever recycled material in its products\nNew milestones include removing plastic from packaging, using 100 percent recycled cobalt in Apple-designed batteries, and replenishing more than half of Apple’s corporate water use\nApple today announced that a record 30 percent of material across all of its products shipped in 2025 came from recycled content.\n1\nThe achievement, along with other key progress milestones Apple shared today, is the result of innovation by teams across Apple and deep collaboration with its global supply chain. As part of this work, Apple now uses 100 percent recycled cobalt in all the batteries it designs and 100 percent recycled rare earth elements in all magnets.\n2\nThe company also accomplished its goal to remove plastic from packaging, with Apple products now shipping in fiber-based packaging that can be easily recycled at home.\n3\n“At Apple, we believe deeply in leaving the world better than we found it, and that commitment runs across everything we do,” said Tim Cook, Apple’s CEO. “These milestones in our work to protect the planet show that ambitious goals can also be powerful engines of innovation. And as always, we’ll keep pushing to build on this progress even more.”\nIn its annual\nEnvironmental Progress Report\nreleased today, Apple marked progress toward Apple 2030, the company’s ambitious goal to be carbon neutral across its entire footprint by the end of this decade. Apple’s greenhouse gas emissions in 2025 remain down over 60 percent compared to 2015 levels, holding constant from 2024 even in a year of significant business growth. The report highlights additional progress in renewable energy, materials innovation and recycling, water stewardship, and zero waste.\n“Across every part of our business, we’re showing how innovation and collaboration can turn big ideas and bold ambitions into measurable progress,” said Sabih Khan, Apple’s chief operating officer. “From expanding recycled material to removing plastic from our packaging, we’re setting new benchmarks that inspire us to reach further and work even harder for the good of people and planet.”\nAs Apple celebrates Earth Day with its teams, partners, and customers around the world — including with a special offer for users who bring in their Apple devices for recycling at participating Apple Store locations\n4\n— here’s a look at the progress the company is making across its environmental initiatives.\nSetting New Benchmarks for Recycled Content\nOn top of hitting 30 percent recycled content across all of its products shipped in 2025, Apple also reached several targets for recycled content in select components last year. Today, all batteries designed by Apple are made with 100 percent recycled cobalt, and all magnets are made with 100 percent recycled rare earth elements. Additionally, all Apple-designed printed circuit boards are made with 100 percent recycled gold plating and tin soldering. Whether materials are recycled or primary, Apple is committed to sourcing all materials responsibly, and drives high standards for human rights and the environment across its supply chain.\nInnovating to Remove Plastic\nApple completed the transition to 100 percent fiber-based packaging last year, fulfilling its pledge to remove plastic from packaging by 2025. Over the past 10 years, Apple engineers and designers have developed alternatives to common packaging components, replacing plastic screen protectors and trays with versions made with recycled or responsibly sourced paper. They also innovated to make packaging more recyclable, designing the largest boxes, like for the new Studio Display XDR, to collapse into smaller pieces that fit into a home recycling bin. Apple avoided more than 15,000 metric tons of plastic in the past five years alone — the equivalent of about 500 million plastic water bottles.\n5\nInvesting in Next-Generation Recycling Technology\nAs the company expands the use of recycled material in its products, Apple is also developing new technology to help maximize the material recovered from devices at the end of their life. Apple launched Cora, a new world-class electronics-recycling line located at the Advanced Recovery Center in California. Designed and built in the U.S., Cora uses precision shredding and advanced sensor technology to achieve material recovery rates that are significantly higher than industry baselines. Apple also developed\nA.R.I.S.\n, a new detection system powered by machine learning, to help recyclers efficiently classify and sort electronic scrap. Leveraging the A.R.I.S. software, which runs on Mac mini, Apple is piloting new, industry-deployable recycling tools with partner recyclers.\nExpanding Renewable Energy Across Apple’s Footprint\nApple’s direct suppliers procured more than 20 gigawatts of renewable energy last year as part of the Supplier Clean Energy Program, generating more than 38 million megawatt-hours of electricity. That’s enough clean electricity to power more than 3.4 million U.S. households for a year.\n6\nApple procured an additional 1.8 gigawatts of renewable energy to power its offices, retail stores, and data centers with 100 percent renewable electricity. And the company is advancing toward its Apple 2030 goal by enabling new renewable energy projects around the world to help match the energy customers use to charge and power their Apple products with 100 percent clean electricity.\nConserving and Replenishing Fresh Water Around the World\nLast year, Apple and its suppliers saved 17 billion gallons of fresh water — enough to fill more than 25,000 Olympic-size swimming pools. The company is also driving water conservation efforts across its corporate operations, and by 2030, is working to replenish all of the fresh water withdrawn to support Apple’s facilities worldwide through innovative, long-term partnerships designed to save, restore, and secure water at the watershed level. In 2025, Apple’s contracted projects replenished more than half the water it withdrew to support its global offices, data centers, and retail stores. Additionally, all eight Apple-owned data centers have now been certified to the Alliance for Water Stewardship standard.\nLaunching the Lowest-Carbon MacBook\nEarlier this year, Apple launched MacBook Neo, which was built from the ground up to be the company’s lowest-carbon MacBook. Featuring 60 percent recycled content overall, MacBook Neo has the most recycled content of any Apple device yet, including 100 percent recycled cobalt in the battery and 100 percent recycled rare earth elements in all magnets.\n7\nIts beautiful, durable enclosure is manufactured with a material-efficient forming process that uses half the raw material compared to traditional machining methods. And to conserve water in its production, Apple and its suppliers developed an enhanced, new anodization process that achieved a 70 percent water-reuse rate — transforming a traditionally water-intensive process into a closed-loop system that continuously recycles and recirculates water, preserving fresh water for only the most critical uses. Apple is working to expand this anodization process to additional production lines in the coming years.\nDriving Waste to Zero\nThrough recycling, composting, and waste reduction efforts across all of its global facilities, Apple reached a waste diversion rate of 75 percent last year. And earlier this year, Apple Fifth Avenue became the company’s first-ever retail store to achieve TRUE Zero Waste Certification, which recognizes facilities that divert more than 90 percent of their waste from landfills. Apple Fifth Avenue joins five data centers and four corporate campuses that have already earned the certification at the platinum level. Across the supply chain, Apple and its suppliers redirected more than 600,000 metric tons of waste from landfills in 2025, with 400 supplier facilities actively participating in the company’s Zero Waste Program. All Apple products continue to ship from final assembly sites that maintain zero-waste-to-landfill operations.\n8\nCelebrating Earth Day by Recycling with Apple\nAs part of Apple’s Earth Day celebration, customers who recycle an eligible Apple product at their local participating Apple Store from now until May 16 can receive 10 percent off Apple AirPods or accessories. Products brought to Apple for free recycling undergo thorough screenings, and eligible devices are sent to Apple’s advanced recycling systems, including Daisy and Cora, for further processing.\nApple defines recycled content in alignment with ISO 14021. Total recycled material shipped in products is driven by product material composition and volume of units sold.\nExcludes inventory for replacement and repair, as well as excess inventory purchased prior to year-end currently being consumed and representing less than 0.1 percent of total material usage.\nApple achieved its goal of removing plastic in its packaging and transitioning to 100 percent fiber-based packaging. Every package manufactured today is made with 100 percent fiber-based materials. Apple’s goal excluded the inks, coatings, or adhesives used in its packaging. Existing inventory shipped with plastic-containing packaging will be sold until consumed to avoid waste. This category represented less than 0.4 percent of Apple’s total packaging footprint in fiscal year 2025.\nOffer available to customers who recycle an eligible Apple device and purchase a new eligible AirPods or accessory in the same transaction between April 16 and May 16, 2026. Only at Apple Store locations. See\napple.com/promo\nfor additional terms.\nSavings from 2021 to 2025 were calculated by multiplying each year’s sales volume by the previous year’s estimated plastic per unit for each product line, and then subtracting that year’s estimated plastic use. The water bottle equivalent assumes each bottle weighs 30 grams.\nSource based on the U.S. Environmental Protection Agency’s greenhouse gas equivalencies calculator:\nepa.gov/energy/greenhouse-gas-equivalencies-calculator\n.\nProduct recycled or renewable content is the mass of certified recycled material relative to the overall mass of the device, not including packaging or in-box accessories.\nAll established final-assembly supplier sites — or those that have been Apple suppliers for more than one year — for iPhone, iPad, Mac, Apple Watch, AirPods, HomePod, Apple TV, and Apple Vision Pro have been third-party verified by UL Solutions against the UL 2799 Zero Waste to Landfill Environmental Claim Validation Procedure (ECVP). UL Solutions requires at least 90 percent diversion through methods other than waste-to-energy to achieve Zero Waste to Landfill designations.\nThe information covered in this release contains forward-looking statements within the meaning of the Private Securities Litigation Reform Act of 1995, including statements regarding our goals, targets, commitments, and strategies. These statements involve risks and uncertainties, and actual results may differ materially from any future results expressed or implied by the forward-looking statements. More information on risks, uncertainties, and other potential factors that could affect our business and performance is included in our filings with the SEC.\nPress Contacts\nSean Redding\nApple\ns_redding@apple.com\nApple Media Helpline\nmedia.help@apple.com\nCopy text\nMedia in this article\nDownload all images\nApple defines recycled content in alignment with ISO 14021. Total recycled material shipped in products is driven by product material composition and volume of units sold.\nExcludes inventory for replacement and repair, as well as excess inventory purchased prior to year-end currently being consumed and representing less than 0.1 percent of total material usage.\nApple achieved its goal of removing plastic in its packaging and transitioning to 100 percent fiber-based packaging. Every package manufactured today is made with 100 percent fiber-based materials. Apple’s goal excluded the inks, coatings, or adhesives used in its packaging. Existing inventory shipped with plastic-containing packaging will be sold until consumed to avoid waste. This category represented less than 0.4 percent of Apple’s total packaging footprint in fiscal year 2025.\nOffer available to customers who recycle an eligible Apple device and purchase a new eligible AirPods or accessory in the same transaction between April 16 and May 16, 2026. Only at Apple Store locations. See\napple.com/promo\nfor additional terms.\nSavings from 2021 to 2025 were calculated by multiplying each year’s sales volume by the previous year’s estimated plastic per unit for each product line, and then subtracting that year’s estimated plastic use. The water bottle equivalent assumes each bottle weighs 30 grams.\nSource based on the U.S. Environmental Protection Agency’s greenhouse gas equivalencies calculator:\nepa.gov/energy/greenhouse-gas-equivalencies-calculator\n.\nProduct recycled or renewable content is the mass of certified recycled material relative to the overall mass of the device, not including packaging or in-box accessories.\nAll established final-assembly supplier sites — or those that have been Apple suppliers for more than one year — for iPhone, iPad, Mac, Apple Watch, AirPods, HomePod, Apple TV, and Apple Vision Pro have been third-party verified by UL Solutions against the UL 2799 Zero Waste to Landfill Environmental Claim Validation Procedure (ECVP). UL Solutions requires at least 90 percent diversion through methods other than waste-to-energy to achieve Zero Waste to Landfill designations.\nThe information covered in this release contains forward-looking statements within the meaning of the Private Securities Litigation Reform Act of 1995, including statements regarding our goals, targets, commitments, and strategies. These statements involve risks and uncertainties, and actual results may differ materially from any future results expressed or implied by the forward-looking statements. More information on risks, uncertainties, and other potential factors that could affect our business and performance is included in our filings with the SEC.\nPress Contacts\nSean Redding\nApple\ns_redding@apple.com\nApple Media Helpline\nmedia.help@apple.com', NULL, '2026-04-16 22:52:16');
INSERT INTO `news_detail` VALUES (57, 2203, 9, '内容与社交', '一夜之间，AI短剧成了所有人的新赛道', '', '<blockquote>\n<p>成本降至1/3，效率提升3倍，AI真人被视为新的创业风口；加上客观上大模型发展对技术难度的大幅降低，大量不同背景的参与者正在以不同方式涌入此赛道。</p>\n</blockquote>\n<p>2026年Q1，短剧市场剧烈变革，AI仿真人赛道开启了狂热的创业潮，几乎所有人都想挤进市场分一杯羹。</p>\n<p>一方面，大批短剧、漫剧公司，甚至一些曾经的长剧、综艺公司，都在Q1集体转型仿真人，开启内部AI工作流搭建、以及大规模的人才裁员招新和转岗培训。</p>\n<p>据了解，郑州头部短剧公司日新月异对实拍团队进行了调整，已裁去四五百人。宙途文化2025年曾月产200部真人短剧，目前开始同郑州本地学校进行AI真人技术、人员合作。云也听风影视也于内部开设AI培训班，培训合格后的导演、声音、剪辑、包括服化道人员往AI方面转岗，「真人实拍业务线基本完全停掉」。</p>\n<p>这主要出于各大平台的风向变化。去年底至今年初，百度、腾讯分别推出「柚漫剧」「火龙漫剧」app；今年2月，抖音版权中心发布新的漫剧分成系数政策，其中仿真人剧系数最高；4月，淘宝短剧和快手短剧也都发布了AI短剧相关的激励计划。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_21ac728c283243b98cbeb9f5a632ca81@5681432_oswg273168oswg1080oswg674_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>转型已成为短剧公司的必选项，不转型就意味着在下一个已经明确的内容竞争周期里被提前淘汰。宙途文化合伙人王小圈表示，宙途文化是和跟红果强绑定的，「95%项目基本上全部是红果，所以行为一定是基于上游的政策」。宙途2025年底开始向AI仿真人赛道转向，还到酱油等头部漫剧公司进行业务学习。</p>\n<p>另一方面，被视为新的创业风口，加上客观上大模型发展对技术难度的大幅降低，大量不同背景的参与者正在以不同方式涌入此赛道。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_577f1abbefad4397915c272a875cc542@5681432_oswg96172oswg1080oswg981_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>个人创作者试图通过报名各类AI培训班学技术，同时也做AI账号，诸如AI短剧情、AI小动物、影视二创等内容以获取流量，期待未来能够试稿接单，我们了解到，AI仿真人剧正在成为新的宝妈热门创业项目。与此同时，无论有没有内容行业背景，近2个月时间，我们在多个人口中听到对方正有计划开设AI剧工作室。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_c7021ef299e3416aa6dd5293544026e9@5681432_oswg162264oswg1080oswg1083_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>小红书上的AIGC个人创作者</p>\n<p>目前，大家都处于技术探索、工作流磨合的初期，暂无作品数据验证，所以也导致市场非常混乱。各家的作品质量参差不齐，「刚刚起步的、技术不成熟的、技术好的，大家在混乱的状况下竞争」。</p>\n<p>一些新搭建的工作室，甚至是此前完全没有接触过AI内容、不懂故事和运镜、也没有demo样稿的零基础个体户都在寻求承制合作。云也听风创始人张吉罡表示，行业都在转，但做到什么程度需打上问号；「很多公司为了接单把话说得很满，但可能有了单子之后才开始搭团队」。</p>\n<p>有公司接单后发现满足不了投资人、品牌方需求，就会将作品层层外包，既导致质量问题，又使市场价越发不规范不透明。目前仿真人剧承制费用平均在1500、2000/分钟，但是「非常不统一，最低单价500，最高单价3000、5000都有」。</p>\n<p>另外，为了提升sd2.0审核速度，排队测试都在倒夜班，这成为当前阶段行业非常内卷且不健康的一面。凌晨0点至9点，或凌晨2点至中午上班成为行业常态。同样，由于新技术不成熟、未规范带来的，还有AI生成人脸肖像可能存在的侵权风险。AI仿真人赛道的起步期，行业正在2026年首个季度里经历混乱和震荡。</p>\n<p>那么，行业的门槛在哪里？转型公司视角里，是十分厌恶目前混乱的市场竞争状态的，也都在试图建立公司内部的能力壁垒，这体现在以下几个维度。</p>\n<p>一是搭建内部工作流，实现更加高效、稳定、低成本、规模化的产出，同时沉淀数字资产。</p>\n<p>云也听风影视在今年1至2月份进行了AI真人剧测试和工作流搭建。从纯技术人员做工作流跑完整部剧，再将导演加入工作环节，以及人物资产方面细节优化以保证每日产能，投入了数十万成本。宙途文化则选择较稳健的校企合作，同河南郑州本地学校进行技术和人员联培，进行初期低风险探索。</p>\n<p>一个共同点是，这批公司在视频生成模型上均选择seedance2.0，agent方面均没有接入第三方工具而选择自行搭建。背后原因有三：自研工作流更适配公司内部生产链；防止数字资产被泄露和利用；长期成本更低。</p>\n<p>项目组织上，精品组8-10人一组，常规组6人一组，每组配置导演、资产师、抽卡师和后期，每组15天一部的效率。目前行业平均水平实现「成本在10万到30万区间，降低为原来的1/3甚至更低，效率也提升3倍」。</p>\n<p>二是，相比真人实拍，AI仿真人剧在内容逻辑、市场受众和商业模式上没有发生大幅变动，传统短剧公司进行转型带有先天的市场理解和内容理解优势。</p>\n<p>本次我们接触到的云也听风、宙途文化、大方互娱此前主要业务是腰部冲量剧，这批公司的转型速度相对更快；「AI真人剧是能平替掉短剧很大一部分项目，尤其是冲量项目」。</p>\n<p>张吉罡判断，大成本、拥有头部演员的精品剧暂时没办法被替代，「女性观众更多需要有CP、有连接感」；另一方面「极致的低成本下沉剧、小团队，成本缩减至几万也还能拍一拍」。</p>\n<p>题材上，题材拓宽、品类趋向多元是AI短剧常被讨论的一个优势点；做玄幻仙侠、科幻脑洞等此前常因现实成本、拍摄条件限制的创意题材，也成为这批转型公司在内容上的主要倾向。大方互娱商务经理李润哲表示，「目前主要做真人短剧很难实现的题材，丧尸、玄幻、仙侠、古装等涉及大场面和多特效的类型」。</p>\n<p>王小圈补充道，考虑投入产出比的话，他们在精品项目还会配置真人配音，将情绪顶上去更容易抓住观众情绪。「比如一部磨了一个多月的大IP，那肯定不会在声音上省钱」。</p>\n<p>王小圈还纠正了我的说法——不能说行业都在转，其实是大家都在开展一条新的业务线。河南的日新月异、乐不可支，西安的深海鱼、风行，他们不会完全放弃真人业务，「真人短剧还是能赚钱，市场也不是完全没需求了」。</p>\n<p>劣势在于，当下这批正在转向的公司，相比25年发家的酱油动漫「少了先发优势，难以拿到更好更集中的资源IP和平台合作」。</p>\n<p>不过，以上只是实现其实现行业内容壁垒的部分前置条件，能打造爆款、打造公司知名度以持续获取平台精品IP，依然是目前短剧行业最核心的竞争要素。</p>\n<p>目前逐渐清晰的市场分野也由爆款决定，如沐心的《风水之王》、时刻互动的《风水天师》、魔方漫剧的《菩提临世》。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_67181ffc056f4d14b209a41474f9406d@5681432_oswg107153oswg1080oswg717_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>这些作品既是单个公司主要的收入来源，也是作品打开了公司本身在AI仿真人赛道的行业认知，云也听风影视由于合作过爆款项目，张吉罡表示目前单子是比较充足的。</p>\n<p>但是曾经他也经历过「同合作对象试稿，但试稿后对方还没有谈好IP」的情况；包括目前大批的个体AI创作者，其中能拿到合作单子的也极其稀少。</p>\n<p>聊及未来，从业者总结出以下四个明显的行业特征。首先，内卷一定会来得比真人短剧更快。</p>\n<p>之前真人短剧对行业而言是新东西，大家都没有市场经验。AI短剧的生产方式发生了改变，但内容、受众、商业模式是相通的，「所以在生产资料抢占，或优质人才抢夺上会更快；包括插画师、动漫师等超级个体都在转型，竞争一定是更激烈的」。</p>\n<p>与此同时也有好的一面，当大公司无法垄断算力和高成本的重资产生产资料，技术平权让内容成为竞争核心，「两种公司一定是都可以并存的」。「大公司生产效率更高，生产成本更低，能拿到更好的资源和IP；小工作室也可以做精品，慢慢去打磨爆款」。</p>\n<p>王小圈在转型探索中还感受到，「AI短剧的所有东西是可计划可计算、确定性的」。此前真人实拍阶段，容易出现场地涨价、演员超时、天气变化等各种突发意外，而做AI短剧「需要多高的生产效率完全可通过增加人力来解决，一切变得更加可控了」。</p>\n<p>此外，出海成为行业玩家都可选择的路径。「出海一定是个必选项，是变现的多元化；不再涉及场景地域、演员、语言等限制，区别就不大了，只是说对于不同的公司而言什么时候去做」。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/gve6e3S9hXG1xjE1-KSpBA\">“叁拾代”</a>，作者：冯勇，36氪经授权发布。</p>', 'https://36kr.com/p/3769338585330180?f=rss', 0, '', '{\"summary\": \"本文梳理国内AI仿真人短剧赛道的发展现状，为计划布局AI短剧出海的从业者提供行业参考\", \"abstract\": \"2026年第一季度，受国内各大内容平台的激励政策推动，AI仿真人短剧成为热门创业赛道，大量传统短剧公司转型、不同背景的新参与者涌入。当前行业处于起步探索阶段，存在市场混乱、定价不透明、AI肖像侵权等问题，头部转型企业正通过搭建自研工作流、沉淀数字资产建立能力壁垒。业内普遍认为出海是AI短剧行业未来的必选多元化变现路径，AI短剧降本提效的特点也为出海布局提供了有利条件。\", \"keywords\": [\"AI短剧\", \"AI仿真人\", \"内容出海\", \"短剧出海\", \"AIGC\", \"大模型\", \"侵权风险\", \"平台激励\"], \"policy_risk\": {\"market_risk\": \"行业处于起步阶段，市场竞争混乱，作品质量参差不齐，定价不透明；AI生成人脸肖像存在侵权风险；行业内卷速度快，竞争激烈，中小个体创作者获单机会稀少\", \"policy_compliance\": \"百度、腾讯、抖音、淘宝、快手等国内内容平台先后推出AI短剧、仿真人漫剧相关产品及分成激励政策，推动全行业转型\"}, \"topic_cluster\": \"内容出海市场洞察\", \"industry_category\": \"内容与社交\"}', '', '{\"url\": \"https://36kr.com/p/3769338585330180?f=rss\", \"title\": \"一夜之间，AI短剧成了所有人的新赛道\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<blockquote>\\n<p>成本降至1/3，效率提升3倍，AI真人被视为新的创业风口；加上客观上大模型发展对技术难度的大幅降低，大量不同背景的参与者正在以不同方式涌入此赛道。</p>\\n</blockquote>\\n<p>2026年Q1，短剧市场剧烈变革，AI仿真人赛道开启了狂热的创业潮，几乎所有人都想挤进市场分一杯羹。</p>\\n<p>一方面，大批短剧、漫剧公司，甚至一些曾经的长剧、综艺公司，都在Q1集体转型仿真人，开启内部AI工作流搭建、以及大规模的人才裁员招新和转岗培训。</p>\\n<p>据了解，郑州头部短剧公司日新月异对实拍团队进行了调整，已裁去四五百人。宙途文化2025年曾月产200部真人短剧，目前开始同郑州本地学校进行AI真人技术、人员合作。云也听风影视也于内部开设AI培训班，培训合格后的导演、声音、剪辑、包括服化道人员往AI方面转岗，「真人实拍业务线基本完全停掉」。</p>\\n<p>这主要出于各大平台的风向变化。去年底至今年初，百度、腾讯分别推出「柚漫剧」「火龙漫剧」app；今年2月，抖音版权中心发布新的漫剧分成系数政策，其中仿真人剧系数最高；4月，淘宝短剧和快手短剧也都发布了AI短剧相关的激励计划。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_21ac728c283243b98cbeb9f5a632ca81@5681432_oswg273168oswg1080oswg674_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>转型已成为短剧公司的必选项，不转型就意味着在下一个已经明确的内容竞争周期里被提前淘汰。宙途文化合伙人王小圈表示，宙途文化是和跟红果强绑定的，「95%项目基本上全部是红果，所以行为一定是基于上游的政策」。宙途2025年底开始向AI仿真人赛道转向，还到酱油等头部漫剧公司进行业务学习。</p>\\n<p>另一方面，被视为新的创业风口，加上客观上大模型发展对技术难度的大幅降低，大量不同背景的参与者正在以不同方式涌入此赛道。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_577f1abbefad4397915c272a875cc542@5681432_oswg96172oswg1080oswg981_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>个人创作者试图通过报名各类AI培训班学技术，同时也做AI账号，诸如AI短剧情、AI小动物、影视二创等内容以获取流量，期待未来能够试稿接单，我们了解到，AI仿真人剧正在成为新的宝妈热门创业项目。与此同时，无论有没有内容行业背景，近2个月时间，我们在多个人口中听到对方正有计划开设AI剧工作室。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c7021ef299e3416aa6dd5293544026e9@5681432_oswg162264oswg1080oswg1083_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>小红书上的AIGC个人创作者</p>\\n<p>目前，大家都处于技术探索、工作流磨合的初期，暂无作品数据验证，所以也导致市场非常混乱。各家的作品质量参差不齐，「刚刚起步的、技术不成熟的、技术好的，大家在混乱的状况下竞争」。</p>\\n<p>一些新搭建的工作室，甚至是此前完全没有接触过AI内容、不懂故事和运镜、也没有demo样稿的零基础个体户都在寻求承制合作。云也听风创始人张吉罡表示，行业都在转，但做到什么程度需打上问号；「很多公司为了接单把话说得很满，但可能有了单子之后才开始搭团队」。</p>\\n<p>有公司接单后发现满足不了投资人、品牌方需求，就会将作品层层外包，既导致质量问题，又使市场价越发不规范不透明。目前仿真人剧承制费用平均在1500、2000/分钟，但是「非常不统一，最低单价500，最高单价3000、5000都有」。</p>\\n<p>另外，为了提升sd2.0审核速度，排队测试都在倒夜班，这成为当前阶段行业非常内卷且不健康的一面。凌晨0点至9点，或凌晨2点至中午上班成为行业常态。同样，由于新技术不成熟、未规范带来的，还有AI生成人脸肖像可能存在的侵权风险。AI仿真人赛道的起步期，行业正在2026年首个季度里经历混乱和震荡。</p>\\n<p>那么，行业的门槛在哪里？转型公司视角里，是十分厌恶目前混乱的市场竞争状态的，也都在试图建立公司内部的能力壁垒，这体现在以下几个维度。</p>\\n<p>一是搭建内部工作流，实现更加高效、稳定、低成本、规模化的产出，同时沉淀数字资产。</p>\\n<p>云也听风影视在今年1至2月份进行了AI真人剧测试和工作流搭建。从纯技术人员做工作流跑完整部剧，再将导演加入工作环节，以及人物资产方面细节优化以保证每日产能，投入了数十万成本。宙途文化则选择较稳健的校企合作，同河南郑州本地学校进行技术和人员联培，进行初期低风险探索。</p>\\n<p>一个共同点是，这批公司在视频生成模型上均选择seedance2.0，agent方面均没有接入第三方工具而选择自行搭建。背后原因有三：自研工作流更适配公司内部生产链；防止数字资产被泄露和利用；长期成本更低。</p>\\n<p>项目组织上，精品组8-10人一组，常规组6人一组，每组配置导演、资产师、抽卡师和后期，每组15天一部的效率。目前行业平均水平实现「成本在10万到30万区间，降低为原来的1/3甚至更低，效率也提升3倍」。</p>\\n<p>二是，相比真人实拍，AI仿真人剧在内容逻辑、市场受众和商业模式上没有发生大幅变动，传统短剧公司进行转型带有先天的市场理解和内容理解优势。</p>\\n<p>本次我们接触到的云也听风、宙途文化、大方互娱此前主要业务是腰部冲量剧，这批公司的转型速度相对更快；「AI真人剧是能平替掉短剧很大一部分项目，尤其是冲量项目」。</p>\\n<p>张吉罡判断，大成本、拥有头部演员的精品剧暂时没办法被替代，「女性观众更多需要有CP、有连接感」；另一方面「极致的低成本下沉剧、小团队，成本缩减至几万也还能拍一拍」。</p>\\n<p>题材上，题材拓宽、品类趋向多元是AI短剧常被讨论的一个优势点；做玄幻仙侠、科幻脑洞等此前常因现实成本、拍摄条件限制的创意题材，也成为这批转型公司在内容上的主要倾向。大方互娱商务经理李润哲表示，「目前主要做真人短剧很难实现的题材，丧尸、玄幻、仙侠、古装等涉及大场面和多特效的类型」。</p>\\n<p>王小圈补充道，考虑投入产出比的话，他们在精品项目还会配置真人配音，将情绪顶上去更容易抓住观众情绪。「比如一部磨了一个多月的大IP，那肯定不会在声音上省钱」。</p>\\n<p>王小圈还纠正了我的说法——不能说行业都在转，其实是大家都在开展一条新的业务线。河南的日新月异、乐不可支，西安的深海鱼、风行，他们不会完全放弃真人业务，「真人短剧还是能赚钱，市场也不是完全没需求了」。</p>\\n<p>劣势在于，当下这批正在转向的公司，相比25年发家的酱油动漫「少了先发优势，难以拿到更好更集中的资源IP和平台合作」。</p>\\n<p>不过，以上只是实现其实现行业内容壁垒的部分前置条件，能打造爆款、打造公司知名度以持续获取平台精品IP，依然是目前短剧行业最核心的竞争要素。</p>\\n<p>目前逐渐清晰的市场分野也由爆款决定，如沐心的《风水之王》、时刻互动的《风水天师》、魔方漫剧的《菩提临世》。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_67181ffc056f4d14b209a41474f9406d@5681432_oswg107153oswg1080oswg717_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>这些作品既是单个公司主要的收入来源，也是作品打开了公司本身在AI仿真人赛道的行业认知，云也听风影视由于合作过爆款项目，张吉罡表示目前单子是比较充足的。</p>\\n<p>但是曾经他也经历过「同合作对象试稿，但试稿后对方还没有谈好IP」的情况；包括目前大批的个体AI创作者，其中能拿到合作单子的也极其稀少。</p>\\n<p>聊及未来，从业者总结出以下四个明显的行业特征。首先，内卷一定会来得比真人短剧更快。</p>\\n<p>之前真人短剧对行业而言是新东西，大家都没有市场经验。AI短剧的生产方式发生了改变，但内容、受众、商业模式是相通的，「所以在生产资料抢占，或优质人才抢夺上会更快；包括插画师、动漫师等超级个体都在转型，竞争一定是更激烈的」。</p>\\n<p>与此同时也有好的一面，当大公司无法垄断算力和高成本的重资产生产资料，技术平权让内容成为竞争核心，「两种公司一定是都可以并存的」。「大公司生产效率更高，生产成本更低，能拿到更好的资源和IP；小工作室也可以做精品，慢慢去打磨爆款」。</p>\\n<p>王小圈在转型探索中还感受到，「AI短剧的所有东西是可计划可计算、确定性的」。此前真人实拍阶段，容易出现场地涨价、演员超时、天气变化等各种突发意外，而做AI短剧「需要多高的生产效率完全可通过增加人力来解决，一切变得更加可控了」。</p>\\n<p>此外，出海成为行业玩家都可选择的路径。「出海一定是个必选项，是变现的多元化；不再涉及场景地域、演员、语言等限制，区别就不大了，只是说对于不同的公司而言什么时候去做」。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/gve6e3S9hXG1xjE1-KSpBA\\\">“叁拾代”</a>，作者：冯勇，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\\\"title\\\": \\\"\\\\u4e00\\\\u591c\\\\u4e4b\\\\u95f4\\\\uff0cAI\\\\u77ed\\\\u5267\\\\u6210\\\\u4e86\\\\u6240\\\\u6709\\\\u4eba\\\\u7684\\\\u65b0\\\\u8d5b\\\\u9053\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u4e00\\\\u591c\\\\u4e4b\\\\u95f4\\\\uff0cAI\\\\u77ed\\\\u5267\\\\u6210\\\\u4e86\\\\u6240\\\\u6709\\\\u4eba\\\\u7684\\\\u65b0\\\\u8d5b\\\\u9053\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769338585330180?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769338585330180?f=rss\\\", \\\"published\\\": \\\"2026-04-16 21:14:19  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 13, 14, 19, 3, 106, 0], \\\"summary\\\": \\\"<blockquote>\\\\n   <p>\\\\u6210\\\\u672c\\\\u964d\\\\u81f31/3\\\\uff0c\\\\u6548\\\\u7387\\\\u63d0\\\\u53473\\\\u500d\\\\uff0cAI\\\\u771f\\\\u4eba\\\\u88ab\\\\u89c6\\\\u4e3a\\\\u65b0\\\\u7684\\\\u521b\\\\u4e1a\\\\u98ce\\\\u53e3\\\\uff1b\\\\u52a0\\\\u4e0a\\\\u5ba2\\\\u89c2\\\\u4e0a\\\\u5927\\\\u6a21\\\\u578b\\\\u53d1\\\\u5c55\\\\u5bf9\\\\u6280\\\\u672f\\\\u96be\\\\u5ea6\\\\u7684\\\\u5927\\\\u5e45\\\\u964d\\\\u4f4e\\\\uff0c\\\\u5927\\\\u91cf\\\\u4e0d\\\\u540c\\\\u80cc\\\\u666f\\\\u7684\\\\u53c2\\\\u4e0e\\\\u8005\\\\u6b63\\\\u5728\\\\u4ee5\\\\u4e0d\\\\u540c\\\\u65b9\\\\u5f0f\\\\u6d8c\\\\u5165\\\\u6b64\\\\u8d5b\\\\u9053\\\\u3002</p>\\\\n  </blockquote>\\\\n  <p>2026\\\\u5e74Q1\\\\uff0c\\\\u77ed\\\\u5267\\\\u5e02\\\\u573a\\\\u5267\\\\u70c8\\\\u53d8\\\\u9769\\\\uff0cAI\\\\u4eff\\\\u771f\\\\u4eba\\\\u8d5b\\\\u9053\\\\u5f00\\\\u542f\\\\u4e86\\\\u72c2\\\\u70ed\\\\u7684\\\\u521b\\\\u4e1a\\\\u6f6e\\\\uff0c\\\\u51e0\\\\u4e4e\\\\u6240\\\\u6709\\\\u4eba\\\\u90fd\\\\u60f3\\\\u6324\\\\u8fdb\\\\u5e02\\\\u573a\\\\u5206\\\\u4e00\\\\u676f\\\\u7fb9\\\\u3002</p>\\\\n  <p>\\\\u4e00\\\\u65b9\\\\u9762\\\\uff0c\\\\u5927\\\\u6279\\\\u77ed\\\\u5267\\\\u3001\\\\u6f2b\\\\u5267\\\\u516c\\\\u53f8\\\\uff0c\\\\u751a\\\\u81f3\\\\u4e00\\\\u4e9b\\\\u66fe\\\\u7ecf\\\\u7684\\\\u957f\\\\u5267\\\\u3001\\\\u7efc\\\\u827a\\\\u516c\\\\u53f8\\\\uff0c\\\\u90fd\\\\u5728Q1\\\\u96c6\\\\u4f53\\\\u8f6c\\\\u578b\\\\u4eff\\\\u771f\\\\u4eba\\\\uff0c\\\\u5f00\\\\u542f\\\\u5185\\\\u90e8AI\\\\u5de5\\\\u4f5c\\\\u6d41\\\\u642d\\\\u5efa\\\\u3001\\\\u4ee5\\\\u53ca\\\\u5927\\\\u89c4\\\\u6a21\\\\u7684\\\\u4eba\\\\u624d\\\\u88c1\\\\u5458\\\\u62db\\\\u65b0\\\\u548c\\\\u8f6c\\\\u5c97\\\\u57f9\\\\u8bad\\\\u3002</p>\\\\n  <p>\\\\u636e\\\\u4e86\\\\u89e3\\\\uff0c\\\\u90d1\\\\u5dde\\\\u5934\\\\u90e8\\\\u77ed\\\\u5267\\\\u516c\\\\u53f8\\\\u65e5\\\\u65b0\\\\u6708\\\\u5f02\\\\u5bf9\\\\u5b9e\\\\u62cd\\\\u56e2\\\\u961f\\\\u8fdb\\\\u884c\\\\u4e86\\\\u8c03\\\\u6574\\\\uff0c\\\\u5df2\\\\u88c1\\\\u53bb\\\\u56db\\\\u4e94\\\\u767e\\\\u4eba\\\\u3002\\\\u5b99\\\\u9014\\\\u6587\\\\u53162025\\\\u5e74\\\\u66fe\\\\u6708\\\\u4ea7200\\\\u90e8\\\\u771f\\\\u4eba\\\\u77ed\\\\u5267\\\\uff0c\\\\u76ee\\\\u524d\\\\u5f00\\\\u59cb\\\\u540c\\\\u90d1\\\\u5dde\\\\u672c\\\\u5730\\\\u5b66\\\\u6821\\\\u8fdb\\\\u884cAI\\\\u771f\\\\u4eba\\\\u6280\\\\u672f\\\\u3001\\\\u4eba\\\\u5458\\\\u5408\\\\u4f5c\\\\u3002\\\\u4e91\\\\u4e5f\\\\u542c\\\\u98ce\\\\u5f71\\\\u89c6\\\\u4e5f\\\\u4e8e\\\\u5185\\\\u90e8\\\\u5f00\\\\u8bbeAI\\\\u57f9\\\\u8bad\\\\u73ed\\\\uff0c\\\\u57f9\\\\u8bad\\\\u5408\\\\u683c\\\\u540e\\\\u7684\\\\u5bfc\\\\u6f14\\\\u3001\\\\u58f0\\\\u97f3\\\\u3001\\\\u526a\\\\u8f91\\\\u3001\\\\u5305\\\\u62ec\\\\u670d\\\\u5316\\\\u9053\\\\u4eba\\\\u5458\\\\u5f80AI\\\\u65b9\\\\u9762\\\\u8f6c\\\\u5c97\\\\uff0c\\\\u300c\\\\u771f\\\\u4eba\\\\u5b9e\\\\u62cd\\\\u4e1a\\\\u52a1\\\\u7ebf\\\\u57fa\\\\u672c\\\\u5b8c\\\\u5168\\\\u505c\\\\u6389\\\\u300d\\\\u3002</p>\\\\n  <p>\\\\u8fd9\\\\u4e3b\\\\u8981\\\\u51fa\\\\u4e8e\\\\u5404\\\\u5927\\\\u5e73\\\\u53f0\\\\u7684\\\\u98ce\\\\u5411\\\\u53d8\\\\u5316\\\\u3002\\\\u53bb\\\\u5e74\\\\u5e95\\\\u81f3\\\\u4eca\\\\u5e74\\\\u521d\\\\uff0c\\\\u767e\\\\u5ea6\\\\u3001\\\\u817e\\\\u8baf\\\\u5206\\\\u522b\\\\u63a8\\\\u51fa\\\\u300c\\\\u67da\\\\u6f2b\\\\u5267\\\\u300d\\\\u300c\\\\u706b\\\\u9f99\\\\u6f2b\\\\u5267\\\\u300dapp\\\\uff1b\\\\u4eca\\\\u5e742\\\\u6708\\\\uff0c\\\\u6296\\\\u97f3\\\\u7248\\\\u6743\\\\u4e2d\\\\u5fc3\\\\u53d1\\\\u5e03\\\\u65b0\\\\u7684\\\\u6f2b\\\\u5267\\\\u5206\\\\u6210\\\\u7cfb\\\\u6570\\\\u653f\\\\u7b56\\\\uff0c\\\\u5176\\\\u4e2d\\\\u4eff\\\\u771f\\\\u4eba\\\\u5267\\\\u7cfb\\\\u6570\\\\u6700\\\\u9ad8\\\\uff1b4\\\\u6708\\\\uff0c\\\\u6dd8\\\\u5b9d\\\\u77ed\\\\u5267\\\\u548c\\\\u5feb\\\\u624b\\\