\\\\u603b\\\\u7ed3\\\\u51fa\\\\u4ee5\\\\u4e0b\\\\u56db\\\\u4e2a\\\\u660e\\\\u663e\\\\u7684\\\\u884c\\\\u4e1a\\\\u7279\\\\u5f81\\\\u3002\\\\u9996\\\\u5148\\\\uff0c\\\\u5185\\\\u5377\\\\u4e00\\\\u5b9a\\\\u4f1a\\\\u6765\\\\u5f97\\\\u6bd4\\\\u771f\\\\u4eba\\\\u77ed\\\\u5267\\\\u66f4\\\\u5feb\\\\u3002</p>\\\\n  <p>\\\\u4e4b\\\\u524d\\\\u771f\\\\u4eba\\\\u77ed\\\\u5267\\\\u5bf9\\\\u884c\\\\u4e1a\\\\u800c\\\\u8a00\\\\u662f\\\\u65b0\\\\u4e1c\\\\u897f\\\\uff0c\\\\u5927\\\\u5bb6\\\\u90fd\\\\u6ca1\\\\u6709\\\\u5e02\\\\u573a\\\\u7ecf\\\\u9a8c\\\\u3002AI\\\\u77ed\\\\u5267\\\\u7684\\\\u751f\\\\u4ea7\\\\u65b9\\\\u5f0f\\\\u53d1\\\\u751f\\\\u4e86\\\\u6539\\\\u53d8\\\\uff0c\\\\u4f46\\\\u5185\\\\u5bb9\\\\u3001\\\\u53d7\\\\u4f17\\\\u3001\\\\u5546\\\\u4e1a\\\\u6a21\\\\u5f0f\\\\u662f\\\\u76f8\\\\u901a\\\\u7684\\\\uff0c\\\\u300c\\\\u6240\\\\u4ee5\\\\u5728\\\\u751f\\\\u4ea7\\\\u8d44\\\\u6599\\\\u62a2\\\\u5360\\\\uff0c\\\\u6216\\\\u4f18\\\\u8d28\\\\u4eba\\\\u624d\\\\u62a2\\\\u593a\\\\u4e0a\\\\u4f1a\\\\u66f4\\\\u5feb\\\\uff1b\\\\u5305\\\\u62ec\\\\u63d2\\\\u753b\\\\u5e08\\\\u3001\\\\u52a8\\\\u6f2b\\\\u5e08\\\\u7b49\\\\u8d85\\\\u7ea7\\\\u4e2a\\\\u4f53\\\\u90fd\\\\u5728\\\\u8f6c\\\\u578b\\\\uff0c\\\\u7ade\\\\u4e89\\\\u4e00\\\\u5b9a\\\\u662f\\\\u66f4\\\\u6fc0\\\\u70c8\\\\u7684\\\\u300d\\\\u3002</p>\\\\n  <p>\\\\u4e0e\\\\u6b64\\\\u540c\\\\u65f6\\\\u4e5f\\\\u6709\\\\u597d\\\\u7684\\\\u4e00\\\\u9762\\\\uff0c\\\\u5f53\\\\u5927\\\\u516c\\\\u53f8\\\\u65e0\\\\u6cd5\\\\u5784\\\\u65ad\\\\u7b97\\\\u529b\\\\u548c\\\\u9ad8\\\\u6210\\\\u672c\\\\u7684\\\\u91cd\\\\u8d44\\\\u4ea7\\\\u751f\\\\u4ea7\\\\u8d44\\\\u6599\\\\uff0c\\\\u6280\\\\u672f\\\\u5e73\\\\u6743\\\\u8ba9\\\\u5185\\\\u5bb9\\\\u6210\\\\u4e3a\\\\u7ade\\\\u4e89\\\\u6838\\\\u5fc3\\\\uff0c\\\\u300c\\\\u4e24\\\\u79cd\\\\u516c\\\\u53f8\\\\u4e00\\\\u5b9a\\\\u662f\\\\u90fd\\\\u53ef\\\\u4ee5\\\\u5e76\\\\u5b58\\\\u7684\\\\u300d\\\\u3002\\\\u300c\\\\u5927\\\\u516c\\\\u53f8\\\\u751f\\\\u4ea7\\\\u6548\\\\u7387\\\\u66f4\\\\u9ad8\\\\uff0c\\\\u751f\\\\u4ea7\\\\u6210\\\\u672c\\\\u66f4\\\\u4f4e\\\\uff0c\\\\u80fd\\\\u62ff\\\\u5230\\\\u66f4\\\\u597d\\\\u7684\\\\u8d44\\\\u6e90\\\\u548cIP\\\\uff1b\\\\u5c0f\\\\u5de5\\\\u4f5c\\\\u5ba4\\\\u4e5f\\\\u53ef\\\\u4ee5\\\\u505a\\\\u7cbe\\\\u54c1\\\\uff0c\\\\u6162\\\\u6162\\\\u53bb\\\\u6253\\\\u78e8\\\\u7206\\\\u6b3e\\\\u300d\\\\u3002</p>\\\\n  <p>\\\\u738b\\\\u5c0f\\\\u5708\\\\u5728\\\\u8f6c\\\\u578b\\\\u63a2\\\\u7d22\\\\u4e2d\\\\u8fd8\\\\u611f\\\\u53d7\\\\u5230\\\\uff0c\\\\u300cAI\\\\u77ed\\\\u5267\\\\u7684\\\\u6240\\\\u6709\\\\u4e1c\\\\u897f\\\\u662f\\\\u53ef\\\\u8ba1\\\\u5212\\\\u53ef\\\\u8ba1\\\\u7b97\\\\u3001\\\\u786e\\\\u5b9a\\\\u6027\\\\u7684\\\\u300d\\\\u3002\\\\u6b64\\\\u524d\\\\u771f\\\\u4eba\\\\u5b9e\\\\u62cd\\\\u9636\\\\u6bb5\\\\uff0c\\\\u5bb9\\\\u6613\\\\u51fa\\\\u73b0\\\\u573a\\\\u5730\\\\u6da8\\\\u4ef7\\\\u3001\\\\u6f14\\\\u5458\\\\u8d85\\\\u65f6\\\\u3001\\\\u5929\\\\u6c14\\\\u53d8\\\\u5316\\\\u7b49\\\\u5404\\\\u79cd\\\\u7a81\\\\u53d1\\\\u610f\\\\u5916\\\\uff0c\\\\u800c\\\\u505aAI\\\\u77ed\\\\u5267\\\\u300c\\\\u9700\\\\u8981\\\\u591a\\\\u9ad8\\\\u7684\\\\u751f\\\\u4ea7\\\\u6548\\\\u7387\\\\u5b8c\\\\u5168\\\\u53ef\\\\u901a\\\\u8fc7\\\\u589e\\\\u52a0\\\\u4eba\\\\u529b\\\\u6765\\\\u89e3\\\\u51b3\\\\uff0c\\\\u4e00\\\\u5207\\\\u53d8\\\\u5f97\\\\u66f4\\\\u52a0\\\\u53ef\\\\u63a7\\\\u4e86\\\\u300d\\\\u3002</p>\\\\n  <p>\\\\u6b64\\\\u5916\\\\uff0c\\\\u51fa\\\\u6d77\\\\u6210\\\\u4e3a\\\\u884c\\\\u4e1a\\\\u73a9\\\\u5bb6\\\\u90fd\\\\u53ef\\\\u9009\\\\u62e9\\\\u7684\\\\u8def\\\\u5f84\\\\u3002\\\\u300c\\\\u51fa\\\\u6d77\\\\u4e00\\\\u5b9a\\\\u662f\\\\u4e2a\\\\u5fc5\\\\u9009\\\\u9879\\\\uff0c\\\\u662f\\\\u53d8\\\\u73b0\\\\u7684\\\\u591a\\\\u5143\\\\u5316\\\\uff1b\\\\u4e0d\\\\u518d\\\\u6d89\\\\u53ca\\\\u573a\\\\u666f\\\\u5730\\\\u57df\\\\u3001\\\\u6f14\\\\u5458\\\\u3001\\\\u8bed\\\\u8a00\\\\u7b49\\\\u9650\\\\u5236\\\\uff0c\\\\u533a\\\\u522b\\\\u5c31\\\\u4e0d\\\\u5927\\\\u4e86\\\\uff0c\\\\u53ea\\\\u662f\\\\u8bf4\\\\u5bf9\\\\u4e8e\\\\u4e0d\\\\u540c\\\\u7684\\\\u516c\\\\u53f8\\\\u800c\\\\u8a00\\\\u4ec0\\\\u4e48\\\\u65f6\\\\u5019\\\\u53bb\\\\u505a\\\\u300d\\\\u3002</p>\\\\n  <p class=\\\\\\\"editor-note\\\\\\\">\\\\u672c\\\\u6587\\\\u6765\\\\u81ea\\\\u5fae\\\\u4fe1\\\\u516c\\\\u4f17\\\\u53f7<a href=\\\\\\\"https://mp.weixin.qq.com/s/gve6e3S9hXG1xjE1-KSpBA\\\\\\\" rel=\\\\\\\"noopener noreferrer\\\\\\\" target=\\\\\\\"_blank\\\\\\\">\\\\u201c\\\\u53c1\\\\u62fe\\\\u4ee3\\\\u201d</a>\\\\uff0c\\\\u4f5c\\\\u8005\\\\uff1a\\\\u51af\\\\u52c7\\\\uff0c36\\\\u6c2a\\\\u7ecf\\\\u6388\\\\u6743\\\\u53d1\\\\u5e03\\\\u3002</p>\\\"}, \\\"source\\\": {\\\"title\\\": \\\"36\\\\u6c2a\\\"}, \\\"authors\\\": [{\\\"name\\\": \\\"\\\\u65b0\\\\u58f0Pro\\\"}], \\\"author\\\": \\\"\\\\u65b0\\\\u58f0Pro\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"\\\\u65b0\\\\u58f0Pro\\\"}, \\\"content\\\": [{\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"26\\\\u5e74\\\\u6700\\\\u5927\\\\u7684\\\\u521b\\\\u4e1a\\\\u98ce\\\\u53e3\\\"}]}\", \"published_at\": \"2026-04-16 21:14:19\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-16 22:52:41');
INSERT INTO `news_detail` VALUES (58, 2204, 8, '新能源与汽车', '宁王：无可撼动的能源时代 “台积电”', '', '<p><strong>2026年4月15日晚，</strong>宁德时代<strong>公布了2026年一季度业绩。在市场对其“能否扛住碳酸锂涨价”和“电动车增速放缓”的疑虑中，宁王用一份全线超预期的成绩单给出了最有力的回击：</strong></p>\n<p><strong>①总收入超预期，由量价齐升所带动： </strong>一季度实现收入 1291 亿元，同比大幅增长52%，再次验证锂电上行周期启动，并大幅超出市场预期1142亿。超预期的核心在于出货量继续高增，以及在上游原材料涨价背景下，公司凭借强大的议价能力顺利将成本传导至下游，带动了销售单价提升。</p>\n<p><strong>② 出货量大幅高增：</strong>一季度，宁德时代电池出货量超200GWh，同比增幅约67%，大幅高于市场预期的168Gwh（市场预期的同比增幅40%），其中：</p>\n<p><strong>动力电池领跑行业，带电量“杠杆效应”爆发：</strong> 动力电池出货约 150GWh（同比+56%），远超国内新能源车销量增速（-4%）。这背后的核心逻辑在于“行业 Beta 升级”：乘用车标配长续航以及高带电量商用车渗透率跃升带来的 1:4 需求杠杆效应已全面兑现。</p>\n<p><strong>储能翻倍增长，AIDC 开启新增长极： </strong>储能出货 50GWh（同比+108%）。除了国内容量电价政策的红利外，AI 数据中心（AIDC）对储能系统的刚性需求已成为公司新的爆发点，叠加济宁基地产能释放，储能业务已成为第二增长曲线。</p>\n<p><strong>③ 价格传导顺利，议价权锁定盈利： </strong>在碳酸锂价格反弹至 15-18 万元/吨的逆风下，公司单价环比提升 4% 至 0.57 元/Wh。凭借完善的价格联动机制，公司成功将成本压力向下游传导，彻底击碎了“原材料涨价侵蚀利润”的担忧。</p>\n<p><strong>④ 毛利率高位回落但显韧性，成本转嫁平滑涨价冲击：</strong>一季度宁王毛利率为 24.8%，单 Wh 毛利约 0.16 元。尽管受碳酸锂价格反弹及淡季产能利用率回落等“多重逆风”影响，但凭借强大的成本转嫁能力（高行业议价权）与 945 亿低价存货的“蓄水池”缓冲，公司盈利表现依然稳健，展现了极强的跨周期防御性。</p>\n<p><strong>⑤ 净利润击穿预期，减值压力出清释放利润： </strong>归母净利 207 亿元（同比+49%），单 Wh 净利依然稳守 0.1 元。</p>\n<p>随着前期“减值包袱”的出清（环比大幅缩减 32 亿）以及核心运营利润率（15.9%）的稳健表现，公司不仅在“量”上领先，在“质”上也彻底击碎了市场关于原材料涨价侵蚀利润的担忧。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_3a020b6505fe4c1dadffe9a9b8d21755@000000_oswg157081oswg1080oswg734_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>海豚君整体观点：</strong></p>\n<p>整体来看，宁德时代在一季报中展现了无可匹敌的盈利韧性。这是一份不仅“量足”而且“质优”的答卷： 收入与净利润双双击穿市场预期，出货量更是走出了独立于行业的“剪刀差”行情。</p>\n<p>在面临上游原材料反弹、传统淡季及政策扰动等多重逆风的“极限测试”下，公司依然交出了双超预期的成绩单。</p>\n<p>这不仅彻底击碎了此前市场关于“原材料涨价将侵蚀利润”的悲观伪命题，更印证了海豚君在《宁王：产能拉满！AI 基建时代霸气归来》中强调的核心观点：在锂电全面上行的“黄金周期”里，宁王凭借其深厚的成本护城河与议价权，拥有极高的业绩确定性与爆发力。</p>\n<p><strong>而宁王强势穿越周期的实力在这五大核心指标中得到了集中爆发与验证：</strong></p>\n<p><strong>① 产能利用率无惧淡季，高位运转印证强劲需求：</strong> 尽管受一季度传统淡季及自身产能不断扩建（分母端扩大）的双重影响，公司的产能利用率仍稳居 85%-90% 的绝对高位。</p>\n<p>叠加二季度排产持续饱满的指引（仍维持85%-90%），排产端的高景气度直接打消了市场对阶段性需求降温以及电动车增速放缓拖累整体出货量的担忧。</p>\n<p><strong>② 资本开支触底飙升，海内外产能扩张高调重启： </strong>本季度资本开支结束下行周期，大幅攀升至逼近上轮扩产巅峰的水平（约124亿元）。面对上修至 1.1-1.2 TWh 的26年排产目标（同比增速达42%-55%），公司在国内大储基地及欧洲、东南亚等高毛利海外市场全面按下扩产加速键，为吃透下一波行业红利备足弹药。</p>\n<p><strong>③ 合同负债稳居高位，充沛订单锁定业绩基本盘： </strong>本季度合同负债（455亿元）虽环比微降，但这并非订单流失，而是由于产能加速释放导致前期积压订单被高效交付结转为收入。在如此高强度的交付下，合同负债依然企稳历史极高水位，说明新增订单补位迅猛，在手订单厚度确保了后续业绩的确定性。</p>\n<p><strong>④ 存货规模创历史新高，“主动备货+在途商品”折射订单爆棚： </strong>高达1089亿的存货并非锂电下行周期中的滞销积压，而是下游需求端旺盛的侧面印证。</p>\n<p>一方面是公司利用资金优势在涨价初期“低价囤货”平滑成本；另一方面，随着系统级储能产品爆发和出海版图扩大，长周期的“在途发出商品”大幅增加。上行周期的高存货，恰恰是下游催单、需求旺盛的隐射。</p>\n<p><strong>⑤ 资产减值包袱彻底出清，带来利润端释放： </strong>随着上一周期跌价准备的充分计提以及一季度锂价的企稳回升，当季资产减值损失环比大幅锐减，占收入比重仅1.1%。减值压力的解除，使得前端通过量价齐升与规模效应积累的毛利优势，顺畅无阻地传导至净利润端，彻底释放了利润高弹性。</p>\n<p><strong>综合考量公司产能周期的重新扩张、海外（尤其是欧洲）产能的加速爬坡以及全球储能市场的爆发，海豚君进一步上调2026年宁德时代电池总出货量预期至 950GWh（同比增长44%）。具体出货结构与核心驱动如下：</strong></p>\n<p><strong>动力电池出货预计达 754 GWh（同增40%）：</strong> 增长不仅得益于公司产能释放带来的市占率的稳步向上，更受两大“Beta杠杆”的强力驱动——乘用车端向“标配长续航”演进带来的单车带电量飙升，以及重卡/物流等高带电量商用车渗透率跃升所释放的巨大需求杠杆（1:4拉动效应）。</p>\n<p>一季度公司动力电池出货约150GWh，同比增速高达56%；同期国内新能源车销量增速仅为-4%。两者之间形成了巨大的“增速剪刀差”，也进一步验证了“单车带电量提升与结构化增量”的逻辑正在兑现。</p>\n<p><strong>储能电池出货预计达 196 GWh（同增62%）：</strong> 增长的确定性来自于供需双核共振——国内独立储能容量电价政策落地彻底打通了项目经济性闭环；同时，全球AI数据中心（AIDC）军备竞赛从电源侧和用户侧双向催生了对储能系统的海量配套需求。</p>\n<p>基于此，海豚君在相对乐观的假设情境下（如：基于金属价格联动机制的顺畅传导向下游提价，叠加自有锂矿重启释放低成本红利等），认为宁德时代全年单 Wh 净利仍有进一步上行的空间，有望抬升至 0.11-0.12元 的区间。按 950GWh 的总出货量测算，预计 2026 年全年净利润将突破千亿大关，达到 1045亿-1140亿元。</p>\n<p>毫无疑问，宁德时代在锂电上行周期中的基本面表现是极其强悍且稳健的。但海豚君需提示，尽管公司基本面无可挑剔，但对于前期未及时介入的投资者，若追求更充厚的安全垫，请保持密切关注，耐心等待市场情绪阶段性回落，或宏观预期扰动砸出更具安全边际的“击球点���时，再行逢低布局。</p>\n<p><strong>以下是详细内容</strong></p>\n<h2><strong>一. 收入端继续超预期，核心驱动仍是出货量高增与成本传导</strong></h2>\n<p>2026年一季度单季收入1291亿元，同比大幅增长52%，再次验证锂电上行周期启动，并大幅超出市场预期1142亿。超预期的核心在于出货量继续高增，以及在上游原材料涨价背景下，公司凭借强大的议价能力顺利将成本传导至下游，带动了销售单价提升。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_db37b1cbb1aa40efb47a59465f7b89f6@000000_oswg67567oswg1080oswg517_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<h3>1. <strong>电池出货量：同比高增约67%至超200GWh</strong></h3>\n<p>一季度，宁德时代电池出货量超200GWh，同比增幅约67%，大幅高于市场预期的168Gwh（市场预期的同比增幅40%），其中：</p>\n<p><strong>① 动力电池出货约150GWh，占比约75%，同比增速高达56%，</strong>显著高于国内新能源车-4%的销量增速，形成巨大“剪刀差”。海豚君认为，动力电池销量增速大幅高于国内新能源车销量增速，主要源于源于行业Beta升级与公司Alpha共振：</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_28cdc55e3729477b8296f7a039c7c474@000000_oswg59302oswg1080oswg508_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>行业beta层面：单车带电量提升+商用车“高带电量”的杠杆效应：</strong></p>\n<p><strong>a. 单车带电量继续提升：</strong>在纯电与插混车型结构相对稳定的背景下，乘用车电池单车容量仍然在不断上行，据CABIA数据，Q1国内新能源单车平均带电量66.7kwh, 同比增长34%（纯电乘用车65.3kwh, 同比增长21.4%，插混乘用车36.2kwh, 同比增长40.6%）。</p>\n<p>一季度国内600km续航以上的车型占比已达到40%-50%，大幅远高于去年一季度10%-20%的水平。这主要得益于：</p>\n<p><strong>纯电车型（BEV）的大电量军备竞赛：</strong>车企为缓解里程焦虑并提升高端产品竞争力，正加速普及大容量电池包。例如，蔚来全系标配门槛提升至100kWh，小米SU7中高配搭载96kWh以上电池包，市场正从“选配长续航”向“标配长续航”跃迁。</p>\n<p><strong>增程式（EREV）的“纯电化”演进：</strong>为追求更好的日常纯电通勤体验，增程车型的电池容量中枢正从传统的40kWh大幅上探至60-80kWh（如零跑D19搭载80.3kWh电池，理想L系列等大电量版本）。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_c2ed5bef01d948e189a5bc63633f5b3c@000000_oswg71785oswg1080oswg401_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_0a42f7ed50b447a984330a0470a00f69@000000_oswg112597oswg1080oswg693_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>b. 高带电量商用车销量占比快速提升，产生需求杠杆</strong></p>\n<p><strong>高带电量商用车渗透率跃升，释放需求杠杆： </strong>一季度，国内新能源商用车累计销量18.4万辆，同比增长23.6%（远超商用车整体6%的增速），渗透率从2024年的约4.5%快速攀升至2026年一季度的近7%。受电池成本下探带来的TCO（全生命周期成本）优势及路权政策驱动，重卡和轻型物流车正迎来爆发。</p>\n<p><strong>巨大的需求杠杆（1:4效应）：</strong> 纯电商用车平均带电量已飙升至近200kWh（2024年同期仅为118kWh），远超纯电乘用车的60-70kWh。</p>\n<p>这意味着每新增1辆纯电商用车销量，相当于拉动了3-4辆纯电乘用车的电池需求。<strong>由于商用车及专用车已占宁德时代动力总销量的1/3，这种杠杆效应对其出货量拉动极为显著。</strong></p>\n<p><strong>公司Alpha层面：全球市占率持续提升</strong></p>\n<p>国内份额持续挤压对手： 一季度宁德时代国内市占率环比继续提升3.2个百分点至47.7%；若剔除比亚迪（主要自供），其在第三方市场的市占率环比上行1.8个百分点至57.3%。</p>\n<p>全球化产能释放与产品红利： 根据2026年1-2月数据，公司全球动力电池使用量市占率达40.5%（同比+1.8pct），其中海外市占率达32.1%（同比+2.2pct）。随着前期因满产限制而压抑的产能得到释放，叠加神行、麒麟等高质量电池产品的放量，公司在全球市场的统治力进一步巩固。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_d067bdad59e6438faf03626119beb6f1@000000_oswg57265oswg1080oswg406_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>② 储能电池出货50Gwh, 同比大增108%，需求与产能释放双驱动</strong></p>\n<p>一季度，宁德时代储能电池出货约50GWh，同比大幅增长108%，增长势头极为强劲。这一增速与行业高景气度相符（2026年一季度中国储能电池销量同比增长112%），主要仍然由于行业对于储能的高需求，以及宁王用于缓解储能产能压力的山东济宁基地（规划超100GWh）的新增产能，在 2026年Q1开始释放。</p>\n<p><strong>a. 国内政策与市场共振，经济性拐点确立</strong></p>\n<p>全国性容量电价机制推行：2026年初，国家出台“114号文”，首次在国家层面建立电网侧独立储能容量电价机制。该政策以煤电价格为基准，为储能项目提供稳定的容量收益，显著改善项目经济性（IRR可提升至8%-9%），彻底激活了投资需求。作为拥有长寿命、低衰减技术的绝对龙头，宁德时代直接受益于终端需求的爆发。</p>\n<p>产能释放支撑交付：公司用于缓解储能产能压力的山东济宁基地（规划新增产能超100GWh）在2026年开始逐步释放产能，有力支撑了出货量的高增长。</p>\n<p><strong>b. AIDC数据中心成为储能新增长极</strong></p>\n<p>AI数据中心（AIDC）的快速发展，从电源侧和用户侧双重维度催生了对储能的新需求：</p>\n<p>电源侧（提升有效容量）：为匹配风光等间歇性新能源的高比例接入，配套储能是提升其有效容量系数、保障电网稳定的关键手段。</p>\n<p>用户侧（负荷管理与经济性）：</p>\n<p>稳定AI负载：AI训练和推理负载具有剧烈、同步的波动性，配备储能可以平抑这种“毫秒级”功率脉冲，保障数据中心自身用电安全。</p>\n<p>经济性与加速并网：储能具备“削峰填谷”的套利经济性。同时，北美等地的电网运营商（如PJM、ERCOT）已出台政策，要求新接入的大型负荷（如数据中心）必须具备调节自身负荷、减少对电网冲击的能力。配备储能成为数据中心加速通过并网审批、实现快速上电的关键解决方案。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_8094b55ae4b84105addad5f1b25ab30e@000000_oswg57482oswg1080oswg529_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_68095d73ae134a3fa86ae61887a2041e@000000_oswg54554oswg1080oswg532_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_a8de6a1d3b36494c9ba3d585b163daf1@000000_oswg79463oswg1080oswg583_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>b. 电池单价：价格联动凸显议价权</strong></p>\n<p><strong>单价方面，一季度宁德时代整体电池销售均价达到0.57元/Wh，环比提升4%。而宁王一季度面临“两大逆风”：</strong></p>\n<p>上游成本急剧推升： 一季度碳酸锂价格从上年四季度的8-10万元/吨快速反弹至15-18万元/吨。</p>\n<p>产品结构带来均价下行压力： 单价相对较低的储能电池出货量占比在一季度提升了5个百分点至25%，对整体均价构成了结构性的的向下拖累。</p>\n<p>但在“成本向上 + 结构向下”的双重压力下，公司整体均价依然实现环比上涨。这直接印证了公司在产业链中强大的议价权：公司表示其大部分订单均已签订完善的碳酸锂等金属价格联动机制，凭借强大的议价能力，宁德时代顺利将原材料涨价压力传导至下游客户，有效对冲了成本波动，带动了销售均价的坚挺向上。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_7b9c4f6623364bb58ade5e3a5ba2a27e@000000_oswg71176oswg1080oswg572_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<h3><strong>2. 毛利率环比受挤压回落，但仍然具备极强盈利韧性</strong></h3>\n<p>1Q26公司毛利率为24.8%，单Wh毛利从去年四季度的0.18元/Wh下滑至约0.16元/Wh。虽然相比去年四季度产能满载时的高点（毛利率28.2%）有所回落，但整体表现与市场预期持平，展现了极其稳健的盈利韧性。</p>\n<p><strong>一季度的盈利端主要面临了多重逆风的集中挤压：</strong></p>\n<p>成本与结构双向承压： 碳酸锂均价快速反弹至15-18万元/吨带来成本冲击，同时相对低毛利的储能电池出货占比提升。</p>\n<p>淡季效应与折旧摊销： 受一季度传统淡季影响，公司产能利用率从25年下半年满产时的103%回落至85%-90%区间，导致单位折旧摊销成本略有上升。</p>\n<p>政策性因素扰动： 出口税收优惠退坡也对表观利润率构成了一定挤压。</p>\n<p><strong>但在上述多重逆风下，公司依然能维持稳健的毛利率和净利率水平，核心得益于其超越周期的抗风险能力：</strong></p>\n<p><strong>① </strong>低价存货的“蓄水池”效应： 去年四季度末，公司账面存货高达945亿元（存货/营业收入比例达67%）。庞大的库存规模相当于一个缓冲垫，使得公司在一季度能够部分使用前期储备的低价原材料进行生产，有效覆盖并平滑了当季的成本上涨冲击。</p>\n<p><strong>② </strong>上游资源的战略级对冲： 相比上一轮锂价上行周期，公司目前的上游资源布局更加完善。公司持有洛阳钼业（CMOC）约25%的股权，叠加自有江西锂矿（JXW）有望在2026年迎来重启。这些上游资产等同于一个巨大的低成本“隐形库存”，对冲外购锂价波动的能力大幅增强。</p>\n<p><strong>③ </strong>极致的规模效应与大单品策略： 尽管处于传统淡季且处在产能扩建期，公司85%-90%的产能利用率在行业内依然处于绝对高位。配合在产品端大力推行的“大单品策略”（如神行、麒麟电池的规模化量产），公司在制造环节的规模经济降本效应依然显著。</p>\n<p><strong>④ </strong>强悍的成本转嫁能力： 无论是面对原材料价格的反弹，还是出口税收优惠减少这类预期内的政策变动，公司凭借完善的金属价格联动合同安排以及极强的产业链话语权，能够将绝大部分的成本增量顺利转嫁给下游客户。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_e460226c954f458aafed7482f5c6b804@000000_oswg102724oswg1080oswg844_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1310c205f29f42b3a0bc13ff4711168d@000000_oswg77786oswg1080oswg539_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<h2><strong>二. 全面上行周期逻辑不改，终端需求仍强劲</strong></h2>\n<p><strong>1）产能利用率稳居85%-90%高位，二季度排产持续饱满</strong></p>\n<p>受一季度新能源车市传统淡季及公司自身产能持续扩建（总产能基数变大）的双重叠加影响，公司一季度的产能利用率从2025年下半年的超负荷满产状态（103%）阶段性回落至85%-90%区间。但在分母端不断扩张的背景下，这一利用率水平在全行业中依然处于绝对领先的高位，侧面印证了终端拿货的积极性。</p>\n<p>而根据公司的最新指引，二季度各项排产计划依然保持饱和状态，预计产能利用率将继续企稳在85%-90%的高位区间。这不仅有效打消了市场对“电动车需求增速放缓拖累总出货”的担忧，也从生产端再次验证了宁德时代依然在量价齐升的全面上行周期内。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_0d0ad10318bc41efa9b3525a81a4fe6d@000000_oswg53078oswg1080oswg285_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>2）资本开支再加速，海内外产能扩张高调重启</strong></p>\n<p>从资本开支的周期律来看，宁德时代正迎来新一轮的扩张拐点。虽然公司在2021-2022年经历了产能的密集投入期，随后因行业阶段性供需错配，资本开支自2022年Q1起进入下行周期（并在2023年Q1触及约67亿元的阶段性低点）。</p>\n<p>但自2024年Q1起，公司的资本支出已开始筑底回升。本季度，资本开支更是加速攀升至约124亿元，逼近上一轮扩产巅峰期的水平，释放出极强的扩张信号。</p>\n<p>伴随资本开支的加速，公司对未来的排产指引也极为积极：公司此前已将2026年的排产目标大幅上修至 1.1-1.2 TWh（对比2025年约772 GWh的基数，预计新增产能约400 GWh），产能同比增速高达42%-55%！</p>\n<p><strong>目前，公司在全球范围内的产能布局正全面开花：</strong></p>\n<p><strong>国内大盘稳步扩建： </strong>山东济宁、广东肇庆（瑞庆时代）、江西宜春、福建厦门、青海及福建宁德等主力基地均在大幅扩产。其中，为承接井喷的储能订单，山东济宁基地（规划超100GWh）的新增产能已按计划于2026年Q1逐步释放。</p>\n<p><strong>海外产能加速兑现：</strong> 海外市场正成为下一阶段量增的核心驱动力。</p>\n<p>欧洲：德国工厂（14GWh）已于24年投产并实现稳定盈利；匈牙利工厂（规划100GWh）的一期项目（34GWh）电芯产线设备已进场调试，预计2025年底建成；西班牙工厂（规划60GWh）已完成前期审批并成立合资公司，即将在2026年正式启动筹建。</p>\n<p>东南亚布局：印尼电池产业链项目进展顺利，预计将于2026年上半年正式投产。</p>\n<p>而强劲的产能释放，不仅直接拉动了宁德时代2026年一季度全球市占率的强势回升，也为后续的需求的释放提供了供给端的保证。</p>\n<p>从投产节奏和基数效应来看，2026年海外市场产能的密集放量，将成为公司业绩高增的基石。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_c4fa266751724fba9c7f06bf179e44e2@000000_oswg56502oswg1080oswg442_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_b6fd85911eac425993122c5e9a23cecc@000000_oswg61882oswg1080oswg633_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>3）存货还在继续高增，背后隐含旺盛订单需求</strong></p>\n<p>本季度末，公司存货规模显著攀升至1089亿元，环比大幅增加约144亿元，绝对值创下历史新高。存货占收入比例由上季度的67%跃升至本季度的84%，存货周转天数也同步延长至近95天。</p>\n<p>不同于传统下行周期中的“被动去库存”压力，海豚君认为，宁德时代当前的存货高企更多体现了上行周期中的“主动备货”与“订单在途”：</p>\n<p>① 原材料战略储备：主动平滑成本波动</p>\n<p>为应对碳酸锂等核心原材料价格的筑底回升，公司利用强大的现金流优势，有针对性地增加了原材料及自制半成品的储备。</p>\n<p>这种在价格上涨通道开启前的“低价囤货”行为，构建了一个巨大的成本缓冲池，能有效对冲未来1-2个季度原材料上行对毛利率的负面挤压。</p>\n<p><strong>② “发出商品”（已发货但未开票确认收入）占比提升：</strong></p>\n<p>产品形态由“芯”向“系统”演进： 随着储能系统（ESS）出货占比显著提升，由于系统级产品涉及现场安装、调试及较长的交付周期，导致在财务报表上表现为较长时间的存货沉淀。</p>\n<p>全球供应链半径拉长： 公司海外市场正从欧洲向中东、美洲等远距离地区多点开花。远洋运输比例的增加及长距离交付周期的延长，使得大量处于交付途中的货品积压在存货端。</p>\n<p>而着反而隐含下游客户订单的极高景气度。随着这部分在途商品在未来几个季度逐步转化结转为收入，公司的业绩增长将获得更强的确定性。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_3a3dc2687c514f8a97f80b6737692f28@000000_oswg76970oswg1080oswg457_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>4） 合同负债继续维持高位</strong></p>\n<p>由于宁王主要是个To B的生意，所以会出现已收下游B端客户的预付款项，但还没交付的情况，所以合同负债可以近似看出宁王在手订单量变化的一个近似指标。</p>\n<p>从宁王一季度合同负债虽然环比上季度高点492亿环比下滑了37亿元至455亿元，但仍然处于高位水平，随着公司各大基地产能利用率维持高位，一季度电池出货量同比大增67%，这使得前期积压的订单得以快速交付并转化为营业收入，从而在财务端体现为合同负债的正常结转回落。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_182c3a99310b44618c0b51efd48a8f46@000000_oswg58596oswg1080oswg499_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>5）资产减值本季度环比回落</strong></p>\n<p>本季度，公司资产减值损失约为14亿元，较上季度的计提峰值（46亿元）环比大幅锐减32亿元。从相对比重来看，资产减值占营业收入的比例环比下降约2个百分点，仅为1.1%。</p>\n<p>海豚君认为，减值压力的下降主要得益于前期计提充分与上游价格企稳的共振：</p>\n<p>历史包袱出清：公司秉持审慎的财务原则，已对存货及涉锂矿产资源等相关资产进行了极为充分的减值计提。</p>\n<p>跌价风险解除： 叠加一季度碳酸锂等核心原材料价格企稳反弹，新增大额存货跌价准备的风险已基本解除。</p>\n<p>而减值风险的出清，也进一步带来了利润端的释放。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_06f65b4b02e942eeb8f67b8f62c2167a@000000_oswg64490oswg1080oswg469_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>一季度，宁王归母净利207亿（同比增长49%）同样大幅高于市场预期176亿，扣非归母净利润164亿元，同比大增53%。</p>\n<p>而超预期的原因仍然在于出货量的继续高增，叠加凭借绝对议价能力实现的成本有效传导，带来的收入与毛利润的超预期。</p>\n<p>研发及各项期间费用得到精准、高效的管控，配合资产减值损失的环比大幅出清，带来了报表段利润的进一步释放。</p>\n<p>本季度公司单Wh净利维持在约0.1元/Wh，与上季度基本持平。在碳酸锂等原材料价格快速反弹的逆风环境下，这一极其坚挺的单位盈利表现，彻底击碎了此前市场关于“原材料涨价将侵蚀公司利润”的悲观预期，再次验证了公司穿越周期的强悍实力。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_3b56fdc737aa40be908a234c4194a4fb@000000_oswg74335oswg1080oswg521_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>而海豚君更关注的核心运营利润率趋势（毛利率-三费-资产/信用减值损失率），一季度205亿元，同比增速高达94%，核心运营利润率也达到15.9%，环比与上季度持平，也表明宁王持续稳健的经营能力。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_6e9cd9c4a92b42c19e7e27ca14643ef9@000000_oswg71224oswg1080oswg531_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MzE5MTU3MzA2OQ==&amp;mid=2247571258&amp;idx=2&amp;sn=8bc3f0b7a53fa0d96bba3bc5e949e696&amp;chksm=97178c0874802d97f11213100f939eef7c598ed3ecdc08fff0483988d7c3dc67fe2e12326b14&amp;scene=0&amp;xtrack=1#rd\">“海豚投研”（ID：haituntouyan）</a>，作者：海豚君，36氪经授权发布。</p>', 'https://36kr.com/p/3769366038872583?f=rss', 0, '', '{\"summary\": \"本文解析宁德时代2026年超预期一季报，梳理其全球产能出海布局与行业增长逻辑，为新能源出海企业提供行业参考\", \"abstract\": \"宁德时代2026年一季度业绩全线超出市场预期，实现收入1291亿元同比增长52%，归母净利润207亿元同比增长49%，展现出强劲的盈利韧性。公司动力电池出货量远超国内新能源车销量增速，储能业务翻倍增长，AI数据中心成为储能新增长极。宁德时代正加快欧洲、东南亚等海外市场的产能扩张，全球市占率持续提升。公司凭借强大议价权和低价存货缓冲，顺利传导碳酸锂涨价带来的成本压力，机构因此上调其全年出货量与盈利预期，看好其在锂电上行周期的业绩确定性。\", \"keywords\": [\"宁德时代\", \"动力电池\", \"储能\", \"出海\", \"产能扩张\", \"全球市占率\", \"碳酸锂\", \"AI数据中心\", \"锂电\"], \"policy_risk\": {\"market_risk\": \"碳酸锂价格波动推高生产成本，国内新能源汽车销量增速放缓，对行业业绩存在潜在扰动\", \"policy_compliance\": \"1.国内出台114号文，首次在国家层面建立电网侧独立储能容量电价机制，激活储能投资需求；2.北美电网运营商要求新接入大型数据中心需配备储能才能通过并网审批；3.出口税收优惠出现退坡\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3769366038872583?f=rss\", \"title\": \"宁王：无可撼动的能源时代 “台积电”\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p><strong>2026年4月15日晚，</strong>宁德时代<strong>公布了2026年一季度业绩。在市场对其“能否扛住碳酸锂涨价”和“电动车增速放缓”的疑虑中，宁王用一份全线超预期的成绩单给出了最有力的回击：</strong></p>\\n<p><strong>①总收入超预期，由量价齐升所带动： </strong>一季度实现收入 1291 亿元，同比大幅增长52%，再次验证锂电上行周期启动，并大幅超出市场预期1142亿。超预期的核心在于出货量继续高增，以及在上游原材料涨价背景下，公司凭借强大的议价能力顺利将成本传导至下游，带动了销售单价提升。</p>\\n<p><strong>② 出货量大幅高增：</strong>一季度，宁德时代电池出货量超200GWh，同比增幅约67%，大幅高于市场预期的168Gwh（市场预期的同比增幅40%），其中：</p>\\n<p><strong>动力电池领跑行业，带电量“杠杆效应”爆发：</strong> 动力电池出货约 150GWh（同比+56%），远超国内新能源车销量增速（-4%）。这背后的核心逻辑在于“行业 Beta 升级”：乘用车标配长续航以及高带电量商用车渗透率跃升带来的 1:4 需求杠杆效应已全面兑现。</p>\\n<p><strong>储能翻倍增长，AIDC 开启新增长极： </strong>储能出货 50GWh（同比+108%）。除了国内容量电价政策的红利外，AI 数据中心（AIDC）对储能系统的刚性需求已成为公司新的爆发点，叠加济宁基地产能释放，储能业务已成为第二增长曲线。</p>\\n<p><strong>③ 价格传导顺利，议价权锁定盈利： </strong>在碳酸锂价格反弹至 15-18 万元/吨的逆风下，公司单价环比提升 4% 至 0.57 元/Wh。凭借完善的价格联动机制，公司成功将成本压力向下游传导，彻底击碎了“原材料涨价侵蚀利润”的担忧。</p>\\n<p><strong>④ 毛利率高位回落但显韧性，成本转嫁平滑涨价冲击：</strong>一季度宁王毛利率为 24.8%，单 Wh 毛利约 0.16 元。尽管受碳酸锂价格反弹及淡季产能利用率回落等“多重逆风”影响，但凭借强大的成本转嫁能力（高行业议价权）与 945 亿低价存货的“蓄水池”缓冲，公司盈利表现依然稳健，展现了极强的跨周期防御性。</p>\\n<p><strong>⑤ 净利润击穿预期，减值压力出清释放利润： </strong>归母净利 207 亿元（同比+49%），单 Wh 净利依然稳守 0.1 元。</p>\\n<p>随着前期“减值包袱”的出清（环比大幅缩减 32 亿）以及核心运营利润率（15.9%）的稳健表现，公司不仅在“量”上领先，在“质”上也彻底击碎了市场关于原材料涨价侵蚀利润的担忧。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3a020b6505fe4c1dadffe9a9b8d21755@000000_oswg157081oswg1080oswg734_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>海豚君整体观点：</strong></p>\\n<p>整体来看，宁德时代在一季报中展现了无可匹敌的盈利韧性。这是一份不仅“量足”而且“质优”的答卷： 收入与净利润双双击穿市场预期，出货量更是走出了独立于行业的“剪刀差”行情。</p>\\n<p>在面临上游原材料反弹、传统淡季及政策扰动等多重逆风的“极限测试”下，公司依然交出了双超预期的成绩单。</p>\\n<p>这不仅彻底击碎了此前市场关于“原材料涨价将侵蚀利润”的悲观伪命题，更印证了海豚君在《宁王：产能拉满！AI 基建时代霸气归来》中强调的核心观点：在锂电全面上行的“黄金周期”里，宁王凭借其深厚的成本护城河与议价权，拥有极高的业绩确定性与爆发力。</p>\\n<p><strong>而宁王强势穿越周期的实力在这五大核心指标中得到了集中爆发与验证：</strong></p>\\n<p><strong>① 产能利用率无惧淡季，高位运转印证强劲需求：</strong> 尽管受一季度传统淡季及自身产能不断扩建（分母端扩大）的双重影响，公司的产能利用率仍稳居 85%-90% 的绝对高位。</p>\\n<p>叠加二季度排产持续饱满的指引（仍维持85%-90%），排产端的高景气度直接打消了市场对阶段性需求降温以及电动车增速放缓拖累整体出货量的担忧。</p>\\n<p><strong>② 资本开支触底飙升，海内外产能扩张高调重启： </strong>本季度资本开支结束下行周期，大幅攀升至逼近上轮扩产巅峰的水平（约124亿元）。面对上修至 1.1-1.2 TWh 的26年排产目标（同比增速达42%-55%），公司在国内大储基地及欧洲、东南亚等高毛利海外市场全面按下扩产加速键，为吃透下一波行业红利备足弹药。</p>\\n<p><strong>③ 合同负债稳居高位，充沛订单锁定业绩基本盘： </strong>本季度合同负债（455亿元）虽环比微降，但这并非订单流失，而是由于产能加速释放导致前期积压订单被高效交付结转为收入。在如此高强度的交付下，合同负债依然企稳历史极高水位，说明新增订单补位迅猛，在手订单厚度确保了后续业绩的确定性。</p>\\n<p><strong>④ 存货规模创历史新高，“主动备货+在途商品”折射订单爆棚： </strong>高达1089亿的存货并非锂电下行周期中的滞销积压，而是下游需求端旺盛的侧面印证。</p>\\n<p>一方面是公司利用资金优势在涨价初期“低价囤货”平滑成本；另一方面，随着系统级储能产品爆发和出海版图扩大，长周期的“在途发出商品”大幅增加。上行周期的高存货，恰恰是下游催单、需求旺盛的隐射。</p>\\n<p><strong>⑤ 资产减值包袱彻底出清，带来利润端释放： </strong>随着上一周期跌价准备的充分计提以及一季度锂价的企稳回升，当季资产减值损失环比大幅锐减，占收入比重仅1.1%。减值压力的解除，使得前端通过量价齐升与规模效应积累的毛利优势，顺畅无阻地传导至净利润端，彻底释放了利润高弹性。</p>\\n<p><strong>综合考量公司产能周期的重新扩张、海外（尤其是欧洲）产能的加速爬坡以及全球储能市场的爆发，海豚君进一步上调2026年宁德时代电池总出货量预期至 950GWh（同比增长44%）。具体出货结构与核心驱动如下：</strong></p>\\n<p><strong>动力电池出货预计达 754 GWh（同增40%）：</strong> 增长不仅得益于公司产能释放带来的市占率的稳步向上，更受两大“Beta杠杆”的强力驱动——乘用车端向“标配长续航”演进带来的单车带电量飙升，以及重卡/物流等高带电量商用车渗透率跃升所释放的巨大需求杠杆（1:4拉动效应）。</p>\\n<p>一季度公司动力电池出货约150GWh，同比增速高达56%；同期国内新能源车销量增速仅为-4%。两者之间形成了巨大的“增速剪刀差”，也进一步验证了“单车带电量提升与结构化增量”的逻辑正在兑现。</p>\\n<p><strong>储能电池出货预计达 196 GWh（同增62%）：</strong> 增长的确定性来自于供需双核共振——国内独立储能容量电价政策落地彻底打通了项目经济性闭环；同时，全球AI数据中心（AIDC）军备竞赛从电源侧和用户侧双向催生了对储能系统的海量配套需求。</p>\\n<p>基于此，海豚君在相对乐观的假设情境下（如：基于金属价格联动机制的顺畅传导向下游提价，叠加自有锂矿重启释放低成本红利等），认为宁德时代全年单 Wh 净利仍有进一步上行的空间，有望抬升至 0.11-0.12元 的区间。按 950GWh 的总出货量测算，预计 2026 年全年净利润将突破千亿大关，达到 1045亿-1140亿元。</p>\\n<p>毫无疑问，宁德时代在锂电上行周期中的基本面表现是极其强悍且稳健的。但海豚君需提示，尽管公司基本面无可挑剔，但对于前期未及时介入的投资者，若追求更充厚的安全垫，请保持密切关注，耐心等待市场情绪阶段性回落，或宏观预期扰动砸出更具安全边际的“击球点���时，再行逢低布局。</p>\\n<p><strong>以下是详细内容</strong></p>\\n<h2><strong>一. 收入端继续超预期，核心驱动仍是出货量高增与成本传导</strong></h2>\\n<p>2026年一季度单季收入1291亿元，同比大幅增长52%，再次验证锂电上行周期启动，并大幅超出市场预期1142亿。超预期的核心在于出货量继续高增，以及在上游原材料涨价背景下，公司凭借强大的议价能力顺利将成本传导至下游，带动了销售单价提升。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_db37b1cbb1aa40efb47a59465f7b89f6@000000_oswg67567oswg1080oswg517_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<h3>1. <strong>电池出货量：同比高增约67%至超200GWh</strong></h3>\\n<p>一季度，宁德时代电池出货量超200GWh，同比增幅约67%，大幅高于市场预期的168Gwh（市场预期的同比增幅40%），其中：</p>\\n<p><strong>① 动力电池出货约150GWh，占比约75%，同比增速高达56%，</strong>显著高于国内新能源车-4%的销量增速，形成巨大“剪刀差”。海豚君认为，动力电池销量增速大幅高于国内新能源车销量增速，主要源于源于行业Beta升级与公司Alpha共振：</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_28cdc55e3729477b8296f7a039c7c474@000000_oswg59302oswg1080oswg508_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>行业beta层面：单车带电量提升+商用车“高带电量”的杠杆效应：</strong></p>\\n<p><strong>a. 单车带电量继续提升：</strong>在纯电与插混车型结构相对稳定的背景下，乘用车电池单车容量仍然在不断上行，据CABIA数据，Q1国内新能源单车平均带电量66.7kwh, 同比增长34%（纯电乘用车65.3kwh, 同比增长21.4%，插混乘用车36.2kwh, 同比增长40.6%）。</p>\\n<p>一季度国内600km续航以上的车型占比已达到40%-50%，大幅远高于去年一季度10%-20%的水平。这主要得益于：</p>\\n<p><strong>纯电车型（BEV）的大电量军备竞赛：</strong>车企为缓解里程焦虑并提升高端产品竞争力，正加速普及大容量电池包。例如，蔚来全系标配门槛提升至100kWh，小米SU7中高配搭载96kWh以上电池包，市场正从“选配长续航”向“标配长续航”跃迁。</p>\\n<p><strong>增程式（EREV）的“纯电化”演进：</strong>为追求更好的日常纯电通勤体验，增程车型的电池容量中枢正从传统的40kWh大幅上探至60-80kWh（如零跑D19搭载80.3kWh电池，理想L系列等大电量版本）。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c2ed5bef01d948e189a5bc63633f5b3c@000000_oswg71785oswg1080oswg401_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_0a42f7ed50b447a984330a0470a00f69@000000_oswg112597oswg1080oswg693_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>b. 高带电量商用车销量占比快速提升，产生需求杠杆</strong></p>\\n<p><strong>高带电量商用车渗透率跃升，释放需求杠杆： </strong>一季度，国内新能源商用车累计销量18.4万辆，同比增长23.6%（远超商用车整体6%的增速），渗透率从2024年的约4.5%快速攀升至2026年一季度的近7%。受电池成本下探带来的TCO（全生命周期成本）优势及路权政策驱动，重卡和轻型物流车正迎来爆发。</p>\\n<p><strong>巨大的需求杠杆（1:4效应）：</strong> 纯电商用车平均带电量已飙升至近200kWh（2024年同期仅为118kWh），远超纯电乘用车的60-70kWh。</p>\\n<p>这意味着每新增1辆纯电商用车销量，相当于拉动了3-4辆纯电乘用车的电池需求。<strong>由于商用车及专用车已占宁德时代动力总销量的1/3，这种杠杆效应对其出货量拉动极为显著。</strong></p>\\n<p><strong>公司Alpha层面：全球市占率持续提升</strong></p>\\n<p>国内份额持续挤压对手： 一季度宁德时代国内市占率环比继续提升3.2个百分点至47.7%；若剔除比亚迪（主要自供），其在第三方市场的市占率环比上行1.8个百分点至57.3%。</p>\\n<p>全球化产能释放与产品红利： 根据2026年1-2月数据，公司全球动力电池使用量市占率达40.5%（同比+1.8pct），其中海外市占率达32.1%（同比+2.2pct）。随着前期因满产限制而压抑的产能得到释放，叠加神行、麒麟等高质量电池产品的放量，公司在全球市场的统治力进一步巩固。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_d067bdad59e6438faf03626119beb6f1@000000_oswg57265oswg1080oswg406_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>② 储能电池出货50Gwh, 同比大增108%，需求与产能释放双驱动</strong></p>\\n<p>一季度，宁德时代储能电池出货约50GWh，同比大幅增长108%，增长势头极为强劲。这一增速与行业高景气度相符（2026年一季度中国储能电池销量同比增长112%），主要仍然由于行业对于储能的高需求，以及宁王用于缓解储能产能压力的山东济宁基地（规划超100GWh）的新增产能，在 2026年Q1开始释放。</p>\\n<p><strong>a. 国内政策与市场共振，经济性拐点确立</strong></p>\\n<p>全国性容量电价机制推行：2026年初，国家出台“114号文”，首次在国家层面建立电网侧独立储能容量电价机制。该政策以煤电价格为基准，为储能项目提供稳定的容量收益，显著改善项目经济性（IRR可提升至8%-9%），彻底激活了投资需求。作为拥有长寿命、低衰减技术的绝对龙头，宁德时代直接受益于终端需求的爆发。</p>\\n<p>产能释放支撑交付：公司用于缓解储能产能压力的山东济宁基地（规划新增产能超100GWh）在2026年开始逐步释放产能，有力支撑了出货量的高增长。</p>\\n<p><strong>b. AIDC数据中心成为储能新增长极</strong></p>\\n<p>AI数据中心（AIDC）的快速发展，从电源侧和用户侧双重维度催生了对储能的新需求：</p>\\n<p>电源侧（提升有效容量）：为匹配风光等间歇性新能源的高比例接入，配套储能是提升其有效容量系数、保障电网稳定的关键手段。</p>\\n<p>用户侧（负荷管理与经济性）：</p>\\n<p>稳定AI负载：AI训练和推理负载具有剧烈、同步的波动性，配备储能可以平抑这种“毫秒级”功率脉冲，保障数据中心自身用电安全。</p>\\n<p>经济性与加速并网：储能具备“削峰填谷”的套利经济性。同时，北美等地的电网运营商（如PJM、ERCOT）已出台政策，要求新接入的大型负荷（如数据中心）必须具备调节自身负荷、减少对电网冲击的能力。配备储能成为数据中心加速通过并网审批、实现快速上电的关键解决方案。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8094b55ae4b84105addad5f1b25ab30e@000000_oswg57482oswg1080oswg529_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_68095d73ae134a3fa86ae61887a2041e@000000_oswg54554oswg1080oswg532_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_a8de6a1d3b36494c9ba3d585b163daf1@000000_oswg79463oswg1080oswg583_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>b. 电池单价：价格联动凸显议价权</strong></p>\\n<p><strong>单价方面，一季度宁德时代整体电池销售均价达到0.57元/Wh，环比提升4%。而宁王一季度面临“两大逆风”：</strong></p>\\n<p>上游成本急剧推升： 一季度碳酸锂价格从上年四季度的8-10万元/吨快速反弹至15-18万元/吨。</p>\\n<p>产品结构带来均价下行压力： 单价相对较低的储能电池出货量占比在一季度提升了5个百分点至25%，对整体均价构成了结构性的的向下拖累。</p>\\n<p>但在“成本向上 + 结构向下”的双重压力下，公司整体均价依然实现环比上涨。这直接印证了公司在产业链中强大的议价权：公司表示其大部分订单均已签订完善的碳酸锂等金属价格联动机制，凭借强大的议价能力，宁德时代顺利将原材料涨价压力传导至下游客户，有效对冲了成本波动，带动了销售均价的坚挺向上。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_7b9c4f6623364bb58ade5e3a5ba2a27e@000000_oswg71176oswg1080oswg572_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<h3><strong>2. 毛利率环比受挤压回落，但仍然具备极强盈利韧性</strong></h3>\\n<p>1Q26公司毛利率为24.8%，单Wh毛利从去年四季度的0.18元/Wh下滑至约0.16元/Wh。虽然相比去年四季度产能满载时的高点（毛利率28.2%）有所回落，但整体表现与市场预期持平，展现了极其稳健的盈利韧性。</p>\\n<p><strong>一季度的盈利端主要面临了多重逆风的集中挤压：</strong></p>\\n<p>成本与结构双向承压： 碳酸锂均价快速反弹至15-18万元/吨带来成本冲击，同时相对低毛利的储能电池出货占比提升。</p>\\n<p>淡季效应与折旧摊销： 受一季度传统淡季影响，公司产能利用率从25年下半年满产时的103%回落至85%-90%区间，导致单位折旧摊销成本略有上升。</p>\\n<p>政策性因素扰动： 出口税收优惠退坡也对表观利润率构成了一定挤压。</p>\\n<p><strong>但在上述多重逆风下，公司依然能维持稳健的毛利率和净利率水平，核心得益于其超越周期的抗风险能力：</strong></p>\\n<p><strong>① </strong>低价存货的“蓄水池”效应： 去年四季度末，公司账面存货高达945亿元（存货/营业收入比例达67%）。庞大的库存规模相当于一个缓冲垫，使得公司在一季度能够部分使用前期储备的低价原材料进行生产，有效覆盖并平滑了当季的成本上涨冲击。</p>\\n<p><strong>② </strong>上游资源的战略级对冲： 相比上一轮锂价上行周期，公司目前的上游资源布局更加完善。公司持有洛阳钼业（CMOC）约25%的股权，叠加自有江西锂矿（JXW）有望在2026年迎来重启。这些上游资产等同于一个巨大的低成本“隐形库存”，对冲外购锂价波动的能力大幅增强。</p>\\n<p><strong>③ </strong>极致的规模效应与大单品策略： 尽管处于传统淡季且处在产能扩建期，公司85%-90%的产能利用率在行业内依然处于绝对高位。配合在产品端大力推行的“大单品策略”（如神行、麒麟电池的规模化量产），公司在制造环节的规模经济降本效应依然显著。</p>\\n<p><strong>④ </strong>强悍的成本转嫁能力： 无论是面对原材料价格的反弹，还是出口税收优惠减少这类预期内的政策变动，公司凭借完善的金属价格联动合同安排以及极强的产业链话语权，能够将绝大部分的成本增量顺利转嫁给下游客户。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_e460226c954f458aafed7482f5c6b804@000000_oswg102724oswg1080oswg844_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1310c205f29f42b3a0bc13ff4711168d@000000_oswg77786oswg1080oswg539_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<h2><strong>二. 全面上行周期逻辑不改，终端需求仍强劲</strong></h2>\\n<p><strong>1）产能利用率稳居85%-90%高位，二季度排产持续饱满</strong></p>\\n<p>受一季度新能源车市传统淡季及公司自身产能持续扩建（总产能基数变大）的双重叠加影响，公司一季度的产能利用率从2025年下半年的超负荷满产状态（103%）阶段性回落至85%-90%区间。但在分母端不断扩张的背景下，这一利用率水平在全行业中依然处于绝对领先的高位，侧面印证了终端拿货的积极性。</p>\\n<p>而根据公司的最新指引，二季度各项排产计划依然保持饱和状态，预计产能利用率将继续企稳在85%-90%的高位区间。这不仅有效打消了市场对“电动车需求增速放缓拖累总出货”的担忧，也从生产端再次验证了宁德时代依然在量价齐升的全面上行周期内。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_0d0ad10318bc41efa9b3525a81a4fe6d@000000_oswg53078oswg1080oswg285_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>2）资本开支再加速，海内外产能扩张高调重启</strong></p>\\n<p>从资本开支的周期律来看，宁德时代正迎来新一轮的扩张拐点。虽然公司在2021-2022年经历了产能的密集投入期，随后因行业阶段性供需错配，资本开支自2022年Q1起进入下行周期（并在2023年Q1触及约67亿元的阶段性低点）。</p>\\n<p>但自2024年Q1起，公司的资本支出已开始筑底回升。本季度，资本开支更是加速攀升至约124亿元，逼近上一轮扩产巅峰期的水平，释放出极强的扩张信号。</p>\\n<p>伴随资本开支的加速，公司对未来的排产指引也极为积极：公司此前已将2026年的排产目标大幅上修至 1.1-1.2 TWh（对比2025年约772 GWh的基数，预计新增产能约400 GWh），产能同比增速高达42%-55%！</p>\\n<p><strong>目前，公司在全球范围内的产能布局正全面开花：</strong></p>\\n<p><strong>国内大盘稳步扩建： </strong>山东济宁、广东肇庆（瑞庆时代）、江西宜春、福建厦门、青海及福建宁德等主力基地均在大幅扩产。其中，为承接井喷的储能订单，山东济宁基地（规划超100GWh）的新增产能已按计划于2026年Q1逐步释放。</p>\\n<p><strong>海外产能加速兑现：</strong> 海外市场正成为下一阶段量增的核心驱动力。</p>\\n<p>欧洲：德国工厂（14GWh）已于24年投产并实现稳定盈利；匈牙利工厂（规划100GWh）的一期项目（34GWh）电芯产线设备已进场调试，预计2025年底建成；西班牙工厂（规划60GWh）已完成前期审批并成立合资公司，即将在2026年正式启动筹建。</p>\\n<p>东南亚布局：印尼电池产业链项目进展顺利，预计将于2026年上半年正式投产。</p>\\n<p>而强劲的产能释放，不仅直接拉动了宁德时代2026年一季度全球市占率的强势回升，也为后续的需求的释放提供了供给端的保证。</p>\\n<p>从投产节奏和基数效应来看，2026年海外市场产能的密集放量，将成为公司业绩高增的基石。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c4fa266751724fba9c7f06bf179e44e2@000000_oswg56502oswg1080oswg442_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_b6fd85911eac425993122c5e9a23cecc@000000_oswg61882oswg1080oswg633_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>3）存货还在继续高增，背后隐含旺盛订单需求</strong></p>\\n<p>本季度末，公司存货规模显著攀升至1089亿元，环比大幅增加约144亿元，绝对值创下历史新高。存货占收入比例由上季度的67%跃升至本季度的84%，存货周转天数也同步延长至近95天。</p>\\n<p>不同于传统下行周期中的“被动去库存”压力，海豚君认为，宁德时代当前的存货高企更多体现了上行周期中的“主动备货”与“订单在途”：</p>\\n<p>① 原材料战略储备：主动平滑成本波动</p>\\n<p>为应对碳酸锂等核心原材料价格的筑底回升，公司利用强大的现金流优势，有针对性地增加了原材料及自制半成品的储备。</p>\\n<p>这种在价格上涨通道开启前的“低价囤货”行为，构建了一个巨大的成本缓冲池，能有效对冲未来1-2个季度原材料上行对毛利率的负面挤压。</p>\\n<p><strong>② “发出商品”（已发货但未开票确认收入）占比提升：</strong></p>\\n<p>产品形态由“芯”向“系统”演进： 随着储能系统（ESS）出货占比显著提升，由于系统级产品涉及现场安装、调试及较长的交付周期，导致在财务报表上表现为较长时间的存货沉淀。</p>\\n<p>全球供应链半径拉长： 公司海外市场正从欧洲向中东、美洲等远距离地区多点开花。远洋运输比例的增加及长距离交付周期的延长，使得大量处于交付途中的货品积压在存货端。</p>\\n<p>而着反而隐含下游客户订单的极高景气度。随着这部分在途商品在未来几个季度逐步转化结转为收入，公司的业绩增长将获得更强的确定性。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3a3dc2687c514f8a97f80b6737692f28@000000_oswg76970oswg1080oswg457_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>4） 合同负债继续维持高位</strong></p>\\n<p>由于宁王主要是个To B的生意，所以会出现已收下游B端客户的预付款项，但还没交付的情况，所以合同负债可以近似看出宁王在手订单量变化的一个近似指标。</p>\\n<p>从宁王一季度合同负债虽然环比上季度高点492亿环比下滑了37亿元至455亿元，但仍然处于高位水平，随着公司各大基地产能利用率维持高位，一季度电池出货量同比大增67%，这使得前期积压的订单得以快速交付并转化为营业收入，从而在财务端体现为合同负债的正常结转回落。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_182c3a99310b44618c0b51efd48a8f46@000000_oswg58596oswg1080oswg499_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>5）资产减值本季度环比回落</strong></p>\\n<p>本季度，公司资产减值损失约为14亿元，较上季度的计提峰值（46亿元）环比大幅锐减32亿元。从相对比重来看，资产减值占营业收入的比例环比下降约2个百分点，仅为1.1%。</p>\\n<p>海豚君认为，减值压力的下降主要得益于前期计提充分与上游价格企稳的共振：</p>\\n<p>历史包袱出清：公司秉持审慎的财务原则，已对存货及涉锂矿产资源等相关资产进行了极为充分的减值计提。</p>\\n<p>跌价风险解除： 叠加一季度碳酸锂等核心原材料价格企稳反弹，新增大额存货跌价准备的风险已基本解除。</p>\\n<p>而减值风险的出清，也进一步带来了利润端的释放。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_06f65b4b02e942eeb8f67b8f62c2167a@000000_oswg64490oswg1080oswg469_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>一季度，宁王归母净利207亿（同比增长49%）同样大幅高于市场预期176亿，扣非归母净利润164亿元，同比大增53%。</p>\\n<p>而超预期的原因仍然在于出货量的继续高增，叠加凭借绝对议价能力实现的成本有效传导，带来的收入与毛利润的超预期。</p>\\n<p>研发及各项期间费用得到精准、高效的管控，配合资产减值损失的环比大幅出清，带来了报表段利润的进一步释放。</p>\\n<p>本季度公司单Wh净利维持在约0.1元/Wh，与上季度基本持平。在碳酸锂等原材料价格快速反弹的逆风环境下，这一极其坚挺的单位盈利表现，彻底击碎了此前市场关于“原材料涨价将侵蚀公司利润”的悲观预期，再次验证了公司穿越周期的强悍实力。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3b56fdc737aa40be908a234c4194a4fb@000000_oswg74335oswg1080oswg521_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>而海豚君更关注的核心运营利润率趋势（毛利率-三费-资产/信用减值损失率），一季度205亿元，同比增速高达94%，核心运营利润率也达到15.9%，环比与上季度持平，也表明宁王持续稳健的经营能力。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6e9cd9c4a92b42c19e7e27ca14643ef9@000000_oswg71224oswg1080oswg531_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>本文来自微信公众号 <a href=\\\"https://mp.weixin.qq.com/s?__biz=MzE5MTU3MzA2OQ==&amp;mid=2247571258&amp;idx=2&amp;sn=8bc3f0b7a53fa0d96bba3bc5e949e696&amp;chksm=97178c0874802d97f11213100f939eef7c598ed3ecdc08fff0483988d7c3dc67fe2e12326b14&amp;scene=0&amp;xtrack=1#rd\\\">“海豚投研”（ID：haituntouyan）</a>，作者：海豚君，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\\\"title\\\": \\\"\\\\u5b81\\\\u738b\\\\uff1a\\\\u65e0\\\\u53ef\\\\u64bc\\\\u52a8\\\\u7684\\\\u80fd\\\\u6e90\\\\u65f6\\\\u4ee3 \\\\u201c\\\\u53f0\\\\u79ef\\\\u7535\\\\u201d\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u5b81\\\\u738b\\\\uff1a\\\\u65e0\\\\u53ef\\\\u64bc\\\\u52a8\\\\u7684\\\\u80fd\\\\u6e90\\\\u65f6\\\\u4ee3 \\\\u201c\\\\u53f0\\\\u79ef\\\\u7535\\\\u201d\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769366038872583?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769366038872583?f=rss\\\", \\\"published\\\": \\\"2026-04-16 21:27:37  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 13, 27, 37, 3, 106, 0], \\\"summary\\\": \\\"<p><strong>2026\\\\u5e744\\\\u670815\\\\u65e5\\\\u665a\\\\uff0c</strong>\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3<strong>\\\\u516c\\\\u5e03\\\\u4e862026\\\\u5e74\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u4e1a\\\\u7ee9\\\\u3002\\\\u5728\\\\u5e02\\\\u573a\\\\u5bf9\\\\u5176\\\\u201c\\\\u80fd\\\\u5426\\\\u625b\\\\u4f4f\\\\u78b3\\\\u9178\\\\u9502\\\\u6da8\\\\u4ef7\\\\u201d\\\\u548c\\\\u201c\\\\u7535\\\\u52a8\\\\u8f66\\\\u589e\\\\u901f\\\\u653e\\\\u7f13\\\\u201d\\\\u7684\\\\u7591\\\\u8651\\\\u4e2d\\\\uff0c\\\\u5b81\\\\u738b\\\\u7528\\\\u4e00\\\\u4efd\\\\u5168\\\\u7ebf\\\\u8d85\\\\u9884\\\\u671f\\\\u7684\\\\u6210\\\\u7ee9\\\\u5355\\\\u7ed9\\\\u51fa\\\\u4e86\\\\u6700\\\\u6709\\\\u529b\\\\u7684\\\\u56de\\\\u51fb\\\\uff1a</strong></p>\\\\n  <p><strong>\\\\u2460\\\\u603b\\\\u6536\\\\u5165\\\\u8d85\\\\u9884\\\\u671f\\\\uff0c\\\\u7531\\\\u91cf\\\\u4ef7\\\\u9f50\\\\u5347\\\\u6240\\\\u5e26\\\\u52a8\\\\uff1a&nbsp;</strong>\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u5b9e\\\\u73b0\\\\u6536\\\\u5165 1291 \\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u5927\\\\u5e45\\\\u589e\\\\u957f52%\\\\uff0c\\\\u518d\\\\u6b21\\\\u9a8c\\\\u8bc1\\\\u9502\\\\u7535\\\\u4e0a\\\\u884c\\\\u5468\\\\u671f\\\\u542f\\\\u52a8\\\\uff0c\\\\u5e76\\\\u5927\\\\u5e45\\\\u8d85\\\\u51fa\\\\u5e02\\\\u573a\\\\u9884\\\\u671f1142\\\\u4ebf\\\\u3002\\\\u8d85\\\\u9884\\\\u671f\\\\u7684\\\\u6838\\\\u5fc3\\\\u5728\\\\u4e8e\\\\u51fa\\\\u8d27\\\\u91cf\\\\u7ee7\\\\u7eed\\\\u9ad8\\\\u589e\\\\uff0c\\\\u4ee5\\\\u53ca\\\\u5728\\\\u4e0a\\\\u6e38\\\\u539f\\\\u6750\\\\u6599\\\\u6da8\\\\u4ef7\\\\u80cc\\\\u666f\\\\u4e0b\\\\uff0c\\\\u516c\\\\u53f8\\\\u51ed\\\\u501f\\\\u5f3a\\\\u5927\\\\u7684\\\\u8bae\\\\u4ef7\\\\u80fd\\\\u529b\\\\u987a\\\\u5229\\\\u5c06\\\\u6210\\\\u672c\\\\u4f20\\\\u5bfc\\\\u81f3\\\\u4e0b\\\\u6e38\\\\uff0c\\\\u5e26\\\\u52a8\\\\u4e86\\\\u9500\\\\u552e\\\\u5355\\\\u4ef7\\\\u63d0\\\\u5347\\\\u3002</p>\\\\n  <p><strong>\\\\u2461 \\\\u51fa\\\\u8d27\\\\u91cf\\\\u5927\\\\u5e45\\\\u9ad8\\\\u589e\\\\uff1a</strong>\\\\u4e00\\\\u5b63\\\\u5ea6\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u7535\\\\u6c60\\\\u51fa\\\\u8d27\\\\u91cf\\\\u8d85200GWh\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u5e45\\\\u7ea667%\\\\uff0c\\\\u5927\\\\u5e45\\\\u9ad8\\\\u4e8e\\\\u5e02\\\\u573a\\\\u9884\\\\u671f\\\\u7684168Gwh\\\\uff08\\\\u5e02\\\\u573a\\\\u9884\\\\u671f\\\\u7684\\\\u540c\\\\u6bd4\\\\u589e\\\\u5e4540%\\\\uff09\\\\uff0c\\\\u5176\\\\u4e2d\\\\uff1a</p>\\\\n  <p><strong>\\\\u52a8\\\\u529b\\\\u7535\\\\u6c60\\\\u9886\\\\u8dd1\\\\u884c\\\\u4e1a\\\\uff0c\\\\u5e26\\\\u7535\\\\u91cf\\\\u201c\\\\u6760\\\\u6746\\\\u6548\\\\u5e94\\\\u201d\\\\u7206\\\\u53d1\\\\uff1a</strong>&nbsp;\\\\u52a8\\\\u529b\\\\u7535\\\\u6c60\\\\u51fa\\\\u8d27\\\\u7ea6 150GWh\\\\uff08\\\\u540c\\\\u6bd4+56%\\\\uff09\\\\uff0c\\\\u8fdc\\\\u8d85\\\\u56fd\\\\u5185\\\\u65b0\\\\u80fd\\\\u6e90\\\\u8f66\\\\u9500\\\\u91cf\\\\u589e\\\\u901f\\\\uff08-4%\\\\uff09\\\\u3002\\\\u8fd9\\\\u80cc\\\\u540e\\\\u7684\\\\u6838\\\\u5fc3\\\\u903b\\\\u8f91\\\\u5728\\\\u4e8e\\\\u201c\\\\u884c\\\\u4e1a Beta \\\\u5347\\\\u7ea7\\\\u201d\\\\uff1a\\\\u4e58\\\\u7528\\\\u8f66\\\\u6807\\\\u914d\\\\u957f\\\\u7eed\\\\u822a\\\\u4ee5\\\\u53ca\\\\u9ad8\\\\u5e26\\\\u7535\\\\u91cf\\\\u5546\\\\u7528\\\\u8f66\\\\u6e17\\\\u900f\\\\u7387\\\\u8dc3\\\\u5347\\\\u5e26\\\\u6765\\\\u7684 1:4 \\\\u9700\\\\u6c42\\\\u6760\\\\u6746\\\\u6548\\\\u5e94\\\\u5df2\\\\u5168\\\\u9762\\\\u5151\\\\u73b0\\\\u3002</p>\\\\n  <p><strong>\\\\u50a8\\\\u80fd\\\\u7ffb\\\\u500d\\\\u589e\\\\u957f\\\\uff0cAIDC \\\\u5f00\\\\u542f\\\\u65b0\\\\u589e\\\\u957f\\\\u6781\\\\uff1a&nbsp;</strong>\\\\u50a8\\\\u80fd\\\\u51fa\\\\u8d27 50GWh\\\\uff08\\\\u540c\\\\u6bd4+108%\\\\uff09\\\\u3002\\\\u9664\\\\u4e86\\\\u56fd\\\\u5185\\\\u5bb9\\\\u91cf\\\\u7535\\\\u4ef7\\\\u653f\\\\u7b56\\\\u7684\\\\u7ea2\\\\u5229\\\\u5916\\\\uff0cAI \\\\u6570\\\\u636e\\\\u4e2d\\\\u5fc3\\\\uff08AIDC\\\\uff09\\\\u5bf9\\\\u50a8\\\\u80fd\\\\u7cfb\\\\u7edf\\\\u7684\\\\u521a\\\\u6027\\\\u9700\\\\u6c42\\\\u5df2\\\\u6210\\\\u4e3a\\\\u516c\\\\u53f8\\\\u65b0\\\\u7684\\\\u7206\\\\u53d1\\\\u70b9\\\\uff0c\\\\u53e0\\\\u52a0\\\\u6d4e\\\\u5b81\\\\u57fa\\\\u5730\\\\u4ea7\\\\u80fd\\\\u91ca\\\\u653e\\\\uff0c\\\\u50a8\\\\u80fd\\\\u4e1a\\\\u52a1\\\\u5df2\\\\u6210\\\\u4e3a\\\\u7b2c\\\\u4e8c\\\\u589e\\\\u957f\\\\u66f2\\\\u7ebf\\\\u3002</p>\\\\n  <p><strong>\\\\u2462 \\\\u4ef7\\\\u683c\\\\u4f20\\\\u5bfc\\\\u987a\\\\u5229\\\\uff0c\\\\u8bae\\\\u4ef7\\\\u6743\\\\u9501\\\\u5b9a\\\\u76c8\\\\u5229\\\\uff1a&nbsp;</strong>\\\\u5728\\\\u78b3\\\\u9178\\\\u9502\\\\u4ef7\\\\u683c\\\\u53cd\\\\u5f39\\\\u81f3 15-18 \\\\u4e07\\\\u5143/\\\\u5428\\\\u7684\\\\u9006\\\\u98ce\\\\u4e0b\\\\uff0c\\\\u516c\\\\u53f8\\\\u5355\\\\u4ef7\\\\u73af\\\\u6bd4\\\\u63d0\\\\u5347 4% \\\\u81f3 0.57 \\\\u5143/Wh\\\\u3002\\\\u51ed\\\\u501f\\\\u5b8c\\\\u5584\\\\u7684\\\\u4ef7\\\\u683c\\\\u8054\\\\u52a8\\\\u673a\\\\u5236\\\\uff0c\\\\u516c\\\\u53f8\\\\u6210\\\\u529f\\\\u5c06\\\\u6210\\\\u672c\\\\u538b\\\\u529b\\\\u5411\\\\u4e0b\\\\u6e38\\\\u4f20\\\\u5bfc\\\\uff0c\\\\u5f7b\\\\u5e95\\\\u51fb\\\\u788e\\\\u4e86\\\\u201c\\\\u539f\\\\u6750\\\\u6599\\\\u6da8\\\\u4ef7\\\\u4fb5\\\\u8680\\\\u5229\\\\u6da6\\\\u201d\\\\u7684\\\\u62c5\\\\u5fe7\\\\u3002</p>\\\\n  <p><strong>\\\\u2463 \\\\u6bdb\\\\u5229\\\\u7387\\\\u9ad8\\\\u4f4d\\\\u56de\\\\u843d\\\\u4f46\\\\u663e\\\\u97e7\\\\u6027\\\\uff0c\\\\u6210\\\\u672c\\\\u8f6c\\\\u5ac1\\\\u5e73\\\\u