4e5f\\\\u8fdb\\\\u4e00\\\\u6b65\\\\u5e26\\\\u6765\\\\u4e86\\\\u5229\\\\u6da6\\\\u7aef\\\\u7684\\\\u91ca\\\\u653e\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_06f65b4b02e942eeb8f67b8f62c2167a@000000_oswg64490oswg1080oswg469_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u4e00\\\\u5b63\\\\u5ea6\\\\uff0c\\\\u5b81\\\\u738b\\\\u5f52\\\\u6bcd\\\\u51c0\\\\u5229207\\\\u4ebf\\\\uff08\\\\u540c\\\\u6bd4\\\\u589e\\\\u957f49%\\\\uff09\\\\u540c\\\\u6837\\\\u5927\\\\u5e45\\\\u9ad8\\\\u4e8e\\\\u5e02\\\\u573a\\\\u9884\\\\u671f176\\\\u4ebf\\\\uff0c\\\\u6263\\\\u975e\\\\u5f52\\\\u6bcd\\\\u51c0\\\\u5229\\\\u6da6164\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u5927\\\\u589e53%\\\\u3002</p>\\\\n  <p>\\\\u800c\\\\u8d85\\\\u9884\\\\u671f\\\\u7684\\\\u539f\\\\u56e0\\\\u4ecd\\\\u7136\\\\u5728\\\\u4e8e\\\\u51fa\\\\u8d27\\\\u91cf\\\\u7684\\\\u7ee7\\\\u7eed\\\\u9ad8\\\\u589e\\\\uff0c\\\\u53e0\\\\u52a0\\\\u51ed\\\\u501f\\\\u7edd\\\\u5bf9\\\\u8bae\\\\u4ef7\\\\u80fd\\\\u529b\\\\u5b9e\\\\u73b0\\\\u7684\\\\u6210\\\\u672c\\\\u6709\\\\u6548\\\\u4f20\\\\u5bfc\\\\uff0c\\\\u5e26\\\\u6765\\\\u7684\\\\u6536\\\\u5165\\\\u4e0e\\\\u6bdb\\\\u5229\\\\u6da6\\\\u7684\\\\u8d85\\\\u9884\\\\u671f\\\\u3002</p>\\\\n  <p>\\\\u7814\\\\u53d1\\\\u53ca\\\\u5404\\\\u9879\\\\u671f\\\\u95f4\\\\u8d39\\\\u7528\\\\u5f97\\\\u5230\\\\u7cbe\\\\u51c6\\\\u3001\\\\u9ad8\\\\u6548\\\\u7684\\\\u7ba1\\\\u63a7\\\\uff0c\\\\u914d\\\\u5408\\\\u8d44\\\\u4ea7\\\\u51cf\\\\u503c\\\\u635f\\\\u5931\\\\u7684\\\\u73af\\\\u6bd4\\\\u5927\\\\u5e45\\\\u51fa\\\\u6e05\\\\uff0c\\\\u5e26\\\\u6765\\\\u4e86\\\\u62a5\\\\u8868\\\\u6bb5\\\\u5229\\\\u6da6\\\\u7684\\\\u8fdb\\\\u4e00\\\\u6b65\\\\u91ca\\\\u653e\\\\u3002</p>\\\\n  <p>\\\\u672c\\\\u5b63\\\\u5ea6\\\\u516c\\\\u53f8\\\\u5355Wh\\\\u51c0\\\\u5229\\\\u7ef4\\\\u6301\\\\u5728\\\\u7ea60.1\\\\u5143/Wh\\\\uff0c\\\\u4e0e\\\\u4e0a\\\\u5b63\\\\u5ea6\\\\u57fa\\\\u672c\\\\u6301\\\\u5e73\\\\u3002\\\\u5728\\\\u78b3\\\\u9178\\\\u9502\\\\u7b49\\\\u539f\\\\u6750\\\\u6599\\\\u4ef7\\\\u683c\\\\u5feb\\\\u901f\\\\u53cd\\\\u5f39\\\\u7684\\\\u9006\\\\u98ce\\\\u73af\\\\u5883\\\\u4e0b\\\\uff0c\\\\u8fd9\\\\u4e00\\\\u6781\\\\u5176\\\\u575a\\\\u633a\\\\u7684\\\\u5355\\\\u4f4d\\\\u76c8\\\\u5229\\\\u8868\\\\u73b0\\\\uff0c\\\\u5f7b\\\\u5e95\\\\u51fb\\\\u788e\\\\u4e86\\\\u6b64\\\\u524d\\\\u5e02\\\\u573a\\\\u5173\\\\u4e8e\\\\u201c\\\\u539f\\\\u6750\\\\u6599\\\\u6da8\\\\u4ef7\\\\u5c06\\\\u4fb5\\\\u8680\\\\u516c\\\\u53f8\\\\u5229\\\\u6da6\\\\u201d\\\\u7684\\\\u60b2\\\\u89c2\\\\u9884\\\\u671f\\\\uff0c\\\\u518d\\\\u6b21\\\\u9a8c\\\\u8bc1\\\\u4e86\\\\u516c\\\\u53f8\\\\u7a7f\\\\u8d8a\\\\u5468\\\\u671f\\\\u7684\\\\u5f3a\\\\u608d\\\\u5b9e\\\\u529b\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_3b56fdc737aa40be908a234c4194a4fb@000000_oswg74335oswg1080oswg521_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u800c\\\\u6d77\\\\u8c5a\\\\u541b\\\\u66f4\\\\u5173\\\\u6ce8\\\\u7684\\\\u6838\\\\u5fc3\\\\u8fd0\\\\u8425\\\\u5229\\\\u6da6\\\\u7387\\\\u8d8b\\\\u52bf\\\\uff08\\\\u6bdb\\\\u5229\\\\u7387-\\\\u4e09\\\\u8d39-\\\\u8d44\\\\u4ea7/\\\\u4fe1\\\\u7528\\\\u51cf\\\\u503c\\\\u635f\\\\u5931\\\\u7387\\\\uff09\\\\uff0c\\\\u4e00\\\\u5b63\\\\u5ea6205\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u901f\\\\u9ad8\\\\u8fbe94%\\\\uff0c\\\\u6838\\\\u5fc3\\\\u8fd0\\\\u8425\\\\u5229\\\\u6da6\\\\u7387\\\\u4e5f\\\\u8fbe\\\\u523015.9%\\\\uff0c\\\\u73af\\\\u6bd4\\\\u4e0e\\\\u4e0a\\\\u5b63\\\\u5ea6\\\\u6301\\\\u5e73\\\\uff0c\\\\u4e5f\\\\u8868\\\\u660e\\\\u5b81\\\\u738b\\\\u6301\\\\u7eed\\\\u7a33\\\\u5065\\\\u7684\\\\u7ecf\\\\u8425\\\\u80fd\\\\u529b\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_6e9cd9c4a92b42c19e7e27ca14643ef9@000000_oswg71224oswg1080oswg531_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u672c\\\\u6587\\\\u6765\\\\u81ea\\\\u5fae\\\\u4fe1\\\\u516c\\\\u4f17\\\\u53f7 <a href=\\\\\\\"https://mp.weixin.qq.com/s?__biz=MzE5MTU3MzA2OQ==&amp;mid=2247571258&amp;idx=2&amp;sn=8bc3f0b7a53fa0d96bba3bc5e949e696&amp;chksm=97178c0874802d97f11213100f939eef7c598ed3ecdc08fff0483988d7c3dc67fe2e12326b14&amp;scene=0&amp;xtrack=1#rd\\\\\\\" rel=\\\\\\\"noopener noreferrer\\\\\\\" target=\\\\\\\"_blank\\\\\\\">\\\\u201c\\\\u6d77\\\\u8c5a\\\\u6295\\\\u7814\\\\u201d\\\\uff08ID\\\\uff1ahaituntouyan\\\\uff09</a>\\\\uff0c\\\\u4f5c\\\\u8005\\\\uff1a\\\\u6d77\\\\u8c5a\\\\u541b\\\\uff0c36\\\\u6c2a\\\\u7ecf\\\\u6388\\\\u6743\\\\u53d1\\\\u5e03\\\\u3002</p>\\\"}, \\\"source\\\": {\\\"title\\\": \\\"36\\\\u6c2a\\\"}, \\\"authors\\\": [{\\\"name\\\": \\\"\\\\u6d77\\\\u8c5a\\\\u6295\\\\u7814\\\"}], \\\"author\\\": \\\"\\\\u6d77\\\\u8c5a\\\\u6295\\\\u7814\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"\\\\u6d77\\\\u8c5a\\\\u6295\\\\u7814\\\"}, \\\"content\\\": [{\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u5728\\\\u5e02\\\\u573a\\\\u5bf9\\\\u5176\\\\u201c\\\\u80fd\\\\u5426\\\\u625b\\\\u4f4f\\\\u78b3\\\\u9178\\\\u9502\\\\u6da8\\\\u4ef7\\\\u201d\\\\u548c\\\\u201c\\\\u7535\\\\u52a8\\\\u8f66\\\\u589e\\\\u901f\\\\u653e\\\\u7f13\\\\u201d\\\\u7684\\\\u7591\\\\u8651\\\\u4e2d\\\\uff0c\\\\u5b81\\\\u738b\\\\u7528\\\\u4e00\\\\u4efd\\\\u5168\\\\u7ebf\\\\u8d85\\\\u9884\\\\u671f\\\\u7684\\\\u6210\\\\u7ee9\\\\u5355\\\\u7ed9\\\\u51fa\\\\u4e86\\\\u6700\\\\u6709\\\\u529b\\\\u7684\\\\u56de\\\\u51fb\\\\u3002\\\"}]}\", \"published_at\": \"2026-04-16 21:27:37\", \"ai_json_output\": \"\"}', '2026年4月15日晚，\n宁德时代\n公布了2026年一季度业绩。在市场对其“能否扛住碳酸锂涨价”和“电动车增速放缓”的疑虑中，宁王用一份全线超预期的成绩单给出了最有力的回击：\n①总收入超预期，由量价齐升所带动：\n一季度实现收入 1291 亿元，同比大幅增长52%，再次验证锂电上行周期启动，并大幅超出市场预期1142亿。超预期的核心在于出货量继续高增，以及在上游原材料涨价背景下，公司凭借强大的议价能力顺利将成本传导至下游，带动了销售单价提升。\n② 出货量大幅高增：\n一季度，宁德时代电池出货量超200GWh，同比增幅约67%，大幅高于市场预期的168Gwh（市场预期的同比增幅40%），其中：\n动力电池领跑行业，带电量“杠杆效应”爆发：\n动力电池出货约 150GWh（同比+56%），远超国内新能源车销量增速（-4%）。这背后的核心逻辑在于“行业 Beta 升级”：乘用车标配长续航以及高带电量商用车渗透率跃升带来的 1:4 需求杠杆效应已全面兑现。\n储能翻倍增长，AIDC 开启新增长极：\n储能出货 50GWh（同比+108%）。除了国内容量电价政策的红利外，AI 数据中心（AIDC）对储能系统的刚性需求已成为公司新的爆发点，叠加济宁基地产能释放，储能业务已成为第二增长曲线。\n③ 价格传导顺利，议价权锁定盈利：\n在碳酸锂价格反弹至 15-18 万元/吨的逆风下，公司单价环比提升 4% 至 0.57 元/Wh。凭借完善的价格联动机制，公司成功将成本压力向下游传导，彻底击碎了“原材料涨价侵蚀利润”的担忧。\n④ 毛利率高位回落但显韧性，成本转嫁平滑涨价冲击：\n一季度宁王毛利率为 24.8%，单 Wh 毛利约 0.16 元。尽管受碳酸锂价格反弹及淡季产能利用率回落等“多重逆风”影响，但凭借强大的成本转嫁能力（高行业议价权）与 945 亿低价存货的“蓄水池”缓冲，公司盈利表现依然稳健，展现了极强的跨周期防御性。\n⑤ 净利润击穿预期，减值压力出清释放利润：\n归母净利 207 亿元（同比+49%），单 Wh 净利依然稳守 0.1 元。\n随着前期“减值包袱”的出清（环比大幅缩减 32 亿）以及核心运营利润率（15.9%）的稳健表现，公司不仅在“量”上领先，在“质”上也彻底击碎了市场关于原材料涨价侵蚀利润的担忧。\n海豚君整体观点：\n整体来看，宁德时代在一季报中展现了无可匹敌的盈利韧性。这是一份不仅“量足”而且“质优”的答卷： 收入与净利润双双击穿市场预期，出货量更是走出了独立于行业的“剪刀差”行情。\n在面临上游原材料反弹、传统淡季及政策扰动等多重逆风的“极限测试”下，公司依然交出了双超预期的成绩单。\n这不仅彻底击碎了此前市场关于“原材料涨价将侵蚀利润”的悲观伪命题，更印证了海豚君在《宁王：产能拉满！AI 基建时代霸气归来》中强调的核心观点：在锂电全面上行的“黄金周期”里，宁王凭借其深厚的成本护城河与议价权，拥有极高的业绩确定性与爆发力。\n而宁王强势穿越周期的实力在这五大核心指标中得到了集中爆发与验证：\n① 产能利用率无惧淡季，高位运转印证强劲需求：\n尽管受一季度传统淡季及自身产能不断扩建（分母端扩大）的双重影响，公司的产能利用率仍稳居 85%-90% 的绝对高位。\n叠加二季度排产持续饱满的指引（仍维持85%-90%），排产端的高景气度直接打消了市场对阶段性需求降温以及电动车增速放缓拖累整体出货量的担忧。\n② 资本开支触底飙升，海内外产能扩张高调重启：\n本季度资本开支结束下行周期，大幅攀升至逼近上轮扩产巅峰的水平（约124亿元）。面对上修至 1.1-1.2 TWh 的26年排产目标（同比增速达42%-55%），公司在国内大储基地及欧洲、东南亚等高毛利海外市场全面按下扩产加速键，为吃透下一波行业红利备足弹药。\n③ 合同负债稳居高位，充沛订单锁定业绩基本盘：\n本季度合同负债（455亿元）虽环比微降，但这并非订单流失，而是由于产能加速释放导致前期积压订单被高效交付结转为收入。在如此高强度的交付下，合同负债依然企稳历史极高水位，说明新增订单补位迅猛，在手订单厚度确保了后续业绩的确定性。\n④ 存货规模创历史新高，“主动备货+在途商品”折射订单爆棚：\n高达1089亿的存货并非锂电下行周期中的滞销积压，而是下游需求端旺盛的侧面印证。\n一方面是公司利用资金优势在涨价初期“低价囤货”平滑成本；另一方面，随着系统级储能产品爆发和出海版图扩大，长周期的“在途发出商品”大幅增加。上行周期的高存货，恰恰是下游催单、需求旺盛的隐射。\n⑤ 资产减值包袱彻底出清，带来利润端释放：\n随着上一周期跌价准备的充分计提以及一季度锂价的企稳回升，当季资产减值损失环比大幅锐减，占收入比重仅1.1%。减值压力的解除，使得前端通过量价齐升与规模效应积累的毛利优势，顺畅无阻地传导至净利润端，彻底释放了利润高弹性。\n综合考量公司产能周期的重新扩张、海外（尤其是欧洲）产能的加速爬坡以及全球储能市场的爆发，海豚君进一步上调2026年宁德时代电池总出货量预期至 950GWh（同比增长44%）。具体出货结构与核心驱动如下：\n动力电池出货预计达 754 GWh（同增40%）：\n增长不仅得益于公司产能释放带来的市占率的稳步向上，更受两大“Beta杠杆”的强力驱动——乘用车端向“标配长续航”演进带来的单车带电量飙升，以及重卡/物流等高带电量商用车渗透率跃升所释放的巨大需求杠杆（1:4拉动效应）。\n一季度公司动力电池出货约150GWh，同比增速高达56%；同期国内新能源车销量增速仅为-4%。两者之间形成了巨大的“增速剪刀差”，也进一步验证了“单车带电量提升与结构化增量”的逻辑正在兑现。\n储能电池出货预计达 196 GWh（同增62%）：\n增长的确定性来自于供需双核共振——国内独立储能容量电价政策落地彻底打通了项目经济性闭环；同时，全球AI数据中心（AIDC）军备竞赛从电源侧和用户侧双向催生了对储能系统的海量配套需求。\n基于此，海豚君在相对乐观的假设情境下（如：基于金属价格联动机制的顺畅传导向下游提价，叠加自有锂矿重启释放低成本红利等），认为宁德时代全年单 Wh 净利仍有进一步上行的空间，有望抬升至 0.11-0.12元 的区间。按 950GWh 的总出货量测算，预计 2026 年全年净利润将突破千亿大关，达到 1045亿-1140亿元。\n毫无疑问，宁德时代在锂电上行周期中的基本面表现是极其强悍且稳健的。但海豚君需提示，尽管公司基本面无可挑剔，但对于前期未及时介入的投资者，若追求更充厚的安全垫，请保持密切关注，耐心等待市场情绪阶段性回落，或宏观预期扰动砸出更具安全边际的“击球点”时，再行逢低布局。\n以下是详细内容\n一. 收入端继续超预期，核心驱动仍是出货量高增与成本传导\n2026年一季度单季收入1291亿元，同比大幅增长52%，再次验证锂电上行周期启动，并大幅超出市场预期1142亿。超预期的核心在于出货量继续高增，以及在上游原材料涨价背景下，公司凭借强大的议价能力顺利将成本传导至下游，带动了销售单价提升。\n1.\n电池出货量：同比高增约67%至超200GWh\n一季度，宁德时代电池出货量超200GWh，同比增幅约67%，大幅高于市场预期的168Gwh（市场预期的同比增幅40%），其中：\n① 动力电池出货约150GWh，占比约75%，同比增速高达56%，\n显著高于国内新能源车-4%的销量增速，形成巨大“剪刀差”。海豚君认为，动力电池销量增速大幅高于国内新能源车销量增速，主要源于源于行业Beta升级与公司Alpha共振：\n行业beta层面：单车带电量提升+商用车“高带电量”的杠杆效应：\na. 单车带电量继续提升：\n在纯电与插混车型结构相对稳定的背景下，乘用车电池单车容量仍然在不断上行，据CABIA数据，Q1国内新能源单车平均带电量66.7kwh, 同比增长34%（纯电乘用车65.3kwh, 同比增长21.4%，插混乘用车36.2kwh, 同比增长40.6%）。\n一季度国内600km续航以上的车型占比已达到40%-50%，大幅远高于去年一季度10%-20%的水平。这主要得益于：\n纯电车型（BEV）的大电量军备竞赛：\n车企为缓解里程焦虑并提升高端产品竞争力，正加速普及大容量电池包。例如，蔚来全系标配门槛提升至100kWh，小米SU7中高配搭载96kWh以上电池包，市场正从“选配长续航”向“标配长续航”跃迁。\n增程式（EREV）的“纯电化”演进：\n为追求更好的日常纯电通勤体验，增程车型的电池容量中枢正从传统的40kWh大幅上探至60-80kWh（如零跑D19搭载80.3kWh电池，理想L系列等大电量版本）。\nb. 高带电量商用车销量占比快速提升，产生需求杠杆\n高带电量商用车渗透率跃升，释放需求杠杆：\n一季度，国内新能源商用车累计销量18.4万辆，同比增长23.6%（远超商用车整体6%的增速），渗透率从2024年的约4.5%快速攀升至2026年一季度的近7%。受电池成本下探带来的TCO（全生命周期成本）优势及路权政策驱动，重卡和轻型物流车正迎来爆发。\n巨大的需求杠杆（1:4效应）：\n纯电商用车平均带电量已飙升至近200kWh（2024年同期仅为118kWh），远超纯电乘用车的60-70kWh。\n这意味着每新增1辆纯电商用车销量，相当于拉动了3-4辆纯电乘用车的电池需求。\n由于商用车及专用车已占宁德时代动力总销量的1/3，这种杠杆效应对其出货量拉动极为显著。\n公司Alpha层面：全球市占率持续提升\n国内份额持续挤压对手： 一季度宁德时代国内市占率环比继续提升3.2个百分点至47.7%；若剔除比亚迪（主要自供），其在第三方市场的市占率环比上行1.8个百分点至57.3%。\n全球化产能释放与产品红利： 根据2026年1-2月数据，公司全球动力电池使用量市占率达40.5%（同比+1.8pct），其中海外市占率达32.1%（同比+2.2pct）。随着前期因满产限制而压抑的产能得到释放，叠加神行、麒麟等高质量电池产品的放量，公司在全球市场的统治力进一步巩固。\n② 储能电池出货50Gwh, 同比大增108%，需求与产能释放双驱动\n一季度，宁德时代储能电池出货约50GWh，同比大幅增长108%，增长势头极为强劲。这一增速与行业高景气度相符（2026年一季度中国储能电池销量同比增长112%），主要仍然由于行业对于储能的高需求，以及宁王用于缓解储能产能压力的山东济宁基地（规划超100GWh）的新增产能，在 2026年Q1开始释放。\na. 国内政策与市场共振，经济性拐点确立\n全国性容量电价机制推行：2026年初，国家出台“114号文”，首次在国家层面建立电网侧独立储能容量电价机制。该政策以煤电价格为基准，为储能项目提供稳定的容量收益，显著改善项目经济性（IRR可提升至8%-9%），彻底激活了投资需求。作为拥有长寿命、低衰减技术的绝对龙头，宁德时代直接受益于终端需求的爆发。\n产能释放支撑交付：公司用于缓解储能产能压力的山东济宁基地（规划新增产能超100GWh）在2026年开始逐步释放产能，有力支撑了出货量的高增长。\nb. AIDC数据中心成为储能新增长极\nAI数据中心（AIDC）的快速发展，从电源侧和用户侧双重维度催生了对储能的新需求：\n电源侧（提升有效容量）：为匹配风光等间歇性新能源的高比例接入，配套储能是提升其有效容量系数、保障电网稳定的关键手段。\n用户侧（负荷管理与经济性）：\n稳定AI负载：AI训练和推理负载具有剧烈、同步的波动性，配备储能可以平抑这种“毫秒级”功率脉冲，保障数据中心自身用电安全。\n经济性与加速并网：储能具备“削峰填谷”的套利经济性。同时，北美等地的电网运营商（如PJM、ERCOT）已出台政策，要求新接入的大型负荷（如数据中心）必须具备调节自身负荷、减少对电网冲击的能力。配备储能成为数据中心加速通过并网审批、实现快速上电的关键解决方案。\nb. 电池单价：价格联动凸显议价权\n单价方面，一季度宁德时代整体电池销售均价达到0.57元/Wh，环比提升4%。而宁王一季度面临“两大逆风”：\n上游成本急剧推升： 一季度碳酸锂价格从上年四季度的8-10万元/吨快速反弹至15-18万元/吨。\n产品结构带来均价下行压力： 单价相对较低的储能电池出货量占比在一季度提升了5个百分点至25%，对整体均价构成了结构性的的向下拖累。\n但在“成本向上 + 结构向下”的双重压力下，公司整体均价依然实现环比上涨。这直接印证了公司在产业链中强大的议价权：公司表示其大部分订单均已签订完善的碳酸锂等金属价格联动机制，凭借强大的议价能力，宁德时代顺利将原材料涨价压力传导至下游客户，有效对冲了成本波动，带动了销售均价的坚挺向上。\n2. 毛利率环比受挤压回落，但仍然具备极强盈利韧性\n1Q26公司毛利率为24.8%，单Wh毛利从去年四季度的0.18元/Wh下滑至约0.16元/Wh。虽然相比去年四季度产能满载时的高点（毛利率28.2%）有所回落，但整体表现与市场预期持平，展现了极其稳健的盈利韧性。\n一季度的盈利端主要面临了多重逆风的集中挤压：\n成本与结构双向承压： 碳酸锂均价快速反弹至15-18万元/吨带来成本冲击，同时相对低毛利的储能电池出货占比提升。\n淡季效应与折旧摊销： 受一季度传统淡季影响，公司产能利用率从25年下半年满产时的103%回落至85%-90%区间，导致单位折旧摊销成本略有上升。\n政策性因素扰动： 出口税收优惠退坡也对表观利润率构成了一定挤压。\n但在上述多重逆风下，公司依然能维持稳健的毛利率和净利率水平，核心得益于其超越周期的抗风险能力：\n①\n低价存货的“蓄水池”效应： 去年四季度末，公司账面存货高达945亿元（存货/营业收入比例达67%）。庞大的库存规模相当于一个缓冲垫，使得公司在一季度能够部分使用前期储备的低价原材料进行生产，有效覆盖并平滑了当季的成本上涨冲击。\n②\n上游资源的战略级对冲： 相比上一轮锂价上行周期，公司目前的上游资源布局更加完善。公司持有洛阳钼业（CMOC）约25%的股权，叠加自有江西锂矿（JXW）有望在2026年迎来重启。这些上游资产等同于一个巨大的低成本“隐形库存”，对冲外购锂价波动的能力大幅增强。\n③\n极致的规模效应与大单品策略： 尽管处于传统淡季且处在产能扩建期，公司85%-90%的产能利用率在行业内依然处于绝对高位。配合在产品端大力推行的“大单品策略”（如神行、麒麟电池的规模化量产），公司在制造环节的规模经济降本效应依然显著。\n④\n强悍的成本转嫁能力： 无论是面对原材料价格的反弹，还是出口税收优惠减少这类预期内的政策变动，公司凭借完善的金属价格联动合同安排以及极强的产业链话语权，能够将绝大部分的成本增量顺利转嫁给下游客户。\n二. 全面上行周期逻辑不改，终端需求仍强劲\n1）产能利用率稳居85%-90%高位，二季度排产持续饱满\n受一季度新能源车市传统淡季及公司自身产能持续扩建（总产能基数变大）的双重叠加影响，公司一季度的产能利用率从2025年下半年的超负荷满产状态（103%）阶段性回落至85%-90%区间。但在分母端不断扩张的背景下，这一利用率水平在全行业中依然处于绝对领先的高位，侧面印证了终端拿货的积极性。\n而根据公司的最新指引，二季度各项排产计划依然保持饱和状态，预计产能利用率将继续企稳在85%-90%的高位区间。这不仅有效打消了市场对“电动车需求增速放缓拖累总出货”的担忧，也从生产端再次验证了宁德时代依然在量价齐升的全面上行周期内。\n2）资本开支再加速，海内外产能扩张高调重启\n从资本开支的周期律来看，宁德时代正迎来新一轮的扩张拐点。虽然公司在2021-2022年经历了产能的密集投入期，随后因行业阶段性供需错配，资本开支自2022年Q1起进入下行周期（并在2023年Q1触及约67亿元的阶段性低点）。\n但自2024年Q1起，公司的资本支出已开始筑底回升。本季度，资本开支更是加速攀升至约124亿元，逼近上一轮扩产巅峰期的水平，释放出极强的扩张信号。\n伴随资本开支的加速，公司对未来的排产指引也极为积极：公司此前已将2026年的排产目标大幅上修至 1.1-1.2 TWh（对比2025年约772 GWh的基数，预计新增产能约400 GWh），产能同比增速高达42%-55%！\n目前，公司在全球范围内的产能布局正全面开花：\n国内大盘稳步扩建：\n山东济宁、广东肇庆（瑞庆时代）、江西宜春、福建厦门、青海及福建宁德等主力基地均在大幅扩产。其中，为承接井喷的储能订单，山东济宁基地（规划超100GWh）的新增产能已按计划于2026年Q1逐步释放。\n海外产能加速兑现：\n海外市场正成为下一阶段量增的核心驱动力。\n欧洲：德国工厂（14GWh）已于24年投产并实现稳定盈利；匈牙利工厂（规划100GWh）的一期项目（34GWh）电芯产线设备已进场调试，预计2025年底建成；西班牙工厂（规划60GWh）已完成前期审批并成立合资公司，即将在2026年正式启动筹建。\n东南亚布局：印尼电池产业链项目进展顺利，预计将于2026年上半年正式投产。\n而强劲的产能释放，不仅直接拉动了宁德时代2026年一季度全球市占率的强势回升，也为后续的需求的释放提供了供给端的保证。\n从投产节奏和基数效应来看，2026年海外市场产能的密集放量，将成为公司业绩高增的基石。\n3）存货还在继续高增，背后隐含旺盛订单需求\n本季度末，公司存货规模显著攀升至1089亿元，环比大幅增加约144亿元，绝对值创下历史新高。存货占收入比例由上季度的67%跃升至本季度的84%，存货周转天数也同步延长至近95天。\n不同于传统下行周期中的“被动去库存”压力，海豚君认为，宁德时代当前的存货高企更多体现了上行周期中的“主动备货”与“订单在途”：\n① 原材料战略储备：主动平滑成本波动\n为应对碳酸锂等核心原材料价格的筑底回升，公司利用强大的现金流优势，有针对性地增加了原材料及自制半成品的储备。\n这种在价格上涨通道开启前的“低价囤货”行为，构建了一个巨大的成本缓冲池，能有效对冲未来1-2个季度原材料上行对毛利率的负面挤压。\n② “发出商品”（已发货但未开票确认收入）占比提升：\n产品形态由“芯”向“系统”演进： 随着储能系统（ESS）出货占比显著提升，由于系统级产品涉及现场安装、调试及较长的交付周期，导致在财务报表上表现为较长时间的存货沉淀。\n全球供应链半径拉长： 公司海外市场正从欧洲向中东、美洲等远距离地区多点开花。远洋运输比例的增加及长距离交付周期的延长，使得大量处于交付途中的货品积压在存货端。\n而着反而隐含下游客户订单的极高景气度。随着这部分在途商品在未来几个季度逐步转化结转为收入，公司的业绩增长将获得更强的确定性。\n4） 合同负债继续维持高位\n由于宁王主要是个To B的生意，所以会出现已收下游B端客户的预付款项，但还没交付的情况，所以合同负债可以近似看出宁王在手订单量变化的一个近似指标。\n从宁王一季度合同负债虽然环比上季度高点492亿环比下滑了37亿元至455亿元，但仍然处于高位水平，随着公司各大基地产能利用率维持高位，一季度电池出货量同比大增67%，这使得前期积压的订单得以快速交付并转化为营业收入，从而在财务端体现为合同负债的正常结转回落。\n5）资产减值本季度环比回落\n本季度，公司资产减值损失约为14亿元，较上季度的计提峰值（46亿元）环比大幅锐减32亿元。从相对比重来看，资产减值占营业收入的比例环比下降约2个百分点，仅为1.1%。\n海豚君认为，减值压力的下降主要得益于前期计提充分与上游价格企稳的共振：\n历史包袱出清：公司秉持审慎的财务原则，已对存货及涉锂矿产资源等相关资产进行了极为充分的减值计提。\n跌价风险解除： 叠加一季度碳酸锂等核心原材料价格企稳反弹，新增大额存货跌价准备的风险已基本解除。\n而减值风险的出清，也进一步带来了利润端的释放。\n一季度，宁王归母净利207亿（同比增长49%）同样大幅高于市场预期176亿，扣非归母净利润164亿元，同比大增53%。\n而超预期的原因仍然在于出货量的继续高增，叠加凭借绝对议价能力实现的成本有效传导，带来的收入与毛利润的超预期。\n研发及各项期间费用得到精准、高效的管控，配合资产减值损失的环比大幅出清，带来了报表段利润的进一步释放。\n本季度公司单Wh净利维持在约0.1元/Wh，与上季度基本持平。在碳酸锂等原材料价格快速反弹的逆风环境下，这一极其坚挺的单位盈利表现，彻底击碎了此前市场关于“原材料涨价将侵蚀公司利润”的悲观预期，再次验证了公司穿越周期的强悍实力。\n而海豚君更关注的核心运营利润率趋势（毛利率-三费-资产/信用减值损失率），一季度205亿元，同比增速高达94%，核心运营利润率也达到15.9%，环比与上季度持平，也表明宁王持续稳健的经营能力。\n本文来自微信公众号\n“海豚投研”（ID：haituntouyan）\n，作者：海豚君，36氪经授权发布。', NULL, '2026-04-17 15:06:28');
INSERT INTO `news_detail` VALUES (59, 2206, 7, '消费与零售', '段永平不小心成了泡泡玛特的榜一大哥', '', '<p><strong>最近，投资界发生了一件抓马的事儿，投资大佬段永平可能因“误操作”而成为泡泡玛特第三大股东。</strong></p>\n<p>段永平本意是通过卖put（看跌期权）的方式买入泡泡玛特股票，却因不熟悉港美股的期权单位差异，一口气卖出了22.5万张泡泡玛特期权。若到期被行权，他将以近百亿港币购入4500万股，跻身第三大股东，仅次于创始人王宁与管理层。</p>\n<p><strong>这一“乌龙”反而成了泡泡玛特股价的强心剂。</strong>泡泡玛特股价在4月14日、15日连续上涨，两日累计涨幅超10%，市值增加约170亿港元。</p>\n<p>然而就在数月前，段永平还曾公开表示“看不懂泡泡玛特”，并以“电子宠物、呼啦圈、魔方”类比，质疑其生意的持续性。直到泡泡玛特2025年财报出炉，段永平的态度发生了180度大转弯。</p>\n<p>作为巴菲特的信徒，价值投资的拥趸，段永平用经典框架重新解构了这家公司，指出其壁垒远比想象中强大：品牌认知、艺术家签约、全球化门店网络、创始人团队的综合实力。</p>\n<p>一边是投资大佬的逆势认可与意外“重仓”，另一边，泡泡玛特股价却与强劲业绩显著背离。</p>\n<p>泡泡玛特的2025年财报堪称历史最佳，但财报发出后，股价仍在三个交易日内跌超30%。即便近日泡泡玛特股价略有回升，但自去年8月高点也已腰斩。</p>\n<p><strong>泡泡玛特似乎又一次站在价值重估的关键路口。</strong></p>\n<h2><strong>1</strong></h2>\n<p>“我的泡泡玛特保险公司正式开张了。”4月9日，段永平在雪球上敲下这行字的时候，应该没有想到，自己一次看似常规的投资操作，会因为一个规则疏忽，不仅影响了公司股价，还引来全网围观调侃。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_3f9ed623b3af47eea7438f682da2ccde@000000_oswg300885oswg588oswg583_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>彼时段永平应该已经开始布局泡泡玛特了。很多人好奇，开“保险公司”和买股票有什么关系？其实他口中的保险公司，指的是投资里常用的“卖出看跌期权（sell put）”策略。</p>\n<p>简单来说，这就好比他开了家保险机构，期权买方支付一笔保费（权利金），段永平则做出承诺 —— 如果未来泡泡玛特股价跌到约定行权价以下，他就按这个价格接盘买入；若股价没跌破，保费直接归他所有，不用买一股，相当于白赚权利金。</p>\n<p><strong>这是典型的“巴菲特式抄底法”。</strong>巴菲特常年靠卖put赚取权利金、等待低价接盘，可口可乐便是经典案例。段永平也如法炮制，在腾讯、苹果、英伟达、阿里等公司均使用过这一策略。</p>\n<p>而且这次出手，他直接干到了顶。4月14日，段永平在雪球上披露了操作细节，“卖put其实也是会受到限制的，我已经被限制了，只能等到期后才能卖新的了。我的卖put的上限是225000张，已经满了。”</p>\n<p>但转折来得猝不及防。4月15日，有细心的雪球网友贴出泡泡玛特港股期权合约细则，并发现了关键问题：美股1张put=100 股，但港股泡泡玛特的期权合约，1张对应200股。</p>\n<p>网友当即 @段永平，提醒他的22.5万张合约，实际对应股数直接翻倍，并非2250万股，而是4500万股。</p>\n<p>显然，段永平本身习惯了美股规则，忘记了港股和美股的差异。事后，段永平自己也在社交平台发文坦言：“确实没注意到这个，还好卖的是put，不然就麻烦了”。</p>\n<p>而这次“手滑”的后果，远比想象中更夸张。<strong>一旦泡泡玛特股价跌破 150港元，他必须掏出68亿港元，拿下4500万股，持股比例将达到3.36%以上，足以让段永平直接成为泡泡玛特第三大股东，仅次于创始人王宁与核心管理层。</strong></p>\n<p>更有意思的是，这波“乌龙操作”反而拉升了泡泡玛特的股价。</p>\n<p>原本做空泡泡玛特的机构，指望砸低股价获利，可段永平相当于在150港元处摆下近68亿港元的天量接盘，彻底堵死了砸盘空间。</p>\n<p>空头眼见砸盘无望，只能争相平仓离场，大量买入回补股票，再叠加市场对投资大佬背书的乐观情绪，双重推动泡泡玛特股价大幅上涨。</p>\n<p>4月14日，泡泡玛特股价单日收涨 6.53%，盘中涨幅一度突破 8%，市值单日暴增超 170 亿港元，次日继续上行，两日累计涨幅超10%。</p>\n<h2><strong>2</strong></h2>\n<p>虽然操作乌龙，但段永平的入局，让泡泡玛特再次站在聚光灯下。</p>\n<p>段永平第一次公开提到泡泡玛特是去年8月，彼时正是泡泡玛特的高光时刻，LABUBU火遍全球，泡泡玛特的股价来到历史高点的339港元。</p>\n<p>“泡泡玛特这家公司的产品确实很有意思，创始人也是个很有意思的人，他们能做到今天这样很了不起，但我看不懂 10 年后公司会怎样。”段永平还把潮玩类比成曾经风靡一时的电子宠物、呼啦圈，核心顾虑是潮玩需求的可持续性。</p>\n<p>之后他多次在雪球上被网友问及对泡泡玛特的看法，态度始终没有发生改变。尤其是在去年12月和王石的那场访谈里，他更是直言“看不懂，不投资，我也许已经过了能理解这个产品的年纪了。”</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_c1bc697f61e847948a55bd95d9b766c2@000000_oswg137440oswg428oswg458_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>熟悉段永平的人都知道，他是价值投资的拥趸，投资理念源自巴菲特。2006 年，段永平还曾以62.01万美元 拍下和巴菲特共进午餐的机会，成为第一位拍得该午餐的华人。</p>\n<p>“看不懂就坚决不碰”是价值投资，也是段永平坚守的铁律。</p>\n<p>转折发生在今年的3月，泡泡玛特交出了一份堪称炸裂的2025年全年财报，3天后，段永平在雪球公开表示，“这两天花时间再看了看泡泡玛特，决定收回我不投资泡泡玛特的说法。”</p>\n<p>“这期财报的盈利激发了我的好奇心，连续花了好几天去理解这家公司，很久没有这种兴奋感了。”段永平在社交平台坦言，正是这份亮眼的财报，让他重新审视泡泡玛特。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_04f02de4d4ae44638113bf20997f7193@000000_oswg157055oswg415oswg632_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>之后，他先是看完了王宁的访谈录《因为独特》，后又实地探访了一家海外泡泡玛特门店并发出感慨，“我怎么觉得泡泡玛特才是中国产品国际化的先驱呢？别的企业似乎还都没到这个水准”。</p>\n<p>那么，段永平到底看懂了什么？</p>\n<p>他在社交平台上分析，目前泡泡玛特的壁垒有用户关注度、艺术家的签约、全球各地的门店以及王宁团队。这些壁垒远比想象中强大，只要潮玩会有持续性，泡泡玛特就是非常好的生意了。</p>\n<p>到了4月，段永平彻底“改口”，不仅收回了“不投资泡泡玛特”的说法，还直言自己是“王宁的粉丝”。于是就有了“开保险公司”的一幕。</p>\n<p>显然，在段永平的分析中，泡泡玛特已经符合“好生意，对的人，好价格”这一价值投资经典框架中的前两条。</p>\n<p>至于“好价格”，显然还没到段永平的心理价位，这也是他选择卖put，而非直接买股票的原因。</p>\n<p>过去很长一段时间，泡泡玛特这个以盲盒、潮玩出圈的新消费品牌，在很多传统投资者眼里，不过是“年轻人的玩具生意”，火爆只是昙花一现，撑不起长期投资价值。</p>\n<p>但如今，价值投资圈的大佬一反常态，入场布局，等待抄底。这是否意味着泡泡玛特得到了价值投资圈的认可？或许还要交给时间来回答。</p>\n<p>但可以肯定的是，当价值投资的标杆开始认真审视这门“玩具生意”时，市场对其价值的重估，才刚刚开始。</p>\n<p>有意思的是，巴菲特也曾两次投资迪士尼，看中的就是迪士尼的IP价值。</p>\n<p>段永平已经入场“开保险公司”，那么，这位远在美国的“奥马哈先知”，会不会也注意到这家来自东方的“潮玩帝国”呢？</p>\n<p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MzI2NjU1MTcwMA==&amp;mid=2247559846&amp;idx=1&amp;sn=6fc1f6eb96cef62ceb3f29ae57064484&amp;chksm=eb6668bcc89ae9c7526d7a1a6904febceccac37a6fbc3f170153f90755c50d5b9c891ed8c798&amp;scene=0&amp;xtrack=1#rd\">“字母榜”（ID：wujicaijing）</a>，作者：张琳，36氪经授权发布。</p>', 'https://36kr.com/p/3769314712568327?f=rss', 0, '', '{\"summary\": \"本文通过段永平投资泡泡玛特的乌龙事件，展现投资界对出海潮玩品牌价值的重新审视，为出海消费品牌的价值认知提供参考\", \"abstract\": \"投资大佬段永平因不熟悉港美股期权单位差异，误操作卖出22.5万张泡泡玛特看跌期权，若行权将成为泡泡玛特第三大股东，该乌龙事件推动泡泡玛特股价两日累计涨幅超10%。此前段永平曾质疑潮玩生意的持续性，不看好泡泡玛特，在泡泡玛特发布2025年亮眼财报后，他重新审视该企业，认可其品牌、艺术家资源、全球化门店网络等核心壁垒，还评价其为中国产品国际化的先驱。此次段永平采用巴菲特式卖put策略布局泡泡玛特，标志着价值投资圈对出海潮玩品牌的态度发生重大转变，泡泡玛特目前正处于价值重估的关键路口。\", \"keywords\": [\"出海\", \"泡泡玛特\", \"段永平\", \"价值投资\", \"看跌期权\", \"国际化\", \"潮玩\", \"港股\"], \"policy_risk\": {\"market_risk\": \"泡泡玛特股价波动较大，曾在发布亮眼财报后出现大幅下跌，市场对其长期价值认知尚未统一，存在估值波动风险\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"消费与零售\"}', '', '{\"url\": \"https://36kr.com/p/3769314712568327?f=rss\", \"title\": \"段永平不小心成了泡泡玛特的榜一大哥\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p><strong>最近，投资界发生了一件抓马的事儿，投资大佬段永平可能因“误操作”而成为泡泡玛特第三大股东。</strong></p>\\n<p>段永平本意是通过卖put（看跌期权）的方式买入泡泡玛特股票，却因不熟悉港美股的期权单位差异，一口气卖出了22.5万张泡泡玛特期权。若到期被行权，他将以近百亿港币购入4500万股，跻身第三大股东，仅次于创始人王宁与管理层。</p>\\n<p><strong>这一“乌龙”反而成了泡泡玛特股价的强心剂。</strong>泡泡玛特股价在4月14日、15日连续上涨，两日累计涨幅超10%，市值增加约170亿港元。</p>\\n<p>然而就在数月前，段永平还曾公开表示“看不懂泡泡玛特”，并以“电子宠物、呼啦圈、魔方”类比，质疑其生意的持续性。直到泡泡玛特2025年财报出炉，段永平的态度发生了180度大转弯。</p>\\n<p>作为巴菲特的信徒，价值投资的拥趸，段永平用经典框架重新解构了这家公司，指出其壁垒远比想象中强大：品牌认知、艺术家签约、全球化门店网络、创始人团队的综合实力。</p>\\n<p>一边是投资大佬的逆势认可与意外“重仓”，另一边，泡泡玛特股价却与强劲业绩显著背离。</p>\\n<p>泡泡玛特的2025年财报堪称历史最佳，但财报发出后，股价仍在三个交易日内跌超30%。即便近日泡泡玛特股价略有回升，但自去年8月高点也已腰斩。</p>\\n<p><strong>泡泡玛特似乎又一次站在价值重估的关键路口。</strong></p>\\n<h2><strong>1</strong></h2>\\n<p>“我的泡泡玛特保险公司正式开张了。”4月9日，段永平在雪球上敲下这行字的时候，应该没有想到，自己一次看似常规的投资操作，会因为一个规则疏忽，不仅影响了公司股价，还引来全网围观调侃。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3f9ed623b3af47eea7438f682da2ccde@000000_oswg300885oswg588oswg583_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>彼时段永平应该已经开始布局泡泡玛特了。很多人好奇，开“保险公司”和买股票有什么关系？其实他口中的保险公司，指的是投资里常用的“卖出看跌期权（sell put）”策略。</p>\\n<p>简单来说，这就好比他开了家保险机构，期权买方支付一笔保费（权利金），段永平则做出承诺 —— 如果未来泡泡玛特股价跌到约定行权价以下，他就按这个价格接盘买入；若股价没跌破，保费直接归他所有，不用买一股，相当于白赚权利金。</p>\\n<p><strong>这是典型的“巴菲特式抄底法”。</strong>巴菲特常年靠卖put赚取权利金、等待低价接盘，可口可乐便是经典案例。段永平也如法炮制，在腾讯、苹果、英伟达、阿里等公司均使用过这一策略。</p>\\n<p>而且这次出手，他直接干到了顶。4月14日，段永平在雪球上披露了操作细节，“卖put其实也是会受到限制的，我已经被限制了，只能等到期后才能卖新的了。我的卖put的上限是225000张，已经满了。”</p>\\n<p>但转折来得猝不及防。4月15日，有细心的雪球网友贴出泡泡玛特港股期权合约细则，并发现了关键问题：美股1张put=100 股，但港股泡泡玛特的期权合约，1张对应200股。</p>\\n<p>网友当即 @段永平，提醒他的22.5万张合约，实际对应股数直接翻倍，并非2250万股，而是4500万股。</p>\\n<p>显然，段永平本身习惯了美股规则，忘记了港股和美股的差异。事后，段永平自己也在社交平台发文坦言：“确实没注意到这个，还好卖的是put，不然就麻烦了”。</p>\\n<p>而这次“手滑”的后果，远比想象中更夸张。<strong>一旦泡泡玛特股价跌破 150港元，他必须掏出68亿港元，拿下4500万股，持股比例将达到3.36%以上，足以让段永平直接成为泡泡玛特第三大股东，仅次于创始人王宁与核心管理层。</strong></p>\\n<p>更有意思的是，这波“乌龙操作”反而拉升了泡泡玛特的股价。</p>\\n<p>原本做空泡泡玛特的机构，指望砸低股价获利，可段永平相当于在150港元处摆下近68亿港元的天量接盘，彻底堵死了砸盘空间。</p>\\n<p>空头眼见砸盘无望，只能争相平仓离场，大量买入回补股票，再叠加市场对投资大佬背书的乐观情绪，双重推动泡泡玛特股价大幅上涨。</p>\\n<p>4月14日，泡泡玛特股价单日收涨 6.53%，盘中涨幅一度突破 8%，市值单日暴增超 170 亿港元，次日继续上行，两日累计涨幅超10%。</p>\\n<h2><strong>2</strong></h2>\\n<p>虽然操作乌龙，但段永平的入局，让泡泡玛特再次站在聚光灯下。</p>\\n<p>段永平第一次公开提到泡泡玛特是去年8月，彼时正是泡泡玛特的高光时刻，LABUBU火遍全球，泡泡玛特的股价来到历史高点的339港元。</p>\\n<p>“泡泡玛特这家公司的产品确实很有意思，创始人也是个很有意思的人，他们能做到今天这样很了不起，但我看不懂 10 年后公司会怎样。”段永平还把潮玩类比成曾经风靡一时的电子宠物、呼啦圈，核心顾虑是潮玩需求的可持续性。</p>\\n<p>之后他多次在雪球上被网友问及对泡泡玛特的看法，态度始终没有发生改变。尤其是在去年12月和王石的那场访谈里，他更是直言“看不懂，不投资，我也许已经过了能理解这个产品的年纪了。”</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c1bc697f61e847948a55bd95d9b766c2@000000_oswg137440oswg428oswg458_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>熟悉段永平的人都知道，他是价值投资的拥趸，投资理念源自巴菲特。2006 年，段永平还曾以62.01万美元 拍下和巴菲特共进午餐的机会，成为第一位拍得该午餐的华人。</p>\\n<p>“看不懂就坚决不碰”是价值投资，也是段永平坚守的铁律。</p>\\n<p>转折发生在今年的3月，泡泡玛特交出了一份堪称炸裂的2025年全年财报，3天后，段永平在雪球公开表示，“这两天花时间再看了看泡泡玛特，决定收回我不投资泡泡玛特的说法。”</p>\\n<p>“这期财报的盈利激发了我的好奇心，连续花了好几天去理解这家公司，很久没有这种兴奋感了。”段永平在社交平台坦言，正是这份亮眼的财报，让他重新审视泡泡玛特。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_04f02de4d4ae44638113bf20997f7193@000000_oswg157055oswg415oswg632_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>之后，他先是看完了王宁的访谈录《因为独特》，后又实地探访了一家海外泡泡玛特门店并发出感慨，“我怎么觉得泡泡玛特才是中国产品国际化的先驱呢？别的企业似乎还都没到这个水准”。</p>\\n<p>那么，段永平到底看懂了什么？</p>\\n<p>他在社交平台上分析，目前泡泡玛特的壁垒有用户关注度、艺术家的签约、全球各地的门店以及王宁团队。这些壁垒远比想象中强大，只要潮玩会有持续性，泡泡玛特就是非常好的生意了。</p>\\n<p>到了4月，段永平彻底“改口”，不仅收回了“不投资泡泡玛特”的说法，还直言自己是“王宁的粉丝”。于是就有了“开保险公司”的一幕。</p>\\n<p>显然，在段永平的分析中，泡泡玛特已经符合“好生意，对的人，好价格”这一价值投资经典框架中的前两条。</p>\\n<p>至于“好价格”，显然还没到段永平的心理价位，这也是他选择卖put，而非直接买股票的原因。</p>\\n<p>过去很长一段时间，泡泡玛特这个以盲盒、潮玩出圈的新消费品牌，在很多传统投资者眼里，不过是“年轻人的玩具生意”，火爆只是昙花一现，撑不起长期投资价值。</p>\\n<p>但如今，价值投资圈的大佬一反常态，入场布局，等待抄底。这是否意味着泡泡玛特得到了价值投资圈的认可？或许还要交给时间来回答。</p>\\n<p>但可以肯定的是，当价值投资的标杆开始认真审视这门“玩具生意”时，市场对其价值的重估，才刚刚开始。</p>\\n<p>有意思的是，巴菲特也曾两次投资迪士尼，看中的就是迪士尼的IP价值。</p>\\n<p>段永平已经入场“开保险公司”，那么，这位远在美国的“奥马哈先知”，会不会也注意到这家来自东方的“潮玩帝国”呢？</p>\\n<p>本文来自微信公众号 <a href=\\\"https://mp.weixin.qq.com/s?__biz=MzI2NjU1MTcwMA==&amp;mid=2247559846&amp;idx=1&amp;sn=6fc1f6eb96cef62ceb3f29ae57064484&amp;chksm=eb6668bcc89ae9c7526d7a1a6904febceccac37a6fbc3f170153f90755c50d5b9c891ed8c798&amp;scene=0&amp;xtrack=1#rd\\\">“字母榜”（ID：wujicaijing）</a>，作者：张琳，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\\\"title\\\": \\\"\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u4e0d\\\\u5c0f\\\\u5fc3\\\\u6210\\\\u4e86\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u7684\\\\u699c\\\\u4e00\\\\u5927\\\\u54e5\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u4e0d\\\\u5c0f\\\\u5fc3\\\\u6210\\\\u4e86\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u7684\\\\u699c\\\\u4e00\\\\u5927\\\\u54e5\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769314712568327?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769314712568327?f=rss\\\", \\\"published\\\": \\\"2026-04-16 19:11:26  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 11, 11, 26, 3, 106, 0], \\\"summary\\\": \\\"<p><strong>\\\\u6700\\\\u8fd1\\\\uff0c\\\\u6295\\\\u8d44\\\\u754c\\\\u53d1\\\\u751f\\\\u4e86\\\\u4e00\\\\u4ef6\\\\u6293\\\\u9a6c\\\\u7684\\\\u4e8b\\\\u513f\\\\uff0c\\\\u6295\\\\u8d44\\\\u5927\\\\u4f6c\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u53ef\\\\u80fd\\\\u56e0\\\\u201c\\\\u8bef\\\\u64cd\\\\u4f5c\\\\u201d\\\\u800c\\\\u6210\\\\u4e3a\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u7b2c\\\\u4e09\\\\u5927\\\\u80a1\\\\u4e1c\\\\u3002</strong></p>\\\\n  <p>\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u672c\\\\u610f\\\\u662f\\\\u901a\\\\u8fc7\\\\u5356put\\\\uff08\\\\u770b\\\\u8dcc\\\\u671f\\\\u6743\\\\uff09\\\\u7684\\\\u65b9\\\\u5f0f\\\\u4e70\\\\u5165\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u80a1\\\\u7968\\\\uff0c\\\\u5374\\\\u56e0\\\\u4e0d\\\\u719f\\\\u6089\\\\u6e2f\\\\u7f8e\\\\u80a1\\\\u7684\\\\u671f\\\\u6743\\\\u5355\\\\u4f4d\\\\u5dee\\\\u5f02\\\\uff0c\\\\u4e00\\\\u53e3\\\\u6c14\\\\u5356\\\\u51fa\\\\u4e8622.5\\\\u4e07\\\\u5f20\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u671f\\\\u6743\\\\u3002\\\\u82e5\\\\u5230\\\\u671f\\\\u88ab\\\\u884c\\\\u6743\\\\uff0c\\\\u4ed6\\\\u5c06\\\\u4ee5\\\\u8fd1\\\\u767e\\\\u4ebf\\\\u6e2f\\\\u5e01\\\\u8d2d\\\\u51654500\\\\u4e07\\\\u80a1\\\\uff0c\\\\u8dfb\\\\u8eab\\\\u7b2c\\\\u4e09\\\\u5927\\\\u80a1\\\\u4e1c\\\\uff0c\\\\u4ec5\\\\u6b21\\\\u4e8e\\\\u521b\\\\u59cb\\\\u4eba\\\\u738b\\\\u5b81\\\\u4e0e\\\\u7ba1\\\\u7406\\\\u5c42\\\\u3002</p>\\\\n  <p><strong>\\\\u8fd9\\\\u4e00\\\\u201c\\\\u4e4c\\\\u9f99\\\\u201d\\\\u53cd\\\\u800c\\\\u6210\\\\u4e86\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u80a1\\\\u4ef7\\\\u7684\\\\u5f3a\\\\u5fc3\\\\u5242\\\\u3002</strong>\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u80a1\\\\u4ef7\\\\u57284\\\\u670814\\\\u65e5\\\\u300115\\\\u65e5\\\\u8fde\\\\u7eed\\\\u4e0a\\\\u6da8\\\\uff0c\\\\u4e24\\\\u65e5\\\\u7d2f\\\\u8ba1\\\\u6da8\\\\u5e45\\\\u8d8510%\\\\uff0c\\\\u5e02\\\\u503c\\\\u589e\\\\u52a0\\\\u7ea6170\\\\u4ebf\\\\u6e2f\\\\u5143\\\\u3002</p>\\\\n  <p>\\\\u7136\\\\u800c\\\\u5c31\\\\u5728\\\\u6570\\\\u6708\\\\u524d\\\\uff0c\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u8fd8\\\\u66fe\\\\u516c\\\\u5f00\\\\u8868\\\\u793a\\\\u201c\\\\u770b\\\\u4e0d\\\\u61c2\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u201d\\\\uff0c\\\\u5e76\\\\u4ee5\\\\u201c\\\\u7535\\\\u5b50\\\\u5ba0\\\\u7269\\\\u3001\\\\u547c\\\\u5566\\\\u5708\\\\u3001\\\\u9b54\\\\u65b9\\\\u201d\\\\u7c7b\\\\u6bd4\\\\uff0c\\\\u8d28\\\\u7591\\\\u5176\\\\u751f\\\\u610f\\\\u7684\\\\u6301\\\\u7eed\\\\u6027\\\\u3002\\\\u76f4\\\\u5230\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u72792025\\\\u5e74\\\\u8d22\\\\u62a5\\\\u51fa\\\\u7089\\\\uff0c\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u7684\\\\u6001\\\\u5ea6\\\\u53d1\\\\u751f\\\\u4e86180\\\\u5ea6\\\\u5927\\\\u8f6c\\\\u5f2f\\\\u3002</p>\\\\n  <p>\\\\u4f5c\\\\u4e3a\\\\u5df4\\\\u83f2\\\\u7279\\\\u7684\\\\u4fe1\\\\u5f92\\\\uff0c\\\\u4ef7\\\\u503c\\\\u6295\\\\u8d44\\\\u7684\\\\u62e5\\\\u8db8\\\\uff0c\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u7528\\\\u7ecf\\\\u5178\\\\u6846\\\\u67b6\\\\u91cd\\\\u65b0\\\\u89e3\\\\u6784\\\\u4e86\\\\u8fd9\\\\u5bb6\\\\u516c\\\\u53f8\\\\uff0c\\\\u6307\\\\u51fa\\\\u5176\\\\u58c1\\\\u5792\\\\u8fdc\\\\u6bd4\\\\u60f3\\\\u8c61\\\\u4e2d\\\\u5f3a\\\\u5927\\\\uff1a\\\\u54c1\\\\u724c\\\\u8ba4\\\\u77e5\\\\u3001\\\\u827a\\\\u672f\\\\u5bb6\\\\u7b7e\\\\u7ea6\\\\u3001\\\\u5168\\\\u7403\\\\u5316\\\\u95e8\\\\u5e97\\\\u7f51\\\\u7edc\\\\u3001\\\\u521b\\\\u59cb\\\\u4eba\\\\u56e2\\\\u961f\\\\u7684\\\\u7efc\\\\u5408\\\\u5b9e\\\\u529b\\\\u3002</p>\\\\n  <p>\\\\u4e00\\\\u8fb9\\\\u662f\\\\u6295\\\\u8d44\\\\u5927\\\\u4f6c\\\\u7684\\\\u9006\\\\u52bf\\\\u8ba4\\\\u53ef\\\\u4e0e\\\\u610f\\\\u5916\\\\u201c\\\\u91cd\\\\u4ed3\\\\u201d\\\\uff0c\\\\u53e6\\\\u4e00\\\\u8fb9\\\\uff0c\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u80a1\\\\u4ef7\\\\u5374\\\\u4e0e\\\\u5f3a\\\\u52b2\\\\u4e1a\\\\u7ee9\\\\u663e\\\\u8457\\\\u80cc\\\\u79bb\\\\u3002</p>\\\\n  <p>\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u76842025\\\\u5e74\\\\u8d22\\\\u62a5\\\\u582a\\\\u79f0\\\\u5386\\\\u53f2\\\\u6700\\\\u4f73\\\\uff0c\\\\u4f46\\\\u8d22\\\\u62a5\\\\u53d1\\\\u51fa\\\\u540e\\\\uff0c\\\\u80a1\\\\u4ef7\\\\u4ecd\\\\u5728\\\\u4e09\\\\u4e2a\\\\u4ea4\\\\u6613\\\\u65e5\\\\u5185\\\\u8dcc\\\\u8d8530%\\\\u3002\\\\u5373\\\\u4fbf\\\\u8fd1\\\\