\u51c6\\\\u201d\\\\u3002</p>\\\\n  <p>\\\\u90a3\\\\u4e48\\\\uff0c\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u5230\\\\u5e95\\\\u770b\\\\u61c2\\\\u4e86\\\\u4ec0\\\\u4e48\\\\uff1f</p>\\\\n  <p>\\\\u4ed6\\\\u5728\\\\u793e\\\\u4ea4\\\\u5e73\\\\u53f0\\\\u4e0a\\\\u5206\\\\u6790\\\\uff0c\\\\u76ee\\\\u524d\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u7684\\\\u58c1\\\\u5792\\\\u6709\\\\u7528\\\\u6237\\\\u5173\\\\u6ce8\\\\u5ea6\\\\u3001\\\\u827a\\\\u672f\\\\u5bb6\\\\u7684\\\\u7b7e\\\\u7ea6\\\\u3001\\\\u5168\\\\u7403\\\\u5404\\\\u5730\\\\u7684\\\\u95e8\\\\u5e97\\\\u4ee5\\\\u53ca\\\\u738b\\\\u5b81\\\\u56e2\\\\u961f\\\\u3002\\\\u8fd9\\\\u4e9b\\\\u58c1\\\\u5792\\\\u8fdc\\\\u6bd4\\\\u60f3\\\\u8c61\\\\u4e2d\\\\u5f3a\\\\u5927\\\\uff0c\\\\u53ea\\\\u8981\\\\u6f6e\\\\u73a9\\\\u4f1a\\\\u6709\\\\u6301\\\\u7eed\\\\u6027\\\\uff0c\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u5c31\\\\u662f\\\\u975e\\\\u5e38\\\\u597d\\\\u7684\\\\u751f\\\\u610f\\\\u4e86\\\\u3002</p>\\\\n  <p>\\\\u5230\\\\u4e864\\\\u6708\\\\uff0c\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u5f7b\\\\u5e95\\\\u201c\\\\u6539\\\\u53e3\\\\u201d\\\\uff0c\\\\u4e0d\\\\u4ec5\\\\u6536\\\\u56de\\\\u4e86\\\\u201c\\\\u4e0d\\\\u6295\\\\u8d44\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u201d\\\\u7684\\\\u8bf4\\\\u6cd5\\\\uff0c\\\\u8fd8\\\\u76f4\\\\u8a00\\\\u81ea\\\\u5df1\\\\u662f\\\\u201c\\\\u738b\\\\u5b81\\\\u7684\\\\u7c89\\\\u4e1d\\\\u201d\\\\u3002\\\\u4e8e\\\\u662f\\\\u5c31\\\\u6709\\\\u4e86\\\\u201c\\\\u5f00\\\\u4fdd\\\\u9669\\\\u516c\\\\u53f8\\\\u201d\\\\u7684\\\\u4e00\\\\u5e55\\\\u3002</p>\\\\n  <p>\\\\u663e\\\\u7136\\\\uff0c\\\\u5728\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u7684\\\\u5206\\\\u6790\\\\u4e2d\\\\uff0c\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u5df2\\\\u7ecf\\\\u7b26\\\\u5408\\\\u201c\\\\u597d\\\\u751f\\\\u610f\\\\uff0c\\\\u5bf9\\\\u7684\\\\u4eba\\\\uff0c\\\\u597d\\\\u4ef7\\\\u683c\\\\u201d\\\\u8fd9\\\\u4e00\\\\u4ef7\\\\u503c\\\\u6295\\\\u8d44\\\\u7ecf\\\\u5178\\\\u6846\\\\u67b6\\\\u4e2d\\\\u7684\\\\u524d\\\\u4e24\\\\u6761\\\\u3002</p>\\\\n  <p>\\\\u81f3\\\\u4e8e\\\\u201c\\\\u597d\\\\u4ef7\\\\u683c\\\\u201d\\\\uff0c\\\\u663e\\\\u7136\\\\u8fd8\\\\u6ca1\\\\u5230\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u7684\\\\u5fc3\\\\u7406\\\\u4ef7\\\\u4f4d\\\\uff0c\\\\u8fd9\\\\u4e5f\\\\u662f\\\\u4ed6\\\\u9009\\\\u62e9\\\\u5356put\\\\uff0c\\\\u800c\\\\u975e\\\\u76f4\\\\u63a5\\\\u4e70\\\\u80a1\\\\u7968\\\\u7684\\\\u539f\\\\u56e0\\\\u3002</p>\\\\n  <p>\\\\u8fc7\\\\u53bb\\\\u5f88\\\\u957f\\\\u4e00\\\\u6bb5\\\\u65f6\\\\u95f4\\\\uff0c\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u8fd9\\\\u4e2a\\\\u4ee5\\\\u76f2\\\\u76d2\\\\u3001\\\\u6f6e\\\\u73a9\\\\u51fa\\\\u5708\\\\u7684\\\\u65b0\\\\u6d88\\\\u8d39\\\\u54c1\\\\u724c\\\\uff0c\\\\u5728\\\\u5f88\\\\u591a\\\\u4f20\\\\u7edf\\\\u6295\\\\u8d44\\\\u8005\\\\u773c\\\\u91cc\\\\uff0c\\\\u4e0d\\\\u8fc7\\\\u662f\\\\u201c\\\\u5e74\\\\u8f7b\\\\u4eba\\\\u7684\\\\u73a9\\\\u5177\\\\u751f\\\\u610f\\\\u201d\\\\uff0c\\\\u706b\\\\u7206\\\\u53ea\\\\u662f\\\\u6619\\\\u82b1\\\\u4e00\\\\u73b0\\\\uff0c\\\\u6491\\\\u4e0d\\\\u8d77\\\\u957f\\\\u671f\\\\u6295\\\\u8d44\\\\u4ef7\\\\u503c\\\\u3002</p>\\\\n  <p>\\\\u4f46\\\\u5982\\\\u4eca\\\\uff0c\\\\u4ef7\\\\u503c\\\\u6295\\\\u8d44\\\\u5708\\\\u7684\\\\u5927\\\\u4f6c\\\\u4e00\\\\u53cd\\\\u5e38\\\\u6001\\\\uff0c\\\\u5165\\\\u573a\\\\u5e03\\\\u5c40\\\\uff0c\\\\u7b49\\\\u5f85\\\\u6284\\\\u5e95\\\\u3002\\\\u8fd9\\\\u662f\\\\u5426\\\\u610f\\\\u5473\\\\u7740\\\\u6ce1\\\\u6ce1\\\\u739b\\\\u7279\\\\u5f97\\\\u5230\\\\u4e86\\\\u4ef7\\\\u503c\\\\u6295\\\\u8d44\\\\u5708\\\\u7684\\\\u8ba4\\\\u53ef\\\\uff1f\\\\u6216\\\\u8bb8\\\\u8fd8\\\\u8981\\\\u4ea4\\\\u7ed9\\\\u65f6\\\\u95f4\\\\u6765\\\\u56de\\\\u7b54\\\\u3002</p>\\\\n  <p>\\\\u4f46\\\\u53ef\\\\u4ee5\\\\u80af\\\\u5b9a\\\\u7684\\\\u662f\\\\uff0c\\\\u5f53\\\\u4ef7\\\\u503c\\\\u6295\\\\u8d44\\\\u7684\\\\u6807\\\\u6746\\\\u5f00\\\\u59cb\\\\u8ba4\\\\u771f\\\\u5ba1\\\\u89c6\\\\u8fd9\\\\u95e8\\\\u201c\\\\u73a9\\\\u5177\\\\u751f\\\\u610f\\\\u201d\\\\u65f6\\\\uff0c\\\\u5e02\\\\u573a\\\\u5bf9\\\\u5176\\\\u4ef7\\\\u503c\\\\u7684\\\\u91cd\\\\u4f30\\\\uff0c\\\\u624d\\\\u521a\\\\u521a\\\\u5f00\\\\u59cb\\\\u3002</p>\\\\n  <p>\\\\u6709\\\\u610f\\\\u601d\\\\u7684\\\\u662f\\\\uff0c\\\\u5df4\\\\u83f2\\\\u7279\\\\u4e5f\\\\u66fe\\\\u4e24\\\\u6b21\\\\u6295\\\\u8d44\\\\u8fea\\\\u58eb\\\\u5c3c\\\\uff0c\\\\u770b\\\\u4e2d\\\\u7684\\\\u5c31\\\\u662f\\\\u8fea\\\\u58eb\\\\u5c3c\\\\u7684IP\\\\u4ef7\\\\u503c\\\\u3002</p>\\\\n  <p>\\\\u6bb5\\\\u6c38\\\\u5e73\\\\u5df2\\\\u7ecf\\\\u5165\\\\u573a\\\\u201c\\\\u5f00\\\\u4fdd\\\\u9669\\\\u516c\\\\u53f8\\\\u201d\\\\uff0c\\\\u90a3\\\\u4e48\\\\uff0c\\\\u8fd9\\\\u4f4d\\\\u8fdc\\\\u5728\\\\u7f8e\\\\u56fd\\\\u7684\\\\u201c\\\\u5965\\\\u9a6c\\\\u54c8\\\\u5148\\\\u77e5\\\\u201d\\\\uff0c\\\\u4f1a\\\\u4e0d\\\\u4f1a\\\\u4e5f\\\\u6ce8\\\\u610f\\\\u5230\\\\u8fd9\\\\u5bb6\\\\u6765\\\\u81ea\\\\u4e1c\\\\u65b9\\\\u7684\\\\u201c\\\\u6f6e\\\\u73a9\\\\u5e1d\\\\u56fd\\\\u201d\\\\u5462\\\\uff1f</p>\\\\n  <p>\\\\u672c\\\\u6587\\\\u6765\\\\u81ea\\\\u5fae\\\\u4fe1\\\\u516c\\\\u4f17\\\\u53f7 <a href=\\\\\\\"https://mp.weixin.qq.com/s?__biz=MzI2NjU1MTcwMA==&amp;mid=2247559846&amp;idx=1&amp;sn=6fc1f6eb96cef62ceb3f29ae57064484&amp;chksm=eb6668bcc89ae9c7526d7a1a6904febceccac37a6fbc3f170153f90755c50d5b9c891ed8c798&amp;scene=0&amp;xtrack=1#rd\\\\\\\" rel=\\\\\\\"noopener noreferrer\\\\\\\" target=\\\\\\\"_blank\\\\\\\">\\\\u201c\\\\u5b57\\\\u6bcd\\\\u699c\\\\u201d\\\\uff08ID\\\\uff1awujicaijing\\\\uff09</a>\\\\uff0c\\\\u4f5c\\\\u8005\\\\uff1a\\\\u5f20\\\\u7433\\\\uff0c36\\\\u6c2a\\\\u7ecf\\\\u6388\\\\u6743\\\\u53d1\\\\u5e03\\\\u3002</p>\\\"}, \\\"source\\\": {\\\"title\\\": \\\"36\\\\u6c2a\\\"}, \\\"authors\\\": [{\\\"name\\\": \\\"\\\\u5b57\\\\u6bcd\\\\u699c\\\"}], \\\"author\\\": \\\"\\\\u5b57\\\\u6bcd\\\\u699c\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"\\\\u5b57\\\\u6bcd\\\\u699c\\\"}, \\\"content\\\": [{\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u5927\\\\u4f6c\\\\u201c\\\\u624b\\\\u6ed1\\\\u201d\\\\u5e26\\\\u98de\\\\u80a1\\\\u4ef7\\\"}]}\", \"published_at\": \"2026-04-16 19:11:26\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:06:33');
INSERT INTO `news_detail` VALUES (60, 2207, 8, '新能源与汽车', '宁王飘了，日赚2.3亿，回应比亚迪“闪充”：跟我学的，构不成挑战', '', '<p>每天净赚超2个小目标，“宁王”业绩又爆了。</p>\n<p>剔除一次性收益后，公司主业的<strong>利润增速甚至超过了营收增速</strong>。</p>\n<p>要知道，宁德时代2025年全年净利润722亿，而到2026年仅仅一个季度就干了近207亿——这还是在原材料价格上涨的背景下实现的。</p>\n<p>“宁王”的赚钱能力，在汽车上下游确实是独一份。</p>\n<p>财报发布后，宁德时代今日股价一度涨超6%，市值一度超过2.09万亿，跻身<strong>A股市值前三</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_25cf828ea6bf481b915509984abe98fd@46958_oswg210282oswg1080oswg629_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>但奇怪的是，明明公司账上躺着超3200亿现金，宁德时代依然选择了大规模融资，筹资现金流暴涨了<strong>11倍</strong>。</p>\n<p>这是……憋了大招？</p>\n<h2><strong>日赚2.3亿，“宁王”一季度赚爆</strong></h2>\n<p>今年一季度，宁德时代营业收入为<strong>1291.31亿元</strong>，同比增长52.45%，已经连续三个季度营收破千亿。</p>\n<p>据财报电话会透露，这其中约1/3收入来自海外。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_9aaeb804c045403eaf063e3019331b8f@46958_oswg82394oswg1076oswg455_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>利润层面的表现更突出。宁德时代Q1的<strong>归母净利润</strong>为207.38亿元，同比增长48.52%，和营收同步实现了高增长。</p>\n<p>大致计算一下，<strong>平均每天净赚2.3亿元，每分钟能赚16万元</strong>。</p>\n<p>什么水平呢？拿国内车圈最赚钱的车企<strong>比亚迪</strong>来参考，宁德时代可能不到5个月就能赚够比亚迪去年全年的利润（326亿元）。</p>\n<p>并且，今年一季度宁德时代的扣非净利润为180.93亿元，同比增了52.95%。</p>\n<p>这项数据剔除了一次性收益，反映的是公司主营业务的真实盈利能力增长，其增速甚至比营收增速更高。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_646fa7d3322f4c0989ba000aa73ee1fe@46958_oswg105771oswg945oswg454_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>在成本和费用层面，宁德时代Q1的营业成本为970.86亿元，同比增长51.63%，增速与营收基本同步。</p>\n<p>因此，公司的毛利水平也没有出现大的波动，这一季度的毛利为320.4亿元，同比增长55%。</p>\n<p>同期综合毛利率为24.8%，同比上涨0.4个百分点，而环比较去年四季度下降3.4个百分点，主要原因是受到季节性因素影响，以及储能出货占比提升导致产品结构变化的影响。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_08bee08ba35e43b48644dd6b339fd34a@46958_oswg156412oswg1080oswg464_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>今年碳酸锂及大宗商品持续涨价，给宁德时代带来了一定的成本压力，不过从毛利率同比实现了增长来看，目前影响并不算大。</p>\n<p>宁德时代在电话会中透露，公司计划供应链布局优化，通过规模经济、产品设计来对冲成本影响；同时，公司还会实施价格联动机制，把材料波动部分传导到终端价格上。</p>\n<p>公司预计，全年的毛利率水平依然能保持平稳。</p>\n<p>另外，宁德时代在财报发布同日还发布了一条公告，计划投资300亿设立<strong>全资子公司</strong>——时代资源集团(厦门)有限公司(暂定名)。</p>\n<p>据公告介绍，这家子公司的定位是<strong>新能源矿产领域的专业投资运营与管理平台</strong>。</p>\n<p>宁德时代的目的是希望进一步向<strong>上游关键原材料领域</strong>延伸，整合现有矿业资产，以保障供应链安全与稳定，构建产业链一体化的竞争优势。</p>\n<p>而在费用方面，宁德时代Q1的<strong>研发费用</strong>为<strong>53.14亿元</strong>，同比增长10.38%，从绝对值来看，依然保持高额投入。</p>\n<p>不过，由于规模效应摊薄了研发强度，研发费用的增速还是远低于营收。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1135ccf857df478b80ae05958150adef@46958_oswg56894oswg840oswg458_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>同时，公司这一季度的财务支出为6.23亿元，而去年同期为-22.88亿元（也就是收益），支出同比猛增102.72%。</p>\n<p>据财报解释，财务费用变动主要来自外币货币性项目，因受<strong>汇率变动</strong>影响产生了<strong>汇兑损失</strong>。</p>\n<p>这里其实隐含了一层挑战，“宁王”的海外业务扩大后，还需要面临一定的汇率风险。</p>\n<p>但从整体上，公司的财务状况仍保持稳健。</p>\n<p>截至一季度末，宁德时代的总资产达到10463.29亿元，首次突破万亿大关，较上年度末增长7.33%。</p>\n<p>期末的现金及现金等价物余额为3243.54亿元，资金相当充裕。</p>\n<p>公司这一季度的<strong>经营活动现金流净额</strong>为336.81亿元，同比增长2.47%；<strong>筹资活动现金流净额</strong>，这一季度为87.62亿元，同比暴增了<strong>1149.24%</strong>，财报说明是由于“本期发行债券收到现金增加”。</p>\n<p>在资金如此充裕的情况下，公司依然选择大规模发行债券融资，不免让人感到疑惑。</p>\n<p>其实，从公司的投资动向，就能感知到宁德时代的战略意图。公司Q1<strong>投资活动现金流净额</strong>为-146.24亿元，主要用于购建固定资产、无形资产等和对外投资。</p>\n<p>这个购建固定资产，代表的是公司为了扩产而提前储备的“弹药”。</p>\n<p>这个新能源产业链上的龙头，似乎正在憋大招。</p>\n<h2><strong>钱从哪来？花到哪去？</strong></h2>\n<p>宁德时代业绩全线上涨，主要来自主营业务的增长。</p>\n<p>今年一季度，公司动力与储能电池销售合计超过<strong>200GWh</strong>，总体销量增长超60%。其中，动力电池的销量约占3/4，储能电池占比提升到占1/4。</p>\n<p>据SNE数据，今年1~2月，宁德时代全球动力电池使用量的市占率为<strong>40.5%</strong>，同比提升了1.8个百分点，龙头地位进一步巩固。</p>\n<p>也就是说，全球市场每卖出10块动力电池，就有4块来自宁德时代。</p>\n<p>其国内动力电池装机量市占率也提升到了47.7%，同比增加了3.4个百分点。</p>\n<p>宁德时代透露，一季度国内外市场旺盛需求，公司订单排产已经饱和，<strong>Q1产能利用率已经高达80%~90%</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_dbc475f38db34c63831f91675223340d@46958_oswg342147oswg960oswg701_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>因此，公司<strong>扩产</strong>已经迫在眉睫。</p>\n<p>实际上，早在2024年下半年开始，宁德时代就在逐步恢复扩产，而2025年~2026年正处于扩张周期当中。</p>\n<p>这种提前布局，来自宁德时代对于市场趋势的预判。</p>\n<p>公司认为，在<strong>动力电池</strong>方面，汽车电动化趋势愈发显著。</p>\n<p>乘用车电动化渗透率已破50%，单车带电量也在攀升，双重因素带动了电池需求快速增长。</p>\n<p>而重卡等商用车的渗透率同样在快速提升，国内重卡2025年的出货量已实现同比翻倍。</p>\n<p>而在<strong>储能领域</strong>，国内政策支持加强，储能的市场定位和容量电价机制愈发清晰，已成为具备稳定收益的资产，带来国内需求爆发。</p>\n<p>另外，宁德时代在海外市场也看到了增长空间。</p>\n<p>这些因素多重叠加，让宁德时代预判到了明确的增量需求，所以提前推进扩产，抢占市场先机——</p>\n<p>公司预计到<strong>2030年</strong>，全球动力和储能电池市场有望达到<strong>4TWh</strong>以上。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_feaf39b0b78747b3a0093021e7358cc2@46958_oswg1262817oswg1080oswg648_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>而海外市场这一新曲线上，很多车企的出口版车型都使用宁德时代的电池，而宁德时代自身也在提速。</p>\n<p>其匈牙利工厂已在Q1量产落地，欧洲本地化产能正式形成闭环。</p>\n<p>宁德时代透露，当前匈牙利工厂的成本虽较国内稍高，但相比德国工厂有明显优势，目前正在产能爬坡阶段，公司后续会通过设备选型优化、简化电芯品类等方式提高生产效率，降低成本。</p>\n<p>所以整体而言，尽管可能存在一些外界因素会对公司造成短期影响，但“宁王”仍能通过能力和体系进行调整，长期来看指引积极。</p>\n<p>也不免有人问到了那个大家都好奇的问题：</p>\n<p>对于<strong>比亚迪发布的第二代刀片电池和闪充技术</strong>，宁德时代怎么看？</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_d2b4714be14942ca9fa248a2ae5678ee@46958_oswg221815oswg995oswg496_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>而“宁王”回应称，关于超充，对于公司而言不是新的挑战。</p>\n<blockquote>\n<p>宁德时代几年前就推出了“神行”超充电池，很高兴看到比亚迪能够「跟进」这条技术路线。</p>\n</blockquote>\n<p>高管坦言，过去宁德时代已在这方面与主机厂达成合作，效果不错，但客观而言普及度并不够，因此没有全面落地。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_4e5d0527e66a4380b77ae123b064d2f0@46958_oswg331442oswg1080oswg583_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>宁德时代还表示，比亚迪此次技术发布，吸引了行业内的更多关注度，也会带动更多主机厂寻求合作，这对宁德时代而言也是利好的。</p>\n<p>因此，可以说比亚迪推动了业内玩家在快充、超充体系上加快布局。</p>\n<p>至于宁德时代的布局，很快也会在国内面世——</p>\n<p>4月21日，宁德时代会在其<strong>超级科技日活动</strong>上，发布全新的产品和生态， 据称每一项都直击行业最关注的<strong>能量密度、快充、低温性能、安全</strong>等核心痛点。</p>\n<p>高管强调，这将是宁德时代成立以来，<strong>“技术密度最高的一次发布会”</strong>。</p>\n<p>外界猜测可能包括<strong>固态电池</strong>，也可能包括<strong>第三代神行超充电池</strong>。</p>\n<p>只能说，现在的宁德时代，闪充和换电双线下注，和比亚迪对“电动化”底层标准的话语权争夺，怕是要更激烈了。</p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/sN9ARbQFNhJSzwGttQL4kQ\">“智能车参考”</a>，作者：杰西卡 ，36氪经授权发布。</p>', 'https://36kr.com/p/3769300040286980?f=rss', 0, '', '{\"summary\": \"帮助新能源出海企业了解宁德时代最新业绩与全球化布局，参考龙头企业的出海扩张逻辑\", \"abstract\": \"本文披露宁德时代2026年一季度财报核心数据，其归母净利润达207.38亿元，日均净赚2.3亿元，营收与利润实现双高增长，约三分之一收入来自海外。宁德时代预判全球动力与储能电池需求将大幅增长，正推进产能扩张，已完成匈牙利工厂量产落地，形成欧洲本地化产能闭环。宁德时代新设矿产子公司向上游延伸，保障供应链稳定，同时因海外业务扩张产生汇率汇兑损失，仍通过大规模融资支撑扩产计划。宁德时代回应比亚迪闪充技术称不构成挑战，将于近期发布新一代核心技术产品，巩固全球龙头地位。\", \"keywords\": [\"宁德时代\", \"动力电池\", \"储能电池\", \"海外布局\", \"本地化产能\", \"汇兑损失\", \"新能源出海\", \"产能扩张\"], \"policy_risk\": {\"market_risk\": \"碳酸锂等原材料价格上涨带来成本压力；海外业务扩张受汇率变动影响产生汇兑损失；动力电池行业技术竞争加剧\", \"policy_compliance\": \"未提及出海相关政策变化与新增合规要求，仅提到国内储能领域政策支持力度加强，市场机制愈发清晰\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3769300040286980?f=rss\", \"title\": \"宁王飘了，日赚2.3亿，回应比亚迪“闪充”：跟我学的，构不成挑战\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>每天净赚超2个小目标，“宁王”业绩又爆了。</p>\\n<p>剔除一次性收益后，公司主业的<strong>利润增速甚至超过了营收增速</strong>。</p>\\n<p>要知道，宁德时代2025年全年净利润722亿，而到2026年仅仅一个季度就干了近207亿——这还是在原材料价格上涨的背景下实现的。</p>\\n<p>“宁王”的赚钱能力，在汽车上下游确实是独一份。</p>\\n<p>财报发布后，宁德时代今日股价一度涨超6%，市值一度超过2.09万亿，跻身<strong>A股市值前三</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_25cf828ea6bf481b915509984abe98fd@46958_oswg210282oswg1080oswg629_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>但奇怪的是，明明公司账上躺着超3200亿现金，宁德时代依然选择了大规模融资，筹资现金流暴涨了<strong>11倍</strong>。</p>\\n<p>这是……憋了大招？</p>\\n<h2><strong>日赚2.3亿，“宁王”一季度赚爆</strong></h2>\\n<p>今年一季度，宁德时代营业收入为<strong>1291.31亿元</strong>，同比增长52.45%，已经连续三个季度营收破千亿。</p>\\n<p>据财报电话会透露，这其中约1/3收入来自海外。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_9aaeb804c045403eaf063e3019331b8f@46958_oswg82394oswg1076oswg455_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>利润层面的表现更突出。宁德时代Q1的<strong>归母净利润</strong>为207.38亿元，同比增长48.52%，和营收同步实现了高增长。</p>\\n<p>大致计算一下，<strong>平均每天净赚2.3亿元，每分钟能赚16万元</strong>。</p>\\n<p>什么水平呢？拿国内车圈最赚钱的车企<strong>比亚迪</strong>来参考，宁德时代可能不到5个月就能赚够比亚迪去年全年的利润（326亿元）。</p>\\n<p>并且，今年一季度宁德时代的扣非净利润为180.93亿元，同比增了52.95%。</p>\\n<p>这项数据剔除了一次性收益，反映的是公司主营业务的真实盈利能力增长，其增速甚至比营收增速更高。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_646fa7d3322f4c0989ba000aa73ee1fe@46958_oswg105771oswg945oswg454_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>在成本和费用层面，宁德时代Q1的营业成本为970.86亿元，同比增长51.63%，增速与营收基本同步。</p>\\n<p>因此，公司的毛利水平也没有出现大的波动，这一季度的毛利为320.4亿元，同比增长55%。</p>\\n<p>同期综合毛利率为24.8%，同比上涨0.4个百分点，而环比较去年四季度下降3.4个百分点，主要原因是受到季节性因素影响，以及储能出货占比提升导致产品结构变化的影响。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_08bee08ba35e43b48644dd6b339fd34a@46958_oswg156412oswg1080oswg464_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>今年碳酸锂及大宗商品持续涨价，给宁德时代带来了一定的成本压力，不过从毛利率同比实现了增长来看，目前影响并不算大。</p>\\n<p>宁德时代在电话会中透露，公司计划供应链布局优化，通过规模经济、产品设计来对冲成本影响；同时，公司还会实施价格联动机制，把材料波动部分传导到终端价格上。</p>\\n<p>公司预计，全年的毛利率水平依然能保持平稳。</p>\\n<p>另外，宁德时代在财报发布同日还发布了一条公告，计划投资300亿设立<strong>全资子公司</strong>——时代资源集团(厦门)有限公司(暂定名)。</p>\\n<p>据公告介绍，这家子公司的定位是<strong>新能源矿产领域的专业投资运营与管理平台</strong>。</p>\\n<p>宁德时代的目的是希望进一步向<strong>上游关键原材料领域</strong>延伸，整合现有矿业资产，以保障供应链安全与稳定，构建产业链一体化的竞争优势。</p>\\n<p>而在费用方面，宁德时代Q1的<strong>研发费用</strong>为<strong>53.14亿元</strong>，同比增长10.38%，从绝对值来看，依然保持高额投入。</p>\\n<p>不过，由于规模效应摊薄了研发强度，研发费用的增速还是远低于营收。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1135ccf857df478b80ae05958150adef@46958_oswg56894oswg840oswg458_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>同时，公司这一季度的财务支出为6.23亿元，而去年同期为-22.88亿元（也就是收益），支出同比猛增102.72%。</p>\\n<p>据财报解释，财务费用变动主要来自外币货币性项目，因受<strong>汇率变动</strong>影响产生了<strong>汇兑损失</strong>。</p>\\n<p>这里其实隐含了一层挑战，“宁王”的海外业务扩大后，还需要面临一定的汇率风险。</p>\\n<p>但从整体上，公司的财务状况仍保持稳健。</p>\\n<p>截至一季度末，宁德时代的总资产达到10463.29亿元，首次突破万亿大关，较上年度末增长7.33%。</p>\\n<p>期末的现金及现金等价物余额为3243.54亿元，资金相当充裕。</p>\\n<p>公司这一季度的<strong>经营活动现金流净额</strong>为336.81亿元，同比增长2.47%；<strong>筹资活动现金流净额</strong>，这一季度为87.62亿元，同比暴增了<strong>1149.24%</strong>，财报说明是由于“本期发行债券收到现金增加”。</p>\\n<p>在资金如此充裕的情况下，公司依然选择大规模发行债券融资，不免让人感到疑惑。</p>\\n<p>其实，从公司的投资动向，就能感知到宁德时代的战略意图。公司Q1<strong>投资活动现金流净额</strong>为-146.24亿元，主要用于购建固定资产、无形资产等和对外投资。</p>\\n<p>这个购建固定资产，代表的是公司为了扩产而提前储备的“弹药”。</p>\\n<p>这个新能源产业链上的龙头，似乎正在憋大招。</p>\\n<h2><strong>钱从哪来？花到哪去？</strong></h2>\\n<p>宁德时代业绩全线上涨，主要来自主营业务的增长。</p>\\n<p>今年一季度，公司动力与储能电池销售合计超过<strong>200GWh</strong>，总体销量增长超60%。其中，动力电池的销量约占3/4，储能电池占比提升到占1/4。</p>\\n<p>据SNE数据，今年1~2月，宁德时代全球动力电池使用量的市占率为<strong>40.5%</strong>，同比提升了1.8个百分点，龙头地位进一步巩固。</p>\\n<p>也就是说，全球市场每卖出10块动力电池，就有4块来自宁德时代。</p>\\n<p>其国内动力电池装机量市占率也提升到了47.7%，同比增加了3.4个百分点。</p>\\n<p>宁德时代透露，一季度国内外市场旺盛需求，公司订单排产已经饱和，<strong>Q1产能利用率已经高达80%~90%</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_dbc475f38db34c63831f91675223340d@46958_oswg342147oswg960oswg701_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>因此，公司<strong>扩产</strong>已经迫在眉睫。</p>\\n<p>实际上，早在2024年下半年开始，宁德时代就在逐步恢复扩产，而2025年~2026年正处于扩张周期当中。</p>\\n<p>这种提前布局，来自宁德时代对于市场趋势的预判。</p>\\n<p>公司认为，在<strong>动力电池</strong>方面，汽车电动化趋势愈发显著。</p>\\n<p>乘用车电动化渗透率已破50%，单车带电量也在攀升，双重因素带动了电池需求快速增长。</p>\\n<p>而重卡等商用车的渗透率同样在快速提升，国内重卡2025年的出货量已实现同比翻倍。</p>\\n<p>而在<strong>储能领域</strong>，国内政策支持加强，储能的市场定位和容量电价机制愈发清晰，已成为具备稳定收益的资产，带来国内需求爆发。</p>\\n<p>另外，宁德时代在海外市场也看到了增长空间。</p>\\n<p>这些因素多重叠加，让宁德时代预判到了明确的增量需求，所以提前推进扩产，抢占市场先机——</p>\\n<p>公司预计到<strong>2030年</strong>，全球动力和储能电池市场有望达到<strong>4TWh</strong>以上。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_feaf39b0b78747b3a0093021e7358cc2@46958_oswg1262817oswg1080oswg648_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>而海外市场这一新曲线上，很多车企的出口版车型都使用宁德时代的电池，而宁德时代自身也在提速。</p>\\n<p>其匈牙利工厂已在Q1量产落地，欧洲本地化产能正式形成闭环。</p>\\n<p>宁德时代透露，当前匈牙利工厂的成本虽较国内稍高，但相比德国工厂有明显优势，目前正在产能爬坡阶段，公司后续会通过设备选型优化、简化电芯品类等方式提高生产效率，降低成本。</p>\\n<p>所以整体而言，尽管可能存在一些外界因素会对公司造成短期影响，但“宁王”仍能通过能力和体系进行调整，长期来看指引积极。</p>\\n<p>也不免有人问到了那个大家都好奇的问题：</p>\\n<p>对于<strong>比亚迪发布的第二代刀片电池和闪充技术</strong>，宁德时代怎么看？</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_d2b4714be14942ca9fa248a2ae5678ee@46958_oswg221815oswg995oswg496_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>而“宁王”回应称，关于超充，对于公司而言不是新的挑战。</p>\\n<blockquote>\\n<p>宁德时代几年前就推出了“神行”超充电池，很高兴看到比亚迪能够「跟进」这条技术路线。</p>\\n</blockquote>\\n<p>高管坦言，过去宁德时代已在这方面与主机厂达成合作，效果不错，但客观而言普及度并不够，因此没有全面落地。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4e5d0527e66a4380b77ae123b064d2f0@46958_oswg331442oswg1080oswg583_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>宁德时代还表示，比亚迪此次技术发布，吸引了行业内的更多关注度，也会带动更多主机厂寻求合作，这对宁德时代而言也是利好的。</p>\\n<p>因此，可以说比亚迪推动了业内玩家在快充、超充体系上加快布局。</p>\\n<p>至于宁德时代的布局，很快也会在国内面世——</p>\\n<p>4月21日，宁德时代会在其<strong>超级科技日活动</strong>上，发布全新的产品和生态， 据称每一项都直击行业最关注的<strong>能量密度、快充、低温性能、安全</strong>等核心痛点。</p>\\n<p>高管强调，这将是宁德时代成立以来，<strong>“技术密度最高的一次发布会”</strong>。</p>\\n<p>外界猜测可能包括<strong>固态电池</strong>，也可能包括<strong>第三代神行超充电池</strong>。</p>\\n<p>只能说，现在的宁德时代，闪充和换电双线下注，和比亚迪对“电动化”底层标准的话语权争夺，怕是要更激烈了。</p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/sN9ARbQFNhJSzwGttQL4kQ\\\">“智能车参考”</a>，作者：杰西卡 ，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\\\"title\\\": \\\"\\\\u5b81\\\\u738b\\\\u98d8\\\\u4e86\\\\uff0c\\\\u65e5\\\\u8d5a2.3\\\\u4ebf\\\\uff0c\\\\u56de\\\\u5e94\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u201c\\\\u95ea\\\\u5145\\\\u201d\\\\uff1a\\\\u8ddf\\\\u6211\\\\u5b66\\\\u7684\\\\uff0c\\\\u6784\\\\u4e0d\\\\u6210\\\\u6311\\\\u6218\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u5b81\\\\u738b\\\\u98d8\\\\u4e86\\\\uff0c\\\\u65e5\\\\u8d5a2.3\\\\u4ebf\\\\uff0c\\\\u56de\\\\u5e94\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u201c\\\\u95ea\\\\u5145\\\\u201d\\\\uff1a\\\\u8ddf\\\\u6211\\\\u5b66\\\\u7684\\\\uff0c\\\\u6784\\\\u4e0d\\\\u6210\\\\u6311\\\\u6218\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769300040286980?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769300040286980?f=rss\\\", \\\"published\\\": \\\"2026-04-16 18:42:24  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 10, 42, 24, 3, 106, 0], \\\"summary\\\": \\\"<p>\\\\u6bcf\\\\u5929\\\\u51c0\\\\u8d5a\\\\u8d852\\\\u4e2a\\\\u5c0f\\\\u76ee\\\\u6807\\\\uff0c\\\\u201c\\\\u5b81\\\\u738b\\\\u201d\\\\u4e1a\\\\u7ee9\\\\u53c8\\\\u7206\\\\u4e86\\\\u3002</p>\\\\n  <p>\\\\u5254\\\\u9664\\\\u4e00\\\\u6b21\\\\u6027\\\\u6536\\\\u76ca\\\\u540e\\\\uff0c\\\\u516c\\\\u53f8\\\\u4e3b\\\\u4e1a\\\\u7684<strong>\\\\u5229\\\\u6da6\\\\u589e\\\\u901f\\\\u751a\\\\u81f3\\\\u8d85\\\\u8fc7\\\\u4e86\\\\u8425\\\\u6536\\\\u589e\\\\u901f</strong>\\\\u3002</p>\\\\n  <p>\\\\u8981\\\\u77e5\\\\u9053\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee32025\\\\u5e74\\\\u5168\\\\u5e74\\\\u51c0\\\\u5229\\\\u6da6722\\\\u4ebf\\\\uff0c\\\\u800c\\\\u52302026\\\\u5e74\\\\u4ec5\\\\u4ec5\\\\u4e00\\\\u4e2a\\\\u5b63\\\\u5ea6\\\\u5c31\\\\u5e72\\\\u4e86\\\\u8fd1207\\\\u4ebf\\\\u2014\\\\u2014\\\\u8fd9\\\\u8fd8\\\\u662f\\\\u5728\\\\u539f\\\\u6750\\\\u6599\\\\u4ef7\\\\u683c\\\\u4e0a\\\\u6da8\\\\u7684\\\\u80cc\\\\u666f\\\\u4e0b\\\\u5b9e\\\\u73b0\\\\u7684\\\\u3002</p>\\\\n  <p>\\\\u201c\\\\u5b81\\\\u738b\\\\u201d\\\\u7684\\\\u8d5a\\\\u94b1\\\\u80fd\\\\u529b\\\\uff0c\\\\u5728\\\\u6c7d\\\\u8f66\\\\u4e0a\\\\u4e0b\\\\u6e38\\\\u786e\\\\u5b9e\\\\u662f\\\\u72ec\\\\u4e00\\\\u4efd\\\\u3002</p>\\\\n  <p>\\\\u8d22\\\\u62a5\\\\u53d1\\\\u5e03\\\\u540e\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u4eca\\\\u65e5\\\\u80a1\\\\u4ef7\\\\u4e00\\\\u5ea6\\\\u6da8\\\\u8d856%\\\\uff0c\\\\u5e02\\\\u503c\\\\u4e00\\\\u5ea6\\\\u8d85\\\\u8fc72.09\\\\u4e07\\\\u4ebf\\\\uff0c\\\\u8dfb\\\\u8eab<strong>A\\\\u80a1\\\\u5e02\\\\u503c\\\\u524d\\\\u4e09</strong>\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_25cf828ea6bf481b915509984abe98fd@46958_oswg210282oswg1080oswg629_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u4f46\\\\u5947\\\\u602a\\\\u7684\\\\u662f\\\\uff0c\\\\u660e\\\\u660e\\\\u516c\\\\u53f8\\\\u8d26\\\\u4e0a\\\\u8eba\\\\u7740\\\\u8d853200\\\\u4ebf\\\\u73b0\\\\u91d1\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u4f9d\\\\u7136\\\\u9009\\\\u62e9\\\\u4e86\\\\u5927\\\\u89c4\\\\u6a21\\\\u878d\\\\u8d44\\\\uff0c\\\\u7b79\\\\u8d44\\\\u73b0\\\\u91d1\\\\u6d41\\\\u66b4\\\\u6da8\\\\u4e86<strong>11\\\\u500d</strong>\\\\u3002</p>\\\\n  <p>\\\\u8fd9\\\\u662f\\\\u2026\\\\u2026\\\\u618b\\\\u4e86\\\\u5927\\\\u62db\\\\uff1f</p>\\\\n  <h2><strong>\\\\u65e5\\\\u8d5a2.3\\\\u4ebf\\\\uff0c\\\\u201c\\\\u5b81\\\\u738b\\\\u201d\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u8d5a\\\\u7206</strong></h2>\\\\n  <p>\\\\u4eca\\\\u5e74\\\\u4e00\\\\u5b63\\\\u5ea6\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u8425\\\\u4e1a\\\\u6536\\\\u5165\\\\u4e3a<strong>1291.31\\\\u4ebf\\\\u5143</strong>\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u957f52.45%\\\\uff0c\\\\u5df2\\\\u7ecf\\\\u8fde\\\\u7eed\\\\u4e09\\\\u4e2a\\\\u5b63\\\\u5ea6\\\\u8425\\\\u6536\\\\u7834\\\\u5343\\\\u4ebf\\\\u3002</p>\\\\n  <p>\\\\u636e\\\\u8d22\\\\u62a5\\\\u7535\\\\u8bdd\\\\u4f1a\\\\u900f\\\\u9732\\\\uff0c\\\\u8fd9\\\\u5176\\\\u4e2d\\\\u7ea61/3\\\\u6536\\\\u5165\\\\u6765\\\\u81ea\\\\u6d77\\\\u5916\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_9aaeb804c045403eaf063e3019331b8f@46958_oswg82394oswg1076oswg455_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u5229\\\\u6da6\\\\u5c42\\\\u9762\\\\u7684\\\\u8868\\\\u73b0\\\\u66f4\\\\u7a81\\\\u51fa\\\\u3002\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3Q1\\\\u7684<strong>\\\\u5f52\\\\u6bcd\\\\u51c0\\\\u5229\\\\u6da6</strong>\\\\u4e3a207.38\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u957f48.52%\\\\uff0c\\\\u548c\\\\u8425\\\\u6536\\\\u540c\\\\u6b65\\\\u5b9e\\\\u73b0\\\\u4e86\\\\u9ad8\\\\u589e\\\\u957f\\\\u3002</p>\\\\n  <p>\\\\u5927\\\\u81f4\\\\u8ba1\\\\u7b97\\\\u4e00\\\\u4e0b\\\\uff0c<strong>\\\\u5e73\\\\u5747\\\\u6bcf\\\\u5929\\\\u51c0\\\\u8d5a2.3\\\\u4ebf\\\\u5143\\\\uff0c\\\\u6bcf\\\\u5206\\\\u949f\\\\u80fd\\\\u8d5a16\\\\u4e07\\\\u5143</strong>\\\\u3002</p>\\\\n  <p>\\\\u4ec0\\\\u4e48\\\\u6c34\\\\u5e73\\\\u5462\\\\uff1f\\\\u62ff\\\\u56fd\\\\u5185\\\\u8f66\\\\u5708\\\\u6700\\\\u8d5a\\\\u94b1\\\\u7684\\\\u8f66\\\\u4f01<strong>\\\\u6bd4\\\\u4e9a\\\\u8fea</strong>\\\\u6765\\\\u53c2\\\\u8003\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u53ef\\\\u80fd\\\\u4e0d\\\\u52305\\\\u4e2a\\\\u6708\\\\u5c31\\\\u80fd\\\\u8d5a\\\\u591f\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u53bb\\\\u5e74\\\\u5168\\\\u5e74\\\\u7684\\\\u5229\\\\u6da6\\\\uff08326\\\\u4ebf\\\\u5143\\\\uff09\\\\u3002</p>\\\\n  <p>\\\\u5e76\\\\u4e14\\\\uff0c\\\\u4eca\\\\u5e74\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u7684\\\\u6263\\\\u975e\\\\u51c0\\\\u5229\\\\u6da6\\\\u4e3a180.93\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u4e8652.95%\\\\u3002</p>\\\\n  <p>\\\\u8fd9\\\\u9879\\\\u6570\\\\u636e\\\\u5254\\\\u9664\\\\u4e86\\\\u4e00\\\\u6b21\\\\u6027\\\\u6536\\\\u76ca\\\\uff0c\\\\u53cd\\\\u6620\\\\u7684\\\\u662f\\\\u516c\\\\u53f8\\\\u4e3b\\\\u8425\\\\u4e1a\\\\u52a1\\\\u7684\\\\u771f\\\\u5b9e\\\\u76c8\\\\u5229\\\\u80fd\\\\u529b\\\\u589e\\\\u957f\\\\uff0c\\\\u5176\\\\u589e\\\\u901f\\\\u751a\\\\u81f3\\\\u6bd4\\\\u8425\\\\u6536\\\\u589e\\\\u901f\\\\u66f4\\\\u9ad8\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_646fa7d3322f4c0989ba000aa73ee1fe@46958_oswg105771oswg945oswg454_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u5728\\\\u6210\\\\u672c\\\\u548c\\\\u8d39\\\\u7528\\\\u5c42\\\\u9762\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3Q1\\\\u7684\\\\u8425\\\\u4e1a\\\\u6210\\\\u672c\\\\u4e3a970.86\\\\u4ebf\\\\u5143\\\\uff0c\\\\u540c\\\\u6bd4\\\\u589e\\\\u957f51.63%\\\\uff0c\\\\u589e\\\\u901f\\\\u4e0e\\\\u8425\\\\u6536\\\\u57fa\\\\u672c\\\\u540c\\\\u6b65\\\\u3002</p>\\\\n  <p>\\\\u56e0\\\\u6b64\\\\uff0c\\\\u516c\\\\u53f8\\\\u7684\\\\u6bdb\\\\u5229\\\\u6c34\\\\u5e73\\\\u4e5f\\\\u6ca1\\\\u6709\\\\u51fa\\\\u73b0\\\\u5927\\\\u7684\\\\u6ce2\\\\u52a8\\\\uff0c\\\\u8fd9\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u7684\\\\u6bdb\\\\u