\\\u5de5\\\\u5382\\\\u7684\\\\u6210\\\\u672c\\\\u867d\\\\u8f83\\\\u56fd\\\\u5185\\\\u7a0d\\\\u9ad8\\\\uff0c\\\\u4f46\\\\u76f8\\\\u6bd4\\\\u5fb7\\\\u56fd\\\\u5de5\\\\u5382\\\\u6709\\\\u660e\\\\u663e\\\\u4f18\\\\u52bf\\\\uff0c\\\\u76ee\\\\u524d\\\\u6b63\\\\u5728\\\\u4ea7\\\\u80fd\\\\u722c\\\\u5761\\\\u9636\\\\u6bb5\\\\uff0c\\\\u516c\\\\u53f8\\\\u540e\\\\u7eed\\\\u4f1a\\\\u901a\\\\u8fc7\\\\u8bbe\\\\u5907\\\\u9009\\\\u578b\\\\u4f18\\\\u5316\\\\u3001\\\\u7b80\\\\u5316\\\\u7535\\\\u82af\\\\u54c1\\\\u7c7b\\\\u7b49\\\\u65b9\\\\u5f0f\\\\u63d0\\\\u9ad8\\\\u751f\\\\u4ea7\\\\u6548\\\\u7387\\\\uff0c\\\\u964d\\\\u4f4e\\\\u6210\\\\u672c\\\\u3002</p>\\\\n  <p>\\\\u6240\\\\u4ee5\\\\u6574\\\\u4f53\\\\u800c\\\\u8a00\\\\uff0c\\\\u5c3d\\\\u7ba1\\\\u53ef\\\\u80fd\\\\u5b58\\\\u5728\\\\u4e00\\\\u4e9b\\\\u5916\\\\u754c\\\\u56e0\\\\u7d20\\\\u4f1a\\\\u5bf9\\\\u516c\\\\u53f8\\\\u9020\\\\u6210\\\\u77ed\\\\u671f\\\\u5f71\\\\u54cd\\\\uff0c\\\\u4f46\\\\u201c\\\\u5b81\\\\u738b\\\\u201d\\\\u4ecd\\\\u80fd\\\\u901a\\\\u8fc7\\\\u80fd\\\\u529b\\\\u548c\\\\u4f53\\\\u7cfb\\\\u8fdb\\\\u884c\\\\u8c03\\\\u6574\\\\uff0c\\\\u957f\\\\u671f\\\\u6765\\\\u770b\\\\u6307\\\\u5f15\\\\u79ef\\\\u6781\\\\u3002</p>\\\\n  <p>\\\\u4e5f\\\\u4e0d\\\\u514d\\\\u6709\\\\u4eba\\\\u95ee\\\\u5230\\\\u4e86\\\\u90a3\\\\u4e2a\\\\u5927\\\\u5bb6\\\\u90fd\\\\u597d\\\\u5947\\\\u7684\\\\u95ee\\\\u9898\\\\uff1a</p>\\\\n  <p>\\\\u5bf9\\\\u4e8e<strong>\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u53d1\\\\u5e03\\\\u7684\\\\u7b2c\\\\u4e8c\\\\u4ee3\\\\u5200\\\\u7247\\\\u7535\\\\u6c60\\\\u548c\\\\u95ea\\\\u5145\\\\u6280\\\\u672f</strong>\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u600e\\\\u4e48\\\\u770b\\\\uff1f</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_d2b4714be14942ca9fa248a2ae5678ee@46958_oswg221815oswg995oswg496_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u800c\\\\u201c\\\\u5b81\\\\u738b\\\\u201d\\\\u56de\\\\u5e94\\\\u79f0\\\\uff0c\\\\u5173\\\\u4e8e\\\\u8d85\\\\u5145\\\\uff0c\\\\u5bf9\\\\u4e8e\\\\u516c\\\\u53f8\\\\u800c\\\\u8a00\\\\u4e0d\\\\u662f\\\\u65b0\\\\u7684\\\\u6311\\\\u6218\\\\u3002</p>\\\\n  <blockquote>\\\\n   <p>\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u51e0\\\\u5e74\\\\u524d\\\\u5c31\\\\u63a8\\\\u51fa\\\\u4e86\\\\u201c\\\\u795e\\\\u884c\\\\u201d\\\\u8d85\\\\u5145\\\\u7535\\\\u6c60\\\\uff0c\\\\u5f88\\\\u9ad8\\\\u5174\\\\u770b\\\\u5230\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u80fd\\\\u591f\\\\u300c\\\\u8ddf\\\\u8fdb\\\\u300d\\\\u8fd9\\\\u6761\\\\u6280\\\\u672f\\\\u8def\\\\u7ebf\\\\u3002</p>\\\\n  </blockquote>\\\\n  <p>\\\\u9ad8\\\\u7ba1\\\\u5766\\\\u8a00\\\\uff0c\\\\u8fc7\\\\u53bb\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u5df2\\\\u5728\\\\u8fd9\\\\u65b9\\\\u9762\\\\u4e0e\\\\u4e3b\\\\u673a\\\\u5382\\\\u8fbe\\\\u6210\\\\u5408\\\\u4f5c\\\\uff0c\\\\u6548\\\\u679c\\\\u4e0d\\\\u9519\\\\uff0c\\\\u4f46\\\\u5ba2\\\\u89c2\\\\u800c\\\\u8a00\\\\u666e\\\\u53ca\\\\u5ea6\\\\u5e76\\\\u4e0d\\\\u591f\\\\uff0c\\\\u56e0\\\\u6b64\\\\u6ca1\\\\u6709\\\\u5168\\\\u9762\\\\u843d\\\\u5730\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_4e5d0527e66a4380b77ae123b064d2f0@46958_oswg331442oswg1080oswg583_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u8fd8\\\\u8868\\\\u793a\\\\uff0c\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u6b64\\\\u6b21\\\\u6280\\\\u672f\\\\u53d1\\\\u5e03\\\\uff0c\\\\u5438\\\\u5f15\\\\u4e86\\\\u884c\\\\u4e1a\\\\u5185\\\\u7684\\\\u66f4\\\\u591a\\\\u5173\\\\u6ce8\\\\u5ea6\\\\uff0c\\\\u4e5f\\\\u4f1a\\\\u5e26\\\\u52a8\\\\u66f4\\\\u591a\\\\u4e3b\\\\u673a\\\\u5382\\\\u5bfb\\\\u6c42\\\\u5408\\\\u4f5c\\\\uff0c\\\\u8fd9\\\\u5bf9\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u800c\\\\u8a00\\\\u4e5f\\\\u662f\\\\u5229\\\\u597d\\\\u7684\\\\u3002</p>\\\\n  <p>\\\\u56e0\\\\u6b64\\\\uff0c\\\\u53ef\\\\u4ee5\\\\u8bf4\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u63a8\\\\u52a8\\\\u4e86\\\\u4e1a\\\\u5185\\\\u73a9\\\\u5bb6\\\\u5728\\\\u5feb\\\\u5145\\\\u3001\\\\u8d85\\\\u5145\\\\u4f53\\\\u7cfb\\\\u4e0a\\\\u52a0\\\\u5feb\\\\u5e03\\\\u5c40\\\\u3002</p>\\\\n  <p>\\\\u81f3\\\\u4e8e\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u7684\\\\u5e03\\\\u5c40\\\\uff0c\\\\u5f88\\\\u5feb\\\\u4e5f\\\\u4f1a\\\\u5728\\\\u56fd\\\\u5185\\\\u9762\\\\u4e16\\\\u2014\\\\u2014</p>\\\\n  <p>4\\\\u670821\\\\u65e5\\\\uff0c\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u4f1a\\\\u5728\\\\u5176<strong>\\\\u8d85\\\\u7ea7\\\\u79d1\\\\u6280\\\\u65e5\\\\u6d3b\\\\u52a8</strong>\\\\u4e0a\\\\uff0c\\\\u53d1\\\\u5e03\\\\u5168\\\\u65b0\\\\u7684\\\\u4ea7\\\\u54c1\\\\u548c\\\\u751f\\\\u6001\\\\uff0c \\\\u636e\\\\u79f0\\\\u6bcf\\\\u4e00\\\\u9879\\\\u90fd\\\\u76f4\\\\u51fb\\\\u884c\\\\u4e1a\\\\u6700\\\\u5173\\\\u6ce8\\\\u7684<strong>\\\\u80fd\\\\u91cf\\\\u5bc6\\\\u5ea6\\\\u3001\\\\u5feb\\\\u5145\\\\u3001\\\\u4f4e\\\\u6e29\\\\u6027\\\\u80fd\\\\u3001\\\\u5b89\\\\u5168</strong>\\\\u7b49\\\\u6838\\\\u5fc3\\\\u75db\\\\u70b9\\\\u3002</p>\\\\n  <p>\\\\u9ad8\\\\u7ba1\\\\u5f3a\\\\u8c03\\\\uff0c\\\\u8fd9\\\\u5c06\\\\u662f\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\u6210\\\\u7acb\\\\u4ee5\\\\u6765\\\\uff0c<strong>\\\\u201c\\\\u6280\\\\u672f\\\\u5bc6\\\\u5ea6\\\\u6700\\\\u9ad8\\\\u7684\\\\u4e00\\\\u6b21\\\\u53d1\\\\u5e03\\\\u4f1a\\\\u201d</strong>\\\\u3002</p>\\\\n  <p>\\\\u5916\\\\u754c\\\\u731c\\\\u6d4b\\\\u53ef\\\\u80fd\\\\u5305\\\\u62ec<strong>\\\\u56fa\\\\u6001\\\\u7535\\\\u6c60</strong>\\\\uff0c\\\\u4e5f\\\\u53ef\\\\u80fd\\\\u5305\\\\u62ec<strong>\\\\u7b2c\\\\u4e09\\\\u4ee3\\\\u795e\\\\u884c\\\\u8d85\\\\u5145\\\\u7535\\\\u6c60</strong>\\\\u3002</p>\\\\n  <p>\\\\u53ea\\\\u80fd\\\\u8bf4\\\\uff0c\\\\u73b0\\\\u5728\\\\u7684\\\\u5b81\\\\u5fb7\\\\u65f6\\\\u4ee3\\\\uff0c\\\\u95ea\\\\u5145\\\\u548c\\\\u6362\\\\u7535\\\\u53cc\\\\u7ebf\\\\u4e0b\\\\u6ce8\\\\uff0c\\\\u548c\\\\u6bd4\\\\u4e9a\\\\u8fea\\\\u5bf9\\\\u201c\\\\u7535\\\\u52a8\\\\u5316\\\\u201d\\\\u5e95\\\\u5c42\\\\u6807\\\\u51c6\\\\u7684\\\\u8bdd\\\\u8bed\\\\u6743\\\\u4e89\\\\u593a\\\\uff0c\\\\u6015\\\\u662f\\\\u8981\\\\u66f4\\\\u6fc0\\\\u70c8\\\\u4e86\\\\u3002</p>\\\\n  <p class=\\\\\\\"editor-note\\\\\\\">\\\\u672c\\\\u6587\\\\u6765\\\\u81ea\\\\u5fae\\\\u4fe1\\\\u516c\\\\u4f17\\\\u53f7<a href=\\\\\\\"https://mp.weixin.qq.com/s/sN9ARbQFNhJSzwGttQL4kQ\\\\\\\" rel=\\\\\\\"noopener noreferrer\\\\\\\" target=\\\\\\\"_blank\\\\\\\">\\\\u201c\\\\u667a\\\\u80fd\\\\u8f66\\\\u53c2\\\\u8003\\\\u201d</a>\\\\uff0c\\\\u4f5c\\\\u8005\\\\uff1a\\\\u6770\\\\u897f\\\\u5361&nbsp;\\\\uff0c36\\\\u6c2a\\\\u7ecf\\\\u6388\\\\u6743\\\\u53d1\\\\u5e03\\\\u3002</p>\\\"}, \\\"source\\\": {\\\"title\\\": \\\"36\\\\u6c2a\\\"}, \\\"authors\\\": [{\\\"name\\\": \\\"\\\\u667a\\\\u80fd\\\\u8f66\\\\u53c2\\\\u8003\\\"}], \\\"author\\\": \\\"\\\\u667a\\\\u80fd\\\\u8f66\\\\u53c2\\\\u8003\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"\\\\u667a\\\\u80fd\\\\u8f66\\\\u53c2\\\\u8003\\\"}, \\\"content\\\": [{\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u5e02\\\\u503c\\\\u8dfb\\\\u8eabA\\\\u80a1\\\\u524d\\\\u4e09\\\"}]}\", \"published_at\": \"2026-04-16 18:42:24\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:06:37');
INSERT INTO `news_detail` VALUES (61, 2208, 8, '新能源与汽车', '上市首日市值冲破1600亿，华为系新贵却被华为告了', '', '<p>4 月 16 日，港股迎来了一位很典型的“闷声发大财”型选手：思格新能源。</p>\n<p>这家公司在国内知名度不算高的企业，却引爆了资本狂欢。</p>\n<p><strong>上市首日，思格开盘价较发行价 324.2 港元高出79.2%���盘中一度冲到 669 港元，最高上涨约 105%；收盘报 659.5 港元，市值达 1628 亿港元。</strong></p>\n<p>在公开发售阶段，它的香港公开发售还录得 1102.05 倍认购，已经和壁仞科技、智谱AI、MiniMax 等 AI 赛道顶流坐到同一桌了。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_3f9cfdb5e0984e93853267b8c8b927d9@46958_oswg108562oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>思格新能源成立于2022年 5 月，距今还不到 4 年就登陆港股上市，创下了中国企业港股 IPO 的最快纪录。</p>\n<p>上市之后，思格新能源也正式成为了<strong>“AI+光储一体化第一股”</strong>；放在“星光熠熠”的港股，都算是王炸开场。</p>\n<p>另一方面，思格新能源的基石投资者名单，也着实令人羡慕：</p>\n<p><strong>既有淡马锡、瑞银资管、高盛资管、AXA、法国巴黎银行资管、霸菱这样的国际机构，也有高瓴、博裕、景林、高毅、CPE 源峰、富国基金、中国太保等熟面孔。</strong></p>\n<p>资本看好、股价狂飙，这一家成立不过数年的硬科技公司，究竟有什么独到之处？</p>\n<h2><strong>两年营收暴涨 154 倍</strong></h2>\n<p>思格之引爆资本热情最直观的原因，当然是它那条陡得有点过于夸张的增长曲线。</p>\n<p>招股书显示，思格 2023 年收入只有5830.2 万元，2024 年猛增至 13.3 亿元，2025 年更是直接飙升90.01 亿元，<strong>相比 2023 年增长了 154 倍；</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_2e0637bb11d24b42bd2a37d865525e51@46958_oswg43197oswg1080oswg394_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>毛利率方面，思格的增长也高得夸张：2023 年是31.3%，然后一路升到 46.9%，再升到 50.1%；</p>\n<p>利润端也完成了从亏损到大赚的切换，从2023 年的亏损 3.73 亿，到2025 年实现 29.19 亿的净利润。</p>\n<p>仅仅两年时间，思格新能源的收入增长 150 多倍，毛利率还越做越高，手里拿着这样的成绩单，思格新能源理所当然会成为市场的抢手货。</p>\n<p>但是，思格新能源身上，却还有比数字更吸引资本的东西。</p>\n<p>首先是人。<strong>思格创始人许映童，在华为待了接近 23 年，做过智能光伏业务，也做过昇腾 AI 计算业务，两条都是当前市场最受关注的赛道。</strong></p>\n<p>更关键的是，思格核心团队里还有大量华为旧部，让思格成了 “同一套班底出来再创业”的公司。</p>\n<p>而且这批被投资者视为“打过硬仗的制造业老兵”，还迅速把硬实力，体现在产品上。</p>\n<p>思格新能源的高格猛进，正是因为押中了一个核心爆款：<strong>SigenStor</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_2bcb797edd64440c84f8ba6d8840d292@46958_oswg107357oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>这款产品把光伏逆变器、储能变流器、储能电池、直流充电模块和能源管理系统整合在一起，做成了“五合一”可堆叠光储充一体机。</p>\n<p>招股书援引弗若斯特沙利文数据称，按 2024 年出货量算，<strong>思格已经是全球最大的可堆叠分布式光储一体机解决方案公司</strong>，市场份额 28.6%；在过去三年，SigenStor 对总收入的贡献一直都在 90% 以上。</p>\n<p>而且，思格的商业模式还非常特别：完全地押注海外市场，主攻高价高利润。</p>\n<p>招股书显示，2025 年思格收入几乎全部来自海外市场，占比达到了 99%，业务覆盖了全球 85 个国家/地区，并拥有多达 172 家合作分销商，注册安装商超过 1.7 万家。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_be218e6e86c348d68ff884314ab2ba18@46958_oswg75556oswg1080oswg328_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>而且，思格新能源打开了海外市场，结合了它华为系出身的身份，还带来了一点不一样的味道：</p>\n<p>产品技术路径与华为有同源性，却通过模块化可堆叠+AI集成实现差异化，最终在海外打开一番新天地...</p>\n<p>一个不可多得的精彩励志故事。</p>\n<p>只是，华为系的光环给思格新能源带来了光环，也给它的未来蒙上了一道阴影。</p>\n<h2><strong>华为系的“同门之争”</strong></h2>\n<p>在思格新能源上市之际，一纸诉状打破了平静。</p>\n<p>4 月 3 日，华为已向地方知识产权局提交专利侵权纠纷处理请求书，请求处理思格及其关联公司涉嫌侵犯专利权的行为；</p>\n<p>目前事件仍处于行政处理阶段，尚未进入法院正式诉讼。</p>\n<p><strong>根据公开资料，这次纠纷涉及的两项专利分别是“逆变器母线电压的调整方法及装置”和“全域最大输出功率确定方法与装置”。</strong></p>\n<p>而 21 世纪经济报道援引消息称，华为实际主张的专利可能不止两项，而是多达 10 余项。</p>\n<p>如果是无关痛痒的专利纠纷，也就罢了，可这次专利纠纷涉及的，却是思格新能源“绝对不能出事”的产品：SigenStor。</p>\n<p>从媒体披露来看，涉及产品主要包括： </p>\n<p> SigenStor 光储一体机、Sigen Hybrid 光储逆变器以及 Sigen PV 工商业光伏逆变器。</p>\n<p>这些偏偏正是占了思格新能源营收 90% 的产品。</p>\n<p>因此，招股书也已经提前提醒过，公司业务对 SigenStor 依赖度较高，如果核心产品销售受影响，可能对业务和财务表现造成重大不利影响。</p>\n<p>也就是说，若认定侵权，思格新能源可能面临停止生产/销售的SigenStor 和相关产品、支付赔偿/许可费、产品整改、品牌重建，甚至对客户/合作伙伴的连带责任等一系列麻烦。</p>\n<p><strong>而光是停止生产/销售的SigenStor和相关产品，就有可能成为思格新能源的灭顶之灾。</strong></p>\n<p>只不过，至少从思格新能源挂牌首日的情况来看，投资者显然更愿意先看增长，再看官司。</p>\n<p>毕竟，思格踩中的是当前最王炸的赛道组合：AI+储能，还有海外高端市场，以及一个已经被验证过的强力产品。</p>\n<p>AI 算力增长带来的电力需求、全球能源转型带来的储能需求，再叠加 AI 对能源管理系统本身的提效想象，巨大的行业前景，很难让投资人因为一宗还处于行政处理阶段的纠纷停下脚步。</p>\n<p>当然，对思格新能源来说，或许比起专利纠纷，更大的麻烦，<strong>是产品结构过于单一、聚焦研发设计与系统集成而对供应链依赖较强，和储能赛道海外巨头围剿等一系列问题。</strong></p>\n<p>尽管上市首天就拿到了泼天富贵，公司的市值也突破了  1600  亿，但思格新能源的挑战，才刚刚开始。 </p>\n<p>本文来自微信公众号<a href=\"https://mp.weixin.qq.com/s/XE0DrceTJirIBRdFxBp7qA\">“蓝字计划”</a>，作者：Hayward，36氪经授权发布。</p>', 'https://36kr.com/p/3769299931415040?f=rss', 0, '', '{\"summary\": \"本文梳理华为系出海光储企业思格新能源港股IPO的亮眼表现，提示其面临的多重风险，可为出海新能源企业及投资者提供参考\", \"abstract\": \"华为前员工创立的思格新能源成立不到四年便登陆港股上市，上市首日市值突破1628亿港元，获超千倍认购，受到资本热捧。该公司99%收入来自海外市场，是全球最大的可堆叠分布式光储一体机解决方案提供商，两年间营收增长超150倍，业绩增速惊人。上市前夕，华为以专利侵权为由对思格新能源提起处理请求，纠纷涉及占思格九成以上营收的核心产品。除专利纠纷外，思格还面临产品结构单一、供应链依赖、海外巨头竞争等多重挑战。\", \"keywords\": [\"思格新能源\", \"港股IPO\", \"光储一体化\", \"专利侵权\", \"企业出海\", \"海外市场\", \"储能\"], \"policy_risk\": {\"market_risk\": \"产品结构单一，对核心产品依赖度极高；聚焦研发设计与系统集成，对供应链依赖较强；面临海外储能赛道巨头的竞争围剿；专利纠纷若失利将对企业业务造成重大不利影响\", \"policy_compliance\": \"华为向地方知识产权局提交专利侵权纠纷处理请求，思格新能源核心营收产品涉案，目前事件处于行政处理阶段；若认定侵权，思格将面临停止产销核心产品、支付赔偿、产品整改等合规后果\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"新能源与汽车\"}', '', '{\"url\": \"https://36kr.com/p/3769299931415040?f=rss\", \"title\": \"上市首日市值冲破1600亿，华为系新贵却被华为告了\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>4 月 16 日，港股迎来了一位很典型的“闷声发大财”型选手：思格新能源。</p>\\n<p>这家公司在国内知名度不算高的企业，却引爆了资本狂欢。</p>\\n<p><strong>上市首日，思格开盘价较发行价 324.2 港元高出79.2%���盘中一度冲到 669 港元，最高上涨约 105%；收盘报 659.5 港元，市值达 1628 亿港元。</strong></p>\\n<p>在公开发售阶段，它的香港公开发售还录得 1102.05 倍认购，已经和壁仞科技、智谱AI、MiniMax 等 AI 赛道顶流坐到同一桌了。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_3f9cfdb5e0984e93853267b8c8b927d9@46958_oswg108562oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>思格新能源成立于2022年 5 月，距今还不到 4 年就登陆港股上市，创下了中国企业港股 IPO 的最快纪录。</p>\\n<p>上市之后，思格新能源也正式成为了<strong>“AI+光储一体化第一股”</strong>；放在“星光熠熠”的港股，都算是王炸开场。</p>\\n<p>另一方面，思格新能源的基石投资者名单，也着实令人羡慕：</p>\\n<p><strong>既有淡马锡、瑞银资管、高盛资管、AXA、法国巴黎银行资管、霸菱这样的国际机构，也有高瓴、博裕、景林、高毅、CPE 源峰、富国基金、中国太保等熟面孔。</strong></p>\\n<p>资本看好、股价狂飙，这一家成立不过数年的硬科技公司，究竟有什么独到之处？</p>\\n<h2><strong>两年营收暴涨 154 倍</strong></h2>\\n<p>思格之引爆资本热情最直观的原因，当然是它那条陡得有点过于夸张的增长曲线。</p>\\n<p>招股书显示，思格 2023 年收入只有5830.2 万元，2024 年猛增至 13.3 亿元，2025 年更是直接飙升90.01 亿元，<strong>相比 2023 年增长了 154 倍；</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_2e0637bb11d24b42bd2a37d865525e51@46958_oswg43197oswg1080oswg394_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>毛利率方面，思格的增长也高得夸张：2023 年是31.3%，然后一路升到 46.9%，再升到 50.1%；</p>\\n<p>利润端也完成了从亏损到大赚的切换，从2023 年的亏损 3.73 亿，到2025 年实现 29.19 亿的净利润。</p>\\n<p>仅仅两年时间，思格新能源的收入增长 150 多倍，毛利率还越做越高，手里拿着这样的成绩单，思格新能源理所当然会成为市场的抢手货。</p>\\n<p>但是，思格新能源身上，却还有比数字更吸引资本的东西。</p>\\n<p>首先是人。<strong>思格创始人许映童，在华为待了接近 23 年，做过智能光伏业务，也做过昇腾 AI 计算业务，两条都是当前市场最受关注的赛道。</strong></p>\\n<p>更关键的是，思格核心团队里还有大量华为旧部，让思格成了 “同一套班底出来再创业”的公司。</p>\\n<p>而且这批被投资者视为“打过硬仗的制造业老兵”，还迅速把硬实力，体现在产品上。</p>\\n<p>思格新能源的高格猛进，正是因为押中了一个核心爆款：<strong>SigenStor</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_2bcb797edd64440c84f8ba6d8840d292@46958_oswg107357oswg1080oswg720_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>这款产品把光伏逆变器、储能变流器、储能电池、直流充电模块和能源管理系统整合在一起，做成了“五合一”可堆叠光储充一体机。</p>\\n<p>招股书援引弗若斯特沙利文数据称，按 2024 年出货量算，<strong>思格已经是全球最大的可堆叠分布式光储一体机解决方案公司</strong>，市场份额 28.6%；在过去三年，SigenStor 对总收入的贡献一直都在 90% 以上。</p>\\n<p>而且，思格的商业模式还非常特别：完全地押注海外市场，主攻高价高利润。</p>\\n<p>招股书显示，2025 年思格收入几乎全部来自海外市场，占比达到了 99%，业务覆盖了全球 85 个国家/地区，并拥有多达 172 家合作分销商，注册安装商超过 1.7 万家。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_be218e6e86c348d68ff884314ab2ba18@46958_oswg75556oswg1080oswg328_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>而且，思格新能源打开了海外市场，结合了它华为系出身的身份，还带来了一点不一样的味道：</p>\\n<p>产品技术路径与华为有同源性，却通过模块化可堆叠+AI集成实现差异化，最终在海外打开一番新天地...</p>\\n<p>一个不可多得的精彩励志故事。</p>\\n<p>只是，华为系的光环给思格新能源带来了光环，也给它的未来蒙上了一道阴影。</p>\\n<h2><strong>华为系的“同门之争”</strong></h2>\\n<p>在思格新能源上市之际，一纸诉状打破了平静。</p>\\n<p>4 月 3 日，华为已向地方知识产权局提交专利侵权纠纷处理请求书，请求处理思格及其关联公司涉嫌侵犯专利权的行为；</p>\\n<p>目前事件仍处于行政处理阶段，尚未进入法院正式诉讼。</p>\\n<p><strong>根据公开资料，这次纠纷涉及的两项专利分别是“逆变器母线电压的调整方法及装置”和“全域最大输出功率确定方法与装置”。</strong></p>\\n<p>而 21 世纪经济报道援引消息称，华为实际主张的专利可能不止两项，而是多达 10 余项。</p>\\n<p>如果是无关痛痒的专利纠纷，也就罢了，可这次专利纠纷涉及的，却是思格新能源“绝对不能出事”的产品：SigenStor。</p>\\n<p>从媒体披露来看，涉及产品主要包括： </p>\\n<p> SigenStor 光储一体机、Sigen Hybrid 光储逆变器以及 Sigen PV 工商业光伏逆变器。</p>\\n<p>这些偏偏正是占了思格新能源营收 90% 的产品。</p>\\n<p>因此，招股书也已经提前提醒过，公司业务对 SigenStor 依赖度较高，如果核心产品销售受影响，可能对业务和财务表现造成重大不利影响。</p>\\n<p>也就是说，若认定侵权，思格新能源可能面临停止生产/销售的SigenStor 和相关产品、支付赔偿/许可费、产品整改、品牌重建，甚至对客户/合作伙伴的连带责任等一系列麻烦。</p>\\n<p><strong>而光是停止生产/销售的SigenStor和相关产品，就有可能成为思格新能源的灭顶之灾。</strong></p>\\n<p>只不过，至少从思格新能源挂牌首日的情况来看，投资者显然更愿意先看增长，再看官司。</p>\\n<p>毕竟，思格踩中的是当前最王炸的赛道组合：AI+储能，还有海外高端市场，以及一个已经被验证过的强力产品。</p>\\n<p>AI 算力增长带来的电力需求、全球能源转型带来的储能需求，再叠加 AI 对能源管理系统本身的提效想象，巨大的行业前景，很难让投资人因为一宗还处于行政处理阶段的纠纷停下脚步。</p>\\n<p>当然，对思格新能源来说，或许比起专利纠纷，更大的麻烦，<strong>是产品结构过于单一、聚焦研发设计与系统集成而对供应链依赖较强，和储能赛道海外巨头围剿等一系列问题。</strong></p>\\n<p>尽管上市首天就拿到了泼天富贵，公司的市值也突破了  1600  亿，但思格新能源的挑战，才刚刚开始。 </p>\\n<p>本文来自微信公众号<a href=\\\"https://mp.weixin.qq.com/s/XE0DrceTJirIBRdFxBp7qA\\\">“蓝字计划”</a>，作者：Hayward，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\\\"title\\\": \\\"\\\\u4e0a\\\\u5e02\\\\u9996\\\\u65e5\\\\u5e02\\\\u503c\\\\u51b2\\\\u78341600\\\\u4ebf\\\\uff0c\\\\u534e\\\\u4e3a\\\\u7cfb\\\\u65b0\\\\u8d35\\\\u5374\\\\u88ab\\\\u534e\\\\u4e3a\\\\u544a\\\\u4e86\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u4e0a\\\\u5e02\\\\u9996\\\\u65e5\\\\u5e02\\\\u503c\\\\u51b2\\\\u78341600\\\\u4ebf\\\\uff0c\\\\u534e\\\\u4e3a\\\\u7cfb\\\\u65b0\\\\u8d35\\\\u5374\\\\u88ab\\\\u534e\\\\u4e3a\\\\u544a\\\\u4e86\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769299931415040?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769299931415040?f=rss\\\", \\\"published\\\": \\\"2026-04-16 18:36:36  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 10, 36, 36, 3, 106, 0], \\\"summary\\\": \\\"<p>4&nbsp;\\\\u6708&nbsp;16&nbsp;\\\\u65e5\\\\uff0c\\\\u6e2f\\\\u80a1\\\\u8fce\\\\u6765\\\\u4e86\\\\u4e00\\\\u4f4d\\\\u5f88\\\\u5178\\\\u578b\\\\u7684\\\\u201c\\\\u95f7\\\\u58f0\\\\u53d1\\\\u5927\\\\u8d22\\\\u201d\\\\u578b\\\\u9009\\\\u624b\\\\uff1a\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u3002</p>\\\\n  <p>\\\\u8fd9\\\\u5bb6\\\\u516c\\\\u53f8\\\\u5728\\\\u56fd\\\\u5185\\\\u77e5\\\\u540d\\\\u5ea6\\\\u4e0d\\\\u7b97\\\\u9ad8\\\\u7684\\\\u4f01\\\\u4e1a\\\\uff0c\\\\u5374\\\\u5f15\\\\u7206\\\\u4e86\\\\u8d44\\\\u672c\\\\u72c2\\\\u6b22\\\\u3002</p>\\\\n  <p><strong>\\\\u4e0a\\\\u5e02\\\\u9996\\\\u65e5\\\\uff0c\\\\u601d\\\\u683c\\\\u5f00\\\\u76d8\\\\u4ef7\\\\u8f83\\\\u53d1\\\\u884c\\\\u4ef7&nbsp;324.2&nbsp;\\\\u6e2f\\\\u5143\\\\u9ad8\\\\u51fa79.2%\\\\ufffd\\\\ufffd\\\\ufffd\\\\u76d8\\\\u4e2d\\\\u4e00\\\\u5ea6\\\\u51b2\\\\u5230&nbsp;669&nbsp;\\\\u6e2f\\\\u5143\\\\uff0c\\\\u6700\\\\u9ad8\\\\u4e0a\\\\u6da8\\\\u7ea6&nbsp;105%\\\\uff1b\\\\u6536\\\\u76d8\\\\u62a5 659.5 \\\\u6e2f\\\\u5143\\\\uff0c\\\\u5e02\\\\u503c\\\\u8fbe 1628 \\\\u4ebf\\\\u6e2f\\\\u5143\\\\u3002</strong></p>\\\\n  <p>\\\\u5728\\\\u516c\\\\u5f00\\\\u53d1\\\\u552e\\\\u9636\\\\u6bb5\\\\uff0c\\\\u5b83\\\\u7684\\\\u9999\\\\u6e2f\\\\u516c\\\\u5f00\\\\u53d1\\\\u552e\\\\u8fd8\\\\u5f55\\\\u5f97&nbsp;1102.05&nbsp;\\\\u500d\\\\u8ba4\\\\u8d2d\\\\uff0c\\\\u5df2\\\\u7ecf\\\\u548c\\\\u58c1\\\\u4ede\\\\u79d1\\\\u6280\\\\u3001\\\\u667a\\\\u8c31AI\\\\u3001MiniMax&nbsp;\\\\u7b49&nbsp;AI&nbsp;\\\\u8d5b\\\\u9053\\\\u9876\\\\u6d41\\\\u5750\\\\u5230\\\\u540c\\\\u4e00\\\\u684c\\\\u4e86\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_3f9cfdb5e0984e93853267b8c8b927d9@46958_oswg108562oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u6210\\\\u7acb\\\\u4e8e2022\\\\u5e74 5 \\\\u6708\\\\uff0c\\\\u8ddd\\\\u4eca\\\\u8fd8\\\\u4e0d\\\\u5230 4 \\\\u5e74\\\\u5c31\\\\u767b\\\\u9646\\\\u6e2f\\\\u80a1\\\\u4e0a\\\\u5e02\\\\uff0c\\\\u521b\\\\u4e0b\\\\u4e86\\\\u4e2d\\\\u56fd\\\\u4f01\\\\u4e1a\\\\u6e2f\\\\u80a1 IPO \\\\u7684\\\\u6700\\\\u5feb\\\\u7eaa\\\\u5f55\\\\u3002</p>\\\\n  <p>\\\\u4e0a\\\\u5e02\\\\u4e4b\\\\u540e\\\\uff0c\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u4e5f\\\\u6b63\\\\u5f0f\\\\u6210\\\\u4e3a\\\\u4e86<strong>\\\\u201cAI+\\\\u5149\\\\u50a8\\\\u4e00\\\\u4f53\\\\u5316\\\\u7b2c\\\\u4e00\\\\u80a1\\\\u201d</strong>\\\\uff1b\\\\u653e\\\\u5728\\\\u201c\\\\u661f\\\\u5149\\\\u71a0\\\\u71a0\\\\u201d\\\\u7684\\\\u6e2f\\\\u80a1\\\\uff0c\\\\u90fd\\\\u7b97\\\\u662f\\\\u738b\\\\u70b8\\\\u5f00\\\\u573a\\\\u3002</p>\\\\n  <p>\\\\u53e6\\\\u4e00\\\\u65b9\\\\u9762\\\\uff0c\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u7684\\\\u57fa\\\\u77f3\\\\u6295\\\\u8d44\\\\u8005\\\\u540d\\\\u5355\\\\uff0c\\\\u4e5f\\\\u7740\\\\u5b9e\\\\u4ee4\\\\u4eba\\\\u7fa1\\\\u6155\\\\uff1a</p>\\\\n  <p><strong>\\\\u65e2\\\\u6709\\\\u6de1\\\\u9a6c\\\\u9521\\\\u3001\\\\u745e\\\\u94f6\\\\u8d44\\\\u7ba1\\\\u3001\\\\u9ad8\\\\u76db\\\\u8d44\\\\u7ba1\\\\u3001AXA\\\\u3001\\\\u6cd5\\\\u56fd\\\\u5df4\\\\u9ece\\\\u94f6\\\\u884c\\\\u8d44\\\\u7ba1\\\\u3001\\\\u9738\\\\u83f1\\\\u8fd9\\\\u6837\\\\u7684\\\\u56fd\\\\u9645\\\\u673a\\\\u6784\\\\uff0c\\\\u4e5f\\\\u6709\\\\u9ad8\\\\u74f4\\\\u3001\\\\u535a\\\\u88d5\\\\u3001\\\\u666f\\\\u6797\\\\u3001\\\\u9ad8\\\\u6bc5\\\\u3001CPE&nbsp;\\\\u6e90\\\\u5cf0\\\\u3001\\\\u5bcc\\\\u56fd\\\\u57fa\\\\u91d1\\\\u3001\\\\u4e2d\\\\u56fd\\\\u592a\\\\u4fdd\\\\u7b49\\\\u719f\\\\u9762\\\\u5b54\\\\u3002</strong></p>\\\\n  <p>\\\\u8d44\\\\u672c\\\\u770b\\\\u597d\\\\u3001\\\\u80a1\\\\u4ef7\\\\u72c2\\\\u98d9\\\\uff0c\\\\u8fd9\\\\u4e00\\\\u5bb6\\\\u6210\\\\u7acb\\\\u4e0d\\\\u8fc7\\\\u6570\\\\u5e74\\\\u7684\\\\u786c\\\\u79d1\\\\u6280\\\\u516c\\\\u53f8\\\\uff0c\\\\u7a76\\\\u7adf\\\\u6709\\\\u4ec0\\\\u4e48\\\\u72ec\\\\u5230\\\\u4e4b\\\\u5904\\\\uff1f</p>\\\\n  <h2><strong>\\\\u4e24\\\\u5e74\\\\u8425\\\\u6536\\\\u66b4\\\\u6da8&nbsp;154&nbsp;\\\\u500d</strong></h2>\\\\n  <p>\\\\u601d\\\\u683c\\\\u4e4b\\\\u5f15\\\\u7206\\\\u8d44\\\\u672c\\\\u70ed\\\\u60c5\\\\u6700\\\\u76f4\\\\u89c2\\\\u7684\\\\u539f\\\\u56e0\\\\uff0c\\\\u5f53\\\\u7136\\\\u662f\\\\u5b83\\\\u90a3\\\\u6761\\\\u9661\\\\u5f97\\\\u6709\\\\u70b9\\\\u8fc7\\\\u4e8e\\\\u5938\\\\u5f20\\\\u7684\\\\u589e\\\\u957f\\\\u66f2\\\\u7ebf\\\\u3002</p>\\\\n  <p>\\\\u62db\\\\u80a1\\\\u4e66\\\\u663e\\\\u793a\\\\uff0c\\\\u601d\\\\u683c&nbsp;2023&nbsp;\\\\u5e74\\\\u6536\\\\u5165\\\\u53ea\\\\u67095830.2&nbsp;\\\\u4e07\\\\u5143\\\\uff0c2024&nbsp;\\\\u5e74\\\\u731b\\\\u589e\\\\u81f3&nbsp;13.3&nbsp;\\\\u4ebf\\\\u5143\\\\uff0c2025&nbsp;\\\\u5e74\\\\u66f4\\\\u662f\\\\u76f4\\\\u63a5\\\\u98d9\\\\u534790.01&nbsp;\\\\u4ebf\\\\u5143\\\\uff0c<strong>\\\\u76f8\\\\u6bd4&nbsp;2023&nbsp;\\\\u5e74\\\\u589e\\\\u957f\\\\u4e86&nbsp;154&nbsp;\\\\u500d\\\\uff1b</strong></p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_2e0637bb11d24b42bd2a37d865525e51@46958_oswg43197oswg1080oswg394_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u6bdb\\\\u5229\\\\u7387\\\\u65b9\\\\u9762\\\\uff0c\\\\u601d\\\\u683c\\\\u7684\\\\u589e\\\\u957f\\\\u4e5f\\\\u9ad8\\\\u5f97\\\\u5938\\\\u5f20\\\\uff1a2023&nbsp;\\\\u5e74\\\\u662f31.3%\\\\uff0c\\\\u7136\\\\u540e\\\\u4e00\\\\u8def\\\\u5347\\\\u5230&nbsp;46.9%\\\\uff0c\\\\u518d\\\\u5347\\\\u5230&nbsp;50.1%\\\\uff1b</p>\\\\n  <p>\\\\u5229\\\\u6da6\\\\u7aef\\\\u4e5f\\\\u5b8c\\\\u6210\\\\u4e86\\\\u4ece\\\\u4e8f\\\\u635f\\\\u5230\\\\u5927\\\\u8d5a\\\\u7684\\\\u5207\\\\u6362\\\\uff0c\\\\u4ece2023&nbsp;\\\\u5e74\\\\u7684\\\\u4e8f\\\\u635f&nbsp;3.73&nbsp;\\\\u4ebf\\\\uff0c\\\\u52302025&nbsp;\\\\u5e74\\\\u5b9e\\\\u73b0&nbsp;29.19&nbsp;\\\\u4ebf\\\\u7684\\\\u51c0\\\\u5229\\\\u6da6\\\\u3002</p>\\\\n  <p>\\\\u4ec5\\\\u4ec5\\\\u4e24\\\\u5e74\\\\u65f6\\\\u95f4\\\\uff0c\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u7684\\\\u6536\\\\u5165\\\\u589e\\\\u957f&nbsp;150&nbsp;\\\\u591a\\\\u500d\\\\uff0c\\\\u6bdb\\\\u5229\\\\u7387\\\\u8fd8\\\\u8d8a\\\\u505a\\\\u8d8a\\\\u9ad8\\\\uff0c\\\\u624b\\\\u91cc\\\\u62ff\\\\u7740\\\\u8fd9\\\\u6837\\\\u7684\\\\u6210\\\\u7ee9\\\\u5355\\\\uff0c\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u7406\\\\u6240\\\\u5f53\\\\u7136\\\\u4f1a\\\\u6210\\\\u4e3a\\\\u5e02\\\\u573a\\\\u7684\\\\u62a2\\\\u624b\\\\u8d27\\\\u3002</p>\\\\n  <p>\\\\u4f46\\\\u662f\\\\uff0c\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u8eab\\\\u4e0a\\\\uff0c\\\\u5374\\\\u8fd8\\\\u6709\\\\u6bd4\\\\u6570\\\\u5b57\\\\u66f4\\\\u