\\u4e86&nbsp;99%\\\\uff0c\\\\u4e1a\\\\u52a1\\\\u8986\\\\u76d6\\\\u4e86\\\\u5168\\\\u7403&nbsp;85&nbsp;\\\\u4e2a\\\\u56fd\\\\u5bb6/\\\\u5730\\\\u533a\\\\uff0c\\\\u5e76\\\\u62e5\\\\u6709\\\\u591a\\\\u8fbe&nbsp;172&nbsp;\\\\u5bb6\\\\u5408\\\\u4f5c\\\\u5206\\\\u9500\\\\u5546\\\\uff0c\\\\u6ce8\\\\u518c\\\\u5b89\\\\u88c5\\\\u5546\\\\u8d85\\\\u8fc7&nbsp;1.7&nbsp;\\\\u4e07\\\\u5bb6\\\\u3002</p>\\\\n  <p class=\\\\\\\"image-wrapper\\\\\\\"><img src=\\\\\\\"https://img.36krcdn.com/hsossms/20260416/v2_be218e6e86c348d68ff884314ab2ba18@46958_oswg75556oswg1080oswg328_img_000?x-oss-process=image/format,jpg/interlace,1\\\\\\\" /></p>\\\\n  <p>\\\\u800c\\\\u4e14\\\\uff0c\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u6253\\\\u5f00\\\\u4e86\\\\u6d77\\\\u5916\\\\u5e02\\\\u573a\\\\uff0c\\\\u7ed3\\\\u5408\\\\u4e86\\\\u5b83\\\\u534e\\\\u4e3a\\\\u7cfb\\\\u51fa\\\\u8eab\\\\u7684\\\\u8eab\\\\u4efd\\\\uff0c\\\\u8fd8\\\\u5e26\\\\u6765\\\\u4e86\\\\u4e00\\\\u70b9\\\\u4e0d\\\\u4e00\\\\u6837\\\\u7684\\\\u5473\\\\u9053\\\\uff1a</p>\\\\n  <p>\\\\u4ea7\\\\u54c1\\\\u6280\\\\u672f\\\\u8def\\\\u5f84\\\\u4e0e\\\\u534e\\\\u4e3a\\\\u6709\\\\u540c\\\\u6e90\\\\u6027\\\\uff0c\\\\u5374\\\\u901a\\\\u8fc7\\\\u6a21\\\\u5757\\\\u5316\\\\u53ef\\\\u5806\\\\u53e0+AI\\\\u96c6\\\\u6210\\\\u5b9e\\\\u73b0\\\\u5dee\\\\u5f02\\\\u5316\\\\uff0c\\\\u6700\\\\u7ec8\\\\u5728\\\\u6d77\\\\u5916\\\\u6253\\\\u5f00\\\\u4e00\\\\u756a\\\\u65b0\\\\u5929\\\\u5730...</p>\\\\n  <p>\\\\u4e00\\\\u4e2a\\\\u4e0d\\\\u53ef\\\\u591a\\\\u5f97\\\\u7684\\\\u7cbe\\\\u5f69\\\\u52b1\\\\u5fd7\\\\u6545\\\\u4e8b\\\\u3002</p>\\\\n  <p>\\\\u53ea\\\\u662f\\\\uff0c\\\\u534e\\\\u4e3a\\\\u7cfb\\\\u7684\\\\u5149\\\\u73af\\\\u7ed9\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u5e26\\\\u6765\\\\u4e86\\\\u5149\\\\u73af\\\\uff0c\\\\u4e5f\\\\u7ed9\\\\u5b83\\\\u7684\\\\u672a\\\\u6765\\\\u8499\\\\u4e0a\\\\u4e86\\\\u4e00\\\\u9053\\\\u9634\\\\u5f71\\\\u3002</p>\\\\n  <h2><strong>\\\\u534e\\\\u4e3a\\\\u7cfb\\\\u7684\\\\u201c\\\\u540c\\\\u95e8\\\\u4e4b\\\\u4e89\\\\u201d</strong></h2>\\\\n  <p>\\\\u5728\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u4e0a\\\\u5e02\\\\u4e4b\\\\u9645\\\\uff0c\\\\u4e00\\\\u7eb8\\\\u8bc9\\\\u72b6\\\\u6253\\\\u7834\\\\u4e86\\\\u5e73\\\\u9759\\\\u3002</p>\\\\n  <p>4&nbsp;\\\\u6708&nbsp;3&nbsp;\\\\u65e5\\\\uff0c\\\\u534e\\\\u4e3a\\\\u5df2\\\\u5411\\\\u5730\\\\u65b9\\\\u77e5\\\\u8bc6\\\\u4ea7\\\\u6743\\\\u5c40\\\\u63d0\\\\u4ea4\\\\u4e13\\\\u5229\\\\u4fb5\\\\u6743\\\\u7ea0\\\\u7eb7\\\\u5904\\\\u7406\\\\u8bf7\\\\u6c42\\\\u4e66\\\\uff0c\\\\u8bf7\\\\u6c42\\\\u5904\\\\u7406\\\\u601d\\\\u683c\\\\u53ca\\\\u5176\\\\u5173\\\\u8054\\\\u516c\\\\u53f8\\\\u6d89\\\\u5acc\\\\u4fb5\\\\u72af\\\\u4e13\\\\u5229\\\\u6743\\\\u7684\\\\u884c\\\\u4e3a\\\\uff1b</p>\\\\n  <p>\\\\u76ee\\\\u524d\\\\u4e8b\\\\u4ef6\\\\u4ecd\\\\u5904\\\\u4e8e\\\\u884c\\\\u653f\\\\u5904\\\\u7406\\\\u9636\\\\u6bb5\\\\uff0c\\\\u5c1a\\\\u672a\\\\u8fdb\\\\u5165\\\\u6cd5\\\\u9662\\\\u6b63\\\\u5f0f\\\\u8bc9\\\\u8bbc\\\\u3002</p>\\\\n  <p><strong>\\\\u6839\\\\u636e\\\\u516c\\\\u5f00\\\\u8d44\\\\u6599\\\\uff0c\\\\u8fd9\\\\u6b21\\\\u7ea0\\\\u7eb7\\\\u6d89\\\\u53ca\\\\u7684\\\\u4e24\\\\u9879\\\\u4e13\\\\u5229\\\\u5206\\\\u522b\\\\u662f\\\\u201c\\\\u9006\\\\u53d8\\\\u5668\\\\u6bcd\\\\u7ebf\\\\u7535\\\\u538b\\\\u7684\\\\u8c03\\\\u6574\\\\u65b9\\\\u6cd5\\\\u53ca\\\\u88c5\\\\u7f6e\\\\u201d\\\\u548c\\\\u201c\\\\u5168\\\\u57df\\\\u6700\\\\u5927\\\\u8f93\\\\u51fa\\\\u529f\\\\u7387\\\\u786e\\\\u5b9a\\\\u65b9\\\\u6cd5\\\\u4e0e\\\\u88c5\\\\u7f6e\\\\u201d\\\\u3002</strong></p>\\\\n  <p>\\\\u800c&nbsp;21&nbsp;\\\\u4e16\\\\u7eaa\\\\u7ecf\\\\u6d4e\\\\u62a5\\\\u9053\\\\u63f4\\\\u5f15\\\\u6d88\\\\u606f\\\\u79f0\\\\uff0c\\\\u534e\\\\u4e3a\\\\u5b9e\\\\u9645\\\\u4e3b\\\\u5f20\\\\u7684\\\\u4e13\\\\u5229\\\\u53ef\\\\u80fd\\\\u4e0d\\\\u6b62\\\\u4e24\\\\u9879\\\\uff0c\\\\u800c\\\\u662f\\\\u591a\\\\u8fbe&nbsp;10&nbsp;\\\\u4f59\\\\u9879\\\\u3002</p>\\\\n  <p>\\\\u5982\\\\u679c\\\\u662f\\\\u65e0\\\\u5173\\\\u75db\\\\u75d2\\\\u7684\\\\u4e13\\\\u5229\\\\u7ea0\\\\u7eb7\\\\uff0c\\\\u4e5f\\\\u5c31\\\\u7f62\\\\u4e86\\\\uff0c\\\\u53ef\\\\u8fd9\\\\u6b21\\\\u4e13\\\\u5229\\\\u7ea0\\\\u7eb7\\\\u6d89\\\\u53ca\\\\u7684\\\\uff0c\\\\u5374\\\\u662f\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u201c\\\\u7edd\\\\u5bf9\\\\u4e0d\\\\u80fd\\\\u51fa\\\\u4e8b\\\\u201d\\\\u7684\\\\u4ea7\\\\u54c1\\\\uff1aSigenStor\\\\u3002</p>\\\\n  <p>\\\\u4ece\\\\u5a92\\\\u4f53\\\\u62ab\\\\u9732\\\\u6765\\\\u770b\\\\uff0c\\\\u6d89\\\\u53ca\\\\u4ea7\\\\u54c1\\\\u4e3b\\\\u8981\\\\u5305\\\\u62ec\\\\uff1a&nbsp;</p>\\\\n  <p>&nbsp;SigenStor&nbsp;\\\\u5149\\\\u50a8\\\\u4e00\\\\u4f53\\\\u673a\\\\u3001Sigen Hybrid&nbsp;\\\\u5149\\\\u50a8\\\\u9006\\\\u53d8\\\\u5668\\\\u4ee5\\\\u53ca&nbsp;Sigen PV&nbsp;\\\\u5de5\\\\u5546\\\\u4e1a\\\\u5149\\\\u4f0f\\\\u9006\\\\u53d8\\\\u5668\\\\u3002</p>\\\\n  <p>\\\\u8fd9\\\\u4e9b\\\\u504f\\\\u504f\\\\u6b63\\\\u662f\\\\u5360\\\\u4e86\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u8425\\\\u6536&nbsp;90%&nbsp;\\\\u7684\\\\u4ea7\\\\u54c1\\\\u3002</p>\\\\n  <p>\\\\u56e0\\\\u6b64\\\\uff0c\\\\u62db\\\\u80a1\\\\u4e66\\\\u4e5f\\\\u5df2\\\\u7ecf\\\\u63d0\\\\u524d\\\\u63d0\\\\u9192\\\\u8fc7\\\\uff0c\\\\u516c\\\\u53f8\\\\u4e1a\\\\u52a1\\\\u5bf9&nbsp;SigenStor&nbsp;\\\\u4f9d\\\\u8d56\\\\u5ea6\\\\u8f83\\\\u9ad8\\\\uff0c\\\\u5982\\\\u679c\\\\u6838\\\\u5fc3\\\\u4ea7\\\\u54c1\\\\u9500\\\\u552e\\\\u53d7\\\\u5f71\\\\u54cd\\\\uff0c\\\\u53ef\\\\u80fd\\\\u5bf9\\\\u4e1a\\\\u52a1\\\\u548c\\\\u8d22\\\\u52a1\\\\u8868\\\\u73b0\\\\u9020\\\\u6210\\\\u91cd\\\\u5927\\\\u4e0d\\\\u5229\\\\u5f71\\\\u54cd\\\\u3002</p>\\\\n  <p>\\\\u4e5f\\\\u5c31\\\\u662f\\\\u8bf4\\\\uff0c\\\\u82e5\\\\u8ba4\\\\u5b9a\\\\u4fb5\\\\u6743\\\\uff0c\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u53ef\\\\u80fd\\\\u9762\\\\u4e34\\\\u505c\\\\u6b62\\\\u751f\\\\u4ea7/\\\\u9500\\\\u552e\\\\u7684SigenStor&nbsp;\\\\u548c\\\\u76f8\\\\u5173\\\\u4ea7\\\\u54c1\\\\u3001\\\\u652f\\\\u4ed8\\\\u8d54\\\\u507f/\\\\u8bb8\\\\u53ef\\\\u8d39\\\\u3001\\\\u4ea7\\\\u54c1\\\\u6574\\\\u6539\\\\u3001\\\\u54c1\\\\u724c\\\\u91cd\\\\u5efa\\\\uff0c\\\\u751a\\\\u81f3\\\\u5bf9\\\\u5ba2\\\\u6237/\\\\u5408\\\\u4f5c\\\\u4f19\\\\u4f34\\\\u7684\\\\u8fde\\\\u5e26\\\\u8d23\\\\u4efb\\\\u7b49\\\\u4e00\\\\u7cfb\\\\u5217\\\\u9ebb\\\\u70e6\\\\u3002</p>\\\\n  <p><strong>\\\\u800c\\\\u5149\\\\u662f\\\\u505c\\\\u6b62\\\\u751f\\\\u4ea7/\\\\u9500\\\\u552e\\\\u7684SigenStor\\\\u548c\\\\u76f8\\\\u5173\\\\u4ea7\\\\u54c1\\\\uff0c\\\\u5c31\\\\u6709\\\\u53ef\\\\u80fd\\\\u6210\\\\u4e3a\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u7684\\\\u706d\\\\u9876\\\\u4e4b\\\\u707e\\\\u3002</strong></p>\\\\n  <p>\\\\u53ea\\\\u4e0d\\\\u8fc7\\\\uff0c\\\\u81f3\\\\u5c11\\\\u4ece\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u6302\\\\u724c\\\\u9996\\\\u65e5\\\\u7684\\\\u60c5\\\\u51b5\\\\u6765\\\\u770b\\\\uff0c\\\\u6295\\\\u8d44\\\\u8005\\\\u663e\\\\u7136\\\\u66f4\\\\u613f\\\\u610f\\\\u5148\\\\u770b\\\\u589e\\\\u957f\\\\uff0c\\\\u518d\\\\u770b\\\\u5b98\\\\u53f8\\\\u3002</p>\\\\n  <p>\\\\u6bd5\\\\u7adf\\\\uff0c\\\\u601d\\\\u683c\\\\u8e29\\\\u4e2d\\\\u7684\\\\u662f\\\\u5f53\\\\u524d\\\\u6700\\\\u738b\\\\u70b8\\\\u7684\\\\u8d5b\\\\u9053\\\\u7ec4\\\\u5408\\\\uff1aAI+\\\\u50a8\\\\u80fd\\\\uff0c\\\\u8fd8\\\\u6709\\\\u6d77\\\\u5916\\\\u9ad8\\\\u7aef\\\\u5e02\\\\u573a\\\\uff0c\\\\u4ee5\\\\u53ca\\\\u4e00\\\\u4e2a\\\\u5df2\\\\u7ecf\\\\u88ab\\\\u9a8c\\\\u8bc1\\\\u8fc7\\\\u7684\\\\u5f3a\\\\u529b\\\\u4ea7\\\\u54c1\\\\u3002</p>\\\\n  <p>AI&nbsp;\\\\u7b97\\\\u529b\\\\u589e\\\\u957f\\\\u5e26\\\\u6765\\\\u7684\\\\u7535\\\\u529b\\\\u9700\\\\u6c42\\\\u3001\\\\u5168\\\\u7403\\\\u80fd\\\\u6e90\\\\u8f6c\\\\u578b\\\\u5e26\\\\u6765\\\\u7684\\\\u50a8\\\\u80fd\\\\u9700\\\\u6c42\\\\uff0c\\\\u518d\\\\u53e0\\\\u52a0&nbsp;AI&nbsp;\\\\u5bf9\\\\u80fd\\\\u6e90\\\\u7ba1\\\\u7406\\\\u7cfb\\\\u7edf\\\\u672c\\\\u8eab\\\\u7684\\\\u63d0\\\\u6548\\\\u60f3\\\\u8c61\\\\uff0c\\\\u5de8\\\\u5927\\\\u7684\\\\u884c\\\\u4e1a\\\\u524d\\\\u666f\\\\uff0c\\\\u5f88\\\\u96be\\\\u8ba9\\\\u6295\\\\u8d44\\\\u4eba\\\\u56e0\\\\u4e3a\\\\u4e00\\\\u5b97\\\\u8fd8\\\\u5904\\\\u4e8e\\\\u884c\\\\u653f\\\\u5904\\\\u7406\\\\u9636\\\\u6bb5\\\\u7684\\\\u7ea0\\\\u7eb7\\\\u505c\\\\u4e0b\\\\u811a\\\\u6b65\\\\u3002</p>\\\\n  <p>\\\\u5f53\\\\u7136\\\\uff0c\\\\u5bf9\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u6765\\\\u8bf4\\\\uff0c\\\\u6216\\\\u8bb8\\\\u6bd4\\\\u8d77\\\\u4e13\\\\u5229\\\\u7ea0\\\\u7eb7\\\\uff0c\\\\u66f4\\\\u5927\\\\u7684\\\\u9ebb\\\\u70e6\\\\uff0c<strong>\\\\u662f\\\\u4ea7\\\\u54c1\\\\u7ed3\\\\u6784\\\\u8fc7\\\\u4e8e\\\\u5355\\\\u4e00\\\\u3001\\\\u805a\\\\u7126\\\\u7814\\\\u53d1\\\\u8bbe\\\\u8ba1\\\\u4e0e\\\\u7cfb\\\\u7edf\\\\u96c6\\\\u6210\\\\u800c\\\\u5bf9\\\\u4f9b\\\\u5e94\\\\u94fe\\\\u4f9d\\\\u8d56\\\\u8f83\\\\u5f3a\\\\uff0c\\\\u548c\\\\u50a8\\\\u80fd\\\\u8d5b\\\\u9053\\\\u6d77\\\\u5916\\\\u5de8\\\\u5934\\\\u56f4\\\\u527f\\\\u7b49\\\\u4e00\\\\u7cfb\\\\u5217\\\\u95ee\\\\u9898\\\\u3002</strong></p>\\\\n  <p>\\\\u5c3d\\\\u7ba1\\\\u4e0a\\\\u5e02\\\\u9996\\\\u5929\\\\u5c31\\\\u62ff\\\\u5230\\\\u4e86\\\\u6cfc\\\\u5929\\\\u5bcc\\\\u8d35\\\\uff0c\\\\u516c\\\\u53f8\\\\u7684\\\\u5e02\\\\u503c\\\\u4e5f\\\\u7a81\\\\u7834\\\\u4e86 &nbsp;1600 &nbsp;\\\\u4ebf\\\\uff0c\\\\u4f46\\\\u601d\\\\u683c\\\\u65b0\\\\u80fd\\\\u6e90\\\\u7684\\\\u6311\\\\u6218\\\\uff0c\\\\u624d\\\\u521a\\\\u521a\\\\u5f00\\\\u59cb\\\\u3002&nbsp;</p>\\\\n  <p class=\\\\\\\"editor-note\\\\\\\">\\\\u672c\\\\u6587\\\\u6765\\\\u81ea\\\\u5fae\\\\u4fe1\\\\u516c\\\\u4f17\\\\u53f7<a href=\\\\\\\"https://mp.weixin.qq.com/s/XE0DrceTJirIBRdFxBp7qA\\\\\\\" rel=\\\\\\\"noopener noreferrer\\\\\\\" target=\\\\\\\"_blank\\\\\\\">\\\\u201c\\\\u84dd\\\\u5b57\\\\u8ba1\\\\u5212\\\\u201d</a>\\\\uff0c\\\\u4f5c\\\\u8005\\\\uff1aHayward\\\\uff0c36\\\\u6c2a\\\\u7ecf\\\\u6388\\\\u6743\\\\u53d1\\\\u5e03\\\\u3002</p>\\\"}, \\\"source\\\": {\\\"title\\\": \\\"36\\\\u6c2a\\\"}, \\\"authors\\\": [{\\\"name\\\": \\\"\\\\u84dd\\\\u5b57\\\\u8ba1\\\\u5212\\\"}], \\\"author\\\": \\\"\\\\u84dd\\\\u5b57\\\\u8ba1\\\\u5212\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"\\\\u84dd\\\\u5b57\\\\u8ba1\\\\u5212\\\"}, \\\"content\\\": [{\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u76f4\\\\u51fb\\\\u547d\\\\u95e8\\\\u7684\\\\u4e13\\\\u5229\\\\u7ea0\\\\u7eb7\\\"}]}\", \"published_at\": \"2026-04-16 18:36:36\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:06:38');
INSERT INTO `news_detail` VALUES (62, 2213, 18, '硬件与半导体出海', '台积电：AI 界“真霸主”，谁能撼动？', '', '<p>台积电（TSMC）于北京时间2026年4月16日下午，美股盘前发布了2026年第一季度财报（截止2026年3月），要点如下：</p>\n<p><strong>1、收入端</strong>：<strong>台积电本季度收入359亿美元，环比增长6.4%，</strong>增长主要来自于AI芯片的带动，其中客户的AI芯片已经开始转移至3nm平台。即使本季度受到美元兑新台币升值的影响，但季度收入还是超了指引区间上限（346-358亿美元）。<strong>若按新台币口径，公司本季度收入环增8.4%，是明显好于公司指引的（环增6%）。</strong></p>\n<p><strong>从量价关系看（等效12寸片）：①台积电的晶圆出货量4174千片，环比增长5.4%；②台积电的晶圆单晶圆收入（等效12寸片）8601美元/片，环比增长1%。</strong></p>\n<p><strong>2、毛利率：公司本季度毛利率66.2%，好于公司指引区间（63-65%）。</strong>具体来看，<strong>本季度公司毛利率提升主要受均价提升和单位成本下降的双重影响，规模效应下对单位固定成本有所稀释</strong>。</p>\n<p>在AI需求的带动下，公司毛利率已经站稳在60%以上。公司此前把长期毛利率（5年以上维度）从53%提升到了56%。</p>\n<p><strong>3、具体业务进展情况：制程、下游应用和地区</strong></p>\n<ul>\n<li><strong>a.分制程看</strong>：台积电本季度7nm以下先进制程的占比维持在74%的相对高位。受AI需求的推动，公司当前3nm和5nm产能已经满载，两项收入占比分别为25%和36%。<strong>随着公司2nm量产，AI芯片将从5nm往3nm转移，公司收入结构有望进一步向先进制程倾斜</strong>。</li>\n<li><strong>b.下游应用端</strong>：公司本季度收入环增主要来自于AI芯片的需求带动，手机业务本季度出现季节性回落的表现。<strong>在英伟达、博通等AI芯片需求的影响下，高性能计算是公司最大的收入来源，本季度达到219亿美元，收入占比达到61%。</strong></li>\n<li><strong>c.分地区收入</strong>：北美地区还是公司最大的收入来源，涵盖了英伟达、苹果、AMD等大客户，本季度收入占比76%。<strong>本季度中国大陆地区收入为25亿美元左右，收入占比7%，是公司第三大收入来源</strong>。</li>\n</ul>\n<p><strong>4、资本开支</strong>：台积电本季度资本开支111亿美元，<strong>由于公司指引2026年全年资本开支上调至520-560亿美元的区间较高水位，那么后面三个季度的资本开支有望达到440亿美元左右，可见公司的资本开支主要集中在下半年</strong>。</p>\n<p><strong>5、台积电业绩指引</strong>：<strong>2026年第二季度公司预期收入390-402亿美元（好于上调后的买方预期388亿美元）和毛利率65.5-67.5%（接近于上调后的买方预期66-66.5%）</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_581e2b95461141d78f3e26c7e2a52bba@000000_oswg235175oswg1080oswg430_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>海豚君整体观点：上调全年指引，产业链地位稳固</p>\n<p><strong>台积电本次财报依然是不错的，收入的增长在月度经营数据中基本体现。</strong>本次财报中的营收359亿美元，是好于指引上限（358亿），其中还受一部分美元/新台币升值的影响。<strong>若以新台币口径来看，本季度收入环比增速为8.4%，实际表现是更好的。</strong></p>\n<p>在本次财报中，相对更重要的是<strong>毛利率、资本开支和未来经营面的指引：</strong></p>\n<p><strong>①毛利率</strong>：台积电本季度的毛利率达到了66.2%，接近上调后的买方预期（66-66.5%），主要是受均价提升和单位成本下降（规模效应）的双重影响。海豚君在原文中会具体分拆；</p>\n<p><strong>公司将下季度毛利率指引直接提高到65.5-67.5%，也基本符合上调后的买方预期（66%-66.5%）</strong>。主要也是在AI芯片逐渐从5nm转移至3nm平台后，对公司产品均价和毛利率的影响是正向的。</p>\n<p><strong>②资本开支</strong>：台积电本季度资本开支111亿美元，由于<strong>公司将2026年资本开支计划再度上调至520-560亿美元的较高水位（此前是520-560亿），</strong>对应着台积电在随后三个季度的资本开支将有望达到440亿美元左右。</p>\n<p>台积电的资本开支也将主要集中在下半年（平均单季度145-150亿美元），这也是与昨日ASML全年“前低后高”的指引相吻合的。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_4e640d66778f4d00ad769d6ce9457320@000000_oswg52789oswg795oswg456_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>③经营面指引</strong>：<strong>公司本次将2026年的营收增长目标上调至“30%以上”（此前是30%左右），</strong>这在彰显公司信心的同时，也是符合市场主流机构的期待的。</p>\n<p><strong>在台积电的核心业绩表现之外，市场还关注着台积电的以下几个方面：</strong></p>\n<p><strong>a）CoWoS产能</strong>：当前主流的AI芯片（英伟达、AMD和TPU）都采用了CoWoS的封装方式，而全球的CoWoS产能基本都来自于台积电（占比达到9成以上）。<strong>即使芯片设计厂想要拉高产量，CoWoS的产能分配将直接影响AI芯片的出货情况，这也让台积电成为AI产业链中卡脖子的关键一环</strong>。</p>\n<p>结合行业数据及市场预期，台积电目前CoWoS的月产能约8万片左右，至2026年末有望扩大至12万片左右。<strong>海豚君预估2026年台积电CoWoS的出货量有望达到110万片以上，同比增长77%，其中英伟达和博通是最主要的客户。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1ab610a9f3b54197896956ba3be9c692@000000_oswg43662oswg721oswg396_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>b）2nm进展及制程迁移</strong>：台积电的2nm在2026年进入大规模量产爬坡，公司会把苹果、高通等部分手机芯片的需求迁移至2nm的平台。与此同时，AI芯片已经全面升级至3nm时代，其中<strong>Rubin、MI350以及谷歌TPUv7都将使用台积电的3nm工艺</strong>进行生产。</p>\n<p>随着工艺结构向更先进的制程节点迁移，在带动产品均价提升的同时，也将促使公司资本开支的继续增长。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_6d7d01c82eda40d0a2e9ae5dd2314303@000000_oswg81092oswg1080oswg399_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>c）代工市场的竞争：在台积电2nm开启量产之后，三星和英特尔也紧跟着分别进入了SF2（2nm）和18A（1.8nm）节点。</strong></p>\n<p><strong>然而英特尔和三星两家与台积电还是存在着明显的差距：①三星和英特尔当前最新节点的晶体管密度还不到250MTr/mm²</strong>，甚至低于台积电上一代的N3P（294 MTr/mm²）；<strong>②英特尔和三星的良率相对较低，当前量产主要是在自有的芯片方面，</strong>而台积电有着大量的核心外部客户<strong>。</strong></p>\n<p><strong>在当前AI芯片供应紧张的情况下，如果英特尔和三星能把良率提升，也有机会获得部分“溢出订单”。尤其是在台积电产能紧张的情况下，谷歌和英特尔在近期宣布扩大合作，其中也有寻求缓解供应瓶颈的“潜在考虑”。</strong></p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_76e9c0131e534dca968f81047553361d@000000_oswg43799oswg932oswg281_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>结合台积电的当前市值（1.9万亿美元），大致对应公司2026年净利润约为24倍PE左右（假定营收同比+38%，毛利率64.7%，税率16.5%）。</strong></p>\n<p><strong>回到财报本身，台积电本次交出的“成绩”是不错的，但也谈不上“炸裂”。市场主流机构对公司的毛利率已经上调至66%附近，这方面是符合期待的。</strong></p>\n<p>相对不错的是，季度指引超出了市场上调后的预期。而由于公司给出了全年营收指引，下季度收入的影响就弱化了。</p>\n<p><strong>公司将2026年全年收入增速指引上调至“30%以上”（此前是30%左右），由于主流机构原本对公司的增速预期是超出30%的，这也并不是大的“惊喜”。台积电管理层的指引，一贯以来都是“相对谨慎”的风格。</strong></p>\n<p><strong>台积电在收入持续创新高的同时，能将毛利率提升到了66%附近，本身也是产业链话语权的体现。在AI芯片的制造环节，台积电具备CoWoS技术的明显优势，几乎揽下了当前市场上所有AI芯片的制造需求</strong>。</p>\n<p>在供应端产能困扰的影响下，下游厂商在试图寻求“备选方案”，比如近期谷歌与英特尔的加大合作。</p>\n<p><strong>而在英特尔/三星的技术及良率还未突破之前，台积电的CoWoS还是市场中的唯一选择。不论下游市场格局如何，公司依然是AI芯片链中最稳健的一环。</strong></p>\n<p><strong>以下是详细分析</strong></p>\n<h2><strong>一、收入端：量价齐升</strong></h2>\n<p><strong>台积电在2026年第一季度实现营收359亿美元， 好于此前指引区间（346-358亿美元）。</strong>本季度收入环比增长6.4%，主要受AI芯片需求增长的推动，当前逐步从5nm转移至3nm平台。</p>\n<p><strong>本季度美元/新台币的升值对增速也有一定的稀释影响，若从新台币口径看，公司本季度收入环比增长8.4%，实际表现是更好的</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_905eb90919fa43d18eb5b2899058f2ff@000000_oswg54410oswg780oswg474_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>台积电的季度收入，由于每月经营指标的公布，市场预期已经充分。</strong>而本季度台积电收入中，价格和出货量分别如何变化的呢？</p>\n<p>海豚君从量和价的维度，来观察台积电本季度收入增长的主要推动力：</p>\n<p><strong>1）量的维度</strong>：<strong>2026Q1台积电的晶圆出货量4174千片，环比增长5.4%。公司将2026年的资本开支目标上调至520-560亿美元的较高水位，年度增加130-150亿美元。大幅提升的资本开支，是公司持续扩产的明确信号。</strong></p>\n<p><strong>2）价的维度</strong>：<strong>2026Q1台积电的晶圆单晶圆收入（等效12寸片）8601美元/片，环比增长1%</strong>。台积电的2nm工艺已经开始量产，随后AI芯片从5nm转向3nm，公司整体的产品结构将进一步向先进制程倾斜，产品均价将继续提升。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_c5d356d1674d4030af1caceafd77921a@000000_oswg76725oswg806oswg448_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<h2><strong>二、毛利及毛利率：持续走高，突破66%</strong></h2>\n<p><strong>台积电在2026年第一季度实现毛利238亿美元，环比增长13%</strong>。其中<strong>毛利率66.2%</strong>，环比提升3.9pct，<strong>接近上调后市场预期（66-66.5%），受均价提升和单位成本下降的双重影响</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_ab8fbd54bfdf4c13bbc1fd77678aa32c@000000_oswg47048oswg795oswg457_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>市场对台积电最为关心的两项数据便是，收入和毛利率。由于每月经营数据的公布，季度收入基本已被市场预期。而毛利率则是本次季报中，市场关注的焦点之一。海豚君将对分析本季度毛利率提升的主要驱动力：</p>\n<p><strong>“毛利=单晶圆收入-固定成本-可变成本”</strong></p>\n<p><strong>1）单片晶圆收入（等效12寸）</strong>：<strong>本季度台积电单晶圆收入约8601美元/片，环比提升85美元/片。</strong></p>\n<p>通常而言，Q1受手机芯片出货占比下滑，公司产品均价会出现季节性回落的情况。<strong>而由于当前AI芯片从5nm逐步迁移至3nm平台，推动产品均价的“反季节性”提升</strong>。</p>\n<p><strong>2）固定成本（折旧摊销）</strong>：<strong>本季度台积电平均固定成本约1255美元/片，环比减少65美元/片。</strong></p>\n<p>在新台币的口径下，公司的折旧摊销总量环比是增加的；<strong>但在美元升值的影响下，美元口径的折旧摊销总量基本持平。出货量增加的规模效应下，单位固定成本出现下滑</strong>；</p>\n<p><strong>3）可变成本（其他制造费用）</strong>：<strong>本季度台积电平均可变成本约1648美元/片，环比减少240美元/片，</strong>受公司本季度其他制造费用出现“季节性回落”的影响。</p>\n<p><strong>综合以上拆分，本季度台积电单片毛利5698美元/片，环比增加390美元</strong>。公司本季度毛利率提升的原因是价格端上升和单位成本下降的双重影响。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_275f72e42ea54b84bb7f96826feb8a83@000000_oswg54222oswg815oswg456_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<h2><strong>三、晶圆结构端：AI芯片向3nm迁移，平滑“季度扰动”</strong></h2>\n<p><strong>3.1晶圆收入占比（按应用类型）</strong></p>\n<p><strong>高性能计算业务（HPC）依然是公司最大的收入来源，本季度收入占比61%。在英伟达GB系列等AI芯片的带动下，公司本季度HPC收入为219亿美元左右，环比增长18%，</strong>其中主要是英伟达Blackwell芯片和博通TPU出货增加的带动。</p>\n<p>手机业务出现“季节性回落”的表现。<strong>本季度手机业务收入93.3亿美元，环比下滑13%。</strong>手机和HPC两项业务合计占比达到87%，是台积电最主要下游应用领域。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_1832230cc19548129c5c20db00cacc22@000000_oswg43254oswg761oswg458_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>3.2晶圆收入占比（按制程节点）</strong></p>\n<p><strong>本季度7nm以下的收入占比维持在74%，先进制程领域是公司的核心收入来源。</strong>具体来看，本季度公司3nm收入占比为25%，5nm的收入占比维持在36%。</p>\n<p><strong>台积电通常在一季度会出现“季节性下滑”的迹象，主要是最先进制程（如3nm）制程基本是提供给手机客户。</strong>在手机及相关产品在“四季度出货旺季”后，一季度环比明显回落。</p>\n<p><strong>公司当前将AI芯片从5nm迁移至3nm平台，较好地平滑了“季节性变化”的扰动，使得公司一季度收入实现了季度的环增。</strong></p>\n<p><strong>随着公司将3nm的手机芯片等产品陆续转移至2nm平台，AI芯片（Rubin、TPU等）将逐步迁移至3nm平台。</strong>公司的制程结构进一步向更先进节点迁移，一方面能带动公司产品均价继续上行，另一方面也能再次扩大与竞争对手的优势。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_ea8dc9a454e4404b8c9c381f91879d8a@000000_oswg48007oswg778oswg461_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p><strong>3.3晶圆收入占比（按地区）</strong></p>\n<p>从各地区收入来看，<strong>北美地区仍是台积电最大的收入来源，收入占比为76%</strong>。这是由于北美地区有苹果、英伟达、AMD、高通等大客户，使得台积电和美国之间有很强的商业绑定关系。</p>\n<p>除北美以外，亚太地区和中国大陆地区是其余的两大收入来源，本季度占比分别为9%和7%。<strong>本季度中国大陆地区的收入维持在25亿美元左右，依然是公司的前三大收入来源之一，在台积电的占比中下降至1成以下</strong>。</p>\n<p><img src=\"https://img.36krcdn.com/hsossms/20260416/v2_8db885299e994b11a143fe8c7dd9f842@000000_oswg41796oswg766oswg446_img_000?x-oss-process=image/format,jpg/interlace,1\"></p>\n<p>本文来自微信公众号 <a href=\"https://mp.weixin.qq.com/s?__biz=MzE5MTU3MzA2OQ==&amp;mid=2247571258&amp;idx=1&amp;sn=71785d1915beec1693b2a842288e3f1e&amp;chksm=97f98ef5ac4b9aa3919e45099bf036bc6df1c7a9d4c831978815cfb21b4bb79e9d24bdc24682&amp;scene=0&amp;xtrack=1#rd\">“海豚投研”（ID：haituntouyan）</a>，作者：海豚君，36氪经授权发布。</p>', 'https://36kr.com/p/3769365943288578?f=rss', 0, '', '{\"summary\": \"帮助出海半导体及AI产业链企业了解全球AI芯片代工市场格局，把握行业龙头发展动态与竞争趋势\", \"abstract\": \"本文深度解析台积电2026年第一季度财报，其当期营收、毛利率均超出此前指引，业绩增长主要由AI芯片需求拉动。台积电当前先进制程收入占比超七成，AI芯片正逐步从5nm向3nm迁移，公司上调全年资本开支用于扩产以应对旺盛需求。台积电在CoWoS封装技术、先进制程良率上优势显著，占据全球绝大多数AI芯片代工份额，龙头地位短期内难以撼动。三星、英特尔在先进制程领域仍与台积电存在明显差距，下游AI芯片厂商已开始布局备选供应方案。\", \"keywords\": [\"台积电\", \"AI芯片\", \"先进制程\", \"CoWoS产能\", \"半导体代工\", \"资本开支\", \"毛利率\", \"财报\"], \"policy_risk\": {\"market_risk\": \"AI芯片代工产能紧张，下游厂商已开始寻求替代供应方案，三星、英特尔若实现技术良率突破，将分流部分订单，行业竞争格局存在潜在变动\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://36kr.com/p/3769365943288578?f=rss\", \"title\": \"台积电：AI 界“真霸主”，谁能撼动？\", \"source\": \"https://36kr.com/feed-article\", \"content\": \"<p>台积电（TSMC）于北京时间2026年4月16日下午，美股盘前发布了2026年第一季度财报（截止2026年3月），要点如下：</p>\\n<p><strong>1、收入端</strong>：<strong>台积电本季度收入359亿美元，环比增长6.4%，</strong>增长主要来自于AI芯片的带动，其中客户的AI芯片已经开始转移至3nm平台。即使本季度受到美元兑新台币升值的影响，但季度收入还是超了指引区间上限（346-358亿美元）。<strong>若按新台币口径，公司本季度收入环增8.4%，是明显好于公司指引的（环增6%）。</strong></p>\\n<p><strong>从量价关系看（等效12寸片）：①台积电的晶圆出货量4174千片，环比增长5.4%；②台积电的晶圆单晶圆收入（等效12寸片）8601美元/片，环比增长1%。</strong></p>\\n<p><strong>2、毛利率：公司本季度毛利率66.2%，好于公司指引区间（63-65%）。</strong>具体来看，<strong>本季度公司毛利率提升主要受均价提升和单位成本下降的双重影响，规模效应下对单位固定成本有所稀释</strong>。</p>\\n<p>在AI需求的带动下，公司毛利率已经站稳在60%以上。公司此前把长期毛利率（5年以上维度）从53%提升到了56%。</p>\\n<p><strong>3、具体业务进展情况：制程、下游应用和地区</strong></p>\\n<ul>\\n<li><strong>a.分制程看</strong>：台积电本季度7nm以下先进制程的占比维持在74%的相对高位。受AI需求的推动，公司当前3nm和5nm产能已经满载，两项收入占比分别为25%和36%。<strong>随着公司2nm量产，AI芯片将从5nm往3nm转移，公司收入结构有望进一步向先进制程倾斜</strong>。</li>\\n<li><strong>b.下游应用端</strong>：公司本季度收入环增主要来自于AI芯片的需求带动，手机业务本季度出现季节性回落的表现。<strong>在英伟达、博通等AI芯片需求的影响下，高性能计算是公司最大的收入来源，本季度达到219亿美元，收入占比达到61%。</strong></li>\\n<li><strong>c.分地区收入</strong>：北美地区还是公司最大的收入来源，涵盖了英伟达、苹果、AMD等大客户，本季度收入占比76%。<strong>本季度中国大陆地区收入为25亿美元左右，收入占比7%，是公司第三大收入来源</strong>。</li>\\n</ul>\\n<p><strong>4、资本开支</strong>：台积电本季度资本开支111亿美元，<strong>由于公司指引2026年全年资本开支上调至520-560亿美元的区间较高水位，那么后面三个季度的资本开支有望达到440亿美元左右，可见公司的资本开支主要集中在下半年</strong>。</p>\\n<p><strong>5、台积电业绩指引</strong>：<strong>2026年第二季度公司预期收入390-402亿美元（好于上调后的买方预期388亿美元）和毛利率65.5-67.5%（接近于上调后的买方预期66-66.5%）</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_581e2b95461141d78f3e26c7e2a52bba@000000_oswg235175oswg1080oswg430_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>海豚君整体观点：上调全年指引，产业链地位稳固</p>\\n<p><strong>台积电本次财报依然是不错的，收入的增长在月度经营数据中基本体现。</strong>本次财报中的营收359亿美元，是好于指引上限（358亿），其中还受一部分美元/新台币升值的影响。<strong>若以新台币口径来看，本季度收入环比增速为8.4%，实际表现是更好的。</strong></p>\\n<p>在本次财报中，相对更重要的是<strong>毛利率、资本开支和未来经营面的指引：</strong></p>\\n<p><strong>①毛利率</strong>：台积电本季度的毛利率达到了66.2%，接近上调后的买方预期（66-66.5%），主要是受均价提升和单位成本下降（规模效应）的双重影响。海豚君在原文中会具体分拆；</p>\\n<p><strong>公司将下季度毛利率指引直接提高到65.5-67.5%，也基本符合上调后的买方预期（66%-66.5%）</strong>。主要也是在AI芯片逐渐从5nm转移至3nm平台后，对公司产品均价和毛利率的影响是正向的。</p>\\n<p><strong>②资本开支</strong>：台积电本季度资本开支111亿美元，由于<strong>公司将2026年资本开支计划再度上调至520-560亿美元的较高水位（此前是520-560亿），</strong>对应着台积电在随后三个季度的资本开支将有望达到440亿美元左右。</p>\\n<p>台积电的资本开支也将主要集中在下半年（平均单季度145-150亿美元），这也是与昨日ASML全年“前低后高”的指引相吻合的。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_4e640d66778f4d00ad769d6ce9457320@000000_oswg52789oswg795oswg456_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>③经营面指引</strong>：<strong>公司本次将2026年的营收增长目标上调至“30%以上”（此前是30%左右），</strong>这在彰显公司信心的同时，也是符合市场主流机构的期待的。</p>\\n<p><strong>在台积电的核心业绩表现之外，市场还关注着台积电的以下几个方面：</strong></p>\\n<p><strong>a）CoWoS产能</strong>：当前主流的AI芯片（英伟达、AMD和TPU）都采用了CoWoS的封装方式，而全球的CoWoS产能基本都来自于台积电（占比达到9成以上）。<strong>即使芯片设计厂想要拉高产量，CoWoS的产能分配将直接影响AI芯片的出货情况，这也让台积电成为AI产业链中卡脖子的关键一环</strong>。</p>\\n<p>结合行业数据及市场预期，台积电目前CoWoS的月产能约8万片左右，至2026年末有望扩大至12万片左右。<strong>海豚君预估2026年台积电CoWoS的出货量有望达到110万片以上，同比增长77%，其中英伟达和博通是最主要的客户。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1ab610a9f3b54197896956ba3be9c692@000000_oswg43662oswg721oswg396_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>b）2nm进展及制程迁移</strong>：台积电的2nm在2026年进入大规模量产爬坡，公司会把苹果、高通等部分手机芯片的需求迁移至2nm的平台。与此同时，AI芯片已经全面升级至3nm时代，其中<strong>Rubin、MI350以及谷歌TPUv7都将使用台积电的3nm工艺</strong>进行生产。</p>\\n<p>随着工艺结构向更先进的制程节点迁移，在带动产品均价提升的同时，也将促使公司资本开支的继续增长。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_6d7d01c82eda40d0a2e9ae5dd2314303@000000_oswg81092oswg1080oswg399_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>c）代工市场的竞争：在台积电2nm开启量产之后，三星和英特尔也紧跟着分别进入了SF2（2nm）和18A（1.8nm）节点。</strong></p>\\n<p><strong>然而英特尔和三星两家与台积电还是存在着明显的差距：①三星和英特尔当前最新节点的晶体管密度还不到250MTr/mm²</strong>，甚至低于台积电上一代的N3P（294 MTr/mm²）；<strong>②英特尔和三星的良率相对较低，当前量产主要是在自有的芯片方面，</strong>而台积电有着大量的核心外部客户<strong>。</strong></p>\\n<p><strong>在当前AI芯片供应紧张的情况下，如果英特尔和三星能把良率提升，也有机会获得部分“溢出订单”。尤其是在台积电产能紧张的情况下，谷歌和英特尔在近期宣布扩大合作，其中也有寻求缓解供应瓶颈的“潜在考虑”。</strong></p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_76e9c0131e534dca968f81047553361d@000000_oswg43799oswg932oswg281_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>结合台积电的当前市值（1.9万亿美元），大致对应公司2026年净利润约为24倍PE左右（假定营收同比+38%，毛利率64.7%，税率16.5%）。</strong></p>\\n<p><strong>回到财报本身，台积电本次交出的“成绩”是不错的，但也谈不上“炸裂”。市场主流机构对公司的毛利率已经上调至66%附近，这方面是符合期待的。</strong></p>\\n<p>相对不错的是，季度指引超出了市场上调后的预期。而由于公司给出了全年营收指引，下季度收入的影响就弱化了。</p>\\n<p><strong>公司将2026年全年收入增速指引上调至“30%以上”（此前是30%左右），由于主流机构原本对公司的增速预期是超出30%的，这也并不是大的“惊喜”。台积电管理层的指引，一贯以来都是“相对谨慎”的风格。</strong></p>\\n<p><strong>台积电在收入持续创新高的同时，能将毛利率提升到了66%附近，本身也是产业链话语权的体现。在AI芯片的制造环节，台积电具备CoWoS技术的明显优势，几乎揽下了当前市场上所有AI芯片的制造需求</strong>。</p>\\n<p>在供应端产能困扰的影响下，下游厂商在试图寻求“备选方案”，比如近期谷歌与英特尔的加大合作。</p>\\n<p><strong>而在英特尔/三星的技术及良率还未突破之前，台积电的CoWoS还是市场中的唯一选择。不论下游市场格局如何，公司依然是AI芯片链中最稳健的一环。</strong></p>\\n<p><strong>以下是详细分析</strong></p>\\n<h2><strong>一、收入端：量价齐升</strong></h2>\\n<p><strong>台积电在2026年第一季度实现营收359亿美元， 好于此前指引区间（346-358亿美元）。</strong>本季度收入环比增长6.4%，主要受AI芯片需求增长的推动，当前逐步从5nm转移至3nm平台。</p>\\n<p><strong>本季度美元/新台币的升值对增速也有一定的稀释影响，若从新台币口径看，公司本季度收入环比增长8.4%，实际表现是更好的</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_905eb90919fa43d18eb5b2899058f2ff@000000_oswg54410oswg780oswg474_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>台积电的季度收入，由于每月经营指标的公布，市场预期已经充分。</strong>而本季度台积电收入中，价格和出货量分别如何变化的呢？</p>\\n<p>海豚君从量和价的维度，来观察台积电本季度收入增长的主要推动力：</p>\\n<p><strong>1）量的维度</strong>：<strong>2026Q1台积电的晶圆出货量4174千片，环比增长5.4%。公司将2026年的资本开支目标上调至520-560亿美元的较高水位，年度增加130-150亿美元。大幅提升的资本开支，是公司持续扩产的明确信号。</strong></p>\\n<p><strong>2）价的维度</strong>：<strong>2026Q1台积电的晶圆单晶圆收入（等效12寸片）8601美元/片，环比增长1%</strong>。台积电的2nm工艺已经开始量产，随后AI芯片从5nm转向3nm，公司整体的产品结构将进一步向先进制程倾斜，产品均价将继续提升。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_c5d356d1674d4030af1caceafd77921a@000000_oswg76725oswg806oswg448_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<h2><strong>二、毛利及毛利率：持续走高，突破66%</strong></h2>\\n<p><strong>台积电在2026年第一季度实现毛利238亿美元，环比增长13%</strong>。其中<strong>毛利率66.2%</strong>，环比提升3.9pct，<strong>接近上调后市场预期（66-66.5%），受均价提升和单位成本下降的双重影响</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ab8fbd54bfdf4c13bbc1fd77678aa32c@000000_oswg47048oswg795oswg457_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>市场对台积电最为关心的两项数据便是，收入和毛利率。由于每月经营数据的公布，季度收入基本已被市场预期。而毛利率则是本次季报中，市场关注的焦点之一。海豚君将对分析本季度毛利率提升的主要驱动力：</p>\\n<p><strong>“毛利=单晶圆收入-固定成本-可变成本”</strong></p>\\n<p><strong>1）单片晶圆收入（等效12寸）</strong>：<strong>本季度台积电单晶圆收入约8601美元/片，环比提升85美元/片。</strong></p>\\n<p>通常而言，Q1受手机芯片出货占比下滑，公司产品均价会出现季节性回落的情况。<strong>而由于当前AI芯片从5nm逐步迁移至3nm平台，推动产品均价的“反季节性”提升</strong>。</p>\\n<p><strong>2）固定成本（折旧摊销）</strong>：<strong>本季度台积电平均固定成本约1255美元/片，环比减少65美元/片。</strong></p>\\n<p>在新台币的口径下，公司的折旧摊销总量环比是增加的；<strong>但在美元升值的影响下，美元口径的折旧摊销总量基本持平。出货量增加的规模效应下，单位固定成本出现下滑</strong>；</p>\\n<p><strong>3）可变成本（其他制造费用）</strong>：<strong>本季度台积电平均可变成本约1648美元/片，环比减少240美元/片，</strong>受公司本季度其他制造费用出现“季节性回落”的影响。</p>\\n<p><strong>综合以上拆分，本季度台积电单片毛利5698美元/片，环比增加390美元</strong>。公司本季度毛利率提升的原因是价格端上升和单位成本下降的双重影响。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_275f72e42ea54b84bb7f96826feb8a83@000000_oswg54222oswg815oswg456_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<h2><strong>三、晶圆结构端：AI芯片向3nm迁移，平滑“季度扰动”</strong></h2>\\n<p><strong>3.1晶圆收入占比（按应用类型）</strong></p>\\n<p><strong>高性能计算业务（HPC）依然是公司最大的收入来源，本季度收入占比61%。在英伟达GB系列等AI芯片的带动下，公司本季度HPC收入为219亿美元左右，环比增长18%，</strong>其中主要是英伟达Blackwell芯片和博通TPU出货增加的带动。</p>\\n<p>手机业务出现“季节性回落”的表现。<strong>本季度手机业务收入93.3亿美元，环比下滑13%。</strong>手机和HPC两项业务合计占比达到87%，是台积电最主要下游应用领域。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_1832230cc19548129c5c20db00cacc22@000000_oswg43254oswg761oswg458_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>3.2晶圆收入占比（按制程节点）</strong></p>\\n<p><strong>本季度7nm以下的收入占比维持在74%，先进制程领域是公司的核心收入来源。</strong>具体来看，本季度公司3nm收入占比为25%，5nm的收入占比维持在36%。</p>\\n<p><strong>台积电通常在一季度会出现“季节性下滑”的迹象，主要是最先进制程（如3nm）制程基本是提供给手机客户。</strong>在手机及相关产品在“四季度出货旺季”后，一季度环比明显回落。</p>\\n<p><strong>公司当前将AI芯片从5nm迁移至3nm平台，较好地平滑了“季节性变化”的扰动，使得公司一季度收入实现了季度的环增。</strong></p>\\n<p><strong>随着公司将3nm的手机芯片等产品陆续转移至2nm平台，AI芯片（Rubin、TPU等）将逐步迁移至3nm平台。</strong>公司的制程结构进一步向更先进节点迁移，一方面能带动公司产品均价继续上行，另一方面也能再次扩大与竞争对手的优势。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_ea8dc9a454e4404b8c9c381f91879d8a@000000_oswg48007oswg778oswg461_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p><strong>3.3晶圆收入占比（按地区）</strong></p>\\n<p>从各地区收入来看，<strong>北美地区仍是台积电最大的收入来源，收入占比为76%</strong>。这是由于北美地区有苹果、英伟达、AMD、高通等大客户，使得台积电和美国之间有很强的商业绑定关系。</p>\\n<p>除北美以外，亚太地区和中国大陆地区是其余的两大收入来源，本季度占比分别为9%和7%。<strong>本季度中国大陆地区的收入维持在25亿美元左右，依然是公司的前三大收入来源之一，在台积电的占比中下降至1成以下</strong>。</p>\\n<p><img src=\\\"https://img.36krcdn.com/hsossms/20260416/v2_8db885299e994b11a143fe8c7dd9f842@000000_oswg41796oswg766oswg446_img_000?x-oss-process=image/format,jpg/interlace,1\\\"></p>\\n<p>本文来自微信公众号 <a href=\\\"https://mp.weixin.qq.com/s?__biz=MzE5MTU3MzA2OQ==&amp;mid=2247571258&amp;idx=1&amp;sn=71785d1915beec1693b2a842288e3f1e&amp;chksm=97f98ef5ac4b9aa3919e45099bf036bc6df1c7a9d4c831978815cfb21b4bb79e9d24bdc24682&amp;scene=0&amp;xtrack=1#rd\\\">“海豚投研”（ID：haituntouyan）</a>，作者：海豚君，36氪经授权发布。</p>\", \"is_policy\": 0, \"origin_msg\": \"{\\\"title\\\": \\\"\\\\u53f0\\\\u79ef\\\\u7535\\\\uff1aAI \\\\u754c\\\\u201c\\\\u771f\\\\u9738\\\\u4e3b\\\\u201d\\\\uff0c\\\\u8c01\\\\u80fd\\\\u64bc\\\\u52a8\\\\uff1f\\\", \\\"title_detail\\\": {\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"\\\\u53f0\\\\u79ef\\\\u7535\\\\uff1aAI \\\\u754c\\\\u201c\\\\u771f\\\\u9738\\\\u4e3b\\\\u201d\\\\uff0c\\\\u8c01\\\\u80fd\\\\u64bc\\\\u52a8\\\\uff1f\\\"}, \\\"links\\\": [{\\\"rel\\\": \\\"alternate\\\", \\\"type\\\": \\\"text/html\\\", \\\"href\\\": \\\"https://36kr.com/p/3769365943288578?f=rss\\\"}], \\\"link\\\": \\\"https://36kr.com/p/3769365943288578?f=rss\\\", \\\"published\\\": \\\"2026-04-16 21:20:14  +0800\\\", \\\"published_parsed\\\": [2026, 4, 16, 13, 20, 14, 3, 106, 0], \\\"summary\\\": \\\"<p>\\\\u53f0\\\\u79ef\\\\u7535\\\\uff08TSMC\\\\uff09\\\\u4e8e\\\\u5317\\\\u4eac\\\\u65f6\\\\u95f42026\\\\u5e744\\\\u670816\\\\u65e5\\\\u4e0b\\\\u5348\\\\uff0c\\\\u7f8e\\\\u80a1\\\\u76d8\\\\u524d\\\\u53d1\\\\u5e03\\\\u4e862026\\\\u5e74\\\\u7b2c\\\\u4e00\\\\u5b63\\\\u5ea6\\\\u8d22\\\\u62a5\\\\uff08\\\\u622a\\\\u6b622026\\\\u5e743\\\\u6708\\\\uff09\\\\uff0c\\\\u8981\\\\u70b9\\\\u5982\\\\u4e0b\\\\uff1a</p>\\\\n  <p><strong>1\\\\u3001\\\\u6536\\\\u5165\\\\u7aef</strong>\\\\uff1a<strong>\\\\u53f0\\\\u79ef\\\\u7535\\\\u672c\\\\u5b63\\\\u5ea6\\\\u6536\\\\u5165359\\\\u4ebf\\\\u7f8e\\\\u5143\\\\uff0c\\\\u73af\\\\u6bd4\\\\u589e\\\\u957f6.4%\\\\uff0c</strong>\\\\u589e\\\\u957f\\\\u4e3b\\\\u8981\\\\u6765\\\\u81ea\\\\u4e8eAI\\\\u82af\\\\u7247\\\\u7684\\\\u5e26\\\\u52a8\\\\uff0c\\\\u5176\\\\u4e2d\\\\u5ba2\\\\u6237\\\\u7684AI\\\\u82af\\\\u7247\\\\u5df2\\\\u7ecf\\\\u5f00\\\\u59cb\\\\u8f6c\\\\u79fb\\\\u81f33nm\\\\u5e73\\\\u53f0\\\\u3002\\\\u5373\\\\u4f7f\\\\u672c\\\\u5b63\\\\u5ea6\\\\u53d7\\\\u5230\\\\u7f8e\\\\u5143\\\\u5151\\\\u65b0\\\\u53f0\\\\u5e01\\\\u5347\\\\u503c\\\\u7684\\\\u5f71\\\\u54cd\\\\uff0c\\\\u4f46\\\\u5b63\\\\u5ea6\\\\u6536\\\\u5165\\\\u8fd8\\\\u662f\\\\u8d85\\\\u4e86\\\\u6307\\\\u5f15\\\\u533a\\\\u95f4\\\\u4e0a\\\\u9650\\\\uff08346-358\\\\u4ebf\\\\u7f8e\\\\u5143\\\\uff09\\\\u3002<strong>\\\\u82e5\\\\u6309\\\\u65b0\\\\u53f0\\\\u5e01\\\\u53e3\\\\u5f84\\\\uff0c\\\\u516c\\\\u53f8\\\\u672c\\\\u5b63\\\\u5ea6\\\\u6536\\\\u5165\\\\u73af\\\\u589e8.4%\\\\uff0c\\\\u662f\\\\u660e\\\\u663e\\\\u597d\\\\u4e8e\\\\u516c\\\\u53f8\\\\u6307\\\\u5f15\\\\u7684\\\\uff08\\\\u73af\\\\u589e6%\\\\uff09\\\\u3002</strong></p>\\\\n  <p><strong>\\\\u4ece\\\\u91cf\\\\u4ef7\\\\u5173\\\\u7cfb\\\\u770b\\\\uff08\\\\u7b49\\\\u654812\\\\u5bf8\\\\u7247\\\\uff09\\\\uff1a\\\\u2460\\\\u53f0\\\\u79ef\\\\u7535\\\\u7684\\\\u6676\\\\u5706\\\\u51fa\\\\u8d27\\\\u91cf4174\\\\u5343\\\\u7247\\\\uff0c\\\\u73af\\\\u6bd4\\\\u589e\\\\u957f5.4%\\\\uff1b\\\\u2461\\\\u53f0\\\\u79ef\\\\u7535\\\\u7684\\\\u6676\\\\u5706\\\\u5355\\\\u6676\\\\u5706\\\\u6536\\\\u5165\\\\uff08\\\\u7b49\\\\u654812\\\\u5bf8\\\\u7247\\\\uff098601\\\\u7f8e\\\\u5143/\\\\u7247\\\\uff0c\\\\u73af\\\\u6bd4\\\\u589e\\\\u957f1%\\\\u3002</strong></p>\\\\n  <p><strong>2\\\\u3001\\\\u6bdb\\\\u5229\\\\u7387\\\\uff1a\\\\u516c\\\\u53f8\\\\u672c\\\\u5b63\\\\u5ea6\\\\u6bdb\\\\u5229\\\\u738766.2%\\\\uff0c\\\\u597d\\\\u4e8e\\\\u516c\\\\u53f8\\\\u6307\\\\u5f15\\\\u533a\\\\u95f4\\\\uff0863-65%\\\\uff09\\\\u3002</strong>\\\\u5177\\\\u4f53\\\\u6765\\\\u770b\\\\uff0c<strong>\\\\u672c\\\\u5b63\\\\u5ea6\\\\u516c\\\\u53f8\\\\u6bdb\\\\u5229\\\\u7387\\\\u63d0\\\\u5347\\\\u4e3b\\\\u8981\\\\u53d7\\\\u5747\\\\u4ef7\\\\u63d0\\\\u5347\\\\u548c\\\\u5355\\\\u4f4d\\\\u6210\\\\u672c\\\\u4e0b\\\\u964d\\\\u7684\\\\u53cc\\\\u91cd\\\\u5f71\\\\u54cd\\\\uff0c\\\\u89c4\\\\u6a21\\\\u6548\\\\u5e94\\\\u4e0b\\\\u5bf9\\\\u5355\\\\u4f4d\\\\u56fa\\\\u5b9a\\\\u6210\\\\u672c\\\\u6709\\\\u6240\\\\u7a00\\\\u91ca</strong>\\\\u3002</p>\\\\n  <p>\\\\u5728AI\\\\u9700\\\\u6c42\\\\u7684\\\\u5e26\\\\u52a8\\\\u4e0b\\\\uff0c\\\\u516c\\\\u53f8\\\\u6bdb\\\\u5229\\\\u7387\\\\u5df2\\\\u7ecf\\\\u7ad9\\\\u7a33\\\\u572860%\\\\u4ee5\\\\u4e0a\\\\u3002\\\\u516c\\\\u53f8\\\\u6b64\\\\u524d\\\\u628a\\\\u957f\\\\u671f\\\\u6bdb\\\\u5229\\\\u7387\\\\uff085\\\\u5e74\\\\u4ee5\\\\u4e0a\\\\u7ef4\\\\u5ea6\\\\uff09\\\\u4ece53%\\\\u63d0\\\\u5347\\\\u5230\\\\u4e8656%\\\\u3002</p>\\\\n  <p><strong>3\\\\u3001\\\\u5177\\\\u4f53\\\\u4e1a\\\\u52a1\\\\u8fdb\\\\u5c55\\\\u60c5\\\\u51b5\\\\uff1a\\\\u5236\\\\u7a0b\\\\u3001\\\\u4e0b\\\\u6e38\\\\u5e94\\\\u7528\\\\u548c\\\\u5730\\\\u533a</strong></p>\\\\n  <ul>\\\\n   <li><strong>a.\\\\u5206\\\\u5236\\\\u7a0b\\\\u770b</strong>\\\\uff1a\\\\u53f0\\\\u79ef\\\\u7535\\\\u672c\\\\u5b63\\\\u5ea67nm\\\\u4ee5\\\\u4e0b\\\\u5148\\\\u8fdb\\\\u5236\\\\u7a0b\\\\u7684\\\\u5360\\\\u6bd4\\\\u7ef4\\\\u6301\\\\u572874%\\\\u7684\\\\u76f8\\\\u5bf9\\\\u9ad8\\\\u4f4d\\\\u3002\\\\u53d7AI\\\\u9700\\\\u6c42\\\\u7684\\\\u63a8\\\\u52a8\\\\uff0c\\\\u516c\\\\u53f8\\\\u5f53\\\\u524d3nm\\\\u548c5nm\\\\u4ea7\\\\u80fd\\\\u5df2\\\\u7ecf\\\\u6ee1\\\\u8f7d\\\\uff0c\\\\u4e24\\\\u9879\\\\u6536\\\\u5165\\\\u5360\\\\u6bd4\\\\u5206\\\\u522b\\\\u4e3a25%\\\\u548c36%\\\\u3002<strong>\\\\u968f\\\\u7740\\\\u516c\\\\u53f82nm\\\\u91cf\\\\u4ea7\\\\uff0cAI\\\\u82af\\\\u7247\\\\u5c06\\\\u4ece5nm\\\\u5f803nm\\\\u8f6c\\\\u79fb\\\\uff0c\\\\u516c\\\\u53f8\\\\u6536\\\\u5165\\\\u7ed3\\\\u6784\\\\u6709\\\\u671b\\\\u8fdb\\\\u4e00\\\\u6b65\\\\u5411\\\\u5148\\\\u8fdb\\\\u5236\\\\u7a0b\\\\u503e\\\\u659c</strong>\\\\u3002</li>\\\\n   <li><strong>b.\\\\u4e0b\\\\u6e38\\\\u5e94\\\\u7528\\\\u7aef</strong>\\\\uff1a\\\\u516c\\\\u53f8\\\\u672c\\\\u5b63\\\\u5ea6\\\\u6536\\\\u5165\\\\u73af\\\\u589e\\\\u4e3b\\\\u8981\\\\u6765\\\\u81ea\\\\u4e8eAI\\\\u82af\\\\u7247\\\\u7684\\\\u9700\\\\u6c42\\\\u5e26\\\\u52a8\\\\uff0c\\\\u624b\\\\u673a\\\\u4e1a\\\\u52a1\\\\u672c\\\\u5b63\\\\u5ea6\\\\u51fa\\\\u73b0\\\\u5b63\\\\u8282\\\\u6027\\\\u56de\\\\u843d\\\\u7684\\\\u8868\\\\u73b0\\\\u3002<strong>\\\\u5728\\\\u82f1\\\\u4f1f\\\\u8fbe\\\\u3001\\\\u535a\\\\u901a\\\\u7b49AI\\\\u82af\\\\u7247\\\\u9700\\\\u6c42\\\\u7684\\\\u5f71\\\\u54cd\\\\u4e0b\\\\uff0c\\\\u9ad8\\\\u6027\\\\u80fd\\\\u8ba1\\\\u7b97\\\\u662f\\\\u516c\\\\u53f8\\\\u6700\\\\u5927\\\\u7684\\\\u6536\\\\u5165\\\\u6765\\\\u6e90\\\\uff0c\\\\u672c\\\\u5b63\\\\u5ea6\\\\u8fbe\\\\u5230219\\\\u4ebf\\\\u7f8e\\\\u5143\\\\uff0c\\\\u6536\\\\u5165\\\\u5360\\\\u6bd4\\\\u8fbe\\\\u523061%\\\\u3002</strong></li>\\\\n   <li><strong>c.\\\\u5206\\\\u5730\\\\u533a\\\\u6536\\\\u5165</strong>\\\\uff1a\\\\u5317\\\\u7f8e\\\\u5730\\\\u533a\\\\u8fd8\\\\u662f\\\\u516c\\\\u53f8\\\\u6700\\\\u5927\\\\u7684\\\\u6536\\\\u5165\\\\u6765\\\\u6e90\\\\uff0c\\\\u6db5\\\\u76d6\\\\u4e86\\\\u82f1\\\\u4f1f\\\\u8fbe\\\\u3001\\\\u82f9\\\\u679c\\\\u3001AMD\\\\u7b49\\\\u5927\\\\u5ba2\\\\u6237\\\\uff0c\\\\u672c\\\\u5b63\\\\u5ea6\\\\u6536\\\\u5165\\\\u5360\\\\u6bd476%\\\\u3002<strong>\\\\u672c\\\\u5b63\\\\u5ea6\\\\u4e2d\\\\u56fd\\\\u5927\\\\u9646\\\\u5730\\\\u533a\\\\u6536\\\