e\\\\u66fe\\\\u7ecf\\\\u88ab\\\\u5168\\\\u7403\\\\u4e2d\\\\u4ea7\\\\u62e5\\\\u8db8\\\\u89c6\\\\u4e3a\\\\u7684\\\\u793e\\\\u4ea4\\\\u8d27\\\\u5e01\\\\uff0c\\\\u5230\\\\u5982\\\\u4eca\\\\u6df1\\\\u9677\\\\u81f4\\\\u764c\\\\u7269\\\\u9634\\\\u5f71\\\\u4e0e\\\\u54c1\\\\u63a7\\\\u9891\\\\u53d1\\\\u8d28\\\\u7591\\\\u7684\\\\u56f0\\\\u6270\\\\u3002Lululemon\\\\u539f\\\\u672c\\\\u7a33\\\\u56fa\\\\u7684\\\\u4fe1\\\\u4ef0\\\\u5821\\\\u5792\\\\uff0c\\\\u4e5f\\\\u4f34\\\\u968f\\\\u7740\\\\u5e02\\\\u573a\\\\u7684\\\\u8d28\\\\u7591\\\\uff0c\\\\u6162\\\\u6162\\\\u4ece\\\\u5e95\\\\u5c42\\\\u53d1\\\\u751f\\\\u4e86\\\\u677e\\\\u52a8\\\\u3002</p>\\\\n  <p>\\\\u8fd9\\\\u79cd\\\\u5371\\\\u673a\\\\u7684\\\\u672c\\\\u8d28\\\\uff0c\\\\u5176\\\\u5b9e\\\\u662f\\\\u54c1\\\\u724c\\\\u8fc7\\\\u5ea6\\\\u5546\\\\u4e1a\\\\u5316\\\\u6269\\\\u5f20\\\\u5bf9\\\\u793e\\\\u533a\\\\u54c1\\\\u724c\\\\u6838\\\\u5fc3\\\\u4ef7\\\\u503c\\\\u7684\\\\u4e25\\\\u91cd\\\\u53cd\\\\u566c\\\\u3002\\\\u4e00\\\\u7cfb\\\\u5217\\\\u5371\\\\u673a\\\\u4e8b\\\\u4ef6\\\\u5e76\\\\u975e\\\\u5b64\\\\u7acb\\\\u7684\\\\u610f\\\\u5916\\\\u4e8b\\\\u4ef6\\\\uff0c\\\\u800c\\\\u662f\\\\u5f53\\\\u5c0f\\\\u4f17\\\\u8fd0\\\\u52a8\\\\u54c1\\\\u724c\\\\u5411\\\\u591a\\\\u54c1\\\\u7c7b\\\\u8fd0\\\\u52a8\\\\u54c1\\\\u724c\\\\u8f6c\\\\u53d8\\\\u7684\\\\u52a0\\\\u901f\\\\u5954\\\\u8dd1\\\\u4e2d\\\\uff0c\\\\u5ffd\\\\u7565\\\\u5730\\\\u57fa\\\\u7a33\\\\u56fa\\\\u7684\\\\u5fc5\\\\u7136\\\\u4ee3\\\\u4ef7\\\\u3002</p>\\\\n  <p>\\\\u5bf9\\\\u4e8eLululemon\\\\u800c\\\\u8a00\\\\uff0c2026\\\\u5e74\\\\u5c06\\\\u662f\\\\u4e00\\\\u9053\\\\u5206\\\\u6c34\\\\u5cad\\\\u3002\\\\u6bd4\\\\u8d77\\\\u5bfb\\\\u627e\\\\u4e0b\\\\u4e00\\\\u4efbCEO\\\\u6216\\\\u901a\\\\u8fc7\\\\u5927\\\\u4e2d\\\\u534e\\\\u533a\\\\u7684\\\\u589e\\\\u957f\\\\u7ea2\\\\u5229\\\\u6765\\\\u5bf9\\\\u51b2\\\\u7f8e\\\\u6d32\\\\u5e02\\\\u573a\\\\u7684\\\\u6ed1\\\\u5761\\\\uff0c\\\\u54c1\\\\u724c\\\\u66f4\\\\u8feb\\\\u5207\\\\u9700\\\\u8981\\\\u5b8c\\\\u6210\\\\u7684\\\\u662f\\\\u4e00\\\\u573a\\\\u201c\\\\u4fe1\\\\u4ef0\\\\u81ea\\\\u6551\\\\u201d\\\\u3002</p>\\\\n  <p>\\\\u6bd5\\\\u7adf\\\\uff0c\\\\u5982\\\\u679c\\\\u90a3\\\\u6761\\\\u6602\\\\u8d35\\\\u7684\\\\u745c\\\\u4f3d\\\\u88e4\\\\u4e0d\\\\u518d\\\\u80fd\\\\u4e3a\\\\u6d88\\\\u8d39\\\\u8005\\\\u63d0\\\\u4f9b\\\\u6700\\\\u57fa\\\\u7840\\\\u7684\\\\u5b89\\\\u5168\\\\u611f\\\\uff0c\\\\u90a3\\\\u4e48\\\\u5173\\\\u4e8e\\\\u5065\\\\u5eb7\\\\u751f\\\\u6d3b\\\\u65b9\\\\u5f0f\\\\u7684\\\\u6240\\\\u6709\\\\u627f\\\\u8bfa\\\\uff0c\\\\u90fd\\\\u5c06\\\\u6ca6\\\\u4e3a\\\\u4e00\\\\u573a\\\\u6602\\\\u8d35\\\\u7684\\\\u9ed1\\\\u8272\\\\u5e7d\\\\u9ed8\\\\u3002</p>\\\\n  <p class=\\\\\\\"editor-note\\\\\\\">\\\\u672c\\\\u6587\\\\u6765\\\\u81ea\\\\u5fae\\\\u4fe1\\\\u516c\\\\u4f17\\\\u53f7<a href=\\\\\\\"https://mp.weixin.qq.com/s/tRM_qARjonuAbFFkjBgiWg\\\\\\\" rel=\\\\\\\"noopener noreferrer\\\\\\\" target=\\\\\\\"_blank\\\\\\\">\\\\u201c\\\\u4f53\\\\u575b\\\\u7ecf\\\\u6d4e\\\\u89c2\\\\u5bdf\\\\u201d</a>\\\\uff0c\\\\u4f5c\\\\u8005\\\\uff1a\\\\u6708\\\\u534a\\\\uff0c36\\\\u6c2a\\\\u7ecf\\\\u6388\\\\u6743\\\\u53d1\\\\u5e03\\\\u3002</p>\\\"}, \\\"source\\\": {\\\"title\\\": \\\"36\\\\u6c2a\\\"}, \\\"authors\\\": [{\\\"name\\\": \\\"\\\\u4f53\\\\u575b\\\\u7ecf\\\\u6d4e\\\\u89c2\\\\u5bdf\\\"}], \\\"author\\\": \\\"\\\\u4f53\\\\u575b\\\\u7ecf\\\\u6d4e\\\\u89c2\\\\u5bdf\\\", \\\"author_detail\\\": {\\\"name\\\": \\\"\\\\u4f53\\\\u575b\\\\u7ecf\\\\u6d4e\\\\u89c2\\\\u5bdf\\\"}, \\\"content\\\": [{\\\"type\\\": \\\"text/plain\\\", \\\"language\\\": null, \\\"base\\\": \\\"https://36kr.com/feed-article\\\", \\\"value\\\": \\\"Lululemon\\\\u56e0PFAS\\\\u88ab\\\\u8c03\\\\u67e5\\\\uff0c\\\\u54c1\\\\u724c\\\\u4fe1\\\\u4efb\\\\u5371\\\\u673a\\\\u52a0\\\\u5267\\\\u3002\\\"}]}\", \"published_at\": \"2026-04-16 19:33:20\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:06:47');
INSERT INTO `news_detail` VALUES (64, 2279, 18, '硬件与半导体出海', '追觅科技受邀出席国家商务部中意企委会圆桌会，作为中方企业代表发言', '', '4月16日，由国家商务部主办的 “中意企业家委员会圆桌会”在北京举行。追觅科技受邀参会，并作为五家中方企业代表之一发言。追觅集团成立于2017年，目前已在高速数字马达领域做到全球行业第一，并在智能算法、仿生机械臂、全域智能芯片等方向形成系统化的核心技术壁垒。在意大利市场，追觅多次登顶亚马逊类目销量第一，并在意大利米兰开设两家旗舰店，并实现多个品类市占率第一。目前，追觅产品已进入全球120多个国家和地区，服务超4200万家庭。', 'https://36kr.com/newsflashes/3770547590808320?f=rss', 0, '', '{\"summary\": \"本文展现中国科技企业追觅科技的出海成绩，为国内企业出海欧洲市场提供成功案例参考\", \"abstract\": \"4月16日，国家商务部主办的中意企业家委员会圆桌会在北京举行，追觅科技受邀参会并作为中方企业代表发言。追觅科技成立于2017年，目前在高速数字马达领域位居全球第一，在智能算法等多领域形成系统化核心技术壁垒。追觅出海成果突出，在意大利市场多个品类拿下销量、市占率第一，其产品已进入全球120余个国家和地区，服务超4200万家庭。\", \"keywords\": [\"追觅科技\", \"企业出海\", \"意大利市场\", \"智能硬件\", \"高速数字马达\", \"全球市场\", \"中意经贸\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3770547590808320?f=rss\", \"title\": \"追觅科技受邀出席国家商务部中意企委会圆桌会，作为中方企业代表发言\", \"source\": \"https://36kr.com/feed\", \"content\": \"4月16日，由国家商务部主办的 “中意企业家委员会圆桌会”在北京举行。追觅科技受邀参会，并作为五家中方企业代表之一发言。追觅集团成立于2017年，目前已在高速数字马达领域做到全球行业第一，并在智能算法、仿生机械臂、全域智能芯片等方向形成系统化的核心技术壁垒。在意大利市场，追觅多次登顶亚马逊类目销量第一，并在意大利米兰开设两家旗舰店，并实现多个品类市占率第一。目前，追觅产品已进入全球120多个国家和地区，服务超4200万家庭。\", \"is_policy\": 0, \"origin_msg\": {\"link\": \"https://36kr.com/newsflashes/3770547590808320?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770547590808320?f=rss\", \"type\": \"text/html\"}], \"title\": \"追觅科技受邀出席国家商务部中意企委会圆桌会，作为中方企业代表发言\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"4月16日，由国家商务部主办的 “中意企业家委员会圆桌会”在北京举行。追觅科技受邀参会，并作为五家中方企业代表之一发言。追觅集团成立于2017年，目前已在高速数字马达领域做到全球行业第一，并在智能算法、仿生机械臂、全域智能芯片等方向形成系统化的核心技术壁垒。在意大利市场，追觅多次登顶亚马逊类目销量第一，并在意大利米兰开设两家旗舰店，并实现多个品类市占率第一。目前，追觅产品已进入全球120多个国家和地区，服务超4200万家庭。\", \"published\": \"2026-04-17 14:39:21  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"追觅科技受邀出席国家商务部中意企委会圆桌会，作为中方企业代表发言\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"4月16日，由国家商务部主办的 “中意企业家委员会圆桌会”在北京举行。追觅科技受邀参会，并作为五家中方企业代表之一发言。追觅集团成立于2017年，目前已在高速数字马达领域做到全球行业第一，并在智能算法、仿生机械臂、全域智能芯片等方向形成系统化的核心技术壁垒。在意大利市场，追觅多次登顶亚马逊类目销量第一，并在意大利米兰开设两家旗舰店，并实现多个品类市占率第一。目前，追觅产品已进入全球120多个国家和地区，服务超4200万家庭。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 6, 39, 21, 4, 107, 0]}, \"published_at\": \"2026-04-17 14:39:21\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:08:20');
INSERT INTO `news_detail` VALUES (65, 2283, 6, '科技与数字服务', '8点1氪丨全季大连某酒店账号公开多名客人特殊订单备注；金立手机创始人被曝在印尼卖家具；雷军将连播15小时测试新SU7续航', '', '<h2>今日热点导览</h2>\n<p>丝芭传媒：创始人王子杰去世，享年63岁</p>\n<p>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</p>\n<p>京东发布机器人产业服务全景图</p>\n<p>为加速重塑Siri，苹果安排近200名工程师培训AI编程</p>\n<p>特朗普签发多项输油管道许可，以促进美加之间的石油运输</p>\n<h2>TOP3大新闻</h2>\n<p><strong>全季大连某酒店账号公开多名客人特殊订单备注，华住集团客服回应</strong></p>\n<p>近日，一则题为“全季客人备注大赏”的帖文在社交平台引发争议。涉事账号“全季大连xx酒店”将多名客人的特殊订单备注公开发布，配文称“每天被客人备注笑到捶桌”“前台已笑晕在系统里”。有网友发帖表示：“一个酒店官方账号，私自将客人订单备注发到网上，评论区引起网友无谓的猜测，有些甚至偏恶意。”</p>\n<p>针对此事，上游新闻记者4月16日致电涉事酒店。工作人员回应称，发布帖文的账号并非酒店官方账号，具体由谁开设他并不清楚。华住酒店集团客服表示，核查后发现，该账号确认为员工的个人账号，目前已要求该员工立即注销账号，并对其进行通报批评。（上游新闻）</p>\n<p><strong>消失8年后，金立创始人刘立荣被曝在印尼卖家具</strong></p>\n<p>据红星新闻4月16日报道，多位网友爆料称，刘立荣在印尼经营家具公司Starlead。去年7月，他曾身穿印尼当地传统服装，出席Starlead展厅开幕仪式，并在上台讲话后落座于该公司CEO身旁。而Starlead的创始人何星是刘立荣的老部下。Starlead公司官网显示，该公司成立于2023年9月，瞄准出海印尼的中国企业，致力于提供现代实用的家居家具，在印尼专卖店超过20家，海尔、宁德时代、小米等都是其客户。Starlead的创始人何星，是刘立荣的“老部下”。</p>\n<p>2017年，金立手机出货量同比减少了1000万台，远低于预期。同一年，有关刘立荣赌博输掉巨额资金的传闻开始在金立供应商之间流传。当时有接近金立公司股东的人士表示，董事长刘立荣在赌博上输了超过100亿，挪用公款的数目可能在60亿左右，不排除有人设局。刘立荣则在接受媒体采访时承认自己曾去塞班赌博，并表示懊悔，“赌这个东西真的不能沾，一失足成千古恨。不光是在于涉及多少钱，它会对你的品行定性，让一个人人格破产。”但他称自己没有输掉100亿，而是“十几亿”，其中不乏“借用”公司的钱。（红星新闻）</p>\n<p><strong>雷军将直播新SU7续航测试，从北京到上海大约15小时</strong></p>\n<p>4月16日，雷军发文称，去年年初他曾说过，“我开YU7标准版，充满电，从北京到上海，1300公里高速，中间只充了一次电，我非常震惊”。雷军表示，这次新SU7打算直播给大家看，他将于17日早上六点半开始，全程参加并直播从北京到上海的长途续航测试，大约十五小时。在评论区雷军回复网友称，自己已经紧张到好几天没睡好觉。他还回应网友对于黑稿的忧虑，表示“咋办呢？不能因为有黑稿，我们就不说话了？”雷军曾在直播中重谈“1300km只充一次电”话题，他表示短视频平台推送的片段很多时候是被水军剪辑的，为了给他贴上“虚假营销”的标签。（界面新闻）</p>\n<h2>大公司/大事件</h2>\n<p><strong>丝芭传媒：创始人王子杰去世，享年63岁</strong></p>\n<p>4月16日，上海丝芭文化传媒集团有限公司发布讣告：公司创始人王子杰，因突发心源性疾病，经抢救无效，于4月14日19时在上海逝世，享年63岁。（界面新闻）</p>\n<p><strong>杨利娟辞任特海CEO，接手海底捞红石榴计划</strong></p>\n<p>36氪获悉，4月15日，特海国际发布公告称，杨利娟已辞任公司执行董事兼CEO，并将加入海底捞国际控股有限公司，统筹推动“红石榴计划”实施。公开资料显示，海底捞于2024年8月启动“红石榴计划”，截至2025年底已推出20个餐饮品牌，共计207家餐厅。</p>\n<p><strong>小米18Pro新增AI按键，支持启动AI功能、控制智能家居及小米汽车</strong></p>\n<p>消息源“leo_hefeng”4月15日在X平台发布推文，分享了一组渲染图，展示了小米18Pro手机，重点凸显机身侧面的AI按键，支持启动AI功能、控制智能家居及小米汽车。</p>\n<p>外观方面，小米18Pro延续小米17Pro的三摄布局和后置副屏设计，值得关注的是侧边新增AI按钮。该按钮支持自定义功能，可在任意场景快速启动AI，同时控制智能家居设备，甚至兼容小米汽车。核心规格方面，小米18Pro预计配备6.3英寸显示屏，主摄与3倍长焦采用2亿像素组合，电池容量将突破7000mAh。（财经网科技）</p>\n<p><strong>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</strong></p>\n<p>国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，智能化发展的引领作用不断增强，中国人工智能商业化、规模化运营取得了阶段性突破。截至今年3月，日均词元（Token）调用量突破140万亿，比上年末增长超40%。人工智能发展赋能千行百业，带动相关领域快速增长。（证券时报）</p>\n<p><strong>算力涨价潮席卷全球：阿里、Anthropic连续调价，严重算力荒再现</strong></p>\n<p>算力涨价潮正在席卷全球，海内外巨头又开始了新一轮调价。阿里云四天连发三条产品涨价公告，调整百炼部分模型单元服务价格及DataWorks部分API免费额度。Anthropic调整了旗下企业级产品Claude Enterprise订阅模式，从每月每用户最高200美元的固定费用，转变为按照实际算力消耗收费，此外用户每月还需要固定缴纳20美元。中信证券指出，Token调用量井喷带来的是算力需求极大爆发，与此同时供给侧受到各类硬约束短期边际增量有限，目前国内外均出现了严重的算力荒。（财联社）</p>\n<p><strong>研究显示：大语言模型会在蒸馏中“夹带”自己的偏好</strong></p>\n<p>《自然》15日发表的一项研究显示，大语言模型（LLM）可能会将某些自己的偏好“夹带私货”传授给其他算法，即使在训练数据中清除原始特征后，这些本不需要的特征，仍可能持续存在。在一个案例中，一个模型似乎通过数据中的隐含信号，将自己对猫头鹰的偏好传递给了其他模型。该研究结果表明，在开发LLM时，需要进行更彻底的安全检查。（财联社）</p>\n<p><strong>京东发布机器人产业服务全景图</strong></p>\n<p>36氪获悉，4月15日，京东发布“机器人产业服务全景图”。全景图聚焦三大核心：携手超200家品牌，目标2026年销售破百亿；依托超级供应链，建全球最大具身数据采集中心、京东机器人售后维修服务3年覆盖50余城；基于JoyAI大模型加速开放JoyInside附身智能交互能力，为机器人注入“智慧大脑”。</p>\n<p><strong>电子布库存持续紧张，涨价周期尚未结束</strong></p>\n<p>从业内获悉，多家电子布（电子级玻璃纤维）厂商库存紧张，部分企业库存不足十天。行业整体扩产进度受织布机供应瓶颈制约，短期内补库难度较大。业内人士分析认为，在织布机瓶颈未突破、产能向高端布倾斜的背景下，电子布高景气格局仍将延续，涨价周期尚未结束。（上证报）</p>\n<p><strong>亚洲富豪挟250亿美元涌入AI领域，面对高估值毫无惧色</strong></p>\n<p>据报道，尽管对美国AI企业估值过高的疑虑渐起，亚洲富裕投资者仍向该领域投入数十亿美元的私人资本，毫无惧色。根据PitchBook数据显示，2025年亚洲高净值个人及家族办公室共向全球AI私募融资投入243亿美元。今年动能延续，截至4月8日，新增投资额已达9.5亿美元。这波投资热潮正值SpaceX、OpenAI和Anthropic PBC等行业巨头在募资中持续创下惊人估值。对亚洲富裕投资人而言，抓住世代级科技机会的吸引力，已超越潜在泡沫的风险。（新浪财经）</p>\n<p><strong>为加速重塑Siri，苹果安排近200名工程师培训AI编程</strong></p>\n<p>据报道，为了追赶AI竞争对手，苹果正在将近200名Siri工程师送往为期数周的训练营，学习如何使用AI进行编程，旨在提升程序员的AI编程能力。据悉，该培训覆盖了Siri团队近九成工程师。训练营的培训重点将是学习使用Anthropic旗下Claude Code等AI辅助开发工具。</p>\n<p>在此之前，Siri团队长期沿用传统开发模式，在AI辅助编程方面的应用相对滞后，这也导致近年来Siri的功能迭代速度放缓，与谷歌Assistant、亚马逊Alexa等竞品的差距逐渐拉大。谷歌Assistant深度集成Gemini模型，早已支持多步复合指令、跨应用协同；亚马逊Alexa拥有超10万种兼容智能家居设备，技能库丰富，擅长多设备联动控制。（界面新闻）</p>\n<p><strong>美联储4月维持利率不变的概率为98.4%</strong></p>\n<p>据CME“美联储观察”：美联储4月加息25个基点的概率为1.6%，维持利率不变的概率为98.4%。美联储到6月累计降息25个基点的概率为0%，维持利率不变的概率为98%，累计加息25个基点的概率为2%。（财联社）</p>\n<p><strong>特朗普签发多项输油管道许可，以促进美加之间的石油运输</strong></p>\n<p>据白宫公布的文件显示，美国总统特朗普15日签发了多项输油管道许可，其中包括一项新建输油管道的许可，旨在促进美国与加拿大之间的原油及油品运输。该建设许可已颁发给Bakken Pipeline Company，用于北达科他州伯克县的管道设施建设。此外，他还签发了其他许可，以维护和运营位于北达科他州和密西根州、靠近边境地区的现有输油管道。（新浪财经）</p>\n<p><strong>美股三大指数集体收涨，纳指十二连涨再创收盘新高</strong></p>\n<p>36氪获悉，4月16日收盘，美股三大指数集体上涨，纳指涨0.36%，为连续12个交易日上涨续创新高，标普500指数涨0.26%创历史新高，道指涨0.24%。大型科技股多数上涨，英特尔、甲骨文涨超5%，微软涨超2%，Meta、亚马逊、奈飞小幅上涨；苹果跌超1%，特斯拉、谷歌、英伟达小幅下跌。热门中概股多数走强，蔚来涨超6%，阿里巴巴、百度、小鹏集团涨超3%，理想汽车、拼多多涨超1%；老虎证券、小马智行跌超1%。</p>\n<p><strong>聚焦充电宝等重点领域，市场监管总局开展专项行动打击虚假CCC认证标志</strong></p>\n<p>市场监管总局在全国范围内部署开展CCC认证守底线专项行动，全链条、全方位加强CCC认证监管，营造安全放心的消费环境。强制性产品认证也就是我们常说的CCC认证制度是我国政府遵循世贸组织规则和国际通行规则建立的具有市场准入性质的合格评定体系，列入CCC认证目录的产品，需要获证后才能出厂、进口、销售。此次专项行动将突出一个“严”字。将对指定认证机构实施全覆盖监督检查，聚焦充电宝、电动自行车、燃气燃烧器具等重点领域，开展有效性抽查。深入推进CCC认证标志试点改革，精准打击虚假CCC认证标志，加强产品质量责任追溯。（界面新闻）</p>\n<p><strong>三星请求法院禁止工会开展非法罢工活动</strong></p>\n<p>一名发言人表示，三星电子于16日向法院提起申请，要求禁止其韩国工会在计划中的罢工期间开展非法活动。眼下这场薪资纠纷，恐将扰乱这家全球最大存储芯片制造商的生产运营。三星并未详细说明此次法律行动的具体细节。工会则将此举称为“宣战”，指责公司侵犯了受法律保护的罢工权。（新浪财经）</p>\n<p><strong>万科回应总裁空缺：已由董事长及高管团队分担相关职责</strong></p>\n<p>36氪获悉，万科A在深交所互动易平台回应了总裁职位空缺、泊寓业务、化债等市场关注。对总裁一职的空缺，万科表示，公司总裁职位目前处于空缺状态，公司已通过董事会授权及高管分工调整，由董事长及公司高管团队分担相关职责，确保了公司经营决策的正常开展和公司治理的有效运作。万科还提到，受多重因素影响，当前公司面临着多重风险挑战，整体经营形势依然十分严峻。在各方支持下，集团全力推进改革化险工作。</p>\n<p><strong>国际原油市场逐渐回归基本面定价，库存消耗继续推升油价</strong></p>\n<p>当前，国际原油市场从3月份“溢价绑架油价”的恐慌性交易，逐渐回归至基本面定价。最直观的数据表现为，纽约WTI近月期货合约升水较峰值回落约60%，国内原油期权波动率指数（VIX）自高点腰斩，同时原油期货沉淀资金规模降幅超四成。（证券时报）</p>\n<p><strong>摩根大通CEO杰米·戴蒙出售价值4000万美元摩根大通股票</strong></p>\n<p>摩根大通首席执行官杰米·戴蒙（Jamie Dimon）4月15日出售了价值超过4000万美元的该行股票，这是他最新一次减持套现。戴蒙执掌这家银行已超过20年，直到2023年底他才开始出售自己持有的该行股票，当时他卖出了100万股，价值约1.8亿美元。他去年出售了价值约2.33亿美元的股票，今年2月出售了价值约2100万美元的股票。他目前仍持有该行超过620万股股票，价值约19亿美元。这些股票由戴蒙、他的妻子和他的家族信托持有。（新浪财经）</p>\n<h2>上市进行时</h2>\n<p><strong>先正达</strong></p>\n<p>先正达寻求最早6月在香港以保密方式提交IPO申请。（财联社）</p>\n<p><strong>春光集团</strong></p>\n<p>36氪获悉，春光集团披露招股书，拟于近期在深市发行新股并上市。</p>\n<p><strong>中科宇航</strong></p>\n<p>36氪获悉，上交所官网显示，4月15日，商业火箭企业中科宇航IPO状态变为已问询。中科宇航成立于2018年，3月31日，该公司IPO申请获受理，后被抽中现场检查。此次IPO，中科宇航拟募资41.8亿元，其保荐机构为国泰海通证券。</p>\n<p><strong>华盛锂电</strong></p>\n<p>36氪获悉，华盛锂电公告，公司已于2026年4月15日向香港联交所递交了发行境外上市股份(H股)并在香港联交所主板上市的申请，并于同日在香港联交所网站刊登了本次发行上市的申请资料。本次发行上市事项的相关申请资料为公司按照香港证监会和香港联交所的要求编制和刊发，为草拟版本，且所载资料可能会适时作出更新及修订。</p>\n<h2>AI最前沿</h2>\n<p><strong>腾讯混元3D世界模型2.0发布并开源</strong></p>\n<p>36氪获悉，4月16日，混元3D世界模型2.0（HY-World 2.0）正式发布并开源。HY-World 2.0是一个多模态世界模型，能够根据文字、图片、视频等不同类型输入，自动生成、重建和模拟3D世界，同时支持多格式3D资产（Mesh/3DGS/点云等）导出，支持与现有的游戏工作流无缝对接，用于快速生成游戏地图和关卡原型。</p>\n<p><strong>OpenAI退出挪威“星门”数据中心合作，微软接手</strong></p>\n<p>OpenAI放弃直接从英国AI云服务商Nscale在挪威运营的数据中心租赁算力的计划。微软将接手该数据中心的剩余算力。OpenAI表示，正与微软洽谈从其手中租赁算力。（新浪财经）</p>\n<p><strong>Adobe推出可操作Claude的创意工具AI助手</strong></p>\n<p>Adobe4月15日宣布推出一款全新的人工智能助手，旨在帮助用户在其照片、视频及数字内容编辑软件套件中执行各项任务。该助手还将与Anthropic的Claude AI模型进行集成。（新浪财经）</p>\n<p><strong>马斯克的xAI据悉将向编程初创公司Cursor提供算力支持</strong></p>\n<p>据知情人士透露，埃隆·马斯克的人工智能公司xAI计划与编程初创公司Cursor达成一项新的合作协议，让后者利用其庞大的计算能力。消息人士称，Cursor计划在xAI的基础设施上训练其最新的AI编程模型Composer 2.5。他们还表示，Cursor将使用xAI的数万快图形处理器（GPU）。（新浪财经）</p>\n<p><strong>阶跃发布新一代语音生成模型StepAudio 2.5 TTS</strong></p>\n<p>36氪获悉，4月16日，阶跃发布新一代语音生成模型StepAudio 2.5 TTS。据介绍，该模型围绕全局语境控制、文中语境控制，以及零样本复刻与全音色控制等能力进行了升级，主要面向角色配音、有声内容创作、智能语音交互等场景。StepAudio 2.5 TTS支持利用自然语言来进行合成控制。目前，StepAudio 2.5 TTS已全量上线“阶跃星辰开放平台”和Step Plan。</p>\n<h2>大公司财报</h2>\n<p><strong>台积电：预计第二季度毛利率65.5％-67.5％</strong></p>\n<p>台积电预计第二季度毛利率65.5％-67.5％，市场预估64.1％；预计第二季度销售额390亿美元-402亿美元，预估381.1亿美元。（财联社）</p>\n<p><strong>永辉超市：一季度净利润2.87亿元，同比增长94.40%</strong></p>\n<p>36氪获悉，永辉超市发布2026年第一季度业绩报告。报告显示，一季度营业收入133.67亿元，同比减少23.53%；净利润2.87亿元，同比增长94.40%；扣非后归母净利润为2.47亿元，同比增长79.55%。此外，截至一季度末，永辉超市全国累计调改门店达327家。</p>\n<p><strong>贵州茅台：2025年实现营业收入1688.38亿元，同比下降1.21%</strong></p>\n<p>36氪获悉，贵州茅台发布2025年业绩报告。报告显示，2025年实现营业收入1688.38亿元，同比下降1.21%；归属于上市公司股东的净利润为823.20亿元，同比下降4.53%。拟向全体股东每股派发现金红利27.993元（含税）。</p>\n<p><strong>太平鸟：2025年净利润1.74亿元，同比下降32.57%</strong></p>\n<p>36氪获悉，太平鸟发布2025年业绩报告。报告显示，2025年营业收入63.34亿元，同比下降6.88%。净利润1.74亿元，同比下降32.57%。公司拟每10股派发现金红利3元（含税），拟派发现金红利1.41亿元，剩余未分配利润结转以后年度分配。2026年第一季度营收为16.56亿元，同比下降0.75%：净利润为1.37亿元，同比增长10.3%。</p>\n<p><strong>华友钴业：2026年第一季度净利润24.97亿元，同比增长99.45%</strong></p>\n<p>36氪获悉，华友钴业发布2026年第一季度业绩报告。报告显示，一季度实现营业收入258.04亿元，同比增长44.62%；归属于上市公司股东的净利润为24.97亿元，同比增长99.45%。业绩变动主要系产品销量增加及金属价格回升所致，以及主要受益于镍、钴、锂等金属价格的回升及公司产业一体化经营优势的持续释放。</p>\n<h2>投融资</h2>\n<p><strong>“它石智航”完成超4.5亿美金Pre-A轮融资</strong></p>\n<p>4月16日，“它石智航”宣布完成超4.5亿美金Pre-A轮融资，创下中国具身智能有史以来最高单轮融资纪录，由高瓴创投，与红杉中国联合领投，美团龙珠、中金资本、凯联资本、东方富海、钧山投资等财务基金跟投。本轮融资将用于加速打造通用具身大模型AWE和持续吸引行业人才，下一轮融资将重点用于打造真干活、真量产的机器人。</p>\n<h2>酷产品</h2>\n<p><strong>宝马将在北京车展推出M3 40周年限量版</strong></p>\n<p>36氪获悉，宝马将在北京国际车展推出M3 40周年限量版车型，涵盖轿车与旅行车两种版本，在华各限量20台，于2026年下半年上市。</p>\n<p><strong>奥迪高管透露明年将推第三款中国专属车型</strong></p>\n<p>据报道，德国奥迪汽车公司首席执行官索内拉表示，为重夺中国市场份额，奥迪计划于明年与中国合作伙伴上汽集团联合推出第三款中国专属车型，定位为高端运动型轿车。索内拉强调，该车型已进入开发阶段，并延续“中国需求优先”策略。（界面新闻）</p>\n<p><strong>追觅科技旗下AI视觉机器人品牌NAVO亮相广交会</strong></p>\n<p>36氪获悉，4月15日，第139届中国进出口商品交易会（即2026春季广交会）在广州开幕，追觅科技旗下AI视觉机器人品牌NAVO，携全系列高端AI智能摄像头产品亮相。据了解，NAVO自研专属安防芯片架构，搭配黑光全彩夜视引擎，首创事件级AI平台AlgoMart。上市半年，订单销售额超过6000万。</p>\n<h2>AI图谱</h2>\n<p><strong>AI图谱，带你解读最新最快的AI咨询。46小时内两次袭击，美国人这么怕AI？</strong></p>\n<p><strong>整理</strong>｜Kris </p>', 'https://36kr.com/p/3770155029398018?f=rss', 0, '', '{\"summary\": \"本文汇总了当日国内外科技、AI、大公司等领域热点，包含面向出海中企的海外产业动态，可为出海从业者提供资讯参考\", \"abstract\": \"本文是4月中旬的财经科技热点新闻汇总，涵盖大公司动态、AI产业、投融资、上市进展等多个领域。文中提及金立手机创始人刘立荣消失8年后，在印尼创办瞄准出海中国企业的家具公司，已有多家出海中企成为其客户。文章梳理了全球AI产业最新动态，指出Token调用量爆发使算力需求激增，全球出现严重算力荒并掀起涨价潮。此外还汇总了企业财报、资本市场、能源市场等领域的最新热点信息。\", \"keywords\": [\"企业出海\", \"出海印尼\", \"人工智能\", \"算力荒\", \"AI大模型\", \"IPO\", \"科技动态\"], \"policy_risk\": {\"market_risk\": \"1. 全球AI Token调用量爆发推高算力需求，供给侧短期增量有限，当前国内外出现严重算力荒，AI领域存在高估值泡沫风险；2. 三星电子薪资纠纷引发罢工争端，或扰乱全球存储芯片生产运营；3. 万科当前面临多重经营风险，整体经营形势严峻\", \"policy_compliance\": \"1. 中国市场监管总局部署CCC认证守底线专项行动，明确列入CCC认证目录的产品需获证后方可进口、出厂、销售，将聚焦充电宝等重点领域打击虚假CCC认证标志；2. 美国特朗普政府签发多项输油管道许可，促进美加间原油及油品运输\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"https://36kr.com/p/3770155029398018?f=rss\", \"title\": \"8点1氪丨全季大连某酒店账号公开多名客人特殊订单备注；金立手机创始人被曝在印尼卖家具；雷军将连播15小时测试新SU7续航\", \"source\": \"https://36kr.com/feed\", \"content\": \"<h2>今日热点导览</h2>\\n<p>丝芭传媒：创始人王子杰去世，享年63岁</p>\\n<p>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</p>\\n<p>京东发布机器人产业服务全景图</p>\\n<p>为加速重塑Siri，苹果安排近200名工程师培训AI编程</p>\\n<p>特朗普签发多项输油管道许可，以促进美加之间的石油运输</p>\\n<h2>TOP3大新闻</h2>\\n<p><strong>全季大连某酒店账号公开多名客人特殊订单备注，华住集团客服回应</strong></p>\\n<p>近日，一则题为“全季客人备注大赏”的帖文在社交平台引发争议。涉事账号“全季大连xx酒店”将多名客人的特殊订单备注公开发布，配文称“每天被客人备注笑到捶桌”“前台已笑晕在系统里”。有网友发帖表示：“一个酒店官方账号，私自将客人订单备注发到网上，评论区引起网友无谓的猜测，有些甚至偏恶意。”</p>\\n<p>针对此事，上游新闻记者4月16日致电涉事酒店。工作人员回应称，发布帖文的账号并非酒店官方账号，具体由谁开设他并不清楚。华住酒店集团客服表示，核查后发现，该账号确认为员工的个人账号，目前已要求该员工立即注销账号，并对其进行通报批评。（上游新闻）</p>\\n<p><strong>消失8年后，金立创始人刘立荣被曝在印尼卖家具</strong></p>\\n<p>据红星新闻4月16日报道，多位网友爆料称，刘立荣在印尼经营家具公司Starlead。去年7月，他曾身穿印尼当地传统服装，出席Starlead展厅开幕仪式，并在上台讲话后落座于该公司CEO身旁。而Starlead的创始人何星是刘立荣的老部下。Starlead公司官网显示，该公司成立于2023年9月，瞄准出海印尼的中国企业，致力于提供现代实用的家居家具，在印尼专卖店超过20家，海尔、宁德时代、小米等都是其客户。Starlead的创始人何星，是刘立荣的“老部下”。</p>\\n<p>2017年，金立手机出货量同比减少了1000万台，远低于预期。同一年，有关刘立荣赌博输掉巨额资金的传闻开始在金立供应商之间流传。当时有接近金立公司股东的人士表示，董事长刘立荣在赌博上输了超过100亿，挪用公款的数目可能在60亿左右，不排除有人设局。刘立荣则在接受媒体采访时承认自己曾去塞班赌博，并表示懊悔，“赌这个东西真的不能沾，一失足成千古恨。不光是在于涉及多少钱，它会对你的品行定性，让一个人人格破产。”但他称自己没有输掉100亿，而是“十几亿”，其中不乏“借用”公司的钱。（红星新闻）</p>\\n<p><strong>雷军将直播新SU7续航测试，从北京到上海大约15小时</strong></p>\\n<p>4月16日，雷军发文称，去年年初他曾说过，“我开YU7标准版，充满电，从北京到上海，1300公里高速，中间只充了一次电，我非常震惊”。雷军表示，这次新SU7打算直播给大家看，他将于17日早上六点半开始，全程参加并直播从北京到上海的长途续航测试，大约十五小时。在评论区雷军回复网友称，自己已经紧张到好几天没睡好觉。他还回应网友对于黑稿的忧虑，表示“咋办呢？不能因为有黑稿，我们就不说话了？”雷军曾在直播中重谈“1300km只充一次电”话题，他表示短视频平台推送的片段很多时候是被水军剪辑的，为了给他贴上“虚假营销”的标签。（界面新闻）</p>\\n<h2>大公司/大事件</h2>\\n<p><strong>丝芭传媒：创始人王子杰去世，享年63岁</strong></p>\\n<p>4月16日，上海丝芭文化传媒集团有限公司发布讣告：公司创始人王子杰，因突发心源性疾病，经抢救无效，于4月14日19时在上海逝世，享年63岁。（界面新闻）</p>\\n<p><strong>杨利娟辞任特海CEO，接手海底捞红石榴计划</strong></p>\\n<p>36氪获悉，4月15日，特海国际发布公告称，杨利娟已辞任公司执行董事兼CEO，并将加入海底捞国际控股有限公司，统筹推动“红石榴计划”实施。公开资料显示，海底捞于2024年8月启动“红石榴计划”，截至2025年底已推出20个餐饮品牌，共计207家餐厅。</p>\\n<p><strong>小米18Pro新增AI按键，支持启动AI功能、控制智能家居及小米汽车</strong></p>\\n<p>消息源“leo_hefeng”4月15日在X平台发布推文，分享了一组渲染图，展示了小米18Pro手机，重点凸显机身侧面的AI按键，支持启动AI功能、控制智能家居及小米汽车。</p>\\n<p>外观方面，小米18Pro延续小米17Pro的三摄布局和后置副屏设计，值得关注的是侧边新增AI按钮。该按钮支持自定义功能，可在任意场景快速启动AI，同时控制智能家居设备，甚至兼容小米汽车。核心规格方面，小米18Pro预计配备6.3英寸显示屏，主摄与3倍长焦采用2亿像素组合，电池容量将突破7000mAh。（财经网科技）</p>\\n<p><strong>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</strong></p>\\n<p>国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，智能化发展的引领作用不断增强，中国人工智能商业化、规模化运营取得了阶段性突破。截至今年3月，日均词元（Token）调用量突破140万亿，比上年末增长超40%。人工智能发展赋能千行百业，带动相关领域快速增长。（证券时报）</p>\\n<p><strong>算力涨价潮席卷全球：阿里、Anthropic连续调价，严重算力荒再现</strong></p>\\n<p>算力涨价潮正在席卷全球，海内外巨头又开始了新一轮调价。阿里云四天连发三条产品涨价公告，调整百炼部分模型单元服务价格及DataWorks部分API免费额度。Anthropic调整了旗下企业级产品Claude Enterprise订阅模式，从每月每用户最高200美元的固定费用，转变为按照实际算力消耗收费，此外用户每月还需要固定缴纳20美元。中信证券指出，Token调用量井喷带来的是算力需求极大爆发，与此同时供给侧受到各类硬约束短期边际增量有限，目前国内外均出现了严重的算力荒。（财联社）</p>\\n<p><strong>研究显示：大语言模型会在蒸馏中“夹带”自己的偏好</strong></p>\\n<p>《自然》15日发表的一项研究显示，大语言模型（LLM）可能会将某些自己的偏好“夹带私货”传授给其他算法，即使在训练数据中清除原始特征后，这些本不需要的特征，仍可能持续存在。在一个案例中，一个模型似乎通过数据中的隐含信号，将自己对猫头鹰的偏好传递给了其他模型。该研究结果表明，在开发LLM时，需要进行更彻底的安全检查。（财联社）</p>\\n<p><strong>京东发布机器人产业服务全景图</strong></p>\\n<p>36氪获悉，4月15日，京东发布“机器人产业服务全景图”。全景图聚焦三大核心：携手超200家品牌，目标2026年销售破百亿；依托超级供应链，建全球最大具身数据采集中心、京东机器人售后维修服务3年覆盖50余城；基于JoyAI大模型加速开放JoyInside附身智能交互能力，为机器人注入“智慧大脑”。</p>\\n<p><strong>电子布库存持续紧张，涨价周期尚未结束</strong></p>\\n<p>从业内获悉，多家电子布（电子级玻璃纤维）厂商库存紧张，部分企业库存不足十天。行业整体扩产进度受织布机供应瓶颈制约，短期内补库难度较大。业内人士分析认为，在织布机瓶颈未突破、产能向高端布倾斜的背景下，电子布高景气格局仍将延续，涨价周期尚未结束。（上证报）</p>\\n<p><strong>亚洲富豪挟250亿美元涌入AI领域，面对高估值毫无惧色</strong></p>\\n<p>据报道，尽管对美国AI企业估值过高的疑虑渐起，亚洲富裕投资者仍向该领域投入数十亿美元的私人资本，毫无惧色。根据PitchBook数据显示，2025年亚洲高净值个人及家族办公室共向全球AI私募融资投入243亿美元。今年动能延续，截至4月8日，新增投资额已达9.5亿美元。这波投资热潮正值SpaceX、OpenAI和Anthropic PBC等行业巨头在募资中持续创下惊人估值。对亚洲富裕投资人而言，抓住世代级科技机会的吸引力，已超越潜在泡沫的风险。（新浪财经）</p>\\n<p><strong>为加速重塑Siri，苹果安排近200名工程师培训AI编程</strong></p>\\n<p>据报道，为了追赶AI竞争对手，苹果正在将近200名Siri工程师送往为期数周的训练营，学习如何使用AI进行编程，旨在提升程序员的AI编程能力。据悉，该培训覆盖了Siri团队近九成工程师。训练营的培训重点将是学习使用Anthropic旗下Claude Code等AI辅助开发工具。</p>\\n<p>在此之前，Siri团队长期沿用传统开发模式，在AI辅助编程方面的应用相对滞后，这也导致近年来Siri的功能迭代速度放缓，与谷歌Assistant、亚马逊Alexa等竞品的差距逐渐拉大。谷歌Assistant深度集成Gemini模型，早已支持多步复合指令、跨应用协同；亚马逊Alexa拥有超10万种兼容智能家居设备，技能库丰富，擅长多设备联动控制。（界面新闻）</p>\\n<p><strong>美联储4月维持利率不变的概率为98.4%</strong></p>\\n<p>据CME“美联储观察”：美联储4月加息25个基点的概率为1.6%，维持利率不变的概率为98.4%。美联储到6月累计降息25个基点的概率为0%，维持利率不变的概率为98%，累计加息25个基点的概率为2%。（财联社）</p>\\n<p><strong>特朗普签发多项输油管道许可，以促进美加之间的石油运输</strong></p>\\n<p>据白宫公布的文件显示，美国总统特朗普15日签发了多项输油管道许可，其中包括一项新建输油管道的许可，旨在促进美国与加拿大之间的原油及油品运输。该建设许可已颁发给Bakken Pipeline Company，用于北达科他州伯克县的管道设施建设。此外，他还签发了其他许可，以维护和运营位于北达科他州和密西根州、靠近边境地区的现有输油管道。（新浪财经）</p>\\n<p><strong>美股三大指数集体收涨，纳指十二连涨再创收盘新高</strong></p>\\n<p>36氪获悉，4月16日收盘，美股三大指数集体上涨，纳指涨0.36%，为连续12个交易日上涨续创新高，标普500指数涨0.26%创历史新高，道指涨0.24%。大型科技股多数上涨，英特尔、甲骨文涨超5%，微软涨超2%，Meta、亚马逊、奈飞小幅上涨；苹果跌超1%，特斯拉、谷歌、英伟达小幅下跌。热门中概股多数走强，蔚来涨超6%，阿里巴巴、百度、小鹏集团涨超3%，理想汽车、拼多多涨超1%；老虎证券、小马智行跌超1%。</p>\\n<p><strong>聚焦充电宝等重点领域，市场监管总局开展专项行动打击虚假CCC认证标志</strong></p>\\n<p>市场监管总局在全国范围内部署开展CCC认证守底线专项行动，全链条、全方位加强CCC认证监管，营造安全放心的消费环境。强制性产品认证也就是我们常说的CCC认证制度是我国政府遵循世贸组织规则和国际通行规则建立的具有市场准入性质的合格评定体系，列入CCC认证目录的产品，需要获证后才能出厂、进口、销售。此次专项行动将突出一个“严”字。将对指定认证机构实施全覆盖监督检查，聚焦充电宝、电动自行车、燃气燃烧器具等重点领域，开展有效性抽查。深入推进CCC认证标志试点改革，精准打击虚假CCC认证标志，加强产品质量责任追溯。（界面新闻）</p>\\n<p><strong>三星请求法院禁止工会开展非法罢工活动</strong></p>\\n<p>一名发言人表示，三星电子于16日向法院提起申请，要求禁止其韩国工会在计划中的罢工期间开展非法活动。眼下这场薪资纠纷，恐将扰乱这家全球最大存储芯片制造商的生产运营。三星并未详细说明此次法律行动的具体细节。工会则将此举称为“宣战”，指责公司侵犯了受法律保护的罢工权。（新浪财经）</p>\\n<p><strong>万科回应总裁空缺：已由董事长及高管团队分担相关职责</strong></p>\\n<p>36氪获悉，万科A在深交所互动易平台回应了总裁职位空缺、泊寓业务、化债等市场关注。对总裁一职的空缺，万科表示，公司总裁职位目前处于空缺状态，公司已通过董事会授权及高管分工调整，由董事长及公司高管团队分担相关职责，确保了公司经营决策的正常开展和公司治理的有效运作。万科还提到，受多重因素影响，当前公司面临着多重风险挑战，整体经营形势依然十分严峻。在各方支持下，集团全力推进改革化险工作。</p>\\n<p><strong>国际原油市场逐渐回归基本面定价，库存消耗继续推升油价</strong></p>\\n<p>当前，国际原油市场从3月份“溢价绑架油价”的恐慌性交易，逐渐回归至基本面定价。最直观的数据表现为，纽约WTI近月期货合约升水较峰值回落约60%，国内原油期权波动率指数（VIX）自高点腰斩，同时原油期货沉淀资金规模降幅超四成。（证券时报）</p>\\n<p><strong>摩根大通CEO杰米·戴蒙出售价值4000万美元摩根大通股票</strong></p>\\n<p>摩根大通首席执行官杰米·戴蒙（Jamie Dimon）4月15日出售了价值超过4000万美元的该行股票，这是他最新一次减持套现。戴蒙执掌这家银行已超过20年，直到2023年底他才开始出售自己持有的该行股票，当时他卖出了100万股，价值约1.8亿美元。他去年出售了价值约2.33亿美元的股票，今年2月出售了价值约2100万美元的股票。他目前仍持有该行超过620万股股票，价值约19亿美元。这些股票由戴蒙、他的妻子和他的家族信托持有。（新浪财经）</p>\\n<h2>上市进行时</h2>\\n<p><strong>先正达</strong></p>\\n<p>先正达寻求最早6月在香港以保密方式提交IPO申请。（财联社）</p>\\n<p><strong>春光集团</strong></p>\\n<p>36氪获悉，春光集团披露招股书，拟于近期在深市发行新股并上市。</p>\\n<p><strong>中科宇航</strong></p>\\n<p>36氪获悉，上交所官网显示，4月15日，商业火箭企业中科宇航IPO状态变为已问询。中科宇航成立于2018年，3月31日，该公司IPO申请获受理，后被抽中现场检查。此次IPO，中科宇航拟募资41.8亿元，其保荐机构为国泰海通证券。</p>\\n<p><strong>华盛锂电</strong></p>\\n<p>36氪获悉，华盛锂电公告，公司已于2026年4月15日向香港联交所递交了发行境外上市股份(H股)并在香港联交所主板上市的申请，并于同日在香港联交所网站刊登了本次发行上市的申请资料。本次发行上市事项的相关申请资料为公司按照香港证监会和香港联交所的要求编制和刊发，为草拟版本，且所载资料可能会适时作出更新及修订。</p>\\n<h2>AI最前沿</h2>\\n<p><strong>腾讯混元3D世界模型2.0发布并开源</strong></p>\\n<p>36氪获悉，4月16日，混元3D世界模型2.0（HY-World 2.0）正式发布并开源。HY-World 2.0是一个多模态世界模型，能够根据文字、图片、视频等不同类型输入，自动生成、重建和模拟3D世界，同时支持多格式3D资产（Mesh/3DGS/点云等）导出，支持与现有的游戏工作流无缝对接，用于快速生成游戏地图和关卡原型。</p>\\n<p><strong>OpenAI退出挪威“星门”数据中心合作，微软接手</strong></p>\\n<p>OpenAI放弃直接从英国AI云服务商Nscale在挪威运营的数据中心租赁算力的计划。微软将接手该数据中心的剩余算力。OpenAI表示，正与微软洽谈从其手中租赁算力。（新浪财经）</p>\\n<p><strong>Adobe推出可操作Claude的创意工具AI助手</strong></p>\\n<p>Adobe4月15日宣布推出一款全新的人工智能助手，旨在帮助用户在其照片、视频及数字内容编辑软件套件中执行各项任务。该助手还将与Anthropic的Claude AI模型进行集成。（新浪财经）</p>\\n<p><strong>马斯克的xAI据悉将向编程初创公司Cursor提供算力支持</strong></p>\\n<p>据知情人士透露，埃隆·马斯克的人工智能公司xAI计划与编程初创公司Cursor达成一项新的合作协议，让后者利用其庞大的计算能力。消息人士称，Cursor计划在xAI的基础设施上训练其最新的AI编程模型Composer 2.5。他们还表示，Cursor将使用xAI的数万快图形处理器（GPU）。（新浪财经）</p>\\n<p><strong>阶跃发布新一代语音生成模型StepAudio 2.5 TTS</strong></p>\\n<p>36氪获悉，4月16日，阶跃发布新一代语音生成模型StepAudio 2.5 TTS。据介绍，该模型围绕全局语境控制、文中语境控制，以及零样本复刻与全音色控制等能力进行了升级，主要面向角色配音、有声内容创作、智能语音交互等场景。StepAudio 2.5 TTS支持利用自然语言来进行合成控制。目前，StepAudio 2.5 TTS已全量上线“阶跃星辰开放平台”和Step Plan。</p>\\n<h2>大公司财报</h2>\\n<p><strong>台积电：预计第二季度毛利率65.5％-67.5％</strong></p>\\n<p>台积电预计第二季度毛利率65.5％-67.5％，市场预估64.1％；预计第二季度销售额390亿美元-402亿美元，预估381.1亿美元。（财联社）</p>\\n<p><strong>永辉超市：一季度净利润2.87亿元，同比增长94.40%</strong></p>\\n<p>36氪获悉，永辉超市发布2026年第一季度业绩报告。报告显示，一季度营业收入133.67亿元，同比减少23.53%；净利润2.87亿元，同比增长94.40%；扣非后归母净利润为2.47亿元，同比增长79.55%。此外，截至一季度末，永辉超市全国累计调改门店达327家。</p>\\n<p><strong>贵州茅台：2025年实现营业收入1688.38亿元，同比下降1.21%</strong></p>\\n<p>36氪获悉，贵州茅台发布2025年业绩报告。报告显示，2025年实现营业收入1688.38亿元，同比下降1.21%；归属于上市公司股东的净利润为823.20亿元，同比下降4.53%。拟向全体股东每股派发现金红利27.993元（含税）。</p>\\n<p><strong>太平鸟：2025年净利润1.74亿元，同比下降32.57%</strong></p>\\n<p>36氪获悉，太平鸟发布2025年业绩报告。报告显示，2025年营业收入63.34亿元，同比下降6.88%。净利润1.74亿元，同比下降32.57%。公司拟每10股派发现金红利3元（含税），拟派发现金红利1.41亿元，剩余未分配利润结转以后年度分配。2026年第一季度营收为16.56亿元，同比下降0.75%：净利润为1.37亿元，同比增长10.3%。</p>\\n<p><strong>华友钴业：2026年第一季度净利润24.97亿元，同比增长99.45%</strong></p>\\n<p>36氪获悉，华友钴业发布2026年第一季度业绩报告。报告显示，一季度实现营业收入258.04亿元，同比增长44.62%；归属于上市公司股东的净利润为24.97亿元，同比增长99.45%。业绩变动主要系产品销量增加及金属价格回升所致，以及主要受益于镍、钴、锂等金属价格的回升及公司产业一体化经营优势的持续释放。</p>\\n<h2>投融资</h2>\\n<p><strong>“它石智航”完成超4.5亿美金Pre-A轮融资</strong></p>\\n<p>4月16日，“它石智航”宣布完成超4.5亿美金Pre-A轮融资，创下中国具身智能有史以来最高单轮融资纪录，由高瓴创投，与红杉中国联合领投，美团龙珠、中金资本、凯联资本、东方富海、钧山投资等财务基金跟投。本轮融资将用于加速打造通用具身大模型AWE和持续吸引行业人才，下一轮融资将重点用于打造真干活、真量产的机器人。</p>\\n<h2>酷产品</h2>\\n<p><strong>宝马将在北京车展推出M3 40周年限量版</strong></p>\\n<p>36氪获悉，宝马将在北京国际车展推出M3 40周年限量版车型，涵盖轿车与旅行车两种版本，在华各限量20台，于2026年下半年上市。</p>\\n<p><strong>奥迪高管透露明年将推第三款中国专属车型</strong></p>\\n<p>据报道，德国奥迪汽车公司首席执行官索内拉表示，为重夺中国市场份额，奥迪计划于明年与中国合作伙伴上汽集团联合推出第三款中国专属车型，定位为高端运动型轿车。索内拉强调，该车型已进入开发阶段，并延续“中国需求优先”策略。（界面新闻）</p>\\n<p><strong>追觅科技旗下AI视觉机器人品牌NAVO亮相广交会</strong></p>\\n<p>36氪获悉，4月15日，第139届中国进出口商品交易会（即2026春季广交会）在广州开幕，追觅科技旗下AI视觉机器人品牌NAVO，携全系列高端AI智能摄像头产品亮相。据了解，NAVO自研专属安防芯片架构，搭配黑光全彩夜视引擎，首创事件级AI平台AlgoMart。上市半年，订单销售额超过6000万。</p>\\n<h2>AI图谱</h2>\\n<p><strong>AI图谱，带你解读最新最快的AI咨询。46小时内两次袭击，美国人这么怕AI？</strong></p>\\n<p><strong>整理</strong>｜Kris </p>\", \"is_policy\": 0, \"origin_msg\": {\"link\": \"https://36kr.com/p/3770155029398018?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/p/3770155029398018?f=rss\", \"type\": \"text/html\"}], \"title\": \"8点1氪丨全季大连某酒店账号公开多名客人特殊订单备注；金立手机创始人被曝在印尼卖家具；雷军将连播15小时测试新SU7续航\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"<h2>今日热点导览</h2>\\n  <p>丝芭传媒：创始人王子杰去世，享年63岁</p>\\n  <p>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</p>\\n  <p>京东发布机器人产业服务全景图</p>\\n  <p>为加速重塑Siri，苹果安排近200名工程师培训AI编程</p>\\n  <p>特朗普签发多项输油管道许可，以促进美加之间的石油运输</p>\\n  <h2>TOP3大新闻</h2>\\n  <p><strong>全季大连某酒店账号公开多名客人特殊订单备注，华住集团客服回应</strong></p>\\n  <p>近日，一则题为“全季客人备注大赏”的帖文在社交平台引发争议。涉事账号“全季大连xx酒店”将多名客人的特殊订单备注公开发布，配文称“每天被客人备注笑到捶桌”“前台已笑晕在系统里”。有网友发帖表示：“一个酒店官方账号，私自将客人订单备注发到网上，评论区引起网友无谓的猜测，有些甚至偏恶意。”</p>\\n  <p>针对此事，上游新闻记者4月16日致电涉事酒店。工作人员回应称，发布帖文的账号并非酒店官方账号，具体由谁开设他并不清楚。华住酒店集团客服表示，核查后发现，该账号确认为员工的个人账号，目前已要求该员工立即注销账号，并对其进行通报批评。（上游新闻）</p>\\n  <p><strong>消失8年后，金立创始人刘立荣被曝在印尼卖家具</strong></p>\\n  <p>据红星新闻4月16日报道，多位网友爆料称，刘立荣在印尼经营家具公司Starlead。去年7月，他曾身穿印尼当地传统服装，出席Starlead展厅开幕仪式，并在上台讲话后落座于该公司CEO身旁。而Starlead的创始人何星是刘立荣的老部下。Starlead公司官网显示，该公司成立于2023年9月，瞄准出海印尼的中国企业，致力于提供现代实用的家居家具，在印尼专卖店超过20家，海尔、宁德时代、小米等都是其客户。Starlead的创始人何星，是刘立荣的“老部下”。</p>\\n  <p>2017年，金立手机出货量同比减少了1000万台，远低于预期。同一年，有关刘立荣赌博输掉巨额资金的传闻开始在金立供应商之间流传。当时有接近金立公司股东的人士表示，董事长刘立荣在赌博上输了超过100亿，挪用公款的数目可能在60亿左右，不排除有人设局。刘立荣则在接受媒体采访时承认自己曾去塞班赌博，并表示懊悔，“赌这个东西真的不能沾，一失足成千古恨。不光是在于涉及多少钱，它会对你的品行定性，让一个人人格破产。”但他称自己没有输掉100亿，而是“十几亿”，其中不乏“借用”公司的钱。（红星新闻）</p>\\n  <p><strong>雷军将直播新SU7续航测试，从北京到上海大约15小时</strong></p>\\n  <p>4月16日，雷军发文称，去年年初他曾说过，“我开YU7标准版，充满电，从北京到上海，1300公里高速，中间只充了一次电，我非常震惊”。雷军表示，这次新SU7打算直播给大家看，他将于17日早上六点半开始，全程参加并直播从北京到上海的长途续航测试，大约十五小时。在评论区雷军回复网友称，自己已经紧张到好几天没睡好觉。他还回应网友对于黑稿的忧虑，表示“咋办呢？不能因为有黑稿，我们就不说话了？”雷军曾在直播中重谈“1300km只充一次电”话题，他表示短视频平台推送的片段很多时候是被水军剪辑的，为了给他贴上“虚假营销”的标签。（界面新闻）</p>\\n  <h2>大公司/大事件</h2>\\n  <p><strong>丝芭传媒：创始人王子杰去世，享年63岁</strong></p>\\n  <p>4月16日，上海丝芭文化传媒集团有限公司发布讣告：公司创始人王子杰，因突发心源性疾病，经抢救无效，于4月14日19时在上海逝世，享年63岁。（界面新闻）</p>\\n  <p><strong>杨利娟辞任特海CEO，接手海底捞红石榴计划</strong></p>\\n  <p>36氪获悉，4月15日，特海国际发布公告称，杨利娟已辞任公司执行董事兼CEO，并将加入海底捞国际控股有限公司，统筹推动“红石榴计划”实施。公开资料显示，海底捞于2024年8月启动“红石榴计划”，截至2025年底已推出20个餐饮品牌，共计207家餐厅。</p>\\n  <p><strong>小米18Pro新增AI按键，支持启动AI功能、控制智能家居及小米汽车</strong></p>\\n  <p>消息源“leo_hefeng”4月15日在X平台发布推文，分享了一组渲染图，展示了小米18Pro手机，重点凸显机身侧面的AI按键，支持启动AI功能、控制智能家居及小米汽车。</p>\\n  <p>外观方面，小米18Pro延续小米17Pro的三摄布局和后置副屏设计，值得关注的是侧边新增AI按钮。该按钮支持自定义功能，可在任意场景快速启动AI，同时控制智能家居设备，甚至兼容小米汽车。核心规格方面，小米18Pro预计配备6.3英寸显示屏，主摄与3倍长焦采用2亿像素组合，电池容量将突破7000mAh。（财经网科技）</p>\\n  <p><strong>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</strong></p>\\n  <p>国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，智能化发展的引领作用不断增强，中国人工智能商业化、规模化运营取得了阶段性突破。截至今年3月，日均词元（Token）调用量突破140万亿，比上年末增长超40%。人工智能发展赋能千行百业，带动相关领域快速增长。（证券时报）</p>\\n  <p><strong>算力涨价潮席卷全球：阿里、Anthropic连续调价，严重算力荒再现</strong></p>\\n  <p>算力涨价潮正在席卷全球，海内外巨头又开始了新一轮调价。阿里云四天连发三条产品涨价公告，调整百炼部分模型单元服务价格及DataWorks部分API免费额度。Anthropic调整了旗下企业级产品Claude Enterprise订阅模式，从每月每用户最高200美元的固定费用，转变为按照实际算力消耗收费，此外用户每月还需要固定缴纳20美元。中信证券指出，Token调用量井喷带来的是算力需求极大爆发，与此同时供给侧受到各类硬约束短期边际增量有限，目前国内外均出现了严重的算力荒。（财联社）</p>\\n  <p><strong>研究显示：大语言模型会在蒸馏中“夹带”自己的偏好</strong></p>\\n  <p>《自然》15日发表的一项研究显示，大语言模型（LLM）可能会将某些自己的偏好“夹带私货”传授给其他算法，即使在训练数据中清除原始特征后，这些本不需要的特征，仍可能持续存在。在一个案例中，一个模型似乎通过数据中的隐含信号，将自己对猫头鹰的偏好传递给了其他模型。该研究结果表明，在开发LLM时，需要进行更彻底的安全检查。（财联社）</p>\\n  <p><strong>京东发布机器人产业服务全景图</strong></p>\\n  <p>36氪获悉，4月15日，京东发布“机器人产业服务全景图”。全景图聚焦三大核心：携手超200家品牌，目标2026年销售破百亿；依托超级供应链，建全球最大具身数据采集中心、京东机器人售后维修服务3年覆盖50余城；基于JoyAI大模型加速开放JoyInside附身智能交互能力，为机器人注入“智慧大脑”。</p>\\n  <p><strong>电子布库存持续紧张，涨价周期尚未结束</strong></p>\\n  <p>从业内获悉，多家电子布（电子级玻璃纤维）厂商库存紧张，部分企业库存不足十天。行业整体扩产进度受织布机供应瓶颈制约，短期内补库难度较大。业内人士分析认为，在织布机瓶颈未突破、产能向高端布倾斜的背景下，电子布高景气格局仍将延续，涨价周期尚未结束。（上证报）</p>\\n  <p><strong>亚洲富豪挟250亿美元涌入AI领域，面对高估值毫无惧色</strong></p>\\n  <p>据报道，尽管对美国AI企业估值过高的疑虑渐起，亚洲富裕投资者仍向该领域投入数十亿美元的私人资本，毫无惧色。根据PitchBook数据显示，2025年亚洲高净值个人及家族办公室共向全球AI私募融资投入243亿美元。今年动能延续，截至4月8日，新增投资额已达9.5亿美元。这波投资热潮正值SpaceX、OpenAI和Anthropic PBC等行业巨头在募资中持续创下惊人估值。对亚洲富裕投资人而言，抓住世代级科技机会的吸引力，已超越潜在泡沫的风险。（新浪财经）</p>\\n  <p><strong>为加速重塑Siri，苹果安排近200名工程师培训AI编程</strong></p>\\n  <p>据报道，为了追赶AI竞争对手，苹果正在将近200名Siri工程师送往为期数周的训练营，学习如何使用AI进行编程，旨在提升程序员的AI编程能力。据悉，该培训覆盖了Siri团队近九成工程师。训练营的培训重点将是学习使用Anthropic旗下Claude Code等AI辅助开发工具。</p>\\n  <p>在此之前，Siri团队长期沿用传统开发模式，在AI辅助编程方面的应用相对滞后，这也导致近年来Siri的功能迭代速度放缓，与谷歌Assistant、亚马逊Alexa等竞品的差距逐渐拉大。谷歌Assistant深度集成Gemini模型，早已支持多步复合指令、跨应用协同；亚马逊Alexa拥有超10万种兼容智能家居设备，技能库丰富，擅长多设备联动控制。（界面新闻）</p>\\n  <p><strong>美联储4月维持利率不变的概率为98.4%</strong></p>\\n  <p>据CME“美联储观察”：美联储4月加息25个基点的概率为1.6%，维持利率不变的概率为98.4%。美联储到6月累计降息25个基点的概率为0%，维持利率不变的概率为98%，累计加息25个基点的概率为2%。（财联社）</p>\\n  <p><strong>特朗普签发多项输油管道许可，以促进美加之间的石油运输</strong></p>\\n  <p>据白宫公布的文件显示，美国总统特朗普15日签发了多项输油管道许可，其中包括一项新建输油管道的许可，旨在促进美国与加拿大之间的原油及油品运输。该建设许可已颁发给Bakken Pipeline Company，用于北达科他州伯克县的管道设施建设。此外，他还签发了其他许可，以维护和运营位于北达科他州和密西根州、靠近边境地区的现有输油管道。（新浪财经）</p>\\n  <p><strong>美股三大指数集体收涨，纳指十二连涨再创收盘新高</strong></p>\\n  <p>36氪获悉，4月16日收盘，美股三大指数集体上涨，纳指涨0.36%，为连续12个交易日上涨续创新高，标普500指数涨0.26%创历史新高，道指涨0.24%。大型科技股多数上涨，英特尔、甲骨文涨超5%，微软涨超2%，Meta、亚马逊、奈飞小幅上涨；苹果跌超1%，特斯拉、谷歌、英伟达小幅下跌。热门中概股多数走强，蔚来涨超6%，阿里巴巴、百度、小鹏集团涨超3%，理想汽车、拼多多涨超1%；老虎证券、小马智行跌超1%。</p>\\n  <p><strong>聚焦充电宝等重点领域，市场监管总局开展专项行动打击虚假CCC认证标志</strong></p>\\n  <p>市场监管总局在全国范围内部署开展CCC认证守底线专项行动，全链条、全方位加强CCC认证监管，营造安全放心的消费环境。强制性产品认证也就是我们常说的CCC认证制度是我国政府遵循世贸组织规则和国际通行规则建立的具有市场准入性质的合格评定体系，列入CCC认证目录的产品，需要获证后才能出厂、进口、销售。此次专项行动将突出一个“严”字。将对指定认证机构实施全覆盖监督检查，聚焦充电宝、电动自行车、燃气燃烧器具等重点领域，开展有效性抽查。深入推进CCC认证标志试点改革，精准打击虚假CCC认证标志，加强产品质量责任追溯。（界面新闻）</p>\\n  <p><strong>三星请求法院禁止工会开展非法罢工活动</strong></p>\\n  <p>一名发言人表示，三星电子于16日向法院提起申请，要求禁止其韩国工会在计划中的罢工期间开展非法活动。眼下这场薪资纠纷，恐将扰乱这家全球最大存储芯片制造商的生产运营。三星并未详细说明此次法律行动的具体细节。工会则将此举称为“宣战”，指责公司侵犯了受法律保护的罢工权。（新浪财经）</p>\\n  <p><strong>万科回应总裁空缺：已由董事长及高管团队分担相关职责</strong></p>\\n  <p>36氪获悉，万科A在深交所互动易平台回应了总裁职位空缺、泊寓业务、化债等市场关注。对总裁一职的空缺，万科表示，公司总裁职位目前处于空缺状态，公司已通过董事会授权及高管分工调整，由董事长及公司高管团队分担相关职责，确保了公司经营决策的正常开展和公司治理的有效运作。万科还提到，受多重因素影响，当前公司面临着多重风险挑战，整体经营形势依然十分严峻。在各方支持下，集团全力推进改革化险工作。</p>\\n  <p><strong>国际原油市场逐渐回归基本面定价，库存消耗继续推升油价</strong></p>\\n  <p>当前，国际原油市场从3月份“溢价绑架油价”的恐慌性交易，逐渐回归至基本面定价。最直观的数据表现为，纽约WTI近月期货合约升水较峰值回落约60%，国内原油期权波动率指数（VIX）自高点腰斩，同时原油期货沉淀资金规模降幅超四成。（证券时报）</p>\\n  <p><strong>摩根大通CEO杰米·戴蒙出售价值4000万美元摩根大通股票</strong></p>\\n  <p>摩根大通首席执行官杰米·戴蒙（Jamie Dimon）4月15日出售了价值超过4000万美元的该行股票，这是他最新一次减持套现。戴蒙执掌这家银行已超过20年，直到2023年底他才开始出售自己持有的该行股票，当时他卖出了100万股，价值约1.8亿美元。他去年出售了价值约2.33亿美元的股票，今年2月出售了价值约2100万美元的股票。他目前仍持有该行超过620万股股票，价值约19亿美元。这些股票由戴蒙、他的妻子和他的家族信托持有。（新浪财经）</p>\\n  <h2>上市进行时</h2>\\n  <p><strong>先正达</strong></p>\\n  <p>先正达寻求最早6月在香港以保密方式提交IPO申请。（财联社）</p>\\n  <p><strong>春光集团</strong></p>\\n  <p>36氪获悉，春光集团披露招股书，拟于近期在深市发行新股并上市。</p>\\n  <p><strong>中科宇航</strong></p>\\n  <p>36氪获悉，上交所官网显示，4月15日，商业火箭企业中科宇航IPO状态变为已问询。中科宇航成立于2018年，3月31日，该公司IPO申请获受理，后被抽中现场检查。此次IPO，中科宇航拟募资41.8亿元，其保荐机构为国泰海通证券。</p>\\n  <p><strong>华盛锂电</strong></p>\\n  <p>36氪获悉，华盛锂电公告，公司已于2026年4月15日向香港联交所递交了发行境外上市股份(H股)并在香港联交所主板上市的申请，并于同日在香港联交所网站刊登了本次发行上市的申请资料。本次发行上市事项的相关申请资料为公司按照香港证监会和香港联交所的要求编制和刊发，为草拟版本，且所载资料可能会适时作出更新及修订。</p>\\n  <h2>AI最前沿</h2>\\n  <p><strong>腾讯混元3D世界模型2.0发布并开源</strong></p>\\n  <p>36氪获悉，4月16日，混元3D世界模型2.0（HY-World 2.0）正式发布并开源。HY-World 2.0是一个多模态世界模型，能够根据文字、图片、视频等不同类型输入，自动生成、重建和模拟3D世界，同时支持多格式3D资产（Mesh/3DGS/点云等）导出，支持与现有的游戏工作流无缝对接，用于快速生成游戏地图和关卡原型。</p>\\n  <p><strong>OpenAI退出挪威“星门”数据中心合作，微软接手</strong></p>\\n  <p>OpenAI放弃直接从英国AI云服务商Nscale在挪威运营的数据中心租赁算力的计划。微软将接手该数据中心的剩余算力。OpenAI表示，正与微软洽谈从其手中租赁算力。（新浪财经）</p>\\n  <p><strong>Adobe推出可操作Claude的创意工具AI助手</strong></p>\\n  <p>Adobe4月15日宣布推出一款全新的人工智能助手，旨在帮助用户在其照片、视频及数字内容编辑软件套件中执行各项任务。该助手还将与Anthropic的Claude AI模型进行集成。（新浪财经）</p>\\n  <p><strong>马斯克的xAI据悉将向编程初创公司Cursor提供算力支持</strong></p>\\n  <p>据知情人士透露，埃隆·马斯克的人工智能公司xAI计划与编程初创公司Cursor达成一项新的合作协议，让后者利用其庞大的计算能力。消息人士称，Cursor计划在xAI的基础设施上训练其最新的AI编程模型Composer 2.5。他们还表示，Cursor将使用xAI的数万快图形处理器（GPU）。（新浪财经）</p>\\n  <p><strong>阶跃发布新一代语音生成模型StepAudio 2.5 TTS</strong></p>\\n  <p>36氪获悉，4月16日，阶跃发布新一代语音生成模型StepAudio 2.5 TTS。据介绍，该模型围绕全局语境控制、文中语境控制，以及零样本复刻与全音色控制等能力进行了升级，主要面向角色配音、有声内容创作、智能语音交互等场景。StepAudio 2.5 TTS支持利用自然语言来进行合成控制。目前，StepAudio 2.5 TTS已全量上线“阶跃星辰开放平台”和Step Plan。</p>\\n  <h2>大公司财报</h2>\\n  <p><strong>台积电：预计第二季度毛利率65.5％-67.5％</strong></p>\\n  <p>台积电预计第二季度毛利率65.5％-67.5％，市场预估64.1％；预计第二季度销售额390亿美元-402亿美元，预估381.1亿美元。（财联社）</p>\\n  <p><strong>永辉超市：一季度净利润2.87亿元，同比增长94.40%</strong></p>\\n  <p>36氪获悉，永辉超市发布2026年第一季度业绩报告。报告显示，一季度营业收入133.67亿元，同比减少23.53%；净利润2.87亿元，同比增长94.40%；扣非后归母净利润为2.47亿元，同比增长79.55%。此外，截至一季度末，永辉超市全国累计调改门店达327家。</p>\\n  <p><strong>贵州茅台：2025年实现营业收入1688.38亿元，同比下降1.21%</strong></p>\\n  <p>36氪获悉，贵州茅台发布2025年业绩报告。报告显示，2025年实现营业收入1688.38亿元，同比下降1.21%；归属于上市公司股东的净利润为823.20亿元，同比下降4.53%。拟向全体股东每股派发现金红利27.993元（含税）。</p>\\n  <p><strong>太平鸟：2025年净利润1.74亿元，同比下降32.57%</strong></p>\\n  <p>36氪获悉，太平鸟发布2025年业绩报告。报告显示，2025年营业收入63.34亿元，同比下降6.88%。净利润1.74亿元，同比下降32.57%。公司拟每10股派发现金红利3元（含税），拟派发现金红利1.41亿元，剩余未分配利润结转以后年度分配。2026年第一季度营收为16.56亿元，同比下降0.75%：净利润为1.37亿元，同比增长10.3%。</p>\\n  <p><strong>华友钴业：2026年第一季度净利润24.97亿元，同比增长99.45%</strong></p>\\n  <p>36氪获悉，华友钴业发布2026年第一季度业绩报告。报告显示，一季度实现营业收入258.04亿元，同比增长44.62%；归属于上市公司股东的净利润为24.97亿元，同比增长99.45%。业绩变动主要系产品销量增加及金属价格回升所致，以及主要受益于镍、钴、锂等金属价格的回升及公司产业一体化经营优势的持续释放。</p>\\n  <h2>投融资</h2>\\n  <p><strong>“它石智航”完成超4.5亿美金Pre-A轮融资</strong></p>\\n  <p>4月16日，“它石智航”宣布完成超4.5亿美金Pre-A轮融资，创下中国具身智能有史以来最高单轮融资纪录，由高瓴创投，与红杉中国联合领投，美团龙珠、中金资本、凯联资本、东方富海、钧山投资等财务基金跟投。本轮融资将用于加速打造通用具身大模型AWE和持续吸引行业人才，下一轮融资将重点用于打造真干活、真量产的机器人。</p>\\n  <h2>酷产品</h2>\\n  <p><strong>宝马将在北京车展推出M3 40周年限量版</strong></p>\\n  <p>36氪获悉，宝马将在北京国际车展推出M3 40周年限量版车型，涵盖轿车与旅行车两种版本，在华各限量20台，于2026年下半年上市。</p>\\n  <p><strong>奥迪高管透露明年将推第三款中国专属车型</strong></p>\\n  <p>据报道，德国奥迪汽车公司首席执行官索内拉表示，为重夺中国市场份额，奥迪计划于明年与中国合作伙伴上汽集团联合推出第三款中国专属车型，定位为高端运动型轿车。索内拉强调，该车型已进入开发阶段，并延续“中国需求优先”策略。（界面新闻）</p>\\n  <p><strong>追觅科技旗下AI视觉机器人品牌NAVO亮相广交会</strong></p>\\n  <p>36氪获悉，4月15日，第139届中国进出口商品交易会（即2026春季广交会）在广州开幕，追觅科技旗下AI视觉机器人品牌NAVO，携全系列高端AI智能摄像头产品亮相。据了解，NAVO自研专属安防芯片架构，搭配黑光全彩夜视引擎，首创事件级AI平台AlgoMart。上市半年，订单销售额超过6000万。</p>\\n  <h2>AI图谱</h2>\\n  <p><strong>AI图谱，带你解读最新最快的AI咨询。46小时内两次袭击，美国人这么怕AI？</strong></p>\\n  <p><strong>整理</strong>｜Kris&nbsp;</p>\", \"published\": \"2026-04-17 08:02:44  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"8点1氪丨全季大连某酒店账号公开多名客人特殊订单备注；金立手机创始人被曝在印尼卖家具；雷军将连播15小时测试新SU7续航\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"<h2>今日热点导览</h2>\\n  <p>丝芭传媒：创始人王子杰去世，享年63岁</p>\\n  <p>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</p>\\n  <p>京东发布机器人产业服务全景图</p>\\n  <p>为加速重塑Siri，苹果安排近200名工程师培训AI编程</p>\\n  <p>特朗普签发多项输油管道许可，以促进美加之间的石油运输</p>\\n  <h2>TOP3大新闻</h2>\\n  <p><strong>全季大连某酒店账号公开多名客人特殊订单备注，华住集团客服回应</strong></p>\\n  <p>近日，一则题为“全季客人备注大赏”的帖文在社交平台引发争议。涉事账号“全季大连xx酒店”将多名客人的特殊订单备注公开发布，配文称“每天被客人备注笑到捶桌”“前台已笑晕在系统里”。有网友发帖表示：“一个酒店官方账号，私自将客人订单备注发到网上，评论区引起网友无谓的猜测，有些甚至偏恶意。”</p>\\n  <p>针对此事，上游新闻记者4月16日致电涉事酒店。工作人员回应称，发布帖文的账号并非酒店官方账号，具体由谁开设他并不清楚。华住酒店集团客服表示，核查后发现，该账号确认为员工的个人账号，目前已要求该员工立即注销账号，并对其进行通报批评。（上游新闻）</p>\\n  <p><strong>消失8年后，金立创始人刘立荣被曝在印尼卖家具</strong></p>\\n  <p>据红星新闻4月16日报道，多位网友爆料称，刘立荣在印尼经营家具公司Starlead。去年7月，他曾身穿印尼当地传统服装，出席Starlead展厅开幕仪式，并在上台讲话后落座于该公司CEO身旁。而Starlead的创始人何星是刘立荣的老部下。Starlead公司官网显示，该公司成立于2023年9月，瞄准出海印尼的中国企业，致力于提供现代实用的家居家具，在印尼专卖店超过20家，海尔、宁德时代、小米等都是其客户。Starlead的创始人何星，是刘立荣的“老部下”。</p>\\n  <p>2017年，金立手机出货量同比减少了1000万台，远低于预期。同一年，有关刘立荣赌博输掉巨额资金的传闻开始在金立供应商之间流传。当时有接近金立公司股东的人士表示，董事长刘立荣在赌博上输了超过100亿，挪用公款的数目可能在60亿左右，不排除有人设局。刘立荣则在接受媒体采访时承认自己曾去塞班赌博，并表示懊悔，“赌这个东西真的不能沾，一失足成千古恨。不光是在于涉及多少钱，它会对你的品行定性，让一个人人格破产。”但他称自己没有输掉100亿，而是“十几亿”，其中不乏“借用”公司的钱。（红星新闻）</p>\\n  <p><strong>雷军将直播新SU7续航测试，从北京到上海大约15小时</strong></p>\\n  <p>4月16日，雷军发文称，去年年初他曾说过，“我开YU7标准版，充满电，从北京到上海，1300公里高速，中间只充了一次电，我非常震惊”。雷军表示，这次新SU7打算直播给大家看，他将于17日早上六点半开始，全程参加并直播从北京到上海的长途续航测试，大约十五小时。在评论区雷军回复网友称，自己已经紧张到好几天没睡好觉。他还回应网友对于黑稿的忧虑，表示“咋办呢？不能因为有黑稿，我们就不说话了？”雷军曾在直播中重谈“1300km只充一次电”话题，他表示短视频平台推送的片段很多时候是被水军剪辑的，为了给他贴上“虚假营销”的标签。（界面新闻）</p>\\n  <h2>大公司/大事件</h2>\\n  <p><strong>丝芭传媒：创始人王子杰去世，享年63岁</strong></p>\\n  <p>4月16日，上海丝芭文化传媒集团有限公司发布讣告：公司创始人王子杰，因突发心源性疾病，经抢救无效，于4月14日19时在上海逝世，享年63岁。（界面新闻）</p>\\n  <p><strong>杨利娟辞任特海CEO，接手海底捞红石榴计划</strong></p>\\n  <p>36氪获悉，4月15日，特海国际发布公告称，杨利娟已辞任公司执行董事兼CEO，并将加入海底捞国际控股有限公司，统筹推动“红石榴计划”实施。公开资料显示，海底捞于2024年8月启动“红石榴计划”，截至2025年底已推出20个餐饮品牌，共计207家餐厅。</p>\\n  <p><strong>小米18Pro新增AI按键，支持启动AI功能、控制智能家居及小米汽车</strong></p>\\n  <p>消息源“leo_hefeng”4月15日在X平台发布推文，分享了一组渲染图，展示了小米18Pro手机，重点凸显机身侧面的AI按键，支持启动AI功能、控制智能家居及小米汽车。</p>\\n  <p>外观方面，小米18Pro延续小米17Pro的三摄布局和后置副屏设计，值得关注的是侧边新增AI按钮。该按钮支持自定义功能，可在任意场景快速启动AI，同时控制智能家居设备，甚至兼容小米汽车。核心规格方面，小米18Pro预计配备6.3英寸显示屏，主摄与3倍长焦采用2亿像素组合，电池容量将突破7000mAh。（财经网科技）</p>\\n  <p><strong>国家统计局：日均词元调用量突破140万亿，较上年末增长40%</strong></p>\\n  <p>国家统计局副局长毛盛勇4月16日在国新办新闻发布会上表示，智能化发展的引领作用不断增强，中国人工智能商业化、规模化运营取得了阶段性突破。截至今年3月，日均词元（Token）调用量突破140万亿，比上年末增长超40%。人工智能发展赋能千行百业，带动相关领域快速增长。（证券时报）</p>\\n  <p><strong>算力涨价潮席卷全球：阿里、Anthropic连续调价，严重算力荒再现</strong></p>\\n  <p>算力涨价潮正在席卷全球，海内外巨头又开始了新一轮调价。阿里云四天连发三条产品涨价公告，调整百炼部分模型单元服务价格及DataWorks部分API免费额度。Anthropic调整了旗下企业级产品Claude Enterprise订阅模式，从每月每用户最高200美元的固定费用，转变为按照实际算力消耗收费，此外用户每月还需要固定缴纳20美元。中信证券指出，Token调用量井喷带来的是算力需求极大爆发，与此同时供给侧受到各类硬约束短期边际增量有限，目前国内外均出现了严重的算力荒。（财联社）</p>\\n  <p><strong>研究显示：大语言模型会在蒸馏中“夹带”自己的偏好</strong></p>\\n  <p>《自然》15日发表的一项研究显示，大语言模型（LLM）可能会将某些自己的偏好“夹带私货”传授给其他算法，即使在训练数据中清除原始特征后，这些本不需要的特征，仍可能持续存在。在一个案例中，一个模型似乎通过数据中的隐含信号，将自己对猫头鹰的偏好传递给了其他模型。该研究结果表明，在开发LLM时，需要进行更彻底的安全检查。（财联社）</p>\\n  <p><strong>京东发布机器人产业服务全景图</strong></p>\\n  <p>36氪获悉，4月15日，京东发布“机器人产业服务全景图”。全景图聚焦三大核心：携手超200家品牌，目标2026年销售破百亿；依托超级供应链，建全球最大具身数据采集中心、京东机器人售后维修服务3年覆盖50余城；基于JoyAI大模型加速开放JoyInside附身智能交互能力，为机器人注入“智慧大脑”。</p>\\n  <p><strong>电子布库存持续紧张，涨价周期尚未结束</strong></p>\\n  <p>从业内获悉，多家电子布（电子级玻璃纤维）厂商库存紧张，部分企业库存不足十天。行业整体扩产进度受织布机供应瓶颈制约，短期内补库难度较大。业内人士分析认为，在织布机瓶颈未突破、产能向高端布倾斜的背景下，电子布高景气格局仍将延续，涨价周期尚未结束。（上证报）</p>\\n  <p><strong>亚洲富豪挟250亿美元涌入AI领域，面对高估值毫无惧色</strong></p>\\n  <p>据报道，尽管对美国AI企业估值过高的疑虑渐起，亚洲富裕投资者仍向该领域投入数十亿美元的私人资本，毫无惧色。根据PitchBook数据显示，2025年亚洲高净值个人及家族办公室共向全球AI私募融资投入243亿美元。今年动能延续，截至4月8日，新增投资额已达9.5亿美元。这波投资热潮正值SpaceX、OpenAI和Anthropic PBC等行业巨头在募资中持续创下惊人估值。对亚洲富裕投资人而言，抓住世代级科技机会的吸引力，已超越潜在泡沫的风险。（新浪财经）</p>\\n  <p><strong>为加速重塑Siri，苹果安排近200名工程师培训AI编程</strong></p>\\n  <p>据报道，为了追赶AI竞争对手，苹果正在将近200名Siri工程师送往为期数周的训练营，学习如何使用AI进行编程，旨在提升程序员的AI编程能力。据悉，该培训覆盖了Siri团队近九成工程师。训练营的培训重点将是学习使用Anthropic旗下Claude Code等AI辅助开发工具。</p>\\n  <p>在此之前，Siri团队长期沿用传统开发模式，在AI辅助编程方面的应用相对滞后，这也导致近年来Siri的功能迭代速度放缓，与谷歌Assistant、亚马逊Alexa等竞品的差距逐渐拉大。谷歌Assistant深度集成Gemini模型，早已支持多步复合指令、跨应用协同；亚马逊Alexa拥有超10万种兼容智能家居设备，技能库丰富，擅长多设备联动控制。（界面新闻）</p>\\n  <p><strong>美联储4月维持利率不变的概率为98.4%</strong></p>\\n  <p>据CME“美联储观察”：美联储4月加息25个基点的概率为1.6%，维持利率不变的概率为98.4%。美联储到6月累计降息25个基点的概率为0%，维持利率不变的概率为98%，累计加息25个基点的概率为2%。（财联社）</p>\\n  <p><strong>特朗普签发多项输油管道许可，以促进美加之间的石油运输</strong></p>\\n  <p>据白宫公布的文件显示，美国总统特朗普15日签发了多项输油管道许可，其中包括一项新建输油管道的许可，旨在促进美国与加拿大之间的原油及油品运输。该建设许可已颁发给Bakken Pipeline Company，用于北达科他州伯克县的管道设施建设。此外，他还签发了其他许可，以维护和运营位于北达科他州和密西根州、靠近边境地区的现有输油管道。（新浪财经）</p>\\n  <p><strong>美股三大指数集体收涨，纳指十二连涨再创收盘新高</strong></p>\\n  <p>36氪获悉，4月16日收盘，美股三大指数集体上涨，纳指涨0.36%，为连续12个交易日上涨续创新高，标普500指数涨0.26%创历史新高，道指涨0.24%。大型科技股多数上涨，英特尔、甲骨文涨超5%，微软涨超2%，Meta、亚马逊、奈飞小幅上涨；苹果跌超1%，特斯拉、谷歌、英伟达小幅下跌。热门中概股多数走强，蔚来涨超6%，阿里巴巴、百度、小鹏集团涨超3%，理想汽车、拼多多涨超1%；老虎证券、小马智行跌超1%。</p>\\n  <p><strong>聚焦充电宝等重点领域，市场监管总局开展专项行动打击虚假CCC认证标志</strong></p>\\n  <p>市场监管总局在全国范围内部署开展CCC认证守底线专项行动，全链条、全方位加强CCC认证监管，营造安全放心的消费环境。强制性产品认证也就是我们常说的CCC认证制度是我国政府遵循世贸组织规则和国际通行规则建立的具有市场准入性质的合格评定体系，列入CCC认证目录的产品，需要获证后才能出厂、进口、销售。此次专项行动将突出一个“严”字。将对指定认证机构实施全覆盖监督检查，聚焦充电宝、电动自行车、燃气燃烧器具等重点领域，开展有效性抽查。深入推进CCC认证标志试点改革，精准打击虚假CCC认证标志，加强产品质量责任追溯。（界面新闻）</p>\\n  <p><strong>三星请求法院禁止工会开展非法罢工活动</strong></p>\\n  <p>一名发言人表示，三星电子于16日向法院提起申请，要求禁止其韩国工会在计划中的罢工期间开展非法活动。眼下这场薪资纠纷，恐将扰乱这家全球最大存储芯片制造商的生产运营。三星并未详细说明此次法律行动的具体细节。工会则将此举称为“宣战”，指责公司侵犯了受法律保护的罢工权。（新浪财经）</p>\\n  <p><strong>万科回应总裁空缺：已由董事长及高管团队分担相关职责</strong></p>\\n  <p>36氪获悉，万科A在深交所互动易平台回应了总裁职位空缺、泊寓业务、化债等市场关注。对总裁一职的空缺，万科表示，公司总裁职位目前处于空缺状态，公司已通过董事会授权及高管分工调整，由董事长及公司高管团队分担相关职责，确保了公司经营决策的正常开展和公司治理的有效运作。万科还提到，受多重因素影响，当前公司面临着多重风险挑战，整体经营形势依然十分严峻。在各方支持下，集团全力推进改革化险工作。</p>\\n  <p><strong>国际原油市场逐渐回归基本面定价，库存消耗继续推升油价</strong></p>\\n  <p>当前，国际原油市场从3月份“溢价绑架油价”的恐慌性交易，逐渐回归至基本面定价。最直观的数据表现为，纽约WTI近月期货合约升水较峰值回落约60%，国内原油期权波动率指数（VIX）自高点腰斩，同时原油期货沉淀资金规模降幅超四成。（证券时报）</p>\\n  <p><strong>摩根大通CEO杰米·戴蒙出售价值4000万美元摩根大通股票</strong></p>\\n  <p>摩根大通首席执行官杰米·戴蒙（Jamie Dimon）4月15日出售了价值超过4000万美元的该行股票，这是他最新一次减持套现。戴蒙执掌这家银行已超过20年，直到2023年底他才开始出售自己持有的该行股票，当时他卖出了100万股，价值约1.8亿美元。他去年出售了价值约2.33亿美元的股票，今年2月出售了价值约2100万美元的股票。他目前仍持有该行超过620万股股票，价值约19亿美元。这些股票由戴蒙、他的妻子和他的家族信托持有。（新浪财经）</p>\\n  <h2>上市进行时</h2>\\n  <p><strong>先正达</strong></p>\\n  <p>先正达寻求最早6月在香港以保密方式提交IPO申请。（财联社）</p>\\n  <p><strong>春光集团</strong></p>\\n  <p>36氪获悉，春光集团披露招股书，拟于近期在深市发行新股并上市。</p>\\n  <p><strong>中科宇航</strong></p>\\n  <p>36氪获悉，上交所官网显示，4月15日，商业火箭企业中科宇航IPO状态变为已问询。中科宇航成立于2018年，3月31日，该公司IPO申请获受理，后被抽中现场检查。此次IPO，中科宇航拟募资41.8亿元，其保荐机构为国泰海通证券。</p>\\n  <p><strong>华盛锂电</strong></p>\\n  <p>36氪获悉，华盛锂电公告，公司已于2026年4月15日向香港联交所递交了发行境外上市股份(H股)并在香港联交所主板上市的申请，并于同日在香港联交所网站刊登了本次发行上市的申请资料。本次发行上市事项的相关申请资料为公司按照香港证监会和香港联交所的要求编制和刊发，为草拟版本，且所载资料可能会适时作出更新及修订。</p>\\n  <h2>AI最前沿</h2>\\n  <p><strong>腾讯混元3D世界模型2.0发布并开源</strong></p>\\n  <p>36氪获悉，4月16日，混元3D世界模型2.0（HY-World 2.0）正式发布并开源。HY-World 2.0是一个多模态世界模型，能够根据文字、图片、视频等不同类型输入，自动生成、重建和模拟3D世界，同时支持多格式3D资产（Mesh/3DGS/点云等）导出，支持与现有的游戏工作流无缝对接，用于快速生成游戏地图和关卡原型。</p>\\n  <p><strong>OpenAI退出挪威“星门”数据中心合作，微软接手</strong></p>\\n  <p>OpenAI放弃直接从英国AI云服务商Nscale在挪威运营的数据中心租赁算力的计划。微软将接手该数据中心的剩余算力。OpenAI表示，正与微软洽谈从其手中租赁算力。（新浪财经）</p>\\n  <p><strong>Adobe推出可操作Claude的创意工具AI助手</strong></p>\\n  <p>Adobe4月15日宣布推出一款全新的人工智能助手，旨在帮助用户在其照片、视频及数字内容编辑软件套件中执行各项任务。该助手还将与Anthropic的Claude AI模型进行集成。（新浪财经）</p>\\n  <p><strong>马斯克的xAI据悉将向编程初创公司Cursor提供算力支持</strong></p>\\n  <p>据知情人士透露，埃隆·马斯克的人工智能公司xAI计划与编程初创公司Cursor达成一项新的合作协议，让后者利用其庞大的计算能力。消息人士称，Cursor计划在xAI的基础设施上训练其最新的AI编程模型Composer 2.5。他们还表示，Cursor将使用xAI的数万快图形处理器（GPU）。（新浪财经）</p>\\n  <p><strong>阶跃发布新一代语音生成模型StepAudio 2.5 TTS</strong></p>\\n  <p>36氪获悉，4月16日，阶跃发布新一代语音生成模型StepAudio 2.5 TTS。据介绍，该模型围绕全局语境控制、文中语境控制，以及零样本复刻与全音色控制等能力进行了升级，主要面向角色配音、有声内容创作、智能语音交互等场景。StepAudio 2.5 TTS支持利用自然语言来进行合成控制。目前，StepAudio 2.5 TTS已全量上线“阶跃星辰开放平台”和Step Plan。</p>\\n  <h2>大公司财报</h2>\\n  <p><strong>台积电：预计第二季度毛利率65.5％-67.5％</strong></p>\\n  <p>台积电预计第二季度毛利率65.5％-67.5％，市场预估64.1％；预计第二季度销售额390亿美元-402亿美元，预估381.1亿美元。（财联社）</p>\\n  <p><strong>永辉超市：一季度净利润2.87亿元，同比增长94.40%</strong></p>\\n  <p>36氪获悉，永辉超市发布2026年第一季度业绩报告。报告显示，一季度营业收入133.67亿元，同比减少23.53%；净利润2.87亿元，同比增长94.40%；扣非后归母净利润为2.47亿元，同比增长79.55%。此外，截至一季度末，永辉超市全国累计调改门店达327家。</p>\\n  <p><strong>贵州茅台：2025年实现营业收入1688.38亿元，同比下降1.21%</strong></p>\\n  <p>36氪获悉，贵州茅台发布2025年业绩报告。报告显示，2025年实现营业收入1688.38亿元，同比下降1.21%；归属于上市公司股东的净利润为823.20亿元，同比下降4.53%。拟向全体股东每股派发现金红利27.993元（含税）。</p>\\n  <p><strong>太平鸟：2025年净利润1.74亿元，同比下降32.57%</strong></p>\\n  <p>36氪获悉，太平鸟发布2025年业绩报告。报告显示，2025年营业收入63.34亿元，同比下降6.88%。净利润1.74亿元，同比下降32.57%。公司拟每10股派发现金红利3元（含税），拟派发现金红利1.41亿元，剩余未分配利润结转以后年度分配。2026年第一季度营收为16.56亿元，同比下降0.75%：净利润为1.37亿元，同比增长10.3%。</p>\\n  <p><strong>华友钴业：2026年第一季度净利润24.97亿元，同比增长99.45%</strong></p>\\n  <p>36氪获悉，华友钴业发布2026年第一季度业绩报告。报告显示，一季度实现营业收入258.04亿元，同比增长44.62%；归属于上市公司股东的净利润为24.97亿元，同比增长99.45%。业绩变动主要系产品销量增加及金属价格回升所致，以及主要受益于镍、钴、锂等金属价格的回升及公司产业一体化经营优势的持续释放。</p>\\n  <h2>投融资</h2>\\n  <p><strong>“它石智航”完成超4.5亿美金Pre-A轮融资</strong></p>\\n  <p>4月16日，“它石智航”宣布完成超4.5亿美金Pre-A轮融资，创下中国具身智能有史以来最高单轮融资纪录，由高瓴创投，与红杉中国联合领投，美团龙珠、中金资本、凯联资本、东方富海、钧山投资等财务基金跟投。本轮融资将用于加速打造通用具身大模型AWE和持续吸引行业人才，下一轮融资将重点用于打造真干活、真量产的机器人。</p>\\n  <h2>酷产品</h2>\\n  <p><strong>宝马将在北京车展推出M3 40周年限量版</strong></p>\\n  <p>36氪获悉，宝马将在北京国际车展推出M3 40周年限量版车型，涵盖轿车与旅行车两种版本，在华各限量20台，于2026年下半年上市。</p>\\n  <p><strong>奥迪高管透露明年将推第三款中国专属车型</strong></p>\\n  <p>据报道，德国奥迪汽车公司首席执行官索内拉表示，为重夺中国市场份额，奥迪计划于明年与中国合作伙伴上汽集团联合推出第三款中国专属车型，定位为高端运动型轿车。索内拉强调，该车型已进入开发阶段，并延续“中国需求优先”策略。（界面新闻）</p>\\n  <p><strong>追觅科技旗下AI视觉机器人品牌NAVO亮相广交会</strong></p>\\n  <p>36氪获悉，4月15日，第139届中国进出口商品交易会（即2026春季广交会）在广州开幕，追觅科技旗下AI视觉机器人品牌NAVO，携全系列高端AI智能摄像头产品亮相。据了解，NAVO自研专属安防芯片架构，搭配黑光全彩夜视引擎，首创事件级AI平台AlgoMart。上市半年，订单销售额超过6000万。</p>\\n  <h2>AI图谱</h2>\\n  <p><strong>AI图谱，带你解读最新最快的AI咨询。46小时内两次袭击，美国人这么怕AI？</strong></p>\\n  <p><strong>整理</strong>｜Kris&nbsp;</p>\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 0, 2, 44, 4, 107, 0]}, \"published_at\": \"2026-04-17 08:02:44\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:08:25');
INSERT INTO `news_detail` VALUES (66, 2295, 11, '服务与基建', '优步斥资2.7亿欧元增持Delivery Hero股份', '', '优步斥资2.7亿欧元增持Delivery Hero股份，优步将以每股20欧元的价格收购Delivery Hero额外4.5%的股权。（财联社）', 'https://36kr.com/newsflashes/3770485623702279?f=rss', 0, '', '{\"summary\": \"本文披露优步增持海外配送企业Delivery Hero股份的交易信息，帮助出海企业掌握海外配送赛道资本动态\", \"abstract\": \"本文报道了优步增持Delivery Hero股份的资本交易。优步将以每股20欧元的价格，斥资2.7亿欧元完成本次收购。本次交易将为优步带来Delivery Hero额外4.5%的股权。该交易体现了海外即时配送赛道的资本动向\", \"keywords\": [\"优步\", \"Delivery Hero\", \"增持股份\", \"股权收购\", \"海外资本\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"服务与基建\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3770485623702279?f=rss\", \"title\": \"优步斥资2.7亿欧元增持Delivery Hero股份\", \"source\": \"https://36kr.com/feed\", \"content\": \"优步斥资2.7亿欧元增持Delivery Hero股份，优步将以每股20欧元的价格收购Delivery Hero额外4.5%的股权。（财联社）\", \"is_policy\": 0, \"origin_msg\": {\"link\": \"https://36kr.com/newsflashes/3770485623702279?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770485623702279?f=rss\", \"type\": \"text/html\"}], \"title\": \"优步斥资2.7亿欧元增持Delivery Hero股份\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"优步斥资2.7亿欧元增持Delivery Hero股份，优步将以每股20欧元的价格收购Delivery Hero额外4.5%的股权。（财联社）\", \"published\": \"2026-04-17 13:36:19  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"优步斥资2.7亿欧元增持Delivery Hero股份\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"优步斥资2.7亿欧元增持Delivery Hero股份，优步将以每股20欧元的价格收购Delivery Hero额外4.5%的股权。（财联社）\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 36, 19, 4, 107, 0]}, \"published_at\": \"2026-04-17 13:36:19\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:08:45');
INSERT INTO `news_detail` VALUES (67, 2308, 10, '传统制造升级', '金螳螂：与越南Sun Group签署的备忘录中不涉及任何具体项目及具体金额', '', '36氪获悉，金螳螂午间公告，近日，公司关注到合作外方越南Sun Group在其所在国家对外发布信息，称与金螳螂签署了23亿美元规模的合作文件，相关报道已被部分国内媒体转载。公司知悉后高度重视，为避免相关信息对广大投资者造成误导，对有关情况进行了核实，现予以澄清说明。公司于2026年4月14日与越南Sun Group签署了《战略合作谅解备忘录》（以下简称“备忘录”）。备忘录系双方经过初步磋商后达成的框架性约定，对双方均不具有法律约束力。双方签署的备忘录中不涉及任何具体项目及具体金额。截至本公告披露日，双方尚未就任何具体合作项目达成具有法律约束力的正式协议。后续合作能否落地实施、具体合作内容及合作规模等，均需双方进一步协商确定，并签署具有法律约束力的正式协议后方可推进。', 'https://36kr.com/newsflashes/3770469160043268?f=rss', 0, '', '{\"summary\": \"本文澄清金螳螂与越南Sun Group的大额合作传闻，帮助出海相关投资者明晰海外框架合作的不确定性\", \"abstract\": \"金螳螂针对越南Sun Group对外宣称双方签署23亿美元规模合作文件的传闻发布澄清公告。金螳螂表示仅与对方签署了无法律约束力的框架性战略合作谅解备忘录，备忘录未涉及任何具体项目与具体金额。截至公告披露日，双方尚未达成任何具有法律约束力的具体合作正式协议。后续合作落地仍需双方进一步协商，签署正式协议后方可推进。\", \"keywords\": [\"金螳螂\", \"越南\", \"海外合作\", \"Sun Group\", \"战略合作谅解备忘录\", \"框架性协议\"], \"policy_risk\": {\"market_risk\": \"双方仅签署无法律约束力的框架性备忘录，尚未达成正式合作协议，出海合作落地存在不确定性，不实信息易引发市场误导\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"传统制造升级\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3770469160043268?f=rss\", \"title\": \"金螳螂：与越南Sun Group签署的备忘录中不涉及任何具体项目及具体金额\", \"source\": \"https://36kr.com/feed\", \"content\": \"36氪获悉，金螳螂午间公告，近日，公司关注到合作外方越南Sun Group在其所在国家对外发布信息，称与金螳螂签署了23亿美元规模的合作文件，相关报道已被部分国内媒体转载。公司知悉后高度重视，为避免相关信息对广大投资者造成误导，对有关情况进行了核实，现予以澄清说明。公司于2026年4月14日与越南Sun Group签署了《战略合作谅解备忘录》（以下简称“备忘录”）。备忘录系双方经过初步磋商后达成的框架性约定，对双方均不具有法律约束力。双方签署的备忘录中不涉及任何具体项目及具体金额。截至本公告披露日，双方尚未就任何具体合作项目达成具有法律约束力的正式协议。后续合作能否落地实施、具体合作内容及合作规模等，均需双方进一步协商确定，并签署具有法律约束力的正式协议后方可推进。\", \"is_policy\": 0, \"origin_msg\": {\"link\": \"https://36kr.com/newsflashes/3770469160043268?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770469160043268?f=rss\", \"type\": \"text/html\"}], \"title\": \"金螳螂：与越南Sun Group签署的备忘录中不涉及任何具体项目及具体金额\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，金螳螂午间公告，近日，公司关注到合作外方越南Sun Group在其所在国家对外发布信息，称与金螳螂签署了23亿美元规模的合作文件，相关报道已被部分国内媒体转载。公司知悉后高度重视，为避免相关信息对广大投资者造成误导，对有关情况进行了核实，现予以澄清说明。公司于2026年4月14日与越南Sun Group签署了《战略合作谅解备忘录》（以下简称“备忘录”）。备忘录系双方经过初步磋商后达成的框架性约定，对双方均不具有法律约束力。双方签署的备忘录中不涉及任何具体项目及具体金额。截至本公告披露日，双方尚未就任何具体合作项目达成具有法律约束力的正式协议。后续合作能否落地实施、具体合作内容及合作规模等，均需双方进一步协商确定，并签署具有法律约束力的正式协议后方可推进。\", \"published\": \"2026-04-17 13:19:34  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"金螳螂：与越南Sun Group签署的备忘录中不涉及任何具体项目及具体金额\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，金螳螂午间公告，近日，公司关注到合作外方越南Sun Group在其所在国家对外发布信息，称与金螳螂签署了23亿美元规模的合作文件，相关报道已被部分国内媒体转载。公司知悉后高度重视，为避免相关信息对广大投资者造成误导，对有关情况进行了核实，现予以澄清说明。公司于2026年4月14日与越南Sun Group签署了《战略合作谅解备忘录》（以下简称“备忘录”）。备忘录系双方经过初步磋商后达成的框架性约定，对双方均不具有法律约束力。双方签署的备忘录中不涉及任何具体项目及具体金额。截至本公告披露日，双方尚未就任何具体合作项目达成具有法律约束力的正式协议。后续合作能否落地实施、具体合作内容及合作规模等，均需双方进一步协商确定，并签署具有法律约束力的正式协议后方可推进。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 19, 34, 4, 107, 0]}, \"published_at\": \"2026-04-17 13:19:34\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:08:54');
INSERT INTO `news_detail` VALUES (68, 2323, 6, '科技与数字服务', '“加速进化”完成近10亿元融资', '', '36氪获悉，具身智能公司“加速进化”于近日完成近10亿元融资。本轮融资由北京高精尖产业基金、京国盛基金与华控基金联合领投，联想之星、国海创新资本、交银资本参与投资，深创投、源码资本、英诺基金、IDG等老股东持续加码。本轮融资将用于全球化交付网络建设、具身模型算法开发、机器人产品迭代升级。', 'https://36kr.com/newsflashes/3770428884812297?f=rss', 0, '', '{\"summary\": \"本文披露具身智能企业加速进化完成近10亿元融资，部分资金用于全球化交付网络建设，可为出海科技企业提供行业动态参考\", \"abstract\": \"具身智能公司\\\"加速进化\\\"近日完成近10亿元融资。本轮融资由多家头部投资机构联合领投，多家机构跟投，老股东持续加码。本轮融资资金将用于三大方向，其中包含全球化交付网络建设。这笔融资将助力公司推进技术研发与全球化业务布局\", \"keywords\": [\"加速进化\", \"具身智能\", \"融资\", \"全球化交付网络\", \"机器人\", \"算法开发\", \"产品迭代\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"未提及\"}, \"topic_cluster\": \"海外市场洞察\", \"industry_category\": \"科技与数字服务\"}', '', '{\"url\": \"https://36kr.com/newsflashes/3770428884812297?f=rss\", \"title\": \"“加速进化”完成近10亿元融资\", \"source\": \"https://36kr.com/feed\", \"content\": \"36氪获悉，具身智能公司“加速进化”于近日完成近10亿元融资。本轮融资由北京高精尖产业基金、京国盛基金与华控基金联合领投，联想之星、国海创新资本、交银资本参与投资，深创投、源码资本、英诺基金、IDG等老股东持续加码。本轮融资将用于全球化交付网络建设、具身模型算法开发、机器人产品迭代升级。\", \"is_policy\": 0, \"origin_msg\": {\"link\": \"https://36kr.com/newsflashes/3770428884812297?f=rss\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://36kr.com/newsflashes/3770428884812297?f=rss\", \"type\": \"text/html\"}], \"title\": \"“加速进化”完成近10亿元融资\", \"source\": {\"title\": \"36氪\"}, \"summary\": \"36氪获悉，具身智能公司“加速进化”于近日完成近10亿元融资。本轮融资由北京高精尖产业基金、京国盛基金与华控基金联合领投，联想之星、国海创新资本、交银资本参与投资，深创投、源码资本、英诺基金、IDG等老股东持续加码。本轮融资将用于全球化交付网络建设、具身模型算法开发、机器人产品迭代升级。\", \"published\": \"2026-04-17 13:01:26  +0800\", \"title_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/plain\", \"value\": \"“加速进化”完成近10亿元融资\", \"language\": null}, \"summary_detail\": {\"base\": \"https://36kr.com/feed\", \"type\": \"text/html\", \"value\": \"36氪获悉，具身智能公司“加速进化”于近日完成近10亿元融资。本轮融资由北京高精尖产业基金、京国盛基金与华控基金联合领投，联想之星、国海创新资本、交银资本参与投资，深创投、源码资本、英诺基金、IDG等老股东持续加码。本轮融资将用于全球化交付网络建设、具身模型算法开发、机器人产品迭代升级。\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 5, 1, 26, 4, 107, 0]}, \"published_at\": \"2026-04-17 13:01:26\", \"ai_json_output\": \"\"}', NULL, NULL, '2026-04-17 15:09:07');
INSERT INTO `news_detail` VALUES (69, 2353, 13, '营销与品牌服务', 'Google is now targeting bad ads over bad actors', '', 'Google blocked 8.3 billion ads in 2025 but suspended fewer advertisers.', 'https://techcrunch.com/2026/04/16/google-blocked-more-ads-but-banned-fewer-advertisers-as-ai-reshapes-enforcement/', 0, '', '{\"summary\": \"本文披露Google 2025年广告治理策略调整方向，帮助出海投放广告的企业提前适配合规要求\", \"abstract\": \"本文分享了Google广告治理的最新策略调整。2025年Google共计拦截了83亿条违规广告，但暂停的广告主账号数量较此前减少。Google当前将治理重心从处罚违规广告主转向打击不良广告本身。出海开展营销的企业可据此调整自身广告合规管理策略\", \"keywords\": [\"Google广告\", \"广告治理\", \"出海营销\", \"违规广告\", \"广告合规\"], \"policy_risk\": {\"market_risk\": \"未提及\", \"policy_compliance\": \"Google广告治理策略调整，治理重心从处罚违规广告主转向打击不良广告，2025年共拦截83亿条违规广告\"}, \"topic_cluster\": \"海外营销\", \"industry_category\": \"营销与品牌服务\"}', '', '{\"url\": \"https://techcrunch.com/2026/04/16/google-blocked-more-ads-but-banned-fewer-advertisers-as-ai-reshapes-enforcement/\", \"title\": \"Google is now targeting bad ads over bad actors\", \"source\": \"https://techcrunch.com/feed/\", \"content\": \"Google blocked 8.3 billion ads in 2025 but suspended fewer advertisers.\", \"is_policy\": 0, \"origin_msg\": {\"id\": \"https://techcrunch.com/?p=3112896\", \"link\": \"https://techcrunch.com/2026/04/16/google-blocked-more-ads-but-banned-fewer-advertisers-as-ai-reshapes-enforcement/\", \"tags\": [{\"term\": \"AI\", \"label\": null, \"scheme\": null}, {\"term\": \"ad fraud\", \"label\": null, \"scheme\": null}, {\"term\": \"Google\", \"label\": null, \"scheme\": null}, {\"term\": \"Google Ads\", \"label\": null, \"scheme\": null}], \"links\": [{\"rel\": \"alternate\", \"href\": \"https://techcrunch.com/2026/04/16/google-blocked-more-ads-but-banned-fewer-advertisers-as-ai-reshapes-enforcement/\", \"type\": \"text/html\"}], \"title\": \"Google is now targeting bad ads over bad actors\", \"author\": \"Jagmeet Singh\", \"authors\": [{\"name\": \"Jagmeet Singh\"}], \"summary\": \"Google blocked 8.3 billion ads in 2025 but suspended fewer advertisers.\", \"published\": \"Thu, 16 Apr 2026 15:00:00 +0000\", \"guidislink\": false, \"title_detail\": {\"base\": \"https://techcrunch.com/feed/\", \"type\": \"text/plain\", \"value\": \"Google is now targeting bad ads over bad actors\", \"language\": null}, \"author_detail\": {\"name\": \"Jagmeet Singh\"}, \"summary_detail\": {\"base\": \"https://techcrunch.com/feed/\", \"type\": \"text/html\", \"value\": \"Google blocked 8.3 billion ads in 2025 but suspended fewer advertisers.\", \"language\": null}, \"published_parsed\": [2026, 4, 16, 15, 0, 0, 3, 106, 0]}, \"published_at\": \"2026-04-16 15:00:00\", \"ai_json_output\": \"\"}', 'Google said Thursday it blocked a record 8.3 billion ads globally in 2025 — up from\n5.1 billion the year before\n. But the company suspended far fewer advertiser accounts than that surge might suggest, raising questions about how it polices its platform.\nThe search giant attributed the disparity to its growing use of AI, particularly its Gemini models — Google’s family of AI systems — which Google says allow it to detect and block policy-violating ads earlier and with greater precision. Its AI-driven systems caught more than 99% of such ads last year before they were shown to users, the company said.\nBoth findings come from Google’s 2025 Ads Safety Report and together reflect a broader change in enforcement. While more problematic ads are being stopped, fewer advertiser accounts are being suspended — suggesting a growing emphasis on blocking individual ads.\nGoogle said the rise in blocked ads also reflects the growing use of generative AI by scammers to produce deceptive content at scale, with its Gemini models helping detect patterns across large campaigns and block them earlier.\nThe shift also mirrors a wider push by Google to integrate its Gemini models\nmore deeply into its core products\nand infrastructure,\nincluding advertising\n, where the company is increasingly using AI to automate campaign creation, detect policy violations, and respond to emerging threats in real time.\nImage Credits:\nJagmeet Singh / TechCrunch\nAmong the blocked ads and suspended accounts, 602 million ads and 4 million advertiser accounts were linked to scams, the company said.\nGoogle removed over 1.7 billion ads and suspended 3.3 million advertiser accounts in the U.S. in 2025, with ad network abuse, misrepresentation, and sexual content among the most common violations. In India, Google’s largest market by users, it blocked 483.7 million ads — nearly double the previous year — even as account suspensions fell to 1.7 million from 2.9 million, with trademarks, financial services, and copyright issues among the top violations.\nTechcrunch event\nMeet your next investor or portfolio startup at Disrupt\nYour next round. Your next hire. Your next breakout opportunity. Find it at TechCrunch Disrupt 2026, where 10,000+ founders, investors, and tech leaders gather for three days of 250+ tactical sessions, powerful introductions, and market-defining innovation. Register now to save up to $410.\nMeet your next investor or portfolio startup at Disrupt\nYour next round. Your next hire. Your next breakout opportunity. Find it at TechCrunch Disrupt 2026, where 10,000+ founders, investors, and tech leaders gather for three days of 250+ tactical sessions, powerful introductions, and market-defining innovation. Register now to save up to $410.\nSan Francisco, CA\n|\nOctober 13-15, 2026\nREGISTER NOW\nAt a virtual briefing, Keerat Sharma, VP and general manager of ads privacy and safety at Google, told reporters the company has shifted toward more targeted, AI-driven enforcement “at a much more granular level, on a creative level, as opposed to using a much more blunt instrument, like advertiser suspensions.” He added that the approach has helped reduce incorrect suspensions by 80% year over year.\nGoogle’s layered defenses, including advertiser verification (a process that requires businesses to confirm their identity before running ads), are designed to prevent bad actors from creating accounts in the first place, Sharma said, adding that this has contributed to the decline in suspensions.\nThe numbers, Sharma said, are likely to fluctuate over time as Google rolls out new defenses and bad actors adapt, with the company aiming to stop harmful ads as early in the pipeline as possible.\nTopics\nad fraud\n,\nAI\n,\nGoogle\n,\nGoogle Ads\n,\nIndia\n,\nUnited States\nJagmeet Singh\nReporter\nJagmeet covers startups, tech policy-related updates, and all other major tech-centric developments from India for TechCrunch. He previously worked as a principal correspondent at NDTV.\nYou can contact or verify outreach from Jagmeet by emailing\nmail@journalistjagmeet.com\n.\nView Bio\nApril 30\nSan Francisco, CA\nStrictlyVC kicks off the year in SF. Get in the room for unfiltered fireside chats with industry leaders, insider VC insights, and high-value connections that actually move the needle.\nTickets are limited.\nREGISTER NOW\nMost Popular\nAfter sale of its shoe business, Allbirds pivots to AI\nSarah Perez\nAn Amazon warehouse worker died on the job at Oregon facility\nAmanda Silberling\nOpenAI has bought AI personal finance startup Hiro\nJulie Bort\nStanford report highlights growing disconnect between AI insiders and everyone else\nSarah Perez\nWalmart-owned Flipkart, Amazon are squeezing India’s quick-commerce startups\nJagmeet Singh\nSam Altman responds to ‘incendiary’ New Yorker article after attack on his home\nAnthony Ha\nFrance to ditch Windows for Linux to reduce reliance on US tech\nZack Whittaker', NULL, '2026-04-17 15:09:51');
INSERT INTO `news_detail` VALUES (70, 2359, 18, '硬件与半导体出海', 'FCC exempts Netgear from ban on foreign routers, doesn\'t explain why', '', '<p>Article URL: <a href=\"https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/\">https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/</a></p>\n<p>Comments URL: <a href=\"https://news.ycombinator.com/item?id=47802394\">https://news.ycombinator.com/item?id=47802394</a></p>\n<p>Points: 27</p>\n<p># Comments: 5</p>', 'https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/', 0, '', '{\"summary\": \"帮助出海美国的网络硬件企业掌握FCC外国路由器禁令的最新变动，为企业调整美国市场准入策略提供参考\", \"abstract\": \"本文报道了美国联邦通信委员会（FCC）作出豁免网件（Netgear）适用外国路由器禁令的决定。FCC并未对外公布此次豁免网件的具体原因。该事件反映了美国网络硬件准入政策的变动，可为相关出海企业提供政策参考。\", \"keywords\": [\"FCC\", \"路由器禁令\", \"网件\", \"美国市场\", \"硬件出海\", \"合规准入\"], \"policy_risk\": {\"market_risk\": \"美国外国网络硬件准入政策存在不确定性，出海硬件企业面临政策变动带来的市场准入风险\", \"policy_compliance\": \"美国FCC豁免网件适用外国路由器禁令，未对外披露此次豁免的具体原因，政策调整细节不透明\"}, \"topic_cluster\": \"合规法律\", \"industry_category\": \"硬件与半导体出海\"}', '', '{\"url\": \"https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/\", \"title\": \"FCC exempts Netgear from ban on foreign routers, doesn\'t explain why\", \"source\": \"https://hnrss.org/frontpage\", \"content\": \"<p>Article URL: <a href=\\\"https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/\\\">https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/</a></p>\\n<p>Comments URL: <a href=\\\"https://news.ycombinator.com/item?id=47802394\\\">https://news.ycombinator.com/item?id=47802394</a></p>\\n<p>Points: 27</p>\\n<p># Comments: 5</p>\", \"is_policy\": 0, \"origin_msg\": {\"id\": \"https://news.ycombinator.com/item?id=47802394\", \"link\": \"https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/\", \"links\": [{\"rel\": \"alternate\", \"href\": \"https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/\", \"type\": \"text/html\"}], \"title\": \"FCC exempts Netgear from ban on foreign routers, doesn\'t explain why\", \"author\": \"rawgabbit\", \"authors\": [{\"name\": \"rawgabbit\"}], \"summary\": \"<p>Article URL: <a href=\\\"https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/\\\">https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/</a></p>\\n<p>Comments URL: <a href=\\\"https://news.ycombinator.com/item?id=47802394\\\">https://news.ycombinator.com/item?id=47802394</a></p>\\n<p>Points: 27</p>\\n<p># Comments: 5</p>\", \"comments\": \"https://news.ycombinator.com/item?id=47802394\", \"published\": \"Fri, 17 Apr 2026 04:13:52 +0000\", \"guidislink\": false, \"title_detail\": {\"base\": \"https://hnrss.org/frontpage\", \"type\": \"text/plain\", \"value\": \"FCC exempts Netgear from ban on foreign routers, doesn\'t explain why\", \"language\": null}, \"author_detail\": {\"name\": \"rawgabbit\"}, \"summary_detail\": {\"base\": \"https://hnrss.org/frontpage\", \"type\": \"text/html\", \"value\": \"<p>Article URL: <a href=\\\"https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/\\\">https://arstechnica.com/tech-policy/2026/04/fcc-exempts-netgear-from-ban-on-foreign-routers-doesnt-explain-why/</a></p>\\n<p>Comments URL: <a href=\\\"https://news.ycombinator.com/item?id=47802394\\\">https://news.ycombinator.com/item?id=47802394</a></p>\\n<p>Points: 27</p>\\n<p># Comments: 5</p>\", \"language\": null}, \"published_parsed\": [2026, 4, 17, 4, 13, 52, 4, 107, 0]}, \"published_at\": \"2026-04-17 04:13:52\", \"ai_json_output\": \"\"}', 'Text\n settings\nStory text\nSize\nSmall\nStandard\nLarge\nWidth\n*\nStandard\nWide\nLinks\nStandard\nOrange\n* Subscribers only\nLearn more\nMinimize to nav\nNetgear is the first major vendor of consumer routers to obtain an exemption from the US government’s sweeping ban on foreign-made routers.\nThe Federal Communications Commission yesterday\nannounced\nan exemption for Netgear’s Nighthawk and Orbi routers, and its cable gateways and modems. It came about three weeks after the\nFCC said it would no longer approve consumer-grade routers\nmade at least partly outside the US, except in cases where the Department of Defense or Department of Homeland Security determines that the router does not pose national security risks.\nUnder the new router ban, the Trump administration decides—through an opaque process in which it’s unclear why any particular company receives an exemption—which companies’ devices can be sold to consumers. Netgear, which is based in the US, was able to move quickly through the multi-agency approval process.\n“We’re pleased to share that Netgear is the first retail consumer router company to receive conditional approval from the Federal Communications Commission (FCC) as a trusted consumer router company,” Netgear CEO CJ Prober\nwrote yesterday\n. “We hope this recognition gives you added peace of mind—knowing that the network powering your home meets rigorous standards.”\nRouter makers seeking conditional approvals\nmust submit\na justification for the use of foreign manufacturing and a “detailed, time-bound plan to establish or expand manufacturing in the United States.” The FCC and Netgear didn’t say what kind of justification or plan was submitted by Netgear.\nExemption lasts until October 2027\nNetgear’s exemption lasts until October 1, 2027, and will have to be renewed. The FCC also gave an exemption of the same length to Adtran’s service delivery gateways. Adtran mostly provides networking products for large businesses, including cable and telecom companies, but also\nsells residential routers\n.\nThe Trump administration is reserving the right to block security patches and other software updates. The FCC last month gave all previously approved routers a waiver allowing software updates until March 1, 2027, leaving open the possibility that routers may not be allowed to receive updates after that date.\nThe FCC imposed the device ban only on consumer-grade routers, even though network gear used by large businesses presents a natural target for the foreign hackers the router ban is ostensibly supposed to thwart. The FCC announcement of exemptions for Netgear and Adtran didn’t provide any specific reason to think the companies’ routers are more secure than others commonly used in the US.\nThe ban didn’t have an immediate effect on router supply because it only affected devices that had not yet been approved through the FCC’s standard equipment authorization process. Routers previously approved for sale in the US can continue to be imported and sold without obtaining a special exemption.\nVirtually every new router needs exemption\nNearly every router maker will have to obtain an exemption for future devices. “Virtually no consumer router is manufactured entirely within the United States,” according to a\nreport\nreleased last week by the Global Electronics Association trade group. “Even US-headquartered brands rely on overseas contract manufacturers, and the component supply chain is rooted in Asia regardless of final assembly location: Wi-Fi chipsets from Qualcomm, Broadcom, or MediaTek (fabricated at TSMC in Taiwan or Samsung in South Korea), multilayer ceramic capacitors from Murata or TDK (Japan), and PCBs overwhelmingly produced in China and Taiwan.”\nThe report adds that “Netgear, Amazon (Eero), Google (Nest WiFi), Ubiquiti, and Linksys, all US-based, manufacture entirely or predominantly outside the United States and are therefore subject to the restriction for any new models. The sole major router product that potentially escapes the order’s reach is SpaceX’s Starlink router, assembled at facilities in Texas, which is not sold as a standalone product but accompanies the satellite dish as part of the Starlink service kit.”\nThe FCC is granting exemptions under the same process it set up for its\nban on foreign-made drones\n. The FCC’s announcement of exemptions yesterday included one drone maker, the UK-based Sees.ai, which makes systems for inspecting electric grids. Previous drone exemptions were\ngranted\nto US-based companies SiFly Aviation and Verge Aero, the Norwegian company ScoutDI, and Israeli company Mobilicom.\nChinese drone companies DJI, the market share leader, and its smaller rival Autel have yet to receive exemptions. “If the router Conditional Approval process follows a similar pattern, Chinese-origin manufacturers like TP-Link may face a presumptive denial, while companies with manufacturing in allied nations like Taiwan, Vietnam, or South Korea could find an easier path,” the Global Electronics Association report said. This easier path for non-Chinese companies is “by no means guaranteed,” the report said.\nTP-Link was founded in China but relocated to the US in 2024. It was already\nfacing the possibility of a US ban\nover a year before the FCC’s industry-wide router action, but the Trump administration\nnever formalized\na TP-Link ban. TP-Link may hope its relocation to the US will help it win an exemption, but the Global Electronics Association report said the drone process suggests that “Chinese-origin manufacturers may face a presumptive denial regardless of corporate restructuring.”\nFast approvals key for router supply, group says\nEven if the Trump administration is inclined to approve most exemption requests, the industry trade group’s report said there are doubts about how fast the administration can process applications for the dozens of new models introduced annually.\n“Existing channel stock of previously authorized models may last three to six months, creating a window during which the market can absorb the disruption, but that window closes if the approval process proves as restrictive or slow as the drone precedent suggests,” the report said. The system “introduces a structural advantage for the largest firms” because “documentation and onshoring obligations are extensive and smaller manufacturers and startups may lack the resources to navigate the process,” it said.\nThe industry already “reduc[ed] Chinese-origin imports from 24 percent of units in 2019 to 4 percent in 2025” in a shift that cost billions and required “full cooperation of contract manufacturing ecosystems across Southeast Asia,” the report said. “The Conditional Approval framework now asks the industry to execute a second migration of comparable magnitude, this time to domestic soil, on a timeline measured in quarters rather than years, and without the established manufacturing ecosystems, workforce pipelines, or supplier networks that made the first migration possible.”\nThe report warned that if the approval process isn’t quick, residential consumers and home Internet service providers “will face constrained selection and delayed access to next-generation products at precisely the moment Wi-Fi 7 adoption should be accelerating.”\nJon Brodkin\nSenior IT Reporter\nJon Brodkin\nSenior IT Reporter\nJon is a Senior IT Reporter for Ars Technica. He covers the telecom industry, Federal Communications Commission rulemakings, broadband consumer affairs, court cases, and government regulation of the tech industry.\n133 Comments', NULL, '2026-04-17 15:09:56');
